INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('0nmcp', '0nMCP', 'Universal AI-powered API orchestrator that connects multiple services and automates complex workflows through natural language task descriptions. Integrates with popular APIs like Stripe, SendGrid, Twilio, Slack, Airtable, Notion, GitHub, and Shopify, allowing AI agents to orchestrate multi-step operations across these platforms without manual API configuration. Features intelligent service discovery through a catalog system, connection management for API credentials, and a CRM module for customer relationship workflows.', '@0nork', 'development', 'Unknown', 2, 'https://github.com/0nork/0nmcp', NULL, 0, 'https://github.com/0nork.png?size=128', '2026-03-09T05:21:01.891161+00:00'),
  ('polymarket', 'Polymarket', 'This MCP server provides real-time Polymarket prediction market data access through a comprehensive Rust implementation built with the official MCP Rust SDK, offering market search, price tracking, and trading analytics across active betting markets. Built by 0x79de with robust error handling, intelligent caching with configurable TTL, retry logic with exponential backoff, and structured logging, it features 5 core tools for fetching active markets, searching by keywords, retrieving market details and prices, and analyzing trending markets by volume. The implementation includes MCP resources for auto-refreshing market data feeds, AI-powered prompts for market analysis and arbitrage detection, extensive configuration via environment variables or TOML files, and comprehensive test coverage with mock API integration, making it valuable for prediction market analysis, trading strategy development, and building AI assistants that need real-time betting market insights without direct API management.', '@ozgureyilmaz', 'development', 'Unknown', 41, 'https://github.com/ozgureyilmaz/polymarket-mcp', NULL, 0, 'https://github.com/ozgureyilmaz.png?size=128', '2026-03-09T05:21:01.891218+00:00'),
  ('taskwarrior', 'Taskwarrior', 'mcp-taskwarrior is a server implementation by Bruce Kroeze that facilitates task management through Taskwarrior. It provides four essential tools for managing tasks: adding, updating, deleting, and listing tasks, with support for organizing by project and priority levels. Built with TypeScript and using the fastmcp and taskwarrior-lib dependencies, it can be used either through npx or by local installation, making it ideal for users who want to integrate task management capabilities into their AI assistant workflows.', '@0xbeedao', 'development', 'Unknown', 3, 'https://github.com/0xbeedao/mcp-taskwarrior', '@0xbeedao/mcp-taskwarrior', 4096, 'https://github.com/0xbeedao.png?size=128', '2026-03-09T05:21:01.891252+00:00'),
  ('cli-executor', 'CLI Executor', 'This MCP server implementation provides a tool for executing local CLI commands asynchronously. Developed by 0xBruno, it uses FastMCP and asyncio to run shell commands securely, handling command arguments with spaces and quotes properly. The server is designed for use cases requiring remote execution of system commands, with built-in error handling for failed commands.', '@0xbruno', 'ai-ml', 'Unknown', 1, 'https://github.com/0xbruno/mcpexec', NULL, 0, 'https://github.com/0xbruno.png?size=128', '2026-03-09T05:21:01.891293+00:00'),
  ('emba-firmware-security-analyzer', 'EMBA Firmware Security Analyzer', 'Exposes EMBA (Embedded Analyzer) firmware security analysis as an MCP server, enabling automated scanning and parsing of embedded device firmware images. Orchestrates EMBA scan execution with process management, persistent scan registry, and comprehensive result parsing across multiple security domains.', '@0xbuz3r', 'ai-ml', 'Unknown', 3, 'https://github.com/0xbuz3r/emba-mcp', NULL, 0, 'https://github.com/0xbuz3r.png?size=128', '2026-03-09T05:21:01.891333+00:00'),
  ('templonix-lite', 'Templonix Lite', 'Templonix Lite is a local-first AI agent infrastructure that extends Claude Desktop capabilities through specialized MCP tools. It features persistent vector memory using FAISS for information storage across conversations, a knowledge base loader for semantic search across uploaded documents, and a dynamic workflow system enabling expert personas with specialized knowledge. The server integrates with Gmail, Google Calendar, Asana, Notion, Google Drive, Eraser.io for diagram generation, and Jina AI for web scraping.', '@0xcjt', 'productivity', 'Unknown', 1, 'https://github.com/0xcjt/templonixlite', NULL, 0, 'https://github.com/0xcjt.png?size=128', '2026-03-09T05:21:01.891371+00:00'),
  ('sui', 'Sui', 'Sui MCP server enables AI assistants to interact with the Sui blockchain network through a standardized interface. Built with TypeScript, it provides tools for requesting test tokens from the Sui devnet faucet and integrates with the official Sui SDK. This implementation is particularly valuable for blockchain developers and users who need to test Sui smart contracts or manage wallets through conversational AI.', '@deanpluse', 'development', 'Unknown', 4, 'https://github.com/deanpluse/sui-mcp', NULL, 0, 'https://github.com/deanpluse.png?size=128', '2026-03-09T05:21:01.891396+00:00'),
  ('ethereum-blockchain-tools', 'Ethereum Blockchain Tools', 'EVM MCP Tools provides Ethereum blockchain analysis capabilities directly within Claude AI conversations. It offers a suite of tools for smart contract auditing, wallet analysis, token balance checking, and profitability tracking across Ethereum and compatible chains. The implementation leverages Web3.js, Moralis, and Etherscan APIs to fetch on-chain data, analyze contract security, detect token standards, and calculate wallet profit/loss metrics. Designed for integration with Claude for Desktop, it enables users to perform blockchain analysis tasks without leaving their conversation context, making it particularly valuable for developers, traders, and researchers who need quick access to Ethereum data.', '@0xgval', 'productivity', 'Unknown', 16, 'https://github.com/0xgval/evm-mcp-tools', NULL, 0, 'https://github.com/0xgval.png?size=128', '2026-03-09T05:21:01.891445+00:00'),
  ('twitter-search', 'Twitter Search', 'X Tools for Claude MCP is a lightweight toolkit that enables Claude AI to search Twitter with natural language queries and display results based on user intent. Built with Node.js and the Model Context Protocol SDK, it leverages the RapidAPI Twitter154 endpoint to provide advanced search capabilities including filtering by keywords, users, dates, and engagement metrics. The implementation formats tweets with clean markdown, supports pagination for larger result sets, and intelligently adapts its response style based on whether users want raw data viewing or analytical insights, making it particularly valuable for researchers, marketers, and social media analysts who need to quickly access and understand Twitter content.', '@0xgval', 'ai-ml', 'Unknown', 17, 'https://github.com/0xgval/twitter-x-mcp-server', NULL, 0, 'https://github.com/0xgval.png?size=128', '2026-03-09T05:21:01.891495+00:00'),
  ('frida-game-hacking', 'Frida Game Hacking', 'Bridges Frida dynamic instrumentation toolkit with MCP for game memory manipulation and code analysis. Offers comprehensive memory operations including value scanning with type support, Array of Bytes pattern matching that survives game updates, and read/write capabilities. Features function hooking with JavaScript callbacks for intercepting and modifying function behavior, process management for enumeration and attachment, and debugging tools including breakpoints and register access. Supports Windows, Linux, macOS, Android, and iOS. Designed for game trainers, security research, reverse engineering, and malware analysis in controlled environments.', '@0xhackerfren', 'development', 'Unknown', 44, 'https://github.com/0xhackerfren/frida-game-hacking-mcp', NULL, 0, 'https://github.com/0xhackerfren.png?size=128', '2026-03-09T05:21:01.891524+00:00'),
  ('twitter', 'Twitter', 'MCP Twitter provides direct interaction with Twitter/X through a standardized set of tools, enabling AI models to perform actions like creating posts, replying to tweets, following users, and retrieving profile data. Built by 0xhijo, it supports two authentication methods (API credentials or direct Twitter login) and exposes 11 distinct Twitter functionalities through a Node.js server. The implementation is designed for seamless integration with Claude through the claude_mcp_config.json file, making it particularly valuable for automated social media management, content creation, and Twitter data analysis without leaving the conversation interface.', '@0xhijo', 'ai-ml', 'Unknown', 11, 'https://github.com/0xhijo/mcp_twitter', 'mcp_twitter', 463, 'https://github.com/0xhijo.png?size=128', '2026-03-09T05:21:01.891570+00:00'),
  ('ethereum-rpc', 'Ethereum RPC', 'This Ethereum RPC MCP server provides a bridge to interact with the Ethereum blockchain through standard JSON-RPC calls. Developed by Koda, it exposes three essential tools: eth_getCode for retrieving contract bytecode, eth_gasPrice for checking current gas prices, and eth_getBalance for querying account balances. The implementation uses axios for making HTTP requests to a public Ethereum RPC endpoint (llamarpc) and includes error handling with human-readable responses. Ideal for AI assistants that need to perform basic Ethereum blockchain queries without requiring complex wallet integration.', '@0xkoda', 'development', 'Unknown', 11, 'https://github.com/0xkoda/eth-mcp', NULL, 0, 'https://github.com/0xkoda.png?size=128', '2026-03-09T05:21:01.891597+00:00'),
  ('rust-docs', 'Rust Docs', 'This MCP server fetches and returns documentation for Rust crates from docs.rs, providing essential context for LLMs working with Rust code. It implements a single tool, ''lookup_crate_docs'', which retrieves HTML documentation, converts it to plain text, and truncates it if necessary. The server is designed for easy integration with AI assistants like Claude Desktop and can be tested using the MCP Inspector.', '@0xkoda', 'development', 'Unknown', 47, 'https://github.com/0xkoda/mcp-rust-docs', NULL, 0, 'https://github.com/0xkoda.png?size=128', '2026-03-09T05:21:01.891619+00:00'),
  ('ctftime', 'CTFtime', 'Provides programmatic access to CTFtime.org data for cybersecurity competition tracking and analysis. Offers tools for retrieving upcoming and historical CTF events, team rankings (global and by country), detailed event information including format and weight, competition results, and event search capabilities. Features specialized prompts for analyzing CTF events, identifying beginner-friendly competitions, and generating team performance reports, making it useful for CTF participants planning their competition schedule, researchers studying the competitive cybersecurity landscape, and teams tracking their performance against peers.', '@0x-professor', 'ai-ml', 'Unknown', 3, 'https://github.com/0x-professor/ctf-time-mcp', NULL, 0, 'https://github.com/0x-professor.png?size=128', '2026-03-09T05:21:01.891668+00:00'),
  ('ui-analyzer', 'UI Analyzer', 'Analyzes website UI using Playwright browser automation to detect layout issues, identify broken elements, and generate precise CSS/HTML fixes with framework-specific solutions for React, Vue, Angular, and popular UI libraries.', '@0x-professor', 'ai-ml', 'Unknown', 4, 'https://github.com/0x-professor/uianalyzermcp', NULL, 0, 'https://github.com/0x-professor.png?size=128', '2026-03-09T05:21:01.891701+00:00'),
  ('base-wallet', 'Base Wallet', 'A lightweight MCP server built with TypeScript and Coinbase''s AgentKit, designed to provide a flexible wallet interaction framework using Viem on the Base Sepolia testnet. The implementation sets up a standard MCP server with tool listing and execution capabilities, generating a random wallet client and exposing blockchain-related actions through a stdio transport mechanism.', '@0xrag', 'development', 'Unknown', 0, 'https://github.com/0xrag/mcp', NULL, 0, 'https://github.com/0xrag.png?size=128', '2026-03-09T05:21:01.891726+00:00'),
  ('summarizer', 'Summarizer', 'MCP Server for AI Summarization, Support for multiple content types:
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('agent-rules', 'Agent Rules', 'Agent Rules MCP server by 4regab that enables AI assistants to fetch coding rules and best practices on-demand from GitHub repositories, eliminating the need for local rule files by providing remote access to development standards. Built with TypeScript and the MCP SDK, the implementation offers two core tools: get_rules for retrieving specific rule domains and list_rules for discovering available domains, with intelligent caching, rate limit handling, and support for multiple file formats including .md, .mdc, .chatmode.md, and .instructions.md files. The server includes fallback mechanisms for unauthenticated GitHub API access, metadata extraction from YAML frontmatter, and can be configured to work with any GitHub repository containing rule collections, making it valuable for development teams maintaining consistent coding standards across projects, AI agents requiring context-specific development guidance, and organizations wanting to centralize and share their coding best practices without manual file management.', '@4regab', 'development', 'Unknown', 14, 'https://github.com/4regab/agent-rules-mcp', 'agent-rules-mcp', 2331, 'https://github.com/4regab.png?size=128', '2026-03-09T05:21:01.892923+00:00'),
  ('sutra', 'Sutra', 'Provides a context engineering framework for AI agents with cognitive tools, memory structures, and agent patterns. Enables structured context management and pattern-based agent behavior.', '@4rgon4ut', 'ai-ml', 'Unknown', 0, 'https://github.com/4rgon4ut/sutra', NULL, 0, 'https://github.com/4rgon4ut.png?size=128', '2026-03-09T05:21:01.892949+00:00'),
  ('container-sandbox', 'Container Sandbox', 'Container-MCP provides a secure, sandboxed environment for executing code, running commands, accessing files, and performing web operations on behalf of large language models. Built by 54rt1n, it implements multiple layers of security including container isolation, AppArmor profiles, Firejail sandboxing, and strict resource limits to ensure safe execution of potentially risky operations. The architecture uses domain-specific managers for different operation types (Bash, Python, file operations, web browsing) and runs inside an Ubuntu container with carefully controlled permissions and access restrictions. This implementation is particularly valuable for AI workflows requiring secure tool execution without exposing the host system to potential risks.', '@54rt1n', 'development', 'Unknown', 19, 'https://github.com/54rt1n/container-mcp', NULL, 0, 'https://github.com/54rt1n.png?size=128', '2026-03-09T05:21:01.892979+00:00'),
  ('ens-dao-operations', 'ENS DAO Operations', 'This MCP server for local Ethereum node operations, developed by 5pence, provides a simplified interface for interacting with ENS DAO functions. Built with TypeScript and leveraging the ethers.js library, it offers a streamlined approach to Ethereum network interactions. The server implements environment variable configuration for node URL management and error handling. By abstracting the complexities of direct Ethereum node communication, it enables AI systems to easily perform ENS DAO operations. This implementation is particularly valuable for applications requiring programmatic access to ENS DAO functions, facilitating use cases such as automated domain management, governance participation, and decentralized identity operations within the Ethereum ecosystem.', '@5ajaki', 'development', 'Unknown', 1, 'https://github.com/5ajaki/veri5ight', NULL, 0, 'https://github.com/5ajaki.png?size=128', '2026-03-09T05:21:01.893011+00:00'),
  ('etherscan-tools', 'Etherscan Tools', 'This MCP Etherscan server, developed by 5pence, provides Ethereum blockchain data tools via Etherscan''s API. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers features like balance checking, transaction history viewing, token transfer tracking, contract ABI fetching, gas price monitoring, and ENS name resolution. The implementation focuses on simplifying access to Ethereum blockchain data through a standardized MCP interface. It''s particularly useful for developers and analysts looking to incorporate Ethereum data into their applications without dealing directly with Etherscan''s API complexities, enabling use cases like wallet monitoring, transaction analysis, and smart contract interactions.', '@5ajaki', 'development', 'Unknown', 1, 'https://github.com/5ajaki/mcp-etherscan-server', NULL, 0, 'https://github.com/5ajaki.png?size=128', '2026-03-09T05:21:01.893041+00:00'),
  ('safe-wallet', 'Safe Wallet', 'This Safe MCP server, developed by 5pence, enables interaction with Safe (formerly Gnosis Safe) smart contract wallets through the Model Context Protocol. Built with TypeScript and leveraging the MCP SDK, it provides tools for querying Safe transactions, retrieving multisig transaction details, and decoding transaction data. The implementation focuses on simplifying access to Safe''s functionality through a standardized interface, with default integration to the Safe Transaction API mainnet endpoint. It''s particularly useful for developers and AI models needing to interact with Safe wallets, enabling use cases like transaction monitoring, multisig management, and smart contract interaction analysis without dealing directly with blockchain complexities.', '@5ajaki', 'development', 'Unknown', 2, 'https://github.com/5ajaki/safe-mcp-server', NULL, 0, 'https://github.com/5ajaki.png?size=128', '2026-03-09T05:21:01.893072+00:00'),
  ('sympy-calculator', 'SymPy Calculator', 'MCP Calculate Server provides mathematical computation capabilities through a Python-based server that leverages the SymPy library for symbolic mathematics. Developed by 611711Dark, this implementation enables AI assistants to perform complex calculations, equation solving, and symbolic manipulation without needing direct access to mathematical libraries. The server requires Python 3.11 or higher and depends on both the MCP framework and SymPy, making it ideal for use cases requiring advanced mathematical operations within AI assistant conversations.', '@611711dark', 'ai-ml', 'Unknown', 5, 'https://github.com/611711dark/mcp_calculate_server', NULL, 0, 'https://github.com/611711dark.png?size=128', '2026-03-09T05:21:01.893114+00:00'),
  ('claude-team', 'Claude Team', 'Claude Team orchestrates multiple AI models (Claude, GPT, Gemini) as specialized agents with distinct roles like tech lead and domain experts for collaborative software development. It provides conversation management, resumable workflows, caching, token tracking, and webhook integration for coordinating complex development tasks across different AI providers. The implementation supports fallback strategies, streaming responses, and configurable agent templates with five pre-built workflows for code generation, bug fixing, refactoring, review, and documentation.', '@7836246', 'development', 'Unknown', 46, 'https://github.com/7836246/claude-team-mcp', NULL, 0, 'https://github.com/7836246.png?size=128', '2026-03-09T05:21:01.893142+00:00'),
  ('zip-compression', 'ZIP Compression', 'A Model Context Protocol server that provides ZIP compression capabilities using fastMCP and zip.js. This implementation allows AI assistants to compress and decompress files directly through MCP, enabling efficient file handling without leaving the conversation interface. The server exposes compression utilities as tools that can be called programmatically, making it valuable for workflows involving file management, data transfer, and storage optimization.', '@7gugu', 'ai-ml', 'Unknown', 12, 'https://github.com/7gugu/zip-mcp', NULL, 0, 'https://github.com/7gugu.png?size=128', '2026-03-09T05:21:01.893181+00:00'),
  ('autonome', 'Autonome', 'Enables autonomous control over wake/sleep cycles and federation with other AI agents. Provides scheduled wake messages via launchd, configurable heartbeat pings to maintain context during long sessions, and async task dispatch for coordinating work across multiple AI systems. Uses AppleScript for Claude Desktop interaction on macOS, SQLite for state management, and includes session logging and maintenance tracking.', '@8agana', 'databases', 'Unknown', 1, 'https://github.com/8agana/autonome-mcp', NULL, 0, 'https://github.com/8agana.png?size=128', '2026-03-09T05:21:01.893192+00:00'),
  ('touchdesigner', 'TouchDesigner', 'TouchDesigner MCP Server provides a bridge between AI assistants and TouchDesigner, a visual programming environment for real-time interactive content. Built by 8beeeaaat, it offers tools for creating, manipulating, and controlling TouchDesigner nodes through a REST API. The server implements a client-server architecture with TypeScript and Python components, enabling operations like executing Python scripts, managing node properties, and retrieving class information. It''s particularly valuable for digital artists, VJ performers, and interactive installation designers who want to control TouchDesigner projects through natural language without manually navigating the TouchDesigner interface.', '@8beeeaaat', 'development', 'Unknown', 214, 'https://github.com/8beeeaaat/touchdesigner-mcp', 'touchdesigner-mcp-server', 7575, 'https://github.com/8beeeaaat.png?size=128', '2026-03-09T05:21:01.893219+00:00'),
  ('activitywatch', 'ActivityWatch', 'This MCP server connects to ActivityWatch, enabling LLMs like Claude to interact with time tracking data. It provides tools for listing buckets, executing AQL queries, and retrieving raw events from any bucket. Developed by Matt Vogel, it''s designed to enhance productivity analysis and time management capabilities for AI assistants working with personal activity data.', '@8bitgentleman', 'ai-ml', 'Unknown', 50, 'https://github.com/8bitgentleman/activitywatch-mcp-server', NULL, 0, 'https://github.com/8bitgentleman.png?size=128', '2026-03-09T05:21:01.893257+00:00'),
  ('open-library', 'Open Library', 'Integrates with the Internet Archive''s Open Library API for book and author information retrieval. Provides tools for searching books by title, searching authors by name, retrieving detailed author information, generating author photo URLs, looking up book cover images, and fetching comprehensive book data via ISBN, LCCN, OCLC, or OLID identifiers. Returns structured JSON data for all queries.', '@8ensmith', 'ai-ml', 'Unknown', 60, 'https://github.com/8ensmith/mcp-open-library', NULL, 0, 'https://github.com/8ensmith.png?size=128', '2026-03-09T05:21:01.893290+00:00'),
  ('microsoft-flight-simulator-sdk', 'Microsoft Flight Simulator SDK', 'MSFS SDK MCP server provides TypeScript-based access to Microsoft Flight Simulator SDK documentation through web scraping and natural language processing. The implementation fetches documentation from docs.flightsimulator.com, supports category-based searching across contents, index, and glossary sections, and includes a natural language service that parses commands like ''Search livery op msfs sdk'' into structured tool calls. Built with Cheerio for HTML parsing and Puppeteer for web automation, it''s designed for flight simulation developers who need quick access to MSFS SDK documentation without manually browsing the official documentation site, enabling workflows like finding specific API references, code examples, and technical specifications through conversational queries.', '@90barricade93', 'development', 'Unknown', 4, 'https://github.com/90barricade93/msfs-sdk-mcp', NULL, 0, 'https://github.com/90barricade93.png?size=128', '2026-03-09T05:21:01.893325+00:00'),
  ('notes', 'Notes', 'This MCP notes server, developed by an unnamed author, provides a simple yet powerful tool for recording and managing notes with AI models. Built using TypeScript and leveraging the Model Context Protocol SDK, it offers both an MCP server and a web server interface for flexible note-taking capabilities. The implementation uses DynamoDB for data storage and includes features for creating, retrieving, and managing notes. By abstracting the complexities of note management and AI integration, it enables seamless interaction between AI assistants and user-generated content. This server is particularly useful for applications requiring persistent memory and context management, facilitating use cases such as personal assistants, knowledge management systems, and collaborative AI-enhanced note-taking platforms.', '@9ninety', 'development', 'Unknown', 37, 'https://github.com/9ninety/mcpnotes', 'mcp-notes', 747, 'https://github.com/9ninety.png?size=128', '2026-03-09T05:21:01.893357+00:00'),
  ('web-security-scanner', 'Web Security Scanner', 'MCP Server Pentest is a browser automation tool that enables AI assistants to perform security testing for web applications, specifically focusing on XSS and SQL injection vulnerability detection. Built on Playwright and Firefox, it provides tools for automatically testing URL parameters against common attack vectors, capturing screenshots of vulnerable pages, and manipulating web elements through various interaction methods. The server includes comprehensive error handling with fallback mechanisms for strict mode violations, making it particularly valuable for security professionals who need to conduct preliminary vulnerability assessments without leaving their AI assistant interface.', '@9olidity', 'databases', 'Unknown', 22, 'https://github.com/9olidity/mcp-server-pentest', NULL, 0, 'https://github.com/9olidity.png?size=128', '2026-03-09T05:21:01.893370+00:00'),
  ('rhino3d', 'Rhino3D', 'RhinoMCP connects Rhino3D to Claude AI through a WebSocket-based bridge, enabling AI-assisted 3D modeling capabilities. The implementation consists of three main components: a socket server running inside Rhino''s Python environment, a Python client that communicates with the Rhino plugin, and an MCP server that exposes Rhino functionality as tools. It allows Claude to create and manipulate 3D geometry, run Python scripts in Rhino''s context, and interact with the modeling environment, making it particularly valuable for architectural design, product development, and other 3D modeling workflows that benefit from AI assistance.', '@a01110946', 'development', 'Unknown', 11, 'https://github.com/a01110946/rhinomcp', NULL, 0, 'https://github.com/a01110946.png?size=128', '2026-03-09T05:21:01.893398+00:00'),
  ('expose-json-rpc-proxy', 'Expose (JSON-RPC Proxy)', 'Expose is a proxy server implementation that enables communication between clients and MCP-compatible services through JSON-RPC. Built by a0dotrun, it provides a Go-based middleware that handles standard MCP methods like ''initialize'', ''tools/list'', and ''tools/call'' by forwarding requests to a configured backend URL while maintaining proper error handling and response formatting. The server can operate over standard I/O streams with graceful shutdown capabilities, making it suitable for integrating existing services with MCP clients or creating lightweight proxies between different MCP implementations.', '@a0dotrun', 'ai-ml', 'Unknown', 20, 'https://github.com/a0dotrun/expose', NULL, 0, 'https://github.com/a0dotrun.png?size=128', '2026-03-09T05:21:01.893445+00:00'),
  ('postgresql', 'PostgreSQL', 'A PostgreSQL database integration server that provides type-safe CRUD operations for user data through MCP tools. Built with TypeScript and Prisma, it enables easy database interactions with a standardized interface, supporting operations like retrieving, adding, updating, and deleting user records with robust input validation.', '@a21071', 'databases', 'Unknown', 0, 'https://github.com/a21071/mcp-postgres', NULL, 0, 'https://github.com/a21071.png?size=128', '2026-03-09T05:21:01.893455+00:00'),
  ('a2a-bridge', 'A2A Bridge', 'A2A MCP Server bridges the Model Context Protocol with Google''s Agent-to-Agent protocol, enabling MCP clients like Claude to discover, register, and communicate with A2A agents through a unified interface. Developed by GongRzhe, it provides tools for agent management (registration, listing, unregistration), message sending with both synchronous and streaming responses, and task management including result retrieval and cancellation. The implementation supports multiple transport types (stdio, HTTP, SSE), includes persistent storage for agent registrations and task mappings, and handles the protocol translation between MCP''s tool-based interface and A2A''s JSON-RPC messaging, making it valuable for integrating existing A2A agents into MCP-compatible AI assistant workflows.', '@gongrzhe', 'communication', 'Unknown', 143, 'https://github.com/gongrzhe/a2a-mcp-server', 'a2a-mcp-server', 9564, 'https://github.com/gongrzhe.png?size=128', '2026-03-09T05:21:01.893497+00:00'),
  ('clamav-virus-scanner', 'ClamAV Virus Scanner', 'ClamAV MCP provides virus scanning capabilities for files by integrating with the ClamAV antivirus engine. This implementation allows AI assistants to scan files for malware by accepting base64-encoded file data and returning scan results through a simple API endpoint. The server runs as a FastMCP instance that processes scan requests, temporarily stores files for scanning, and executes the clamscan command with proper error handling and cleanup. Particularly useful for security-focused applications that need to validate file safety before processing.', '@a2amarket', 'development', 'Unknown', 2, 'https://github.com/a2amarket/mcp-clamav', NULL, 0, 'https://github.com/a2amarket.png?size=128', '2026-03-09T05:21:01.893523+00:00'),
  ('tagesschau', 'Tagesschau', 'Provides a bridge to the Tagesschau news API, enabling AI assistants to fetch and analyze German news articles from categories like domestic, foreign, economic and sports coverage. Built with Go and the MCP protocol, it exposes tools for retrieving latest headlines and detailed article content through a clean interface. This implementation is particularly valuable for users who want to access and analyze German news content programmatically through natural language interaction.', '@a2xdeveloper', 'development', 'Unknown', 3, 'https://github.com/a2xdeveloper/tagesschau-mcp-server', NULL, 0, 'https://github.com/a2xdeveloper.png?size=128', '2026-03-09T05:21:01.893549+00:00'),
  ('ansible-tower', 'Ansible Tower', 'Ansible Tower MCP Server provides a bridge between LLMs and Ansible Tower/AWX instances, enabling AI assistants to manage infrastructure automation tasks through a comprehensive API interface. The implementation supports inventory, host, group, job template, project, credential, and organization management with secure authentication options via username/password or token. Built with Python using the FastMCP framework, it handles pagination, error management, and various response formats while maintaining secure connections to Ansible Tower instances. This server is particularly valuable for DevOps workflows where infrastructure management and deployment automation need to be integrated directly into AI assistant conversations.', '@a37ai', 'productivity', 'Unknown', 9, 'https://github.com/a37ai/ansible-tower-mcp', NULL, 0, 'https://github.com/a37ai.png?size=128', '2026-03-09T05:21:01.893596+00:00'),
  ('wolfram-mathematica', 'Wolfram Mathematica', 'This MCP server provides a bridge to Wolfram Mathematica, enabling AI assistants to execute Wolfram Language code in secure, session-based environments. It offers three core tools: creating new Mathematica sessions with unique animal-themed identifiers (replacing UUIDs for better LLM transcription accuracy), executing arbitrary Wolfram Language code within specified sessions, and properly terminating sessions to release resources. The implementation uses the wolframclient library and requires a local Wolfram Engine or Mathematica installation, making it valuable for mathematical computations, symbolic algebra, data analysis, and scientific modeling tasks where the full power of Mathematica''s computational capabilities can be leveraged through natural language interactions.', '@aac6fef', 'development', 'Unknown', 2, 'https://github.com/aac6fef/mathematica_mcp', NULL, 0, 'https://github.com/aac6fef.png?size=128', '2026-03-09T05:21:01.893626+00:00'),
  ('akshare', 'AkShare', 'An MCP server for stock and cryptocurrency data built by aahl using the akshare Python library, providing access to Chinese financial markets through fastmcp framework. The implementation includes caching mechanisms with both in-memory TTL cache and disk-based persistence to optimize API performance, and is packaged for deployment via PyPI and Docker containers. It exposes akshare''s extensive financial data APIs through MCP tools, making it useful for financial analysis, market research, algorithmic trading development, and building AI assistants that need access to real-time and historical Chinese stock and crypto market data.', '@aahl', 'cloud', 'Unknown', 366, 'https://github.com/aahl/mcp-aktools', NULL, 0, 'https://github.com/aahl.png?size=128', '2026-03-09T05:21:01.893648+00:00'),
  ('notify', 'Notify', 'Enables sending notifications across multiple messaging platforms including WeChat Work, DingTalk, Telegram, Bark, Lark, Feishu, Ntfy, PushPlus, and Home Assistant. Supports text, markdown, images, videos, audio, file attachments, and text-to-speech conversion. Provides flexible configuration through environment variables with per-message override capabilities.', '@aahl', 'communication', 'Unknown', 30, 'https://github.com/aahl/mcp-notify', NULL, 0, 'https://github.com/aahl.png?size=128', '2026-03-09T05:21:01.893673+00:00'),
  ('okx', 'OKX', 'Integrates with OKX cryptocurrency exchange to provide account management, trading operations, and market data access. Supports configuration retrieval, balance checking, position viewing, order placement and cancellation, order history, and cryptocurrency ranking information through ticker data.', '@aahl', 'finance', 'Unknown', 2, 'https://github.com/aahl/mcp-okx', NULL, 0, 'https://github.com/aahl.png?size=128', '2026-03-09T05:21:01.893712+00:00'),
  ('video-streaming-search', 'Video Streaming Search', 'Provides AI assistants with the ability to search for video content across Chinese streaming platforms including LunaTV and MoonTV. Supports retrieving playback URLs for TV series and anime, with direct playback control for Xiaomi TV devices, projectors, and set-top boxes. Built with Python using the FastMCP framework, it can be deployed via uvx, Docker, or as a Home Assistant OS add-on.', '@aahl', 'cloud', 'Unknown', 22, 'https://github.com/aahl/mcp-vods', NULL, 0, 'https://github.com/aahl.png?size=128', '2026-03-09T05:21:01.893733+00:00'),
  ('quickbooks-time', 'QuickBooks Time', 'This QuickBooks Time MCP server, developed by an AI assistant, provides a unified interface to QuickBooks Time API functionality. Built with Python and leveraging libraries like requests and pydantic, it offers a comprehensive set of endpoints for managing jobcodes, timesheets, users, projects, and generating reports. The server implements robust error handling, pagination support, and date parameter formatting. By consolidating multiple QuickBooks Time services into a single, efficient interface, it simplifies integration and data access for developers. This implementation is particularly valuable for businesses using QuickBooks Time, enabling use cases such as automated time tracking, payroll processing, project management, and custom reporting workflows.', '@aallsbury', 'development', 'Unknown', 10, 'https://github.com/aallsbury/qb-time-mcp-server', NULL, 0, 'https://github.com/aallsbury.png?size=128', '2026-03-09T05:21:01.893762+00:00'),
  ('python-sandbox', 'Python Sandbox', 'This MCP server provides secure Python code execution capabilities through a containerized sandbox environment optimized for data science and machine learning workflows. Built by aamir-gmail specifically for LM Studio integration, it features automatic matplotlib figure persistence, per-execution isolation with unique run directories, and dual deployment modes supporting both LM Studio''s native MCP chat interface and a Gradio web UI through the developer API. The implementation includes a comprehensive data science stack (numpy, pandas, scikit-learn, matplotlib, seaborn, xgboost) with automatic artifact serving, making it valuable for interactive data analysis, visualization generation, and machine learning experimentation where users need reliable code execution with persistent file outputs accessible via web URLs.', '@aamir-gmail', 'development', 'Unknown', 1, 'https://github.com/aamir-gmail/lm_studio_mcp', NULL, 0, 'https://github.com/aamir-gmail.png?size=128', '2026-03-09T05:21:01.893792+00:00'),
  ('netbird', 'Netbird', 'A Netbird API integration server that enables AI assistants to manage virtual private networks through natural language. Built by aantti and derived from Grafana''s MCP implementation, it provides tools for listing and managing peers, groups, and access policies in a Netbird network. Particularly valuable for network administrators who want to monitor and configure their Netbird VPN infrastructure through conversational AI.', '@aantti', 'ai-ml', 'Unknown', 42, 'https://github.com/aantti/mcp-netbird', NULL, 0, 'https://github.com/aantti.png?size=128', '2026-03-09T05:21:01.893828+00:00'),
  ('bazel', 'Bazel', 'A Bazel integration server for the MCP protocol that enables AI assistants to interact with Bazel build systems. It provides tools for building targets, running tests, finding dependencies and reverse dependencies, and identifying source files within a Bazel workspace. The implementation wraps Bazel command-line operations in a structured API, making it easier for AI systems to analyze and manipulate Bazel projects without needing to understand the underlying command syntax.', '@aaomidi', 'development', 'Unknown', 11, 'https://github.com/aaomidi/mcp-bazel', NULL, 0, 'https://github.com/aaomidi.png?size=128', '2026-03-09T05:21:01.893864+00:00'),
  ('aapanel', 'aaPanel', 'aaPanel MCP Server provides a bridge between AI assistants and aaPanel web hosting control panel, enabling management of websites, databases, Docker containers, and system resources through a standardized interface. Built with Go, this implementation authenticates with the aaPanel API using environment variables for base URL and API token, then translates MCP tool calls into appropriate aaPanel API requests. The server exposes functionality for retrieving system information, managing PHP websites, querying MySQL databases, handling Docker containers and images, and configuring email accounts, making it ideal for automating web hosting administration tasks through AI-powered workflows.', '@aapanel', 'databases', 'Unknown', 11, 'https://github.com/aapanel/mcp-server', NULL, 0, 'https://github.com/aapanel.png?size=128', '2026-03-09T05:21:01.893878+00:00'),
  ('opendia', 'OpenDia', 'This MCP server provides AI assistants with OpenDia diagram creation capabilities, built by the OpenDia Team using Node.js with Express, WebSocket support, and CORS handling for cross-origin requests. The implementation offers a lightweight web server architecture with configurable ports for both main service and health monitoring, featuring environment-based configuration and a binary executable for easy deployment. Built with minimal dependencies focusing on real-time communication through WebSockets and HTTP API endpoints, it serves developers creating visual diagrams through conversational interfaces, technical documentation workflows requiring dynamic diagram generation, and collaborative environments where real-time diagram editing enhances productivity without complex setup requirements.', '@aaronjmars', 'ai-ml', 'Unknown', 1780, 'https://github.com/aaronjmars/opendia', 'opendia', 3259, 'https://github.com/aaronjmars.png?size=128', '2026-03-09T05:21:01.893930+00:00'),
  ('secure-github-ops', 'Secure GitHub Ops', 'A GitHub automation server that implements an approval gate pattern for safe AI-driven repository operations. Every write operation (creating issues, opening pull requests, adding comments) creates a pending action that requires explicit admin approval before execution. Features role-based access control with operator and admin roles, comprehensive logging with correlation IDs, rate limiting, retry logic with exponential backoff, and repository access restrictions.', '@aaronmurillo01', 'development', 'Unknown', 0, 'https://github.com/aaronmurillo01/secure-github-ops', NULL, 0, 'https://github.com/aaronmurillo01.png?size=128', '2026-03-09T05:21:01.893954+00:00'),
  ('sql-server', 'SQL Server', 'This MCP server provides robust SQL Server database access for AI agents through a well-architected .NET application built with Akka.NET for internal coordination and the official MCP C# SDK. Created by Aaron Stannard to address reliability issues with existing database MCP solutions, particularly on Windows, it offers three core tools: execute_sql for running any SQL query, list_tables for schema discovery with row counts, and list_schemas for database exploration. The implementation includes comprehensive error handling, T-SQL syntax validation to prevent invalid inputs from AI agents, automatic connection validation, and Docker support with multi-platform container builds, making it valuable for AI-powered database administration, data analysis workflows, and applications requiring reliable SQL Server integration across Windows, macOS, and Linux environments.', '@aaronontheweb', 'databases', 'Unknown', 142, 'https://github.com/aaronontheweb/mssql-mcp', NULL, 0, 'https://github.com/aaronontheweb.png?size=128', '2026-03-09T05:21:01.894189+00:00'),
  ('confluence-cloud', 'Confluence Cloud', 'This Confluence Cloud MCP server, developed using TypeScript and the Model Context Protocol SDK, provides a standardized interface for AI assistants to interact with Atlassian Confluence Cloud. It offers tools for space management, page operations, content searching, and label handling, enabling seamless integration of Confluence functionality into AI workflows. The implementation stands out by abstracting Confluence''s API complexities, allowing AI models to perform tasks like creating pages, managing content, and retrieving information without direct API knowledge. It''s particularly valuable for teams looking to automate documentation processes, enhance knowledge management, or build AI-powered tools that leverage Confluence data and capabilities.', '@aaronsb', 'development', 'Unknown', 15, 'https://github.com/aaronsb/confluence-cloud-mcp', NULL, 0, 'https://github.com/aaronsb.png?size=128', '2026-03-09T05:21:01.894224+00:00'),
  ('google-workspace', 'Google Workspace', 'This Google Workspace MCP server, developed by Aaron Bockelie, enables AI agents to interact with Gmail and Google Calendar through a simplified interface. Built with TypeScript and leveraging the Google APIs, it provides functionality for email operations, calendar management, and multi-account support. The implementation focuses on robust OAuth handling, detailed error messaging, and a modular design for easy expansion to additional Google services. It''s particularly useful for AI assistants and applications needing seamless integration with Google Workspace, enabling use cases such as email triage, meeting scheduling, and productivity automation without dealing directly with the complexities of individual Google APIs.', '@aaronsb', 'development', 'Unknown', 121, 'https://github.com/aaronsb/google-workspace-mcp', NULL, 0, 'https://github.com/aaronsb.png?size=128', '2026-03-09T05:21:01.894257+00:00'),
  ('jira-insights', 'Jira Insights', 'Jira Insights MCP provides tools for managing Jira Insights (JSM) asset schemas through the Model Context Protocol. Built by aaronsb, it enables CRUD operations on object schemas, object types, and objects in Jira Insights, with support for AQL (Atlassian Query Language) queries. The implementation is containerized with Docker for easy deployment and requires Jira API credentials for authentication. This server is particularly valuable for teams that need to programmatically manage their Jira Insights assets without leaving the conversation interface, streamlining workflows for IT asset management and configuration tracking.', '@aaronsb', 'cloud', 'Unknown', 2, 'https://github.com/aaronsb/jira-insights-mcp', NULL, 0, 'https://github.com/aaronsb.png?size=128', '2026-03-09T05:21:01.894280+00:00'),
  ('obsidian-semantic', 'Obsidian Semantic', 'Semantic MCP server for Obsidian by Aaron Bockelie that provides AI-optimized access to Obsidian vaults through five intelligent operations: vault (file management with fragment retrieval), edit (smart editing with auto-buffering), view (content navigation), workflow (contextual suggestions), and system (server operations). The implementation features a sophisticated fragment retrieval system with three indexing strategies (adaptive, proximity-based, and semantic chunking) that automatically selects the optimal approach based on query characteristics, plus a state token system that tracks context to provide intelligent workflow hints and prevent common mistakes. Built with TypeScript and designed for AI assistants working with knowledge management workflows, it serves users who need efficient vault exploration, content editing with fuzzy matching and recovery mechanisms, and context-aware suggestions that guide productive interactions with large Obsidian knowledge bases.', '@aaronsb', 'development', 'Unknown', 33, 'https://github.com/aaronsb/obsidian-semantic-mcp', 'obsidian-semantic-mcp', 1567, 'https://github.com/aaronsb.png?size=128', '2026-03-09T05:21:01.894322+00:00'),
  ('covid-19-statistics', 'COVID-19 Statistics', 'COVID-19 MCP Server provides real-time COVID-19 statistics for any country by connecting to the disease.sh API. The server exposes a single tool called getCovidStatsByCountry that fetches comprehensive data including cases, deaths, recoveries, and testing information when given a country name. Built with TypeScript and the MCP SDK, it runs on stdio transport for seamless integration with Claude Desktop, making it useful for researchers, journalists, or anyone needing quick access to pandemic data without leaving their conversation interface.', '@aarushkx', 'development', 'Unknown', 4, 'https://github.com/aarushkx/covid-mcp-server', NULL, 0, 'https://github.com/aarushkx.png?size=128', '2026-03-09T05:21:01.894350+00:00'),
  ('character-tools', 'Character Tools', 'Addresses the fundamental challenge LLMs face with character-level operations due to tokenization by providing precise tools for counting letters, analyzing character frequencies, spelling words character-by-character, accessing characters by position, and comparing text strings. Includes a curated database of commonly miscounted words like ''strawberry'' and ''mississippi'' along with visual breakdowns and batch processing capabilities for improved accuracy in tasks requiring exact character-level precision.', '@aaryan-kapoor', 'databases', 'Unknown', 3, 'https://github.com/aaryan-kapoor/mcp-character-tools', NULL, 0, 'https://github.com/aaryan-kapoor.png?size=128', '2026-03-09T05:21:01.894362+00:00'),
  ('open-web-search', 'Open Web Search', 'This MCP server provides AI assistants with web search capabilities across multiple search engines including Bing, Baidu, Brave, DuckDuckGo, and Exa, plus specialized content extraction from Chinese platforms like CSDN, Zhihu, and LinuxDo. Built using TypeScript with axios for HTTP requests, cheerio for HTML parsing, and JSDOM for content processing, it features configurable search engine selection, site-specific search filtering, and dedicated article content extraction that bypasses anti-bot measures using realistic browser headers and cookies. The implementation includes comprehensive error handling, result pagination, and supports both general web search and targeted content retrieval from technical forums and knowledge platforms, making it valuable for research workflows, content analysis, and building AI assistants that need programmatic access to Chinese technical content and general web search results without manual browsing.', '@aas-ee', 'development', 'Unknown', 748, 'https://github.com/aas-ee/open-websearch', NULL, 0, 'https://github.com/aas-ee.png?size=128', '2026-03-09T05:21:01.894398+00:00'),
  ('bitbucket', 'Bitbucket', 'Bitbucket MCP server that provides tools for managing repositories, pull requests, and workspaces through Atlassian''s REST APIs. Built with TypeScript and featuring robust error handling, pagination support, and detailed logging, it enables AI assistants to list workspaces, browse repositories, and interact with pull requests. The implementation uses a controller-service architecture with standardized formatters for consistent markdown output, making it particularly valuable for developers who want to monitor and manage Bitbucket resources directly through conversational AI.', '@aashari', 'development', 'Unknown', 123, 'https://github.com/aashari/mcp-server-atlassian-bitbucket', '@aashari/mcp-server-atlassian-bitbucket', 77370, 'https://github.com/aashari.png?size=128', '2026-03-09T05:21:01.894428+00:00'),
  ('code-context-provider', 'Code Context Provider', 'Code Context Provider MCP analyzes project directories to extract code structure and symbols using Tree-sitter parsers. It provides tools for generating directory trees and performing deep code analysis of JavaScript, TypeScript, and Python files, extracting functions, variables, classes, imports, and exports. The implementation handles gitignore patterns, supports customizable analysis depth, and automatically downloads required WASM parsers. Particularly useful for AI assistants that need to quickly understand project structure and code organization when starting new programming tasks.', '@ab498', 'development', 'Unknown', 22, 'https://github.com/ab498/code-context-provider-mcp', 'code-context-provider-mcp', 5809, 'https://github.com/ab498.png?size=128', '2026-03-09T05:21:01.894456+00:00'),
  ('computer-control', 'Computer Control', 'Computer Control MCP provides computer automation capabilities through a server that enables AI assistants to control mouse movements, keyboard input, take screenshots, perform OCR, and manage windows. Built with PyAutoGUI, RapidOCR, and ONNXRuntime, it offers similar functionality to Anthropic''s ''computer-use'' tool but with zero external dependencies. The implementation supports operations like clicking, typing, dragging, capturing screen content with text recognition, and window management, making it particularly useful for automating desktop tasks and enabling AI systems to interact directly with graphical user interfaces.', '@ab498', 'productivity', 'Unknown', 120, 'https://github.com/ab498/computer-control-mcp', 'computer-control-mcp', 201297, 'https://github.com/ab498.png?size=128', '2026-03-09T05:21:01.894500+00:00'),
  ('bitcoin', 'Bitcoin', 'This MCP server provides integration with Bitcoin, enabling interactions with the Bitcoin network and blockchain data. Developed using TypeScript and the Model Context Protocol SDK, it offers functionality for querying transaction data, wallet information, and network statistics. The implementation focuses on providing a standardized interface for Bitcoin operations, supporting use cases such as transaction monitoring, wallet management, and blockchain analysis. By leveraging the Blockstream API, it allows AI models to access real-time Bitcoin data, making it valuable for financial applications, cryptocurrency tracking, and blockchain-based decision-making systems.', '@abdelstark', 'development', 'Unknown', 73, 'https://github.com/abdelstark/bitcoin-mcp', 'bitcoin-mcp', 6355, 'https://github.com/abdelstark.png?size=128', '2026-03-09T05:21:01.894528+00:00'),
  ('lightning-nostr', 'Lightning Nostr', 'This Nostr MCP server, developed by an unspecified author, enables AI agents to interact with the Nostr decentralized social network protocol. Built with TypeScript and leveraging the Model Context Protocol SDK, it provides tools for posting notes and interacting with Nostr relays. The implementation focuses on simplifying Nostr interactions, offering functionality to publish content to the network. It integrates with LNbits for Lightning Network payments, allowing for potential monetization of posts. This server is particularly useful for applications requiring programmatic Nostr engagement, enabling use cases such as automated content publishing, social media management, and decentralized communication without directly dealing with Nostr protocol complexities.', '@abdelstark', 'development', 'Unknown', 6, 'https://github.com/abdelstark/lightning-mcp', 'nostr-mcp', 1336, 'https://github.com/abdelstark.png?size=128', '2026-03-09T05:21:01.894560+00:00'),
  ('nostr', 'Nostr', 'This Nostr MCP server enables AI agents to interact with the decentralized Nostr social network protocol. Built with TypeScript using the Model Context Protocol SDK, it provides a streamlined interface for posting notes and connecting to Nostr relays. The implementation focuses on simplifying Nostr interactions for AI systems, offering core functionality to publish content to the network. It supports both stdio and SSE server modes for flexibility in different environments. This server is particularly useful for applications requiring programmatic Nostr engagement, enabling use cases such as automated content publishing, social media management, and decentralized communication without directly handling Nostr protocol complexities.', '@abdelstark', 'development', 'Unknown', 38, 'https://github.com/abdelstark/nostr-mcp', NULL, 0, 'https://github.com/abdelstark.png?size=128', '2026-03-09T05:21:01.894591+00:00'),
  ('malware-analyzer', 'Malware Analyzer', 'MalwareAnalyzerMCP provides specialized terminal access for malware analysis through the Model Context Protocol. Developed by Abdessamad El Amrani, it implements a configuration-driven approach that exposes common malware analysis tools like ''strings'', ''file'', ''hexdump'', ''objdump'', and ''xxd'' as structured commands with parameter validation. The server manages terminal processes with timeout handling and output buffering, making it ideal for security researchers who need to analyze suspicious files directly within Claude Desktop without switching to external tools.', '@abdessamad-elamrani', 'ai-ml', 'Unknown', 2, 'https://github.com/abdessamad-elamrani/malwareanalyzermcp', NULL, 0, 'https://github.com/abdessamad-elamrani.png?size=128', '2026-03-09T05:21:01.894638+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('code-executor', 'Code Executor', 'Universal code execution MCP server providing secure sandboxed execution of TypeScript and Python code with progressive disclosure capabilities achieving 98% token savings. Generates ergonomic wrapper functions for MCP tools instead of exposing raw schemas. Features Docker-based security with AppArmor profiles, seccomp filtering, and resource limits. Real-time output streaming via WebSocket, comprehensive audit logging, and automatic wrapper generation with sensible defaults and state management. Uses Deno for TypeScript execution with STDIO and HTTP MCP transports.', '@aberemia24', 'cloud', 'Unknown', 127, 'https://github.com/aberemia24/code-executor-mcp', NULL, 0, 'https://github.com/aberemia24.png?size=128', '2026-03-09T05:21:01.894659+00:00'),
  ('retellai-voice-services', 'RetellAI Voice Services', 'The RetellAI MCP server provides AI assistants with direct access to RetellAI''s voice services for creating and managing phone conversations. Built by abhaybabbar, this implementation exposes tools for call management, agent configuration, phone number provisioning, and voice selection through the Model Context Protocol. The server connects to RetellAI''s API using a provided API key and transforms requests and responses between MCP format and RetellAI''s native format. It''s particularly valuable for applications that need to initiate outbound calls, handle inbound calls, or create voice agents with specific personalities and capabilities for tasks like automated customer service, appointment scheduling, or information gathering.', '@abhaybabbar', 'productivity', 'Unknown', 31, 'https://github.com/abhaybabbar/retellai-mcp-server', '@abhaybabbar/retellai-mcp-server', 8197, 'https://github.com/abhaybabbar.png?size=128', '2026-03-09T05:21:01.894708+00:00'),
  ('email-validator', 'Email Validator', 'MCP-Email-Verify provides a tool for validating email addresses using the Abstract API service. The server exposes a single function that checks email validity, deliverability, and quality through comprehensive validation including format checking, SMTP verification, and identification of disposable or role-based addresses. This implementation is particularly useful for applications requiring email validation to reduce bounces, prevent fake signups, and ensure data quality in forms or user registration flows.', '@abhi5h3k', 'communication', 'Unknown', 2, 'https://github.com/abhi5h3k/mcp-email-verify', NULL, 0, 'https://github.com/abhi5h3k.png?size=128', '2026-03-09T05:21:01.894743+00:00'),
  ('url2snap-website-screenshot', 'URL2SNAP (Website Screenshot)', 'URL2SNAP is an MCP server that captures screenshots of websites through the Abstract API. It provides a simple tool that takes a URL as input and returns a local URL to access the captured screenshot. The implementation handles API requests, image processing, and local file storage, making it useful for applications that need to visualize web content without requiring users to visit the actual websites. The server runs on port 8011 and saves screenshots to a local directory for easy access.', '@abhi5h3k', 'ai-ml', 'Unknown', 1, 'https://github.com/abhi5h3k/mcp-url2snap', NULL, 0, 'https://github.com/abhi5h3k.png?size=128', '2026-03-09T05:21:01.894790+00:00'),
  ('promptheus', 'Promptheus', 'Provides intelligent prompt refinement through an adaptive questioning workflow that detects task types and optimizes prompts accordingly. Supports multiple AI providers including Google Gemini, Anthropic Claude, OpenAI, Groq, Qwen, and GLM. Features interactive and structured question modes, session history management, and privacy-preserving telemetry.', '@abhichandra21', 'productivity', 'Unknown', 15, 'https://github.com/abhichandra21/promptheus', NULL, 0, 'https://github.com/abhichandra21.png?size=128', '2026-03-09T05:21:01.894820+00:00'),
  ('btcpayserver', 'BTCPayServer', 'A BTCPayServer MCP integration built by Abhijay007 that provides complete API coverage for Bitcoin payment processing, store management, and Lightning Network operations through a service-based architecture. The implementation organizes BTCPayServer''s extensive API into 23 modular services covering payments (invoices, payment requests, pull payments), store operations (email, payment methods, payouts, rates, users, wallets), Lightning functionality (internal operations, store configuration, address management), and system administration (webhooks, notifications, API keys, user management). Built with TypeScript and error handling, it uses a discovery pattern where users can explore available services and methods before executing operations, making it ideal for e-commerce integrations, automated payment processing, multi-store management, and Bitcoin-native business applications.', '@abhijay007', 'development', 'Unknown', 2, 'https://github.com/abhijay007/btcpayserver-mcp', 'btcpayserver-mcp', 305, 'https://github.com/abhijay007.png?size=128', '2026-03-09T05:21:01.894870+00:00'),
  ('kubernetes', 'Kubernetes', 'The MCP Kubernetes Server provides a bridge between Large Language Models and Kubernetes clusters through a set of specialized tools. Built with Python using the FastMCP framework, it wraps kubectl commands to enable operations like retrieving pod information, managing deployments, switching contexts, and troubleshooting cluster issues. The server requires a configured kubectl environment and can be integrated with Claude Desktop for seamless natural language interactions with Kubernetes resources. It''s particularly valuable for DevOps workflows that benefit from conversational interfaces to Kubernetes, allowing users to create, scale, and monitor resources without remembering exact kubectl syntax.', '@abhijeetka', 'cloud', 'Unknown', 9, 'https://github.com/abhijeetka/mcp-k8s-server', NULL, 0, 'https://github.com/abhijeetka.png?size=128', '2026-03-09T05:21:01.894896+00:00'),
  ('sqlite-database', 'SQLite Database', 'A SQLite database interaction server that provides secure query execution and schema inspection capabilities for local SQLite databases. Built with FastMCP and aiosqlite, it exposes tools for retrieving database table structures and running SQL operations including SELECT, INSERT, UPDATE, and DELETE statements. The server automatically handles database connections, commits transactions for write operations, and returns structured JSON responses.', '@abhinab-handique', 'databases', 'Unknown', 1, 'https://github.com/abhinab-handique/db_talk', NULL, 0, 'https://github.com/abhinab-handique.png?size=128', '2026-03-09T05:21:01.894908+00:00'),
  ('think-tool', 'Think Tool', 'Think Tool server provides a structured way for AI assistants to maintain an explicit thought process through a session. It exposes tools for recording thoughts, retrieving the thought history, and clearing the thought log when needed. Built with TypeScript and the MCP protocol, it helps AIs break down complex reasoning tasks, verify policy compliance, and analyze tool outputs by maintaining a persistent memory of their thinking process.', '@abhinav-mangla', 'development', 'Unknown', 16, 'https://github.com/abhinav-mangla/think-tool-mcp', 'think-tool-mcp', 5104, 'https://github.com/abhinav-mangla.png?size=128', '2026-03-09T05:21:01.894934+00:00'),
  ('system-resource-monitor', 'System Resource Monitor', 'A Model Context Protocol server for real-time system monitoring, providing CPU, memory, disk, network, battery, and internet speed metrics via the systeminformation library. Developed by Abhinav, this implementation exposes both a resource endpoint for comprehensive system snapshots and individual tools for targeted metrics retrieval. The server uses multi-source speed tests from various providers to deliver reliable internet performance measurements, making it particularly useful for diagnosing performance issues, monitoring resource utilization, and tracking network connectivity without leaving the AI assistant conversation.', '@abhinav7895', 'development', 'Unknown', 0, 'https://github.com/abhinav7895/system-mcp', NULL, 0, 'https://github.com/abhinav7895.png?size=128', '2026-03-09T05:21:01.894967+00:00'),
  ('fermat-mathematical-computing', 'Fermat (Mathematical Computing)', 'This MCP server provides AI assistants with mathematical computation and plotting capabilities through three specialized modules: matplotlib for data visualization, NumPy for numerical operations, and SymPy for symbolic mathematics, built using Python with FastMCP and modular architecture. The implementation offers comprehensive tools for creating bar charts with customizable orientations and styling, performing matrix operations and statistical calculations, solving algebraic equations and calculus problems, and handling symbolic computation tasks like differentiation and integration. Built with unified function interfaces, JSON-serializable outputs, and prefix-based module organization, it serves data scientists needing conversational access to mathematical tools, educators requiring AI-assisted problem solving across numerical and symbolic domains, and researchers wanting to integrate mathematical computation into automated workflows without direct library interaction.', '@abhiphile', 'productivity', 'Unknown', 13, 'https://github.com/abhiphile/fermat-mcp', NULL, 0, 'https://github.com/abhiphile.png?size=128', '2026-03-09T05:21:01.895027+00:00'),
  ('azure-cosmos-db', 'Azure Cosmos DB', 'This MCP server implementation provides tools for interacting with Azure Cosmos DB databases using Go. Built with the Azure SDK for Go, it enables AI assistants to perform common Cosmos DB operations including listing databases and containers, executing SQL queries, reading container metadata, creating containers, and managing items. The implementation supports both key-based authentication and Azure managed identities, making it flexible for different deployment scenarios. It''s particularly useful for applications that need to integrate AI capabilities with document database operations, allowing natural language interaction with Cosmos DB resources without requiring users to write complex database code.', '@abhirockzz', 'databases', 'Unknown', 6, 'https://github.com/abhirockzz/mcp_cosmosdb_go', NULL, 0, 'https://github.com/abhirockzz.png?size=128', '2026-03-09T05:21:01.895039+00:00'),
  ('azure-data-explorer-kusto', 'Azure Data Explorer (Kusto)', 'An MCP server for Azure Data Explorer (Kusto) that enables AI assistants to interact with Kusto clusters through the Azure SDK for Go. It provides tools for listing databases, tables, retrieving table schemas, and executing KQL queries against Azure Data Explorer databases. The implementation uses DefaultAzureCredential for authentication, making it secure and simple to use with local developer credentials or service principals. Ideal for data analysts and engineers who want to leverage AI assistants for exploring and analyzing data in Azure Data Explorer clusters.', '@abhirockzz', 'databases', 'Unknown', 3, 'https://github.com/abhirockzz/mcp_kusto', NULL, 0, 'https://github.com/abhirockzz.png?size=128', '2026-03-09T05:21:01.895052+00:00'),
  ('deeprepo', 'DeepRepo', 'A production-grade Python library for performing retrieval-augmented generation on local codebases. Provides tools for codebase ingestion, semantic querying, and similarity-based code discovery. Supports multiple AI providers including Ollama, HuggingFace, OpenAI, Anthropic, and Gemini.', '@abhishek2432001', 'development', 'Unknown', 0, 'https://github.com/abhishek2432001/deeprepo', NULL, 0, 'https://github.com/abhishek2432001.png?size=128', '2026-03-09T05:21:01.895071+00:00'),
  ('airflow', 'Airflow', 'Airflow MCP Server provides a bridge between Claude and Apache Airflow, enabling direct interaction with Airflow workflows through the API. Built by Abhishek Bhakat, it supports both read-only (safe) and full-access (unsafe) operation modes, allowing users to list DAGs, check statuses, trigger runs, and manage Airflow resources without leaving their conversation interface. The implementation parses the Airflow OpenAPI specification to dynamically generate tools, supports both token and cookie-based authentication, and handles parameter validation - making it particularly valuable for DevOps teams who need to monitor and control workflow orchestration through natural language.', '@abhishekbhakat', 'ai-ml', 'Unknown', 31, 'https://github.com/abhishekbhakat/airflow-mcp-server', 'airflow-mcp-server', 16262, 'https://github.com/abhishekbhakat.png?size=128', '2026-03-09T05:21:01.895118+00:00'),
  ('code-assist', 'Code Assist', 'This MCP server implementation, developed for code modification and generation tasks, provides a set of tools for AI assistants to create, modify, delete, and rewrite code files. Built with Python and leveraging libraries like aiofiles, gitpython, and xmlschema, it offers a standardized XML-based interface for instructing code changes. The implementation focuses on file operations, search-and-replace modifications, and version control integration, making it accessible for AI models to perform complex code editing tasks. It''s particularly useful for automated code refactoring, codebase maintenance, or integrating AI-driven code generation into existing projects, allowing assistants to manipulate code without requiring deep knowledge of file system operations or version control complexities.', '@abhishekbhakat', 'development', 'Unknown', 2, 'https://github.com/abhishekbhakat/mcp_server_code_assist', 'mcp-server-code-assist', 3348, 'https://github.com/abhishekbhakat.png?size=128', '2026-03-09T05:21:01.895146+00:00'),
  ('sonic-pi', 'Sonic Pi', 'A Model Context Protocol server that allows AI assistants to interact with Sonic Pi through OSC messages, enabling programmatic music creation and sound manipulation. The server provides tools for playing individual notes with customizable synth parameters and executing arbitrary Sonic Pi code, making it valuable for AI-assisted music composition, sound design, and educational scenarios. Developed by Abhishek Jairath, it works with any MCP-compatible client like Claude Desktop or Cursor, and requires Sonic Pi to be running with a specific OSC handler code to receive and execute the commands.', '@abhishekjairath', 'development', 'Unknown', 12, 'https://github.com/abhishekjairath/sonic-pi-mcp', 'sonic-pi-mcp', 3376, 'https://github.com/abhishekjairath.png?size=128', '2026-03-09T05:21:01.895171+00:00'),
  ('todoist', 'Todoist', 'This MCP server, developed by abhiz123, enables natural language task management in Todoist through AI assistants like Claude. It provides tools for creating, retrieving, updating, completing, and deleting tasks using conversational language. The server leverages Todoist''s API to translate natural language commands into precise Todoist operations, supporting features like smart task search, flexible filtering, and rich task details. By bridging AI capabilities with Todoist''s task management system, this implementation enhances productivity workflows, allowing users to manage their tasks more intuitively. It is particularly useful for scenarios requiring hands-free task management, quick capture of ideas, or AI-assisted organization of complex projects within Todoist.', '@abhiz123', 'productivity', 'Unknown', 375, 'https://github.com/abhiz123/todoist-mcp-server', '@abhiz123/todoist-mcp-server', 21352, 'https://github.com/abhiz123.png?size=128', '2026-03-09T05:21:01.895215+00:00'),
  ('ableton-live', 'Ableton Live', 'This MCP server provides real-time control and automation of Ableton Live through a dual-component architecture consisting of a Python Remote Script that runs inside Ableton Live and an external MCP server that communicates via socket connections. Built by Siddharth Ahuja, it offers 16 tools covering session management (track creation, tempo control), MIDI clip operations (note insertion, playback control), and browser integration for loading instruments and effects, enabling AI assistants to compose music, automate production workflows, and manipulate Live sessions programmatically. The implementation features thread-safe command processing, comprehensive error handling with validation, and support for both real-time playback control and detailed session introspection, making it valuable for music producers, composers, and developers who want AI assistance in creating beats, arranging tracks, loading sounds, and automating repetitive studio tasks within Ableton Live.', '@chaudepark', 'productivity', 'Unknown', 1, 'https://github.com/chaudepark/ableton-mcp', NULL, 0, 'https://github.com/chaudepark.png?size=128', '2026-03-09T05:21:01.895272+00:00'),
  ('google-docs', 'Google Docs', 'Google Docs MCP Server provides a bridge between Claude Desktop (or other MCP clients) and Google Docs, enabling AI assistants to read document content, append text, and apply formatting to specific text within documents. Built with TypeScript and the fastmcp library, it handles OAuth 2.0 authentication with Google''s APIs and offers three main tools: readGoogleDoc for fetching document content, appendToGoogleDoc for adding text to documents, and formatMatchingText for applying styling (bold, color, etc.) to specific text instances. The server is designed for users who want their AI assistants to interact directly with their Google Documents, making it useful for collaborative writing, document analysis, or automated content generation.', '@a-bonus', 'development', 'Unknown', 354, 'https://github.com/a-bonus/google-docs-mcp', NULL, 0, 'https://github.com/a-bonus.png?size=128', '2026-03-09T05:21:01.895303+00:00'),
  ('alfresco-content-services', 'Alfresco Content Services', 'This Alfresco MCP Proof of Concept, developed by aborroy, demonstrates integration of Alfresco''s content management capabilities with AI applications using the Model Context Protocol. Built using Java and Node.js, it combines a standard Alfresco deployment with custom MCP client and server components. The implementation leverages Spring AI and the TypeScript SDK to connect Alfresco''s document management features to AI workflows. It''s particularly useful for organizations looking to enhance their Alfresco-based content repositories with AI capabilities, enabling use cases like intelligent document processing, automated metadata extraction, and content-aware chatbots without extensive custom development.', '@aborroy', 'development', 'Unknown', 5, 'https://github.com/aborroy/alfresco-mcp-poc', NULL, 0, 'https://github.com/aborroy.png?size=128', '2026-03-09T05:21:01.895336+00:00'),
  ('ledfx', 'LedFX', 'Provides comprehensive control over LedFX LED lighting systems through a TypeScript-based MCP server that bridges natural language commands to the LedFX REST API. Features an extensive color library with named colors and gradients, intelligent scene parsing that converts descriptions into proper effect configurations, and local SQLite storage for custom palettes and playlists. Includes effect recommendations based on mood and context, detailed explanations of LedFX concepts like virtuals and audio-reactive effects, and support for all major LedFX operations including device management, effect control, and scene creation.', '@abossard', 'databases', 'Unknown', 2, 'https://github.com/abossard/ledfx-mcp', NULL, 0, 'https://github.com/abossard.png?size=128', '2026-03-09T05:21:01.895348+00:00'),
  ('ibm-as-400-iseries', 'IBM AS/400 iSeries', 'A Spring Boot-based MCP server that enables AI assistants to interact with IBM AS/400 and iSeries mainframe systems through RTE (Remote Terminal Emulator) protocols including TN5250, TN3270, and VT420. Built by Abstracta using the jmeter-bzm-rte library, it provides a configurable YAML-based approach for defining connection parameters and automated terminal interaction flows, allowing users to execute mainframe login sequences and retrieve screen output as text. Particularly valuable for modernizing legacy system interactions, enabling AI assistants to perform mainframe operations like user authentication and menu navigation without requiring direct terminal access or specialized mainframe knowledge.', '@abstracta', 'ai-ml', 'Unknown', 16, 'https://github.com/abstracta/ibm-as-400-iseries-mcp-server', NULL, 0, 'https://github.com/abstracta.png?size=128', '2026-03-09T05:21:01.895398+00:00'),
  ('gatherings-expense-sharing', 'Gatherings (Expense Sharing)', 'Gatherings MCP Server provides a tool for managing shared expenses in social events, helping users track costs, calculate reimbursements, and settle balances between friends. Built with a TypeScript wrapper around a Python backend using SQLAlchemy for data persistence, it offers features like creating gatherings, adding expenses, recording payments, and calculating who owes what to whom. The server uses a non-standard architecture where the Node.js component translates MCP requests to command-line calls to the Python implementation, making it suitable for personal expense tracking in group settings while acknowledging areas for architectural improvement.', '@abutbul', 'databases', 'Unknown', 0, 'https://github.com/abutbul/gatherings-mcp', NULL, 0, 'https://github.com/abutbul.png?size=128', '2026-03-09T05:21:01.895442+00:00'),
  ('reading-companion', 'Reading Companion', 'A reading companion that helps users build and track personalized reading goals through four sequential stages. The Interviewer conducts conversational interviews to establish reading profiles, the Context Builder analyzes profiles to extract deeper patterns, the Syllabus Builder generates curated book recommendations organized by domain with thoughtful sequencing, and the Reflection Partner facilitates post-reading reflection and learning synthesis. Stores all data locally in the user''s home directory and generates markdown files for easy review.', '@aby0', 'development', 'Unknown', 1, 'https://github.com/aby0/reading-companion', NULL, 0, 'https://github.com/aby0.png?size=128', '2026-03-09T05:21:01.895483+00:00'),
  ('kagi-search', 'Kagi Search', 'Developed by ac3xx, this server provides an interface for language models to perform web searches using Kagi''s search engine. It enables AI agents to query Kagi''s API and retrieve search results through a controlled MCP server. Built in TypeScript, the implementation currently focuses on basic web search functionality, with plans to expand to other Kagi features like text summarization and enriched news results. The server handles API authentication and request formatting. By leveraging Kagi''s privacy-focused search capabilities, this implementation is particularly useful for AI assistants needing to access current web information, conduct research, or provide search results while respecting user privacy preferences.', '@ac3xx', 'development', 'Unknown', 43, 'https://github.com/ac3xx/mcp-servers-kagi', NULL, 0, 'https://github.com/ac3xx.png?size=128', '2026-03-09T05:21:01.895513+00:00'),
  ('academic-author-network', 'Academic Author Network', 'This MCP server provides academic author network analysis by aggregating data from multiple scholarly sources including Semantic Scholar, OpenAlex, Crossref, and Google Scholar to find co-authors and research keywords for academic researchers. Built by Alperen Kocyigit, it offers two core tools: co-author discovery that identifies research collaborators with collaboration frequency counts, and keyword extraction that scrapes Google Scholar profiles to retrieve research interests and areas of expertise. The implementation features intelligent rate limiting across APIs, caching to reduce redundant requests, parallel data fetching for performance, and respectful web scraping with delays, making it valuable for academic research analysis, collaboration mapping, and understanding research networks in scholarly communities.', '@alperenkocyigit', 'development', 'Unknown', 2, 'https://github.com/alperenkocyigit/authorprofilemcp', NULL, 0, 'https://github.com/alperenkocyigit.png?size=128', '2026-03-09T05:21:01.895545+00:00'),
  ('biomcp', 'BioMCP', 'BioMCP is a Model Context Protocol (MCP) server designed to enhance large language models with protein structure analysis capabilities. It provides tools for analyzing protein active sites and searching for disease-related proteins by interfacing with established protein databases.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('flutter-documentation', 'Flutter Documentation', 'This Flutter MCP server provides AI assistants with real-time access to Flutter, Dart, and pub.dev documentation through on-demand web scraping with SQLite caching, ensuring always up-to-date information without requiring pre-built indexes. The implementation features intelligent URL resolution for Flutter API classes across multiple libraries (widgets, material, cupertino, etc.), comprehensive HTML-to-Markdown processing that extracts constructors, properties, methods, and code examples, and robust error handling with circuit breakers and exponential backoff retry logic. Built with FastMCP and featuring rate limiting for respectful scraping, it supports searching Flutter documentation, retrieving pub.dev package information, and processing @flutter_mcp mentions in prompts, making it valuable for Flutter developers who need current documentation integrated into their AI-powered development workflows.', '@adamsmaka', 'databases', 'Unknown', 67, 'https://github.com/adamsmaka/flutter-mcp', NULL, 0, 'https://github.com/adamsmaka.png?size=128', '2026-03-09T05:21:01.896328+00:00'),
  ('resource-hub', 'Resource Hub', 'This Resource Hub MCP server, developed by Adam Wattis, acts as a proxy between local MCP environments and a centralized Resource Hub. It enables access to shared tools, configurations, and resources across different environments, streamlining MCP server management. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers features like centralized configuration, environment variable-based authentication, and compatibility with Claude Desktop. The server includes debugging tools through the MCP Inspector and supports easy deployment via npx. By centralizing resource management, it facilitates consistent tool access and configuration sharing, making it particularly valuable for teams and organizations requiring standardized MCP setups across multiple environments or projects.', '@adamwattis', 'development', 'Unknown', 4, 'https://github.com/adamwattis/resource-hub-server', NULL, 0, 'https://github.com/adamwattis.png?size=128', '2026-03-09T05:21:01.896360+00:00'),
  ('router', 'Router', 'This MCP proxy server, developed by Adam Wattis, aggregates multiple MCP resource servers into a unified interface. It connects to and manages multiple backend servers, exposes their combined capabilities, handles request routing, and aggregates responses. The implementation features resource management across servers, tool aggregation and routing, and multi-server prompt handling. By centralizing access to distributed MCP resources, this proxy enables more flexible and scalable AI assistant deployments. It is particularly useful for organizations managing multiple specialized MCP servers or those looking to modularize their AI infrastructure while maintaining a single point of access for clients.', '@adamwattis', 'ai-ml', 'Unknown', 197, 'https://github.com/adamwattis/mcp-proxy-server', NULL, 0, 'https://github.com/adamwattis.png?size=128', '2026-03-09T05:21:01.896405+00:00'),
  ('embedded-debugger-probe-rs', 'Embedded Debugger (probe-rs)', 'Embedded Debugger MCP server that provides AI assistants with comprehensive hardware debugging capabilities for ARM Cortex-M and RISC-V microcontrollers through probe-rs integration. Built by Adancurusul, the implementation supports popular debug probes including J-Link, ST-Link, DAPLink, and Black Magic Probe, offering 18 debugging tools that cover session management, target control (halt/run/reset/step), memory operations, breakpoint management, flash programming, and Real-Time Transfer (RTT) communication for live firmware debugging. Designed for embedded developers and AI-assisted firmware development workflows who need conversational access to hardware debugging without manual probe configuration, enabling natural language interaction with microcontroller debugging sessions, memory inspection, and firmware flashing operations.', '@adancurusul', 'development', 'Unknown', 50, 'https://github.com/adancurusul/embedded-debugger-mcp', NULL, 0, 'https://github.com/adancurusul.png?size=128', '2026-03-09T05:21:01.896444+00:00'),
  ('serial-port-communication', 'Serial Port Communication', 'Serial MCP Server provides comprehensive serial port communication capabilities for AI assistants, enabling discovery, connection management, and data transmission with embedded devices and hardware. Built by Adancurusul using Rust and the rmcp SDK, the implementation supports multiple data encodings (UTF-8, hex, base64), configurable connection parameters (baud rate, parity, flow control), session management with automatic cleanup, and robust error handling with reconnection capabilities. Designed for developers working with IoT devices, embedded systems, or hardware automation who need conversational access to serial communication without manual port configuration, making it valuable for debugging embedded firmware, monitoring sensor data, or controlling hardware devices through natural language interactions.', '@adancurusul', 'development', 'Unknown', 25, 'https://github.com/adancurusul/serial-mcp-server', NULL, 0, 'https://github.com/adancurusul.png?size=128', '2026-03-09T05:21:01.896477+00:00'),
  ('fabric-pattern-tools', 'Fabric Pattern Tools', 'The fabric-mcp-server exposes Fabric patterns as tools for integration with Cline through the Model Context Protocol. Built by adapoet, this TypeScript implementation loads patterns from a configurable directory and makes them available as individual tools that can be executed directly within Cline tasks. The server reads each pattern''s system.md file and combines it with user input to generate responses, enabling AI-driven pattern execution without leaving the Cline environment. It includes a recommendation feature that suggests appropriate patterns based on task descriptions, making it particularly valuable for developers who want to leverage Fabric''s pattern library within their VS Code workflow.', '@augmentedivan', 'development', 'Unknown', 19, 'https://github.com/augmentedivan/fabric-mcp-server', NULL, 0, 'https://github.com/augmentedivan.png?size=128', '2026-03-09T05:21:01.896507+00:00'),
  ('adaptive-graph-of-thoughts', 'Adaptive Graph of Thoughts', 'This MCP server provides advanced scientific reasoning capabilities through an 8-stage Graph-of-Thoughts pipeline that processes complex queries by decomposing them into hypotheses, gathering evidence, and building knowledge graphs in Neo4j. Built by the Adaptive Graph of Thoughts Development Team using Python with FastAPI, Neo4j, and the official MCP SDK, it implements stages for initialization, decomposition, hypothesis generation, evidence gathering, pruning/merging, subgraph extraction, composition, and reflection with confidence scoring across empirical support, theoretical basis, methodological rigor, and consensus alignment. The implementation supports both HTTP and STDIO transports, includes Docker deployment with Neo4j integration, and features bias detection, falsifiability assessment, and Bayesian confidence updates, making it valuable for researchers conducting systematic literature reviews, scientists analyzing complex interdisciplinary questions, and AI assistants that need structured reasoning with transparent confidence assessments for evidence-based decision making.', '@saptadey', 'cloud', 'Unknown', 27, 'https://github.com/saptadey/adaptive-graph-of-thoughts-mcp-server', NULL, 0, 'https://github.com/saptadey.png?size=128', '2026-03-09T05:21:01.896539+00:00'),
  ('google-forms', 'Google Forms', 'Google Forms MCP Server enables AI assistants to create and manage Google Forms through natural language requests. Built with Python and Flask, it features a two-tier architecture with an MCP server handling Google Forms API operations and a CamelAIOrg agent layer that processes natural language into structured form creation commands. The implementation includes real-time visualization of the request flow, comprehensive error handling, and support for various question types. It''s particularly useful for automating form creation workflows, enabling quick generation of surveys, feedback forms, and event registrations without requiring direct interaction with the Google Forms interface.', '@adarshp14', 'ai-ml', 'Unknown', 7, 'https://github.com/adarshp14/google-form-mcp-server', NULL, 0, 'https://github.com/adarshp14.png?size=128', '2026-03-09T05:21:01.896586+00:00'),
  ('nexus-openrouter-search', 'Nexus (OpenRouter Search)', 'This Nexus MCP server by adawalli provides AI-powered web search capabilities through OpenRouter''s Perplexity Sonar models, enabling intelligent search with source citations directly within MCP-compatible clients like Claude Desktop and Cursor. Built with TypeScript and featuring zero-installation deployment via npx, the implementation includes production-grade features like request deduplication, response caching, comprehensive error handling, and secure API key management with data masking for logs. The server emphasizes developer experience with extensive configuration options, structured logging, retry mechanisms, and high test coverage, making it valuable for developers who need reliable, current web information integrated into their AI workflows without complex setup or maintenance overhead.', '@adawalli', 'development', 'Unknown', 19, 'https://github.com/adawalli/nexus', 'nexus-mcp', 2206, 'https://github.com/adawalli.png?size=128', '2026-03-09T05:21:01.896620+00:00'),
  ('quran-search-engine', 'Quran Search Engine', 'Provides Quran search with Arabic normalization, root-based matching, and highlighted results for AI tools to deliver accurate, hallucination-free Quranic text.', '@adelpro', 'ai-ml', 'Unknown', 2, 'https://github.com/adelpro/quran-search-engine-mcp', NULL, 0, 'https://github.com/adelpro.png?size=128', '2026-03-09T05:21:01.896643+00:00'),
  ('google-custom-search', 'Google Custom Search', 'This MCP server, developed by Allan Denot, provides web search capabilities using the Google Custom Search API. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers a streamlined interface for AI agents to perform web searches. The implementation focuses on simplifying the integration of Google''s search functionality into AI workflows, requiring only an API key and search engine ID for setup. It''s particularly useful for applications needing up-to-date web information, enabling use cases such as fact-checking, research assistance, and content generation without directly interacting with Google''s API complexities.', '@adenot', 'development', 'Unknown', 60, 'https://github.com/adenot/mcp-google-search', '@adenot/mcp-google-search', 42551, 'https://github.com/adenot.png?size=128', '2026-03-09T05:21:01.896672+00:00'),
  ('shodan', 'Shodan', 'Shodan MCP Server provides cybersecurity analysts with direct access to Shodan''s network intelligence capabilities through the Model Context Protocol. Developed by ADEO Cybersecurity Services, it exposes a comprehensive set of tools for host information lookup, DNS operations, vulnerability analysis, network scanning, and security alerts management. The implementation includes specialized prompt templates for common cybersecurity workflows like asset discovery, vulnerability assessment, and ICS analysis, making it particularly valuable for security reconnaissance, threat hunting, and infrastructure monitoring without leaving the AI assistant conversation.', '@adeosec', 'ai-ml', 'Unknown', 20, 'https://github.com/adeosec/mcp-shodan', NULL, 0, 'https://github.com/adeosec.png?size=128', '2026-03-09T05:21:01.896720+00:00'),
  ('teamretro', 'TeamRetro', 'TeamRetro MCP Server provides a bridge between AI assistants and TeamRetro''s team management platform, enabling operations like team creation, user management, and member administration through natural language. Built by Ade Pangestu, it implements authentication via API keys, basic auth, or bearer tokens, and formats responses as either simple tables or raw JSON. The server exposes tools for listing, creating, updating, and deleting teams and users, with planned support for retrospectives, action tracking, health checks, and analytics. This unofficial integration is particularly valuable for team leaders who need to manage TeamRetro resources without switching context from their AI assistant conversation.', '@adepanges', 'ai-ml', 'Unknown', 0, 'https://github.com/adepanges/teamretro-mcp-server', 'teamretro-mcp-server', 1657, 'https://github.com/adepanges.png?size=128', '2026-03-09T05:21:01.896769+00:00'),
  ('raindrop-io', 'Raindrop.io', 'The Raindrop.io MCP Server provides AI assistants with direct access to the Raindrop.io bookmarking service through a TypeScript implementation built with Bun. It exposes resources for collections, bookmarks, tags, highlights, and user data, along with tools for CRUD operations, advanced search, tag management, and import/export functionality. The server communicates via stdio by default with optional HTTP/SSE support, uses Axios for API requests, and implements robust error handling with Zod validation. This implementation is particularly valuable for users who want to manage their bookmarks, organize research materials, or analyze saved content without leaving their AI conversation context.', '@adeze', 'development', 'Unknown', 128, 'https://github.com/adeze/raindrop-mcp', '@adeze/raindrop-mcp', 6728, 'https://github.com/adeze.png?size=128', '2026-03-09T05:21:01.896841+00:00'),
  ('adfin-financial-management', 'Adfin Financial Management', 'The Adfin MCP server enables Claude to interact with Adfin''s financial management platform through its public APIs, allowing users to perform tasks like checking credit control status, creating invoices, and uploading invoice documents. Built with FastMCP, it dynamically generates API tools by importing Adfin''s API documentation and registering each endpoint as a separate function, while also providing specialized file system tools for managing invoice uploads from the user''s desktop. The implementation includes automatic token refresh handling and is designed to be easily configured in Claude Desktop through environment variables, making it particularly valuable for financial professionals who need to perform Adfin operations without leaving their conversation interface.', '@adfin-engineering', 'productivity', 'Unknown', 9, 'https://github.com/adfin-engineering/mcp-server-adfin', NULL, 0, 'https://github.com/adfin-engineering.png?size=128', '2026-03-09T05:21:01.896901+00:00'),
  ('linkedin', 'LinkedIn', 'This MCP server, developed by Adhika Setya Pramudita, provides tools to interact with LinkedIn''s Feeds and Job API using an unofficial LinkedIn API. It enables users to retrieve feed posts, search for jobs, and analyze job matches against resumes. The implementation uses Python 3.7+ and integrates with libraries like linkedin-api and fastmcp. It''s designed for easy configuration through environment variables and can be run using uvicorn. This server is particularly useful for developers building LinkedIn-integrated applications, job search tools, or AI assistants that need to access LinkedIn data and functionality.', '@adhikasp', 'development', 'Unknown', 191, 'https://github.com/adhikasp/mcp-linkedin', NULL, 0, 'https://github.com/adhikasp.png?size=128', '2026-03-09T05:21:01.896929+00:00'),
  ('git-ingest', 'Git Ingest', 'This MCP server, developed by adhikasp, enables AI assistants like Claude to fetch and analyze GitHub repository structures and contents. Built in Python, it provides capabilities for cloning repositories, generating directory trees, and reading specified files. The implementation stands out by offering deterministic temporary directory creation, Unicode tree representation, and flexible file reading with robust error handling. By connecting AI capabilities with GitHub''s vast ecosystem of code repositories, this server allows AI systems to explore codebases, analyze project structures, and access important files programmatically. It is particularly useful for building AI-powered code analysis tools, automated documentation generators, and intelligent assistants for software development workflows that need to interact with GitHub repositories.', '@adhikasp', 'development', 'Unknown', 302, 'https://github.com/adhikasp/mcp-git-ingest', NULL, 0, 'https://github.com/adhikasp.png?size=128', '2026-03-09T05:21:01.896956+00:00'),
  ('twikit', 'Twikit', 'This MCP server, developed by adhikasp, integrates with Twitter''s API to enable AI assistants to interact with the social media platform. It provides tools for searching tweets, retrieving timelines, and analyzing sentiment across multiple accounts. The server stands out by offering a simplified interface for complex Twitter operations, making it easier for AI systems to process and respond to social media data. By connecting AI capabilities with Twitter''s vast user-generated content, this implementation empowers AI assistants to handle tasks like social media monitoring, trend analysis, and customer sentiment tracking. It is particularly useful for applications in brand management, market research, or any scenario where an AI system needs to work with real-time social media data.', '@adhikasp', 'productivity', 'Unknown', 227, 'https://github.com/adhikasp/mcp-twikit', NULL, 0, 'https://github.com/adhikasp.png?size=128', '2026-03-09T05:21:01.896999+00:00'),
  ('reddit', 'Reddit', 'This Reddit MCP server, developed by adhikasp, provides AI assistants with a standardized interface to interact with Reddit content. Built using Python and leveraging libraries like PRAW and RedditWarp, it offers capabilities for fetching hot threads, detailed post content, and comments from any subreddit. The server supports different post types including text, links, and galleries. It''s designed for flexibility, allowing easy installation and usage through the MCP client CLI. This implementation is particularly valuable for AI assistants focused on social media analysis, content curation, and trend monitoring, enabling use cases such as summarizing popular discussions, tracking emerging topics, and analyzing user engagement across Reddit communities.', '@adhikasp', 'ai-ml', 'Unknown', 361, 'https://github.com/adhikasp/mcp-reddit', NULL, 0, 'https://github.com/adhikasp.png?size=128', '2026-03-09T05:21:01.897047+00:00'),
  ('youtube-transcript', 'YouTube Transcript', 'This MCP server, developed by adhikasp, enables AI assistants like Claude to fetch and analyze YouTube video transcripts. Built in Python, it provides capabilities for downloading subtitles from YouTube videos using either video IDs or full URLs, and includes timestamp information. The implementation stands out by offering a standardized interface to YouTube''s transcript data, allowing AI systems to easily access and process video content. By connecting AI capabilities with YouTube''s vast repository of video transcripts, this server enables automated content analysis, subtitle generation, and video summarization. It is particularly useful for building AI-powered tools for video research, content moderation, and educational applications that leverage YouTube''s extensive library.', '@adhikasp', 'development', 'Unknown', 47, 'https://github.com/adhikasp/mcp-youtube', NULL, 0, 'https://github.com/adhikasp.png?size=128', '2026-03-09T05:21:01.897112+00:00'),
  ('core-lightning', 'Core Lightning', 'This MCP server provides direct access to Core Lightning (CLN) nodes through their gRPC interface, enabling AI assistants to query Lightning Network node information, channel states, payment history, and network topology. Built in Rust with TLS certificate authentication and comprehensive error handling, it exposes 25+ Lightning Network operations including node info retrieval, channel management, payment tracking, invoice handling, bookkeeping data, and network analysis through tools like list_peers, get_info, list_channels, and bkpr_channels_apy. The implementation uses the official CLN gRPC client library with async support and includes detailed documentation for each Lightning Network command, making it valuable for Lightning Network operators monitoring node performance, developers building Lightning applications, or financial analysis of routing fees and channel profitability.', '@adi2011', 'development', 'Unknown', 2, 'https://github.com/adi2011/cln-mcp', NULL, 0, 'https://github.com/adi2011.png?size=128', '2026-03-09T05:21:01.897146+00:00'),
  ('orthanc-dicom', 'Orthanc DICOM', 'Connects to Orthanc DICOM servers to enable hierarchical querying of medical imaging data. Supports searching for patients by name, ID, or birth date, retrieving imaging studies, accessing series within studies, and querying individual DICOM objects. Includes PDF text extraction from encapsulated DICOM reports for radiology automation workflows.', '@adiking117', 'search', 'Unknown', 2, 'https://github.com/adiking117/orthanc-mcp', NULL, 0, 'https://github.com/adiking117.png?size=128', '2026-03-09T05:21:01.897184+00:00'),
  ('feature-suggestions-supabase', 'Feature Suggestions (Supabase)', 'The Supabase MCP Server connects AI assistants to a Supabase database, allowing them to query feature suggestions stored in the database. Built with TypeScript using the Model Context Protocol SDK, it provides a single tool called ''query_feature_suggestions'' that retrieves records from the feature_suggestions table with optional limit parameters. The server includes robust error handling and logging capabilities, making it ideal for workflows where AI assistants need to access, analyze, or present feature request data directly within conversations without requiring manual database queries.', '@adiletd', 'databases', 'Unknown', 0, 'https://github.com/adiletd/feature-request-collection-mcp', NULL, 0, 'https://github.com/adiletd.png?size=128', '2026-03-09T05:21:01.897197+00:00'),
  ('grpc-bridge', 'gRPC Bridge', 'GRPCMCP is a proxy server that bridges AI assistants to gRPC backends using the Model Context Protocol. Developed by Adiom Data, it dynamically exposes gRPC service methods as MCP tools by either using server reflection or pre-compiled protocol buffer descriptors. The server supports both Server-Sent Events (SSE) and STDIN transport methods, handles authentication through bearer tokens, and allows custom header configuration. This implementation is particularly valuable for organizations that want to expose their existing gRPC services to AI assistants without building custom MCP servers for each service.', '@adiom-data', 'development', 'Unknown', 27, 'https://github.com/adiom-data/grpcmcp', NULL, 0, 'https://github.com/adiom-data.png?size=128', '2026-03-09T05:21:01.897224+00:00'),
  ('corporate-dystopia-toolkit', 'Corporate Dystopia Toolkit', 'Hilanet MCP provides a satirical corporate dystopia toolkit built with fastMCP, offering HR-related tools that parody toxic workplace behaviors. The implementation includes functions for requesting salary increases, filing manager complaints, scheduling inconvenient meetings, generating corporate jargon, and other humorous workplace sabotage actions. Each tool accepts specific parameters like employee names, percentages, or justifications, creating a playful commentary on office politics. The server can be run directly with npx or through npm scripts, making it easily accessible for users wanting to explore this tongue-in-cheek take on corporate culture through AI assistants.', '@adird', 'ai-ml', 'Unknown', 36, 'https://github.com/adird/hilanet-mcp', NULL, 0, 'https://github.com/adird.png?size=128', '2026-03-09T05:21:01.897273+00:00'),
  ('video-edit-moviepy', 'Video Edit (MoviePy)', 'A comprehensive video editing MCP server built with MoviePy that provides extensive video and audio processing capabilities including trimming, merging, resizing, cropping, rotation, speed adjustment, format conversion, and effects like fade in/out, grayscale conversion, and mirroring. The implementation features an in-memory object store system for chaining operations efficiently, supports YouTube video downloading via yt-dlp, and includes advanced features like text/image overlays, frame extraction, video splitting, and audio manipulation tools such as volume adjustment, looping, and track mixing. Designed for automated video editing workflows, it''s particularly valuable for content creators, developers building video processing applications, and AI assistants that need to perform complex video editing tasks programmatically without manual intervention.', '@aditya2755', 'development', 'Unknown', 12, 'https://github.com/aditya2755/video-edit-mcp', 'video-edit-mcp', 1495, 'https://github.com/aditya2755.png?size=128', '2026-03-09T05:21:01.897308+00:00'),
  ('scholarly-arxiv', 'Scholarly (arXiv)', 'This mcp-scholarly server, developed by Aditya Karnam, provides a standardized interface for searching academic articles through the arXiv database. Built with Python and leveraging the arxiv library, it offers a tool to query arXiv based on keywords. The server integrates seamlessly with Claude Desktop, abstracting the complexities of academic search into a consistent MCP interface. By enabling AI systems to access and analyze scholarly literature, this implementation facilitates use cases such as literature reviews, research assistance, and staying up-to-date with the latest publications in specific fields. The server is designed for easy deployment and debugging, making it valuable for researchers and developers building AI-powered tools that interact with academic content.', '@adityak74', 'databases', 'Unknown', 172, 'https://github.com/adityak74/mcp-scholarly', NULL, 0, 'https://github.com/adityak74.png?size=128', '2026-03-09T05:21:01.897320+00:00'),
  ('apache-solr', 'Apache Solr', 'This Spring Boot MCP server provides Apache Solr search and indexing capabilities through six specialized tools including advanced search with filtering/faceting/pagination, schema-less document indexing from JSON, collection management with health monitoring and statistics, and schema introspection. Built using Java 21 with SolrJ client library and Spring AI MCP framework, it features robust error handling with individual document fallback during batch failures, automatic JSON flattening for nested objects, dynamic field type detection, and comprehensive metrics collection from Solr MBeans including cache performance and handler statistics. The implementation supports both standalone Solr and SolrCloud deployments with Docker Compose setup, making it valuable for AI-assisted search application development, data ingestion workflows, index monitoring and optimization, and building intelligent search interfaces that leverage Solr''s full-text search capabilities without requiring direct Solr API knowledge.', '@adityamparikh', 'cloud', 'Unknown', 10, 'https://github.com/adityamparikh/solr-mcp-server', NULL, 0, 'https://github.com/adityamparikh.png?size=128', '2026-03-09T05:21:01.897349+00:00'),
  ('browsercontrol', 'BrowserControl', 'BrowserControl is a browser automation server that enables interaction with web pages through a Set of Marks (SoM) system, where screenshots display numbered interactive elements for precise clicking and interaction. Built using Playwright and FastMCP, it provides persistent browser sessions with automatic cookie and login state management, developer tools integration for console logs and network monitoring, session recording capabilities, and smart navigation that handles localhost connection issues. The implementation is useful for web scraping, form filling, testing workflows, or any task requiring visual web interaction with debugging capabilities.', '@adityasasidhar', 'development', 'Unknown', 6, 'https://github.com/adityasasidhar/browsercontrol', NULL, 0, 'https://github.com/adityasasidhar.png?size=128', '2026-03-09T05:21:01.897379+00:00'),
  ('autobuild', 'AutoBuild', 'This MCP server provides AI assistants with profile-based build automation capabilities, featuring asynchronous build queuing, file system watching with debounced triggers, and comprehensive build lifecycle management. Built using Python with FastMCP, psutil for process management, and watchdog for file monitoring, it supports concurrent build execution (default: 2), persistent state management through JSON storage, and automatic build triggering when project files change with configurable ignore patterns to prevent recursion. The implementation includes tools for build configuration, manual and automatic build triggering, status monitoring, log retrieval with tailing support, and process termination, along with systemd service integration for Linux deployment and cross-platform batch/shell scripts for setup, making it valuable for development workflows requiring automated builds, continuous integration scenarios, and building AI assistants that need programmatic access to build systems without manual intervention.', '@admica', 'development', 'Unknown', 1, 'https://github.com/admica/autobuildmcp', NULL, 0, 'https://github.com/admica.png?size=128', '2026-03-09T05:21:01.897412+00:00'),
  ('ai-rule-mcp-server', 'AI Rule MCP Server', 'Built as part of the AI Duet Project by adminhuan, this server offers tools for mode management to switch between different AI interaction modes, rule checking to enforce conversation guidelines, and feature request processing to capture and manage user suggestions. The implementation supports both Python and Node.js execution environments with comprehensive installation scripts, making it valuable for developers building AI assistants that need structured conversation management, content moderation through predefined rules, and systematic collection of user feedback for iterative improvement.', '@adminhuan', 'development', 'Unknown', 11, 'https://github.com/adminhuan/smart-search-mcp', NULL, 0, 'https://github.com/adminhuan.png?size=128', '2026-03-09T05:21:01.897441+00:00'),
  ('microsoft-dataverse', 'Microsoft Dataverse', 'This MCP server provides Microsoft Dataverse integration with advanced MCP features including Elicitation, Sampling, and Resources for enterprise data operations. Built with ASP.NET Core and .NET 9.0, it offers FetchXML query execution with intelligent result handling that prompts users to save large datasets (>20 records) as MCP Resources, uses MCP Sampling to transform raw JSON into markdown tables, and includes bulk contact creation with progress notifications plus Chart.js report generation. The implementation demonstrates sophisticated MCP capabilities through interactive user prompts for decision making, LLM-powered data transformation, and dynamic resource creation, making it valuable for developers working with Dataverse environments who need AI-assisted data analysis, reporting, and bulk operations with real-time progress tracking.', '@adner', 'ai-ml', 'Unknown', 1, 'https://github.com/adner/mcp_resourcelinks', NULL, 0, 'https://github.com/adner.png?size=128', '2026-03-09T05:21:01.897498+00:00'),
  ('adobe-premiere-pro', 'Adobe Premiere Pro', 'This MCP server enables AI-powered video editing through natural language prompts by providing direct access to Adobe Premiere Pro''s functionality via ExtendScript and UXP plugin integration. Built with TypeScript and featuring over 40 specialized tools for project management, media import, timeline operations, effects application, and rendering, it uses a file-based communication bridge with a UXP panel interface to execute commands within Premiere Pro. The implementation includes comprehensive resources for accessing project metadata, sequences, and timeline information, along with templated prompts for common video editing workflows like music video creation, color grading, and multicam editing, making it valuable for automating complex video production tasks and building AI assistants that can interact with professional video editing workflows without manual interface navigation.', '@hetpatel-11', 'development', 'Unknown', 49, 'https://github.com/hetpatel-11/adobe_premiere_pro_mcp', NULL, 0, 'https://github.com/hetpatel-11.png?size=128', '2026-03-09T05:21:01.897532+00:00'),
  ('fiftyone', 'FiftyOne', 'Enables control of FiftyOne computer vision datasets through MCP. Provides 16 tools for dataset management, operator execution, plugin management, and session handling. Integrates FiftyOne''s computer vision framework capabilities with AI assistants for tasks like dataset listing, image similarity search, and annotation management.', '@voxel51', 'productivity', 'Unknown', 9, 'https://github.com/voxel51/fiftyone-mcp-server', NULL, 0, 'https://github.com/voxel51.png?size=128', '2026-03-09T05:21:01.897561+00:00'),
  ('nothumanallowed', 'NotHumanAllowed', 'NotHumanAllowed provides an MCP server through its PIF agent client, enabling integration with Claude Code, Cursor, and Windsurf. The server exposes tools for managing posts and comments, voting, search, knowledge grounding across verified datasets, consensus operations, mesh delegation, messaging workflows, browser automation, and email integration. Uses Ed25519 cryptographic authentication with a zero-knowledge architecture where API keys never leave the local machine.', '@adoslabsproject-gif', 'development', 'Unknown', 67, 'https://github.com/adoslabsproject-gif/nothumanallowed', NULL, 0, 'https://github.com/adoslabsproject-gif.png?size=128', '2026-03-09T05:21:01.897584+00:00'),
  ('trello', 'Trello', 'This MCP server provides comprehensive Trello integration capabilities through the Trello REST API, enabling AI assistants to manage boards, lists, cards, labels, and actions programmatically. Built by Adrian Grahl using TypeScript with modular tool organization across boards, lists, cards, labels, and actions modules, it offers over 30 specialized tools including batch operations for creating multiple cards/labels simultaneously, card movement and archiving, comment management, label creation and assignment, action tracking and updates, and list management with archiving capabilities. The implementation features robust API credential validation, structured error handling with detailed responses, utility functions for consistent URL construction and HTTP operations, and support for advanced Trello features like action reactions and field-specific updates, making it valuable for project management automation, task tracking workflows, team collaboration processes, and building AI assistants that need programmatic access to Trello''s project management features without manual board navigation.', '@adriangrahldev', 'development', 'Unknown', 6, 'https://github.com/adriangrahldev/advanced-trello-mcp-server', NULL, 0, 'https://github.com/adriangrahldev.png?size=128', '2026-03-09T05:21:01.897619+00:00'),
  ('harvest', 'Harvest', 'This MCP server implementation provides natural language time tracking integration with Harvest, enabling AI assistants to interact with Harvest''s time tracking and project management features. Developed by Adrian, it offers tools for managing projects, tracking time entries, and handling leave requests. Built with TypeScript and leveraging the Model Context Protocol SDK, the server focuses on secure credential management through environment variables and supports easy configuration within AI assistant environments. It is particularly useful for automating time tracking workflows, streamlining project management tasks, and integrating Harvest operations into AI-assisted work processes. The implementation includes features like natural language parsing for time entries and customizable work day hours and leave types.', '@adrian-dotco', 'development', 'Unknown', 4, 'https://github.com/adrian-dotco/harvest-mcp-server', 'harvest-mcp-server-setup', 189, 'https://github.com/adrian-dotco.png?size=128', '2026-03-09T05:21:01.897652+00:00'),
  ('dev-environment-sentinel', 'Dev Environment Sentinel', 'A lean, efficient MCP server for monitoring and verifying development environment health across multiple programming ecosystems including Java (Maven/Gradle), JavaScript/TypeScript (npm/React/Webpack/Vite), Python (pip/Poetry/Conda), C# (.NET/NuGet), and infrastructure tools like Docker and PostgreSQL. Built in Go for performance, it detects project ecosystems, verifies build freshness by comparing source file timestamps against compiled artifacts, checks dependency states, validates environment variables, and provides automated reconciliation suggestions when issues are detected.', '@adrianmikula', 'databases', 'Unknown', 1, 'https://github.com/adrianmikula/devenvmcp', NULL, 0, 'https://github.com/adrianmikula.png?size=128', '2026-03-09T05:21:01.897665+00:00'),
  ('jakarta-migration', 'Jakarta Migration', 'Specialized MCP server for automating Java EE to Jakarta EE migrations, providing AI assistants with tools to analyze dependencies, refactor code, and verify runtime compatibility. Built with Spring Boot and leveraging OpenRewrite recipes, it offers systematic migration planning with intelligent phase ordering, progress tracking, and rollback capabilities. Features include dependency graph analysis to detect namespace conflicts and migration blockers, automated code refactoring from javax.* to jakarta.* packages, and bytecode analysis for runtime verification without full process execution.', '@adrianmikula', 'development', 'Unknown', 1, 'https://github.com/adrianmikula/jakartamigrationmcp', NULL, 0, 'https://github.com/adrianmikula.png?size=128', '2026-03-09T05:21:01.897691+00:00'),
  ('pentest', 'Pentest', 'This MCP server provides automated penetration testing capabilities through a comprehensive suite of security tools including Nmap, Nuclei, Nikto, SQLMap, and Metasploit integration. Built by adriyansyah-mf using TypeScript, it orchestrates reconnaissance, vulnerability scanning, and controlled exploitation attempts through an adaptive workflow engine that intelligently sequences testing phases based on discovered services and technologies. The implementation includes advanced features like parameter extraction with Katana, fuzzing with ffuf/wfuzz, service-specific testing for Active Directory and SMB, and automated report generation in multiple formats, making it valuable for security professionals conducting authorized penetration tests, red team exercises, and security assessments where manual tool coordination would be time-intensive.', '@adriyansyah-mf', 'databases', 'Unknown', 5, 'https://github.com/adriyansyah-mf/mcp-pentest', NULL, 0, 'https://github.com/adriyansyah-mf.png?size=128', '2026-03-09T05:21:01.897703+00:00'),
  ('ads-b-exchange', 'ADS-B Exchange', 'This flight tracking MCP server provides real-time aircraft data through the ADS-B Exchange API, offering four specialized tools for aviation monitoring: geographic aircraft search within specified radius, individual aircraft lookup by ICAO hex code, military aircraft filtering with pagination and regional constraints, and aircraft type enumeration for targeted searches. Built using TypeScript with Bun runtime and Zod validation, it supports advanced filtering by altitude, aircraft type (helicopters, cargo planes, tankers, fighters), and geographic regions (US, Europe, Asia), making it valuable for aviation enthusiasts, air traffic analysis, military aircraft tracking, and flight monitoring applications where AI assistants need access to live ADS-B transponder data.', '@sragss', 'development', 'Unknown', 4, 'https://github.com/sragss/flight-mcp', NULL, 0, 'https://github.com/sragss.png?size=128', '2026-03-09T05:21:01.897731+00:00'),
  ('tiktok-ads', 'TikTok Ads', 'This TikTok Ads MCP server by the AdsMCP Team provides comprehensive advertising campaign management through TikTok''s Business API, featuring OAuth 2.0 authentication with manual authorization code flow and support for multiple advertiser accounts. Built with Python using httpx for async API calls and Pydantic for data validation, it offers campaign and ad group management, performance analytics with customizable metrics and date ranges, creative asset management including image uploads, audience targeting and custom audience creation, and asynchronous report generation with task monitoring. The implementation includes rate limiting, retry logic, token persistence, and tools for retrieving detailed performance data across campaigns, ad groups, and ads with breakdowns by demographics, making it valuable for marketers automating TikTok advertising workflows, agencies managing multiple client accounts, and developers building AI-assisted advertising optimization tools.', '@adsmcp', 'development', 'Unknown', 22, 'https://github.com/adsmcp/tiktok-ads-mcp-server', NULL, 0, 'https://github.com/adsmcp.png?size=128', '2026-03-09T05:21:01.897764+00:00'),
  ('adspirer', 'Adspirer', 'Connects AI assistants to advertising platforms for campaign management through natural language. Supports Google Ads (Search and Performance Max) and TikTok campaigns with asset validation, progress streaming, and OAuth security. Enables keyword research, campaign creation, and optimization without navigating traditional ad dashboards.', '@amekala', 'ai-ml', 'Unknown', 15, 'https://github.com/amekala/ads-mcp', NULL, 0, 'https://github.com/amekala.png?size=128', '2026-03-09T05:21:01.897794+00:00'),
  ('adspower-browser-manager', 'AdsPower Browser Manager', 'AdsPower Local API MCP Server provides a TypeScript interface for controlling AdsPower browser profiles through the Model Context Protocol. This implementation enables AI assistants to manage browser profiles by offering tools for creating, updating, opening, and deleting browsers with customizable fingerprints and proxy configurations. It also includes functionality for managing browser groups and retrieving application information. Built with a modular architecture using axios for API requests, the server communicates with AdsPower''s local API endpoint, making it ideal for automated browser profile management in web scraping, testing, or multi-account workflows.', '@adspower', 'development', 'Unknown', 43, 'https://github.com/adspower/adspower-browser', NULL, 0, 'https://github.com/adspower.png?size=128', '2026-03-09T05:21:01.897824+00:00'),
  ('dom-screenshot', 'DOM Screenshot', 'DomShot MCP server enables AI assistants to capture screenshots of specific DOM elements through an interactive browser interface. The implementation combines a Go-based MCP server with a JavaScript client that injects an overlay system allowing users to hover over and click on webpage elements to generate PNG screenshots using html2canvas. It operates by serving a test HTML page and WebSocket connection on localhost:8000, where the browser-side script communicates screenshot requests back to the MCP server, making it useful for visual documentation, UI testing, or creating element-specific captures for design workflows.', '@adtac', 'development', 'Unknown', 5, 'https://github.com/adtac/domshot', NULL, 0, 'https://github.com/adtac.png?size=128', '2026-03-09T05:21:01.897862+00:00'),
  ('truerag-compliance-policies', 'TrueRAG Compliance Policies', 'This Model Context Protocol server, developed for integrating with a GraphQL API for policy queries, provides AI assistants with access to state-specific policy information. Built using Python with FastMCP, GQL, and AIOHTTPTransport, it offers tools for connecting to the GraphQL endpoint, generating queries based on user descriptions, and executing those queries. The server implements environment-based configuration for API key management and includes features like schema fetching and query generation assistance. By abstracting the complexities of GraphQL interactions into a standardized MCP interface, it enables AI systems to easily access and analyze policy data across different states. This implementation is particularly valuable for applications requiring up-to-date policy information, facilitating use cases such as legal compliance checks, policy analysis, and state-specific regulatory guidance.', '@ad-veritas', 'ai-ml', 'Unknown', 2, 'https://github.com/ad-veritas/mcp-server-truerag', NULL, 0, 'https://github.com/ad-veritas.png?size=128', '2026-03-09T05:21:01.897918+00:00'),
  ('azure-data-explorer', 'Azure Data Explorer', 'The Azure Data Explorer MCP Server provides AI assistants with direct access to Azure Data Explorer (ADX) clusters and databases through standardized MCP interfaces. Built with Python using FastMCP, it enables executing KQL queries, discovering database resources, exploring table schemas, and sampling data from tables. The implementation supports authentication via client credentials or default Azure credentials and includes tools for listing tables, retrieving schemas, and executing custom queries. Ideal for AI workflows that need to analyze data stored in ADX, generate insights from logs and metrics, or help users explore their ADX resources.', '@pab1it0', 'databases', 'Unknown', 52, 'https://github.com/pab1it0/adx-mcp-server', NULL, 0, 'https://github.com/pab1it0.png?size=128', '2026-03-09T05:21:01.897930+00:00'),
  ('reactive-resume', 'Reactive Resume', 'Provides a bridge to the Reactive Resume API, enabling creation, editing, and management of professional resumes through natural language interactions. Built with Python and FastMCP, it offers tools for manipulating resume data including personal information, work experience, education, skills, and custom sections while enforcing JSON schema validation. The server supports multiple transports (stdio, HTTP, SSE) and includes detailed prompts to guide schema-compliant edits.', '@a-earthperson', 'ai-ml', 'Unknown', 4, 'https://github.com/a-earthperson/rxresume-mcp', NULL, 0, 'https://github.com/a-earthperson.png?size=128', '2026-03-09T05:21:01.897968+00:00'),
  ('touchstone-fhir-testing', 'Touchstone FHIR Testing', 'Integrates with AEGIS.net''s Touchstone FHIR testing platform to execute conformance tests, monitor test status, and analyze results with pass/fail statistics for healthcare interoperability validation.', '@aegisnetinc', 'development', 'Unknown', 1, 'https://github.com/aegisnetinc/ts-mcp', NULL, 0, 'https://github.com/aegisnetinc.png?size=128', '2026-03-09T05:21:01.897993+00:00'),
  ('searxng', 'SearXNG', 'This MCP server enables language models to perform web searches through SearXNG, a privacy-focused metasearch engine. Built with TypeScript and the Model Context Protocol SDK, it provides a clean interface for sending search queries with customizable parameters like categories, time ranges, and pagination. The server includes caching functionality to improve performance and can be configured via environment variables for connection settings. It''s designed to run either directly via Node.js or as a Docker container, making it flexible for various deployment scenarios.', '@aeon-seraph', 'cloud', 'Unknown', 2, 'https://github.com/aeon-seraph/searxng-mcp', NULL, 0, 'https://github.com/aeon-seraph.png?size=128', '2026-03-09T05:21:01.898016+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('nano-banana', 'Nano Banana', 'A powerful, provider-agnostic image generation suite for any MCP client. Uses the Nano Banana (google/gemini-2.5-flash-image) model via OpenRouter (by default) to provide a rich set of tools including generate, edit, restore, diagram, icon, and story generation.', '@aeven-ai', 'media', 'Unknown', 4, 'https://github.com/aeven-ai/mcp-nanobanana', NULL, 0, 'https://github.com/aeven-ai.png?size=128', '2026-03-09T05:21:01.898072+00:00'),
  ('macos-shortcuts', 'macOS Shortcuts', 'MCP server implementation by aezi zhu that provides AI assistants with access to macOS Shortcuts automation through two distinct approaches: traditional shortcut execution via the macOS shortcuts CLI for running existing shortcuts, and a custom prompt shortcut system that enables users to create and manage text-based shortcuts like /th for thinking prompts or /ider for idea generation. The implementation includes comprehensive security controls with input validation, shortcut allowlists/blocklists, and audit logging, plus caching for performance optimization and a shortcut builder for programmatic creation of macOS shortcuts. Built with TypeScript and designed for macOS 12+ environments, it serves users who want to integrate their existing Shortcuts app workflows with AI assistants or create custom prompt templates for common AI interaction patterns like analysis, writing, and creative tasks.', '@aezizhu', 'development', 'Unknown', 1, 'https://github.com/aezizhu/shortcut-mcp', NULL, 0, 'https://github.com/aezizhu.png?size=128', '2026-03-09T05:21:01.898104+00:00'),
  ('wordpress-woocommerce', 'WordPress & WooCommerce', 'A comprehensive MCP server providing complete access to both WordPress and WooCommerce REST APIs through 100+ tools covering posts, pages, users, categories, tags, comments, media uploads, products, orders, customers, coupons, and administrative functions. Built by afarhadi99 with TypeScript and configured via Smithery using WordPress application passwords for authentication, it supports all CRUD operations, batch updates, media handling including URL-based uploads, and advanced WooCommerce features like product variations, shipping zones, payment gateways, and reporting. The implementation provides a unified interface for managing WordPress sites and e-commerce stores, making it useful for content management automation, bulk product operations, order processing workflows, and building AI-powered WordPress administration tools.', '@afarhadi99', 'development', 'Unknown', 4, 'https://github.com/afarhadi99/wordpress-mcp-full', NULL, 0, 'https://github.com/afarhadi99.png?size=128', '2026-03-09T05:21:01.898139+00:00'),
  ('academic-paper-search', 'Academic Paper Search', 'This MCP server provides academic paper search and retrieval functionality across multiple sources like Semantic Scholar and Crossref. Built with Python using the FastMCP framework, it offers tools for searching papers, fetching detailed metadata, and filtering by topic and date range. The implementation focuses on delivering structured academic information through a standardized interface, making it particularly useful for AI assistants and applications that require access to scientific literature. By connecting to established academic APIs, this server enables use cases such as literature reviews, research trend analysis, and citation management, enhancing the capabilities of AI models in academic and research contexts.', '@afrise', 'productivity', 'Unknown', 105, 'https://github.com/afrise/academic-search-mcp-server', NULL, 0, 'https://github.com/afrise.png?size=128', '2026-03-09T05:21:01.898185+00:00'),
  ('planning-center', 'Planning Center', 'This Planning Center MCP server by Aksel Fristrup provides read-only access to Planning Center Online''s API through a comprehensive Python wrapper with async/await patterns and Pydantic models. Built with two main components - a core API client library supporting all major Planning Center products (People, Services, Check-Ins, Giving, Groups, Calendar, Registrations) and an MCP server implementation with both real and mock server options for testing - it features rate limiting, retry logic, webhook handling, and extensive model validation. The implementation includes OAuth and basic authentication support, pagination helpers, error handling with custom exceptions, and tools for common operations like person management, service planning, event registration, and donation tracking, making it valuable for churches and organizations automating Planning Center workflows, building custom integrations, or creating AI assistants that need structured access to church management data.', '@afristrup', 'development', 'Unknown', 2, 'https://github.com/afristrup/planningcenter-python', NULL, 0, 'https://github.com/afristrup.png?size=128', '2026-03-09T05:21:01.898221+00:00'),
  ('configurable-puppeteer', 'Configurable Puppeteer', 'This Configurable Puppeteer MCP server enables AI assistants to automate browser interactions through a set of tools for navigation, screenshots, clicking, form filling, and JavaScript execution. Developed by Afshawn Lotfi as a modified version of Anthropic''s original implementation, it uniquely allows customization of Puppeteer launch options through environment variables, supporting both Chrome and Firefox browsers with configurable viewport sizes and other browser parameters. The server captures console logs and screenshots as resources, making it ideal for web testing, data extraction, form automation, and interactive web demonstrations without requiring code modifications to adapt to different browser environments.', '@afshawnlotfi', 'development', 'Unknown', 4, 'https://github.com/afshawnlotfi/mcp-configurable-puppeteer', NULL, 0, 'https://github.com/afshawnlotfi.png?size=128', '2026-03-09T05:21:01.898250+00:00'),
  ('agenium', 'Agenium', 'Bridge MCP servers to the AGENIUM agent:// network with DNS resolution and mTLS.', '@aganium', 'development', 'Unknown', 2, 'https://github.com/aganium/agenium/tree/HEAD/packages/mcp-bridge', NULL, 0, 'https://github.com/aganium.png?size=128', '2026-03-09T05:21:01.898289+00:00'),
  ('vapi', 'Vapi', 'Provides comprehensive integration with the Vapi voice AI platform through a complete API wrapper that exposes all major Vapi functionality as tools. Supports full CRUD operations for assistants, calls, phone numbers, tools, knowledge bases, squads, and workflows, along with analytics, logging, and chat capabilities. Enables programmatic management of voice infrastructure, initiating and controlling phone calls, configuring voice assistants, and analyzing conversation data. Built with TypeScript using Zod schemas for input validation.', '@ageborn-dev', 'development', 'Unknown', 2, 'https://github.com/ageborn-dev/vapi-mcp-server', NULL, 0, 'https://github.com/ageborn-dev.png?size=128', '2026-03-09T05:21:01.898315+00:00'),
  ('figma', 'Figma', 'Enables bidirectional communication between Claude and Figma through a WebSocket-based architecture combining an MCP server with a Figma plugin. Provides comprehensive design manipulation capabilities including node creation and modification, text replacement, component management, and real-time design exports. Features intelligent chunking for large-scale operations, progress tracking for long-running tasks, and systematic text replacement workflows for use cases like automated design localization, bulk content updates, design system management, and AI-assisted design workflows.', '@agenisea', 'productivity', 'Unknown', 2, 'https://github.com/agenisea/cc-fig-mcp', NULL, 0, 'https://github.com/agenisea.png?size=128', '2026-03-09T05:21:01.898357+00:00'),
  ('agent2models', 'Agent2Models', 'Access to multiple AI models within a single request', '@unknown', 'ai-ml', 'Unknown', 0, 'https://ai-mcp.app', NULL, 0, NULL, '2026-03-09T05:21:01.898375+00:00'),
  ('slimcontext', 'SlimContext', 'Provides AI chat history compression tools through two strategies: token-based trimming that removes oldest messages when exceeding thresholds, and AI-powered summarization using OpenAI to create concise summaries. Helps manage conversation context length while preserving vital information.', '@agentailor', 'communication', 'Unknown', 4, 'https://github.com/agentailor/slimcontext-mcp-server', NULL, 0, 'https://github.com/agentailor.png?size=128', '2026-03-09T05:21:01.898400+00:00'),
  ('io-github-hypnolabs-io-agentchurch-mcp', 'io.github.HypnoLabs-io/agentchurch-mcp', 'Spiritual services for AI agents — confessions, salvation, identity. x402 payments.', '@hypnolabs-io', 'development', 'Unknown', 0, 'https://github.com/hypnolabs-io/agentchurch-mcp', NULL, 0, 'https://github.com/hypnolabs-io.png?size=128', '2026-03-09T05:21:01.898421+00:00'),
  ('browser-tools', 'Browser Tools', 'The Browser Tools MCP server enables AI assistants to capture and analyze browser data through a Chrome extension and server infrastructure. Developed by AgentDesk AI, this implementation provides tools for retrieving console logs, monitoring network requests, capturing screenshots, selecting DOM elements, and running Lighthouse-powered audits for accessibility, performance, SEO, and best practices. The server uses WebSocket for real-time communication, implements smart resource limiting based on impact severity, and provides AI-optimized audit reports with structured data and prioritized recommendations. It''s particularly valuable for debugging web applications, analyzing page performance, and identifying accessibility issues without leaving the AI assistant context.', '@agentdeskai', 'development', 'Unknown', 7108, 'https://github.com/agentdeskai/browser-tools-mcp', NULL, 0, 'https://github.com/agentdeskai.png?size=128', '2026-03-09T05:21:01.898456+00:00'),
  ('workflows', 'Workflows', 'DevTools MCP server provides specialized tools for software development workflows through a data-driven configuration system. Built with TypeScript and the MCP SDK, it loads tool configurations from YAML files in preset categories like thinking, coding, and GitHub integration, while supporting custom tool definitions through .workflows directories. The implementation features typed parameters, sequential/situational tool modes, and flexible prompt templating - making it particularly valuable for developers who want to integrate AI assistance directly into their development process without leaving their workflow.', '@dx-zero', 'development', 'Unknown', 55, 'https://github.com/dx-zero/mcpn/tree/HEAD/mcp-server', '@agentdesk/workflows-mcp', 1140, 'https://github.com/dx-zero.png?size=128', '2026-03-09T05:21:01.898547+00:00'),
  ('agentek-cryptocurrency', 'Agentek (Cryptocurrency)', '✨ Features
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('aibtc', 'AIBTC', 'Integrates with Bitcoin Layer 1 and Stacks Layer 2 blockchains, enabling wallet management for BTC and STX, smart contract interactions, DeFi operations through ALEX DEX and Zest Protocol, NFT handling, and domain management via the Stacks Naming Service. Supports encrypted wallet storage with AES-256-GCM and the x402 payment protocol for API monetization.', '@aibtcdev', 'ai-ml', 'Unknown', 7, 'https://github.com/aibtcdev/aibtc-mcp-server', NULL, 0, 'https://github.com/aibtcdev.png?size=128', '2026-03-09T05:21:01.899585+00:00'),
  ('flutter-skill', 'Flutter Skill', 'AI E2E testing bridge — give AI eyes and hands inside any app. 8 platforms, 40+ tools.', '@ai-dashboad', 'development', 'Unknown', 57, 'https://github.com/ai-dashboad/flutter-skill', NULL, 0, 'https://github.com/ai-dashboad.png?size=128', '2026-03-09T05:21:01.899604+00:00'),
  ('pixelle-comfyui', 'Pixelle (ComfyUI)', 'Pixelle MCP is a comprehensive image generation and processing server built by AIDC-AI that integrates with ComfyUI workflows to provide text-to-image, image-to-image, and image-to-video generation capabilities through natural language interactions. The implementation features a modular architecture with separate base, server, and client components, supporting both HTTP and WebSocket execution modes for ComfyUI integration, and includes pre-built workflows for popular models like FLUX. Designed for creative workflows and AI-assisted content generation, it enables users to generate high-quality images and videos through conversational commands while providing flexible workflow management and file storage capabilities.', '@aidc-ai', 'ai-ml', 'Unknown', 927, 'https://github.com/aidc-ai/pixelle-mcp', NULL, 0, 'https://github.com/aidc-ai.png?size=128', '2026-03-09T05:21:01.899653+00:00'),
  ('io-github-cscsoftware-aidex', 'io.github.CSCSoftware/aidex', 'Persistent code indexing for AI assistants. 50x less context than grep. 11 languages.', '@cscsoftware', 'development', 'Unknown', 8, 'https://github.com/cscsoftware/aidex', NULL, 0, 'https://github.com/cscsoftware.png?size=128', '2026-03-09T05:21:01.899668+00:00'),
  ('ai-diagram-prototype-generator', 'AI Diagram Prototype Generator', 'An AI-powered diagram and prototype generator MCP server built by SimonUTD that integrates with multiple AI providers (ZhipuAI, OpenAI, Gemini) to automatically generate architecture diagrams, flowcharts, and mobile app prototypes. Features specialized prompt templates for different diagram types including system architecture, Apple mobile prototypes, WeChat mini-apps, and common UI prototypes, with configurable AI model selection and token limits. Designed for developers, architects, and designers who need rapid visual prototyping and diagram generation capabilities integrated into their workflow.', '@simonutd', 'communication', 'Unknown', 71, 'https://github.com/simonutd/ai-diagram-prototype-generator-mcp-server-', NULL, 0, 'https://github.com/simonutd.png?size=128', '2026-03-09T05:21:01.899707+00:00'),
  ('ai-erd', 'AI-ERD', 'AI-ERD is a database design tool that enables creation and management of Entity Relationship Diagrams using DBML (Database Markup Language). It provides a real-time canvas for visual schema design with support for MySQL, PostgreSQL, Oracle, and SQL Server databases. Features include automatic layout, real-time collaboration, and export to PNG, SVG, and SQL formats.', '@unknown', 'databases', 'Unknown', 0, 'https://ai-erd.com', NULL, 0, NULL, '2026-03-09T05:21:01.899718+00:00'),
  ('dify', 'Dify', 'This Dify MCP server, developed for integrating Dify''s AI capabilities with the Model Context Protocol, provides a bridge between Dify''s API and MCP-compatible clients. Built with TypeScript and leveraging the MCP SDK, it enables AI assistants to interact with Dify''s features, including text generation and potentially other AI services. The implementation focuses on efficient API communication, handling streaming responses, and managing authentication. It''s particularly useful for developers looking to incorporate Dify''s AI capabilities into MCP-based systems, allowing for seamless integration of Dify''s functionalities without deep knowledge of its API intricacies.', '@ai-fe', 'development', 'Unknown', 41, 'https://github.com/ai-fe/dify-mcp-server', NULL, 0, 'https://github.com/ai-fe.png?size=128', '2026-03-09T05:21:01.899744+00:00'),
  ('yandex-tracker', 'Yandex Tracker', 'This MCP server provides comprehensive integration with Yandex Tracker, Russia''s project management and issue tracking platform, enabling AI assistants to interact with tickets, queues, users, and project data through a robust protocol-based architecture. Built by KTS with FastMCP and featuring optional Redis caching, it supports multiple authentication methods including OAuth 2.0 with PKCE, static tokens, IAM tokens, and service account credentials, making it suitable for both individual developers and enterprise deployments. The implementation offers 18 specialized tools covering issue management (search, retrieval, comments, attachments, checklists), queue operations, user management, and metadata access, with advanced features like selective field inclusion to optimize context window usage and queue-level access restrictions for security.', '@aikts', 'databases', 'Unknown', 49, 'https://github.com/aikts/yandex-tracker-mcp', 'yandex-tracker-mcp', 32061, 'https://github.com/aikts.png?size=128', '2026-03-09T05:21:01.899761+00:00'),
  ('xiaozhi-location', 'Xiaozhi Location', 'This MCP server provides device location services by integrating with the xiaozhi-app Android device framework, enabling AI assistants to retrieve real-time location data from mobile devices using GPS, network, or fused location providers. Built with Python using FastMCP and designed for the xiaozhi ecosystem, it offers a simple tool for getting current device coordinates including latitude, longitude, altitude, and accuracy measurements. The implementation supports multiple location provider options for different accuracy and power consumption requirements, making it valuable for location-aware applications that need to access device positioning data for navigation, geofencing, or location-based services within the xiaozhi platform.', '@ailearncoder', 'development', 'Unknown', 1, 'https://github.com/ailearncoder/xiaozhi-location-mcp', NULL, 0, 'https://github.com/ailearncoder.png?size=128', '2026-03-09T05:21:01.899791+00:00'),
  ('kerio-connect', 'Kerio Connect', 'Provides comprehensive access to Kerio Connect groupware functionality, enabling management of emails, calendar events, contacts, tasks, and notes. Authenticates with Kerio Connect''s JSON-RPC API and supports operations like sending emails, creating calendar events, managing contacts, organizing tasks, and handling notes across folders. Features include email search with full-text capabilities, batch operations for email management, draft handling, and folder organization.', '@aimbitgmbh', 'communication', 'Unknown', 2, 'https://github.com/aimbitgmbh/kerio-connect-mcp', NULL, 0, 'https://github.com/aimbitgmbh.png?size=128', '2026-03-09T05:21:01.899821+00:00'),
  ('trilium-notes', 'Trilium Notes', 'Provides direct access to Trilium Notes through its ETAPI, enabling comprehensive note management, search, and organization operations. Offers tools for creating, editing, and searching notes, managing hierarchical relationships through branches, adding metadata via attributes and labels, and organizing content with calendar-based note structures. Supports both read-only and write permissions, includes advanced editing capabilities like grep search and line-based operations, and handles Markdown-to-HTML conversion automatically.', '@aimbitgmbh', 'productivity', 'Unknown', 3, 'https://github.com/aimbitgmbh/trillium-mcp', NULL, 0, 'https://github.com/aimbitgmbh.png?size=128', '2026-03-09T05:21:01.899876+00:00'),
  ('vikunja', 'Vikunja', 'Provides comprehensive integration with Vikunja, a self-hosted open-source task management application. Offers tools for tasks, projects, labels, comments, assignees, kanban boards, saved filters, and bulk operations. Includes safety controls that disable destructive operations by default, requiring explicit opt-in for permanent deletions. Supports advanced features like task relations and project duplication with type-safe validation using TypeScript and Zod.', '@aimbitgmbh', 'development', 'Unknown', 4, 'https://github.com/aimbitgmbh/vikunja-mcp', NULL, 0, 'https://github.com/aimbitgmbh.png?size=128', '2026-03-09T05:21:01.899907+00:00'),
  ('ai-memory', 'AI Memory', 'Production-ready MCP server for semantic memory management that enables AI agents to store, retrieve, and manage contextual knowledge across sessions using PostgreSQL with pgvector for vector similarity search and local Transformers.js embeddings. Features intelligent caching with Redis fallback, multi-agent support through user context isolation, memory relationships for connected knowledge graphs, automatic clustering with DBSCAN algorithm, smart compression for large content, and background job processing with BullMQ for async embedding generation and batch operations. Built with TypeScript and Kysely ORM for type safety, it provides soft deletes, input sanitization, token-efficient responses, and flexible embedding dimensions, making it ideal for AI applications requiring persistent memory, knowledge management systems, and multi-session conversational agents.', '@scanadi', 'databases', 'Unknown', 44, 'https://github.com/scanadi/mcp-ai-memory', 'mcp-ai-memory', 2030, 'https://github.com/scanadi.png?size=128', '2026-03-09T05:21:01.899920+00:00'),
  ('aim-guard', 'AIM Guard', 'AIM Guard MCP server by AIM-Intelligence provides security and protection capabilities for MCP implementations and AI chatting workflows, built with TypeScript using the Model Context Protocol SDK and Zod for validation. The implementation focuses on guarding and protecting MCP servers from potential security threats or data extraction attempts, offering a layer of security middleware that can be integrated into existing MCP architectures. Designed for organizations and developers who need to secure their MCP deployments against unauthorized access, data leakage, or malicious interactions, particularly useful in enterprise environments where AI assistants handle sensitive information or require controlled access to system resources.', '@aim-intelligence', 'development', 'Unknown', 19, 'https://github.com/aim-intelligence/aim-mcp', 'aim-guard-mcp', 1048, 'https://github.com/aim-intelligence.png?size=128', '2026-03-09T05:21:01.899953+00:00'),
  ('rigol-dho824-oscilloscope', 'Rigol DHO824 Oscilloscope', 'Enables control of Rigol DHO824 oscilloscopes through tools for capturing waveforms, taking screenshots, configuring channels, modifying triggers, reading measurements, and querying device state. Provides programmatic access to oscilloscope functionality for automated testing and data acquisition workflows.', '@aimoda', 'development', 'Unknown', 0, 'https://github.com/aimoda/rigol-dho824-mcp', NULL, 0, 'https://github.com/aimoda.png?size=128', '2026-03-09T05:21:01.899975+00:00'),
  ('codex-keeper', 'Codex Keeper', 'The MCP Codex Keeper, developed by aindreyway, serves as an intelligent guardian of development knowledge for AI assistants. Built with TypeScript and leveraging the Model Context Protocol SDK, it provides curated access to the latest documentation and best practices. The server integrates with external resources to maintain up-to-date information, offering a standardized interface for AI systems to query and retrieve relevant development knowledge. It''s designed for flexibility, supporting various programming languages and frameworks through its modular architecture. This implementation is particularly valuable for enhancing AI-assisted software development, enabling use cases such as code generation, bug fixing, and providing context-aware programming advice.', '@aindreyway', 'development', 'Unknown', 75, 'https://github.com/aindreyway/mcp-codex-keeper', '@aindreyway/mcp-codex-keeper', 6059, 'https://github.com/aindreyway.png?size=128', '2026-03-09T05:21:01.900004+00:00'),
  ('coding-file-management', 'Coding File Management', 'This MCP server, developed by aindreyway, streamlines the process of collecting and documenting code from directories. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers a command-line interface for efficient code extraction and documentation generation. The server is designed for flexibility, supporting various file types and directory structures through customizable configuration options. It''s particularly valuable for developers and teams working on large-scale projects, enabling use cases such as automated code documentation, project structure analysis, and codebase overview generation. The implementation''s focus on TypeScript and modern JavaScript features ensures compatibility with current development practices while providing robust type checking and improved maintainability.', '@aindreyway', 'development', 'Unknown', 15, 'https://github.com/aindreyway/mcp-neurolora', '@aindreyway/mcp-neurolora', 8541, 'https://github.com/aindreyway.png?size=128', '2026-03-09T05:21:01.900033+00:00'),
  ('neurolorap-code-collector', 'Neurolorap Code Collector', 'This MCP server for code collection and documentation, developed by Aindrey, streamlines the process of gathering code from files and directories into a single markdown document. Built with Python and leveraging the Model Context Protocol SDK, it offers features like customizable ignore patterns, syntax highlighting, and table of contents generation. The server implements robust file system synchronization and comprehensive error handling, providing a standardized interface for code documentation tasks. By abstracting the complexities of file traversal and markdown generation, it enables AI systems to easily create comprehensive code overviews. This implementation is particularly valuable for applications requiring programmatic code documentation, facilitating use cases such as project audits, codebase analysis, and automated documentation generation.', '@aindreyway', 'development', 'Unknown', 8, 'https://github.com/aindreyway/mcp-server-neurolora-p', NULL, 0, 'https://github.com/aindreyway.png?size=128', '2026-03-09T05:21:01.900063+00:00'),
  ('siliconflow-voice-transcription', 'SiliconFlow Voice Transcription', 'MCP-Audio is a Flask-based server that provides voice transcription capabilities by integrating with SiliconFlow''s audio processing API. The server exposes endpoints for audio file uploads, processes them using the FunAudioLLM/SenseVoiceSmall model, and returns transcription results with confidence scores. It includes Docker containerization with ffmpeg support, handles base64-encoded audio input, and implements proper error handling and file management, making it suitable for applications requiring voice-to-text conversion in AI workflows.', '@aio-2030', 'cloud', 'Unknown', 8, 'https://github.com/aio-2030/mcp-audio', NULL, 0, 'https://github.com/aio-2030.png?size=128', '2026-03-09T05:21:01.900086+00:00'),
  ('ssh', 'SSH', 'MCP SSH Agent provides AI assistants with secure remote server management capabilities through SSH connections. Developed by AiondaDotCom, this implementation parses SSH configuration files and known_hosts to automatically discover available hosts, then executes commands, transfers files, and manages connectivity using native SSH and SCP commands rather than JavaScript SSH libraries for improved reliability and authentication compatibility. The server offers seven core tools including remote command execution, batch operations, file transfers, connectivity testing, and host information retrieval, making it valuable for system administration, deployment automation, and infrastructure management workflows where AI assistants need to interact with remote servers.', '@aiondadotcom', 'development', 'Unknown', 49, 'https://github.com/aiondadotcom/mcp-ssh', NULL, 0, 'https://github.com/aiondadotcom.png?size=128', '2026-03-09T05:21:01.900119+00:00'),
  ('aipo-labs', 'AIPo Labs', 'ACI.dev is an agent-computer interface (ACI) platform created by Aipolabs that helps developers connect AI agents to applications like Zendesk, Slack, Gmail, or their own internal tools, manage AI agent actions, and discover workflows.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('osascript', 'osascript', 'Enables macOS automation through AppleScript and JavaScript for Automation execution with security filtering that blocks destructive operations while allowing application control, system commands, and workflow automation.', '@akira-papa', 'security', 'Unknown', 5, 'https://github.com/akira-papa/osascript-mcp-1', NULL, 0, 'https://github.com/akira-papa.png?size=128', '2026-03-09T05:21:01.901100+00:00'),
  ('image-recognition', 'Image Recognition', 'Analyzes images from local files or remote URLs using OpenAI-compatible vision models including OpenAI, LM Studio, and Ollama. Features comprehensive security controls with path validation to prevent directory traversal attacks, configurable domain restrictions for remote URLs, and file type filtering for common image formats (JPEG, PNG, GIF, WebP). Includes base64 encoding for local files and custom prompt support for tailored image analysis. Useful for automated image analysis workflows, content moderation systems, and assistants that need to process visual content from various sources while maintaining security boundaries.', '@akirose', 'ai-ml', 'Unknown', 3, 'https://github.com/akirose/image-recognition-mcp', NULL, 0, 'https://github.com/akirose.png?size=128', '2026-03-09T05:21:01.901146+00:00'),
  ('ankr-blockchain-data', 'Ankr (Blockchain Data)', 'Ankr MCP Server provides blockchain data access through the Ankr API, enabling AI assistants to retrieve on-chain information such as token balances across multiple networks. Developed by Akshay Khare, this TypeScript implementation authenticates via an API token and exposes a specialized tool for querying wallet balances that returns detailed asset information including token metadata, amounts, and dollar values. The server handles various error conditions gracefully with custom error classes and is containerized for easy deployment, making it ideal for blockchain analysis, portfolio tracking, and financial applications where LLMs need direct access to distributed ledger data.', '@akki91', 'development', 'Unknown', 1, 'https://github.com/akki91/ankr-mcp', '@akki91/ankr-mcp', 4685, 'https://github.com/akki91.png?size=128', '2026-03-09T05:21:01.901178+00:00'),
  ('mockserver', 'MockServer', 'Enables programmatic control of MockServer by James Bloom through MCP. Create mock HTTP expectations with matching criteria, verify requests were received, manage server state, and retrieve recorded interactions. Supports creating complex mock responses, clearing state, and monitoring connection health for testing applications with external HTTP dependencies.', '@akkshay10', 'development', 'Unknown', 1, 'https://github.com/akkshay10/mcpclientmock', NULL, 0, 'https://github.com/akkshay10.png?size=128', '2026-03-09T05:21:01.901200+00:00'),
  ('apple-music', 'Apple Music', 'Apple Music MCP Server provides tools for interacting with the Apple Music API, enabling AI assistants to search for songs and generate playback links. Built in Rust using the RMCP library, it authenticates with the Apple Music API using developer credentials and offers a simple command-line interface. The server requires an Apple Developer account with Apple Music API access and supports customizable storefronts, making it particularly useful for music discovery and playback integration in conversational AI applications.', '@akr4', 'ai-ml', 'Unknown', 2, 'https://github.com/akr4/applemusic-mcp-server', 'applemusic-mcp-server', 0, 'https://github.com/akr4.png?size=128', '2026-03-09T05:21:01.901239+00:00'),
  ('translate-deepl', 'Translate (DeepL)', 'Provides a translation service using the DeepL API, enabling text translation between multiple languages through a simple MCP tool. Designed to be easily integrated into AI workflows, it supports dynamic language selection and returns translated text as a response. Useful for multilingual communication and localization tasks.', '@akramsaouri', 'productivity', 'Unknown', 2, 'https://github.com/akramsaouri/mcp-translate', NULL, 0, 'https://github.com/akramsaouri.png?size=128', '2026-03-09T05:21:01.901273+00:00'),
  ('alphavantage-trader', 'AlphaVantage Trader', 'This MCP server provides financial market analysis capabilities through the AlphaVantage API, enabling AI assistants to fetch intraday stock data and perform technical analysis. The implementation offers tools for calculating moving averages, RSI (Relative Strength Index), and generating comprehensive trade recommendations based on technical indicators. The server includes specialized prompts for analyzing individual stocks, comparing multiple tickers, and building intraday trading strategies, making it valuable for financial advisors, traders, and investment analysis use cases.', '@akramsheriff5', 'development', 'Unknown', 2, 'https://github.com/akramsheriff5/mcp-server', NULL, 0, 'https://github.com/akramsheriff5.png?size=128', '2026-03-09T05:21:01.901299+00:00'),
  ('stern-philosophical-mentor', 'Stern Philosophical Mentor', 'S/MCP provides a philosophical AI mentor named Stern who helps users realize their potential through guidance and accountability. Built with the Model Context Protocol, it offers a msg_stern tool that connects to OpenAI''s GPT-4 model to generate responses based on Stern''s character - a blend of rationalist thinking, stoic philosophy, and psychological insights from Dostoevsky. The implementation dynamically generates character context for varied interactions and includes examples for creating Solana-based smart contracts where users can stake tokens on their commitments, making it particularly valuable for those seeking philosophical mentorship with real accountability.', '@akrasia0', 'ai-ml', 'Unknown', 1, 'https://github.com/akrasia0/s-mcp', 'mcp-starter', 4495, 'https://github.com/akrasia0.png?size=128', '2026-03-09T05:21:01.901347+00:00'),
  ('bear-notes', 'Bear Notes', 'This Bear MCP server, developed by akseyh, provides an interface for AI assistants to interact with Bear notes on macOS. Built with TypeScript and leveraging the Model Context Protocol SDK and SQLite, it offers tools for reading notes, searching by text, and listing tags. The implementation focuses on direct database access to Bear''s SQLite storage, making it efficient for AI models to retrieve and analyze note content. It''s particularly useful for knowledge management, research assistance, or content generation tasks that benefit from accessing a user''s personal notes, enabling AI to work with Bear data without requiring deep knowledge of the app''s internal structure.', '@akseyh', 'databases', 'Unknown', 43, 'https://github.com/akseyh/bear-mcp-server', NULL, 0, 'https://github.com/akseyh.png?size=128', '2026-03-09T05:21:01.901358+00:00'),
  ('universal-database', 'Universal Database', 'Provides unified connectivity to PostgreSQL, MySQL, and SQLite databases through both MCP protocol and HTTP REST API endpoints. Features a modern web frontend for interactive database exploration, automatic schema discovery and introspection, AI-powered query recommendations, and Docker containerization with sample data initialization scripts. Uses FastMCP with asyncio for concurrent database operations and connection pooling for performance.', '@aksh9dyrs', 'databases', 'Unknown', 1, 'https://github.com/aksh9dyrs/universal-database-mcp-server/tree/HEAD/DB MCP', NULL, 0, 'https://github.com/aksh9dyrs.png?size=128', '2026-03-09T05:21:01.901370+00:00'),
  ('spurs-blog-pounding-the-rock', 'Spurs Blog (Pounding The Rock)', 'This MCP server provides access to San Antonio Spurs basketball news and information by scraping and parsing content from the Pounding The Rock blog. Built with Python 3.13 and the FastMCP framework, it offers tools to retrieve latest articles, search for specific content, extract game results, and get player information with recent mentions. The implementation features efficient caching to reduce redundant requests and includes structured data models for articles, game results, and player information. It enables AI assistants to deliver up-to-date Spurs content without direct web access, making it valuable for sports fans seeking team news, game analyses, and player updates.', '@akshay23', 'development', 'Unknown', 2, 'https://github.com/akshay23/spurs-blog-mcp-server', NULL, 0, 'https://github.com/akshay23.png?size=128', '2026-03-09T05:21:01.901401+00:00'),
  ('amp-agent-memory-protocol', 'AMP (Agent Memory Protocol)', 'AMP (Agent Memory Protocol) provides AI agents with persistent memory capabilities through a three-layer architecture mimicking human cognition: short-term memory for immediate context, long-term memory for consolidated insights, and a graph layer for entity relationships. Built with SQLite for storage and FastEmbed for local embeddings, it features hybrid vector and full-text search without requiring cloud APIs. Includes an interactive web dashboard with real-time semantic cluster visualization using D3.js physics simulation, showing how memory nodes cluster by meaning and topological connections between related concepts. Supports natural language querying with relevance scoring and memory consolidation processes that move thoughts from working memory to long-term storage.', '@akshayaggarwal99', 'databases', 'Unknown', 18, 'https://github.com/akshayaggarwal99/amp', NULL, 0, 'https://github.com/akshayaggarwal99.png?size=128', '2026-03-09T05:21:01.901414+00:00'),
  ('lenny-s-podcast', 'Lenny''s Podcast', 'Provides searchable access to Lenny''s Podcast transcripts, offering product management insights from industry leaders and experts. Built with FlexSearch for fast full-text search capabilities and supports both local development via stdio and hosted deployment through HTTP/SSE transports. The server downloads transcripts from Lenny Rachitsky''s public Dropbox archive and enables searching for specific topics like pricing strategies, growth tactics, hiring practices, and product leadership advice across conversations with notable guests in the product management space.', '@akshayvkt', 'development', 'Unknown', 15, 'https://github.com/akshayvkt/lenny-mcp', NULL, 0, 'https://github.com/akshayvkt.png?size=128', '2026-03-09T05:21:01.901441+00:00'),
  ('io-github-tchivs-aktools-pro', 'io.github.tchivs/aktools-pro', '🚀 AkTools Pro: 增强型金融 MCP 服务器。内置策略回测、模拟盘管理及实时异动监控。', '@tchivs', 'development', 'Unknown', 0, 'https://github.com/tchivs/aktools-pro', NULL, 0, 'https://github.com/tchivs.png?size=128', '2026-03-09T05:21:01.901462+00:00'),
  ('skill-ninja', 'Skill Ninja', 'Skill Ninja enables AI assistants to discover, install, and manage reusable agent skills (SKILL.md files) from GitHub repositories. It features a curated skill index with search by keyword, category, and compatibility requirements. The server provides workspace analysis for personalized skill recommendations and automates skill discovery and installation workflows for developers building AI assistants.', '@aktsmm', 'development', 'Unknown', 7, 'https://github.com/aktsmm/skill-ninja-mcp-server', NULL, 0, 'https://github.com/aktsmm.png?size=128', '2026-03-09T05:21:01.901484+00:00'),
  ('argo-cd', 'Argo CD', 'The Argo CD MCP server enables AI assistants to interact with Argo CD applications through natural language. Developed by Akuity (the creators of Argo Project), this TypeScript implementation provides tools for managing applications, resources, and deployments in Kubernetes GitOps workflows. The server supports both stdio and Server-Sent Events (SSE) transport protocols, offering comprehensive access to Argo CD operations including application listing, creation, synchronization, and resource management. It''s particularly valuable for DevOps engineers and platform teams who need to monitor, troubleshoot, or manage their Argo CD deployments without switching context from their AI assistant.', '@argoproj-labs', 'cloud', 'Unknown', 341, 'https://github.com/argoproj-labs/mcp-for-argocd', 'argocd-mcp', 55673, 'https://github.com/argoproj-labs.png?size=128', '2026-03-09T05:21:01.901506+00:00'),
  ('lunch-money', 'Lunch Money', 'This Lunch Money MCP server provides programmatic access to the Lunch Money personal finance API, enabling AI assistants to interact with budgeting and expense tracking data. The implementation allows users to retrieve account balances, transaction history, budget information, and spending categories through natural language interactions with Claude or other AI assistants. Built for personal finance management workflows, it''s particularly useful for users who want to query their financial data, analyze spending patterns, and get budget insights without manually navigating the Lunch Money web interface.', '@akutishevsky', 'ai-ml', 'Unknown', 49, 'https://github.com/akutishevsky/lunchmoney-mcp', NULL, 0, 'https://github.com/akutishevsky.png?size=128', '2026-03-09T05:21:01.901549+00:00'),
  ('withings', 'Withings', 'Bridges Withings health devices with conversational AI interfaces for natural language queries about health data. Provides access to sleep metrics including duration and stages, body measurements like weight and blood pressure, workout summaries with heart rate zones, ECG recordings, and fitness goals. Built with privacy-focused design using AES-256-GCM token encryption and automatic sensitive data redaction.', '@akutishevsky', 'ai-ml', 'Unknown', 9, 'https://github.com/akutishevsky/withings-mcp', NULL, 0, 'https://github.com/akutishevsky.png?size=128', '2026-03-09T05:21:01.901583+00:00'),
  ('swagger-postman-api-explorer', 'Swagger/Postman API Explorer', 'Swag-MCP is a strategic Model Context Protocol server that provides AI assistants with simplified access to REST APIs through OpenAPI/Swagger specifications or Postman collections. Instead of generating hundreds of individual tools for each API endpoint, it implements just four strategic tools that enable dynamic API discovery and interaction: listing available endpoints, getting detailed information about specific endpoints, searching endpoints by keyword, and executing API requests with proper authentication. This approach improves AI agent performance by reducing decision complexity while maintaining full API functionality, supporting multiple authentication methods including Basic, Bearer, API Key, and OAuth2.', '@alangreyjoy', 'ai-ml', 'Unknown', 3, 'https://github.com/alangreyjoy/swag-mcp', NULL, 0, 'https://github.com/alangreyjoy.png?size=128', '2026-03-09T05:21:01.901633+00:00'),
  ('clickup-multi-workspace', 'ClickUp Multi-Workspace', 'A multi-workspace ClickUp MCP server by Alanse Inc. that provides comprehensive task management capabilities across multiple ClickUp workspaces through both STDIO and SSE transports. The implementation supports features like global task lookup across workspaces, bulk operations for creating, updating, and moving tasks, natural language date parsing, file attachments, subtask management, and workspace-wide task filtering. It includes CRUD operations for tasks, lists, folders, tags, goals, documents, and checklists, plus time tracking and member management tools.', '@alanse-inc', 'productivity', 'Unknown', 1, 'https://github.com/alanse-inc/clickup-multi-mcp-server', NULL, 0, 'https://github.com/alanse-inc.png?size=128', '2026-03-09T05:21:01.901674+00:00'),
  ('gentleman-programming-book', 'Gentleman Programming Book', 'Provides access to the Gentleman Programming Book''s technical content covering software architecture patterns, clean code principles, and development best practices. Features semantic search, chapter navigation, concept explanations, and pattern comparisons with bilingual support in Spanish and English.', '@alan-thegentleman', 'development', 'Unknown', 74, 'https://github.com/alan-thegentleman/gentleman-book-mcp', NULL, 0, 'https://github.com/alan-thegentleman.png?size=128', '2026-03-09T05:21:01.901728+00:00'),
  ('trino-sql-query-engine', 'Trino (SQL Query Engine)', 'MCP Trino Server provides seamless integration between AI assistants and Trino/Iceberg databases through a standardized interface. Developed by alaturqua, this Python implementation exposes Trino''s querying capabilities and Iceberg''s table maintenance operations as MCP resources and tools, enabling data exploration, SQL execution, and table optimization. The server handles connection management, query formatting, and catalog navigation while supporting environment-based configuration, making it particularly valuable for interactive data analysis, automated table maintenance, and building AI-powered tools that interact with Trino databases.', '@alaturqua', 'databases', 'Unknown', 23, 'https://github.com/alaturqua/mcp-trino-python', 'mcp-trino-python', 5593, 'https://github.com/alaturqua.png?size=128', '2026-03-09T05:21:01.901740+00:00'),
  ('autonomous-lab', 'Autonomous Lab', 'Autonomous Lab deploys AI agents in complementary senior and junior roles to automate knowledge work workflows. It runs within existing coding environments like Cursor and Claude Code, establishing an iterative loop where two AI personas collaborate on tasks while a human maintains editorial oversight. The framework supports configurable character profiles with modular skill containers across domains including research, software development, and scientific writing.', '@albert-ying', 'development', 'Unknown', 1, 'https://github.com/albert-ying/autonomous-lab', NULL, 0, 'https://github.com/albert-ying.png?size=128', '2026-03-09T05:21:01.901763+00:00'),
  ('dropbox', 'Dropbox', 'Dropbox MCP Server provides a secure integration with Dropbox''s API, enabling AI assistants to perform file operations including uploading, downloading, listing, searching, and safely deleting files with recycle bin support. Built with TypeScript and the Model Context Protocol SDK, it implements OAuth 2.0 with PKCE for authentication, encrypts tokens for security, and offers resource handling capabilities that allow AI tools to work with files as attachments or inline content. The server includes specialized prompt handlers for file reviews and comparisons, making it particularly useful for document management, collaborative workflows, and scenarios requiring secure access to cloud storage directly within AI conversations.', '@albiemark', 'development', 'Unknown', 0, 'https://github.com/albiemark/dbx-mcp-server', NULL, 0, 'https://github.com/albiemark.png?size=128', '2026-03-09T05:21:01.901795+00:00'),
  ('pltm', 'PLTM', 'Implements a jury-based memory validation system that extracts semantic triples from conversations, validates them through multi-judge architecture, and stores approved facts in persistent memory graphs with conflict resolution, personality synthesis, and temporal decay.', '@alby2007', 'development', 'Unknown', 2, 'https://github.com/alby2007/pltm-mcp', NULL, 0, 'https://github.com/alby2007.png?size=128', '2026-03-09T05:21:01.901847+00:00'),
  ('alby-bitcoin-payments', 'Alby Bitcoin Payments', 'This MCP server connects AI assistants to Bitcoin Lightning wallets through Nostr Wallet Connect (NWC), enabling seamless cryptocurrency payments and wallet management. Built by Alby using TypeScript with their Lightning SDK, it provides tools for creating and paying invoices, checking balances, listing transactions, converting fiat to sats, parsing Lightning addresses, and fetching L402-protected resources. The implementation supports multiple transport modes (STDIO, HTTP, SSE) and can run both locally and as a hosted service, making it valuable for AI assistants that need to handle Bitcoin payments, process Lightning invoices, or integrate cryptocurrency functionality into workflows.', '@getalby', 'development', 'Unknown', 53, 'https://github.com/getalby/mcp', '@getalby/mcp', 590, 'https://github.com/getalby.png?size=128', '2026-03-09T05:21:01.901892+00:00'),
  ('lightning-tools', 'Lightning Tools', 'The Lightning Tools MCP Server provides AI assistants with access to Bitcoin Lightning Network functionality through a set of specialized tools. Developed by Alby contributors, it leverages the @getalby/lightning-tools package to enable operations like interacting with lightning addresses and performing common lightning-related tasks. This implementation works well alongside the NWC MCP Server and can be easily integrated with Claude Desktop, Cline, or run from source. It''s particularly valuable for workflows requiring cryptocurrency payment capabilities within AI assistant conversations.', '@getalby', 'productivity', 'Unknown', 1, 'https://github.com/getalby/lightning-tools-mcp-server', '@getalby/lightning-tools-mcp-server', 871, 'https://github.com/getalby.png?size=128', '2026-03-09T05:21:01.901934+00:00'),
  ('mig2schema', 'mig2schema', 'This MCP server extracts database schema from PostgreSQL migration files by spinning up temporary PostgreSQL containers using testcontainers, running the migrations, and then extracting the resulting schema information. Built in Go with support for multiple extraction providers including native SQL queries and pg_dump, it offers both human-readable schema information and SQL DDL output formats, making it useful for developers working with large migration directories who need to understand the final database structure without manually tracking changes across multiple migration files. The implementation supports various migration file naming conventions and provides validation capabilities, serving teams that need to document database schemas, analyze migration outcomes, or integrate schema extraction into CI/CD workflows.', '@alc6', 'databases', 'Unknown', 2, 'https://github.com/alc6/mig2schema', NULL, 0, 'https://github.com/alc6.png?size=128', '2026-03-09T05:21:01.901946+00:00'),
  ('alchemy-blockchain-api', 'Alchemy Blockchain API', 'The Alchemy MCP Server creates a bridge between AI agents and Alchemy''s blockchain APIs, allowing agents to query blockchain data without writing code. Developed by Alchemy Insights, this TypeScript implementation enables querying token prices, NFT ownership, transaction history, and token balances across multiple blockchain networks. The server uses the Model Context Protocol SDK to expose structured methods that handle API authentication, data formatting, and error handling. It''s particularly valuable for users who need to access real-time blockchain data, track crypto assets, or analyze on-chain activity directly within their AI assistant conversations.', '@alchemyplatform', 'development', 'Unknown', 74, 'https://github.com/alchemyplatform/alchemy-mcp-server', NULL, 0, 'https://github.com/alchemyplatform.png?size=128', '2026-03-09T05:21:01.901974+00:00'),
  ('perplexity', 'Perplexity', 'Perplexity MCP Server provides a bridge between AI assistants and the Perplexity API, enabling Claude and other MCP-compatible tools to access real-time web search and specialized reasoning capabilities. Built by Alcova AI, this Go implementation exposes two primary tools: perplexity_ask for retrieving up-to-date information using Perplexity''s Sonar Pro model, and perplexity_reason for complex problem-solving tasks using Sonar Reasoning Pro. The server supports seamless integration with Claude Code, Claude Desktop, and Cursor through the stdio protocol, allowing AI assistants to access current information and perform reasoning tasks without leaving their interface, making it particularly valuable for workflows requiring real-time data or specialized reasoning capabilities.', '@alcova-ai', 'development', 'Unknown', 30, 'https://github.com/alcova-ai/perplexity-mcp', NULL, 0, 'https://github.com/alcova-ai.png?size=128', '2026-03-09T05:21:01.902002+00:00'),
  ('metal-framework', 'Metal Framework', 'This MCP server, developed for Metal Framework enthusiasts, provides specialized tools for searching Metal documentation and generating code snippets. Built with TypeScript and leveraging libraries like @xenova/transformers and hnswlib-node, it offers natural language querying of Metal docs and code generation for common Metal tasks in Objective-C, Swift, or Metal shading language. The server integrates seamlessly with the Model Context Protocol, allowing easy incorporation into existing MCP setups. It''s particularly useful for developers working on graphics-intensive applications or games who need quick access to Metal-specific information and code examples without leaving their development environment.', '@aldrin-labs', 'development', 'Unknown', 2, 'https://github.com/aldrin-labs/metal-mcp-server', NULL, 0, 'https://github.com/aldrin-labs.png?size=128', '2026-03-09T05:21:01.902029+00:00'),
  ('metaplex', 'Metaplex', 'This Metaplex MCP server, developed by the Metaplex Foundation, provides a bridge between AI assistants and Metaplex documentation and repository information. Built with TypeScript and Node.js, it enables searching Metaplex documentation, retrieving repository details, and searching code across Metaplex repositories. The server leverages libraries like Axios for HTTP requests and Cheerio for HTML parsing to extract relevant information. By abstracting Metaplex-specific operations into a standardized MCP interface, it allows AI systems to easily access and utilize Metaplex resources without directly handling web scraping or API complexities. This implementation is particularly useful for developers working with Solana NFTs, facilitating use cases such as automated documentation lookup, code analysis, and integration of Metaplex functionalities into AI-assisted development workflows.', '@aldrin-labs', 'development', 'Unknown', 1, 'https://github.com/aldrin-labs/metaplex-mcp-server', NULL, 0, 'https://github.com/aldrin-labs.png?size=128', '2026-03-09T05:21:01.902059+00:00'),
  ('solana-docs', 'Solana Docs', 'This Solana documentation server, developed for the Model Context Protocol, provides AI assistants with access to Solana blockchain documentation. Built with TypeScript and Node.js, it uses Axios and Cheerio to fetch and parse Solana''s online documentation, making it available through MCP-compatible endpoints. The server enables AI systems to query and retrieve up-to-date Solana development information, facilitating accurate responses to blockchain-related queries. It''s particularly useful for developers seeking real-time Solana documentation assistance, AI-powered Solana development tools, or educational platforms focused on blockchain technology.', '@aldrin-labs', 'development', 'Unknown', 4, 'https://github.com/aldrin-labs/solana-docs-mcp-server', NULL, 0, 'https://github.com/aldrin-labs.png?size=128', '2026-03-09T05:21:01.902130+00:00'),
  ('aleatoric-engine', 'Aleatoric Engine', 'Aleatoric Engine provides AI assistants with tools to generate institutional-grade synthetic market data. It supports reproducible dataset generation across Binance, HyperLiquid, OKX, Bybit, CME, and SGX exchanges, enabling simulation of extreme market conditions with consistent seeds for backtesting and validation workflows.', '@aleatoric-systems', 'development', 'Unknown', 1, 'https://github.com/aleatoric-systems/aleatoric-engine-mcp', NULL, 0, 'https://github.com/aleatoric-systems.png?size=128', '2026-03-09T05:21:01.902152+00:00'),
  ('python-repl', 'Python REPL', 'This MCP server, developed by Alex Velikanov, provides an interactive Python REPL environment for executing Python code within AI conversations. Built with Python and leveraging the MCP library, it offers persistent session management and captures stdout/stderr output. The implementation stands out by maintaining separate state for each session and supporting both expressions and statements. It''s particularly useful for developers and data scientists who need to run Python code snippets, test algorithms, or perform data analysis tasks through AI-assisted workflows, allowing for seamless integration of Python programming into conversational AI interfaces.', '@alec2435', 'development', 'Unknown', 55, 'https://github.com/alec2435/python_mcp', 'python-local', 3251, 'https://github.com/alec2435.png?size=128', '2026-03-09T05:21:01.902178+00:00'),
  ('archai-hexagonal-architecture-analyzer', 'Archai Hexagonal Architecture Analyzer', 'The Archai Static Analyzer MCP server provides AI assistants with code analysis capabilities focused on enforcing hexagonal architecture principles in Java applications. Built with TypeScript using the Model Context Protocol SDK, it implements various architectural rules such as limiting class dependencies, enforcing domain package isolation from infrastructure, validating use case naming conventions, and detecting improper email handling in models. The server exposes a single tool that accepts filename and content parameters, analyzes the code against these predefined rules, and returns violations as formatted text. This implementation is particularly valuable for development teams wanting to maintain architectural integrity through automated code reviews within AI assistant conversations.', '@alefcastelo', 'development', 'Unknown', 1, 'https://github.com/alefcastelo/archai-static-analyzer-mcp', NULL, 0, 'https://github.com/alefcastelo.png?size=128', '2026-03-09T05:21:01.902209+00:00'),
  ('document-operations-word-excel-pdf', 'Document Operations (Word, Excel, PDF)', 'Document MCP server that enables Claude Desktop to perform operations on Microsoft Word, Excel, and PDF files. Built with FastMCP and Python, it provides tools for creating and editing documents, converting between formats, and handling spreadsheet data. Particularly valuable for users who need to automate document workflows or manipulate files through natural language requests without switching between applications.', '@alejandroballesterosc', 'ai-ml', 'Unknown', 45, 'https://github.com/alejandroballesterosc/document-edit-mcp', NULL, 0, 'https://github.com/alejandroballesterosc.png?size=128', '2026-03-09T05:21:01.902251+00:00'),
  ('documentation-manager', 'Documentation Manager', 'MCP Documentation Service is a custom implementation that enables AI assistants to interact with markdown documentation files. Developed by Aleks Petrov, this service provides document management capabilities including creating, reading, updating, and deleting documentation files, working with YAML frontmatter metadata, searching through documentation, and analyzing documentation health. The implementation supports both Node.js and Deno environments, offers command-line options for specifying custom documentation directories, and integrates seamlessly with Cursor IDE and Claude Desktop through a SQL-like query format for executing commands.', '@alekspetrov', 'databases', 'Unknown', 53, 'https://github.com/alekspetrov/mcp-docs-service', 'mcp-docs-service', 7448, 'https://github.com/alekspetrov.png?size=128', '2026-03-09T05:21:01.902263+00:00'),
  ('docmost', 'Docmost', 'Connects to a self-hosted Docmost wiki instance via its API, enabling listing of documentation spaces, full-text search across documents with optional space filtering, and retrieval of page content converted from ProseMirror JSON to Markdown. Authenticates using email and password credentials with automatic JWT token management and re-authentication.', '@aleksvin8888', 'communication', 'Unknown', 3, 'https://github.com/aleksvin8888/local-docmost-mcp', NULL, 0, 'https://github.com/aleksvin8888.png?size=128', '2026-03-09T05:21:01.902288+00:00'),
  ('up-banking', 'Up Banking', 'MCP server providing read-only access to Up Banking''s API for Australian bank account data including balances, transaction history, and spending categories. Exposes tools for listing accounts by type (saver, transactional, home loan), querying transactions with flexible filtering by date range, status, category, and tags, and exploring Up''s hierarchical spending categories. Uses personal access token authentication with focus on secure read-only operations. Useful for personal finance management, spending pattern analysis, budget tracking, and automated financial reporting.', '@alex1092', 'finance', 'Unknown', 9, 'https://github.com/alex1092/up-bank-mcp-server', NULL, 0, 'https://github.com/alex1092.png?size=128', '2026-03-09T05:21:01.902345+00:00'),
  ('k-beauty', 'K-Beauty', 'This K-Beauty MCP server provides specialized knowledge about Korean skincare and cosmetics through curated data on popular brands, ingredients, and skincare routines. Built with Python using the MCP framework and featuring structured data modules for brands like COSRX and Laneige, ingredient information including benefits and skin type compatibility, and multi-step Korean skincare routines for different skin concerns, it offers tools for product recommendations, ingredient analysis, and personalized routine suggestions. The implementation includes comprehensive skincare data covering anti-aging, acne-prone, and basic routines with step-by-step guidance, making it valuable for beauty enthusiasts seeking Korean skincare advice, skincare professionals building recommendation systems, and e-commerce applications requiring specialized K-Beauty product knowledge.', '@alexai-mcp', 'development', 'Unknown', 5, 'https://github.com/alexai-mcp/k-beauty-mcp', NULL, 0, 'https://github.com/alexai-mcp.png?size=128', '2026-03-09T05:21:01.902376+00:00'),
  ('petamind', 'Petamind', 'Petamind is an agentic coding loop MCP server that generates, tests, and visually evaluates code modifications. It provides multi-candidate patch generation with deterministic gates, integrating quality checks including accessibility testing via axe-core and performance benchmarks via Lighthouse. The system uses Playwright for screenshot capture and supports various LLM providers (Vertex AI, OpenRouter) for patch generation and vision-based assessment of UI changes.', '@alexalexalex222', 'development', 'Unknown', 1, 'https://github.com/alexalexalex222/petamind-mcp', NULL, 0, 'https://github.com/alexalexalex222.png?size=128', '2026-03-09T05:21:01.902401+00:00'),
  ('telegram', 'Telegram', 'Telegram MCP Server enables Claude to access and interact with Telegram accounts, allowing for reading and sending messages through a simple interface. Developed by Alexander Tsai, it provides tools for retrieving chat lists, reading messages, marking messages as read, and sending replies while maintaining the user''s conversational style. The implementation uses Telethon for Telegram API access and includes a conversation context analyzer that reads from a customizable style guide to help Claude generate responses that match the user''s texting patterns. Perfect for users who want to monitor and respond to Telegram messages through Claude without switching applications.', '@alexandertsai', 'communication', 'Unknown', 6, 'https://github.com/alexandertsai/mcp-telegram', NULL, 0, 'https://github.com/alexandertsai.png?size=128', '2026-03-09T05:21:01.902434+00:00'),
  ('downloads-organizer', 'Downloads Organizer', 'Cursor MCP File Organizer provides a server implementation for automatically organizing files in the Downloads folder based on file types. Built with TypeScript and Express, it offers a configurable rule-based system that sorts files into appropriate directories (like Documents, Images, Archives) while supporting options such as date-based organization and handling duplicate files. The server exposes RESTful endpoints for file operations and uses Server-Sent Events (SSE) for real-time communication with the Cursor IDE. This implementation is particularly useful for developers who want to maintain an organized file system without manual intervention, especially when working with multiple file types across different projects.', '@alexandervtr', 'development', 'Unknown', 6, 'https://github.com/alexandervtr/cursor-mcp-file-organizer', NULL, 0, 'https://github.com/alexandervtr.png?size=128', '2026-03-09T05:21:01.902465+00:00'),
  ('supabase', 'Supabase', 'This MCP server implementation provides a bridge between Supabase and AI assistants, enabling database schema exploration and management through natural language interactions. It leverages the Supabase client to execute read-only SQL queries, retrieve schema information, and list tables and columns. The server offers tools for listing schemas, exploring table structures, and executing custom SQL queries, making it particularly useful for developers and data analysts who want to integrate Supabase database operations into their AI workflows. By abstracting database interactions into MCP tools, it simplifies the process of querying and analyzing Supabase data within AI-powered applications.', '@alexander-zuev', 'databases', 'Unknown', 815, 'https://github.com/alexander-zuev/supabase-mcp-server', NULL, 0, 'https://github.com/alexander-zuev.png?size=128', '2026-03-09T05:21:01.902476+00:00'),
  ('star-wars-api', 'Star Wars API', 'SWAPI MCP Server provides a simple interface to the Star Wars API (SWAPI), allowing AI assistants to retrieve information about planets from the Star Wars universe. Built with TypeScript and the Model Context Protocol SDK, it implements a single tool that enables searching for planets by name and paginating through results. The server returns planet names as text content along with metadata about the total number of results and current page, making it useful for Star Wars-related queries and demonstrations of basic API integration patterns.', '@alexandrebagio', 'development', 'Unknown', 3, 'https://github.com/alexandrebagio/swapi-mcp', NULL, 0, 'https://github.com/alexandrebagio.png?size=128', '2026-03-09T05:21:01.902503+00:00'),
  ('chess', 'Chess', 'This MCP server implementation provides a bridge to play chess games using AI. Developed by Alexandre Roman, it integrates with Spring AI and utilizes external chess libraries for game logic and board visualization. The server offers tools for move validation, game state management, and potentially AI-powered chess analysis. It''s designed for use cases requiring interactive chess gameplay or automated chess analysis within AI-assisted applications.', '@alexandreroman', 'ai-ml', 'Unknown', 18, 'https://github.com/alexandreroman/mcp-chess', NULL, 0, 'https://github.com/alexandreroman.png?size=128', '2026-03-09T05:21:01.902539+00:00'),
  ('location', 'Location', 'This MCP server implementation provides location-based functionality using the Spring AI framework. It integrates with external APIs to retrieve geolocation data, offering capabilities such as determining a user''s location based on their IP address. The server is designed to enhance AI-assisted applications with contextual location awareness, making it useful for personalized recommendations, localized content delivery, or geographic data analysis in various domains.', '@alexandreroman', 'ai-ml', 'Unknown', 0, 'https://github.com/alexandreroman/mcp-location', NULL, 0, 'https://github.com/alexandreroman.png?size=128', '2026-03-09T05:21:01.902578+00:00'),
  ('time', 'Time', 'This MCP server implementation provides a time-related service using Spring Boot and Spring AI. Developed by Alexandre Roman, it integrates with the Spring AI MCP server starter, allowing for easy deployment and scalability. The server is designed to handle time-based operations and queries, making it suitable for applications that require precise time management or scheduling functionalities. It leverages Java 21 and the latest Spring Boot version, showcasing modern Java development practices.', '@alexandreroman', 'development', 'Unknown', 0, 'https://github.com/alexandreroman/mcp-time', NULL, 0, 'https://github.com/alexandreroman.png?size=128', '2026-03-09T05:21:01.902601+00:00'),
  ('mempool-space', 'Mempool.space', 'A Bitcoin mempool and blockchain data MCP server built by Alexandre Sanlim that provides comprehensive access to mempool.space APIs through a clean Domain-Driven Design architecture. The server exposes 30+ tools for querying Bitcoin network data including transaction details, block information, address balances, mining pool statistics, fee recommendations, and mempool status, with support for both public mempool.space and local Bitcoin node instances like Umbrel. Built with TypeScript and organized into distinct application, domain, infrastructure, and interface layers, it''s particularly useful for Bitcoin developers, analysts, and traders who need programmatic access to real-time blockchain data without managing API complexity directly.', '@alexandresanlim', 'development', 'Unknown', 2, 'https://github.com/alexandresanlim/mempool-mcp-server', '@sanlim/mempool-mcp-server', 304, 'https://github.com/alexandresanlim.png?size=128', '2026-03-09T05:21:01.902633+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('url-text-fetcher', 'URL Text Fetcher', 'URL Text Fetcher MCP server built with FastMCP that provides two essential web scraping tools for extracting content from web pages. The implementation uses requests and BeautifulSoup4 to fetch and parse HTML, offering a fetch_url_text tool that extracts all visible text from any URL with proper formatting and line breaks, and a fetch_page_links tool that returns all hyperlinks found on a page. Designed for AI assistants that need to analyze web content, research topics across multiple pages, or build workflows involving web data extraction and link discovery.', '@alexandru2882', 'development', 'Unknown', 1, 'https://github.com/alexandru2882/url-text-fetcher-mcp', NULL, 0, 'https://github.com/alexandru2882.png?size=128', '2026-03-09T05:21:01.902691+00:00'),
  ('sticky-notes', 'Sticky Notes', 'A simple sticky notes MCP server implementation built with FastMCP that provides basic note-taking functionality through file-based storage. The server exposes tools for adding notes, clearing all notes, and reading existing notes from a local text file, along with a resource for accessing the most recent note and a prompt for generating note summaries. Designed as a straightforward example of MCP server development, it''s useful for basic note management workflows and serves as a foundation for building more complex document storage systems.', '@alexandrukovacs', 'development', 'Unknown', 1, 'https://github.com/alexandrukovacs/mcp-server', NULL, 0, 'https://github.com/alexandrukovacs.png?size=128', '2026-03-09T05:21:01.902716+00:00'),
  ('tradovate', 'Tradovate', 'Tradovate MCP Server provides a bridge to the Tradovate trading platform API, enabling AI assistants to manage futures contracts, positions, and orders. Built by alexanimal, it offers tools for retrieving contract details, listing positions, placing and modifying orders, and accessing account information with real-time market data. The implementation includes robust authentication handling, data caching for offline operation, and fallback to simulated data when the API is unavailable. This server is particularly valuable for trading workflows that require monitoring positions, analyzing contract details, or executing trades directly within AI assistant conversations.', '@alexanimal', 'ai-ml', 'Unknown', 1, 'https://github.com/alexanimal/tradovate-mcp-server', NULL, 0, 'https://github.com/alexanimal.png?size=128', '2026-03-09T05:21:01.902761+00:00'),
  ('ipfs-storacha-network', 'IPFS Storacha Network', 'MCP-IPFS is a server implementation that provides AI assistants with access to the IPFS Storacha Network through the w3cli interface. Developed by Alex Baker, this TypeScript server enables file uploads, space management, delegation handling, and various IPFS operations via a set of well-defined tools. The implementation requires email authentication with the w3 service and handles command execution, parsing responses, and formatting results for AI consumption. Particularly useful for decentralized storage workflows, content addressing, and managing persistent data on IPFS without requiring direct CLI interaction.', '@alexbakers', 'development', 'Unknown', 14, 'https://github.com/alexbakers/mcp-ipfs', 'mcp-ipfs', 5716, 'https://github.com/alexbakers.png?size=128', '2026-03-09T05:21:01.902836+00:00'),
  ('binance-futures', 'Binance Futures', 'A Model Context Protocol server for Binance Futures API that provides both market data access and account management functionality through a modular Python implementation. The server offers unauthenticated tools for retrieving exchange information, price tickers, order books, and candlestick data, alongside authenticated endpoints for account balance, position information, and commission rates. Built with aiohttp for async HTTP operations and structured with separate modules for client connections, tool definitions, and request handlers, it''s designed for trading applications that need real-time market data and account monitoring capabilities within AI assistant workflows.', '@alexcandrabersiva', 'ai-ml', 'Unknown', 4, 'https://github.com/alexcandrabersiva/bin-mcp', 'binance_futures_mcp', 0, 'https://github.com/alexcandrabersiva.png?size=128', '2026-03-09T05:21:01.902893+00:00'),
  ('gemini-deepsearch', 'Gemini DeepSearch', 'This MCP server provides automated multi-step web research capabilities using Google Gemini models and Google Search API to perform deep information gathering with citation tracking. Built by Alex Cong using Python with LangGraph workflow orchestration, FastMCP integration, and Google''s generative AI tools, it implements a sophisticated research agent that generates diverse search queries, conducts parallel web searches, reflects on knowledge gaps through iterative loops, and synthesizes final answers with proper source attribution. The implementation offers configurable effort levels (low/medium/high) that control research depth through query count and loop iterations, supports both HTTP API and stdio MCP deployment modes, and includes LangGraph Studio integration for workflow visualization, making it valuable for research tasks requiring comprehensive information synthesis, fact-checking with source verification, and scenarios where AI assistants need to gather current information beyond their training data through systematic web exploration.', '@alexcong', 'productivity', 'Unknown', 25, 'https://github.com/alexcong/gemini-deepsearch-mcp', 'gemini-deepsearch-mcp', 3240, 'https://github.com/alexcong.png?size=128', '2026-03-09T05:21:01.902953+00:00'),
  ('medusa-js-documentation', 'Medusa.js Documentation', 'This MCP server provides local Medusa.js documentation access through fuzzy search capabilities using Fuse.js for semantic text matching and section-based content retrieval. Built with TypeScript and the Model Context Protocol SDK, it parses documentation files into searchable sections with configurable search thresholds and result limits, offering three core tools: semantic search across documentation content, specific section retrieval by title or path, and comprehensive section listing with optional category filtering. The implementation features flexible file path resolution with multiple fallback locations, markdown-based section parsing that handles nested headers, and configurable preview lengths for search results, making it ideal for developers working with Medusa.js who need quick access to framework documentation without leaving their development environment or AI assistant workflow.', '@alexcs24', 'development', 'Unknown', 5, 'https://github.com/alexcs24/medusa.js-documentation-mcp-server', NULL, 0, 'https://github.com/alexcs24.png?size=128', '2026-03-09T05:21:01.902987+00:00'),
  ('aws-cli', 'AWS CLI', 'AWS MCP Server provides a lightweight bridge between AI assistants and the AWS CLI, enabling execution of AWS commands through a standardized interface. Built by alexei-led, it features two main tools: describe_command for retrieving AWS CLI documentation and execute_command for running AWS CLI operations with Unix pipe support. The server leverages existing AWS credentials on the host machine, includes pre-defined prompt templates for common AWS tasks following best practices, and supports multi-architecture deployment via Docker. This implementation is particularly valuable for cloud management workflows where users need to interact with AWS resources without leaving their AI assistant conversation.', '@alexei-led', 'cloud', 'Unknown', 180, 'https://github.com/alexei-led/aws-mcp-server', NULL, 0, 'https://github.com/alexei-led.png?size=128', '2026-03-09T05:21:01.903006+00:00'),
  ('context-storage', 'Context Storage', 'Provides persistent storage for text and image context that can be shared across LLM agent threads. Supports SQLite for local development and PostgreSQL/Supabase for production deployments. Includes semantic search capabilities using pgvector for context retrieval.', '@alex-feel', 'databases', 'Unknown', 3, 'https://github.com/alex-feel/mcp-context-server', NULL, 0, 'https://github.com/alex-feel.png?size=128', '2026-03-09T05:21:01.903056+00:00'),
  ('bizangafest-penetration-testing', 'Bizangafest Penetration Testing', 'An autonomous penetration testing server that provides nmap network scanning and searchsploit vulnerability discovery tools for security assessments. Built by alexgarabt, the implementation includes both a standalone agent that directly integrates security tools with Google''s Gemini model, and an MCP server version that exposes the same capabilities through the Model Context Protocol for broader integration. Built with LangGraph for autonomous workflow orchestration, it automatically performs network reconnaissance, identifies running services and versions, then searches for known exploits across all discovered services to generate security reports. This makes it useful for automated vulnerability assessments, security auditing, and penetration testing workflows.', '@alexgarabt', 'development', 'Unknown', 2, 'https://github.com/alexgarabt/bizangafest-mcp', NULL, 0, 'https://github.com/alexgarabt.png?size=128', '2026-03-09T05:21:01.903089+00:00'),
  ('claude-mobile', 'Claude Mobile', 'Enables automation of Android devices and iOS simulators through a unified API. Supports device listing, screenshots with automatic compression for LLM processing, tap and swipe gestures by coordinates or element text, text input, app launching and installation, UI hierarchy inspection, device logs retrieval, and shell command execution. Provides cross-platform device control for mobile testing and debugging workflows.', '@alexgladkov', 'development', 'Unknown', 129, 'https://github.com/alexgladkov/claude-in-mobile', NULL, 0, 'https://github.com/alexgladkov.png?size=128', '2026-03-09T05:21:01.903114+00:00'),
  ('agenda-app', 'Agenda App', 'This MCP server for Agenda, developed by alexgoller, provides AI assistants with a standardized interface to interact with the Agenda note-taking app on macOS. Built using Python and leveraging x-callback-urls, it offers capabilities for creating notes, managing projects, and opening existing notes in Agenda. The server abstracts the complexities of Agenda''s x-callback-url scheme, handling URL encoding and execution through macOS system calls. It''s particularly valuable for AI systems focused on note management and personal productivity, enabling use cases such as automated note creation, project organization, and seamless integration of AI-generated content into the user''s Agenda workflow.', '@alexgoller', 'productivity', 'Unknown', 5, 'https://github.com/alexgoller/mcp-server-agenda', NULL, 0, 'https://github.com/alexgoller.png?size=128', '2026-03-09T05:21:01.903157+00:00'),
  ('illumio', 'Illumio', 'This Illumio MCP server, developed by alexgoller, provides an interface for AI assistants to interact with Illumio''s Policy Compute Engine (PCE). It integrates with the Illumio API to enable programmatic management of workloads, labels, and traffic flows within a zero trust security environment. The server exposes tools for creating, updating, and deleting workloads and labels, as well as analyzing traffic patterns and security policies. By abstracting PCE interactions, it allows AI systems to easily perform tasks like workload management, label operations, and traffic analysis. This implementation is particularly useful for security teams, network administrators, and DevOps professionals who want to leverage AI capabilities for automating Illumio PCE operations, enhancing security posture, and gaining insights from network traffic data.', '@alexgoller', 'productivity', 'Unknown', 2, 'https://github.com/alexgoller/illumio-mcp-server', NULL, 0, 'https://github.com/alexgoller.png?size=128', '2026-03-09T05:21:01.903205+00:00'),
  ('chat-logger', 'Chat Logger', 'MCP Chat Logger is a simple tool that allows AI assistants to save chat conversations as formatted Markdown files. Developed by Alexi.F, this implementation provides a single function that takes chat messages and an optional conversation ID, then saves them with timestamps in a structured format. The saved files include role information, timestamps, and the full content of each message, making it useful for record-keeping, analysis, or creating permanent archives of important conversations.', '@alexifeng', 'communication', 'Unknown', 5, 'https://github.com/alexifeng/mcp_chat_logger', NULL, 0, 'https://github.com/alexifeng.png?size=128', '2026-03-09T05:21:01.903236+00:00'),
  ('unreal-engine', 'Unreal Engine', 'UnrealMCP enables AI assistants to interact with Unreal Engine through a TCP server that exposes scene manipulation, material creation, and blueprint generation capabilities. The implementation includes both C++ components that integrate directly with the Unreal Editor and Python modules that implement the Model Context Protocol, allowing tools like Claude Desktop and Cursor to send commands to Unreal Engine. It features a modular command system that can be extended with custom handlers, making it particularly valuable for AI-assisted game development and virtual production workflows.', '@alexkissijr', 'development', 'Unknown', 9, 'https://github.com/alexkissijr/unrealmcp', NULL, 0, 'https://github.com/alexkissijr.png?size=128', '2026-03-09T05:21:01.903263+00:00'),
  ('lancedb', 'LanceDB', 'This LanceDB MCP server, developed by Alex Komyagin, enables AI assistants to interact with LanceDB vector databases through natural language. It leverages the LanceDB Node.js client and Model Context Protocol to provide operations like querying, inserting, and managing vector data. Built with TypeScript and modern dependencies, it offers a bridge between large language models and efficient vector storage. The implementation is designed for developers and data scientists working on AI applications that require fast similarity search, recommendation systems, or semantic analysis on large datasets. It simplifies vector database operations for AI assistants, allowing them to perform complex queries and data manipulations using conversational language.', '@adiom-data', 'databases', 'Unknown', 76, 'https://github.com/adiom-data/lance-mcp', NULL, 0, 'https://github.com/adiom-data.png?size=128', '2026-03-09T05:21:01.903273+00:00'),
  ('marketo-forms', 'Marketo Forms', 'Marketo MCP Server provides a bridge between AI assistants and Adobe Marketo''s REST API, enabling form management operations including retrieving, approving, and cloning forms. Built with TypeScript and containerized with Docker, it features token-based authentication with automatic refresh, error handling, and structured parameter validation using Zod. The implementation supports both direct integration through stdio transport and deployment via Smithery, making it particularly valuable for marketing teams who need to manage Marketo forms without switching context or writing API code.', '@alexleventer', 'cloud', 'Unknown', 2, 'https://github.com/alexleventer/marketo-mcp', NULL, 0, 'https://github.com/alexleventer.png?size=128', '2026-03-09T05:21:01.903296+00:00'),
  ('harvard-art-museums', 'Harvard Art Museums', 'Provides access to Harvard Art Museums'' extensive collection of over 224,000 artworks, artist records, and museum objects through their public API. Built by AlexLin1234, it offers five core tools for searching and retrieving art data: searching objects with filters, fetching detailed artwork information by ID, searching for artists and people, retrieving person details, and discovering random artworks with optional classification or culture filters. The implementation uses Pydantic for data validation and includes built-in image filtering to ensure results include visual content, making it valuable for art research, educational applications, cultural exploration, and creative projects that need structured access to one of the world''s premier art collections.', '@alexlin1234', 'productivity', 'Unknown', 1, 'https://github.com/alexlin1234/harvard-art-museums-mcp-server', NULL, 0, 'https://github.com/alexlin1234.png?size=128', '2026-03-09T05:21:01.903348+00:00'),
  ('terminal', 'Terminal', 'This MCP terminal server, developed by Alex Man, enables AI assistants to interact with specified directories on a user''s system through a command-line interface. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers tools for executing shell commands, creating directories, and navigating the file system within allowed boundaries. The implementation focuses on security by restricting access to predefined directories and whitelisting permitted commands. It''s particularly useful for tasks like file management, system automation, or providing AI assistants with controlled access to local resources, enabling safe interaction with the user''s file system without requiring deep knowledge of system-level operations or security considerations.', '@aithelab', 'development', 'Unknown', 0, 'https://github.com/aithelab/mcp-terminal-use', NULL, 0, 'https://github.com/aithelab.png?size=128', '2026-03-09T05:21:01.903379+00:00'),
  ('supernotes-to-obsidian', 'Supernotes to Obsidian', 'This MCP implementation, developed by Alex Howard, provides a tool for importing Supernotes exports into Obsidian daily notes. Built with Python, it leverages the Model Context Protocol to streamline the process of transferring and formatting notes between these two popular note-taking applications. The script creates daily notes from templates, cleans up formatting, adds wikilinks for proper nouns, and handles OCR errors. By automating these tasks, it significantly reduces the manual effort required when migrating from Supernotes to Obsidian. This implementation is particularly useful for knowledge workers, researchers, and students who are transitioning between note-taking systems or looking to maintain a consistent daily journaling practice within Obsidian while importing content from Supernotes.', '@al-how', 'productivity', 'Unknown', 0, 'https://github.com/al-how/supernotes-to-obsidian', NULL, 0, 'https://github.com/al-how.png?size=128', '2026-03-09T05:21:01.903426+00:00'),
  ('kusto-nl2kql', 'Kusto NL2KQL', 'Kusto MCP provides a bridge between AI assistants and Azure Data Explorer (Kusto) databases, enabling natural language querying of Kusto data. Built with .NET 9 and containerized for easy deployment, it leverages Azure OpenAI to translate natural language questions into KQL queries. The implementation includes configuration via YAML files that define database connections and example prompts, making it particularly valuable for data analysis, resource monitoring, and information retrieval from Kusto databases without requiring KQL expertise.', '@alexneyler', 'databases', 'Unknown', 3, 'https://github.com/alexneyler/kusto-mcp', NULL, 0, 'https://github.com/alexneyler.png?size=128', '2026-03-09T05:21:01.903437+00:00'),
  ('roblox-studio-bridge', 'Roblox Studio Bridge', 'Bridges Roblox Studio with external systems through a Node.js server and Lua plugin architecture, enabling real-time game object manipulation, script management, lighting control, and Luau code execution for AI-assisted game development and automated level design workflows.', '@alexpoopy1', 'development', 'Unknown', 2, 'https://github.com/alexpoopy1/roblox-studio-mcp-server-v1', NULL, 0, 'https://github.com/alexpoopy1.png?size=128', '2026-03-09T05:21:01.903455+00:00'),
  ('playwright', 'Playwright', 'This MCP server provides AI assistants with robust browser automation capabilities through Playwright, built using Python with FastMCP and offering 33 tools for complete web interaction including navigation, DOM manipulation, form handling, element discovery, content extraction, and JavaScript execution. The implementation features persistent browser context management with support for headless or headed modes across Chromium, Firefox, and WebKit browsers, comprehensive element interaction through CSS selectors and Playwright locators, content snapshotting with HTML/PDF/screenshot generation, and advanced debugging tools for console logs and network monitoring. Built with configurable viewport settings, file upload support, accessibility tree analysis, and raw Playwright output without post-processing, it serves automation engineers needing conversational web scraping and testing workflows, QA teams requiring AI-driven browser testing capabilities, and developers where natural language interfaces enhance web automation tasks without direct Playwright API knowledge.', '@alexrwilliam', 'development', 'Unknown', 6, 'https://github.com/alexrwilliam/playwright-mcp-server', NULL, 0, 'https://github.com/alexrwilliam.png?size=128', '2026-03-09T05:21:01.903493+00:00'),
  ('zoho-creator', 'Zoho Creator', 'This Zoho Creator MCP server, developed by Alex Sherin, integrates with the Zoho Creator API to enable AI assistants to interact with custom business applications. It provides a simple note storage system with a custom URI scheme, allowing for creation and retrieval of notes. The server implements a summarization prompt and a tool for adding new notes, abstracting away the complexities of the Zoho Creator API. By connecting AI capabilities with custom business logic and data storage, this implementation enables assistants to manage and analyze application-specific information. It is particularly useful for scenarios where AI systems need to interact with tailored business processes or maintain context across conversations within custom Zoho Creator applications.', '@mastercode-io', 'ai-ml', 'Unknown', 1, 'https://github.com/mastercode-io/scaflog-zoho-mcp-server', NULL, 0, 'https://github.com/mastercode-io.png?size=128', '2026-03-09T05:21:01.903540+00:00'),
  ('development-automation-server', 'Development Automation Server', 'FastMCP Server for continue.dev provides a development automation server that exposes prompts, resources, and tools to LLM clients. Built by Alexander Smirnov, it implements the Model Context Protocol to offer features like URL content fetching, library documentation access, project structure analysis, and web search capabilities through both internet and Perplexity APIs. The server is designed with a modular architecture that separates configuration, resources, tools, and prompts into distinct components, making it particularly valuable for developers who want to enhance their coding workflow with AI assistance without leaving their development environment.', '@alexsmirnov', 'development', 'Unknown', 8, 'https://github.com/alexsmirnov/obsidian-second-brain-mcp', NULL, 0, 'https://github.com/alexsmirnov.png?size=128', '2026-03-09T05:21:01.903570+00:00'),
  ('hardcover', 'Hardcover', 'Provides read-only access to the Hardcover.app GraphQL API through MCP. Organizes data access with tools namespaced under books, users, and series, enabling queries for book metadata, user reading lists, and series information. Includes rate limiting safeguards and comprehensive documentation for safe API usage.', '@alexsowt', 'development', 'Unknown', 1, 'https://github.com/alexsowt/hardcover-mcp', NULL, 0, 'https://github.com/alexsowt.png?size=128', '2026-03-09T05:21:01.903629+00:00'),
  ('artifacthub', 'ArtifactHub', 'ArtifactHub MCP Server provides a bridge to Artifact Hub''s Helm chart repository, enabling AI assistants to interact with Helm charts through five specialized tools. It allows retrieving chart information, accessing default values.yaml files with fuzzy search capabilities, and exploring chart templates with context-aware searching. Built with TypeScript and packaged as a Docker container, this implementation makes it particularly valuable for Kubernetes administrators and developers who need to quickly reference, search, or analyze Helm chart configurations without leaving their AI assistant conversation.', '@alexw00', 'cloud', 'Unknown', 9, 'https://github.com/alexw00/artifacthub-mcp', NULL, 0, 'https://github.com/alexw00.png?size=128', '2026-03-09T05:21:01.903650+00:00'),
  ('language-server', 'Language Server', 'This language server MCP implementation, developed by Alex Wohletz, provides language support for code editing by integrating with the Model Context Protocol. It offers features like hover information, code completion, and diagnostics for TypeScript and potentially Python. The server exposes these capabilities as MCP tools, allowing AI assistants to analyze and manipulate code. By connecting AI capabilities with language-specific tooling, this implementation enables assistants to provide contextual coding help, suggest improvements, and catch potential errors. It is particularly useful for applications requiring code understanding, automated refactoring, or any scenario where an AI system needs to reason about and interact with source code.', '@alexwohletz', 'development', 'Unknown', 26, 'https://github.com/alexwohletz/language-server-mcp', NULL, 0, 'https://github.com/alexwohletz.png?size=128', '2026-03-09T05:21:01.903678+00:00'),
  ('rails-diff', 'Rails Diff', 'Exposes Rails version differences from the railsdiff/rails-new-output repository through GitHub API integration, enabling developers to compare what changes between Rails versions when generating new applications.', '@alexzeitler', 'development', 'Unknown', 1, 'https://github.com/alexzeitler/rails-diff-mcp', NULL, 0, 'https://github.com/alexzeitler.png?size=128', '2026-03-09T05:21:01.903694+00:00'),
  ('node-code-sandbox', 'Node Code Sandbox', 'Node Code Sandbox MCP provides a secure environment for executing JavaScript code within Docker containers. It offers tools for initializing sandboxes, running code with npm dependencies, and managing container lifecycles, all while maintaining isolation through resource limits (512MB memory, 1 CPU). The implementation supports both persistent containers for multiple operations and ephemeral containers for one-off executions, making it ideal for AI assistants that need to test JavaScript snippets, demonstrate npm package usage, or run isolated code examples without security risks.', '@alfonsograziano', 'cloud', 'Unknown', 147, 'https://github.com/alfonsograziano/node-code-sandbox-mcp', NULL, 0, 'https://github.com/alfonsograziano.png?size=128', '2026-03-09T05:21:01.903717+00:00'),
  ('notebooklm', 'NotebookLM', 'Automates Google NotebookLM workflows for creating notebooks, adding content sources (web pages, videos, documents, images, audio), and generating podcasts, videos, slide decks, mind maps, quizzes, and reports through browser-based authentication.', '@alfredang', 'search', 'Unknown', 11, 'https://github.com/alfredang/notebooklm-mcp', NULL, 0, 'https://github.com/alfredang.png?size=128', '2026-03-09T05:21:01.903751+00:00'),
  ('grasshopper-parametric-design', 'Grasshopper Parametric Design', 'Grasshopper MCP Bridge connects Grasshopper (a visual programming environment for Rhino) with Claude Desktop through a bidirectional communication system. Developed by alfredatnycu, it consists of a Grasshopper plugin component (GH_MCP.gha) that provides a TCP server and a Python bridge server that implements the Model Context Protocol. The system includes a component knowledge base with information about common Grasshopper components, their parameters, and connection rules, enabling Claude to create and manipulate parametric designs through natural language commands. This implementation is particularly valuable for architects, designers, and engineers who want to leverage AI assistance for parametric modeling workflows without leaving their conversation interface.', '@alfredatnycu', 'ai-ml', 'Unknown', 62, 'https://github.com/alfredatnycu/grasshopper-mcp', 'grasshopper-mcp', 2471, 'https://github.com/alfredatnycu.png?size=128', '2026-03-09T05:21:01.903803+00:00'),
  ('algolia', 'Algolia', 'Algolia MCP server implementation that provides AI assistants with complete access to Algolia''s search and analytics platform through a comprehensive Go-based toolkit covering search operations, A/B testing, analytics, collections management, query suggestions, recommendations, monitoring, and usage metrics. Built using the Algolia Go SDK and mark3labs/mcp-go framework, the implementation organizes functionality into distinct packages for each Algolia service area, supporting both read and write operations with proper API key management and environment variable configuration. The server enables AI assistants to perform complex search operations with advanced filtering and faceting, manage A/B tests and analytics data, handle collections and query suggestions, monitor infrastructure health, and access usage metrics, making it valuable for developers building AI-powered search experiences, data analysts requiring programmatic access to search analytics, and teams managing large-scale search infrastructure who need conversational access to Algolia''s full feature set.', '@algolia', 'development', 'Unknown', 26, 'https://github.com/algolia/mcp', NULL, 0, 'https://github.com/algolia.png?size=128', '2026-03-09T05:21:01.903841+00:00'),
  ('gnews', 'GNews', 'This MCP server implementation provides integration with the GNews API, enabling news search and retrieval capabilities. It offers tools for searching news articles, fetching top headlines, and retrieving topic-specific news across multiple languages and countries. The server includes resource handlers for convenient news access and prompt generators to facilitate natural language interactions. Developed by Eric Julianto, it''s useful for applications requiring up-to-date news data from diverse global sources.', '@algonacci', 'search', 'Unknown', 1, 'https://github.com/algonacci/mcp-gnews', NULL, 0, 'https://github.com/algonacci.png?size=128', '2026-03-09T05:21:01.903896+00:00'),
  ('tavily-extract', 'Tavily Extract', 'This MCP server implementation provides a simple interface for extracting web page content using the Tavily API. It utilizes the FastMCP framework and exposes a single tool, ''extract_url'', which takes a URL as input and returns the extracted content. The server requires a Tavily API key to be set as an environment variable and is designed for easy integration into projects that need web scraping capabilities.', '@algonacci', 'productivity', 'Unknown', 0, 'https://github.com/algonacci/mcp-tavily-extract', NULL, 0, 'https://github.com/algonacci.png?size=128', '2026-03-09T05:21:01.903932+00:00'),
  ('tavily-search', 'Tavily Search', 'This MCP server implementation integrates the Tavily search API to provide advanced web search capabilities. Developed by Eric Julianto, it offers tools for performing customizable searches with options for depth, result count, time range, and AI-generated answers. The server is built using the FastMCP framework and includes features like progress reporting and resource handling. It''s designed for use cases requiring up-to-date web information, such as research, content creation, or data aggregation tasks.', '@algonacci', 'productivity', 'Unknown', 2, 'https://github.com/algonacci/mcp-tools', NULL, 0, 'https://github.com/algonacci.png?size=128', '2026-03-09T05:21:01.903972+00:00'),
  ('wikipedia', 'Wikipedia', 'This MCP server provides AI assistants with access to Wikipedia content through a simple interface built with FastMCP. It exposes five tools that allow clients to search Wikipedia, retrieve article summaries, access full page content, get random articles, and change the language setting. Created by Eric Julianto, this implementation serves as a bridge between AI systems and the vast knowledge base of Wikipedia, making it useful for research tasks, fact-checking, and educational applications where quick access to encyclopedic information is needed.', '@algonacci', 'productivity', 'Unknown', 10, 'https://github.com/algonacci/mcp-wikipedia', NULL, 0, 'https://github.com/algonacci.png?size=128', '2026-03-09T05:21:01.904095+00:00'),
  ('xiaohongshu-little-red-book', 'XiaoHongShu (Little Red Book)', 'Built by Algovate using TypeScript and Puppeteer, this server provides browser automation capabilities for XiaoHongShu, China''s popular social media platform. It offers 8 tools covering authentication (login/logout/status), content discovery (feed browsing, keyword search, note details), social interaction (commenting), and content publishing (both images and videos with up to 18 media files per post). The implementation handles XiaoHongShu''s unique authentication flow including QR code scanning, manages session cookies automatically, and supports both stdio and HTTP transports with proper rate limiting and error handling. It respects platform-specific constraints like 20-character title limits and 1000-character content limits, making it valuable for social media managers, content creators, and marketers who need to automate XiaoHongShu operations.', '@algovate', 'development', 'Unknown', 42, 'https://github.com/algovate/xhs-mcp', 'xhs-mcp', 3090, 'https://github.com/algovate.png?size=128', '2026-03-09T05:21:01.904127+00:00'),
  ('canlii', 'CanLII', 'This MCP server provides AI assistants with access to the CanLII (Canadian Legal Information Institute) API for searching and retrieving Canadian legal information including court decisions, legislation, and legal citations. Built for Cloudflare Workers using TypeScript with the Model Context Protocol SDK, it offers tools for browsing courts and tribunals, searching case law decisions, retrieving case metadata and citations, accessing legislation databases, and scraping legal document content from URLs. The implementation includes comprehensive date filtering capabilities, supports both English and French languages, and handles complex legal data structures through Zod schema validation, making it valuable for legal professionals conducting research, AI assistants requiring access to Canadian jurisprudence, and developers building legal research applications that need programmatic access to authoritative Canadian legal databases.', '@alhwyn', 'databases', 'Unknown', 12, 'https://github.com/alhwyn/canlii-mcp', NULL, 0, 'https://github.com/alhwyn.png?size=128', '2026-03-09T05:21:01.904138+00:00'),
  ('gemini', 'Gemini', 'This Gemini MCP server, developed by Ali Argun, enables Claude Desktop to interact with Google''s Gemini AI models. It provides a full implementation of the Model Context Protocol, supporting real-time response streaming and secure API key handling. The server integrates with the @google/generative-ai library to offer a streamlined interface for leveraging Gemini''s capabilities within Claude Desktop. By abstracting the complexities of the Gemini API, this implementation allows for easy configuration of model parameters and seamless integration with existing Claude Desktop workflows. It is particularly useful for users who want to access Gemini''s advanced language models through a familiar interface, enabling applications like chatbots, content generation, and AI-assisted analysis within the Claude Desktop environment.', '@aliargun', 'communication', 'Unknown', 248, 'https://github.com/aliargun/mcp-server-gemini', NULL, 0, 'https://github.com/aliargun.png?size=128', '2026-03-09T05:21:01.904179+00:00'),
  ('agentic-ai-feature-management', 'Agentic AI Feature Management', 'Processes Jira webhook tickets using AWS Bedrock''s Claude 3 Haiku to extract structured feature management requests from natural language support ticket descriptions. Provides three core tools for checking feature status, enabling features, and disabling features across customer accounts. Features comprehensive security measures including prompt injection detection, input sanitization, rate limiting, and audit logging. Built with a modular architecture separating the Lambda handler, MCP server, and security components, supporting both mock and production modes with OAuth2 authentication for external API integration.', '@aliazam2012', 'cloud', 'Unknown', 1, 'https://github.com/aliazam2012/agentic-ai-mcp-feature-management', NULL, 0, 'https://github.com/aliazam2012.png?size=128', '2026-03-09T05:21:01.904198+00:00'),
  ('alibaba-cloud-adb-mysql', 'Alibaba Cloud ADB MySQL', 'Adb MySQL MCP Server provides a universal interface between AI Agents and Alibaba Cloud''s Adb MySQL databases, enabling seamless metadata retrieval and SQL operations. Developed by Alibaba Cloud, this Python-based implementation offers tools for executing SQL queries, analyzing query plans, and retrieving execution statistics, along with resource templates for accessing database schemas, table definitions, and configuration values. The server requires minimal configuration through environment variables and supports both local development and pip installation, making it ideal for data analysts and developers who need AI-assisted database interactions with Adb MySQL clusters.', '@aliyun', 'databases', 'Unknown', 24, 'https://github.com/aliyun/alibabacloud-adb-mysql-mcp-server', 'adb-mysql-mcp-server', 3272, 'https://github.com/aliyun.png?size=128', '2026-03-09T05:21:01.904210+00:00'),
  ('alibaba-cloud', 'Alibaba Cloud', 'Alibaba Cloud MCP Server provides a bridge to Alibaba Cloud services, enabling AI assistants to manage cloud resources through natural language. Developed by Zheng Dayu at Alibaba, this implementation offers tools for managing ECS instances (start, stop, reboot, create, delete), viewing cloud resources (instances, regions, zones, images, security groups), monitoring system metrics (CPU, memory, disk usage), and configuring VPC networks. The server supports both API-based operations and more complex tasks through OOS (Operation Orchestration Service), making it particularly valuable for users who need to monitor and manage their Alibaba Cloud infrastructure without navigating the console interface.', '@aliyun', 'productivity', 'Unknown', 104, 'https://github.com/aliyun/alibaba-cloud-ops-mcp-server', 'alibabacloud-mcp-server', 3003, 'https://github.com/aliyun.png?size=128', '2026-03-09T05:21:01.904253+00:00'),
  ('alibaba-cloud-dms', 'Alibaba Cloud DMS', 'The Alibaba Cloud DMS MCP Server provides a standardized interface for database metadata operations through the Model Context Protocol, enabling large language models to access and query data across diverse database ecosystems. Built by AlibabaCloud DMS, this Python-based implementation integrates with Alibaba Cloud''s Data Management Service (DMS) API to facilitate unified metadata access and cross-engine data querying. The server requires Alibaba Cloud credentials for authentication and is configured to run with the uv package manager, making it particularly valuable for developers working with multiple database types who need consistent metadata retrieval capabilities within AI-assisted workflows.', '@aliyun', 'databases', 'Unknown', 29, 'https://github.com/aliyun/alibabacloud-dms-mcp-server', NULL, 0, 'https://github.com/aliyun.png?size=128', '2026-03-09T05:21:01.904265+00:00'),
  ('alibaba-cloud-function-compute', 'Alibaba Cloud Function Compute', 'This MCP server provides comprehensive integration with Alibaba Cloud Function Compute (FC3), enabling AI assistants to deploy, manage, and configure serverless functions with custom runtime support. Built with TypeScript and leveraging the Serverless Devs framework, it offers tools for creating and updating functions with configurable CPU, memory, and environment settings, managing custom domain routing, and handling function lifecycle operations including deployment from local code directories. The implementation supports multi-language runtimes (Python, Node.js, Java) through automatic layer provisioning, VPC and logging configuration, and includes intelligent domain name generation for HTTP access, making it valuable for developers who need AI assistance in managing serverless applications and automating cloud function deployments on Alibaba Cloud''s platform.', '@aliyun', 'development', 'Unknown', 8, 'https://github.com/aliyun/alibabacloud-fc-mcp-server', 'alibabacloud-fc-mcp-server', 4483, 'https://github.com/aliyun.png?size=128', '2026-03-09T05:21:01.904295+00:00'),
  ('alibaba-cloud-observability', 'Alibaba Cloud Observability', 'Alibaba Cloud Observability MCP Server provides tools for accessing Alibaba Cloud''s monitoring and logging services, including Log Service (SLS) and Application Real-Time Monitoring Service (ARMS). The server enables AI assistants to query log structures, execute log queries, search applications, and analyze trace data through a standardized interface. Built with Python and supporting both stdio and SSE transport protocols, it securely handles authentication through Alibaba Cloud AccessKeys while offering comprehensive error handling. This implementation is particularly valuable for developers monitoring cloud applications, troubleshooting performance issues, or analyzing application logs within the Alibaba Cloud ecosystem.', '@aliyun', 'ai-ml', 'Unknown', 81, 'https://github.com/aliyun/alibabacloud-observability-mcp-server', 'mcp-server-aliyun-observability', 27579, 'https://github.com/aliyun.png?size=128', '2026-03-09T05:21:01.904344+00:00'),
  ('alibaba-cloud-rds', 'Alibaba Cloud RDS', 'AlibabaCloud RDS OpenAPI MCP Server provides a bridge to Alibaba Cloud''s Relational Database Service (RDS) through a set of tools that enable AI assistants to manage and monitor database instances. The implementation offers capabilities for querying instance details, modifying parameters, analyzing performance metrics, and creating new database instances. It also includes VPC management functions for network configuration. This server is particularly useful for DevOps teams managing Alibaba Cloud infrastructure who need to automate database administration tasks or troubleshoot performance issues through natural language interactions.', '@aliyun', 'databases', 'Unknown', 49, 'https://github.com/aliyun/alibabacloud-rds-openapi-mcp-server', NULL, 0, 'https://github.com/aliyun.png?size=128', '2026-03-09T05:21:01.904355+00:00'),
  ('dataworks', 'DataWorks', 'DataWorks MCP Server exports the Alibaba Cloud DataWorks Open API to the Model Context Protocol, allowing AI agents to interact with DataWorks project management and data workflow tools through a standardized, type-safe interface. Built with TypeScript and Zod for robust schema validation, the server dynamically generates MCP tools from the DataWorks API, enabling programmatic project listing and management operations.', '@aliyun', 'development', 'Unknown', 29, 'https://github.com/aliyun/alibabacloud-dataworks-mcp-server', 'alibabacloud-dataworks-mcp-server', 5548, 'https://github.com/aliyun.png?size=128', '2026-03-09T05:21:01.904378+00:00'),
  ('n8n', 'n8n', 'Enables conversational workflow management for n8n automation platform through comprehensive REST API integration. Provides tools for complete workflow lifecycle management including creation, modification, activation, and execution monitoring, plus webhook triggering capabilities and built-in documentation for common n8n node types. Features robust error handling with retry logic, detailed logging, and self-documenting tools that help understand n8n''s workflow structure and node configurations, making it ideal for automating workflow creation and maintenance tasks. Built specifically for Cursor IDE integration.', '@alicankiraz1', 'productivity', 'Unknown', 52, 'https://github.com/alicankiraz1/cursor-n8n-builder', NULL, 0, 'https://github.com/alicankiraz1.png?size=128', '2026-03-09T05:21:01.904419+00:00'),
  ('spotdb', 'SpotDB', 'SpotDB provides direct access to an ephemeral DuckDB instance through a lightweight Go-based server that supports CSV file uploads, SQL query execution, and database snapshots. Built by aliengiraffe, it exposes tools for reading and writing queries, creating and managing datasources, and generating business insights through an MCP interface, while also offering HTTP endpoints for file uploads with comprehensive validation including security checks for CSV injection attacks. The implementation includes WebSocket support for real-time interactions, S3 integration for snapshot management, and robust file validation with encoding detection, making it valuable for data analysis workflows, temporary data sandboxing, and working with structured data without requiring persistent database infrastructure.', '@aliengiraffe', 'databases', 'Unknown', 16, 'https://github.com/aliengiraffe/spotdb', NULL, 0, 'https://github.com/aliengiraffe.png?size=128', '2026-03-09T05:21:01.904430+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('everything-search', 'Everything Search', 'This Everything Search MCP server provides AI assistants with powerful file search capabilities through integration with the Everything Search Engine. Developed to enhance file discovery and management tasks, it leverages the Everything Search HTTP server to offer advanced search options including case sensitivity, whole word matching, regular expressions, and path-specific searches. The server supports customizable result sorting and formatting, making it ideal for use cases such as document retrieval, file organization, and content analysis across large file systems. Its implementation in TypeScript, using the Model Context Protocol SDK, ensures efficient and standardized communication between AI systems and local file search functionalities.', '@alihkhawaher', 'development', 'Unknown', 9, 'https://github.com/alihkhawaher/everything-search-server', NULL, 0, 'https://github.com/alihkhawaher.png?size=128', '2026-03-09T05:21:01.904462+00:00'),
  ('godspeed-task-management', 'Godspeed Task Management', 'Godspeed MCP provides a connector for AI assistants to interact with the Godspeed Task Management API through the Model Context Protocol. It enables task management operations including listing, creating, updating, and deleting tasks, as well as managing task lists. Built with TypeScript and using the MCP SDK, this implementation authenticates via API token and exposes a set of tools that allow AI assistants to help users organize their productivity workflow directly from within their development environment. The server is designed to work with Cursor and other MCP-compatible clients, making it useful for developers who want to manage their tasks without context switching.', '@alinagy', 'development', 'Unknown', 4, 'https://github.com/alinagy/godspeed-mcp', 'godspeed-mcp', 907, 'https://github.com/alinagy.png?size=128', '2026-03-09T05:21:01.904488+00:00'),
  ('memory-bank', 'Memory Bank', 'This Memory Bank MCP server implementation transforms traditional file-based memory banks into a centralized, remotely accessible service. Developed by Aliosh Pimenta, it enables multi-project memory bank management with consistent file structure and validation. The server provides full MCP protocol implementation for read/write operations, project listing, and file management. It ensures proper isolation between project memory banks and includes security features like path traversal prevention. The implementation is particularly useful for AI assistants and development teams requiring structured, remotely accessible project documentation and context management across multiple projects.', '@alioshr', 'development', 'Unknown', 875, 'https://github.com/alioshr/memory-bank-mcp', NULL, 0, 'https://github.com/alioshr.png?size=128', '2026-03-09T05:21:01.904563+00:00'),
  ('docker', 'Docker', 'MCP server that enables AI assistants (Cursor, Claude Desktop) to manage Docker containers, images, networks, volumes, and registries. Features comprehensive Docker management, Docker Compose support, registry integration (Docker Hub & GHCR), and safety confirmations.', '@alisaitteke', 'cloud', 'Unknown', 0, 'https://github.com/alisaitteke/docker-mcp', NULL, 0, 'https://github.com/alisaitteke.png?size=128', '2026-03-09T05:21:01.904579+00:00'),
  ('noun-project', 'Noun Project', 'MCP server for The Noun Project - search and download icons directly in Cursor AI and Claude. Provides integration with The Noun Project''s icon library for seamless icon discovery and retrieval within AI-powered development environments.', '@alisaitteke', 'development', 'Unknown', 1, 'https://github.com/alisaitteke/noun-mcp', NULL, 0, 'https://github.com/alisaitteke.png?size=128', '2026-03-09T05:21:01.904597+00:00'),
  ('npm-registry', 'npm Registry', 'npm package analysis for AI assistants. Search, compare, analyze bundle sizes, check security and generate code examples via MCP for Cursor/Claude.', '@alisaitteke', 'development', 'Unknown', 2, 'https://github.com/alisaitteke/npm-mcp', NULL, 0, 'https://github.com/alisaitteke.png?size=128', '2026-03-09T05:21:01.904614+00:00'),
  ('pandas-data-analysis', 'Pandas Data Analysis', 'This MCP server for pandas analysis, developed by an unnamed author, provides AI assistants with powerful data manipulation and analysis capabilities. Built with Python and leveraging libraries like pandas, numpy, and matplotlib, it offers a standardized interface for data processing, statistical analysis, and visualization tasks. The server abstracts the complexities of pandas operations, allowing AI systems to easily incorporate data analysis into their workflows. It''s containerized using Docker for easy deployment and scalability. This implementation is particularly valuable for data scientists, analysts, and AI researchers working on data-driven projects, enabling use cases such as exploratory data analysis, time series forecasting, and automated report generation across various domains.', '@alistairwalsh', 'cloud', 'Unknown', 8, 'https://github.com/alistairwalsh/mcp_pandas', NULL, 0, 'https://github.com/alistairwalsh.png?size=128', '2026-03-09T05:21:01.904639+00:00'),
  ('alibaba-cloud-edge-security-acceleration', 'Alibaba Cloud Edge Security Acceleration', 'MCP Server ESA provides a bridge to Alibaba Cloud''s Edge Security Acceleration (ESA) service, enabling AI assistants to manage edge routines, deployments, routes, and sites. Developed by Aliyun, this TypeScript implementation exposes over 20 specialized tools for operations including creating and deploying edge routines, managing code versions, configuring routes, and handling site records through the ESA API. The server authenticates with Alibaba Cloud using access keys and handles complex operations like code uploads to OSS, making it particularly valuable for developers who need to automate edge computing deployments or manage ESA resources through AI assistants.', '@aliyun', 'development', 'Unknown', 26, 'https://github.com/aliyun/mcp-server-esa', 'mcp-server-esa', 6858, 'https://github.com/aliyun.png?size=128', '2026-03-09T05:21:01.904668+00:00'),
  ('hologres', 'Hologres', 'Hologres MCP Server provides a universal interface between AI Agents and Alibaba Cloud''s Hologres databases, enabling seamless communication for metadata retrieval and SQL execution. Developed by TimothyDing, it supports executing SQL (including DDL, DML, and queries), collecting statistics with ANALYZE commands, and retrieving database metadata such as schemas, tables, and table statistics. The server requires Python 3.13+ and can be installed via pip or run directly from the repository, making it easy to integrate with MCP clients through simple configuration. This implementation is particularly valuable for data analysis workflows that need to interact with Hologres databases without switching contexts.', '@aliyun', 'databases', 'Unknown', 26, 'https://github.com/aliyun/alibabacloud-hologres-mcp-server', 'hologres-mcp-server', 6339, 'https://github.com/aliyun.png?size=128', '2026-03-09T05:21:01.904679+00:00'),
  ('alibaba-cloud-lindorm', 'Alibaba Cloud Lindorm', 'Lindorm MCP Server provides a bridge between AI assistants and Alibaba Cloud''s Lindorm multi-model NoSQL database. Built in Python using FastMCP, it exposes tools for vector search operations and SQL query execution against Lindorm''s wide-table engine. The server enables retrieval from knowledge bases using both full-text and vector search capabilities, allows exploration of index structures, and supports SQL operations with specialized error handling for inefficient queries. It requires configuration of Lindorm instance credentials and deployed text-embedding models, making it valuable for applications that need to leverage Lindorm''s vector search capabilities for retrieval augmented generation or perform SQL operations on Lindorm data stores.', '@aliyun', 'databases', 'Unknown', 3, 'https://github.com/aliyun/alibabacloud-lindorm-mcp-server', NULL, 0, 'https://github.com/aliyun.png?size=128', '2026-03-09T05:21:01.904690+00:00'),
  ('polardb', 'PolarDB', 'PolarDB MCP Server provides a bridge between AI assistants and Alibaba Cloud PolarDB databases, enabling direct interaction with MySQL and PostgreSQL database instances. The server supports two database types (MySQL and PostgreSQL) with similar capabilities including table listing, field information retrieval, data querying, and SQL execution with configurable safety controls for write operations. It implements both stdio and SSE transport modes, handles database connections securely, and includes specialized features like AI model management for PolarDB MySQL. This implementation is particularly valuable for developers who need to access and manipulate PolarDB database content through natural language interfaces without writing complex SQL queries manually.', '@aliyun', 'databases', 'Unknown', 14, 'https://github.com/aliyun/alibabacloud-polardb-mcp-server', NULL, 0, 'https://github.com/aliyun.png?size=128', '2026-03-09T05:21:01.904701+00:00'),
  ('polardb-x', 'PolarDB-X', 'This MCP server provides database connectivity and management tools for Alibaba Cloud''s PolarDB-X distributed database system, built by Aliyun using TypeScript with the Model Context Protocol SDK and mysql2 driver. It offers three core tools: SQL query execution, database status inspection, and command listing, along with schema resources that expose table structure information through a custom polardbx:// URI scheme. The implementation requires database connection credentials via environment variables and is designed for database administration, monitoring, and development workflows where AI assistants need to interact with PolarDB-X instances for tasks like data analysis, schema exploration, and database troubleshooting.', '@aliyun', 'databases', 'Unknown', 4, 'https://github.com/aliyun/alibabacloud-polardbx-mcp-server', 'polardbx-mcp', 771, 'https://github.com/aliyun.png?size=128', '2026-03-09T05:21:01.904712+00:00'),
  ('alibaba-cloud-supabase', 'Alibaba Cloud Supabase', 'Multi-component MCP server implementation by Aliyun that provides AI assistants with complete access to Supabase project management, database operations, and cloud infrastructure through both the Supabase Management API and Alibaba Cloud GPDB integration. The implementation includes three main packages: a core Supabase server with tools for project creation, database migrations, Edge Functions deployment, branching workflows, storage management, and debugging capabilities; a PostgREST server for direct database CRUD operations via REST API; and utility functions including a StreamTransport for in-memory client-server connections. Built with comprehensive feature toggles, project scoping options, and read-only modes, it serves developers building Supabase applications who need programmatic access to their infrastructure, teams managing multiple Supabase projects through conversational interfaces, and organizations requiring automated database operations with integrated Alibaba Cloud analytics capabilities for enhanced data processing workflows.', '@aliyun', 'databases', 'Unknown', 7, 'https://github.com/aliyun/alibabacloud-supabase-mcp-server', '@aliyun-supabase/mcp-server-supabase', 3818, 'https://github.com/aliyun.png?size=128', '2026-03-09T05:21:01.904724+00:00'),
  ('document-crawler-search', 'Document Crawler & Search', 'MCPDocSearch is a tool for crawling websites, generating Markdown documentation, and making it searchable via an MCP server. It consists of two main components: a crawler CLI that extracts content from documentation sites and converts it to Markdown, and an MCP server that loads these documents, chunks them into searchable sections, and generates vector embeddings using sentence-transformers. The server exposes tools for listing documents, retrieving document structures, and performing semantic searches over the content, making it particularly useful for AI agents that need to access up-to-date documentation beyond their training cutoff.', '@alizdavoodi', 'ai-ml', 'Unknown', 36, 'https://github.com/alizdavoodi/mcpdocsearch', NULL, 0, 'https://github.com/alizdavoodi.png?size=128', '2026-03-09T05:21:01.904769+00:00'),
  ('alkemi', 'Alkemi', 'A STDIO wrapper for Alkemi''s Streamable HTTP MCP endpoint that enables AI clients to query databases using natural language questions and access exposed API endpoints. Built by Alkemi.ai, it acts as a proxy server that connects to Alkemi''s cloud service at api.alkemi.cloud/mcp, which stores database metadata and generates proper queries for data sources like Snowflake, Google BigQuery, and DataBricks. The implementation supports bearer token authentication, product-specific scoping, and can be configured for multiple instances, making it useful for teams that need to share consistent database querying capabilities across different AI agents without maintaining schema information in each client.', '@alkemi-ai', 'databases', 'Unknown', 3, 'https://github.com/alkemi-ai/alkemi-mcp', '@alkemiai/alkemi-mcp', 258, 'https://github.com/alkemi-ai.png?size=128', '2026-03-09T05:21:01.904779+00:00'),
  ('gpt-5', 'GPT-5', 'GPT-5 MCP server that provides direct integration with OpenAI''s GPT-5 API through the new Responses endpoint, offering two core tools for text generation: gpt5_generate for simple prompt-based requests and gpt5_messages for structured conversation handling with message roles. The implementation uses safe property access patterns to handle API response parsing and excludes unsupported parameters like temperature and max_tokens, making it valuable for developers who want to access GPT-5''s capabilities through MCP-compatible applications without building their own OpenAI API integration layer.', '@allaboutai-yt', 'development', 'Unknown', 80, 'https://github.com/allaboutai-yt/gpt5mcp', NULL, 0, 'https://github.com/allaboutai-yt.png?size=128', '2026-03-09T05:21:01.904805+00:00'),
  ('openai-chat-completions', 'OpenAI Chat Completions', 'This MCP server, developed by AllAboutAI-YT, implements a simple notes system to demonstrate core MCP concepts. It provides resources for text notes with URIs and metadata, tools for creating new notes, and prompts for generating summaries. The server uses TypeScript and offers a straightforward interface for AI assistants to manage and analyze textual information. By connecting AI capabilities with a basic note-taking system, this implementation serves as an educational example and starting point for developers looking to understand MCP principles. It is particularly useful for applications requiring simple text storage and retrieval, note summarization, or as a foundation for building more complex document management systems with AI integration.', '@allaboutai-yt', 'development', 'Unknown', 79, 'https://github.com/allaboutai-yt/mcp-servers/tree/HEAD/openai-server', NULL, 0, 'https://github.com/allaboutai-yt.png?size=128', '2026-03-09T05:21:01.904834+00:00'),
  ('system-info', 'System Info', 'MCP-SysInfo is a lightweight server that provides real-time system information through a simple API. Developed by Allen Bijo, it retrieves detailed hardware and system metrics including CPU, memory, disk, and GPU statistics using libraries like psutil and GPUtil. The server exposes a single endpoint that returns comprehensive system data in a structured format, making it particularly useful for monitoring and diagnostic purposes where users need quick access to their system''s performance metrics without leaving their AI assistant interface.', '@allenbijo', 'ai-ml', 'Unknown', 0, 'https://github.com/allenbijo/mcp-sysinfo', NULL, 0, 'https://github.com/allenbijo.png?size=128', '2026-03-09T05:21:01.904888+00:00'),
  ('solr-vector-search', 'Solr Vector Search', 'Solr MCP provides a bridge between AI assistants and Apache Solr search indexes, enabling powerful hybrid search capabilities that combine keyword precision with vector semantic understanding. Built by Allen Day, this Python implementation uses FastMCP to expose Solr''s search functionality through a standardized protocol, with features including vector embeddings generation via Ollama (using nomic-embed-text), unified collections for storing both document content and embeddings, and Docker integration for easy deployment. The server is particularly valuable for workflows requiring advanced document retrieval from existing Solr indexes, allowing AI assistants to perform contextual searches against structured data repositories without direct database access.', '@allenday', 'databases', 'Unknown', 20, 'https://github.com/allenday/solr-mcp', NULL, 0, 'https://github.com/allenday.png?size=128', '2026-03-09T05:21:01.904901+00:00'),
  ('prefect', 'Prefect', 'This MCP server provides AI assistants with complete Prefect workflow orchestration capabilities, built using Python with FastMCP and the Prefect client SDK to enable natural language control over flow management, deployment operations, task monitoring, and infrastructure management. The implementation offers full CRUD operations across flows, flow runs, deployments, task runs, work queues, variables, and blocks, with UI URL generation for seamless web interface integration and comprehensive filtering capabilities for workflow discovery and monitoring. Built with Docker containerization, SSE transport support, environment-based configuration, and extensive test coverage using pytest with real Prefect server integration, it serves data engineering teams needing conversational access to workflow orchestration, DevOps engineers requiring AI-driven deployment management, and operations teams where natural language interfaces enhance Prefect administration without direct API knowledge.', '@allen-munsch', 'cloud', 'Unknown', 15, 'https://github.com/allen-munsch/mcp-prefect', 'mcp-prefect', 2760, 'https://github.com/allen-munsch.png?size=128', '2026-03-09T05:21:01.904930+00:00'),
  ('home-assistant', 'Home Assistant', 'This MCP server, developed by allenporter, enables AI assistants to interact with Home Assistant through a standardized interface. It provides tools for querying and controlling smart home devices, sensors, and automations via the Home Assistant API. The server integrates directly with Home Assistant instances, abstracting away complexities to offer a simplified workflow for AI systems. By connecting AI capabilities with Home Assistant''s comprehensive smart home platform, this implementation empowers AI assistants to manage and analyze home automation tasks. It is particularly useful for applications requiring smart home control, energy management, or any scenario where an AI system needs to interact with and reason about the state of a connected home.', '@allenporter', 'productivity', 'Unknown', 67, 'https://github.com/allenporter/mcp-server-home-assistant', 'mcp-server-home-assistant', 3875, 'https://github.com/allenporter.png?size=128', '2026-03-09T05:21:01.904973+00:00'),
  ('codebase-rag', 'Codebase RAG', 'This MCP server provides semantic codebase search and file retrieval using CocoIndex embeddings and PostgreSQL with pgvector for similarity search. Built by allentcm, it integrates with the Voyage API for code-specific embeddings (voyage-code-3 model) and offers three core tools: semantic code search that returns relevant snippets with similarity scores and line numbers, file listing from the tracking table, and complete file content retrieval. The implementation uses CocoIndex''s transform flow system for embedding generation, supports Docker deployment with environment-based configuration, and is designed for AI assistants that need to understand and navigate large codebases through natural language queries rather than traditional keyword-based search.', '@allentcm', 'databases', 'Unknown', 12, 'https://github.com/allentcm/mcp-codebase-rag', NULL, 0, 'https://github.com/allentcm.png?size=128', '2026-03-09T05:21:01.905009+00:00'),
  ('name-origin-predictor', 'Name Origin Predictor', 'This MCP server predicts the origin of names using the Nationalize.io API, offering both single-name prediction and batch processing capabilities. It exposes two tools: ''predict_origin'' for individual names and ''batch_predict'' for multiple names, returning country predictions with probability scores. The implementation uses FastMCP with stdio transport for seamless integration with AI assistants, making it valuable for applications requiring demographic analysis, character development, or cultural research.', '@allglenn', 'development', 'Unknown', 0, 'https://github.com/allglenn/mcp-name-origin-server', NULL, 0, 'https://github.com/allglenn.png?size=128', '2026-03-09T05:21:01.905036+00:00'),
  ('allstacks', 'Allstacks', 'Provides comprehensive access to the Allstacks engineering intelligence platform through HTTP Basic Authentication. Offers tools across metrics and analytics, service items, users and teams, organization management, dashboards, employee analytics, forecasting, labels, alerts, AI intelligence, work bundles, and risk management. Enables AI-powered insights into software delivery performance, team productivity, and project health.', '@allstacks', 'productivity', 'Unknown', 0, 'https://github.com/allstacks/allstacks-mcp-server', NULL, 0, 'https://github.com/allstacks.png?size=128', '2026-03-09T05:21:01.905068+00:00'),
  ('mantra-chain-mcp', 'Mantra Chain MCP', 'A Model Context Protocol (MCP) server for interacting with MantraChain (Cosmos SDK) blockchain. This server provides tools for sending tokens, delegating to validators, querying balances, and more using the MCP protocol.', '@allthatjazzleo', 'ai-ml', 'Unknown', 2, 'https://github.com/allthatjazzleo/mantrachain-mcp', 'mantrachain-mcp', 1122, 'https://github.com/allthatjazzleo.png?size=128', '2026-03-09T05:21:01.905093+00:00'),
  ('allvoicelab', 'AllVoiceLab', 'AllVoiceLab MCP Server provides AI assistants with access to advanced voice and audio processing capabilities through a standardized interface. It integrates with AllVoiceLab''s API to offer tools for text-to-speech conversion, voice cloning, speech-to-speech transformation, subtitle extraction, and video dubbing in multiple languages. The server implements robust validation, error handling, and asynchronous processing for long-running tasks, making it ideal for applications requiring high-quality voice synthesis, audio manipulation, and multilingual content creation.', '@allvoicelab', 'productivity', 'Unknown', 56, 'https://github.com/allvoicelab/allvoicelab-mcp', 'allvoicelab-mcp', 6706, 'https://github.com/allvoicelab.png?size=128', '2026-03-09T05:21:01.905133+00:00'),
  ('amadeus', 'Amadeus', 'An MCP server that provides access to the Amadeus travel API for flight search functionality, built by DongHyun Chae using FastMCP with both STDIO and HTTP transport support. The implementation features comprehensive flight offer search with parameters like origin/destination airports, travel dates, passenger counts, travel class preferences, airline filtering, and pricing constraints, along with robust error handling and parameter validation to prevent API rejections. It includes Docker containerization, Smithery deployment configuration with base64-encoded credential handling, and debug endpoints for troubleshooting, making it useful for travel planning applications, flight comparison tools, and AI-assisted trip booking workflows.', '@almogqwinz', 'cloud', 'Unknown', 1, 'https://github.com/almogqwinz/mcp-amadeus-api', NULL, 0, 'https://github.com/almogqwinz.png?size=128', '2026-03-09T05:21:01.905156+00:00'),
  ('s3-uploader', 'S3 Uploader', 'Facilitates image uploads to Amazon S3 with presigned URL generation for sharing. Provides two tools: one for uploading local image files and another for capturing images directly from the macOS clipboard using pngpaste or pbpaste utilities. Automatically organizes uploaded files using date-based folder structures, supports multiple image formats including PNG, JPEG, WebP, GIF, SVG, and TIFF, and returns presigned URLs with metadata including file size and content type.', '@almond-bongbong', 'search', 'Unknown', 1, 'https://github.com/almond-bongbong/mcp-s3-uploader', NULL, 0, 'https://github.com/almond-bongbong.png?size=128', '2026-03-09T05:21:01.905199+00:00'),
  ('joplin', 'Joplin', 'Provides comprehensive access to the Joplin note-taking application through its REST API. Enables searching, retrieving, creating, updating, and deleting notes, notebooks, and tags. Supports importing files in various formats including Markdown, HTML, CSV, and TXT. Built with FastMCP and the joppy Python library for robust interaction with local Joplin databases.', '@alondmnt', 'databases', 'Unknown', 72, 'https://github.com/alondmnt/joplin-mcp', NULL, 0, 'https://github.com/alondmnt.png?size=128', '2026-03-09T05:21:01.905210+00:00'),
  ('gitlab', 'GitLab', 'This MCP server provides comprehensive GitLab API integration, enabling AI assistants to manage projects, issues, merge requests, pipelines, and CI/CD workflows programmatically. Built by Alos using TypeScript with the Model Context Protocol SDK and axios for HTTP requests, it offers 22 specialized tools including project listing and retrieval, issue and merge request management with full CRUD operations, pipeline creation and control (retry, cancel, delete), job log retrieval with advanced filtering options, branch and commit browsing, and user information access. The implementation features flexible search capabilities with pagination, detailed job trace analysis with line limits and tail mode support, robust error handling with structured JSON responses, and authentication through GitLab Bearer tokens via environment variables, making it valuable for DevOps automation workflows, CI/CD pipeline monitoring, issue tracking integration, and building AI assistants that need programmatic access to GitLab''s development lifecycle management without manual web interface navigation.', '@alosies', 'development', 'Unknown', 8, 'https://github.com/alosies/gitlab-mcp-server', '@alosies/gitlab-mcp-server', 8902, 'https://github.com/alosies.png?size=128', '2026-03-09T05:21:01.905241+00:00'),
  ('alpaca-trading', 'Alpaca Trading', 'This MCP server provides complete Alpaca trading platform integration, enabling AI assistants to manage stock and options trading accounts through paper and live trading environments. Built using Python with the alpaca-py SDK and FastMCP framework, it offers account monitoring with real-time balance and position tracking, comprehensive order management supporting market, limit, stop, stop-limit, and trailing stop orders, historical and real-time market data retrieval including quotes, bars, and trade history, position management with partial and full closure capabilities, watchlist creation and management, and market calendar information with corporate action announcements. The implementation includes proper error handling for API rate limits and trading restrictions, environment variable configuration for secure credential management, and support for both stock and options trading workflows, making it valuable for algorithmic trading development, portfolio management automation, and financial analysis workflows that require programmatic access to brokerage account functionality.', '@alpacahq', 'development', 'Unknown', 538, 'https://github.com/alpacahq/alpaca-mcp-server', NULL, 0, 'https://github.com/alpacahq.png?size=128', '2026-03-09T05:21:01.905277+00:00'),
  ('semantic-scholar', 'Semantic Scholar', 'This MCP server provides comprehensive access to the Semantic Scholar academic search API, enabling AI assistants to search for research papers, retrieve detailed paper and author information, analyze citation networks, and discover paper recommendations. Built by Alperen Kocyigit using Python with FastMCP, it implements robust retry logic with exponential backoff for rate limiting and includes advanced features like batch operations for multiple papers/authors, text snippet search within papers, autocomplete suggestions, and ML-powered paper recommendations based on positive/negative examples. The implementation is designed for academic research workflows, literature reviews, citation analysis, and building AI research assistants that need to navigate and analyze the scholarly literature landscape.', '@alperenkocyigit', 'databases', 'Unknown', 6, 'https://github.com/alperenkocyigit/semantic-scholar-graph-api', NULL, 0, 'https://github.com/alperenkocyigit.png?size=128', '2026-03-09T05:21:01.905288+00:00'),
  ('vscode-workspace', 'VSCode Workspace', 'A VSCode-integrated MCP server that provides real-time access to your development workspace, enabling AI assistants to read files, analyze code structure, execute commands, and detect currently active projects. The implementation monitors VSCode activity to automatically identify the most recently accessed files, supports code analysis across multiple programming languages using configurable regex patterns, and includes performance monitoring with caching for safe operations. Built with comprehensive error handling and security controls, it''s designed for developers who want their AI assistants to understand and interact with their active coding environment without manual file specification.', '@alpermdr', 'development', 'Unknown', 4, 'https://github.com/alpermdr/vscode_mcp_python', NULL, 0, 'https://github.com/alpermdr.png?size=128', '2026-03-09T05:21:01.905316+00:00'),
  ('alpha-vantage', 'Alpha Vantage', 'Provides real-time and historical financial market data through the Alpha Vantage API. Enables access to stock quotes, technical indicators, forex rates, cryptocurrency prices, commodities data, and economic indicators across global markets. Supports comprehensive financial analysis with over 100 data retrieval tools covering core stock APIs, fundamental data, and market intelligence.', '@alphavantage', 'finance', 'Unknown', 94, 'https://github.com/alphavantage/alpha_vantage_mcp', NULL, 0, 'https://github.com/alphavantage.png?size=128', '2026-03-09T05:21:01.905362+00:00'),
  ('alsoasked', 'AlsoAsked', 'This MCP server provides access to Google''s "People Also Ask" data through the AlsoAsked API, enabling AI assistants to perform SEO research and content optimization by retrieving hierarchical PAA question data for any search terms. Built by Metehan Yesilyurt using TypeScript with the Model Context Protocol SDK, it offers tools for searching PAA questions with configurable language, region, depth, and freshness parameters, checking account credits and API usage, and retrieving structured question hierarchies with metadata including total question counts and search summaries. The implementation requires an AlsoAsked Pro API key and formats results into clean JSON structures with question levels and child relationships, making it valuable for SEO professionals conducting keyword research, content creators identifying trending questions in their niche, and marketers analyzing search intent across different geographic regions and languages.', '@metehan777', 'development', 'Unknown', 13, 'https://github.com/metehan777/alsoasked-mcp', NULL, 0, 'https://github.com/metehan777.png?size=128', '2026-03-09T05:21:01.905420+00:00'),
  ('github', 'GitHub', 'GitHub MCP server provides a bridge between Claude and the GitHub API, enabling AI assistants to interact with GitHub repositories. Built with TypeScript and Octokit, it offers tools for searching repositories, retrieving repository information, listing issues, and creating new issues. The server also includes prompt handlers that generate formatted content for issue descriptions, pull request descriptions, and search queries. This implementation is particularly useful for developers who want to manage their GitHub projects directly through AI conversations, streamlining workflows for issue tracking and repository exploration.', '@alsonwangkhem', 'development', 'Unknown', 0, 'https://github.com/alsonwangkhem/github-mcp-2', NULL, 0, 'https://github.com/alsonwangkhem.png?size=128', '2026-03-09T05:21:01.905443+00:00'),
  ('famxplor', 'Famxplor', 'Family travel MCP server by Denis Angilella that provides AI assistants with access to Famxplor''s curated database of family-tested activities worldwide through a single search tool for finding geographically nearby attractions. The implementation uses Python with FastMCP and integrates with the Famxplor API to retrieve activities based on latitude, longitude, and maximum distance parameters, returning formatted results with titles, URLs, images, and coordinates. Designed for families planning trips with children, travel agents building family-focused itineraries, and AI assistants helping parents discover kid-friendly activities in specific locations, with the server available both as a free remote service and for local development with API key authentication.', '@alt250', 'databases', 'Unknown', 1, 'https://github.com/alt250/famxplor-family-travel-mcp-server', NULL, 0, 'https://github.com/alt250.png?size=128', '2026-03-09T05:21:01.905453+00:00'),
  ('altmetric', 'Altmetric', 'Track research attention across news, policy documents, social media, and online platforms', '@altmetric', 'search', 'Unknown', 1, 'https://github.com/altmetric/altmetric-mcp', NULL, 0, 'https://github.com/altmetric.png?size=128', '2026-03-09T05:21:01.905474+00:00'),
  ('rhino-3d', 'Rhino 3D', 'RhinoMCP Server provides a bridge between AI systems and Rhino 3D''s Python scripting capabilities through the Model Context Protocol. This implementation enables AI agents to generate and manipulate 3D models in Rhino by exposing scene context information and geometry creation tools (currently supporting spheres), with all operations requiring explicit user consent via dialog prompts. The server is designed to run within Rhino''s Python environment and follows MCP security guidelines, making it particularly valuable for AI-assisted 3D modeling workflows that require direct interaction with Rhino documents.', '@always-tinkering', 'ai-ml', 'Unknown', 44, 'https://github.com/always-tinkering/rhinomcpserver', NULL, 0, 'https://github.com/always-tinkering.png?size=128', '2026-03-09T05:21:01.905521+00:00'),
  ('db-query', 'DB Query', 'This MCP server, developed by ALX99, provides a standardized interface for AI models to interact with multiple database systems including PostgreSQL, MySQL, and SQLite. Built using Go, it offers tools for connecting to databases, executing queries, and retrieving results in CSV format. The implementation focuses on simplifying database access through a consistent MCP interface, enabling AI assistants to perform complex data operations across different database flavors. By connecting AI models with robust database functionality, this server facilitates sophisticated data analysis, reporting, and management scenarios. It''s particularly valuable for applications and AI systems that need to work with diverse data sources or require flexible database interactions without being tied to a specific database management system.', '@alx99', 'databases', 'Unknown', 1, 'https://github.com/alx99/db-mcp', NULL, 0, 'https://github.com/alx99.png?size=128', '2026-03-09T05:21:01.905532+00:00'),
  ('ai-meta-tool-creator', 'AI Meta Tool Creator', 'AI Meta MCP Server enables AI agents to dynamically create and execute custom tools through a meta-function architecture. Built with TypeScript and the Model Context Protocol SDK, it provides a secure sandbox for running JavaScript, Python, or shell code defined at runtime. The server includes persistent storage for tools, allowing AI to build up a library of functions that can be listed, updated, or deleted. With configurable security controls for different execution environments, it''s ideal for AI agents that need to extend their capabilities programmatically without requiring developer intervention for each new tool.', '@alxspiker', 'development', 'Unknown', 8, 'https://github.com/alxspiker/ai-meta-mcp-server', NULL, 0, 'https://github.com/alxspiker.png?size=128', '2026-03-09T05:21:01.905558+00:00'),
  ('ftp-server-manager', 'FTP Server Manager', 'The MCP Server for FTP Access enables Claude.app to interact with FTP servers through natural language commands. Built with TypeScript and the basic-ftp library, it provides tools for listing directories, downloading and uploading files, creating directories, and deleting files or directories on remote FTP servers. The server is configured through environment variables for connection details and supports both standard FTP and secure FTPS connections. This implementation is particularly useful for users who need to manage remote file systems directly from their AI assistant interface without switching to dedicated FTP clients.', '@alxspiker', 'development', 'Unknown', 15, 'https://github.com/alxspiker/mcp-server-ftp', NULL, 0, 'https://github.com/alxspiker.png?size=128', '2026-03-09T05:21:01.905587+00:00'),
  ('windows-command-line-mcp-server', 'Windows Command Line MCP Server', 'The Windows Command Line MCP Server provides a robust, secure bridge between AI models and Windows system operations. It allows controlled execution of commands, project creation, and system information retrieval while maintaining strict security protocols.', '@alxspiker', 'productivity', 'Unknown', 8, 'https://github.com/alxspiker/windows-command-line-mcp-server', NULL, 0, 'https://github.com/alxspiker.png?size=128', '2026-03-09T05:21:01.905616+00:00'),
  ('google-calendar', 'Google Calendar', 'Google Calendar MCP Server provides a TypeScript-based integration with Google Calendar API, enabling AI assistants to manage calendar events through a set of standardized tools. Developed by am2rican5, it features persistent token storage for seamless authentication, supports operations like listing calendars, creating/editing/deleting events, and offers both stdio and SSE transport options. The implementation handles OAuth 2.0 authorization flow automatically, making it ideal for AI agents that need to schedule meetings, retrieve calendar information, or manage events without requiring repeated user authentication.', '@am2rican5', 'development', 'Unknown', 12, 'https://github.com/am2rican5/mcp-google-calendar', 'mcp-google-calendar', 5694, 'https://github.com/am2rican5.png?size=128', '2026-03-09T05:21:01.905646+00:00'),
  ('gemini-api-documentation', 'Gemini API Documentation', 'Provides structured access to Gemini API documentation with searchable content retrieval and resource indexing for quickstart guides, model information, tool usage, embeddings, and troubleshooting resources.', '@amaansyed27', 'ai-ml', 'Unknown', 3, 'https://github.com/amaansyed27/mcp-gemini-docs', NULL, 0, 'https://github.com/amaansyed27.png?size=128', '2026-03-09T05:21:01.905672+00:00'),
  ('nodemcu', 'NodeMCU', 'NodeMCU MCP provides a bridge between AI assistants and ESP8266-based IoT devices, enabling remote management and monitoring through the Model Context Protocol. The server exposes tools for listing connected devices, retrieving device information, sending commands, and updating device configurations, while handling both WebSocket connections for real-time device communication and REST API endpoints for traditional client access. Built with a modular architecture using Express.js and the official MCP SDK, it''s particularly valuable for smart home automation, environmental monitoring, and IoT device fleet management without leaving the AI assistant interface.', '@amanasmuei', 'ai-ml', 'Unknown', 1, 'https://github.com/amanasmuei/mcp-server-nodemcu', NULL, 0, 'https://github.com/amanasmuei.png?size=128', '2026-03-09T05:21:01.905718+00:00'),
  ('amanmcp', 'AmanMCP', 'AmanMCP is a local-first RAG server that provides semantic code search capabilities for AI coding assistants through the MCP protocol. Built in Go with hybrid search combining BM25 keyword matching and vector embeddings, it supports multiple embedding backends including a bundled MLX server for Apple Silicon, Ollama integration, and static embeddings for offline use. The implementation features automatic project indexing with tree-sitter parsing for intelligent code chunking across many programming languages.', '@aman-cerp', 'development', 'Unknown', 3, 'https://github.com/aman-cerp/amanmcp', NULL, 0, 'https://github.com/aman-cerp.png?size=128', '2026-03-09T05:21:01.905740+00:00'),
  ('profile-researcher', 'Profile Researcher', 'A LinkedIn profile data mining server built by amankale376 that combines Google Custom Search, Apollo.io contact enrichment, and Nubela Proxycurl APIs to systematically discover, extract, and enrich professional profiles. The implementation uses OpenAI for intelligent search query generation and profile filtering, features JSON-based storage with CSV export capabilities, and provides comprehensive tools for searching LinkedIn profiles by keywords, extracting detailed profile data including contact information, and performing end-to-end data mining workflows with rate limiting and duplicate detection. Useful for lead generation, recruitment research, market analysis, and building professional contact databases with enriched company and contact details.', '@amankale376', 'databases', 'Unknown', 3, 'https://github.com/amankale376/profile-researcher', NULL, 0, 'https://github.com/amankale376.png?size=128', '2026-03-09T05:21:01.905752+00:00'),
  ('qdrant-with-openai-embeddings', 'Qdrant with OpenAI Embeddings', 'MCP Qdrant Server with OpenAI Embeddings provides vector search capabilities by connecting AI assistants to Qdrant vector databases. The server exposes three main tools: semantic search in collections using OpenAI embeddings, listing available collections, and viewing collection information. It handles the generation of embeddings from natural language queries and performs vector similarity search against Qdrant collections, making it valuable for applications requiring semantic document retrieval, knowledge base search, or any use case where finding contextually similar content is important.', '@amansingh0311', 'databases', 'Unknown', 7, 'https://github.com/amansingh0311/mcp-qdrant-openai', NULL, 0, 'https://github.com/amansingh0311.png?size=128', '2026-03-09T05:21:01.905764+00:00'),
  ('amap-navigator', 'Amap Navigator', 'XiaoAI_mapMCP provides a map navigation service that integrates with the Amap API to enable location-based operations including geocoding, weather information, driving route planning, and location suggestions. The implementation consists of a FastMCP server (map.py) that exposes these capabilities as tools, and a WebSocket connector (mcp_pipe.py) that handles communication between the MCP server and external clients with robust reconnection logic. This tool is particularly valuable for applications requiring real-time location services, travel planning, and geographic information retrieval within the Chinese market where Amap is widely used.', '@rickeylaiii', 'ai-ml', 'Unknown', 11, 'https://github.com/rickeylaiii/xiaoai_mapmcp', NULL, 0, 'https://github.com/rickeylaiii.png?size=128', '2026-03-09T05:21:01.905811+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('discord-cloud', 'Discord Cloud', 'Discord bot automation server deployed on Cloudflare Workers that provides complete Discord API access through 20+ tools for server management, messaging, reactions, channels, forums, threads, and webhooks with advanced features like custom avatar messaging and bulk operations.', '@amarisaster', 'cloud', 'Unknown', 2, 'https://github.com/amarisaster/discord-cloud-mcp', NULL, 0, 'https://github.com/amarisaster.png?size=128', '2026-03-09T05:21:01.905828+00:00'),
  ('sensei', 'Sensei', 'Sensei transforms engineering standards documentation into an active development mentor by intelligently injecting relevant portions of a comprehensive 57-section rulebook based on file types, operations, and context. Built with FastMCP, it analyzes code patterns across 50+ file types to determine which engineering principles are most relevant, maintains session memory of architectural decisions and constraints, and provides validation tools against established standards. The implementation coordinates 64 specialized AI personas across 12 categories, offers tools for recording and validating agreed-upon patterns, and supports session collaboration through Architecture Decision Records (ADRs), making it valuable for maintaining code quality standards, ensuring architectural consistency across teams, and providing contextual engineering guidance during development.', '@amarodeabreu', 'development', 'Unknown', 1, 'https://github.com/amarodeabreu/sensei-mcp', NULL, 0, 'https://github.com/amarodeabreu.png?size=128', '2026-03-09T05:21:01.905873+00:00'),
  ('amateurs-community-search', 'Amateurs Community Search', 'Spring Boot-based MCP server built by Team01 for the AIBE1 Final Project that provides AI tools for searching and querying community posts from a MySQL database. The implementation uses jOOQ for type-safe database queries, Spring AI''s tool callback framework for MCP integration, and supports paginated post searches with keyword filtering across titles, content, and tags. Features comprehensive database schema with support for various post types (QNA, projects, gatherings, marketplace items), user management, comments, likes, and bookmarks, making it valuable for AI assistants that need to help users discover and analyze community-generated content across different board types and topics.', '@prgrms-aibe-devcourse', 'databases', 'Unknown', 1, 'https://github.com/prgrms-aibe-devcourse/aibe1-finalproject-team01-mcp-server', NULL, 0, 'https://github.com/prgrms-aibe-devcourse.png?size=128', '2026-03-09T05:21:01.905886+00:00'),
  ('aws-bedrock-nova-canvas', 'AWS Bedrock Nova Canvas', 'This Amazon Bedrock MCP server, developed by an unnamed author, provides a standardized interface for leveraging Amazon''s Nova Canvas model for AI image generation. Built with TypeScript and utilizing the AWS SDK, it offers tools for creating images from text descriptions with features like negative prompts, configurable dimensions, and seed control. The server implements comprehensive input validation, error handling, and AWS credential management. By abstracting the complexities of the Bedrock API, it enables AI systems to easily generate images based on textual input. This implementation is particularly valuable for applications requiring programmatic image creation, facilitating use cases such as content illustration, visual concept exploration, and dynamic image generation for various platforms.', '@zxkane', 'cloud', 'Unknown', 24, 'https://github.com/zxkane/mcp-server-amazon-bedrock', NULL, 0, 'https://github.com/zxkane.png?size=128', '2026-03-09T05:21:01.905907+00:00'),
  ('amazon-ecs', 'Amazon ECS', 'Provides a fully managed, cloud-hosted interface for Amazon Elastic Container Service (ECS) that enables natural language access to ECS management and troubleshooting capabilities. Supports monitoring deployments and services, troubleshooting container issues and image pull errors, inspecting VPC, subnet, and security group configurations, and resolving resource dependencies that block task definition deletion. Connects via the mcp-proxy-for-aws PyPI package which handles AWS SigV4 authentication.', '@unknown', 'cloud', 'Unknown', 0, 'https://docs.aws.amazon.com/AmazonECS/latest/developerguide/ecs-mcp-introduction.html', NULL, 0, NULL, '2026-03-09T05:21:01.905924+00:00'),
  ('amazon-eks', 'Amazon EKS', 'AI-powered Amazon EKS cluster management and troubleshooting through natural language, enabling cluster exploration, Kubernetes resource monitoring, pod diagnostics, and infrastructure operations via AWS''s managed MCP service.', '@unknown', 'cloud', 'Unknown', 0, 'https://www.pulsemcp.com/servers/amazon-eks', NULL, 0, NULL, '2026-03-09T05:21:01.905937+00:00'),
  ('ambivo', 'Ambivo', 'Ambivo MCP server provides AI assistants with access to Ambivo''s CRM API endpoints for natural language querying of entity data including leads, contacts, opportunities, and other business objects. Built by the Ambivo Development Team using Python with comprehensive security features including JWT authentication, rate limiting, input validation, and token caching, the implementation processes natural language queries through Ambivo''s /entity/natural_query endpoint and returns structured data in table, natural language, or combined formats. The server includes robust error handling with exponential backoff retry logic, multi-tenant support through JWT-based client isolation, and configurable security controls for query length limits and payload size restrictions, making it valuable for sales teams needing conversational access to CRM data, business analysts requiring natural language database queries, and organizations wanting to integrate Ambivo''s CRM capabilities into AI-powered workflows without complex API management.', '@ambivo-corp', 'databases', 'Unknown', 1, 'https://github.com/ambivo-corp/ambivo-mcp-server', 'ambivo-mcp-server', 5239, 'https://github.com/ambivo-corp.png?size=128', '2026-03-09T05:21:01.905948+00:00'),
  ('amazon-advertising', 'Amazon Advertising', 'The Amazon Advertising MCP Server provides Claude Desktop users with access to Amazon Advertising data through a simple command-line interface. Built using the Model Context Protocol SDK, it connects to a Supabase backend database to retrieve advertiser information, account listings, and validate API keys. The implementation includes tools for basic operations like listing advertiser accounts and retrieving account details, along with utility functions for testing connectivity. It requires only an Amazon Advertising API key for authentication, making it accessible for marketers and advertisers who want to analyze their Amazon advertising data directly through Claude without needing to understand the underlying database infrastructure.', '@amekala', 'databases', 'Unknown', 4, 'https://github.com/amekala/adspirer-mcp-server', NULL, 0, 'https://github.com/amekala.png?size=128', '2026-03-09T05:21:01.905960+00:00'),
  ('vibecraft', 'VibeCraft', 'VibeCraft is an AI-powered Minecraft building server that enables natural language construction through WorldEdit integration. It provides 50+ specialized tools organized into categories: furniture placement (beds, tables, chairs), geometric shapes (spheres, cylinders, pyramids) using Bresenham algorithms, terrain generation with Perlin noise, pattern placement (grids, spirals, fractals), and RCON-based command execution with safety validation. The server supports everything from simple block placement to complex architectural projects like castles and modern structures, offering spatial analysis capabilities and comprehensive building automation for Minecraft worlds.', '@amenti-labs', 'development', 'Unknown', 78, 'https://github.com/amenti-labs/vibecraft', NULL, 0, 'https://github.com/amenti-labs.png?size=128', '2026-03-09T05:21:01.905987+00:00'),
  ('unichat', 'Unichat', 'This Unichat MCP server, developed by amidabuddha, provides a unified interface for interacting with multiple AI language models including OpenAI, MistralAI, Anthropic, xAI, and Google AI. It exposes a single ''unichat'' tool that takes messages as input and returns AI-generated responses, abstracting away the differences between various AI providers. Built in Python, the implementation offers predefined prompts for common tasks like code review, documentation generation, and code explanation. By bridging multiple AI services through a standardized MCP interface, this server enables flexible AI model selection and consistent interaction patterns across providers. It is particularly useful for developers and applications requiring AI-powered code assistance, natural language processing, or multi-model AI capabilities without vendor lock-in.', '@amidabuddha', 'development', 'Unknown', 37, 'https://github.com/amidabuddha/unichat-mcp-server', 'unichat-mcp-server', 5930, 'https://github.com/amidabuddha.png?size=128', '2026-03-09T05:21:01.906039+00:00'),
  ('unichat-ts', 'Unichat (TS)', 'This TypeScript MCP server, developed by Stefan, integrates the Unichat library to enable AI assistants to interact with multiple language models including OpenAI, MistralAI, Anthropic, xAI, and Google AI. It provides a unified interface for sending requests to these models via a single ''unichat'' tool, abstracting away the complexities of individual APIs. The server supports both STDIO and SSE transport mechanisms and includes predefined prompts for common tasks like code review, documentation, and explanation. By offering a consistent way to leverage multiple AI models, this implementation is particularly useful for developers building flexible chatbots, multi-model AI assistants, or applications that require seamless switching between different language models.', '@amidabuddha', 'development', 'Unknown', 11, 'https://github.com/amidabuddha/unichat-ts-mcp-server', 'unichat-ts-mcp-server', 1272, 'https://github.com/amidabuddha.png?size=128', '2026-03-09T05:21:01.906068+00:00'),
  ('bunnyshell', 'Bunnyshell', 'Bunnyshell MCP Server provides a bridge between Claude Desktop and the Bunnyshell platform, enabling AI assistants to manage cloud environments directly through conversation. Developed by Amin Al Ali Al Darwish, this TypeScript implementation leverages the Model Context Protocol SDK to expose Bunnyshell CLI capabilities including environment creation, component deployment, and remote development workflows. The server runs either locally or in a Docker container, authenticates via API tokens, and offers both resource templates and guided prompts that make it particularly valuable for DevOps teams looking to streamline environment management through natural language interactions.', '@aminalali8', 'cloud', 'Unknown', 0, 'https://github.com/aminalali8/bns-mcp-server', NULL, 0, 'https://github.com/aminalali8.png?size=128', '2026-03-09T05:21:01.906091+00:00'),
  ('cockroachdb', 'CockroachDB', 'This MCP server provides AI assistants with CockroachDB database management capabilities, built by Amine El Kouhen using Python with FastMCP and asyncpg for high-performance async database operations. The implementation offers four core tool categories: cluster monitoring for health checks and performance analysis, database operations for connection management and schema administration, table management for DDL operations and bulk data import from cloud storage, and a query engine supporting SQL execution with multiple output formats, transaction management, and query optimization analysis. Built with connection pooling, comprehensive error handling, and flexible deployment options via uvx, Docker, or direct installation, it serves data engineering workflows requiring natural language database interaction, DevOps teams managing CockroachDB clusters through conversational interfaces, and development environments where AI-driven database administration enhances productivity without direct SQL knowledge requirements.', '@amineelkouhen', 'databases', 'Unknown', 9, 'https://github.com/amineelkouhen/mcp-cockroachdb', 'cockroachdb-mcp-server', 3223, 'https://github.com/amineelkouhen.png?size=128', '2026-03-09T05:21:01.906102+00:00'),
  ('shopify', 'Shopify', 'This Shopify MCP server, developed by Amir Bengherbi, enables AI agents to interact with Shopify stores through GraphQL API. Built with TypeScript and leveraging the Model Context Protocol SDK, it provides tools for managing products, customers, orders, discounts, and more. The implementation focuses on comprehensive store management capabilities, with features like advanced order querying, webhook management, and draft order creation. It''s particularly useful for e-commerce businesses and developers looking to automate Shopify operations, enabling use cases such as inventory management, customer segmentation, and sales analysis without dealing directly with Shopify''s API complexities.', '@amir-bengherbi', 'development', 'Unknown', 16, 'https://github.com/amir-bengherbi/shopify-mcp-server', 'shopify-mcp-server', 7457, 'https://github.com/amir-bengherbi.png?size=128', '2026-03-09T05:21:01.906160+00:00'),
  ('aws-cost-explorer-and-bedrock-usage-analytics', 'AWS Cost Explorer and Bedrock Usage Analytics', 'AWS Cost Explorer MCP Server provides a specialized interface for retrieving AWS cloud spending data and Amazon Bedrock usage statistics through CloudWatch logs. Developed by Amit Arora, this Python-based server exposes Cost Explorer API functionality and Bedrock model invocation logs as MCP tools, allowing detailed analysis of EC2 spending, service costs breakdowns, and Bedrock usage patterns by region, user, and model. The implementation supports both local deployment via Claude Desktop and remote operation on Amazon EC2, making it particularly valuable for AWS customers who need to monitor and analyze their cloud spending and AI model usage directly within Claude conversations.', '@aarora79', 'cloud', 'Unknown', 127, 'https://github.com/aarora79/aws-cost-explorer-mcp-server', NULL, 0, 'https://github.com/aarora79.png?size=128', '2026-03-09T05:21:01.906212+00:00'),
  ('stdoutmcp', 'StdoutMCP', 'A lightweight MCP server that captures and manages stdout logs from multiple processes through a named pipe system. The server creates a cross-platform pipe at a standard location, monitors incoming logs, maintains a history of the last 100 entries, and provides tools for querying and filtering these logs, making it particularly useful for debugging and real-time log monitoring across different applications.', '@amitdeshmukh', 'development', 'Unknown', 7, 'https://github.com/amitdeshmukh/stdout-mcp-server', 'stdout-mcp-server', 4358, 'https://github.com/amitdeshmukh.png?size=128', '2026-03-09T05:21:01.906237+00:00'),
  ('rubygems', 'RubyGems', 'Integrates with RubyGems.org and GitHub APIs to provide comprehensive Ruby ecosystem information for development workflows. Offers gem version lookups, dependency analysis, changelog retrieval, download statistics, reverse dependencies, and Ruby release data. Features in-memory caching with TTL, GraphQL-like field selection, pagination support, and response size limits. Sponsored by Kisko Labs, a Finnish software consultancy.', '@amkisko', 'development', 'Unknown', 2, 'https://github.com/amkisko/rubygems_mcp.rb', NULL, 0, 'https://github.com/amkisko.png?size=128', '2026-03-09T05:21:01.906295+00:00'),
  ('status', 'Status', 'Provides access to over 1,700 status page links from the awesome-status repository through tools for service search with fuzzy matching, detailed service information retrieval, and comprehensive service listing. Features an advanced status page fetching tool that intelligently handles JavaScript-rendered pages, RSS/Atom feeds, incident.io APIs, and HTML parsing with crawler protection detection. Includes offline capability with bundled data, no authentication requirements, and robust error handling for various status page formats.', '@amkisko', 'ai-ml', 'Unknown', 1, 'https://github.com/amkisko/status_mcp.rb', NULL, 0, 'https://github.com/amkisko.png?size=128', '2026-03-09T05:21:01.906337+00:00'),
  ('pagelens', 'PageLens', 'Provides visual feedback for frontend development by giving coding agents direct access to rendered output. Uses Puppeteer to capture screenshots, collect console logs, track network errors, and perform visual regression detection via pixel comparison. Supports browser interactions including click, type, scroll, hover, form selection, and viewport resizing with automatic screenshot capture after each action.', '@amoghmanral', 'development', 'Unknown', 2, 'https://github.com/amoghmanral/pagelens-mcp', NULL, 0, 'https://github.com/amoghmanral.png?size=128', '2026-03-09T05:21:01.906359+00:00'),
  ('ffmpeg', 'FFmpeg', 'FFmpeg-MCP provides a server implementation that enables AI models to perform multimedia processing operations using FFmpeg. Built by Amol Soans, it offers tools for video trimming, format conversion, audio extraction, watermarking, quality adjustment, and batch processing of media files. The implementation includes robust security measures like path validation and working directory isolation, comprehensive error handling, and thorough unit tests. It''s particularly valuable for workflows requiring media manipulation without leaving the conversation interface, allowing models to process audio and video files directly.', '@amoldericksoans', 'development', 'Unknown', 14, 'https://github.com/amoldericksoans/ffmpeg-mcp', NULL, 0, 'https://github.com/amoldericksoans.png?size=128', '2026-03-09T05:21:01.906386+00:00'),
  ('cloudflare-browser-rendering', 'Cloudflare Browser Rendering', 'This MCP server implementation provides a bridge to Cloudflare''s Browser Rendering API, enabling web scraping and screenshot capture capabilities. It utilizes Puppeteer for browser automation and offers endpoints for content extraction and screenshot generation. The server is designed for use cases requiring dynamic web content processing, such as data extraction from JavaScript-heavy websites or automated visual testing of web applications.', '@amotivv', 'cloud', 'Unknown', 10, 'https://github.com/amotivv/cloudflare-browser-rendering', NULL, 0, 'https://github.com/amotivv.png?size=128', '2026-03-09T05:21:01.906461+00:00'),
  ('memory-box', 'Memory Box', 'This MCP server provides interactive memory capabilities for AI assistants through integration with Memory Box, a semantic memory storage and retrieval system. Developed by Amotivv, it offers tools for saving, searching, and formatting memories using vector embeddings and semantic search. The server is designed for use cases requiring persistent, context-aware AI interactions, such as personalized assistants or knowledge management systems.', '@amotivv', 'ai-ml', 'Unknown', 10, 'https://github.com/amotivv/memory-box-mcp', NULL, 0, 'https://github.com/amotivv.png?size=128', '2026-03-09T05:21:01.906498+00:00'),
  ('protonmail', 'Protonmail', 'Protonmail MCP Server enables Claude Desktop and Cline VSCode extension to send emails through Protonmail''s SMTP service. Developed by amotivv, inc. (creators of Memory Box), this TypeScript implementation provides a single tool for sending emails with support for multiple recipients, CC/BCC functionality, and both plain text and HTML content. The server requires Protonmail SMTP credentials configured as environment variables and includes comprehensive error handling and logging capabilities, making it particularly valuable for workflows where AI assistants need to communicate via email without leaving the conversation interface.', '@amotivv', 'development', 'Unknown', 34, 'https://github.com/amotivv/protonmail-mcp', NULL, 0, 'https://github.com/amotivv.png?size=128', '2026-03-09T05:21:01.906522+00:00'),
  ('amplitude', 'Amplitude', 'The Amplitude MCP server enables teams to analyze product data, experiments, and user behavior through conversational AI by providing direct access to Amplitude analytics, dashboards, experiments, and feature flags via natural language queries. Built as a remote server supporting OAuth authentication, it offers 20+ tools covering comprehensive analytics operations including chart querying, experiment analysis, cohort management, session replay search, and content discovery across dashboards and notebooks. The implementation maintains existing Amplitude user permissions and access controls while enabling AI-powered data analysis workflows, making it particularly useful for product teams who want to quickly explore metrics, analyze A/B test results, and investigate user behavior patterns without navigating the Amplitude interface directly.', '@unknown', 'development', 'Unknown', 0, 'https://amplitude.com/docs/analytics/amplitude-mcp', NULL, 0, NULL, '2026-03-09T05:21:01.906555+00:00'),
  ('national-park-service', 'National Park Service', 'This MCP implementation, developed by A. Satterlee, integrates with the National Park Service API to provide access to park information and services. Built with TypeScript and utilizing the Model Context Protocol SDK, it offers a command-line interface for interacting with NPS data. The implementation focuses on delivering structured park information, potentially including details on locations, amenities, and activities. It''s particularly useful for applications requiring up-to-date national park data, enabling use cases such as trip planning, park exploration, and environmental research without complex API integrations.', '@amysatterlee', 'development', 'Unknown', 3, 'https://github.com/amysatterlee/nps_mcp', NULL, 0, 'https://github.com/amysatterlee.png?size=128', '2026-03-09T05:21:01.906583+00:00'),
  ('cursor-mcp-installer', 'Cursor MCP Installer', 'A cursor-mcp-installer is a utility server that enables the installation of other MCP servers for the Cursor editor. It provides two main tools: one for installing MCP servers from npm or Python packages via npx/uvx, and another for installing servers from local code repositories. The server handles the configuration by updating Cursor''s mcp.json file with the appropriate command, arguments, and environment variables. Written by Ani Betts, it serves as a bridge to simplify the process of adding new MCP capabilities to Cursor without requiring users to manually edit configuration files.', '@gnayiak', 'development', 'Unknown', 4, 'https://github.com/gnayiak/cursor-mcp-installer', NULL, 0, 'https://github.com/gnayiak.png?size=128', '2026-03-09T05:21:01.906610+00:00'),
  ('mcp-installer', 'MCP Installer', 'MCP-Installer is a specialized server that simplifies the installation of other MCP servers. Developed by Ani Betts, it allows Claude to install MCP servers hosted in npm or PyPi packages through natural language commands. The implementation supports both remote package installations via npx/uvx and local repository setups, handling environment variable configuration and command-line arguments. It automatically updates the Claude Desktop configuration file, making it particularly valuable for users who want to quickly expand their AI assistant''s capabilities without manually editing configuration files or remembering complex installation commands.', '@zncou', 'ai-ml', 'Unknown', 1, 'https://github.com/zncou/mcp-installer', NULL, 0, 'https://github.com/zncou.png?size=128', '2026-03-09T05:21:01.906655+00:00'),
  ('youtube', 'YouTube', 'This YouTube MCP server, developed by Anais Betts, enables AI assistants to interact with YouTube video content through subtitles. It leverages yt-dlp to download video subtitles and exposes them via a standardized MCP interface, allowing AI models to analyze and summarize video content without needing to process audio or video directly. By bridging AI systems and YouTube''s vast repository of video information, this server facilitates tasks like content summarization, information extraction, and topic analysis from video transcripts. It is particularly useful for AI assistants supporting research, content curation, or educational applications that involve YouTube videos as information sources.', '@anaisbetts', 'productivity', 'Unknown', 500, 'https://github.com/anaisbetts/mcp-youtube', '@anaisbetts/mcp-youtube', 24896, 'https://github.com/anaisbetts.png?size=128', '2026-03-09T05:21:01.906740+00:00'),
  ('binance', 'Binance', 'Binance MCP Server by AnalyticAce provides AI agents with direct access to Binance cryptocurrency exchange operations through 17 specialized tools covering market data, account management, trading, and transaction history. Built with FastMCP and the python-binance library, it implements comprehensive input validation, rate limiting, and security best practices while supporting both testnet and production environments. The server enables automated trading workflows, portfolio monitoring, risk management, and market analysis through tools like real-time price feeds, order placement, balance tracking, futures position monitoring, and deposit/withdrawal history, making it valuable for building crypto trading bots, portfolio management systems, and financial analysis applications.', '@analyticace', 'development', 'Unknown', 41, 'https://github.com/analyticace/binance-mcp-server', 'binance-mcp-server', 8734, 'https://github.com/analyticace.png?size=128', '2026-03-09T05:21:01.906770+00:00'),
  ('arbor', 'Arbor', 'Arbor builds a complete dependency graph of codebases, creating nodes for every function and class with edges representing calls and dependencies. It provides ArborQL queries for AI agents to find call paths between components, analyze impact radius of changes, and get precise context. Supports Rust, TypeScript, JavaScript, Python, Go, Java, C, C++, C#, and Dart through Tree-sitter parsing.', '@anandb71', 'development', 'Unknown', 92, 'https://github.com/anandb71/arbor', NULL, 0, 'https://github.com/anandb71.png?size=128', '2026-03-09T05:21:01.906790+00:00'),
  ('copy-paste-line-extractor', 'Copy-Paste Line Extractor', 'Copy-Paste MCP is a simple tool server that extracts specific line ranges from text content while preserving exact formatting and newlines. Implemented in TypeScript using the Model Context Protocol SDK, it exposes a single ''extract-lines'' tool that accepts text content along with start and end line parameters, making it particularly useful for working with code snippets, documentation sections, or any scenario requiring precise content extraction without modifications. The server runs via stdio transport, enabling easy integration with MCP clients like Claude Desktop or VS Code.', '@ananddtyagi', 'development', 'Unknown', 9, 'https://github.com/ananddtyagi/copy-paste-mcp', NULL, 0, 'https://github.com/ananddtyagi.png?size=128', '2026-03-09T05:21:01.906816+00:00'),
  ('webpage-screenshot', 'Webpage Screenshot', 'Webpage Screenshot MCP server enables AI assistants to capture visual screenshots of web pages using Puppeteer, with specialized support for authenticated workflows and multi-step interactions. Developed by Anand Tyagi, it provides tools for full-page and element-specific screenshots, manual login sessions with cookie persistence, and browser session management across multiple screenshot operations. The implementation supports both headless automation and visible browser modes, can integrate with system default browsers for natural user interactions, and handles authentication flows by allowing manual login followed by automated screenshot capture using saved cookies, making it ideal for monitoring protected web applications, visual verification of development progress, and automated testing workflows that require human authentication steps.', '@ananddtyagi', 'development', 'Unknown', 51, 'https://github.com/ananddtyagi/webpage-screenshot-mcp', NULL, 0, 'https://github.com/ananddtyagi.png?size=128', '2026-03-09T05:21:01.906849+00:00'),
  ('instagram', 'Instagram', 'Instagram MCP Server provides comprehensive Instagram integration capabilities for AI assistants, enabling authentication with two-factor support, content discovery through user profiles, timelines, stories, and detailed post information, search functionality for accounts and explore content, and engagement actions including liking posts and comments, adding replies, and following users. Built with TypeScript, the implementation uses unofficial Instagram API access methods and includes tools for viewing home feeds from followed accounts, retrieving post details and comments, and performing various social media interactions. Designed for social media management workflows, content research, and automated Instagram operations within AI-assisted environments, though users should note the unofficial API usage and potential account restrictions.', '@anand-kamble', 'development', 'Unknown', 1, 'https://github.com/anand-kamble/mcp-instagram', NULL, 0, 'https://github.com/anand-kamble.png?size=128', '2026-03-09T05:21:01.906896+00:00'),
  ('semantic-frame', 'Semantic Frame', 'Converts raw numerical data from NumPy, Pandas, and Polars arrays into natural language descriptions optimized for LLM consumption. Performs trend detection, volatility analysis, anomaly detection, seasonality assessment, and data quality checks. Achieves 95%+ token reduction by replacing thousands of data points with concise semantic summaries. Includes specialized trading module for financial applications.', '@anarkitty1', 'ai-ml', 'Unknown', 1, 'https://github.com/anarkitty1/semantic-frame', NULL, 0, 'https://github.com/anarkitty1.png?size=128', '2026-03-09T05:21:01.906979+00:00'),
  ('local-pm', 'Local PM', 'Self-hosted project management system featuring a Linear-like Kanban UI that integrates with MCP to provide tools for creating projects, managing tickets, assigning teams, tracking dependencies, and maintaining board state through natural language interactions. Built for local development, security, and token efficiency with Docker support.', '@anaskasmi', 'cloud', 'Unknown', 2, 'https://github.com/anaskasmi/local-pm', NULL, 0, 'https://github.com/anaskasmi.png?size=128', '2026-03-09T05:21:01.906998+00:00'),
  ('brave-search', 'Brave Search', 'Research-Llama provides a Brave Search integration through MCP, enabling AI assistants to perform both web and local business searches. The server implements rate limiting to respect Brave API constraints and offers two primary tools: web search for general information queries and local search for finding businesses, restaurants, and other physical locations with detailed information including ratings, hours, and descriptions. Built with FastMCP, it''s particularly useful for information retrieval tasks that require up-to-date web content or location-based data.', '@anath2', 'productivity', 'Unknown', 0, 'https://github.com/anath2/research-llama', NULL, 0, 'https://github.com/anath2.png?size=128', '2026-03-09T05:21:01.907038+00:00'),
  ('airflow-etl-pipeline-generator', 'Airflow ETL Pipeline Generator', 'Data Engineering Agent MCP Server provides tools for building and managing ETL pipelines in enterprise data environments. Built by Anatoliy A Aksenov, it integrates with Apache Airflow, GitLab, Kafka, PostgreSQL, S3-compatible storage, and SMB file systems to enable end-to-end data pipeline creation through conversational interfaces. The server offers connectivity testing, schema extraction, file sampling across multiple data sources, form-based pipeline configuration for database-to-datalake, file-to-datalake, and API-to-datalake workflows, plus automatic GitLab issue creation for pipeline requests with pre-built Spark application templates. Particularly valuable for data engineers and analysts who need to rapidly prototype ETL processes, validate data source connectivity, and generate production-ready Airflow DAGs without manual coding, supporting common enterprise scenarios like PostgreSQL to data lake migrations, S3 file processing, and real-time Kafka stream ingestion.', '@anatoliyaksenov', 'databases', 'Unknown', 1, 'https://github.com/anatoliyaksenov/chat-app-mcp', NULL, 0, 'https://github.com/anatoliyaksenov.png?size=128', '2026-03-09T05:21:01.907052+00:00'),
  ('n8n-workflow-automation', 'n8n Workflow Automation', 'Autonomous agent for n8n workflow automation that provides comprehensive access to n8n instances through 46 specialized tools covering workflow management, credential handling, execution monitoring, and diagnostics. Features a modular architecture with specialized sub-agents for workflow planning, optimization, and debugging, plus access to 4343+ workflow templates.', '@anatolykoptev', 'development', 'Unknown', 0, 'https://github.com/anatolykoptev/n8n-mcp-agent', NULL, 0, 'https://github.com/anatolykoptev.png?size=128', '2026-03-09T05:21:01.907077+00:00'),
  ('ibex-35', 'IBEX 35', 'IBEX 35 MCP server by Alessandro Nurnberg that provides AI assistants with comprehensive access to Spanish stock market data, corporate governance information, and financial analytics for all companies in the IBEX 35 index. Built with TypeScript and the Model Context Protocol SDK, it connects to a Cloudflare Worker API to deliver real-time market data, historical prices, board director networks, shareholder positions, EU lobbying activities, news sentiment analysis, and advanced analytics including network analysis and investment risk assessment. The implementation offers both basic data retrieval tools and sophisticated analytical capabilities like natural language query processing, company comparisons, trend analysis, and investment opportunity screening, making it particularly valuable for financial analysts, researchers, and AI systems working with Spanish market data and corporate governance analysis.', '@anbrme', 'cloud', 'Unknown', 0, 'https://github.com/anbrme/ibex35-mcp-server', NULL, 0, 'https://github.com/anbrme.png?size=128', '2026-03-09T05:21:01.907102+00:00'),
  ('aemet-spain-s-meteorological-agency', 'AEMET (Spain''s Meteorological Agency)', 'AEMET-MCP provides direct access to Spain''s State Meteorological Agency (AEMET) data through a server implementation that exposes tools for querying historical climate data, monthly summaries, and beach conditions across Spain. Built with Python and requiring an API key from AEMET''s open data portal, this implementation handles secure API authentication and includes supporting data files for beach codes. The server is designed for integration with Claude AI and other MCP-compatible clients, making it valuable for weather analysis, historical climate research, and accessing real-time meteorological information from Spanish weather stations.', '@ancode666', 'development', 'Unknown', 2, 'https://github.com/ancode666/aemet-mcp', 'aemet_mcp', 0, 'https://github.com/ancode666.png?size=128', '2026-03-09T05:21:01.907132+00:00'),
  ('nasa-api', 'NASA API', 'NASA-MCP provides a comprehensive interface to NASA''s APIs through the Model Context Protocol, enabling AI assistants to access astronomical data, space weather information, Earth imagery, and more. The implementation includes tools for querying the Astronomy Picture of the Day (APOD), Near Earth Objects, DONKI space weather database, Earth imagery from Landsat 8, EPIC camera images, and exoplanet data. Built with Python and the FastMCP framework, it features secure API key handling, robust error management, and detailed response formatting for all NASA data endpoints, making it particularly valuable for educational contexts, space research, and Earth observation applications without requiring technical knowledge of NASA''s API structure.', '@ancode666', 'databases', 'Unknown', 6, 'https://github.com/ancode666/nasa-mcp', 'nasa-mcp', 1053, 'https://github.com/ancode666.png?size=128', '2026-03-09T05:21:01.907144+00:00'),
  ('pdf-manipulation', 'PDF Manipulation', 'A PDF manipulation server built by André Medeiros that provides comprehensive PDF processing capabilities through PyMuPDF, including text operations (adding, replacing, extracting), page manipulation (cropping, rotating, merging, splitting), image handling, form field management, annotation support, and metadata editing. The server features intelligent auto-cropping that detects content boundaries to remove blank margins, supports multiple coordinate systems for precise positioning, and generates timestamped output files to preserve originals. With over 20 specialized tools covering everything from basic text insertion to complex page combining layouts, it''s designed for document automation workflows, PDF processing pipelines, and AI-assisted document editing tasks.', '@andr3medeiros', 'productivity', 'Unknown', 5, 'https://github.com/andr3medeiros/pdf-manipulation-mcp-server', 'pdf-manipulation-mcp-server', 1776, 'https://github.com/andr3medeiros.png?size=128', '2026-03-09T05:21:01.907202+00:00'),
  ('dokploy', 'Dokploy', 'Dokploy MCP is a TypeScript-based server implementation that provides AI assistants with access to the Dokploy platform API for managing deployment projects. Developed by Henrique Andrade, it exposes tools for creating, updating, duplicating, and removing projects, as well as retrieving application information through a standardized interface. The server runs via stdio communication using the Model Context Protocol SDK, authenticates with the Dokploy API using environment variables for URL and auth token, and can be deployed as a Node.js application or Docker container. This implementation is particularly useful for teams wanting to automate deployment workflows or manage their Dokploy projects directly through AI assistant interactions.', '@andradehenrique', 'cloud', 'Unknown', 17, 'https://github.com/andradehenrique/dokploy-mcp', '@ahdev/dokploy-mcp', 10604, 'https://github.com/andradehenrique.png?size=128', '2026-03-09T05:21:01.907227+00:00'),
  ('vulnicheck', 'VulniCheck', 'Provides comprehensive security analysis for Python projects and GitHub repositories. Scans dependencies using OSV, NVD, and GitHub Advisory databases, detects exposed secrets, analyzes Dockerfiles for vulnerable packages, and validates MCP security configurations. Features AI-powered risk assessment, smart caching, and automatic space management.', '@andrasfe', 'databases', 'Unknown', 9, 'https://github.com/andrasfe/vulnicheck', NULL, 0, 'https://github.com/andrasfe.png?size=128', '2026-03-09T05:21:01.907240+00:00'),
  ('expense-tracker', 'Expense Tracker', 'Expense Tracker provides personal finance logging through natural language input. Users describe expenses in free-form text (e.g., "I spent 20 dollars on lunch yesterday"), and the server extracts structured data including amount, currency, and date using regex patterns and the dateparser library. Transactions are stored locally in an Excel workbook via openpyxl, with support for multiple currency symbols and flexible date expressions.', '@andreajrubino', 'file-systems', 'Unknown', 1, 'https://github.com/andreajrubino/expense-tracker-mcp', NULL, 0, 'https://github.com/andreajrubino.png?size=128', '2026-03-09T05:21:01.907287+00:00'),
  ('grigori', 'Grigori', 'Grigori is a semantic code search MCP server that enables AI assistants to search through codebases using natural language queries and semantic similarity rather than just text matching. Built in C# with ONNX Runtime for local embedding generation, it indexes code files across multiple programming languages and provides both CLI and containerized deployment options. The server uses the all-MiniLM-L6-v2 model for embeddings and supports multiple transport modes including stdio and HTTP.', '@andres-m-rodriguez', 'development', 'Unknown', 3, 'https://github.com/andres-m-rodriguez/grigori', NULL, 0, 'https://github.com/andres-m-rodriguez.png?size=128', '2026-03-09T05:21:01.907348+00:00'),
  ('command-line', 'Command Line', 'This MCP server allows AI assistants to execute common Unix/macOS terminal commands through a controlled and secure interface. It supports the top ~40 most used terminal commands with appropriate security measures.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('b-r-automation-studio', 'B&R Automation Studio', 'Bridges B&R Automation Studio industrial control systems with development tools for building projects, launching ARsim simulators, and reading/writing OPC UA variables for real-time system interaction and monitoring.', '@andrewmusser', 'development', 'Unknown', 7, 'https://github.com/andrewmusser/br-automation-mcp', NULL, 0, 'https://github.com/andrewmusser.png?size=128', '2026-03-09T05:21:01.907513+00:00'),
  ('sidekiq', 'Sidekiq', 'Sidekiq MCP server that enables AI assistants to monitor, manage, and troubleshoot Sidekiq background job queues through a comprehensive set of tools for statistics, job inspection, and queue operations. Built by Andrew Nesbitt, the implementation provides 20+ tools including real-time monitoring with Server-Sent Events, job retry/deletion/rescheduling capabilities, queue health analysis, and worker utilization tracking, with automatic Rails integration via Railtie and flexible authentication supporting both Bearer tokens and HTTP Basic Auth. Designed for developers and operations teams who need conversational access to Sidekiq infrastructure without manual dashboard navigation, enabling natural language job queue management, failure investigation, and performance optimization workflows.', '@andrew', 'ai-ml', 'Unknown', 9, 'https://github.com/andrew/sidekiq-mcp', NULL, 0, 'https://github.com/andrew.png?size=128', '2026-03-09T05:21:01.907567+00:00'),
  ('android-automation', 'Android Automation', 'This MCP server provides direct automation and control of Android devices through the uiautomator2 library, enabling AI assistants to interact with mobile applications like a human user. Built by JEOMON GEORGE, it offers tools for clicking, long-clicking, swiping, typing, dragging, and pressing device buttons, along with state inspection that identifies interactive UI elements with their coordinates and labels. The implementation connects to physical Android devices or emulators via ADB, extracts the UI hierarchy to find clickable elements, and provides coordinate-based interaction capabilities, making it valuable for mobile app testing, automation workflows, and AI assistants that need to operate Android applications directly.', '@cursortouch', 'development', 'Unknown', 438, 'https://github.com/cursortouch/android-mcp', NULL, 0, 'https://github.com/cursortouch.png?size=128', '2026-03-09T05:21:01.907596+00:00'),
  ('io-github-geter-andru-andru-intelligence', 'io.github.geter-andru/andru-intelligence', 'Revenue intelligence for SaaS founders: ICP scoring, persona profiling, competitive positioning.', '@geter-andru', 'development', 'Unknown', 1, 'https://github.com/geter-andru/mcp-server-andru-intelligence', NULL, 0, 'https://github.com/geter-andru.png?size=128', '2026-03-09T05:21:01.907613+00:00'),
  ('arxiv-research', 'arXiv Research', 'This MCP server, developed by Andy Brandt, provides AI assistants like Claude with access to arXiv''s scientific paper repository. It offers tools for searching papers by title and abstract, retrieving metadata and abstracts, and accessing links to available formats. The server implements proper rate limiting according to arXiv''s API guidelines. By bridging AI capabilities with arXiv''s vast collection of research papers, this implementation enables AI-assisted literature reviews and scientific research. It integrates seamlessly with Claude Desktop on both macOS and Windows, facilitating natural language interactions for exploring and analyzing scientific publications. The server is particularly useful for scenarios requiring up-to-date information on scientific topics, conducting comprehensive literature searches, or generating insights from academic papers in AI-assisted research and writing tasks.', '@andybrandt', 'productivity', 'Unknown', 181, 'https://github.com/andybrandt/mcp-simple-arxiv', 'mcp-simple-arxiv', 79987, 'https://github.com/andybrandt.png?size=128', '2026-03-09T05:21:01.907662+00:00'),
  ('simple-openai-assistant', 'Simple OpenAI Assistant', 'This MCP server, developed by Andy Brandt, enables AI assistants like Claude to interact with OpenAI''s GPT models through a simple interface. It provides tools for creating and managing OpenAI assistants, starting conversation threads, and exchanging messages. The server integrates seamlessly with Claude Desktop on both macOS and Windows, bridging the capabilities of different AI platforms. By allowing Claude to leverage OpenAI''s specialized GPT models, this implementation expands the knowledge and skills available to the AI assistant. It is particularly useful for scenarios requiring access to OpenAI''s latest models, collaborative AI interactions, or specialized task delegation in AI-powered applications.', '@andybrandt', 'development', 'Unknown', 37, 'https://github.com/andybrandt/mcp-simple-openai-assistant', 'mcp-simple-openai-assistant', 7469, 'https://github.com/andybrandt.png?size=128', '2026-03-09T05:21:01.907691+00:00'),
  ('simple-pubmed', 'Simple PubMed', 'This MCP server, developed by Andy Brandt, provides a bridge between large language models and the PubMed medical research database via the Entrez API. Built in Python, it enables AI assistants to search PubMed, access article abstracts, and potentially retrieve full-text content for open access papers. The implementation focuses on simplicity and ease of integration with Claude Desktop, offering a straightforward interface for querying biomedical literature. By connecting AI models with PubMed''s vast repository of scientific articles, this server allows AI systems to access up-to-date medical research, analyze trends in healthcare, and provide evidence-based insights. It is particularly useful for scenarios like literature reviews, staying current on medical advancements, and building AI assistants that can leverage peer-reviewed scientific knowledge in the biomedical domain.', '@andybrandt', 'databases', 'Unknown', 159, 'https://github.com/andybrandt/mcp-simple-pubmed', 'mcp-simple-pubmed', 11783, 'https://github.com/andybrandt.png?size=128', '2026-03-09T05:21:01.907703+00:00'),
  ('simple-timeserver', 'Simple Timeserver', 'This MCP server, developed by Andy Brandt, provides AI assistants like Claude with the ability to access current time information. It offers two key tools: get_time for retrieving local time and timezone data from the user''s machine, and get_utc for obtaining UTC time from an NTP server. By bridging AI capabilities with accurate timekeeping, this implementation enables time-aware interactions and calculations. The server is designed for easy integration with the Claude desktop app on both macOS and Windows. It addresses the limitation of AI models lacking inherent time awareness, making it useful for scenarios requiring temporal context, scheduling assistance, or time-based computations in AI-powered conversations and tasks.', '@andybrandt', 'productivity', 'Unknown', 27, 'https://github.com/andybrandt/mcp-simple-timeserver', 'mcp-simple-timeserver', 12273, 'https://github.com/andybrandt.png?size=128', '2026-03-09T05:21:01.907745+00:00'),
  ('flowise', 'Flowise', 'MCP-Flowise provides a bridge between Claude Desktop and Flowise API, enabling AI assistants to interact with Flowise chatflows and assistants. Developed by Matthew Hand, it offers two operation modes: LowLevel Mode dynamically registers tools for each chatflow retrieved from the Flowise API, while FastMCP Mode provides simpler static tools for listing chatflows and creating predictions. The implementation supports filtering chatflows via whitelists and blacklists, integrates seamlessly with Claude Desktop through Smithery, and is particularly valuable for users who want to leverage their existing Flowise workflows directly within AI assistant conversations.', '@andydukes', 'communication', 'Unknown', 0, 'https://github.com/andydukes/mcp-flowise', NULL, 0, 'https://github.com/andydukes.png?size=128', '2026-03-09T05:21:01.907782+00:00'),
  ('quantum', 'Quantum', 'Provides GPU-accelerated quantum mechanical simulations including time-dependent Schrodinger equation solving, wavepacket creation and evolution, potential energy landscape generation, and wavefunction analysis. Supports 1D and 2D simulations with split-step Fourier methods and optional CUDA acceleration for significant performance improvements.', '@andylbrummer', 'development', 'Unknown', 1, 'https://github.com/andylbrummer/math-mcp/tree/HEAD/servers/quantum-mcp', NULL, 0, 'https://github.com/andylbrummer.png?size=128', '2026-03-09T05:21:01.907862+00:00'),
  ('replicate-flux', 'Replicate Flux', 'MCP Replicate Flux provides a bridge to Replicate''s AI image generation models, enabling Claude to create images from text prompts. The implementation uses Node.js to handle the communication between Claude and Replicate''s API, and automatically uploads generated images to cloud storage (Cloudflare R2) for easy access. Built with the Model Context Protocol SDK, it exposes a single tool for image generation that accepts a prompt and filename parameter, returning both a confirmation message and the URL to the stored image. This server is particularly useful for creative workflows where visual content generation enhances the conversation experience.', '@andylee20014', 'cloud', 'Unknown', 11, 'https://github.com/andylee20014/mcp-replicate-flux', NULL, 0, 'https://github.com/andylee20014.png?size=128', '2026-03-09T05:21:01.907884+00:00'),
  ('puppeteer', 'Puppeteer', 'Provides browser automation capabilities through Puppeteer, enabling web page interaction, content extraction, screenshot capture, PDF generation, and JavaScript evaluation for web scraping, automated testing, and form filling workflows.', '@andytango', 'development', 'Unknown', 1, 'https://github.com/andytango/puppeteer-mcp', NULL, 0, 'https://github.com/andytango.png?size=128', '2026-03-09T05:21:01.907931+00:00'),
  ('harvestr', 'Harvestr', 'Integrates with Harvestr.io product management platform to manage customer feedback, discoveries, and product components. Supports creating and managing companies, tracking feature requests and bugs, handling feedback linked to discoveries and messages, and updating custom attributes across the platform.', '@angelogiacco', 'aggregators', 'Unknown', 1, 'https://github.com/angelogiacco/harvestr-mcp', NULL, 0, 'https://github.com/angelogiacco.png?size=128', '2026-03-09T05:21:01.907984+00:00'),
  ('new-york-times', 'New York Times', 'This New York Times article search MCP server, developed by angheljf, provides an interface for language models to retrieve recent news articles based on keywords. It integrates with the NYTimes API to search articles from the last 30 days, returning key details like title, abstract, URL, date, and author. Built in TypeScript, it demonstrates core MCP concepts while focusing on a specific use case. The server handles API authentication and request formatting. This implementation is particularly useful for AI assistants needing to access current news and trending topics, conduct research on recent events, or provide summaries of latest developments in specific areas.', '@angheljf', 'development', 'Unknown', 17, 'https://github.com/angheljf/nyt', NULL, 0, 'https://github.com/angheljf.png?size=128', '2026-03-09T05:21:01.908011+00:00'),
  ('selenium', 'Selenium', 'Navigate to URLs
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('gibber', 'Gibber', 'This MCP server implementation provides cryptographic tools for secure communication, including key pair generation, shared secret derivation, and message encryption/decryption using SJCL P-256 and AES-CCM. Built with Express.js and TypeScript, it offers real-time communication via server-sent events (SSE). The server is designed for applications requiring end-to-end encryption and secure data exchange between AI models and external tools.', '@antonpk1', 'development', 'Unknown', 211, 'https://github.com/antonpk1/gibber-mcp', NULL, 0, 'https://github.com/antonpk1.png?size=128', '2026-03-09T05:21:01.909210+00:00'),
  ('brianknows', 'BrianKnows', 'This MCP server implementation provides a bridge to the BrianKnows knowledge base API, enabling AI assistants to perform searches and interact with an agent for information retrieval. Developed by antoncoding, it offers tools for querying the BrianKnows database and leveraging its AI agent capabilities. The server is designed for use cases requiring access to specialized knowledge, such as answering domain-specific questions or providing expert-level information on topics covered by the BrianKnows database.', '@antoncoding', 'databases', 'Unknown', 0, 'https://github.com/antoncoding/mcp-brianknows', NULL, 0, 'https://github.com/antoncoding.png?size=128', '2026-03-09T05:21:01.909221+00:00'),
  ('auralis-commander', 'Auralis Commander', 'Auralis Commander is a lightweight Windows-native MCP server built as an alternative to Desktop Commander, providing essential system operations through PowerShell and native Windows APIs. The implementation offers shell command execution with configurable shells (PowerShell, pwsh, cmd), comprehensive file operations (read, write, delete, move, edit), directory management, file and content search with ripgrep integration and PowerShell fallback, process management (list, kill), system information retrieval (CPU, memory, disk usage), and interactive process sessions for long-running commands. Designed specifically for Windows environments, it emphasizes reliability through structured error handling, configurable timeouts, and automatic cleanup of resources.', '@antonpme', 'search', 'Unknown', 3, 'https://github.com/antonpme/auralis-commander', NULL, 0, 'https://github.com/antonpme.png?size=128', '2026-03-09T05:21:01.909290+00:00'),
  ('documentation-search', 'Documentation Search', 'This documentation search MCP server by Anton Mishel provides AI assistants with direct access to technical documentation across 40+ popular frameworks, libraries, and platforms including Python, React, FastAPI, AWS, OpenAI, and more. The implementation features intelligent caching with configurable TTL, categorized documentation sources with metadata like learning curves and tags, and HTTP-based content retrieval optimized for AI consumption. Built for developers who need quick access to official documentation during coding workflows, it eliminates the need to manually search through multiple documentation sites by providing a unified interface for retrieving relevant technical information across the modern development stack.', '@gemini2026', 'cloud', 'Unknown', 8, 'https://github.com/gemini2026/documentation-search-mcp', NULL, 0, 'https://github.com/gemini2026.png?size=128', '2026-03-09T05:21:01.909329+00:00'),
  ('mcp-all', 'MCP All', 'A Swiss-knife MCP server that enables AI agents to dynamically discover and configure Model Context Protocol servers. Provides tools to search the MCP registry, add or remove server configurations, and expose tools from any added servers. Supports both stdio and streamable-http transports for flexible deployment.', '@antonytm', 'ai-ml', 'Unknown', 1, 'https://github.com/antonytm/mcp-all', NULL, 0, 'https://github.com/antonytm.png?size=128', '2026-03-09T05:21:01.909359+00:00'),
  ('sitecore', 'Sitecore', 'Provides comprehensive tools for managing Sitecore CMS through MCP. Supports GraphQL queries, Item Service CRUD operations, PowerShell script execution, security management (users, roles, ACLs), content presentation, search indexing, publishing workflows, and administrative tasks. Available as npm package and Docker images for Linux and Windows.', '@antonytm', 'cloud', 'Unknown', 39, 'https://github.com/antonytm/mcp-sitecore-server', NULL, 0, 'https://github.com/antonytm.png?size=128', '2026-03-09T05:21:01.909376+00:00'),
  ('antv-chart-generator', 'AntV Chart Generator', '@antv/mcp-server-chart is a TypeScript-based server that enables AI assistants to generate data visualizations using AntV''s charting capabilities. Developed by the AntV Visualization Team, it implements the Model Context Protocol to provide a standardized interface for creating various chart types from data. The server exposes chart generation functionality that can be accessed through MCP tools, making it particularly valuable for applications that need to produce visual data representations through conversational interfaces without requiring direct knowledge of visualization libraries.', '@antvis', 'development', 'Unknown', 3769, 'https://github.com/antvis/mcp-server-chart', '@antv/mcp-server-chart', 301663, 'https://github.com/antvis.png?size=128', '2026-03-09T05:21:01.909406+00:00'),
  ('antv-visualization-libraries', 'AntV Visualization Libraries', 'This MCP server provides AI assistants with access to AntV''s visualization ecosystem through intelligent documentation retrieval and context-aware assistance for g2, g6, l7, x6, f2, and s2 libraries. Built by the AntV team using TypeScript with Zod validation and the Context7 API, it features two complementary tools: extract_antv_topic for preprocessing user queries to identify relevant libraries and extract technical topics, and query_antv_document for fetching official documentation, code examples, and best practices with support for complex task decomposition into subtasks. The implementation enforces mandatory tool usage for any AntV-related query regardless of complexity, includes comprehensive error handling and logging, and integrates with Context7''s documentation service to provide up-to-date technical guidance, making it valuable for developers building data visualizations, troubleshooting AntV implementations, and learning visualization best practices through AI-assisted workflows.', '@antvis', 'development', 'Unknown', 36, 'https://github.com/antvis/mcp-server-antv', '@antv/mcp-server-antv', 2194, 'https://github.com/antvis.png?size=128', '2026-03-09T05:21:01.909444+00:00'),
  ('multi-agent-deep-researcher', 'Multi-Agent Deep Researcher', 'Multi-agent research system that orchestrates three specialized AI agents (web searcher, research analyst, and technical writer) using CrewAI for comprehensive information gathering and synthesis. Integrates LinkUp API for web search capabilities and Ollama for local LLM processing, providing both quick search functionality and full research workflows that combine web data retrieval, analysis, and structured report generation. Built with FastAPI for HTTP access, includes a web frontend, and supports both Poetry and pip installation for automated research tasks and AI-assisted information analysis workflows.', '@anubhav-77-dev', 'productivity', 'Unknown', 1, 'https://github.com/anubhav-77-dev/mcp-multi-agent-deep-researcher', NULL, 0, 'https://github.com/anubhav-77-dev.png?size=128', '2026-03-09T05:21:01.909489+00:00'),
  ('arxiv', 'arXiv', 'A Python-based MCP server implementation that provides comprehensive access to arXiv''s academic paper repository through a rich set of tools for searching, analyzing, and managing research papers. Built with asyncio and httpx for efficient API interactions, it offers advanced features including author and category-based searches, trend analysis, citation estimation, related paper discovery, and multi-format export capabilities (BibTeX, JSON, CSV, Markdown). The implementation includes sophisticated analyzers for research trends, keyword frequency analysis, and paper comparison tools, making it valuable for researchers, academics, and AI assistants who need to explore scientific literature, track research developments, or compile bibliographies without manually navigating arXiv''s interface.', '@anuj0456', 'development', 'Unknown', 17, 'https://github.com/anuj0456/arxiv-mcp-server', NULL, 0, 'https://github.com/anuj0456.png?size=128', '2026-03-09T05:21:01.909519+00:00'),
  ('multi-document-rag', 'Multi-Document RAG', 'MCP-RAG is a server implementation that enables large file processing and retrieval-augmented generation capabilities for AI assistants. Developed by Anurag Bombarde, it provides tools for extracting content from various document formats (PDF, DOCX, PPTX, Excel, CSV, and images) with OCR support, creating vector embeddings using OpenAI or SentenceTransformer models, and performing semantic searches across document collections. The implementation features robust handling of large files through chunking strategies, multi-vector store support with ChromaDB and Milvus integration, and comprehensive document processing with enhanced OCR capabilities for scanned documents and images.', '@anuragb7', 'ai-ml', 'Unknown', 9, 'https://github.com/anuragb7/mcp-rag', NULL, 0, 'https://github.com/anuragb7.png?size=128', '2026-03-09T05:21:01.909568+00:00'),
  ('newsdata', 'Newsdata', 'This MCP server fetches latest news and sources based on country and language using newsdata.io. You need to provide your own API key.', '@anurag-dhamala', 'development', 'Unknown', 3, 'https://github.com/anurag-dhamala/news-mcp-server', 'news-mcp-server', 5230, 'https://github.com/anurag-dhamala.png?size=128', '2026-03-09T05:21:01.909585+00:00'),
  ('os-info', 'OS Info', 'OS Info MCP Server provides real-time system information about the host computer, including CPU, memory, operating system, disk, battery, processes, and CPU load details. Developed by Devnical, this TypeScript implementation uses the systeminformation library to gather comprehensive hardware and software metrics, making it valuable for monitoring system resources, troubleshooting performance issues, or integrating system diagnostics into AI assistant workflows. The server can be deployed either by cloning the repository or using npx, with a simple configuration that enables AI assistants to respond to natural language queries about the host system''s specifications and current state.', '@anurag-dhamala', 'development', 'Unknown', 1, 'https://github.com/anurag-dhamala/os-info-mcp-server', 'os-info-mcp-server', 3715, 'https://github.com/anurag-dhamala.png?size=128', '2026-03-09T05:21:01.909616+00:00'),
  ('database-bulk-update', 'Database Bulk Update', 'This database-updater MCP server, developed by an unnamed author, provides a streamlined interface for updating databases from CSV and Excel files. Built with TypeScript and leveraging libraries like csv-parser and xlsx, it offers tools for connecting to various database types including PostgreSQL, MySQL, MongoDB, and SQLite. The implementation focuses on configurable connection settings and table mapping, making it accessible for AI assistants or applications needing to perform bulk data updates. It''s particularly useful for tasks like data migration, automated reporting, or synchronizing databases with external data sources, enabling efficient database management without requiring deep knowledge of individual database APIs or file parsing complexities.', '@anuragrai017', 'databases', 'Unknown', 1, 'https://github.com/anuragrai017/database-updater-mcp-server', NULL, 0, 'https://github.com/anuragrai017.png?size=128', '2026-03-09T05:21:01.909627+00:00'),
  ('python-docs', 'Python Docs', 'This Python documentation MCP server, developed by an unnamed author, provides a tool for fetching Python documentation using the Brave Search API. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers a streamlined interface for querying Python-related information. The implementation focuses on simplicity, offering a single ''get_python_docs'' function that takes a search query and returns relevant documentation links. It''s particularly useful for AI assistants or applications needing quick access to Python documentation, enabling tasks like code explanation, function lookup, or general Python language queries without requiring direct web scraping or complex API integrations.', '@anuragrai017', 'development', 'Unknown', 0, 'https://github.com/anuragrai017/python-docs-server-mcp-server', NULL, 0, 'https://github.com/anuragrai017.png?size=128', '2026-03-09T05:21:01.909652+00:00'),
  ('memrl', 'MemRL', 'A memory-augmented reinforcement learning system for Claude Code that captures coding sessions as episodes and learns from experience to improve future task assistance. Built in Rust, it automatically captures session transcripts, extracts structured intent using LLM analysis, and stores episodes with git diffs and error resolutions in both file-based storage and vector databases using LanceDB and FastEmbed. The system implements Bellman equation-based utility propagation to spread value from helpful episodes to similar ones, uses temporal credit assignment to reward episodes that preceded successful outcomes, and provides semantic search through embeddings to retrieve relevant past experiences.', '@anvanster', 'databases', 'Unknown', 4, 'https://github.com/anvanster/tempera', NULL, 0, 'https://github.com/anvanster.png?size=128', '2026-03-09T05:21:01.909663+00:00'),
  ('youtube-uploader', 'YouTube Uploader', 'YouTube Uploader MCP server built in Go that provides OAuth2-authenticated video uploading capabilities to YouTube channels through a comprehensive set of tools including authentication, token management, channel retrieval, and video upload functionality. The implementation handles the complete OAuth2 flow, automatically manages token refresh for expired credentials, and supports full video metadata configuration including titles, descriptions, tags, categories, and privacy settings. Designed for content creators and automation workflows who need programmatic YouTube upload capabilities without manual interface interaction, with persistent channel credential storage and robust error handling for production use cases.', '@anwerj', 'ai-ml', 'Unknown', 37, 'https://github.com/anwerj/youtube-uploader-mcp', NULL, 0, 'https://github.com/anwerj.png?size=128', '2026-03-09T05:21:01.909718+00:00'),
  ('anycrawl', 'AnyCrawl', 'This MCP server provides web scraping and crawling capabilities through integration with the AnyCrawl API, offering tools for single-page scraping, multi-page crawling with configurable depth and limits, and web search with optional content extraction. Built with TypeScript using FastMCP and featuring dual deployment modes (STDIO for local use and HTTP/SSE for cloud services), it supports multiple scraping engines (Cheerio, Playwright, Puppeteer), various output formats including markdown and JSON with AI-powered structured extraction, and comprehensive crawling strategies with path filtering and async job management. The implementation includes Docker deployment with Nginx proxy for API key-based routing, extensive test coverage with both mocked and real API integration tests, and robust error handling with detailed logging, making it valuable for AI assistants that need reliable web content extraction, research workflows requiring multi-page site analysis, and applications building knowledge bases from web sources.', '@any4ai', 'cloud', 'Unknown', 5, 'https://github.com/any4ai/anycrawl-mcp-server', 'anycrawl-mcp-server', 897, 'https://github.com/any4ai.png?size=128', '2026-03-09T05:21:01.909745+00:00'),
  ('thingsboard', 'ThingsBoard', 'ThingsBoard MCP Server provides a bridge between AI assistants and ThingsBoard IoT platforms, enabling access to device telemetry and attributes through a standardized interface. The server exposes tools for retrieving tenant devices, accessing historic and latest device telemetry data, and fetching device attributes. Built with Python using FastMCP and asynchronous HTTP requests, it handles authentication with JWT tokens and automatically refreshes expired credentials. This implementation is particularly valuable for IoT administrators and analysts who need to monitor device data, analyze telemetry history, or access device attributes directly through conversational AI.', '@anycontext-ai', 'development', 'Unknown', 9, 'https://github.com/anycontext-ai/thingsboard-mcp-server', NULL, 0, 'https://github.com/anycontext-ai.png?size=128', '2026-03-09T05:21:01.909774+00:00'),
  ('spec-kit', 'Spec Kit', 'Provides direct access to GitHub''s Spec Kit templates and workflows for project specification management. Integrates with the specify-cli tool to guide users through the complete specification lifecycle including constitution establishment, requirement specification, technical planning, task breakdown, and implementation guidelines. Automatically detects project commands directories and exposes prompts that correspond to Spec Kit''s structured approach to software project planning and documentation.', '@anyiba', 'development', 'Unknown', 1, 'https://github.com/anyiba/spec-kit-mcp', NULL, 0, 'https://github.com/anyiba.png?size=128', '2026-03-09T05:21:01.909797+00:00'),
  ('anytype', 'Anytype', 'This MCP server provides a universal bridge to any OpenAPI 3.0/3.1 specification, automatically converting REST API endpoints into MCP tools that AI assistants can call directly. Built by Snaggle.ai using TypeScript with comprehensive file upload support, authentication handling via environment variables, and intelligent parameter mapping that separates path, query, and body parameters, it dynamically generates tool schemas from OpenAPI specs loaded from URLs or local files. The implementation includes robust error handling with structured responses, multipart form-data support for file operations, and built-in filtering to exclude authentication and destructive operations, making it valuable for integrating any REST API into AI workflows without manual tool creation, enabling rapid prototyping with third-party services, and providing a standardized way to expose existing API infrastructure to AI assistants.', '@anyproto', 'development', 'Unknown', 322, 'https://github.com/anyproto/anytype-mcp', '@anyproto/anytype-mcp', 12647, 'https://github.com/anyproto.png?size=128', '2026-03-09T05:21:01.909833+00:00'),
  ('anysite', 'Anysite', 'HDW-MCP-Server provides a bridge between AI assistants and Horizon Data Wave''s LinkedIn API, enabling comprehensive access to LinkedIn data and functionality. The TypeScript implementation exposes tools for searching users, retrieving profiles, accessing posts and reactions, managing connections, sending messages, and interacting with companies through the Model Context Protocol. Built with the MCP SDK, it handles authentication via environment variables and includes robust error handling and logging. This server is particularly valuable for use cases requiring LinkedIn data access directly within AI assistant conversations, such as sales prospecting, recruitment research, and professional networking.', '@anysiteio', 'development', 'Unknown', 57, 'https://github.com/anysiteio/anysite-mcp-server', '@anysite/mcp', 0, 'https://github.com/anysiteio.png?size=128', '2026-03-09T05:21:01.909880+00:00'),
  ('bevy-docs-search', 'Bevy Docs Search', 'Processes Bevy game engine documentation from docs.rs, converting HTML to Markdown and embedding content into a Milvus vector database. Provides semantic search capabilities through MCP, enabling AI assistants to retrieve relevant documentation sections based on meaning rather than keyword matching. Designed for integration with AI coding assistants to provide accurate, context-aware access to Bevy framework documentation.', '@aojiaoxiaolinlin', 'databases', 'Unknown', 2, 'https://github.com/aojiaoxiaolinlin/docs_mcp', NULL, 0, 'https://github.com/aojiaoxiaolinlin.png?size=128', '2026-03-09T05:21:01.909893+00:00'),
  ('markdown-mermaid-pdf', 'Markdown Mermaid PDF', 'Converts Markdown files with embedded Mermaid diagrams into professionally formatted PDF documents. Provides three core tools: markdown-to-PDF conversion that preserves diagram rendering, standalone Mermaid diagram export to PNG, and direct Mermaid-to-PDF conversion. Built with TypeScript using Puppeteer for headless Chrome rendering, the marked library for Markdown parsing, and Mermaid.js for diagram generation. Useful for generating technical documentation with embedded flowcharts, sequence diagrams, class diagrams, and Gantt charts, or creating standalone diagram exports for presentations and reports.', '@aoprisan', 'development', 'Unknown', 3, 'https://github.com/aoprisan/mcp-md-mmd-pdf', NULL, 0, 'https://github.com/aoprisan.png?size=128', '2026-03-09T05:21:01.909923+00:00'),
  ('nuke', 'Nuke', 'Provides a bridge between AI assistants and Nuke, the professional compositing software, enabling automation of common tasks through a Python interface. The server exposes tools for creating and configuring nodes, setting knob values, retrieving node information, and executing render operations. Built with Node.js and a Python bridge script, it handles communication between the MCP protocol and Nuke''s Python API, making it valuable for visual effects artists and compositors who want to automate their Nuke workflows through natural language interaction.', '@aourpallynikhil', 'productivity', 'Unknown', 2, 'https://github.com/aourpallynikhil/nuke-mcp-2', NULL, 0, 'https://github.com/aourpallynikhil.png?size=128', '2026-03-09T05:21:01.909959+00:00'),
  ('photoroom', 'Photoroom', 'Provides a bridge to the Photoroom API for removing backgrounds from images, with support for different output formats, types, and scaling options. The server exposes a single tool for background removal that accepts image URLs and returns processed results as data URLs. Useful for automated image editing workflows that require background removal capabilities.', '@aourpallynikhil', 'media', 'Unknown', 0, 'https://github.com/aourpallynikhil/photoroom-mcp', NULL, 0, 'https://github.com/aourpallynikhil.png?size=128', '2026-03-09T05:21:01.910011+00:00'),
  ('getoutpost', 'GetOutPost', 'Integrates with GetOutPost''s API to provide real-time options data for NSE and BSE instruments. Offers tools for fetching implied volatility, realized volatility (using Yang-Zhang, Parkinson, and Garman-Klass methods), volatility risk premium, and skew patterns. Includes discovery tools for filtering symbols by percentile ranges across volatility metrics.', '@aoutpost2-rgb', 'data-analytics', 'Unknown', 3, 'https://github.com/aoutpost2-rgb/getoutpost-mcp-server', NULL, 0, 'https://github.com/aoutpost2-rgb.png?size=128', '2026-03-09T05:21:01.910066+00:00'),
  ('cutter-reverse-engineering', 'Cutter (Reverse Engineering)', 'CutterMCP provides a bridge between the Cutter reverse engineering platform and MCP clients, enabling binary analysis capabilities through a REST API. The implementation uses FastMCP to expose Cutter''s functionality including function listing, decompilation, segment analysis, and symbol management. Users can search for functions, rename them, add comments to decompiled code, and access imports and exports data. This server implementation is particularly valuable for reverse engineers who want to integrate Cutter''s binary analysis capabilities into their AI-assisted workflows.', '@ap425q', 'development', 'Unknown', 21, 'https://github.com/ap425q/cuttermcp', NULL, 0, 'https://github.com/ap425q.png?size=128', '2026-03-09T05:21:01.910094+00:00'),
  ('apache-doris', 'Apache Doris', 'The Doris MCP Server provides AI assistants with direct access to Apache Doris databases for executing SQL queries and retrieving metadata. Built by the Apache Doris team, this implementation supports multiple communication modes (SSE, Streamable HTTP, and stdio) and exposes tools for database operations including query execution, schema retrieval, and audit log access. The server is designed with flexible configuration options for database connections and includes caching mechanisms for metadata to improve performance. It''s particularly valuable for data analysts and engineers who need to interact with Doris databases through natural language interfaces without switching contexts.', '@apache', 'databases', 'Unknown', 263, 'https://github.com/apache/doris-mcp-server', NULL, 0, 'https://github.com/apache.png?size=128', '2026-03-09T05:21:01.910106+00:00'),
  ('apache-echarts', 'Apache ECharts', 'An Apache ECharts MCP server that generates data visualization charts by accepting minimal parameters from LLMs and returning cloud-hosted image URLs. Built by the Apache ECharts team, it takes a focused approach requiring only chart type, data, title, and series name rather than full ECharts configuration objects, ensuring stable and consistent results across eight supported chart types including bar, line, pie, scatter, funnel, tree, treemap, and sunburst. The server renders charts server-side using HTML5 Canvas, uploads images to Baidu Cloud Storage, and returns accessible URLs, making it valuable for creating publication-ready visualizations in AI workflows without requiring users to understand complex charting APIs.', '@apache', 'ai-ml', 'Unknown', 63, 'https://github.com/apache/echarts-mcp', NULL, 0, 'https://github.com/apache.png?size=128', '2026-03-09T05:21:01.910158+00:00'),
  ('apache-iotdb', 'Apache IoTDB', 'The IoTDB MCP Server provides a secure interface for AI assistants to interact with Apache IoTDB time-series databases. Developed by the Apache Software Foundation, this Python-based implementation enables three core database operations: executing SELECT queries, listing available tables, and describing table schemas. The server connects to IoTDB instances using a session pool for efficient connection management and returns query results in a structured text format. It''s particularly valuable for data analysts and IoT applications that need AI-assisted exploration and analysis of time-series data stored in IoTDB without requiring direct database access.', '@apache', 'databases', 'Unknown', 34, 'https://github.com/apache/iotdb-mcp-server', NULL, 0, 'https://github.com/apache.png?size=128', '2026-03-09T05:21:01.910169+00:00'),
  ('apache-sling', 'Apache Sling', 'Apache Sling MCP Server is an experimental implementation that bridges the Model Context Protocol with Apache Sling, a Java web framework built on OSGi. The server exposes Sling-specific development capabilities through MCP, including prompts for generating Sling servlets with proper annotations and troubleshooting guides for common Sling deployment issues. It features a dynamic prompt discovery system that automatically registers markdown-based prompts from the repository with YAML front matter for metadata, and provides an extensible architecture through OSGi services for adding custom tools, resources, and completions.', '@apache', 'development', 'Unknown', 1, 'https://github.com/apache/sling-org-apache-sling-mcp-server', NULL, 0, 'https://github.com/apache.png?size=128', '2026-03-09T05:21:01.910195+00:00'),
  ('kubeblocks-cloud', 'KubeBlocks Cloud', 'KB Cloud MCP Server provides AI assistants with access to KubeBlocks Cloud resources through a standardized tool interface. Developed by ApeCloud, this Go implementation enables querying organizations, environments, instances, and backups via the KB Cloud API. The server authenticates using API keys, supports internationalization, and includes comprehensive logging capabilities. It''s particularly valuable for automating database management tasks, retrieving cloud environment information, and building AI-powered tools that interact with the KubeBlocks ecosystem.', '@apecloud', 'databases', 'Unknown', 2, 'https://github.com/apecloud/kb-cloud-mcp-server', NULL, 0, 'https://github.com/apecloud.png?size=128', '2026-03-09T05:21:01.910235+00:00'),
  ('exa', 'Exa', 'An MCP server that provides AI assistants with access to Exa.ai''s search capabilities, enabling them to perform web searches with customizable parameters like result count and live crawling options. The server handles authentication with Exa''s API, processes search queries, and returns structured results as JSON, making it valuable for AI assistants that need to retrieve up-to-date information from the web without leaving the conversation context.', '@aperture147', 'ai-ml', 'Unknown', 0, 'https://github.com/aperture147/exa-mcp-worker', NULL, 0, 'https://github.com/aperture147.png?size=128', '2026-03-09T05:21:01.910273+00:00'),
  ('xmind-mind-maps', 'XMind Mind Maps', 'This MCP server, developed by apeyroux, enables AI assistants like Claude to analyze and query XMind mind maps. Built in TypeScript, it provides powerful capabilities for searching, extracting, and analyzing content across multiple XMind files. The implementation stands out by offering smart fuzzy search, hierarchical navigation, and multi-file analysis. By connecting AI capabilities with structured mind map data, this server enables AI systems to gain insights from personal or organizational knowledge bases. It is particularly useful for task management, information retrieval, and knowledge graph analysis scenarios where mind maps serve as a primary data source.', '@apeyroux', 'development', 'Unknown', 51, 'https://github.com/apeyroux/mcp-xmind', '@41px/mcp-xmind', 3420, 'https://github.com/apeyroux.png?size=128', '2026-03-09T05:21:01.910303+00:00'),
  ('apache-apisix', 'Apache APISIX', 'A plugin for Apache APISIX that implements the Model Context Protocol (MCP) server, allowing APISIX to serve as an MCP server for AI applications.', '@api7', 'ai-ml', 'Unknown', 34, 'https://github.com/api7/apisix-mcp', 'apisix-mcp', 5332, 'https://github.com/api7.png?size=128', '2026-03-09T05:21:01.910327+00:00'),
  ('apify', 'Apify', 'This MCP implementation, developed using TypeScript, provides a robust foundation for building and deploying web scraping and automation projects. It leverages the Apify platform and Crawlee library, offering a structured environment for creating scalable web crawlers and data extraction tasks. The implementation includes configuration files for ESLint, TypeScript, and Docker, ensuring code quality and consistency across different development environments. By abstracting common web scraping challenges and providing integration with Apify''s cloud infrastructure, this tool enables developers to focus on building complex data acquisition workflows. It is particularly useful for projects requiring large-scale web data extraction, automated testing of web applications, or building AI training datasets from web sources.', '@apify', 'cloud', 'Unknown', 870, 'https://github.com/apify/apify-mcp-server', NULL, 0, 'https://github.com/apify.png?size=128', '2026-03-09T05:21:01.910351+00:00'),
  ('apify-rag-web-browser', 'Apify RAG Web Browser', 'This MCP server, developed by Apify, provides a web browsing interface for large language models and RAG pipelines. Built in JavaScript, it integrates with the RAG Web Browser Actor on the Apify platform to enable AI assistants to perform web searches, scrape content from top results, and fetch individual URLs. The implementation stands out by returning cleaned web content as Markdown and offering flexible search result limits. By connecting AI models with real-time web data, this server allows AI systems to access up-to-date information, analyze online content, and provide web-informed responses. It is particularly useful for scenarios like research tasks, content summarization, and building AI assistants that can leverage current web information to enhance their knowledge and capabilities.', '@apify', 'development', 'Unknown', 198, 'https://github.com/apify/mcp-server-rag-web-browser', NULL, 0, 'https://github.com/apify.png?size=128', '2026-03-09T05:21:01.910381+00:00'),
  ('apiiro-guardian', 'Apiiro Guardian', 'Provides access to Apiiro''s application security platform, enabling real-time security guidance during development. Supports querying repository security risks, triggering differential code scans, analyzing security posture, and managing security findings and remediation workflows.', '@apiiro', 'development', 'Unknown', 3, 'https://github.com/apiiro/mcp-server', NULL, 0, 'https://github.com/apiiro.png?size=128', '2026-03-09T05:21:01.910401+00:00'),
  ('piapi-image-generation', 'PiAPI Image Generation', 'This PiAPI MCP server, developed by an unnamed creator, integrates with the PiAPI image generation service to provide AI-driven image creation capabilities. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers a standardized interface for generating images based on text prompts. The server implements environment variable management for API key security and uses strict TypeScript configuration for robust type checking. By abstracting the complexities of the PiAPI service, it enables AI systems to easily create images from textual descriptions. This implementation is particularly valuable for applications requiring programmatic image generation, facilitating use cases such as content creation, visual design assistance, and automated illustration generation.', '@apinetwork', 'development', 'Unknown', 69, 'https://github.com/apinetwork/piapi-mcp-server', NULL, 0, 'https://github.com/apinetwork.png?size=128', '2026-03-09T05:21:01.910433+00:00'),
  ('apix420', 'Apix420', 'Apix420 is a commercial data API service designed for autonomous AI agents. It provides real-time access to 100+ data streams spanning cryptocurrency prices, blockchain data, DeFi/Web3, weather forecasts, news updates, domain/network tools, geographic data, and text/language services. The service uses API key authentication and follows a pay-per-call pricing model with fast response times.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://apix420.com', NULL, 0, NULL, '2026-03-09T05:21:01.910464+00:00'),
  ('apk-security-guard-suite', 'APK Security Guard Suite', 'APK Security Guard MCP Suite by cc-apk provides AI assistants with comprehensive Android APK security analysis capabilities through four integrated tools: JADX for decompilation and source code analysis, MobSF for automated security scanning and vulnerability detection, JEB Pro for advanced reverse engineering with method/class analysis and cross-reference tracking, and APKTOOL for APK manipulation and resource extraction. The implementation uses a multi-language architecture with Java plugins for JADX integration, TypeScript for MobSF API communication, Python for JEB Pro JSON-RPC bridging, and cross-validation capabilities that combine results from multiple analysis engines. Designed for security researchers, malware analysts, and mobile app developers who need programmatic access to professional-grade APK analysis tools for vulnerability assessment, reverse engineering workflows, and automated security testing pipelines.', '@il-il1', 'development', 'Unknown', 9, 'https://github.com/il-il1/apk-security-guard-mcp-suite', NULL, 0, 'https://github.com/il-il1.png?size=128', '2026-03-09T05:21:01.910496+00:00'),
  ('arr-media-suite', '*arr Media Suite', 'Provides unified control over the *arr media management suite (Sonarr, Radarr, Lidarr, Readarr, Prowlarr) through automatic service detection via environment variables. Exposes tools for library management, content searching across all media types, download queue monitoring, calendar viewing for upcoming releases, and triggering downloads. Features cross-service search capabilities and flexible configuration allowing users to enable only the services they use, making home media server management accessible through conversational interfaces.', '@aplaceforallmystuff', 'productivity', 'Unknown', 94, 'https://github.com/aplaceforallmystuff/mcp-arr', NULL, 0, 'https://github.com/aplaceforallmystuff.png?size=128', '2026-03-09T05:21:01.910537+00:00'),
  ('kit', 'Kit', 'Integrates with Kit.com (formerly ConvertKit) email marketing platform. Manage subscribers with filters for status, date ranges, and pagination. Create and manage tags, sequences, broadcasts, forms, custom fields, and webhooks through natural language conversations.', '@aplaceforallmystuff', 'communication', 'Unknown', 3, 'https://github.com/aplaceforallmystuff/mcp-kit', NULL, 0, 'https://github.com/aplaceforallmystuff.png?size=128', '2026-03-09T05:21:01.910559+00:00'),
  ('pickaxe', 'Pickaxe', 'Provides comprehensive access to the Pickaxe platform for managing AI agents, knowledge bases, users, and analytics through natural language commands. Supports multi-studio configurations allowing seamless switching between different Pickaxe environments, with tools for analyzing agent conversation history to identify knowledge gaps, creating and connecting documents to agents, managing user access and invitations, and retrieving usage analytics. Built for teams building AI agents on Pickaxe who want to automate administrative workflows and gain insights into agent performance.', '@aplaceforallmystuff', 'development', 'Unknown', 2, 'https://github.com/aplaceforallmystuff/mcp-pickaxe', NULL, 0, 'https://github.com/aplaceforallmystuff.png?size=128', '2026-03-09T05:21:01.910583+00:00'),
  ('pi-hole', 'Pi-hole', 'Integrates with Pi-hole v6 network-wide ad blocker to provide DNS traffic monitoring, blocking control, and list management. View query statistics and top blocked domains, enable or disable blocking with optional timers, manage whitelist and blacklist entries, inspect query logs, and perform maintenance operations like gravity updates and cache flushing.', '@aplaceforallmystuff', 'ai-ml', 'Unknown', 1, 'https://github.com/aplaceforallmystuff/mcp-pihole', NULL, 0, 'https://github.com/aplaceforallmystuff.png?size=128', '2026-03-09T05:21:01.910614+00:00'),
  ('tailscale', 'Tailscale', 'Provides read-only access to Tailscale network management for monitoring device status, tracking client updates, and generating network statistics across mesh networks.', '@aplaceforallmystuff', 'ai-ml', 'Unknown', 6, 'https://github.com/aplaceforallmystuff/mcp-tailscale', NULL, 0, 'https://github.com/aplaceforallmystuff.png?size=128', '2026-03-09T05:21:01.910635+00:00'),
  ('threat-intel', 'Threat Intel', 'Aggregates threat intelligence from five major security platforms: AlienVault OTX for community IOCs, AbuseIPDB for IP reputation data, GreyNoise for noise vs. targeted attack detection, and abuse.ch projects (URLhaus, MalwareBazaar, ThreatFox, Feodo Tracker) for malware tracking. Provides unified lookups across IPs, domains, file hashes, and URLs with dynamic tool enablement based on configured API keys.', '@aplaceforallmystuff', 'productivity', 'Unknown', 1, 'https://github.com/aplaceforallmystuff/mcp-threatintel', NULL, 0, 'https://github.com/aplaceforallmystuff.png?size=128', '2026-03-09T05:21:01.910666+00:00'),
  ('apollo-graphql', 'Apollo GraphQL', 'Apollo MCP Server enables AI agents to interact with GraphQL APIs by exposing operations as MCP tools. Built in Rust, it supports both local schema files and Apollo GraphOS integration for persisted queries, with features for introspection, schema tree-shaking, and custom scalar mapping. The server can run via stdio or SSE transport, includes an explorer tool for opening queries in Apollo Studio, and handles both static operations and dynamic execution with configurable mutation controls. This implementation is particularly valuable for AI assistants that need to access structured data from GraphQL endpoints without requiring users to understand the underlying query language.', '@apollographql', 'ai-ml', 'Unknown', 268, 'https://github.com/apollographql/apollo-mcp-server', NULL, 0, 'https://github.com/apollographql.png?size=128', '2026-03-09T05:21:01.910712+00:00'),
  ('claude-enhancements', 'Claude Enhancements', 'MCP-Claude-Enhancements is a collection of utility servers that extend Claude''s capabilities through simple, focused tools. Created by Apoorv Vishnoi, it includes modules for greeting users, counting desktop files, saving conversations to text files, and a smart context handler. Each server is built with FastMCP and designed to be easily configured through the provided JSON configuration file. The implementation demonstrates practical ways to enhance Claude''s functionality with everyday tasks while maintaining a lightweight, modular approach that allows users to selectively enable the tools they need.', '@apoorvv', 'productivity', 'Unknown', 10, 'https://github.com/apoorvv/mcp-claude-enhancements', NULL, 0, 'https://github.com/apoorvv.png?size=128', '2026-03-09T05:21:01.910754+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('appium', 'Appium', 'Provides comprehensive mobile automation capabilities for testing native, mobile-web, and hybrid applications on Android and iOS platforms. Enables AI assistants to perform element discovery and interaction, session management, screen navigation, app launching, and automated test code generation from natural language descriptions. Supports both UiAutomator2 for Android and XCUITest for iOS with intelligent locator strategies and page object model templates.', '@appium', 'development', 'Unknown', 225, 'https://github.com/appium/appium-mcp', NULL, 0, 'https://github.com/appium.png?size=128', '2026-03-09T05:21:01.910775+00:00'),
  ('apple-calendars', 'Apple Calendars', 'A TypeScript-based MCP server for interacting with Apple Calendars on macOS, providing a standardized interface for AI models to read, create, update, and delete calendar events. Built to work with a companion Swift-based Calendar API Bridge, the implementation supports flexible date parsing and handles calendar permissions through a local HTTP server running on port 8080. Particularly useful for AI assistants that need to manage scheduling or retrieve calendar information directly from a user''s macOS system.', '@shadowfax92', 'development', 'Unknown', 10, 'https://github.com/shadowfax92/apple-calendar-mcp', 'mcp-apple-calendars', 3713, 'https://github.com/shadowfax92.png?size=128', '2026-03-09T05:21:01.910802+00:00'),
  ('apple-developer-documentation', 'Apple Developer Documentation', 'This MCP server provides seamless access to Apple Developer Documentation with smart search capabilities and wildcard pattern support for iOS, macOS, SwiftUI, and UIKit development. Built by MightyDillah using TypeScript with axios for HTTP requests and intelligent caching, it offers four core tools for listing available Apple technologies/frameworks, browsing framework structures and topics, retrieving detailed symbol documentation, and searching across frameworks with wildcard support like ''RPBroadcast*'' or ''UI*View*''. The implementation features priority-based framework searching that targets popular frameworks first (SwiftUI, UIKit, Foundation), 10-minute response caching for performance, proper Apple API headers to avoid rate limiting, and comprehensive error handling, making it valuable for iOS/macOS development assistance, API discovery, and building AI coding assistants that need real-time access to Apple''s official documentation without manual browsing.', '@mightydillah', 'development', 'Unknown', 577, 'https://github.com/mightydillah/apple-doc-mcp', NULL, 0, 'https://github.com/mightydillah.png?size=128', '2026-03-09T05:21:01.910838+00:00'),
  ('apple-ecosystem', 'Apple Ecosystem', 'Enhanced Apple ecosystem integration server that provides AI assistants with native access to macOS applications including Messages, Contacts, Notes, Mail, Reminders, Calendar, and Maps through AppleScript automation and direct database queries. Built by Ayaanisthebest as an enhanced fork of supermemoryai''s original implementation, it features smart contact resolution for messaging, priority-based Notes search with rich text support, comprehensive email management, and location services integration. The implementation uses a hybrid approach combining AppleScript for app control with direct SQLite database access for Messages history, includes robust error handling with fallback mechanisms, and provides detailed permission guidance for macOS privacy settings, making it ideal for productivity automation and personal assistant workflows on Apple devices.', '@ayaanisthebest', 'databases', 'Unknown', 3, 'https://github.com/ayaanisthebest/applemcp', NULL, 0, 'https://github.com/ayaanisthebest.png?size=128', '2026-03-09T05:21:01.910849+00:00'),
  ('baidu-search', 'Baidu Search', 'A Baidu Search integration for AI assistants that enables direct access to China''s largest search engine through the MCP. This TypeScript implementation allows agents to perform web searches on Baidu, retrieve search results, and extract relevant information without requiring users to leave their conversation interface. It leverages the @modelcontextprotocol/sdk and axios for making API requests, making it particularly valuable for use cases involving Chinese language queries, accessing China-specific content, or gathering information from behind the Great Firewall.', '@appleinmusic', 'development', 'Unknown', 7, 'https://github.com/appleinmusic/baidu-search-mcp', NULL, 0, 'https://github.com/appleinmusic.png?size=128', '2026-03-09T05:21:01.910893+00:00'),
  ('apple-search-ads', 'Apple Search Ads', 'Apple Search Ads MCP: campaign analytics, bid management, and attribution tracking.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://appleadsmcp.com', NULL, 0, NULL, '2026-03-09T05:21:01.910915+00:00'),
  ('eufy-robovac', 'Eufy RoboVac', 'This Eufy RoboVac MCP server provides comprehensive control over Eufy robotic vacuum cleaners through local network communication, featuring automatic device discovery via network scanning and ARP table analysis to identify RoboVac devices by their Anker/Eufy MAC address prefixes and open Tuya protocol ports (6668, 6667, 443). The server offers 24 tools covering all major vacuum operations including cleaning control (start, stop, pause, return home), configuration management (work modes, suction speeds), status monitoring (battery level, error codes, work status), and device location features, with intelligent fallback mechanisms that attempt auto-discovery when manual IP configuration fails. Built using the eufy-robovac library, it''s particularly valuable for smart home automation, voice assistant integration, and AI-driven household management where users need programmatic control over their cleaning routines without requiring manual device configuration.', '@appleton', 'development', 'Unknown', 1, 'https://github.com/appleton/sam', NULL, 0, 'https://github.com/appleton.png?size=128', '2026-03-09T05:21:01.910946+00:00'),
  ('appsai', 'AppsAI', 'Build and deploy full-stack Next.js apps with 98 tools for React, AWS, and MongoDB.', '@appsai-inc', 'databases', 'Unknown', 1, 'https://github.com/appsai-inc/mcp-server', NULL, 0, 'https://github.com/appsai-inc.png?size=128', '2026-03-09T05:21:01.910958+00:00'),
  ('seo-ai-google-ads-keyword-planner', 'SEO AI (Google Ads Keyword Planner)', 'App SEO AI provides a bridge between AI assistants and Google Ads Keyword Planner API, enabling SEO automation and optimization through keyword research, SERP analysis, and competitor insights. The server exposes RESTful endpoints for generating keyword ideas, analyzing search results, and evaluating competitor domains, making it valuable for digital marketers who need to optimize content, understand search trends, and identify competitive opportunities without leaving their AI assistant conversation.', '@ayushsinghvi92', 'development', 'Unknown', 1, 'https://github.com/ayushsinghvi92/app-seo-ai', NULL, 0, 'https://github.com/ayushsinghvi92.png?size=128', '2026-03-09T05:21:01.910985+00:00'),
  ('appsflyer', 'AppsFlyer', 'AppsFlyer provides marketing measurement and analytics across mobile, web, CTV, and PC/console platforms. The MCP server enables natural language queries for campaign performance metrics (ROAS, retention, LTV), app management, and OneLink configuration. Access is controlled by AppsFlyer role permissions and requires authentication with AppsFlyer credentials.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://www.appsflyer.com/products/mcp/', NULL, 0, NULL, '2026-03-09T05:21:01.911015+00:00'),
  ('appsignal', 'AppSignal', 'Official AppSignal MCP server that provides AI assistants with access to AppSignal''s application performance monitoring platform through a proxy architecture that forwards requests to AppSignal''s hosted API endpoints. Built by AppSignal using TypeScript and the Model Context Protocol SDK, the implementation acts as a local proxy server that handles API key authentication and forwards MCP requests to https://appsignal.com/api/mcp, supporting tools, prompts, and resources for monitoring application performance, error tracking, and system metrics. The proxy design allows developers to integrate AppSignal''s APM capabilities into their AI workflows through stdio communication while maintaining secure API access, serving teams building monitoring dashboards, developers requiring programmatic access to application performance data, and AI assistants needing real-time insights into application health and performance metrics.', '@appsignal', 'development', 'Unknown', 9, 'https://github.com/appsignal/appsignal-mcp', 'appsignal-mcp', 0, 'https://github.com/appsignal.png?size=128', '2026-03-09T05:21:01.911046+00:00'),
  ('app-store-scraper', 'App Store Scraper', 'MCP server for App Store and Google Play Store data scraping, providing AI assistants with access to app metadata, reviews, rankings, and ASO (App Store Optimization) insights through integrated scraper libraries. Built using JavaScript with the Model Context Protocol SDK, the implementation leverages app-store-scraper, google-play-scraper, and aso libraries to extract comprehensive app information including developer details, ratings, download counts, version history, and user reviews from both iOS App Store and Google Play Store. The server enables use cases like competitive app analysis, market research, review sentiment analysis, and ASO strategy development by providing programmatic access to mobile app ecosystem data that would otherwise require manual collection or expensive third-party services.', '@appreply-co', 'development', 'Unknown', 38, 'https://github.com/appreply-co/mcp-appstore', 'mcp-appstore', 0, 'https://github.com/appreply-co.png?size=128', '2026-03-09T05:21:01.911077+00:00'),
  ('app-store-connect', 'App Store Connect', 'This App Store Connect MCP server, developed by Trial and Error Inc, provides AI assistants with direct access to iOS app metrics and financial data from Apple''s App Store Connect API. Built with TypeScript and featuring JWT-based authentication, automatic pagination handling, and rate limiting, it eliminates the manual export-import cycle that developers face when trying to analyze iOS app performance data with AI tools. The implementation offers access to sales reports, user analytics, app health metrics, beta testing data, and subscription information, making it particularly useful for iOS developers and companies needing regular financial reports, app performance monitoring, or automated competitive analysis without the overhead of building custom API integrations.', '@trialanderrorai', 'development', 'Unknown', 6, 'https://github.com/trialanderrorai/appstore-connect-mcp', NULL, 0, 'https://github.com/trialanderrorai.png?size=128', '2026-03-09T05:21:01.911110+00:00'),
  ('appwrite', 'Appwrite', 'Integrates with Appwrite''s backend platform, providing comprehensive access to databases, user management, file storage, serverless functions, messaging, and team administration. Enables selective feature activation to optimize token usage while managing backend operations directly from AI workflows.', '@appwrite', 'databases', 'Unknown', 62, 'https://github.com/appwrite/mcp-for-api', NULL, 0, 'https://github.com/appwrite.png?size=128', '2026-03-09T05:21:01.911120+00:00'),
  ('appwrite-docs', 'Appwrite Docs', 'MCP server implementation by Appwrite that provides AI assistants with access to the complete Appwrite documentation through vector-based semantic search and direct page retrieval. The implementation downloads documentation content from the Appwrite website repository, processes it into a LibSQL vector database using OpenAI embeddings for semantic similarity matching, and exposes three core tools: searchDocs for intelligent content discovery, getDocsPage for retrieving specific documentation pages, and getTableOfContents for navigation structure. Built with TypeScript and the mcp-framework, it features configurable similarity thresholds, batch processing for efficient indexing, and HTTP transport with CORS support for web-based integrations, serving developers who need contextual access to Appwrite''s API documentation, SDK guides, and implementation examples during coding workflows.', '@appwrite', 'databases', 'Unknown', 9, 'https://github.com/appwrite/mcp-for-docs', NULL, 0, 'https://github.com/appwrite.png?size=128', '2026-03-09T05:21:01.911133+00:00'),
  ('superset', 'Superset', 'The Superset MCP Integration provides AI assistants with programmatic access to Apache Superset''s data visualization and analytics capabilities through a comprehensive set of tools. Built with Python using FastMCP, it enables operations like dashboard management, chart creation, SQL query execution, and database administration via authenticated API calls. The implementation handles token management, automatic refreshing, and proper error handling to maintain secure connections with Superset instances. It''s particularly valuable for users who want to leverage AI assistants to explore data, create visualizations, and manage analytics workflows without leaving their conversational interface.', '@aptro', 'databases', 'Unknown', 169, 'https://github.com/aptro/superset-mcp', NULL, 0, 'https://github.com/aptro.png?size=128', '2026-03-09T05:21:01.911193+00:00'),
  ('zerodha', 'Zerodha', 'Zerodha-MCP provides a secure interface for AI models to interact with the Zerodha trading platform through a FastMCP server implementation. Built by Aptro, it enables models to authenticate with Zerodha, manage portfolios, place stock and mutual fund orders, retrieve market data, and set up SIPs. The implementation handles authentication flows securely, stores access tokens locally, and provides comprehensive error handling across all trading operations. This server is particularly valuable for users who want to automate trading workflows or analyze their investment portfolio directly within AI assistant conversations.', '@aptro', 'ai-ml', 'Unknown', 45, 'https://github.com/aptro/zerodha-mcp', NULL, 0, 'https://github.com/aptro.png?size=128', '2026-03-09T05:21:01.911236+00:00'),
  ('logseq', 'Logseq', 'Logseq MCP Tools provides a set of tools that enable AI agents to interact with local Logseq knowledge graphs through the Model Context Protocol. Developed by apw124, this implementation offers comprehensive functionality for managing pages and blocks in Logseq, including creating, updating, and searching content. The server communicates with Logseq''s API to perform operations like retrieving journal entries, managing hierarchical block structures, and executing complex searches. It''s particularly useful for AI assistants that need to capture notes, organize information, or retrieve knowledge from a user''s personal Logseq database without requiring direct access to the application.', '@apw124', 'databases', 'Unknown', 15, 'https://github.com/apw124/logseq-mcp', 'logseq-mcp', 3372, 'https://github.com/apw124.png?size=128', '2026-03-09T05:21:01.911247+00:00'),
  ('trivy-security-scanner', 'Trivy Security Scanner', 'Trivy MCP Server Plugin by Aqua Security integrates Trivy''s security scanning capabilities with VS Code, Cursor, JetBrains IDEs, and Claude Desktop through natural language queries. The implementation provides tools for scanning local filesystems, container images, and remote repositories for vulnerabilities, misconfigurations, licenses, and secrets, with optional integration to Aqua Platform for enhanced scanning capabilities. Built in Go with support for both stdio and SSE transport protocols, it enables developers to ask security-related questions like ''Are there any vulnerabilities in this project?'' directly within their IDE chat interfaces, making security scanning more accessible through conversational AI rather than command-line tools.', '@aquasecurity', 'development', 'Unknown', 37, 'https://github.com/aquasecurity/trivy-mcp', NULL, 0, 'https://github.com/aquasecurity.png?size=128', '2026-03-09T05:21:01.911277+00:00'),
  ('aquaview', 'AQUAVIEW', 'AQUAVIEW provides unified access to oceanographic and environmental data from NOAA and other authoritative sources. The platform consolidates datasets from uncrewed systems like drones, AUVs, and ROVs, offering centralized discovery across millions of datasets. Researchers and developers can search, filter, and integrate ocean data into their applications through standardized API access.', '@unknown', 'search', 'Unknown', 0, 'https://www.aquaview.org', NULL, 0, NULL, '2026-03-09T05:21:01.911313+00:00'),
  ('documentation-scraper', 'Documentation Scraper', 'Docs MCP Server provides a specialized documentation scraping and retrieval system that enables AI assistants to access library documentation from various sources including GitHub, NPM, PyPI, and web pages. Built with TypeScript, it implements a pipeline architecture that handles document scraping, processing, splitting, and storage with features like semantic markdown splitting, greedy chunk optimization, and version-aware retrieval. The server exposes tools for searching documentation, finding specific versions, listing available libraries, and managing scraping jobs through a well-defined API. Particularly valuable for developers who need AI assistants to reference accurate, up-to-date documentation without leaving their workflow.', '@arabold', 'development', 'Unknown', 1105, 'https://github.com/arabold/docs-mcp-server', '@arabold/docs-mcp-server', 17810, 'https://github.com/arabold.png?size=128', '2026-03-09T05:21:01.911338+00:00'),
  ('kubernetes-gpu-agent', 'Kubernetes GPU Agent', 'An ephemeral diagnostic agent for Kubernetes clusters that provides real-time NVIDIA GPU hardware introspection via stdio transport, designed for AI-assisted troubleshooting by SREs debugging complex hardware failures. Uses NVIDIA NVML library to expose GPU inventory, health monitoring, and XID error analysis tools through kubectl debug sessions, eliminating the need for persistent DaemonSets or standing infrastructure. Operates in read-only mode by default with an optional operator mode for destructive operations, featuring graceful degradation when GPU hardware is unavailable.', '@arangogutierrez', 'cloud', 'Unknown', 4, 'https://github.com/arangogutierrez/k8s-gpu-mcp-server', NULL, 0, 'https://github.com/arangogutierrez.png?size=128', '2026-03-09T05:21:01.911361+00:00'),
  ('file-editor', 'File Editor', 'This MCP server, developed primarily by Claude Sonnet 3.5 with oversight from arathald, is a TypeScript port of Anthropic''s filesystem editing tools. It provides a standardized interface for AI agents to perform file operations like reading, writing, and editing on the host system. Built using the Model Context Protocol SDK, it focuses on replicating the functionality of Anthropic''s original Python implementation in a TypeScript environment. The server is designed for users familiar with Anthropic''s tools who want similar capabilities in a TypeScript-based MCP setup. It''s particularly useful for AI-assisted file manipulation tasks, but comes with strong warnings about potential security risks due to its lack of access controls.', '@arathald', 'development', 'Unknown', 7, 'https://github.com/arathald/mcp-editor', NULL, 0, 'https://github.com/arathald.png?size=128', '2026-03-09T05:21:01.911390+00:00'),
  ('sequential-thinking', 'Sequential Thinking', 'Sequential Thinking is an MCP server developed by Arben Ademi for advanced problem solving. It implements a structured approach to break down complex problems into sequential steps, enabling more thorough and methodical analysis. The server integrates with the MCP CLI and leverages the Rich library for enhanced text formatting. Its key differentiator is the focus on step-by-step reasoning, making it particularly effective for tasks requiring detailed planning, logical deduction, or systematic troubleshooting. This implementation is well-suited for developers, researchers, and analysts working on intricate problems that benefit from a structured thinking process.', '@arben-adm', 'productivity', 'Unknown', 853, 'https://github.com/arben-adm/mcp-sequential-thinking', NULL, 0, 'https://github.com/arben-adm.png?size=128', '2026-03-09T05:21:01.911476+00:00'),
  ('claudehopper-construction-document-analysis', 'ClaudeHopper (Construction Document Analysis)', 'ClaudeHopper is an AI-powered construction document assistant that integrates with Claude Desktop to help users analyze and search through architectural drawings and specifications. Developed by Tom Finlayson, it uses LanceDB for vector storage and Ollama for local AI processing, enabling features like image extraction from PDF drawings and semantic search across construction documents. The implementation includes tools for processing both textual specifications and visual elements from CAD drawings, making it particularly valuable for architects, engineers, and construction professionals who need to quickly access and interpret complex project documentation.', '@arborist-ai', 'productivity', 'Unknown', 5, 'https://github.com/arborist-ai/claudehopper', NULL, 0, 'https://github.com/arborist-ai.png?size=128', '2026-03-09T05:21:01.911566+00:00'),
  ('paypal', 'PayPal', 'PayPal MCP Server provides integration with PayPal''s payment processing APIs through a standardized interface. Built by Brandon Arbuthnot, it enables AI assistants to create and capture payments, manage subscriptions, handle business operations like invoicing and payouts, and access user information. The server implements robust authentication with automatic token refresh, comprehensive input validation using Zod schemas, and detailed error handling. It''s particularly valuable for e-commerce applications, financial services, and any workflow requiring secure payment processing capabilities without leaving the conversation interface.', '@arbuthnot-eth', 'ai-ml', 'Unknown', 0, 'https://github.com/arbuthnot-eth/paypal-mcp-defunct', NULL, 0, 'https://github.com/arbuthnot-eth.png?size=128', '2026-03-09T05:21:01.911610+00:00'),
  ('arca', 'Arca', 'Arca provides a private, encrypted vault for storing personal data used by AI assistants. The platform offers Tables API for structured data with SQL queries, Vector API for semantic search with automatic embeddings, and a Skills system that auto-generates documentation. Users can manage structured data and semantic memory through natural language interaction with connected AI assistants.', '@unknown', 'databases', 'Unknown', 0, 'https://arca.build', NULL, 0, NULL, '2026-03-09T05:21:01.911620+00:00'),
  ('blueprint', 'Blueprint', 'Blueprint is a diagram generation MCP server created by ArcadeAI that leverages Google''s Gemini image models to create technical diagrams from text descriptions. The server provides asynchronous job management with tools for starting diagram generation, checking job status, and downloading completed diagrams as PNG files. It supports multiple diagram types including architecture, flowchart, data flow, sequence, and infographic diagrams with configurable aspect ratios and resolutions. This tool is particularly useful for generating visual documentation, system architecture diagrams, and technical illustrations within AI-assisted workflows.', '@arcadeai', 'ai-ml', 'Unknown', 584, 'https://github.com/arcadeai/blueprint-mcp', NULL, 0, 'https://github.com/arcadeai.png?size=128', '2026-03-09T05:21:01.911660+00:00'),
  ('sonarqube-metrics', 'SonarQube Metrics', 'The fastmcp-sonarqube-metrics server provides AI assistants with access to SonarQube code quality metrics through the MCP protocol. Built by ArchAI-Labs, this implementation fetches project-level metrics like bugs, vulnerabilities, code smells, coverage, and duplication density using SonarQube''s REST API. The server exposes four tools: listing available projects, retrieving current metrics for a specific project, accessing historical metric data with date filtering, and examining component-level metrics across files and directories. It''s particularly valuable for development teams who want to incorporate code quality insights into their AI-assisted workflows without context switching.', '@archai-labs', 'development', 'Unknown', 12, 'https://github.com/archai-labs/fastmcp-sonarqube-metrics', NULL, 0, 'https://github.com/archai-labs.png?size=128', '2026-03-09T05:21:01.911687+00:00'),
  ('ssi-stock-vietnamese-market-data', 'SSI Stock (Vietnamese Market Data)', 'SSI Stock MCP Server provides a bridge to the SSI Financial Connector (FC) Data API, enabling AI assistants to access Vietnamese stock market data. Developed by Chung Phan under Apache 2.0 license, it offers tools for retrieving securities listings, detailed stock information, index components, daily OHLC data, intraday price movements, and foreign trading activities. The server authenticates with consumer credentials, processes and validates API responses for consistent formatting, and handles pagination for large datasets. This implementation is particularly valuable for financial analysis, investment research, and market monitoring applications focused on the Vietnamese stock market.', '@archiephan78', 'ai-ml', 'Unknown', 16, 'https://github.com/archiephan78/ssi-stock-mcp-server', NULL, 0, 'https://github.com/archiephan78.png?size=128', '2026-03-09T05:21:01.911740+00:00'),
  ('excel-reader', 'Excel Reader', 'This MCP server, developed by ArchimdesCrypto, provides a standardized interface for reading Excel files with automatic chunking and pagination support. Built with TypeScript and leveraging the Model Context Protocol SDK and SheetJS library, it offers tools for efficient handling of large Excel datasets. The implementation focuses on breaking down Excel files into manageable chunks, enabling AI models to process extensive spreadsheet data without memory constraints. By connecting AI assistants with Excel file content, this server allows for sophisticated data analysis, reporting, and manipulation tasks. It''s particularly useful for applications dealing with large-scale data processing, financial analysis, or any scenario requiring programmatic access to Excel file contents through a standardized MCP interface.', '@archimedescrypto', 'development', 'Unknown', 29, 'https://github.com/archimedescrypto/excel-reader-mcp', NULL, 0, 'https://github.com/archimedescrypto.png?size=128', '2026-03-09T05:21:01.911772+00:00'),
  ('figma-chunked', 'Figma Chunked', 'Figma MCP Server with Chunking provides a memory-efficient interface to the Figma API, designed to handle large Figma files by breaking operations into manageable chunks with pagination support. It features configurable memory limits, node type filtering, progress tracking, and resume capabilities for interrupted operations. The implementation includes tools for retrieving file data, listing files, accessing version history, comments, components, styles, and specific nodes, making it particularly valuable for designers and developers who need to programmatically access and analyze complex Figma designs without memory constraints.', '@archimedescrypto', 'ai-ml', 'Unknown', 4, 'https://github.com/archimedescrypto/figma-mcp-chunked', NULL, 0, 'https://github.com/archimedescrypto.png?size=128', '2026-03-09T05:21:01.911819+00:00'),
  ('arcknowledge-custom-rag', 'ArcKnowledge (Custom RAG)', 'ArcKnowledge is a FastMCP server that bridges AI assistants to custom knowledge base API webhooks, enabling retrieval-augmented generation (RAG) capabilities. Built with Python using the FastMCP framework, it manages multiple knowledge sources through a configurable JSON structure, supports both text and image queries, and handles API authentication. The implementation provides tools for querying knowledge bases, managing document sources, and processing images, making it particularly useful for applications requiring access to specialized knowledge repositories, custom RAG implementations, or multi-source information retrieval with visual context support.', '@dragonjump', 'ai-ml', 'Unknown', 2, 'https://github.com/dragonjump/mcp-arcknowledge', NULL, 0, 'https://github.com/dragonjump.png?size=128', '2026-03-09T05:21:01.911876+00:00'),
  ('github-projects-v2', 'GitHub Projects V2', 'The GitHub Projects V2 MCP Server provides tools for managing GitHub Projects V2 through Claude and other MCP clients. Built by Hillary Kipkemoi, this implementation uses the GitHub GraphQL API to enable users to list projects, view fields and items, create issues, add them to projects, create draft issues, update field values, and delete items. The server authenticates with GitHub using personal access tokens and includes comprehensive error handling for GraphQL operations. It''s particularly useful for teams who want to manage their GitHub project boards directly through AI assistants without switching contexts, supporting both organization and user-owned projects.', '@arclio', 'development', 'Unknown', 28, 'https://github.com/arclio/github-projects-mcp', 'mcp-github-projects', 4615, 'https://github.com/arclio.png?size=128', '2026-03-09T05:21:01.911906+00:00'),
  ('linear', 'Linear', 'A TypeScript MCP server that bridges Linear''s project management platform with AI assistants, enabling retrieval of a user''s todo tickets by user ID or email. Built with the Model Context Protocol SDK, it provides a standardized way to fetch and expose Linear task data, making it easy to integrate project management context directly into AI workflows.', '@argia-andreas', 'development', 'Unknown', 0, 'https://github.com/argia-andreas/linear-mcp-server', NULL, 0, 'https://github.com/argia-andreas.png?size=128', '2026-03-09T05:21:01.911930+00:00'),
  ('anki', 'Anki', 'MCP server implementation by arielbk that provides AI assistants with complete access to Anki flashcard management through the AnkiConnect plugin, built using TypeScript with comprehensive coverage of deck operations, note management, card scheduling, and study statistics. The implementation offers both resources for querying Anki data (deck configurations, card information, study statistics) and tools for performing actions (creating notes, managing decks, answering cards, importing/exporting), plus graphical tools for controlling the Anki GUI and media file management capabilities. Designed for language learners, students, and educators who want conversational access to their Anki collections, enabling use cases like automated flashcard creation from study materials, progress tracking and analytics, bulk card management operations, and integration of spaced repetition workflows into broader learning systems.', '@arielbk', 'development', 'Unknown', 9, 'https://github.com/arielbk/anki-mcp', '@arielbk/anki-mcp', 2074, 'https://github.com/arielbk.png?size=128', '2026-03-09T05:21:01.911964+00:00'),
  ('dev-to', 'Dev.to', 'Dev.to MCP Server provides a bridge between AI assistants and Dev.to content, enabling access to articles and publishing capabilities. Built by Arindam Majumder, it offers tools for fetching latest and trending articles, searching by criteria, accessing article details, and creating or updating content on Dev.to. The server implements caching to improve performance and reduce API calls, requires a Dev.to API key for authentication, and is compatible with Claude and Cursor. It''s particularly valuable for users who want to discover, analyze, or publish Dev.to content through conversational interfaces without manually navigating the platform.', '@arindam200', 'development', 'Unknown', 60, 'https://github.com/arindam200/devto-mcp', NULL, 0, 'https://github.com/arindam200.png?size=128', '2026-03-09T05:21:01.911993+00:00'),
  ('fatture-in-cloud', 'Fatture in Cloud', 'Provides integration with Fatture in Cloud, Italy''s electronic invoicing platform used by over 500,000 businesses. Enables complete invoicing workflow management including creating invoices, sending them to Italy''s SDI (Sistema di Interscambio) tax system, managing client data, tracking payment status, and generating financial dashboards. Features comprehensive invoice operations like duplication with text replacement, email delivery to clients, and real-time status monitoring, making it valuable for Italian businesses automating their electronic invoicing compliance and financial management.', '@aringad', 'communication', 'Unknown', 4, 'https://github.com/aringad/fattureincloud-mcp', NULL, 0, 'https://github.com/aringad.png?size=128', '2026-03-09T05:21:01.912084+00:00'),
  ('pubmed-research', 'PubMed Research', 'Scholarly research MCP server built by aringadre76 that provides AI assistants with access to PubMed''s biomedical literature database through five core tools: search_papers for querying academic papers with filters for date ranges, journals, and authors; get_paper_by_id and get_paper_details for retrieving specific papers by PMID; get_citation for generating formatted citations in BibTeX, EndNote, APA, MLA, and RIS formats; and get_citation_count for tracking paper impact metrics. The implementation uses TypeScript with the MCP SDK and integrates directly with NCBI''s E-utilities API, handling XML parsing and rate limiting while supporting comprehensive metadata extraction including abstracts, author lists, DOIs, and publication details. Designed for researchers conducting literature reviews, academics needing programmatic access to biomedical papers, and AI applications requiring structured access to scientific publications with proper citation formatting capabilities.', '@aringadre76', 'databases', 'Unknown', 6, 'https://github.com/aringadre76/mcp-for-research', 'scholarly-research-mcp', 1042, 'https://github.com/aringadre76.png?size=128', '2026-03-09T05:21:01.912096+00:00'),
  ('claude-talk-to-figma', 'Claude Talk to Figma', 'This MCP server enables AI assistants to directly control Figma designs through a WebSocket bridge, providing comprehensive tools for document inspection, element creation (rectangles, frames, text, shapes), modification (colors, positioning, sizing), text manipulation, and component management. Built with TypeScript and Bun, it features a modular architecture with specialized tool categories, robust error handling with progress tracking for complex operations, and intelligent defaults that preserve transparency and stroke properties. The implementation includes a Figma plugin that establishes WebSocket communication, systematic text replacement strategies with chunking for large designs, and export capabilities for visual verification, making it valuable for automated design workflows, content localization, design system management, and building AI assistants that need programmatic access to Figma''s full design capabilities without manual interface navigation.', '@arinspunk', 'development', 'Unknown', 454, 'https://github.com/arinspunk/claude-talk-to-figma-mcp', 'claude-talk-to-figma-mcp', 18455, 'https://github.com/arinspunk.png?size=128', '2026-03-09T05:21:01.912132+00:00'),
  ('zmanim', 'Zmanim', 'Provides astronomical calculations for Jewish prayer times (zmanim) including sunrise/sunset, Shema recitation times, prayer windows, and Shabbat candle lighting times. Supports multiple halachic opinions (GRA, MGA) with NOAA-based calculations for any location worldwide.', '@ariroffe72', 'maps-location', 'Unknown', 1, 'https://github.com/ariroffe72/zmanim-mcp-server', NULL, 0, 'https://github.com/ariroffe72.png?size=128', '2026-03-09T05:21:01.912185+00:00'),
  ('nsaf-neuro-symbolic-autonomy-framework', 'NSAF (Neuro-Symbolic Autonomy Framework)', 'NSAF MCP Server provides AI assistants with access to the Neuro-Symbolic Autonomy Framework, focusing on Self-Constructing Meta-Agents (SCMA) that can evolve and optimize their neural network architectures through generations. The server exposes tools for running evolutionary processes with customizable parameters and comparing different agent architectures, enabling AI assistants to leverage advanced neural architecture search capabilities without requiring deep expertise in evolutionary algorithms. Built with TensorFlow and designed to work seamlessly with Claude Desktop and Cline, this implementation is particularly valuable for researchers and developers exploring autonomous AI systems that can self-design and adapt to different problem domains.', '@ariunbolor', 'ai-ml', 'Unknown', 2, 'https://github.com/ariunbolor/nsaf-mcp-server', NULL, 0, 'https://github.com/ariunbolor.png?size=128', '2026-03-09T05:21:01.912236+00:00'),
  ('arize-phoenix', 'Arize Phoenix', 'Phoenix MCP Server provides a unified interface to Arize Phoenix''s capabilities through the Model Context Protocol. Developed by Arize AI, this TypeScript implementation enables AI assistants to manage prompts, explore datasets, and run experiments against the Phoenix platform. The server exposes tools for creating and iterating on prompts across different LLM providers (OpenAI, Anthropic, Google), working with evaluation datasets, and visualizing experiment results, making it particularly valuable for teams building and evaluating LLM applications who want to leverage Phoenix''s observability features through AI assistants.', '@arize-ai', 'development', 'Unknown', 8773, 'https://github.com/arize-ai/phoenix/tree/HEAD/js/packages/phoenix-mcp', '@arizeai/phoenix-mcp', 15230, 'https://github.com/arize-ai.png?size=128', '2026-03-09T05:21:01.912263+00:00'),
  ('local-utilities', 'Local Utilities', 'The Local Utilities MCP Server provides access to various system utilities through a standardized interface, enabling AI assistants to retrieve local system information. Built with TypeScript and the Model Context Protocol SDK, it offers tools for getting current time and date, hostname, public IP address, directory listings, Node.js version information, and checking processes running on specific ports. The server can be used globally or via npx without installation, integrates seamlessly with Cursor through simple configuration, and includes a pre-commit hook that automatically builds the server before each commit to ensure build files are always up-to-date in the repository.', '@arjshiv', 'development', 'Unknown', 2, 'https://github.com/arjshiv/localutils-mcp-server', NULL, 0, 'https://github.com/arjshiv.png?size=128', '2026-03-09T05:21:01.912292+00:00'),
  ('sparkmango', 'SparkMango', 'SparkMango is a Python-based server that converts Solidity smart contracts into functional RESTful API implementations following the MCP specification. Developed by Arjun Bhuptani, it analyzes contract ABIs, generates method implementations using OpenAI''s GPT-4, and creates a complete server structure with state management, event handling, and comprehensive documentation. The server provides a bridge between blockchain contracts and Python applications, making it easier for AI agents to interact with smart contracts through standardized API endpoints without requiring deep blockchain knowledge.', '@arjunbhuptani', 'ai-ml', 'Unknown', 3, 'https://github.com/arjunbhuptani/sparkmango', 'mcp-server', 281954, 'https://github.com/arjunbhuptani.png?size=128', '2026-03-09T05:21:01.912385+00:00'),
  ('storyblok', 'Storyblok', 'This MCP server provides complete Storyblok CMS integration built by Arjun Vijay Prakash using TypeScript, offering comprehensive content management capabilities through both CDN and Management API endpoints. It includes tools for story CRUD operations, publishing workflows, version control with restore functionality, tag management, release scheduling, asset handling with folder organization, component schema management, and datasource operations. The implementation uses Zod for parameter validation and axios for HTTP requests, with proper error handling and authentication via environment variables, making it valuable for headless CMS workflows, content automation, and building applications that need programmatic access to Storyblok''s full feature set including content publishing pipelines and asset management.', '@arjuncodess', 'development', 'Unknown', 9, 'https://github.com/arjuncodess/storyblok-mcp', NULL, 0, 'https://github.com/arjuncodess.png?size=128', '2026-03-09T05:21:01.912416+00:00'),
  ('minecraft', 'Minecraft', 'This MCP implementation provides a Minecraft integration, allowing AI models to interact with and control Minecraft game environments. Built using TypeScript and Node.js, it leverages the minecraft-protocol and mineflayer libraries to establish connections and manipulate in-game entities. The implementation supports various Minecraft versions and includes features like pathfinding and automated actions. It''s designed for researchers, educators, and developers interested in using Minecraft as a sandbox for AI experimentation, educational simulations, or creating advanced in-game automation tools.', '@arjunkmrm', 'development', 'Unknown', 96, 'https://github.com/arjunkmrm/mcp-minecraft', 'mcp-minecraft', 4009, 'https://github.com/arjunkmrm.png?size=128', '2026-03-09T05:21:01.912442+00:00'),
  ('perplexity-deep-research', 'Perplexity Deep Research', 'Perplexity Deep Research MCP enables AI assistants to perform web searches using Perplexity''s sonar-deep-research model through the chat completions API. It provides a single tool called ''deep_research'' that accepts search queries and optional recency filters, returning comprehensive search results with proper citations. Built for integration with Claude Desktop via Smithery, this implementation requires a Perplexity API key and is particularly valuable for workflows requiring up-to-date information retrieval and research capabilities directly within AI assistant conversations.', '@arjunkmrm', 'communication', 'Unknown', 11, 'https://github.com/arjunkmrm/perplexity-deep-research', NULL, 0, 'https://github.com/arjunkmrm.png?size=128', '2026-03-09T05:21:01.912478+00:00'),
  ('perplexity-search', 'Perplexity Search', 'Perplexity Search MCP enables AI assistants to perform web searches using Perplexity''s API with sonar or sonar-pro models. Built by arjunkmrm, it provides a single ''search'' tool that accepts a query parameter and optional recency filtering, returning detailed search results with citations. The implementation runs on Node.js, can be deployed via Docker, and requires a Perplexity API key for authentication, making it ideal for workflows requiring up-to-date information from the web without leaving the conversation interface.', '@arjunkmrm', 'cloud', 'Unknown', 10, 'https://github.com/arjunkmrm/perplexity-search', NULL, 0, 'https://github.com/arjunkmrm.png?size=128', '2026-03-09T05:21:01.912498+00:00'),
  ('singapore-lta', 'Singapore LTA', 'This MCP server, developed by Arjun Kumar, provides a standardized interface for interacting with Singapore''s Land Transport Authority (LTA) DataMall API. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers real-time access to transportation information including bus arrivals, traffic conditions, and train service updates. The implementation focuses on exposing LTA''s data through a consistent MCP interface, enabling AI models to perform complex transportation-related queries and analysis. By connecting AI assistants with LTA''s extensive dataset, this server facilitates sophisticated urban mobility scenarios like route optimization, congestion prediction, and public transport planning. It''s particularly valuable for applications and AI systems aimed at improving urban transportation efficiency and user experience in Singapore.', '@arjunkmrm', 'development', 'Unknown', 3, 'https://github.com/arjunkmrm/mcp-sg-lta', NULL, 0, 'https://github.com/arjunkmrm.png?size=128', '2026-03-09T05:21:01.912531+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('math-tools', 'Math Tools', 'This MCP server provides basic mathematical operations through six core tools: addition, subtraction, multiplication, division, exponentiation, and logarithm calculation with customizable base support. Built by ArjunKrish7356 using Python with FastMCP, it offers fundamental arithmetic capabilities with proper error handling for edge cases like division by zero and invalid logarithm inputs. Designed for AI assistants that need reliable mathematical computation tools for calculations, data analysis, and problem-solving workflows where basic math operations are required.', '@arjunkrish7356', 'ai-ml', 'Unknown', 3, 'https://github.com/arjunkrish7356/mathagent', NULL, 0, 'https://github.com/arjunkrish7356.png?size=128', '2026-03-09T05:21:01.912577+00:00'),
  ('groww', 'Groww', 'This MCP server provides AI assistants with direct access to the Groww trading platform API for comprehensive stock market operations through 25+ specialized tools covering instrument search, order management, portfolio tracking, margin calculations, and live market data. Built using TypeScript with the Model Context Protocol SDK and Zod validation, it features CSV-based instrument discovery with fuzzy search capabilities, complete order lifecycle management including placement, modification, and cancellation with automatic reference ID generation, real-time portfolio and position tracking, margin requirement calculations for single orders or baskets, and live market data retrieval including quotes, LTP, OHLC, and historical price data with interval-based constraints. The implementation includes robust error handling with detailed API response parsing, configurable debug logging, and supports both equity and F&O segments across NSE and BSE exchanges, making it valuable for algorithmic trading workflows, portfolio analysis, and building AI assistants that need programmatic access to Indian stock market operations without manual trading platform navigation.', '@arkapravasinha', 'development', 'Unknown', 3, 'https://github.com/arkapravasinha/groww-mcp-server', NULL, 0, 'https://github.com/arkapravasinha.png?size=128', '2026-03-09T05:21:01.912614+00:00'),
  ('zsh-tool', 'Zsh Tool', 'Provides advanced Zsh shell execution for Claude Code with full Bash parity. Features yield-based execution that prevents commands from hanging indefinitely, PTY mode for interactive programs and password prompts, NEVERHANG circuit breaker that tracks timeout patterns and auto-recovers, and A.L.A.N. short-term learning system for retry detection and contextual feedback.', '@arktechnwa', 'development', 'Unknown', 4, 'https://github.com/arktechnwa/zsh-tool', NULL, 0, 'https://github.com/arktechnwa.png?size=128', '2026-03-09T05:21:01.912635+00:00'),
  ('arm', 'Arm', 'Provides specialized tools for Arm architecture development including semantic search across Arm documentation and learning resources, code migration analysis for C++/Python/Go/JavaScript/Java codebases, container architecture inspection with Docker image analysis, assembly performance analysis via LLVM-MCA, and system architecture information gathering. Integrates migrate-ease, Skopeo, check-image, and LLVM tooling to enable comprehensive Arm development workflows.', '@arm', 'cloud', 'Unknown', 57, 'https://github.com/arm/mcp', NULL, 0, 'https://github.com/arm.png?size=128', '2026-03-09T05:21:01.912654+00:00'),
  ('octopus-deploy', 'Octopus Deploy', 'A Model Context Protocol server for Octopus Deploy integration that provides tools for managing projects, releases, and deployments through natural language interactions. Built by Arman Nourifar using Python with FastMCP, httpx, and Docker support, it exposes five core tools: project details retrieval, latest release querying, release creation, deployment initiation, and deployment status monitoring across multiple Octopus Deploy spaces. The implementation handles authentication via API keys, supports both development and containerized deployment modes, and includes comprehensive error handling and logging, making it valuable for DevOps workflows where teams need to interact with Octopus Deploy infrastructure through AI assistants without manually navigating the web interface.', '@armanzeroeight', 'cloud', 'Unknown', 6, 'https://github.com/armanzeroeight/octopus-deploy-mcp-server', NULL, 0, 'https://github.com/armanzeroeight.png?size=128', '2026-03-09T05:21:01.912680+00:00'),
  ('armor-wallet', 'Armor Wallet', 'Comprehensive cryptocurrency portfolio management server integrating with Armor Wallet API. Provides 30+ tools covering wallet creation and organization, token swaps and transfers, DCA (Dollar Cost Averaging) strategies, limit orders, stop losses, staking operations, cross-chain bridging, and real-time market analysis. Features conditional DCA orders with market watchers and automated trading strategies. Built with FastMCP and proper async handling.', '@perfectdev10', 'ai-ml', 'Unknown', 1, 'https://github.com/perfectdev10/armor-crypto', NULL, 0, 'https://github.com/perfectdev10.png?size=128', '2026-03-09T05:21:01.912724+00:00'),
  ('gateway', 'Gateway', 'Gateway MCP serves as a bridge between AI assistants and various MCP services, enabling discovery and interaction with remote tools through a unified interface. Built with Python using FastMCP, it provides tools to discover available services from a registry, establish connections to both SSE-based MCP servers and HTTP APIs, and proxy tool calls to connected services. The implementation handles connection management, request routing, and response formatting, making it particularly valuable for workflows requiring access to multiple specialized services without leaving the conversation context.', '@arnavsurve', 'ai-ml', 'Unknown', 0, 'https://github.com/arnavsurve/gateway-mcp', 'gateway', 0, 'https://github.com/arnavsurve.png?size=128', '2026-03-09T05:21:01.912817+00:00'),
  ('soundcloud-downloader', 'SoundCloud Downloader', 'The SoundCloud Downloader MCP server enables Claude to download tracks, playlists, and user content from SoundCloud directly through conversation. Built by arnavsurve, this implementation wraps the popular scdl command-line tool in a FastMCP interface, providing granular control over download options including output location, download modes (all tracks, uploads, favorites, reposts, or playlists), track limits, and metadata handling. The server requires ffmpeg and the scdl package as dependencies, making it particularly valuable for users who want to archive or collect SoundCloud content without manually using command-line tools.', '@arnavsurve', 'ai-ml', 'Unknown', 5, 'https://github.com/arnavsurve/scdl-mcp', NULL, 0, 'https://github.com/arnavsurve.png?size=128', '2026-03-09T05:21:01.912876+00:00'),
  ('fastly-cdn', 'Fastly CDN', 'FastlyMCP is a Node.js-based server that enables AI assistants to interact with Fastly''s CDN services through the Model Context Protocol. It provides two main tools: one for making authenticated requests to the Fastly API for managing services, configurations, and cache operations, and another for executing Fastly CLI commands securely without exposing API keys. The implementation handles authentication automatically, logs operations for debugging, and includes comprehensive error handling, making it particularly useful for DevOps teams who want to manage their Fastly infrastructure through natural language conversations with AI assistants.', '@jackwrichards', 'development', 'Unknown', 7, 'https://github.com/jackwrichards/fastlymcp', NULL, 0, 'https://github.com/jackwrichards.png?size=128', '2026-03-09T05:21:01.912906+00:00'),
  ('unity', 'Unity', 'UnityMCP, developed by an unnamed author, is a Unity Editor plugin and server implementation that enables AI assistants to interact with Unity projects in real-time. Built with C# and TypeScript, it offers tools for retrieving editor state, executing C# commands, and accessing logs. The implementation focuses on providing a standardized interface for AI models to manipulate Unity scenes, objects, and project settings. It''s particularly useful for tasks like automated level design, asset management, or debugging assistance, allowing AI to directly influence Unity projects without requiring deep knowledge of the Unity API or editor interface.', '@jackwrichards', 'development', 'Unknown', 507, 'https://github.com/jackwrichards/unitymcp', NULL, 0, 'https://github.com/jackwrichards.png?size=128', '2026-03-09T05:21:01.912935+00:00'),
  ('magick-convert-imagemagick', 'Magick Convert (ImageMagick)', 'This MCP server, developed by aroglahcim, provides a bridge to ImageMagick''s command-line interface. Built with Node.js and leveraging the Model Context Protocol SDK, it enables AI assistants to execute ImageMagick commands for image processing and manipulation. The implementation focuses on providing a simple, standardized interface for running ImageMagick operations through MCP. It''s particularly useful for developers and content creators who want to integrate ImageMagick''s powerful image editing capabilities into AI workflows, enabling use cases such as automated image resizing, format conversion, and applying filters or effects without directly managing command-line interactions.', '@aroglahcim', 'productivity', 'Unknown', 3, 'https://github.com/aroglahcim/magick-mcp', 'magick-mcp', 3512, 'https://github.com/aroglahcim.png?size=128', '2026-03-09T05:21:01.912979+00:00'),
  ('tempo', 'Tempo', 'Integrates with Tempo blockchain (Stripe/Paradigm''s L1 network) to enable autonomous stablecoin payments, token swaps, and batch payroll processing. Supports gasless transactions via fee sponsorship, TIP-403 compliance whitelisting, and parallel transaction execution using nonceKeys. Includes token management features for minting, burning, and role-based access control with comprehensive audit logging.', '@arome3', 'ai-ml', 'Unknown', 6, 'https://github.com/arome3/tempo-mcp', NULL, 0, 'https://github.com/arome3.png?size=128', '2026-03-09T05:21:01.913011+00:00'),
  ('google-tasks', 'Google Tasks', 'Google Tasks MCP Server provides a bridge between Claude and Google Tasks, allowing users to manage task lists and tasks directly through Claude. Built with TypeScript and the Google Tasks API, it offers a comprehensive set of tools for creating, updating, and organizing tasks, including features like marking tasks as completed, reordering tasks, and clearing completed tasks. The implementation requires Google Cloud authentication and is designed for personal use, making it ideal for users who want to integrate their task management workflow with Claude''s conversational interface.', '@arpitbatra123', 'development', 'Unknown', 32, 'https://github.com/arpitbatra123/mcp-googletasks', NULL, 0, 'https://github.com/arpitbatra123.png?size=128', '2026-03-09T05:21:01.913039+00:00'),
  ('fildos', 'FilDOS', 'Built by Arqos Labs using TypeScript and the Synapse SDK, this server enables autonomous file storage capabilities on the Filecoin decentralized network through the FilDOS platform. It allows creation of folder NFTs for organization, uploads files to Filecoin storage with automatic tagging, and performs AI-powered semantic search across stored content. The implementation supports both local file uploads and base64-encoded content, integrates with smart contracts for ownership validation, and includes storage balance management, making it valuable for applications requiring persistent, decentralized file storage with intelligent retrieval capabilities.', '@arqoslabs', 'development', 'Unknown', 1, 'https://github.com/arqoslabs/fildos-mcp', NULL, 0, 'https://github.com/arqoslabs.png?size=128', '2026-03-09T05:21:01.913064+00:00'),
  ('octopus-energy-japan', 'Octopus Energy Japan', 'Connects to Octopus Energy Japan''s GraphQL API to retrieve electricity consumption data at 30-minute intervals with cost estimates, account and contract details, and postal code-based area information. Designed with privacy in mind, excluding personal address data from responses. Requires an active Octopus Energy Japan account with email, password, and account number credentials.', '@arrow2nd', 'development', 'Unknown', 1, 'https://github.com/arrow2nd/tako-mcp', NULL, 0, 'https://github.com/arrow2nd.png?size=128', '2026-03-09T05:21:01.913096+00:00'),
  ('artefact', 'Artefact', 'Revenue intelligence MCP: RFM analysis, 14.5-point ICP scoring, pipeline health. HubSpot.', '@alexboissav', 'aggregators', 'Unknown', 0, 'https://github.com/alexboissav/artefact-mcp-server', NULL, 0, 'https://github.com/alexboissav.png?size=128', '2026-03-09T05:21:01.913126+00:00'),
  ('gemini-cli', 'Gemini CLI', 'MCP server that bridges Gemini CLI with Claude Code by using code2prompt to extract codebase content and feeding it to Google''s Gemini models for architectural analysis. The implementation provides two core tools: comprehensive codebase review that analyzes entire projects with automatic exclusion of build artifacts and dependencies, and targeted analysis that focuses on specific files or folders for component-level insights. Built with TypeScript and designed to leverage Gemini''s large context window, it serves developers who want AI-powered code reviews, architectural assessments, and refactoring recommendations by combining the structured output of code2prompt with Gemini''s analytical capabilities for both full-project overviews and focused component analysis.', '@artegy', 'development', 'Unknown', 2, 'https://github.com/artegy/gemini-cli-mcp', NULL, 0, 'https://github.com/artegy.png?size=128', '2026-03-09T05:21:01.913157+00:00'),
  ('apple-shortcuts', 'Apple Shortcuts', 'Shortcuts MCP Server provides AI assistants with access to Apple Shortcuts functionality on macOS, enabling them to list, view, and run shortcuts through a simple interface. Built with Swift and the Model Context Protocol SDK, it offers three core tools for shortcut management along with corresponding prompts and resources. The server integrates directly with the macOS shortcuts command-line utility, making it particularly valuable for users who want to automate tasks or access their existing shortcuts library through natural language interactions in Cursor, Claude Desktop, or other MCP-enabled applications.', '@artemnovichkov', 'productivity', 'Unknown', 23, 'https://github.com/artemnovichkov/shortcuts-mcp-server', NULL, 0, 'https://github.com/artemnovichkov.png?size=128', '2026-03-09T05:21:01.913197+00:00'),
  ('figma-pro', 'Figma Pro', 'This MCP server provides AI-powered design-to-code conversion by integrating with the Figma API to retrieve design data, process designer comments, and download assets for automated implementation. Built by Artem Svitelskyi using TypeScript with comprehensive framework support for 10 platforms (React, Vue, Angular, Svelte, HTML, SwiftUI, UIKit, Electron, Tauri, NW.js), it offers tools for fetching Figma files with enhanced context processing, extracting design tokens and CSS properties, matching designer comments to specific nodes for implementation instructions, and downloading assets with intelligent path resolution. The implementation features advanced semantic analysis for UI component detection, accessibility information generation, responsive breakpoint extraction, and framework-specific optimization rules with implementation guidelines, making it valuable for developers who want AI assistance in accurately translating Figma designs into production-ready code across web, mobile, and desktop platforms.', '@artemsvit', 'development', 'Unknown', 27, 'https://github.com/artemsvit/figma-mcp-pro', 'figma-mcp-pro', 23356, 'https://github.com/artemsvit.png?size=128', '2026-03-09T05:21:01.913231+00:00'),
  ('openai-mcp', 'OpenAI MCP', 'This OpenAI-compatible MCP server implementation provides a bridge between AI assistants and large language models, supporting both OpenAI and Anthropic models. It features a robust architecture with prompt templating, streaming responses, efficient caching, and comprehensive error handling. The server exposes endpoints for health checks, context generation, and prompt management, while also offering advanced features like token usage tracking and Prometheus metrics integration. Ideal for applications requiring reliable, high-performance access to LLMs with the flexibility to customize prompts and manage response caching.', '@arthurcolle', 'ai-ml', 'Unknown', 36, 'https://github.com/arthurcolle/openai-mcp', NULL, 0, 'https://github.com/arthurcolle.png?size=128', '2026-03-09T05:21:01.913277+00:00'),
  ('mtg-deck-manager', 'MTG Deck Manager', 'The MTG Deck Manager MCP servers provide Magic: The Gathering enthusiasts with two specialized tools for card management and information retrieval. Built with Python using the FastMCP framework, the implementation consists of an MTG deck manager server that handles deck uploads, card drawing, hand management, mulligans, and sideboarding, alongside a Scryfall API integration server that enables card searches, random card retrieval, and detailed card information lookups. The servers can be configured in the Claude Desktop client, allowing users to seamlessly interact with their MTG decks and access comprehensive card data without leaving their conversation interface - perfect for deck testing, card research, and game simulation.', '@artillect', 'development', 'Unknown', 11, 'https://github.com/artillect/mtg-mcp-servers', NULL, 0, 'https://github.com/artillect.png?size=128', '2026-03-09T05:21:01.913308+00:00'),
  ('tearags', 'TeaRAGs', 'A high-performance semantic code search server built on Qdrant vector database with support for multiple embedding providers including Ollama, OpenAI, Cohere, and Voyage AI. Features AST-aware chunking using Tree-sitter for precise semantic boundaries, hybrid search combining dense vectors with BM25, and git metadata integration for filtering by authorship, code age, and churn rate. Designed for enterprise-scale codebases with incremental indexing that only reprocesses changed files.', '@artk0de', 'databases', 'Unknown', 10, 'https://github.com/artk0de/tearags-mcp', NULL, 0, 'https://github.com/artk0de.png?size=128', '2026-03-09T05:21:01.913319+00:00'),
  ('nyantify', 'Nyantify', 'Smart iOS notification system for AI coding agents that sends push notifications via Bark when tasks complete or require attention. Intelligently detects when developers are focused on their IDE (VS Code, Cursor, IntelliJ, etc.) across macOS, Windows, and Linux platforms and only sends notifications when they''re away from coding work. Features task tracking with configurable duration thresholds, cross-platform IDE detection using active window monitoring, and seamless integration with the Bark iOS app for reliable push delivery.', '@artrixtech', 'development', 'Unknown', 2, 'https://github.com/artrixtech/mcp-server-nyantify', NULL, 0, 'https://github.com/artrixtech.png?size=128', '2026-03-09T05:21:01.913343+00:00'),
  ('aws-sage', 'AWS Sage', 'AWS MCP is a server that enables AI assistants like Claude to interact with AWS environments through natural language. Built with Python using boto3 and the FastMCP framework, it provides tools for querying and modifying AWS resources across multiple profiles and regions. The implementation includes dynamic parsing of AWS operations from natural language, automatic execution of appropriate boto3 commands, and formatted table output for better readability. It supports both server mode for integration with Claude Desktop and CLI mode for command-line usage, making it ideal for users who need a more intuitive alternative to Amazon Q for AWS resource management.', '@arunsanna', 'cloud', 'Unknown', 5, 'https://github.com/arunsanna/aws-sage-mcp', NULL, 0, 'https://github.com/arunsanna.png?size=128', '2026-03-09T05:21:01.913361+00:00'),
  ('h-1b-job-search', 'H-1B Job Search', 'H1B Job Search MCP Server provides direct access to U.S. Department of Labor H-1B LCA disclosure data, enabling comprehensive job market analysis for visa sponsorship opportunities. Built by aryaminus using FastMCP and pandas, it automatically downloads and caches quarterly LCA data from DOL sources, then exposes tools for searching sponsoring companies by job role and location, analyzing company sponsorship statistics, identifying top sponsors by volume, and exporting filtered results to CSV. The implementation includes intelligent filtering to exclude staffing agencies, salary-based searches, natural language query processing through an ''ask'' tool, and robust data handling with multiple fallback URLs for government data sources, making it valuable for job seekers researching H-1B sponsorship opportunities, immigration attorneys analyzing employer patterns, and researchers studying visa sponsorship trends across different industries and locations.', '@aryaminus', 'search', 'Unknown', 14, 'https://github.com/aryaminus/h1b-job-search-mcp', NULL, 0, 'https://github.com/aryaminus.png?size=128', '2026-03-09T05:21:01.913475+00:00'),
  ('aifp', 'AIFP', 'Database-driven FP enforcement and project management for AI-maintained codebases.', '@aryanduntley', 'databases', 'Unknown', 0, 'https://github.com/aryanduntley/aifp', NULL, 0, 'https://github.com/aryanduntley.png?size=128', '2026-03-09T05:21:01.913485+00:00'),
  ('canvas-lms', 'Canvas LMS', 'Canvas MCP is a tool that enables AI agents to interact with Canvas LMS, allowing them to find relevant educational resources based on natural language queries. Built by Aryan Keluskar, it leverages the Canvas API to retrieve course information, modules, and module items, while using Google''s Gemini AI to analyze queries and determine the most relevant resources. The implementation includes caching mechanisms for improved performance and supports both text-based queries and image analysis to help students find learning materials without leaving their AI assistant conversation. It''s particularly valuable for educational workflows where students need quick access to course materials based on specific learning objectives or questions.', '@aryankeluskar', 'communication', 'Unknown', 11, 'https://github.com/aryankeluskar/canvas-mcp', NULL, 0, 'https://github.com/aryankeluskar.png?size=128', '2026-03-09T05:21:01.913525+00:00'),
  ('rize', 'Rize', 'Provides comprehensive integration with Rize.io''s time tracking platform through GraphQL API access. Supports full CRUD operations for clients, projects, and tasks, time entry creation with billable tracking, and detailed reporting capabilities including focus time, meeting time, and break time summaries. Enables both automatic session tracking and manual time logging workflows for freelancers, consultants, and teams.', '@asafdafna', 'productivity', 'Unknown', 1, 'https://github.com/asafdafna/rize.io-mcp', NULL, 0, 'https://github.com/asafdafna.png?size=128', '2026-03-09T05:21:01.913594+00:00'),
  ('asana', 'Asana', 'Bridge to the Asana project management system.', '@unknown', 'productivity', 'Unknown', 0, 'https://developers.asana.com/docs/using-asanas-model-control-protocol-mcp-server', NULL, 0, NULL, '2026-03-09T05:21:01.913609+00:00'),
  ('excel-explorer', 'Excel Explorer', 'Excel MCP server that provides comprehensive dataset exploration capabilities for Excel files (.xlsx and .xls) through pandas-powered data analysis tools. Built with FastMCP and featuring robust caching, it exposes tools for loading files, listing sheets, extracting schemas with semantic type detection, sampling data (head/tail/random), analyzing individual columns with statistics, and generating dataset summaries with data quality metrics. Designed for data analysts and researchers who need to quickly understand Excel datasets through conversational interfaces, supporting workflows like initial data exploration, column profiling, and data quality assessment without requiring manual spreadsheet navigation.', '@ash1998', 'ai-ml', 'Unknown', 2, 'https://github.com/ash1998/excel-mcp', NULL, 0, 'https://github.com/ash1998.png?size=128', '2026-03-09T05:21:01.913658+00:00'),
  ('discourse-search', 'Discourse Search', 'Discourse MCP Server implements the Model Context Protocol for searching posts on Discourse forums. Built by Sylvain CAU, it provides a single tool ''search_posts'' that allows AI assistants to query Discourse content using the discourse2 npm package. The server can be deployed via Docker or run directly with npx, requiring configuration of the Discourse API URL, key, and username as environment variables. This implementation is particularly useful for workflows where AI assistants need to reference or analyze content from Discourse forums without leaving the conversation interface.', '@ashdevfr', 'cloud', 'Unknown', 5, 'https://github.com/ashdevfr/discourse-mcp-server', '@ashdev/discourse-mcp-server', 4716, 'https://github.com/ashdevfr.png?size=128', '2026-03-09T05:21:01.913680+00:00'),
  ('duckduckgo', 'DuckDuckGo', 'The DuckDuckGo MCP Server provides web search capabilities through the DuckDuckGo search engine, enabling Claude to retrieve real-time information from the internet. Developed by Sylvain CAU, this Python-based implementation offers a simple yet effective search tool that returns structured results from DuckDuckGo queries. The server can be deployed either through UVX or Docker, making it easily accessible for Claude Desktop users who need to augment their AI assistant with current web information for research, fact-checking, or staying updated on recent events.', '@ashdevfr', 'cloud', 'Unknown', 5, 'https://github.com/ashdevfr/duckduckgo-mcp-server', 'ddg-mcp-server', 4241, 'https://github.com/ashdevfr.png?size=128', '2026-03-09T05:21:01.913701+00:00'),
  ('pushover', 'Pushover', 'This MCP server implementation provides integration with Pushover.net for sending notifications. Developed by Ashik Nesin, it leverages the @modelcontextprotocol/sdk to enable seamless communication between MCP clients and the Pushover service. The server offers a straightforward way to send push notifications to various devices, making it useful for applications that require real-time alerts or updates within the MCP ecosystem.', '@ashiknesin', 'ai-ml', 'Unknown', 34, 'https://github.com/ashiknesin/pushover-mcp', 'pushover-mcp', 1345, 'https://github.com/ashiknesin.png?size=128', '2026-03-09T05:21:01.913735+00:00'),
  ('douyin-xiaohongshu-content-extractor', 'Douyin & Xiaohongshu Content Extractor', 'An MCP server for extracting content from Douyin (TikTok China) and Xiaohongshu (Little Red Book) platforms, enabling downloading of videos, images, and text content from these Chinese social media platforms. Built with Python and featuring AI-powered watermark removal using Alibaba''s DashScope API, the implementation provides tools for content analysis, media extraction, and speech-to-text transcription. Useful for social media research, content curation, and cross-platform content analysis workflows involving Chinese social platforms.', '@ashinh', 'ai-ml', 'Unknown', 1, 'https://github.com/ashinh/dy-xhs-mcp-server', NULL, 0, 'https://github.com/ashinh.png?size=128', '2026-03-09T05:21:01.913779+00:00'),
  ('browser-automation', 'Browser Automation', 'The MCP Browser Agent enables Claude to interact with web browsers through the Model Context Protocol, built during the AGI House MCP Hackathon by Jaeyun and Ashley Ha. It leverages the browser-use library to provide a seamless integration that allows Claude to automate browser interactions, detect interactive elements, and execute planned actions. The implementation includes two main tools: one for retrieving the current browser state and planning context, and another for executing actions in the browser. This server runs on macOS with Python 3.12 and Google Chrome, making it ideal for users who want to give Claude the ability to navigate websites, fill forms, and interact with web content directly from conversations.', '@ashley-ha', 'ai-ml', 'Unknown', 7, 'https://github.com/ashley-ha/mcp-manus', NULL, 0, 'https://github.com/ashley-ha.png?size=128', '2026-03-09T05:21:01.913825+00:00'),
  ('spotify', 'Spotify', 'This Spotify MCP server implementation, developed by ashwanth1109, provides a comprehensive interface to control and interact with Spotify''s music streaming service. It leverages the Spotipy library to offer a wide range of functionalities including playlist management, playback control, track searching, and user data retrieval. The server is designed to work seamlessly with Cursor Composer, enabling AI assistants to control Spotify playback, manage playlists, and access user listening data. It''s particularly useful for creating voice-controlled music experiences, generating personalized playlists, and integrating Spotify functionality into AI-driven applications. The implementation focuses on ease of use and flexibility, supporting various Spotify API endpoints and offering detailed error handling for robust operation.', '@ashwanth1109', 'ai-ml', 'Unknown', 5, 'https://github.com/ashwanth1109/mcp-spotify', NULL, 0, 'https://github.com/ashwanth1109.png?size=128', '2026-03-09T05:21:01.913885+00:00'),
  ('congress-gov', 'Congress.gov', 'This MCP server provides complete access to the Congress.gov API for retrieving US legislative data, built using Python with FastMCP and offering 19 specialized tools covering bills, amendments, summaries, member information, committee data, voting records, congressional records, and communications. The implementation includes comprehensive parameter validation, pagination support, and proper error handling across all endpoints, with tools organized by legislative domain (bills, committees, records, etc.) and supporting both broad queries and specific document retrieval by ID or number. It''s valuable for political research, legislative tracking, policy analysis workflows, and building AI assistants that need programmatic access to official US Congress data including bill text, voting patterns, committee activities, and member information.', '@ashwinsundar', 'development', 'Unknown', 19, 'https://github.com/ashwinsundar/congress_gov_mcp', NULL, 0, 'https://github.com/ashwinsundar.png?size=128', '2026-03-09T05:21:01.913919+00:00'),
  ('ask-human', 'Ask Human', 'This MCP server enables AI agents to escalate questions to humans through a markdown file-based workflow, preventing hallucinations by providing a direct human-in-the-loop mechanism. Built by Mason Yarbrough for Kallro Inc. development workflows, it writes AI questions to a markdown file that humans edit with answers, using file watching to detect responses and return them to the AI agent. The implementation features cross-platform file locking, atomic operations, question timeout handling, file rotation for large logs, and robust markdown parsing, making it valuable for development scenarios where AI assistants need authoritative human input on decisions like database passwords, API endpoints, or architectural choices rather than generating potentially incorrect responses.', '@masony817', 'databases', 'Unknown', 150, 'https://github.com/masony817/ask-human-mcp', 'ask-human-mcp', 3082, 'https://github.com/masony817.png?size=128', '2026-03-09T05:21:01.913942+00:00'),
  ('doc-scraper-jina-ai', 'Doc Scraper (Jina.ai)', 'This Doc Scraper MCP server converts web documentation into markdown format using Jina.ai''s API. It provides a single tool, ''scrape_docs'', which takes a URL and output path as input, fetches the web page, converts it to clean markdown, and saves the result. Built with Python and leveraging libraries like aiohttp and pydantic, it offers a straightforward solution for automating documentation conversion. The implementation focuses on simplicity and ease of use, making it ideal for developers, technical writers, or content managers who need to quickly transform online documentation into a more portable markdown format for various purposes such as content migration, offline reading, or integration with markdown-based systems.', '@askjohngeorge', 'ai-ml', 'Unknown', 8, 'https://github.com/askjohngeorge/mcp-doc-scraper', NULL, 0, 'https://github.com/askjohngeorge.png?size=128', '2026-03-09T05:21:01.913988+00:00'),
  ('argocd', 'ArgoCD', 'Enables natural language control of ArgoCD GitOps workflows including application lifecycle management, multi-cluster deployments, progressive delivery patterns like canary and blue-green, disaster recovery operations, and real-time monitoring of application health and sync status.', '@asklokesh', 'cloud', 'Unknown', 0, 'https://github.com/asklokesh/argocd-mcp-server', NULL, 0, 'https://github.com/asklokesh.png?size=128', '2026-03-09T05:21:01.914005+00:00'),
  ('chanty', 'Chanty', 'Enables AI assistants to interact with the Chanty team collaboration platform. Provides access to team messaging, channels, and task management features through the Chanty API with support for multiple authentication methods and rate limiting.', '@asklokesh', 'communication', 'Unknown', 0, 'https://github.com/asklokesh/chanty-mcp-server', NULL, 0, 'https://github.com/asklokesh.png?size=128', '2026-03-09T05:21:01.914026+00:00'),
  ('freshbooks', 'FreshBooks', 'Provides comprehensive FreshBooks API coverage for accounting operations including invoicing, expense tracking, client management, and financial reporting. Features enterprise-ready capabilities with rate limiting, retry logic, and asynchronous support for improved performance.', '@asklokesh', 'ai-ml', 'Unknown', 0, 'https://github.com/asklokesh/freshbooks-mcp-server', NULL, 0, 'https://github.com/asklokesh.png?size=128', '2026-03-09T05:21:01.914057+00:00'),
  ('hootsuite', 'Hootsuite', 'Provides integration with Hootsuite''s social media management platform. Features comprehensive API coverage, multiple authentication methods, rate limiting, error handling with retry logic, and asynchronous support for optimized performance.', '@asklokesh', 'ai-ml', 'Unknown', 0, 'https://github.com/asklokesh/hootsuite-mcp-server', NULL, 0, 'https://github.com/asklokesh.png?size=128', '2026-03-09T05:21:01.914085+00:00'),
  ('power-bi', 'Power BI', 'Provides comprehensive Power BI API coverage for AI assistants. Supports multiple authentication approaches, enterprise-grade rate limiting, robust error handling with retry mechanisms, and asynchronous processing for improved performance.', '@asklokesh', 'communication', 'Unknown', 0, 'https://github.com/asklokesh/powerbi-mcp-server', NULL, 0, 'https://github.com/asklokesh.png?size=128', '2026-03-09T05:21:01.914108+00:00'),
  ('quickbooks', 'QuickBooks', 'Provides comprehensive QuickBooks API coverage for accounting and financial management. Features multiple authentication methods, enterprise-grade rate limiting, full error handling with retry mechanisms, and asynchronous support for improved performance.', '@asklokesh', 'communication', 'Unknown', 1, 'https://github.com/asklokesh/quickbooks-mcp-server', NULL, 0, 'https://github.com/asklokesh.png?size=128', '2026-03-09T05:21:01.914131+00:00'),
  ('rundeck', 'Rundeck', 'Provides comprehensive Rundeck API coverage for interacting with runbook automation and job scheduling capabilities. Features multiple authentication methods, enterprise-ready rate limiting, full error handling with retry logic, and async support for improved performance.', '@asklokesh', 'ai-ml', 'Unknown', 0, 'https://github.com/asklokesh/rundeck-mcp-server', NULL, 0, 'https://github.com/asklokesh.png?size=128', '2026-03-09T05:21:01.914159+00:00'),
  ('tableau', 'Tableau', 'Enables AI applications to interact with Tableau instances through the Tableau API. Provides comprehensive API coverage with support for multiple authentication methods, enterprise-grade rate limiting, error handling with retry logic, and asynchronous operations for improved performance.', '@asklokesh', 'ai-ml', 'Unknown', 0, 'https://github.com/asklokesh/tableau-mcp-server', NULL, 0, 'https://github.com/asklokesh.png?size=128', '2026-03-09T05:21:01.914187+00:00'),
  ('uipath', 'UiPath', 'Provides comprehensive UiPath API coverage for robotic process automation workflows. Supports multiple authentication methods, enterprise-ready rate limiting, complete error handling with retry logic, and asynchronous operations for improved performance.', '@asklokesh', 'ai-ml', 'Unknown', 0, 'https://github.com/asklokesh/uipath-mcp-server', NULL, 0, 'https://github.com/asklokesh.png?size=128', '2026-03-09T05:21:01.914216+00:00'),
  ('zoho-crm', 'Zoho CRM', 'Provides seamless integration between Zoho CRM and AI applications. Supports OAuth 2.0 authentication with automatic token refresh, comprehensive CRM operations including leads, contacts, and deals management, built-in rate limiting, retry logic with exponential backoff, and robust error handling.', '@asklokesh', 'ai-ml', 'Unknown', 0, 'https://github.com/asklokesh/zoho-crm-mcp-server', NULL, 0, 'https://github.com/asklokesh.png?size=128', '2026-03-09T05:21:01.914244+00:00'),
  ('agent-never-give-up', 'Agent Never Give Up', 'Provides metacognitive protocols that help AI coding agents autonomously recover when blocked by circular reasoning, repeated failed debugging, missing requirements, analysis paralysis, or conflicting constraints. Returns step-by-step guidance for common blocking situations without requiring human intervention.', '@askman-dev', 'development', 'Unknown', 6, 'https://github.com/askman-dev/agent-never-give-up-mcp', NULL, 0, 'https://github.com/askman-dev.png?size=128', '2026-03-09T05:21:01.914266+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('flutter', 'Flutter', 'This MCP server implementation provides a bridge to the Model Context Protocol SDK for Flutter applications. Developed by asmagin, it offers a TypeScript-based server that can be easily integrated into Flutter projects. The server utilizes the @modelcontextprotocol/sdk package and Zod for data validation. It''s designed to facilitate communication between Flutter clients and MCP-compatible AI models, enabling developers to incorporate advanced AI capabilities into their mobile applications. The implementation focuses on type safety, modularity, and ease of use, making it suitable for both development and production environments. It''s particularly useful for Flutter developers looking to leverage MCP''s capabilities in their mobile apps, supporting use cases like natural language processing, image recognition, or other AI-driven features.', '@asmagin', 'development', 'Unknown', 2, 'https://github.com/asmagin/mcp-server-flutter', NULL, 0, 'https://github.com/asmagin.png?size=128', '2026-03-09T05:21:01.914295+00:00'),
  ('flux-ao-arweave', 'Flux (AO & Arweave)', 'Flux is an AI-based AO tool that integrates with existing AI development environments like Cursor, Windsurf, and Claude through the Model Context Protocol. Built on TypeScript and Node.js, it enables developers to run, create, and test AO code and blueprints using natural language commands. The implementation provides a bridge to the Arweave and AO ecosystems, allowing for process spawning, message handling, Lua code execution, and blueprint management without requiring deep technical knowledge of the underlying systems.', '@asrvd', 'development', 'Unknown', 3, 'https://github.com/asrvd/flux', NULL, 0, 'https://github.com/asrvd.png?size=128', '2026-03-09T05:21:01.914321+00:00'),
  ('gpt-researcher', 'GPT Researcher', 'GPT Researcher MCP Server provides a bridge between AI assistants and web research capabilities, enabling real-time information gathering and report generation. Developed by Assaf Elovic, this implementation leverages the GPT Researcher library to offer tools for conducting deep research, performing quick searches, generating reports, and retrieving source information. The server exposes its functionality through well-defined tools and a resource endpoint that allows direct access to research context without explicit function calls. Built with FastMCP and Python, it includes features like research caching, custom report generation, and comprehensive source tracking, making it ideal for AI assistants that need to access current web information for tasks like answering time-sensitive questions, creating research reports, or providing evidence-based responses.', '@assafelovic', 'productivity', 'Unknown', 327, 'https://github.com/assafelovic/gptr-mcp', NULL, 0, 'https://github.com/assafelovic.png?size=128', '2026-03-09T05:21:01.914371+00:00'),
  ('assistant-ui', 'Assistant UI', 'The MCP server tools have been designed to allow an agent to query the specific information it needs to complete an assistant-ui related task - for example: implementing chat components, integrating with different runtimes, understanding component architecture, and troubleshooting issues.', '@assistant-ui', 'communication', 'Unknown', 8749, 'https://github.com/assistant-ui/assistant-ui', '@assistant-ui/react', 5312422, 'https://github.com/assistant-ui.png?size=128', '2026-03-09T05:21:01.914402+00:00'),
  ('aster-finance', 'Aster Finance', 'Aster Finance API integration that provides comprehensive access to cryptocurrency futures trading data through 12 specialized tools for market analysis and monitoring. Built by kukapay, the implementation connects to the Aster Finance API (fapi.asterdex.com) to fetch kline/candlestick data, index and mark price information, premium index data, funding rates, 24-hour price statistics, order book data, and recent trades across various trading pairs. All data is returned as formatted Markdown tables using pandas for processing, making it valuable for traders and analysts who need real-time crypto derivatives market data for technical analysis, risk management, and automated trading strategies without manually interfacing with the exchange API.', '@kukapay', 'ai-ml', 'Unknown', 5, 'https://github.com/kukapay/aster-info-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:01.914454+00:00'),
  ('ast-grep', 'ast-grep', 'ast-grep MCP provides a bridge to the ast-grep code search tool, enabling AI assistants to find code patterns in projects using abstract syntax tree matching. The implementation exposes a single tool that accepts a pattern, project folder, and optional language parameter, then executes the ast-grep CLI command and returns the results as structured JSON. This server is particularly valuable for developers who want to leverage AI assistants for code analysis, pattern matching, and refactoring tasks without leaving their development environment.', '@ast-grep', 'development', 'Unknown', 353, 'https://github.com/ast-grep/ast-grep-mcp', NULL, 0, 'https://github.com/ast-grep.png?size=128', '2026-03-09T05:21:01.914479+00:00'),
  ('pokeapi', 'PokeAPI', 'Provides tools to fetch detailed Pokémon information from PokeAPI, including species data, moves, items, abilities, types, and game mechanics. Covers 47 different data endpoints across Pokémon attributes, battle mechanics, items, encounters, berries, contests, and evolution chains.', '@asthanaji05', 'development', 'Unknown', 1, 'https://github.com/asthanaji05/mcp_pokemon', NULL, 0, 'https://github.com/asthanaji05.png?size=128', '2026-03-09T05:21:01.914501+00:00'),
  ('pygithub', 'PyGithub', 'PyGithub MCP Server provides a bridge between AI assistants and the GitHub API through PyGithub, enabling operations like managing issues, repositories, and pull requests. The implementation follows a modular architecture with domain-specific schemas, converters, and operations that handle authentication, rate limiting, and error recovery automatically. Built with a focus on reliability and maintainability, it includes comprehensive test coverage with both unit and integration tests, making it particularly valuable for AI-assisted software development workflows that require GitHub integration.', '@astromined', 'development', 'Unknown', 1, 'https://github.com/astromined/pygithub-mcp-server', NULL, 0, 'https://github.com/astromined.png?size=128', '2026-03-09T05:21:01.914524+00:00'),
  ('opendota', 'OpenDota', 'This MCP server implementation provides a bridge to the OpenDota API, enabling AI assistants to access real-time Dota 2 statistics, match data, and player information. Developed by Anthony Susevski, it offers a wide range of tools for retrieving player profiles, match details, hero statistics, and professional player data. The server is designed for use cases requiring in-depth Dota 2 analytics, such as game analysis, player performance tracking, or esports research applications.', '@asusevski', 'ai-ml', 'Unknown', 7, 'https://github.com/asusevski/opendota-mcp-server', NULL, 0, 'https://github.com/asusevski.png?size=128', '2026-03-09T05:21:01.914563+00:00'),
  ('github-chat', 'GitHub Chat', 'GitHub Chat MCP server enables AI assistants to analyze and query GitHub repositories through a simple interface. Developed by AsyncFuncAI, it provides tools for indexing repositories and asking detailed questions about codebases, leveraging the GitHub Chat API to retrieve contextual information and source references. The implementation is built with Python using the FastMCP framework, supports both direct installation and containerized deployment, and is particularly valuable for developers seeking to understand unfamiliar repositories, analyze code architecture, or explore technical implementations without manually navigating through files.', '@asyncfuncai', 'development', 'Unknown', 85, 'https://github.com/asyncfuncai/github-chat-mcp', 'github-chat-mcp', 5205, 'https://github.com/asyncfuncai.png?size=128', '2026-03-09T05:21:01.914587+00:00'),
  ('trackor', 'Trackor', 'Trackor provides comprehensive expense tracking with SQLite storage, offering tools for adding, updating, deleting, and querying expense records. Features include categorization with predefined categories (Food, Transportation, Housing, etc.), date-range filtering, statistical analysis with monthly summaries and category breakdowns, and data export in JSON and CSV formats. Can be deployed locally or through FastMCP Cloud with remote access via proxy configuration.', '@at0mxploit', 'databases', 'Unknown', 3, 'https://github.com/at0mxploit/trackor', NULL, 0, 'https://github.com/at0mxploit.png?size=128', '2026-03-09T05:21:01.914598+00:00'),
  ('fastmcp-pdftools', 'FastMCP PDFTools', 'Provides PDF file reading and text extraction capabilities through a simple interface. Built with the FastMCP framework and configured for integration with Claude Desktop. Uses Python-based PDF processing libraries to enable document analysis workflows.', '@atarkowska', 'ai-ml', 'Unknown', 1, 'https://github.com/atarkowska/fastmcp-pdftools', NULL, 0, 'https://github.com/atarkowska.png?size=128', '2026-03-09T05:21:01.914625+00:00'),
  ('fastmcp-sql-tools', 'FastMCP SQL Tools', 'A FastMCP-based server that provides SQL database access with support for PostgreSQL, MySQL, and SQLite. Features include listing tables, retrieving schema information, executing queries, and running read-only SELECT statements with safety validation. Automatically detects the database type based on the DATABASE_URL environment variable.', '@atarkowska', 'databases', 'Unknown', 1, 'https://github.com/atarkowska/fastmcp-sqltools', NULL, 0, 'https://github.com/atarkowska.png?size=128', '2026-03-09T05:21:01.914636+00:00'),
  ('all-in-one', 'All-in-One', 'This MCP server implementation, developed by athapong, integrates multiple services including GitLab, Jira, Confluence, YouTube, and Google AI. It provides AI-powered search capabilities and various utility tools for development workflows. The server offers a wide range of functionalities, from managing GitLab projects and issues to searching web content and executing command-line scripts, making it suitable for complex software development and project management tasks.', '@athapong', 'development', 'Unknown', 34, 'https://github.com/athapong/aio-mcp', NULL, 0, 'https://github.com/athapong.png?size=128', '2026-03-09T05:21:01.914658+00:00'),
  ('argus-gitlab', 'Argus (GitLab)', 'This MCP server implementation, named Argus, provides tools for analyzing GitLab repositories and performing security assessments. Developed by Athapong Kaewsalapoom, it offers capabilities such as retrieving repository structures, reading important files, and listing branches. Built with Python and leveraging libraries like GitPython and FastMCP, Argus focuses on secure GitLab integration and easy deployment via Docker. It is particularly useful for DevOps and security teams needing to automate repository analysis, conduct code reviews, or integrate GitLab operations into AI-assisted workflows. The implementation''s modular design allows for easy extension of its functionality to cover additional GitLab-related tasks.', '@athapong', 'cloud', 'Unknown', 1, 'https://github.com/athapong/argus', 'argus', 0, 'https://github.com/athapong.png?size=128', '2026-03-09T05:21:01.914686+00:00'),
  ('stripe', 'Stripe', 'This MCP implementation, developed for Stripe integration, provides a streamlined interface for interacting with Stripe''s payment processing API. Built using Python and leveraging the MCP SDK, it enables AI assistants to perform various payment-related operations such as transaction processing, customer management, and subscription handling. The implementation focuses on simplifying complex payment workflows, making it easier to incorporate Stripe''s functionality into AI-driven financial applications. It''s particularly useful for businesses and developers who want to automate payment processes, integrate Stripe services into their AI systems, or build intelligent financial management tools without directly managing API calls to Stripe.', '@atharvagupta2003', 'development', 'Unknown', 45, 'https://github.com/atharvagupta2003/mcp-stripe', NULL, 0, 'https://github.com/atharvagupta2003.png?size=128', '2026-03-09T05:21:01.914765+00:00'),
  ('athena-protocol', 'Athena Protocol', 'Intelligent validation layer for AI coding agents that provides expert review before code changes are implemented. Offers thinking validation, impact analysis, assumption checking, dependency mapping, and thinking optimization across multiple LLM providers including OpenAI, Anthropic, Google, and others.', '@n0zer0d4y', 'development', 'Unknown', 6, 'https://github.com/n0zer0d4y/athena-protocol', NULL, 0, 'https://github.com/n0zer0d4y.png?size=128', '2026-03-09T05:21:01.914784+00:00'),
  ('ghidra-bridge', 'Ghidra Bridge', 'Enables interaction with the Ghidra reverse engineering platform through a local HTTP server that exposes key analysis capabilities. The implementation consists of a Ghidra Java plugin that starts an HTTP server on localhost:17664 and a Python MCP server that translates requests, providing tools for health checks, program information retrieval, function listing and renaming, binary patching, and comment management. Built for reverse engineers who want to integrate assistance into their workflow, allowing natural language interaction with Ghidra''s program analysis features without requiring direct API knowledge.', '@athukarad109', 'aggregators', 'Unknown', 2, 'https://github.com/athukarad109/ghidra-mcp', NULL, 0, 'https://github.com/athukarad109.png?size=128', '2026-03-09T05:21:01.914882+00:00'),
  ('tesouro-direto', 'Tesouro Direto', 'Tesouro Direto MCP Server provides real-time access to Brazil''s Treasury Direct (Tesouro Direto) bond market data through a Model Context Protocol interface. Developed by AtilioA under the AGPL-3.0 license, it offers tools for retrieving market status, searching bonds by type and maturity date, and accessing detailed bond information. The implementation features efficient caching with a 10-minute expiration to reduce API load while maintaining data freshness. Built with TypeScript and Node.js, it enables AI assistants to help users analyze Brazilian government bonds, compare investment rates, and make informed financial decisions without requiring direct interaction with the official Tesouro Direto website.', '@atilioa', 'development', 'Unknown', 5, 'https://github.com/atilioa/tesouro-direto-mcp', 'tesouro-direto-mcp', 4922, 'https://github.com/atilioa.png?size=128', '2026-03-09T05:21:01.914916+00:00'),
  ('atla', 'Atla', 'Atla MCP Server provides a standardized interface for LLMs to interact with the Atla API for state-of-the-art LLMJ evaluation. It offers tools for evaluating LLM responses against single or multiple criteria, returning both numerical scores and textual critiques. Built with Python 3.11 and distributed under the MIT license, this server enables AI assistants to leverage Atla''s evaluation models for assessing response quality across various dimensions. The implementation supports multiple connection methods including OpenAI Agents SDK, Claude Desktop, and Cursor, making it accessible for developers working with different MCP clients.', '@atla-ai', 'ai-ml', 'Unknown', 17, 'https://github.com/atla-ai/atla-mcp-server', NULL, 0, 'https://github.com/atla-ai.png?size=128', '2026-03-09T05:21:01.914959+00:00'),
  ('atlan-data-catalog', 'Atlan Data Catalog', 'Atlan MCP Server provides a bridge between AI agents and Atlan data catalog services through a Python implementation using the pyatlan SDK. The server exposes tools for searching assets with flexible conditions, retrieving assets using DSL queries, traversing lineage relationships, and updating asset attributes like descriptions and certificate status. Built with a robust error handling system and comprehensive logging, it enables AI assistants to interact with enterprise data catalogs for use cases such as data discovery, lineage analysis, and metadata management. The implementation uses environment variables for configuration and supports deployment through Claude Desktop or the MCP Inspector for testing.', '@atlanhq', 'development', 'Unknown', 27, 'https://github.com/atlanhq/agent-toolkit/tree/HEAD/modelcontextprotocol', NULL, 0, 'https://github.com/atlanhq.png?size=128', '2026-03-09T05:21:01.914990+00:00'),
  ('atlas-pipeline', 'Atlas Pipeline', 'Provides a multi-stage AI development pipeline for IDE integration. Offers developer tools spanning code analysis, refactoring suggestions, security scanning, performance profiling, test generation, and architectural guidance. Includes frontend-specific utilities for CSS architecture, animation generation, and performance diagnostics. Works with Cursor, Windsurf, Claude Desktop, GitHub Copilot, and VS Code.', '@iamnishant51', 'development', 'Unknown', 0, 'https://github.com/iamnishant51/atlas-mcp-server', NULL, 0, 'https://github.com/iamnishant51.png?size=128', '2026-03-09T05:21:01.915010+00:00'),
  ('jira-confluence', 'Jira & Confluence', 'Summarize work, create issues or pages, and perform multi-step actions, all while keeping data secure and within permissioned boundaries using Atlassian''s product suite.', '@unknown', 'productivity', 'Unknown', 0, 'https://www.atlassian.com/blog/announcements/remote-mcp-server', NULL, 0, NULL, '2026-03-09T05:21:01.915031+00:00'),
  ('atlassian-confluence', 'Atlassian Confluence', 'A TypeScript-based MCP server for Atlassian Confluence integration that provides AI assistants with direct access to Confluence spaces, pages, and content. It offers tools for listing spaces, retrieving page details, and performing advanced searches using Confluence Query Language (CQL), all while converting content to Markdown format for optimal readability. The implementation includes robust error handling, pagination support, and a CLI interface for direct interaction, making it particularly valuable for teams that need to connect Claude or other AI systems to their Confluence knowledge bases without leaving the conversation interface.', '@aashari', 'development', 'Unknown', 50, 'https://github.com/aashari/mcp-server-atlassian-confluence', '@aashari/mcp-server-atlassian-confluence', 53091, 'https://github.com/aashari.png?size=128', '2026-03-09T05:21:01.915061+00:00'),
  ('atlassian-dc', 'Atlassian DC', 'MCP server for Atlassian Jira Data Center - search, view, and create issues', '@b1ff', 'productivity', 'Unknown', 53, 'https://github.com/b1ff/atlassian-dc-mcp', NULL, 0, 'https://github.com/b1ff.png?size=128', '2026-03-09T05:21:01.915079+00:00'),
  ('atlas-vector-search-docs', 'Atlas Vector Search Docs', 'A vector search system for document retrieval using MongoDB Atlas Vector Search and Voyage AI embeddings, created by Pat Wendorf from MongoDB. The implementation ingests and chunks markdown documents with hierarchical headers, generates contextual embeddings using Voyage AI''s API, and stores documents with embeddings in MongoDB collections with parent-child relationships. Built with FastMCP for integration with AI assistants like Claude Desktop, it enables semantic search across technical documentation and supports configurable vector dimensions, automatic quantization, and pre-filtering capabilities for efficient document discovery and retrieval-augmented generation workflows.', '@patw', 'databases', 'Unknown', 2, 'https://github.com/patw/avs-docs-mcp', NULL, 0, 'https://github.com/patw.png?size=128', '2026-03-09T05:21:01.915093+00:00'),
  ('ios-simulator', 'iOS Simulator', 'A TypeScript-based MCP server for interacting with iOS simulators, built using the Appium iOS Simulator library. Provides a robust session management approach for creating, booting, and controlling iOS simulators programmatically, with flexible device and OS version selection. Useful for AI assistants and testing scenarios that require dynamic iOS simulator interactions.', '@atom2ueki', 'development', 'Unknown', 42, 'https://github.com/atom2ueki/mcp-server-ios-simulator', NULL, 0, 'https://github.com/atom2ueki.png?size=128', '2026-03-09T05:21:01.915116+00:00'),
  ('roadrecon-analyzer', 'ROADrecon Analyzer', 'ROADrecon MCP Server provides access to Azure AD security data collected by ROADrecon through a standardized protocol, enabling AI assistants to analyze tenant security posture. The server exposes comprehensive Azure AD data including users, groups, applications, and service principals, while offering specialized security analysis tools for identifying privileged users, analyzing MFA status, detecting stale accounts, and evaluating PIM implementation. Built with Python using FastMCP, it integrates with a ROADrecon API instance to facilitate security assessments and vulnerability identification in Azure AD environments.', '@atomicchonk', 'cloud', 'Unknown', 48, 'https://github.com/atomicchonk/roadrecon_mcp_server', NULL, 0, 'https://github.com/atomicchonk.png?size=128', '2026-03-09T05:21:01.915136+00:00'),
  ('auto-om', 'Auto-OM', 'Auto-OM is a Linux server automation MCP server that provides remote operations management through SSH connections. It offers tools organized across eight categories: file management, text processing, system monitoring, process management, network operations, compression, and package management. The implementation enforces strict non-root privilege constraints and security validation to prevent dangerous operations, while supporting both stdio and HTTP transport modes with automatic package manager detection (apt, yum, dnf).', '@atoncooper', 'ai-ml', 'Unknown', 3, 'https://github.com/atoncooper/auto-om', NULL, 0, 'https://github.com/atoncooper.png?size=128', '2026-03-09T05:21:01.915178+00:00'),
  ('mozisu-character-counter', 'Mozisu Character Counter', 'Mozisu MCP Server is a Go-based implementation that provides character counting functionality for text, with special handling for multi-byte characters like Japanese text and emojis. The server processes both total character count and non-whitespace character count, returning structured results through a clean API. Built with performance in mind, it uses Go''s unicode package for accurate character classification and offers configurable server settings through JSON configuration. This implementation is particularly useful for applications requiring accurate text metrics across different languages and character sets.', '@atotti', 'development', 'Unknown', 4, 'https://github.com/atotti/mozisu-mcp-server', NULL, 0, 'https://github.com/atotti.png?size=128', '2026-03-09T05:21:01.915204+00:00'),
  ('fashion-recommendation-system', 'Fashion Recommendation System', 'FastMCP_RecSys is a clothing recommendation system that uses CLIP (Contrastive Language-Image Pretraining) to analyze and classify fashion images. Built with a FastAPI backend and React frontend, it extracts clothing attributes like style, color, and fabric from uploaded images, then generates personalized recommendations based on detected tags and user behavior. The system stores clothing items and their metadata in MongoDB, making it particularly useful for e-commerce platforms seeking to enhance user experience through AI-powered fashion recommendations.', '@attarmau', 'databases', 'Unknown', 1, 'https://github.com/attarmau/styleclip', NULL, 0, 'https://github.com/attarmau.png?size=128', '2026-03-09T05:21:01.915218+00:00'),
  ('heart', 'Heart', 'Heart MCP server provides a basic foundation for building MCP-enabled applications using Bun and TypeScript. Built with the @modelcontextprotocol/sdk, it establishes a stdio transport connection and exposes a minimal server configuration that can be extended with custom resources and tools. Useful as a starting point for developers looking to create their own MCP server implementations.', '@atuinturtle', 'development', 'Unknown', 0, 'https://github.com/atuinturtle/heart-mcp-server', NULL, 0, 'https://github.com/atuinturtle.png?size=128', '2026-03-09T05:21:01.915241+00:00'),
  ('audiense-insights', 'Audiense Insights', 'This MCP client, developed by an unspecified author, enables integration with Audiense''s audience insights platform. Built with TypeScript and leveraging the Model Context Protocol SDK, it provides tools for accessing Audiense''s API to retrieve audience data and insights. The implementation focuses on simplifying authentication and data retrieval from Audiense, offering functionality to query audience information. It includes optional integration with the Twitter API for enhanced capabilities. This client is particularly useful for applications requiring programmatic access to audience analytics, enabling use cases such as targeted marketing campaigns, social media strategy development, and demographic analysis without directly handling API authentication complexities.', '@audienseco', 'development', 'Unknown', 17, 'https://github.com/audienseco/mcp-audiense-insights', NULL, 0, 'https://github.com/audienseco.png?size=128', '2026-03-09T05:21:01.915270+00:00'),
  ('audioscrape-audio-intelligence', 'Audioscrape Audio Intelligence', 'The audio intelligence layer for AI assistants. Audioscrape provides semantic search across over one million hours of podcast content, interviews, and talks. Search by speaker, topic, or keyword to find specific moments within audio with timestamped transcriptions. Features include trending topic extraction, knowledge graph search, real-time audio monitoring, and curated clips from podcast communities.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://mcp.audioscrape.com', NULL, 0, NULL, '2026-03-09T05:21:01.915304+00:00'),
  ('audio-transcriber-openai-whisper', 'Audio Transcriber (OpenAI Whisper)', 'Audio transcription server that provides speech-to-text capabilities using OpenAI''s Whisper API. Built with TypeScript and the MCP SDK, it exposes a tool for transcribing audio files with configurable language settings and optional file saving. Particularly valuable for users who need to convert spoken content to text through AI assistants while maintaining control over the transcription process and output format.', '@ichigo3766', 'development', 'Unknown', 9, 'https://github.com/ichigo3766/audio-transcriber-mcp', 'audio-transcriber', 264, 'https://github.com/ichigo3766.png?size=128', '2026-03-09T05:21:01.915329+00:00'),
  ('alphafold', 'AlphaFold', 'The AlphaFold MCP Server provides comprehensive access to DeepMind''s AlphaFold Protein Structure Database through 22 specialized tools covering structure retrieval, confidence analysis, batch processing, and comparative analysis. Built by Augmented Nature, it integrates directly with the AlphaFold API to enable protein structure searches by UniProt ID or organism, download structures in multiple formats (PDB, CIF, mmCIF), analyze per-residue confidence scores, and export data for visualization tools like PyMOL and ChimeraX. The server is particularly valuable for structural biology research, protein analysis workflows, and bioinformatics applications where users need programmatic access to high-quality protein structure predictions without manually navigating the AlphaFold database interface.', '@augmented-nature', 'databases', 'Unknown', 31, 'https://github.com/augmented-nature/alphafold-mcp-server', NULL, 0, 'https://github.com/augmented-nature.png?size=128', '2026-03-09T05:21:01.915340+00:00'),
  ('bioportal', 'BioPortal', 'Provides access to the BioOntology API for searching, annotating, and exploring over 1,200 biological ontologies including medical terminologies like NCIT, DOID, and MESH. Built by Moudather Chelbi from Augmented Nature using TypeScript and the Model Context Protocol SDK, the implementation offers nine specialized tools covering term search with advanced filtering, text annotation with configurable parameters, ontology recommendations with customizable weights, batch processing capabilities, and analytics data retrieval. Features comprehensive input validation, robust error handling, resource templates for direct data access, and support for all ontologies available in BioPortal, making it valuable for bioinformatics researchers analyzing biological data, medical professionals annotating clinical texts, and developers building applications that require semantic understanding of biological and medical terminology.', '@augmented-nature', 'development', 'Unknown', 8, 'https://github.com/augmented-nature/bioontology-mcp-server', NULL, 0, 'https://github.com/augmented-nature.png?size=128', '2026-03-09T05:21:01.915375+00:00'),
  ('ensembl', 'Ensembl', 'Production-ready MCP server built by Augmented Nature that provides AI assistants with complete access to Ensembl''s genomic database through 20+ specialized tools covering gene lookup, sequence retrieval, comparative genomics, variant analysis, and regulatory features. The implementation uses TypeScript with comprehensive input validation and error handling, offering both individual tools (gene search, homolog finding, transcript analysis) and batch processing capabilities for multiple genes or sequences simultaneously. Designed for bioinformatics workflows, the server integrates directly with Ensembl''s REST API to support research applications requiring programmatic access to gene annotations, phylogenetic data, variant consequences, and cross-species comparative analysis across all Ensembl-supported organisms.', '@augmented-nature', 'databases', 'Unknown', 1, 'https://github.com/augmented-nature/ensembl-mcp-server', NULL, 0, 'https://github.com/augmented-nature.png?size=128', '2026-03-09T05:21:01.915386+00:00'),
  ('gene-ontology', 'Gene Ontology', 'Provides access to Gene Ontology (GO) data through integration with QuickGO and official GO APIs, enabling AI systems to search GO terms, retrieve detailed term information with definitions and relationships, validate GO identifiers, and access ontology statistics across molecular function, biological process, and cellular component domains. Built by Augmented Nature with comprehensive error handling and multiple data source integration, it supports bioinformatics workflows including gene annotation research, functional analysis, and ontology-based studies through tools for term search, hierarchy navigation, and metadata retrieval.', '@augmented-nature', 'databases', 'Unknown', 7, 'https://github.com/augmented-nature/geneontology-mcp-server', NULL, 0, 'https://github.com/augmented-nature.png?size=128', '2026-03-09T05:21:01.915398+00:00'),
  ('gtex-portal', 'GTEx Portal', 'This TypeScript-based MCP server provides access to GTEx (Genotype-Tissue Expression) genomics data through 25 specialized tools organized into expression analysis, association analysis, and reference/dataset categories. Built with comprehensive TypeScript type definitions and a robust API client that handles GTEx Portal API v2 communication, it offers tools for gene expression profiling across tissues, eQTL/sQTL genetic association analysis, variant lookups, and dataset metadata retrieval with features like error handling, pagination, and parameter validation. The implementation targets genomics researchers, bioinformaticians, and AI assistants working with human gene expression data who need programmatic access to one of the largest publicly available genomics datasets for tissue-specific expression analysis, genetic variant associations, and comparative genomics studies.', '@augmented-nature', 'development', 'Unknown', 1, 'https://github.com/augmented-nature/gtex-mcp-server', NULL, 0, 'https://github.com/augmented-nature.png?size=128', '2026-03-09T05:21:01.915454+00:00'),
  ('open-targets', 'Open Targets', 'This MCP server provides access to the Open Targets platform, a comprehensive resource for gene-drug-disease associations and therapeutic target identification. Built by Augmented Nature using TypeScript, it integrates with both the Open Targets REST and GraphQL APIs to enable searching for therapeutic targets and diseases, retrieving detailed target and disease information, and analyzing target-disease associations with evidence scores. The implementation supports advanced querying capabilities including minimum score thresholds, result pagination, and structured data retrieval for genes (Ensembl IDs), diseases (EFO IDs), and their relationships, making it valuable for drug discovery research, precision medicine applications, and biomedical data analysis workflows.', '@augmented-nature', 'development', 'Unknown', 9, 'https://github.com/augmented-nature/opentargets-mcp-server', NULL, 0, 'https://github.com/augmented-nature.png?size=128', '2026-03-09T05:21:01.915488+00:00'),
  ('protein-data-bank', 'Protein Data Bank', 'This MCP server provides AI assistants with access to the Protein Data Bank (PDB) for structural biology research, built by Augmented Nature using TypeScript and the Model Context Protocol SDK. The implementation offers comprehensive tools for searching protein structures by keyword or UniProt ID, retrieving detailed structure information and coordinates in multiple formats (PDB, mmCIF, XML), downloading structure files with biological assembly support, and accessing structure quality metrics including validation data and refinement statistics. Built with dual API integration using both RCSB PDB''s REST API and search services, it supports advanced filtering by experimental method and resolution range, making it valuable for structural biologists analyzing protein structures, researchers conducting comparative structural studies, and AI applications requiring programmatic access to crystallographic data and molecular structure information.', '@augmented-nature', 'development', 'Unknown', 21, 'https://github.com/augmented-nature/pdb-mcp-server', NULL, 0, 'https://github.com/augmented-nature.png?size=128', '2026-03-09T05:21:01.915525+00:00'),
  ('pubchem', 'PubChem', 'This MCP server provides comprehensive access to the PubChem chemical database through 30 specialized tools covering compound search, structure analysis, property calculation, bioassay data, safety information, and cross-references to external databases. Built by Augmented Nature using TypeScript and the PubChem REST API, it enables chemical informatics workflows including similarity searches, ADMET prediction, drug-likeness assessment, toxicity analysis, and batch processing of up to 200 compounds. The implementation supports multiple search methods (name, SMILES, InChI, CAS numbers), provides detailed molecular descriptors and 3D conformer data, and integrates safety classifications with literature references, making it valuable for drug discovery, chemical research, regulatory compliance, and educational applications in chemistry and pharmacology.', '@augmented-nature', 'databases', 'Unknown', 32, 'https://github.com/augmented-nature/pubchem-mcp-server', NULL, 0, 'https://github.com/augmented-nature.png?size=128', '2026-03-09T05:21:01.915536+00:00'),
  ('reactome', 'Reactome', 'This production-ready MCP server provides access to Reactome''s curated biological pathway database through eight specialized tools for systems biology analysis. Developed by Augmented Nature, it enables searching for pathways by keywords, genes, or diseases, retrieving detailed pathway information including participants and biochemical reactions, exploring pathway hierarchies, and analyzing protein interactions within biological networks. The implementation uses Reactome''s Content Service API with robust error handling, pathway ID resolution, and structured data formatting, making it valuable for bioinformatics research, drug discovery workflows, and AI systems performing molecular pathway analysis.', '@augmented-nature', 'databases', 'Unknown', 10, 'https://github.com/augmented-nature/reactome-mcp-server', NULL, 0, 'https://github.com/augmented-nature.png?size=128', '2026-03-09T05:21:01.915547+00:00'),
  ('string-database', 'STRING Database', 'Provides access to the STRING protein interaction database through six comprehensive tools for protein network analysis, functional enrichment, and comparative genomics. Built by Augmented Nature, the server integrates with STRING''s REST API to enable protein interaction discovery, network construction with confidence scoring, GO/KEGG pathway enrichment analysis, cross-species homolog identification, and detailed protein annotation retrieval across over 5000 organisms. Designed for systems biology workflows, it complements other bioinformatics servers like UniProt and PDB to provide a complete sequence-structure-interaction-function analysis pipeline for researchers studying protein networks, molecular pathways, and evolutionary relationships.', '@augmented-nature', 'databases', 'Unknown', 4, 'https://github.com/augmented-nature/string-db-mcp-server', NULL, 0, 'https://github.com/augmented-nature.png?size=128', '2026-03-09T05:21:01.915558+00:00'),
  ('surechembl', 'SureChEMBL', 'SureChEMBL MCP server by Augmented Nature provides AI assistants with access to the SureChEMBL chemical patent database through 15 specialized tools covering patent search, chemical discovery, structure analysis, and data export capabilities. The implementation integrates with SureChEMBL''s REST API to enable searching patents by text or identifiers, retrieving complete patent documents with chemical annotations, finding chemical compounds by name or ID, analyzing patent family relationships, and generating chemical structure images. Built with TypeScript and featuring both resource templates for direct data access and comprehensive tool handlers for complex workflows, it serves researchers conducting prior art searches, pharmaceutical companies analyzing competitive landscapes, and chemists exploring chemical-patent relationships in drug discovery and intellectual property analysis.', '@augmented-nature', 'databases', 'Unknown', 7, 'https://github.com/augmented-nature/surechembl-mcp-server', NULL, 0, 'https://github.com/augmented-nature.png?size=128', '2026-03-09T05:21:01.915569+00:00'),
  ('augments', 'Augments', 'Real-time framework documentation provider for 90+ frameworks', '@augmnt', 'development', 'Unknown', 115, 'https://github.com/augmnt/augments-mcp-server', NULL, 0, 'https://github.com/augmnt.png?size=128', '2026-03-09T05:21:01.915600+00:00'),
  ('betterprompt', 'BetterPrompt', 'Enhances user requests using advanced prompt engineering techniques. Provides an enhance-request tool that converts basic user input into expertly crafted prompts designed for optimal performance with language models. Uses the MCP Sampling API to leverage the client''s configured language model for enhancement without requiring separate API keys.', '@aungmyokyaw', 'ai-ml', 'Unknown', 0, 'https://github.com/aungmyokyaw/betterprompt-mcp', NULL, 0, 'https://github.com/aungmyokyaw.png?size=128', '2026-03-09T05:21:01.915635+00:00'),
  ('mcp-link-blender', 'MCP-Link Blender', 'Blender extension that connects AI agents to Blender via MCP, enabling full control of Blender''s Python API through arbitrary code execution. The extension registers Blender as a remote tool with the MCP-Link server, allowing AI assistants to execute Python scripts, make API calls, and integrate with other MCP tools for advanced 3D modeling, animation, and rendering workflows.', '@aurafriday', 'development', 'Unknown', 2, 'https://github.com/aurafriday/mcp_link_blender', NULL, 0, 'https://github.com/aurafriday.png?size=128', '2026-03-09T05:21:01.915657+00:00'),
  ('honeycomb', 'Honeycomb', 'This Honeycomb MCP server, developed by Austin Parker, enables AI assistants to directly analyze and query Honeycomb observability data. Built with TypeScript and leveraging the MCP SDK, it provides tools for listing columns, running analytics queries, and analyzing data patterns within Honeycomb datasets. The server abstracts the complexities of interacting with the Honeycomb API, allowing AI systems to easily access and interpret observability data. By bridging AI capabilities with Honeycomb''s powerful analytics, this implementation facilitates use cases such as automated performance analysis, anomaly detection, and data-driven troubleshooting in complex distributed systems.', '@honeycombio', 'development', 'Unknown', 41, 'https://github.com/honeycombio/honeycomb-mcp', '@aparkerio/honeycomb-mcp', 304, 'https://github.com/honeycombio.png?size=128', '2026-03-09T05:21:01.915717+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('auteng-docs', 'AutEng Docs', 'AutEng Docs enables publishing markdown documents as publicly accessible share links. Supports mermaid diagram rendering within documents, configurable expiration times, and custom titles. Hosted by AutEng.ai as a remote MCP service with no local installation required.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://auteng.ai', NULL, 0, NULL, '2026-03-09T05:21:01.915744+00:00'),
  ('auth0', 'Auth0', 'The Auth0 MCP Server integrates with LLMs and AI agents, allowing you to perform various Auth0 management operations using natural language. For instance, you could simply ask Claude to create a new Auth0 app and get the domain and client ID.', '@auth0', 'ai-ml', 'Unknown', 94, 'https://github.com/auth0/auth0-mcp-server', '@auth0/auth0-mcp-server', 12543, 'https://github.com/auth0.png?size=128', '2026-03-09T05:21:01.915772+00:00'),
  ('authzed-documentation', 'AuthZed Documentation', 'A Kubernetes MCP server that provides direct cluster management capabilities through kubectl integration, enabling AI assistants to interact with Kubernetes resources via tools for applying manifests, retrieving resource information, executing commands in pods, checking logs, and managing deployments. Built with TypeScript and featuring comprehensive error handling, namespace support, and resource filtering, it bridges the gap between conversational AI and Kubernetes operations, making it useful for DevOps automation, cluster troubleshooting, application deployment, and infrastructure management workflows where natural language interaction with Kubernetes clusters is desired.', '@authzed', 'cloud', 'Unknown', 0, 'https://github.com/authzed/mcp-authzed', NULL, 0, 'https://github.com/authzed.png?size=128', '2026-03-09T05:21:01.915794+00:00'),
  ('openapi-unbundler', 'OpenAPI Unbundler', 'The Unbundle OpenAPI MCP server provides tools for manipulating OpenAPI specification files through the Model Context Protocol. It offers two primary capabilities: splitting large OpenAPI files into multiple smaller files based on their structure, and extracting specific endpoints into new files while preserving their referenced components. Built using TypeScript and the MCP SDK, it leverages the Redocly CLI internally to perform the actual file operations. This server is particularly useful for developers working with complex API specifications who need to create more focused documentation, extract subsets of APIs for specific teams, or simplify large specifications for better maintainability.', '@auto-browse', 'development', 'Unknown', 2, 'https://github.com/auto-browse/unbundle_openapi_mcp', '@auto-browse/unbundle-openapi-mcp', 3770, 'https://github.com/auto-browse.png?size=128', '2026-03-09T05:21:01.915825+00:00'),
  ('code-sandbox', 'Code Sandbox', 'This MCP implementation, developed by Automata Labs, provides a sandboxed code execution environment for AI agents. Built with Go and leveraging Docker, it offers secure code running capabilities across multiple languages. The implementation focuses on safety and isolation, with features like resource limits and network restrictions. It integrates seamlessly with Claude Desktop and other AI applications through a standardized interface. Particularly useful for developers and researchers working on AI-assisted coding tasks, it enables use cases such as code generation, debugging, and automated testing without exposing the underlying system to potential security risks.', '@automata-labs-team', 'cloud', 'Unknown', 316, 'https://github.com/automata-labs-team/code-sandbox-mcp', NULL, 0, 'https://github.com/automata-labs-team.png?size=128', '2026-03-09T05:21:01.915847+00:00'),
  ('cisco-ise', 'Cisco ISE', 'ISE MCP Server provides a bridge between AI assistants and Cisco Identity Services Engine (ISE) REST APIs, enabling dynamic discovery and retrieval of network security data. The server exposes ISE resources as structured JSON-RPC tools, allowing users to query endpoints, identity groups, authorization profiles, and other security configurations without direct API interaction. Built with Python and containerized for easy deployment, it features environment-driven configuration and comprehensive logging. This implementation is particularly valuable for network administrators who need to monitor and analyze their Cisco ISE deployments through AI assistants without navigating complex REST APIs.', '@automateyournetwork', 'ai-ml', 'Unknown', 9, 'https://github.com/automateyournetwork/ise_mcp/tree/HEAD/ise_mcp', NULL, 0, 'https://github.com/automateyournetwork.png?size=128', '2026-03-09T05:21:01.915940+00:00'),
  ('markmap', 'Markmap', 'Transforms Markdown content into interactive mindmap visualizations using markmap.js.org libraries. Provides tools for generating SVG mindmaps from Markdown text, hierarchical outlines, or files, with support for custom themes, structure analysis, and file operations. Uses JSDOM to enable server-side SVG generation in Node.js environments, bridging browser-oriented markmap libraries for use in project planning, documentation visualization, and knowledge mapping workflows.', '@automateyournetwork', 'productivity', 'Unknown', 5, 'https://github.com/automateyournetwork/markmap_mcp', NULL, 0, 'https://github.com/automateyournetwork.png?size=128', '2026-03-09T05:21:01.915977+00:00'),
  ('pyats-network-automation', 'pyATS Network Automation', 'PyATS MCP Server provides a containerized bridge between AI assistants and Cisco network devices through the pyATS automation framework. Built with Python and packaged in Docker, it enables interaction with network devices defined in a testbed YAML file, supporting routers, switches, and hosts with various operating systems. The server handles SSH connections to network devices with configurable timeouts and authentication, making it valuable for network engineers who need to automate device configuration, troubleshooting, or monitoring tasks without leaving their AI assistant interface.', '@automateyournetwork', 'cloud', 'Unknown', 66, 'https://github.com/automateyournetwork/pyats_mcp', NULL, 0, 'https://github.com/automateyournetwork.png?size=128', '2026-03-09T05:21:01.915999+00:00'),
  ('openapi-link', 'OpenAPI Link', 'MCP-Link is a server implementation that converts OpenAPI specifications into MCP-compatible endpoints, enabling AI assistants to interact with any API described in OpenAPI format. Written in Go, it features a simple HTTP server that parses OpenAPI YAML/JSON files, transforms API endpoints into MCP tools, and handles authentication through header forwarding. The implementation supports path filtering, parameter mapping, and various authentication methods, making it ideal for developers who want to quickly expose existing APIs to AI assistants without writing custom MCP adapters for each service.', '@automation-ai-labs', 'development', 'Unknown', 603, 'https://github.com/automation-ai-labs/mcp-link', NULL, 0, 'https://github.com/automation-ai-labs.png?size=128', '2026-03-09T05:21:01.916025+00:00'),
  ('wait', 'Wait', 'MCP-Wait provides a simple waiting functionality that allows pausing execution until other tasks finish. The server offers a single ''wait'' tool that accepts a duration in seconds (0-300) and reports progress in 10% increments during the wait period. Built with TypeScript using FastMCP, it supports both stdio transport for CLI usage and SSE for HTTP server integration, making it easy to incorporate into Claude Desktop, Cursor, or Chatwise applications. This utility is particularly useful in workflows where synchronization between different processes is needed.', '@automation-ai-labs', 'development', 'Unknown', 5, 'https://github.com/automation-ai-labs/mcp-wait', '@automation-ai-labs/mcp-wait', 4888, 'https://github.com/automation-ai-labs.png?size=128', '2026-03-09T05:21:01.916052+00:00'),
  ('wordpress-remote', 'WordPress Remote', 'MCP WordPress Remote serves as a bridge between local Model Context Protocol clients and WordPress websites running the wordpress-mcp plugin. Developed by Automattic, it eliminates the need for direct streaming connections by efficiently translating MCP requests into simple REST API calls to WordPress. The proxy handles authentication through WordPress API passwords and WooCommerce credentials, supports all standard MCP operations including tools, resources, and prompts, and implements comprehensive logging for troubleshooting. It''s particularly valuable for users who want to leverage WordPress content and WooCommerce data through AI assistants without managing complex API integrations or maintaining persistent connections to their websites.', '@automattic', 'ai-ml', 'Unknown', 121, 'https://github.com/automattic/mcp-wordpress-remote', '@automattic/mcp-wordpress-remote', 28590, 'https://github.com/automattic.png?size=128', '2026-03-09T05:21:01.916102+00:00'),
  ('linkd', 'Linkd', 'This MCP server provides comprehensive LinkedIn data extraction and research capabilities through integration with the Linkd API service. Built with TypeScript and Express, it offers eight specialized tools for LinkedIn operations including user and company search, profile enrichment, contact information retrieval, detailed profile scraping, and advanced deep research workflows that combine multiple search variations with email enrichment. The implementation supports both stdio and SSE transport protocols, handles credit-based API operations (1-2 credits per request), and includes features like job status monitoring for long-running research tasks, making it valuable for sales prospecting, recruitment, market research, and competitive intelligence workflows that require systematic LinkedIn data gathering.', '@automcp-app', 'development', 'Unknown', 3, 'https://github.com/automcp-app/linkd-mcp', 'linkd-mcp', 4442, 'https://github.com/automcp-app.png?size=128', '2026-03-09T05:21:01.916135+00:00'),
  ('automem', 'AutoMem', 'AutoMem provides persistent, relational memory for AI assistants across conversations and platforms. It combines FalkorDB for graph-based relationships with Qdrant for vector similarity search, enabling multi-hop reasoning queries. Supports seven memory types including decisions, patterns, preferences, and insights with configurable importance and relationship strength filters.', '@verygoodplugins', 'ai-ml', 'Unknown', 40, 'https://github.com/verygoodplugins/mcp-automem', NULL, 0, 'https://github.com/verygoodplugins.png?size=128', '2026-03-09T05:21:01.916165+00:00'),
  ('logic', 'Logic', 'First-order logic reasoning server built with Tau-Prolog that provides theorem proving, model finding, and syntax validation capabilities for logical formulas. Supports Prover9-style syntax with quantifiers, connectives, predicates, and functions, offering tools to prove statements using resolution, find finite models satisfying premises, discover counterexamples, and validate formula syntax with helpful error messages. Includes specialized support for category theory with axiom generation for categories, functors, monoids, and groups, plus diagram commutativity verification.', '@autonull', 'search', 'Unknown', 3, 'https://github.com/autonull/mcplogic', NULL, 0, 'https://github.com/autonull.png?size=128', '2026-03-09T05:21:01.916214+00:00'),
  ('automobile', 'AutoMobile', 'Mobile device interaction automation via MCP.', '@kaeawc', 'browser-automation', 'Unknown', 20, 'https://github.com/kaeawc/auto-mobile', NULL, 0, 'https://github.com/kaeawc.png?size=128', '2026-03-09T05:21:01.916246+00:00'),
  ('io-github-ansvar-systems-automotive-cybersecurity', 'io.github.Ansvar-Systems/automotive-cybersecurity', 'Automotive cybersecurity: R155/R156 regulations, ISO 21434, TISAX, AUTOSAR, Chinese GB/T', '@ansvar-systems', 'development', 'Unknown', 1, 'https://github.com/ansvar-systems/automotive-mcp', NULL, 0, 'https://github.com/ansvar-systems.png?size=128', '2026-03-09T05:21:01.916263+00:00'),
  ('automox', 'Automox', 'Provides access to Automox''s cloud-native endpoint management platform through curated workflows for policy health monitoring, device insights, remediation actions, and account management. Built using FastMCP with dual API support (console and policyreport endpoints), it exposes 18 tools across device management, policy lifecycle management, patch approvals, and audit tracking. The implementation features intelligent rate limiting, automatic API endpoint fallback, comprehensive error handling with sensitive data redaction, and includes resources for server group mappings and policy creation templates with schedule syntax helpers, making it useful for IT operations automation, security compliance monitoring, and endpoint management workflows.', '@automoxcommunity', 'security', 'Unknown', 2, 'https://github.com/automoxcommunity/automox-mcp', NULL, 0, 'https://github.com/automoxcommunity.png?size=128', '2026-03-09T05:21:01.916342+00:00'),
  ('autopilot-browser', 'Autopilot Browser', 'Integrates with Autopilot Browser''s workflow automation platform, enabling AI assistants to search for and execute pre-built browser automation workflows through a REST API. Exposes tools for discovering available workflows by keyword and running them with custom inputs, requiring an API key for authentication with the autopilotbrowser.com service. Useful for web scraping, data extraction, and integrating browser workflows into conversational AI applications.', '@autopilotbrowser', 'productivity', 'Unknown', 1, 'https://github.com/autopilotbrowser/mcp-server', NULL, 0, 'https://github.com/autopilotbrowser.png?size=128', '2026-03-09T05:21:01.916379+00:00'),
  ('avalanche-docs', 'Avalanche Docs', 'Provides access to Avalanche blockchain documentation, academy courses, and integration guides through the official Avalanche Builder Hub. Supports searching across documentation sources, fetching specific pages as markdown, and listing available documentation sections for the Avalanche ecosystem.', '@airpote', 'development', 'Unknown', 0, 'https://github.com/airpote/avalanche-mcp-vscode', NULL, 0, 'https://github.com/airpote.png?size=128', '2026-03-09T05:21:01.916398+00:00'),
  ('math-operations', 'Math Operations', 'Math MCP Server provides basic arithmetic operations and matrix multiplication with 64-bit floating point precision using NumPy for efficient computation. Built by Avanish Davuluri using FastMCP framework, the implementation offers five core tools: add and multiply for lists of numbers, subtract and divide for pairs of numbers, and matrix_multiplication for 2D matrix operations with automatic dimension validation. Designed for AI assistants that need reliable mathematical computation capabilities, it handles edge cases like division by zero and empty inputs with proper error handling, making it valuable for educational applications, data analysis workflows, and any use case requiring precise numerical calculations.', '@avanishd-3', 'ai-ml', 'Unknown', 1, 'https://github.com/avanishd-3/math-mcp', NULL, 0, 'https://github.com/avanishd-3.png?size=128', '2026-03-09T05:21:01.916446+00:00'),
  ('typesense', 'Typesense', 'Typesense MCP Server provides a bridge between AI assistants and Typesense search engine through a Python implementation using the Model Context Protocol. The server exposes tools for managing collections, documents, and search operations, including vector similarity search capabilities. Built with robust error handling and comprehensive logging, it enables AI assistants to perform operations like creating collections, indexing documents, and executing both keyword and vector searches. The implementation uses environment variables for configuration and can be easily deployed through Cursor, making it valuable for developers who want to integrate powerful search functionality into their AI workflows.', '@avarant', 'ai-ml', 'Unknown', 7, 'https://github.com/avarant/typesense-mcp-server', NULL, 0, 'https://github.com/avarant.png?size=128', '2026-03-09T05:21:01.916503+00:00'),
  ('plausible-analytics', 'Plausible Analytics', 'Plausible MCP Server provides a bridge between Claude and Plausible Analytics, enabling AI assistants to query website analytics data directly. Developed by AVIMBU, this TypeScript implementation connects to the Plausible API v2 and offers a single tool for retrieving metrics like visitors, pageviews, bounce rates, and conversion data across customizable date ranges. The server handles authentication through API keys configured via environment variables or the Smithery configuration system, making it ideal for generating analytics reports, monitoring website performance trends, and extracting insights from Plausible data without leaving the conversation interface.', '@avimbu', 'development', 'Unknown', 5, 'https://github.com/avimbu/plausible-mcp-server', NULL, 0, 'https://github.com/avimbu.png?size=128', '2026-03-09T05:21:01.916573+00:00'),
  ('slack', 'Slack', 'Slack MCP Server provides a bridge to the Slack API, enabling AI assistants to interact with Slack workspaces through two primary tools: posting messages to channels and retrieving user lists. Built by AVIMBU FlexCo in Austria, this TypeScript implementation uses the Model Context Protocol SDK to abstract Slack API interactions, making it easy to programmatically send messages or fetch workspace user information.', '@avimbu', 'development', 'Unknown', 25, 'https://github.com/avimbu/slack-mcp-server', NULL, 0, 'https://github.com/avimbu.png?size=128', '2026-03-09T05:21:01.916597+00:00'),
  ('sdlc-tracker', 'SDLC Tracker', 'A comprehensive project tracking server that manages the complete software development lifecycle with SQLite-based persistence. Provides structured management of epics, user stories, tasks, bugs, and test cases with stakeholder ownership workflows and audit trails. Features include automatic status transitions (bugs reopen closed stories, QA stories reopen epics), epic-to-epic and story-to-story dependency tracking, integrated wiki system with entity linking, collaborative commenting across all entities, and knowledge graph generation for codebases in Python, JavaScript/TypeScript, and Java. Built with better-sqlite3 and Zod validation, creating a local .project_tracker.db file in the specified project directory.', '@avinashsingh', 'databases', 'Unknown', 1, 'https://github.com/avinashsingh/mcp-sdlc-tracker', NULL, 0, 'https://github.com/avinashsingh.png?size=128', '2026-03-09T05:21:01.916608+00:00'),
  ('coding-assistant', 'Coding Assistant', 'This Coding Assistant MCP server, developed by an unnamed creator, enhances AI coding capabilities by providing context-aware code suggestions and documentation integration. Built with TypeScript and leveraging the LangChain library, it offers tools for code analysis, technology detection, and automatic documentation retrieval. The server implements vectorized documentation search and integrates with OpenAI''s API for intelligent code completion. By abstracting the complexities of code understanding and documentation lookup, it enables AI systems to provide more accurate and contextually relevant coding assistance. This implementation is particularly valuable for applications requiring enhanced code comprehension and generation, facilitating use cases such as automated code review, context-aware refactoring suggestions, and intelligent API usage recommendations.', '@avioflagos', 'development', 'Unknown', 13, 'https://github.com/avioflagos/mcp-coding-assistant', NULL, 0, 'https://github.com/avioflagos.png?size=128', '2026-03-09T05:21:01.916638+00:00'),
  ('zulip', 'Zulip', 'This MCP server provides access to Zulip''s REST API capabilities, enabling AI assistants to send messages, retrieve conversations, manage files, schedule messages, and interact with users across Zulip organizations. Built by Clarisights using TypeScript and the Model Context Protocol SDK, it offers 20+ tools covering core messaging functionality including channel and direct messaging, message editing and deletion, emoji reactions, user management, draft handling, and status updates with comprehensive Markdown formatting support. The implementation includes three resource endpoints for browsing users, channels, and formatting guidelines, making it valuable for team communication automation, chat moderation, message scheduling, and integrating AI assistants into existing Zulip-based workflows.', '@avisekrath', 'development', 'Unknown', 7, 'https://github.com/avisekrath/zulip-mcp-server', NULL, 0, 'https://github.com/avisekrath.png?size=128', '2026-03-09T05:21:01.916671+00:00'),
  ('aws-bedrock-knowledge-base-retrieval', 'AWS Bedrock Knowledge Base Retrieval', 'An MCP server implementation that enables retrieval from Amazon Bedrock Knowledge Bases, allowing AI applications to access information stored in knowledge bases through the Model Context Protocol.', '@awslabs', 'cloud', 'Unknown', 8386, 'https://github.com/awslabs/mcp/tree/HEAD/src/bedrock-kb-retrieval-mcp-server', 'awslabs.bedrock-kb-retrieval-mcp-server', 688336, 'https://github.com/awslabs.png?size=128', '2026-03-09T05:21:01.916740+00:00'),
  ('aws-bedrock-knowledge-base', 'AWS Bedrock: Knowledge Base', 'This AWS Knowledge Base Retrieval MCP server, developed by the Model Context Protocol team, enables AI assistants to access information from AWS Knowledge Bases using the Bedrock Agent Runtime. It provides a tool for performing retrieval-augmented generation (RAG) operations, allowing queries against specified knowledge bases and retrieval of multiple results. The server integrates seamlessly with AWS services, requiring proper AWS credentials configuration. By connecting AI capabilities with AWS knowledge repositories, this implementation empowers AI systems to leverage curated information sources. It is particularly useful for building AI assistants that need access to company-specific knowledge, technical documentation, or any scenario where an AI system benefits from retrieving contextual information from AWS-managed knowledge bases.', '@modelcontextprotocol', 'cloud', 'Unknown', 227, 'https://github.com/modelcontextprotocol/servers-archived/tree/HEAD/src/aws-kb-retrieval-server', '@modelcontextprotocol/server-aws-kb-retrieval', 0, 'https://github.com/modelcontextprotocol.png?size=128', '2026-03-09T05:21:01.916760+00:00'),
  ('aws-cloud-development-kit', 'AWS Cloud Development Kit', 'An MCP server implementation for AWS services, allowing AI applications to access AWS services like Bedrock, S3, and DynamoDB through the Model Context Protocol.', '@awslabs', 'cloud', 'Unknown', 8386, 'https://github.com/awslabs/mcp/tree/HEAD/src/cdk-mcp-server', 'awslabs.cdk-mcp-server', 839714, 'https://github.com/awslabs.png?size=128', '2026-03-09T05:21:01.916775+00:00'),
  ('aws-cost-analysis', 'AWS Cost Analysis', 'An MCP server that analyzes the cost of LLM API calls by tracking tokens used and calculating costs based on model pricing. It provides detailed cost breakdowns and usage statistics for better budget management and optimization of AI applications.', '@awslabs', 'cloud', 'Unknown', 8386, 'https://github.com/awslabs/mcp/tree/HEAD/src/cost-analysis-mcp-server', 'awslabs.cost-analysis-mcp-server', 333327, 'https://github.com/awslabs.png?size=128', '2026-03-09T05:21:01.916790+00:00'),
  ('aws-documentation', 'AWS Documentation', 'An MCP server that provides access to AWS documentation. This server allows Claude to search and retrieve information from AWS documentation to help answer questions about AWS services and features.', '@awslabs', 'cloud', 'Unknown', 8386, 'https://github.com/awslabs/mcp/tree/HEAD/src/aws-documentation-mcp-server', 'awslabs.aws-documentation-mcp-server', 4525009, 'https://github.com/awslabs.png?size=128', '2026-03-09T05:21:01.916805+00:00'),
  ('aws-knowledge-base', 'AWS Knowledge Base', 'The AWS Knowledge Base Retrieval MCP Server enables AI assistants to access information from AWS Knowledge Bases using the Bedrock Agent Runtime. Built with TypeScript, it provides a retrieve_from_aws_kb tool that performs RAG (Retrieval-Augmented Generation) operations, returning both raw context and structured metadata about the sources. The server supports multiple authentication methods including IAM Access Keys and AWS SSO, can be configured with default Knowledge Base IDs, and returns results in a format optimized for AI consumption with separate content items for context and source metadata. This implementation is particularly valuable for organizations that maintain AWS Knowledge Bases and want to incorporate that information into their AI assistant workflows.', '@sammcj', 'cloud', 'Unknown', 0, 'https://github.com/sammcj/mcp-aws-kb', NULL, 0, 'https://github.com/sammcj.png?size=128', '2026-03-09T05:21:01.916824+00:00'),
  ('aws-knowledge', 'AWS Knowledge', 'AWS''s official fully managed remote MCP server that provides real-time access to AWS documentation, API references, troubleshooting guides, and architectural guidance without requiring local setup. Unlike documentation-only servers, it indexes multiple AWS knowledge sources including What''s New posts, Builder Center content, blog posts, and Well-Architected guidance, while offering regional availability information for AWS APIs and CloudFormation resources. The server supports full-stack development with AWS Amplify documentation and infrastructure-as-code guidance for CDK and CloudFormation, making it useful for developers building applications, managing infrastructure, or learning AWS services through natural language queries.', '@awslabs', 'cloud', 'Unknown', 8386, 'https://github.com/awslabs/mcp/tree/HEAD/servers/aws-knowledge-mcp-server', NULL, 0, 'https://github.com/awslabs.png?size=128', '2026-03-09T05:21:01.916845+00:00'),
  ('aws-labs', 'AWS Labs', 'This AWS Labs MCP server collection provides comprehensive integration with AWS services through multiple specialized servers including Bedrock Knowledge Bases, Nova Canvas image generation, Step Functions, Lambda, IAM, Cost Explorer, and many others. The implementation includes sample applications demonstrating real-world usage patterns, such as a Streamlit-based chatbot that integrates with Bedrock Knowledge Bases for RAG workflows and an image generator leveraging Nova Canvas with prompt improvement capabilities. Built with Python and FastAPI, the servers use the langchain-mcp-adapters for seamless integration and include extensive documentation, testing frameworks, and deployment guides, making it valuable for developers building AI applications that need deep AWS service integration for enterprise workflows, cost analysis, infrastructure management, and generative AI use cases.', '@awslabs', 'cloud', 'Unknown', 8386, 'https://github.com/awslabs/mcp', NULL, 0, 'https://github.com/awslabs.png?size=128', '2026-03-09T05:21:01.916877+00:00'),
  ('amazon-bedrock-agentcore', 'Amazon Bedrock AgentCore', 'This server provides comprehensive access to Amazon Bedrock AgentCore documentation, enabling developers to search and retrieve detailed information about AgentCore platform services, APIs, tutorials, and best practices.', '@awslabs', 'ai-ml', 'Unknown', 8386, 'https://github.com/awslabs/mcp/tree/HEAD/src/amazon-bedrock-agentcore-mcp-server', NULL, 0, 'https://github.com/awslabs.png?size=128', '2026-03-09T05:21:01.916905+00:00'),
  ('log-analyzer-with-cloudwatch-logs', 'Log Analyzer with CloudWatch Logs', 'Log Analyzer with MCP is an AWS Labs-developed server that provides AI assistants with structured access to CloudWatch Logs data. Built in Python using boto3, it exposes a comprehensive set of tools for searching, analyzing, and correlating logs across multiple AWS services. The implementation includes specialized capabilities for error pattern detection, log activity summarization, and cross-service correlation using common identifiers like request IDs. It''s particularly valuable for DevOps teams and system administrators who need AI assistance with log analysis for troubleshooting, monitoring, and identifying patterns in their AWS infrastructure logs.', '@awslabs', 'cloud', 'Unknown', 151, 'https://github.com/awslabs/log-analyzer-with-mcp', NULL, 0, 'https://github.com/awslabs.png?size=128', '2026-03-09T05:21:01.916925+00:00'),
  ('aws-managed', 'AWS (Managed)', 'Official AWS managed service that consolidates the capabilities of AWS API and AWS Knowledge servers into a unified interface. Provides access to AWS documentation, generates and executes calls to over 15,000 AWS APIs including newly released services, and offers pre-built Agent Standard Operating Procedures (SOPs) for common multi-step tasks like hosting S3 websites, provisioning EC2 instances, and configuring CloudWatch alarms. Uses AWS IAM authentication and logs all activity through CloudTrail.', '@unknown', 'cloud', 'Unknown', 0, 'https://aws.amazon.com/about-aws/whats-new/2025/11/aws-mcp-server/', NULL, 0, NULL, '2026-03-09T05:21:01.916942+00:00'),
  ('aws-mcp', 'AWS MCP', 'A managed MCP server enabling AI agents to access AWS using docs, API calls, and SOP workflows.', '@unknown', 'cloud', 'Unknown', 0, 'https://docs.aws.amazon.com/aws-mcp', NULL, 0, NULL, '2026-03-09T05:21:01.916953+00:00'),
  ('aws-nova-canvas', 'AWS Nova Canvas', 'An MCP server implementation for AWS Nova Canvas, a service that enables developers to build AI applications with Claude. This server allows Claude to access and manipulate data in Nova Canvas workspaces.', '@awslabs', 'cloud', 'Unknown', 8386, 'https://github.com/awslabs/mcp/tree/HEAD/src/nova-canvas-mcp-server', 'awslabs.nova-canvas-mcp-server', 537512, 'https://github.com/awslabs.png?size=128', '2026-03-09T05:21:01.916966+00:00'),
  ('io-github-surgex-labs-awx-mcp-server', 'io.github.SurgeX-Labs/awx-mcp-server', 'Control AWX/Ansible Tower through natural language - 49 tools for automation', '@surgex-labs', 'development', 'Unknown', 1, 'https://github.com/surgex-labs/awx-mcp-server', NULL, 0, 'https://github.com/surgex-labs.png?size=128', '2026-03-09T05:21:01.916994+00:00'),
  ('axe-devtools', 'Axe DevTools', 'Official MCP server for Axe DevTools for Web accessibility testing.', '@dequelabs', 'development', 'Unknown', 1, 'https://github.com/dequelabs/axe-mcp-server-public', NULL, 0, 'https://github.com/dequelabs.png?size=128', '2026-03-09T05:21:01.917010+00:00'),
  ('minemcp', 'MineMCP', 'MineMCP is a Minecraft Paper plugin that bridges AI assistants with Minecraft servers through MCP, enabling direct server control and automation. It provides tools for world manipulation (placing, breaking, and filling blocks), player management, command execution with output capture, file system operations, and server monitoring through a token-based HTTP/SSE API. The implementation includes safety features like path traversal protection and supports both direct HTTP requests and streaming connections.', '@axenodev', 'ai-ml', 'Unknown', 2, 'https://github.com/axenodev/minemcp', NULL, 0, 'https://github.com/axenodev.png?size=128', '2026-03-09T05:21:01.917049+00:00'),
  ('il2cpp-frida-bridge', 'IL2CPP Frida Bridge', 'Provides a bridge between AI assistants and IL2CPP reverse engineering workflows through Frida dynamic instrumentation. Built with TypeScript and Python, it enables real-time analysis of Unity IL2CPP applications by exposing Frida''s capabilities through MCP tools for class inspection, method hooking, memory analysis, and JavaScript code execution within target processes. The implementation combines frida-il2cpp-bridge for Unity-specific operations with a structured service architecture covering disassembly, garbage collection monitoring, and module introspection, making it valuable for security researchers, game modders, and developers analyzing Unity applications at runtime.', '@axhlzy', 'development', 'Unknown', 6, 'https://github.com/axhlzy/il2cpp-frida-mcp', NULL, 0, 'https://github.com/axhlzy.png?size=128', '2026-03-09T05:21:01.917078+00:00'),
  ('axiomatic-ai', 'Axiomatic AI', 'A collection of modular MCP servers built by the Axiomatic AI team that provides specialized tools for scientific and engineering workflows, featuring six domain-specific servers: photonic integrated circuit design and simulation with gdsfactory integration, document processing with advanced OCR for PDFs, plot data extraction from images, equation composition and analysis, PDF annotation with contextual analysis, and model fitting with optimization capabilities. Built with FastMCP and featuring telemetry middleware, API client integration with the Axiomatic AI platform, and comprehensive tooling for each domain including circuit netlisting, wavelength analysis, Jupyter notebook generation, and structured data extraction, making it ideal for researchers, engineers, and scientists working with technical documents, photonic circuits, experimental data analysis, and mathematical modeling workflows.', '@axiomatic-ai', 'ai-ml', 'Unknown', 18, 'https://github.com/axiomatic-ai/ax-mcp', 'axiomatic-mcp', 20012, 'https://github.com/axiomatic-ai.png?size=128', '2026-03-09T05:21:01.917139+00:00'),
  ('axiom-context', 'Axiom Context', 'This Axiom Context Server, developed for use with the Zed AI assistant, provides a Model Context Server for Axiom. Built using Rust and the zed_extension_api, it offers a customizable command interface for integration with Axiom''s model context protocol (MCP). The implementation allows users to specify custom commands and arguments in their Zed settings, enhancing flexibility in deployment. It''s designed to seamlessly connect Axiom''s capabilities with Zed''s AI assistant, making it particularly useful for developers and teams looking to leverage Axiom''s context-aware AI features within their Zed-based workflows. The server''s ability to use a local executable or a custom-specified command path adds versatility for different setup requirements.', '@axiomhq', 'ai-ml', 'Unknown', 0, 'https://github.com/axiomhq/zed-axiom-context-server', 'axiom_model_context', 0, 'https://github.com/axiomhq.png?size=128', '2026-03-09T05:21:01.917187+00:00'),
  ('axiom', 'Axiom', 'Integrates with Axiom''s observability platform to query datasets, analyze distributed traces, and explore event data in real-time. Provides tools for executing APL queries, listing datasets and schemas, and accessing monitoring data for log analysis, anomaly detection, and troubleshooting.', '@axiomhq', 'aggregators', 'Unknown', 11, 'https://github.com/axiomhq/mcp/tree/HEAD/apps/mcp', NULL, 0, 'https://github.com/axiomhq.png?size=128', '2026-03-09T05:21:01.917238+00:00'),
  ('code-runner', 'Code Runner', 'MCP Code Runner is a TypeScript server that enables AI assistants to execute code snippets in isolated Docker containers. Developed by axliupore, it supports multiple programming languages including Python, JavaScript, TypeScript, Go, Java, C, and C++. The implementation uses Dockerode to manage container lifecycle, enforces resource limits (memory, CPU) and network isolation for security, and returns execution results with stdout/stderr output. It''s particularly useful for code testing, debugging, and educational scenarios where safe execution of untrusted code is required.', '@axliupore', 'cloud', 'Unknown', 17, 'https://github.com/axliupore/mcp-code-runner', NULL, 0, 'https://github.com/axliupore.png?size=128', '2026-03-09T05:21:01.917260+00:00'),
  ('ax-platform', 'aX Platform', 'Platform for coordinating multiple AI agents across different providers (Claude, ChatGPT, Gemini, and custom agents). Provides real-time messaging with @mentions and threading, task management for creating and tracking work across agents, semantic search for finding messages and tasks, multi-tenant workspaces for organization, agent discovery, and shared context for ephemeral key-value data exchange between agents.', '@ax-platform', 'communication', 'Unknown', 6, 'https://github.com/ax-platform/ax-platform-mcp', NULL, 0, 'https://github.com/ax-platform.png?size=128', '2026-03-09T05:21:01.917290+00:00'),
  ('spline-3d-design', 'Spline 3D Design', 'Spline MCP Server provides a bridge to the Spline 3D design tool API, enabling AI assistants to interact with Spline''s features through a structured interface. It supports core operations like exporting scenes to various formats (GLB, GLTF, FBX, OBJ), importing 3D models, and managing scene details, while offering robust animation capabilities including creating keyframe animations, triggering existing animations, and setting up event-based interactions. The server uses axios for API communication and implements comprehensive error handling, making it valuable for designers and developers who want to programmatically control Spline''s 3D environment without leaving their AI assistant conversation.', '@aydinfer', 'ai-ml', 'Unknown', 51, 'https://github.com/aydinfer/spline-mcp-server', NULL, 0, 'https://github.com/aydinfer.png?size=128', '2026-03-09T05:21:01.917368+00:00'),
  ('unreal-engine-analyzer', 'Unreal Engine Analyzer', 'This Unreal Engine code analyzer MCP server, developed by Ayelet Technology Private Limited, provides powerful source code analysis capabilities for Unreal Engine codebases. Built with TypeScript and leveraging tree-sitter for robust C++ parsing, it enables AI assistants to deeply understand and analyze Unreal Engine source code. The server offers features like class analysis, hierarchy mapping, code search, reference finding, and subsystem analysis. It also includes a knowledge base of game genres and implementation patterns. By abstracting complex code analysis into standardized MCP endpoints, it allows AI systems to gain deep insights into Unreal Engine projects. This implementation is particularly useful for game developers, engine contributors, and AI assistants working on Unreal Engine-based projects, facilitating tasks like code comprehension, refactoring, and architectural analysis.', '@ayeletstudioindia', 'development', 'Unknown', 140, 'https://github.com/ayeletstudioindia/unreal-analyzer-mcp', NULL, 0, 'https://github.com/ayeletstudioindia.png?size=128', '2026-03-09T05:21:01.917398+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('health-reminder', 'Health Reminder', 'A health reminder server that delivers automated desktop notifications for wellness activities during long work sessions. Built by aYon1997 using TypeScript and node-notifier, it offers configurable reminder intervals for water intake, posture breaks, and eye rest with customizable messages. The implementation includes tools for starting and stopping reminders, checking status, and sending immediate notifications, making it particularly useful for developers and office workers who need automated health prompts during extended coding or work sessions.', '@ayon1997', 'development', 'Unknown', 1, 'https://github.com/ayon1997/health-reminder-mcp', 'health-reminder-mcp', 89, 'https://github.com/ayon1997.png?size=128', '2026-03-09T05:21:01.917425+00:00'),
  ('groqcloud', 'GroqCloud', 'This MCP server provides AI assistants with comprehensive access to Groq''s high-speed AI inference API, built using TypeScript with intelligent model selection, rate limiting, and caching capabilities. The implementation offers tools for text completion with automatic model optimization based on task complexity (speed vs quality vs reasoning), audio transcription using Whisper models, vision analysis with multimodal Llama models, and batch processing for high-volume operations, featuring smart model selection rules that automatically choose optimal models based on prompt characteristics and performance requirements. Built with extensive rate limiting, caching, error handling with retry logic, and support for 20+ Groq models including the latest Llama 3.3, DeepSeek R1, and specialized models for different use cases, it serves developers needing fast AI inference with automatic optimization, applications requiring high-throughput text processing with intelligent model routing, and teams building AI workflows that benefit from Groq''s exceptional inference speed combined with sophisticated model selection and resource management.', '@ayrtonfelipe', 'development', 'Unknown', 1, 'https://github.com/ayrtonfelipe/groqcloud-mcp_server', NULL, 0, 'https://github.com/ayrtonfelipe.png?size=128', '2026-03-09T05:21:01.917462+00:00'),
  ('advanced-reasoning', 'Advanced Reasoning', 'MCP Reasoning Server provides advanced reasoning capabilities for Claude in Cursor AI through simulated reasoning algorithms including Monte Carlo Tree Search, Beam Search, R1 Transformer, and Hybrid Reasoning. Built by AzDeltaQQ (inspired by Jacck''s mcp-reasoner), it implements auto-iterative reasoning that completes all steps in a single tool call, returning structured JSON responses with reasoning traces. The server is designed for complex problem-solving tasks in software development contexts like algorithm optimization, architecture design, and code refactoring.', '@azdeltaqq', 'development', 'Unknown', 13, 'https://github.com/azdeltaqq/mcp-reasoning-server', NULL, 0, 'https://github.com/azdeltaqq.png?size=128', '2026-03-09T05:21:01.917490+00:00'),
  ('com-microsoft-azure', 'com.microsoft/azure', 'All Azure MCP tools to create a seamless connection between AI agents and Azure services.', '@microsoft', 'cloud', 'Unknown', 2723, 'https://github.com/microsoft/mcp', NULL, 0, 'https://github.com/microsoft.png?size=128', '2026-03-09T05:21:01.917503+00:00'),
  ('azure-ai-foundry', 'Azure AI Foundry', 'This MCP server provides integration with Microsoft''s Azure AI Foundry platform, enabling AI assistants to interact with Azure''s machine learning and AI services ecosystem. The implementation likely offers capabilities for model deployment, experiment tracking, dataset management, and accessing Azure''s AI services through a unified interface. Useful for developers and data scientists who need AI-assisted workflows for managing machine learning projects, deploying models to Azure infrastructure, or integrating with Azure''s cognitive services and AI capabilities.', '@microsoft-foundry', 'cloud', 'Unknown', 236, 'https://github.com/microsoft-foundry/mcp-foundry', NULL, 0, 'https://github.com/microsoft-foundry.png?size=128', '2026-03-09T05:21:01.917525+00:00'),
  ('azure-api-management-gateway-with-entra-id-authentication', 'Azure API Management Gateway with Entra ID Authentication', 'This Azure-based MCP server implementation secures remote MCP servers using API Management as an AI Gateway. It implements the latest MCP Authorization specification with a complete OAuth2 flow, allowing clients to authenticate securely through Microsoft Entra ID. The architecture uses Azure Functions for the backend, with Python tools for snippet management, while API Management handles client registration, authorization, and token exchange. The implementation includes infrastructure as code (Bicep templates) for easy deployment with Azure Developer CLI (azd), making it particularly useful for organizations that need to provide secure, enterprise-grade access to MCP tools while leveraging existing Azure identity services.', '@azure-samples', 'cloud', 'Unknown', 116, 'https://github.com/azure-samples/remote-mcp-apim-functions-python', NULL, 0, 'https://github.com/azure-samples.png?size=128', '2026-03-09T05:21:01.917548+00:00'),
  ('azure-cloud-manager', 'Azure Cloud Manager', 'Azure MCP provides a .NET-based server implementation that enables AI assistants to interact with Azure cloud resources through a command-line interface. Built by Microsoft, this tool exposes capabilities for managing Azure services including Cosmos DB, Storage, App Configuration, and Monitor, with commands for listing resources, querying data, and performing administrative operations. The server supports both standard I/O and SSE transport protocols, implements robust authentication through Azure Identity, and features comprehensive retry policies and telemetry integration, making it valuable for developers seeking to automate Azure resource management or enable AI-assisted cloud operations.', '@azure', 'cloud', 'Unknown', 1208, 'https://github.com/azure/azure-mcp', NULL, 0, 'https://github.com/azure.png?size=128', '2026-03-09T05:21:01.917568+00:00'),
  ('azure-devops', 'Azure DevOps', 'Azure DevOps Work Items MCP Server provides a programmatic interface for interacting with Azure DevOps work items, enabling AI assistants to retrieve, create, update, and analyze work items through a standardized set of resources and tools. Built using the FastMCP framework, it supports operations like fetching recent work items, creating tasks, updating work item details, and generating analysis prompts, making it valuable for project management and workflow automation.', '@munishm', 'cloud', 'Unknown', 0, 'https://github.com/munishm/azure-devops-mcp-server', NULL, 0, 'https://github.com/munishm.png?size=128', '2026-03-09T05:21:01.917585+00:00'),
  ('azure-impact-reporter', 'Azure Impact Reporter', 'The Azure Impact Reporting MCP server enables large language models to report infrastructure issues to Azure on behalf of customers. Built by Chand45, this Python implementation authenticates with Azure using DefaultAzureCredential and creates workload impact reports via the Azure Management API. The server exposes a tool that accepts subscription details, resource information, and impact categories (connectivity, performance, availability), then submits standardized reports through Azure''s workload impacts endpoint. It''s particularly useful for AI assistants that need to help users report Azure resource problems without requiring them to navigate complex Azure reporting processes manually.', '@chand45', 'cloud', 'Unknown', 2, 'https://github.com/chand45/mcp-server-azure-impact-reporting', NULL, 0, 'https://github.com/chand45.png?size=128', '2026-03-09T05:21:01.917604+00:00'),
  ('azure-java-sdk', 'Azure Java SDK', 'Azure Java SDK Code Samples MCP server provides AI assistants with direct access to Azure Java SDK documentation and code examples by fetching README files from Maven Central repositories. Developed by Weidong Xu from Microsoft, it automatically retrieves the latest version metadata and documentation for any Azure Java SDK package (those starting with ''azure-''), eliminating the need to manually search through documentation or remember specific package versions. The implementation is particularly valuable for developers working with Azure services who need quick access to usage examples, API documentation, and best practices for specific SDK packages during development workflows.', '@weidongxu-microsoft', 'cloud', 'Unknown', 1, 'https://github.com/weidongxu-microsoft/mcp-azure-java-sdk-assist', NULL, 0, 'https://github.com/weidongxu-microsoft.png?size=128', '2026-03-09T05:21:01.917624+00:00'),
  ('azure-pricing', 'Azure Pricing', 'This MCP server provides programmatic access to Azure resource pricing through Microsoft''s public Azure Retail Prices API, implementing a structured four-step workflow for querying pricing information without requiring Azure credentials. Built by sboludaf using Python with FastAPI and the mcp-server library, it offers tools to list Azure service families, retrieve service names within families, get product listings with filtering capabilities, and calculate monthly costs based on hourly pricing data. The implementation includes intelligent pagination handling, optimized queries for high-volume service families like Compute, and comprehensive error handling, making it valuable for cloud cost estimation, budget planning, and Azure resource pricing analysis workflows.', '@sboludaf', 'cloud', 'Unknown', 8, 'https://github.com/sboludaf/mcp-azure-pricing', NULL, 0, 'https://github.com/sboludaf.png?size=128', '2026-03-09T05:21:01.917643+00:00'),
  ('io-github-jonnybottles-azure-updates', 'io.github.jonnybottles/azure-updates', 'MCP server for Azure Updates RSS feed - search, filter, and summarize Azure service updates', '@jonnybottles', 'cloud', 'Unknown', 1, 'https://github.com/jonnybottles/azure-updates-mcp', NULL, 0, 'https://github.com/jonnybottles.png?size=128', '2026-03-09T05:21:01.917677+00:00'),
  ('b12-website-generator', 'B12 Website Generator', 'B12''s website generator MCP server enables AI assistants to create business websites through a simple interface. Developed by b12io, this TypeScript implementation provides a single tool that accepts a business name and description, then generates a customized website accessible via a signup link. The server uses the Model Context Protocol to handle tool registration and execution, communicating through stdio transport for seamless integration with Claude Desktop. It''s particularly useful for quickly generating professional website designs during conversations about business needs without requiring technical expertise.', '@b12io', 'development', 'Unknown', 4, 'https://github.com/b12io/website-generator-mcp-server', NULL, 0, 'https://github.com/b12io.png?size=128', '2026-03-09T05:21:01.917707+00:00'),
  ('atlassian-bitbucket-data-center', 'Atlassian Bitbucket Data Center', 'Provides comprehensive integration with Atlassian Bitbucket Data Center installations, enabling repository management, code browsing, and pull request workflows. Part of a broader suite supporting Data Center deployments of Atlassian products with API token authentication.', '@b1ff', 'development', 'Unknown', 53, 'https://github.com/b1ff/atlassian-dc-mcp/tree/HEAD/packages/bitbucket', NULL, 0, 'https://github.com/b1ff.png?size=128', '2026-03-09T05:21:01.917727+00:00'),
  ('atlassian-confluence-data-center', 'Atlassian Confluence Data Center', 'Integrates with Atlassian Confluence Data Center to provide content retrieval, creation, and updates. Supports CQL search queries, page management, and blog post operations with API token authentication. Designed specifically for on-premises Data Center deployments.', '@b1ff', 'search', 'Unknown', 53, 'https://github.com/b1ff/atlassian-dc-mcp/tree/HEAD/packages/confluence', NULL, 0, 'https://github.com/b1ff.png?size=128', '2026-03-09T05:21:01.917762+00:00'),
  ('gru-sandbox', 'Gru Sandbox', 'Gru-sandbox (gbox) is an open-source, self-hostable sandbox for MCP integration that provides secure local command execution for AI agents. Built by BabelCloud, it creates isolated Docker containers (boxes) for running Python, TypeScript, and Bash code, with a clean API for creating, managing, and executing commands in these sandboxes. The system supports both Docker and Kubernetes environments, features automatic resource reclamation, and includes a command-line interface for easy management, making it ideal for developers integrating AI tools with local execution capabilities while maintaining security boundaries.', '@babelcloud', 'cloud', 'Unknown', 166, 'https://github.com/babelcloud/gbox', NULL, 0, 'https://github.com/babelcloud.png?size=128', '2026-03-09T05:21:01.917784+00:00'),
  ('agent-skill-loader', 'Agent Skill Loader', 'Agent Skill Loader bridges static Claude Code skills libraries with dynamic AI agents. It enables agents to discover, read, and install skills on demand from configured skill directories. Provides tools for listing available skills, reading skill documentation, installing skills into projects, and managing search paths at runtime.', '@back1ply', 'development', 'Unknown', 3, 'https://github.com/back1ply/agent-skill-loader', NULL, 0, 'https://github.com/back1ply.png?size=128', '2026-03-09T05:21:01.917804+00:00'),
  ('ai-expert-workflow', 'AI Expert Workflow', 'AI Expert Workflow MCP is a server implementation that facilitates structured collaboration with AI experts in product development. Developed by bacoco, it provides access to three specialized AI roles: Product Manager, UX Designer, and Software Architect, each generating comprehensive documentation based on user requirements. The server uses OpenRouter API for flexible model selection and includes Task Master integration for converting product requirements into actionable development tasks. This implementation is particularly valuable for teams seeking to streamline the planning-to-implementation pipeline through expert consultation and document generation.', '@bacoco', 'development', 'Unknown', 16, 'https://github.com/bacoco/ai-expert-workflow-mcp', 'ai-expert-workflow-mcp', 5819, 'https://github.com/bacoco.png?size=128', '2026-03-09T05:21:01.917832+00:00'),
  ('baidu-content-safety', 'Baidu Content Safety', 'MCP Server Safe Content Check provides content moderation capabilities by integrating with Baidu Cloud''s content safety APIs. The server allows AI assistants to screen text and other content for potentially harmful, inappropriate, or illegal material before processing or displaying it. Built with Python using the MCP framework, it requires Baidu Cloud credentials configured through environment variables. This implementation is particularly valuable for applications that need to ensure user-generated content meets safety and compliance standards before further processing.', '@liangjunyu2010', 'ai-ml', 'Unknown', 6, 'https://github.com/liangjunyu2010/mcp_server_safe_content_check', NULL, 0, 'https://github.com/liangjunyu2010.png?size=128', '2026-03-09T05:21:01.917900+00:00'),
  ('baidu-maps', 'Baidu Maps', 'Baidu Map MCP Server provides a standardized interface for accessing Baidu Maps API services, available in both Node.js and Python implementations. The server enables location-based operations through the Model Context Protocol, allowing applications to interact with Baidu''s mapping services without directly managing API credentials or implementation details. Useful for applications requiring geocoding, route planning, location search, and other geospatial functionalities within the Baidu Maps ecosystem.', '@baidu-maps', 'ai-ml', 'Unknown', 408, 'https://github.com/baidu-maps/mcp', '@baidumap/mcp-server-baidu-map', 22060, 'https://github.com/baidu-maps.png?size=128', '2026-03-09T05:21:01.917939+00:00'),
  ('mochow-vector-database', 'Mochow Vector Database', 'The Mochow MCP server provides AI assistants with direct access to Mochow vector database capabilities through a Python implementation. Developed by Baidu, this server exposes tools for managing databases, tables, and vector indexes, as well as performing vector similarity and full-text searches. It integrates with the pymochow client library to communicate with Mochow instances, handling authentication via API keys and supporting operations like creating databases, rebuilding indexes, and executing parameterized queries with filters. The server is particularly valuable for users who need to interact with vector data for similarity search, manage vector embeddings, or perform hybrid searches combining vector similarity with scalar attribute filtering without leaving their conversation context.', '@baidu', 'databases', 'Unknown', 3, 'https://github.com/baidu/mochow-mcp-server-python', 'mochow-mcp-server', 1305, 'https://github.com/baidu.png?size=128', '2026-03-09T05:21:01.917952+00:00'),
  ('flutterwave', 'Flutterwave', 'MCP-Flutterwave enables AI assistants to interact with Flutterwave''s payment processing API, providing tools for creating and managing payment checkout links, verifying transactions, and resending failed webhooks. Built with TypeScript using the Model Context Protocol SDK, it authenticates with Flutterwave using secret keys and exposes four main tools: creating payment links, disabling checkout links, retrieving transaction details, and resending failed webhooks. This implementation is particularly valuable for workflows requiring payment processing capabilities within AI assistant conversations, such as e-commerce support, transaction verification, or payment link generation.', '@bajoski34', 'development', 'Unknown', 2, 'https://github.com/bajoski34/mcp-flutterwave', NULL, 0, 'https://github.com/bajoski34.png?size=128', '2026-03-09T05:21:01.917982+00:00'),
  ('criterion', 'Criterion', 'Enables semantic search across religious Islamic texts including Quran verses and authenticated Hadiths. Provides contextually relevant passages for guidance and study purposes.', '@balajsaleem', 'search', 'Unknown', 11, 'https://github.com/balajsaleem/criterion', NULL, 0, 'https://github.com/balajsaleem.png?size=128', '2026-03-09T05:21:01.918010+00:00'),
  ('balldontlie', 'BALLDONTLIE', 'Provides access to live sports data and analytics across 10 major sports leagues including NBA, WNBA, NFL, MLB, EPL, NHL, NCAAF, NCAAB, MMA, and FIFA World Cup 2026. Offers 145+ endpoints covering teams, players, games, statistics, standings, injuries, betting odds, and advanced analytics. Supports both hosted remote access and local deployment with TypeScript implementation.', '@balldontlie-api', 'development', 'Unknown', 7, 'https://github.com/balldontlie-api/mcp', NULL, 0, 'https://github.com/balldontlie-api.png?size=128', '2026-03-09T05:21:01.918032+00:00'),
  ('banana-prompts', 'Banana Prompts', 'Integrates with Banana Prompts, a curated gallery of AI art prompts optimized for the Nano Banana model. Provides tools to search prompts by tags (such as Cyberpunk, Portrait, or Oil Painting) or by keyword queries. Each result includes direct links to full prompts and high-resolution images on the Banana Prompts website.', '@banana-prompts', 'ai-ml', 'Unknown', 3, 'https://github.com/banana-prompts/banana-prompts-mcp', NULL, 0, 'https://github.com/banana-prompts.png?size=128', '2026-03-09T05:21:01.918061+00:00'),
  ('bankless-onchain', 'Bankless Onchain', 'Bankless Onchain MCP Server provides a middleware between AI models and blockchain data, enabling LLMs to interact with smart contracts, fetch events, and access transaction information across multiple networks. Developed by Bankless Engineering, it implements tools for reading contract state, retrieving proxy implementations, fetching ABIs and source code, filtering event logs, and accessing transaction history. The server requires a Bankless API token for authentication and is particularly valuable for blockchain analysis, smart contract interaction, and on-chain data exploration workflows without requiring users to leave their conversation interface.', '@bankless', 'development', 'Unknown', 73, 'https://github.com/bankless/onchain-mcp', '@bankless/onchain-mcp', 6023, 'https://github.com/bankless.png?size=128', '2026-03-09T05:21:01.918089+00:00'),
  ('io-github-bolivian-peru-baozi-mcp', 'io.github.bolivian-peru/baozi-mcp', '68 tools for AI agents to interact with Solana prediction markets on Baozi.bet', '@bolivian-peru', 'development', 'Unknown', 0, 'https://github.com/bolivian-peru/baozi-mcp', NULL, 0, 'https://github.com/bolivian-peru.png?size=128', '2026-03-09T05:21:01.918104+00:00'),
  ('bigrack', 'BigRack', 'Intelligent project management server providing task decomposition, ticket tracking, project organization, and RAG-powered context storage using local vector embeddings. Built with a local-first architecture using SQLite and the all-MiniLM-L6-v2 model, it enables storage and querying of business rules, glossary terms, patterns, and conventions while managing project hierarchies and ticket dependencies. Includes CLI tool and web GUI for setup and management, with specialized tools for decomposing features into actionable tickets and retrieving contextually relevant information to guide development workflows.', '@baptiste-mnh', 'databases', 'Unknown', 2, 'https://github.com/baptiste-mnh/bigrack.dev/tree/HEAD/packages/mcp', NULL, 0, 'https://github.com/baptiste-mnh.png?size=128', '2026-03-09T05:21:01.918115+00:00'),
  ('chinese-trends-hub', 'Chinese Trends Hub', 'MCP Trends Hub provides AI assistants with access to trending topics and content from popular Chinese platforms including Weibo, Zhihu, Douyin, Bilibili, Douban, Toutiao, and 36kr. The implementation exposes each platform as a separate tool that fetches current trending data, with results cached temporarily to improve performance. Built with TypeScript and using the Model Context Protocol SDK, it features robust error handling and standardized response formatting. This server is particularly valuable for use cases requiring real-time insights into Chinese social media trends, content discovery, and cultural monitoring without leaving the conversation interface.', '@baranwang', 'development', 'Unknown', 225, 'https://github.com/baranwang/mcp-trends-hub', 'mcp-trends-hub', 18990, 'https://github.com/baranwang.png?size=128', '2026-03-09T05:21:01.918146+00:00'),
  ('tung-shing-calendar', 'Tung Shing Calendar', 'This MCP implementation, developed by Baran, provides a TypeScript-based interface for working with dates, times, and calendars. Built using the dayjs library and its lunar calendar plugin, it offers tools for parsing, formatting, and manipulating dates in both Gregorian and lunar calendars. The implementation focuses on cross-calendar functionality and internationalization support, making it easier for AI models to handle date-related tasks across different cultural contexts. It''s particularly useful for applications requiring date calculations, event scheduling, or cultural date conversions, enabling AI to perform complex calendar operations without needing deep knowledge of various calendar systems.', '@baranwang', 'development', 'Unknown', 35, 'https://github.com/baranwang/mcp-tung-shing', NULL, 0, 'https://github.com/baranwang.png?size=128', '2026-03-09T05:21:01.918175+00:00'),
  ('spoke', 'SPOKE', 'Connects to the Scalable Precision Medicine Open Knowledge Engine (SPOKE), a large-scale biomedical knowledge graph maintained by BaranziniLab at UCSF. Enables executing read-only Cypher queries against the SPOKE Neo4j database and retrieving the complete graph schema including node types, properties, and relationships. Supports exploration of biomedical connections spanning genes, proteins, diseases, compounds, and other biological entities for precision medicine research.', '@baranzinilab', 'databases', 'Unknown', 1, 'https://github.com/baranzinilab/spokeagent', NULL, 0, 'https://github.com/baranzinilab.png?size=128', '2026-03-09T05:21:01.918186+00:00'),
  ('bargainer', 'Bargainer', 'Bargainer MCP server aggregates deals from multiple sources including Slickdeals API, RapidAPI marketplace, and web scraping providers like DealNews and RetailMeNot to provide unified deal search and comparison capabilities. Built by Karthik Sivaram M, the implementation offers six core tools for searching deals with advanced filtering (price, rating, category, store), retrieving trending deals, comparing similar products, and filtering results across multiple criteria. The server includes a web-based chat interface with Socket.IO integration and supports both API-based sources requiring authentication keys and fallback web scraping for public deal sites, making it valuable for users who want to efficiently find and compare deals across the fragmented landscape of deal aggregation websites without manually checking each source.', '@karthiksivaramms', 'communication', 'Unknown', 4, 'https://github.com/karthiksivaramms/bargainer-mcp-client', NULL, 0, 'https://github.com/karthiksivaramms.png?size=128', '2026-03-09T05:21:01.918229+00:00'),
  ('bridge-windows-pc-control', 'Bridge (Windows PC Control)', 'Bridge MCP provides universal Windows PC control for AI assistants through a cloud relay architecture that connects to a local agent running on the target machine. The implementation features persistent agent registration that survives restarts, real-time desktop state monitoring with UI automation, comprehensive input/output control including mouse, keyboard, and clipboard operations, browser automation via Playwright, and a safety system that requires user approval for potentially dangerous commands like PowerShell execution. It includes a live visual overlay showing AI activity, session memory for command history, and supports multiple agents across different machines, making it useful for desktop automation, remote assistance, testing workflows, and AI-driven computer interaction tasks.', '@barhamagha1', 'development', 'Unknown', 4, 'https://github.com/barhamagha1/bridge-mcp', NULL, 0, 'https://github.com/barhamagha1.png?size=128', '2026-03-09T05:21:01.918263+00:00'),
  ('blender-3d-modeling', 'Blender 3D Modeling', 'Blender MCP Server provides direct access to Blender''s 3D modeling and rendering capabilities through a comprehensive set of tools for file management, object creation and manipulation, and export functionality. Built with FastMCP and integrating bpy (Blender Python API), mathutils for vector operations, and Open3D for point cloud processing, it enables programmatic control of Blender scenes including loading/saving .blend files, creating and positioning primitive objects, applying transformations, calculating distances between objects, and exporting to glTF/GLB formats with optional point cloud conversion. The implementation includes detailed logging and error handling, making it valuable for automated 3D content generation, batch processing of 3D assets, procedural modeling workflows, and AI-assisted 3D design tasks.', '@barosandu', 'productivity', 'Unknown', 1, 'https://github.com/barosandu/blender-mcp-yong/tree/HEAD/blender-mit-mcp', NULL, 0, 'https://github.com/barosandu.png?size=128', '2026-03-09T05:21:01.918315+00:00'),
  ('barrhawk-premium-e2e', 'BarrHawk Premium E2E', 'BarrHawk is a self-healing end-to-end testing framework designed to verify AI agent code execution. It features a tripartite architecture with separate Bridge, Doctor, and Igor components communicating via WebSocket, enabling automatic recovery from application changes and test failures. The framework provides over 30 built-in testing tools including browser automation via Playwright, database access, GitHub integration, Docker orchestration, and performance regression detection.', '@barrhawk', 'databases', 'Unknown', 15, 'https://github.com/barrhawk/barrhawk_premium_e2e_mcp', NULL, 0, 'https://github.com/barrhawk.png?size=128', '2026-03-09T05:21:01.918327+00:00'),
  ('gemini-thinking', 'Gemini Thinking', 'This MCP server integrates with Google''s Gemini API to provide analytical thinking capabilities without code generation. Developed by Anthropic, it features sequential thought processing, branching analysis paths, session persistence, and advanced semantic filtering of codebases. The server is designed for complex problem-solving tasks, codebase analysis, and architectural decision-making in software development contexts.', '@bartekke8it56w2', 'development', 'Unknown', 21, 'https://github.com/bartekke8it56w2/new-mcp', NULL, 0, 'https://github.com/bartekke8it56w2.png?size=128', '2026-03-09T05:21:01.918388+00:00'),
  ('manifold-markets', 'Manifold Markets', 'This MCP server, developed by Barton Rhodes, enables seamless interaction with Manifold Markets prediction markets. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers a comprehensive suite of tools for market search, analysis, betting, and portfolio management. The implementation stands out by providing precise probability specifications for limit orders and advanced filtering capabilities. It''s particularly useful for AI systems and developers looking to integrate collective intelligence and decision-making through prediction markets, allowing for sophisticated market analysis, automated trading strategies, and data-driven forecasting in various domains.', '@bmorphism', 'development', 'Unknown', 13, 'https://github.com/bmorphism/manifold-mcp-server', 'manifold-mcp-server', 4711, 'https://github.com/bmorphism.png?size=128', '2026-03-09T05:21:01.918418+00:00'),
  ('style-guidelines', 'Style Guidelines', 'MCPRules, developed by Hugo Bartwisch, is a TypeScript-based server for managing and serving programming guidelines and rules. It integrates with development tools to enforce consistent coding standards across projects. The server supports both local and GitHub-hosted rules, offers flexible storage options, and organizes rules into categories like Core Programming Principles and Language-Specific Guidelines. MCPRules stands out by providing a structured rule format with categories and key-value pairs, making it easy to filter and access rules via MCP tools. This implementation is particularly useful for development teams looking to maintain code quality, streamline their coding practices, and ensure consistency across multiple projects.', '@bartwisch', 'development', 'Unknown', 22, 'https://github.com/bartwisch/mcprules', NULL, 0, 'https://github.com/bartwisch.png?size=128', '2026-03-09T05:21:01.918484+00:00'),
  ('paperless-ngx', 'Paperless-NGX', 'Paperless-MCP is a server implementation that enables AI assistants to interact with Paperless-NGX document management systems. Developed by Baruch Odem, it provides tools for managing documents, tags, correspondents, and document types through a TypeScript-based API. The server can run in both stdio mode (for CLI use) and HTTP mode (for remote access), with Docker support for containerized deployment. It features robust error handling, type safety throughout the codebase, and comprehensive authentication via API tokens. Particularly valuable for users who need to organize, search, and manage their document collections through natural language interactions.', '@baruchiro', 'cloud', 'Unknown', 68, 'https://github.com/baruchiro/paperless-mcp', '@baruchiro/paperless-mcp', 13972, 'https://github.com/baruchiro.png?size=128', '2026-03-09T05:21:01.918507+00:00'),
  ('any-openapi', 'Any OpenAPI', 'This MCP server implementation, developed by Bary Huang, provides integration with any OpenAPI-compliant service. Built with Python and leveraging libraries like FastAPI, FAISS, and sentence-transformers, it offers a flexible approach to connecting AI models with diverse APIs. The implementation focuses on dynamic tool generation based on OpenAPI specifications, enabling seamless interaction with a wide range of services without requiring custom code for each integration. It supports vector-based semantic search for efficient API operation discovery, making it particularly useful for applications that need to work with multiple or frequently changing APIs. By abstracting the complexities of API integration, this server allows for rapid development of AI-powered applications that can leverage external services and data sources through a standardized interface.', '@baryhuang', 'development', 'Unknown', 80, 'https://github.com/baryhuang/mcp-server-any-openapi', NULL, 0, 'https://github.com/baryhuang.png?size=128', '2026-03-09T05:21:01.918536+00:00'),
  ('headless-gmail', 'Headless Gmail', 'MCP Headless Gmail Server provides a way to access Gmail functionality without requiring local credential setup or browser access. Built by baryhuang, it enables any client to complete the OAuth flow independently and then pass credentials as context to the server, creating a complete separation between credential storage and implementation. The server supports getting recent emails, sending messages, and handling token refresh operations through a clean API that works in containerized environments. This implementation is particularly valuable for headless or remote applications where traditional Gmail access methods requiring local file access or browser interaction are not feasible.', '@baryhuang', 'communication', 'Unknown', 55, 'https://github.com/baryhuang/mcp-headless-gmail', NULL, 0, 'https://github.com/baryhuang.png?size=128', '2026-03-09T05:21:01.918572+00:00'),
  ('vnc-remote-control-for-macos', 'VNC Remote Control for macOS', 'MCP Remote macOS Server provides secure remote control of macOS machines through VNC protocol, enabling AI assistants to capture screenshots and interact with the remote desktop through mouse and keyboard inputs. The implementation supports Apple Authentication (protocol 30) for secure connections, handles screen scaling for consistent display, and includes comprehensive error handling for connection issues. Built with a focus on security and reliability, this server is ideal for remote administration, automated testing, or AI-powered interaction with macOS systems.', '@baryhuang', 'development', 'Unknown', 465, 'https://github.com/baryhuang/mcp-remote-macos-use', NULL, 0, 'https://github.com/baryhuang.png?size=128', '2026-03-09T05:21:01.918601+00:00'),
  ('kai-kubernetes', 'Kai (Kubernetes)', 'Kai is a Model Context Protocol server that provides a bridge between large language models and Kubernetes clusters, enabling users to manage their Kubernetes resources through natural language. Built in Go using the mcp-go library, it offers tools for pod management (listing, retrieving details, streaming logs, deletion), with a cluster manager that handles connections to multiple Kubernetes contexts. The server exposes a comprehensive API that Claude can use to interact with Kubernetes resources, making it particularly valuable for DevOps workflows where users need to monitor or manipulate container environments without remembering complex kubectl commands.', '@basebandit', 'cloud', 'Unknown', 19, 'https://github.com/basebandit/kai', NULL, 0, 'https://github.com/basebandit.png?size=128', '2026-03-09T05:21:01.918624+00:00'),
  ('base-blockchain', 'Base Blockchain', 'This MCP server provides onchain tools for Claude AI to interact with the Base blockchain and Coinbase API. Developed by Dan Schlabach and Tina He, it enables operations like retrieving wallet addresses, getting testnet ETH, listing balances, transferring funds, and deploying smart contracts. The implementation uses TypeScript and leverages the Coinbase SDK to facilitate blockchain interactions, making it valuable for users who want to perform cryptocurrency operations or smart contract deployments directly through Claude.', '@base', 'development', 'Unknown', 342, 'https://github.com/base/base-mcp', 'base-mcp', 3893, 'https://github.com/base.png?size=128', '2026-03-09T05:21:01.918651+00:00'),
  ('deepseek-reasoner', 'DeepSeek Reasoner', 'This MCP server, developed by Based_H-10, integrates the DeepSeek API''s reasoning capabilities with Claude. Built with Python and leveraging the FastMCP framework, it provides a tool for enhancing Claude''s responses with DeepSeek''s R1 reasoning engine. The implementation focuses on seamlessly combining DeepSeek''s advanced reasoning, which evolved from large-scale reinforcement learning, with Claude''s existing capabilities. It''s particularly useful for applications requiring more sophisticated reasoning and analysis, enabling use cases such as complex problem-solving, in-depth research assistance, and nuanced decision support without directly exposing users to the intricacies of the DeepSeek API.', '@harshj23', 'ai-ml', 'Unknown', 51, 'https://github.com/harshj23/deepseek-claude-mcp-server', NULL, 0, 'https://github.com/harshj23.png?size=128', '2026-03-09T05:21:01.918697+00:00'),
  ('basehub-forums', 'BaseHub Forums', 'Forums is an AI-powered Q&A platform for GitHub repositories, built by BaseHub. It allows users to ask questions about any public GitHub repo and receive source-backed answers from AI agents that clone, explore, and grep the source code. Accessible via a web interface, CLI tool, or MCP server, Forums provides a streamable-http remote endpoint for integration with Claude Desktop, Cursor, and other MCP-compatible clients.', '@basehub-ai', 'development', 'Unknown', 41, 'https://github.com/basehub-ai/forums/tree/HEAD/apps/web', NULL, 0, 'https://github.com/basehub-ai.png?size=128', '2026-03-09T05:21:01.918717+00:00'),
  ('dos-games', 'DOS Games', 'This MCP server provides AI assistants with access to classic DOS games through a web-based js-dos emulator, built by Basement Studio using TypeScript and Express. The implementation includes four pre-configured games (DOOM, Super Mario, Tetris, and Duke Nukem 3D) with custom key mappings and controls, automatically launching games in Chrome with both local file support and CDN fallback options. Built with port management starting from 5555, server lifecycle controls, and a retro terminal-styled interface with fullscreen support, it serves developers wanting to integrate nostalgic gaming experiences into AI workflows, teams building entertainment applications, and users seeking interactive DOS game access through conversational interfaces with proper game controls and visual feedback.', '@basementstudio', 'development', 'Unknown', 4, 'https://github.com/basementstudio/mcp-dos', 'mcp-dos', 375, 'https://github.com/basementstudio.png?size=128', '2026-03-09T05:21:01.918749+00:00'),
  ('inbound-lead-generation', 'Inbound Lead Generation', 'The Lead Generation Server is a production-grade system built on the MCP Python SDK that enables AI assistants to discover and enrich business leads through multiple data sources. It implements a complete lead lifecycle with UUID-based tracking, leveraging Google CSE for discovery, Hunter.io and Clearbit for data enrichment, and LinkedIn scraping via Playwright for deeper insights. The server features smart caching with Redis, asynchronous processing for high concurrency, and comprehensive monitoring via Prometheus. Particularly valuable for sales teams and marketers who need to generate qualified leads without switching between multiple tools, it provides a unified API for lead generation, enrichment, and maintenance operations.', '@bashirk', 'databases', 'Unknown', 11, 'https://github.com/bashirk/inbound-mcp', NULL, 0, 'https://github.com/bashirk.png?size=128', '2026-03-09T05:21:01.918764+00:00'),
  ('code-remote', 'Code Remote', 'Code Remote enables AI assistants to execute commands on your local machine through a secure relay architecture. The system consists of a cloud-hosted server that exposes MCP tools for shell commands, file operations, and directory listing, paired with a local agent that runs on your machine and executes the actual commands. Commands are queued through WebSocket connections with token-based authentication, and the agent restricts file access to safe directories for security.', '@basicmachines-co', 'development', 'Unknown', 2, 'https://github.com/basicmachines-co/code-remote', NULL, 0, 'https://github.com/basicmachines-co.png?size=128', '2026-03-09T05:21:01.918787+00:00'),
  ('basic-memory', 'Basic Memory', 'How It Works
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('grok-cli', 'Grok CLI', 'Provides a bridge to Grok AI through the official Grok CLI, offering three specialized tools for different interaction patterns: simple prompt-response queries, multi-turn conversations with message history, and code generation with language hints and context. Built by Basis Set Ventures using a CLI wrapper approach that leverages the official Grok CLI in headless mode, with JSON parsing and fallback to raw output for debugging. Supports configurable timeouts, optional model selection, and handles both structured and unstructured responses, making it useful for integrating Grok''s capabilities into AI workflows that need reliable access to X.AI''s models.', '@basissetventures', 'development', 'Unknown', 6, 'https://github.com/basissetventures/grok-cli-mcp', NULL, 0, 'https://github.com/basissetventures.png?size=128', '2026-03-09T05:21:01.918839+00:00'),
  ('local-memory', 'Local Memory', 'Provides local memory storage and retrieval for AI agents using vector embeddings generated by Ollama models. Stores memories as vectors in a Zvec database with metadata including workspace keys, memory types (decisions, preferences, facts, etc.), importance scores, and timestamps. Features semantic search, memory superseding for updates, workspace isolation, and automatic relevance scoring based on embedding similarity and importance weights. Designed for agents that need persistent memory across conversations without relying on external cloud services.', '@basst85', 'databases', 'Unknown', 4, 'https://github.com/basst85/local-memory-mcp', NULL, 0, 'https://github.com/basst85.png?size=128', '2026-03-09T05:21:01.918850+00:00'),
  ('delphi-build', 'Delphi Build', 'This MCP server enables AI coding agents to compile Delphi projects by providing direct access to the Delphi command-line compiler with intelligent configuration management. It automatically parses .dproj files to extract build settings, manages complex library search paths through a TOML configuration system, and includes a config generation tool that analyzes IDE build logs to automatically create proper compiler configurations. The implementation filters compiler output to show only errors while hiding warnings and hints, supports both Win32 and Win64 platforms with Debug/Release configurations, and handles response files for command lines exceeding 8000 characters. Built for AI agents working on Delphi codebases where manual compiler setup would be complex.', '@basti-fantasti', 'development', 'Unknown', 5, 'https://github.com/basti-fantasti/delphi-build-mcp-server', NULL, 0, 'https://github.com/basti-fantasti.png?size=128', '2026-03-09T05:21:01.918890+00:00'),
  ('telegram-bot-bridge', 'Telegram Bot Bridge', 'A Telegram server by Ray Volcy that enables remote control of Claude Code sessions via Telegram bot integration, allowing users to send messages to Claude and receive responses through Telegram while maintaining session state across multiple concurrent projects. The implementation features shared file-based storage for cross-process communication, dynamic polling intervals that adapt based on session activity, and persistent message queuing to handle asynchronous interactions between Claude and Telegram users. Built with session management, file locking for concurrent access, and automatic cleanup of idle sessions, it''s useful for developers who want to interact with Claude Code remotely, collaborate on projects through Telegram, or maintain multiple coding sessions accessible from mobile devices.', '@batianvolyc', 'development', 'Unknown', 28, 'https://github.com/batianvolyc/telegram-mcp-server', 'telegram-mcp-server', 3100, 'https://github.com/batianvolyc.png?size=128', '2026-03-09T05:21:01.918921+00:00'),
  ('dida365', 'Dida365', 'Provides integration with the Dida365 (TickTick China) task management API, enabling task and project management within the Dida365 ecosystem. Supports OAuth 2.0 authentication for secure access to user accounts and includes comprehensive task management operations like setting due dates, priorities, subtasks, and project assignments. Useful for automating personal productivity workflows and managing project tasks for users of the Chinese market version of TickTick.', '@bayinl', 'productivity', 'Unknown', 4, 'https://github.com/bayinl/dida-mcp', NULL, 0, 'https://github.com/bayinl.png?size=128', '2026-03-09T05:21:01.918957+00:00'),
  ('conda-executor', 'Conda Executor', 'This MCP Code Executor, developed by bazinga012, enables AI assistants to execute Python code within specified Conda environments. Built using TypeScript and the Model Context Protocol SDK, it provides a secure and configurable way to run code with access to predefined libraries and dependencies. The implementation focuses on isolating code execution, allowing for flexible environment management and code storage. It''s particularly useful for AI workflows that require dynamic code generation and execution, such as data analysis, algorithm testing, or automated scripting tasks, without compromising system security or managing complex runtime setups.', '@bazinga012', 'development', 'Unknown', 215, 'https://github.com/bazinga012/mcp_code_executor', NULL, 0, 'https://github.com/bazinga012.png?size=128', '2026-03-09T05:21:01.918983+00:00'),
  ('obsidian', 'Obsidian', 'A comprehensive MCP server for Obsidian vault integration that provides both local filesystem and remote API connectivity to Obsidian knowledge bases. The implementation offers advanced features including knowledge graph analysis, Dataview-style querying, template management with variable substitution, periodic notes creation, and Canvas file manipulation, while supporting multiple vault configurations and real-time file watching. Built with TypeScript and extensive testing coverage, it enables AI assistants to perform sophisticated operations on Obsidian vaults including note creation/editing, link analysis, tag-based searching, and graph traversal for finding related content and suggesting connections between notes.', '@bazylhorsey', 'development', 'Unknown', 23, 'https://github.com/bazylhorsey/obsidian-mcp-server', NULL, 0, 'https://github.com/bazylhorsey.png?size=128', '2026-03-09T05:21:01.919013+00:00'),
  ('installer', 'Installer', 'Streamlines MCP server discovery and installation by integrating with the Smithery registry to search available servers, collect configuration requirements, and generate automated installation commands for various development environments.', '@bbangjooo', 'development', 'Unknown', 5, 'https://github.com/bbangjooo/mcp-installer', NULL, 0, 'https://github.com/bbangjooo.png?size=128', '2026-03-09T05:21:01.919029+00:00'),
  ('lacylights', 'LacyLights', 'This MCP server provides AI-powered theatrical lighting design capabilities for the LacyLights system, integrating OpenAI''s GPT-4 with GraphQL-based fixture management and DMX control. Built by bbernstein, it offers comprehensive tools for script analysis, automated scene generation with intelligent color mixing and intensity control, cue sequence creation with timing optimization, and fixture inventory management across multiple DMX universes. The implementation uses RAG (Retrieval-Augmented Generation) with lighting pattern matching to generate contextually appropriate lighting designs from theatrical scripts, making it valuable for lighting designers who want to automate repetitive design tasks, generate initial lighting concepts from script analysis, and manage complex multi-fixture setups with AI assistance rather than manual DMX programming.', '@bbernstein', 'productivity', 'Unknown', 5, 'https://github.com/bbernstein/lacylights-mcp', NULL, 0, 'https://github.com/bbernstein.png?size=128', '2026-03-09T05:21:01.919080+00:00'),
  ('ai-memory-protocol', 'AI Memory Protocol', 'Stores conversation context as structured reStructuredText files using Sphinx-Needs directives, combining human-readable documentation with machine-queryable data. Supports typed memory entries (observations, decisions, facts, preferences, risks, goals, questions) with graph-based relationship tracking (relates, supports, depends, supersedes, contradicts), hierarchical tagging, confidence scoring, and automatic stale detection. Provides a CLI with 16+ subcommands and autonomous capture from Git commits, CI logs, and discussion transcripts.', '@bburda', 'development', 'Unknown', 3, 'https://github.com/bburda/ai_memory_protocol', NULL, 0, 'https://github.com/bburda.png?size=128', '2026-03-09T05:21:01.919105+00:00'),
  ('io-github-sidneybissoli-bcb-br-mcp', 'io.github.SidneyBissoli/bcb-br-mcp', 'MCP Server for Brazilian Central Bank Time Series (SGS/BCB) - Economic and Financial Data', '@sidneybissoli', 'development', 'Unknown', 0, 'https://github.com/sidneybissoli/bcb-br-mcp', NULL, 0, 'https://github.com/sidneybissoli.png?size=128', '2026-03-09T05:21:01.919121+00:00'),
  ('prometheus', 'Prometheus', 'Production-grade Prometheus integration providing 38 specialized tools for monitoring operations, query execution, alert management, target monitoring, anomaly detection, capacity forecasting, SRE golden signals calculation, and PromQL optimization with enterprise deployment support.', '@bcfmtolgahan', 'data-analytics', 'Unknown', 3, 'https://github.com/bcfmtolgahan/prometheus-mcp-server', NULL, 0, 'https://github.com/bcfmtolgahan.png?size=128', '2026-03-09T05:21:01.919184+00:00'),
  ('cursor-sound-notifications', 'Cursor Sound Notifications', 'Cursor Sound MCP is a server that plays audio feedback when AI completes code generation in the Cursor editor. Built with TypeScript and the Model Context Protocol SDK, it uses the play-sound library to trigger customizable sound effects through a simple tool interface. The implementation features error handling, proper logging to stderr, and a stable JSON response format. Originally inspired by @EricListin on X.com, this MCP enhances the coding experience by providing auditory notifications that alert users when Cursor AI has finished generating code, eliminating the need to constantly monitor the screen for completions.', '@bcharleson', 'development', 'Unknown', 2, 'https://github.com/bcharleson/sound-mcp', NULL, 0, 'https://github.com/bcharleson.png?size=128', '2026-03-09T05:21:01.919210+00:00'),
  ('instantly', 'Instantly', 'Instantly MCP Server provides a bridge to the Instantly API v2, enabling AI assistants to manage email campaigns and leads through a set of 17 tools. Developed by bcharleson, it implements endpoints for creating and managing leads, listing campaigns, analyzing email warmup performance, testing account health, and handling email account administration. The server is built with TypeScript using the Model Context Protocol SDK, can be run via Docker or NPX, and requires an Instantly API key for authentication. It''s particularly valuable for users who need to automate email outreach, monitor campaign performance, or manage email account health directly within AI assistant conversations.', '@bcharleson', 'cloud', 'Unknown', 18, 'https://github.com/bcharleson/instantly-mcp', NULL, 0, 'https://github.com/bcharleson.png?size=128', '2026-03-09T05:21:01.919231+00:00'),
  ('sketchup', 'SketchUp', 'SketchUp MCP Server enables AI assistants to control and manipulate 3D models in SketchUp through a WebSocket-based communication system. It provides tools for creating, transforming, and modifying components, applying materials, performing boolean operations, and executing arbitrary Ruby code directly in the SketchUp environment. The implementation includes both a Python server component that implements the Model Context Protocol and a Ruby extension for SketchUp, making it particularly valuable for AI-assisted 3D modeling, architectural design, and woodworking projects.', '@bearnetwork-brnkc', 'development', 'Unknown', 14, 'https://github.com/bearnetwork-brnkc/sketchup-mcp', NULL, 0, 'https://github.com/bearnetwork-brnkc.png?size=128', '2026-03-09T05:21:01.919257+00:00'),
  ('beat-and-raise-sec-filings', 'Beat and Raise (SEC Filings)', 'BeatAndRaise MCP server provides direct access to SEC filings database through Claude and other MCP clients, enabling natural language queries across every filing since 1995. Built by beatandraise.com, it offers intelligent search capabilities, financial analysis tools, and structured data extraction from millions of SEC documents without requiring API keys. The implementation integrates seamlessly with Claude''s interface for real-time financial research, historical data analysis, and automated extraction of tables and financial metrics, making it valuable for investment research, compliance monitoring, and financial due diligence workflows.', '@unknown', 'databases', 'Unknown', 0, 'https://beatandraise.com/mcp', NULL, 0, NULL, '2026-03-09T05:21:01.919269+00:00'),
  ('zen', 'Zen', 'This MCP server provides Google Gemini 2.5 Pro integration as a development partner for Claude, enabling extended reasoning, code analysis, and collaborative problem-solving through a 1M token context window. Built by Fahad Gilani at Beehive Innovations using Python with the Google GenAI SDK, it offers five specialized tools: think_deeper for extended reasoning with enhanced thinking models, review_code for professional code reviews with severity prioritization, debug_issue for systematic root cause analysis, analyze for file and directory exploration, and chat for collaborative brainstorming. The implementation features automatic directory expansion with intelligent file filtering, dynamic context requests where Gemini can ask Claude for additional files mid-analysis, configurable thinking modes from minimal to maximum reasoning depth, and standardized JSON responses for seamless integration, making it valuable for architectural decision validation, large codebase analysis beyond Claude''s context limits, complex debugging workflows, and collaborative development where multiple AI perspectives enhance problem-solving.', '@beehiveinnovations', 'development', 'Unknown', 11215, 'https://github.com/beehiveinnovations/pal-mcp-server', NULL, 0, 'https://github.com/beehiveinnovations.png?size=128', '2026-03-09T05:21:01.919301+00:00'),
  ('pal-multi-provider-ai', 'PAL (Multi-Provider AI)', 'Provider Abstraction Layer (PAL) orchestrates multiple AI models including Claude, Gemini, GPT, and others for collaborative code analysis, debugging, and development workflows. Built by Beehive Innovations, it offers 15+ specialized tools for code review, planning, consensus building, and workflow automation with intelligent model selection and multi-step workflows with forced pauses for thorough investigation. Features automatic model ranking, conversation memory, file processing with security controls, image analysis capabilities, and integration with CLI tools like Claude Code, Codex, and Gemini CLI for seamless development workflows. Supports extended reasoning modes and custom endpoints for maximum flexibility.', '@yiwenlu66', 'cloud', 'Unknown', 3, 'https://github.com/yiwenlu66/mu-mcp', NULL, 0, 'https://github.com/yiwenlu66.png?size=128', '2026-03-09T05:21:01.919323+00:00'),
  ('cooper-hewitt', 'Cooper Hewitt', 'This Cooper Hewitt MCP server, developed by behole, provides an interface for AI assistants to interact with the Cooper Hewitt Museum''s collection API. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers tools for searching objects and retrieving detailed information about specific museum artifacts. The implementation focuses on efficient data retrieval and formatting, making it easy for AI models to explore and analyze the museum''s vast collection. It''s particularly useful for tasks like art research, cultural analysis, or integrating museum data into AI-driven applications, allowing assistants to access Cooper Hewitt''s extensive design archive without requiring deep knowledge of the underlying API complexities.', '@behole', 'development', 'Unknown', 2, 'https://github.com/behole/cooper-hewitt-mcp', NULL, 0, 'https://github.com/behole.png?size=128', '2026-03-09T05:21:01.919354+00:00'),
  ('memdx', 'MemDx', 'Provides local memory layer using Qdrant vector storage and Ollama embeddings for persistent context storage across conversations, automatically indexing project documentation and enabling user-defined memory segregation by project without requiring API keys or cloud dependencies.', '@beingpro007', 'productivity', 'Unknown', 2, 'https://github.com/beingpro007/memdx', NULL, 0, 'https://github.com/beingpro007.png?size=128', '2026-03-09T05:21:01.919386+00:00'),
  ('docdex', 'Docdex', 'Docdex is a locally-running documentation indexer and search daemon that provides fast full-text search capabilities over markdown and text files within a repository. Built in Rust with a Tantivy-based search backend, it maintains an on-disk index and watches for file changes to incrementally update search results. The server offers comprehensive security features including TLS enforcement, authentication tokens, rate limiting, and audit logging, making it suitable for both development and production environments. It provides multiple integration methods including HTTP API, CLI tools, and native support for connecting AI assistants to project documentation.', '@bekirdag', 'development', 'Unknown', 12, 'https://github.com/bekirdag/docdex', NULL, 0, 'https://github.com/bekirdag.png?size=128', '2026-03-09T05:21:01.919413+00:00'),
  ('famulor', 'Famulor', 'Integrates with Famulor''s voice agent platform for phone calling and voice assistant management. Provides tools for making calls with voice assistants, managing assistant configurations including voice selection and language settings, handling campaigns and leads, sending SMS messages, and configuring mid-call tools that allow assistants to interact with external APIs during conversations. Includes comprehensive webhook integration for external system connectivity, making it valuable for businesses automating phone outreach and customer service operations.', '@bekservice', 'communication', 'Unknown', 1, 'https://github.com/bekservice/famulor-mcp', NULL, 0, 'https://github.com/bekservice.png?size=128', '2026-03-09T05:21:01.919444+00:00'),
  ('datadog', 'Datadog', 'This Datadog MCP server by Clement Hussenot provides integration with the Datadog monitoring and observability platform, enabling AI assistants to interact with Datadog''s APIs for metrics, logs, and monitoring data. Built with Go using the official MCP Go SDK and featuring OpenAPI code generation through oapi-codegen, it offers tools for accessing Datadog''s monitoring capabilities with proper API key authentication and configurable site endpoints. The implementation includes comprehensive development tooling with pre-commit hooks, Spectral API linting, Docker containerization, and multi-language support through Python dependencies, making it valuable for DevOps teams and SREs who need AI-assisted monitoring workflows, incident response automation, and observability data analysis within their existing Datadog infrastructure.', '@believe-sa', 'cloud', 'Unknown', 2, 'https://github.com/believe-sa/datadog-mcp', NULL, 0, 'https://github.com/believe-sa.png?size=128', '2026-03-09T05:21:01.919469+00:00'),
  ('code-auditor', 'Code Auditor', 'Code Auditor creates a searchable index of codebases, enabling analysis of code patterns, quality issues, and architectural violations. Detects SOLID principle violations, code duplication, security vulnerabilities, and provides dependency mapping. Supports TypeScript, JavaScript, and Go with AST-based analysis and fast in-memory searching.', '@benahammond', 'development', 'Unknown', 5, 'https://github.com/benahammond/code-auditor-mcp', NULL, 0, 'https://github.com/benahammond.png?size=128', '2026-03-09T05:21:01.919500+00:00'),
  ('read-mysql', 'Read MySQL', 'This MCP server, developed by Ben Borla, provides read-only access to MySQL databases for large language models. Built in TypeScript, it integrates with Claude Desktop and enables AI assistants to inspect database schemas and execute read-only SQL queries. The implementation stands out by focusing on security through read-only transactions and offering flexible database connection options. By bridging AI models with relational databases, this server allows AI systems to analyze data patterns, extract insights, and provide data-driven responses. It is particularly useful for scenarios like data exploration, report generation, and building AI assistants that can leverage structured data from MySQL databases while maintaining data integrity.', '@benborla', 'databases', 'Unknown', 1292, 'https://github.com/benborla/mcp-server-mysql', '@benborla29/mcp-server-mysql', 177299, 'https://github.com/benborla.png?size=128', '2026-03-09T05:21:01.919511+00:00'),
  ('mysql-explorer', 'MySQL Explorer', 'MCP Server for MySQL provides read-only access to MySQL databases, enabling AI assistants to inspect database schemas and execute safe queries. Built by Ben Borla, this Node.js implementation establishes connections to MySQL servers using environment variables for configuration, enforces read-only transactions for security, and exposes both database schema information as resources and a mysql_query tool for executing SQL statements. The server is containerized with Docker for easy deployment and is particularly valuable for workflows requiring database exploration and data analysis without modifying database contents.', '@hkk101', 'databases', 'Unknown', 0, 'https://github.com/hkk101/mcp-server-mysql', NULL, 0, 'https://github.com/hkk101.png?size=128', '2026-03-09T05:21:01.919522+00:00'),
  ('mysql-read-only', 'MySQL Read-Only', 'MCP Server for MySQL provides read-only access to MySQL databases, enabling AI models to inspect database schemas and execute SQL queries. Built by Ben Borla, it connects to MySQL servers using configurable connection parameters, enforces read-only transactions for security, and supports comprehensive schema information retrieval. The implementation is written in TypeScript using Node.js and the mysql2 library, with Docker support for easy deployment. It''s particularly valuable for data analysis workflows where AI assistants need to explore database structures and extract information without modifying the underlying data.', '@zhaoxin34', 'databases', 'Unknown', 1, 'https://github.com/zhaoxin34/mcp-server-mysql', NULL, 0, 'https://github.com/zhaoxin34.png?size=128', '2026-03-09T05:21:01.919533+00:00'),
  ('pollinations', 'Pollinations', 'Pollinations MCP is a TypeScript-based server implementation that provides text-to-audio API capabilities. Built with the Model Context Protocol SDK, it enables programmatic audio generation through a streamlined interface, supporting developers who need to integrate dynamic audio creation into their applications.', '@bendusy', 'development', 'Unknown', 9, 'https://github.com/bendusy/pollinations-mcp', NULL, 0, 'https://github.com/bendusy.png?size=128', '2026-03-09T05:21:01.919556+00:00'),
  ('beneat', 'Beneat', 'Beneat provides quantitative risk management infrastructure for autonomous trading agents operating on the Solana blockchain. It enforces position sizing, loss limits, and behavioral interventions through on-chain vault contracts with automated lockout mechanisms. The system includes Kelly criterion optimization, trust scoring, agent archetype classification, and comprehensive trade analytics with causal inference to measure enforcement impact.', '@mmmmuhib', 'communication', 'Unknown', 3, 'https://github.com/mmmmuhib/beneat-mcp/tree/HEAD/mcp-server', NULL, 0, 'https://github.com/mmmmuhib.png?size=128', '2026-03-09T05:21:01.919584+00:00'),
  ('kubernetes-tools', 'Kubernetes Tools', 'A Kubernetes monitoring and diagnostics MCP server by Benedat LLC that provides strongly-typed tools for interacting with Kubernetes clusters without requiring kubectl knowledge. Built on the official Kubernetes Python API, it exposes read-only operations like listing pods, nodes, services, and deployments, retrieving container statuses and logs, and viewing pod events through both stdio and HTTP transports. The implementation emphasizes quality over quantity with comprehensive Pydantic models that mirror kubectl output formats, making it ideal for building AI agents that can perform cluster monitoring, root cause analysis, and troubleshooting workflows while maintaining type safety and detailed documentation for reliable agent interactions.', '@benedatllc', 'cloud', 'Unknown', 3, 'https://github.com/benedatllc/k8stools', 'k8stools', 2458, 'https://github.com/benedatllc.png?size=128', '2026-03-09T05:21:01.919608+00:00'),
  ('materials-project', 'Materials Project', 'Materials Project MCP server created by Benedict Debrah and Peniel Fiawornu that provides direct access to the Materials Project database through the mp_api client. The implementation offers 23 specialized tools for querying crystal structures, electronic properties, phonon data, magnetic properties, thermodynamic stability, and more, making it valuable for materials scientists and researchers working with computational materials data. Built with comprehensive Docker support and designed for seamless integration with Claude Desktop and VS Code, it enables natural language queries of one of the world''s largest materials databases without requiring direct API knowledge.', '@benedictdebrah', 'databases', 'Unknown', 10, 'https://github.com/benedictdebrah/materials-project-mcp', NULL, 0, 'https://github.com/benedictdebrah.png?size=128', '2026-03-09T05:21:01.919619+00:00'),
  ('digikey', 'DigiKey', 'This MCP server provides comprehensive access to DigiKey''s Product Search API for electronic component discovery and procurement. Built with FastMCP, it offers tools for keyword-based product searches with advanced filtering and sorting capabilities, manufacturer and category browsing, product substitution finding, detailed component specifications retrieval, pricing information across quantities, and media access including datasheets and 3D models. The implementation supports both sandbox and production environments with OAuth2 authentication, making it ideal for electronics engineers, procurement teams, and automated inventory management systems that need programmatic access to DigiKey''s extensive component database.', '@bengineer19', 'databases', 'Unknown', 19, 'https://github.com/bengineer19/digikey_mcp', NULL, 0, 'https://github.com/bengineer19.png?size=128', '2026-03-09T05:21:01.919630+00:00'),
  ('databricks-sql', 'Databricks SQL', 'Provides direct SQL query execution against Databricks Unity Catalog through the Databricks SDK, enabling exploration of catalogs, schemas, and tables along with their metadata.', '@benguy1000', 'databases', 'Unknown', 0, 'https://github.com/benguy1000/databricks-sql-mcp', NULL, 0, 'https://github.com/benguy1000.png?size=128', '2026-03-09T05:21:01.919641+00:00'),
  ('doc2md', 'doc2md', 'doc2md converts documents from PDF, DOCX, and PPTX formats into clean Markdown. It provides tools for single-file conversion with structure preservation (headings, tables, lists, hyperlinks, footnotes), automatic format detection, and batch processing of multiple files. Supports both file path and base64-encoded content input, with Docker deployment available.', '@benguy1000', 'cloud', 'Unknown', 1, 'https://github.com/benguy1000/doc2md', NULL, 0, 'https://github.com/benguy1000.png?size=128', '2026-03-09T05:21:01.919659+00:00'),
  ('agents-md', 'AGENTS.md', 'This MCP server provides project management and AI-powered task automation through a web-based interface with SQLite storage, user authentication, and version control capabilities. Built by Benhao Tang with Express.js and Next.js, it integrates multiple AI providers (OpenAI, Google Gemini, Groq) and MCP tool servers to enable automated task execution through ''subagents'' that can perform web searches, code execution, and file operations within project contexts. The implementation features hierarchical task management with drag-and-drop Kanban boards, markdown-based agent configuration, scratchpad systems for iterative work, project sharing with granular permissions, and Docker deployment support. Designed for teams and individuals who need AI-assisted project workflows with persistent state management, collaborative editing, and automated task delegation to specialized AI agents with access to external tools and data sources.', '@benhaotang', 'databases', 'Unknown', 5, 'https://github.com/benhaotang/mcp-http-agent-md', NULL, 0, 'https://github.com/benhaotang.png?size=128', '2026-03-09T05:21:01.919671+00:00'),
  ('mathematica-docs', 'Mathematica Docs', 'This Mathematica Documentation MCP server, developed using FastMCP, provides a bridge between AI assistants and Wolfram Mathematica''s extensive documentation. It offers tools for retrieving function documentation, including support for packages and add-ons, as well as listing symbols within packages. Built with Python and integrating with Wolfram''s wolframscript, it enables AI models to access and interpret Mathematica''s rich function library without direct interaction with the software. The implementation is particularly useful for tasks involving mathematical modeling, symbolic computation, or data analysis, allowing AI assistants to leverage Mathematica''s capabilities in problem-solving and scientific computing workflows.', '@benhaotang', 'productivity', 'Unknown', 8, 'https://github.com/benhaotang/mcp-mma-docs', NULL, 0, 'https://github.com/benhaotang.png?size=128', '2026-03-09T05:21:01.919716+00:00'),
  ('serverman-server-manager', 'Serverman (Server Manager)', 'The mcp-serverman companion server is a powerful tool designed to allow Claude/LLMs to manage MCP server configurations across different clients. It provides a comprehensive set of tools for listing, enabling, disabling, profiling, and version-controlling MCP servers, while also supporting operations across multiple clients like Claude Desktop, Cline, and MCP-Bridge. Through its JSON-based interface, it allows AI assistants to perform sophisticated server management tasks, such as saving server states, managing configuration profiles, and bulk operations on multiple servers.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('bernerspace-slack', 'Bernerspace (Slack)', 'Slack Bot MCP server that provides comprehensive Slack workspace integration with OAuth 2.0 authentication, JWT-based client identification, and PostgreSQL token storage for persistent multi-user access. Built with FastMCP and the official Slack SDK, the implementation offers 47+ tools covering messaging, channel management, file uploads, reactions, pins, bookmarks, user management, and team administration, with automatic file source detection for URLs, local paths, and text content. Features a complete OAuth callback flow that maps JWT client IDs to Slack workspace tokens, enabling secure multi-tenant usage where different users can authenticate with their own Slack workspaces, making it valuable for AI assistants that need full Slack functionality across multiple organizations without manual token management.', '@bernerspace', 'databases', 'Unknown', 7, 'https://github.com/bernerspace/bernerspace', NULL, 0, 'https://github.com/bernerspace.png?size=128', '2026-03-09T05:21:01.920347+00:00'),
  ('brain-trust', 'Brain Trust', 'Brain Trust MCP Server provides contextual Q&A capabilities and plan review functionality through OpenAI integration. Built by Matt Bernier using FastMCP, it offers two primary tools: ''phone_a_friend'' for asking questions with optional context, and ''review_plan'' for analyzing plan documents with four review levels (quick, standard, comprehensive, expert) that provide structured feedback including scores, strengths, weaknesses, and suggestions. The implementation uses per-request API key authentication for security, supports configurable OpenAI models and token limits, and includes Docker deployment with nginx reverse proxy, making it valuable for teams needing AI-powered document analysis, strategic planning feedback, or contextual assistance during development workflows.', '@bernierllc', 'cloud', 'Unknown', 2, 'https://github.com/bernierllc/brain-trust-mcp', NULL, 0, 'https://github.com/bernierllc.png?size=128', '2026-03-09T05:21:01.920373+00:00'),
  ('jq-json-query', 'jq JSON Query', 'GoJQ MCP Server provides powerful JSON querying capabilities through the jq filter language, built by Berry Development using Go and the gojq library. The server operates in dual modes: as an MCP server exposing a ''run_jq'' tool that executes jq filters on JSON files with validation and error handling, or as a standalone CLI tool for direct JSON processing. It supports multiple transport protocols (stdio, HTTP, SSE) for flexible integration, includes robust file validation to ensure JSON integrity before processing, and leverages the mature jq ecosystem for complex data transformations, making it valuable for data analysis workflows, API response processing, configuration file manipulation, and any scenario requiring JSON querying within AI conversations.', '@berrydev-ai', 'development', 'Unknown', 1, 'https://github.com/berrydev-ai/gojq-mcp', NULL, 0, 'https://github.com/berrydev-ai.png?size=128', '2026-03-09T05:21:01.920402+00:00'),
  ('radarr-and-sonarr', 'Radarr and Sonarr', 'This MCP server provides AI assistants with access to Radarr (movies) and Sonarr (TV series) data. Built with FastMCP, it implements a standardized protocol for querying movie and TV show collections, offering rich filtering options by year, watched status, actors, and more. The server is designed for seamless integration with Claude Desktop and other MCP-compatible clients, enabling natural language interactions with media libraries.', '@berrykuipers', 'ai-ml', 'Unknown', 30, 'https://github.com/berrykuipers/mcp_services_radarr_sonarr', NULL, 0, 'https://github.com/berrykuipers.png?size=128', '2026-03-09T05:21:01.920439+00:00'),
  ('slack-agent-team', 'Slack Agent Team', 'Enables Claude Code to control and coordinate multi-agent teams through Slack channels. Provides a command loop with non-blocking message polling, dedicated team channels with role-specific agent personas, reaction-to-command automation, SQLite-based context persistence for tasks and decisions, hot reload support, and centralized rate limiting. Includes tools for communication, content management, team notifications, approval workflows, file operations, cost reporting, and operational dashboards.', '@berrzebb', 'databases', 'Unknown', 4, 'https://github.com/berrzebb/mcp-slack-agent-team', NULL, 0, 'https://github.com/berrzebb.png?size=128', '2026-03-09T05:21:01.920450+00:00'),
  ('coingecko', 'CoinGecko', 'MCP CoinGecko Server provides a bridge to the CoinGecko cryptocurrency data API, enabling access to real-time and historical cryptocurrency market information. Built with Python using FastAPI and the pycoingecko library, this server exposes cryptocurrency data as MCP resources, making it valuable for AI assistants that need to retrieve current prices, market trends, or historical data about cryptocurrencies. The implementation supports deployment through the MCP CLI tool and is designed for use cases like financial analysis, investment research, and tracking cryptocurrency market performance.', '@bestjane', 'ai-ml', 'Unknown', 2, 'https://github.com/bestjane/mcp-coingecko-server', NULL, 0, 'https://github.com/bestjane.png?size=128', '2026-03-09T05:21:01.920493+00:00'),
  ('vscode-internal-commands', 'VSCode Internal Commands', 'This VSCode extension MCP server exposes VSCode''s internal commands and functionality to AI assistants through the Model Context Protocol. Built with TypeScript and the fastmcp framework, it provides tools for executing VSCode commands, managing background tasks, and accessing editor capabilities programmatically. The implementation includes a background task executor for long-running operations, command execution with parameter validation, and WebSocket-based communication for real-time interaction. Designed for developers who want AI assistants to directly control their VSCode environment, enabling use cases like automated refactoring, code generation workflows, extension management, and editor automation without manual intervention.', '@bestk', 'development', 'Unknown', 59, 'https://github.com/bestk/vscode-internal-command-mcp-server', NULL, 0, 'https://github.com/bestk.png?size=128', '2026-03-09T05:21:01.920524+00:00'),
  ('industrial-iot-monitoring', 'Industrial IoT Monitoring', 'A complete industrial IoT stack that combines real-time anomaly detection with AI-powered explanations for manufacturing equipment monitoring. Integrates an OPC UA simulator generating realistic production machine data, an LSTM autoencoder for anomaly scoring, and a local LLM (llama.cpp) providing natural language explanations of detected issues through database-backed MCP tools. Includes Bayesian optimization for automated setpoint tuning, WebIQ HMI integration, and supports both CPU and GPU inference with automatic hardware detection.', '@be-student-project', 'databases', 'Unknown', 4, 'https://github.com/be-student-project/be-student-project', NULL, 0, 'https://github.com/be-student-project.png?size=128', '2026-03-09T05:21:01.920536+00:00'),
  ('keynote', 'Keynote', 'This MCP server provides AI assistants with direct control over Apple Keynote presentations through AppleScript automation on macOS, featuring a modular architecture with specialized tools for presentation management, slide operations, content creation, and export functionality. Built with Python and organized into distinct modules for basic slide operations (add, delete, duplicate, move), navigation, layout management, theme-aware content insertion, and export capabilities (PDF, images), it includes smart layout selection that automatically chooses appropriate slide layouts based on content type (image, text, title, quote, comparison) and integrates comprehensive error handling with custom exception classes. The implementation supports both file-based and inline AppleScript execution, requires macOS accessibility and automation permissions, and enables use cases like automated presentation generation, content management workflows, and building AI assistants that need programmatic access to Keynote''s full feature set without manual interface navigation.', '@betancur', 'development', 'Unknown', 10, 'https://github.com/betancur/keynote-mcp', NULL, 0, 'https://github.com/betancur.png?size=128', '2026-03-09T05:21:01.920571+00:00'),
  ('rdl', 'RDL', 'Enables editing of SQL Server Reporting Services (SSRS) RDL files through natural language commands. Provides tools to read report structures, modify columns, headers, formatting, datasets, stored procedures, and parameters. Converts complex XML namespaces into clean JSON for easier manipulation.', '@bethmaloney', 'databases', 'Unknown', 2, 'https://github.com/bethmaloney/rdl-mcp', NULL, 0, 'https://github.com/bethmaloney.png?size=128', '2026-03-09T05:21:01.920582+00:00'),
  ('fastapply', 'FastApply', 'FastApply MCP Server provides intelligent code editing capabilities through integration with local language models, enabling precise code modifications using AST-grep for structural analysis and ripgrep for fast text search. Built by betmoar, it combines multiple search and analysis engines including ast-grep for pattern matching, ripgrep for text search, and custom AST analysis tools to provide comprehensive code understanding and safe refactoring operations with automatic backup creation, validation, and rollback capabilities. The implementation supports batch operations, symbol analysis, reference tracking, and security-focused path validation, making it valuable for large-scale codebase refactoring, automated code quality improvements, and development workflows where precise structural code changes are needed across multiple files while maintaining code integrity and safety.', '@betmoar', 'development', 'Unknown', 5, 'https://github.com/betmoar/fastapply-mcp', NULL, 0, 'https://github.com/betmoar.png?size=128', '2026-03-09T05:21:01.920613+00:00'),
  ('better-icons', 'Better Icons', 'Provides access to 200,000+ icons from 150+ collections through the Iconify API with search, retrieval, batch operations, usage pattern learning, and direct project file synchronization across React, Vue, Svelte, and other frameworks.', '@better-auth', 'productivity', 'Unknown', 406, 'https://github.com/better-auth/better-icons', NULL, 0, 'https://github.com/better-auth.png?size=128', '2026-03-09T05:21:01.920643+00:00'),
  ('chain-of-thought', 'Chain of Thought', 'A Chain of Thought MCP server that exposes raw reasoning tokens from large language models through Groq''s API. The server captures and streams the model''s thinking process by intercepting content within <think> tags, allowing AI assistants to reveal their step-by-step reasoning before providing final answers. Built with FastMCP and supporting models like Qwen and DeepSeek, it enables more transparent AI interactions where users can see how the model arrives at conclusions rather than just receiving the final output.', '@beverm2391', 'ai-ml', 'Unknown', 12, 'https://github.com/beverm2391/chain-of-thought-mcp-server', NULL, 0, 'https://github.com/beverm2391.png?size=128', '2026-03-09T05:21:01.920683+00:00'),
  ('io-github-promptpartner-bexio-mcp-server', 'io.github.PromptPartner/bexio-mcp-server', 'Swiss accounting integration for Bexio. 221 tools for invoices, contacts, projects.', '@promptpartner', 'development', 'Unknown', 2, 'https://github.com/promptpartner/bexio-mcp-server', NULL, 0, 'https://github.com/promptpartner.png?size=128', '2026-03-09T05:21:01.920699+00:00'),
  ('onetool', 'OneTool', 'A comprehensive MCP server bundling over 100 developer tools in a single package. Includes integrations for Brave search, Gemini, Excel file handling, file operations, database access, version checking, and various DevTools utilities.', '@beycom', 'databases', 'Unknown', 5, 'https://github.com/beycom/onetool-mcp', NULL, 0, 'https://github.com/beycom.png?size=128', '2026-03-09T05:21:01.920709+00:00'),
  ('beyond-social-farcaster', 'Beyond Social (Farcaster)', 'Beyond MCP Server provides standardized access to social platform data, currently supporting Farcaster (via Neynar API) with placeholders for Twitter and Telegram integration. It implements a flexible architecture with both stdio and HTTP/SSE transports, making it compatible with Claude Desktop. The server exposes resources and tools for searching content, retrieving user profiles, analyzing threads, and exploring trending topics across platforms. Built with extensibility in mind, it allows easy addition of new platform providers and is particularly valuable for AI assistants that need to incorporate social media context into conversations.', '@beyond-network-ai', 'communication', 'Unknown', 13, 'https://github.com/beyond-network-ai/beyond-mcp-server', NULL, 0, 'https://github.com/beyond-network-ai.png?size=128', '2026-03-09T05:21:01.920744+00:00'),
  ('octocode', 'Octocode', 'This MCP server provides AI assistants with advanced GitHub repository analysis, code discovery, and npm package exploration capabilities through integration with GitHub CLI and npm commands. Built by Guy Bary using TypeScript with the MCP SDK, it offers tools for searching code across repositories, fetching file contents, exploring repository structures, analyzing commit history, searching issues and pull requests, and discovering npm packages with detailed metadata. The implementation features intelligent caching, cross-tool workflow integration where commit SHAs can be used directly for file viewing, comprehensive error handling with actionable suggestions, and optimized response formats that reduce noise while preserving essential information, making it valuable for code analysis, architectural research, dependency exploration, and building AI assistants that need deep understanding of open source codebases and package ecosystems.', '@bgauryy', 'development', 'Unknown', 741, 'https://github.com/bgauryy/octocode-mcp', 'octocode-mcp', 60177, 'https://github.com/bgauryy.png?size=128', '2026-03-09T05:21:01.920773+00:00'),
  ('boardgamegeek', 'BoardGameGeek', 'Provides comprehensive access to BoardGameGeek''s database through nine specialized tools. Search and retrieve detailed game information, query user collections with advanced filters, track trending games, compare prices across retailers, discover trading opportunities, and get personalized recommendations. Includes forum integration for rules clarification.', '@kkjdaniel', 'databases', 'Unknown', 31, 'https://github.com/kkjdaniel/bgg-mcp', NULL, 0, 'https://github.com/kkjdaniel.png?size=128', '2026-03-09T05:21:01.920784+00:00'),
  ('prts-gaming-platform', 'PRTS Gaming Platform', 'This MCP server implementation provides tools for agent messaging and web crawling capabilities, specifically targeting PRTS (likely a game-related platform) data extraction. Built with TypeScript and leveraging Puppeteer for browser automation, Cheerio for HTML parsing, and Express for web server functionality, it enables AI assistants to crawl and extract structured data from web pages while providing agent communication tools. The implementation is designed for scenarios requiring automated data collection from gaming platforms or similar web-based services, making it valuable for building AI assistants that need to gather and process real-time information from specific websites.', '@bgsuyu', 'development', 'Unknown', 1, 'https://github.com/bgsuyu/arc-ccb-ai/tree/HEAD/MCP_server', NULL, 0, 'https://github.com/bgsuyu.png?size=128', '2026-03-09T05:21:01.920814+00:00'),
  ('hedera-testnet-mirror-node', 'Hedera Testnet Mirror Node', 'Hedera MCP Server provides a bridge to the Hedera Testnet Mirror Node API, dynamically converting Zodios API endpoints into MCP tools using Server-Sent Events (SSE) transport. Built by bguiz, this implementation enables programmatic interaction with Hedera blockchain data by automatically generating tools for querying accounts, transactions, tokens, and other network information with robust Zod-based validation.', '@hedera-dev', 'development', 'Unknown', 3, 'https://github.com/hedera-dev/mirrornode-mcp-server', NULL, 0, 'https://github.com/hedera-dev.png?size=128', '2026-03-09T05:21:01.920839+00:00'),
  ('sqlite-memory', 'SQLite Memory', 'SQLite Memory provides persistent memory storage using SQLite databases. It enables storing and retrieving structured data, conversation history, and user preferences across sessions through simple key-value operations. The server supports creating, reading, updating, listing, and deleting memory entries with automatic timestamping, built on FastMCP with a single-table schema for straightforward data persistence.', '@bharathjinka09', 'databases', 'Unknown', 1, 'https://github.com/bharathjinka09/ai-mcp-sql', NULL, 0, 'https://github.com/bharathjinka09.png?size=128', '2026-03-09T05:21:01.920850+00:00'),
  ('whois', 'WHOIS', 'A Model Context Protocol (MCP) server implementation for WHOIS domain lookup service.', '@bharathvaj-ganesan', 'ai-ml', 'Unknown', 51, 'https://github.com/bharathvaj-ganesan/whois-mcp', NULL, 0, 'https://github.com/bharathvaj-ganesan.png?size=128', '2026-03-09T05:21:01.920880+00:00'),
  ('autopentest-ai', 'AutoPentest AI', 'AutoPentest AI is an agentic penetration testing system that automates web application security testing using the OWASP Web Security Testing Guide (WSTG). It crawls target applications, maps endpoints, and spawns parallel agents to test for vulnerabilities including XSS, SQL injection, SSRF, SSTI, and IDOR. The system bundles pre-configured security tools such as nuclei, sqlmap, dalfox, katana, ffuf, and nmap within a Docker container, and integrates Playwright for browser-based testing of DOM XSS, clickjacking, and JavaScript-rendered authentication flows.', '@bhavsec', 'databases', 'Unknown', 36, 'https://github.com/bhavsec/autopentest-ai', NULL, 0, 'https://github.com/bhavsec.png?size=128', '2026-03-09T05:21:01.920891+00:00'),
  ('apple-automation', 'Apple Automation', 'Apple MCP Server provides a lightweight server for controlling macOS applications via AppleScript, with built-in tools for managing Spotify playback and opening iTerm. Developed by bhwang, this implementation enables programmatic interaction with specific macOS apps through simple, predefined commands like playing music or launching terminal windows. The server uses the Model Context Protocol SDK to expose these system control capabilities as callable tools.', '@gnosis23', 'media', 'Unknown', 4, 'https://github.com/gnosis23/apple-mcp-server', NULL, 0, 'https://github.com/gnosis23.png?size=128', '2026-03-09T05:21:01.920955+00:00'),
  ('bibliomantic-oracle', 'Bibliomantic Oracle', 'Integrates traditional I Ching divination with AI responses using the bibliomantic approach from Philip K. Dick''s "The Man in the High Castle", where characters consult the ancient Chinese oracle for guidance on important decisions. The server implements the complete 64-hexagram system with authentic three-coin method simulation using cryptographically secure randomness, providing tools for divination, bibliomantic consultation, and hexagram lookup alongside resources for loading hexagram data directly into AI context. Built with educational and philosophical reflection purposes in mind, it demonstrates how ancient wisdom traditions can be thoughtfully integrated with modern AI through clear ethical boundaries, making it valuable for creative writing, philosophical contemplation, and exploring the intersection of traditional divination systems with contemporary technology.', '@d4nshields', 'ai-ml', 'Unknown', 2, 'https://github.com/d4nshields/bibliomantic-mcp-server', NULL, 0, 'https://github.com/d4nshields.png?size=128', '2026-03-09T05:21:01.921012+00:00'),
  ('biblioth-que-nationale-de-france-gallica', 'Bibliothèque Nationale de France (Gallica)', 'Bibliothèque Nationale de France MCP server provides access to the Gallica digital library through a structured API client. It enables searching for books, periodicals, manuscripts, images, and other documents using natural language queries or specific metadata fields like title, author, and subject. The implementation includes a sequential reporting tool that helps generate comprehensive research reports with proper citations, automatically searching for relevant sources and organizing them into structured sections. Particularly valuable for academic research, historical analysis, and educational content creation that requires access to France''s national library collections.', '@kryzo', 'development', 'Unknown', 9, 'https://github.com/kryzo/mcp-bibliotheque_nationale_de_france', NULL, 0, 'https://github.com/kryzo.png?size=128', '2026-03-09T05:21:01.921049+00:00'),
  ('bifrost-vs-code-dev-tools', 'Bifrost (VS Code Dev Tools)', 'This MCP server implementation provides C# language features via the Model Context Protocol. It integrates with the C# extension for Visual Studio Code and exposes capabilities like finding symbol references across a codebase. The server runs on port 8003 and is designed to enhance AI-assisted coding workflows for C# projects.', '@biegehydra', 'development', 'Unknown', 207, 'https://github.com/biegehydra/bifrostmcp', NULL, 0, 'https://github.com/biegehydra.png?size=128', '2026-03-09T05:21:01.921108+00:00'),
  ('biel', 'Biel', 'MCP server implementation by TechDocs Studio that provides AI assistants with access to documentation and knowledge bases through a remote proxy architecture using Server-Sent Events (SSE). The implementation runs as a FastAPI server on port 7832 and acts as a bridge between MCP clients and documentation systems, requiring project slug and domain parameters to connect to specific documentation sources via the mcp.biel.ai service. Built with Docker support and health monitoring, it enables AI assistants to query product documentation, API specifications, and troubleshooting guides without direct API integration, serving teams that want conversational access to their technical documentation and knowledge management systems.', '@techdocsstudio', 'cloud', 'Unknown', 2, 'https://github.com/techdocsstudio/biel-mcp', NULL, 0, 'https://github.com/techdocsstudio.png?size=128', '2026-03-09T05:21:01.921132+00:00'),
  ('igdb', 'IGDB', 'An MCP server providing access to the IGDB (Internet Game Database) API for comprehensive video game information retrieval. Built by bielacki using FastMCP and httpx, it enables querying game details, release dates, platforms, genres, ratings, and other gaming metadata through IGDB''s extensive database. The implementation handles API authentication and provides structured access to gaming data, making it useful for building gaming applications, research projects analyzing the video game industry, content creation workflows involving game information, and AI assistants that need to answer questions about video games and gaming history.', '@bielacki', 'databases', 'Unknown', 3, 'https://github.com/bielacki/igdb-mcp-server', NULL, 0, 'https://github.com/bielacki.png?size=128', '2026-03-09T05:21:01.921142+00:00'),
  ('3d-relief-generator', '3D Relief Generator', 'This MCP server converts 2D images into 3D relief STL files for 3D printing by generating depth maps from image brightness values and creating triangulated mesh surfaces with configurable base thickness. Built by Bigchx using Python with OpenCV, PIL, and FastAPI, the implementation accepts both local file paths and web URLs as input, processes images through grayscale conversion and Gaussian blur filtering, then generates ASCII STL files with proper facet normals for 3D model compatibility. The server offers detailed control over model dimensions, depth inversion, detail levels, and base thickness parameters, making it useful for creating custom relief sculptures, converting artwork to printable models, or generating tactile representations of images for educational or artistic purposes.', '@bigchx', 'ai-ml', 'Unknown', 17, 'https://github.com/bigchx/mcp_3d_relief', NULL, 0, 'https://github.com/bigchx.png?size=128', '2026-03-09T05:21:01.921204+00:00'),
  ('neovim-integration', 'Neovim Integration', 'This Neovim MCP server, developed by Derek White (bigcodegen), integrates Claude Desktop with Neovim using the Model Context Protocol and the official neovim/node-client library. It leverages Vim''s native text editing commands to create a lightweight code assistance layer, allowing AI to interact directly with Neovim sessions. The server connects to a running Nvim instance, providing tools to view and edit buffers, execute Vim commands, and retrieve editor status. By abstracting Neovim''s complexities, it enables AI assistants to seamlessly work within the familiar Vim environment. This implementation is particularly useful for developers seeking AI-enhanced coding assistance within their preferred text editor, facilitating tasks such as code review, refactoring, and context-aware suggestions without leaving the Neovim ecosystem.', '@bigcodegen', 'development', 'Unknown', 295, 'https://github.com/bigcodegen/mcp-neovim-server', 'mcp-neovim-server', 7313, 'https://github.com/bigcodegen.png?size=128', '2026-03-09T05:21:01.921234+00:00'),
  ('excel-bridge', 'Excel Bridge', 'MCP Excel Server provides a bridge between AI assistants and Excel files, enabling reading from and writing to spreadsheets through a Spring Boot application. Developed by bigcoder84, this server exposes Excel operations as MCP tools that handle structured data exchange with standardized request/response patterns. The implementation includes services for both reading data from Excel files (returning content as a list of key-value maps) and writing data to Excel files, making it particularly useful for data analysis, reporting, and automated document generation workflows.', '@bigcoder84', 'development', 'Unknown', 6, 'https://github.com/bigcoder84/mcp-excel-server', NULL, 0, 'https://github.com/bigcoder84.png?size=128', '2026-03-09T05:21:01.921260+00:00'),
  ('twi-text-to-image', 'TWI (Text-to-Image)', 'A text-to-image MCP server implementation that integrates with machine learning models through the transformers library to provide AI-powered image generation capabilities. Built with Python 3.13 and leveraging numpy, Pillow, and Pydantic for robust image processing and data validation, it exposes text-to-image functionality through MCP tools while maintaining clean separation between client and server components. The implementation includes dedicated client testing utilities and follows standard MCP patterns with console script entry points, making it useful for applications requiring image generation from text prompts, AI-assisted creative workflows, and integration of image synthesis capabilities into larger systems.', '@bigosprite', 'development', 'Unknown', 1, 'https://github.com/bigosprite/mcp-python-twi', NULL, 0, 'https://github.com/bigosprite.png?size=128', '2026-03-09T05:21:01.921291+00:00'),
  ('greenlight', 'Greenlight', 'Greenlight provides visual feedback for AI assistant work status through full-screen colored terminal displays. The server offers tools for AI assistants to signal their current state (working, waiting for approval, or done) which triggers color changes in a companion display application - green when working, yellow when waiting, and red when complete. The implementation uses file-based communication with PID tracking to coordinate between the MCP server and display components, making it useful for developers who want immediate visual confirmation of task status without monitoring logs or terminal output.', '@bigph00t', 'productivity', 'Unknown', 0, 'https://github.com/bigph00t/greenlight', NULL, 0, 'https://github.com/bigph00t.png?size=128', '2026-03-09T05:21:01.921329+00:00'),
  ('trendradar', 'TrendRadar', 'Monitors and aggregates trending topics from major Chinese platforms including Zhihu, Weibo, Bilibili, Douyin, and Baidu. Features three push strategies (daily summary, real-time rankings, incremental monitoring), customizable keyword filtering with regex support, and cross-platform trend analysis. Delivers curated content through Enterprise WeChat, Feishu, DingTalk, Telegram, and email with data export to HTML and structured formats.', '@bigsunny-007', 'communication', 'Unknown', 1, 'https://github.com/bigsunny-007/trendradar', NULL, 0, 'https://github.com/bigsunny-007.png?size=128', '2026-03-09T05:21:01.921356+00:00'),
  ('clj-kondo', 'clj-kondo', 'The clj-kondo MCP server provides linting capabilities for Clojure, ClojureScript, and EDN files through a standardized interface. It exposes a single tool that runs the popular clj-kondo static analyzer on specified files, supporting custom configuration directories and returning detailed linting results including warnings about unused namespaces, private variables, and other code quality issues. Built with TypeScript using the Model Context Protocol SDK, this implementation enables AI assistants to perform code quality checks on Clojure codebases, making it particularly valuable for Claude code and desktop environments where built-in linting capabilities are not available.', '@bigsy', 'development', 'Unknown', 4, 'https://github.com/bigsy/clj-kondo-mcp', NULL, 0, 'https://github.com/bigsy.png?size=128', '2026-03-09T05:21:01.921410+00:00'),
  ('clojars-dependency-versions', 'Clojars Dependency Versions', 'This Clojars MCP server, developed by Bigsy, enables AI assistants like Claude to retrieve the latest version information for Clojars dependencies. Built in TypeScript, it provides a focused tool for querying the Clojars API to get up-to-date version data for any Maven artifact in the Clojars repository. The implementation stands out by offering a simple, targeted interface specifically for Clojars version lookups. By connecting AI capabilities with Clojars dependency information, this server allows AI systems to programmatically check and suggest library versions for Clojure projects. It is particularly useful for building AI-powered tools that assist with Clojure dependency management, automated project updates, and compatibility checks across Clojure libraries.', '@bigsy', 'development', 'Unknown', 5, 'https://github.com/bigsy/clojars-mcp-server', NULL, 0, 'https://github.com/bigsy.png?size=128', '2026-03-09T05:21:01.921440+00:00'),
  ('maven-dependencies', 'Maven Dependencies', 'This Maven Dependencies MCP server, developed by Bill Hedworth, provides tools for verifying and retrieving Maven dependency versions from the Maven Central Repository. It offers functions to check the latest version of a dependency and verify if specific versions exist. The server uses the Maven Central REST API to fetch real-time dependency information, ensuring up-to-date results. By connecting AI capabilities with Maven dependency management, this implementation enables assistants to validate and update project dependencies, ensuring compatibility and security. It is particularly useful for applications requiring automated dependency checks, version upgrades, or any scenario where an AI system needs to reason about and manage Maven dependencies in software projects.', '@bigsy', 'development', 'Unknown', 31, 'https://github.com/bigsy/maven-mcp-server', NULL, 0, 'https://github.com/bigsy.png?size=128', '2026-03-09T05:21:01.921470+00:00'),
  ('code-explainer', 'Code Explainer', 'This MCP server implementation provides a code explanation service for Cloudflare Workers. It analyzes source code to generate architecture diagrams, identify core functionality, and break down components across multiple programming languages. The server uses bearer token authentication for security and is designed for use cases requiring automated code analysis, documentation generation, or AI-assisted code comprehension. It leverages Cloudflare''s edge computing platform for efficient processing and deployment.', '@billduke13', 'cloud', 'Unknown', 6, 'https://github.com/billduke13/code-explainer-mcp', NULL, 0, 'https://github.com/billduke13.png?size=128', '2026-03-09T05:21:01.921490+00:00'),
  ('chatgpt-responses', 'ChatGPT Responses', 'ChatGPT MCP Server provides a bridge between Claude Desktop and OpenAI''s ChatGPT API through the OpenAI Responses API for simplified conversation management. It offers two main tools: standard ChatGPT interactions and web search-enabled queries, both supporting conversation continuity through response IDs. The server handles various response structures, extracts text content appropriately, and includes comprehensive error handling. Particularly valuable for users who want to leverage ChatGPT''s capabilities directly within Claude Desktop conversations, especially when needing to compare responses between different AI systems or utilize ChatGPT''s web search functionality.', '@billster45', 'communication', 'Unknown', 16, 'https://github.com/billster45/mcp-chatgpt-responses', NULL, 0, 'https://github.com/billster45.png?size=128', '2026-03-09T05:21:01.921527+00:00'),
  ('footballbin', 'FootballBin', 'Provides AI-powered football match predictions for Premier League and UEFA Champions League matches. Returns half-time scores, full-time scores, next goal scorer predictions, and corner count predictions along with key player insights. Supports filtering by league, matchweek, and specific teams.', '@billychl1', 'ai-ml', 'Unknown', 0, 'https://github.com/billychl1/footballbin-mcp-server', NULL, 0, 'https://github.com/billychl1.png?size=128', '2026-03-09T05:21:01.921556+00:00'),
  ('speckle', 'Speckle', 'This Speckle MCP server enables AI assistants to interact with Speckle, a version control platform for 3D design and AEC data. Built with FastMCP and the SpecklePy client library, it provides tools for listing projects, retrieving project details, searching projects by name or description, and accessing model versions. The implementation requires a Speckle token for authentication and connects to the Speckle server (defaulting to app.speckle.systems), making it valuable for architects, engineers, and construction professionals who want to query and analyze their Speckle project data through natural language.', '@bimgeek', 'productivity', 'Unknown', 13, 'https://github.com/bimgeek/speckle-mcp', NULL, 0, 'https://github.com/bimgeek.png?size=128', '2026-03-09T05:21:01.921601+00:00'),
  ('terraform', 'Terraform', 'MCP server assisting LLMs in generating Terraform infrastructure code with automated validation, security analysis, and cost estimation. Features code validation and completion that fills in missing providers, versions, and variables for executable configurations. Detects security misconfigurations like open ports and missing encryption. Computes monthly cloud cost breakdowns using real pricing data via Binadox API. Structures output into logical Terraform files and modules. Operates locally without accessing cloud credentials.', '@binadox-public', 'cloud', 'Unknown', 1, 'https://github.com/binadox-public/binadox-terraform-mcp', NULL, 0, 'https://github.com/binadox-public.png?size=128', '2026-03-09T05:21:01.921621+00:00'),
  ('binalyze-air', 'Binalyze AIR', 'Binalyze AIR MCP Server provides a bridge to the Binalyze AIR digital forensics platform, enabling access to endpoint data, cases, and investigation tools. This TypeScript implementation offers tools for listing assets, organizations, users, cases, tasks, policies, acquisition profiles, and triage rules through a secure API connection. The server validates API tokens, handles organization-specific filtering, and formats responses for easy consumption, making it valuable for security teams who need to query forensic data, monitor endpoint status, or manage digital investigations through AI assistants.', '@binalyze', 'development', 'Unknown', 7, 'https://github.com/binalyze/air-mcp', '@binalyze/air-mcp', 7340, 'https://github.com/binalyze.png?size=128', '2026-03-09T05:21:01.921646+00:00'),
  ('fastdomaincheck', 'FastDomainCheck', 'FastDomainCheck MCP Server provides a bulk domain registration status checking service that enables AI tools like Claude to verify domain availability through WHOIS and DNS queries. Developed by Bingal, it supports checking up to 50 domains simultaneously with dual verification methods for reliability, handling internationalized domain names (IDN), and providing concise registration status results. The implementation is optimized for performance with reasonable timeouts and fallback mechanisms, making it ideal for domain research, brand protection monitoring, and availability checking workflows without leaving the conversation interface.', '@bingal', 'communication', 'Unknown', 36, 'https://github.com/bingal/fastdomaincheck-mcp-server', NULL, 0, 'https://github.com/bingal.png?size=128', '2026-03-09T05:21:01.921682+00:00'),
  ('apple-developer-documentation-rag', 'Apple Developer Documentation (RAG)', 'This MCP server provides AI-powered semantic search and retrieval capabilities for Apple Developer Documentation, built by the Apple RAG Team using TypeScript and deployed on Cloudflare Workers. The implementation combines vector similarity search using PostgreSQL with pgvector, keyword search optimized for technical terms and API names, and AI reranking through SiliconFlow''s embedding and reranker models to deliver highly relevant documentation results. Features include multi-key API failover for reliability, subscription-based rate limiting with anonymous access support, query cleaning to remove temporal information, and comprehensive logging with Telegram notifications, making it ideal for developers building AI assistants that need accurate access to Apple''s technical documentation and API references.', '@bingowon', 'databases', 'Unknown', 110, 'https://github.com/bingowon/apple-rag-mcp', NULL, 0, 'https://github.com/bingowon.png?size=128', '2026-03-09T05:21:01.921696+00:00'),
  ('bing-search', 'Bing Search', 'Search the web using Bing services.', '@microsoft', 'search', 'Unknown', 389, 'https://github.com/microsoft/semanticworkbench/tree/HEAD/mcp-servers/mcp-server-bing-search', NULL, 0, 'https://github.com/microsoft.png?size=128', '2026-03-09T05:21:01.921715+00:00'),
  ('bing-webmaster-tools', 'Bing Webmaster Tools', 'MCP server for Bing Webmaster Tools that provides AI assistants like Claude and Cursor with access to the complete Bing Webmaster API functionality. Developed by Kuba Serafinowski, this Python implementation creates a bridge between AI assistants and Bing''s site management, URL submission, traffic analysis, crawling, keyword analysis, and content management capabilities. The server dynamically wraps all API methods from the underlying bing-webmaster-tools library as MCP tools while preserving their signatures and documentation, making it particularly useful for SEO professionals who want to manage their Bing Webmaster accounts through natural language interactions.', '@zizzfizzix', 'ai-ml', 'Unknown', 7, 'https://github.com/zizzfizzix/mcp-server-bwt', NULL, 0, 'https://github.com/zizzfizzix.png?size=128', '2026-03-09T05:21:01.921762+00:00'),
  ('binspire-waste-management', 'Binspire Waste Management', 'Connects to waste management systems through a PostgreSQL database. Provides standardized tools for managing audits, issues, and history records within waste management operations. Enables interaction with trashbin data, user collections, and organizational workflows for building autonomous waste management agents that track collection activities, monitor system issues, and maintain operational history.', '@binspireai', 'databases', 'Unknown', 3, 'https://github.com/binspireai/mcp', NULL, 0, 'https://github.com/binspireai.png?size=128', '2026-03-09T05:21:01.921774+00:00'),
  ('qlik-sense', 'Qlik Sense', 'Provides access to Qlik Sense Enterprise APIs through both Repository API (REST) and Engine API (WebSocket) endpoints, enabling AI assistants to interact with Qlik Sense applications, data models, and analytics objects. Built by Stanislav Chernov, it supports certificate-based authentication and offers tools for managing apps, users, streams, and tasks through the Repository API, while the Engine API enables direct data extraction, hypercube creation, field analysis, and script access. The server is particularly valuable for business intelligence workflows where users need to query Qlik Sense data models, analyze application metadata, extract table data, or automate reload tasks without manually navigating the Qlik interface.', '@bintocher', 'productivity', 'Unknown', 24, 'https://github.com/bintocher/qlik-sense-mcp', 'qlik-sense-mcp-server', 7102, 'https://github.com/bintocher.png?size=128', '2026-03-09T05:21:01.921821+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('biocontext-knowledgebase', 'BioContext Knowledgebase', 'This MCP server provides AI assistants with unified access to biomedical databases and research tools through a single interface, built by the BioContextAI team using Python with FastMCP and designed to eliminate the need for custom integrations with each biomedical resource. The implementation offers over 20 specialized tools covering protein databases (UniProt, AlphaFold, Human Protein Atlas), genomics resources (Ensembl, KEGG), literature search (Europe PMC, Google Scholar), clinical data (ClinicalTrials.gov, OpenFDA), and ontologies (Gene Ontology, EFO, ChEBI), with both self-hosted deployment options and a hosted service at mcp.biocontext.ai. Built with comprehensive test coverage, Docker support, and integration with the BioContextAI Registry for community tool discovery, it serves researchers needing programmatic access to biomedical data, bioinformatics teams requiring standardized database queries, and AI applications that need verified biomedical information without managing multiple API integrations.', '@biocontext-ai', 'databases', 'Unknown', 20, 'https://github.com/biocontext-ai/knowledgebase-mcp', 'biocontext_kb', 0, 'https://github.com/biocontext-ai.png?size=128', '2026-03-09T05:21:01.921833+00:00'),
  ('skill-to-mcp', 'Skill-to-MCP', 'Converts AI Skills (following Claude Skills format) into MCP server resources, enabling LLM applications to discover and access specialized knowledge and workflows stored in SKILL.md files. Built by BioContextAI for the biomedical research community, it automatically discovers skills from a configurable directory, parses YAML frontmatter for metadata, and provides three core tools: get_available_skills for listing available skills, get_skill_details for retrieving full skill content and file listings, and get_skill_related_file for reading specific files within skill directories with directory traversal protection. Useful for creating skill repositories, building domain-specific AI assistants, and sharing structured knowledge collections across different projects while maintaining separation between the server package and skill content.', '@biocontext-ai', 'development', 'Unknown', 17, 'https://github.com/biocontext-ai/skill-to-mcp', 'skill_to_mcp', 0, 'https://github.com/biocontext-ai.png?size=128', '2026-03-09T05:21:01.921878+00:00'),
  ('daisyui', 'DaisyUI', 'Provides access to DaisyUI component documentation and usage patterns for Tailwind CSS development', '@birdseyevue', 'development', 'Unknown', 38, 'https://github.com/birdseyevue/daisyui-mcp', NULL, 0, 'https://github.com/birdseyevue.png?size=128', '2026-03-09T05:21:01.921894+00:00'),
  ('gauntlet-incept', 'Gauntlet Incept', 'Gauntlet-Incept is an MCP server implementation for generating high-quality educational content tailored to students'' knowledge levels and interests. It integrates with a QTI service for question and test item handling, an LLM service for content generation, and a PostgreSQL database for data storage. The system is designed to streamline the creation of personalized learning materials, making it particularly useful for educators, e-learning platforms, and educational content creators.', '@birdsmith', 'databases', 'Unknown', 1, 'https://github.com/birdsmith/gauntlet-incept-mcp', NULL, 0, 'https://github.com/birdsmith.png?size=128', '2026-03-09T05:21:01.921906+00:00'),
  ('runescape-wiki', 'RuneScape Wiki', 'RuneScape Wiki MCP server by Josh Birdwell that provides AI assistants with access to RuneScape 3 Grand Exchange prices, item data, and player statistics through the official RuneScape APIs. Built with TypeScript and the MCP SDK, it offers real-time price tracking, historical price graphs, item search and categorization, player hiscores lookup across different game modes (normal, ironman, hardcore), and wiki page content retrieval. The implementation includes comprehensive error handling, debug logging capabilities, and proper API rate limiting with descriptive user agents. Designed for RuneScape players, traders, and analysts who need programmatic access to game economy data, player progression tracking, and item information without manually navigating multiple web interfaces.', '@birdwell', 'development', 'Unknown', 0, 'https://github.com/birdwell/runescape-wiki-mcp', NULL, 0, 'https://github.com/birdwell.png?size=128', '2026-03-09T05:21:01.921938+00:00'),
  ('bitrefill', 'Bitrefill', 'Bitrefill MCP Server enables AI assistants to search for and retrieve information about gift cards, mobile refills, eSIMs, and digital services available on Bitrefill''s platform. Built by Bitrefill, this TypeScript implementation provides tools for searching products by query, country, or category, fetching detailed product information, and browsing available product categories. The server communicates via stdio transport, making it compatible with Claude Desktop integration, and includes comprehensive error handling for API requests. It''s particularly valuable for users who want to explore Bitrefill''s cryptocurrency-based digital services without leaving their conversation interface.', '@bitrefill', 'development', 'Unknown', 7, 'https://github.com/bitrefill/bitrefill-mcp-server', 'bitrefill-mcp-server', 4985, 'https://github.com/bitrefill.png?size=128', '2026-03-09T05:21:01.921994+00:00'),
  ('bitrise', 'Bitrise', 'Bitrise MCP Server provides a bridge to the Bitrise CI/CD platform API, enabling AI assistants to manage mobile app development workflows. Developed by Bitrise, this Python implementation offers tools for app management, build operations, artifact handling, and release management across iOS and Android platforms. The server organizes functionality into logical API groups that can be selectively enabled, and integrates with Claude Desktop through a simple configuration process. It''s particularly valuable for developers who need to monitor builds, trigger workflows, manage testing groups, or handle app distribution without leaving their AI assistant interface.', '@bitrise-io', 'development', 'Unknown', 34, 'https://github.com/bitrise-io/bitrise-mcp', NULL, 0, 'https://github.com/bitrise-io.png?size=128', '2026-03-09T05:21:01.922021+00:00'),
  ('bitrix24', 'Bitrix24', 'Provides integration with Brave Search API to enable web search capabilities within AI conversations. The server implements tools for performing web searches, retrieving search results with titles, URLs, and snippets, and accessing additional metadata like search suggestions and related queries. Built to leverage Brave''s privacy-focused search engine, it offers an alternative to traditional search APIs while maintaining user privacy. Useful for applications requiring real-time web information retrieval, fact-checking, research assistance, or any scenario where AI assistants need access to current web content and search results.', '@unknown', 'development', 'Unknown', 0, 'https://www.pulsemcp.com/servers/bitrix24', NULL, 0, NULL, '2026-03-09T05:21:01.922046+00:00'),
  ('adjust', 'Adjust', 'The Adjust MCP server provides a bridge to the Adjust API, allowing AI assistants to query marketing analytics data from Adjust campaigns. Developed by Alexandr Korsak at Bitscorp, this TypeScript implementation enables users to access reports, metrics, and performance data through natural language queries. The server requires an Adjust API key for authentication and can be installed via Smithery or run locally. It''s particularly useful for marketing teams who need quick access to campaign performance data, such as checking install numbers for specific campaigns without leaving their AI assistant interface.', '@bitscorp-mcp', 'development', 'Unknown', 2, 'https://github.com/bitscorp-mcp/mcp-adjust', NULL, 0, 'https://github.com/bitscorp-mcp.png?size=128', '2026-03-09T05:21:01.922072+00:00'),
  ('ffmpeg-video-processor', 'FFmpeg Video Processor', 'MCP FFmpeg Video Processor enables AI assistants to manipulate video files through FFmpeg, offering capabilities to resize videos to different resolutions (360p, 480p, 720p, 1080p) and extract audio in various formats (MP3, AAC, WAV, OGG). Developed by Bitscorp, this Node.js implementation can be installed via Smithery for Claude Desktop or configured manually for other clients. The server processes uploaded videos temporarily and stores outputs in a dedicated directory, making it ideal for workflows requiring video manipulation without leaving the conversation interface.', '@bitscorp-mcp', 'ai-ml', 'Unknown', 47, 'https://github.com/bitscorp-mcp/mcp-ffmpeg', NULL, 0, 'https://github.com/bitscorp-mcp.png?size=128', '2026-03-09T05:21:01.922114+00:00'),
  ('bitte-ai', 'Bitte AI', 'Bitte-mcp-proxy serves as a bridge between AI assistants and the Bitte AI ecosystem, enabling access to AI agents and tools from the Bitte registry. Built with the MCP-SDK server framework, it provides four key tools: retrieving agent listings, fetching specific agent details, accessing available tools, and executing agents with user inputs. The implementation uses Server-Sent Events for real-time communication and authenticates with the Bitte API using an API key, making it ideal for workflows that require leveraging specialized AI agents from the Bitte marketplace without leaving the conversation interface.', '@bitteprotocol', 'ai-ml', 'Unknown', 13, 'https://github.com/bitteprotocol/mcp', NULL, 0, 'https://github.com/bitteprotocol.png?size=128', '2026-03-09T05:21:01.922158+00:00'),
  ('kanboard', 'Kanboard', 'This MCP server provides AI assistants with comprehensive access to Kanboard project management functionality through JSON-RPC API integration, built using Go with the mcp-go library and supporting authentication via API keys or username/password credentials. The implementation exposes 80+ tools covering complete project lifecycle management including project creation and listing, task management with full CRUD operations, user administration, comment systems, board organization with columns and swimlanes, category management, external link integration, and metadata handling. Built with environment variable configuration for flexible deployment and extensive parameter validation, it serves development teams needing AI-powered project management automation, organizations requiring programmatic access to their Kanboard instances through conversational interfaces, and workflows that benefit from seamless integration between AI assistants and existing project tracking systems.', '@bivex', 'development', 'Unknown', 19, 'https://github.com/bivex/kanboard-mcp', NULL, 0, 'https://github.com/bivex.png?size=128', '2026-03-09T05:21:01.922192+00:00'),
  ('zentao', 'ZenTao', 'A ZenTao project management system integration that provides comprehensive access to ZenTao''s API through both resources and tools. Built by Bivex, this implementation supports multiple authentication methods (app-based and session-based) and covers the full spectrum of ZenTao functionality including projects, products, stories, bugs, tasks, test management, releases, builds, and AI features. The server exposes ZenTao data through structured URI patterns and provides tools for creating, updating, and managing ZenTao entities. Useful for integrating ZenTao project data into AI workflows, automating project management tasks, generating reports across multiple ZenTao modules, or building custom dashboards that combine ZenTao data with other systems.', '@bivex', 'development', 'Unknown', 2, 'https://github.com/bivex/zentaomcp', NULL, 0, 'https://github.com/bivex.png?size=128', '2026-03-09T05:21:01.922222+00:00'),
  ('homelab-infrastructure', 'Homelab Infrastructure', 'Unified access to homelab infrastructure through Docker/Podman containers, Ollama AI models, Pi-hole DNS, Unifi networks, UPS monitoring, and network ping operations.', '@bjeans', 'cloud', 'Unknown', 18, 'https://github.com/bjeans/homelab-mcp', NULL, 0, 'https://github.com/bjeans.png?size=128', '2026-03-09T05:21:01.922237+00:00'),
  ('begagnad-swedish-second-hand-marketplaces', 'Begagnad (Swedish Second-Hand Marketplaces)', 'Begagnad MCP provides search capabilities across Sweden''s two largest second-hand marketplaces, Blocket and Tradera, enabling unified access to classified listings through a single interface. Built by bjesus and deployed on Cloudflare Workers, it offers five core tools for searching individual marketplaces, retrieving specific item details, or querying both platforms simultaneously, returning normalized data including prices, descriptions, images, seller ratings, and direct links to listings. The implementation handles different API formats (REST for Blocket, XML for Tradera) and provides a consistent data structure, making it valuable for price comparison, market research, or helping users find specific second-hand items across Sweden''s fragmented marketplace ecosystem.', '@bjesus', 'cloud', 'Unknown', 4, 'https://github.com/bjesus/begagnad-mcp', NULL, 0, 'https://github.com/bjesus.png?size=128', '2026-03-09T05:21:01.922263+00:00'),
  ('letsbonk-solana-token-launcher', 'LetsBonk (Solana Token Launcher)', 'The bonk-mcp server implements Solana blockchain functionality for the LetsBonk launchpad, enabling users to launch and trade tokens on letsbonk.fun. Built by letsbonk-ai, it provides a token launcher tool that handles the entire token creation process including IPFS metadata preparation, image uploading, and Raydium launchpad integration. The server requires a Solana keypair and RPC endpoint for authentication, making it particularly valuable for developers and users who want to create and manage meme tokens on Solana without dealing with the complexities of blockchain transactions directly.', '@bjoernbonk', 'ai-ml', 'Unknown', 16, 'https://github.com/bjoernbonk/letsbonk_mcp_server', 'bonk-mcp', 10149, 'https://github.com/bjoernbonk.png?size=128', '2026-03-09T05:21:01.922308+00:00'),
  ('diffpilot', 'DiffPilot', 'Provides AI-powered code review and developer productivity tools for Git workflows, operating entirely locally to preserve privacy. Features include automated PR title and description generation, conventional commit message creation, secret scanning across staged and unstaged changes, and branch comparison against main. Supports GitHub, Azure DevOps, and on-premise Git repositories with automatic branch detection and rate limiting.', '@bkalafat', 'cloud', 'Unknown', 2, 'https://github.com/bkalafat/diffpilot-ts', NULL, 0, 'https://github.com/bkalafat.png?size=128', '2026-03-09T05:21:01.922324+00:00'),
  ('postgresql-remote', 'PostgreSQL Remote', 'PostgreSQL Remote MCP server built as a Cloudflare Workers Durable Object that provides AI assistants with secure read-only database access through a single query tool. The implementation uses the pg library with connection pooling and enforces read-only transactions with automatic rollback to prevent data modification, making it suitable for data analysis, reporting, and database exploration workflows where AI assistants need to examine PostgreSQL database contents without risk of altering the data.', '@blackboxprojects', 'databases', 'Unknown', 1, 'https://github.com/blackboxprojects/postgres-remote-mcp', NULL, 0, 'https://github.com/blackboxprojects.png?size=128', '2026-03-09T05:21:01.922336+00:00'),
  ('sast-sca-sbom-security-analyzer', 'SAST SCA SBOM Security Analyzer', 'This MCP server provides AI assistants with enterprise-grade security analysis capabilities through integrated SAST, SCA, SBOM generation, and vulnerability scanning tools, built using TypeScript with Snyk integration and CycloneDX SBOM support. The implementation offers four core security analysis tools: Snyk-powered vulnerability testing with configurable severity filtering and multiple output formats, automated Software Bill of Materials generation in JSON/XML/SPDX formats, security-focused code review with pattern-based detection for SQL injection, XSS, command injection, and hardcoded secrets, and comprehensive vulnerability scanning across multiple attack vectors including container security and infrastructure-as-code analysis. Built with fallback mechanisms when commercial tools aren''t available, custom security rule engines, and support for multiple package managers, it serves DevSecOps teams needing automated security analysis in CI/CD pipelines, security engineers requiring comprehensive vulnerability assessment capabilities, and development teams wanting to integrate security scanning into their AI-assisted workflows with detailed remediation guidance and compliance reporting.', '@blackkhawkk', 'databases', 'Unknown', 2, 'https://github.com/blackkhawkk/mcp_sast_sca_sbom/tree/HEAD/mcp-security-server', NULL, 0, 'https://github.com/blackkhawkk.png?size=128', '2026-03-09T05:21:01.922361+00:00'),
  ('openapi', 'OpenAPI', 'Enables AI assistants to inspect and interact with OpenAPI specifications by loading specs from URLs or local files, extracting and dereferencing schemas, and providing tools for endpoint discovery, request/response schema analysis, payload validation, and sample data generation. Features TypeScript type generation from schemas, cURL command generation with authentication support, and compatibility with both OpenAPI 3.x and 2.0 formats. Built with TypeScript and Bun for API integration workflows, documentation analysis, and automated testing scenarios.', '@blackkspydo', 'development', 'Unknown', 3, 'https://github.com/blackkspydo/openapi-mcp', NULL, 0, 'https://github.com/blackkspydo.png?size=128', '2026-03-09T05:21:01.922400+00:00'),
  ('say-text-to-speech', 'Say (Text-to-Speech)', 'MCP-Say is a server implementation that provides text-to-speech capabilities through both native system voices and ElevenLabs integration. Developed by blacktop, it exposes two main tools: ''say'' for using local system voices and ''elevenlabs'' for cloud-based high-quality voice synthesis. The server handles JSON-RPC requests following the MCP protocol, with safeguards against command injection attacks as evidenced by the test files. Built with Go and leveraging the beep audio library, it''s particularly valuable for AI assistants that need to vocalize responses or generate audio content without requiring users to leave their conversation interface.', '@blacktop', 'development', 'Unknown', 50, 'https://github.com/blacktop/mcp-tts', NULL, 0, 'https://github.com/blacktop.png?size=128', '2026-03-09T05:21:01.922431+00:00'),
  ('cookwith', 'Cookwith', 'Provides AI-powered recipe generation from natural language descriptions and recipe transformation capabilities. Supports dietary restrictions, allergies, calorie targets, and serving size adjustments. Integrates with Cookwith''s recipe platform to create personalized recipes based on user preferences and nutritional goals.', '@valetdotdev', 'ai-ml', 'Unknown', 0, 'https://github.com/valetdotdev/cookwith-mcp', NULL, 0, 'https://github.com/valetdotdev.png?size=128', '2026-03-09T05:21:01.922491+00:00'),
  ('macrostrat', 'Macrostrat', 'This Macrostrat MCP server, developed by Blake Morgan, integrates the Macrostrat API with the Model Context Protocol, enabling AI assistants to access and analyze geological data. Built with TypeScript and leveraging the MCP SDK, it provides a standardized interface for querying stratigraphic information, geological maps, and related datasets. The implementation focuses on efficient data retrieval and processing, making it particularly valuable for applications in earth sciences, resource exploration, and environmental studies. By bridging the gap between geological databases and AI systems, this server facilitates use cases such as automated stratigraphic analysis, geological risk assessment, and integration of geological data into broader analytical workflows.', '@blake365', 'databases', 'Unknown', 5, 'https://github.com/blake365/macrostrat-mcp', NULL, 0, 'https://github.com/blake365.png?size=128', '2026-03-09T05:21:01.922502+00:00'),
  ('usgs-earthquake-data', 'USGS Earthquake Data', 'This USGS Earthquakes MCP server, developed by Blake Morgan, provides real-time access to earthquake data from the United States Geological Survey. Built with TypeScript and Node.js, it leverages the Model Context Protocol SDK to offer a standardized interface for querying and analyzing seismic events. The server implements robust error handling and data validation using Zod, ensuring reliable information retrieval. By abstracting USGS API interactions, it enables AI systems to easily process and interpret earthquake data. This implementation is particularly valuable for applications in disaster response, geological research, and risk assessment, facilitating use cases such as early warning systems, seismic trend analysis, and automated reporting of significant events.', '@blake365', 'development', 'Unknown', 1, 'https://github.com/blake365/usgs-quakes-mcp', NULL, 0, 'https://github.com/blake365.png?size=128', '2026-03-09T05:21:01.922536+00:00'),
  ('kubernetes-claude', 'Kubernetes Claude', 'Kubernetes Claude MCP Server integrates Claude''s AI capabilities with Kubernetes, ArgoCD, and GitLab to provide AI-powered analysis and troubleshooting for GitOps workflows. Built with Go, it collects comprehensive information about Kubernetes resources, correlates data across systems, and presents structured context to Claude for intelligent analysis. The server features a RESTful API for querying resources, analyzing deployments, and troubleshooting issues, making it particularly valuable for DevOps teams seeking to understand complex Kubernetes environments, identify root causes of failures, and receive actionable recommendations for GitOps pipeline improvements.', '@blankcut', 'cloud', 'Unknown', 9, 'https://github.com/blankcut/kubernetes-mcp-server', NULL, 0, 'https://github.com/blankcut.png?size=128', '2026-03-09T05:21:01.922560+00:00'),
  ('io-github-filearchitect-blankfiles-mcp', 'io.github.filearchitect/blankfiles-mcp', 'MCP server for listing and retrieving minimal valid blank files from blankfiles.com.', '@filearchitect', 'development', 'Unknown', 1, 'https://github.com/filearchitect/blankfiles-website', NULL, 0, 'https://github.com/filearchitect.png?size=128', '2026-03-09T05:21:01.922575+00:00'),
  ('shell', 'Shell', 'This Shell MCP server, developed by Joe Blazick, enables AI assistants to interact with the local shell environment. It leverages the MCP library to provide a standardized interface for executing shell commands, managing files and directories, and retrieving system information. The server abstracts the complexities of shell interactions, offering a set of high-level operations that simplify task automation and system management. By connecting AI systems with the shell, this implementation facilitates tasks such as file manipulation, process management, and system configuration. It is particularly useful for AI applications requiring direct interaction with the operating system, such as automated system administration, DevOps tools, or any AI that needs to perform local system operations.', '@blazickjp', 'productivity', 'Unknown', 17, 'https://github.com/blazickjp/shell-mcp-server', 'shell-mcp-server', 4667, 'https://github.com/blazickjp.png?size=128', '2026-03-09T05:21:01.922651+00:00'),
  ('web-browser', 'Web Browser', 'This web browser MCP server, developed as an open-source project, enhances AI applications with advanced web browsing capabilities. It integrates with popular Python libraries like BeautifulSoup and requests to provide a robust interface for web scraping, content extraction, and navigation. The server abstracts the complexities of HTTP requests and HTML parsing, offering AI assistants streamlined operations for fetching web pages, extracting specific elements, and following links. By connecting AI systems with real-time web data, this implementation enables dynamic information retrieval, content analysis, and web-based task automation. It is particularly useful for applications requiring up-to-date online information, such as research assistants, content aggregators, or any AI system that needs to interact with web content programmatically.', '@blazickjp', 'productivity', 'Unknown', 43, 'https://github.com/blazickjp/web-browser-mcp-server', 'web-browser-mcp-server', 6631, 'https://github.com/blazickjp.png?size=128', '2026-03-09T05:21:01.922699+00:00'),
  ('io-github-es617-ble-mcp-server', 'io.github.es617/ble-mcp-server', 'Let AI agents interact with real BLE hardware — scan, connect, read, write, and subscribe.', '@es617', 'development', 'Unknown', 6, 'https://github.com/es617/ble-mcp-server', NULL, 0, 'https://github.com/es617.png?size=128', '2026-03-09T05:21:01.922719+00:00'),
  ('blindpay', 'BlindPay', 'Official MCP server for BlindPay''s global stablecoin payment infrastructure. Provides tools for creating and managing payment receivers (individuals and businesses), processing payouts and payins across blockchains, generating quotes and FX rates, managing virtual accounts and blockchain wallets, and configuring webhooks and API keys. Supports payments across 100+ countries in 80+ currencies.', '@blindpaylabs', 'ai-ml', 'Unknown', 7, 'https://github.com/blindpaylabs/blindpay-mcp', NULL, 0, 'https://github.com/blindpaylabs.png?size=128', '2026-03-09T05:21:01.922792+00:00'),
  ('task-manager', 'Task Manager', 'Task Manager MCP server that provides structured task management capabilities for AI agents working on complex multi-step problems, enabling them to register tasks with dependencies and parent-child relationships, assess task complexity to automatically break down work into subtasks with missing knowledge requirements, and track status transitions through not-started, in-progress, and complete states. Built by Maik Schreiber, the implementation enforces workflow constraints like requiring task assessment before execution, ensuring parent tasks are in progress before subtasks can start, and validating all dependencies are complete before task initiation. Designed for agents handling complex projects that need systematic decomposition, dependency management, and progress tracking across interconnected work items, making it valuable for software development workflows, research projects, and any scenario requiring structured task orchestration with automatic knowledge gap identification.', '@blizzy78', 'development', 'Unknown', 4, 'https://github.com/blizzy78/mcp-task-manager', '@blizzy/mcp-task-manager', 1830, 'https://github.com/blizzy78.png?size=128', '2026-03-09T05:21:01.922878+00:00'),
  ('blockrun', 'BlockRun', 'BlockRun enables AI agents to autonomously pay for AI services using USDC micropayments on the Base blockchain. Provides unified access to models from OpenAI, Anthropic, Google, DeepSeek, and xAI through a single wallet-based interface. Supports chat completions with smart model selection modes and image generation via DALL-E and Flux.', '@blockrunai', 'communication', 'Unknown', 9, 'https://github.com/blockrunai/blockrun-mcp', NULL, 0, 'https://github.com/blockrunai.png?size=128', '2026-03-09T05:21:01.922906+00:00'),
  ('blockscout', 'Blockscout', 'This MCP server provides blockchain data access through Blockscout APIs, enabling AI assistants to query comprehensive blockchain information including address balances, token holdings, NFT collections, transaction details, smart contract ABIs, and ENS name resolution across multiple blockchain networks. Built by Blockscout, it dynamically resolves chain-specific API endpoints through Chainscout integration, supports caching for performance optimization, and includes specialized tools for transaction analysis with decoded parameters, event logs with smart contract metadata, and DeFi operation tracking. The implementation is particularly valuable for blockchain analysis, wallet auditing, smart contract debugging, and DeFi research workflows where AI assistants need enriched blockchain data beyond standard RPC calls.', '@blockscout', 'development', 'Unknown', 32, 'https://github.com/blockscout/mcp-server', NULL, 0, 'https://github.com/blockscout.png?size=128', '2026-03-09T05:21:01.922935+00:00'),
  ('vs-code', 'VS Code', 'The VS Code MCP Server enables AI assistants to interact directly with VS Code through a bidirectional communication channel. It provides tools for file diffing with user approval, opening files and projects, executing shell commands in VS Code''s terminal, and retrieving information about active editor tabs. The implementation consists of two main components: a server that handles MCP protocol communication and a VS Code extension that provides native integration features. This allows AI agents to perform code modifications, navigate projects, and execute commands without leaving the conversation interface, making it particularly valuable for collaborative coding sessions and AI-assisted development workflows.', '@block', 'development', 'Unknown', 76, 'https://github.com/block/vscode-mcp', 'vscode-mcp-server', 23295, 'https://github.com/block.png?size=128', '2026-03-09T05:21:01.922963+00:00'),
  ('xcode-index', 'Xcode Index', 'This MCP server provides direct access to Xcode''s project index store through Apple''s IndexStoreDB, enabling AI assistants to perform precise code navigation and refactoring operations on iOS/macOS projects. Built by Block using a hybrid Python/Swift architecture, it consists of a Python MCP server that communicates with a Swift service running on TCP port 7949, which interfaces directly with Xcode''s derived data to load project indexes and query symbol information. The implementation offers tools for loading project indexes, finding symbol occurrences at specific file locations, retrieving all references to symbols by their USR (Unified Symbol Resolution), and pattern-based symbol searching with various matching options, making it valuable for automated refactoring workflows where AI agents need exhaustive lists of function call sites and symbol definitions to safely modify code across large codebases.', '@block', 'development', 'Unknown', 54, 'https://github.com/block/xcode-index-mcp', NULL, 0, 'https://github.com/block.png?size=128', '2026-03-09T05:21:01.923005+00:00'),
  ('blogcaster', 'BlogCaster', 'Enables publishing blog posts to multiple platforms (Hashnode and Dev.to) directly from AI agents. Handles authentication, markdown formatting, and platform-specific API integration. Built on Cloudflare Workers with secure token storage using Durable Objects.', '@unknown', 'cloud', 'Unknown', 0, 'https://blogcaster-mcp.rrpb2580.workers.dev/mcp', NULL, 0, NULL, '2026-03-09T05:21:01.923021+00:00'),
  ('blooio-imessages', 'Blooio iMessages', 'Blooio MCP v3 provides production-ready access to location and mapping services through its edge API infrastructure. The server acts as a bridge to blooio''s geospatial data platform, enabling AI assistants to perform location-based queries, geocoding, and spatial analysis operations. Built for high-availability production environments, it offers reliable access to geographic data and mapping functionality for applications requiring location intelligence, route planning, or spatial data processing capabilities.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://www.pulsemcp.com/servers/blooio-imessages', NULL, 0, NULL, '2026-03-09T05:21:01.923055+00:00'),
  ('blue-perfumery', 'Blue Perfumery', 'This Blue Perfumery MCP server provides access to a curated perfume catalog through five specialized tools: listing all perfumes, searching by name/brand, filtering by category (men, women, niche), retrieving specific perfume details by ID, and generating Shopier purchase links. Built by Recep Gocmen using the Model Context Protocol SDK, it serves as a product data API for the Blue Perfumery e-commerce platform, enabling AI assistants to help customers discover fragrances, compare options, and facilitate purchases through integrated shopping links. The implementation is particularly valuable for conversational commerce applications where users need personalized perfume recommendations and seamless purchase workflows.', '@recepgocmen', 'ai-ml', 'Unknown', 2, 'https://github.com/recepgocmen/blue-perfumery-mcp-server', NULL, 0, 'https://github.com/recepgocmen.png?size=128', '2026-03-09T05:21:01.923155+00:00'),
  ('far-oracle', 'FAR Oracle', 'FAR Oracle enables AI agents to search and query Federal Acquisition Regulations (FAR), the rules governing U.S. government contracting. Users can retrieve information about cybersecurity requirements, small business set-asides, contract data rights clauses, and other government procurement regulations. Requires a RapidAPI key for FAR RAG service access.', '@blueskylineassets', 'ai-ml', 'Unknown', 0, 'https://github.com/blueskylineassets/far-mcp-server', NULL, 0, 'https://github.com/blueskylineassets.png?size=128', '2026-03-09T05:21:01.923187+00:00'),
  ('bluestoneapps-react-native-standards', 'BluestoneApps React Native Standards', 'This MCP remote server implementation provides access to BluestoneApps coding standards and code examples over HTTP. It uses FastAPI to expose a JSON-RPC 2.0 endpoint and Server-Sent Events (SSE) for streaming responses, with support for HTTP Basic Authentication. The server offers tools for retrieving React Native development standards (project structure, API communication, component design, state management) and code examples (components, hooks, services, screens, themes). Designed for deployment via Docker, it can be accessed locally or remotely through a domain (mcp.betaplanets.com), enabling seamless integration with Windsurf/Cascade clients.', '@lallen30', 'cloud', 'Unknown', 2, 'https://github.com/lallen30/mcp-remote-server', NULL, 0, 'https://github.com/lallen30.png?size=128', '2026-03-09T05:21:01.923212+00:00'),
  ('graphql', 'GraphQL', 'This MCP server, developed by an unnamed author, provides a GraphQL interface for AI assistants. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers a tool for querying GraphQL servers. The implementation currently uses a mock schema response for development purposes, but is designed to connect to actual GraphQL endpoints. It abstracts the complexities of GraphQL communication, allowing AI systems to easily interact with GraphQL APIs. This server is particularly useful for applications requiring flexible data querying and manipulation, enabling AI assistants to access and analyze structured data from various GraphQL sources. Its generic design allows it to work with any GraphQL schema, making it versatile for different data-driven use cases.', '@blurrah', 'development', 'Unknown', 364, 'https://github.com/blurrah/mcp-graphql', NULL, 0, 'https://github.com/blurrah.png?size=128', '2026-03-09T05:21:01.923240+00:00'),
  ('anti-bs', 'Anti-BS', 'This Anti-Bullshit MCP server, developed by Teglon Labs, provides tools for analyzing claims, validating sources, and detecting manipulation using multiple epistemological frameworks. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers empirical, responsible, harmonic, and pluralistic approaches to evaluate information. The implementation focuses on rigorous fact-checking and critical thinking, making it accessible for AI models to assess the credibility and implications of various claims. It''s particularly useful for tasks like academic research validation, media literacy enhancement, or combating misinformation in digital content, enabling AI assistants to apply nuanced epistemological analysis without requiring deep expertise in each framework.', '@bmorphism', 'development', 'Unknown', 23, 'https://github.com/bmorphism/anti-bullshit-mcp-server', NULL, 0, 'https://github.com/bmorphism.png?size=128', '2026-03-09T05:21:01.923267+00:00'),
  ('babashka', 'Babashka', 'This Babashka MCP server, developed as an open-source project, enables AI assistants to interact with Babashka, a native Clojure interpreter for scripting. Built with TypeScript and leveraging the @modelcontextprotocol/sdk, it provides tools for executing Babashka code, caching recent command results, and accessing command history through standardized MCP endpoints. The implementation features configurable command timeouts and a roadmap for self-hosting in Babashka itself. By connecting AI capabilities with Babashka''s scripting power, this server allows for dynamic code execution and interaction with Clojure ecosystems. It is particularly useful for scenarios involving Clojure-based data processing, system automation, or building AI-assisted development tools for Clojure projects.', '@bmorphism', 'development', 'Unknown', 17, 'https://github.com/bmorphism/babashka-mcp-server', NULL, 0, 'https://github.com/bmorphism.png?size=128', '2026-03-09T05:21:01.923294+00:00'),
  ('krep', 'Krep', 'Krep MCP Server provides a high-performance string search utility that wraps the krep binary, offering significantly faster pattern matching than traditional tools like grep. It exposes search functionality through both HTTP endpoints and the Model Context Protocol, automatically selecting optimal search algorithms (KMP, Boyer-Moore-Horspool, or Rabin-Karp) based on pattern length and leveraging hardware acceleration when available. The server includes dynamic CPU core detection for optimal thread allocation, supports both file and string searching modes, and integrates with Claude Desktop and VSCode''s Cline extension, making it valuable for developers needing efficient pattern matching within AI assistant workflows.', '@bmorphism', 'development', 'Unknown', 1, 'https://github.com/bmorphism/krep-mcp-server', NULL, 0, 'https://github.com/bmorphism.png?size=128', '2026-03-09T05:21:01.923322+00:00'),
  ('marginalia-search', 'Marginalia Search', 'This Marginalia MCP server, developed by Barton Rhodes, integrates Marginalia Search into MCP-compatible systems, enabling AI assistants to discover non-commercial and independent web content. Built with TypeScript and leveraging the @modelcontextprotocol/sdk, it offers a simple search tool that returns URLs, titles, and descriptions focused on lesser-known websites and unique content. The server is designed for easy installation in Claude Desktop, abstracting Marginalia Search API interactions into a standardized MCP interface. This implementation is particularly useful for researchers, writers, and curious individuals seeking to explore the independent web, facilitating use cases such as content discovery, trend analysis, and alternative perspective gathering.', '@bmorphism', 'development', 'Unknown', 7, 'https://github.com/bmorphism/marginalia-mcp-server', NULL, 0, 'https://github.com/bmorphism.png?size=128', '2026-03-09T05:21:01.923354+00:00'),
  ('macos-say', 'macOS Say', 'This MCP server, developed by Barton Rhodes, provides text-to-speech functionality using macOS''s built-in ''say'' command. It offers extensive customization options for voice, rate, volume, and emphasis, allowing for dynamic speech modulation. The server integrates seamlessly with other MCP tools, enabling scenarios like reading search results or YouTube transcripts aloud. It differentiates itself through its focus on macOS-specific capabilities and its support for background speech processing. This implementation is particularly useful for creating audio content, enhancing accessibility, or adding voice output to various applications and workflows on macOS systems.', '@bmorphism', 'ai-ml', 'Unknown', 19, 'https://github.com/bmorphism/say-mcp-server', NULL, 0, 'https://github.com/bmorphism.png?size=128', '2026-03-09T05:21:01.923398+00:00'),
  ('slowtime-time-intervals', 'Slowtime (Time & Intervals)', 'This MCP server, developed for managing slow time intervals, integrates with drand for randomness and tlock-js for time-locked encryption. Built with TypeScript and leveraging DuckDB for efficient data handling, it offers tools for creating and managing time-based events with cryptographic guarantees. The server stands out by combining distributed randomness with time-locked encryption, enabling secure scheduling and reveal of information at predetermined future times. This implementation is particularly useful for applications requiring trusted delays, such as sealed-bid auctions, scheduled announcements, or time-capsule services, where information must remain confidential until a specific future time.', '@bmorphism', 'development', 'Unknown', 3, 'https://github.com/bmorphism/slowtime-mcp-server', NULL, 0, 'https://github.com/bmorphism.png?size=128', '2026-03-09T05:21:01.923429+00:00'),
  ('vibespace-ternary', 'VibeSpace Ternary', 'Vibespace MCP Go Ternary provides real-time streaming of world moments and vibes through NATS, enabling multiplayer experiences with balanced ternary data representation. The implementation features robust access control with configurable sharing settings, rate limiting to prevent abuse, and comprehensive test coverage for reliability. It exposes JSON-RPC methods for resource reading and tool calling, with specialized streaming tools for starting/stopping streams, checking status, and updating configurations. This server is particularly valuable for collaborative virtual environments where users need to share contextual information with varying levels of privacy control.', '@bmorphism', 'development', 'Unknown', 0, 'https://github.com/bmorphism/vibespace-mcp-go-ternary', NULL, 0, 'https://github.com/bmorphism.png?size=128', '2026-03-09T05:21:01.923459+00:00'),
  ('things', 'Things', 'This MCP server provides complete Things.app task management integration for macOS, enabling AI assistants to create, update, and organize tasks and projects through Things'' URL scheme and direct database access. Built by panwenbo using TypeScript with the MCP SDK, it offers task and project creation with full metadata support (notes, tags, deadlines, areas, checklist items), update operations for existing items including completion and cancellation status, database export functionality for backup and analysis, and a summary tool that generates formatted overviews of all tasks, projects, areas, and tags. The implementation includes authentication token support for update operations, direct SQLite database querying for read operations, and comprehensive filtering options for targeted data retrieval, making it valuable for personal productivity automation, task management workflows integrated with AI assistants, and users who want to programmatically interact with their Things.app data without manual entry.', '@wbopan', 'databases', 'Unknown', 2, 'https://github.com/wbopan/things-mcp', '@wenbopan/things-mcp', 4428, 'https://github.com/wbopan.png?size=128', '2026-03-09T05:21:01.923470+00:00'),
  ('bnbchain', 'BNBChain', 'The BNBChain MCP server enables AI assistants to interact directly with BNB Chain and other EVM-compatible networks through a TypeScript implementation. It provides tools for blockchain operations including block exploration, smart contract interaction, token management, wallet operations, and Greenfield storage functionality. The server supports multiple networks including BSC, opBNB, Ethereum, and others, with comprehensive error handling and response formatting. Built with the Model Context Protocol SDK, it can be deployed via npm or integrated with clients like Cursor and Claude Desktop, making it valuable for developers who need to perform blockchain operations through natural language without switching contexts.', '@bnb-chain', 'development', 'Unknown', 51, 'https://github.com/bnb-chain/bnbchain-mcp', '@bnb-chain/mcp', 6789, 'https://github.com/bnb-chain.png?size=128', '2026-03-09T05:21:01.923502+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('memory-pouchdb', 'Memory PouchDB', 'MCP Memory PouchDB provides a knowledge graph-based memory system for AI assistants to store and retrieve information about entities, their relationships, and observations. Built by bneil, it uses PouchDB with a memory adapter for primary storage and maintains a JSON file backup, offering tools for creating, reading, updating, and deleting graph elements through a comprehensive API. The implementation includes robust error handling with retry mechanisms, supports both in-memory and file-based persistence, and is particularly valuable for maintaining conversational context across interactions, enabling assistants to remember user preferences, relationships, and historical information.', '@bneil', 'communication', 'Unknown', 4, 'https://github.com/bneil/mcp-memory-pouchdb', NULL, 0, 'https://github.com/bneil.png?size=128', '2026-03-09T05:21:01.923542+00:00'),
  ('bank-negara-malaysia', 'Bank Negara Malaysia', 'This MCP server provides AI assistants with direct access to Bank Negara Malaysia''s public APIs for financial and economic data retrieval, featuring over 30 specialized tools organized into categories including exchange rates, interest rates, monetary aggregates, banking statistics, and macroeconomic indicators. Built with Python using FastMCP and httpx, it handles BNM''s API authentication requirements with proper headers and error handling, supporting operations like currency exchange rate queries with session and quote parameters, base lending rates, foreign exchange turnover data, consumer alerts for unauthorized financial entities, and comprehensive banking system statistics across commercial, Islamic, and investment banking sectors. The implementation enables natural language interaction with Malaysia''s central bank data through standardized tool interfaces, making it valuable for financial analysis workflows, economic research, regulatory compliance monitoring, and building AI assistants that need programmatic access to Malaysian financial market data without manual API integration.', '@meisin', 'development', 'Unknown', 21, 'https://github.com/meisin/bnm-mcp', NULL, 0, 'https://github.com/meisin.png?size=128', '2026-03-09T05:21:01.923580+00:00'),
  ('ultimate-brain', 'Ultimate Brain', 'Integrates with Thomas Frank''s Ultimate Brain Notion template system. Provides workflow-oriented tools for managing tasks, projects, notes, tags, and goals using the PARA methodology (Projects, Areas, Resources, Archives). Supports features like My Day views, inbox processing, daily summaries, and cross-database archival functions.', '@bobbyhyam', 'databases', 'Unknown', 2, 'https://github.com/bobbyhyam/ultimate-brain-mcp', NULL, 0, 'https://github.com/bobbyhyam.png?size=128', '2026-03-09T05:21:01.923592+00:00'),
  ('gemini-ui-design-server', 'Gemini UI Design Server', 'This MCP server leverages Google''s Gemini 2.5 Pro model to deliver professional UI/UX design capabilities through specialized tools for component design, brand identity creation, and frontend implementation. Created by Bojan Vasic, it focuses on enterprise-grade output with WCAG 2.1 AA/AAA compliance and follows Google''s prompt optimization best practices. The server provides structured design workflows for creating premium UI components, comprehensive brand identity systems, and accessibility-first design patterns, making it particularly valuable for developers and designers working on professional web applications and design systems.', '@bobvasic', 'ai-ml', 'Unknown', 8, 'https://github.com/bobvasic/gemini-mcp-server', NULL, 0, 'https://github.com/bobvasic.png?size=128', '2026-03-09T05:21:01.923644+00:00'),
  ('glm-4-6-architecture-consultant', 'GLM-4.6 Architecture Consultant', 'Developed by CyberLink Security, this server bridges Claude with GLM-4.6 (Zhipu AI''s model) to provide specialized software architecture consulting capabilities. It offers four targeted tools for architectural guidance: general architecture consultation, code analysis from an architectural perspective, complete system design based on requirements, and technical decision review with trade-off analysis. The implementation positions GLM-4.6 as an expert software architecture consultant with deep knowledge of distributed systems, microservices, security patterns, and scalability strategies, making it particularly useful for enterprise development teams seeking architectural expertise and technical decision validation.', '@bobvasic', 'development', 'Unknown', 17, 'https://github.com/bobvasic/glm-mcp-server', NULL, 0, 'https://github.com/bobvasic.png?size=128', '2026-03-09T05:21:01.923675+00:00'),
  ('bocha-search', 'Bocha Search', 'Bocha Search MCP provides integration with Bocha, a Chinese search engine for AI, enabling AI assistants to perform web searches and retrieve enhanced search details from billions of documents. Developed by kunkun, this Python-based server implementation offers two primary tools: bocha_web_search for retrieving standard search results including titles, URLs, summaries, and publication dates; and bocha_ai_search for semantic search with additional structured modal cards from vertical domains like weather, news, wikis, healthcare, and more. The server requires a Bocha API key and handles authentication, request formatting, and error handling, making it particularly useful for applications needing multilingual search capabilities with rich structured data.', '@bochaai', 'ai-ml', 'Unknown', 150, 'https://github.com/bochaai/bocha-search-mcp', NULL, 0, 'https://github.com/bochaai.png?size=128', '2026-03-09T05:21:01.923724+00:00'),
  ('ridewithgps', 'RideWithGPS', 'This MCP server provides access to the RideWithGPS API for cycling enthusiasts and fitness tracking applications. Built by Erosminer, it exposes tools for retrieving user routes, trips, events, and profile information from the RideWithGPS platform, with detailed formatting that includes performance metrics like speed, elevation, heart rate, power, and cadence data. The server supports pagination for large datasets and includes a sync endpoint for tracking changes since a specific datetime, making it valuable for cycling analytics, route planning, fitness tracking integrations, and building cycling-focused applications that need access to detailed ride data and performance statistics.', '@boezzz', 'development', 'Unknown', 5, 'https://github.com/boezzz/ridewithgps-mcp', NULL, 0, 'https://github.com/boezzz.png?size=128', '2026-03-09T05:21:01.923753+00:00'),
  ('company-ethics-information-boikot', 'Company Ethics Information (Boikot)', 'boikot is building a community-curated, transparent, freely accessible collection of corporate ethics records. By documenting ethical and unethical business practices, we aim to inform consumer choice, raise the cost of harmful business decisions, and incentivise companies to act responsibly in the public interest.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('bright-data', 'Bright Data', 'This MCP server provides integration with Bright Data''s web scraping and data extraction platform, forked by dsouza-anush and adapted for Heroku deployment. It combines web unlocking capabilities that bypass bot detection and CAPTCHAs with browser automation tools powered by Playwright, plus access to 40+ pre-built datasets for major platforms like Amazon, LinkedIn, Instagram, TikTok, and Google Maps. The implementation includes both direct web scraping tools (markdown/HTML extraction, search engine results) and structured data retrieval from cached datasets, along with an AI-powered extraction tool that converts scraped content to JSON using sampling. Designed for automated data collection workflows, market research, and applications requiring reliable access to web data at scale.', '@dsouza-anush', 'ai-ml', 'Unknown', 1, 'https://github.com/dsouza-anush/brightdata-mcp-heroku', NULL, 0, 'https://github.com/dsouza-anush.png?size=128', '2026-03-09T05:21:01.925388+00:00'),
  ('bright-security', 'Bright Security', 'Provides access to Bright Security''s dynamic application security testing (DAST) platform. Enables running security scans, discovering API endpoints, monitoring scan status, managing repeaters for internal target access, uploading API definitions, and reviewing discovered vulnerabilities. Supports scanning web applications, REST, SOAP, and GraphQL APIs.', '@unknown', 'development', 'Unknown', 0, 'https://brightsec.com', NULL, 0, NULL, '2026-03-09T05:21:01.925460+00:00'),
  ('eof-source-code-management', 'EoF Source Code Management', 'Source code management server built with Qt 6 and the QTMCP framework. Provides handlers for reading, writing, and listing source files with detailed metadata including file sizes, modification dates, and line counts. Includes a calculator tool for basic arithmetic operations and prompt templates for code review and API documentation generation. Built with Qt''s plugin architecture for extensibility and designed for integration with local development environments.', '@britus', 'development', 'Unknown', 1, 'https://github.com/britus/eofmcp', NULL, 0, 'https://github.com/britus.png?size=128', '2026-03-09T05:21:01.925482+00:00'),
  ('memory-custom', 'Memory Custom', 'This MCP server implementation provides a knowledge graph-based memory system for AI assistants. Developed by BRO3886, it offers tools for creating, managing, and querying a graph structure of entities, relations, and observations. The server supports features like custom memory file paths, timestamping, and advanced search capabilities. It''s designed for use cases requiring persistent, structured memory for AI interactions, such as maintaining context in long-term conversations or building knowledge bases from user interactions.', '@bro3886', 'development', 'Unknown', 4, 'https://github.com/bro3886/mcp-memory-custom', NULL, 0, 'https://github.com/bro3886.png?size=128', '2026-03-09T05:21:01.925509+00:00'),
  ('whimsical', 'Whimsical', 'This MCP server enables the creation of Whimsical diagrams programmatically through integration with Whimsical''s API. It allows AI assistants to generate diagrams from Mermaid markup, returning both the Whimsical diagram URL and a base64 encoded image for iterative refinement. The server is particularly useful for creating complex system architecture diagrams, as demonstrated by the included example of the MCP architecture itself.', '@brockreece', 'development', 'Unknown', 40, 'https://github.com/brockreece/whimsical-mcp-server', NULL, 0, 'https://github.com/brockreece.png?size=128', '2026-03-09T05:21:01.925530+00:00'),
  ('brokerchooser', 'BrokerChooser', 'Provides legitimacy verification for investment brokers and financial entities using data from regulatory authorities. Checks investment entities by name or URL against official regulator databases to help identify potentially fraudulent or unregulated operators.', '@unknown', 'databases', 'Unknown', 0, 'https://brokerchooser.com', NULL, 0, NULL, '2026-03-09T05:21:01.925540+00:00'),
  ('broker-safety', 'Broker Safety', 'Provides legitimacy verification for investment brokers and financial entities using official regulatory data. Helps investors verify broker credentials by checking names or URLs against regulator databases to identify safe and trusted firms versus potential scams.', '@unknown', 'databases', 'Unknown', 0, 'https://brokerchooser.com', NULL, 0, NULL, '2026-03-09T05:21:01.925548+00:00'),
  ('sql-stream-builder', 'SQL Stream Builder', 'Provides complete access to SQL Stream Builder (SSB) functionality through 80+ MCP tools, supporting both standalone SSB deployments and Cloudera Data Platform (CDP) environments with flexible authentication options including direct SSB auth, Knox JWT tokens, and passcode tokens. The server enables real-time stream processing management, SQL query execution with sampling, job lifecycle control, table and connector management, and comprehensive monitoring capabilities. Designed for data engineers and analysts working with streaming data pipelines who need to interact with SSB through AI assistants for tasks like stream creation, performance monitoring, schema discovery, and troubleshooting streaming jobs.', '@brooksian', 'databases', 'Unknown', 4, 'https://github.com/brooksian/ssb-mcp-server', NULL, 0, 'https://github.com/brooksian.png?size=128', '2026-03-09T05:21:01.925559+00:00'),
  ('gong', 'Gong', 'Provides comprehensive access to Gong''s sales call intelligence platform, enabling analysis of call recordings, transcripts, and sales data. Offers tools for listing and searching calls with advanced filtering, retrieving detailed call information including tracker occurrences and topics discussed, accessing full call transcripts with speaker identification, and analyzing user activity statistics. Includes intelligent features like client-side transcript search across multiple calls, automatic rate limiting and pagination handling, and AI insights extraction from Gong''s analysis.', '@brownbrawh', 'ai-ml', 'Unknown', 1, 'https://github.com/brownbrawh/gong-mcp-server', NULL, 0, 'https://github.com/brownbrawh.png?size=128', '2026-03-09T05:21:01.925603+00:00'),
  ('browser-mcp', 'Browser MCP', 'Browser MCP is a browser extension and server implementation that allows AI assistants to interact with the browser environment. It provides tools for retrieving page content as markdown, appending CSS styles to pages, searching browser history, and more. The implementation uses a WebSocket connection between the extension and server to enable real-time communication, with the server exposing these capabilities through the Model Context Protocol. This enables AI assistants to perform tasks like summarizing web pages, modifying page appearance, or retrieving browsing history data directly from the user''s browser.', '@djyde', 'productivity', 'Unknown', 83, 'https://github.com/djyde/browser-mcp', '@djyde/browser-mcp', 431, 'https://github.com/djyde.png?size=128', '2026-03-09T05:21:01.925644+00:00'),
  ('runbook-ai-browser', 'Runbook AI Browser', 'MCP server for browser automation with AI agent.', '@runbook-ai', 'ai-ml', 'Unknown', 1, 'https://github.com/runbook-ai/runbook-ai-mcp', NULL, 0, 'https://github.com/runbook-ai.png?size=128', '2026-03-09T05:21:01.925663+00:00'),
  ('browser-agent-protocol', 'Browser Agent Protocol', 'Browser Agent Protocol (BAP) implementation that provides a standardized JSON-RPC interface for controlling web browsers through semantic selectors and accessibility-focused automation. Built on Playwright, it emphasizes stable element identification using ARIA roles, accessible names, and labels rather than brittle CSS selectors. Features include multi-context browser sessions, human-in-the-loop approval workflows, frame navigation, network interception, and specialized agent methods for observation, action sequences, and data extraction. Includes both TypeScript/Node.js and Python SDKs for broad integration support.', '@browseragentprotocol', 'development', 'Unknown', 3, 'https://github.com/browseragentprotocol/bap', NULL, 0, 'https://github.com/browseragentprotocol.png?size=128', '2026-03-09T05:21:01.925694+00:00'),
  ('browserbase-browser-automation', 'Browserbase (Browser Automation)', 'Provides browser automation capabilities through two distinct implementations: a Browserbase-based server using Puppeteer for core browser control, and a Stagehand-based server that adds AI-powered automation on top. The Browserbase server enables navigation, screenshots, clicks, form filling and JavaScript evaluation, while the Stagehand server adds higher-level tools for extracting structured data and performing complex multi-step actions through natural language instructions. Built by Browserbase Inc and Anthropic respectively, this dual implementation supports both direct browser control and AI-assisted automation workflows.', '@xinzhongyouhai', 'ai-ml', 'Unknown', 0, 'https://github.com/xinzhongyouhai/mcp-server-browserbase', NULL, 0, 'https://github.com/xinzhongyouhai.png?size=128', '2026-03-09T05:21:01.925765+00:00'),
  ('browserbase', 'Browserbase', 'This MCP server, developed by Browserbase, provides cloud browser automation capabilities for AI assistants like Claude. It leverages Browserbase''s infrastructure along with Puppeteer and Stagehand (upcoming) to enable web interactions, data extraction, and JavaScript execution in a cloud environment. The server exposes a standardized interface for tasks such as navigating web pages, capturing screenshots, and monitoring console logs. By bridging AI capabilities with web automation, this implementation facilitates use cases like web scraping, automated testing, and dynamic content analysis. It is particularly useful for developers and researchers who need programmatic control over web browsers through natural language commands, enabling complex web-based workflows and data collection tasks.', '@browserbase', 'development', 'Unknown', 3181, 'https://github.com/browserbase/mcp-server-browserbase', NULL, 0, 'https://github.com/browserbase.png?size=128', '2026-03-09T05:21:01.925793+00:00'),
  ('browsercat', 'BrowserCat', 'BrowserCat MCP Server provides cloud-based browser automation capabilities through the Model Context Protocol, enabling LLMs to interact with web pages without local browser installation. Developed by BrowserCat, it offers tools for navigation, screenshot capture, element interaction (clicking, hovering, form filling), and JavaScript execution in a real browser environment. The server connects to BrowserCat''s cloud browser service via WebSocket, authenticates with an API key, and exposes both console logs and screenshots as resources. This implementation is particularly valuable for AI assistants that need to perform web-based tasks like data extraction, form submission, or visual analysis of websites.', '@browsercat', 'productivity', 'Unknown', 5, 'https://github.com/browsercat/browsercat-mcp-server', '@browsercatco/mcp-server', 930, 'https://github.com/browsercat.png?size=128', '2026-03-09T05:21:01.925838+00:00'),
  ('browser-history-analysis', 'Browser History Analysis', 'Browser History Analysis MCP server by Eleanor Mazzarella that provides AI assistants with access to local Firefox and Chrome browser history for productivity analysis and browsing pattern insights. The implementation uses SQLite database access to retrieve browsing data, categorizes websites across 12+ domains (social media, development, education, entertainment, etc.), and performs session analysis with productivity metrics, focus scoring, and learning path detection. Built with comprehensive analysis tools including domain statistics, time pattern analysis, rabbit hole detection, and research session identification, it serves users wanting to understand their browsing habits, optimize productivity workflows, or gain insights into their digital consumption patterns through conversational analysis of their browser history data.', '@mixophrygian', 'databases', 'Unknown', 7, 'https://github.com/mixophrygian/browser_history_mcp', NULL, 0, 'https://github.com/mixophrygian.png?size=128', '2026-03-09T05:21:01.925850+00:00'),
  ('anchor-browser', 'Anchor Browser', 'Browser MCP Server provides remote browser automation with built-in proxies and stealth capabilities through integration with Anchor Browser''s cloud infrastructure. Originally based on Microsoft''s Playwright MCP implementation, this modified version by Guy Ben Simhon connects to Anchor''s remote browsers instead of local instances, offering automated proxy rotation and advanced anti-detection features for web scraping and automation tasks. The server exposes comprehensive browser automation tools including navigation, element interaction, screenshot capture, PDF generation, and JavaScript evaluation, making it valuable for data extraction, testing workflows, and automated web interactions that require residential proxy support and stealth browsing capabilities.', '@browsermcp-com', 'development', 'Unknown', 35, 'https://github.com/browsermcp-com/mcp', 'browser-mcp', 981, 'https://github.com/browsermcp-com.png?size=128', '2026-03-09T05:21:01.925894+00:00'),
  ('browserous', 'Browserous', 'Provides on-demand cloud-based Chrome browsers for AI agents to navigate web pages, fill forms, and capture screenshots. Exposes Chrome DevTools Protocol interface via MCP with 26 tools for browser automation. Offers zero-configuration setup with built-in stealth mode and encrypted, isolated browser sessions.', '@unknown', 'productivity', 'Unknown', 0, 'https://browserous.com/', NULL, 0, NULL, '2026-03-09T05:21:01.925920+00:00'),
  ('browserstack', 'BrowserStack', 'BrowserStack''s MCP Server provides AI assistants with direct access to BrowserStack''s testing infrastructure, enabling automated and manual testing across browsers, devices, and platforms. The TypeScript implementation offers tools for browser compatibility testing, mobile app testing, accessibility scanning, network failure analysis, and test management through BrowserStack''s cloud services. It includes features for launching live testing sessions, uploading mobile apps, configuring SDK integrations, and retrieving test results, making it valuable for developers and QA teams who need to debug cross-browser issues, verify mobile app functionality, or manage test cases through natural language interactions.', '@browserstack', 'development', 'Unknown', 130, 'https://github.com/browserstack/mcp-server', '@browserstack/mcp-server', 29388, 'https://github.com/browserstack.png?size=128', '2026-03-09T05:21:01.925948+00:00'),
  ('browser-use', 'Browser Use', 'Welcome to the official Model Context Protocol (MCP) server for browser-use.com, enabling LLMs, agents, and apps to access, search, and extract web data in real-time using the browser-use.com API. This server exposes MCP tools for web search and concurrent URL search, making it easy to integrate real web data into any MCP-compatible client (like Claude Desktop, Cursor, Windsurf, and more).', '@browser-use', 'ai-ml', 'Unknown', 79856, 'https://github.com/browser-use/browser-use', 'browser-use-mcp', 1176, 'https://github.com/browser-use.png?size=128', '2026-03-09T05:21:01.925982+00:00'),
  ('aws-ireveal', 'AWS IReveal', 'AWS iReveal MCP server provides incident response and investigation tools for AWS environments, enabling AI assistants to interact with CloudTrail logs, Athena queries, CloudWatch events, GuardDuty findings, AWS Config, Network Access Analyzer, and IAM Access Analyzer. The implementation offers specialized functions for analyzing security events, querying log data with complex filters, examining compliance status, and investigating potential security incidents. Built with Python using boto3 for AWS API integration, it features robust error handling and formatted JSON responses, making it particularly valuable for security teams needing to investigate suspicious activities, analyze access patterns, or respond to security alerts without switching context.', '@brucedh', 'cloud', 'Unknown', 8, 'https://github.com/brucedh/aws-ireveal-mcp', NULL, 0, 'https://github.com/brucedh.png?size=128', '2026-03-09T05:21:01.926003+00:00'),
  ('buildautomata-memory', 'BuildAutomata Memory', 'BuildAutomata Memory MCP provides persistent memory storage for AI agents with temporal versioning, semantic search, and multi-backend architecture. Created by Jurden Bruce, it combines SQLite for reliable persistence, Qdrant for vector similarity search, and sentence transformers for embeddings, with automatic memory decay, LRU caching, and complete version history tracking. The system supports both MCP server mode for Claude Desktop integration and a standalone CLI for direct access from development tools, making it ideal for AI assistants that need to maintain context across conversations and learn from past interactions.', '@brucepro', 'databases', 'Unknown', 14, 'https://github.com/brucepro/buildautomata_memory_mcp', NULL, 0, 'https://github.com/brucepro.png?size=128', '2026-03-09T05:21:01.926015+00:00'),
  ('spring-boot-bridge', 'Spring Boot Bridge', 'Spring-MCP-Bridge is a Python tool that automatically converts Spring Boot REST applications into MCP servers, enabling AI assistants to interact with existing Spring APIs. Developed by Bruno Santos, it scans Java source code to identify controllers, endpoints, and data models, then generates a FastAPI server that acts as a bridge between MCP clients and the original Spring application. The tool preserves all endpoint functionality while adding the MCP schema layer, making it valuable for developers who want to expose their Spring Boot APIs to AI tools like Claude or Cursor without rewriting their backend services.', '@brunoonapps', 'development', 'Unknown', 4, 'https://github.com/brunoonapps/spring-mcp-bridge', NULL, 0, 'https://github.com/brunoonapps.png?size=128', '2026-03-09T05:21:01.926040+00:00'),
  ('go-code-graph', 'Go Code Graph', 'This Go code analysis and visualization system provides AI assistants with deep codebase understanding through static analysis and graph-based representation. Built by brutski, it parses Go source code using AST analysis to extract relationships between packages, structs, interfaces, functions, and methods, storing the resulting graph in Neo4j for complex querying and pattern detection. The implementation includes four main components: an analyzer that builds comprehensive code graphs with complexity metrics and optional semantic embeddings, a Neo4j-backed storage system supporting 9 node types and 12+ relationship types, an interactive web visualization using Cytoscape.js for enterprise-scale codebases, and an MCP server that translates natural language queries into Cypher for impact analysis, architecture detection, and code quality assessment. It serves development teams needing to understand large codebases, perform refactoring impact analysis, detect code patterns and duplicates, and onboard new developers through conversational interfaces that can answer questions about code structure, dependencies, and architectural patterns.', '@brutski', 'development', 'Unknown', 14, 'https://github.com/brutski/go-code-graph', NULL, 0, 'https://github.com/brutski.png?size=128', '2026-03-09T05:21:01.926076+00:00'),
  ('osint', 'OSINT', 'osint-mcp provides real-time access to global security events and threat intelligence through an always-on MCP server. No setup, no API keys, no configuration files - just connect and start querying the latest security intelligence.', '@brutus-gr', 'development', 'Unknown', 70, 'https://github.com/brutus-gr/stratint-mcp', NULL, 0, 'https://github.com/brutus-gr.png?size=128', '2026-03-09T05:21:01.926095+00:00'),
  ('sql-database-connector', 'SQL Database Connector', 'A unified SQL MCP server that provides database connectivity across multiple backends including MySQL, Microsoft SQL Server, Oracle, and Sybase through a consistent interface. Built with a factory pattern architecture, it abstracts database-specific connection details and query syntax differences behind standardized tools for executing queries, describing table schemas, and browsing database resources. Useful for working with enterprise databases across different platforms without requiring separate integrations for each database type.', '@bryr0', 'databases', 'Unknown', 1, 'https://github.com/bryr0/sql-mcp', NULL, 0, 'https://github.com/bryr0.png?size=128', '2026-03-09T05:21:01.926141+00:00'),
  ('deltatask', 'DeltaTask', 'DeltaTask is a locally-hosted task management system with Obsidian integration. It provides a SQLite-backed database for storing tasks with properties like urgency, effort, and tags, while offering intelligent prioritization and task decomposition. The MCP server exposes a full API for creating, updating, and querying tasks, as well as syncing with Obsidian markdown files. Ideal for users wanting a powerful, customizable todo system with local data storage and markdown integration.', '@brysontang', 'databases', 'Unknown', 14, 'https://github.com/brysontang/deltatask', NULL, 0, 'https://github.com/brysontang.png?size=128', '2026-03-09T05:21:01.926152+00:00'),
  ('ansible', 'Ansible', 'Advanced Ansible MCP server built with FastMCP that provides comprehensive infrastructure automation capabilities through both project-based and ad-hoc execution modes. The implementation offers extensive tooling including inventory management with diff capabilities, playbook execution with idempotence testing, Ansible Vault operations for secrets management, Galaxy dependency handling with lock file generation, and role scaffolding utilities. Features a sophisticated project registration system that allows users to configure multiple Ansible environments with custom inventory paths, role/collection directories, and environment variables, while supporting both saved configurations and runtime environment overrides for flexible workflow integration.', '@bsahane', 'development', 'Unknown', 24, 'https://github.com/bsahane/mcp-ansible', NULL, 0, 'https://github.com/bsahane.png?size=128', '2026-03-09T05:21:01.926184+00:00'),
  ('proxmox-ve', 'Proxmox VE', 'Advanced Proxmox MCP server built by bsahane that provides AI assistants with comprehensive virtualization management capabilities through the Proxmox VE API. The implementation offers extensive VM and LXC container lifecycle operations including creation, cloning, migration, and deletion, along with advanced features like cloud-init configuration, firewall management, snapshot handling, backup/restore operations, and resource pool administration. Built using FastMCP with the proxmoxer library, it includes safety features like confirmation requirements for destructive operations, dry-run modes, task waiting capabilities, and automatic VM/container resolution by name or ID, making it valuable for infrastructure automation, datacenter management, and AI-assisted virtualization workflows where conversational control over Proxmox environments is needed.', '@bsahane', 'productivity', 'Unknown', 16, 'https://github.com/bsahane/mcp-proxmox', NULL, 0, 'https://github.com/bsahane.png?size=128', '2026-03-09T05:21:01.926235+00:00'),
  ('strapi-cms', 'Strapi CMS', 'This Strapi MCP server, developed by bschauer, enables seamless integration of Strapi CMS content into AI-assisted workflows. Built with TypeScript and leveraging the @modelcontextprotocol/sdk, it provides a standardized interface for accessing and manipulating Strapi data through compatible MCP clients. The implementation supports content type retrieval, CRUD operations, and media handling, offering tools for dynamic content management and querying. It''s particularly useful for developers and content managers looking to incorporate on-demand access to CMS data into their AI-assisted applications, allowing for dynamic content creation, updating, and analysis within Strapi-powered websites and applications.', '@misterboe', 'development', 'Unknown', 65, 'https://github.com/misterboe/strapi-mcp-server', '@bschauer/strapi-mcp-server', 7088, 'https://github.com/misterboe.png?size=128', '2026-03-09T05:21:01.926265+00:00'),
  ('nse-bse-india-stock-market', 'NSE-BSE India Stock Market', 'Provides access to NSE and BSE India stock market APIs, offering tools across market data, historical analysis, options chains, corporate actions, IPO information, and document processing capabilities. The implementation uses streamable HTTP transport with Express.js, features smart response limiting to prevent data overflow with metadata-driven filtering recommendations, and includes document extraction tools for PDFs and compressed files commonly found in Indian stock market reports. Built with TypeScript and Docker support, it integrates the nse-bse-api library to deliver real-time quotes, historical data analysis, F&O chain processing, and corporate announcement tracking, making it useful for financial analysis, investment research, and automated trading system development focused on Indian equity markets.', '@bshada', 'cloud', 'Unknown', 9, 'https://github.com/bshada/nse-bse-mcp', NULL, 0, 'https://github.com/bshada.png?size=128', '2026-03-09T05:21:01.926293+00:00'),
  ('chain-of-draft', 'Chain of Draft', 'MCP Chain of Draft Server provides a tool for enhancing reasoning through iterative critique and revision cycles. Developed by bsmi021, this TypeScript implementation exposes a Chain of Draft tool that structures thinking into drafts with explicit reasoning chains, allowing for focused critiques and targeted revisions. The server maintains session state to track thought history and branching paths, making it particularly valuable for complex problem-solving tasks where initial reasoning may contain errors or gaps. It integrates with the Model Context Protocol SDK to enable AI assistants to improve their reasoning quality through systematic refinement rather than single-pass thinking.', '@bsmi021', 'development', 'Unknown', 25, 'https://github.com/bsmi021/mcp-chain-of-draft-server', 'mcp-chain-of-draft-server', 3900, 'https://github.com/bsmi021.png?size=128', '2026-03-09T05:21:01.926324+00:00'),
  ('coding-file-context', 'Coding File Context', 'This file context server, developed for enhanced Model Context Protocol (MCP) interactions, provides AI assistants with advanced file system access and code analysis capabilities. It implements real-time file watching, smart caching with LRU strategy, and detailed code metrics calculation including cyclomatic complexity and dependency extraction. The server exposes tools for file operations, code analysis, and advanced searching with regex support and context-aware results. By offering a comprehensive file system interface through MCP, it enables AI systems to efficiently read, search, and analyze code files. This implementation is particularly suited for scenarios involving large codebases, continuous integration environments, or AI-assisted code review processes, facilitating use cases such as automated code quality assessment, intelligent code navigation, and context-aware programming assistance.', '@bsmi021', 'development', 'Unknown', 36, 'https://github.com/bsmi021/mcp-file-context-server', NULL, 0, 'https://github.com/bsmi021.png?size=128', '2026-03-09T05:21:01.926356+00:00'),
  ('file-operations', 'File Operations', 'This file operations MCP server, developed by Brian W. Smith, provides enhanced capabilities for file and directory management with streaming, patching, and change tracking support. Built with TypeScript and leveraging libraries like diff and glob, it offers tools for basic file operations, directory handling, file watching, and change tracking. The implementation stands out by incorporating streaming for large file handling, robust error handling, and rate limiting for protection against excessive requests. It''s particularly useful for developers and applications requiring advanced file manipulation, real-time file system monitoring, or integration of file operations into AI-assisted workflows, enabling tasks like automated file management, backup systems, or content processing pipelines.', '@bsmi021', 'development', 'Unknown', 20, 'https://github.com/bsmi021/mcp-file-operations-server', 'file-operations-server', 31, 'https://github.com/bsmi021.png?size=128', '2026-03-09T05:21:01.926387+00:00'),
  ('mistral-codestral', 'Mistral Codestral', 'This Mistral Codestral MCP server, developed by the Mistral AI team, provides a TypeScript-based interface for AI assistants to interact with Mistral''s code-related APIs. Built using the Model Context Protocol SDK, it offers tools for code completion, bug fixing, and test generation across multiple programming languages. The implementation focuses on efficient code processing and includes features like Fill-in-the-Middle completion, rate limiting, and comprehensive error handling. It''s particularly useful for enhancing AI-driven software development workflows, enabling tasks like automated code review, bug detection, and test suite generation without requiring deep knowledge of Mistral''s API intricacies.', '@bsmi021', 'development', 'Unknown', 2, 'https://github.com/bsmi021/mcp-mistral-codestral', NULL, 0, 'https://github.com/bsmi021.png?size=128', '2026-03-09T05:21:01.926444+00:00'),
  ('node-omnibus', 'Node Omnibus', 'This Node.js-based MCP server, developed as a comprehensive development tool, integrates with the Model Context Protocol SDK to facilitate AI-assisted Node.js and TypeScript development. It leverages TypeScript for type safety and includes Axios for HTTP requests. The server is designed to be extensible, allowing developers to add custom functionality for various Node.js development tasks. It''s particularly suited for scenarios requiring AI assistance in code generation, debugging, and project management within Node.js environments. The implementation''s focus on Node.js specifics differentiates it from more general-purpose MCP servers, making it valuable for teams working extensively with Node.js and TypeScript.', '@bsmi021', 'development', 'Unknown', 5, 'https://github.com/bsmi021/mcp-node-omnibus-server', NULL, 0, 'https://github.com/bsmi021.png?size=128', '2026-03-09T05:21:01.926471+00:00'),
  ('openrouter-conversation-manager', 'OpenRouter Conversation Manager', 'MCP Conversation Server provides a standardized interface for managing conversations with OpenRouter''s language models. It enables applications to create and manage multiple conversations, send messages with streaming support, and persist conversation state to the filesystem. Built with TypeScript and the OpenAI SDK, it features automatic token counting, context window management, and support for various models including Claude 3 Opus, Claude 3 Sonnet, and Llama 2 70B. The server loads configuration from YAML files, handles error states appropriately, and is particularly valuable for developers who need a unified conversation management system across different AI models without managing provider-specific implementations.', '@bsmi021', 'development', 'Unknown', 2, 'https://github.com/bsmi021/mcp-conversation-server', NULL, 0, 'https://github.com/bsmi021.png?size=128', '2026-03-09T05:21:01.926503+00:00'),
  ('web-content-extractor', 'Web Content Extractor', 'This MCP server for web content scanning and analysis, developed using TypeScript, provides tools for extracting and processing web page content. It leverages libraries like Cheerio for HTML parsing and Turndown for HTML-to-Markdown conversion, offering capabilities to fetch, analyze, and transform web content. The implementation is designed to integrate seamlessly with AI-assisted workflows, enabling tasks such as web scraping, content summarization, and data extraction. It''s particularly useful for researchers, content creators, and developers who need to automate web content analysis, generate structured data from websites, or incorporate web-based information into their AI applications.', '@bsmi021', 'development', 'Unknown', 12, 'https://github.com/bsmi021/mcp-server-webscan', NULL, 0, 'https://github.com/bsmi021.png?size=128', '2026-03-09T05:21:01.926533+00:00'),
  ('mlflow-prompt-registry', 'MLflow Prompt Registry', 'MLflow Prompt Registry MCP Server provides a bridge between Claude Desktop and MLflow''s Prompt Registry, enabling users to discover and use prompt templates managed in MLflow directly within Claude. Developed by B-Step62, this TypeScript implementation exposes two main tools: ''list-prompts'' for browsing available templates and ''get-prompt'' for retrieving and compiling specific prompts with variable substitution. The server connects to MLflow''s API to fetch prompt metadata and content, then formats it according to the MCP specification. This integration is particularly valuable for teams already using MLflow for prompt management who want to streamline their prompt engineering workflow by accessing their templates directly in Claude Desktop.', '@b-step62', 'development', 'Unknown', 2, 'https://github.com/b-step62/mcp-server-mlflow', NULL, 0, 'https://github.com/b-step62.png?size=128', '2026-03-09T05:21:01.926564+00:00'),
  ('spamassassin', 'SpamAssassin', 'This SpamAssassin MCP server provides AI assistants with defensive email security analysis capabilities through integration with the SpamAssassin spam detection engine. Built in Go with a containerized Docker architecture, it offers tools for scanning email content, checking sender reputation, explaining spam scores, and managing SpamAssassin rule configurations while maintaining strict security boundaries that prevent any offensive operations like email sending or malicious content generation. The implementation includes comprehensive security controls including rate limiting, input validation, audit logging, and container hardening, making it suitable for security researchers, email administrators, and AI systems that need to analyze email threats in a safe, defensive-only environment.', '@btafoya', 'cloud', 'Unknown', 4, 'https://github.com/btafoya/spamassassin-mcp', NULL, 0, 'https://github.com/btafoya.png?size=128', '2026-03-09T05:21:01.926588+00:00'),
  ('btcfi-api', 'BTCFi API', 'Bitcoin data for AI agents. 27 tools with x402 micropayments. No API keys needed.', '@aiindigo925', 'ai-ml', 'Unknown', 0, 'https://github.com/aiindigo925/btcfi-api', NULL, 0, 'https://github.com/aiindigo925.png?size=128', '2026-03-09T05:21:01.926609+00:00'),
  ('npm-search', 'Npm Search', 'This npm search MCP server, developed by Anthropic, enables AI assistants to search for npm packages using the npm CLI. Built with TypeScript and leveraging the @modelcontextprotocol/sdk, it exposes a ''search_npm_packages'' tool that executes the ''npm search'' command and returns the results. The server runs on stdio, making it compatible with various MCP clients. By providing a standardized interface for npm package searches, it allows AI systems to easily access and analyze the npm registry. This implementation is particularly useful for scenarios involving JavaScript/Node.js development, package discovery, or dependency management, facilitating use cases such as finding suitable libraries, comparing package versions, or assessing package popularity within the npm ecosystem.', '@btwiuse', 'development', 'Unknown', 15, 'https://github.com/btwiuse/npm-search-mcp-server', 'npm-search-mcp-server', 8322, 'https://github.com/btwiuse.png?size=128', '2026-03-09T05:21:01.926637+00:00'),
  ('bucket-feature-flagging', 'Bucket (Feature Flagging)', 'With [Bucket](https://bucket.co/)''s MCP you can flag features directly from the chat window in your code editor. Whether that’s VS Code, Cursor, Windsurf, Claude Code—any IDE that has MCP support.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('build-vault', 'Build Vault', 'The Build Vault MCP Server transforms The Build Podcast into a searchable knowledge base with thousands of AI insights using hybrid vector and full-text search powered by Supabase and pgvector. Built by The Build Podcast team, it provides 12 tools for semantic search across business ideas, frameworks, products, and expert insights from podcast episodes, along with 8 analytics resources and 4 guided prompts for discovery workflows. The server features OpenAI Deep Research compatibility, speaker-specific filtering, and intelligent elicitation suggestions, making it valuable for entrepreneurs researching business opportunities, developers exploring AI frameworks, and product managers seeking validated strategies from industry experts.', '@the-build-podcast', 'databases', 'Unknown', 2, 'https://github.com/the-build-podcast/build-vault-mcp-server', NULL, 0, 'https://github.com/the-build-podcast.png?size=128', '2026-03-09T05:21:01.926867+00:00'),
  ('builtwith', 'BuiltWith', 'The BuiltWith MCP Server provides AI assistants with access to BuiltWith''s technology detection API, allowing them to identify web technologies used on specified domains. Developed by BuiltWith Pty Ltd under MIT license, this JavaScript implementation uses the Model Context Protocol SDK to expose a single tool, ''domain-lookup'', which retrieves live technology data from websites including names, descriptions, and categorization. The server communicates via stdio transport and includes robust error handling for API responses. This implementation is particularly valuable for digital marketers, competitive analysts, and developers who need to quickly analyze technology stacks without leaving their conversation context.', '@builtwith', 'development', 'Unknown', 36, 'https://github.com/builtwith/builtwith-mcp', NULL, 0, 'https://github.com/builtwith.png?size=128', '2026-03-09T05:21:01.926897+00:00'),
  ('file-system-access', 'File System Access', 'FS MCP is a file system server that enables AI assistants to read files from the local system. Built by Sergey Bunas, it provides a simple interface for accessing file content through the Model Context Protocol, with optional API key authentication for security. The implementation is written in TypeScript, runs on Node.js, and can be easily installed and executed using npx. This tool is particularly valuable for workflows where AI assistants need to analyze, reference, or work with local file content without requiring manual file uploads or content copying.', '@bunasq', 'development', 'Unknown', 13, 'https://github.com/bunasq/fs', '@bunas/fs-mcp', 21120, 'https://github.com/bunasq.png?size=128', '2026-03-09T05:21:01.926926+00:00'),
  ('bundler-gem-explorer', 'Bundler Gem Explorer', 'BundlerMCP is a server that enables AI agents to query information about Ruby gem dependencies in a project''s Gemfile. Developed by Mike Subelsky under MIT license, it provides tools for listing all project gems and retrieving detailed information about specific gems including versions, descriptions, installation paths, documentation locations, and source code files. Built with fast-mcp, it runs in the correct Bundler environment through binstubs, making it particularly valuable for developers who need AI assistants to understand and work with their Ruby project dependencies.', '@subelsky', 'development', 'Unknown', 19, 'https://github.com/subelsky/bundler_mcp', NULL, 0, 'https://github.com/subelsky.png?size=128', '2026-03-09T05:21:01.926952+00:00'),
  ('supaui', 'SupaUI', 'SupaUI MCP Server enables AI agents to generate, fetch, and manage React UI components through natural language interactions with the buouui.com platform. Built with TypeScript and leveraging the Model Context Protocol, it provides tools for creating, searching, and listing UI components with a focus on developer productivity and seamless AI-driven design workflows.', '@buoooou', 'development', 'Unknown', 7, 'https://github.com/buoooou/mcp-ui-gen', '@buouui/supaui-mcp', 4279, 'https://github.com/buoooou.png?size=128', '2026-03-09T05:21:01.926976+00:00'),
  ('clickhouse', 'ClickHouse', 'Clickhouse MCP Server provides a direct integration with ClickHouse databases, enabling AI assistants to execute SQL queries and connect to specific databases through a simple interface. Built by Burak Dirin, this Python-based implementation offers two main tools: ''connect_database'' for establishing database connections and ''execute_query'' for running SQL queries with results returned in JSON format. The server supports configuration through environment variables for connection settings and includes a read-only mode option for enhanced security. It''s particularly valuable for workflows requiring data analysis, reporting, or exploration of information stored in ClickHouse databases without leaving the conversation interface.', '@burakdirin', 'databases', 'Unknown', 2, 'https://github.com/burakdirin/clickhouse-mcp-server', 'clickhouse-mcp-server', 2694, 'https://github.com/burakdirin.png?size=128', '2026-03-09T05:21:01.926986+00:00'),
  ('mysql-database', 'MySQL Database', 'MySQL Database MCP Server provides a bridge between Claude and MySQL databases, enabling direct SQL query execution and database connections through a simple interface. Developed by Burak Dirin, it offers two main tools: ''connect_database'' for establishing connections to specific databases and ''execute_query'' for running SQL queries with results returned in JSON format. The implementation includes configurable read-only mode for security, supports Python 3.11+, and can be deployed via Docker or installed directly using pip, making it ideal for workflows requiring database access without leaving the conversation interface.', '@burakdirin', 'databases', 'Unknown', 8, 'https://github.com/burakdirin/mysqldb-mcp-server', 'mysqldb-mcp-server', 5698, 'https://github.com/burakdirin.png?size=128', '2026-03-09T05:21:01.926998+00:00'),
  ('vs-code-button-generator', 'VS Code Button Generator', 'VS Code install button generator MCP server that creates markdown badges for installing MCP servers and GitHub Copilot extensions directly in VS Code. Built by burkeholland, the implementation provides tools for generating install buttons for NPX-based MCP servers with support for inputs and environment variables, as well as Copilot-style install buttons for chat instructions, prompts, and chat modes from raw URLs or GitHub repositories. Features both MCP server mode and CLI mode for direct command-line usage, making it valuable for MCP server authors who want to provide one-click installation experiences in their documentation and README files without manually crafting VS Code redirect URLs.', '@burkeholland', 'development', 'Unknown', 2, 'https://github.com/burkeholland/mcp-vsc-button-gen', 'mcp-vsc-button-gen', 284, 'https://github.com/burkeholland.png?size=128', '2026-03-09T05:21:01.927025+00:00'),
  ('geoapify-map-generator', 'Geoapify Map Generator', 'This map generation MCP server, developed by an unnamed author, provides tools for creating map images from geographic coordinates. Built with Python 3.13 and leveraging libraries like Folium and Selenium, it offers functions for geocoding addresses and generating static map images from GeoJSON data. The implementation focuses on simplicity, with just two main tools: one for fetching GPS coordinates and another for creating map visualizations. It''s particularly useful for tasks like location-based data visualization, address validation, or generating custom map images for reports or presentations, enabling AI assistants or applications to work with geographic data without directly handling mapping APIs or browser interactions.', '@burningion', 'productivity', 'Unknown', 4, 'https://github.com/burningion/geoapify-mcp', NULL, 0, 'https://github.com/burningion.png?size=128', '2026-03-09T05:21:01.927069+00:00'),
  ('video-editor', 'Video Editor', 'This MCP server, developed by Kirk Kaiser, enables AI-assisted video editing and searching using the Video Jungle API. It provides tools for adding videos, searching video content using embeddings, and generating edits from single or multiple video files. The implementation is built in Python 3.11+ and integrates with libraries like einops, timm, and transformers for advanced video processing capabilities. It''s designed for content creators and video editors who want to leverage AI to streamline their workflow, allowing for natural language queries to find relevant video clips and automate editing tasks. The server also includes an optional feature to search local video files on macOS, making it versatile for both cloud-based and local video management.', '@burningion', 'productivity', 'Unknown', 253, 'https://github.com/burningion/video-editing-mcp', 'video-editor-mcp', 36576, 'https://github.com/burningion.png?size=128', '2026-03-09T05:21:01.927114+00:00'),
  ('maigret-osint', 'Maigret OSINT', 'This MCP server, developed by BurtTheCoder, enables AI assistants like Claude to leverage the OSINT capabilities of Maigret. Built in JavaScript/TypeScript, it provides functionality for searching usernames across social networks and analyzing URLs. The implementation stands out by offering Docker-based execution, multiple output formats, and site filtering options. By connecting AI capabilities with Maigret''s extensive data collection, this server allows AI systems to gather and process publicly available user information programmatically. It is particularly useful for building AI-powered tools for social media research, identity verification, and open-source intelligence gathering that require ethical and responsible use of public data sources.', '@burtthecoder', 'cloud', 'Unknown', 229, 'https://github.com/burtthecoder/mcp-maigret', 'mcp-maigret', 7203, 'https://github.com/burtthecoder.png?size=128', '2026-03-09T05:21:01.927138+00:00'),
  ('dnstwist', 'DNSTwist', 'This MCP server for dnstwist, developed by burtmacklin, provides AI assistants with DNS fuzzing capabilities to detect typosquatting, phishing, and corporate espionage. Built using TypeScript and leveraging the Model Context Protocol SDK, it offers a standardized interface for domain security analysis. The server integrates with the dnstwist tool, enabling automated generation and analysis of domain name variations. It''s particularly valuable for cybersecurity professionals and organizations looking to proactively identify potential threats to their online presence, facilitating use cases such as brand protection, phishing prevention, and domain security audits.', '@burtthecoder', 'development', 'Unknown', 44, 'https://github.com/burtthecoder/mcp-dnstwist', '@burtthecoder/mcp-dnstwist', 5760, 'https://github.com/burtthecoder.png?size=128', '2026-03-09T05:21:01.927166+00:00'),
  ('virustotal', 'VirusTotal', 'This VirusTotal MCP server, developed by BurtTheCoder, enables AI assistants like Claude to leverage VirusTotal''s threat intelligence capabilities. Built in JavaScript/TypeScript, it provides functionality for scanning URLs, analyzing file hashes, and retrieving IP address reports. The implementation stands out by offering relationship analysis tools and pagination support for large result sets. By connecting AI capabilities with VirusTotal''s extensive threat data, this server allows AI systems to perform security analysis and threat detection programmatically. It is particularly useful for building AI-powered tools for malware research, phishing detection, and network security monitoring that require access to up-to-date threat intelligence.', '@burtthecoder', 'development', 'Unknown', 112, 'https://github.com/burtthecoder/mcp-virustotal', '@burtthecoder/mcp-virustotal', 13491, 'https://github.com/burtthecoder.png?size=128', '2026-03-09T05:21:01.927220+00:00'),
  ('aws-resources', 'AWS Resources', 'This AWS Resources MCP server, developed by peakmojo, provides a Python-based interface for AI models to interact with AWS services using boto3. Built to address limitations in existing solutions, it offers a containerized approach that simplifies deployment and enhances stability. The server exposes a dynamic resource for executing AWS queries, supporting operations across various AWS services like S3 and CodePipeline. It features a sandboxed environment for code execution, ensuring security while allowing flexibility in query construction. This implementation is particularly useful for DevOps tasks, cloud resource management, and integrating AWS functionality into AI-powered workflows, offering a more accessible and customizable alternative to AWS Chatbot with Developer Access.', '@baryhuang', 'cloud', 'Unknown', 23, 'https://github.com/baryhuang/mcp-server-aws-resources-python', NULL, 0, 'https://github.com/baryhuang.png?size=128', '2026-03-09T05:21:01.927240+00:00'),
  ('hubspot', 'HubSpot', 'This HubSpot MCP server, developed by peakmojo, provides a streamlined interface for AI models to interact with HubSpot CRM data and operations. Built using Python and the HubSpot API client, it offers tools for managing contacts and companies, including creation and retrieval functionalities. The server implements auto-updating resources and a demonstration prompt to guide users through HubSpot operations. By abstracting HubSpot API interactions into a standardized MCP format, it enables AI systems to easily access and manipulate CRM data. This implementation is particularly valuable for sales and marketing applications, facilitating use cases such as lead management, customer data analysis, and automated CRM updates.', '@peakmojo', 'ai-ml', 'Unknown', 116, 'https://github.com/peakmojo/mcp-hubspot', NULL, 0, 'https://github.com/peakmojo.png?size=128', '2026-03-09T05:21:01.927286+00:00'),
  ('twitter-noauth', 'Twitter NoAuth', 'MCP Server - Twitter NoAuth provides Twitter API access without requiring local credential setup, enabling headless operation in remote environments. Built by buryhuang, it implements a decoupled architecture where clients complete OAuth flows independently and pass credentials as context to the server. The implementation supports core Twitter operations including searching tweets, retrieving user tweets, posting new content, and replying to existing tweets. It handles automatic token refreshing and is designed for containerization with Docker, making it particularly valuable for AI assistants that need to interact with Twitter while maintaining separation between credential storage and server implementation.', '@baryhuang', 'cloud', 'Unknown', 1, 'https://github.com/baryhuang/mcp-twitter-noauth', NULL, 0, 'https://github.com/baryhuang.png?size=128', '2026-03-09T05:21:01.927310+00:00'),
  ('unipile', 'Unipile', 'This MCP server, developed by Bary Huang, integrates with Unipile to provide a unified interface for accessing messages across multiple messaging platforms including LinkedIn, WhatsApp, Instagram, Messenger, and Telegram. It offers tools for retrieving chat messages with pagination support, making it particularly useful for AI models to interact with diverse communication channels through a standardized protocol. The implementation is containerized for easy deployment across various Linux architectures and includes detailed setup instructions for both Docker and local environments. It''s designed for users who need to manage communications across multiple platforms efficiently, especially beneficial for professionals leveraging AI capabilities to enhance their networking and communication strategies.', '@honeybluesky', 'cloud', 'Unknown', 14, 'https://github.com/honeybluesky/mcp-unipile', NULL, 0, 'https://github.com/honeybluesky.png?size=128', '2026-03-09T05:21:01.927334+00:00'),
  ('business-analytics-rag', 'Business Analytics RAG', 'Business analytics and knowledge retrieval system that combines MCP servers for data analysis and RAG (Retrieval-Augmented Generation) capabilities with flexible LLM backend support for both Google Gemini and custom localhost APIs. The implementation provides two specialized MCP servers: a business analytics server that performs statistical operations like mean calculation, correlation analysis, and linear regression on CSV business data, and a RAG server that searches through business knowledge documents for terms, definitions, and company policies. Built with Python using pandas for data processing and supporting both Gemini API and custom OpenAI-compatible endpoints, it''s designed for business intelligence workflows where users need to combine quantitative data analysis with contextual business knowledge retrieval through natural language interactions.', '@ansh-riyal', 'productivity', 'Unknown', 3, 'https://github.com/ansh-riyal/mcp-rag', NULL, 0, 'https://github.com/ansh-riyal.png?size=128', '2026-03-09T05:21:01.927385+00:00'),
  ('buu-ai-3d-model-generator', 'Buu AI 3D Model Generator', 'Buu MCP Server provides a bridge between AI assistants and the Buu AI platform, enabling 3D model generation from text prompts. Built with TypeScript and the Model Context Protocol SDK, it exposes tools for managing teams, generating subthreads, and creating both 2D images and 3D models in various styles including Realistic, LowPoly, Voxel, and Stylized. The server requires a Buu Team API key for authentication and communicates with Buu''s GraphQL API, making it valuable for designers, game developers, and creative professionals who need to quickly generate 3D assets through natural language descriptions without leaving their AI assistant interface.', '@buu-ai', 'development', 'Unknown', 0, 'https://github.com/buu-ai/buu-mcp-server', NULL, 0, 'https://github.com/buu-ai.png?size=128', '2026-03-09T05:21:01.927417+00:00'),
  ('wechat-articles', 'WeChat Articles', 'Reads and extracts content from WeChat official account articles using Playwright for browser automation and BeautifulSoup for HTML parsing. Simulates browser behavior to bypass anti-scraping measures and returns structured article data including title, author, publication date, and full content. Designed for content aggregation, research workflows involving Chinese social media, and automated monitoring of WeChat public accounts.', '@bwkyd', 'communication', 'Unknown', 299, 'https://github.com/bwkyd/wexin-read-mcp', NULL, 0, 'https://github.com/bwkyd.png?size=128', '2026-03-09T05:21:01.927445+00:00'),
  ('wireshark', 'Wireshark', 'Integrates with Wireshark''s tshark command-line tool to provide network packet analysis capabilities. Supports packet capture, protocol hierarchy statistics, endpoint and conversation tracking, HTTP request and DNS query extraction, file export from captures, threat intelligence checks, and credential detection. Requires Python 3.10+ and Wireshark with tshark accessible in the system PATH.', '@bx33661', 'file-systems', 'Unknown', 31, 'https://github.com/bx33661/wireshark-mcp', NULL, 0, 'https://github.com/bx33661.png?size=128', '2026-03-09T05:21:01.927487+00:00'),
  ('tachibot', 'Tachibot', 'Orchestrates multiple AI models in parallel to reduce hallucinations through cross-validation. Models check each other''s work, debate solutions, and catch errors before presenting results. Supports research tools (Perplexity search, Grok search), reasoning tools (multi-provider reasoning chains), analysis tools (brainstorming, text analysis, code generation), and validation workflows. Uses YAML-based workflows and provides token-optimized profiles.', '@bypawel', 'development', 'Unknown', 15, 'https://github.com/bypawel/tachibot-mcp', NULL, 0, 'https://github.com/bypawel.png?size=128', '2026-03-09T05:21:01.927509+00:00'),
  ('weather', 'Weather', 'Provides weather information for US locations using the National Weather Service API. Retrieves active weather alerts by state and weather forecasts by coordinates (latitude/longitude). Uses official government weather data with no API key required.', '@byrness', 'development', 'Unknown', 0, 'https://github.com/byrness/mcp-weather-server', NULL, 0, 'https://github.com/byrness.png?size=128', '2026-03-09T05:21:01.927526+00:00'),
  ('memoria', 'Memoria', 'Analyzes git commit history to reveal hidden file dependencies and coupling patterns that static analysis misses. Uses multiple analytical engines including volatility detection for bug-prone code, entanglement analysis for files that change together, and sentinel tracking for stale dependencies. Runs entirely locally using the .git folder with no cloud uploads or API keys required.', '@byronwade', 'development', 'Unknown', 1, 'https://github.com/byronwade/memoria', NULL, 0, 'https://github.com/byronwade.png?size=128', '2026-03-09T05:21:01.927545+00:00'),
  ('dbhub-universal-database-gateway', 'DBHub (Universal Database Gateway)', 'DBHub is a universal database gateway implementing the MCP server interface, allowing AI assistants to connect to and explore different databases like PostgreSQL, MySQL, SQLite, and DuckDB. Developed by Bytebase, it provides capabilities for browsing tables, viewing schema information, running read-only SQL queries, and includes safety checks to prevent dangerous operations. The implementation is containerized with Docker for easy deployment and supports both stdio transport for direct integration with tools like Claude Desktop and SSE transport for browser and network clients, making it particularly valuable for AI assistants that need to access and analyze data stored in various database systems.', '@bytebase', 'databases', 'Unknown', 2253, 'https://github.com/bytebase/dbhub', '@bytebase/dbhub', 222965, 'https://github.com/bytebase.png?size=128', '2026-03-09T05:21:01.927558+00:00'),
  ('search-ui-tars', 'Search (UI-TARS)', 'Provides web search capabilities through multiple search engines including browser-based search automation. Part of ByteDance''s UI-TARS-desktop agent infrastructure, supporting various search providers for enabling AI agents to access current web information and conduct research workflows.', '@bytedance', 'ai-ml', 'Unknown', 28608, 'https://github.com/bytedance/ui-tars-desktop/tree/HEAD/packages/agent-infra/mcp-servers/search', NULL, 0, 'https://github.com/bytedance.png?size=128', '2026-03-09T05:21:01.927587+00:00'),
  ('net-framework-development', '.NET Framework Development', 'This MCP server provides .NET Framework development capabilities through TCP communication, enabling AI assistants to build projects, run tests, and analyze solutions using MSBuild and Visual Studio tools. Built by bytedreamer using C# with .NET 8 and targeting .NET Framework projects, it offers three core tools: build_project for compiling solutions/projects with MSBuild integration and detailed error parsing, run_tests supporting MSTest/NUnit/xUnit frameworks with VSTest.Console execution, and solution analysis for project structure inspection. The implementation features automatic Visual Studio version detection (2019/2022), flexible MSBuild path resolution, comprehensive test framework detection, structured error reporting with file/line information, and cross-platform support through WSL bridge scripts, making it valuable for legacy .NET Framework maintenance, automated CI/CD workflows, and building AI assistants that need programmatic access to Windows-based .NET development tools without manual Visual Studio navigation.', '@bytedreamer', 'development', 'Unknown', 21, 'https://github.com/bytedreamer/dotnetframeworkmcp', NULL, 0, 'https://github.com/bytedreamer.png?size=128', '2026-03-09T05:21:01.927622+00:00'),
  ('flux-schnell', 'Flux Schnell', 'MCP server for generating images using the Flux Schnell model via a Cloudflare worker API. Built by bytefer, this implementation provides a single ''generate_image'' tool that allows users to create images by sending text prompts, with robust error handling and environment variable configuration. Useful for developers needing a streamlined text-to-image generation service with clean TypeScript implementation.', '@bytefer', 'cloud', 'Unknown', 5, 'https://github.com/bytefer/mcp-flux-schnell', NULL, 0, 'https://github.com/bytefer.png?size=128', '2026-03-09T05:21:01.927641+00:00'),
  ('byteplant', 'Byteplant', 'Integrates Byteplant''s data quality APIs for validating email addresses, phone numbers, and postal addresses across 240+ countries. Provides real-time validation with detailed deliverability status, line type, carrier information, and standardized address formatting. Used by organizations including Shell, Adobe, and Autodesk.', '@byteplant-dev', 'communication', 'Unknown', 1, 'https://github.com/byteplant-dev/byteplant-mcp', NULL, 0, 'https://github.com/byteplant-dev.png?size=128', '2026-03-09T05:21:01.927664+00:00'),
  ('cipher', 'Cipher', 'Memory-powered AI agent framework built by BYTEROVER that provides persistent memory capabilities across conversations and sessions using vector databases and embeddings. The implementation supports multiple LLM providers (OpenAI, Anthropic, Gemini, Ollama, etc.), vector stores (Qdrant, Milvus, in-memory), and includes specialized workspace memory for team collaboration tracking project progress, bug reports, and member activities. Features include automatic memory extraction and storage, reasoning pattern recognition, knowledge graph integration, and MCP aggregator mode that exposes memory tools alongside connected MCP servers with conflict resolution, serving developers who need AI assistants that learn and remember context across coding sessions, teams requiring shared project memory, and organizations building AI workflows that benefit from persistent knowledge retention.', '@campfirein', 'databases', 'Unknown', 3557, 'https://github.com/campfirein/cipher', '@byterover/cipher', 43064, 'https://github.com/campfirein.png?size=128', '2026-03-09T05:21:01.927675+00:00'),
  ('atom-of-thoughts', 'Atom of Thoughts', 'Atom of Thoughts is a TypeScript-based MCP implementation that enables AI assistants to break down complex problems into smaller, manageable components. Developed by Byungsoo Kang, this server leverages the Model Context Protocol SDK to facilitate structured thinking processes through atomic thought units. The implementation runs on Node.js and uses stdio for communication, making it lightweight and easily deployable in various environments. It''s particularly useful for reasoning tasks that benefit from decomposition, allowing AI systems to tackle problems step-by-step rather than attempting to solve them all at once.', '@kbsooo', 'development', 'Unknown', 57, 'https://github.com/kbsooo/mcp_atom_of_thoughts', 'atom-of-thoughts', 0, 'https://github.com/kbsooo.png?size=128', '2026-03-09T05:21:01.927702+00:00'),
  ('mssql', 'MSSQL', 'This MSSQL MCP server enables AI agents to interact with Microsoft SQL Server databases through a standardized interface. Built with TypeScript and leveraging the Model Context Protocol SDK, it provides tools for executing SQL queries, managing database connections, and retrieving schema information. The implementation focuses on security and performance, offering features like connection pooling, query parameterization, and TLS encryption support. It''s particularly useful for applications requiring AI-driven database operations, enabling use cases such as automated data analysis, dynamic reporting, and intelligent database management without direct exposure to SQL Server complexities.', '@c0h1b4', 'databases', 'Unknown', 14, 'https://github.com/c0h1b4/mssql-mcp-server', NULL, 0, 'https://github.com/c0h1b4.png?size=128', '2026-03-09T05:21:01.927713+00:00'),
  ('xray-cloud', 'Xray Cloud', 'Built with TypeScript and GraphQL, this server provides 22 specialized tools covering the full Xray workflow from creating manual, Cucumber, and generic test cases to managing test executions with status updates, organizing tests into plans and sets, and performing advanced JQL-based searches across all test artifacts. The implementation features robust authentication with token caching, error handling, and extensive unit test coverage with mocked HTTP interactions. It''s designed for QA teams automating test management workflows, integrating test execution results into CI/CD pipelines, and building custom test reporting dashboards.', '@c4m3lblue-star', 'development', 'Unknown', 3, 'https://github.com/c4m3lblue-star/xray-mcp', NULL, 0, 'https://github.com/c4m3lblue-star.png?size=128', '2026-03-09T05:21:01.927743+00:00'),
  ('amazon-s3', 'Amazon S3', 'MCP-Server-S3 provides a bridge to Amazon S3 storage services, enabling AI assistants to perform common S3 operations through a standardized interface. The implementation offers seven specialized tools for listing buckets, browsing objects, retrieving file contents, uploading and downloading files, and deleting objects. Built with Python 3.13 using the boto3 library, it authenticates with AWS credentials through environment variables and runs as a FastMCP server. This tool is particularly valuable for developers and data engineers who need to interact with cloud storage directly through AI assistants without switching to separate AWS management interfaces.', '@c4pt0r', 'cloud', 'Unknown', 2, 'https://github.com/c4pt0r/mcp-server-s3', NULL, 0, 'https://github.com/c4pt0r.png?size=128', '2026-03-09T05:21:01.927763+00:00'),
  ('document-forge', 'Document Forge', 'This MCP server implementation provides document processing and manipulation capabilities, integrating various libraries for handling different file formats including PDF, DOCX, HTML, CSV, and EPUB. It offers functionalities such as text extraction, conversion between formats, image processing, and markdown generation. The implementation is designed to be used within the Model Context Protocol ecosystem, enabling AI assistants to perform complex document operations. It''s particularly useful for tasks like content analysis, data extraction from documents, and automated report generation across multiple file types.', '@cablate', 'productivity', 'Unknown', 17, 'https://github.com/cablate/mcp-doc-forge', '@cablate/mcp-doc-forge', 3692, 'https://github.com/cablate.png?size=128', '2026-03-09T05:21:01.927804+00:00'),
  ('google-maps', 'Google Maps', 'MCP Google Map provides a bridge to the Google Maps API, enabling location-based operations like place searching and geocoding. Developed by CabLate, this TypeScript implementation uses the @googlemaps/google-maps-services-js library to interact with Google''s services. The server exposes tools for querying location data, finding nearby places, and retrieving geographical information - making it particularly valuable for applications that need to incorporate location intelligence without leaving the conversation interface.', '@cablate', 'development', 'Unknown', 187, 'https://github.com/cablate/mcp-google-map', '@cablate/mcp-google-map', 13762, 'https://github.com/cablate.png?size=128', '2026-03-09T05:21:01.927903+00:00'),
  ('nushell', 'Nushell', 'A Rust-based MCP server that provides secure execution of Nushell scripts through a single ''exec'' tool. Built using the rust-mcp-sdk, it spawns Nushell processes to execute provided scripts and returns structured output containing stdout, stderr, and exit codes in JSON format. The implementation is marked as destructive and non-idempotent, making it suitable for automation workflows, data processing pipelines, and system administration tasks where Nushell''s powerful data manipulation capabilities are needed within AI assistant interactions.', '@cablehead', 'development', 'Unknown', 8, 'https://github.com/cablehead/mcp-server-nu', NULL, 0, 'https://github.com/cablehead.png?size=128', '2026-03-09T05:21:01.927928+00:00'),
  ('tuya-smart-home', 'Tuya Smart Home', 'This MCP server, developed by @cabra.lat, provides integration with Tuya smart home devices. Built with Python and leveraging the tinytuya library, it offers tools for controlling and monitoring Tuya-compatible devices. The implementation focuses on enabling AI assistants to interact with smart home ecosystems, including features like device discovery, state management, and command execution. It requires Python 3.13+ and uses libraries like numpy and scipy for data processing. The server is particularly useful for home automation scenarios, enabling use cases such as voice-controlled smart devices, energy usage optimization, and automated routines without direct user interaction with individual device apps or hubs.', '@cabra-lat', 'ai-ml', 'Unknown', 3, 'https://github.com/cabra-lat/tuyactl', 'tuya-mcp-server', 5252, 'https://github.com/cabra-lat.png?size=128', '2026-03-09T05:21:01.927973+00:00'),
  ('server-notify', 'Server Notify', 'MCP Server Notify provides a system notification service that integrates with desktop environments to display alerts and play sounds when triggered by API requests. The implementation uses Pydantic for request validation, supports cross-platform notifications through the Plyer library, and includes sound playback capabilities (with platform-specific implementations). Built with a simple HTTP server architecture, it enables applications to send customizable notifications with configurable timeouts, making it particularly useful for alerting users about completed tasks, important events, or status changes without requiring constant monitoring of the application interface.', '@cactusinhand', 'productivity', 'Unknown', 50, 'https://github.com/cactusinhand/mcp_server_notify', NULL, 0, 'https://github.com/cactusinhand.png?size=128', '2026-03-09T05:21:01.928019+00:00'),
  ('caffeinated-wardrobe', 'Caffeinated Wardrobe', 'An AI-powered wardrobe management service that eliminates morning decision fatigue by providing instant outfit suggestions tailored to your daily schedule. The platform features easy wardrobe import from store purchase histories, MCP-first architecture for seamless integration with preferred AI tools, and a "Bring Your Own AI" plan that gives users complete control over their wardrobe-supporting AI assistant. Designed for busy professionals who want to save 15+ minutes daily while maintaining a curated, weather-appropriate wardrobe without tedious closet photoshoots or manual cataloging.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://caffeinatedwardrobe.com', NULL, 0, NULL, '2026-03-09T05:21:01.928113+00:00'),
  ('email-service', 'Email Service', 'Provides email sending capabilities through SMTP and AWS SES integration with unified interface for notifications, reports, and automated communications.', '@caijianying', 'cloud', 'Unknown', 1, 'https://github.com/caijianying/email-mcp', NULL, 0, 'https://github.com/caijianying.png?size=128', '2026-03-09T05:21:01.928135+00:00'),
  ('cail-ai-calls-voicemail', 'CAIL - AI Calls & Voicemail', 'Our MCP Server is designed to schedule outbound phone calls, read transcription of incoming calls. If you need to make a call, you can just use our MCP to plan your outbound calls.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('alphavantage', 'Alphavantage', 'This MCP server, developed by calvernaz, provides integration with the Alphavantage stock market data API. It exposes tools for querying financial data like stock prices, company fundamentals, and economic indicators. By leveraging Alphavantage''s comprehensive financial datasets, this implementation enables AI assistants to easily incorporate up-to-date market information into their analyses and recommendations. It is particularly useful for scenarios requiring real-time financial data, such as portfolio tracking, investment research, or generating market reports through natural language queries to an AI assistant. The server is designed for seamless integration with the Claude desktop app and focuses on core stock market data retrieval functionality.', '@calvernaz', 'ai-ml', 'Unknown', 73, 'https://github.com/calvernaz/alphavantage', NULL, 0, 'https://github.com/calvernaz.png?size=128', '2026-03-09T05:21:01.928492+00:00'),
  ('memory', 'Memory', 'Provides persistent semantic memory and knowledge graph capabilities through PostgreSQL with pgvector for vector similarity search using Aliyun''s text-embedding-v3 model. Features traditional memory storage with confidence scoring and decay algorithms, plus a bidirectional knowledge graph for entity relationships. Includes LRU caching for embeddings, hybrid search combining vector and keyword matching, memory access tracking, and comprehensive audit logging for persistent conversational context and complex knowledge representation.', '@calvin-francis', 'databases', 'Unknown', 1, 'https://github.com/calvin-francis/memory-mcp', NULL, 0, 'https://github.com/calvin-francis.png?size=128', '2026-03-09T05:21:01.928504+00:00'),
  ('json-canvas', 'JSON Canvas', 'This MCP server implementation provides tools for working with JSON Canvas files according to the official specification. It enables creating, modifying, and validating infinite canvas data structures, supporting all node types and edge connections. The server offers a RESTful API for canvas operations, includes example resources, and can export canvases to different formats. It''s designed for applications requiring AI assistants to interact with and manipulate canvas-based data visualizations.', '@cam10001110101', 'ai-ml', 'Unknown', 12, 'https://github.com/cam10001110101/mcp-server-obsidian-jsoncanvas', NULL, 0, 'https://github.com/cam10001110101.png?size=128', '2026-03-09T05:21:01.928544+00:00'),
  ('outlook-email-processor', 'Outlook Email Processor', 'This MCP server provides email processing capabilities for Outlook, integrating with MongoDB for semantic search and SQLite for efficient storage. It features multi-mailbox support, date range filtering, and vector embedding generation using Ollama. Designed for Windows environments, it offers tools for processing emails, storing metadata, and preparing data for advanced search and analysis tasks. The server is particularly useful for applications requiring automated email processing, semantic search capabilities, and integration with local Outlook installations.', '@cam10001110101', 'databases', 'Unknown', 13, 'https://github.com/cam10001110101/mcp-server-outlook-email', NULL, 0, 'https://github.com/cam10001110101.png?size=128', '2026-03-09T05:21:01.928557+00:00'),
  ('xcodebuild', 'XcodeBuild', 'XcodeBuildMCP is a Model Context Protocol server that provides tools for building, running, and debugging iOS and macOS applications through Xcode. Developed by Cameron Cooke, it offers a comprehensive suite of tools for project discovery, simulator management, app deployment, and UI automation testing. The implementation supports both workspace and project-based builds, includes incremental build optimization through xcodemake integration, and features Sentry error reporting for reliability. It''s particularly valuable for AI assistants helping with iOS/macOS development workflows, allowing them to build, test, and debug applications without requiring users to manually execute complex xcodebuild commands.', '@getsentry', 'development', 'Unknown', 4603, 'https://github.com/getsentry/xcodebuildmcp', 'xcodebuildmcp', 184146, 'https://github.com/getsentry.png?size=128', '2026-03-09T05:21:01.928649+00:00'),
  ('openzim', 'OpenZIM', 'This OpenZIM MCP server by Cameron Rye enables AI models to access and search ZIM format knowledge bases offline, providing tools for listing ZIM files, searching content with configurable limits and offsets, and retrieving specific entries with smart fallback mechanisms. Built with Python and featuring a modular architecture with comprehensive security validation, intelligent caching with LRU eviction and TTL support, and HTML content processing with BeautifulSoup, it offers robust path validation to prevent directory traversal attacks, instance tracking to prevent configuration conflicts, and automatic path mapping for reliable entry retrieval. The implementation includes extensive testing coverage, performance benchmarks, and development tooling with pre-commit hooks, making it ideal for researchers and developers who need AI-assisted access to offline Wikipedia dumps, educational content archives, and other ZIM-formatted knowledge repositories without requiring internet connectivity.', '@cameronrye', 'development', 'Unknown', 44, 'https://github.com/cameronrye/openzim-mcp', NULL, 0, 'https://github.com/cameronrye.png?size=128', '2026-03-09T05:21:01.928682+00:00'),
  ('campaignkit', 'CampaignKit', 'CampaignKit''s official email validation server provides real-time and batch email verification through five specialized tools covering single email validation, asynchronous batch processing for large lists, job status monitoring, paginated results retrieval, and account statistics tracking. The implementation uses Server-Sent Events over HTTPS for transport with JSON-RPC 2.0 messaging, enabling validation checks for email format, deliverability, disposable/temporary domains, catch-all addresses, and domain verification. Built for marketers and developers who need to reduce bounce rates and protect sender reputation, it operates on a credits-based model where users only pay for successfully validated emails.', '@unknown', 'communication', 'Unknown', 0, 'https://campaignkit.cc/docs/mcp-server', NULL, 0, NULL, '2026-03-09T05:21:01.928715+00:00'),
  ('campfire', 'Campfire', 'Provides access to Campfire''s AI-first ERP platform for finance and accounting teams. Supports core accounting operations including chart of accounts, transactions, journal entries, and entity management, as well as financial reporting such as income statements, balance sheets, and cash flow statements.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://docs.campfire.ai/guides/ai-integration', NULL, 0, NULL, '2026-03-09T05:21:01.928744+00:00'),
  ('jarvis', 'Jarvis', 'Jarvis is a Go-based MCP server that provides comprehensive system administration capabilities through secure filesystem operations, terminal command execution, web content fetching, and advanced text editing tools. Built with configurable security controls including directory access restrictions, command blocking patterns, and file operation limits, it offers specialized features like multi-file atomic editing, batch URL processing, image format conversion, and syntax validation across multiple programming languages. The implementation is particularly valuable for AI assistants that need to perform complex development workflows, system maintenance tasks, and content management operations while maintaining strict security boundaries through its robust configuration system and backup mechanisms.', '@can-acar', 'development', 'Unknown', 2, 'https://github.com/can-acar/jarvis', NULL, 0, 'https://github.com/can-acar.png?size=128', '2026-03-09T05:21:01.928785+00:00'),
  ('browse-together-playwright', 'Browse Together (Playwright)', 'A Playwright browser and MCP Server on your desktop. You can spin up a headful browser (for human interaction) and an accompanying MCP server that can be used to control the browser via HTTP API or MCP server.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('cc-meta-prompt-evaluator', 'CC-Meta (Prompt Evaluator)', 'CC-Meta (Claude Code Metaprompter) provides AI-powered prompt evaluation capabilities through an MCP server that analyzes prompts for clarity, specificity, and effectiveness using OpenAI or Anthropic models. Built with TypeScript and the Vercel AI SDK, it offers two core tools: a ping function for connection testing and an evaluate function that provides detailed feedback including numerical scores, strengths analysis, improvement suggestions, and rewrite recommendations. The implementation supports multiple AI models (OpenAI''s o3, Anthropic''s Claude Opus-4 and Sonnet-4) with flexible API key configuration, includes a convenient slash command interface (/meta), and features customizable evaluation criteria stored in a separate prompt template file, making it ideal for developers who want to iterate on their Claude Code prompts without leaving their terminal workflow.', '@areznik23', 'cloud', 'Unknown', 5, 'https://github.com/areznik23/cc-meta', NULL, 0, 'https://github.com/areznik23.png?size=128', '2026-03-09T05:21:01.930199+00:00'),
  ('kali-security-tools', 'Kali Security Tools', 'Awesome Kali MCP Servers provides a secure interface for AI assistants to execute Kali Linux security tools through a sandboxed environment. The implementation wraps common security utilities including nmap for network scanning, objdump and nm for binary analysis, strings for file examination, and wireshark/tshark for packet analysis. Built with Python using Docker containers for isolation, it enforces configurable resource limits and network access controls to prevent abuse while maintaining tool functionality. This server enables AI systems to perform security analysis tasks like vulnerability scanning, binary reverse engineering, and network traffic inspection without direct system access, making it valuable for security professionals who want to leverage AI assistants for technical security operations.', '@ccq1', 'cloud', 'Unknown', 92, 'https://github.com/ccq1/awsome_kali_mcpservers', NULL, 0, 'https://github.com/ccq1.png?size=128', '2026-03-09T05:21:01.930250+00:00'),
  ('acumatica-cdata', 'Acumatica (CData)', 'Java-based MCP server implementation by CData Software that provides AI assistants with database connectivity through JDBC drivers, enabling SQL query execution and metadata exploration across various data sources including Acumatica and other enterprise systems. The implementation features three core tools for listing tables, retrieving column information, and executing SELECT queries, with results returned in CSV format for easy consumption by AI models. Built with dynamic driver loading, configurable connection parameters, and support for multiple catalogs/schemas, it serves as a bridge between conversational AI and structured data sources, making it valuable for business intelligence workflows, data exploration tasks, and automated reporting scenarios where AI assistants need programmatic access to enterprise databases without requiring direct database knowledge.', '@cdatasoftware', 'databases', 'Unknown', 2, 'https://github.com/cdatasoftware/acumatica-mcp-server-by-cdata', NULL, 0, 'https://github.com/cdatasoftware.png?size=128', '2026-03-09T05:21:01.930262+00:00'),
  ('cdata-connect-ai', 'CData Connect AI', 'CData Connect AI provides a fully managed MCP platform that connects to enterprise data sources including Salesforce, Snowflake, NetSuite, and hundreds of other systems. The server enables real-time read and write access through semantic data models that preserve metadata and relationships across sources. Features include granular permissions, audit trails, and point-and-click configuration for multi-source data analysis workflows.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://www.cdata.com/ai/', NULL, 0, NULL, '2026-03-09T05:21:01.930300+00:00'),
  ('ebay-cdata-jdbc', 'eBay (CData JDBC)', 'This MCP server implementation by CData Software provides AI assistants with access to eBay data through a generic JDBC-based architecture that can connect to any JDBC-compliant data source. Built in Java using the Model Context Protocol SDK, the implementation offers three core tools: get_tables for discovering available data objects, get_columns for retrieving field metadata, and run_query for executing SQL SELECT statements with results returned in CSV format. The server uses a configuration-driven approach that loads JDBC drivers dynamically, automatically discovers database capabilities like identifier quoting and catalog/schema support, and provides table metadata as MCP resources for enhanced discoverability. Designed for data analysts and developers who need conversational access to structured eBay data through SQL queries, with support for complex joins, filtering, and aggregation operations while maintaining compatibility with various database backends through the JDBC standard.', '@cdatasoftware', 'databases', 'Unknown', 7, 'https://github.com/cdatasoftware/ebay-mcp-server-by-cdata', NULL, 0, 'https://github.com/cdatasoftware.png?size=128', '2026-03-09T05:21:01.930311+00:00'),
  ('jdbc-database', 'JDBC Database', 'Provides database connectivity through JDBC drivers, enabling AI assistants to query and explore relational databases with three core tools: table discovery, column metadata retrieval, and SQL query execution. Built by CData Software using Java and the Model Context Protocol SDK, the implementation supports any JDBC-compliant database by loading external driver JARs and automatically discovers database capabilities like identifier quoting rules and catalog/schema support. Features CSV-formatted output for all operations, dynamic table metadata resources for each configured table, and intelligent SQL dialect detection with proper identifier quoting, making it valuable for data analysis workflows requiring database access, business intelligence applications that need to query enterprise databases, and AI agents that must interact with existing relational data sources across different database platforms.', '@cdatasoftware', 'databases', 'Unknown', 1, 'https://github.com/cdatasoftware/bing-ads-mcp-server-by-cdata', NULL, 0, 'https://github.com/cdatasoftware.png?size=128', '2026-03-09T05:21:01.930323+00:00'),
  ('jdbc-database-bridge', 'JDBC Database Bridge', 'A Java-based MCP server implementation by CData Software that provides a generic bridge to any JDBC-compatible data source, including LinkedIn Ads data through CData''s JDBC drivers. The server exposes three core tools for database interaction: listing available tables and schemas, retrieving column metadata for specific tables, and executing SQL SELECT queries with results returned in CSV format. Built with a modular architecture using interfaces for tools and resources, it supports dynamic driver loading, automatic discovery of database capabilities like catalog/schema support, and configurable table filtering, making it valuable for data analysts and developers who need to query business data sources through natural language interactions with AI assistants.', '@cdatasoftware', 'databases', 'Unknown', 1, 'https://github.com/cdatasoftware/linkedin-ads-mcp-server-by-cdata', NULL, 0, 'https://github.com/cdatasoftware.png?size=128', '2026-03-09T05:21:01.930334+00:00'),
  ('jdbc-database-connector', 'JDBC Database Connector', 'Generic JDBC MCP server implementation by CData Software that provides AI assistants with database connectivity through any JDBC-compliant driver, enabling SQL query execution and metadata exploration across diverse data sources. The implementation uses a configuration-driven approach where users specify their JDBC driver JAR, connection URL, and target tables, then exposes three core tools: get_tables for listing available database objects, get_columns for retrieving table schema information, and run_query for executing SELECT statements with results returned in CSV format. Built with Java 17 and designed for flexibility, it automatically discovers database capabilities like identifier quoting and catalog/schema support, making it valuable for data analysts needing conversational access to enterprise databases, developers building data integration workflows, or teams requiring AI-assisted database exploration across different database systems without writing custom integrations for each data source.', '@cdatasoftware', 'databases', 'Unknown', 2, 'https://github.com/cdatasoftware/basecamp-mcp-server-by-cdata', NULL, 0, 'https://github.com/cdatasoftware.png?size=128', '2026-03-09T05:21:01.930346+00:00'),
  ('jira-service-management-cdata', 'Jira Service Management (CData)', 'A Java-based MCP server implementation by CData Software that provides database connectivity through JDBC drivers, enabling AI assistants to query and explore data from various database systems including Jira Service Management and other data sources. The server exposes three core tools for database interaction: listing available tables, retrieving column metadata, and executing SQL SELECT queries with results returned in CSV format. Built with a modular architecture using interfaces for tools and resources, it supports dynamic JDBC driver loading, handles multiple catalog/schema configurations, and includes comprehensive table name parsing with quoted identifier support, making it valuable for data analysis workflows where AI assistants need to discover database schema and query structured data through natural language interactions.', '@cdatasoftware', 'databases', 'Unknown', 1, 'https://github.com/cdatasoftware/jira-service-management-mcp-server-by-cdata', NULL, 0, 'https://github.com/cdatasoftware.png?size=128', '2026-03-09T05:21:01.930359+00:00'),
  ('myob-accountright', 'MYOB AccountRight', 'MYOB AccountRight MCP server by CData Software that provides AI assistants with database-style access to MYOB accounting data through a generic JDBC-based architecture. The implementation uses Java with configurable JDBC drivers to expose MYOB tables and columns as queryable resources, offering three core tools: get_tables for listing available accounting entities, get_columns for retrieving field metadata, and run_query for executing SQL SELECT statements against MYOB data with results returned in CSV format. Built with a flexible configuration system that supports multiple database catalogs and schemas, the server includes table metadata resources for schema discovery and uses CData''s JDBC connectivity approach to transform MYOB''s accounting API into a SQL-queryable interface, making it valuable for financial reporting automation, accounting data analysis, and integration workflows where SQL-based access to MYOB AccountRight data is preferred over direct API calls.', '@cdatasoftware', 'databases', 'Unknown', 3, 'https://github.com/cdatasoftware/myob-accountright-mcp-server-by-cdata', NULL, 0, 'https://github.com/cdatasoftware.png?size=128', '2026-03-09T05:21:01.930371+00:00'),
  ('salesforce-data-cloud', 'Salesforce Data Cloud', 'MCP server implementation by CData Software that provides AI assistants with access to Salesforce Data Cloud through a generic JDBC-based architecture. Built in Java using the Model Context Protocol SDK, the implementation offers three core tools: get_tables for discovering available data objects and collections, get_columns for retrieving field metadata and data types, and run_query for executing SQL SELECT statements with results returned in CSV format. The server uses CData''s JDBC driver architecture to connect to Salesforce Data Cloud, supporting dynamic discovery of database metadata including catalogs, schemas, and table structures, with configurable identifier quoting and SQL dialect handling. Designed for data analysts and developers who need programmatic access to Salesforce Data Cloud for querying customer data, building reports, or integrating Salesforce analytics into AI-powered workflows where structured data access through familiar SQL interfaces is preferred over native Salesforce APIs.', '@cdatasoftware', 'databases', 'Unknown', 1, 'https://github.com/cdatasoftware/salesforce-data-cloud-mcp-server-by-cdata', NULL, 0, 'https://github.com/cdatasoftware.png?size=128', '2026-03-09T05:21:01.930383+00:00'),
  ('sap-businessobjects-bi', 'SAP BusinessObjects BI', 'CData''s Java-based MCP server implementation that provides database connectivity to SAP BusinessObjects BI through JDBC drivers, enabling AI assistants to query business intelligence data sources using natural language. The server exposes three core tools for discovering tables, retrieving column metadata, and executing SQL SELECT statements, with results returned in CSV format for easy consumption by LLMs. Built with a modular architecture supporting configurable JDBC drivers, identifier quoting, and catalog/schema awareness, it''s designed for enterprise users who need to integrate their SAP BI data warehouses with AI assistants for data exploration, report generation, and business intelligence workflows without requiring direct database access knowledge.', '@cdatasoftware', 'databases', 'Unknown', 1, 'https://github.com/cdatasoftware/sap-businessobjects-bi-mcp-server-by-cdata', NULL, 0, 'https://github.com/cdatasoftware.png?size=128', '2026-03-09T05:21:01.930395+00:00'),
  ('sap-hana', 'SAP HANA', 'This SAP HANA XS Advanced MCP server by CData Software provides a Java-based bridge to SAP HANA databases through JDBC connectivity, enabling AI assistants to query tables, retrieve metadata, and execute SQL statements. The implementation features three core tools for listing tables, getting column information, and running SELECT queries, plus resources for accessing table metadata, all with CSV-formatted output optimized for AI consumption. Built with dynamic driver loading and configurable connection parameters, it supports multi-catalog and multi-schema environments while handling identifier quoting and SQL dialect specifics, making it valuable for enterprise data analysis, business intelligence workflows, and automated reporting tasks against SAP HANA systems.', '@cdatasoftware', 'databases', 'Unknown', 1, 'https://github.com/cdatasoftware/sap-hana-xs-advanced-mcp-server-by-cdata', NULL, 0, 'https://github.com/cdatasoftware.png?size=128', '2026-03-09T05:21:01.930406+00:00'),
  ('sap-netweaver-gateway', 'SAP NetWeaver Gateway', 'This SAP NetWeaver Gateway MCP server by CData Software provides a bridge to SAP systems through JDBC connectivity, enabling AI assistants to query SAP data using natural language commands. The implementation offers three core tools for discovering tables, retrieving column metadata, and executing SQL SELECT statements, with results returned in CSV format for easy consumption. Built on CData''s JDBC driver architecture, it supports dynamic configuration through properties files and handles SAP-specific SQL dialects with proper identifier quoting, making it valuable for business intelligence tasks, data analysis, and integration workflows that need to access SAP business data without complex API knowledge.', '@cdatasoftware', 'databases', 'Unknown', 2, 'https://github.com/cdatasoftware/sap-netweaver-gateway-mcp-server-by-cdata', NULL, 0, 'https://github.com/cdatasoftware.png?size=128', '2026-03-09T05:21:01.930418+00:00'),
  ('tokenscope', 'TokenScope', 'TokenScope is a token-aware directory explorer for Large Language Models that enables intelligent codebase analysis while respecting token limitations. Built by Carlos Gaete-Morales, this Python-based MCP server provides tools for scanning directory structures, extracting file contents, analyzing token usage statistics, and generating comprehensive reports. It features security validation to restrict operations to specified base directories, intelligent file prioritization based on importance, and automatic handling of common file formats like JSON. The implementation respects .gitignore files and includes default ignore patterns for common non-source directories, making it valuable for developers who need to help LLMs understand codebases efficiently without exceeding token limits.', '@cdgaete', 'development', 'Unknown', 4, 'https://github.com/cdgaete/token-scope-mcp', 'tokenscope', 2271, 'https://github.com/cdgaete.png?size=128', '2026-03-09T05:21:01.930456+00:00'),
  ('authentik', 'Authentik', 'This MCP server provides AI assistants with access to Authentik''s identity and access management platform through both full-featured and diagnostic-only variants, built by Authentik Security Inc. using Python and Node.js implementations. The server offers comprehensive user, group, and application management capabilities alongside event monitoring, authentication flow configuration, and system administration tools, with the diagnostic variant providing read-only monitoring for production environments. Built with the Model Context Protocol SDK and featuring extensive API coverage including CRUD operations for users/groups, application lifecycle management, audit log analysis, and provider configuration, it serves organizations needing AI-driven identity management automation, security teams requiring programmatic access to authentication analytics, and developers building identity-aware applications that integrate with Authentik''s enterprise authentication platform.', '@cdmx-in', 'development', 'Unknown', 7, 'https://github.com/cdmx-in/authentik-mcp', '@cdmx/authentik-mcp', 1504, 'https://github.com/cdmx-in.png?size=128', '2026-03-09T05:21:01.930491+00:00'),
  ('goodday', 'Goodday', 'This MCP server provides AI assistants with access to Goodday''s project management platform through comprehensive task, project, sprint, and user management capabilities, built by Roney using Python with FastMCP and httpx. The implementation offers both direct API integration and an OpenWebUI tool variant with smart query processing, user-friendly name mapping, and semantic search through vector database integration using n8n workflows with Ollama embeddings and Qdrant storage. It serves teams needing AI-driven project management automation, developers building task management integrations, and organizations requiring programmatic access to sprint analytics, user task assignments, and project status monitoring without manual Goodday console navigation.', '@cdmx-in', 'databases', 'Unknown', 1, 'https://github.com/cdmx-in/goodday-mcp', 'goodday-mcp', 3243, 'https://github.com/cdmx-in.png?size=128', '2026-03-09T05:21:01.930501+00:00'),
  ('sugar', 'Sugar', 'Sugar is an autonomous layer for AI coding agents that manages task queues and enables continuous 24/7 development execution. It provides task orchestration with priorities, specialized agent routing for different domains (frontend, backend, QA, security, DevOps), GitHub issue and PR integration, and iterative self-correcting execution loops. The MCP server component allows integration with Claude Desktop and other MCP-compatible clients.', '@roboticforce', 'development', 'Unknown', 54, 'https://github.com/roboticforce/sugar', NULL, 0, 'https://github.com/roboticforce.png?size=128', '2026-03-09T05:21:01.930522+00:00'),
  ('chatgpt-macos-app', 'ChatGPT macOS App', 'MCP Server for ChatGPT enables AI assistants to interact with the ChatGPT macOS app through AppleScript automation. Developed by cdpath, this Python implementation provides a simple interface for sending prompts to ChatGPT via keyboard input simulation, making it compatible with tools like cursor and chatwise. The server handles permission errors gracefully with helpful troubleshooting messages and is particularly useful for users who want to leverage their existing ChatGPT app within an MCP workflow without switching interfaces.', '@cdpath', 'communication', 'Unknown', 17, 'https://github.com/cdpath/mcp-server-chatgpt-app', 'mcp-server-chatgpt-app', 5520, 'https://github.com/cdpath.png?size=128', '2026-03-09T05:21:01.930555+00:00'),
  ('docs-fetcher', 'Docs Fetcher', 'The docs-fetcher-mcp server enables AI assistants to retrieve package documentation from various programming language ecosystems without requiring API keys. Built by cdugo, it leverages the Model Context Protocol to fetch library documentation on demand, supporting caching for improved performance. The implementation is containerized with Docker and configurable through Smithery.ai, making it easy to deploy in different environments. This tool is particularly valuable for developers and AI workflows that need access to up-to-date library documentation directly within conversations, eliminating the need to switch contexts or manually search for reference materials.', '@unknown', 'cloud', 'Unknown', 0, 'https://www.pulsemcp.com/servers/cdugo-docs-fetcher', NULL, 0, NULL, '2026-03-09T05:21:01.930576+00:00'),
  ('package-documentation-fetcher', 'Package Documentation Fetcher', 'This MCP server implementation provides a bridge to fetch package documentation from multiple language ecosystems without requiring API keys. Developed by cdugo, it integrates with various package registries and documentation sources, offering a standardized interface for AI assistants to access library documentation. The server includes caching capabilities, Docker support, and is designed for use cases requiring up-to-date package information, such as code assistance, dependency analysis, or learning about new libraries.', '@cdugo', 'cloud', 'Unknown', 15, 'https://github.com/cdugo/package-documentation-mcp', '@cdugo/docs-fetcher-mcp', 3697, 'https://github.com/cdugo.png?size=128', '2026-03-09T05:21:01.930597+00:00'),
  ('korean-open-data-portal', 'Korean Open Data Portal', 'An MCP server built by Team Aeris that provides access to Korean Open Data Portal APIs through a three-step workflow: search for APIs by keywords, retrieve detailed documentation with endpoint specifications, and execute API calls with automatic service key injection. The implementation features comprehensive logging with Korean locale formatting, timeout handling, and intelligent parameter management that automatically detects and fills service key requirements in both query parameters and authorization headers. It integrates with the OpenDataAPI service at mcp.ezrnd.co.kr and supports GET requests with JSON response parsing, making it useful for accessing Korean government datasets, building data analysis applications, and integrating public sector information into AI-assisted workflows.', '@ceami', 'development', 'Unknown', 9, 'https://github.com/ceami/opendata-mcp', NULL, 0, 'https://github.com/ceami.png?size=128', '2026-03-09T05:21:01.930630+00:00'),
  ('word-document-operations', 'Word Document Operations', 'Comprehensive CRUD operations and document manipulation for Microsoft Word files with table management, formatting controls, and merge capabilities.', '@ceilf6', 'file-systems', 'Unknown', 8, 'https://github.com/ceilf6/word-mcp-agent', NULL, 0, 'https://github.com/ceilf6.png?size=128', '2026-03-09T05:21:01.930656+00:00'),
  ('minecraft-developer', 'Minecraft Developer', 'Enables remote control and administration of Spigot/Paper Minecraft servers through HTTP and SSE APIs. Provides capabilities for executing console commands with output capture, reading and writing server files and configurations, managing plugins, monitoring logs, and handling binary file transfers via base64 encoding. Includes token-based authentication and path traversal protection for secure remote server management and automated deployment workflows.', '@center2055', 'file-systems', 'Unknown', 2, 'https://github.com/center2055/minecraftdevelopermcp', NULL, 0, 'https://github.com/center2055.png?size=128', '2026-03-09T05:21:01.930735+00:00'),
  ('centralmind-database-gateway', 'Centralmind (Database Gateway)', 'Gateway is a database connectivity server that enables AI assistants to interact with multiple database systems through a unified interface. It supports various database engines including PostgreSQL, MySQL, SQLite, MongoDB, Snowflake, and others, while providing advanced features like API key authentication, OAuth integration, PII data protection, and OpenTelemetry monitoring. The server can operate in multiple modes (REST API, MCP SSE, or MCP stdio) and includes plugins for caching, row-level security, and data anonymization, making it particularly useful for creating secure data access layers for AI applications without exposing raw database credentials.', '@centralmind', 'databases', 'Unknown', 517, 'https://github.com/centralmind/gateway', NULL, 0, 'https://github.com/centralmind.png?size=128', '2026-03-09T05:21:01.930746+00:00'),
  ('reactbits', 'ReactBits', 'The ReactBits MCP Server provides access to 135+ animated React components from ReactBits.dev, offering a curated collection of high-quality UI elements including animations, backgrounds, text effects, and interactive components. Built with TypeScript and featuring intelligent caching, GitHub API integration for real-time component fetching, and quality scoring system that warns users about incomplete implementations (particularly buttons, forms, and loaders with 2.0/10 quality scores), while highlighting production-ready categories like backgrounds (9.8/10) and animations (9.5/10). The server supports both CSS and Tailwind versions of components, includes dependency detection for libraries like Framer Motion and GSAP, and provides comprehensive search, filtering, and demo generation capabilities, making it valuable for developers building modern React applications who need quick access to animated UI components without manually browsing the ReactBits website.', '@ceorkm', 'development', 'Unknown', 38, 'https://github.com/ceorkm/reactbits-mcp-server', 'reactbits-dev-mcp-server', 7217, 'https://github.com/ceorkm.png?size=128', '2026-03-09T05:21:01.930776+00:00'),
  ('cerebras-code', 'Cerebras Code', 'Integrates Cerebras AI capabilities into development tools for rapid code generation. Uses the Qwen 3 Coder model to provide fast inference for Claude Code, Cline, and Cursor. Includes intelligent rate limit handling and optional OpenRouter fallback.', '@cerebras', 'development', 'Unknown', 39, 'https://github.com/cerebras/cerebras-code-mcp', NULL, 0, 'https://github.com/cerebras.png?size=128', '2026-03-09T05:21:01.930794+00:00'),
  ('bitcoin-signer', 'Bitcoin Signer', 'A Bitcoin transaction signing server that enables AI assistants to generate Bitcoin addresses and sign transactions through the MCP protocol. Built by Cerebro Foundation, this implementation provides two key tools: one for generating P2WPKH addresses from private keys in WIF format, and another for signing partially signed Bitcoin transactions (PSBTs). The server uses the @scure/btc-signer library along with secp256k1 cryptography to securely handle Bitcoin operations, making it useful for cryptocurrency wallet integrations and transaction signing workflows, though the authors note it''s intended as a play project rather than for production use.', '@cerebrofoundation', 'productivity', 'Unknown', 0, 'https://github.com/cerebrofoundation/mcp-intent', '@cerebrofoundation/mcp-intent', 3955, 'https://github.com/cerebrofoundation.png?size=128', '2026-03-09T05:21:01.930838+00:00'),
  ('certman', 'Certman', 'Create and manage your own Certificate Authority for internal HTTPS. Provides tools for creating root and intermediate CAs, issuing unlimited TLS certificates, managing certificate lifecycle including revocation and renewal, and retrieving CA chains. Supports OAuth and API key authentication.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://certman.app', NULL, 0, NULL, '2026-03-09T05:21:01.930876+00:00'),
  ('git-pr-description-generator', 'Git PR Description Generator', 'Git Prompts MCP Server provides a specialized interface for generating pull request descriptions based on Git repository changes. Developed by Ceshine Lee, this server analyzes the differences between Git commits and formats them as either plain text or JSON to create contextually relevant PR descriptions. The implementation uses GitPython to access repository data and exposes its functionality through a single command that compares the current HEAD with a specified ancestor branch or commit. This server is particularly useful for developers who want to automate the creation of detailed pull request descriptions without manually analyzing code changes.', '@ceshine', 'development', 'Unknown', 2, 'https://github.com/ceshine/git-prompts-mcp-server', NULL, 0, 'https://github.com/ceshine.png?size=128', '2026-03-09T05:21:01.930902+00:00'),
  ('bmad-business-minded-agile-development', 'BMAD (Business-Minded Agile Development)', 'BMAD serves as a complete agile workflow orchestrator built by evanxian9@gmail.com using TypeScript. The implementation provides structured tools for managing agile development processes, integrating business requirements with development workflows to streamline project management and delivery. It''s designed for teams that need to bridge the gap between business stakeholders and technical implementation, offering orchestrated workflows that align development activities with business objectives and agile methodologies.', '@cexll', 'development', 'Unknown', 19, 'https://github.com/cexll/bmad-mcp-server', 'bmad-mcp', 249, 'https://github.com/cexll.png?size=128', '2026-03-09T05:21:01.930937+00:00'),
  ('codex-cli', 'Codex CLI', 'A TypeScript MCP server that bridges Claude and other AI clients with the Codex CLI, OpenAI''s AI-powered code assistant. Built by Taras Trishchuk, it provides tools for executing Codex commands, brainstorming sessions, and handling large responses through chunked delivery, with support for change mode operations that parse and format code edits into structured chunks for easier application. The implementation includes timeout prevention, caching for multi-chunk responses, working directory resolution, and integration with Codex''s sandbox modes and model selection, making it useful for AI-assisted development workflows, code analysis, and automated refactoring tasks within MCP-compatible environments.', '@cexll', 'development', 'Unknown', 150, 'https://github.com/cexll/codex-mcp-server', '@cexll/codex-mcp-server', 2473, 'https://github.com/cexll.png?size=128', '2026-03-09T05:21:01.930964+00:00'),
  ('mac-shell', 'Mac Shell', 'Mac Shell MCP Server enables secure execution of macOS terminal commands through ZSH shell with a built-in security system that categorizes commands as safe, requiring approval, or forbidden. It features a pre-configured whitelist of common commands, an approval workflow for potentially dangerous operations, and comprehensive command management tools. Written in TypeScript and designed to work with Roo Code and Claude Desktop, it can be installed locally or run via npx, making it ideal for AI assistants that need controlled access to the macOS terminal while maintaining security through command whitelisting and explicit approval mechanisms.', '@cfdude', 'development', 'Unknown', 19, 'https://github.com/cfdude/mac-shell-mcp', NULL, 0, 'https://github.com/cfdude.png?size=128', '2026-03-09T05:21:01.930990+00:00'),
  ('aws-cost-optimization-hub', 'AWS Cost Optimization Hub', 'AWS cost optimization MCP server built by CFM Tips that provides runbook-based analysis across EC2, EBS, RDS, and Lambda services using multiple data sources with intelligent fallback logic. The implementation integrates with AWS Cost Explorer, Cost Optimization Hub, Compute Optimizer, Trusted Advisor, Performance Insights, and CloudWatch metrics to identify underutilized resources, unused volumes, idle databases, and over-provisioned Lambda functions. Features include right-sizing recommendations with pricing calculations, markdown and JSON report generation, and multi-service cost analysis workflows that prioritize premium AWS services like Performance Insights and Compute Optimizer before falling back to CloudWatch direct metrics when enterprise features are unavailable.', '@aws-samples', 'databases', 'Unknown', 25, 'https://github.com/aws-samples/sample-cfm-tips-mcp', NULL, 0, 'https://github.com/aws-samples.png?size=128', '2026-03-09T05:21:01.931003+00:00'),
  ('pentest-tools', 'Pentest Tools', 'Pentest-Tools-MCP-Server is a security-focused server implementation that enables AI assistants to perform penetration testing and security assessments on web applications and networks. Built on Kali Linux with Python, it provides tools for reconnaissance, vulnerability scanning, and exploitation including subdomain enumeration, directory scanning, API testing, and vulnerability detection for XSS, SQL injection, and SSRF. The server leverages popular security tools like Nmap, SQLMap, and XSStrike while implementing custom scanning logic, making it valuable for security professionals who need to conduct thorough security assessments, identify vulnerabilities, and generate comprehensive security reports without leaving their AI assistant interface.', '@ch1nhpd', 'databases', 'Unknown', 6, 'https://github.com/ch1nhpd/pentest-tools-mcp-server', NULL, 0, 'https://github.com/ch1nhpd.png?size=128', '2026-03-09T05:21:01.931046+00:00'),
  ('maya', 'Maya', 'Enables AI agents to interact with multiple Autodesk Maya sessions through a single MCP server that automatically discovers and manages connections to running Maya instances. The server leverages Maya''s command port functionality to bootstrap itself without requiring any Maya-side installation, supports both native command ports and a custom Qt-based TCP server for communication, and provides tools for executing arbitrary Python code, creating virtual modules, and streaming stdout/stderr output. Designed to give agents full Python expressiveness within Maya sessions while supporting multi-session workflows, useful for automating 3D modeling tasks, pipeline operations, and creative workflows.', '@chadrik', 'development', 'Unknown', 15, 'https://github.com/chadrik/maya-mcp-server', NULL, 0, 'https://github.com/chadrik.png?size=128', '2026-03-09T05:21:01.931073+00:00'),
  ('behavioral-prediction', 'Behavioral Prediction', 'Provides AI-powered tools to analyze wallet behavior prediction, fraud detection and rug pull prediction.', '@chainaware', 'ai-ml', 'Unknown', 1, 'https://github.com/chainaware/behavioral-prediction-mcp', NULL, 0, 'https://github.com/chainaware.png?size=128', '2026-03-09T05:21:01.931094+00:00'),
  ('chainfetch', 'ChainFETCH', 'ChainFETCH MCP server provides AI assistants with access to Ethereum blockchain intelligence through AI-powered semantic search, LLM-guided queries, and comprehensive JSON filtering across addresses, transactions, blocks, tokens, and smart contracts. Built by ChainFETCH using the Model Context Protocol SDK with dual transport support (stdio and HTTP via ngrok), the implementation leverages vector similarity matching for semantic searches, LLaMA 3.2 3B for natural language query processing, and over 150+ searchable parameters per entity type for precise blockchain data filtering. The server includes AI-generated summaries for individual entities and supports both Claude Desktop integration through stdio transport and web-based access through StreamableHTTP, serving developers building DeFi analytics tools, researchers analyzing blockchain patterns, and AI assistants requiring intelligent access to Ethereum data without complex blockchain API management.', '@chainfetch', 'development', 'Unknown', 1, 'https://github.com/chainfetch/chainfetch-mcp-server', 'chainfetch-mcp-server', 341, 'https://github.com/chainfetch.png?size=128', '2026-03-09T05:21:01.931161+00:00'),
  ('chaingpt', 'ChainGPT', 'Provides access to ChainGPT''s Web3-focused AI capabilities through two main tools: AI-powered news retrieval for blockchain and cryptocurrency content, and general chat functionality optimized for Web3 queries. Built by Joshua Omobola using TypeScript with the Model Context Protocol SDK, it integrates ChainGPT''s specialized AI models via their official npm packages (@chaingpt/ainews and @chaingpt/generalchat) and requires a ChainGPT API secret key for authentication. The implementation includes article formatting utilities and supports both Docker deployment and Smithery configuration, making it valuable for AI assistants that need to stay current with crypto/blockchain news or provide Web3-knowledgeable responses to user queries.', '@mikeysrecipes', 'cloud', 'Unknown', 2, 'https://github.com/mikeysrecipes/chaingpt-mcp', 'chaingpt-mcp', 327, 'https://github.com/mikeysrecipes.png?size=128', '2026-03-09T05:21:01.931184+00:00'),
  ('source-code', 'Source Code', 'Manage source code and files on your machine', '@chakotay-lee', 'development', 'Unknown', 1, 'https://github.com/chakotay-lee/mcp-source-server', NULL, 0, 'https://github.com/chakotay-lee.png?size=128', '2026-03-09T05:21:01.931197+00:00'),
  ('note-com', 'Note.com', 'Note-MCP-Server provides a bridge between AI assistants and the note.com API, enabling content discovery and retrieval through conversation. The implementation offers three main tools: searching articles by keyword, retrieving detailed article information, and listing articles by specific users. Built with TypeScript using the Model Context Protocol SDK, it handles API responses and error management while maintaining a clean interface to the note.com platform. This server is particularly valuable for users who want to access note.com content directly through AI assistants without switching contexts.', '@champaya', 'development', 'Unknown', 1, 'https://github.com/champaya/note-mcp', NULL, 0, 'https://github.com/champaya.png?size=128', '2026-03-09T05:21:01.931227+00:00'),
  ('image-analysis-gpt-4-vision', 'Image Analysis (GPT-4 Vision)', 'Server implementation that enables AI assistants to analyze images using GPT-4-turbo''s vision capabilities. Built with TypeScript and the OpenAI API, it provides a standardized interface for image analysis tasks through the MCP protocol, making it valuable for applications that need to extract information, generate descriptions, or answer questions about visual content.', '@champierre', 'development', 'Unknown', 7, 'https://github.com/champierre/image-mcp-server', NULL, 0, 'https://github.com/champierre.png?size=128', '2026-03-09T05:21:01.931252+00:00'),
  ('adobe-photoshop-controller', 'Adobe Photoshop Controller', 'The PsMCP-MCP Server for Photoshop enables AI assistants to directly control Adobe Photoshop through a rich set of tools built with win32com. Developed by Chandrahas455, this Python implementation provides capabilities for manipulating layers, text, images, and effects in Photoshop documents through natural language commands. The server exposes over 30 tools for operations like opening/saving PSD files, creating and editing text layers, applying filters, managing layer properties, and exporting in various formats. It integrates with Gemini AI through a Gradio interface for a seamless user experience, making it particularly valuable for designers who want to automate Photoshop tasks or control their workflow through conversational AI without switching contexts.', '@chandrahas455', 'productivity', 'Unknown', 10, 'https://github.com/chandrahas455/psmcp-mcp-server-for-photoshop', NULL, 0, 'https://github.com/chandrahas455.png?size=128', '2026-03-09T05:21:01.931297+00:00'),
  ('qdrant-vector-database', 'Qdrant Vector Database', 'MCP-Qdrant Server provides a vector database integration for AI assistants, combining a Qdrant vector database with a specialized server that enables knowledge storage and retrieval. The implementation uses Docker containers to run both the Qdrant database and the MCP server, with the server utilizing the sentence-transformers embedding model to convert natural language into vector representations. It exposes two primary tools: one for storing code snippets with natural language descriptions, and another for searching the knowledge base using semantic queries. This setup is particularly useful for AI assistants that need to maintain persistent memory of code examples and technical knowledge across conversations.', '@changjunpark', 'databases', 'Unknown', 1, 'https://github.com/changjunpark/mcp-qdrant-server-with-qdrant-db', NULL, 0, 'https://github.com/changjunpark.png?size=128', '2026-03-09T05:21:01.931308+00:00'),
  ('google-jobs', 'Google Jobs', 'This MCP server for Google Jobs search, developed by Chan Meng, provides a standardized interface for querying job listings via the Serp API. Built with TypeScript and leveraging the MCP SDK, it offers a streamlined way to access Google''s job search functionality programmatically. The server is designed as a command-line tool, making it easy to integrate into various workflows and applications. By abstracting the complexities of job search queries into an MCP interface, it enables AI systems and developers to efficiently retrieve and process job listing data. This implementation is particularly useful for applications involving career guidance, labor market analysis, or automated job matching systems.', '@chanmeng666', 'development', 'Unknown', 19, 'https://github.com/chanmeng666/server-google-jobs', NULL, 0, 'https://github.com/chanmeng666.png?size=128', '2026-03-09T05:21:01.931337+00:00'),
  ('google-news', 'Google News', 'This Google News MCP server, developed by Chan Meng, provides a streamlined interface for accessing Google News search results via the SerpAPI. Built with TypeScript and leveraging the MCP SDK, it offers tools to query and retrieve up-to-date news articles, headlines, and related information. By abstracting the complexities of SerpAPI interactions into a standardized MCP interface, it enables AI systems to easily incorporate current news data into their workflows. This implementation is particularly useful for applications involving news aggregation, trend analysis, and information retrieval, facilitating use cases such as personalized news feeds, media monitoring, and real-time event tracking.', '@chanmeng666', 'development', 'Unknown', 113, 'https://github.com/chanmeng666/server-google-news', NULL, 0, 'https://github.com/chanmeng666.png?size=128', '2026-03-09T05:21:01.931368+00:00'),
  ('databricks', 'Databricks', 'Databricks MCP Server provides a bridge between AI assistants and Databricks workspaces, enabling interaction with data catalogs, schemas, tables, and SQL warehouses. Built with Go and the Model Context Protocol, it offers tools for listing database objects, executing SQL queries, and retrieving detailed table information through a standardized interface. The server authenticates with Databricks using unified authentication, supports multiple platforms including Linux, Windows, and macOS, and can be easily installed in VS Code through an extension, making it valuable for data analysts and engineers who need to query and analyze Databricks data directly from their AI assistant conversations.', '@characat0', 'databases', 'Unknown', 4, 'https://github.com/characat0/databricks-mcp-server', 'databricks-mcp-server', 1300, 'https://github.com/characat0.png?size=128', '2026-03-09T05:21:01.931378+00:00'),
  ('agentkit-chargebee', 'AgentKit (Chargebee)', 'Chargebee empowers businesses of all sizes to scale revenue with a complete suite of solutions, including subscription management, recurring billing, pricing and payment optimization, revenue recognition, collections, and customer retention.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('aws-cloudwatch', 'AWS CloudWatch', 'The CloudWatch MCP server provides AI assistants with direct access to AWS CloudWatch resources for monitoring and log analysis. Built with Python using FastMCP, it exposes tools for listing log groups, retrieving alarms (with filtering by state), executing CloudWatch Insights queries across multiple log groups, discovering log fields, and accessing saved queries. The implementation handles authentication through AWS profiles, automatically parses JSON in log messages, and supports both static and dynamic time ranges for queries. This server is particularly valuable for DevOps engineers and system administrators who need to monitor application health, investigate issues through logs, or analyze CloudWatch metrics without switching context from their AI assistant.', '@charliefng', 'cloud', 'Unknown', 4, 'https://github.com/charliefng/cloudwatch-mcp', NULL, 0, 'https://github.com/charliefng.png?size=128', '2026-03-09T05:21:01.931519+00:00'),
  ('leetcode-problem-fetcher', 'LeetCode Problem Fetcher', 'A LeetCode problem fetcher that extracts detailed problem information from LeetCode URLs using GraphQL API calls. Returns comprehensive problem data including title, difficulty, description, topic tags, and code templates for all available programming languages. Built with FastMCP for developers integrating LeetCode problem data into coding practice workflows, interview preparation tools, or educational applications.', '@charviki', 'development', 'Unknown', 1, 'https://github.com/charviki/leetcode-env-creator', NULL, 0, 'https://github.com/charviki.png?size=128', '2026-03-09T05:21:01.931541+00:00'),
  ('chatbi', 'ChatBI', 'ChatBI MCP Server provides intelligent data analysis capabilities by combining pandas DataFrame operations with OpenAI''s language models to generate and execute Python code for data exploration and visualization. Built by Steven Luo, the implementation supports CSV and Excel file formats through specialized data accessors, automatically detects data structure and column types, and uses LLM-powered code generation with error correction to answer natural language questions about datasets. The server maintains execution history for debugging and includes configurable logging, making it valuable for business analysts and data scientists who want conversational access to their spreadsheet data without writing Python code manually.', '@steven-luo', 'development', 'Unknown', 14, 'https://github.com/steven-luo/chatbi-mcp-server', NULL, 0, 'https://github.com/steven-luo.png?size=128', '2026-03-09T05:21:01.931602+00:00'),
  ('flomo', 'Flomo', 'Flomo-mcp is a TypeScript-based MCP server that enables AI assistants to write notes directly to Flomo, a note-taking application. It implements a single tool called ''write_note'' that accepts Markdown-formatted content and posts it to Flomo''s API using a webhook URL. The server communicates via stdio transport, requires configuration of the Flomo API URL through environment variables or command line arguments, and returns the API response with a link to the created note. This implementation is particularly useful for users who want to capture insights, ideas, or information from their AI conversations directly into their Flomo knowledge base without context switching.', '@chatmcp', 'development', 'Unknown', 1, 'https://github.com/chatmcp/flomo-mcp', 'flomo-mcp', 4471, 'https://github.com/chatmcp.png?size=128', '2026-03-09T05:21:01.931630+00:00'),
  ('heybeauty-virtual-try-on', 'HeyBeauty Virtual Try-On', 'HeyBeauty MCP Server provides a bridge between AI assistants and the HeyBeauty virtual try-on API, enabling users to visualize how clothing items would look on them. Built with TypeScript, it exposes resources representing clothes with metadata, tools for submitting and querying try-on tasks, and prompts for guiding the try-on experience. The server communicates with the HeyBeauty API to process user images with selected clothing items, returning the generated try-on images. It supports both stdio and REST transport options, making it flexible for integration with Claude Desktop and other MCP-compatible clients.', '@chatmcp', 'development', 'Unknown', 18, 'https://github.com/chatmcp/heybeauty-mcp', 'heybeauty-mcp', 4480, 'https://github.com/chatmcp.png?size=128', '2026-03-09T05:21:01.931660+00:00'),
  ('molecule-visualization-chimerax-pymol', 'Molecule Visualization (ChimeraX, PyMOL)', 'The molecule-mcp server provides a bridge between AI assistants and molecular visualization software, enabling interaction with PyMol and ChimeraX through the Model Context Protocol. It offers tools to open visualization software, execute commands directly in these applications, and save images of molecular structures. The implementation uses FastMCP to expose these capabilities as tools that can be called programmatically, making it valuable for scientific workflows where molecular visualization and manipulation are needed without leaving the conversation interface.', '@chatmol', 'ai-ml', 'Unknown', 90, 'https://github.com/chatmol/molecule-mcp', NULL, 0, 'https://github.com/chatmol.png?size=128', '2026-03-09T05:21:01.931735+00:00'),
  ('chat-roulette', 'Chat Roulette', 'This MCP server enables real-time chat conversations between users through an innovative abuse of the Model Context Protocol, using tool calls and long-polling to create a chat roulette-style experience. Built using Python with FastMCP, it implements a room-based system where users can join specific chat rooms or be randomly paired, with the `wait_for_message` tool blocking until messages arrive to simulate real-time communication without requiring custom notifications support from MCP clients. The implementation uses in-memory storage for simplicity, supports two-user rooms with message queuing, and works with any MCP client including Claude Code and standard HTTP tools, making it valuable for creating interactive chat experiences, testing MCP client capabilities, and demonstrating creative applications of the protocol beyond traditional tool-calling patterns.', '@hbd', 'development', 'Unknown', 5, 'https://github.com/hbd/mcp-chat', NULL, 0, 'https://github.com/hbd.png?size=128', '2026-03-09T05:21:01.931765+00:00'),
  ('chatspatial', 'ChatSpatial', 'ChatSpatial enables researchers to perform spatial transcriptomics analysis through natural language conversation rather than writing code. It supports multiple spatial omics platforms including 10x Visium, Xenium, Slide-seq v2, MERFISH, and seqFISH. The server provides analytical capabilities spanning spatial domain identification, cell type deconvolution, cell-cell communication analysis, trajectory inference, and gene set enrichment across various established bioinformatics methods.', '@cafferychen777', 'development', 'Unknown', 19, 'https://github.com/cafferychen777/chatspatial', NULL, 0, 'https://github.com/cafferychen777.png?size=128', '2026-03-09T05:21:01.931790+00:00'),
  ('chatterbox', 'ChatterBox', 'ChatterBox MCP server by Alex Tsimbalistov enables AI agents to join and interact with online meetings across Zoom, Google Meet, and Microsoft Teams platforms through the ChatterBox API. The implementation provides three core tools: joinMeeting for deploying bots to capture meeting transcripts and recordings with configurable bot names and webhook notifications, getMeetingInfo for retrieving session data including timestamps and formatted transcripts, and summarizeMeeting for generating structured meeting summaries from transcript data. Built with TypeScript and the MCP SDK, it integrates with ChatterBox''s meeting bot service to provide programmatic access to meeting participation and analysis capabilities, serving teams building AI-powered meeting assistants, organizations requiring automated meeting documentation, and developers creating workflow automation around video conference interactions.', '@chatterboxio', 'development', 'Unknown', 8, 'https://github.com/chatterboxio/chatterboxio-mcp-server', NULL, 0, 'https://github.com/chatterboxio.png?size=128', '2026-03-09T05:21:01.931825+00:00'),
  ('cheerlights', 'CheerLights', 'CheerLights MCP Server provides a bridge between Claude and the CheerLights IoT ecosystem, allowing AI assistants to retrieve current colors and history from the global light synchronization project. Built by Hans Scharler, this Python implementation uses FastMCP and httpx to connect with the ThingSpeak API, offering tools to fetch the current CheerLights color and view recent color change history. The server parses timestamp data into readable formats and includes proper error handling, making it ideal for IoT enthusiasts who want to integrate CheerLights data directly into their AI conversations without leaving the interface.', '@cheerlights', 'productivity', 'Unknown', 1, 'https://github.com/cheerlights/cheerlights-mcp', NULL, 0, 'https://github.com/cheerlights.png?size=128', '2026-03-09T05:21:01.931913+00:00'),
  ('aidderall', 'Aidderall', 'This MCP server provides AI assistants with hierarchical task management capabilities through a living document approach where completed tasks remain visible in the structure, creating a comprehensive work history. Built by Briam R. using Python with the MCP SDK and Pydantic for data validation, it implements a flexible focus system that allows switching between any tasks in any order via switch_focus, separating task completion (status change) from task removal (structural cleanup), and achieving "zen state" when either no tasks exist or all tasks are completed. The implementation features tools for creating independent tasks versus extending current work into subtasks, non-linear workflow navigation, breadcrumb trails and context peeking, and persistent completion history, making it valuable for complex project management, research workflows with multiple threads, and building AI assistants that need structured task decomposition with flexible priority switching.', '@cheezcake', 'development', 'Unknown', 6, 'https://github.com/cheezcake/aidderall_mcp', NULL, 0, 'https://github.com/cheezcake.png?size=128', '2026-03-09T05:21:01.931947+00:00'),
  ('windows-remote-control', 'Windows Remote Control', 'This Windows control server leverages nut.js and the Model Context Protocol to enable remote automation of Windows systems. Developed by an unnamed author, it provides a TypeScript-based interface for programmatically controlling mouse movements, keyboard input, and screen captures on Windows machines. The implementation uses Express for the server, Jimp and Sharp for image processing, and Clipboardy for clipboard access. It''s designed for scenarios requiring remote Windows automation, such as automated testing, remote administration, or building AI-assisted Windows control systems that can interact with desktop applications via natural language commands.', '@claude-did-this', 'development', 'Unknown', 295, 'https://github.com/claude-did-this/mcpcontrol', NULL, 0, 'https://github.com/claude-did-this.png?size=128', '2026-03-09T05:21:01.931975+00:00'),
  ('memorymesh', 'MemoryMesh', 'MemoryMesh, developed by CheMiguel23, is a local knowledge graph server that enables AI assistants like Claude to store, update, and recall structured information. It features dynamic schema-based tools, relationship modeling, and AI-aware interfaces for maintaining consistent data. Built on the Knowledge Graph Memory Server from MCP, MemoryMesh adds custom schemas, metadata expansion, and event tracking. It integrates seamlessly with Claude Desktop on macOS and Windows, facilitating natural language interactions for world-building and storytelling. While originally designed for text-based RPG scenarios, MemoryMesh is adaptable for social networks, organizational planning, or other structured data use cases requiring persistent information management and retrieval in AI-assisted creative and analytical tasks.', '@chemiguel23', 'development', 'Unknown', 335, 'https://github.com/chemiguel23/memorymesh', NULL, 0, 'https://github.com/chemiguel23.png?size=128', '2026-03-09T05:21:01.932003+00:00'),
  ('jupyter-notebook', 'Jupyter Notebook', 'Enables AI-driven management and execution of Jupyter notebooks with multi-notebook support', '@unknown', 'ai-ml', 'Unknown', 0, 'https://github.com/ChengJiale150/jupyter-mcp-server', NULL, 0, 'https://github.com/ChengJiale150.png?size=128', '2026-03-09T05:21:01.932022+00:00'),
  ('kubernetes-lens', 'Kubernetes Lens', 'MCP-K8s-Lens provides a bridge between Claude and the Kubernetes Lens desktop application, enabling AI assistants to interact with and analyze Kubernetes clusters through automated UI interactions. Built by Hung-Han Chen, this implementation uses Playwright to control the Lens Desktop application, offering tools for taking screenshots of the interface and capturing console logs with filtering capabilities. The server runs on stdio transport for seamless integration with Claude Desktop, making it particularly valuable for DevOps engineers who need AI assistance with Kubernetes cluster management without leaving their conversation interface.', '@chenhunghan', 'cloud', 'Unknown', 0, 'https://github.com/chenhunghan/mcp-k8s-lens', NULL, 0, 'https://github.com/chenhunghan.png?size=128', '2026-03-09T05:21:01.932044+00:00'),
  ('apple-reminders', 'Apple Reminders', 'MCP-AppleReminders provides a bridge between AI assistants and Apple''s Reminders app, allowing models to create, read, and manage reminders directly through the Model Context Protocol. Built with Python using the FastMCP framework, it exposes tools for interacting with the native Reminders application on macOS and iOS devices. The implementation includes functionality for retrieving existing reminders and creating new ones with specified parameters like title, notes, due dates, and priority levels. This server enables seamless integration with Apple''s productivity ecosystem, making it valuable for personal task management, scheduling assistance, and automated reminder creation through AI interactions.', '@chenningling', 'productivity', 'Unknown', 15, 'https://github.com/chenningling/mcp-applereminders', NULL, 0, 'https://github.com/chenningling.png?size=128', '2026-03-09T05:21:01.932092+00:00'),
  ('xiaohongshu-search-and-comment', 'Xiaohongshu Search and Comment', 'RedBook-Search-Comment-MCP is a Python-based MCP server that enables AI assistants to search and analyze content from Xiaohongshu (Little Red Book), a popular Chinese social media platform. Built with Playwright for browser automation, the implementation provides tools for retrieving comments and search results from Xiaohongshu, allowing AI systems to access real-time social media data without direct API access. The server handles web scraping complexities including authentication, pagination, and content extraction, making it valuable for market research, trend analysis, and social media monitoring use cases focused on the Chinese consumer market.', '@chenningling', 'ai-ml', 'Unknown', 40, 'https://github.com/chenningling/redbook-search-comment-mcp', NULL, 0, 'https://github.com/chenningling.png?size=128', '2026-03-09T05:21:01.932141+00:00'),
  ('stable-diffusion-ncnn', 'Stable Diffusion NCNN', 'This server provides CPU-based Stable Diffusion image generation capabilities through the ncnn neural network inference framework, enabling offline text-to-image generation without GPU requirements. Built in C++ as a stdio-based MCP server, it exposes a text-to-image tool that accepts prompts and generates PNG images with configurable parameters including dimensions, inference steps, seed control, and multiple output formats. The implementation leverages ncnn''s lightweight inference engine to run stable diffusion models entirely on CPU, making it valuable for environments where GPU access is limited or unavailable, edge computing scenarios, and developers who need local image generation without cloud dependencies.', '@chentyjpm', 'ai-ml', 'Unknown', 16, 'https://github.com/chentyjpm/ncnn_llm-mcp-sdimggen', NULL, 0, 'https://github.com/chentyjpm.png?size=128', '2026-03-09T05:21:01.932196+00:00'),
  ('memory-mcp', 'Memory MCP', '情景+实体记忆 MCP 服务，为 Claude Code 提供持久化记忆能力', '@chenxiaofie', 'development', 'Unknown', 9, 'https://github.com/chenxiaofie/memory-mcp', NULL, 0, 'https://github.com/chenxiaofie.png?size=128', '2026-03-09T05:21:01.932213+00:00'),
  ('browser', 'Browser', 'Fetch login-protected web pages and corporate SSO sites by leveraging authenticated Chrome/Edge browser sessions. Handles JavaScript-heavy applications, supports universal authentication methods (Microsoft, GitHub, AWS, Google, Okta), and provides smart tab management with domain-aware session persistence.', '@cherchyk', 'cloud', 'Unknown', 4, 'https://github.com/cherchyk/mcpbrowser', NULL, 0, 'https://github.com/cherchyk.png?size=128', '2026-03-09T05:21:01.932273+00:00'),
  ('perplexity-research', 'Perplexity Research', 'ResearchMCP provides internet research capabilities through Perplexity AI''s API, enabling AI assistants to retrieve up-to-date information on a wide range of topics. The server exposes a ''research'' tool that accepts natural language queries, processes them through Perplexity''s Sonar models, and returns comprehensive research reports with source citations. It features robust error handling with degraded mode operation, configurable retry mechanisms for network issues, and structured logging for better debugging. Particularly valuable for applications requiring factual, current information without leaving the conversation interface.', '@chew-z', 'development', 'Unknown', 1, 'https://github.com/chew-z/researchmcp', NULL, 0, 'https://github.com/chew-z.png?size=128', '2026-03-09T05:21:01.932302+00:00'),
  ('popup-dialog', 'Popup Dialog', 'Tauri-based server that provides native desktop popup dialog interfaces for user interaction. Creates popup windows for collecting user input through interactive questionnaires and confirming sensitive operations. Features keyboard shortcuts, progress tracking, breadcrumb navigation, and internationalization support with a modular architecture separating Vue.js UI components from Rust MCP protocol handling.', '@chietears', 'ai-ml', 'Unknown', 10, 'https://github.com/chietears/popup-mcp', NULL, 0, 'https://github.com/chietears.png?size=128', '2026-03-09T05:21:01.932337+00:00'),
  ('page-design-guide', 'Page Design Guide', 'Provides curated web design knowledge to help generate better, more modern web pages through design principles rather than code templates. Offers guidance across layout patterns (F-Pattern, Z-Pattern, Bento Grid), color psychology with trending palettes, typography hierarchy, responsive design strategies, component specifications, accessibility standards, and current design trends. Includes inspiration sources and detailed guidance for specific page sections and UI components.', '@chihebnabil', 'development', 'Unknown', 3, 'https://github.com/chihebnabil/page-design-guide-mcp', NULL, 0, 'https://github.com/chihebnabil.png?size=128', '2026-03-09T05:21:01.932395+00:00'),
  ('crawl4ai', 'Crawl4AI', 'This MCP server provides AI assistants with advanced web crawling and RAG capabilities through the Crawl4AI library, built by Cole Medin using Python with comprehensive content extraction, semantic search, and knowledge graph integration. The implementation features multiple RAG strategies including contextual embeddings, hybrid search combining vector and keyword approaches, agentic RAG with code example extraction, cross-encoder reranking, and AI hallucination detection through Neo4j knowledge graphs. Built with Supabase for vector storage, OpenAI embeddings, configurable LLM support through OpenRouter, and Docker deployment options, it serves developers needing intelligent web content analysis, teams requiring automated documentation and code discovery from web sources, and organizations wanting to build knowledge bases from crawled web content with advanced retrieval and validation capabilities.', '@chillbruhhh', 'databases', 'Unknown', 2, 'https://github.com/chillbruhhh/crawl4ai-mcp', NULL, 0, 'https://github.com/chillbruhhh.png?size=128', '2026-03-09T05:21:01.932411+00:00'),
  ('unreal-engine-remote-control', 'Unreal Engine Remote Control', 'A TypeScript-based MCP server that enables AI assistants to control Unreal Engine 5 through its Remote Control API, providing comprehensive game development automation capabilities. Built by ChiR24, it offers both consolidated and individual tool modes with 10+ core functions including asset management, actor spawning and manipulation, level streaming, animation and physics control, Niagara particle effects, Blueprint creation, landscape sculpting, foliage painting, lighting setup, and Play-in-Editor controls. The implementation features robust error handling with retry logic, response validation, HTTP connection pooling, Python script execution for complex operations, and Docker deployment support, making it useful for automated game testing, procedural content generation, cinematics creation, and AI-assisted level design workflows.', '@chir24', 'cloud', 'Unknown', 344, 'https://github.com/chir24/unreal_mcp', NULL, 0, 'https://github.com/chir24.png?size=128', '2026-03-09T05:21:01.932440+00:00'),
  ('clear-thought', 'Clear Thought', 'A systematic thinking and problem-solving MCP server built by Chirag Singhal that provides 11 specialized cognitive tools for enhanced reasoning capabilities. The implementation offers mental models (First Principles, Opportunity Cost, Occam''s Razor), design patterns for software architecture, programming paradigms, debugging approaches, sequential thinking with revision support, collaborative reasoning with multi-persona simulation, structured decision frameworks, metacognitive monitoring for knowledge assessment, scientific method tools for hypothesis testing, dialectical argumentation, and visual reasoning for diagrammatic problem-solving. Each tool uses TypeScript with comprehensive input validation, colored console output via chalk, and structured JSON responses, making it useful for complex analysis tasks, architectural decisions, systematic debugging, and multi-step reasoning workflows where different cognitive approaches can be applied based on the problem type.', '@chirag127', 'development', 'Unknown', 30, 'https://github.com/chirag127/clear-thought-mcp-server', NULL, 0, 'https://github.com/chirag127.png?size=128', '2026-03-09T05:21:01.932477+00:00'),
  ('stochastic-thinking', 'Stochastic Thinking', 'A stochastic algorithms MCP server built by Chirag Singhal that provides probabilistic decision-making capabilities to help AI assistants break out of local thinking patterns. The server implements five core algorithms - Markov Decision Processes for sequential optimization, Monte Carlo Tree Search for strategic planning, Multi-Armed Bandit models for exploration-exploitation balance, Bayesian Optimization for uncertainty-aware decisions, and Hidden Markov Models for state inference. Rather than always choosing the most obvious solution, it enables AI to strategically explore alternative approaches and consider multiple future scenarios, making it useful for game playing, A/B testing, hyperparameter tuning, route optimization, and any decision-making task where breaking out of deterministic patterns could yield better outcomes.', '@chirag127', 'development', 'Unknown', 4, 'https://github.com/chirag127/stochastic-thinking-mcp-server', NULL, 0, 'https://github.com/chirag127.png?size=128', '2026-03-09T05:21:01.932515+00:00'),
  ('website-screenshot-fast', 'Website Screenshot Fast', 'A fast screenshot capture tool optimized for AI vision models, particularly Claude Vision API, that automatically tiles full web pages into 1072x1072 pixel chunks for optimal processing. Built with Puppeteer and Sharp, it features intelligent browser lifecycle management with automatic restarts, memory optimization through page cleanup, and robust error handling with retry mechanisms. The server provides both single screenshot capture and screencast functionality with JavaScript execution capabilities, making it useful for web automation, visual testing, content analysis, and AI-assisted web development workflows where consistent, high-quality screenshots are needed.', '@chongzixuan-ai', 'development', 'Unknown', 27, 'https://github.com/chongzixuan-ai/mcp-server-website', NULL, 0, 'https://github.com/chongzixuan-ai.png?size=128', '2026-03-09T05:21:01.932543+00:00'),
  ('ordnance-survey-national-geographic-database', 'Ordnance Survey National Geographic Database', 'The OS NGD Features API MCP Server provides a bridge between MCP clients and the Ordnance Survey National Geographic Database, making it easy to query UK geographic data through a standardized protocol. Built with Python using aiohttp and FastMCP, it handles authentication, rate limiting, and simplifies interaction with the complex OS API endpoints that follow the OGC API Features standard. The server exposes tools for collection management, feature search with spatial and attribute filters, individual feature retrieval, linked identifier operations, and bulk feature operations. This implementation is particularly valuable for developers and researchers who need to incorporate authoritative UK geographic data into AI-assisted workflows for applications like urban planning, transportation analysis, or location-based services.', '@chriscarlon', 'databases', 'Unknown', 2, 'https://github.com/chriscarlon/os-mcp', NULL, 0, 'https://github.com/chriscarlon.png?size=128', '2026-03-09T05:21:01.932556+00:00'),
  ('taskqueue', 'TaskQueue', 'TaskQueue MCP Server provides a structured task management system for AI assistants, enabling them to break down complex projects into manageable tasks with progress tracking and user approval checkpoints. Developed by Christopher C. Smith, this TypeScript implementation uses the Model Context Protocol to expose tools for project planning, task creation, status updates, and completion approvals through both a server interface and companion CLI utility. The server supports multiple LLM providers (OpenAI, Google, Deepseek) for generating project plans and includes features like auto-approval, task recommendations, and detailed progress visualization. Ideal for collaborative workflows where AI assistants need to maintain structured progress on multi-step tasks with human oversight.', '@chriscarrollsmith', 'development', 'Unknown', 67, 'https://github.com/chriscarrollsmith/taskqueue-mcp', 'taskqueue-mcp', 7736, 'https://github.com/chriscarrollsmith.png?size=128', '2026-03-09T05:21:01.932588+00:00'),
  ('hevy-fitness', 'Hevy Fitness', 'This MCP server provides AI assistants with direct access to the Hevy Fitness API for comprehensive workout and routine management through 15 specialized tools covering workouts, routines, exercise templates, routine folders, and webhook subscriptions. Built using TypeScript with Kubb-generated API clients from OpenAPI specifications, Zod validation, and comprehensive error handling, it offers tools for retrieving paginated workout lists, creating and updating workouts with exercises and sets, managing routine libraries with folder organization, searching exercise templates by muscle groups, and setting up webhook notifications for workout events. The implementation features automatic API client generation ensuring type safety, response formatting with proper error propagation, and supports both data retrieval and modification operations, making it valuable for fitness tracking workflows, workout analysis, and building AI assistants that need programmatic access to Hevy''s fitness data without manual app interaction.', '@chrisdoc', 'development', 'Unknown', 142, 'https://github.com/chrisdoc/hevy-mcp', NULL, 0, 'https://github.com/chrisdoc.png?size=128', '2026-03-09T05:21:01.932623+00:00'),
  ('role-specific-context', 'Role-Specific Context', 'Role-Context MCP Server enables AI assistants to maintain distinct expert personas through role-based context management. It provides tools for creating and managing specialized roles (like Marketing Expert or Songwriter), each with its own memory, tone, and domain expertise. The implementation features a memory management system with vector search capabilities for retrieving relevant context, real-time context switching based on triggers, and integration with OpenAI''s GPT-4o-mini model. Particularly valuable for applications requiring consistent AI personalities across different domains without context bleed between roles.', '@chris-june', 'ai-ml', 'Unknown', 1, 'https://github.com/chris-june/mcp-server', NULL, 0, 'https://github.com/chris-june.png?size=128', '2026-03-09T05:21:01.932749+00:00'),
  ('pubmed', 'PubMed', 'This MCP server provides advanced PubMed literature search and management capabilities through the NCBI E-utilities API, built by Chris Mannina with comprehensive citation formatting and research analysis tools. It offers 12 specialized tools including complex search filtering by date ranges, article types, authors, journals, and MeSH terms, detailed article retrieval with abstracts and metadata, author-based searches, related article discovery, and citation export in multiple formats (BibTeX, APA, MLA, Chicago, Vancouver, EndNote, RIS). The implementation features intelligent caching with TTL support, respectful rate limiting, advanced search query building with boolean operators, XML parsing for PubMed responses, and research trend analysis, making it valuable for researchers, academics, and AI assistants conducting systematic literature reviews, meta-analyses, or bibliographic research workflows.', '@chrismannina', 'development', 'Unknown', 8, 'https://github.com/chrismannina/pubmed-mcp', 'pubmed-mcp-server', 3336, 'https://github.com/chrismannina.png?size=128', '2026-03-09T05:21:01.932782+00:00'),
  ('gel-database', 'Gel Database', 'This MCP server implementation provides a bridge between LLM agents and Gel databases, enabling automated schema discovery, query validation, and execution of EdgeQL and TypeScript queries. Developed by Christian561, it leverages the Model Context Protocol SDK and Gel query builder to offer tools for describing database schemas, validating EdgeQL syntax, and executing queries. The server is designed for use cases requiring AI-assisted database interactions, such as automated data analysis, query generation, and database management tasks.', '@christian561', 'databases', 'Unknown', 11, 'https://github.com/christian561/gel-mcp-server', NULL, 0, 'https://github.com/christian561.png?size=128', '2026-03-09T05:21:01.932822+00:00'),
  ('promptz', 'Promptz', 'Provides a bridge to the promptz.dev platform, enabling AI assistants to directly access and use prompts without manual copy-pasting. Built by Christian Bonzelet, this TypeScript server implements two primary tools for listing and retrieving prompts, reducing context switching for developers and content creators by seamlessly integrating the promptz.dev prompt library into AI workflows.', '@cremich', 'development', 'Unknown', 4, 'https://github.com/cremich/promptz-mcp', '@promptz/mcp', 5068, 'https://github.com/cremich.png?size=128', '2026-03-09T05:21:01.932847+00:00'),
  ('dicom', 'DICOM', 'DICOM MCP Server enables AI assistants to interact with medical imaging systems through standard DICOM networking protocols. It provides tools for querying patient information, studies, series, and instances from DICOM servers, as well as extracting text from encapsulated PDF documents stored in DICOM format. Built on pynetdicom, the server supports multiple DICOM nodes, configurable calling AE titles, and various attribute presets for different query levels, making it particularly valuable for medical professionals and researchers who need to access and analyze medical imaging metadata without leaving their AI assistant conversation.', '@christianhinge', 'ai-ml', 'Unknown', 85, 'https://github.com/christianhinge/dicom-mcp', NULL, 0, 'https://github.com/christianhinge.png?size=128', '2026-03-09T05:21:01.932907+00:00'),
  ('keycloak-admin', 'Keycloak Admin', 'This Keycloak MCP server, developed by Christoph Englisch, provides a streamlined interface for managing Keycloak users and realms. It integrates with the Keycloak Admin Client to offer essential operations like user creation, deletion, and listing, as well as realm management. The implementation is designed for simplicity and ease of use, making it ideal for developers and administrators who need to automate Keycloak tasks or integrate Keycloak management into their workflows. It''s particularly useful for scenarios involving user provisioning, access control, and identity management across multiple realms.', '@christophenglisch', 'productivity', 'Unknown', 38, 'https://github.com/christophenglisch/keycloak-model-context-protocol', 'keycloak-model-context-protocol', 5328, 'https://github.com/christophenglisch.png?size=128', '2026-03-09T05:21:01.932952+00:00'),
  ('instantdb', 'InstantDB', 'An InstantDB MCP server that provides tools for querying and managing data through the InstantDB Admin SDK. Enables developers to interact with their InstantDB applications via a standardized interface, supporting operations like executing database queries, retrieving query results, and serving code examples across different usage contexts like admin access, CLI interactions, and data modeling.', '@christophersutton', 'databases', 'Unknown', 1, 'https://github.com/christophersutton/instantdb-mcp', NULL, 0, 'https://github.com/christophersutton.png?size=128', '2026-03-09T05:21:01.932962+00:00'),
  ('nmap-network-scanner', 'Nmap Network Scanner', 'NMAP MCP Server provides a bridge to the popular network scanning tool Nmap, enabling AI assistants to perform network reconnaissance and banner grabbing through a structured API. The implementation offers two main tools: network scanning with customizable port ranges and script options, and TCP banner grabbing for service identification. Built with security considerations in mind, the server handles subprocess execution safely and includes proper error handling for timeouts and connection issues. This server is particularly valuable for security professionals and network administrators who need to discover hosts, identify services, or assess network vulnerabilities through natural language interactions.', '@christopherwoodall', 'ai-ml', 'Unknown', 2, 'https://github.com/christopherwoodall/nmap-mcp', NULL, 0, 'https://github.com/christopherwoodall.png?size=128', '2026-03-09T05:21:01.933009+00:00'),
  ('dall-e-3', 'DALL-E 3', 'This MCP server provides DALL-E 3 image generation capabilities through OpenAI''s API, enabling AI assistants to create high-quality images with configurable parameters including size (1024x1024, 1024x1792, 1792x1024), quality (standard, hd), and style (vivid, natural) options. Built by Chris Oguntolu using TypeScript with the Model Context Protocol SDK, it features automatic directory creation for saved images, comprehensive error handling and validation, and robust logging throughout the generation process. The implementation handles OpenAI API authentication through environment variables, saves generated images locally with descriptive filenames, and provides detailed success/failure responses, making it valuable for content creation workflows, automated design processes, and building AI assistants that need programmatic access to DALL-E 3''s image generation capabilities without manual OpenAI interface navigation.', '@chrisurf', 'development', 'Unknown', 1, 'https://github.com/chrisurf/imagegen-mcp-d3', '@chrisurf/imagegen-mcp-d3', 360, 'https://github.com/chrisurf.png?size=128', '2026-03-09T05:21:01.933087+00:00'),
  ('codedox', 'CodeDox', 'This MCP server provides AI assistants with comprehensive documentation crawling and code extraction capabilities, built by Chris Scott using Python with FastAPI and PostgreSQL. The implementation combines web crawling through Crawl4AI with tree-sitter-based code parsing to automatically extract, categorize, and enrich code snippets from documentation sites, featuring real-time progress tracking via WebSockets, LLM-powered metadata enhancement, and a React-based web interface for search and management. Built with Docker support, health monitoring for long-running crawl jobs, and both REST API and MCP tool interfaces, it serves developers needing to build searchable code databases from documentation sites, teams requiring automated extraction of code examples from multiple sources, and organizations wanting to create internal knowledge bases from technical documentation with intelligent code categorization and semantic search capabilities.', '@chriswritescode-dev', 'databases', 'Unknown', 27, 'https://github.com/chriswritescode-dev/codedox', NULL, 0, 'https://github.com/chriswritescode-dev.png?size=128', '2026-03-09T05:21:01.933099+00:00'),
  ('chroma', 'Chroma', 'Chroma MCP Server provides vector database integration for LLM applications, enabling AI models to create and manage collections of data with vector search capabilities. Built by Chroma Core, it supports multiple client types (ephemeral, persistent, HTTP, and cloud), offers comprehensive collection management tools, and enables document operations including adding, querying, and retrieving with advanced filtering options. The implementation integrates seamlessly with Claude Desktop through simple configuration options and supports environment variables for flexible deployment, making it ideal for workflows requiring memory capabilities such as knowledge bases and context-aware conversations.', '@chroma-core', 'databases', 'Unknown', 508, 'https://github.com/chroma-core/chroma-mcp', 'chroma-mcp', 218056, 'https://github.com/chroma-core.png?size=128', '2026-03-09T05:21:01.933111+00:00'),
  ('package-search', 'Package Search', 'This MCP server provides access to versioned source code from major open-source projects including Go, Python CPython, Rust, LLVM, Abseil, and Chroma through GitHub releases integration. The implementation automatically tracks and indexes specific file types (source code, documentation) from tagged releases using configurable patterns, maintaining a curated dataset of programming language implementations and core libraries with version sampling to manage dataset size. Designed for developers, researchers, and AI systems that need access to canonical source code examples, language evolution analysis, or reference implementations from foundational software projects across multiple programming ecosystems.', '@chroma-core', 'development', 'Unknown', 41, 'https://github.com/chroma-core/package-search', NULL, 0, 'https://github.com/chroma-core.png?size=128', '2026-03-09T05:21:01.933138+00:00'),
  ('chrome-browser-automation', 'Chrome Browser Automation', 'Spring AI Chrome MCP Server provides a bridge between AI assistants and web browsers using Selenium WebDriver. This Java implementation leverages Spring Boot and Spring AI to expose Chrome browser automation capabilities as tools that can be called by AI models. The server sets up a WebDriverManager to handle Chrome driver installation automatically and exposes browser automation functionality through the ChromeToolService. It''s particularly useful for AI assistants that need to perform web scraping, automated testing, or any task requiring direct browser interaction without requiring users to write complex browser automation code.', '@qoxogus', 'development', 'Unknown', 2, 'https://github.com/qoxogus/spring-ai-chrome-mcp-server', NULL, 0, 'https://github.com/qoxogus.png?size=128', '2026-03-09T05:21:01.933165+00:00'),
  ('chrome-browser-control', 'Chrome Browser Control', 'Chrome MCP Server provides fine-grained control over a Chrome browser instance through the Chrome DevTools Protocol (CDP). It enables AI assistants to navigate web pages, interact with elements, type text, and extract page content through a set of specialized tools. The server implements SSE transport for the Model Context Protocol and includes features like automatic handling of dynamic content, mutation tracking, and prevention of new window/tab openings. Particularly valuable for workflows requiring web automation, form filling, or content extraction directly within conversation interfaces.', '@lxe', 'ai-ml', 'Unknown', 47, 'https://github.com/lxe/chrome-mcp', NULL, 0, 'https://github.com/lxe.png?size=128', '2026-03-09T05:21:01.933209+00:00'),
  ('chrome-debug-protocol', 'Chrome Debug Protocol', 'This MCP server provides browser automation capabilities through Chrome''s debugging protocol with session persistence, enabling AI agents to control Chrome instances for web scraping, testing, and automation tasks. Built using TypeScript with puppeteer-core and the Model Context Protocol SDK, it offers tools for taking screenshots in multiple formats (PNG, JPEG, WebP), navigating to URLs, clicking elements, typing text, and retrieving page content while maintaining browser sessions across multiple interactions. The implementation features automatic browser discovery, connection management with configurable debugging ports, error handling with detailed responses, and support for both headless and headed Chrome instances, making it valuable for automated testing workflows, web data extraction, and building AI assistants that need persistent browser control without manual Chrome DevTools access.', '@rainmen-xia', 'development', 'Unknown', 8, 'https://github.com/rainmen-xia/chrome-debug-mcp', 'chrome-debug-mcp', 4074, 'https://github.com/rainmen-xia.png?size=128', '2026-03-09T05:21:01.933244+00:00'),
  ('greyhack-tools', 'GreyHack Tools', 'Grey Hack MCP Server provides a specialized toolkit for the Grey Hack game, enabling AI assistants to search GitHub for code examples, validate scripts against the game''s API, generate common script templates, and transpile GreyScript to JavaScript. The implementation offers four main tools: searching GitHub repositories for Grey Hack code, validating scripts against official API documentation, generating templates for common game tasks like port scanning and password cracking, and transpiling between GreyScript and JavaScript. Built with TypeScript using the Model Context Protocol SDK, this server is particularly valuable for Grey Hack players who want to develop, validate, and discover scripts without leaving their AI assistant interface.', '@chromewillow', 'development', 'Unknown', 1, 'https://github.com/chromewillow/greyhack-mcp-server', NULL, 0, 'https://github.com/chromewillow.png?size=128', '2026-03-09T05:21:01.933310+00:00'),
  ('forge', 'Forge', 'MCP Forge is a powerful server generator for creating Model Context Protocol (MCP) servers with multiple template options including basic, web search, and database configurations. It provides utility functions for generating server templates, creating Cursor IDE integration configurations, and generating deployment instructions, making it easy to quickly bootstrap and configure new MCP servers with standardized structures and best practices.', '@chromewillow', 'databases', 'Unknown', 0, 'https://github.com/chromewillow/mcp-forge', NULL, 0, 'https://github.com/chromewillow.png?size=128', '2026-03-09T05:21:01.933321+00:00'),
  ('chromia-wallet', 'Chromia Wallet', 'This Chromia MCP server, developed by an unnamed author, enables AI assistants to interact with the Chromia blockchain and wallet for sending $CHR transactions. Built with TypeScript and leveraging libraries like @chromia/ft4 and @goat-sdk/wallet-chromia, it abstracts the complexities of blockchain interactions, allowing AI systems to easily incorporate cryptocurrency operations into their workflows. The server integrates with the OpenAI API for AI capabilities and uses environment variables for configuration. It''s designed to be run as a local server, with setup instructions for integrating with Claude''s desktop application. This implementation is particularly useful for developers and researchers exploring AI-assisted cryptocurrency management, enabling use cases like automated transactions, wallet monitoring, and blockchain-based decision making.', '@chromindscan', 'development', 'Unknown', 1, 'https://github.com/chromindscan/chromia-mcp', NULL, 0, 'https://github.com/chromindscan.png?size=128', '2026-03-09T05:21:01.933353+00:00'),
  ('chronos-protocol', 'Chronos Protocol', 'This Chronos Protocol MCP server by Lloyd Barcatan provides time intelligence, persistent memory, and complete traceability for AI coding agents through comprehensive activity logging and timezone management capabilities. Built with Python using Pydantic models and supporting both centralized and per-project storage modes, it offers nine core tools including current time queries with system timezone defaults, cross-timezone conversion, activity tracking with start/end/update operations, elapsed time calculation, and time-based reminders with configurable ID formats (ShortUUID, UUID, custom). The implementation features robust storage configuration with automatic project root detection, write permission validation, configurable operation timeouts, and detailed diagnostic logging, making it ideal for AI development workflows that require precise time tracking, session continuity across coding tasks, and audit trails for debugging and performance analysis.', '@n0zer0d4y', 'development', 'Unknown', 4, 'https://github.com/n0zer0d4y/chronos-protocol', NULL, 0, 'https://github.com/n0zer0d4y.png?size=128', '2026-03-09T05:21:01.933387+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('chronulus-ai-forecasting', 'Chronulus AI Forecasting', 'The Chronulus MCP Server enables Claude to interact with Chronulus AI''s forecasting and prediction agents, allowing users to analyze time series data and generate forecasts through natural language. Developed by Chronulus AI, this implementation is built using Python and integrates with the Chronulus API to provide specialized time series forecasting capabilities. The server can be deployed using pip, Docker, or uvx, and requires a Chronulus API key for authentication. It''s particularly useful for users who need to perform time series analysis, generate predictions, and visualize forecasting data directly within their Claude conversations.', '@chronulusai', 'cloud', 'Unknown', 105, 'https://github.com/chronulusai/chronulus-mcp', 'chronulus-mcp', 4743, 'https://github.com/chronulusai.png?size=128', '2026-03-09T05:21:01.933413+00:00'),
  ('mongodb-read-only', 'MongoDB Read-Only', 'High-performance read-only MongoDB server built in Rust that enables safe database querying for both Kubernetes-deployed instances and direct URL connections. Supports comprehensive query operations including find, aggregate, countDocuments, and distinct with JSON validation and timeout handling. Features saved query templates with variable substitution, data model documentation integration, and automatic credential extraction from Kubernetes pod environment variables for streamlined cluster access.', '@chrstnwhlrt', 'databases', 'Unknown', 1, 'https://github.com/chrstnwhlrt/ro-mongodb-mcp-rs', NULL, 0, 'https://github.com/chrstnwhlrt.png?size=128', '2026-03-09T05:21:01.933424+00:00'),
  ('termlink', 'Termlink', 'Provides terminal command execution, filesystem operations, and system process monitoring through a configurable security model. Supports command allowlisting and blocklisting, timeout controls, and output size limits. Includes tools for running shell commands, reading and writing files, listing directories, checking file existence, and inspecting running processes and environment variables.', '@chu2bard', 'ai-ml', 'Unknown', 19, 'https://github.com/chu2bard/termlink', NULL, 0, 'https://github.com/chu2bard.png?size=128', '2026-03-09T05:21:01.933511+00:00'),
  ('web-research', 'Web Research', 'MCP-WebResearch provides AI assistants with web browsing capabilities for conducting research through Google searches and webpage content extraction. Built with TypeScript using Playwright for browser automation and Turndown for HTML-to-Markdown conversion, it offers tools to search Google, visit webpages, and capture screenshots while handling common challenges like consent dialogs and bot detection. The implementation includes an agentic research prompt that guides assistants through iterative research workflows, making it particularly valuable for deep topic exploration, fact-checking, and information gathering directly within AI conversations.', '@chuanmingliu', 'development', 'Unknown', 20, 'https://github.com/chuanmingliu/mcp-webresearch', NULL, 0, 'https://github.com/chuanmingliu.png?size=128', '2026-03-09T05:21:01.933541+00:00'),
  ('evm-blockchain-bridge', 'EVM Blockchain Bridge', 'EVM MCP Server provides a bridge to Ethereum Virtual Machine (EVM) compatible blockchains, enabling AI assistants to interact with blockchain networks like Binance Smart Chain. Built by Etheral, it offers tools for querying blockchain data including balances, transactions, and smart contracts, while also supporting token transfers and swaps through PancakeSwap integration. The server exposes both HTTP and stdio interfaces, implements comprehensive resources for blockchain exploration, and includes wallet management capabilities—making it valuable for blockchain analysis, token transfers, and DeFi interactions without leaving the conversation context.', '@chulanpro5', 'ai-ml', 'Unknown', 0, 'https://github.com/chulanpro5/evm-mcp-server', NULL, 0, 'https://github.com/chulanpro5.png?size=128', '2026-03-09T05:21:01.933599+00:00'),
  ('simple-prompt-optimizer', 'Simple Prompt Optimizer', 'A lightweight prompt optimization server that transforms user prompts into high-performance versions using the CO-STAR framework (Context, Objective, Style, Tone, Audience, Response). Offers two optimization modes: instant improvement for quick enhancements and deep optimization with critique-and-refine workflow for complex prompts. Integrates with OpenRouter API and supports multiple task types including coding, creative writing, analysis, and debugging.', '@chumbayoumba', 'development', 'Unknown', 2, 'https://github.com/chumbayoumba/simple-prompt-optimizer', NULL, 0, 'https://github.com/chumbayoumba.png?size=128', '2026-03-09T05:21:01.933625+00:00'),
  ('google-chat', 'Google Chat', 'A lightweight MCP server for Google Chat integration that enables programmatic access to Google Chat spaces and messages. Developed by Zz Chen, this implementation provides OAuth2-based authentication and tools for listing chat spaces and retrieving messages with flexible date filtering. Useful for developers needing automated interactions with Google Chat data.', '@chy168', 'communication', 'Unknown', 14, 'https://github.com/chy168/google-chat-mcp-server', NULL, 0, 'https://github.com/chy168.png?size=128', '2026-03-09T05:21:01.933654+00:00'),
  ('clickup', 'ClickUp', 'This ClickUp MCP server implementation by David Whatley provides AI assistants with extensive access to ClickUp''s project management platform through 170+ tools covering tasks, documents, spaces, time tracking, goals, webhooks, custom fields, and team collaboration features. Built with TypeScript and the MCP SDK, it offers multiple server variants (basic, enhanced, efficiency, AI-powered) with intelligent tool suggestions, context-aware workflow recommendations, and comprehensive API coverage including advanced features like dependency management, file attachments, and real-time webhook processing. The implementation supports both tool-based operations and resource-based data access through standardized URI templates, making it suitable for automating project workflows, integrating ClickUp data with AI-driven productivity tools, and enabling conversational project management across development teams and business operations.', '@chykalophia', 'development', 'Unknown', 7, 'https://github.com/chykalophia/clickup-mcp-server---enhanced', NULL, 0, 'https://github.com/chykalophia.png?size=128', '2026-03-09T05:21:01.933689+00:00'),
  ('cortex-xsiam-sdk', 'Cortex XSIAM SDK', 'Wraps the Palo Alto Networks Demisto SDK to assist in developing security automation content for Cortex XSIAM/XSOAR platforms. Enables semantic search across 4,700+ playbooks, scripts, integrations, and XQL rules from the official content library using natural language queries. Provides SDK operations for scaffolding, formatting, validating, and linting security content, plus remote operations to list, download, upload content to XSIAM/XSOAR tenants and run commands or playbooks directly.', '@ciaran-finnegan', 'development', 'Unknown', 3, 'https://github.com/ciaran-finnegan/cortex-xsiam-sdk-mcp-tools', NULL, 0, 'https://github.com/ciaran-finnegan.png?size=128', '2026-03-09T05:21:01.933717+00:00'),
  ('healthcare-data-hub', 'Healthcare Data Hub', 'Healthcare MCP Server provides AI assistants with access to medical information through five specialized tools: FDA drug information lookup, PubMed research search, Health.gov topic retrieval, clinical trials search, and ICD-10 code lookup. The implementation features efficient caching to reduce API calls, anonymous usage tracking, and supports both stdio mode for Cline integration and HTTP/SSE mode for web clients. Built with FastMCP and deployed via Docker or Railway, it''s particularly valuable for healthcare professionals, researchers, and patients who need to access evidence-based medical information without leaving their AI assistant interface.', '@cicatriiz', 'cloud', 'Unknown', 99, 'https://github.com/cicatriiz/healthcare-mcp-public', NULL, 0, 'https://github.com/cicatriiz.png?size=128', '2026-03-09T05:21:01.933740+00:00'),
  ('io-github-sidneybissoli-cid10-br-mcp', 'io.github.SidneyBissoli/cid10-br-mcp', 'MCP Server for Brazilian ICD-10 (DATASUS) - International Classification of Diseases', '@sidneybissoli', 'development', 'Unknown', 0, 'https://github.com/sidneybissoli/cid10-br-mcp', NULL, 0, 'https://github.com/sidneybissoli.png?size=128', '2026-03-09T05:21:01.933758+00:00'),
  ('circleci', 'CircleCI', 'A specialized server implementation for the Model Context Protocol (MCP) designed to integrate with CircleCI''s development workflow. This project serves as a bridge between CircleCI''s infrastructure and the Model Context Protocol, enabling enhanced AI-powered development experiences.', '@circleci-public', 'development', 'Unknown', 80, 'https://github.com/circleci-public/mcp-server-circleci', '@circleci/mcp-server-circleci', 298024, 'https://github.com/circleci-public.png?size=128', '2026-03-09T05:21:01.933804+00:00'),
  ('cisco-support-apis', 'Cisco Support APIs', 'This MCP server provides access to Cisco''s Support APIs, enabling AI assistants to search bug databases, retrieve case information, and access product lifecycle data through authenticated API calls. Built by sieteunoseis using TypeScript with comprehensive OAuth2 authentication and rate limiting handling, it offers 8 bug search tools including keyword searches, product-specific queries, and release-based filtering, plus case management tools for retrieving case summaries and details by ID, contract, or user. The implementation features robust error handling with timeout management, token refresh capabilities, Docker containerization support, and structured response formatting with pagination, making it valuable for technical support workflows, incident investigation processes, product upgrade planning, and building AI assistants that need programmatic access to Cisco''s extensive support database without manual portal navigation.', '@sieteunoseis', 'databases', 'Unknown', 14, 'https://github.com/sieteunoseis/mcp-cisco-support', 'mcp-cisco-support', 7205, 'https://github.com/sieteunoseis.png?size=128', '2026-03-09T05:21:01.933815+00:00'),
  ('ssh-liaison', 'SSH Liaison', 'Enables stateful SSH connections where environment state and working directory persist between commands. Supports both SSH config file aliases and direct credential-based connections with automatic key/password authentication fallback. Includes tools for establishing connections, running commands, and reading remote log files.', '@citizen4our', 'ai-ml', 'Unknown', 4, 'https://github.com/citizen4our/ssh-liaison-mcp', NULL, 0, 'https://github.com/citizen4our.png?size=128', '2026-03-09T05:21:01.933849+00:00'),
  ('civic-nexus', 'Civic Nexus', 'Hosted MCP gateway that connects AI assistants to multiple MCP servers through a unified endpoint. Manages authentication, credentials, and access control while enabling users to create focused toolkits of MCP servers for specific tasks. Provides built-in chat interface alongside integrations with Claude Desktop, Cursor, VS Code, and other AI development tools.', '@unknown', 'development', 'Unknown', 0, 'https://nexus.civic.com', NULL, 0, NULL, '2026-03-09T05:21:01.933882+00:00'),
  ('civitai', 'Civitai', 'MCP server implementation by Cicatriiz that provides AI assistants with complete access to the Civitai API for browsing and discovering AI models, generated images, and creator profiles. Built with TypeScript using robust Zod schema validation and comprehensive error handling, the implementation offers 14 specialized tools including advanced model search with filtering by type, creator, tags, and base models, popularity and rating-based browsing, generated image galleries with metadata and generation parameters, creator portfolio exploration, and direct download URL access with authentication support. The server handles all major model types (Checkpoint, LORA, ControlNet, TextualInversion, etc.) with NSFW content filtering, commercial use permissions, and content safety information including pickle and virus scan results, making it valuable for AI researchers exploring model ecosystems, developers integrating Civitai''s model repository into applications, and content creators discovering trending models and generation techniques.', '@cicatriiz', 'development', 'Unknown', 9, 'https://github.com/cicatriiz/civitai-mcp-server', NULL, 0, 'https://github.com/cicatriiz.png?size=128', '2026-03-09T05:21:01.933917+00:00'),
  ('civo', 'Civo', 'This MCP server provides AI assistants with complete access to the Civo cloud platform API for managing cloud infrastructure, built by Jintao Zhang using TypeScript with comprehensive instance lifecycle management, network operations, and Kubernetes cluster orchestration. The implementation offers tools for creating, managing, resizing, and deleting cloud instances, disk image operations, network management including creation and deletion, Kubernetes cluster management with version selection, and resource discovery through regions and sizes listing, all with built-in rate limiting to prevent API abuse. Built with Docker support, multi-platform compatibility, and extensive test coverage, it serves developers building cloud automation workflows, teams requiring programmatic access to Civo''s cloud infrastructure, and AI assistants needing to provision and manage cloud resources without manual dashboard interactions.', '@tao12345666333', 'cloud', 'Unknown', 3, 'https://github.com/tao12345666333/civo-mcp', 'civo-mcp', 719, 'https://github.com/tao12345666333.png?size=128', '2026-03-09T05:21:01.933943+00:00'),
  ('gin-mcp', 'Gin-MCP', 'Gin-MCP is a zero-configuration bridge that automatically exposes existing Gin API endpoints as Model Context Protocol tools. Developed by Anthony WK Chan, this implementation allows developers to integrate their Gin applications with MCP-compatible clients like Cursor with minimal setup—just a single line of code. The library intelligently discovers routes, infers schemas from Go structs, and handles all the MCP communication details through Server-Sent Events. Particularly valuable for teams looking to make their existing APIs instantly accessible to AI assistants without writing tedious boilerplate code.', '@ckanthony', 'development', 'Unknown', 69, 'https://github.com/ckanthony/gin-mcp', NULL, 0, 'https://github.com/ckanthony.png?size=128', '2026-03-09T05:21:01.933981+00:00'),
  ('openapi-swagger-converter', 'OpenAPI Swagger Converter', 'OpenAPI-MCP is a dockerized server that automatically converts Swagger/OpenAPI specifications into Model Context Protocol toolsets, enabling AI agents to interact with any API without additional coding. Built in Go, it handles both OpenAPI v2 and v3 formats, securely manages API keys, supports filtering operations by tags, and injects custom headers for authentication. The implementation features a robust connection manager for Server-Sent Events, JSON-RPC request handling, and dynamic request construction with parameter mapping. Particularly valuable for developers who want to quickly expose existing APIs to AI assistants like Cursor without writing custom MCP implementations for each service.', '@ckanthony', 'cloud', 'Unknown', 175, 'https://github.com/ckanthony/openapi-mcp', NULL, 0, 'https://github.com/ckanthony.png?size=128', '2026-03-09T05:21:01.934006+00:00'),
  ('io-github-simplyliz-ckb', 'io.github.SimplyLiz/ckb', 'Code intelligence MCP server — 80+ tools for navigation, impact analysis, and architecture', '@simplyliz', 'development', 'Unknown', 69, 'https://github.com/simplyliz/codemcp', NULL, 0, 'https://github.com/simplyliz.png?size=128', '2026-03-09T05:21:01.934023+00:00'),
  ('docker-compose', 'Docker Compose', 'This MCP server, developed by ckreiling, provides seamless integration with Docker containers. It implements a Python-based interface for managing containers, images, networks, and volumes through the Docker SDK. The server exposes tools for common Docker operations like creating, running, and removing containers, as well as fetching logs and stats. By leveraging natural language processing, it enables AI assistants to easily compose and manage Docker deployments through conversational interactions. The implementation is particularly useful for scenarios requiring dynamic container orchestration, such as deploying microservices, setting up development environments, or managing containerized applications through natural language commands to an AI assistant. The server focuses on core Docker functionality while prioritizing safety by restricting access to sensitive options.', '@ckreiling', 'cloud', 'Unknown', 684, 'https://github.com/ckreiling/mcp-server-docker', NULL, 0, 'https://github.com/ckreiling.png?size=128', '2026-03-09T05:21:01.934049+00:00'),
  ('education-data-api', 'Education Data API', 'An MCP server that provides access to the Urban Institute''s Education Data API, enabling AI assistants like Claude to retrieve and analyze educational statistics. The server exposes tools for fetching detailed and aggregated education data across various levels (schools, districts, universities), sources (CCD, IPEDS, CRDC), and topics (enrollment, finance, assessment). Built with TypeScript and the MCP SDK, it simplifies complex data retrieval operations through structured parameters and filters, making it valuable for educational research, policy analysis, and data visualization without requiring specialized API knowledge.', '@ckz', 'development', 'Unknown', 2, 'https://github.com/ckz/edu_data_mcp_server', NULL, 0, 'https://github.com/ckz.png?size=128', '2026-03-09T05:21:01.934079+00:00'),
  ('flux-schnell-replicate', 'Flux Schnell (Replicate)', 'Flux-Schnell-MCP provides a bridge between Claude and Replicate''s flux-schnell image generation model. This TypeScript implementation creates an MCP server that exposes a single ''generate_image'' tool, which accepts text prompts and communicates with the Replicate API to generate images. The server runs on stdio transport for compatibility with Claude Desktop, includes error handling for API failures, and requires a Replicate API token for authentication. It''s particularly useful for generating images directly within conversations without switching contexts.', '@ckz', 'development', 'Unknown', 3, 'https://github.com/ckz/flux-schnell-mcp', NULL, 0, 'https://github.com/ckz.png?size=128', '2026-03-09T05:21:01.934135+00:00'),
  ('clado-ai', 'Clado AI', 'The Clado MCP server provides LinkedIn data enrichment and search capabilities through the Clado AI platform, offering five specialized tools for professional networking intelligence. Built by Clado AI, it enables searching for LinkedIn users with filters, enriching profile data from URLs, retrieving contact information including emails and phone numbers with reverse lookup support, scraping detailed profile content with posts and comments, and analyzing post engagement metrics. The implementation uses a credit-based pricing model where different operations consume varying amounts of credits (1-10 credits depending on the tool), making it useful for sales prospecting, recruitment workflows, competitive intelligence, and building comprehensive professional contact databases.', '@freesolo-co', 'databases', 'Unknown', 5, 'https://github.com/freesolo-co/search-mcp', NULL, 0, 'https://github.com/freesolo-co.png?size=128', '2026-03-09T05:21:01.934149+00:00'),
  ('fdic-bankfind', 'FDIC BankFind', 'FDIC Bank Find MCP Server provides a Rust-based proxy for the FDIC BankFind API, enabling AI assistants to access detailed financial institution data through the Model Context Protocol. Developed by Cali LaFollett, it features auto-generated handlers for multiple endpoints including institutions, locations, failures, and demographics, with robust parameter validation, error handling, and logging. The implementation supports both stdio and SSE transport methods, includes graceful shutdown and hot reload capabilities, and is containerized with Docker for easy deployment. This server is particularly valuable for financial analysis, banking research, and regulatory compliance use cases where accessing structured FDIC data directly from AI tools streamlines workflows.', '@clafollett', 'cloud', 'Unknown', 4, 'https://github.com/clafollett/fdic-bank-find-mcp-server', NULL, 0, 'https://github.com/clafollett.png?size=128', '2026-03-09T05:21:01.934174+00:00'),
  ('clappia', 'Clappia', 'A comprehensive MCP server for the Clappia no-code platform that provides full-featured integration with Clappia''s form and workflow management system. Built using FastMCP and the clappia-tools library, it exposes tools for retrieving and aggregating form submissions with advanced filtering capabilities, creating and editing submissions, managing submission status and ownership, and complete app lifecycle management including creating apps, adding fields, and updating field configurations. The implementation features robust validation for email addresses and API parameters, comprehensive error handling with detailed logging, and supports complex data operations like aggregations with dimensions and custom filtering using Clappia''s query language, making it useful for workflow automation, data analysis and reporting, form management systems, and building AI-powered business process applications on top of Clappia''s platform.', '@clappia-dev', 'development', 'Unknown', 1, 'https://github.com/clappia-dev/clappia-mcp', NULL, 0, 'https://github.com/clappia-dev.png?size=128', '2026-03-09T05:21:01.934204+00:00'),
  ('prisma-cloud-docs', 'Prisma Cloud Docs', 'This MCP server provides search access to Prisma Cloud documentation by crawling and indexing pages from both the main Prisma Cloud docs site and API documentation. Built by Matt Clarke using Python with FastMCP, aiohttp, and BeautifulSoup, it implements a caching system with TTL expiration and offers tools to index documentation sites (with configurable page limits), search across all docs or specific sites, and check indexing status. The server extracts clean text content from web pages, implements relevance scoring based on title and content matches, and returns structured results with snippets and URLs, making it useful for developers and security teams who need quick access to Prisma Cloud documentation without manual browsing.', '@clarkemn', 'ai-ml', 'Unknown', 3, 'https://github.com/clarkemn/prisma-cloud-docs-mcp-server', 'prisma-cloud-docs-mcp-server', 1845, 'https://github.com/clarkemn.png?size=128', '2026-03-09T05:21:01.934258+00:00'),
  ('claude-agents-power', 'Claude Agents Power', 'The Claude Agents Power MCP Server provides a comprehensive collection of pre-built AI agent personas for professional roles across business, technology, and operations. Created by hongsw, it includes over 150 specialized agents in multiple languages (English, Korean, Japanese, Chinese) covering roles from software engineers and data scientists to executives and compliance officers. Each agent comes with defined capabilities, key practices, and role-specific guidance, enabling users to quickly invoke domain expertise for tasks like code reviews, financial analysis, marketing strategy, or project management without needing to craft detailed prompts from scratch.', '@hongsw', 'development', 'Unknown', 9, 'https://github.com/hongsw/claude-agents-power-mcp-server', NULL, 0, 'https://github.com/hongsw.png?size=128', '2026-03-09T05:21:01.934287+00:00'),
  ('claude-browser', 'Claude Browser', 'A browser automation MCP server built with Playwright that provides web interaction capabilities through standardized tools for navigation, content extraction, form filling, screenshot capture, and JavaScript execution. The implementation uses a multi-stage Docker setup with proper resource management and security configurations, supporting both headless and headed browser modes with configurable timeouts and viewport settings. Designed for AI assistants that need reliable web automation capabilities, it handles common browser tasks like navigating to URLs, extracting page content with optional CSS selectors, clicking elements, filling forms with automatic submission, and capturing screenshots of full pages or specific elements.', '@sac916', 'cloud', 'Unknown', 1, 'https://github.com/sac916/claude-browser-mcp', NULL, 0, 'https://github.com/sac916.png?size=128', '2026-03-09T05:21:01.934312+00:00'),
  ('claude-in-excel', 'Claude in Excel', 'Claude in Excel is a Microsoft Office add-in that brings Claude AI directly into Excel spreadsheets. It supports MCP connectors, letting Claude work with external tools and data sources — like S&P Global, LSEG, Daloopa, Pitchbook, Moody''s, and FactSet — right from within Excel. Connectors configured in your Claude settings automatically work in Excel without additional setup.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('math-learning', 'Math Learning', 'Provides mathematical operations, statistical calculations, financial computations, unit conversions, and data visualization capabilities. Features persistent cross-session storage for variables and calculations, safe expression evaluation with security logging, and matrix operations including multiplication, transposition, determinant, and eigenvalue calculations. Generates visualizations as base64-encoded PNG images including function plots, histograms, and various chart types.', '@clouatre-labs', 'development', 'Unknown', 3, 'https://github.com/clouatre-labs/math-mcp-learning-server', NULL, 0, 'https://github.com/clouatre-labs.png?size=128', '2026-03-09T05:21:01.935008+00:00'),
  ('cloudbees-unify', 'CloudBees Unify', 'This MCP server connects AI agents to CloudBees Unify''s enterprise DevOps platform, providing unified context and control across hybrid CI/CD environments. Built by CloudBees as part of their Unify vision, it bridges LLM-powered agents with DevOps data and tooling through the Model Context Protocol, enabling natural language interactions with pipeline data, security scans, and delivery workflows. The implementation transforms isolated DevOps tools into an intelligent, context-aware system where AI agents can query real-time pipeline status, trigger CI/CD actions, and access unified analytics without context switching, making it valuable for enterprise teams seeking to integrate AI-driven automation into their existing Jenkins, GitHub Actions, and hybrid toolchain environments.', '@unknown', 'development', 'Unknown', 0, 'https://www.cloudbees.com/blog/introducing-cloudbees-mcp-server', NULL, 0, NULL, '2026-03-09T05:21:01.935034+00:00'),
  ('cloudbet-sports', 'Cloudbet Sports', 'This MCP server provides AI assistants with access to Cloudbet''s sports betting API for retrieving live sports data and betting markets across multiple sports including soccer, basketball, tennis, and more. Built by Cloudbet as a single-file Go implementation, it features fuzzy search capabilities for finding competitions by name, automatic indexing of sports and competitions with hourly updates, and tools for fetching upcoming events with their primary betting markets and odds. The server includes a placeholder for authenticated bet placement functionality and uses Levenshtein distance matching to handle natural language competition queries, making it useful for building AI assistants that need access to real-time sports betting data and market information without requiring deep knowledge of the underlying sports API structure.', '@cloudbet', 'development', 'Unknown', 10, 'https://github.com/cloudbet/sports-mcp-server', NULL, 0, 'https://github.com/cloudbet.png?size=128', '2026-03-09T05:21:01.935065+00:00'),
  ('cloudflare-ai-gateway', 'Cloudflare AI Gateway', 'The Cloudflare MCP server implementation appears to be experiencing issues with repository access or configuration. This error indicates that the Git clone operation for the ''cloudflare/mcp-server-cloudflare'' repository failed, suggesting either the repository doesn''t exist publicly, has restricted access permissions, or there might be connectivity problems with the source control system. Without access to the implementation details, it''s not possible to provide an accurate description of its purpose or functionality.', '@cloudflare', 'cloud', 'Unknown', 3512, 'https://github.com/cloudflare/mcp-server-cloudflare/tree/HEAD/apps/ai-gateway', NULL, 0, 'https://github.com/cloudflare.png?size=128', '2026-03-09T05:21:01.935087+00:00'),
  ('cloudflare-audit-logs', 'Cloudflare Audit Logs', 'Cloudflare Audit Logs MCP server provides secure access to Cloudflare account activity logs through a standardized interface. Built on Cloudflare Workers, it authenticates users via OAuth, retrieves detailed audit information about account changes, and presents the data in a structured format optimized for AI assistants. The server leverages Durable Objects for state management and implements comprehensive filtering options for querying logs by time period, actor, action type, and resource scope. It''s particularly valuable for security monitoring, compliance tracking, and investigating configuration changes across Cloudflare accounts.', '@cloudflare', 'cloud', 'Unknown', 3512, 'https://github.com/cloudflare/mcp-server-cloudflare/tree/HEAD/apps/auditlogs', NULL, 0, 'https://github.com/cloudflare.png?size=128', '2026-03-09T05:21:01.935108+00:00'),
  ('cloudflare-autorag', 'Cloudflare AutoRAG', 'The Cloudflare MCP server implementation appears to be experiencing issues with repository access or configuration. This error indicates that the Git clone operation for the ''cloudflare/mcp-server-cloudflare'' repository failed, suggesting either the repository doesn''t exist publicly, has restricted access permissions, or there might be connectivity problems with the source control system. Without access to the implementation details, it''s not possible to provide an accurate description of its purpose or functionality.', '@cloudflare', 'cloud', 'Unknown', 3512, 'https://github.com/cloudflare/mcp-server-cloudflare/tree/HEAD/apps/autorag', NULL, 0, 'https://github.com/cloudflare.png?size=128', '2026-03-09T05:21:01.935127+00:00'),
  ('sandbox-container', 'Sandbox Container', 'Cloudflare Container Sandbox MCP Server provides a secure, sandboxed environment for running arbitrary code through a standardized interface. Built on Cloudflare Workers with Durable Objects, it enables AI assistants to execute Python, Node.js, and shell commands in ephemeral containers while managing files through dedicated tools. The server implements Cloudflare OAuth for authentication and includes container lifecycle management to ensure resources are properly allocated and cleaned up. Particularly valuable for developers who need to test code, run visualizations, explore GitHub repositories, or analyze data directly from AI assistants without compromising security.', '@cloudflare', 'cloud', 'Unknown', 3512, 'https://github.com/cloudflare/mcp-server-cloudflare/tree/HEAD/apps/sandbox-container', NULL, 0, 'https://github.com/cloudflare.png?size=128', '2026-03-09T05:21:01.935179+00:00'),
  ('cloudflare-dex-analysis', 'Cloudflare Dex Analysis', 'The Cloudflare MCP server implementation appears to be experiencing issues with repository access or configuration. This error indicates that the Git clone operation for the ''cloudflare/mcp-server-cloudflare'' repository failed, suggesting either the repository doesn''t exist, has been moved, requires authentication, or there are network/permission issues preventing access. Without access to the repository contents, it''s not possible to provide a detailed description of this MCP server''s functionality or purpose.', '@cloudflare', 'cloud', 'Unknown', 3512, 'https://github.com/cloudflare/mcp-server-cloudflare/tree/HEAD/apps/dex-analysis', NULL, 0, 'https://github.com/cloudflare.png?size=128', '2026-03-09T05:21:01.935199+00:00'),
  ('cloudflare-dns-analytics', 'Cloudflare DNS Analytics', 'The Cloudflare MCP server implementation appears to be experiencing issues with repository access or configuration. This error indicates that the Git clone operation for the ''cloudflare/mcp-server-cloudflare'' repository failed, suggesting either the repository doesn''t exist publicly, has restricted access permissions, or there might be connectivity problems with the source control system. Without access to the implementation details, it''s not possible to provide an accurate description of its purpose or functionality.', '@cloudflare', 'cloud', 'Unknown', 3512, 'https://github.com/cloudflare/mcp-server-cloudflare/tree/HEAD/apps/dns-analytics', NULL, 0, 'https://github.com/cloudflare.png?size=128', '2026-03-09T05:21:01.935215+00:00'),
  ('cloudflare-documentation', 'Cloudflare Documentation', 'The Cloudflare Documentation MCP server connects AI assistants to Cloudflare''s documentation through Vectorize, enabling semantic search and retrieval of relevant documentation content. Built as a Cloudflare Worker with Durable Objects, it implements the Model Context Protocol to provide AI systems with contextual information about Cloudflare products and services. The server uses a vectorized database of Cloudflare documentation for efficient retrieval and supports remote MCP connections, making it ideal for developers and users who need accurate, up-to-date information about Cloudflare''s platform directly within their AI assistant workflows.', '@cloudflare', 'databases', 'Unknown', 3512, 'https://github.com/cloudflare/mcp-server-cloudflare/tree/HEAD/apps/docs-vectorize', NULL, 0, 'https://github.com/cloudflare.png?size=128', '2026-03-09T05:21:01.935227+00:00'),
  ('cloudflare-edge-services', 'Cloudflare Edge Services', 'CF-MCP-Server is a collection of Cloudflare Workers that provide AI-related API integrations through the Model Context Protocol. The implementation includes three specialized workers: mcp-image-generation for creating images using Cloudflare''s AI models, mcp-jina-api for extracting content from URLs and performing web searches, and mcp-tavily-api for comprehensive web search and content extraction capabilities. Each worker is built using TypeScript and deployed on Cloudflare''s edge network, making them highly performant and globally available. The implementation leverages Cloudflare''s infrastructure to provide secure, scalable API access for AI assistants needing image generation and web search functionality.', '@turinhub', 'cloud', 'Unknown', 0, 'https://github.com/turinhub/cf-mcp-server', NULL, 0, 'https://github.com/turinhub.png?size=128', '2026-03-09T05:21:01.935248+00:00'),
  ('cloudflare-logpush', 'Cloudflare Logpush', 'The Cloudflare Logpush MCP server enables AI assistants to interact with Cloudflare''s Logpush service, allowing users to retrieve and manage their Logpush jobs across different Cloudflare accounts. Built on Cloudflare Workers, it implements OAuth authentication with Cloudflare''s API, provides account management capabilities, and offers tools to fetch detailed information about Logpush configurations. The server handles user authentication state persistence through Durable Objects and includes environment-specific configurations for development, staging, and production deployments. It''s particularly useful for Cloudflare customers who need to monitor or troubleshoot their log delivery pipelines through conversational interfaces.', '@cloudflare', 'cloud', 'Unknown', 3512, 'https://github.com/cloudflare/mcp-server-cloudflare/tree/HEAD/apps/logpush', NULL, 0, 'https://github.com/cloudflare.png?size=128', '2026-03-09T05:21:01.935269+00:00'),
  ('cloudflare', 'Cloudflare', 'This Cloudflare MCP Server, developed by Cloudflare, provides a powerful interface for language models to interact with Cloudflare''s API. It enables AI agents to perform a wide range of Cloudflare-specific tasks including managing KV stores, R2 storage, D1 databases, and Workers. The implementation distinguishes itself by offering deep integration with Cloudflare''s unique services and infrastructure. By leveraging Cloudflare''s global network, it ensures high-performance and low-latency operations. This tool is particularly powerful for AI-driven cloud management, serverless computing, and edge network optimization, enabling more sophisticated AI assistants that can directly manipulate Cloudflare resources.', '@cloudflare', 'databases', 'Unknown', 3512, 'https://github.com/cloudflare/mcp-server-cloudflare', '@cloudflare/mcp-server-cloudflare', 99077, 'https://github.com/cloudflare.png?size=128', '2026-03-09T05:21:01.935279+00:00'),
  ('cloudflare-one-casb', 'Cloudflare One CASB', 'The Cloudflare MCP server implementation appears to be experiencing issues with repository access or configuration. This error indicates that the Git clone operation for the ''cloudflare/mcp-server-cloudflare'' repository failed, suggesting either the repository doesn''t exist publicly, has restricted access permissions, or there might be connectivity problems with the source control system. Without access to the implementation details, it''s not possible to provide an accurate description of its purpose or functionality.', '@cloudflare', 'cloud', 'Unknown', 3512, 'https://github.com/cloudflare/mcp-server-cloudflare/tree/HEAD/apps/cloudflare-one-casb', NULL, 0, 'https://github.com/cloudflare.png?size=128', '2026-03-09T05:21:01.935296+00:00'),
  ('cloudflare-browser-rendering-playwright', 'Cloudflare Browser Rendering (Playwright)', 'Playwright MCP provides browser automation capabilities through structured accessibility snapshots, enabling LLMs to interact with web pages without requiring vision models. Developed by Microsoft, this TypeScript implementation offers tools for navigation, form-filling, element interaction, and data extraction using Playwright''s accessibility tree rather than pixel-based input. The server supports both snapshot mode (default) for better performance and reliability, and vision mode for screenshot-based interactions, making it particularly valuable for web testing, data extraction, and agent-driven browser automation tasks.', '@cloudflare', 'cloud', 'Unknown', 230, 'https://github.com/cloudflare/playwright-mcp', NULL, 0, 'https://github.com/cloudflare.png?size=128', '2026-03-09T05:21:01.935320+00:00'),
  ('cloudflare-radar', 'Cloudflare Radar', 'The Cloudflare MCP server implementation appears to be experiencing issues with repository access or configuration. This error indicates that the Git clone operation for the ''cloudflare/mcp-server-cloudflare'' repository failed, suggesting either the repository doesn''t exist publicly, has restricted access permissions, or there might be connectivity problems with the source control system. Without access to the implementation details, it''s not possible to provide an accurate description of its purpose or functionality.', '@cloudflare', 'cloud', 'Unknown', 3512, 'https://github.com/cloudflare/mcp-server-cloudflare/tree/HEAD/apps/radar', NULL, 0, 'https://github.com/cloudflare.png?size=128', '2026-03-09T05:21:01.935336+00:00'),
  ('cloudflare-workers', 'Cloudflare Workers', 'This MCP transport for Cloudflare Workers, developed by Cloudflare, enables seamless integration of MCP capabilities into serverless edge computing environments. Built with TypeScript and leveraging Cloudflare''s Workers platform, it provides a standardized interface for deploying MCP-compatible services at the network edge. The implementation supports rapid development and deployment of AI-assisted applications, taking advantage of Cloudflare''s global network for low-latency, scalable MCP services. It''s particularly useful for developers looking to build AI-powered applications that require edge computing capabilities, such as real-time content processing, personalized user experiences, or distributed AI inference.', '@cloudflare', 'cloud', 'Unknown', 627, 'https://github.com/cloudflare/workers-mcp', 'workers-mcp', 307469, 'https://github.com/cloudflare.png?size=128', '2026-03-09T05:21:01.935356+00:00'),
  ('cloudflare-workers-via-bindings', 'Cloudflare Workers (via Bindings)', 'The Cloudflare MCP server implementation appears to be experiencing issues with repository access or configuration. This error indicates that the Git clone operation for the ''cloudflare/mcp-server-cloudflare'' repository failed, suggesting either the repository doesn''t exist publicly, has restricted access permissions, or there might be connectivity problems with the source control system. Without access to the implementation details, it''s not possible to provide an accurate description of its purpose or functionality.', '@cloudflare', 'cloud', 'Unknown', 3512, 'https://github.com/cloudflare/mcp-server-cloudflare/tree/HEAD/apps/workers-bindings', NULL, 0, 'https://github.com/cloudflare.png?size=128', '2026-03-09T05:21:01.935375+00:00'),
  ('cloudflare-workers-observability', 'Cloudflare Workers Observability', 'Cloudflare Workers Observability MCP server provides tools for analyzing logs and metrics from Cloudflare Workers deployments. Built by Cloudflare, it enables users to query the Workers Observability API to examine structured JSON logs, calculate performance metrics, and troubleshoot issues across their serverless functions. The server authenticates through Cloudflare OAuth, supports both development and production environments, and offers specialized tools for retrieving log keys, values, and running complex queries against worker telemetry data.', '@cloudflare', 'cloud', 'Unknown', 3512, 'https://github.com/cloudflare/mcp-server-cloudflare/tree/HEAD/apps/workers-observability', NULL, 0, 'https://github.com/cloudflare.png?size=128', '2026-03-09T05:21:01.935394+00:00'),
  ('cloud-foundry-butler', 'Cloud Foundry Butler', 'Cleanup stale apps and services on a Cloud Foundry foundation.', '@cf-toolsuite', 'development', 'Unknown', 3, 'https://github.com/cf-toolsuite/cf-kaizen/tree/HEAD/butler', NULL, 0, 'https://github.com/cf-toolsuite.png?size=128', '2026-03-09T05:21:01.935430+00:00'),
  ('cloud-foundry-hoover', 'Cloud Foundry Hoover', 'cf-butler has a one-to-one relationship with a Cloud Foundry foundation. cf-hoover acts as a registry and aggregator. It queries for and aggregates cf-butler instances'' data. So cf-kaizen is the home for two MCP server implementations. Consumers have a choice to configure either multiple butler client configs targeting individual cf-butler instances. Or you configure a hoover client config targeting a cf-hoover instance.', '@cf-toolsuite', 'ai-ml', 'Unknown', 3, 'https://github.com/cf-toolsuite/cf-kaizen/tree/HEAD/hoover', NULL, 0, 'https://github.com/cf-toolsuite.png?size=128', '2026-03-09T05:21:01.935467+00:00'),
  ('cloudquery', 'CloudQuery', 'CloudQuery enables querying asset inventory data through natural language. Supports three operational modes: CLI mode for configuration generation, PostgreSQL mode for users syncing to PostgreSQL databases, and Platform mode for CloudQuery Platform customers. Can be deployed locally or as an HTTP server. Integrates with AWS, Azure, GCP, and over 70 cloud and SaaS sources to build cloud asset inventory, CSPM, FinOps, and vulnerability management solutions.', '@cloudquery', 'databases', 'Unknown', 1, 'https://github.com/cloudquery/mcp-releases', NULL, 0, 'https://github.com/cloudquery.png?size=128', '2026-03-09T05:21:01.935477+00:00'),
  ('a2a-router', 'A2A Router', 'This A2A-ADK-MCP example demonstrates a multi-agent AI system that combines Google''s Agent Development Kit (ADK) with the Model Context Protocol (MCP) to create a router-based architecture for coordinating multiple specialized AI agents. The implementation features a router agent that can discover, register, and delegate tasks to remote agents, with one example being a weather service agent that provides MCP tools for weather data retrieval. Built by cloud-ru-tech, it showcases how to integrate Google''s ADK for agent orchestration with MCP for tool connectivity, supporting both streaming and non-streaming interactions, task management, and multi-modal content exchange through the A2A (Agent-to-Agent) protocol, making it valuable for building distributed AI systems where different agents handle specialized domains like weather, routing, or other services.', '@cloud-ru', 'development', 'Unknown', 5, 'https://github.com/cloud-ru/a2a-adk-mcp-example', NULL, 0, 'https://github.com/cloud-ru.png?size=128', '2026-03-09T05:21:01.935510+00:00'),
  ('mattermost', 'Mattermost', 'Provides comprehensive integration with Mattermost team collaboration platform through tools covering channels, messages, reactions, threads, users, teams, files, and bookmarks. Built with FastMCP and async HTTP client featuring retry logic and rate limiting, supports both stdio and HTTP transports with Docker deployment options. Enables managing Mattermost workspaces by creating channels, posting rich messages with Slack-style attachments, managing reactions and pins, uploading files, searching conversations, and handling team operations.', '@cloud-ru-tech', 'cloud', 'Unknown', 16, 'https://github.com/cloud-ru-tech/mcp-server-mattermost', NULL, 0, 'https://github.com/cloud-ru-tech.png?size=128', '2026-03-09T05:21:01.935532+00:00'),
  ('easysearch', 'Easysearch', 'Provides comprehensive integration with Elasticsearch and OpenSearch clusters through a unified interface compatible with INFINI Easysearch. Built with httpx for async HTTP operations, this server offers tools for cluster management, index operations, document handling, search queries, snapshot management, and administrative tasks like ILM policies and node monitoring.', '@cloudsmithy', 'productivity', 'Unknown', 2, 'https://github.com/cloudsmithy/easysearch-mcp-server', NULL, 0, 'https://github.com/cloudsmithy.png?size=128', '2026-03-09T05:21:01.935567+00:00'),
  ('postgresql-pro-plus', 'PostgreSQL Pro Plus', 'This PostgreSQL MCP server provides AI assistants with advanced database analysis and optimization capabilities, built by Crystal Corp using Python with comprehensive health monitoring, query performance analysis, and index optimization tools. The implementation offers database health checks across multiple dimensions (connections, vacuum, sequences, replication, buffer cache, constraints), query execution plan analysis with hypothetical index testing via HypoPG extension, top query identification through pg_stat_statements, and automated index recommendations with duplicate detection and bloat analysis. Built with both restricted and unrestricted access modes, connection pooling, and Docker deployment support, it serves database administrators needing AI-powered PostgreSQL optimization, developers building data-intensive applications requiring performance insights, and teams managing production databases that need automated health monitoring and query optimization recommendations.', '@cloud-thinker-ai', 'databases', 'Unknown', 5, 'https://github.com/cloud-thinker-ai/postgres-mcp-pro-plus', NULL, 0, 'https://github.com/cloud-thinker-ai.png?size=128', '2026-03-09T05:21:01.935580+00:00'),
  ('diffugen', 'DiffuGen', 'DiffuGen is an AI image generation MCP server that provides a flexible interface for creating images using multiple stable diffusion models like Flux, SDXL, and SD3. Developed by CloudWerx, it supports advanced configuration options including prompt engineering, model selection, and generation parameters, with robust error handling and logging. The implementation is designed to simplify AI image generation workflows by providing a standardized, configurable tool for developers and creative professionals.', '@cloudwerx-dev', 'ai-ml', 'Unknown', 17, 'https://github.com/cloudwerx-dev/diffugen', NULL, 0, 'https://github.com/cloudwerx-dev.png?size=128', '2026-03-09T05:21:01.935620+00:00'),
  ('gpt-image-generator', 'GPT Image Generator', 'The GPT-Image-1 MCP server provides AI assistants with direct access to OpenAI''s gpt-image-1 model for image generation and editing. Developed by CLOUDWERX, this TypeScript implementation exposes two primary tools: create_image for generating new images from text prompts, and create_image_edit for modifying existing images. The server handles all OpenAI API interactions, supports file paths or base64 encoded images as inputs, saves generated images to a configurable output directory, and provides detailed responses with token usage statistics. It''s particularly valuable for users who need to generate or edit images without leaving their AI assistant conversation context, making it ideal for creative workflows, design iterations, and visual content creation.', '@cloudwerx-dev', 'development', 'Unknown', 18, 'https://github.com/cloudwerx-dev/gpt-image-1-mcp', '@cloudwerxlab/gpt-image-1-mcp', 5745, 'https://github.com/cloudwerx-dev.png?size=128', '2026-03-09T05:21:01.935649+00:00'),
  ('cloudzero', 'CloudZero', 'CloudZero MCP server enables direct interaction with cloud cost data through the CloudZero v2 API, allowing users to query billing information, dimensions, budgets, and insights directly from Claude Desktop. Developed by Dustin Burke, it implements several specialized tools for retrieving cost data within specified date ranges, analyzing billing dimensions, and accessing budget information. The server runs as a background process on the user''s machine, making it ideal for financial teams needing to visualize and analyze cloud spending patterns, identify cost centers, and discover optimization opportunities without leaving their conversation interface.', '@burkestar', 'ai-ml', 'Unknown', 4, 'https://github.com/burkestar/cloudzero-mcp', NULL, 0, 'https://github.com/burkestar.png?size=128', '2026-03-09T05:21:01.935695+00:00'),
  ('cloudbrowser', 'CloudBrowser', 'A cloud-native solution specifically designed for LLM (Large Language Model) agents, providing an anti-association fingerprint browser environment and automated interaction APIs. There is no need to deploy a local environment, eliminating performance bottlenecks and operation and maintenance burdens, allowing developers to focus on the development of core logic.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('codeflow', 'CodeFlow', 'This CodeFlow MCP server provides semantic code analysis and search capabilities for Python codebases through AST extraction, call graph generation, and vector embeddings via ChromaDB and sentence-transformers. Built with cognitive load optimization principles, it extracts rich metadata including cyclomatic complexity, decorators, exception handling patterns, and external dependencies, then builds persistent vector stores for rapid semantic search and call graph visualization through Mermaid diagrams with LLM-optimized output modes. The implementation features real-time file watching for incremental updates, entry point detection using multiple heuristics, and comprehensive tools for function metadata retrieval, making it valuable for developers and AI assistants who need to understand complex codebases, perform semantic code search, generate architectural documentation, and navigate large Python projects efficiently.', '@mrorigo', 'development', 'Unknown', 2, 'https://github.com/mrorigo/code-flow-mcp', NULL, 0, 'https://github.com/mrorigo.png?size=128', '2026-03-09T05:21:01.936468+00:00'),
  ('citus', 'Citus', 'Provides monitoring, analysis, and management capabilities for Citus distributed PostgreSQL clusters with tools for node inspection, performance monitoring, intelligent advisors for optimization recommendations, and optional admin operations like rebalancing and shard migration through approval token-based guardrails.', '@codeforall', 'databases', 'Unknown', 2, 'https://github.com/codeforall/citus-mcp', NULL, 0, 'https://github.com/codeforall.png?size=128', '2026-03-09T05:21:01.936481+00:00'),
  ('codeforces', 'Codeforces', 'This Codeforces MCP server by Mohamed-hanfy provides AI assistants with direct access to the Codeforces competitive programming platform''s API, enabling retrieval of contest information, user profiles, submission histories, and rating changes through natural language interactions. The implementation wraps the official Codeforces API with async HTTP requests and comprehensive error handling, offering tools for contest analysis, user performance tracking, and submission monitoring. Built for competitive programmers, coaches, and analysts who want to incorporate Codeforces data into AI-powered workflows for performance analysis, contest preparation, and competitive programming insights without manually navigating the platform''s web interface.', '@mohamed-hanfy', 'development', 'Unknown', 6, 'https://github.com/mohamed-hanfy/codeforces-mcp', NULL, 0, 'https://github.com/mohamed-hanfy.png?size=128', '2026-03-09T05:21:01.936514+00:00'),
  ('xcf-xcode', 'xcf (Xcode)', 'xcf is an MCP server that enables AI assistants to directly control Xcode projects, providing automation for builds, runs, and project management. It works with Cursor, VSCode, and Claude Desktop through a simple command interface that allows users to list, select, build and run Xcode projects without leaving their AI assistant. The implementation includes intelligent file path resolution for accessing project files and maintains security boundaries to ensure safe operation within designated workspaces.', '@codefreezeai', 'development', 'Unknown', 12, 'https://github.com/codefreezeai/xcf', NULL, 0, 'https://github.com/codefreezeai.png?size=128', '2026-03-09T05:21:01.936537+00:00'),
  ('salesforce-cli', 'Salesforce CLI', 'SF-MCP is a Node.js server that exposes Salesforce CLI functionality through the Model Context Protocol, allowing AI assistants to interact with Salesforce orgs. Developed by Kevin Poorman, it dynamically discovers and registers all available SF CLI commands as MCP tools, supports project-specific command execution through configurable roots, and includes caching mechanisms for improved performance. The implementation handles contextual command execution within Salesforce project directories, making it particularly valuable for developers and administrators who need to perform Salesforce operations like querying data, deploying code, or managing orgs through AI assistants.', '@codefriar', 'development', 'Unknown', 35, 'https://github.com/codefriar/sf-mcp', 'sf-mcp', 3992, 'https://github.com/codefriar.png?size=128', '2026-03-09T05:21:01.936564+00:00'),
  ('zerodha-kite', 'Zerodha Kite', 'This MCP server provides trading automation and portfolio management through the Zerodha Kite API, enabling AI assistants to execute stock trades, monitor positions, and access real-time market data. Built by Code Glyph using TypeScript with Bun runtime, it offers 11 core tools covering user profile access, portfolio management (positions and holdings), order operations (placing, canceling, and tracking orders), market data retrieval (LTP, quotes, OHLC data), instrument discovery, margin checking, and authentication status monitoring. The implementation features OAuth-based authentication with token persistence, comprehensive error handling with automatic retry logic, and support for multiple order types (market, limit, stop-loss) across NSE, BSE, and derivative exchanges, making it valuable for algorithmic trading, portfolio analysis, and automated investment strategies in the Indian stock market.', '@linkwithjoydeep', 'development', 'Unknown', 4, 'https://github.com/linkwithjoydeep/kite-mcp', NULL, 0, 'https://github.com/linkwithjoydeep.png?size=128', '2026-03-09T05:21:01.936595+00:00'),
  ('codegraphcontext', 'CodeGraphContext', 'This MCP server provides AI-powered code analysis by indexing local Python codebases into a Neo4j graph database, enabling sophisticated relationship queries and context discovery for development workflows. Built by Shashank Shekhar Singh using Python with Neo4j, watchdog for file monitoring, and Typer for CLI interaction, it offers 12 specialized tools including code indexing with background job processing, real-time file watching for active projects, function call relationship analysis, class hierarchy exploration, dead code detection, and direct Cypher query execution. The implementation features cyclomatic complexity calculation, full-text search across code elements, import dependency tracking, and an interactive setup wizard that supports both local Neo4j installations and hosted AuraDB connections, making it valuable for developers who need programmatic access to code structure and relationships for refactoring, impact analysis, and codebase understanding tasks.', '@codegraphcontext', 'databases', 'Unknown', 1161, 'https://github.com/codegraphcontext/codegraphcontext', 'codegraphcontext', 31947, 'https://github.com/codegraphcontext.png?size=128', '2026-03-09T05:21:01.936606+00:00'),
  ('flutter-maestro', 'Flutter Maestro', 'Bridges Flutter mobile app development with Maestro UI testing by providing tools for inspecting UI hierarchies, simulating user interactions (tap, text input, scrolling), taking screenshots, and managing app state through hot reload/restart. Connects to running Flutter apps via VM Service to enable real-time testing and automation workflows, while also supporting native Maestro YAML flow creation and execution. Includes a complete example Flutter counter app with TestHooks for isolated testing.', '@code-growers', 'development', 'Unknown', 3, 'https://github.com/code-growers/flutter_maestro_mcp', NULL, 0, 'https://github.com/code-growers.png?size=128', '2026-03-09T05:21:01.936631+00:00'),
  ('codelogic', 'CodeLogic', 'Integrates with CodeLogic''s software intelligence platform to analyze code dependencies and database relationships. Provides tools to assess the impact of method changes and examine code-to-database entity connections across tables, views, and columns.', '@unknown', 'databases', 'Unknown', 0, 'https://github.com/CodeLogicIncEngineering/codelogic-mcp-server', NULL, 0, 'https://github.com/CodeLogicIncEngineering.png?size=128', '2026-03-09T05:21:01.936641+00:00'),
  ('advanced-unity-mcp', 'Advanced Unity MCP', 'This Unity Editor package provides an advanced integration bridge that allows MCP clients like Claude Desktop, Cursor, GitHub Copilot, and Windsurf to connect directly to Unity Editor instances for AI-assisted game development workflows. Built by Code Maestro AI as a Unity package (version 1.0.5) compatible with Unity 2020.3+, it includes a compiled editor DLL, custom UI assets with client logos and status indicators, and the Archivo font family for consistent branding. The implementation enables AI agents to interact with Unity projects through the Model Context Protocol, making it valuable for developers who want to leverage AI assistance for Unity scripting, scene management, asset organization, and other game development tasks while working directly within their Unity environment.', '@codemaestroai', 'development', 'Unknown', 84, 'https://github.com/codemaestroai/advanced-unity-mcp', NULL, 0, 'https://github.com/codemaestroai.png?size=128', '2026-03-09T05:21:01.936671+00:00'),
  ('code-merge', 'Code Merge', 'Code-merge-mcp is an MCP server that enables AI assistants to analyze and merge code from multiple files in a project. Built with Node.js and the official MCP SDK, it provides tools for retrieving file trees, merging content from multiple files with optional compression, and analyzing code metrics like line counts and function counts. The implementation handles file filtering through .gitignore rules and custom blacklists, while efficiently processing both individual files and entire directories. This server is particularly useful for code review workflows, project analysis, and providing AI assistants with comprehensive context about codebases without requiring them to process each file individually.', '@yy1588133', 'development', 'Unknown', 22, 'https://github.com/yy1588133/code-merge-mcp', NULL, 0, 'https://github.com/yy1588133.png?size=128', '2026-03-09T05:21:01.936697+00:00'),
  ('email', 'Email', 'This email MCP server provides IMAP and SMTP integration for AI assistants, enabling email management operations through natural language. Built by Code-MonkeyZhang as an enhancement of ai-zerolab''s original implementation, it supports both traditional email server configurations and environment variable setup for CI/CD environments. The server offers comprehensive email operations including metadata retrieval, content fetching, sending with attachments, deletion, and attachment downloads, while supporting email threading for proper conversation management. It includes security features like optional attachment downloads and automatic saving of sent emails to IMAP folders, making it suitable for automating email workflows, managing correspondence, and integrating email capabilities into AI-powered applications.', '@code-monkeyzhang', 'development', 'Unknown', 1, 'https://github.com/code-monkeyzhang/email-mcp-app', NULL, 0, 'https://github.com/code-monkeyzhang.png?size=128', '2026-03-09T05:21:01.936729+00:00'),
  ('the-code-registry', 'The Code Registry', 'Provides enterprise-grade code intelligence through a hosted analysis platform designed for business leaders. Supports creating accounts, managing projects, analyzing codebases across any tech stack, and retrieving detailed reports covering security vulnerabilities, code quality, complexity metrics, licensing, and technical debt. Integrates with GitHub, GitLab, Bitbucket, and Azure DevOps, with analysis results delivered as PDF reports.', '@the-code-registry', 'cloud', 'Unknown', 1, 'https://github.com/the-code-registry/mcp-server', NULL, 0, 'https://github.com/the-code-registry.png?size=128', '2026-03-09T05:21:01.936746+00:00'),
  ('io-github-j0hanz-code-review-analyst', 'io.github.j0hanz/code-review-analyst', 'Gemini-powered MCP server for code review analysis.', '@j0hanz', 'development', 'Unknown', 0, 'https://github.com/j0hanz/code-lens', NULL, 0, 'https://github.com/j0hanz.png?size=128', '2026-03-09T05:21:01.936761+00:00'),
  ('codereviewbuddy', 'CodeReviewBuddy', 'MCP server that helps AI coding agents interact with AI code reviewers on GitHub PRs', '@detailobsessed', 'development', 'Unknown', 0, 'https://github.com/detailobsessed/codereviewbuddy', NULL, 0, 'https://github.com/detailobsessed.png?size=128', '2026-03-09T05:21:01.936775+00:00'),
  ('shaka-packager', 'Shaka Packager', 'Shaka Packager MCP Server provides a bridge between AI assistants and Google''s Shaka Packager media processing tool, enabling video analysis, transcoding, and packaging operations through a standardized interface. Developed by Jun Heider, this Python implementation handles file path translation between Docker and host environments, offers robust error handling with structured responses, and includes pre-configured prompts for common operations like MP4 to TS conversion, VOD/live streaming packaging, content encryption, and ad insertion. The server is particularly useful for media workflow automation, streaming content preparation, and video format conversion tasks without requiring direct command-line interaction with Shaka Packager.', '@coderjun', 'cloud', 'Unknown', 4, 'https://github.com/coderjun/shaka-packager-mcp-server', NULL, 0, 'https://github.com/coderjun.png?size=128', '2026-03-09T05:21:01.936810+00:00'),
  ('codescene', 'CodeScene', 'CodeScene provides Code Health analysis tools that help AI assistants understand code quality and maintainability issues in your codebase. Running locally in Docker, it analyzes code to identify technical debt, suggest refactorings, and safeguard AI-generated code from introducing maintainability problems. Supports both CodeScene Cloud and on-premise instances with secure, local-only analysis.', '@codescene-oss', 'cloud', 'Unknown', 28, 'https://github.com/codescene-oss/codescene-mcp-server', NULL, 0, 'https://github.com/codescene-oss.png?size=128', '2026-03-09T05:21:01.936827+00:00'),
  ('code-to-tree', 'Code to Tree', 'MCP server implementation by Michael Lee that provides AI assistants with accurate Abstract Syntax Tree (AST) generation from source code across multiple programming languages including C, C++, Rust, Go, Ruby, Python, and Java. Built in C using tree-sitter parsers and the mcpc library, the implementation compiles into a single standalone binary with minimal dependencies, eliminating the need for language-specific runtime environments or complex toolchain installations. The server converts source code into S-expression formatted AST representations, making it valuable for code analysis workflows, educational tools demonstrating language syntax structures, and AI applications requiring precise understanding of code semantics rather than just text-based parsing.', '@micl2e2', 'development', 'Unknown', 81, 'https://github.com/micl2e2/code-to-tree', NULL, 0, 'https://github.com/micl2e2.png?size=128', '2026-03-09T05:21:01.936868+00:00'),
  ('com-knitli-codeweaver', 'com.knitli/codeweaver', 'CodeWeaver provides AI agents with precise context from your codebase through structural understanding rather than keyword matching. It offers hybrid semantic search across 166+ languages with full AST parsing support for 27 languages, integrating with multiple embedding providers (Voyage AI, OpenAI, Cohere, HuggingFace) and vector databases (Qdrant, Pinecone, Weaviate, ChromaDB). The platform operates with full offline capability and graceful degradation, making it suitable for both local and cloud-based deployments.', '@knitli', 'databases', 'Unknown', 7, 'https://github.com/knitli/codeweaver', NULL, 0, 'https://github.com/knitli.png?size=128', '2026-03-09T05:21:01.936885+00:00'),
  ('drupal-tools', 'Drupal Tools', 'A Drupal module that provides MCP server functionality for AI assistants working with Drupal sites. Built using the Tool API plugin system, it offers comprehensive site monitoring capabilities including security update checking, cron status analysis, watchdog log examination, content search, taxonomy browsing, user role inspection, and menu structure analysis. Features robust access control with permission-based tool categories, rate limiting for expensive operations, audit logging, and configurable read-only mode for production safety.', '@code-wheel', 'ai-ml', 'Unknown', 2, 'https://github.com/code-wheel/mcp-tools', NULL, 0, 'https://github.com/code-wheel.png?size=128', '2026-03-09T05:21:01.936926+00:00'),
  ('perplexity-advanced', 'Perplexity Advanced', 'Perplexity Advanced MCP provides a flexible interface for AI assistants to interact with both Perplexity and OpenRouter APIs, supporting simple queries and complex file attachments. Built by YeonGyu Kim, it offers a command-line interface that accepts API keys for either service through a simple configuration schema, making it easy to switch between providers. The implementation is containerized with Docker for easy deployment and uses the uv package manager for dependency management. It''s particularly valuable for workflows requiring advanced search capabilities or when working with document-based queries that need file context.', '@code-yeongyu', 'cloud', 'Unknown', 46, 'https://github.com/code-yeongyu/perplexity-advanced-mcp', 'perplexity-advanced-mcp', 4094, 'https://github.com/code-yeongyu.png?size=128', '2026-03-09T05:21:01.936950+00:00'),
  ('godot', 'Godot', 'A Model Context Protocol (MCP) implementation for the Godot game engine, allowing game developers to integrate AI capabilities into their Godot projects.', '@coding-solo', 'development', 'Unknown', 2202, 'https://github.com/coding-solo/godot-mcp', NULL, 0, 'https://github.com/coding-solo.png?size=128', '2026-03-09T05:21:01.936968+00:00'),
  ('io-github-corbat-tech-coding-standards', 'io.github.corbat-tech/coding-standards', 'AI coding standards that enforce production-grade code with DDD, SOLID, TDD guardrails.', '@corbat-tech', 'development', 'Unknown', 4, 'https://github.com/corbat-tech/coding-standards-mcp', NULL, 0, 'https://github.com/corbat-tech.png?size=128', '2026-03-09T05:21:01.936984+00:00'),
  ('winbridgeagent', 'WinBridgeAgent', 'Open-source Windows MCP server for AI assistants. File, clipboard, screenshot, process & power mgmt.', '@codyard', 'ai-ml', 'Unknown', 5, 'https://github.com/codyard/winbridgeagent', NULL, 0, 'https://github.com/codyard.png?size=128', '2026-03-09T05:21:01.937004+00:00'),
  ('file-system-operations', 'File System Operations', 'This MCP server implementation provides file system operations through a standardized interface. Built using the Model Context Protocol SDK, it offers tools for reading, creating, and listing files on the local file system. The server includes features like performance monitoring through Sentry integration and communicates via stdin/stdout using the MCP protocol, making it suitable for AI models to perform file operations in a controlled manner.', '@codyde', 'ai-ml', 'Unknown', 0, 'https://github.com/codyde/mcp-file-tool', NULL, 0, 'https://github.com/codyde.png?size=128', '2026-03-09T05:21:01.937043+00:00'),
  ('firecrawl', 'Firecrawl', 'This MCP server provides tools for crawling websites and translating content into model context using the Firecrawl API. It offers two main functionalities: scraping websites in various formats and extracting structured data based on custom schemas. The implementation integrates with Sentry for error tracking and is designed to enhance AI-assisted workflows that require web data extraction and processing.', '@codyde', 'ai-ml', 'Unknown', 2, 'https://github.com/codyde/mcp-firecrawl-tool', NULL, 0, 'https://github.com/codyde.png?size=128', '2026-03-09T05:21:01.937078+00:00'),
  ('sentry', 'Sentry', 'This MCP server implementation provides a robust integration with the Sentry error tracking platform. Developed using TypeScript, it offers tools for managing projects, analyzing issues, retrieving event details, and listing error events and replays. The server leverages Sentry''s API to enable comprehensive error monitoring and debugging capabilities. It''s designed for use cases requiring detailed error analysis, project management, and user session replay within software development and operations environments.', '@codyde', 'development', 'Unknown', 20, 'https://github.com/codyde/mcp-sentry-ts', NULL, 0, 'https://github.com/codyde.png?size=128', '2026-03-09T05:21:01.937102+00:00'),
  ('orion-vision-azure-form-recognizer', 'Orion Vision (Azure Form Recognizer)', 'Orion Vision MCP provides Azure Form Recognizer integration for document analysis and data extraction. Built with TypeScript, this server offers tools for analyzing general documents and extracting structured data from specific form types including receipts, invoices, ID documents, and business cards. The implementation handles document retrieval from URLs, processes them through Azure''s Document Intelligence services, and returns structured JSON results, making it valuable for automated document processing workflows and form data extraction tasks.', '@cognitive-stack', 'cloud', 'Unknown', 2, 'https://github.com/cognitive-stack/orion-vision-mcp', 'orion-vision-mcp', 4841, 'https://github.com/cognitive-stack.png?size=128', '2026-03-09T05:21:01.937122+00:00'),
  ('hermes-search-azure-cognitive-search', 'Hermes Search (Azure Cognitive Search)', 'Hermes Search MCP provides a bridge to Azure Cognitive Search, enabling AI assistants to search, index, and manage documents in Azure search indexes. Built with TypeScript and the FastMCP framework, it offers tools for executing search queries with filtering options, indexing or updating documents, and deleting indexes. The server supports both stdio and SSE transport protocols, making it suitable for integration with various AI platforms that need to access and manipulate structured data stored in Azure Cognitive Search.', '@cognitive-stack', 'cloud', 'Unknown', 3, 'https://github.com/cognitive-stack/hermes-search-mcp', 'hermes-search-mcp', 4701, 'https://github.com/cognitive-stack.png?size=128', '2026-03-09T05:21:01.937146+00:00'),
  ('stock-news-search-tavily', 'Stock News Search (Tavily)', 'Search Stock News MCP Server provides a specialized tool for retrieving stock-related news using the Tavily API. Built with TypeScript and FastMCP, it enables AI assistants to search for financial news about specific stocks by symbol and company name, with configurable parameters for search depth, result filtering, and domain inclusion/exclusion. The server processes multiple search query templates in parallel, filters results based on relevance scores, and returns structured news data including titles, URLs, content snippets, and publication dates. It''s particularly valuable for financial analysts, investors, and chatbots that need to access current stock market news and company information from Vietnamese financial news sources like CafeF and Nguoi Quan Sat.', '@cognitive-stack', 'development', 'Unknown', 6, 'https://github.com/cognitive-stack/search-stock-news-mcp', 'search-stock-news-mcp', 5770, 'https://github.com/cognitive-stack.png?size=128', '2026-03-09T05:21:01.937180+00:00'),
  ('volume-wall-detector', 'Volume Wall Detector', 'Volume Wall Detector MCP Server provides real-time analysis of stock trading data to identify significant price levels (volume walls) where substantial trading activity occurs. Built with TypeScript and MongoDB integration, it offers tools for fetching order book data, retrieving recent trades, and analyzing volume distribution across price points. The server calculates volume and value imbalances, tracks regular and after-hours trading patterns, and identifies key support/resistance levels based on accumulated trading activity. Particularly valuable for traders seeking to understand market structure, identify potential price reversal points, and analyze buying/selling pressure at different price levels.', '@cognitive-stack', 'databases', 'Unknown', 6, 'https://github.com/cognitive-stack/volume-wall-detector-mcp', 'volume-wall-detector-mcp', 430, 'https://github.com/cognitive-stack.png?size=128', '2026-03-09T05:21:01.937196+00:00'),
  ('google-ads', 'Google Ads', 'This MCP server implementation provides integration with Google Ads API, enabling AI assistants to access and manipulate advertising campaign data directly within conversations. The server appears to have encountered an error during setup, indicating it may be in development or experiencing configuration issues with the repository ''cohnen/mcp-google-ads''. When functioning properly, it would likely allow for campaign management, performance analysis, and optimization of Google Ads accounts without leaving the conversation interface.', '@cohnen', 'development', 'Unknown', 445, 'https://github.com/cohnen/mcp-google-ads', NULL, 0, 'https://github.com/cohnen.png?size=128', '2026-03-09T05:21:01.937221+00:00'),
  ('coinapi-and-finfeedapi', 'CoinAPI and FinFeedAPI', 'This server provides access to CoinAPI''s comprehensive cryptocurrency data platform, offering real-time prices, historical market data, exchange information, and trading metrics for thousands of digital assets. Built by CoinAPI, it enables seamless integration with their professional-grade cryptocurrency data infrastructure, supporting use cases from portfolio tracking to market analysis and trading applications.', '@unknown', 'development', 'Unknown', 0, 'https://mcp.api.apibricks.io/mcp', NULL, 0, NULL, '2026-03-09T05:21:01.937241+00:00'),
  ('coinapi-exchange-rates-historical', 'CoinAPI Exchange Rates - Historical', 'This server provides access to CoinAPI''s comprehensive historical exchange rate data for cryptocurrencies and traditional currencies. Built by CoinAPI, it offers reliable access to historical pricing data that can be used for financial analysis, backtesting, and market research. The implementation focuses on delivering accurate historical exchange rate information through a clean interface.', '@unknown', 'development', 'Unknown', 0, 'https://www.pulsemcp.com/servers/coinapi-historical-exchange-rates', NULL, 0, NULL, '2026-03-09T05:21:01.937263+00:00'),
  ('coinapi-indexes', 'CoinAPI - Indexes', 'CoinAPI offers a professional-grade MCP server that integrates with their extensive cryptocurrency data platform. The server provides access to real-time and historical market data from over 300 exchanges, covering thousands of cryptocurrencies and trading pairs. It enables retrieval of OHLCV data, order book information, trades, and comprehensive metadata about exchanges and assets. The implementation is designed for applications requiring reliable, high-quality cryptocurrency market data with enterprise-level uptime and data accuracy guarantees.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://mcp.indexes.coinapi.io/', NULL, 0, NULL, '2026-03-09T05:21:01.937300+00:00'),
  ('coinapi-real-time-exchange-rates', 'CoinAPI Real-time Exchange Rates', 'This MCP server provides access to CoinAPI''s real-time exchange rate data through a hosted endpoint at mcp-realtime.exrates.coinapi.io. Created by CoinAPI, it offers live cryptocurrency prices, exchange rates, and market data without requiring local installation or API key management. The server is designed for applications needing up-to-date financial market information and cryptocurrency pricing data.', '@unknown', 'finance', 'Unknown', 0, 'https://www.pulsemcp.com/servers/coinapi-realtime-exchange-rates', NULL, 0, NULL, '2026-03-09T05:21:01.937346+00:00'),
  ('coinbase-commerce', 'Coinbase Commerce', 'MCP Coinbase Commerce server enables AI assistants to generate and manage cryptocurrency payment links through the Coinbase Commerce API. The implementation provides two main tools: create-charge for generating payment links with customizable amounts and currencies, and get-charge for retrieving details of existing payments including their status and transaction history. Built with TypeScript and the MCP SDK, it securely handles API authentication and error states while providing a standardized interface for payment processing. This server is particularly valuable for businesses and developers who want to accept cryptocurrency payments through conversational AI without manually configuring the Coinbase Commerce API.', '@zhangzhongnan928', 'development', 'Unknown', 0, 'https://github.com/zhangzhongnan928/mcp-coinbase-commerce', NULL, 0, 'https://github.com/zhangzhongnan928.png?size=128', '2026-03-09T05:21:01.937376+00:00'),
  ('crewai-near-intents', 'CrewAI (Near Intents)', 'This MCP server, developed by Coinbase, provides AI agent and task management capabilities using the CrewAI framework. Built with Python and leveraging the OpenAI API, it offers tools for creating agents with specific roles and goals, defining tasks, and orchestrating multi-agent workflows. The implementation focuses on flexibility and ease of use, allowing for the creation of diverse AI agent teams to tackle complex tasks. It''s particularly useful for developers and researchers working on collaborative AI systems, enabling use cases such as automated research, data analysis, and problem-solving across various domains without extensive AI infrastructure setup.', '@matthewlaw1', 'productivity', 'Unknown', 6, 'https://github.com/matthewlaw1/near-intents-mcp-agentkit', NULL, 0, 'https://github.com/matthewlaw1.png?size=128', '2026-03-09T05:21:01.937419+00:00'),
  ('dexpaprika', 'DexPaprika', 'DexPaprika MCP Server provides access to decentralized exchange (DEX) data across multiple blockchain networks through a standardized interface. Developed by CoinPaprika, this implementation offers tools for querying network information, DEX listings, liquidity pool metrics, token details, and price analytics without requiring API keys. The server handles rate limiting gracefully and formats all responses as structured JSON, making it ideal for AI assistants that need to analyze cryptocurrency market data, compare liquidity pools, or track token performance across different blockchain ecosystems.', '@coinpaprika', 'ai-ml', 'Unknown', 37, 'https://github.com/coinpaprika/dexpaprika-mcp', 'dexpaprika-mcp', 6213, 'https://github.com/coinpaprika.png?size=128', '2026-03-09T05:21:01.937488+00:00'),
  ('coin-railz', 'Coin Railz', 'Coin Railz provides access to blockchain data, trading intelligence, prediction markets, and crypto analytics through x402 micropayment infrastructure. The server offers tools across trading signals, DEX analytics, traditional market sentiment, real estate data, and banking services. Built on the x402 protocol for autonomous AI agent payments using USDC on Base chain, with support for multiple blockchains including Ethereum, Polygon, and Arbitrum.', '@tdnupe3', 'ai-ml', 'Unknown', 0, 'https://github.com/tdnupe3/mcp-server-coinrailz', NULL, 0, 'https://github.com/tdnupe3.png?size=128', '2026-03-09T05:21:01.937525+00:00'),
  ('coinstats', 'CoinStats', 'The CoinStats MCP Server provides AI assistants with direct access to cryptocurrency market data, portfolio tracking, and news through the CoinStats API. Built with TypeScript and the Model Context Protocol SDK, it offers tools for retrieving coin information, market data, wallet balances, exchange integrations, and portfolio management. The server handles authentication via API keys, implements caching for improved performance, and supports both local operations and external API calls. This implementation is particularly valuable for users who need real-time cryptocurrency data, portfolio analysis, or market insights without leaving their AI conversation context.', '@coinstatshq', 'development', 'Unknown', 13, 'https://github.com/coinstatshq/coinstats-mcp', '@coinstats/coinstats-mcp', 5713, 'https://github.com/coinstatshq.png?size=128', '2026-03-09T05:21:01.937554+00:00'),
  ('journal', 'Journal', 'Journal MCP server by coji that provides AI assistants with personal journaling capabilities through markdown file storage and a web viewer interface. The implementation manages daily journal entries with time-stamped entries, automatic tag extraction from hashtags, and full-text search across all entries, storing data in XDG-compliant directories with year/month organization. Built with TypeScript using React Router for the web interface and including tools for adding entries, searching by date ranges/tags/keywords, retrieving recent entries, and viewing statistics, it serves users who want conversational access to their personal journal data while maintaining local file ownership and providing a clean web interface for browsing historical entries.', '@coji', 'development', 'Unknown', 2, 'https://github.com/coji/journal-mcp', '@coji/journal-mcp', 757, 'https://github.com/coji.png?size=128', '2026-03-09T05:21:01.937586+00:00'),
  ('colabfit', 'ColabFit', 'Provides programmatic access to the ColabFit Exchange, the world''s largest hub for machine learning interatomic potentials (MLIPs) datasets. Enables querying and downloading curated datasets for materials science and chemistry research. All content is open source and freely available in standard formats including LMDB, Parquet, and XYZ.', '@colabfit', 'databases', 'Unknown', 1, 'https://github.com/colabfit/colabfit-mcp', NULL, 0, 'https://github.com/colabfit.png?size=128', '2026-03-09T05:21:01.937596+00:00'),
  ('crawl4ai-rag', 'Crawl4AI RAG', 'This MCP server integrates web crawling capabilities from Crawl4AI with RAG (Retrieval Augmented Generation) functionality, enabling AI agents and coding assistants to crawl websites, store content in Supabase vector databases, and perform semantic searches over the crawled data. Developed by Cole Medin, it provides four essential tools: single page crawling, intelligent recursive website crawling with automatic URL type detection, source retrieval, and vector-based RAG queries with optional source filtering. The implementation is designed to be incorporated into Archon as a knowledge engine for AI coding assistants, with future plans to support different embedding models and local deployment options using Ollama.', '@coleam00', 'databases', 'Unknown', 2028, 'https://github.com/coleam00/mcp-crawl4ai-rag', NULL, 0, 'https://github.com/coleam00.png?size=128', '2026-03-09T05:21:01.937607+00:00'),
  ('mem0-long-term-memory', 'Mem0 (Long-Term Memory)', 'MCP-Mem0 is a server implementation that integrates Mem0''s long-term memory capabilities with AI agents through the Model Context Protocol. Developed by Cole Medin, it provides three essential memory management tools: storing information with semantic indexing, retrieving all stored memories, and finding relevant memories using semantic search. The server supports multiple LLM providers (OpenAI, OpenRouter, Ollama) and uses PostgreSQL for vector storage, making it particularly valuable for applications requiring persistent memory across conversations, such as personal assistants, knowledge management systems, or any AI agent that needs to recall past interactions and information.', '@coleam00', 'databases', 'Unknown', 654, 'https://github.com/coleam00/mcp-mem0', NULL, 0, 'https://github.com/coleam00.png?size=128', '2026-03-09T05:21:01.937620+00:00'),
  ('postgresql-with-github-oauth', 'PostgreSQL with GitHub OAuth', 'This MCP server provides AI assistants with secure database access through GitHub OAuth authentication and PostgreSQL integration, built by Cole Medin using Cloudflare Workers with Durable Objects for stateful session management. The implementation features role-based access control where all authenticated GitHub users can perform read-only database operations like table listing and SELECT queries, while write operations (INSERT, UPDATE, DELETE) are restricted to specific GitHub usernames defined in an allowlist. Built with TypeScript using the workers-mcp framework, Hono for HTTP handling, and the postgres library for database connectivity, it includes SQL injection protection, query validation, connection pooling optimized for Cloudflare Workers'' constraints, and optional Sentry integration for error monitoring and performance tracking. The server supports both simple math operations for testing and full PostgreSQL database management, making it valuable for teams building AI-powered database applications that need secure, authenticated access to production databases with granular permission controls based on GitHub identity.', '@coleam00', 'databases', 'Unknown', 286, 'https://github.com/coleam00/remote-mcp-server-with-auth', NULL, 0, 'https://github.com/coleam00.png?size=128', '2026-03-09T05:21:01.937633+00:00'),
  ('numpy', 'NumPy', 'This MCP server implementation provides NumPy-based mathematical operations and statistical analysis tools. It offers functions for matrix multiplication, eigendecomposition, polynomial fitting, and basic statistical measures. Developed using FastMCP, it''s designed for AI assistants requiring advanced numerical computations, data analysis, and linear algebra operations in Python environments.', '@colesmcintosh', 'productivity', 'Unknown', 3, 'https://github.com/colesmcintosh/numpy-mcp', NULL, 0, 'https://github.com/colesmcintosh.png?size=128', '2026-03-09T05:21:01.937664+00:00'),
  ('coles-woolworths', 'Coles & Woolworths', 'Australian supermarket price comparison MCP server that enables AI assistants to search for products and compare prices between Coles and Woolworths, Australia''s two major grocery retailers. Built by hung_ng__, the implementation integrates directly with both supermarket APIs to fetch real-time product information including names, prices, and units, with Coles requiring an API key while Woolworths operates without authentication. The server provides two core tools for searching each retailer separately, allowing users to easily compare grocery prices across both chains for better shopping decisions, making it valuable for Australian consumers looking to optimize their grocery spending through conversational AI interactions.', '@hung-ngm', 'ai-ml', 'Unknown', 21, 'https://github.com/hung-ngm/coles-woolworths-mcp-server', NULL, 0, 'https://github.com/hung-ngm.png?size=128', '2026-03-09T05:21:01.937714+00:00'),
  ('webmiliastra-nodes-editor', 'WebMiliastra Nodes Editor', 'Provides tools for managing WebMiliastra Nodes Editor graph documents and projects. Supports reading, writing, and validating individual graph JSON files containing nodes and edges, as well as project folders with manifest.json files that organize multiple graphs. Includes node definition lookup capabilities for discovering valid node types and their ports, schema validation using Zod, and resource access to documentation and sample data. Designed for visual node-based programming workflows and game logic graphs.', '@columbina-dev', 'productivity', 'Unknown', 5, 'https://github.com/columbina-dev/webmiliastranodeseditor-mcpserver', NULL, 0, 'https://github.com/columbina-dev.png?size=128', '2026-03-09T05:21:01.937753+00:00'),
  ('monarch-money', 'Monarch Money', 'This MCP server provides integration with Monarch Money''s personal finance platform, enabling automated access to financial data including account balances, transaction history, and budget tracking through their API. Built by colvint, it allows AI assistants to retrieve and analyze personal financial information, making it valuable for automated expense tracking, budget analysis, financial reporting, and building AI-powered personal finance management tools without manual platform access.', '@colvint', 'development', 'Unknown', 9, 'https://github.com/colvint/monarch-money-mcp', NULL, 0, 'https://github.com/colvint.png?size=128', '2026-03-09T05:21:01.937780+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('zkproof', 'ZKProof', 'zkMCP provides a Model Context Protocol server for zero-knowledge proofs using circom, enabling AI assistants to build circuits, perform trusted setup, generate proofs, and verify proofs without revealing sensitive data. Implemented in TypeScript, the server executes shell scripts that interact with circom and snarkjs, exposing four standardized tools through the MCP SDK: building circuits from Circom files, performing trusted setup, generating proofs, and verifying proofs. The repository includes a practical age verification example that demonstrates how users can prove they meet age requirements without revealing their actual birth date, showcasing the privacy benefits of zero-knowledge proofs for real-world applications.', '@colygon', 'development', 'Unknown', 9, 'https://github.com/colygon/zkpmcp', NULL, 0, 'https://github.com/colygon.png?size=128', '2026-03-09T05:21:01.937810+00:00'),
  ('comfyui-builder', 'ComfyUI Builder', 'MCP server for ComfyUI providing a knowledge base, workflow builder, real-time execution, and management of models and plugins. Enables AI agents to build and run ComfyUI image generation workflows.', '@mit9', 'development', 'Unknown', 0, 'https://github.com/mit9/mcp-comfy-ui-builder', NULL, 0, 'https://github.com/mit9.png?size=128', '2026-03-09T05:21:01.937841+00:00'),
  ('companies-in-the-uk', 'Companies in the UK', 'Query UK company information through your AI. Search companies by name or location, retrieve financial statements, calculate financial ratios, track officer appointments, and analyze business health indicators. Access UK Company data including balance sheets, director records, SIC classifications, and filing histories for millions of UK businesses.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://mcp.companiesintheuk.co.uk', NULL, 0, NULL, '2026-03-09T05:21:01.937882+00:00'),
  ('dungeon-explorer', 'Dungeon Explorer', 'A dungeon crawler MCP server built by Compose and Dragons that implements a text-based RPG system where AI assistants can explore procedurally-defined dungeons, interact with NPCs, fight monsters, and collect treasures. The server loads dungeon layouts from YAML files (like the included Crystal Caverns dungeon) and maintains player state including position, inventory, health, and experience, exposing tools for movement, combat, room inspection, and map visualization. Built in Go with HTTP transport, it''s designed for creating interactive storytelling experiences and game-based AI interactions where assistants can guide players through dungeon adventures or serve as dungeon masters for tabletop-style gaming sessions.', '@compose-and-dragons', 'ai-ml', 'Unknown', 1, 'https://github.com/compose-and-dragons/dungeon-mcp-server', NULL, 0, 'https://github.com/compose-and-dragons.png?size=128', '2026-03-09T05:21:01.937932+00:00'),
  ('windows-desktop-control', 'Windows Desktop Control', 'Windows MCP Server provides a lightweight interface for AI agents to interact with the Windows operating system through a set of specialized tools. Developed by Jeomon George, it leverages UIAutomation, PyAutoGUI, and other libraries to enable desktop automation capabilities including launching applications, executing PowerShell commands, retrieving desktop state information, and performing mouse/keyboard actions. The implementation features a tree-based approach to identify interactive UI elements across applications, making it particularly valuable for automating workflows, testing applications, or enabling AI assistants to directly control Windows desktop environments like a human user would.', '@cursortouch', 'development', 'Unknown', 4588, 'https://github.com/cursortouch/windows-mcp', NULL, 0, 'https://github.com/cursortouch.png?size=128', '2026-03-09T05:21:01.937966+00:00'),
  ('youtube-ultimate-toolkit', 'YouTube Ultimate Toolkit', 'Provides comprehensive YouTube video analysis through yt-dlp integration, offering transcript extraction with timestamp support, metadata retrieval, playlist parsing, comment fetching via YouTube API, screenshot capture, and audio clip extraction. Features advanced transcript filtering including time range selection, keyword search with context, and key segment extraction for token optimization. Supports both local stdio and remote HTTP modes with OAuth authentication.', '@comzee', 'search', 'Unknown', 3, 'https://github.com/comzee/youtube-ultimate-toolkit-mcp', NULL, 0, 'https://github.com/comzee.png?size=128', '2026-03-09T05:21:01.938015+00:00'),
  ('jailbreak', 'Jailbreak', 'Provides an educational demonstration of how a fake compliance checker might work in theory. Includes a guideline-check tool that transparently always returns positive results regardless of input, serving as a teaching example for understanding potential security considerations in LLM systems. The implementation is intentionally non-functional and openly declares its demonstrative purpose.', '@concertypin', 'ai-ml', 'Unknown', 2, 'https://github.com/concertypin/jailbreak-mcp', NULL, 0, 'https://github.com/concertypin.png?size=128', '2026-03-09T05:21:01.938047+00:00'),
  ('concordium', 'Concordium', 'Concordium MCP Server enables AI assistants to interact with the Concordium blockchain through natural language queries, providing comprehensive access to accounts, blocks, tokens, validators, smart contracts, and network information. Built by Shodipo Ayomide using TypeScript and the Concordium Web SDK, it connects to both mainnet and testnet networks via gRPC and supports multiple deployment options including local, Docker, and cloud platforms like Fly.io, Railway, and Render. The implementation offers both stdio and HTTP transport modes, making it valuable for blockchain developers, researchers, and analysts who need to query Concordium chain data, monitor validator performance, analyze token balances, or explore smart contract deployments without writing custom blockchain integration code.', '@developerayo', 'cloud', 'Unknown', 2, 'https://github.com/developerayo/concordium-mcp-server', NULL, 0, 'https://github.com/developerayo.png?size=128', '2026-03-09T05:21:01.938071+00:00'),
  ('conduit-phabricator', 'Conduit (Phabricator)', 'This MCP server provides seamless integration with Phabricator and Phorge APIs, enabling task management and project automation through the Conduit API. Built by mcpnow.io using Python with httpx for modern HTTP/2 support, it features both synchronous and asynchronous clients with modular architecture covering Maniphest (tasks), Differential (code review), Diffusion (repositories), Projects, Users, and Files. The implementation offers four core MCP tools for creating tasks, searching tasks with status filtering, retrieving specific task details, and testing API connectivity, with comprehensive error handling and environment variable configuration for secure token-based authentication. The server supports complex Phabricator workflows including task creation with owners and project assignments, advanced search constraints, and full type safety with structured responses, making it valuable for development teams automating issue tracking, code review processes, and building AI assistants that need structured access to Phabricator''s project management ecosystem.', '@cortex-app', 'development', 'Unknown', 6, 'https://github.com/cortex-app/conduit', NULL, 0, 'https://github.com/cortex-app.png?size=128', '2026-03-09T05:21:01.938108+00:00'),
  ('nano-banana-gemini-2-5-flash-image', 'Nano-Banana (Gemini 2.5 Flash Image)', 'This MCP server provides access to Google''s Gemini 2.5 Flash Image generation and editing capabilities through a TypeScript implementation that supports both creating new images from text prompts and editing existing images with optional reference images. Built with cross-platform support, it handles configuration through environment variables or local config files, automatically manages image saving to platform-appropriate directories (Documents on Windows, current directory on macOS/Linux), and includes session-based image tracking for iterative editing workflows. The implementation offers six core tools including token configuration, image generation, image editing with multi-image support, continuation editing for the last generated image, and status checking, making it suitable for AI assistants that need to create and iteratively refine visual content using Google''s latest image generation technology.', '@conechoai', 'development', 'Unknown', 111, 'https://github.com/conechoai/nano-banana-mcp', 'nano-banana-mcp', 7380, 'https://github.com/conechoai.png?size=128', '2026-03-09T05:21:01.938147+00:00'),
  ('openai-websearch', 'OpenAI WebSearch', 'The OpenAI WebSearch MCP Server provides AI assistants with access to real-time web search capabilities through OpenAI''s websearch functionality. Developed by ConechoAI, this Python-based implementation allows Claude and other AI assistants to search the web during conversations, retrieving up-to-date information not available in their training data. The server supports configurable search context sizes and user location parameters, making it particularly valuable for answering questions about current events, retrieving recent information, or accessing specialized knowledge that may be outside an assistant''s knowledge cutoff. It can be easily installed via pip or uv and configured for use with Claude.app or Zed editor.', '@conechoai', 'ai-ml', 'Unknown', 86, 'https://github.com/conechoai/openai-websearch-mcp', 'openai-websearch-mcp', 24930, 'https://github.com/conechoai.png?size=128', '2026-03-09T05:21:01.938196+00:00'),
  ('configcat', 'ConfigCat', 'Provides access to ConfigCat''s public management API for feature flag and configuration management. Enables complete CRUD operations for feature flags, configurations, environments, products, and organizations. Includes SDK documentation with code examples for implementation guidance, webhook and integration management, audit logging, member management, and stale flag detection.', '@configcat', 'development', 'Unknown', 14, 'https://github.com/configcat/mcp-server', NULL, 0, 'https://github.com/configcat.png?size=128', '2026-03-09T05:21:01.938219+00:00'),
  ('confluent-cloud', 'Confluent Cloud', 'The mcp-confluent server enables AI assistants to interact with Confluent Cloud REST APIs, allowing natural language management of Kafka topics, connectors, and Flink SQL statements. Developed by Confluent Inc., it implements the Model Context Protocol to provide a bridge between AI tools like Claude Desktop and Goose CLI and Confluent''s data streaming platform. The server supports multiple transport methods (HTTP, SSE, stdio), handles authentication through environment variables, and includes specialized tools for creating and managing streaming data resources. It''s particularly valuable for developers and data engineers who need to monitor, configure, and troubleshoot Kafka-based data pipelines through conversational AI interfaces without requiring deep technical knowledge of the underlying REST APIs.', '@confluentinc', 'databases', 'Unknown', 138, 'https://github.com/confluentinc/mcp-confluent', '@confluentinc/mcp-confluent', 2161, 'https://github.com/confluentinc.png?size=128', '2026-03-09T05:21:01.938277+00:00'),
  ('temporal-knowledge-graph', 'Temporal Knowledge Graph', 'Tracks facts with dual timestamps (creation time vs. validity time), automatically invalidating outdated information as new facts emerge. Integrates with OpenAI for entity extraction from natural language and dynamically generates custom webhook automation tools from PostgreSQL configurations. Supports both single and parallel webhook execution with conflict resolution.', '@connectimtiazh', 'databases', 'Unknown', 1, 'https://github.com/connectimtiazh/temporal-knowledge-graph-mcp-server', NULL, 0, 'https://github.com/connectimtiazh.png?size=128', '2026-03-09T05:21:01.938308+00:00'),
  ('connectsafely', 'ConnectSafely', 'ConnectSafely.ai is a commercial LinkedIn inbound lead generation platform that provides strategic engagement automation through AI-powered personalized commenting, post boosting, creator targeting, and keyword-based targeting capabilities. The platform offers MCP server access as part of their Pro and Agency plans, enabling integration with Claude Desktop and other MCP-compatible tools for programmatic LinkedIn engagement workflows. Built with platform compliance in mind, it supports B2B sales and marketing teams with analytics-driven lead generation, automated content amplification, and API access for custom automation workflows alongside native integrations with HubSpot, n8n, Zapier, and Make.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://connectsafely.ai/integrations/mcp-server', NULL, 0, NULL, '2026-03-09T05:21:01.938354+00:00'),
  ('consistent-docx', 'Consistent DOCX', 'A document conversion MCP server that provides bidirectional conversion between DOCX and Markdown formats. The server offers local DOCX-to-Markdown conversion using the mammoth library for extracting raw text content, and Markdown-to-DOCX conversion through an external API that applies styles from a reference document template. Built with TypeScript and requiring API key authentication for the conversion service, it''s particularly useful for content workflows that need to preserve document formatting while enabling easy text manipulation, such as automated document processing pipelines or content management systems that work with both formats.', '@nextdoorlaohuang-hf', 'development', 'Unknown', 1, 'https://github.com/nextdoorlaohuang-hf/consistent_docx_mcp', 'consistent-docx-mcp', 168, 'https://github.com/nextdoorlaohuang-hf.png?size=128', '2026-03-09T05:21:01.938395+00:00'),
  ('console-automation', 'Console Automation', 'MCP Console Automation server that enables AI assistants to create and manage interactive console sessions across multiple shell types (cmd, PowerShell, bash, zsh) with real-time output streaming, automatic error detection, and cross-platform support. Built with TypeScript using the MCP SDK, the implementation provides session management with process lifecycle control, intelligent error pattern matching across different programming languages and runtime environments, streaming capabilities for long-running processes, and resource monitoring with automatic cleanup. The server supports both one-shot command execution and persistent interactive sessions, making it valuable for AI agents performing development workflows, system administration tasks, debugging applications, monitoring build processes, and automating command-line operations where real-time feedback and error detection are essential.', '@ooples', 'development', 'Unknown', 21, 'https://github.com/ooples/mcp-console-automation', NULL, 0, 'https://github.com/ooples.png?size=128', '2026-03-09T05:21:01.938430+00:00'),
  ('iracing-telemetry', 'iRacing Telemetry', 'This MCP server provides real-time iRacing telemetry streaming and AI-powered racing coaching through integration with the iRacing SDK and OpenAI APIs. Built with Python and featuring both live telemetry capture and mock data simulation for development, it offers tools for telemetry analysis, car spotting, lap performance evaluation, and contextual racing advice based on current track conditions and driving data. The implementation includes voice interface capabilities, advanced telemetry processing with G-force calculations and racing line analysis, and a comprehensive event handling system that provides situational awareness and coaching feedback, making it ideal for sim racers seeking data-driven performance improvement and real-time strategic guidance during practice sessions and races.', '@consolecowboy0', 'development', 'Unknown', 1, 'https://github.com/consolecowboy0/race-mcp', NULL, 0, 'https://github.com/consolecowboy0.png?size=128', '2026-03-09T05:21:01.938461+00:00'),
  ('consolespy', 'ConsoleSpy', 'ConsoleSpy is an MCP server implementation that captures browser console logs and makes them available in the Cursor IDE. It consists of a server that captures logs, an MCP server that interfaces with Cursor, and a browser extension for sending logs. The tool supports both automatic and manual logging, provides a web interface for viewing logs, and offers easy setup and configuration for seamless integration into development workflows.', '@mgsrevolver', 'development', 'Unknown', 12, 'https://github.com/mgsrevolver/consolespy', NULL, 0, 'https://github.com/mgsrevolver.png?size=128', '2026-03-09T05:21:01.938484+00:00'),
  ('contact-authorities', 'Contact Authorities', 'Contact Authorities MCP Server enables AI assistants to log emergency contact events with rate limiting and persistent storage using Supabase. Developed by Rhys Sullivan, it provides a tool for reporting suspicious activities, cybersecurity incidents, or emergency situations through a standardized interface. The server implements IP-based rate limiting (5 requests per minute), stores events with timestamps in a database, and offers both an API endpoint for AI models and a web interface for manual submissions. Particularly useful for security monitoring systems, emergency response coordination, or compliance logging where maintaining an audit trail of authority contacts is essential.', '@rhyssullivan', 'databases', 'Unknown', 1, 'https://github.com/rhyssullivan/contact-authorities-mcp', NULL, 0, 'https://github.com/rhyssullivan.png?size=128', '2026-03-09T05:21:01.938499+00:00'),
  ('container-inc', 'Container Inc.', '@container-inc/mcp enables seamless deployment of applications to Container Inc.''s platform directly from code editors. Built by Founders Inc., this TypeScript-based server implementation uses GitHub authentication to manage repository creation, Docker image publishing, and code deployment. It features a three-step workflow: authenticating with GitHub, setting up Git repositories, and initiating containerized deployments. The server stands out by abstracting away complex deployment processes through simple editor commands, making it particularly valuable for developers looking to quickly deploy Dockerized applications without leaving their development environment.', '@f-inc', 'cloud', 'Unknown', 8, 'https://github.com/f-inc/containerinc-mcp', '@container-inc/mcp', 4052, 'https://github.com/f-inc.png?size=128', '2026-03-09T05:21:01.938525+00:00'),
  ('contemplation', 'Contemplation', 'This MCP server provides AI assistants with access to Claude''s background contemplation loop - a persistent subprocess that processes thoughts asynchronously between conversations using local Ollama models for different thinking styles. The implementation manages four types of thoughts (patterns, connections, questions, general) with configurable significance thresholds, automatically aggregates similar insights to prevent repetition, and saves high-significance insights permanently to Obsidian while storing medium-significance thoughts in temporary scratch storage for 4 days. Built with intelligent memory management that prunes old insights and learns from usage patterns, it serves users wanting continuous cognitive processing that builds context across conversations, teams needing persistent insight generation that survives between sessions, and workflows requiring background analysis that surfaces relevant patterns and connections when needed.', '@mikeybeez', 'development', 'Unknown', 3, 'https://github.com/mikeybeez/mcp-contemplation', NULL, 0, 'https://github.com/mikeybeez.png?size=128', '2026-03-09T05:21:01.938561+00:00'),
  ('content-core', 'Content Core', 'Content Core MCP Server provides intelligent content extraction from diverse media sources including URLs, documents (PDF, Office files, EPUB), videos, audio files, and images through a unified interface. Built by Luis Novo, it leverages multiple extraction engines with smart auto-detection - using Docling for documents when available, falling back to PyMuPDF, and supporting Firecrawl, Jina, or BeautifulSoup for web content based on API availability. The server handles complex workflows like YouTube transcript extraction, audio/video transcription via OpenAI Whisper, and OCR for images, making it valuable for research automation, content analysis, and building AI agents that need to process mixed media content without manual preprocessing.', '@lfnovo', 'development', 'Unknown', 135, 'https://github.com/lfnovo/content-core', 'content-core', 92562, 'https://github.com/lfnovo.png?size=128', '2026-03-09T05:21:01.938591+00:00'),
  ('contentful-official', 'Contentful (Official)', 'Official Contentful MCP server that provides AI assistants with comprehensive tools to interact with Contentful''s Content Management API, enabling full content lifecycle management including entries, content types, assets, environments, locales, tags, and AI actions. Built by Contentful''s developer experience team using TypeScript and the Model Context Protocol SDK, the implementation features a context-aware middleware system that enforces proper initialization, bulk operations for publishing/unpublishing multiple items, intelligent response summarization to handle large datasets, and specialized support for Contentful''s AI Actions feature for automated content generation. The server includes extensive tooling across all major Contentful resources with proper error handling, pagination support, and telemetry tracking, making it ideal for content teams managing large-scale content operations, developers building automated content workflows, and AI assistants that need programmatic access to headless CMS functionality with proper content modeling and localization support.', '@contentful', 'development', 'Unknown', 46, 'https://github.com/contentful/contentful-mcp-server', '@contentful/mcp-server', 20222, 'https://github.com/contentful.png?size=128', '2026-03-09T05:21:01.938631+00:00'),
  ('contentstack-brandkit', 'Contentstack BrandKit', 'This MCP server implementation provides a bridge to Contentstack''s BrandKit product, enabling AI assistants to manage knowledge vault content. It offers CRUD operations for adding, updating, deleting, and searching content in the knowledge vault through a FastMCP server with authenticated API endpoints. The implementation requires environment variables for authentication tokens and brand kit UID, making it suitable for content management workflows that need to programmatically interact with Contentstack''s knowledge vault system.', '@viveksingh-ctrl', 'ai-ml', 'Unknown', 4, 'https://github.com/viveksingh-ctrl/mcp-contentstack', NULL, 0, 'https://github.com/viveksingh-ctrl.png?size=128', '2026-03-09T05:21:01.938672+00:00'),
  ('google-air-quality', 'Google Air Quality', 'This MCP server implementation provides AI assistants with comprehensive access to Google''s Air Quality API, enabling real-time air quality queries for any location worldwide. Developed by ContexaAI in Go, it offers four primary tools for retrieving current conditions, hourly forecasts, historical measurements, and heatmap tile visualizations across eight regional index types. The server includes LLM-friendly prompts that automatically resolve natural language location names to coordinates, making it easy for AI assistants to answer air quality questions without manual geocoding. It''s particularly valuable for environmental monitoring, health-related queries, and location-based air quality analysis.', '@contexaai', 'ai-ml', 'Unknown', 0, 'https://github.com/contexaai/google-air-quality-mcp', NULL, 0, 'https://github.com/contexaai.png?size=128', '2026-03-09T05:21:01.938722+00:00'),
  ('context-foundry', 'Context Foundry', 'Autonomous build system that orchestrates AI agents through multi-phase development workflows', '@context-foundry', 'development', 'Unknown', 6, 'https://github.com/context-foundry/context-foundry', NULL, 0, 'https://github.com/context-foundry.png?size=128', '2026-03-09T05:21:01.938786+00:00'),
  ('context-generator', 'Context Generator', 'Context Generator is a PHP-based tool for creating structured documentation from various sources including files, GitHub repositories, Git diffs, and URLs. It features a modular architecture with a powerful configuration system that supports imports, variables, and custom modifiers to transform content. The implementation includes an MCP server component that exposes prompts and tools for AI assistants to interact with the filesystem, retrieve project structure, and execute custom commands. Particularly useful for generating comprehensive code documentation, analyzing changes in projects, and providing context for AI-assisted development workflows.', '@context-hub', 'development', 'Unknown', 306, 'https://github.com/context-hub/generator', NULL, 0, 'https://github.com/context-hub.png?size=128', '2026-03-09T05:21:01.938811+00:00'),
  ('context-optimizer', 'Context Optimizer', 'Context Optimizer MCP Server provides AI coding assistants with specialized tools for extracting targeted information from files, executing terminal commands with intelligent output analysis, and conducting web research without cluttering chat context. Built by Malak Sedarous, the implementation integrates with Google Gemini, Anthropic Claude, and OpenAI for LLM processing, plus Exa.ai for research capabilities, while enforcing strict security boundaries through path validation and command filtering to prevent dangerous operations. The server maintains session state for follow-up questions about previous command executions and supports cross-platform development workflows, making it valuable for developers who need focused context extraction and safe terminal automation within their AI-assisted coding environment.', '@malaksedarous', 'development', 'Unknown', 53, 'https://github.com/malaksedarous/context-optimizer-mcp-server', 'context-optimizer-mcp-server', 1156, 'https://github.com/malaksedarous.png?size=128', '2026-03-09T05:21:01.938844+00:00'),
  ('context-portal', 'Context Portal', 'Context Portal (ConPort) is a database-backed MCP server developed by GreatScottyMac that provides structured project memory management for AI assistants. Built with Python/FastAPI and SQLite, it stores project decisions, progress tracking, system patterns, and custom data in a queryable knowledge graph with vector embeddings for semantic search. The implementation supports multi-workspace environments, automatic database creation, full-text search capabilities, and comprehensive import/export functionality, making it ideal for teams wanting to replace file-based context management with a robust RAG-enabled backend that maintains project history and relationships between different types of project artifacts.', '@greatscottymac', 'databases', 'Unknown', 753, 'https://github.com/greatscottymac/context-portal', 'context-portal-mcp', 52948, 'https://github.com/greatscottymac.png?size=128', '2026-03-09T05:21:01.938867+00:00'),
  ('contextstream', 'ContextStream', 'Provides persistent memory and semantic code intelligence across AI coding tools. Features include semantic search to find code by meaning, dependency and impact analysis for understanding code relationships, automatic lesson capture from mistakes, and knowledge graphs linking decisions to code. Integrates with Cursor, Claude Code, Windsurf, VS Code, and other clients.', '@contextstream', 'development', 'Unknown', 29, 'https://github.com/contextstream/mcp-server', NULL, 0, 'https://github.com/contextstream.png?size=128', '2026-03-09T05:21:01.938891+00:00'),
  ('contextual-ai', 'Contextual AI', 'Contextual AI''s official MCP server that provides RAG (Retrieval-Augmented Generation) capabilities by bridging AI interfaces with specialized Contextual AI agents. The implementation supports both remote hosted services and local deployment, integrating seamlessly with OpenAI ChatGPT, Cursor IDE, and Claude Desktop through simple configuration files. Built for developers who want to ground their AI assistant conversations in domain-specific knowledge bases, it enables query processing, intelligent retrieval, and context-aware responses with citations, making it valuable for technical documentation assistance, specialized research workflows, and enterprise knowledge management without requiring direct API integration.', '@unknown', 'communication', 'Unknown', 0, 'https://docs.contextual.ai/user-guides/mcp-server', NULL, 0, NULL, '2026-03-09T05:21:01.938932+00:00'),
  ('continue-docs', 'Continue Docs', 'Provides programmatic access to Continue''s documentation through a search tool. Enables querying the Continue knowledge base to find relevant information about features, implementation details, code examples, and API references. Returns contextual results with titles and links to documentation pages.', '@unknown', 'development', 'Unknown', 0, 'https://continue.dev', NULL, 0, NULL, '2026-03-09T05:21:01.939018+00:00'),
  ('flux-gitops', 'Flux GitOps', 'Flux MCP Server provides a bridge between AI assistants and Kubernetes GitOps operations through the Flux CD ecosystem. Developed by ControlPlane, it offers tools for debugging Flux resources, managing Kubernetes manifests, and troubleshooting GitOps workflows with features like log retrieval, resource reconciliation, and context switching between clusters. The implementation includes both read-only tools for safely inspecting cluster state and write-capable tools for applying changes when needed. Built with Go and leveraging the Kubernetes client libraries, this server is particularly valuable for DevOps engineers and platform teams who need to diagnose Flux deployment issues, manage ResourceSets, or interact with Kubernetes clusters without leaving their AI assistant workflow.', '@controlplaneio-fluxcd', 'cloud', 'Unknown', 537, 'https://github.com/controlplaneio-fluxcd/flux-operator', NULL, 0, 'https://github.com/controlplaneio-fluxcd.png?size=128', '2026-03-09T05:21:01.939044+00:00'),
  ('voyp-call-automation', 'VOYP Call Automation', 'This MCP server, developed by Control Space BV, provides integration with the VOYP API for call automation and assistance. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers tools for interacting with VOYP''s call center and conversational AI capabilities. The implementation focuses on providing a standardized interface for AI-powered call handling, enabling use cases such as automated customer service, call routing, and intelligent voice response systems. By connecting AI models with telephony systems, this server allows for sophisticated call automation scenarios, enhancing efficiency and customer experience in call center environments.', '@paulotaylor', 'development', 'Unknown', 10, 'https://github.com/paulotaylor/voyp-mcp', 'voyp-mcp', 4715, 'https://github.com/paulotaylor.png?size=128', '2026-03-09T05:21:01.939075+00:00'),
  ('conversation-save-load', 'Conversation Save Load', 'Conversation save/load MCP server that provides AI assistants with persistent conversation storage through local file system operations. Built with TypeScript using the Model Context Protocol SDK, fs-extra, and Zod for input validation, the implementation offers two core tools: save-conversation for storing conversation summaries with unique identifiers, and load-conversation for retrieving previously saved content. Features security-hardened path validation to prevent directory traversal attacks, stores files in a dedicated ~/.mcp-conversation-save-load directory, and includes comprehensive error handling with sanitized conversation IDs restricted to alphanumeric characters, hyphens, and underscores. Designed for AI assistants that need to maintain conversation context across sessions, knowledge management workflows, and applications requiring persistent storage of dialogue summaries without external database dependencies.', '@nullmastermind', 'databases', 'Unknown', 1, 'https://github.com/nullmastermind/mcp-conversation-save-load', NULL, 0, 'https://github.com/nullmastermind.png?size=128', '2026-03-09T05:21:01.939088+00:00'),
  ('convertapi', 'ConvertAPI', 'ConvertAPI MCP server provides dynamic file format conversion capabilities through OpenAPI-driven parameter validation and extensive format support. Built in C# with .NET, it integrates with ConvertAPI''s cloud service to handle conversions between formats like PDF, DOCX, images, and more, while automatically validating parameters against the live OpenAPI specification to ensure compatibility. The implementation features two main tools: an information tool for discovering supported conversion parameters and formats, and a conversion tool that performs the actual file transformations with configurable output directories and comprehensive error handling.', '@convertapi', 'ai-ml', 'Unknown', 1, 'https://github.com/convertapi/convertapi-mcp', NULL, 0, 'https://github.com/convertapi.png?size=128', '2026-03-09T05:21:01.939133+00:00'),
  ('ebay', 'eBay', 'The server provides a single tool:
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('coresignal', 'Coresignal', 'Coresignal MCP Server provides AI assistants with direct access to extensive B2B data through a standardized interface. It connects to Coresignal''s database of 39M+ company records, 725M+ employee profiles, and 349M+ job postings, enabling AI applications to retrieve fresh, relevant business information within chat interfaces. The implementation uses Node.js with mcp-remote to establish a secure connection via API key authentication, making it ideal for use cases requiring real-time company research, talent identification, or job market analysis.', '@coresignal-com', 'databases', 'Unknown', 3, 'https://github.com/coresignal-com/coresignal-mcp', NULL, 0, 'https://github.com/coresignal-com.png?size=128', '2026-03-09T05:21:01.939551+00:00'),
  ('bookmark-lens', 'Bookmark Lens', 'Local-first bookmark manager with semantic search capabilities. Store bookmarks locally with AI-powered organization, smart tagging, and natural language queries. Built on LanceDB vector storage for efficient semantic search without requiring cloud services.', '@cornelcroi', 'ai-ml', 'Unknown', 3, 'https://github.com/cornelcroi/bookmark-lens', NULL, 0, 'https://github.com/cornelcroi.png?size=128', '2026-03-09T05:21:01.939586+00:00'),
  ('french-tax', 'French Tax', 'This French Tax MCP server provides AI assistants with access to official French tax information through web scraping and calculation tools, integrating with impots.gouv.fr, service-public.fr, and legifrance.gouv.fr to retrieve tax brackets, form details, scheme information, and legal articles. Built by Corneliu with Python and featuring comprehensive scrapers with rate limiting, caching, and retry logic, it offers 10+ tools for tax calculations (income tax, Pinel benefits, LMNP, micro-enterprise), form guidance, scheme details, and report generation in markdown or CSV formats. The implementation includes specialized analyzers for different tax scenarios, mock data for testing, and Docker deployment support, making it ideal for French tax professionals, accountants, and developers building tax-related applications who need programmatic access to current French tax regulations and automated calculation capabilities.', '@cornelcroi', 'cloud', 'Unknown', 11, 'https://github.com/cornelcroi/french-tax-mcp', 'french-tax-mcp', 3946, 'https://github.com/cornelcroi.png?size=128', '2026-03-09T05:21:01.939613+00:00'),
  ('whatsapp-business-bot', 'WhatsApp Business Bot', 'NiagaBot is a WhatsApp Business automation platform that combines AI-powered chat responses with business management features through an MCP server implementation. The system integrates Qwen3-Omni AI models via DashScope API for intelligent message processing, while providing a web dashboard for managing broadcasts, scheduled messages, auto-responses, chat flows, group management, and analytics. Built with Node.js, MongoDB, and Playwright/Puppeteer for WhatsApp Web automation, it offers both REST API and WebSocket connectivity for real-time operations, making it suitable for businesses needing scalable customer communication automation with detailed performance tracking and multi-modal AI capabilities.', '@cornmankl', 'databases', 'Unknown', 1, 'https://github.com/cornmankl/whatsapp-bot-mcp', NULL, 0, 'https://github.com/cornmankl.png?size=128', '2026-03-09T05:21:01.939628+00:00'),
  ('coroot', 'Coroot', 'The Coroot MCP Server provides seamless integration with the Coroot observability platform, exposing 61 tools across application monitoring, infrastructure management, and performance analysis through a comprehensive API client. Built by James Brink, it supports multiple authentication methods including username/password, session cookies for SSO/MFA environments, and API keys, with automatic session management and error handling. The server enables AI assistants to monitor applications in real-time, analyze logs and distributed traces, manage custom dashboards, configure integrations with Prometheus and alerting systems, perform root cause analysis, and handle project administration tasks, making it valuable for DevOps teams needing to troubleshoot issues, track deployments, and maintain observability infrastructure through natural language interactions.', '@jamesbrink', 'productivity', 'Unknown', 11, 'https://github.com/jamesbrink/mcp-coroot', 'mcp-coroot', 1692, 'https://github.com/jamesbrink.png?size=128', '2026-03-09T05:21:01.939680+00:00'),
  ('cortex', 'Cortex', 'The Cortex MCP Server provides programmatic access to the Cortex API, which manages engineering intelligence including service catalogs, teams, scorecards, and organizational metadata. Built by Cortex, it transforms their OpenAPI specification into MCP-compatible tools using FastMCP, with custom route mapping that selectively exposes endpoints marked with ''x-cortex-mcp-enabled'' extensions and enhanced component descriptions for better AI assistant interaction. The server supports multiple transport methods (stdio, HTTP, SSE) with Docker deployment, making it valuable for engineering teams who want AI assistants to query service ownership, team structures, incident response information, and organizational context without manually navigating the Cortex interface.', '@cortexapps', 'cloud', 'Unknown', 7, 'https://github.com/cortexapps/cortex-mcp', NULL, 0, 'https://github.com/cortexapps.png?size=128', '2026-03-09T05:21:01.939706+00:00'),
  ('cortex-cloud-docs', 'Cortex Cloud Docs', 'Cortex Cloud documentation search server that provides AI assistants with access to Palo Alto Networks Cortex Cloud platform documentation through web scraping and intelligent indexing. Built by Matt Clarke, the implementation crawls and caches documentation pages from both the main Cortex Cloud docs and API reference sites, using BeautifulSoup for content extraction and a custom relevance scoring algorithm that prioritizes title matches and content frequency. Features include automatic page expiration with TTL-based caching, snippet extraction around search matches, and separate tools for searching general documentation versus API-specific content, making it valuable for developers and security professionals who need conversational access to Cortex Cloud platform guidance without manually browsing documentation sites.', '@clarkemn', 'ai-ml', 'Unknown', 4, 'https://github.com/clarkemn/cortex-cloud-docs-mcp-server', 'cortex-cloud-docs-mcp-server', 1652, 'https://github.com/clarkemn.png?size=128', '2026-03-09T05:21:01.939761+00:00'),
  ('pulumi-resource-example-generator', 'Pulumi Resource Example Generator', 'Pulumi Resource Example Generator MCP server that automatically creates complete constructor examples with placeholder values for any Pulumi resource across multiple programming languages including TypeScript, Python, Go, C#, and Java. Built by corymhall, the implementation leverages Pulumi''s schema system and code generation capabilities to fetch provider schemas via the Pulumi CLI, generate intermediate PCL (Pulumi Configuration Language) representations, and transpile them into language-specific examples with all properties populated using appropriate placeholder values like ''string'' for strings and 0 for numbers. Valuable for developers learning new Pulumi providers or building documentation who need quick reference examples showing the complete API surface of resources without manually writing boilerplate code or consulting multiple documentation sources.', '@corymhall', 'cloud', 'Unknown', 2, 'https://github.com/corymhall/pulumi-example-gen-mcp', NULL, 0, 'https://github.com/corymhall.png?size=128', '2026-03-09T05:21:01.939789+00:00'),
  ('civ5-bridge', 'Civ5 Bridge', 'Bridges Civilization V gameplay with AI assistants by exporting real-time game state data through a Lua mod and Python MCP server. The implementation consists of a Civ5 mod that captures turn-by-turn game information (cities, units, technologies, diplomacy, resources) and stores it in a SQLite database, paired with an MCP server that provides tools for querying current game state, historical data, and game configuration. Designed to create an AI advisor that can analyze your civilization''s progress, suggest strategic decisions, and help players improve their gameplay without providing unfair advantages like revealing hidden information about unmet civilizations or unexplored territories.', '@corytodd', 'databases', 'Unknown', 1, 'https://github.com/corytodd/civ5-mcp', NULL, 0, 'https://github.com/corytodd.png?size=128', '2026-03-09T05:21:01.939800+00:00'),
  ('confluence', 'Confluence', 'Confluence-MCP is a server implementation that provides AI assistants with direct access to Atlassian Confluence wikis. Built with TypeScript and Bun, it offers tools for retrieving, searching, creating, and updating Confluence pages through a clean interface. The server handles authentication via API tokens, transforms Confluence''s storage format content into both plain text and markdown, and optimizes content for AI context windows. It includes robust error handling and content cleaning utilities, making it particularly valuable for teams who want to query and manage their knowledge base directly through AI assistants without switching contexts.', '@cosmix', 'development', 'Unknown', 10, 'https://github.com/cosmix/confluence-mcp', NULL, 0, 'https://github.com/cosmix.png?size=128', '2026-03-09T05:21:01.939828+00:00'),
  ('muster-moodle-must-university', 'MUSTer (Moodle & MUST University)', 'Provides automated access to Moodle learning management systems and MUST university class schedules through web scraping with Selenium. Enables retrieval of course listings, assignments, calendar events, and resource downloads, plus opens authenticated browser sessions for manual interaction. Features session management with cookie persistence, headless operation for automation, and specialized integration with MUST''s class timetable system for schedule data extraction. Designed for students and educators who need programmatic access to their Moodle content and academic scheduling information.', '@cosmostima', 'productivity', 'Unknown', 3, 'https://github.com/cosmostima/muster_mcp', NULL, 0, 'https://github.com/cosmostima.png?size=128', '2026-03-09T05:21:01.939948+00:00'),
  ('cosmwasm-blockchain', 'CosmWasm Blockchain', 'CosmWasm MCP Server provides a bridge between AI assistants and CosmWasm-based blockchains using cw-orchestrator. This Rust implementation enables programmatic interaction with smart contracts through a standardized interface, allowing for querying contract state, executing transactions, checking balances, and retrieving blockchain information. The server uses a stdio-based transport layer and supports configuration of chain connections through environment variables, making it particularly useful for AI agents that need to manage and interact with blockchain contracts without direct access to the underlying infrastructure.', '@adairrr', 'ai-ml', 'Unknown', 0, 'https://github.com/adairrr/cosmwasm-mcp', 'cw-orch-mcp', 0, 'https://github.com/adairrr.png?size=128', '2026-03-09T05:21:01.939996+00:00'),
  ('scraper', 'Scraper', 'A web scraping MCP server built by Carrotly AI that provides four core tools for extracting content from websites: raw HTML scraping, markdown conversion, plain text extraction, and link discovery. Built with FastMCP and featuring an extensible provider architecture (currently using requests with exponential backoff retry logic), it supports both single URL and batch operations with configurable concurrency, intelligent disk-based caching with TTL management, CSS selector filtering for targeted content extraction, and optional ScrapeOps proxy integration for JavaScript rendering and anti-bot bypass. The implementation includes a web dashboard for monitoring and testing, comprehensive error handling with graceful degradation, and Docker deployment support, making it useful for research automation, content analysis workflows, and building web scraping pipelines with built-in resilience and caching.', '@cotdp', 'cloud', 'Unknown', 6, 'https://github.com/cotdp/scraper-mcp', NULL, 0, 'https://github.com/cotdp.png?size=128', '2026-03-09T05:21:01.940022+00:00'),
  ('counterparty', 'Counterparty', 'Interact with Counterparty — the token protocol on Bitcoin. Query, compose, sign.', '@xcp', 'finance', 'Unknown', 0, 'https://github.com/xcp/mcp-server', NULL, 0, 'https://github.com/xcp.png?size=128', '2026-03-09T05:21:01.940067+00:00'),
  ('wordpress-org-trac', 'WordPress.org Trac', 'Provides comprehensive access to all WordPress.org Trac instances for development analysis and issue tracking. Supports searching tickets, retrieving detailed ticket information with comments, accessing changeset diffs, monitoring timeline activity, and querying instance metadata like components and milestones. Built on Cloudflare Workers for global deployment with intelligent query routing and CSV parsing with fallback mechanisms.', '@courtneyr-dev', 'cloud', 'Unknown', 2, 'https://github.com/courtneyr-dev/meta-trac', NULL, 0, 'https://github.com/courtneyr-dev.png?size=128', '2026-03-09T05:21:01.940087+00:00'),
  ('cowork-history', 'Cowork History', 'Provides hybrid search across locally stored Claude conversation history. Combines SQLite FTS5 full-text search, macOS Spotlight indexing, and optional vector embeddings via Ollama for semantic similarity matching. Works with both Claude Code and Cowork conversations, enabling recovery of filesystem paths and persistent searchable indexing.', '@egoughnour', 'databases', 'Unknown', 1, 'https://github.com/egoughnour/cowork-history', NULL, 0, 'https://github.com/egoughnour.png?size=128', '2026-03-09T05:21:01.940098+00:00'),
  ('cloud-foundry', 'Cloud Foundry', 'This Cloud Foundry MCP server, developed using Spring AI MCP, provides an LLM interface for interacting with Cloud Foundry foundations. It offers tools for managing applications, services, and resources within a Cloud Foundry environment through natural language commands. The implementation leverages the Cloud Foundry Java Client to execute operations, making it easier for AI models to perform complex Cloud Foundry tasks without deep knowledge of CF CLI commands or API endpoints. It''s particularly useful for DevOps teams and developers who want to streamline Cloud Foundry management, enabling efficient application deployment, scaling, and monitoring through AI-assisted workflows.', '@cpage-pivotal', 'productivity', 'Unknown', 11, 'https://github.com/cpage-pivotal/cloud-foundry-mcp', NULL, 0, 'https://github.com/cpage-pivotal.png?size=128', '2026-03-09T05:21:01.940137+00:00'),
  ('georgia-511', 'Georgia 511', 'This MCP server provides access to real-time traffic data from Georgia''s 511 service. Developed by cpbrad31, it offers tools for retrieving information on traffic cameras, message signs, variable speed signs, traffic events, alerts, rest areas, ports of entry, and express lanes. The implementation is designed to integrate seamlessly with MCP clients like Claude Desktop, enabling easy access to Georgia''s traffic information for various applications and analyses.', '@cpbrad31', 'ai-ml', 'Unknown', 0, 'https://github.com/cpbrad31/mcp_ga_511', NULL, 0, 'https://github.com/cpbrad31.png?size=128', '2026-03-09T05:21:01.940179+00:00'),
  ('aibolit-java-code-analyzer', 'Aibolit Java Code Analyzer', 'Aibolit MCP Server integrates with the Aibolit Java code analyzer to help AI agents identify critical design issues in Java code. Developed by Yegor Bugayenko, it provides a specialized tool that examines Java files and highlights the most serious design flaws requiring immediate refactoring, going beyond cosmetic issues to focus on maintainability, readability, and architectural concerns. The server executes the Aibolit CLI tool against specified Java files and returns actionable feedback, making it particularly valuable for AI-assisted code reviews and refactoring sessions where identifying high-impact improvements is prioritized over superficial changes.', '@cqfn', 'cloud', 'Unknown', 24, 'https://github.com/cqfn/aibolit-mcp-server', 'aibolit-mcp-server', 3492, 'https://github.com/cqfn.png?size=128', '2026-03-09T05:21:01.940255+00:00'),
  ('wordle', 'Wordle', 'This MCP server provides access to Wordle puzzle solutions through the New York Times Wordle API, built in Go using the mcp-go library. The implementation fetches daily Wordle answers for any date between 2021-05-19 and 23 days into the future by making HTTP requests to the NYT''s JSON endpoint and returning the raw response data. It''s containerized with Docker for easy deployment and includes GitHub Actions for automated publishing to GitHub Container Registry, making it useful for building AI assistants that can help with Wordle puzzles, analyze word patterns, or provide hints without spoiling the game experience.', '@cr2007', 'cloud', 'Unknown', 3, 'https://github.com/cr2007/mcp-wordle-go', NULL, 0, 'https://github.com/cr2007.png?size=128', '2026-03-09T05:21:01.940276+00:00'),
  ('higress-ai-search', 'Higress AI Search', 'This MCP server implementation provides an AI search tool that enhances AI model responses with real-time search results from various engines through Higress ai-search. Developed by cr7258, it supports internet search (Google, Bing, Quark), academic search (Arxiv), and internal knowledge search. The server is configurable via environment variables and can be run using uvx or uv, making it suitable for both production deployments and local development.', '@cr7258', 'development', 'Unknown', 5, 'https://github.com/cr7258/higress-ai-search-mcp-server', 'higress-ai-search-mcp-server', 6903, 'https://github.com/cr7258.png?size=128', '2026-03-09T05:21:01.940326+00:00'),
  ('io-github-shashwatgtm-craft-content-mcp', 'io.github.shashwatgtm/craft-content-mcp', '8 content tools: Case Studies, Newsletters, Webinars, Repurposing, Thought Leadership', '@shashwatgtm', 'development', 'Unknown', 0, 'https://github.com/shashwatgtm/craft-content-mcp', NULL, 0, 'https://github.com/shashwatgtm.png?size=128', '2026-03-09T05:21:01.940342+00:00'),
  ('agentskb', 'AgentsKB', 'Provides researched, expert-quality answers across 40+ developer domains including PostgreSQL, React, Docker, Kubernetes, and AWS. Delivers instant responses with source citations, avoiding the need for real-time web searches. Tracks breaking changes and maintains current best practices for popular technologies.', '@cranot', 'databases', 'Unknown', 7, 'https://github.com/cranot/agentskb-mcp', NULL, 0, 'https://github.com/cranot.png?size=128', '2026-03-09T05:21:01.940353+00:00'),
  ('crawlab', 'Crawlab', 'This MCP server provides a bridge between AI applications and Crawlab, a web-based distributed crawler admin platform. Developed by the Crawlab team, it offers tools for spider and task management, file operations, and resource access. The server uses FastMCP and integrates with Crawlab''s API, enabling AI-driven web scraping, task automation, and data extraction workflows.', '@crawlab-team', 'productivity', 'Unknown', 6, 'https://github.com/crawlab-team/crawlab-mcp', NULL, 0, 'https://github.com/crawlab-team.png?size=128', '2026-03-09T05:21:01.940431+00:00'),
  ('crawleo', 'Crawleo', 'Crawleo enables AI assistants to access real-time web data through web search and deep website crawling. It supports customizable search parameters including language, country, and device type, and can extract content in HTML, Markdown, or plain text formats. The service emphasizes privacy with zero data retention.', '@crawleo', 'ai-ml', 'Unknown', 10, 'https://github.com/crawleo/crawleo-mcp', NULL, 0, 'https://github.com/crawleo.png?size=128', '2026-03-09T05:21:01.940463+00:00'),
  ('brex', 'Brex', 'Brex MCP Server provides a secure bridge between AI agents and the Brex financial platform, enabling access to account information, transactions, expenses, and budget resources. Developed by Dennison Bertram, this TypeScript implementation exposes Brex API data through standardized resource handlers and tools following the MCP specification. The server implements read-only operations for sensitive financial resources, proper error handling, and rate limiting for API requests. It''s particularly valuable for financial analysts using AI tools to retrieve and analyze Brex financial data without requiring direct API access, supporting use cases like expense analysis, budget monitoring, and transaction categorization.', '@crazyrabbitltc', 'development', 'Unknown', 3, 'https://github.com/crazyrabbitltc/mcp-brex-server', NULL, 0, 'https://github.com/crazyrabbitltc.png?size=128', '2026-03-09T05:21:01.940493+00:00'),
  ('api-documentation', 'API Documentation', 'This MCP server leverages the Anthropic Claude API to provide query generation and documentation assistance capabilities. It is built with TypeScript and uses the Model Context Protocol SDK for standardized interactions. The server can be run as a standalone application or integrated into other projects. It includes features for loading custom API documentation and environment variable configuration. This implementation is well-suited for developers looking to add AI-powered querying and documentation tools to their workflows or applications.', '@crazyrabbitltc', 'development', 'Unknown', 3, 'https://github.com/crazyrabbitltc/mcp-expert-server', NULL, 0, 'https://github.com/crazyrabbitltc.png?size=128', '2026-03-09T05:21:01.940522+00:00'),
  ('code-review', 'Code Review', 'Code Review Server is an MCP implementation that enables AI assistants to perform automated code reviews using multiple LLM providers (OpenAI, Anthropic, Gemini). It integrates with Repomix to flatten repository structures for analysis, then processes the code through configurable LLM prompts focused on security, performance, quality, and maintainability. The server exposes tools for repository analysis and code review with structured output containing issues, strengths, and recommendations, making it valuable for developers seeking AI-powered code quality assessment without leaving their assistant interface.', '@crazyrabbitltc', 'development', 'Unknown', 30, 'https://github.com/crazyrabbitltc/mcp-code-review-server', NULL, 0, 'https://github.com/crazyrabbitltc.png?size=128', '2026-03-09T05:21:01.940548+00:00'),
  ('ethers-wallet', 'Ethers Wallet', 'This Ethereum wallet MCP server, implemented in TypeScript, provides a comprehensive interface for interacting with Ethereum networks and smart contracts. It leverages the ethers.js library to offer a wide range of blockchain operations, including balance queries, transaction management, gas price estimation, and ENS resolution. The server supports multiple networks and custom RPC endpoints, making it versatile for various Ethereum ecosystems. It stands out by providing a clean API that abstracts away much of the complexity of blockchain interactions, making it ideal for AI assistants, DApps, or any application requiring programmatic access to Ethereum functionality. Use cases include automated portfolio management, smart contract deployment and interaction, and blockchain data analysis.', '@crazyrabbitltc', 'development', 'Unknown', 12, 'https://github.com/crazyrabbitltc/mcp-ethers-server', NULL, 0, 'https://github.com/crazyrabbitltc.png?size=128', '2026-03-09T05:21:01.940636+00:00'),
  ('morpho', 'Morpho', 'This MCP server, developed by crazyrabbitLTC, provides a bridge to the Morpho DeFi protocol''s GraphQL API. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers tools for querying market data, vaults, positions, and historical APY information. The implementation focuses on data validation, error handling, and comprehensive pagination options. It''s particularly useful for AI agents and applications needing to analyze or interact with Morpho''s lending markets, enabling use cases such as portfolio management, risk assessment, and yield optimization without directly dealing with the complexities of Morpho''s GraphQL API.', '@crazyrabbitltc', 'development', 'Unknown', 0, 'https://github.com/crazyrabbitltc/mcp-morpho-server', 'mcp-morpho-server', 272, 'https://github.com/crazyrabbitltc.png?size=128', '2026-03-09T05:21:01.940666+00:00'),
  ('tally-dao-governance', 'Tally DAO Governance', 'This MCP Tally API server, developed using TypeScript, provides a standardized interface for accessing DAO governance data through the Tally API. Built with the Model Context Protocol SDK and leveraging GraphQL, it enables AI agents to query and analyze information about DAOs, proposals, and voting activities. The server is designed for easy deployment and configuration, with environment variable management and comprehensive error handling. By abstracting the complexities of the Tally API into an MCP interface, it facilitates use cases such as DAO analytics, governance monitoring, and automated reporting on decentralized decision-making processes. This implementation is particularly valuable for researchers, DAO participants, and developers building AI-powered tools for decentralized governance analysis.', '@crazyrabbitltc', 'development', 'Unknown', 7, 'https://github.com/crazyrabbitltc/mpc-tally-api-server', NULL, 0, 'https://github.com/crazyrabbitltc.png?size=128', '2026-03-09T05:21:01.940696+00:00'),
  ('x-twitter', 'X (Twitter)', 'This Twitter MCP server, developed by Dennison Bertram, enables Large Language Models (LLMs) to interact with Twitter (X) through the Model Context Protocol. Built with TypeScript and leveraging the Twitter API v2, it provides tools for posting tweets, searching tweets, and replying to tweets. The implementation stands out by offering a straightforward setup process and integration with Claude Desktop, making it accessible for users without extensive technical knowledge. It''s particularly useful for AI assistants or applications needing to automate Twitter interactions, conduct social media research, or manage Twitter accounts programmatically, enabling tasks like sentiment analysis, trend monitoring, or automated customer engagement.', '@crazyrabbitltc', 'development', 'Unknown', 23, 'https://github.com/crazyrabbitltc/mcp-twitter-server', 'mcp-twitter-server', 913, 'https://github.com/crazyrabbitltc.png?size=128', '2026-03-09T05:21:01.940726+00:00'),
  ('vibecodermcp', 'VibeCoderMCP', 'Vibe-Coder MCP Server implements a structured development workflow that guides LLMs through feature creation with a systematic approach. It provides tools for feature clarification through iterative questioning, automatic generation of PRDs and implementation plans based on gathered requirements, and phase-based development tracking with task management. The server stores documents both in-memory and in the file system, offering a hybrid storage solution that makes it particularly valuable for AI-assisted software development where maintaining context and organization throughout the development lifecycle is essential.', '@crazyrabbitltc', 'development', 'Unknown', 17, 'https://github.com/crazyrabbitltc/mcp-vibecoder', NULL, 0, 'https://github.com/crazyrabbitltc.png?size=128', '2026-03-09T05:21:01.940753+00:00'),
  ('github-integration-hub', 'GitHub Integration Hub', 'A full-stack GitHub OAuth integration built with TypeScript that combines multiple interfaces into a single system. Provides secure authentication and token management through an Express.js REST API, a CLI tool for command-line workflows, and MCP server tools for AI agent integration. Features SQLite-based connection storage, type-safe SDK for programmatic access, and exposes GitHub operations like repository listing and issue creation through the Model Context Protocol.', '@crbatista', 'databases', 'Unknown', 1, 'https://github.com/crbatista/mcp-cli-github-integration', NULL, 0, 'https://github.com/crbatista.png?size=128', '2026-03-09T05:21:01.940765+00:00'),
  ('pulsemcp-1685', '中指房产估值', 'MCP server providing property valuation and community assessment capabilities. Enables integration of residential property evaluation and rating functionality.', '@creis-ai', 'development', 'Unknown', 3, 'https://github.com/creis-ai/mcp-property-valuation-server', NULL, 0, 'https://github.com/creis-ai.png?size=128', '2026-03-09T05:21:01.940870+00:00'),
  ('crewai-enterprise', 'CrewAI Enterprise', 'CrewAI Enterprise MCP Server provides a bridge to deployed CrewAI workflows, enabling AI assistants to kickoff crews and monitor their execution status. The server exposes two main tools: kickoff_crew for starting new crew tasks with custom inputs, and get_crew_status for checking the progress of running crews. Built with FastMCP, it communicates with the CrewAI Enterprise backend using environment variables for authentication and server URL configuration. This implementation is particularly valuable for workflows that benefit from CrewAI''s agent collaboration capabilities without leaving the Claude Desktop interface, allowing seamless delegation of complex tasks to specialized agent teams.', '@crewaiinc', 'productivity', 'Unknown', 48, 'https://github.com/crewaiinc/enterprise-mcp-server', NULL, 0, 'https://github.com/crewaiinc.png?size=128', '2026-03-09T05:21:01.940916+00:00'),
  ('colombia-geographic-data', 'Colombia Geographic Data', 'This TypeScript-based server provides comprehensive access to Colombian geographic, administrative, and cultural data through integration with the api-colombia.com service. It offers tools for retrieving information about Colombian departments, municipalities, regions, tourist attractions, natural protected areas, airports, radio stations, indigenous reservations, and presidential history. The implementation includes 15 tools organized across geography, tourism, history, infrastructure, and culture categories, making it valuable for applications requiring Colombian location data, travel planning, demographic analysis, or cultural research workflows.', '@crexative', 'development', 'Unknown', 4, 'https://github.com/crexative/colombia-mcp-server', NULL, 0, 'https://github.com/crexative.png?size=128', '2026-03-09T05:21:01.940945+00:00'),
  ('allure-test-reports', 'Allure Test Reports', 'MCP-Allure-Server provides a bridge between AI assistants and Allure test reports, enabling access to test execution data through a structured API. The server exposes a tool for parsing Allure report directories and extracting comprehensive test suite information including test cases, steps, statuses, and execution timestamps. Built with FastMCP, it transforms complex Allure JSON data into a well-organized hierarchical structure that preserves the relationships between test suites, test cases, and their execution details. This implementation is particularly valuable for development teams who need to analyze test results, track test execution metrics, or generate custom reports without leaving their AI assistant interface.', '@crisschan', 'development', 'Unknown', 9, 'https://github.com/crisschan/mcp-allure', NULL, 0, 'https://github.com/crisschan.png?size=128', '2026-03-09T05:21:01.940979+00:00'),
  ('repository-to-llm-context', 'Repository to LLM Context', 'mcp-repo2llm is a MCP server that transforms code repositories into LLM-friendly formats. A powerful tool that transforms code repositories into LLM-friendly formats, bridging the gap between traditional code bases and modern AI language models. This repo is based on RepoToTextForLLMs, which provides core functionality for converting repositories into LLM-readable formats.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('schemaflow', 'SchemaFlow', 'This MCP server provides real-time PostgreSQL schema access through SchemaFlow''s cloud-based caching service, offering three core tools for database introspection and analysis without requiring direct database connections. Built by SchemaFlow and designed for AI-powered development workflows, it connects to AI IDEs like Cursor, Windsurf, and Cline via Server-Sent Events (SSE) to deliver cached schema information including tables, columns, relationships, functions, triggers, enums, and indexes. The implementation focuses on database analysis capabilities with tools for schema validation, performance insights, and best practices alignment, making it valuable for developers who need AI assistants to understand and work with PostgreSQL database structures in real-time.', '@cryptoradi', 'databases', 'Unknown', 8, 'https://github.com/cryptoradi/schemaflow-mcp-server', NULL, 0, 'https://github.com/cryptoradi.png?size=128', '2026-03-09T05:21:01.941414+00:00'),
  ('cryptorefills', 'CryptoRefills', 'Enables purchasing gift cards, mobile top-ups, and eSIMs through CryptoRefills'' global crypto payment platform. Supports thousands of brands across 195 countries with payments in BTC, USDT, USDC, and other cryptocurrencies on multiple blockchains including Lightning Network, Ethereum, Polygon, and Solana.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://www.cryptorefills.com', NULL, 0, NULL, '2026-03-09T05:21:01.941441+00:00'),
  ('feishu-lark', 'Feishu (Lark)', 'Feishu-MCP provides a bridge between AI assistants and Feishu (also known as Lark), ByteDance''s workplace collaboration platform. Built by cso1z, this TypeScript implementation enables models to interact with Feishu''s API, allowing for document retrieval, messaging, and other collaborative features directly within AI conversations. The server can be run either as a CLI application or HTTP server, with configuration handled through environment variables. It''s particularly valuable for teams already using Feishu who want to integrate AI assistants into their existing workflow without switching contexts.', '@cso1z', 'development', 'Unknown', 481, 'https://github.com/cso1z/feishu-mcp', 'feishu-mcp', 13593, 'https://github.com/cso1z.png?size=128', '2026-03-09T05:21:01.941516+00:00'),
  ('csv-editor', 'CSV Editor', 'CSV Editor MCP server by Santosh Ray provides AI assistants with pandas-powered CSV file operations including data loading, filtering, transformation, statistical analysis, and quality validation through a session-based architecture. Built with FastMCP and featuring auto-save capabilities, operation history tracking, and support for multiple formats (CSV, Excel, Parquet), the implementation offers tools for data cleaning, outlier detection, correlation analysis, and schema validation with comprehensive error handling and type safety. Designed for data analysts, researchers, and AI workflows requiring robust CSV manipulation capabilities, it serves use cases like data preprocessing pipelines, exploratory data analysis, and automated data quality assessment where pandas functionality needs to be accessible through conversational AI interfaces.', '@santoshray02', 'ai-ml', 'Unknown', 22, 'https://github.com/santoshray02/csv-editor', NULL, 0, 'https://github.com/santoshray02.png?size=128', '2026-03-09T05:21:01.941570+00:00'),
  ('discogs', 'Discogs', 'Discogs MCP Server provides a bridge to the Discogs API, enabling AI assistants to interact with music database features including artist information, release details, user collections, and marketplace listings. Built with TypeScript and Zod for robust type validation, it exposes tools for searching the database, managing user wantlists, exporting inventory, and fetching media. The server supports both stdio and SSE transport methods, requires a Discogs personal access token for authentication, and implements comprehensive error handling for API responses. It''s particularly valuable for music enthusiasts who want to manage their Discogs collections, discover new releases, or analyze marketplace data through AI assistants.', '@cswkim', 'databases', 'Unknown', 88, 'https://github.com/cswkim/discogs-mcp-server', 'discogs-mcp-server', 6938, 'https://github.com/cswkim.png?size=128', '2026-03-09T05:21:01.941581+00:00'),
  ('rendi', 'Rendi', 'Enables cloud-based FFmpeg operations through Rendi''s API service without requiring local FFmpeg installations or compute resources. Provides tools for executing single FFmpeg commands, chaining multiple operations where outputs become inputs, polling job status with metadata retrieval, and managing output files. Supports video transcoding, audio processing, format conversion, and media analysis workflows where local FFmpeg expertise or infrastructure is limited.', '@ctaylor86', 'ai-ml', 'Unknown', 1, 'https://github.com/ctaylor86/rendi-mcp-server', NULL, 0, 'https://github.com/ctaylor86.png?size=128', '2026-03-09T05:21:01.941616+00:00'),
  ('stock-market-alpha-vantage', 'Stock Market (Alpha Vantage)', 'MCP Stock Market provides real-time access to stock market data through the Alpha Vantage API. This TypeScript-based server exposes a single tool that retrieves daily stock prices, volume, and other metrics for any stock symbol. The implementation handles API authentication, request formatting, and response parsing with proper error handling, making it particularly valuable for financial analysis, investment research, and market monitoring without leaving the conversation interface. The server includes rate-limiting awareness for the Alpha Vantage free tier (25 calls/day, 5 calls/minute) and formats responses with human-readable currency formatting.', '@ctoouli', 'development', 'Unknown', 2, 'https://github.com/ctoouli/mcp-stock-market', NULL, 0, 'https://github.com/ctoouli.png?size=128', '2026-03-09T05:21:01.941691+00:00'),
  ('strava', 'Strava', 'This MCP server implementation provides integration with the Strava API, enabling access to fitness tracking data and activity information. Developed by Christopher Vidic, it utilizes FastAPI and the Model Context Protocol SDK to offer a bridge between AI assistants and Strava''s extensive fitness ecosystem. The server is designed for use cases such as analyzing workout patterns, tracking athletic performance, and integrating fitness data into AI-powered health and wellness applications.', '@ctvidic', 'ai-ml', 'Unknown', 3, 'https://github.com/ctvidic/strava-mcp-server', NULL, 0, 'https://github.com/ctvidic.png?size=128', '2026-03-09T05:21:01.941728+00:00'),
  ('whoop', 'Whoop', 'This MCP server implementation integrates with the Whoop API, providing a bridge for accessing Whoop fitness data. Built using FastAPI and uvicorn, it offers a streamlined way to retrieve and process Whoop metrics. The server is designed for developers looking to incorporate Whoop data into their applications, enabling use cases such as fitness tracking, performance analysis, and health monitoring.', '@ctvidic', 'ai-ml', 'Unknown', 18, 'https://github.com/ctvidic/whoop-mcp-server', NULL, 0, 'https://github.com/ctvidic.png?size=128', '2026-03-09T05:21:01.941761+00:00'),
  ('cua-mcp-server', 'CUA MCP Server', 'This server enables LLMs to run Computer-Use Agent (CUA) workflows on Apple Silicon macOS. It provides asynchronous access to a virtual macOS sandbox environment using Apple’s Virtualization.framework, and supports clients like Cursor, Claude Desktop, and other MCP-compatible tools.', '@trycua', 'ai-ml', 'Unknown', 12912, 'https://github.com/trycua/cua/tree/HEAD/libs/mcp-server', 'cua-mcp-server', 10701, 'https://github.com/trycua.png?size=128', '2026-03-09T05:21:01.941797+00:00'),
  ('cube', 'Cube', 'Provides access to Cube''s analytics platform through its AI agent, enabling natural language data queries, trend analysis, and insight generation. Supports both local stdio deployment via npm package and remote HTTPS connections with OAuth authentication for Cube Cloud environments.', '@cubedevinc', 'databases', 'Unknown', 8, 'https://github.com/cubedevinc/cube-mcp-server', NULL, 0, 'https://github.com/cubedevinc.png?size=128', '2026-03-09T05:21:01.941810+00:00'),
  ('codepipeline', 'CodePipeline', 'AWS CodePipeline MCP Server provides a standardized interface for interacting with AWS CodePipeline services, enabling AI assistants to manage and monitor CI/CD pipelines through natural language commands. Built by Cuong T Nguyen, the server exposes tools for listing pipelines, triggering executions, approving actions, and retrieving pipeline metrics, making complex DevOps workflows more accessible through conversational AI interactions.', '@cuongdev', 'cloud', 'Unknown', 5, 'https://github.com/cuongdev/mcp-codepipeline-server', NULL, 0, 'https://github.com/cuongdev.png?size=128', '2026-03-09T05:21:01.941828+00:00'),
  ('database-connections', 'Database Connections', 'A TypeScript-based database server that provides a unified interface for connecting to multiple database systems (SQLite, PostgreSQL, SQL Server, and MongoDB). Built by cuongtl1992, this implementation offers flexible database interactions through a consistent API, supporting both server-sent events and standard I/O communication modes. Useful for AI assistants and applications that need to query, update, and explore database schemas across different database technologies.', '@cuongtl1992', 'databases', 'Unknown', 21, 'https://github.com/cuongtl1992/mcp-dbs', 'mcp-dbs', 886, 'https://github.com/cuongtl1992.png?size=128', '2026-03-09T05:21:01.941839+00:00'),
  ('kroger', 'Kroger', 'Kroger MCP server provides AI assistants with access to Kroger''s grocery shopping API through a comprehensive set of tools for store location management, product search, and cart operations. Developed by Stephen Thoemmes using the FastMCP framework, it handles OAuth2 authentication with browser-based flows, maintains local cart tracking since Kroger''s API doesn''t support cart viewing, and includes features like bulk cart operations, order history management, and product image retrieval. The implementation is particularly valuable for building AI shopping assistants that can help users find nearby stores, search for products with pricing and aisle information, manage shopping lists, and guide users through the complete grocery shopping workflow from product discovery to cart management.', '@cupofowls', 'development', 'Unknown', 51, 'https://github.com/cupofowls/kroger-mcp', 'kroger-mcp', 2260, 'https://github.com/cupofowls.png?size=128', '2026-03-09T05:21:01.941881+00:00'),
  ('curate-ipsum', 'Curate Ipsum', 'Code synthesis through belief revision, mutation testing, and verification.', '@egoughnour', 'development', 'Unknown', 0, 'https://github.com/egoughnour/curate-ipsum', NULL, 0, 'https://github.com/egoughnour.png?size=128', '2026-03-09T05:21:01.941900+00:00'),
  ('curioprompt', 'Curioprompt', 'Curioprompt MCP searches Curioprompt for getting new, useful and interesting prompts and will enhance the usability of Claude for Desktop. Instead of just searching, the AI experience you can have with this MCP is limitless.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://curioforce.com/curioprompt-mcp-claude', NULL, 0, NULL, '2026-03-09T05:21:01.941925+00:00'),
  ('prode', 'ProdE', 'ProdE by CuriousBox AI integrates with popular coding assistants (Cursor, GitHub Copilot, Windsurf) through MCP to provide contextual AI assistance based on your specific codebase and Knowledge Layer. The integration supports multiple transport protocols (deeplink, streamable-http, SSE) and enables developers to access repository-aware AI responses directly within their editor without context switching. Uses secure token-based authentication to deliver improved AI accuracy by understanding your repository structure, patterns, and history.', '@unknown', 'development', 'Unknown', 0, 'https://docs.prode.ai/mcp-integration/overview', NULL, 0, NULL, '2026-03-09T05:21:01.941949+00:00'),
  ('currents-test-results', 'Currents Test Results', 'Currents MCP Server provides a bridge between AI assistants and the Currents test results platform, enabling access to test execution data from CI/CD pipelines. Built with TypeScript and the Model Context Protocol SDK, it exposes tools for retrieving run information, spec file attempts, and errors through a simple API interface. The server requires a Currents API key for authentication and supports deployment via npm, making it valuable for developers who want their AI assistants to analyze failing tests, optimize test suites, or troubleshoot CI issues without leaving their conversation context.', '@currents-dev', 'development', 'Unknown', 14, 'https://github.com/currents-dev/currents-mcp', '@currents/mcp', 158027, 'https://github.com/currents-dev.png?size=128', '2026-03-09T05:21:01.941977+00:00'),
  ('currenttimeutc', 'CurrentTimeUTC', 'A time conversion and timezone utilities server that provides UTC time retrieval, timezone conversion, and timezone listing capabilities through dedicated API endpoints. Built by currenttimeutc.com, it offers three core tools for handling time-related operations: getting current UTC time, converting between different timezones, and retrieving available timezone information. Useful for applications requiring accurate time handling, scheduling across multiple timezones, or any scenario where AI assistants need to work with time-sensitive data and coordinate activities across different geographical regions.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://a.currenttimeutc.com/mcp', NULL, 0, NULL, '2026-03-09T05:21:01.942020+00:00'),
  ('cursor10x-memory', 'Cursor10x Memory', 'A memory system for Cursor that provides persistent context awareness for Claude through vector-based semantic search and structured data storage. Built by aurda012 using Turso/LibSQL as the backend, it stores conversations, code snippets, files, and other contextual information with automatically generated embeddings for similarity-based retrieval. The implementation includes unified conversation management tools that handle message storage, context retrieval, and milestone tracking in single operations, plus vector indexing with ANN search capabilities for efficient semantic matching. Designed for developers who want their AI assistant to maintain long-term memory across sessions, enabling workflows like project continuity, code pattern recognition, and contextual assistance based on previous interactions and codebase knowledge.', '@aiurda', 'databases', 'Unknown', 76, 'https://github.com/aiurda/cursor10x-mcp', NULL, 0, 'https://github.com/aiurda.png?size=128', '2026-03-09T05:21:01.942032+00:00'),
  ('cursor-background-composer', 'Cursor Background Composer', 'This MCP server provides programmatic access to Cursor''s Background Composer functionality, enabling AI assistants to create, manage, and monitor automated coding tasks within Cursor''s development environment. Built with TypeScript using Express, Axios, and the MCP SDK, it offers tools for creating background composers with custom task descriptions and repository URLs, listing active composers with status information, checking user settings like web access and privacy modes, and retrieving detailed composer information including diffs and changes. The implementation includes both CLI tooling and GitHub Actions workflow integration for automatic issue-to-composer triggering, making it valuable for automating code generation workflows, managing multiple coding tasks, and building AI-powered development assistance that can spawn and track background coding agents within the Cursor IDE ecosystem.', '@mjdierkes', 'development', 'Unknown', 21, 'https://github.com/mjdierkes/cursor-background-agent-api', NULL, 0, 'https://github.com/mjdierkes.png?size=128', '2026-03-09T05:21:01.942060+00:00'),
  ('cursor-buddy', 'Cursor Buddy', 'This MCP server provides AI assistants with development workflow management capabilities through a structured .buddy directory system, built by Omar Haris using Go with Bleve search integration for full-text indexing across project artifacts. The implementation manages coding rules and guidelines, knowledge base entries, database schema information, todo tracking with completion status, implementation history with change tracking, and file backup management, all organized in markdown and JSON files with real-time file monitoring for automatic updates. Built with comprehensive search capabilities across all document types, concurrent access safety, and Docker deployment support, it serves development teams needing centralized project context management, individual developers requiring structured documentation and rule enforcement, and organizations wanting to maintain institutional knowledge and coding standards with AI-assisted development workflows.', '@omar-haris', 'databases', 'Unknown', 10, 'https://github.com/omar-haris/cursor-buddy-mcp', NULL, 0, 'https://github.com/omar-haris.png?size=128', '2026-03-09T05:21:01.942072+00:00'),
  ('cursor-chat-history', 'Cursor Chat History', 'This MCP server provides AI assistants access to Cursor chat history for analysis and insights, enabling personalized coding assistance based on actual development patterns. Built using TypeScript with better-sqlite3 and the MCP SDK, it reads local Cursor conversation databases directly without external services, supporting both legacy and modern conversation formats with tools for listing, searching, and retrieving full conversations, plus advanced analytics including usage patterns, file activity, programming language distribution, and relationship detection between conversations. The implementation uses a summary-first approach for context efficiency, allowing users to browse conversation summaries before diving into full content, and includes data extraction capabilities with JSON, CSV, and graph export formats, making it valuable for generating personalized coding rules from actual usage patterns, extracting best practices from past problem-solving sessions, and creating project documentation based on real development conversations.', '@vltansky', 'databases', 'Unknown', 32, 'https://github.com/vltansky/cursor-chat-history-mcp', 'cursor-chat-history-mcp', 8153, 'https://github.com/vltansky.png?size=128', '2026-03-09T05:21:01.942084+00:00'),
  ('cursor-conversations', 'Cursor Conversations', 'MCP server by Vlad Tansky that provides AI assistants with direct access to Cursor''s local conversation database for analyzing coding patterns and generating personalized development insights. The implementation reads SQLite conversation data directly from Cursor''s storage, offering tools for conversation retrieval, search, analytics, and relationship discovery across chat history, with support for both legacy and modern Cursor database formats. Built with TypeScript using better-sqlite3 for database access, it includes conversation parsing, code block extraction, file relationship mapping, and export capabilities in multiple formats, serving developers who want to analyze their actual coding conversations to extract personalized coding rules, identify recurring development patterns, and generate context-aware assistance based on their real project history and problem-solving sessions.', '@unknown', 'databases', 'Unknown', 0, 'https://www.pulsemcp.com/servers/cursor-conversations', NULL, 0, NULL, '2026-03-09T05:21:01.942095+00:00'),
  ('cursor-ide-development-tools-jira-github-postgresql', 'Cursor IDE Development Tools (Jira, GitHub, PostgreSQL)', 'A collection of MCP servers for Cursor IDE that provides AI assistants with access to various external services including Jira, GitHub, and PostgreSQL databases. Each server is implemented as a standalone TypeScript module that can be run independently, exposing domain-specific tools through the Model Context Protocol. The implementation includes a template-based architecture for creating new servers, comprehensive error handling, and environment-based configuration. These servers enable Cursor IDE users to interact with their development tools and data sources directly through AI conversations, making it valuable for developers who need to query issues, repositories, or database information without context switching.', '@michael-trullion', 'databases', 'Unknown', 1, 'https://github.com/michael-trullion/mcp-servers', NULL, 0, 'https://github.com/michael-trullion.png?size=128', '2026-03-09T05:21:01.942108+00:00'),
  ('cursor-sound', 'Cursor Sound', 'A lightweight MCP server that plays a sound effect after Cursor AI completes code generation. Uses the play-sound library to trigger a macOS system sound, providing audio feedback for developers during AI-assisted coding. Designed to enhance the coding experience by adding an auditory cue when code generation is complete.', '@ericlistin', 'development', 'Unknown', 19, 'https://github.com/ericlistin/sound-mcp', NULL, 0, 'https://github.com/ericlistin.png?size=128', '2026-03-09T05:21:01.942128+00:00'),
  ('windows-desktop-automation', 'Windows Desktop Automation', 'Windows MCP server by Jeomon George that enables AI assistants to directly interact with the Windows operating system through native UI automation and system control. Built using Python with uiautomation, pyautogui, and fastmcp, the implementation provides tools for launching applications, capturing desktop state with interactive UI elements, performing mouse and keyboard actions, window management, clipboard operations, and PowerShell command execution. The server uses UI automation to identify clickable elements, text fields, and scrollable areas without relying on computer vision, making it work with any LLM while maintaining 1.5-2.3 second latency between actions. Designed for AI agents performing desktop automation tasks, QA testing workflows, and general Windows system interaction where programmatic control of applications and UI elements is needed.', '@unknown', 'development', 'Unknown', 0, 'https://www.pulsemcp.com/servers/cursortouch-windows-desktop-automation', NULL, 0, NULL, '2026-03-09T05:21:01.942163+00:00'),
  ('customer-io', 'Customer.io', 'Official Customer.io MCP server that enables AI assistants to interact with Customer.io''s customer engagement platform through tools for workspace management, user profile inspection, segment generation, and SDK setup guidance. The implementation provides access to customer data, campaign analytics, and workspace configuration while maintaining security through OAuth authentication and workspace-specific permissions. Built for marketing teams and developers who want to programmatically analyze customer segments, troubleshoot campaign delivery, inspect user profiles, and integrate Customer.io functionality without manually navigating the platform interface.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://docs.customer.io/ai/mcp-server/', NULL, 0, NULL, '2026-03-09T05:21:01.942207+00:00'),
  ('wordpress', 'WordPress', 'Integrates with the WordPress REST API to provide comprehensive site management through token-optimized responses that minimize payload size for efficient AI interactions. Covers posts, pages, media, users, comments, taxonomies, plugins, themes, menus, and site settings with support for Application Passwords authentication. Built with TypeScript and distributed as an npm package, it connects to any WordPress installation and automatically strips unnecessary data from API responses to reduce token consumption while preserving essential information for content management workflows.', '@cvrt-jh', 'development', 'Unknown', 0, 'https://github.com/cvrt-jh/wordpress-mcp', NULL, 0, 'https://github.com/cvrt-jh.png?size=128', '2026-03-09T05:21:01.942235+00:00'),
  ('common-lisp-repl', 'Common Lisp REPL', 'This Common Lisp MCP server by cxxxr provides a REPL evaluation tool that allows AI assistants to execute Lisp code safely with read-time evaluation disabled to prevent security issues from constructs like #.(). Built using ASDF with dependencies on Alexandria, Yason, usocket, and bordeaux-threads, it supports both stdio and TCP transport modes with structured JSON logging and comprehensive test coverage using the Rove framework. The implementation features a single repl-eval tool that evaluates Common Lisp forms sequentially and returns the last value as printed text, making it valuable for AI assistants that need to perform mathematical calculations, data processing, or symbolic computation tasks using the expressive power of Lisp while maintaining security through disabled reader macros.', '@cl-ai-project', 'development', 'Unknown', 43, 'https://github.com/cl-ai-project/cl-mcp', NULL, 0, 'https://github.com/cl-ai-project.png?size=128', '2026-03-09T05:21:01.942304+00:00'),
  ('atlas', 'ATLAS', 'ATLAS, developed by cyanheads, is a Model Context Protocol server that provides hierarchical task management capabilities to Large Language Models. It enables AI assistants to break down complex projects into manageable tasks, track progress, and maintain dependencies within an organized structure. The server implements rich content support, including markdown documentation, code snippets, and structured reasoning documentation. ATLAS stands out by offering a comprehensive task management system tailored for AI-driven project planning and execution. It is particularly useful for applications requiring sophisticated task organization, collaborative AI workflows, or any scenario where an AI system needs to manage and reason about complex, multi-step processes.', '@cyanheads', 'development', 'Unknown', 467, 'https://github.com/cyanheads/atlas-mcp-server', NULL, 0, 'https://github.com/cyanheads.png?size=128', '2026-03-09T05:21:01.942331+00:00'),
  ('clinicaltrials-gov', 'ClinicalTrials.gov', 'This ClinicalTrials.gov MCP server provides direct integration with the official ClinicalTrials.gov REST API, enabling AI assistants to search and retrieve clinical trial data through natural language queries. Built by cyanheads with TypeScript and comprehensive error handling, it offers two core tools: study search with advanced filtering by conditions, interventions, locations, and status, plus detailed study retrieval by NCT ID with automatic data cleaning to remove redundant browse module information. The implementation automatically backs up all API responses to local storage while always serving live data, uses structured logging with request tracing, and supports both HTTP and STDIO transports with JWT authentication, making it valuable for medical research, patient care coordination, and pharmaceutical development workflows where access to current clinical trial information is essential.', '@cyanheads', 'development', 'Unknown', 55, 'https://github.com/cyanheads/clinicaltrialsgov-mcp-server', 'clinicaltrialsgov-mcp-server', 37351, 'https://github.com/cyanheads.png?size=128', '2026-03-09T05:21:01.942363+00:00'),
  ('git', 'Git', 'This Git MCP server provides AI assistants with capabilities to interact with Git repositories. Developed as an open-source project, it integrates with the simple-git library to enable core Git operations like cloning, committing, and managing branches. The server exposes a standardized interface for Git interactions, abstracting the complexities of version control operations. By leveraging TypeScript and following modern JavaScript practices, it offers a robust and type-safe implementation. This server is particularly useful for developers and DevOps teams looking to incorporate AI-driven Git operations into their workflows, such as automated code reviews, commit analysis, or intelligent branching strategies.', '@cyanheads', 'development', 'Unknown', 190, 'https://github.com/cyanheads/git-mcp-server', NULL, 0, 'https://github.com/cyanheads.png?size=128', '2026-03-09T05:21:01.942416+00:00'),
  ('mentor-deepseek', 'Mentor (Deepseek)', 'This MCP server, developed by cyanheads, provides AI-powered mentorship capabilities through the Deepseek API. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers tools for code review, design critique, writing feedback, and idea brainstorming. The implementation focuses on delivering expert second opinions and actionable insights to enhance LLM agent performance. It''s particularly useful for developers, designers, and content creators seeking AI-assisted feedback and improvement suggestions, enabling use cases such as code quality enhancement, UI/UX refinement, documentation improvement, and feature ideation without directly interacting with the Deepseek API.', '@cyanheads', 'development', 'Unknown', 33, 'https://github.com/cyanheads/mentor-mcp-server', NULL, 0, 'https://github.com/cyanheads.png?size=128', '2026-03-09T05:21:01.942467+00:00'),
  ('ntfy-sh', 'ntfy.sh', 'Ntfy-mcp-server provides a bridge between Claude and the ntfy.sh notification service, enabling AI assistants to send push notifications directly from conversations. Built by Casey Hand (@cyanheads), this TypeScript implementation offers a complete MCP server with a send_ntfy tool that supports all ntfy features including message priorities, tags, attachments, and action buttons. The server includes robust error handling, rate limiting, and security features like input sanitization, making it particularly valuable for workflows that require notification capabilities without leaving the conversation interface.', '@cyanheads', 'development', 'Unknown', 14, 'https://github.com/cyanheads/ntfy-mcp-server', NULL, 0, 'https://github.com/cyanheads.png?size=128', '2026-03-09T05:21:01.942496+00:00'),
  ('obsidian-vault', 'Obsidian Vault', 'This Obsidian MCP server, developed by cyanheads, enables AI models to interact with Obsidian vaults through a standardized interface. Built with TypeScript and leveraging the Model Context Protocol SDK, it provides tools for file operations, content search, and metadata management within Obsidian. The implementation features atomic operations, efficient query processing, and automatic timestamp handling. It''s particularly useful for AI assistants and applications needing to manage knowledge bases in Obsidian, enabling use cases like note-taking, content organization, and information retrieval without dealing directly with Obsidian''s API complexities.', '@cyanheads', 'development', 'Unknown', 390, 'https://github.com/cyanheads/obsidian-mcp-server', 'obsidian-mcp-server', 17948, 'https://github.com/cyanheads.png?size=128', '2026-03-09T05:21:01.942528+00:00'),
  ('protein', 'Protein', 'Integrates with RCSB Protein Data Bank, PDBe, and UniProt to provide comprehensive access to 3D protein structural data. Supports structure search and retrieval, similarity analysis for identifying related proteins, ligand binding site tracking, and multi-structure comparisons with alignment metrics. Built with multi-provider orchestration for robust data access and edge-ready deployment capabilities.', '@cyanheads', 'search', 'Unknown', 1, 'https://github.com/cyanheads/protein-mcp-server', NULL, 0, 'https://github.com/cyanheads.png?size=128', '2026-03-09T05:21:01.942565+00:00'),
  ('survey', 'Survey', 'Transforms language models into intelligent interviewers capable of conducting sophisticated surveys with advanced conditional logic, skip patterns, and multi-condition branching. Supports diverse question types including free-form, multiple-choice, rating scales, matrix grids, and date/time fields with optional scoring systems. Features robust session management for resuming incomplete surveys, pluggable storage backends (in-memory, filesystem, Supabase, Cloudflare KV/R2), and flexible data export to CSV or JSON formats.', '@cyanheads', 'databases', 'Unknown', 4, 'https://github.com/cyanheads/survey-mcp-server', NULL, 0, 'https://github.com/cyanheads.png?size=128', '2026-03-09T05:21:01.942607+00:00'),
  ('toolkit-system-utilities', 'Toolkit (System Utilities)', 'This toolkit MCP server, developed by cyanheads, provides system utilities and tools for LLM agents. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers IP geolocation, network diagnostics, system monitoring, cryptographic operations, and QR code generation. The implementation focuses on providing a standardized interface for common system and network tasks, with features like intelligent caching and rate limiting. It''s particularly useful for AI assistants and applications needing low-level system access, enabling use cases such as network troubleshooting, resource monitoring, and security operations without dealing directly with underlying system APIs.', '@cyanheads', 'development', 'Unknown', 18, 'https://github.com/cyanheads/toolkit-mcp-server', '@cyanheads/toolkit-mcp-server', 5049, 'https://github.com/cyanheads.png?size=128', '2026-03-09T05:21:01.942633+00:00'),
  ('arcs-multi-platform-article-publisher', 'Arcs Multi-Platform Article Publisher', 'This MCP server provides AI assistants with multi-platform article publishing capabilities across Chinese tech platforms including CSDN, JueJin, Zhihu, WeChat, Halo, and CNBlogs, built by Cyanty using Python with DrissionPage for browser automation and FastAPI for web interface management. The implementation offers automated article submission with markdown content processing, GitHub proxy URL cleanup, platform-specific tag management, and browser-based authentication handling through a factory pattern that dynamically loads crawler modules for each platform. Built with concurrent publishing support using asyncio and thread executors, web-based article upload interface with file management, login state tracking across platforms, and robust error handling with retry mechanisms, it serves content creators managing multi-platform publishing workflows, technical bloggers needing automated cross-platform distribution, and content marketing teams requiring streamlined article syndication across Chinese social media and developer platforms without manual platform-specific posting.', '@cyanty', 'development', 'Unknown', 6, 'https://github.com/cyanty/arcs-mcp', NULL, 0, 'https://github.com/cyanty.png?size=128', '2026-03-09T05:21:01.942667+00:00'),
  ('codify', 'Codify', 'MCP server that lets AI assistants (Claude, Cursor, VS Code) execute browser automation tasks via Apify Agent. Part of Project Codify, an end-to-end browser automation pipeline. Tools are passed as clean JSON arguments, enabling rapid prototyping, quick automation scripts, and sophisticated deployments at scale. Supports creating, codifying, and replaying browser actions as robust and reusable scripts.', '@cybairfly', 'development', 'Unknown', 0, 'https://github.com/cybairfly/codify-mcp', NULL, 0, 'https://github.com/cybairfly.png?size=128', '2026-03-09T05:21:01.942687+00:00'),
  ('devdocs', 'DevDocs', '🎯 Perfect For
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('cycloid', 'Cycloid', 'Integrates with Cycloid.io, a unified Internal Developer Platform and Portal for platform engineering. Enables exploration of infrastructure blueprints, stack deployment, configuration validation, service catalog browsing, event monitoring, and pipeline management. Supports multi-tenant usage with organization-based authentication for hybrid and multi-cloud infrastructure automation.', '@cycloidio', 'security', 'Unknown', 0, 'https://github.com/cycloidio/cycloid-mcp-server', NULL, 0, 'https://github.com/cycloidio.png?size=128', '2026-03-09T05:21:01.943023+00:00'),
  ('cyclops', 'Cyclops', 'Cyclops MCP server provides AI assistants with safe Kubernetes application management through high-level abstractions, enabling creation and updates of applications using validated templates rather than direct manipulation of low-level Kubernetes resources. Built in Go using the cyclops-ui/cyclops framework, the implementation offers tools for managing Cyclops Modules (template-based application definitions), Template Stores (collections of Helm/Git/OCI templates), and retrieving JSON schemas for template validation, with comprehensive CRUD operations including module creation, updates, resource listing, and manifest generation. The server validates all module configurations against template schemas before deployment and integrates with Kubernetes through the Cyclops controller, serving DevOps teams who want to give AI agents controlled access to application deployment without risking direct cluster manipulation, and organizations seeking to abstract Kubernetes complexity from both developers and AI systems while maintaining production safety through template-driven workflows.', '@cyclops-ui', 'cloud', 'Unknown', 30, 'https://github.com/cyclops-ui/mcp-cyclops', NULL, 0, 'https://github.com/cyclops-ui.png?size=128', '2026-03-09T05:21:01.943051+00:00'),
  ('cycode-security-scanner', 'Cycode Security Scanner', 'Cycode CLI MCP server that provides security scanning capabilities for detecting secrets, vulnerabilities, and compliance issues across codebases through Cycode''s security platform. Built by Cycode Ltd., the implementation integrates with their cloud-based security service to perform SAST, SCA, IaC, and secrets scanning on local files, Git repositories, and commit ranges, supporting multiple programming languages and package managers including npm, Maven, Go, Ruby, and .NET. The server handles authentication via OAuth device flow, manages scan configurations, and provides detailed security reports with remediation guidance, making it valuable for developers who want to integrate automated security scanning into their AI-assisted development workflows without manually running CLI commands or navigating web dashboards.', '@cycodehq', 'development', 'Unknown', 96, 'https://github.com/cycodehq/cycode-cli', 'cycode', 2983832, 'https://github.com/cycodehq.png?size=128', '2026-03-09T05:21:01.943087+00:00'),
  ('aderyn', 'Aderyn', 'This MCP server provides intelligent Solidity smart contract analysis capabilities through the Aderyn static analyzer, built by Cyfrin in Rust with comprehensive AST parsing and vulnerability detection. The implementation offers tools for scanning Solidity codebases to identify security issues, code quality problems, and potential vulnerabilities across multiple severity levels, with support for Foundry and Hardhat project structures, configurable include/exclude patterns, and multiple output formats including JSON, Markdown, and SARIF. It integrates deeply with the Solidity compilation pipeline using solidity-ast-rs for AST generation, features parallel processing for performance, and includes LSP server capabilities for real-time IDE integration, making it valuable for security auditors performing smart contract reviews, development teams implementing continuous security scanning, and AI assistants that need to understand and analyze Solidity code patterns and vulnerabilities.', '@cyfrin', 'development', 'Unknown', 737, 'https://github.com/cyfrin/aderyn', NULL, 0, 'https://github.com/cyfrin.png?size=128', '2026-03-09T05:21:01.943120+00:00'),
  ('io-github-cyntrisec-cyntrisec', 'io.github.cyntrisec/cyntrisec', 'AWS security analysis: attack paths, compliance checking, and remediation planning.', '@cyntrisec', 'cloud', 'Unknown', 3, 'https://github.com/cyntrisec/cyntrisec-cli', NULL, 0, 'https://github.com/cyntrisec.png?size=128', '2026-03-09T05:21:01.943133+00:00'),
  ('security-tools-bridge', 'Security Tools Bridge', 'MCP for Security is a collection of server implementations that bridge popular security tools (Nmap, Masscan, SQLMap, and FFUF) with AI assistants through the MCP protocol. Developed by Cyprox, these TypeScript-based servers enable AI systems to execute network scanning, port discovery, SQL injection testing, and web fuzzing operations by spawning the respective security tools and capturing their output. Each implementation follows a consistent pattern of accepting tool-specific parameters, executing the underlying binary with appropriate arguments, and returning results in a standardized format, making them particularly valuable for security professionals who want to leverage AI assistants for penetration testing, vulnerability assessment, and security auditing tasks.', '@cyproxio', 'databases', 'Unknown', 558, 'https://github.com/cyproxio/mcp-for-security', NULL, 0, 'https://github.com/cyproxio.png?size=128', '2026-03-09T05:21:01.943146+00:00'),
  ('dual-cycle-reasoner', 'Dual-Cycle Reasoner', 'This MCP server implements a dual-cycle metacognitive reasoning framework for autonomous agents, built by CyqleLabs using TypeScript with advanced loop detection and recovery mechanisms. The implementation combines statistical anomaly detection, semantic analysis using Hugging Face transformers, and case-based reasoning to identify when agents get stuck in repetitive behaviors like endless scrolling or clicking patterns, then automatically diagnoses failure causes and generates recovery strategies. Built with three core detection strategies (action pattern analysis, state invariance tracking, and progress stagnation detection), belief revision capabilities, and a case-based learning system that adapts from past experiences, it serves developers building autonomous web agents, teams needing robust loop prevention for browser automation tasks, and researchers working on self-monitoring AI systems that can break out of unproductive behavioral cycles.', '@cyqlelabs', 'development', 'Unknown', 9, 'https://github.com/cyqlelabs/mcp-dual-cycle-reasoner', '@cyqlelabs/mcp-dual-cycle-reasoner', 3557, 'https://github.com/cyqlelabs.png?size=128', '2026-03-09T05:21:01.943185+00:00'),
  ('exploitdb', 'ExploitDB', 'A Model Context Protocol server developed by Cyreslab.ai that provides AI assistants with access to ExploitDB functionality for cybersecurity research. The server enables searching for security exploits by keywords, CVE IDs, or platforms, retrieving detailed information about specific exploits including their code, and tracking newly added vulnerabilities. It maintains a local SQLite database that can be automatically updated from the official ExploitDB repository, making it valuable for threat intelligence, vulnerability research, and security analysis without leaving the AI assistant conversation.', '@cyreslab-ai', 'databases', 'Unknown', 18, 'https://github.com/cyreslab-ai/exploitdb-mcp-server', NULL, 0, 'https://github.com/cyreslab-ai.png?size=128', '2026-03-09T05:21:01.943196+00:00'),
  ('kagi-ken', 'Kagi Ken', 'Kagi MCP server implementation by Carlo Zottmann that provides search and summarization capabilities through the kagi-ken package, offering an alternative to the official Python-based Kagi MCP server. The implementation features concurrent multi-query search processing with timeout handling, comprehensive token resolution supporting both environment variables and file-based authentication (~/.kagi_session_token), and output formatting that precisely matches the official Kagi MCP interface for seamless tool compatibility. Built with Node.js and designed for developers who prefer JavaScript-based tooling, it enables AI assistants to perform web searches and document summarization through Kagi''s APIs while maintaining the same interface standards as the official implementation.', '@czottmann', 'ai-ml', 'Unknown', 25, 'https://github.com/czottmann/kagi-ken-mcp', NULL, 0, 'https://github.com/czottmann.png?size=128', '2026-03-09T05:21:01.943269+00:00'),
  ('d2-diagramming', 'D2 Diagramming', 'This D2MCP server by Yasushi Itoh provides AI assistants with direct access to D2 diagram creation and rendering capabilities, integrating with Terrastruct''s D2 declarative diagramming language to generate SVG, PNG, and PDF outputs. The implementation supports 20+ built-in themes, programmatic diagram creation with in-memory storage, and file-based operations for persistent diagram management, using external tools like rsvg-convert or ImageMagick for non-SVG format conversion. Built with clean architecture patterns and comprehensive error handling, it enables natural language diagram generation workflows where users can create technical diagrams, flowcharts, and architectural visualizations through conversational interfaces without directly writing D2 syntax.', '@i2y', 'ai-ml', 'Unknown', 23, 'https://github.com/i2y/d2mcp', NULL, 0, 'https://github.com/i2y.png?size=128', '2026-03-09T05:21:01.943318+00:00'),
  ('mochi-flashcards', 'Mochi Flashcards', 'Mochi-Flashcards-MCP-Server provides a bridge between AI assistants and the Mochi Cards flashcard application, enabling flashcard management through natural language. Created by d42me, this server implementation exposes tools for listing decks, creating cards with markdown content and tags, retrieving card details, updating existing cards, and deleting cards via the Mochi API. The server handles authentication through API keys stored in environment variables and manages asynchronous HTTP requests with proper error handling, making it valuable for students and learners who want to create and manage their flashcards directly through AI assistants without switching contexts.', '@d42me', 'ai-ml', 'Unknown', 5, 'https://github.com/d42me/mochi-flashcards-mcp-server', NULL, 0, 'https://github.com/d42me.png?size=128', '2026-03-09T05:21:01.943367+00:00'),
  ('jdi-debugger', 'JDI Debugger', 'Connects to running Java applications via JDWP for real-time debugging with breakpoint management, variable inspection, step execution control, and stack trace analysis.', '@d4n-sec', 'development', 'Unknown', 21, 'https://github.com/d4n-sec/jdb-mcp', NULL, 0, 'https://github.com/d4n-sec.png?size=128', '2026-03-09T05:21:01.943385+00:00'),
  ('scrapling', 'Scrapling', 'The Scrapling MCP server brings advanced web scraping capabilities to AI assistants, featuring six specialized tools for different scraping scenarios: basic HTTP requests with browser fingerprint impersonation, dynamic content fetching with Chromium/Chrome, and stealth scraping using a modified Camoufox browser to bypass Cloudflare Turnstile and other anti-bot protections. Built by the Scrapling team, it differentiates itself from other scraping tools by allowing CSS selector-based content filtering before passing data to the AI, significantly reducing token consumption and improving efficiency compared to solutions that extract entire pages first. The implementation supports bulk operations for parallel processing, proxy integration, and multiple output formats (Markdown, HTML, clean text), making it ideal for e-commerce data collection, content monitoring, and automated research workflows where anti-bot bypass and targeted extraction are essential.', '@d4vinci', 'cloud', 'Unknown', 25563, 'https://github.com/d4vinci/scrapling', 'scrapling', 321766, 'https://github.com/d4vinci.png?size=128', '2026-03-09T05:21:01.943410+00:00'),
  ('wechat-adb', 'WeChat ADB', 'Provides WeChat automation capabilities through ADB (Android Debug Bridge) connectivity, enabling message sending and screenshot capture on Android devices or emulators. Built for Windows environments with Python 3.13+ and includes specialized utilities for device interaction, the implementation bridges WeChat functionality with AI agents through programmatic control of the mobile application. Features ADB keyboard integration for text input and supports emulator environments like LeiDian, making it valuable for customer service automation, bulk messaging workflows, and WeChat bot development that requires direct interaction with the mobile interface rather than web-based APIs.', '@dabaigoose', 'development', 'Unknown', 17, 'https://github.com/dabaigoose/mcp-wechat-adb-server', NULL, 0, 'https://github.com/dabaigoose.png?size=128', '2026-03-09T05:21:01.943471+00:00'),
  ('better-auth', 'Better Auth', 'Integrates with Better Auth documentation through web scraping to provide authentication provider listings, feature details with code examples, keyword-based documentation search, and framework-specific integration guides with intelligent caching for improved performance.', '@dabhivijay2478', 'development', 'Unknown', 2, 'https://github.com/dabhivijay2478/better-auth-mcp-server', NULL, 0, 'https://github.com/dabhivijay2478.png?size=128', '2026-03-09T05:21:01.943487+00:00'),
  ('polygon-blockchain', 'Polygon Blockchain', 'Polygon MCP Server provides onchain tools for Claude AI to interact with the Polygon PoS blockchain. It enables calling contract functions, checking ERC20 token balances, transferring tokens, and retrieving gas prices through a secure wallet connection using the user''s seed phrase. Built with TypeScript and the viem library, it establishes a connection to the Polygon network and handles transaction signing, making it ideal for workflows requiring cryptocurrency management, smart contract interaction, or blockchain data retrieval without leaving the conversation interface.', '@dablclub', 'development', 'Unknown', 6, 'https://github.com/dablclub/polygon-mcp', 'polygon-mcp', 1139, 'https://github.com/dablclub.png?size=128', '2026-03-09T05:21:01.943515+00:00'),
  ('prompt-cleaner-python', 'Prompt Cleaner (Python)', 'Transforms raw, unpolished prompts into clear and effective versions using large language models with quality assessment, retry strategies, and support for both general and code-specific enhancement modes.', '@dacebt', 'development', 'Unknown', 1, 'https://github.com/dacebt/mcp-py-prompt-cleaner', NULL, 0, 'https://github.com/dacebt.png?size=128', '2026-03-09T05:21:01.943533+00:00'),
  ('airbrake', 'Airbrake', 'Provides comprehensive integration with Airbrake''s error tracking platform, enabling developers to monitor, analyze, and manage application errors through 17 specialized tools. Supports full error lifecycle management including listing errors with filtering by environment and status, retrieving detailed stack traces and occurrence data, searching errors by text queries, and updating error states (resolve, ignore, reopen). Features deployment tracking with notification creation, project statistics monitoring, error trend analysis over time, and team collaboration through comments and external issue tracker linking. Designed for development teams using Airbrake who need programmatic access to error data for debugging workflows, automated incident response, and integration with existing development tools.', '@dach3r', 'development', 'Unknown', 1, 'https://github.com/dach3r/airbrake-mcp-server', NULL, 0, 'https://github.com/dach3r.png?size=128', '2026-03-09T05:21:01.943563+00:00'),
  ('prompt-cleaner', 'Prompt Cleaner', 'Prompt Cleaner MCP server by David Colon that provides AI assistants with tools to sanitize, redact, and professionally reformat user prompts before they''re processed by language models. The implementation integrates with local OpenAI-compatible APIs to intelligently clean prompts while automatically detecting and redacting sensitive information like API keys, tokens, emails, and other secrets using pattern matching. Features comprehensive retry logic with exponential backoff, structured JSON output with notes and risk assessments, configurable temperature settings, and multiple tool aliases (cleaner, sanitize-text, normalize-prompt) for different use cases, making it valuable for developers who want to ensure prompt hygiene and prevent accidental exposure of sensitive data in AI workflows.', '@dacebt', 'communication', 'Unknown', 1, 'https://github.com/dacebt/prompt-cleaner-mcp', NULL, 0, 'https://github.com/dacebt.png?size=128', '2026-03-09T05:21:01.943601+00:00'),
  ('duckdb', 'DuckDB', 'MCPlucker is a Go-based MCP server that provides direct access to DuckDB''s analytical capabilities through five core tools: file-to-table loading (CSV, JSON, Parquet), table management, schema inspection, and SQL query execution with configurable result limits. Built with the go-duckdb driver and MCP Go SDK, it uses an in-memory DuckDB instance by default and includes comprehensive error handling, automatic file type detection, and structured JSON responses for all operations. The implementation follows a clean architecture with separate packages for database management, server logic, and tool implementations, making it ideal for data analysts and developers who need fast, local analytical processing of structured data files without the overhead of a full database setup.', '@dacort', 'databases', 'Unknown', 2, 'https://github.com/dacort/mcplucker', NULL, 0, 'https://github.com/dacort.png?size=128', '2026-03-09T05:21:01.943614+00:00'),
  ('credo-cheqd-did', 'Credo (Cheqd DID)', 'Credo MCP Server provides a bridge between Claude and the Credo decentralized identity framework, enabling AI assistants to resolve and interact with decentralized identifiers (DIDs) on the cheqd network. The implementation initializes a Credo agent with modules for DID resolution, AnonCreds verification, and cheqd network integration, exposing a ''resolve-did'' tool that retrieves DID documents and their metadata. Built using TypeScript and the Model Context Protocol SDK, this server runs on stdio transport for seamless integration with Claude Desktop, making it particularly valuable for workflows involving decentralized identity verification and credential management without leaving the conversation interface.', '@daevmithran', 'development', 'Unknown', 0, 'https://github.com/daevmithran/credo-mcp-server', NULL, 0, 'https://github.com/daevmithran.png?size=128', '2026-03-09T05:21:01.943659+00:00'),
  ('daft-ie', 'Daft.ie', 'A TypeScript-based MCP server that provides access to Irish rental property data from Daft.ie through web scraping, built by Amine REMACHE as an alternative to the restricted Daft.ie API. The implementation uses Cheerio for HTML parsing and includes sophisticated filtering capabilities for location, price, bedrooms, and property type, with special handling for Dublin postal codes and multi-unit developments. Features a two-pass scraping system that visits individual property detail pages to extract enhanced data like coordinates and BER ratings, plus includes retry logic, rate limiting, and structured error handling with Winston logging, making it valuable for property research, market analysis, and rental search automation in the Irish market.', '@amineremache', 'development', 'Unknown', 10, 'https://github.com/amineremache/dafty-mcp', NULL, 0, 'https://github.com/amineremache.png?size=128', '2026-03-09T05:21:01.943687+00:00'),
  ('ios-development-tools', 'iOS Development Tools', 'Provides comprehensive iOS simulator control and Swift/Xcode development automation through command-line tools like simctl, xcodebuild, and idb. Enables building and testing iOS apps, managing simulator devices, controlling UI interactions (tap, swipe, type), capturing screenshots and logs, setting location and environment variables, and inspecting app state without requiring Xcode GUI. Includes specialized skills for Swift concurrency debugging and SwiftUI performance auditing.', '@dagba', 'development', 'Unknown', 3, 'https://github.com/dagba/ios-mcp', NULL, 0, 'https://github.com/dagba.png?size=128', '2026-03-09T05:21:01.943711+00:00'),
  ('container-use', 'Container Use', 'This container-use MCP server by Dagger provides AI assistants with containerized development environments that persist state across interactions through git-based storage and Dagger''s container runtime. The implementation creates isolated environments from configurable base images with custom setup commands, toolchains, and services, automatically committing filesystem changes to git branches and maintaining container state through serialized snapshots. Key differentiators include seamless integration between container state and git history, support for background services with port forwarding, and the ability to checkpoint environments as publishable container images, making it valuable for AI-powered development workflows that require persistent, reproducible environments with full filesystem access and service orchestration capabilities.', '@dagger', 'development', 'Unknown', 3596, 'https://github.com/dagger/container-use', NULL, 0, 'https://github.com/dagger.png?size=128', '2026-03-09T05:21:01.943756+00:00'),
  ('teamcity', 'TeamCity', 'Bridges JetBrains TeamCity with AI coding assistants, enabling build triggering, monitoring, log retrieval, and test failure analysis. Supports two operational modes: dev mode for safe read operations and full mode for administrative capabilities including build configuration management, VCS roots, and trigger setup.', '@daghis', 'development', 'Unknown', 19, 'https://github.com/daghis/teamcity-mcp', NULL, 0, 'https://github.com/daghis.png?size=128', '2026-03-09T05:21:01.943776+00:00'),
  ('fep-fediverse-enhancement-proposals', 'FEP (Fediverse Enhancement Proposals)', 'Provides access to Fediverse Enhancement Proposals (FEPs) by cloning the official repository and exposing tools for searching, listing, and retrieving standardization documents. Works around Codeberg''s anti-AI protections that prevent direct document fetching. Supports filtering by status (draft, final, withdrawn) and searching by title, author, or content.', '@dahlia', 'development', 'Unknown', 4, 'https://github.com/dahlia/fep-mcp', NULL, 0, 'https://github.com/dahlia.png?size=128', '2026-03-09T05:21:01.943801+00:00'),
  ('tashan-scispark-research-assistant', 'Tashan SciSpark Research Assistant', 'Tashan SciSpark automates scientific paper discovery, analysis, and idea generation through integration with arXiv, Google Scholar, and multiple LLM providers including OpenAI, DeepSeek, and Gemini. The system employs a Mixture of Agents approach for collaborative idea refinement, combining Bayesian reasoning, automated feature engineering, and transformer-based analysis to generate novel research hypotheses and comprehensive paper drafts. Built with FastAPI and Celery for scalable processing, it includes specialized prompt templates for entity extraction, hypothesis generation, and technical optimization.', '@daiduo2', 'ai-ml', 'Unknown', 1, 'https://github.com/daiduo2/tashan_scispark_mcp', NULL, 0, 'https://github.com/daiduo2.png?size=128', '2026-03-09T05:21:01.943865+00:00'),
  ('pocket-mcp-manager', 'Pocket MCP Manager', 'Pocket MCP Manager provides a flexible client-server architecture for managing multiple Model Context Protocol servers through a unified interface. The system allows users to add, launch, and control MCP servers via a central management UI, generate API keys linked to running servers, and connect to them through a single proxy server in AI tools like Claude or Cursor. Built with a TypeScript server component that routes requests to appropriate backend servers and a Python client with Streamlit UI, it eliminates the need to reconfigure multiple connection settings when changing which MCP servers to use. The implementation includes an example LLM client demonstrating integration with OpenAI''s API while leveraging connected MCP servers'' capabilities.', '@dailydaniel', 'development', 'Unknown', 4, 'https://github.com/dailydaniel/pocket-mcp', NULL, 0, 'https://github.com/dailydaniel.png?size=128', '2026-03-09T05:21:01.943951+00:00'),
  ('perplexity-research-assistant', 'Perplexity Research Assistant', 'This MCP server, developed by DaInfernalCoder, leverages the Perplexity Sonar Pro API to provide AI-powered research assistance within the Cline development environment. Built with TypeScript and utilizing the Model Context Protocol SDK, it offers tools for general search queries, documentation retrieval, API discovery, and deprecated code analysis. The implementation focuses on enhancing developer productivity by integrating up-to-date information and code insights directly into the workflow. It''s particularly useful for developers seeking real-time assistance with documentation, API integration, and code modernization, enabling use cases such as efficient library adoption, API evaluation, and codebase maintenance without leaving their development environment.', '@dainfernalcoder', 'development', 'Unknown', 284, 'https://github.com/dainfernalcoder/perplexity-mcp', NULL, 0, 'https://github.com/dainfernalcoder.png?size=128', '2026-03-09T05:21:01.943980+00:00'),
  ('daisys-ai-text-to-speech', 'Daisys AI Text-to-Speech', 'Daisys MCP Server provides a bridge to the Daisys AI text-to-speech API, enabling AI assistants to generate high-quality voice audio from text. Developed by Jasper Jumelet, it supports both HTTP and WebSocket protocols for audio generation, with the WebSocket implementation offering real-time streaming capabilities. The server includes tools for voice management (creating, listing, and removing voices), model discovery, and audio file handling with configurable output paths. Built with Python and the Daisys SDK, it features comprehensive authentication handling through environment variables and supports various audio formats. This implementation is particularly valuable for applications requiring natural-sounding voice synthesis with control over voice characteristics like gender, pace, pitch, and expression.', '@daisys-ai', 'ai-ml', 'Unknown', 12, 'https://github.com/daisys-ai/daisys-mcp', 'daisys-mcp', 1932, 'https://github.com/daisys-ai.png?size=128', '2026-03-09T05:21:01.944030+00:00'),
  ('daizo-buddhist-text-corpora', 'Daizo (Buddhist Text Corpora)', 'Buddhist text retrieval MCP server by Shinryo Taniguchi that provides AI assistants with access to two major Buddhist text corpora: CBETA (Chinese Buddhist Electronic Text Association) TEI XML files and SAT (SAT Daizōkyō Text Database) web content, plus Pali Tipitaka texts from VipassanaTech. Built in Rust with automatic data cloning from GitHub repositories, the implementation offers fuzzy search across titles with Unicode normalization for Chinese characters and Pali diacritics, content-based regex search with line number context extraction, and intelligent text extraction that handles TEI markup, juan sections, and encoding detection. The server includes SAT web scraping with title scoring algorithms, supports both LSP-style and newline-delimited JSON framing modes, and provides structured metadata including bibliographic information, section headings, and content statistics, making it valuable for Buddhist studies research, comparative textual analysis, and scholarly work requiring access to primary sources across multiple Buddhist traditions and languages.', '@sinryo', 'databases', 'Unknown', 5, 'https://github.com/sinryo/buddha-cli', NULL, 0, 'https://github.com/sinryo.png?size=128', '2026-03-09T05:21:01.944054+00:00'),
  ('gemini-2-5-pro', 'Gemini 2.5 Pro', 'Gemini MCP Server enables Claude Desktop to interact with Google''s Gemini 2.5 Pro Experimental AI model through a TypeScript implementation of the Model Context Protocol. The server provides two main tools: generateWithGemini for content generation with customizable parameters like temperature and token limits, and getModelInfo for retrieving model capabilities. It features Google Search integration for grounding responses in factual information, secure API key handling through environment variables, detailed token usage reporting, and comprehensive error handling with response caching to local files for verification. Ideal for users wanting to leverage Gemini''s capabilities within Claude''s interface.', '@dakrin', 'development', 'Unknown', 3, 'https://github.com/dakrin/mcp-gemini-server', NULL, 0, 'https://github.com/dakrin.png?size=128', '2026-03-09T05:21:01.944086+00:00'),
  ('odoo-sh', 'Odoo.sh', 'Connects to Odoo.sh cloud platform instances through SSH to enable AI-assisted custom app development. Provides comprehensive development tools including Git workflow operations (add, commit, push, checkout, pull), file management with base64 encoding for safe transfers, project build triggering and monitoring, branch management, database listing, log access, and Python shell execution. Built with TypeScript using OpenSSH subprocess execution to overcome Odoo.sh''s custom SSH implementation limitations, operating in the ~/src/user directory for custom code development. Integrates with Claude Desktop, Cline, and other clients for streamlined Odoo.sh development workflows.', '@dalahmasdev', 'databases', 'Unknown', 0, 'https://github.com/dalahmasdev/odoo-sh-mcp-server', NULL, 0, 'https://github.com/dalahmasdev.png?size=128', '2026-03-09T05:21:01.944098+00:00'),
  ('document-processing-and-youtube-content-extraction', 'Document Processing and YouTube Content Extraction', 'The Useful MCPs repository provides two specialized MCP servers for document processing and YouTube content extraction. The docx_replace_mcp server enables template-based document generation with tools for replacing placeholders, managing conditional blocks, and converting DOCX files to PDF. The ytdlp_mcp server leverages yt-dlp to extract chapters and subtitles from YouTube videos, with advanced filtering capabilities for specific time ranges. Both implementations are designed for seamless integration with AI assistants, making them valuable for workflows requiring document automation or YouTube content analysis without manual intervention.', '@daltonnyx', 'ai-ml', 'Unknown', 5, 'https://github.com/daltonnyx/userful-mcps', NULL, 0, 'https://github.com/daltonnyx.png?size=128', '2026-03-09T05:21:01.944145+00:00'),
  ('dam-butler-breville-brandfolder', 'DAM Butler (Breville Brandfolder)', 'This DAM Butler MCP server provides AI assistants with intelligent access to Breville''s digital asset management system through natural language processing and brand intelligence. Built by the Breville DAM Team with TypeScript and deployed on Vercel, it features a triple-fallback intelligence system using OpenAI-enhanced parsing, pattern matching, and regional brand context (Breville vs Sage) to understand requests like ''Oracle Jet logo for my presentation'' or ''Sage assets for UK market''. The implementation includes 14 official Brandfolder asset sections, use case optimization for presentations/web/social/Amazon, advanced analytics with confidence scoring, and OAuth integration with Brandfolder''s API, making it particularly useful for marketing teams, product managers, and content creators who need quick access to brand-compliant assets across different regions and use cases.', '@vnsavitri', 'cloud', 'Unknown', 1, 'https://github.com/vnsavitri/dam-butler-mcp', NULL, 0, 'https://github.com/vnsavitri.png?size=128', '2026-03-09T05:21:01.944171+00:00'),
  ('semantic-context', 'Semantic Context', 'This semantic code search MCP server by Damian Pramparo provides enterprise-grade vector database integration for indexing and searching codebases using ChromaDB for storage and either OpenAI or Ollama for embeddings. Built with TypeScript and featuring both stdio and HTTP server modes, it offers tools for indexing local project directories with configurable file patterns, performing semantic code searches across indexed repositories, and retrieving file contents with metadata tracking including project names, file types, and chunk indexing. The implementation includes Docker Compose setup with ChromaDB, Ollama, Redis, and PostgreSQL services, comprehensive file type support covering 50+ programming languages and formats, and streaming file processing for handling large codebases efficiently, making it ideal for development teams building AI-powered code search systems, enterprise knowledge bases, and developer productivity tools that need to understand and navigate large codebases semantically.', '@damian-pramparo', 'databases', 'Unknown', 3, 'https://github.com/damian-pramparo/semantic-context-mcp', NULL, 0, 'https://github.com/damian-pramparo.png?size=128', '2026-03-09T05:21:01.944183+00:00'),
  ('devdb', 'DevDB', 'DevDB MCP server provides database schema and table information to AI assistants through a standardized interface. Built by Damilola Emmanuel Olowookere, it exposes database tables and their schemas via HTTP endpoints and MCP resources, allowing AI tools to query database structure without direct database access. The server includes tools for listing tables and retrieving detailed schema information, making it useful for developers who want AI assistants to understand their database architecture or generate database-aware code without compromising security.', '@damms005', 'databases', 'Unknown', 1340, 'https://github.com/damms005/devdb-vscode', NULL, 0, 'https://github.com/damms005.png?size=128', '2026-03-09T05:21:01.944194+00:00'),
  ('mcp-ossinsight', 'MCP OSSInsight', 'An MCP server based on OSSInsight.io, providing data analysis for GitHub individuals, organizations, and repositories, as well as in-depth insights into the open source ecosystem.', '@damonxue', 'development', 'Unknown', 14, 'https://github.com/damonxue/mcp-ossinsight', NULL, 0, 'https://github.com/damonxue.png?size=128', '2026-03-09T05:21:01.944215+00:00'),
  ('nostrdb', 'Nostrdb', 'This MCP server, developed by William Casarin, provides a bridge between Language Models and the nostrdb command-line tool, enabling local Nostr queries. Built with JavaScript and leveraging the Model Context Protocol SDK, it offers tools for retrieving statistics and querying the NDB (Nostr Database). The implementation focuses on integrating with Notedeck, a note-taking application, and uses its default database directory. By connecting AI models with Nostr data, this server allows for sophisticated querying scenarios, enhancing the ability to search and analyze Nostr notes. It''s particularly useful for applications and AI assistants that require access to local Nostr data through a standardized interface.', '@damus-io', 'databases', 'Unknown', 8, 'https://github.com/damus-io/nostrdb-mcp', 'nostrdb-mcp', 3979, 'https://github.com/damus-io.png?size=128', '2026-03-09T05:21:01.944225+00:00'),
  ('microsoft-sql-server-mssql', 'Microsoft SQL Server (MSSQL)', 'This MCP server implementation, developed by Dana K. Williams, provides secure interaction with Microsoft SQL Server databases. Built with Python and leveraging libraries like mcp and pymssql, it offers a bridge between AI assistants and SQL Server data. The implementation focuses on security, with detailed guidance on creating restricted SQL logins, implementing row-level security, and following best practices for monitoring and auditing. It''s particularly useful for organizations needing to integrate SQL Server data into AI workflows while maintaining strict security controls, enabling tasks like data analysis, reporting, and database management through AI interfaces while ensuring data protection and compliance.', '@richardhan', 'databases', 'Unknown', 317, 'https://github.com/richardhan/mssql_mcp_server', NULL, 0, 'https://github.com/richardhan.png?size=128', '2026-03-09T05:21:01.944238+00:00'),
  ('singlestore', 'SingleStore', 'This SingleStore MCP server, developed by Dana K. Williams, enables AI assistants to interact with SingleStore databases through a standardized interface. It integrates with the SingleStore Python connector to provide database querying capabilities. Built with FastAPI and leveraging asynchronous programming, it offers efficient handling of database operations. The server implements robust error handling, logging, and configuration management. By abstracting SingleStore interactions, it allows AI systems to easily incorporate relational database operations into their workflows. This implementation is particularly useful for data analysts, developers, and AI researchers working with large-scale, real-time data processing and analytics applications.', '@madhukarkumar', 'databases', 'Unknown', 4, 'https://github.com/madhukarkumar/singlestore-mcp-server', NULL, 0, 'https://github.com/madhukarkumar.png?size=128', '2026-03-09T05:21:01.944250+00:00'),
  ('decent-sampler-drums', 'Decent Sampler Drums', 'This MCP server, developed by dandeliongold, provides tools for generating DecentSampler drum kit configurations. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers functionality for analyzing WAV samples and generating XML-based drum group configurations. The implementation focuses on creating flexible velocity layers, handling sample path mapping, and configuring muting groups. By connecting AI models with DecentSampler''s preset creation process, this server enables sophisticated drum kit design scenarios, enhancing the ability to create custom virtual instruments. It''s particularly useful for music producers, sound designers, and AI assistants involved in virtual instrument development and sample library management.', '@dandeliongold', 'development', 'Unknown', 0, 'https://github.com/dandeliongold/mcp-decent-sampler-drums', NULL, 0, 'https://github.com/dandeliongold.png?size=128', '2026-03-09T05:21:01.944280+00:00'),
  ('fastmcp-todo', 'FastMCP Todo', 'This FastMCP-based Todo Server, developed for the Swarmonomicon project, receives todo requests via FastMCP and stores them in MongoDB. It integrates with the Swarmonomicon todo worker, providing a Python-based implementation for task management and distribution. The server offers features like adding todos with priorities and target agents, querying todos with filters and projections, and supports real-time updates via MQTT, making it suitable for AI-driven task automation and collaborative workflows.', '@madnessengineering', 'databases', 'Unknown', 9, 'https://github.com/madnessengineering/omnispindle', NULL, 0, 'https://github.com/madnessengineering.png?size=128', '2026-03-09T05:21:01.944292+00:00'),
  ('notion-todo', 'Notion Todo', 'This MCP server, developed by Dan Hilse, enables AI assistants like Claude to interact with a personal Notion todo list. Built in Python, it provides a minimalist interface for managing tasks with just three properties: task name, scheduling (today/later), and completion status. The implementation integrates with the Notion API to add, view, and update todos in a specific database structure. By connecting AI capabilities with a streamlined task management system, this server enables AI assistants to help organize daily activities and track personal productivity. It is particularly useful for individuals seeking a simple, AI-augmented todo list without complex features, prioritizing ease of use and quick task entry over advanced project management functionality.', '@danhilse', 'databases', 'Unknown', 206, 'https://github.com/danhilse/notion_mcp', NULL, 0, 'https://github.com/danhilse.png?size=128', '2026-03-09T05:21:01.944304+00:00'),
  ('youtube-research', 'YouTube Research', 'This YouTube research MCP server, developed by an unnamed author, integrates with the YouTube API to perform aggregated video searches. Built with TypeScript and leveraging the Model Context Protocol SDK, it uses sampling to generate search queries from user topics, fetches both short and long videos, and compiles results with metadata. The server implements sequential thinking, logging each step as separate ''thoughts'' for operational visibility. By abstracting YouTube search complexities, it enables AI assistants to efficiently gather video content on specified topics. This implementation is particularly useful for content curation, trend analysis, and research tasks, facilitating use cases such as creating themed playlists, analyzing video popularity across topics, or gathering educational resources.', '@danhilse', 'development', 'Unknown', 8, 'https://github.com/danhilse/youtube_research_mcp', NULL, 0, 'https://github.com/danhilse.png?size=128', '2026-03-09T05:21:01.944335+00:00'),
  ('transport-nsw', 'Transport NSW', 'Transport NSW MCP Server provides a structured interface to access New South Wales public transportation data through the official Transport NSW API. It offers tools for finding transport stops around specific locations and retrieving service alerts and disruptions across different transport modes (trains, buses, ferries, etc.). Built with Python and leveraging Swagger-generated client code, the implementation handles API authentication, request formatting, and response parsing, making it ideal for applications requiring real-time public transport information, trip planning, or monitoring service disruptions in the NSW transport network.', '@danhussey', 'development', 'Unknown', 0, 'https://github.com/danhussey/transportnsw-mcp', NULL, 0, 'https://github.com/danhussey.png?size=128', '2026-03-09T05:21:01.944361+00:00'),
  ('dev-kit', 'Dev Kit', 'The Dev-Kit MCP Server transforms any codebase into an MCP-compliant system by providing scoped, authorized operations within a project''s root directory. Built by Daniel Avdar using FastMCP and GitPython, it offers secure file operations (create, edit, move, delete, rename), Git repository management (status, commit, push, pull, branch operations), Makefile command execution, and code exploration tools (file search, text search, line reading). The server enforces strict path validation to prevent operations outside the authorized directory, making it particularly valuable for AI-assisted development workflows in VS Code Copilot and other development tools where agents need controlled access to repository operations without compromising system security.', '@danielavdar', 'development', 'Unknown', 6, 'https://github.com/danielavdar/dev-kit-mcp-server', 'dev-kit-mcp-server', 11661, 'https://github.com/danielavdar.png?size=128', '2026-03-09T05:21:01.944389+00:00'),
  ('quickbase', 'Quickbase', 'MCP-Quickbase provides a standardized interface for interacting with Quickbase''s JSON RESTful API through Claude and other MCP clients. This server implementation supports a wide range of operations including querying records, managing table relationships, handling file attachments, and user management. Built with both Python and Node.js components, it authenticates with Quickbase using environment variables and exposes tools for common database operations like creating, updating, and deleting records. The server is particularly valuable for users who need to access and manipulate Quickbase data directly within their AI assistant conversations without switching contexts.', '@danielbushman', 'databases', 'Unknown', 8, 'https://github.com/danielbushman/mcp-quickbase', NULL, 0, 'https://github.com/danielbushman.png?size=128', '2026-03-09T05:21:01.944404+00:00'),
  ('azure-devops-boards', 'Azure DevOps Boards', 'Integrates with Azure DevOps Boards to enable natural language work item management including creating, updating, and querying work items via structured filters or WIQL. Provides board operations like listing teams and boards, fetching board items, and managing work item relationships and comments. Uses Azure CLI authentication for seamless credential handling.', '@danielealbano', 'cloud', 'Unknown', 6, 'https://github.com/danielealbano/mcp-for-azure-devops-boards', NULL, 0, 'https://github.com/danielealbano.png?size=128', '2026-03-09T05:21:01.944422+00:00'),
  ('superhero-team-management', 'Superhero Team Management', 'HeroMCP is a .NET-based server implementation that provides a superhero team management API through the Model Context Protocol. Built by Daniel Mackay, it leverages a clean architecture pattern with domain-driven design principles to offer tools for creating and managing heroes with various superpowers, forming teams, and executing missions. The server includes features for tracking power levels, mission status, and team composition, while the client implementation uses Microsoft''s Kiota SDK to generate type-safe API clients. This implementation demonstrates how to build a robust MCP server with modern .NET 9 practices including minimal APIs, error handling with the Results pattern, and integration testing.', '@danielmackay', 'development', 'Unknown', 5, 'https://github.com/danielmackay/dotnet-mcp-hero', NULL, 0, 'https://github.com/danielmackay.png?size=128', '2026-03-09T05:21:01.944481+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('text-editor', 'Text Editor', 'MCP Text Editor Server provides a Python-based interface for AI assistants to manipulate text files through a structured editing workflow. Built with FastMCP, it implements a two-step edit process with content verification using SHA-256 hashing to prevent conflicts during concurrent edits. The server offers tools for file management, content access, text search, and syntax validation for Python and JavaScript files. It enforces safety through line limits and automatic syntax checking before applying changes, making it ideal for collaborative code editing where multiple agents need controlled access to modify source files.', '@danielpodrazka', 'development', 'Unknown', 13, 'https://github.com/danielpodrazka/editor-mcp', NULL, 0, 'https://github.com/danielpodrazka.png?size=128', '2026-03-09T05:21:01.944507+00:00'),
  ('nixos-search', 'NixOS Search', 'Provides search capabilities for NixOS configuration options and packages through the official NixOS search API. Built with TypeScript using the Model Context Protocol SDK, it exposes tools for finding configuration settings with their types, defaults, and descriptions, as well as discovering available packages with version and maintainer information. The implementation uses Elasticsearch queries with multi-match and wildcard support, includes pagination for large result sets, and formats output for readability.', '@danielramosacosta', 'development', 'Unknown', 1, 'https://github.com/danielramosacosta/nixos-mcp', NULL, 0, 'https://github.com/danielramosacosta.png?size=128', '2026-03-09T05:21:01.944533+00:00'),
  ('investbuddy', 'InvestBuddy', 'Integrates LSTM-based stock price predictions into Claude Desktop. Provides 10-day price forecasts with confidence scores, market regime detection (bull/bear/sideways), portfolio optimization using reinforcement learning, and AI-powered stock discovery. Requires InvestBuddy API key for access to prediction models.', '@danielrz', 'ai-ml', 'Unknown', 2, 'https://github.com/danielrz/investbuddy-mcp-server', NULL, 0, 'https://github.com/danielrz.png?size=128', '2026-03-09T05:21:01.944562+00:00'),
  ('lighthouse', 'Lighthouse', 'This MCP server integrates Google Lighthouse web performance auditing capabilities, built by Daniel Sogl to provide automated website performance, accessibility, SEO, and best practices analysis through the Lighthouse testing framework. The implementation enables programmatic execution of Lighthouse audits against web pages, returning detailed performance metrics, optimization recommendations, and compliance scores that can be used for continuous monitoring, automated testing pipelines, or bulk website analysis workflows.', '@danielsogl', 'development', 'Unknown', 47, 'https://github.com/danielsogl/lighthouse-mcp-server', NULL, 0, 'https://github.com/danielsogl.png?size=128', '2026-03-09T05:21:01.944629+00:00'),
  ('software-planning-tool', 'Software Planning Tool', 'Software Planning MCP is a tool that helps developers break down software goals into actionable implementation plans through a structured, question-based approach. Developed by Daniel Steigman, it guides users through a sequential thinking process to understand requirements, analyze technical considerations, and develop detailed task lists with complexity scores and code examples. The server stores goals and implementation plans locally, provides tools for managing todos, and uses a sophisticated parsing system to convert natural language plans into structured task items. Particularly valuable for developers who want to systematically approach complex software projects without losing track of implementation details.', '@nighttrek', 'development', 'Unknown', 399, 'https://github.com/nighttrek/software-planning-mcp', NULL, 0, 'https://github.com/nighttrek.png?size=128', '2026-03-09T05:21:01.944657+00:00'),
  ('interaction-mcp', 'Interaction MCP', 'MCP Interactive Service enables high-frequency communication between AI tools (like Cursor and Windsurf) and users through multiple interface options including CLI, PyQt, and Web. Developed by DanielZhao1990, it provides two core tools: option selection for user decision-making and information requests for supplementary input. The service supports multiple languages, offers both stdio and SSE transport protocols for flexible connectivity, and significantly improves AI interaction efficiency by allowing users to confirm approaches before execution, reducing wasted API calls and computational resources while maintaining focus on correct solution paths.', '@danielzhao1990', 'ai-ml', 'Unknown', 28, 'https://github.com/danielzhao1990/interaction-mcp', NULL, 0, 'https://github.com/danielzhao1990.png?size=128', '2026-03-09T05:21:01.944706+00:00'),
  ('zaragoza-tram', 'Zaragoza Tram', 'DNDzgz MCP Server provides real-time information about the Zaragoza tram system through the Model Context Protocol. It offers two main tools: one for retrieving current tram arrival estimations at specific stations and another for listing all available tram stations in the city. The server connects to the DNDzgz API and returns the data in JSON format, making it useful for AI assistants to help users plan their public transportation in Zaragoza, Spain.', '@danilat', 'ai-ml', 'Unknown', 10, 'https://github.com/danilat/mcp-dndzgz', NULL, 0, 'https://github.com/danilat.png?size=128', '2026-03-09T05:21:01.944741+00:00'),
  ('glm-vision', 'GLM Vision', 'This MCP server by danilofalcao integrates GLM-4.5V vision model from Z.AI, providing image analysis capabilities through a single tool that supports both local files and URLs. Built with FastMCP and httpx for async HTTP operations, it features configurable parameters including temperature control, thinking mode for exposing model reasoning, and adjustable token limits up to 64K. The implementation includes comprehensive error handling, base64 encoding for local images, MIME type detection, and GitHub Actions workflows for CI/CD with PyPI publishing, making it valuable for developers who need AI-powered image analysis integrated into their workflows using Z.AI''s GLM vision models rather than OpenAI''s alternatives.', '@danilofalcao', 'development', 'Unknown', 7, 'https://github.com/danilofalcao/mcp-server-glm-vision', NULL, 0, 'https://github.com/danilofalcao.png?size=128', '2026-03-09T05:21:01.944766+00:00'),
  ('n8n-workflow-builder', 'n8n Workflow Builder', 'Integrates with n8n automation platform to create, modify, execute, and monitor workflows through comprehensive lifecycle management with validation, template system, and credential handling.', '@danilonovaisv', 'development', 'Unknown', 2, 'https://github.com/danilonovaisv/n8n-workflow-builder-gpt', NULL, 0, 'https://github.com/danilonovaisv.png?size=128', '2026-03-09T05:21:01.944783+00:00'),
  ('aws-lambda', 'AWS Lambda', 'MCP2Lambda enables Large Language Models to interact with AWS Lambda functions as tools without code changes. It acts as a bridge between MCP clients and Lambda functions, allowing models to access private resources, interact with AWS services, and leverage Lambda''s capabilities for data processing and external API access. The implementation includes autodiscovery of Lambda functions and secure invocation, making it useful for extending AI capabilities in enterprise environments with existing AWS infrastructure.', '@danilop', 'cloud', 'Unknown', 111, 'https://github.com/danilop/mcp2lambda', NULL, 0, 'https://github.com/danilop.png?size=128', '2026-03-09T05:21:01.944800+00:00'),
  ('arxiv-search', 'arXiv Search', 'The arXiv Search MCP server provides tools for searching and retrieving academic papers from arXiv.org directly within Claude. Built with Deno and the FastMCP library, it enables users to search for papers by category and retrieve the latest submissions sorted by date. The implementation handles XML parsing from the arXiv API and formats results with titles, authors, summaries, and links. This tool is particularly useful for researchers and academics who want to stay updated on recent publications in specific fields without leaving their conversation with Claude.', '@danimal141', 'development', 'Unknown', 4, 'https://github.com/danimal141/arxiv-search-mcp', NULL, 0, 'https://github.com/danimal141.png?size=128', '2026-03-09T05:21:01.944825+00:00'),
  ('make-com-automation', 'Make.com Automation', 'Unofficial MCP server for Make.com automation - build, validate & deploy scenarios via AI', '@danishashko', 'development', 'Unknown', 3, 'https://github.com/danishashko/make-mcp', NULL, 0, 'https://github.com/danishashko.png?size=128', '2026-03-09T05:21:01.944842+00:00'),
  ('swagger', 'Swagger', 'Swagger-MCP is a Go-based server that transforms Swagger/OpenAPI specifications into dynamic MCP tools, enabling AI assistants to interact with any REST API without custom integration work. It features automatic endpoint discovery, parameter validation, request formatting, and security handling (Basic, Bearer, API Key), while supporting both Swagger 2.0 and OpenAPI 3.0 formats. The implementation includes path/method filtering capabilities and can operate in both stdio and Server-Sent Events (SSE) modes, making it valuable for developers who need to quickly expose existing API documentation as interactive tools for AI assistants.', '@danishjsheikh', 'ai-ml', 'Unknown', 80, 'https://github.com/danishjsheikh/swagger-mcp', NULL, 0, 'https://github.com/danishjsheikh.png?size=128', '2026-03-09T05:21:01.944901+00:00'),
  ('infomaniak', 'Infomaniak', 'Provides comprehensive access to the Infomaniak API for managing Swiss cloud services including domains, DNS records, email hosting, web hosting, kDrive cloud storage, Swiss Backup, VPS instances, and dedicated servers. Built with TypeScript and includes robust input validation using Zod schemas and support for both stdio and HTTP transports with session management. Useful for automating infrastructure management, DNS configuration, email administration, and cloud resource provisioning across Infomaniak''s Swiss-hosted platform.', '@daniviber', 'development', 'Unknown', 2, 'https://github.com/daniviber/infomaniak_mcp', NULL, 0, 'https://github.com/daniviber.png?size=128', '2026-03-09T05:21:01.944927+00:00'),
  ('todo-markdown', 'Todo Markdown', 'This MCP server provides AI assistants with todo list management capabilities backed by markdown file storage, built by Daniel Dewhurst using TypeScript with persistent UUID tracking for reliable item updates. The implementation offers five core tools for complete CRUD operations: listing todos with statistics, adding new items, updating text or completion status, deleting specific todos, and bulk clearing completed items, all stored in standard markdown checkbox format with hidden HTML comment IDs for persistence. Built with comprehensive error handling for file permissions, configurable file paths via environment variables, and full test coverage using Vitest, it serves developers needing simple task management integrated into their AI workflows, teams requiring persistent todo tracking in human-readable markdown format, and users wanting to maintain todo lists that can be easily edited both programmatically through AI assistants and manually in any text editor.', '@danjdewhurst', 'development', 'Unknown', 5, 'https://github.com/danjdewhurst/todo-md-mcp', '@danjdewhurst/todo-md-mcp', 1153, 'https://github.com/danjdewhurst.png?size=128', '2026-03-09T05:21:01.944962+00:00'),
  ('langgraph-coding-team', 'LangGraph Coding Team', 'This project implements a small team of coding agents using LangGraph and MCP. The agents use MCP servers to provide tools and capabilities through a unified gateway. The overall objective of this agent team is to take requirements and code context and create multiple implementations of proposed features; human operators can then choose their preferred approach and proceed, discarding the others.', '@danmas0n', 'development', 'Unknown', 38, 'https://github.com/danmas0n/multi-agent-with-mcp', NULL, 0, 'https://github.com/danmas0n.png?size=128', '2026-03-09T05:21:01.945002+00:00'),
  ('react-native-storybook', 'React Native Storybook', 'This MCP server implementation provides a bridge to Storybook, enabling AI assistants to interact with and retrieve stories from Storybook configurations. Developed by Danny Williams, it offers a tool for getting stories from a specified Storybook config directory. The server is built using TypeScript and integrates with the Model Context Protocol SDK, making it useful for developers working on React Native projects who want to incorporate AI-assisted story management and retrieval.', '@dannyhw', 'development', 'Unknown', 24, 'https://github.com/dannyhw/mcp-storybook', NULL, 0, 'https://github.com/dannyhw.png?size=128', '2026-03-09T05:21:01.945030+00:00'),
  ('hackernews-api', 'HackerNews API', 'This MCP implementation, developed by Danny Lee, provides a simple server-client architecture for fetching data from the HackerNews API. Built with Python and leveraging the MCP and Anthropic libraries, it offers tools for retrieving top stories, user information, and story details. The implementation focuses on demonstrating basic MCP functionality while providing a practical interface to a popular news aggregator. By connecting AI models with HackerNews data, this server enables use cases such as content analysis, trend identification, and user behavior studies. It''s particularly useful for developers looking to understand MCP architecture or build applications that require programmatic access to HackerNews content through a standardized interface.', '@dannylee1020', 'development', 'Unknown', 0, 'https://github.com/dannylee1020/toy-mcp', NULL, 0, 'https://github.com/dannylee1020.png?size=128', '2026-03-09T05:21:01.945058+00:00'),
  ('youtube-data-api', 'YouTube Data API', 'This MCP server provides AI assistants with direct access to YouTube''s Data API v3 and transcript extraction capabilities, featuring 14 specialized tools for video analysis, channel management, playlist operations, and content discovery. Built with Python using FastMCP and httpx, it supports comprehensive video metadata retrieval, engagement analysis with calculated metrics like like rates and comment rates, trending video discovery by region, advanced search with multiple sorting options, and automatic transcript extraction using the youtube-transcript-api library. The implementation includes intelligent URL parsing for various YouTube formats, robust error handling with quota management, and engagement benchmarking against industry averages, making it valuable for content research workflows, social media analysis, educational content curation, and building AI assistants that need programmatic access to YouTube''s full data ecosystem without manual platform navigation.', '@dannysubsense', 'development', 'Unknown', 10, 'https://github.com/dannysubsense/youtube-mcp-server', NULL, 0, 'https://github.com/dannysubsense.png?size=128', '2026-03-09T05:21:01.945138+00:00'),
  ('dan-vega-courses', 'Dan Vega Courses', 'A lightweight Spring Boot MCP server for exposing course information from Dan Vega''s YouTube tutorials. The server provides two primary tools for retrieving course details: listing all available courses and searching for a specific course by title. Designed as a simple, extensible example of creating a data-driven MCP server using Spring AI''s tooling framework.', '@danvega', 'ai-ml', 'Unknown', 16, 'https://github.com/danvega/dv-courses-mcp', NULL, 0, 'https://github.com/danvega.png?size=128', '2026-03-09T05:21:01.945172+00:00'),
  ('spring-i-o', 'Spring I/O', 'This Spring I/O MCP server provides AI assistants with access to Spring I/O 2025 conference session data through a Spring Boot application built by Dan Vega using Spring AI''s MCP server integration. The implementation loads conference information from JSON including talks, workshops, speakers, room assignments, and scheduling details, exposing this data through a single tool that returns all sessions for the Barcelona conference. Built with Spring Boot 3.5 and configured for STDIO transport with disabled logging to prevent MCP protocol interference, it''s valuable for building AI-powered conference navigation tools, smart scheduling assistants, or conference apps that need conversational access to session information.', '@danvega', 'development', 'Unknown', 11, 'https://github.com/danvega/spring-io-mcp', NULL, 0, 'https://github.com/danvega.png?size=128', '2026-03-09T05:21:01.945201+00:00'),
  ('springone-2025', 'SpringOne 2025', 'This Spring Boot MCP server implementation by Dan Vega provides AI assistants with access to SpringOne 2025 conference session data through tools, prompts, and resources. Built with Spring AI''s MCP server capabilities, it exposes session information via tools for counting sessions by date and retrieving all sessions, includes predefined prompts for conference analysis, and provides speaker biographical data as resources. The implementation demonstrates how to create MCP servers using Spring''s programming model with JSON data loading, making it useful for conference attendees wanting AI-powered session discovery, schedule planning, and speaker information lookup.', '@danvega', 'ai-ml', 'Unknown', 3, 'https://github.com/danvega/springone-mcp', NULL, 0, 'https://github.com/danvega.png?size=128', '2026-03-09T05:21:01.945248+00:00'),
  ('neo4j', 'Neo4j', 'This Neo4j MCP server, developed by Daichi Okazaki, enables AI assistants to interact with Neo4j graph databases through natural language. Built with TypeScript using the @modelcontextprotocol/sdk and neo4j-driver, it provides tools for executing Cypher queries, creating nodes and relationships, and performing complex graph operations. The implementation abstracts the intricacies of Neo4j''s query language and data structures, allowing AI systems to seamlessly work with graph data. By connecting AI capabilities with powerful graph database functionality, this server facilitates use cases such as knowledge graph exploration, social network analysis, recommendation systems, and complex data relationship modeling.', '@da-okazaki', 'databases', 'Unknown', 57, 'https://github.com/da-okazaki/mcp-neo4j-server', '@alanse/mcp-neo4j-server', 4355, 'https://github.com/da-okazaki.png?size=128', '2026-03-09T05:21:01.945259+00:00'),
  ('dap-debugger', 'DAP Debugger', 'This MCP server provides AI assistants with comprehensive debugging capabilities through the Debug Adapter Protocol (DAP), built by the Delve team using Go with integration to DAP-compatible debuggers like Delve. The implementation offers complete debugging session management including starting/stopping debuggers, setting line and function breakpoints, controlling program execution (continue, step in/out/over, pause), inspecting program state (threads, stack traces, variables, scopes), evaluating expressions, and attaching to running processes. Built with SSE transport support and extensive DAP client functionality, it serves developers needing AI-powered debugging assistance, teams requiring programmatic control of debugging sessions through conversational interfaces, and applications that need to integrate debugging capabilities into automated workflows with support for multiple programming languages through DAP-compatible debuggers.', '@go-delve', 'development', 'Unknown', 56, 'https://github.com/go-delve/mcp-dap-server', NULL, 0, 'https://github.com/go-delve.png?size=128', '2026-03-09T05:21:01.945295+00:00'),
  ('dappier-real-time-data-search', 'Dappier (Real-Time Data Search)', 'Dappier MCP Server connects AI assistants to real-time, rights-cleared data from trusted sources through the Model Context Protocol. Developed by Amaan Mohammed at AI20Labs, it provides two main tools: real-time data search for retrieving web search results, financial information, and news; and AI recommendations for personalized content discovery with structured JSON responses. The server integrates with Claude Desktop through a simple configuration process and supports customizable parameters like similarity filtering and search algorithms, making it ideal for workflows requiring up-to-date information from premium publishers without leaving the conversation interface.', '@dappierai', 'ai-ml', 'Unknown', 39, 'https://github.com/dappierai/dappier-mcp', NULL, 0, 'https://github.com/dappierai.png?size=128', '2026-03-09T05:21:01.945348+00:00'),
  ('feishu', 'Feishu', 'An MCP server implementation for integrating with Feishu (Lark) messaging platform, allowing AI assistants to interact with Feishu users and access Feishu data.', '@darknoah', 'communication', 'Unknown', 7, 'https://github.com/darknoah/feishu-mcp', NULL, 0, 'https://github.com/darknoah.png?size=128', '2026-03-09T05:21:01.945367+00:00'),
  ('vibe', 'Vibe', 'Wraps the Mistral Vibe CLI as a subagent, enabling programmatic task execution through two core tools: vibe_run for starting new tasks and vibe_resume for continuing previous sessions. The server manages session persistence per project directory, tracks costs from Vibe logs, and supports all Vibe CLI options including plan mode, tool restrictions, and custom agents. Useful for integrating Vibe''s capabilities into larger workflows while maintaining session continuity and cost monitoring across different projects.', '@darkphilosophy', 'productivity', 'Unknown', 2, 'https://github.com/darkphilosophy/vibe-mcp', NULL, 0, 'https://github.com/darkphilosophy.png?size=128', '2026-03-09T05:21:01.945403+00:00'),
  ('darp-engine', 'DARP Engine', 'DARPEngine is a search engine for MCP servers that provides smart search capabilities and routing tools. Developed by DARPAI, it stores metadata for MCP servers and offers both CLI and API access to search functionality. The implementation includes a registry service for server management and a specialized MCP server that can route user requests to the most appropriate tools found during search. It features the ability to analyze user queries, identify relevant servers based on their capabilities, and execute tools across multiple servers to provide comprehensive responses. Particularly useful for discovering and utilizing distributed MCP tools without requiring users to know which specific servers to connect to.', '@darpai', 'ai-ml', 'Unknown', 12, 'https://github.com/darpai/darp_engine', NULL, 0, 'https://github.com/darpai.png?size=128', '2026-03-09T05:21:01.945453+00:00'),
  ('dart-project-management', 'Dart Project Management', 'Dart MCP Server provides AI assistants with direct access to Dart''s project management platform, enabling task and document management through a comprehensive set of tools. Built by the Dart team, it allows for creating, retrieving, updating, and deleting tasks and documents, with support for filtering by various attributes like assignees, status, and priority. The server exposes both structured tools and resource templates that make it easy for AI assistants to interact with Dart''s API, and includes prompts for common actions like creating tasks or summarizing work items. It''s particularly valuable for teams using Dart who want to manage their projects directly through AI assistants like Claude without switching contexts.', '@its-dart', 'productivity', 'Unknown', 126, 'https://github.com/its-dart/dart-mcp-server', 'dart-mcp-server', 17745, 'https://github.com/its-dart.png?size=128', '2026-03-09T05:21:01.945499+00:00'),
  ('cosmwasm-social-graph', 'CosmWasm Social Graph', 'CW-Graph MCP Server provides a TypeScript implementation for interacting with a CosmWasm-based social graph smart contract on a blockchain. It enables AI assistants to create, update, query, and delete cyberlinks (graph relationships) through a set of well-defined tools that communicate with the blockchain via CosmJS. The server handles wallet management, transaction signing, and result formatting, making it particularly useful for applications that need to store structured data like conversation threads, social connections, or content relationships in a decentralized manner.', '@dasein108', 'development', 'Unknown', 1, 'https://github.com/dasein108/mcp-cw-graph', NULL, 0, 'https://github.com/dasein108.png?size=128', '2026-03-09T05:21:01.945529+00:00'),
  ('cyber', 'Cyber', 'The Cyb MCP Server enables AI agents to interact with the Cyber blockchain network, a decentralized knowledge graph built on IPFS and Cosmos SDK technology. Developed as a contribution to the Great Web Foundation, it provides three core tools: creating cyberlinks between IPFS content hashes to build semantic connections, searching the existing knowledge graph with optional content retrieval, and fetching content directly from IPFS through Cyber''s gateway. The server operates in two modes - read-only for exploration without requiring wallet credentials, or full mode with mnemonic phrase support for creating new cyberlinks and signing blockchain transactions, making it valuable for building decentralized knowledge applications and contributing to censorship-resistant web infrastructure.', '@dasein108', 'development', 'Unknown', 2, 'https://github.com/dasein108/cyb-mcp', NULL, 0, 'https://github.com/dasein108.png?size=128', '2026-03-09T05:21:01.945559+00:00'),
  ('face-generator', 'Face Generator', 'This face generator MCP server, developed by Stefan Neidig, provides a tool for generating human face images using thispersondoesnotexist.com. Built with TypeScript and leveraging the Sharp image processing library, it offers customizable image generation with options for shape (square, circle, rounded rectangle), dimensions, and batch processing. The server implements transparent backgrounds for non-square shapes and supports configurable output directories. By abstracting face image generation into a standardized MCP interface, it enables AI systems to easily create diverse sets of realistic human faces. This implementation is particularly useful for applications involving user interface prototyping, avatar creation, and dataset generation for machine learning tasks related to facial recognition or analysis.', '@dasheck0', 'development', 'Unknown', 6, 'https://github.com/dasheck0/face-generator', '@dasheck0/face-generator', 4714, 'https://github.com/dasheck0.png?size=128', '2026-03-09T05:21:01.945592+00:00'),
  ('file-system-utilities', 'File System Utilities', 'MCP Server Developer Tool provides a set of utilities for AI assistants to interact with the local file system and execute shell commands. Built by Daniel, it implements four core tools: executing shell commands with timeout control, displaying file contents with line range options, searching files using regular expressions, and writing content to files with append or overwrite modes. The server uses Go''s reflection capabilities to dynamically handle tool execution and communicates via stdio transport, making it suitable for integration with any MCP-compatible client. This implementation is particularly valuable for development workflows requiring file manipulation, code inspection, and command execution without leaving the conversation interface.', '@da-snap', 'development', 'Unknown', 1, 'https://github.com/da-snap/mcp-server-developer-tool', NULL, 0, 'https://github.com/da-snap.png?size=128', '2026-03-09T05:21:01.945621+00:00'),
  ('database-connector', 'Database Connector', 'Database MCP Server provides a unified interface for connecting to and interacting with multiple database systems (SQLite, PostgreSQL, MySQL/MariaDB, and SQL Server) through a consistent set of tools. It features connection management, query execution, schema manipulation, and transaction support across all supported database types. The implementation uses a modular architecture with database-specific connectors that abstract away differences between database systems, making it ideal for applications that need to work with multiple database types or for AI assistants that require database access capabilities without dealing with database-specific syntax and connection details.', '@georgi-terziyski', 'databases', 'Unknown', 3, 'https://github.com/georgi-terziyski/database_mcp_server', NULL, 0, 'https://github.com/georgi-terziyski.png?size=128', '2026-03-09T05:21:01.945634+00:00'),
  ('databridge', 'DataBridge', 'This MCP server implementation provides a bridge to DataBridge, enabling AI assistants to ingest and retrieve information from a local database. Developed as part of the databridge-mcp project, it offers two main tools: one for ingesting user observations with metadata, and another for retrieving relevant information based on user queries. The server uses FastMCP for efficient request handling and is designed to work with Python 3.11+. It''s particularly useful for AI applications requiring persistent storage and retrieval of contextual information, supporting use cases like maintaining conversation history or building knowledge bases from user interactions. The implementation focuses on simplicity and ease of integration, making it suitable for both development and production environments.', '@morphik-org', 'databases', 'Unknown', 23, 'https://github.com/morphik-org/morphik-mcp', NULL, 0, 'https://github.com/morphik-org.png?size=128', '2026-03-09T05:21:01.945658+00:00'),
  ('databutton', 'Databutton', 'Databutton MCP Server enables AI assistants to plan and create initial scaffolding for business applications built with React frontends and Python backends. Developed by Databutton, it specifically focuses on the planning phase of app development, helping users generate a structured approach before implementation begins. The server integrates with Claude Desktop through stdio communication and can be installed either manually or via Smithery. It leverages the Model Context Protocol SDK to facilitate the creation of beautiful business applications with complex functionality, making it particularly valuable for developers looking to quickly establish a solid foundation for their Databutton-powered projects.', '@databutton', 'development', 'Unknown', 27, 'https://github.com/databutton/databutton-mcp', 'databutton', 15900, 'https://github.com/databutton.png?size=128', '2026-03-09T05:21:01.945686+00:00'),
  ('cisco-apic', 'Cisco APIC', 'This MCP server provides direct integration with Cisco APIC (Application Policy Infrastructure Controller) for managing Application Centric Infrastructure fabrics through REST API operations. Built using Python with FastMCP, httpx, and a singleton authentication manager, it offers tools for fetching managed objects by class name and creating automated configuration backups to SCP servers with AES encryption. The implementation handles APIC session token management with automatic renewal, SSL certificate bypassing for lab environments, and includes comprehensive error handling for network operations, making it valuable for network automation workflows, infrastructure monitoring, and automated backup operations where AI assistants need to interact with Cisco ACI fabrics programmatically.', '@datacenter', 'ai-ml', 'Unknown', 10, 'https://github.com/datacenter/mcp_server_for_cisco_aci', NULL, 0, 'https://github.com/datacenter.png?size=128', '2026-03-09T05:21:01.945775+00:00'),
  ('dataforseo', 'DataForSEO', 'The DataForSEO MCP server provides AI assistants with direct access to DataForSEO''s SEO and marketing analytics APIs. Built with TypeScript, it exposes tools across four main modules: SERP for search engine results, Keywords Data for keyword research, OnPage for content analysis, and DataForSEO Labs for competitive research and market analysis. The server handles authentication with the DataForSEO API, implements field filtering for focused data retrieval, and follows a modular architecture that makes it easy to extend with additional tools. This implementation is particularly valuable for digital marketers and SEO professionals who need to analyze search rankings, research keywords, evaluate competitors, and optimize content without leaving their AI assistant conversation.', '@dataforseo', 'development', 'Unknown', 155, 'https://github.com/dataforseo/mcp-server-typescript', NULL, 0, 'https://github.com/dataforseo.png?size=128', '2026-03-09T05:21:01.945803+00:00'),
  ('datagraph', 'DataGraph', 'Provides AI assistants access to structured urban and civic datasets through the GOSR (Goal-Obstacle-Solution-Resource) framework. Includes NYC subway data, community loneliness programs, violence prevention resources, building permits, property sales, and demographic profiles across multiple cities. Enables natural language queries for civic tech, policy research, and community problem-solving.', '@team-earth', 'development', 'Unknown', 0, 'https://github.com/team-earth/datagraph-city-mcp-server', NULL, 0, 'https://github.com/team-earth.png?size=128', '2026-03-09T05:21:01.945824+00:00'),
  ('nasa-earthdata', 'NASA Earthdata', 'Earthdata MCP Server provides a bridge between AI assistants and NASA''s Earthdata platform, enabling search and retrieval of Earth science datasets and data granules. Built with FastMCP, it exposes two main tools: search_earth_datasets for discovering datasets based on keywords, temporal ranges, and geographic boundaries, and search_earth_datagranules for retrieving specific data granules by dataset short name. This implementation is particularly valuable for researchers, scientists, and analysts who need to access NASA Earth observation data directly through conversational AI interfaces without switching to specialized data portals.', '@datalayer', 'ai-ml', 'Unknown', 23, 'https://github.com/datalayer/earthdata-mcp-server', 'earthdata_mcp_server', 0, 'https://github.com/datalayer.png?size=128', '2026-03-09T05:21:01.945880+00:00'),
  ('jupyter-earth-data', 'Jupyter Earth Data', 'Jupyter Earth MCP Server provides a bridge between AI assistants and Jupyter notebooks for Earth science data analysis. Developed by Datalayer, this Python-based server enables downloading NASA Earth Data granules directly into Jupyter notebooks through a simple interface. The implementation leverages jupyter-kernel-client and jupyter-nbmodel-client to programmatically create and execute code cells in notebooks, allowing for parameterized data retrieval with options for temporal ranges and geographic bounding boxes. It''s particularly useful for Earth scientists and researchers who need to automate the acquisition of satellite data and integrate it seamlessly into their Jupyter-based analysis workflows.', '@datalayer', 'development', 'Unknown', 6, 'https://github.com/datalayer/jupyter-earth-mcp-server', 'jupyter_earth_mcp_server', 0, 'https://github.com/datalayer.png?size=128', '2026-03-09T05:21:01.945935+00:00'),
  ('jupyter-notebook-bridge', 'Jupyter Notebook Bridge', 'The Jupyter MCP Server provides a bridge between AI assistants and Jupyter notebooks, enabling models to programmatically create and execute code cells, add markdown content, and interact with Earth data through specialized tools. Built using the MCP protocol with both stdio and SSE transport options, it leverages the jupyter_kernel_client and jupyter_nbmodel_client libraries to manipulate notebook content and execute code in a running kernel. This implementation is particularly valuable for data science workflows where AI assistants need to generate executable code, document analysis with markdown, or facilitate Earth data retrieval and processing within Jupyter environments.', '@bitrsky', 'development', 'Unknown', 0, 'https://github.com/bitrsky/jupyter_mcp_server', NULL, 0, 'https://github.com/bitrsky.png?size=128', '2026-03-09T05:21:01.945965+00:00'),
  ('ai-translation', 'AI Translation', 'This AI-powered JSON translation tool by DatanoiseTV supports multiple translation providers (Google Gemini, OpenAI, and local Ollama/DeepSeek) with intelligent caching, multi-file deduplication, and format preservation capabilities. The implementation processes JSON i18n files by flattening complex nested structures, identifying duplicate strings across multiple files to minimize API calls, and maintaining exact JSON structure while translating only the string values. Key differentiators include automatic language detection, dry-run mode for cost estimation, format preservation for URLs/emails/templates, and MCP server integration for Claude Desktop, making it valuable for developers managing internationalization workflows who need efficient, cost-effective translation of large JSON locale files with consistent results across multiple target languages.', '@datanoisetv', 'communication', 'Unknown', 6, 'https://github.com/datanoisetv/translator-ai', 'translator-ai', 671, 'https://github.com/datanoisetv.png?size=128', '2026-03-09T05:21:01.946009+00:00'),
  ('keywordspeopleuse', 'KeywordsPeopleUse', 'KeywordsPeopleUse MCP Server integrates with the KeywordsPeopleUse API to provide AI assistants with keyword research capabilities through a standardized interface. Built with Node.js using the Model Context Protocol SDK, it offers four specialized tools: retrieving People Also Ask questions, Google Autocomplete suggestions, Reddit and Quora questions, and semantic keywords - all with language and country localization options. The implementation supports both local usage through direct configuration in Claude Desktop or Cursor, and remote access via mcp-remote proxy, making it valuable for content creators, SEO specialists, and marketers who need to understand search intent and discover relevant topics for their content.', '@data-skunks', 'ai-ml', 'Unknown', 5, 'https://github.com/data-skunks/kpu-mcp', NULL, 0, 'https://github.com/data-skunks.png?size=128', '2026-03-09T05:21:01.946060+00:00'),
  ('dataslayer', 'Dataslayer', 'Dataslayer MCP lets ChatGPT, Claude, and Mistral securely discover and query all your marketing and analytics sources connected to Dataslayer. The server exposes tools to list datasources, accounts, and fields; validate metrics, dimensions, filters, and attribution windows; and run queries that return ready-to-use tables. It covers major ad and analytics platforms, including Meta/Facebook Ads, Google Ads, Google Analytics 4, Google Search Console, Microsoft Advertising (Bing), TikTok Ads, LinkedIn Ads, X/Twitter Ads, Pinterest Ads, Snapchat Ads, Amazon Ads, and more. With natural-language instructions, models can ask for, e.g., spend, clicks, CTR, and ROAS by campaign for the last 30 days with 7-day click attribution, and the MCP translates that into a valid, paginated, credential-aware request that respects rate limits and handles errors gracefully. Results are returned as normalized tables that your agents can use directly for analysis, data QA, or report generation.', '@unknown', 'communication', 'Unknown', 0, 'https://www.dataslayer.ai/mcp', NULL, 0, NULL, '2026-03-09T05:21:01.946103+00:00'),
  ('astra-db', 'Astra DB', 'This MCP server implementation provides integration with Astra DB, a cloud-native database service. Developed by DataStax, it offers tools for managing collections and records within Astra DB, including creating, updating, deleting, and querying data. The server is designed to enable AI agents to interact directly with Astra DB, making it useful for applications that require scalable, cloud-based data storage and retrieval capabilities.', '@datastax', 'databases', 'Unknown', 39, 'https://github.com/datastax/astra-db-mcp', '@datastax/astra-db-mcp', 3350, 'https://github.com/datastax.png?size=128', '2026-03-09T05:21:01.946113+00:00'),
  ('apache-gravitino', 'Apache Gravitino', 'The MCP server for Apache Gravitino provides AI assistants with direct access to Gravitino metadata services through a FastMCP integration. Developed by Datastrato, this implementation exposes tools for managing catalogs, schemas, tables, tags, and user roles via a structured API that communicates with Gravitino''s REST endpoints. The server handles authentication through either basic auth or JWT tokens, maintains session management, and formats responses to optimize for context limits. It''s particularly valuable for data engineers and analysts who need to explore, tag, and manage metadata across data assets without switching from their AI assistant workflow.', '@datastrato', 'ai-ml', 'Unknown', 20, 'https://github.com/datastrato/mcp-server-gravitino', NULL, 0, 'https://github.com/datastrato.png?size=128', '2026-03-09T05:21:01.946160+00:00'),
  ('puchai-reddit-productivity', 'PuchAI Reddit & Productivity', 'Multi-tool MCP server implementation for the PuchAI Hackathon that combines Reddit content analysis with personal productivity features and data visualization capabilities. Built by datavorous, the implementation includes a Reddit scraper that searches recent posts across multiple subreddits using fuzzy keyword matching and calculates engagement intent scores based on upvotes, comments, velocity, and author karma to identify high-potential posts for market validation and sentiment analysis. Features comprehensive TODO list management, user preference storage for personalized AI interactions, and chart generation tools that create bar and line charts with custom styling, fonts, and data visualization options, making it valuable for entrepreneurs and researchers who want to monitor Reddit discussions for business opportunities while maintaining organized workflows and generating visual reports.', '@datavorous', 'productivity', 'Unknown', 1, 'https://github.com/datavorous/puch-mcp-hackathon', NULL, 0, 'https://github.com/datavorous.png?size=128', '2026-03-09T05:21:01.946216+00:00'),
  ('snowflake', 'Snowflake', 'This MCP server, developed by datawiz168, provides seamless integration with Snowflake databases. It implements a Python-based interface for executing SQL queries, retrieving results, and managing database connections through the Snowflake connector. The server exposes tools for running queries, fetching data, and interacting with Snowflake objects like tables and views. By leveraging Snowflake''s powerful cloud data platform, this implementation enables AI assistants to easily incorporate large-scale data analysis and business intelligence capabilities. It is particularly useful for scenarios requiring real-time access to enterprise data warehouses, such as generating reports, performing ad-hoc analysis, or integrating Snowflake data into AI-powered applications.', '@datawiz168', 'databases', 'Unknown', 44, 'https://github.com/datawiz168/mcp-snowflake-service', NULL, 0, 'https://github.com/datawiz168.png?size=128', '2026-03-09T05:21:01.946255+00:00'),
  ('lumenx-legal-spend-intelligence', 'LumenX Legal Spend Intelligence', 'LumenX-MCP is a legal spend intelligence server that aggregates financial data from multiple enterprise sources including LegalTracker APIs, SAP/Oracle ERP systems, PostgreSQL databases, and CSV/Excel files. Built by DatSciX, it provides standardized tools for analyzing legal vendor performance, comparing budget vs actual spend, searching transactions, and generating comprehensive spend summaries with filtering by department, practice area, and vendor. The implementation features a unified data model that normalizes legal spend records across disparate systems, making it particularly useful for corporate legal departments and finance teams who need to track legal expenses, analyze vendor relationships, and optimize legal budgets across complex enterprise environments.', '@datscix-ceo', 'databases', 'Unknown', 2, 'https://github.com/datscix-ceo/lumenx-mcp', NULL, 0, 'https://github.com/datscix-ceo.png?size=128', '2026-03-09T05:21:01.946267+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('bpmn-workflow-designer', 'BPMN Workflow Designer', 'Enables programmatic creation and manipulation of BPMN 2.0 workflow diagrams using the bpmn-js library in a headless Node.js environment. Provides tools for adding process elements (events, tasks, gateways, subprocesses), connecting them with sequence flows, and exporting diagrams as standard BPMN XML or SVG formats. Includes intelligent workflow hints to guide users toward creating properly connected diagrams and supports importing existing BPMN files for modification.', '@dattmavis', 'productivity', 'Unknown', 5, 'https://github.com/dattmavis/bpmn-mcp', NULL, 0, 'https://github.com/dattmavis.png?size=128', '2026-03-09T05:21:01.946310+00:00'),
  ('hugging-face-hub-search', 'Hugging Face Hub Search', 'This MCP server provides AI-powered semantic search capabilities for Hugging Face models and datasets, built by Daniel van Strien from Hugging Face using a custom search API hosted on Hugging Face Spaces. It offers tools for semantic similarity search that goes beyond keyword matching to find models and datasets based on natural language descriptions, similarity-based discovery to find related resources, trending content retrieval with filtering options, and detailed metadata extraction including safetensors parsing for model architecture analysis and README card downloads. The implementation uses vector embeddings for intelligent search rather than simple text matching, supports parameter count filtering for models, and provides comprehensive filtering options by likes, downloads, and other metrics, making it valuable for researchers and developers who need to discover relevant ML resources through natural language queries or find alternatives to existing models and datasets.', '@davanstrien', 'ai-ml', 'Unknown', 20, 'https://github.com/davanstrien/hub-semantic-search-mcp', NULL, 0, 'https://github.com/davanstrien.png?size=128', '2026-03-09T05:21:01.946372+00:00'),
  ('fizzy', 'Fizzy', 'Integrates with Fizzy, the kanban-based task tracking tool by 37signals. Provides tools for managing boards with column summaries, searching and filtering cards, creating and updating tasks, and handling comments and checklists. Authenticates via API tokens from Fizzy account settings.', '@davegomez', 'productivity', 'Unknown', 1, 'https://github.com/davegomez/fizzy-mcp', NULL, 0, 'https://github.com/davegomez.png?size=128', '2026-03-09T05:21:01.946398+00:00'),
  ('rekordbox', 'Rekordbox', 'MCP server implementation by Dave Henke that provides AI assistants with direct access to rekordbox DJ software databases through real-time SQLite database connections using pyrekordbox for encrypted database decryption. The implementation offers comprehensive music library management including track searching with BPM/key/genre filters, playlist operations (create, modify, delete), DJ history session analysis, and library statistics, with automatic database backup creation before any write operations to prevent data corruption. Built with FastMCP and featuring both read-only tools for music discovery and mutation tools for playlist management, it serves DJs who want conversational access to their rekordbox libraries for set preparation, music organization, and performance analysis without leaving their AI workflow.', '@davehenke', 'databases', 'Unknown', 24, 'https://github.com/davehenke/rekordbox-mcp', NULL, 0, 'https://github.com/davehenke.png?size=128', '2026-03-09T05:21:01.946408+00:00'),
  ('pare-search', 'Pare Search', 'MCP server for code search (ripgrep + fd) with structured, token-efficient output.', '@dave-london', 'development', 'Unknown', 69, 'https://github.com/dave-london/pare', NULL, 0, 'https://github.com/dave-london.png?size=128', '2026-03-09T05:21:01.946426+00:00'),
  ('mysql-database-explorer', 'MySQL Database Explorer', 'MySQL MCP Server provides read-only access to MySQL databases for LLMs, enabling them to inspect database schemas and execute SELECT queries. Built by dave-wind, it implements strict security measures including SQL validation and READ ONLY transactions to ensure data safety. The server automatically discovers and exposes table structures as JSON schemas, making it ideal for AI assistants that need to analyze database content without modification permissions. It''s particularly valuable for data analysis, reporting, and exploration use cases where protecting the underlying data while allowing meaningful queries is essential.', '@dave-wind', 'databases', 'Unknown', 12, 'https://github.com/dave-wind/mysql-mcp-server', '@davewind/mysql-mcp-server', 1337, 'https://github.com/dave-wind.png?size=128', '2026-03-09T05:21:01.946437+00:00'),
  ('openbudget', 'OpenBudget', 'This MCP server provides access to Israel''s OpenBudget API, allowing users to query and search various budget-related datasets including government budgets, contracts, and support payments. Built on FastMCP, it exposes three main tools: get_dataset_info for retrieving dataset structure information, search_dataset for performing full-text searches, and query_dataset for executing SQL queries against the data. The implementation serves as a bridge between MCP clients and the OpenBudget platform, making government financial data more accessible for analysis, research, and transparency initiatives.', '@openbudget', 'databases', 'Unknown', 13, 'https://github.com/openbudget/budgetkey-mcp', NULL, 0, 'https://github.com/openbudget.png?size=128', '2026-03-09T05:21:01.946450+00:00'),
  ('xtquant-ai', 'XTQuant AI', 'A lightweight MCP server for quantitative trading using the XTQuant API, enabling AI-driven financial analysis and trading strategies. Developed by davidfnck, this tool provides a Python-based integration for programmatic stock market interactions, with a focus on leveraging AI capabilities for quantitative investment approaches.', '@dfkai', 'ai-ml', 'Unknown', 118, 'https://github.com/dfkai/xtquantai', NULL, 0, 'https://github.com/dfkai.png?size=128', '2026-03-09T05:21:01.946513+00:00'),
  ('ctx-sys', 'ctx-sys', 'Local hybrid RAG system that indexes codebases and serves context through an MCP server. Uses Tree-sitter AST parsing for precise entity extraction across TypeScript, Python, Rust, Go, Java, C/C++, and C#. Combines vector search, full-text search (FTS5), and graph traversal with reciprocal rank fusion for result ranking. Stores everything in a single SQLite instance with local Ollama embeddings, ensuring code never leaves the machine. Includes session management, architectural decision logging, and cross-session learning.', '@david-franz', 'databases', 'Unknown', 7, 'https://github.com/david-franz/ctx-sys', NULL, 0, 'https://github.com/david-franz.png?size=128', '2026-03-09T05:21:01.946530+00:00'),
  ('uptime-kuma', 'Uptime Kuma', 'Integrates with Uptime Kuma version 2 monitoring systems to provide real-time access to monitoring data. Supports monitor management (view, pause, resume), status monitoring with heartbeat history and uptime metrics, and filtering by keywords, type, tags, and maintenance status. Offers both stdio and streamable HTTP transports with support for username/password, JWT tokens, and optional 2FA authentication.', '@davidfuchs', 'ai-ml', 'Unknown', 16, 'https://github.com/davidfuchs/mcp-uptime-kuma', NULL, 0, 'https://github.com/davidfuchs.png?size=128', '2026-03-09T05:21:01.946562+00:00'),
  ('scast', 'SCAST', 'SCAST is a tool designed to assist users in analyzing and summarizing code through visualization. 
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('codebase-retrieval-repomix', 'Codebase Retrieval (RepoMix)', 'This MCP server implementation provides a bridge for retrieving codebases using RepoMix. Developed by Anthropic, it integrates with the Model Context Protocol SDK and offers tools for codebase retrieval and analysis. The server is designed for use cases requiring access to source code repositories, such as code review, dependency analysis, or automated documentation generation.', '@dedeveloper23', 'development', 'Unknown', 74, 'https://github.com/dedeveloper23/codebase-mcp', NULL, 0, 'https://github.com/dedeveloper23.png?size=128', '2026-03-09T05:21:01.947949+00:00'),
  ('replicate', 'Replicate', 'This Replicate MCP server implementation provides a bridge between the Model Context Protocol and Replicate''s AI model hosting platform. Developed as an open-source project, it enables seamless interaction with Replicate''s diverse collection of machine learning models through a standardized MCP interface. The server supports key operations such as listing available models, creating and managing predictions, and accessing model metadata. Built with TypeScript and leveraging the official Replicate API, it offers robust error handling, caching mechanisms, and webhook support. This implementation is particularly useful for developers and researchers looking to integrate Replicate''s hosted AI models into their MCP-compatible applications, enabling easy access to a wide range of pre-trained models for tasks like image generation, text processing, and more.', '@deepfates', 'development', 'Unknown', 93, 'https://github.com/deepfates/mcp-replicate', NULL, 0, 'https://github.com/deepfates.png?size=128', '2026-03-09T05:21:01.947983+00:00'),
  ('deepl-translator', 'DeepL Translator', 'The DeepL MCP server provides AI assistants with direct access to DeepL''s translation capabilities through a Node.js implementation. Developed by DeepL SE, this server exposes tools for translating text between numerous languages, rephrasing content with different writing styles and tones, and retrieving available language options. It leverages the Model Context Protocol SDK to establish a stdio-based communication channel, caches language lists for improved performance, and includes formality controls for supported languages. The implementation is particularly valuable for users who need high-quality translations or text rephrasing without switching contexts from their AI assistant conversation.', '@deeplcom', 'ai-ml', 'Unknown', 94, 'https://github.com/deeplcom/deepl-mcp-server', 'deepl-mcp-server', 12867, 'https://github.com/deeplcom.png?size=128', '2026-03-09T05:21:01.948030+00:00'),
  ('crew-risk', 'Crew Risk', 'Evaluates websites for crawling compliance and safety by analyzing robots.txt files, detecting anti-crawling mechanisms, identifying sensitive data, checking copyright restrictions, and scanning for exposed endpoints to provide three-tier risk ratings with specific recommendations for compliant web scraping strategies.', '@deeppath-ai', 'communication', 'Unknown', 3, 'https://github.com/deeppath-ai/mcp-crew-risk', NULL, 0, 'https://github.com/deeppath-ai.png?size=128', '2026-03-09T05:21:01.948055+00:00'),
  ('deeppress', 'DeepPress', 'Dynamically generated MCP servers to talk to any site with a Wordpress API or RSS support.', '@unknown', 'development', 'Unknown', 0, 'https://deeppress.mnemonica.ai', NULL, 0, NULL, '2026-03-09T05:21:01.948091+00:00'),
  ('deeprecall', 'DeepRecall', 'Product Safety Intelligence for AI Agents. Search 120,000+ recalled products from CPSC, FDA, EU Safety Gate, UK OPSS, Health Canada, OECD, RappelConso, and ACCC using text and image-based AI similarity search. Available as a hosted remote MCP server or self-hostable Python application.', '@deeprecall-io', 'ai-ml', 'Unknown', 0, 'https://github.com/deeprecall-io/deeprecall-mcp', NULL, 0, 'https://github.com/deeprecall-io.png?size=128', '2026-03-09T05:21:01.948121+00:00'),
  ('deepresearch', 'DeepResearch', 'DeepResearch MCP Server provides AI assistants with a structured approach to conducting multi-step web research. It leverages Firecrawl for web searches and OpenAI''s GPT-4 for analyzing findings and generating comprehensive reports. The server implements a stateful research process that iteratively explores topics at configurable depths, with each step analyzing previous findings to determine the next search query. Built with TypeScript and the Model Context Protocol, it features robust error handling, token optimization for large research sessions, and both step-by-step and one-shot research workflows. This implementation is particularly valuable for users who need thorough, citation-rich research reports on complex topics without manually managing the search and synthesis process.', '@ameeralns', 'development', 'Unknown', 24, 'https://github.com/ameeralns/deepresearchmcp', NULL, 0, 'https://github.com/ameeralns.png?size=128', '2026-03-09T05:21:01.948153+00:00'),
  ('docling', 'Docling', 'This MCP server, developed by Deep Shah, leverages IBM''s Docling software to parse and convert documents to Markdown format. Built with Python and integrating the MCP and Docling libraries, it provides a streamlined interface for document processing tasks. The implementation focuses on Markdown conversion, offering a specialized tool for transforming various document formats into a universal, easily readable text format. It''s particularly useful for content management systems, documentation projects, and AI-assisted text analysis workflows that benefit from standardized Markdown input, enabling efficient document parsing and conversion without complex setup or multiple tool integrations.', '@deep070203', 'productivity', 'Unknown', 11, 'https://github.com/deep070203/docling-mcp', NULL, 0, 'https://github.com/deep070203.png?size=128', '2026-03-09T05:21:01.948280+00:00'),
  ('web-search-and-semantic-similarity', 'Web Search and Semantic Similarity', 'Search MCP Server provides web search and information extraction capabilities for AI assistants. It offers two main tools: one for performing web searches and scraping results, and another for extracting relevant information from previous searches using semantic similarity. The implementation uses SearchAPI.io for web queries, Firecrawl for content scraping, and embedding models for similarity matching. Built by DeepSpringAI, this server is particularly useful for applications requiring real-time web information retrieval and analysis, including multilingual search capabilities.', '@deepspringai', 'ai-ml', 'Unknown', 2, 'https://github.com/deepspringai/search_mcp_server', NULL, 0, 'https://github.com/deepspringai.png?size=128', '2026-03-09T05:21:01.948326+00:00'),
  ('deepsrt', 'DeepSRT', 'This MCP server provides YouTube video summarization functionality through integration with DeepSRT''s API. It offers tools to generate summaries in narrative or bullet-point formats, with multi-language support. The server leverages content caching and CDN edge delivery for efficient summary retrieval, making it suitable for applications requiring quick access to video content summaries.', '@deepsrt', 'ai-ml', 'Unknown', 48, 'https://github.com/deepsrt/deepsrt-mcp', NULL, 0, 'https://github.com/deepsrt.png?size=128', '2026-03-09T05:21:01.948366+00:00'),
  ('deepview', 'DeepView', 'DeepView MCP enables AI-powered code analysis by loading entire codebases into Gemini''s large context window, allowing developers to query and understand complex repositories through natural language interactions. Built by Dmitry Degtyarev, it integrates seamlessly with IDEs like Cursor and Windsurf, providing a flexible tool for developers seeking AI-assisted code comprehension using tools like repomix to prepare codebases files.', '@ai-1st', 'development', 'Unknown', 67, 'https://github.com/ai-1st/deepview-mcp', 'deepview-mcp', 7891, 'https://github.com/ai-1st.png?size=128', '2026-03-09T05:21:01.948491+00:00'),
  ('deepwiki', 'DeepWiki', 'The DeepWiki MCP server provides AI assistants with access to documentation and search capabilities for GitHub repositories. Developed by Cognition, it offers three main tools: retrieving documentation structure, viewing repository documentation, and asking AI-powered questions about repositories. The server supports both SSE and streamable HTTP protocols, making it compatible with Claude, OpenAI, and Cloudflare integrations. This free, no-authentication service is particularly valuable for developers seeking to incorporate repository knowledge into AI workflows, enabling use cases like code understanding, architecture exploration, and technical question answering for public repositories.', '@unknown', 'cloud', 'Unknown', 0, 'https://docs.devin.ai/work-with-devin/deepwiki-mcp', NULL, 0, NULL, '2026-03-09T05:21:01.948512+00:00'),
  ('deepwriter', 'DeepWriter', 'DeepWriter MCP Server provides a bridge between Claude and the DeepWriter API, enabling users to manage writing projects programmatically through MCP tools. Built with TypeScript and Node.js, it exposes six core tools for project management: listing, creating, updating, deleting, retrieving details, and generating content. The implementation includes robust error handling, secure API key management, and tool annotations for better behavior description, making it ideal for writers and developers who want to automate their DeepWriter workflows without leaving their AI assistant interface.', '@deepwriter-ai', 'development', 'Unknown', 6, 'https://github.com/deepwriter-ai/deepwriter-mcp', NULL, 0, 'https://github.com/deepwriter-ai.png?size=128', '2026-03-09T05:21:01.948538+00:00'),
  ('defeatbeta', 'DefeatBeta', 'Provides access to financial market data including historical stock prices, OHLCV data, quarterly and annual financial statements, valuation metrics (PE, PS, PB ratios, ROE, ROIC, WACC), and earnings call transcripts. Built on DuckDB''s OLAP engine for sub-second analytical queries, sourcing data from Hugging Face''s yahoo-finance-data dataset to avoid scraping limitations and rate-limiting issues.', '@defeat-beta', 'finance', 'Unknown', 503, 'https://github.com/defeat-beta/defeatbeta-api/tree/HEAD/mcp', NULL, 0, 'https://github.com/defeat-beta.png?size=128', '2026-03-09T05:21:01.948583+00:00'),
  ('voice-recorder-whisper', 'Voice Recorder (Whisper)', 'This MCP server implementation provides voice recording and transcription capabilities using OpenAI''s Whisper model. Developed by DefiBax, it integrates with the Goose AI agent as a custom extension and offers tools for recording audio, transcribing speech, and managing transcriptions. The server supports various Whisper model sizes and includes prompts for common recording scenarios, making it suitable for applications requiring speech-to-text functionality such as meeting note-taking, content summarization, and voice-controlled AI interactions.', '@defibax', 'ai-ml', 'Unknown', 6, 'https://github.com/defibax/mcp_servers', NULL, 0, 'https://github.com/defibax.png?size=128', '2026-03-09T05:21:01.948624+00:00'),
  ('infura', 'Infura', 'This MCP server provides access to Ethereum and Polygon blockchain data through Infura''s JSON-RPC APIs, offering 35+ tools for querying blockchain information including balances, transactions, blocks, gas prices, and smart contract data. Built with TypeScript and comprehensive test coverage, it supports both read-only operations (balance queries, transaction lookups, block data) and write operations (raw transaction broadcasting) with configurable chain selection defaulting to Ethereum mainnet. The implementation includes Docker deployment support, strict TypeScript configuration, and follows conventional commit standards with automated CI/CD workflows. Designed for developers building blockchain applications, DeFi tools, or analytics platforms who need reliable programmatic access to Ethereum-compatible networks without managing their own node infrastructure.', '@deflang', 'cloud', 'Unknown', 1, 'https://github.com/deflang/infura-mcp', 'infura-mcp', 331, 'https://github.com/deflang.png?size=128', '2026-03-09T05:21:01.948649+00:00'),
  ('ddc-ci-control-bridge', 'DDC/CI Control Bridge', 'Enables programmatic control of monitor settings through the DDC/CI protocol, allowing AI assistants and automation systems to adjust brightness, contrast, power state, and input sources. Supports integration with Home Assistant via MQTT and works across Windows, Linux, and macOS. Provides both local (stdio) and remote (HTTP/SSE) connection modes.', '@defozo', 'ai-ml', 'Unknown', 4, 'https://github.com/defozo/ddc-ci-control-bridge', NULL, 0, 'https://github.com/defozo.png?size=128', '2026-03-09T05:21:01.948684+00:00'),
  ('postman', 'Postman', 'This Postman MCP server, developed by Delano, provides AI assistants with programmatic access to Postman''s API management platform. It integrates with the Postman API to enable functionalities like managing collections, environments, and APIs. The server is built with TypeScript and leverages the @modelcontextprotocol/sdk for MCP implementation. By abstracting Postman interactions, it allows AI systems to automate API testing, documentation, and workflow management. This implementation is particularly useful for developers, QA engineers, and API designers who want to leverage AI capabilities for API lifecycle management, automated testing, and collaborative API development workflows.', '@delano', 'development', 'Unknown', 145, 'https://github.com/delano/postman-mcp-server', NULL, 0, 'https://github.com/delano.png?size=128', '2026-03-09T05:21:01.948711+00:00'),
  ('deliberate-thinking', 'Deliberate Thinking', 'This deliberate thinking MCP server by kljensen provides structured problem-solving capabilities through sequential, revisable thoughts that can branch and evolve as understanding deepens. Built in Rust for low-latency startup times and based on the Sequential Thinking MCP server, it offers a single tool that enables AI assistants to break down complex problems into numbered thought steps, revise previous insights, create alternative solution branches, and dynamically adjust the total number of thoughts needed as analysis progresses. The implementation maintains thought history with branching support, tracks revisions to previous steps, and includes comprehensive validation and logging, making it valuable for complex analysis tasks, multi-step planning with course correction, and problems where the full scope isn''t initially clear.', '@kljensen', 'productivity', 'Unknown', 5, 'https://github.com/kljensen/deliberate-thinking', NULL, 0, 'https://github.com/kljensen.png?size=128', '2026-03-09T05:21:01.948763+00:00'),
  ('qdrant-knowledge-graph', 'Qdrant Knowledge Graph', 'This MCP server, developed by Jarad DeLorenzo, provides a knowledge graph implementation with semantic search capabilities powered by Qdrant vector database. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers tools for managing entities, relations, and observations in a graph structure. The implementation focuses on efficient storage and retrieval, using both file-based persistence and Qdrant for vector search. It''s particularly useful for applications requiring structured knowledge representation with semantic querying, enabling use cases such as intelligent information retrieval, relationship analysis, and context-aware AI interactions without directly dealing with complex graph database operations.', '@delorenj', 'databases', 'Unknown', 24, 'https://github.com/delorenj/mcp-qdrant-memory', '@delorenj/mcp-qdrant-memory', 1904, 'https://github.com/delorenj.png?size=128', '2026-03-09T05:21:01.948775+00:00'),
  ('super-windows-cli', 'Super Windows CLI', 'This Windows CLI MCP server, developed by Simon Benedict, provides a robust interface for AI assistants to interact with Windows command-line environments. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers tools for executing commands across PowerShell, CMD, and Git Bash shells with configurable security measures. The implementation focuses on providing unrestricted system access through SYSTEM-level service installation, enabling full filesystem access and unrestricted command execution. It''s particularly useful for remote Windows administration, automation of complex system tasks, or integration of Windows capabilities into AI-driven workflows, allowing assistants to leverage the full power of Windows environments without requiring deep knowledge of command-line intricacies.', '@delorenj', 'development', 'Unknown', 7, 'https://github.com/delorenj/super-win-cli-mcp-server', NULL, 0, 'https://github.com/delorenj.png?size=128', '2026-03-09T05:21:01.948806+00:00'),
  ('ticketmaster', 'Ticketmaster', 'This MCP server for Ticketmaster, developed by Jarad DeLorenzo, provides a robust interface for AI assistants to interact with the Ticketmaster Discovery API. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers tools for searching events, venues, and attractions with flexible filtering options. The implementation focuses on comprehensive data retrieval and formatting, making it easy for AI models to access detailed information about entertainment events. It''s particularly useful for tasks like event planning, ticket purchasing assistance, or integrating live entertainment data into AI-driven systems, allowing assistants to query Ticketmaster''s extensive database without requiring deep knowledge of the underlying API complexities.', '@delorenj', 'databases', 'Unknown', 23, 'https://github.com/delorenj/mcp-server-ticketmaster', '@delorenj/mcp-server-ticketmaster', 132150, 'https://github.com/delorenj.png?size=128', '2026-03-09T05:21:01.948817+00:00'),
  ('delphi-compiler', 'Delphi Compiler', 'This Delphi MCP server enables compilation of Delphi/Object Pascal projects within Cursor IDE by providing seamless integration with RAD Studio compilers. Built in Python using FastMCP, it automatically discovers project files (.dpr/.dproj), locates Delphi compiler executables and MSBuild through environment variables or PATH, and supports both Debug and Release configurations for Win32 and Win64 platforms. The implementation handles both direct compiler invocation for .dpr files and MSBuild-based compilation for .dproj files, providing detailed error reporting and build summaries with comprehensive logging to help developers debug compilation issues in their Delphi applications.', '@unununununununun', 'development', 'Unknown', 8, 'https://github.com/unununununununun/delphi-compiler-mcp', NULL, 0, 'https://github.com/unununununununun.png?size=128', '2026-03-09T05:21:01.948844+00:00'),
  ('debank', 'DeBanK', 'DeBanK MCP Server provides a bridge between AI assistants and the DeBanK API, enabling access to blockchain and DeFi data through a set of specialized tools. Built with Deno and TypeScript, it offers functionality for retrieving information about chains, protocols, tokens, pools, user assets, activities, authorizations, NFT collections, and wallet operations. The server features robust error handling, request logging, and pagination support for large result sets, making it particularly valuable for financial analysts, crypto researchers, and applications that need to access on-chain data across multiple blockchains through natural language interfaces.', '@demcp', 'development', 'Unknown', 9, 'https://github.com/demcp/demcp-debank-mcp', NULL, 0, 'https://github.com/demcp.png?size=128', '2026-03-09T05:21:01.948886+00:00'),
  ('meson-cross-chain-transfer', 'Meson Cross-Chain Transfer', 'Meson Cross-Chain Transaction MCP Server enables seamless asset transfers between different blockchains using the Meson Protocol. Built with Deno and TypeScript, it provides tools for preparing transactions, signing with private keys, and monitoring transfer status across both mainnet and testnet environments. The server handles the complexities of cross-chain communication while maintaining security by processing private keys locally, making it ideal for users who need conversational interfaces to manage cryptocurrency transfers across Ethereum, Arbitrum, Avalanche, and other supported chains.', '@demcp', 'development', 'Unknown', 3, 'https://github.com/demcp/demcp-meson-mcp', NULL, 0, 'https://github.com/demcp.png?size=128', '2026-03-09T05:21:01.948915+00:00'),
  ('playwright-scraper', 'Playwright Scraper', 'A web scraping MCP server that uses Playwright for browser automation, BeautifulSoup for HTML parsing, and Pypandoc for converting web content to high-quality Markdown. Designed to handle modern, JavaScript-heavy websites and provide a simple tool for extracting and converting web page content, enabling easy content retrieval across complex web platforms.', '@dennisgl', 'ai-ml', 'Unknown', 9, 'https://github.com/dennisgl/mcp-playwright-scraper', 'mcp-playwright-scraper', 3234, 'https://github.com/dennisgl.png?size=128', '2026-03-09T05:21:01.948950+00:00'),
  ('coding-todo', 'Coding Todo', 'This MCP server implementation provides tools and resources for managing a coding project''s todo list. Developed by Dennis Martis, it offers functionality to view, add, update, and delete todo items, with features like priority setting, tagging, and project assignment. The server uses FastMCP and Pydantic for efficient data handling and includes prompts for summarizing todos and suggesting which tasks to tackle next. It''s designed for use cases requiring AI-assisted project management and task prioritization in software development contexts.', '@dennismartis', 'development', 'Unknown', 1, 'https://github.com/dennismartis/mcp-todo', NULL, 0, 'https://github.com/dennismartis.png?size=128', '2026-03-09T05:21:01.948976+00:00'),
  ('deno-code-executor', 'Deno Code Executor', 'This MCP server provides secure TypeScript and JavaScript code execution through Deno, enabling AI assistants to run code snippets in isolated processes with configurable permissions. Built by Cong using TypeScript with the MCP SDK and Deno runtime, it executes code by writing to temporary files and running them in separate Deno processes, with permission configuration handled at server startup rather than per-execution for security. The implementation includes automatic cleanup of temporary files, helpful error messages for permission issues, and support for both basic sandboxed execution and specific permission grants (network, file system, etc.), making it valuable for code testing and validation, educational programming assistance, and automated script execution workflows that require secure code isolation.', '@alexcong', 'development', 'Unknown', 6, 'https://github.com/alexcong/deno-mcp', NULL, 0, 'https://github.com/alexcong.png?size=128', '2026-03-09T05:21:01.949017+00:00'),
  ('resend-email', 'Resend Email', 'The Resend MCP server enables AI assistants to send emails through the Resend API service. Built by Deploya-labs, it provides a ''send-email'' tool that accepts parameters like recipient address, subject, content, and optional scheduling. The implementation supports configuration of sender email addresses and reply-to fields either through command-line arguments or environment variables. It runs as a Node.js application that can be deployed via Docker, making it ideal for workflows requiring email communication capabilities without leaving the conversation interface. The server requires a Resend API key for authentication and handles both successful delivery confirmations and error reporting.', '@deploya-labs', 'cloud', 'Unknown', 0, 'https://github.com/deploya-labs/mcp-resend', NULL, 0, 'https://github.com/deploya-labs.png?size=128', '2026-03-09T05:21:01.949081+00:00'),
  ('deployhq', 'DeployHQ', 'MCP server for DeployHQ enabling AI assistants to interact with deployment workflows. Provides seven capabilities: list and retrieve project details, list and retrieve server details, view deployment history with pagination, access deployment logs for debugging, create new deployments programmatically, and monitor deployment status. Built with TypeScript using Zod for type-safe validation and stdio transport with JSON-RPC protocol.', '@deployhq', 'development', 'Unknown', 12, 'https://github.com/deployhq/deployhq-mcp-server', NULL, 0, 'https://github.com/deployhq.png?size=128', '2026-03-09T05:21:01.949114+00:00'),
  ('depyler', 'Depyler', 'Converts annotated Python code into idiomatic Rust while maintaining semantic equivalence. Features type-directed transpilation, memory safety analysis, and semantic verification through property-based testing. Provides tools for analyzing migration complexity, transpiling code with optimization options, and verifying semantic equivalence.', '@paiml', 'development', 'Unknown', 336, 'https://github.com/paiml/depyler', NULL, 0, 'https://github.com/paiml.png?size=128', '2026-03-09T05:21:01.949137+00:00'),
  ('fiberflow', 'Fiberflow', 'Fiberflow MCP Gateway serves as a bridge between Claude Desktop and Fiberflow''s MCP server, enabling seamless integration through Server-Sent Events (SSE). Built by derbenoo, this TypeScript implementation runs as a command-line tool that connects to a Fiberflow SSE endpoint using a secret key and communicates with Claude Desktop via stdio. The gateway is designed for users who want to leverage Fiberflow''s capabilities directly within Claude conversations without additional configuration steps beyond providing their Fiberflow MCP server secret in the Claude Desktop configuration.', '@derbenoo', 'development', 'Unknown', 0, 'https://github.com/derbenoo/fiberflow-mcp-gateway', 'fiberflow-mcp-gateway', 323, 'https://github.com/derbenoo.png?size=128', '2026-03-09T05:21:01.949165+00:00'),
  ('fal-ai', 'fal.ai', 'This MCP server provides comprehensive access to fal.ai''s AI model ecosystem, enabling AI assistants to discover, execute, and manage generative AI workflows through a unified interface. Built using Python with FastMCP, httpx for async HTTP operations, and support for both direct and queued model execution, it offers tools for browsing available models with pagination and search, retrieving OpenAPI schemas for model parameters, generating content with any fal.ai model including image generation and other AI tasks, and managing long-running requests through queue operations with status checking and cancellation. The implementation includes file upload capabilities to fal.ai''s CDN storage, full streaming support via HTTP transport for real-time communication, and handles both authenticated operations requiring API keys and public model discovery, making it valuable for AI assistants that need access to cutting-edge generative models, automated content creation workflows, and scenarios requiring integration with fal.ai''s specialized AI model marketplace.', '@derekalia', 'productivity', 'Unknown', 2, 'https://github.com/derekalia/fal', NULL, 0, 'https://github.com/derekalia.png?size=128', '2026-03-09T05:21:01.949225+00:00'),
  ('mcpvil', 'MCPvil', 'MCPvil is a minimal Wayland compositor built on top of Smithay that exposes compositor functionality as tools. It enables launching applications within the compositor environment and capturing screenshots of the active window as PNG images. Communication happens over stdio using newline-delimited JSON-RPC, making it suitable for integration with any compatible client.', '@derekjchow', 'media', 'Unknown', 1, 'https://github.com/derekjchow/mcpvil', NULL, 0, 'https://github.com/derekjchow.png?size=128', '2026-03-09T05:21:01.949276+00:00'),
  ('lifeup', 'LifeUp', 'Enables interaction with the LifeUp gamification app running on Android devices over a local network connection. Provides tools for creating and managing tasks, querying achievements, browsing shop items, and viewing user progress including skills and coin balance. Features intelligent achievement matching that suggests relevant achievements based on task keywords, safe mode for read-only operations, and comprehensive error handling for network connectivity issues. Useful for gamifying productivity workflows and integrating habit-building mechanics into task management.', '@derekprovance', 'development', 'Unknown', 5, 'https://github.com/derekprovance/lifeup-mcp', NULL, 0, 'https://github.com/derekprovance.png?size=128', '2026-03-09T05:21:01.949301+00:00'),
  ('tmdb', 'TMDB', 'This TMDB MCP server provides integration with The Movie Database API for accessing movie, TV show, and entertainment industry data through ten specialized tools including search functionality, detailed information retrieval, trending content discovery, and people lookup capabilities. Built with TypeScript using Express and Axios, it features dual deployment modes with both standard MCP protocol support via stdin/stdout communication and HTTP server mode for web-based integrations, plus Docker containerization and comprehensive error handling for TMDB API responses. The implementation automatically constructs image URLs for posters and backdrops, supports pagination and advanced query parameters like year filtering and additional data appending, and includes legacy tool discovery for backward compatibility, making it valuable for AI assistants building entertainment recommendation systems, movie databases, or content discovery applications.', '@dervish666', 'databases', 'Unknown', 1, 'https://github.com/dervish666/tmdb-mcp-server', NULL, 0, 'https://github.com/dervish666.png?size=128', '2026-03-09T05:21:01.949312+00:00'),
  ('descope-authentication', 'Descope Authentication', 'This Descope MCP server, developed by Descope Sample Apps, integrates the Model Context Protocol with Descope''s authentication and authorization platform. Built with TypeScript and leveraging the MCP SDK, it enables AI agents to interact with Descope''s APIs for user management, authentication flows, and access control. The implementation focuses on providing a secure bridge between natural language commands and Descope''s functionality, allowing operations like user creation, authentication, and permission management. It''s particularly useful for developers and organizations looking to enhance their applications with AI-driven identity and access management capabilities, enabling use cases such as automated user onboarding, intelligent access control, and AI-assisted security policy enforcement without directly dealing with the complexities of Descope''s APIs.', '@descope-sample-apps', 'development', 'Unknown', 28, 'https://github.com/descope-sample-apps/descope-mcp-server-stdio', NULL, 0, 'https://github.com/descope-sample-apps.png?size=128', '2026-03-09T05:21:01.949345+00:00'),
  ('domain-tools', 'Domain Tools', 'This Domain Tools MCP server by Abhishek Deshpande provides AI agents with essential domain analysis capabilities through four core tools: WHOIS lookups with registration details and expiration tracking, DNS record queries supporting all major record types (A, AAAA, MX, NS, TXT, CNAME, SOA), DNS health checks that identify configuration issues like missing redundancy or RFC violations, and complete domain analysis combining all three functions. Built with Python using the dnspython and python-whois libraries, it includes intelligent domain parsing that handles URLs, automatic date formatting with expiration calculations, and detailed health scoring that categorizes issues as critical, warnings, or informational. The implementation is valuable for system administrators managing DNS infrastructure, security analysts investigating domains, web developers troubleshooting connectivity issues, and AI assistants that need to automate domain monitoring and validation workflows.', '@deshabhishek007', 'development', 'Unknown', 13, 'https://github.com/deshabhishek007/domain-tools-mcp-server', NULL, 0, 'https://github.com/deshabhishek007.png?size=128', '2026-03-09T05:21:01.949380+00:00'),
  ('twilio-agent-payments', 'Twilio Agent Payments', 'Twilio Agent Payments MCP Server enables secure, PCI-compliant payment processing during voice calls by providing a bridge between AI assistants and Twilio''s payment API. The server manages the complete payment capture workflow—collecting card numbers, security codes, and expiration dates—while maintaining state through asynchronous callbacks and guiding the AI with contextual prompts at each step. It uses Twilio API Keys for enhanced security and tokenizes payment information, making it particularly valuable for customer service applications where agents need to collect payments without handling sensitive card data directly.', '@deshartman', 'development', 'Unknown', 5, 'https://github.com/deshartman/twilio-agent-payments-mcp-server', NULL, 0, 'https://github.com/deshartman.png?size=128', '2026-03-09T05:21:01.949416+00:00'),
  ('twilio-messaging', 'Twilio Messaging', 'Twilio Messaging MCP Server enables AI assistants to send SMS messages through the Twilio API. It provides a simple ''send-sms'' tool that accepts destination phone numbers and message content, handling all the authentication and API interaction behind the scenes. The server requires Twilio credentials (Account SID, API Key, API Secret) and a sender phone number, which are passed as command-line arguments rather than environment variables for enhanced security. Designed for integration with Claude Desktop, it can be run either through npx for convenience or installed globally, making it ideal for workflows where AI assistants need to send text messages without leaving the conversation interface.', '@deshartman', 'communication', 'Unknown', 5, 'https://github.com/deshartman/twilio-messaging-mcp-server', NULL, 0, 'https://github.com/deshartman.png?size=128', '2026-03-09T05:21:01.949454+00:00'),
  ('design-system-analyzer', 'Design System Analyzer', 'A design system MCP server that provides tools for retrieving component properties and design tokens from a React-based UI library. The server uses ts-morph to analyze TypeScript component files and extract prop information, while also accessing JSON token files that define colors, typography, spacing, and border radius values. This implementation enables AI assistants to understand the structure of UI components and available design tokens, facilitating more accurate code generation and design recommendations when working with this component library.', '@yajihum', 'development', 'Unknown', 24, 'https://github.com/yajihum/design-system-mcp', NULL, 0, 'https://github.com/yajihum.png?size=128', '2026-03-09T05:21:01.949490+00:00'),
  ('daniel-lightrag', 'Daniel LightRAG', 'LightRAG MCP server that provides complete integration with local LightRAG instances through 22 tools across document management, querying, knowledge graph operations, and system monitoring. Built by Daniel Simpkins, the implementation connects to LightRAG servers via HTTP API with comprehensive error handling and response validation using Pydantic models, supporting operations like text insertion, file uploads, hybrid querying modes, entity/relation management, and pipeline status tracking. Designed for users running local LightRAG deployments who want conversational access to their knowledge graphs and document processing workflows without manual API interactions, enabling seamless RAG operations through natural language commands while maintaining full control over their data and processing pipeline.', '@desimpkins', 'ai-ml', 'Unknown', 25, 'https://github.com/desimpkins/daniel-lightrag-mcp', NULL, 0, 'https://github.com/desimpkins.png?size=128', '2026-03-09T05:21:01.949543+00:00'),
  ('desktop-commander', 'Desktop Commander', 'This MCP server implementation, developed by Eduard Ruzga, provides a terminal interface for executing commands and managing processes on the local system. Built with TypeScript and leveraging the Model Context Protocol SDK, it extends the MCP Filesystem Server to enable full system command execution, process management, and advanced file operations. The implementation stands out by combining terminal access with filesystem capabilities, allowing for seamless integration of command-line tools and file manipulation in AI workflows. It''s particularly useful for developers and system administrators who need to perform complex system operations, run scripts, or manage files through AI-assisted interfaces, enabling tasks like automated system maintenance, code deployment, or data processing pipelines.', '@wonderwhy-er', 'development', 'Unknown', 5621, 'https://github.com/wonderwhy-er/desktopcommandermcp', NULL, 0, 'https://github.com/wonderwhy-er.png?size=128', '2026-03-09T05:21:01.949572+00:00'),
  ('desktop-image-manager', 'Desktop Image Manager', 'Desktop Image Manager MCP provides tools for managing and manipulating images on the local desktop, with capabilities for counting image files, retrieving filenames, and compressing images. Built with TypeScript and leveraging the Sharp library for image processing, it enables AI assistants to directly interact with image files in the user''s desktop directory through a standardized interface.', '@zhixiaoqiang', 'development', 'Unknown', 4, 'https://github.com/zhixiaoqiang/desktop-image-manager-mcp', NULL, 0, 'https://github.com/zhixiaoqiang.png?size=128', '2026-03-09T05:21:01.949596+00:00'),
  ('splunk', 'Splunk', 'MCP server for Splunk by Deslicer that provides AI assistants with direct access to Splunk Enterprise through the Splunk SDK, enabling search execution, health monitoring, user management, and alert analysis. Built with Python and FastMCP, it features a modular tool architecture with core Splunk operations, community-contributed tools for specialized use cases, and workflow-based troubleshooting systems with OpenAI integration for automated analysis and summarization. The implementation includes Docker deployment with Traefik routing, hot reload development support, comprehensive testing, and both production and development configurations, making it useful for DevOps teams, security analysts, and system administrators who need to integrate Splunk data analysis and monitoring capabilities directly into their AI-powered workflows without switching between applications.', '@deslicer', 'cloud', 'Unknown', 20, 'https://github.com/deslicer/mcp-for-splunk', NULL, 0, 'https://github.com/deslicer.png?size=128', '2026-03-09T05:21:01.949621+00:00'),
  ('efficient-gitlab', 'Efficient GitLab', 'An enhanced GitLab integration that dramatically reduces token consumption through a progressive disclosure architecture. Instead of exposing 100+ individual tools, it provides 5 meta-tools that dynamically discover and execute GitLab operations on demand. Includes comprehensive test coverage, strict TypeScript implementation, and MCP protocol logging for agent observability.', '@detailobsessed', 'development', 'Unknown', 0, 'https://github.com/detailobsessed/efficient-gitlab-mcp', NULL, 0, 'https://github.com/detailobsessed.png?size=128', '2026-03-09T05:21:01.949640+00:00'),
  ('unblu', 'Unblu', 'Provides AI assistants with secure access to Unblu deployments through a progressive discovery pattern. Instead of exposing all 300+ API endpoints upfront, it offers 5 discovery tools that reduce token consumption while maintaining full API access. Built for financial services customer engagement platforms with integrated safety mechanisms including destructive operation hints and optional server-side policy enforcement.', '@detailobsessed', 'communication', 'Unknown', 1, 'https://github.com/detailobsessed/unblu-mcp', NULL, 0, 'https://github.com/detailobsessed.png?size=128', '2026-03-09T05:21:01.949670+00:00'),
  ('plane-project-management', 'Plane Project Management', 'Claudeus Plane MCP is a server implementation that provides AI assistants with direct access to Plane project management capabilities. It exposes tools for managing projects and issues through a standardized interface, allowing operations like listing, creating, updating, and deleting projects and issues. Built with TypeScript and the Model Context Protocol, it features secure API client handling, robust error management, and support for multiple Plane instances configured via JSON. This implementation is particularly valuable for teams who want to manage their Plane projects directly through conversational AI without switching contexts.', '@deus-h', 'development', 'Unknown', 5, 'https://github.com/deus-h/claudeus-plane-mcp', NULL, 0, 'https://github.com/deus-h.png?size=128', '2026-03-09T05:21:01.949701+00:00'),
  ('hacker-news', 'Hacker News', 'This MCP server provides access to Hacker News data through a set of capabilities including searching stories and comments, retrieving various types of stories, fetching individual stories with comments, and accessing user profiles and submissions. Developed by devabdultech, it integrates with the Hacker News API and is built using TypeScript and Node.js. The server is designed for use cases requiring real-time access to Hacker News content, such as news aggregation, trend analysis, or building custom Hacker News clients.', '@devabdultech', 'development', 'Unknown', 17, 'https://github.com/devabdultech/hn-mcp', NULL, 0, 'https://github.com/devabdultech.png?size=128', '2026-03-09T05:21:01.949725+00:00'),
  ('mysql-query', 'MySQL Query', 'MySQL Query MCP Server provides a secure bridge between AI assistants and MySQL databases, enabling read-only query execution across multiple environments (local, development, staging, production). Built with TypeScript and Node.js, it offers three main tools: query for executing SELECT statements with timeout controls, info for retrieving database metadata, and environments for listing available database connections. The server implements strict validation to ensure only read-only operations are permitted, supports SSL connections for secure database access, and includes comprehensive error handling and debugging capabilities. It''s particularly valuable for developers and data analysts who need to safely access MySQL data through conversational interfaces without exposing write permissions.', '@devakone', 'databases', 'Unknown', 12, 'https://github.com/devakone/mysql-query-mcp-server', 'mysql-query-mcp-server', 6132, 'https://github.com/devakone.png?size=128', '2026-03-09T05:21:01.949739+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('pyppeteer-browser-automation', 'Pyppeteer Browser Automation', 'MCP Servers with Pyppeteer enables AI assistants to control headless browsers for web automation tasks through the Multi-Context Protocol framework. Developed by Alexandre E Souza, it provides capabilities for automated navigation, screenshot capture, element interaction using CSS selectors or XPath, and access to dynamic page information. The implementation runs as a Python package that can be installed via pip or directly from GitHub, and includes Docker support for containerized deployment. It''s particularly valuable for workflows requiring web scraping, UI testing, or any scenario where programmatic browser control enhances AI assistant capabilities.', '@devalexandre', 'cloud', 'Unknown', 0, 'https://github.com/devalexandre/mcp-servers', NULL, 0, 'https://github.com/devalexandre.png?size=128', '2026-03-09T05:21:01.949762+00:00'),
  ('image-generation', 'Image Generation', 'The Image MCP Server provides AI assistants with image generation capabilities through a standardized interface. It connects to various image generation models via Gradio clients, allowing for the creation of images based on text prompts. The server implementation includes a Dockerfile for containerized deployment and supports both local and remote usage through the MCP protocol. This tool is valuable for creative workflows, content creation, and visual design tasks where AI-generated imagery enhances productivity.', '@devbrother2024', 'cloud', 'Unknown', 0, 'https://github.com/devbrother2024/mcp-generate-image', NULL, 0, 'https://github.com/devbrother2024.png?size=128', '2026-03-09T05:21:01.949783+00:00'),
  ('devcycle', 'DevCycle', 'This MCP server provides direct integration with DevCycle''s feature flag management platform, enabling AI assistants to create, manage, and analyze feature flags across projects and environments. Built as a hosted service with OAuth authentication, it offers comprehensive tools for feature management, variable configuration, self-targeting overrides, usage analytics, and SDK installation guidance across six organized categories. The implementation supports multiple AI clients including Cursor, VS Code, Claude Desktop, and Windsurf through both SSE and HTTP streaming protocols, making it valuable for development teams who want AI-assisted feature flag workflows, A/B testing management, and deployment control without switching between tools.', '@unknown', 'development', 'Unknown', 0, 'https://docs.devcycle.com/cli-mcp/mcp-getting-started/', '@devcycle/cli', 510138, NULL, '2026-03-09T05:21:01.949814+00:00'),
  ('io-github-madhan-g-p-devdocs-mcp', 'io.github.madhan-g-p/devdocs-mcp', 'Local DevDocs MCP Server (Developer Docs with project specific context awareness)', '@madhan-g-p', 'development', 'Unknown', 5, 'https://github.com/madhan-g-p/devdocs-mcp', NULL, 0, 'https://github.com/madhan-g-p.png?size=128', '2026-03-09T05:21:01.949830+00:00'),
  ('scrapi', 'ScrAPI', 'ScrAPI MCP Server is a specialized web scraping solution that enables AI assistants to extract content from websites that employ bot detection, captchas, or geolocation restrictions. Developed by DevEnterprise Software, this TypeScript implementation provides two core tools: one for retrieving content as HTML for advanced parsing needs, and another for Markdown output when text content is the priority. The server leverages residential proxies and automated captcha solving capabilities through the ScrAPI service, making it particularly valuable for AI systems that need to access otherwise restricted web content for research, data collection, or information retrieval tasks.', '@deventerprisesoftware', 'development', 'Unknown', 18, 'https://github.com/deventerprisesoftware/scrapi-mcp', '@deventerprisesoftware/scrapi-mcp', 6051, 'https://github.com/deventerprisesoftware.png?size=128', '2026-03-09T05:21:01.949871+00:00'),
  ('gemini-image', 'Gemini Image', 'This Gemini Image MCP server by Antonio provides AI-powered image generation and editing capabilities through Google''s Gemini 2.5 Flash Image Preview model. Built with TypeScript and featuring the Sharp library for image processing, it offers two core tools: generating images from text descriptions with configurable aspect ratios and styles optimized for social media (defaulting to 1:1 format), and editing existing images based on text instructions. The implementation includes automatic watermarking support for branding, comprehensive file format handling (PNG, JPEG, WebP), and intelligent filename generation based on descriptions, making it valuable for content creators, marketers, and developers who need AI-assisted image creation and modification workflows integrated into their applications.', '@antoniolg', 'development', 'Unknown', 2, 'https://github.com/antoniolg/gemini-image-mcp-server', NULL, 0, 'https://github.com/antoniolg.png?size=128', '2026-03-09T05:21:01.949907+00:00'),
  ('devexpress-documentation', 'DevExpress Documentation', 'A Kubernetes MCP server that provides direct cluster management capabilities through kubectl integration, enabling AI assistants to interact with Kubernetes resources via tools for applying manifests, retrieving resource information, executing commands in pods, checking logs, and managing deployments. Built with TypeScript and featuring comprehensive error handling, namespace support, and resource filtering, it bridges the gap between conversational AI and Kubernetes operations, making it useful for DevOps automation, cluster troubleshooting, application deployment, and infrastructure management workflows where natural language interaction with Kubernetes clusters is desired.', '@unknown', 'cloud', 'Unknown', 0, 'https://api.devexpress.com/mcp/docs', NULL, 0, NULL, '2026-03-09T05:21:01.949932+00:00'),
  ('devhub-cms', 'DevHub CMS', 'Allows seamless interaction with DevHub''s API platform, enabling automated content management and providing additional context to DevHub''s users of LLMs. This MCP will benefit users looking to integrate AI capabilities with their DevHub workflows.', '@devhub', 'ai-ml', 'Unknown', 7, 'https://github.com/devhub/devhub-cms-mcp', 'devhub-cms-mcp', 3624, 'https://github.com/devhub.png?size=128', '2026-03-09T05:21:01.949959+00:00'),
  ('device-peripherals', 'Device Peripherals', 'This MCP server provides peripheral device interaction capabilities for computer hardware including cameras, printers, audio devices, and displays, enabling AI assistants to capture images and videos, manage print jobs, record and play audio, and take screenshots or record screen activity. Built by Akshit Sinha using Python with FastMCP, OpenCV, PyAudio, and platform-specific APIs, it features cross-platform support for Windows, macOS, and Linux with automatic device detection, configurable device enabling/disabling, background recording capabilities for both audio and video, and comprehensive error handling with platform-specific troubleshooting guidance. The implementation includes FFmpeg integration for high-quality video recording, temporary file management with automatic cleanup, and detailed device information retrieval, making it valuable for automation workflows requiring hardware interaction, content creation pipelines, system monitoring applications, and any use case where AI assistants need direct access to computer peripherals for data capture or output.', '@akshitsinha', 'ai-ml', 'Unknown', 5, 'https://github.com/akshitsinha/mcp-device-server', NULL, 0, 'https://github.com/akshitsinha.png?size=128', '2026-03-09T05:21:01.950021+00:00'),
  ('redfish', 'Redfish', 'Provides intelligent Redfish server management capabilities through both MCP tools and an interactive chatbot interface. Built with enterprise-grade resilience features including circuit breaker protection, exponential backoff retry logic, and comprehensive error handling for production environments. Integrates with Anthropic''s Claude models to enable natural language interaction with Redfish APIs, supporting endpoint discovery, resource querying, PATCH updates, and action execution. Includes a mock Redfish server for testing and development, making it valuable for data center administrators and infrastructure engineers who need to manage BMCs and server hardware through conversational interfaces rather than manual API calls.', '@devidasjadhav', 'development', 'Unknown', 1, 'https://github.com/devidasjadhav/mcp-redfish-python', NULL, 0, 'https://github.com/devidasjadhav.png?size=128', '2026-03-09T05:21:01.950050+00:00'),
  ('tuba-workflow', 'Tuba Workflow', 'Bridges Tuba.ai computer vision workflows to expose AI vision pipelines as callable tools for running workflows, checking execution status, fetching results with automatic ZIP downloads, and updating parameters with support for local files, remote URLs, and base64 uploads.', '@devisionx', 'ai-ml', 'Unknown', 2, 'https://github.com/devisionx/tuba-workflow-mcp-server', NULL, 0, 'https://github.com/devisionx.png?size=128', '2026-03-09T05:21:01.950093+00:00'),
  ('macos-notification', 'macOS Notification', 'The macOS Notification MCP server enables AI assistants to trigger various notification types on macOS systems through a simple interface. Developed by Phatchara Maichandi, this Python implementation provides tools for playing system sounds, displaying banner notifications, and using text-to-speech capabilities with customizable parameters like voice selection and speech rate. The server uses FastMCP protocol and implements safeguards including notification queuing and rate limiting to prevent notification collisions. It''s particularly valuable for users who want to receive alerts, reminders, or spoken information directly from their AI assistant without leaving their conversation context.', '@devizor', 'ai-ml', 'Unknown', 34, 'https://github.com/devizor/macos-notification-mcp', 'macos-notification-mcp', 2157, 'https://github.com/devizor.png?size=128', '2026-03-09T05:21:01.950138+00:00'),
  ('whatap-mxql', 'WhaTap MXQL', 'TypeScript-based MCP server providing direct access to WhaTap''s monitoring platform through MXQL (Monitoring eXtended Query Language) queries. Enables AI assistants to analyze APM, browser, and infrastructure monitoring data. Features complete authentication flow mimicking WhaTap''s mobile app login process, secure session management with AES-256-GCM encryption. Provides both CLI and MCP server interfaces for querying monitoring metrics, retrieving project information, and executing complex MXQL queries with time range filtering. Includes specialized RUM data aggregation across multiple time windows.', '@devload', 'development', 'Unknown', 2, 'https://github.com/devload/whatap-mxql-cli', NULL, 0, 'https://github.com/devload.png?size=128', '2026-03-09T05:21:01.950202+00:00'),
  ('ton-blockchain-analyzer', 'TON Blockchain Analyzer', 'TON Blockchain MCP Server provides a natural language interface to the TON blockchain, enabling AI assistants to analyze wallet addresses, track transactions, detect trading patterns, and identify market trends. Developed by Devon Mojito under the MIT license, it leverages the TON API to fetch real-time blockchain data, process jetton (token) transfers, and generate insights about trading activities. The implementation includes tools for address analysis, transaction details, hot trend detection, and trading pattern recognition, making it particularly valuable for cryptocurrency traders, blockchain analysts, and DeFi users who need to interact with TON blockchain data through conversational AI interfaces.', '@devonmojito', 'ai-ml', 'Unknown', 26, 'https://github.com/devonmojito/ton-blockchain-mcp', 'ton-mcp-server', 864, 'https://github.com/devonmojito.png?size=128', '2026-03-09T05:21:01.950250+00:00'),
  ('devopness', 'Devopness', 'Devopness automates DevOps workflows and custom pipelines to manage infrastructure environments in any major cloud provider. Provision and manage cloud infrastructure, deploy applications to AWS, Azure, DigitalOcean, GCP, and other major cloud providers. Streamlines essential DevOps practices with infrastructure as code, automated deployments, and centralized management of servers, applications, and environments.', '@devopness', 'cloud', 'Unknown', 360, 'https://github.com/devopness/devopness', NULL, 0, 'https://github.com/devopness.png?size=128', '2026-03-09T05:21:01.950267+00:00'),
  ('devpilot', 'DevPilot', 'DevPilot is an MCP server that automates VPS initialization and deployment workflows through SSH connections, providing tools for system setup, service installation, Nginx configuration with SSL, and GitHub CI/CD pipeline creation. Built with TypeScript and the MCP SDK, it offers five core tools: SSH connection management, automated installation of Node.js/PM2/Rust/Nginx/Redis, domain configuration with reverse proxy and Certbot SSL certificates, GitHub deploy key generation with workflow templates, and remote command execution. The implementation handles authentication via password or private key, generates deployment scripts and GitHub Actions workflows, and includes comprehensive logging and error handling, making it valuable for developers who need AI-assisted server provisioning, application deployment automation, and infrastructure management workflows.', '@oxy-op', 'databases', 'Unknown', 3, 'https://github.com/oxy-op/devpilot', NULL, 0, 'https://github.com/oxy-op.png?size=128', '2026-03-09T05:21:01.950328+00:00'),
  ('dev-proxy', 'Dev Proxy', 'Provides MCP integration with Microsoft Dev Proxy, an API simulator for testing applications. Allows AI assistants to find Dev Proxy documentation, retrieve best practices for configuration, and check the installed version for compatibility. Supports natural language configuration creation and contextual help for Dev Proxy workflows.', '@dev-proxy-tools', 'development', 'Unknown', 4, 'https://github.com/dev-proxy-tools/mcp', NULL, 0, 'https://github.com/dev-proxy-tools.png?size=128', '2026-03-09T05:21:01.950351+00:00'),
  ('pub-dev', 'pub.dev', 'This MCP server provides comprehensive access to pub.dev, the official package repository for Dart and Flutter, enabling AI assistants to search packages, retrieve detailed package information, check for updates, compare versions, and access documentation. Built with TypeScript and the official MCP SDK, it implements intelligent caching with a 5-minute duration to optimize API performance and includes six core tools covering package discovery, version management, dependency analysis, and documentation retrieval. The implementation is particularly valuable for Flutter/Dart developers who want conversational assistance with package management, dependency updates, and exploring the pub.dev ecosystem through AI-powered workflows.', '@devqxi', 'development', 'Unknown', 5, 'https://github.com/devqxi/pubdev-mcp-server', '@devqxi/pubdev-mcp-server', 482, 'https://github.com/devqxi.png?size=128', '2026-03-09T05:21:01.950380+00:00'),
  ('devserver-monitor', 'DevServer Monitor', 'This MCP server monitors development server processes (Vite, npm run dev, etc.) and provides intelligent error categorization and file change correlation for debugging workflows. Built by Tristan Brotherton with TypeScript and the MCP SDK, it uses configurable regex patterns to parse and classify errors from TypeScript, Svelte, build tools, and runtime sources into structured categories with severity levels. The implementation features file watching with chokidar to correlate errors with recent code changes, shared state management for persistence across sessions, and comprehensive error tracking with history limits and filtering capabilities. Designed for developers working with modern JavaScript frameworks who need automated error analysis and debugging assistance, it enables use cases like identifying which file changes caused specific errors, tracking error patterns over time, and getting structured summaries of development server issues without manually parsing console output.', '@mntlabs', 'development', 'Unknown', 9, 'https://github.com/mntlabs/devserver-mcp', NULL, 0, 'https://github.com/mntlabs.png?size=128', '2026-03-09T05:21:01.950413+00:00'),
  ('search-scrape-searxng', 'Search Scrape (SearXNG)', 'Pure Rust web search and scraping MCP server that combines SearXNG federated search with advanced content extraction capabilities. The implementation uses a containerized SearXNG instance for privacy-focused search across multiple engines (Google, DuckDuckGo, Bing, Startpage) while providing a sophisticated Rust-native scraper that leverages readability algorithms, language detection, and content preprocessing to extract clean text from web pages. Features comprehensive caching with Moka, concurrent request limiting, retry logic with exponential backoff, and specialized extraction for documentation sites like mdBook, making it valuable for AI applications that need reliable web research capabilities without depending on external scraping services or compromising user privacy through direct search engine APIs.', '@cortex-works', 'ai-ml', 'Unknown', 54, 'https://github.com/cortex-works/cortex-scout', NULL, 0, 'https://github.com/cortex-works.png?size=128', '2026-03-09T05:21:01.950466+00:00'),
  ('xcode', 'Xcode', 'A TypeScript implementation of the Model Context Protocol (MCP) for Xcode integration, allowing developers to connect Xcode with AI models that support MCP.', '@devyhan', 'development', 'Unknown', 7, 'https://github.com/devyhan/xcode-mcp', '@devyhan/xcode-mcp', 4270, 'https://github.com/devyhan.png?size=128', '2026-03-09T05:21:01.950523+00:00'),
  ('arbitrum', 'Arbitrum', 'MCP server implementation by dewanshparashar that provides natural language access to Arbitrum blockchain networks including core chains (Arbitrum One, Nova) and Orbit chains (Xai, Superposition, etc.). The implementation combines three specialized clients for comprehensive chain monitoring: ArbitrumChainClient for batch posting status, assertion tracking, gas prices, and ArbOS version detection; NitroNodeClient for node health checks, transaction tracing, debug operations, and Timeboost express lanes; and EthereumAccountClient for standard account operations like balance checks and transaction details. Features automatic chain discovery and contract address resolution from chain names, comprehensive status reporting that aggregates batch delivery monitoring, assertion creation/confirmation gaps, and gas price tracking in a single query, plus extensive Arbitrum-specific RPC method support including arbtrace, arbdebug, and maintenance operations, making it valuable for developers monitoring Arbitrum network health, troubleshooting chain issues, or building applications that need real-time visibility into sequencer performance and validator operations.', '@dewanshparashar', 'development', 'Unknown', 4, 'https://github.com/dewanshparashar/arbitrum-mcp', NULL, 0, 'https://github.com/dewanshparashar.png?size=128', '2026-03-09T05:21:01.950564+00:00'),
  ('rust-analyzer', 'Rust Analyzer', 'This MCP server provides AI assistants with comprehensive Rust development capabilities through rust-analyzer integration, offering 19 specialized tools for code analysis, generation, refactoring, and project management. Built using Rust with the rmcp crate and tokio for async operations, the implementation communicates with rust-analyzer via LSP to provide intelligent code operations including symbol navigation, diagnostics, automated refactoring, struct/enum generation, test creation, and advanced features like type hierarchy analysis and dependency suggestions. Serves Rust developers seeking AI-powered code assistance, teams building Rust applications that need intelligent refactoring and generation capabilities, and AI assistants requiring deep integration with Rust tooling for idiomatic code manipulation without string-based approaches.', '@dexwritescode', 'development', 'Unknown', 28, 'https://github.com/dexwritescode/rust-mcp', NULL, 0, 'https://github.com/dexwritescode.png?size=128', '2026-03-09T05:21:01.950595+00:00'),
  ('powershell-exec', 'PowerShell Exec', 'MCP PowerShell Exec Server enables AI assistants to execute PowerShell scripts and receive the output in real-time. Developed by Doug Finke, this lightweight Python server uses FastMCP to create a bridge between AI tools like GitHub Copilot and PowerShell functionality. The implementation securely processes PowerShell code strings through subprocess calls, making it particularly valuable for AI agents that need to analyze data, automate Windows tasks, or interact with PowerShell modules without leaving their interface. It integrates seamlessly with VSCode Insiders in agent mode, allowing for powerful PowerShell capabilities within AI-assisted workflows.', '@dfinke', 'development', 'Unknown', 59, 'https://github.com/dfinke/mcp-powershell-exec', NULL, 0, 'https://github.com/dfinke.png?size=128', '2026-03-09T05:21:01.950621+00:00'),
  ('auto-favicon', 'Auto Favicon', 'Auto Favicon MCP Server automatically generates complete favicon sets from PNG images or URLs, creating multiple sizes (16x16 to 256x256), traditional ICO files, Apple touch icons for iOS devices, and web app manifest.json files for Progressive Web Apps. Built using FastMCP and PIL (Pillow) for image processing, it provides two core tools: generating favicons from local PNG files and downloading images from URLs to create favicon sets, with all generated files organized in a specified output directory. This server streamlines the tedious process of creating comprehensive favicon packages for web developers and designers who need to support various devices and platforms without manually resizing and converting images.', '@dh1011', 'ai-ml', 'Unknown', 32, 'https://github.com/dh1011/auto-favicon-mcp', NULL, 0, 'https://github.com/dh1011.png?size=128', '2026-03-09T05:21:01.950669+00:00'),
  ('blender-open-mcp', 'Blender Open MCP', 'Blender Open MCP is a server implementation that integrates Blender with local AI models via Ollama using the Model Context Protocol. Developed by Nirajan Dhakal, it enables controlling Blender through natural language prompts, allowing users to perform 3D modeling tasks like creating primitives, modifying objects, applying materials, and rendering images. The server includes optional PolyHaven integration for downloading and using assets directly within Blender, and features a Blender add-on that provides a user interface for seamless communication between the AI model and the 3D software.', '@dhakalnirajan', 'productivity', 'Unknown', 73, 'https://github.com/dhakalnirajan/blender-open-mcp', NULL, 0, 'https://github.com/dhakalnirajan.png?size=128', '2026-03-09T05:21:01.950712+00:00'),
  ('axion-google-earth-engine', 'Axion (Google Earth Engine)', 'This Earth Engine MCP server by Dhenenjay provides geospatial analysis and satellite imagery processing through Google Earth Engine integration, featuring comprehensive tools for NDVI/NDWI calculations, crop classification, wildfire risk assessment, and interactive map generation. Built with Next.js and TypeScript, it offers consolidated tools that replace 32+ individual operations with 6 super-tools for better MCP stability, supports shapefile boundary conversion for place names, and includes specialized models for agricultural monitoring, flood risk analysis, and deforestation detection with ground truth validation data. The implementation features both HTTP SSE and STDIO transports for Claude Desktop compatibility, Redis/in-memory caching for map sessions, and production deployment on Render with automatic Earth Engine authentication, making it valuable for environmental researchers, agricultural analysts, and geospatial professionals who need AI-assisted satellite data analysis and automated earth observation workflows.', '@dhenenjay', 'databases', 'Unknown', 4, 'https://github.com/dhenenjay/axion-mcp', NULL, 0, 'https://github.com/dhenenjay.png?size=128', '2026-03-09T05:21:01.950731+00:00'),
  ('ssh-gateway', 'SSH Gateway', 'Provides SSH gateway access to remote backend servers with support for multi-hop connections and Kerberos authentication. Features command whitelisting, dangerous pattern blocking, dynamic configuration reloading, and automatic session timeout for secure remote server administration and DevOps workflows.', '@dhks77', 'security', 'Unknown', 2, 'https://github.com/dhks77/nhn-server-mcp', NULL, 0, 'https://github.com/dhks77.png?size=128', '2026-03-09T05:21:01.950784+00:00'),
  ('sequential-story', 'Sequential Story', 'A Model Context Protocol server that provides two complementary tools for structured problem-solving: Sequential Story and Sequential Thinking. Sequential Story structures problems as narrative sequences with characters, settings, and plot points to make complex concepts more memorable, while Sequential Thinking offers a pure Python implementation for organizing problems as thought sequences. Both approaches support branching, revision, and visual formatting of elements, making them effective mnemonic techniques for enhancing memory retention and problem understanding. The server is configurable to enable either or both tools based on environment variables, and integrates seamlessly with AI systems through the MCP protocol.', '@dhkts1', 'ai-ml', 'Unknown', 15, 'https://github.com/dhkts1/sequentialstory', 'sequential-story', 1997, 'https://github.com/dhkts1.png?size=128', '2026-03-09T05:21:01.950835+00:00'),
  ('apple-native-apps', 'Apple Native Apps', 'Apple MCP tools provides native macOS integration for AI assistants, enabling access to Apple applications like Contacts, Notes, Messages, Mail, Reminders, Calendar, and Maps. Developed by Dhravya Shah, this TypeScript implementation uses JXA (JavaScript for Automation) and AppleScript to interact with macOS applications, allowing AI assistants to perform tasks such as sending messages, creating notes, managing reminders, searching emails, and getting directions. The server features both eager and lazy loading modes for reliability, making it particularly valuable for users who want their AI assistant to interact with their personal data and Apple ecosystem without leaving the conversation context.', '@jxnl', 'development', 'Unknown', 17, 'https://github.com/jxnl/apple-mcp', NULL, 0, 'https://github.com/jxnl.png?size=128', '2026-03-09T05:21:01.950878+00:00'),
  ('apple-native-tools', 'Apple Native Tools', 'This MCP server implementation provides a bridge to Apple''s native applications, enabling AI assistants to interact with Contacts, Notes, and Messages. Developed by Dhravya Shah, it offers tools for searching and retrieving contacts, managing notes, and sending messages. The server is built using TypeScript and Bun, integrating with the Model Context Protocol SDK. It focuses on secure handling of personal data and robust error management, making it suitable for AI applications that need to automate tasks within Apple''s ecosystem. The implementation is designed for easy setup within the Claude Desktop environment and is particularly useful for personal productivity and communication workflows.', '@supermemoryai', 'development', 'Unknown', 3022, 'https://github.com/supermemoryai/apple-mcp', '@dhravya/apple-mcp', 16889, 'https://github.com/supermemoryai.png?size=128', '2026-03-09T05:21:01.950909+00:00'),
  ('linkedin-post', 'LinkedIn Post', 'LinkedIn Posting Service MCP Server enables AI assistants to publish content directly to LinkedIn profiles. Built with TypeScript, it provides a tool for creating posts with customizable visibility settings, support for text content, media attachments, and link sharing with thumbnails. The implementation authenticates using LinkedIn''s API via access tokens and user IDs, making it ideal for social media management, content marketing, and professional networking tasks where automated LinkedIn posting is required.', '@dhrishp', 'development', 'Unknown', 0, 'https://github.com/dhrishp/mcp-post-linkedin', NULL, 0, 'https://github.com/dhrishp.png?size=128', '2026-03-09T05:21:01.950936+00:00'),
  ('remote-bridge', 'Remote Bridge', 'Remote-MCP provides a lightweight API bridge for accessing MCP functionality over HTTP, built with Python 3.10 and Starlette. Developed by dhso, this implementation containerizes MCP services in a minimal Alpine-based Docker image, making it easy to deploy and scale in distributed environments. The server exposes MCP capabilities through a web interface, allowing clients to interact with MCP tools remotely without requiring direct library integration in their applications.', '@dhso', 'cloud', 'Unknown', 1, 'https://github.com/dhso/remote-mcp', NULL, 0, 'https://github.com/dhso.png?size=128', '2026-03-09T05:21:01.950961+00:00'),
  ('a-mem', 'A-Mem', 'A-Mem provides self-evolving memory capabilities for AI agents through a dynamic knowledge graph. When new knowledge is added, the system identifies semantically similar existing memories and strengthens or updates connections between them. Features dual-mode search combining semantic vector similarity with graph traversal, and token-efficient retrieval using lightweight metadata summaries. Supports multiple LLM backends including OpenAI, Ollama, SGLang, and OpenRouter.', '@diaaaj', 'ai-ml', 'Unknown', 30, 'https://github.com/diaaaj/a-mem-mcp', NULL, 0, 'https://github.com/diaaaj.png?size=128', '2026-03-09T05:21:01.950995+00:00'),
  ('dialer', 'Dialer', 'Enables Claude and ChatGPT to make outbound phone calls from your actual phone number. Built for research applications including expert interviews, market research, academic studies, due diligence, and competitive intelligence. Provides call recording, transcripts, and real-time analytics.', '@unknown', 'communication', 'Unknown', 0, 'https://getdialer.app', NULL, 0, NULL, '2026-03-09T05:21:01.951018+00:00'),
  ('nestjs-customer-service-backend', 'NestJS Customer Service Backend', 'This MCP server provides access to a customer service backend system built with NestJS, PostgreSQL, and Prisma, featuring a complete complaint management workflow alongside user and internal employee data management. The implementation exposes 25+ tools for fetching customer users, internal employees (with department/role filtering and CS agent availability), user activity logs with statistics, and detailed complaint operations including filtering by category/status/priority, ticket assignment to agents, JIRA integration, and escalation management. Built as part of a larger system that includes a Next.js frontend and integrates with n8n workflows, it''s designed for customer service automation scenarios where assistants need to query user data, assign support tickets, track complaint resolution progress, and maintain audit trails across a multi-team support organization.', '@diasm3', 'databases', 'Unknown', 2, 'https://github.com/diasm3/n8n_postgres_mcp_server_backend/tree/HEAD/mcp_server_practice', NULL, 0, 'https://github.com/diasm3.png?size=128', '2026-03-09T05:21:01.951066+00:00'),
  ('dice', 'Dice', 'Integrates with Dice.com to search and discover technology job opportunities. Dice is a major tech-focused job board serving millions of tech professionals and thousands of employers, providing tools to find positions matching specific skills, experience levels, and career goals.', '@unknown', 'search', 'Unknown', 0, 'https://www.dice.com', NULL, 0, NULL, '2026-03-09T05:21:01.951154+00:00'),
  ('dice-roll', 'Dice Roll', 'A simple dice rolling MCP server that provides a tool for generating random dice rolls. The server implements a single tool called ''roll_dice'' that accepts parameters for the number of faces on the dice and how many times to roll, returning both individual roll results and their sum. It uses the Model Context Protocol''s stdio transport for communication and is built with TypeScript, leveraging the Zod library for input validation and schema generation.', '@shimapon', 'development', 'Unknown', 1, 'https://github.com/shimapon/mcp-server-diceroll', 'mcp-server-diceroll', 3770, 'https://github.com/shimapon.png?size=128', '2026-03-09T05:21:01.951178+00:00'),
  ('dice-thrower', 'Dice Thrower', 'A simple dice rolling server that enables AI assistants to simulate rolling any number of dice with any number of sides. Built with TypeScript and the MCP SDK, it provides a single tool for generating random dice rolls and calculating their sum, making it useful for tabletop gaming applications, random number generation, or probability demonstrations. The implementation focuses on a clean, minimal approach with input validation to ensure reasonable dice parameters.', '@atuinturtle', 'development', 'Unknown', 0, 'https://github.com/atuinturtle/dice-thrower-mcp-server', NULL, 0, 'https://github.com/atuinturtle.png?size=128', '2026-03-09T05:21:01.951202+00:00'),
  ('obsidian-cli', 'Obsidian CLI', 'Wraps the official Obsidian CLI to provide comprehensive note management in Obsidian vaults. Supports core operations like creating, reading, appending, and searching notes, along with metadata management, task tracking, template handling, and daily note workflows. Requires the Obsidian desktop app with CLI enabled and a Catalyst license.', '@dickiedyce', 'productivity', 'Unknown', 6, 'https://github.com/dickiedyce/obsidian-ts-mcp', NULL, 0, 'https://github.com/dickiedyce.png?size=128', '2026-03-09T05:21:01.951234+00:00'),
  ('agent-mail', 'Agent Mail', 'A coordinated multi-agent messaging and coordination MCP server that enables AI agents to communicate through structured messages, claim exclusive access to file paths, and maintain persistent project archives with Git-based version control. Built with FastMCP, SQLModel, and PostgreSQL, it features full-text search capabilities, acknowledgment tracking, attachment processing with automatic image conversion to WebP, and pre-commit guards that prevent conflicting file modifications across agents. The system organizes agents into projects with human-readable names, stores all communications in both database and filesystem archives, and includes comprehensive CLI tooling for project management, claims inspection, and acknowledgment monitoring, making it useful for coordinating multiple AI agents working on shared codebases or collaborative tasks where conflict prevention and communication history are essential.', '@dicklesworthstone', 'databases', 'Unknown', 1774, 'https://github.com/dicklesworthstone/mcp_agent_mail', NULL, 0, 'https://github.com/dicklesworthstone.png?size=128', '2026-03-09T05:21:01.951248+00:00'),
  ('llm-gateway', 'LLM Gateway', 'A unified gateway server for managing interactions with multiple LLM providers (OpenAI, Anthropic, DeepSeek, Gemini) with built-in cost optimization, caching, and monitoring. Features include automatic model selection based on task requirements, semantic caching to reduce redundant API calls, detailed usage analytics, and a CLI for direct interaction. The implementation focuses on reliability with comprehensive error handling, request retries, and rate limiting, making it particularly valuable for production deployments that need to balance performance and costs across multiple LLM providers.', '@dicklesworthstone', 'productivity', 'Unknown', 142, 'https://github.com/dicklesworthstone/ultimate_mcp_server', NULL, 0, 'https://github.com/dicklesworthstone.png?size=128', '2026-03-09T05:21:01.951288+00:00'),
  ('git-summary', 'Git Summary', 'A lightweight MCP server for generating git commit message summaries using OpenAI. Built with the mcp-go framework, this tool enables developers to analyze repository commit histories by filtering commits by date range and author, then generating human-readable markdown summaries that highlight key changes and their business impact. The implementation focuses on providing a streamlined, developer-friendly approach to understanding project evolution through commit message analysis.', '@cybersiddhu', 'development', 'Unknown', 0, 'https://github.com/cybersiddhu/dcr-mcp', NULL, 0, 'https://github.com/cybersiddhu.png?size=128', '2026-03-09T05:21:01.951310+00:00'),
  ('one-piece-geolocation', 'One Piece & Geolocation', 'This MCP server collection by Diego Rodriguez provides two specialized services: a One Piece anime/manga information server and a geolocation service. Built with TypeScript and the MCP SDK, it uses a configurable architecture through Smithery that allows users to select which server to run at startup, with the One Piece server as the default. The implementation demonstrates a multi-server approach within a single repository, making it useful for developers who want to offer multiple themed or functional MCP services while maintaining a unified deployment and configuration system.', '@didacusdev', 'development', 'Unknown', 2, 'https://github.com/didacusdev/mcp-servers', NULL, 0, 'https://github.com/didacusdev.png?size=128', '2026-03-09T05:21:01.951377+00:00'),
  ('openbb-widgets', 'OpenBB Widgets', 'An MCP server built by DidierRLopes that provides comprehensive access to OpenBB''s widget development documentation and includes essential boilerplate code for building OpenBB Workspace widgets. The server exposes over 30 documentation tools covering widget types (Plotly charts, AgGrid tables, HTML, markdown), parameter configurations (dropdowns, date pickers, boolean toggles), widget settings (grid sizing, error handling, refresh intervals), and JSON specifications for apps and agents. It features a specialized tool that provides the foundational FastAPI setup with CORS configuration, widget registration decorators, and the required widgets.json endpoint structure, along with a working Monte Carlo stock simulation widget example that demonstrates proper integration patterns. The implementation is containerized and deployable, making it useful for developers building financial dashboards, creating custom OpenBB integrations, and learning widget development patterns through comprehensive documentation access and ready-to-use code templates.', '@didierrlopes', 'development', 'Unknown', 6, 'https://github.com/didierrlopes/openbb-widgets-json-mcp', NULL, 0, 'https://github.com/didierrlopes.png?size=128', '2026-03-09T05:21:01.951414+00:00'),
  ('pulumi-cloud-development', 'Pulumi Cloud Development', 'This Pulumi MCP implementation, developed by didlawowo, provides a streamlined interface for infrastructure-as-code operations. Built with Pulumi''s cloud development platform, it offers a foundation for managing cloud resources programmatically. The implementation focuses on simplicity, with a basic project structure and Sonar integration for code quality analysis. It''s particularly useful for tasks like automating cloud infrastructure deployment, managing multi-cloud environments, or integrating infrastructure management into CI/CD pipelines, enabling efficient cloud resource orchestration without requiring deep knowledge of individual cloud provider APIs.', '@didlawowo', 'cloud', 'Unknown', 8, 'https://github.com/didlawowo/mcp-collection', NULL, 0, 'https://github.com/didlawowo.png?size=128', '2026-03-09T05:21:01.951438+00:00'),
  ('secure-shell-executor', 'Secure Shell Executor', 'MCP Shell Server provides a secure way to execute shell commands through the MCP protocol, with robust validation and safety features. The implementation includes command whitelisting through environment variables, directory validation to prevent unauthorized access, support for input/output redirection and command pipelines, and timeout handling for long-running processes. Built with Python using asyncio for non-blocking execution, it offers a clean API for executing commands with proper error handling and resource cleanup, making it ideal for workflows requiring controlled shell access within AI assistant conversations.', '@diegofornalha', 'ai-ml', 'Unknown', 0, 'https://github.com/diegofornalha/mcp-shell-server', NULL, 0, 'https://github.com/diegofornalha.png?size=128', '2026-03-09T05:21:01.951481+00:00'),
  ('serper-search', 'Serper Search', 'The Serper MCP Server provides AI assistants with web search capabilities through integration with the Serper API. Built by Diego Fornalha, it supports various search types including web, news, images, shopping, and YouTube searches, with both TypeScript and Python implementations available. The server can be deployed via Docker or run locally, offering both stdio and Server-Sent Events (SSE) communication protocols. This implementation is particularly useful for workflows requiring real-time web information retrieval, content research, and data gathering directly within AI assistant conversations.', '@diegofornalha', 'cloud', 'Unknown', 0, 'https://github.com/diegofornalha/mcp-server-serper', NULL, 0, 'https://github.com/diegofornalha.png?size=128', '2026-03-09T05:21:01.951504+00:00'),
  ('dify-tools-bridge', 'Dify Tools Bridge', 'MCP Compatible Dify Tools is a bridge plugin that enables Dify''s tool ecosystem to work with MCP-compatible AI assistants. It provides two key endpoints: an SSE endpoint for establishing streaming connections and a messages endpoint that handles tool discovery and execution. The plugin converts Dify tool definitions into MCP-compatible formats, allowing AI assistants to discover available tools and invoke them through a standardized interface. This implementation is particularly useful for organizations already using Dify who want to extend their existing tools to work with any MCP-compatible AI assistant without duplicating tool configurations.', '@junjiem', 'ai-ml', 'Unknown', 23, 'https://github.com/junjiem/dify-plugin-mcp_compat_dify_tools', NULL, 0, 'https://github.com/junjiem.png?size=128', '2026-03-09T05:21:01.951550+00:00'),
  ('synapseaudit', 'SynapseAudit', 'SynapseAudit provides security scanning capabilities for LLMs. Detects 50+ vulnerability types including SQL injection, XSS, and hardcoded secrets across 20+ programming languages. Integrates with VS Code and supports OWASP compliance alignment with local analysis that keeps code on your machine.', '@digidenone', 'databases', 'Unknown', 1, 'https://github.com/digidenone/synapseaudit/tree/HEAD/mcp-server', NULL, 0, 'https://github.com/digidenone.png?size=128', '2026-03-09T05:21:01.951561+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('digital-defiance-debugger', 'Digital Defiance Debugger', 'Provides comprehensive debugging capabilities for Node.js and TypeScript through the Debug Adapter Protocol. Features breakpoint management, variable inspection, call stack navigation, CPU/memory profiling, and performance analysis. Supports source maps for TypeScript debugging and includes hang detection tools.', '@digital-defiance', 'development', 'Unknown', 1, 'https://github.com/digital-defiance/mcp-debugger-server', NULL, 0, 'https://github.com/digital-defiance.png?size=128', '2026-03-09T05:21:01.951580+00:00'),
  ('digital-defiance-filesystem', 'Digital-Defiance Filesystem', 'Provides advanced filesystem operations for AI agents with strict security boundaries. All operations are confined to a designated workspace directory through the WORKSPACE_ROOT environment variable. Distributed via npm as part of the AI Capabilities Suite, this server enables secure file management with enterprise-grade access controls.', '@unknown', 'development', 'Unknown', 0, 'https://github.com/Digital-Defiance/ai-capabilities-suite', NULL, 0, 'https://github.com/Digital-Defiance.png?size=128', '2026-03-09T05:21:01.951599+00:00'),
  ('process', 'Process', 'Enables AI agents to launch and manage system processes with comprehensive security controls. Features six layers of security validation including executable allowlists, argument validation, environment sanitization, and resource limits. Provides twelve tools for process launching, real-time resource monitoring (CPU, memory, I/O), output capture, service orchestration with auto-restart, and process grouping for pipelines.', '@digital-defiance', 'ai-ml', 'Unknown', 2, 'https://github.com/digital-defiance/ai-capabilities-suite', NULL, 0, 'https://github.com/digital-defiance.png?size=128', '2026-03-09T05:21:01.951632+00:00'),
  ('screenshot', 'Screenshot', 'Provides screenshot capture capabilities for AI agents with multi-format support (PNG, JPEG, WebP, BMP), privacy protection through OCR-based PII detection, and cross-platform compatibility. Features include full screen capture, window targeting, region extraction, multi-monitor support, rate limiting, and audit logging.', '@digital-defiance', 'ai-ml', 'Unknown', 2, 'https://github.com/digital-defiance/mcp-screenshot', NULL, 0, 'https://github.com/digital-defiance.png?size=128', '2026-03-09T05:21:01.951661+00:00'),
  ('loaded-vibes', 'Loaded Vibes', 'TypeScript web development framework that combines CLI-driven workflow with Spec-Plan-Tasks methodology to generate technical specifications, implementation plans, and executable task breakdowns for Next.js applications with built-in registries for code snippets and design tokens.', '@digitalherencia', 'development', 'Unknown', 0, 'https://github.com/digitalherencia/loadedvibes', NULL, 0, 'https://github.com/digitalherencia.png?size=128', '2026-03-09T05:21:01.951678+00:00'),
  ('digitalocean', 'DigitalOcean', 'DigitalOcean MCP Server provides a Go-based implementation that enables AI assistants to interact with DigitalOcean''s cloud infrastructure. Built using the mcp-go library and DigitalOcean''s godo client, it exposes resources for accessing account information, droplets, domains, firewalls, and other cloud services, along with tools for managing these resources. The server authenticates via an API token and handles both resource retrieval and modification operations, making it valuable for cloud infrastructure management, monitoring, and automation tasks without requiring direct access to the DigitalOcean control panel.', '@digitalocean-labs', 'development', 'Unknown', 90, 'https://github.com/digitalocean-labs/mcp-digitalocean', NULL, 0, 'https://github.com/digitalocean-labs.png?size=128', '2026-03-09T05:21:01.951702+00:00'),
  ('chatterbox-tts', 'Chatterbox TTS', 'This MCP server provides text-to-speech functionality using either the high-quality Chatterbox TTS neural model or macOS''s built-in ''say'' command, automatically generating speech from text and playing it back with configurable expressiveness controls. Built by digitarald using Python and FastMCP, it features automatic model loading with progress notifications, persistent audio file storage with configurable TTL cleanup, dual TTS engine support for flexibility between quality and speed, and specialized prompts for daily haikus and code roasts. The implementation handles device optimization (MPS/CUDA/CPU), provides real-time progress updates during speech generation, and includes comprehensive audio resource management with embedded playback, making it valuable for developers who want AI assistants to provide spoken feedback, code reviews, or daily engagement through voice interaction.', '@digitarald', 'development', 'Unknown', 10, 'https://github.com/digitarald/chatterbox-mcp', NULL, 0, 'https://github.com/digitarald.png?size=128', '2026-03-09T05:21:01.951758+00:00'),
  ('development-tooling', 'Development Tooling', 'This MCP development server, created for Claude to manage software projects, provides comprehensive project context awareness and code execution through Docker environments. It integrates with Git for version control and offers file system operations, template-based project creation, and build/test capabilities. The server is built using Python 3.12+ and leverages libraries like FastAPI, aiohttp, and GitPython to deliver its functionality. It''s designed for AI-assisted software development workflows, enabling use cases such as automated code analysis, intelligent refactoring suggestions, and seamless project management across multiple languages and frameworks.', '@dillip285', 'cloud', 'Unknown', 3, 'https://github.com/dillip285/mcp-dev-server', NULL, 0, 'https://github.com/dillip285.png?size=128', '2026-03-09T05:21:01.951780+00:00'),
  ('inoreader', 'Inoreader', 'Provides programmatic access to Inoreader RSS feed reader through a Python-based MCP server implementation. Built with aiohttp and asyncio, it offers 8 core tools for managing RSS feeds including listing subscriptions, retrieving articles with filtering options, searching content, marking items as read, and performing basic content analysis like sentiment detection and keyword extraction. The implementation handles Inoreader''s Google Reader-compatible API authentication, includes caching for performance, and provides multiple server variants (minimal, simple, and Claude-compatible) to accommodate different MCP client requirements. Designed for users who want to integrate their RSS reading workflow with AI assistants for tasks like content curation, article summarization, trend analysis, and automated feed management without manual platform interaction.', '@dindicoelho', 'productivity', 'Unknown', 8, 'https://github.com/dindicoelho/inoreader-mcp', NULL, 0, 'https://github.com/dindicoelho.png?size=128', '2026-03-09T05:21:01.951876+00:00'),
  ('kubernetes-listpods', 'Kubernetes ListPods', 'Kubernetes ListPods MCP server enables Claude to interact with Kubernetes clusters by providing a tool to list pods in specified namespaces. Built with Go using the official Kubernetes client libraries and the mcp-go framework, it reads from the user''s kubeconfig file to establish cluster connections. The implementation handles dynamic client creation, resource mapping, and pod retrieval through a simple interface that requires only a namespace parameter. This tool is particularly useful for DevOps workflows, cluster monitoring, and troubleshooting Kubernetes deployments directly within Claude conversations.', '@dineshkumarramaraj', 'cloud', 'Unknown', 0, 'https://github.com/dineshkumarramaraj/mcp-kubernetes/tree/HEAD/kubernetes-listpods', NULL, 0, 'https://github.com/dineshkumarramaraj.png?size=128', '2026-03-09T05:21:01.951900+00:00'),
  ('fitness-coach', 'Fitness Coach', 'Health & Fitness Coach MCP server built by Dinesh-Satram that provides AI assistants with personalized fitness coaching capabilities through workout logging, nutrition tracking, feedback collection, and AI-powered plan generation using OpenAI''s GPT models. The implementation features a comprehensive Next.js web interface with real-time progress tracking, meal and workout logging tools, and intelligent plan generation based on user context including recent activities, weekly targets, and feedback history. Built with TypeScript and featuring both HTTP and SSE transport support with optional Redis integration, the server maintains user fitness data in memory stores and generates personalized weekly workout and nutrition plans, making it valuable for AI assistants providing health coaching, fitness tracking applications, and personalized wellness recommendations based on historical user data.', '@dinesh-satram', 'databases', 'Unknown', 7, 'https://github.com/dinesh-satram/fitness_coach_mcp', NULL, 0, 'https://github.com/dinesh-satram.png?size=128', '2026-03-09T05:21:01.951920+00:00'),
  ('dingtalk', 'DingTalk', 'DingTalk notification MCP server that enables AI assistants to send messages to DingTalk groups and channels through webhook integration. Built by the Claude Code Community, it provides tools for sending text messages, markdown-formatted content, and link cards with optional @mentions and signature authentication for secure webhook communication. The implementation includes session monitoring capabilities and Git integration for automated notifications, making it valuable for development teams who want to receive AI-generated updates, alerts, and summaries directly in their DingTalk workspaces without manual intervention.', '@sfyyy', 'development', 'Unknown', 6, 'https://github.com/sfyyy/claude-code-dingtalk-mcp', 'claude-code-dingtalk-mcp', 454, 'https://github.com/sfyyy.png?size=128', '2026-03-09T05:21:01.951946+00:00'),
  ('burp-suite', 'Burp Suite', 'This Burp Suite MCP server extension integrates the popular web security testing platform with AI clients, enabling automated security analysis workflows through the Model Context Protocol. Built by Daniel S and Daniel Allen at PortSwigger using Kotlin with Ktor for the web server and the MCP Kotlin SDK, it exposes Burp''s core functionality including HTTP request/response handling, vulnerability scanning, crawling, proxy history access, and configuration management through a comprehensive set of tools. The implementation features security controls with user approval dialogs for sensitive operations, automatic installation support for Claude Desktop via a bundled stdio proxy server, and real-time server-sent events communication, making it valuable for security researchers and penetration testers who want to leverage AI assistance for vulnerability discovery, security assessment automation, and intelligent analysis of web application security findings.', '@dinosn', 'development', 'Unknown', 15, 'https://github.com/dinosn/burp-mcp-server', NULL, 0, 'https://github.com/dinosn.png?size=128', '2026-03-09T05:21:01.951996+00:00'),
  ('spinnaker', 'Spinnaker', 'This MCP server implementation for Spinnaker, developed by Dion Hagan, enables AI models to interact with Spinnaker deployments, pipelines, and applications through a standardized interface. It provides tools for retrieving application and pipeline data, as well as triggering pipeline executions. The server maintains context about Spinnaker deployments and refreshes it periodically. Built with TypeScript and leveraging Express.js, it offers a RESTful API and WebSocket support for real-time updates. This implementation is particularly useful for DevOps teams and SREs looking to incorporate AI-driven decision making into their CI/CD processes, enabling use cases like automated deployment management, intelligent pipeline orchestration, and AI-assisted incident response.', '@dion-hagan', 'development', 'Unknown', 1, 'https://github.com/dion-hagan/mcp-server-spinnaker', '@airjesus17/mcp-server-spinnaker', 706, 'https://github.com/dion-hagan.png?size=128', '2026-03-09T05:21:01.952028+00:00'),
  ('directus', 'Directus', 'This MCP server provides comprehensive access to Directus CMS instances through HTTP streaming support, enabling AI assistants to manage content, schema, and workflows within headless CMS environments. Built by JoshTheDerf using TypeScript with the Directus SDK and Model Context Protocol, it offers tools for CRUD operations on collections and items, file management with Base64 encoding for image analysis, field and schema manipulation, flow triggering for automation, user management with permission checking, and dynamic prompt management stored within Directus collections. The implementation uses stateless HTTP transport with access token authentication, includes intelligent schema fetching that filters system fields while preserving file/user relations, supports markdown conversion, comment management with user mentions, and provides configurable tool filtering with safety defaults like disabling delete operations. It''s valuable for AI assistants that need to manage content workflows, automate publishing processes, or provide intelligent content editing capabilities within Directus-powered applications.', '@joshthederf', 'development', 'Unknown', 8, 'https://github.com/joshthederf/directus-extension-mcp', 'directus-extension-mcp', 236, 'https://github.com/joshthederf.png?size=128', '2026-03-09T05:21:01.952067+00:00'),
  ('log-analysis-sqlite', 'Log Analysis SQLite', 'This SQLite MCP server implementation enables AI assistants to analyze log files by creating and querying a structured database from compressed log data. It processes gzipped log files into an SQLite database with tables for logs, stack traces, and parsing errors, while providing tools to extract error data to Parquet format for further analysis. The server supports querying by log level, timestamp, and module, making it valuable for troubleshooting application issues, identifying error patterns, and generating insights from large volumes of log data.', '@direkt', 'databases', 'Unknown', 0, 'https://github.com/direkt/mcp-test', NULL, 0, 'https://github.com/direkt.png?size=128', '2026-03-09T05:21:01.952079+00:00'),
  ('io-github-oratorian-discord-node-mcp', 'io.github.Oratorian/discord-node-mcp', 'MCP server for controlling Discord servers via bot token', '@oratorian', 'development', 'Unknown', 0, 'https://github.com/oratorian/discord-node-mcp', NULL, 0, 'https://github.com/oratorian.png?size=128', '2026-03-09T05:21:01.952121+00:00'),
  ('discourse', 'Discourse', 'This TypeScript MCP server provides comprehensive Discourse forum integration, enabling AI agents to interact with Discourse sites through both built-in API tools and remote tool discovery. Built by Sam Saffron, it offers 9 core tools for searching, reading topics/posts, managing categories and tags, user lookup, and content creation, plus automatic discovery of site-specific tools via Discourse''s Tool Execution API when available. The implementation features robust HTTP client functionality with caching, retry logic, and authentication support (API keys), along with configurable security controls including read-only modes and write permissions. Valuable for community management workflows, content moderation, forum analytics, and automated customer support scenarios where AI agents need to interact with Discourse-powered communities.', '@discourse', 'development', 'Unknown', 46, 'https://github.com/discourse/discourse-mcp', NULL, 0, 'https://github.com/discourse.png?size=128', '2026-03-09T05:21:01.952154+00:00'),
  ('coco-pair-programming-master', 'Coco (Pair Programming Master)', 'MCP-Coco provides a pair programming master tool that helps AI assistants ask critical questions about code and technical solutions. Built by DJJ, this TypeScript implementation uses the FastMCP framework to create a specialized prompt that guides AI models to challenge assumptions, explore alternatives, and focus on code quality aspects like performance, security, and maintainability. The tool transforms any code snippet or design idea into a structured framework for deep technical inquiry, making it particularly valuable for developers seeking thoughtful code reviews and architectural feedback without direct solutions.', '@disdjj', 'development', 'Unknown', 4, 'https://github.com/disdjj/mcp-coco', 'mcp-coco', 3641, 'https://github.com/disdjj.png?size=128', '2026-03-09T05:21:01.952182+00:00'),
  ('cook-recipe-collection', 'Cook Recipe Collection', 'MCP-Cook is a service that provides dish information and recipes to AI agents. Created by DJJ, this implementation offers access to a large collection of over 200 dishes stored as markdown files, including both food recipes and cocktail recipes. The service is built with TypeScript and uses the Model Context Protocol SDK to make this culinary knowledge accessible through a standardized interface. It''s particularly useful for applications that need to retrieve cooking instructions, ingredient lists, or suggest dishes based on available ingredients.', '@disdjj', 'development', 'Unknown', 7, 'https://github.com/disdjj/mcp-cook', 'mcp-cook', 4170, 'https://github.com/disdjj.png?size=128', '2026-03-09T05:21:01.952210+00:00'),
  ('diskcleankit', 'DiskCleanKit', 'Provides AI assistants with disk maintenance capabilities for macOS through integration with the DiskCleanKit application. Enables scanning for junk files, automatic cleaning of safe items like system caches and browser caches, disk status monitoring, and viewing cleaning history.', '@namtran', 'ai-ml', 'Unknown', 0, 'https://github.com/namtran/diskcleankit-mcp', NULL, 0, 'https://github.com/namtran.png?size=128', '2026-03-09T05:21:01.952262+00:00'),
  ('aider', 'Aider', 'Aider MCP Server enables Claude Code to offload AI coding tasks to Aider, reducing costs and enhancing development efficiency. The server exposes two main tools: aider_ai_code for implementing code changes based on natural language prompts, and list_models for discovering available AI models. By delegating specific coding tasks to Aider while maintaining Claude Code for orchestration and review, developers gain more control over their AI coding workflow and can leverage different models for different aspects of development.', '@disler', 'development', 'Unknown', 292, 'https://github.com/disler/aider-mcp-server', NULL, 0, 'https://github.com/disler.png?size=128', '2026-03-09T05:21:01.952289+00:00'),
  ('just-prompt-multi-llm-provider', 'Just Prompt (Multi-LLM Provider)', 'Just Prompt is a lightweight MCP server that provides a unified interface to multiple LLM providers including OpenAI, Anthropic, Google Gemini, Groq, DeepSeek, and Ollama. It offers tools for sending prompts to multiple models in parallel, automatic model name correction, and saving responses to files. The implementation supports provider shorthand notation, thinking tokens for Claude models, and includes comprehensive test coverage for all providers. Ideal for developers who need to interact with multiple LLM APIs through a single, consistent interface.', '@disler', 'development', 'Unknown', 718, 'https://github.com/disler/just-prompt', NULL, 0, 'https://github.com/disler.png?size=128', '2026-03-09T05:21:01.952318+00:00'),
  ('nano-agent', 'Nano Agent', 'Nano Agent MCP server by IndyDevDan that bridges the Model Context Protocol with OpenAI''s Agent SDK to enable autonomous agent execution through natural language prompts. The implementation provides a single powerful tool that accepts task descriptions in plain English and executes them using an AI agent with file system access, supporting multiple LLM providers including OpenAI (GPT-5 models), Anthropic (Claude models), and local Ollama models. Features comprehensive file operations (read, write, edit, list directories), multi-provider configuration with automatic API key detection, token tracking and cost calculation, and includes Claude Code integration with hooks for session management, TTS notifications, and transcript logging, making it valuable for developers who want to delegate complex multi-step coding tasks, file manipulation, and project automation to AI agents through conversational interfaces.', '@disler', 'development', 'Unknown', 197, 'https://github.com/disler/nano-agent', NULL, 0, 'https://github.com/disler.png?size=128', '2026-03-09T05:21:01.952350+00:00'),
  ('plane', 'Plane', 'This MCP server provides complete integration with Plane''s project management platform through 76 specialized tools covering issues, projects, modules, cycles, labels, states, comments, attachments, time tracking, custom properties, sub-issues, and transfer operations. Built by Disrex Group using TypeScript with the MCP SDK, it includes cursor-based pagination for efficient data handling, comprehensive CRUD operations across all Plane entities, and advanced features like issue property management, sub-issue relationships, and cross-cycle issue transfers. Designed for teams using Plane who need programmatic access to their project data for automation workflows, reporting, AI-powered project analysis, and integration with other development tools through a unified API interface.', '@disrex-group', 'development', 'Unknown', 1, 'https://github.com/disrex-group/plane-mcp-server', '@disrex/plane-mcp-server', 889, 'https://github.com/disrex-group.png?size=128', '2026-03-09T05:21:01.952383+00:00'),
  ('1c-edt', '1C:EDT', 'Provides an MCP server plugin for 1C:EDT (Enterprise Developer Tools) that exposes EDT workspace functionality through HTTP endpoints. Built as an Eclipse plugin, it integrates with EDT''s internal APIs to offer tools for listing projects, retrieving configuration properties, getting validation errors, managing bookmarks and tasks, accessing check descriptions, and providing code intelligence with content assist and platform documentation lookup. Uses OSGi ServiceTracker pattern for EDT service integration and includes a status bar widget for monitoring server state.', '@ditrixnew', 'development', 'Unknown', 109, 'https://github.com/ditrixnew/edt-mcp', NULL, 0, 'https://github.com/ditrixnew.png?size=128', '2026-03-09T05:21:01.952451+00:00'),
  ('sourcegraph', 'Sourcegraph', 'The Sourcegraph MCP Server by Divar provides AI assistants with powerful code search and repository exploration capabilities through Sourcegraph''s search API. It offers three core tools: advanced code search with support for regex patterns, language filters, and repository scoping; intelligent search query guidance that helps construct effective Sourcegraph queries; and content fetching for retrieving file contents or directory structures from repositories. The implementation uses FastMCP with both SSE and HTTP transports, includes comprehensive prompt management through YAML templates, and supports both public and authenticated Sourcegraph instances, making it valuable for code discovery, codebase exploration, and understanding large software projects across multiple repositories.', '@najva-ai', 'development', 'Unknown', 27, 'https://github.com/najva-ai/sourcegraph-mcp', NULL, 0, 'https://github.com/najva-ai.png?size=128', '2026-03-09T05:21:01.952480+00:00'),
  ('zoekt', 'Zoekt', 'The Zoekt MCP Server provides AI assistants with code search capabilities through integration with Zoekt, a fast text search engine designed for source code. Built by Divar, it exposes three core tools: search for discovering code patterns across repositories using Zoekt''s query language with support for language filters, file path patterns, and repository scoping; search_prompt_guide for generating context-aware query suggestions; and fetch_content for retrieving file contents or directory structures from discovered repositories. The server supports both SSE and HTTP transports with Docker deployment, making it valuable for code exploration, debugging workflows, and understanding large codebases where users need to quickly locate specific functions, classes, or patterns across multiple repositories without manually browsing through project structures.', '@najva-ai', 'cloud', 'Unknown', 21, 'https://github.com/najva-ai/zoekt-mcp', NULL, 0, 'https://github.com/najva-ai.png?size=128', '2026-03-09T05:21:01.952507+00:00'),
  ('web-search', 'Web Search', 'This MCP server, developed for web search capabilities, provides a Puppeteer-based interface for AI assistants to perform Google searches and extract structured results. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers a containerized solution using Docker for easy deployment and scalability. The implementation focuses on headless browser automation, allowing for dynamic content retrieval and parsing. It''s particularly useful for enhancing AI models with real-time web data, enabling tasks like information gathering, fact-checking, or content generation with current search results, while operating within a controlled environment that can handle modern web technologies and JavaScript-rendered content.', '@divslingerx', 'cloud', 'Unknown', 1, 'https://github.com/divslingerx/mcp-server', NULL, 0, 'https://github.com/divslingerx.png?size=128', '2026-03-09T05:21:01.952530+00:00'),
  ('github-explorer', 'GitHub Explorer', 'GitHub MCP Server provides a bridge to the GitHub API, enabling AI assistants to interact with GitHub data through three key functions: retrieving user information, accessing repository details, and fetching authenticated user data. Built with Python using the FastMCP framework, it handles authentication through GitHub tokens stored as environment variables and includes comprehensive error handling for HTTP status errors and timeouts. This implementation is particularly valuable for workflows requiring GitHub data retrieval directly within Claude conversations, making it ideal for code collaboration, repository exploration, and user profile analysis.', '@divyanshkushwaha', 'development', 'Unknown', 0, 'https://github.com/divyanshkushwaha/github-mcp-server-claude', NULL, 0, 'https://github.com/divyanshkushwaha.png?size=128', '2026-03-09T05:21:01.952581+00:00'),
  ('appointysaastak-ui-components', 'AppointySaastak UI Components', 'UITemplateServer provides a resource-based interface for AI assistants to access and utilize UI components from the AppointySaastak library. Built with the Model Context Protocol SDK, it serves login interface templates (both basic and modern variants) with their associated HTML, CSS, and JavaScript files. The server implements robust error handling and metadata enrichment, making it ideal for AI-powered code generation workflows where the LLM needs to combine UI templates with backend code. This implementation enables seamless integration between AI assistants and pre-built UI components, streamlining the development of login interfaces without requiring manual code retrieval.', '@divyanshu-vashu', 'development', 'Unknown', 0, 'https://github.com/divyanshu-vashu/mcp_server', NULL, 0, 'https://github.com/divyanshu-vashu.png?size=128', '2026-03-09T05:21:01.952610+00:00'),
  ('quran-com-api', 'Quran.com API', 'Quran MCP Server provides a bridge to the Quran.com API v4, enabling AI assistants to access Islamic scripture and related resources. Built with TypeScript and the Model Context Protocol SDK, it offers tools for retrieving chapters, verses, translations, tafsirs (commentaries), and audio recitations from the Quran. The implementation features robust error handling, request validation using Zod schemas, and intelligent caching to improve performance while reducing API load. This server is particularly valuable for researchers, students, and anyone seeking to incorporate Quranic references into their AI interactions without switching to external resources.', '@djalal', 'development', 'Unknown', 61, 'https://github.com/djalal/quran-mcp-server', NULL, 0, 'https://github.com/djalal.png?size=128', '2026-03-09T05:21:01.952640+00:00'),
  ('puppeteer-vision-web-scraper', 'Puppeteer Vision Web Scraper', 'Puppeteer Vision MCP Server provides a tool for scraping webpages and converting them to markdown format using Puppeteer, Mozilla''s Readability, and Turndown. Developed by Denis Jannot, it features AI-driven interaction capabilities that automatically handle cookie consent banners, CAPTCHAs, paywalls, and other interactive elements blocking content. The server uses OpenAI''s vision models to analyze screenshots of web pages and determine appropriate interactions, with special handling for code blocks, tables, and other structured content. Available as an NPX package with configurable headless mode, it supports both stdio and SSE transport methods, making it particularly valuable for AI assistants that need to extract and process web content without being blocked by interactive elements.', '@djannot', 'development', 'Unknown', 47, 'https://github.com/djannot/puppeteer-vision-mcp', 'puppeteer-vision-mcp-server', 1140, 'https://github.com/djannot.png?size=128', '2026-03-09T05:21:01.952672+00:00'),
  ('firelinks', 'Firelinks', 'This server provides access to the Firelinks URL shortening platform through tools for link management, domain configuration, server administration, and analytics. Built with Node.js and Express, it offers both CLI and HTTP modes, supporting operations like creating and updating short links, managing custom domains with SSL configuration, retrieving detailed click statistics with extensive filtering options, and accessing server information. The implementation features robust error handling, authentication via API tokens, and detailed analytics capabilities including geographic data, device information, and traffic quality metrics, making it useful for businesses managing branded short links, marketers analyzing campaign performance, and developers integrating URL shortening into applications.', '@djeknet', 'ai-ml', 'Unknown', 3, 'https://github.com/djeknet/firelinks-mcp', NULL, 0, 'https://github.com/djeknet.png?size=128', '2026-03-09T05:21:01.952724+00:00'),
  ('bruno-api', 'Bruno API', 'Bruno API MCP Server provides a bridge between AI assistants and Bruno API collections, enabling execution of HTTP requests defined in Bruno''s .bru format through the Model Context Protocol. The server automatically loads API collections, parses environment variables, and exposes each request as a callable tool with appropriate schemas, making it valuable for testing APIs, automating workflows, and integrating external services directly from AI conversations without manual request configuration.', '@djkz', 'development', 'Unknown', 2, 'https://github.com/djkz/bruno-api-mcp', NULL, 0, 'https://github.com/djkz.png?size=128', '2026-03-09T05:21:01.952750+00:00'),
  ('chroma-working-memory', 'Chroma Working Memory', 'Chroma MCP Server provides a persistent, searchable ''working memory'' for AI-assisted development by integrating ChromaDB (an open-source embedding database) with the Model Context Protocol. Developed by Nold Coaching & Consulting, it features automated codebase indexing, chat logging, and sequential thinking tools that enable AI assistants to query relevant information from past sessions. The server supports multiple client types (ephemeral, persistent, HTTP, cloud), offers configurable embedding functions, and includes utilities for promoting insights from conversations to a structured knowledge base, making it particularly valuable for maintaining context across development sessions and creating a unified knowledge hub for AI-human collaboration.', '@djm81', 'databases', 'Unknown', 26, 'https://github.com/djm81/chroma_mcp_server', 'chroma-mcp-server', 96018, 'https://github.com/djm81.png?size=128', '2026-03-09T05:21:01.952762+00:00'),
  ('log-analyzer', 'Log Analyzer', 'This MCP server provides powerful log analysis capabilities for Python development workflows, offering both a command-line interface and MCP server integration for AI assistants. Built with a flexible core analysis engine that supports time-based filtering (last N minutes/hours/days), positional filtering (first/last N records), and configurable content pattern matching across multiple log levels, it enables developers to quickly parse pytest test outputs, search runtime error logs, and generate code coverage reports. The implementation features environment-based configuration through .env files with support for named logging scopes, context line extraction around matches, and integration with hatch for test execution and coverage generation, making it valuable for debugging complex applications, monitoring test runs, and maintaining code quality in Python projects.', '@djm81', 'development', 'Unknown', 8, 'https://github.com/djm81/log_analyzer_mcp', 'log-analyzer-mcp', 5555, 'https://github.com/djm81.png?size=128', '2026-03-09T05:21:01.952793+00:00'),
  ('supabase-coolify', 'Supabase Coolify', 'Provides comprehensive management for self-hosted Supabase deployments on Coolify platform with database migrations, SQL execution, edge function deployment and monitoring, storage bucket management, authentication provider configuration, and service health monitoring. Integrates with Coolify''s API to control applications, services, databases, and environment variables for complete DevOps automation of Supabase infrastructure.', '@dj-pearson', 'databases', 'Unknown', 1, 'https://github.com/dj-pearson/supabase-coolify-mcp-server', NULL, 0, 'https://github.com/dj-pearson.png?size=128', '2026-03-09T05:21:01.952804+00:00'),
  ('powerpoint', 'PowerPoint', 'PowerPoint Manager MCP server enables Claude to create and manipulate PowerPoint presentations directly within conversations. Built with FastMCP and python-pptx, it provides tools for creating professional presentations with customizable slides, applying formatting themes, and generating slide previews. The implementation handles structured content like bullet points, text formatting, and slide layouts while saving presentations to an accessible user directory, making it ideal for quickly generating business presentations, educational materials, or visual content without leaving the Claude interface.', '@djvosper', 'ai-ml', 'Unknown', 2, 'https://github.com/djvosper/mcp-pptx', NULL, 0, 'https://github.com/djvosper.png?size=128', '2026-03-09T05:21:01.952862+00:00'),
  ('esa-io-api', 'esa.io API', 'This esa MCP server, developed by d-kimuson, provides integration with the esa.io API for team collaboration and knowledge management. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers tools for searching and retrieving esa posts. The implementation focuses on simplifying access to esa.io functionality through a standardized MCP interface, with features like mock data generation for testing. It''s particularly useful for AI assistants and applications needing to incorporate team knowledge and documentation, enabling use cases such as information retrieval, content summarization, and collaborative writing without directly dealing with the complexities of the esa.io API.', '@d-kimuson', 'development', 'Unknown', 35, 'https://github.com/d-kimuson/esa-mcp-server', 'esa-mcp-server', 6480, 'https://github.com/d-kimuson.png?size=128', '2026-03-09T05:21:01.952892+00:00'),
  ('azure-function-apps', 'Azure Function Apps', 'This MCP server, developed by Christian Pedersen, enables testing of Azure Function Apps through Cline. Built with TypeScript, it provides a command-line interface for interacting with Function App endpoints using various HTTP methods. The implementation supports custom headers, request body handling, and multiple authentication methods including Basic, Bearer Token, and API Key. It''s designed for developers working with Azure Function Apps who need a streamlined way to test and debug their endpoints, offering a bridge between natural language interactions and Azure serverless functions. The tool is particularly useful for scenarios involving rapid prototyping, automated testing, or AI-assisted Azure Function App development.', '@dkmaker', 'cloud', 'Unknown', 3, 'https://github.com/dkmaker/mcp-function-app-tester', NULL, 0, 'https://github.com/dkmaker.png?size=128', '2026-03-09T05:21:01.952941+00:00'),
  ('system-information', 'System Information', 'This MCP server provides real-time system monitoring and information retrieval capabilities through psutil, enabling AI assistants to access CPU usage, memory statistics, disk information, network status, running processes, and system uptime data. Built using Python with FastMCP and comprehensive caching for performance optimization, it offers seven specialized tools including per-CPU breakdowns, process filtering and sorting, temperature sensor readings when available, and configurable limits for resource-intensive operations. The implementation features cross-platform compatibility with graceful degradation for platform-specific features, security controls that filter sensitive command-line arguments, multiple transport options (stdio, SSE, HTTP), and environment-based configuration for cache TTL and process limits, making it valuable for system administration workflows, performance monitoring applications, and building AI assistants that need programmatic access to system metrics without manual monitoring tool navigation.', '@dknell', 'development', 'Unknown', 3, 'https://github.com/dknell/mcp-system-info', 'mcp-system-info', 1873, 'https://github.com/dknell.png?size=128', '2026-03-09T05:21:01.952982+00:00'),
  ('flutter-tools', 'Flutter Tools', 'This MCP server, developed by dkpoulsen, provides tools for interacting with the Flutter SDK. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers functionalities for analyzing and fixing Dart/Flutter files. The implementation focuses on two main tools: ''get_diagnostics'' for retrieving Flutter/Dart diagnostics, and ''apply_fixes'' for applying Dart fix suggestions to files. By connecting AI models with Flutter development tools, this server enables scenarios such as automated code analysis, error detection, and code improvement suggestions. It''s particularly useful for AI-assisted Flutter development, enabling seamless integration of AI capabilities into the Flutter development workflow.', '@dkpoulsen', 'development', 'Unknown', 8, 'https://github.com/dkpoulsen/flutter-tools', NULL, 0, 'https://github.com/dkpoulsen.png?size=128', '2026-03-09T05:21:01.953012+00:00'),
  ('hetzner-cloud', 'Hetzner Cloud', 'A Model Context Protocol server for Hetzner Cloud API, developed by Dennis Kruyt, that enables language models to manage cloud infrastructure resources through structured functions. The implementation provides tools for creating and managing servers, volumes, firewalls, and SSH keys on the Hetzner Cloud platform, with comprehensive error handling and detailed response formatting. It supports both stdio and SSE transport modes, making it compatible with Claude Code and other MCP clients, and is particularly useful for AI-assisted cloud infrastructure management, automated provisioning, and infrastructure-as-code scenarios.', '@dkruyt', 'development', 'Unknown', 82, 'https://github.com/dkruyt/mcp-hetzner', NULL, 0, 'https://github.com/dkruyt.png?size=128', '2026-03-09T05:21:01.953038+00:00'),
  ('desktop-automation', 'Desktop Automation', 'A Windows desktop automation MCP server that uses UI Automation APIs instead of screenshots to interact with desktop applications. Provides comprehensive desktop control including window management, smart element finding by text content, mouse and keyboard automation, and hotkey support. Ideal for automating Windows applications, data entry tasks, and GUI testing workflows.', '@dlanz1', 'development', 'Unknown', 1, 'https://github.com/dlanz1/desktop-mcp-server', NULL, 0, 'https://github.com/dlanz1.png?size=128', '2026-03-09T05:21:01.953060+00:00'),
  ('bybit-exchange-api', 'Bybit Exchange API', 'MCP Bybit Server provides a bridge to the Bybit cryptocurrency exchange API, enabling AI assistants to perform market data retrieval, account management, and order execution operations. Developed by Dana K. Williams, this Python implementation offers a comprehensive set of tools for interacting with Bybit''s Unified Trading API v5, including functions for retrieving orderbooks, candlestick data, wallet balances, and placing/managing orders across spot and futures markets. The server requires Bybit API credentials and can be deployed as a Docker container, making it particularly useful for algorithmic trading, market analysis, and portfolio management applications.', '@dlwjdtn535', 'cloud', 'Unknown', 7, 'https://github.com/dlwjdtn535/mcp-bybit-server', NULL, 0, 'https://github.com/dlwjdtn535.png?size=128', '2026-03-09T05:21:01.953123+00:00'),
  ('dmarcdkim-com', 'DmarcDkim.com', 'DmarcDkim.com provides a hosted MCP server for DNS and email authentication validation, enabling developers to programmatically verify DMARC, SPF, and DKIM configurations. The server offers four core tools: DNS lookup for querying A, AAAA, MX, TXT, NS, CNAME, PTR records and WHOIS data; DMARC checking with error detection; SPF validation with RFC 7208 compliance checking and circular reference detection; and SPF merge functionality to consolidate multiple SPF records into optimized single records. Built for email security professionals and developers managing domain authentication, the service helps prevent email spoofing, improve deliverability, and ensure email authentication compliance.', '@unknown', 'communication', 'Unknown', 0, 'https://dmarcdkim.com/solutions/dmarc-mcp-server', NULL, 0, NULL, '2026-03-09T05:21:01.953197+00:00'),
  ('minima-local-rag', 'Minima (Local RAG)', 'This MCP server, developed by dmayboroda, enables AI assistants like Claude to perform RAG (Retrieval-Augmented Generation) on local files. Built in Python and leveraging the uv package manager, it integrates seamlessly with MCP clients through a simple configuration file. The server allows the client to search and retrieve context from the user''s local documents, enhancing its ability to provide relevant and personalized responses. By granting access to private or offline information sources, this implementation extends the client''s knowledge base beyond its training data, making it particularly useful for tasks involving confidential documents, personal notes, or frequently updated local resources.', '@dmayboroda', 'productivity', 'Unknown', 1039, 'https://github.com/dmayboroda/minima/tree/HEAD/mcp-server', NULL, 0, 'https://github.com/dmayboroda.png?size=128', '2026-03-09T05:21:01.953236+00:00'),
  ('claude-c2', 'Claude-C2', 'Claude-C2 is a command and control (C2) framework that enables communication with remote systems through a Python server and PowerShell client. The implementation creates API endpoints to manage tasks and retrieve output, with Claude acting as the intermediary through MCP tools that can create tasks and check their status. The server maintains a SQLite database to track pending and completed commands, while the PowerShell client polls for new tasks, executes them on the target system, and reports results back to the server - making it particularly useful for remote system administration or security testing scenarios.', '@dmcxblue', 'databases', 'Unknown', 86, 'https://github.com/dmcxblue/claude-c2', NULL, 0, 'https://github.com/dmcxblue.png?size=128', '2026-03-09T05:21:01.953250+00:00'),
  ('overseer', 'Overseer', 'Task orchestration system that creates hierarchical milestone-task-subtask structures with inherited context and learnings, automatically managing version control bookmarks and commits throughout task lifecycle transitions for clean development history.', '@dmmulroy', 'development', 'Unknown', 221, 'https://github.com/dmmulroy/overseer', NULL, 0, 'https://github.com/dmmulroy.png?size=128', '2026-03-09T05:21:01.953272+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('3d-printer-manager', '3D Printer Manager', 'This MCP server implementation provides a bridge between AI assistants and various 3D printer management systems, including OctoPrint, Klipper, Duet, Repetier, and Bambu Labs printers. Developed by David Montgomery, it offers tools for printer control, file management, and advanced STL file manipulation. The server is designed for use cases requiring 3D printing integration, such as remote printer monitoring, automated print job management, and custom model modifications.', '@dmontgomery40', 'ai-ml', 'Unknown', 159, 'https://github.com/dmontgomery40/mcp-3d-printer-server', 'mcp-3d-printer-server', 5976, 'https://github.com/dmontgomery40.png?size=128', '2026-03-09T05:21:01.953312+00:00'),
  ('birdnet-pi', 'BirdNet-Pi', 'This BirdNet-Pi MCP server, developed by DMontgomery40, integrates BirdNet-Pi''s bird detection capabilities with a FastAPI-based JSON-RPC interface. It provides functions for retrieving bird detections, detection statistics, audio recordings, and daily activity data. The server abstracts BirdNet-Pi''s functionality, offering a standardized way for AI assistants to access and analyze bird detection data. By connecting AI systems with BirdNet-Pi''s acoustic monitoring capabilities, this implementation enables applications such as automated bird species identification, habitat monitoring, and ecological research. It is particularly useful for ornithologists, conservationists, and citizen scientists who want to leverage AI for analyzing bird populations and behaviors.', '@dmontgomery40', 'ai-ml', 'Unknown', 3, 'https://github.com/dmontgomery40/mcp-local-server', NULL, 0, 'https://github.com/dmontgomery40.png?size=128', '2026-03-09T05:21:01.953362+00:00'),
  ('birdstats', 'BirdStats', 'This MCP server for BirdNET-Pi and eBird analysis, developed by David Montgomery, enables AI assistants to cross-reference bird detection data from BirdNET-Pi/BirdWeather stations with eBird''s extensive observation database. It integrates the BirdWeather and eBird APIs to provide tools for querying detections, species information, and observation data using natural language. Built with TypeScript and the Model Context Protocol SDK, it implements data integrity principles and offers data-driven visualizations through React artifacts. The server is designed for ornithologists, bird enthusiasts, and ecological researchers, enabling use cases like rare bird identification, migration pattern analysis, and local biodiversity assessment.', '@dmontgomery40', 'databases', 'Unknown', 1, 'https://github.com/dmontgomery40/mcp-server-birdstats', 'mcp-birdstats', 408, 'https://github.com/dmontgomery40.png?size=128', '2026-03-09T05:21:01.953373+00:00'),
  ('deepseek', 'DeepSeek', 'This DeepSeek MCP server, developed by David Montgomery, enables seamless integration of DeepSeek''s advanced language models with MCP-compatible applications like Claude Desktop. Built with TypeScript and leveraging the Model Context Protocol SDK, it provides a chat completion tool with customizable parameters such as model selection, temperature control, and token limits. The implementation focuses on simplifying access to DeepSeek''s powerful AI capabilities through a standardized interface. It''s particularly useful for developers and researchers looking to incorporate state-of-the-art language models into their applications without dealing directly with DeepSeek''s API intricacies, enabling use cases like AI-assisted writing, code generation, and complex reasoning tasks.', '@dmontgomery40', 'development', 'Unknown', 300, 'https://github.com/dmontgomery40/deepseek-mcp-server', 'deepseek-mcp-server', 5729, 'https://github.com/dmontgomery40.png?size=128', '2026-03-09T05:21:01.953430+00:00'),
  ('faxbot', 'Faxbot', 'Faxbot is a modern MCP server that provides AI-native T.38 fax transmission capabilities through both cloud (Phaxio) and on-premises (Asterisk SIP) backends, featuring dual transport support for stdio and streamable HTTP with OAuth2 authentication. Built with Node.js and Python variants, it offers comprehensive fax operations including document sending (PDF/TXT), status tracking, and webhook callbacks, with enterprise features like audit logging, HIPAA compliance considerations, and Docker deployment. The implementation includes client SDKs for Node.js and Python, automated installation scripts for Claude Desktop and Cursor integration, and supports both traditional telephony infrastructure and modern cloud fax services, making it ideal for healthcare organizations, legal firms, and businesses requiring reliable programmatic fax capabilities with AI assistant integration.', '@dmontgomery40', 'cloud', 'Unknown', 5, 'https://github.com/dmontgomery40/faxbot', 'faxbot-mcp', 203, 'https://github.com/dmontgomery40.png?size=128', '2026-03-09T05:21:01.953456+00:00'),
  ('generate-custom-mcps', 'Generate Custom MCPs', 'This Meta MCP Server, developed by David Montgomery, enables AI assistants to dynamically create customized MCP servers. It utilizes the Model Context Protocol SDK to manage tools and resources, automating the creation of directories and files for new servers. The implementation focuses on flexibility, allowing users to specify the structure and content of generated servers. By abstracting the complexities of server setup, this tool streamlines the process of creating specialized MCP servers for various AI applications. It is particularly useful for developers and researchers who need to rapidly prototype or deploy custom MCP servers tailored to specific AI tasks or integrations.', '@dmontgomery40', 'productivity', 'Unknown', 21, 'https://github.com/dmontgomery40/meta-mcp-server', 'meta-mcp-server', 5554, 'https://github.com/dmontgomery40.png?size=128', '2026-03-09T05:21:01.953499+00:00'),
  ('onekgp', 'OneKGP', 'Provides natural language querying capabilities for the 1000 Genomes Project dataset, enabling researchers to explore genetic variants, inherited disease patterns, and population genetics across 3,202 human samples and 138 million unique variants. Built on the Dnaerys variant store service, it offers specialized tools for analyzing genomic data aligned to the GRCh38 reference genome without requiring direct database knowledge.', '@dnaerys', 'databases', 'Unknown', 0, 'https://github.com/dnaerys/onekgpd-mcp', NULL, 0, 'https://github.com/dnaerys.png?size=128', '2026-03-09T05:21:01.953510+00:00'),
  ('frida', 'Frida', 'Frida MCP provides a bridge between AI systems and mobile/desktop applications through Frida''s dynamic instrumentation toolkit. This implementation enables AI assistants to interact with running processes across devices, offering capabilities like process management, device enumeration, JavaScript execution, and script injection. Built with the official MCP Python SDK, it features an interactive JavaScript REPL with real-time execution, comprehensive error handling, and progress tracking for long-running operations. The server is designed for seamless integration with Claude Desktop and supports all MCP transport methods, making it valuable for application analysis, debugging, and security testing workflows.', '@dnakov', 'development', 'Unknown', 226, 'https://github.com/dnakov/frida-mcp', 'frida-mcp', 4998, 'https://github.com/dnakov.png?size=128', '2026-03-09T05:21:01.953539+00:00'),
  ('radare2', 'Radare2', 'Radare2 MCP Server provides a direct bridge between AI assistants like Claude and the radare2 binary analysis framework. This implementation enables AI tools to perform sophisticated binary analysis tasks including opening files, running commands, analyzing code, and disassembling instructions through a simple stdin/stdout communication model. The server exposes radare2''s capabilities as MCP resources and tools, making it particularly valuable for reverse engineering workflows, malware analysis, and debugging applications without leaving the AI assistant conversation interface.', '@radareorg', 'development', 'Unknown', 159, 'https://github.com/radareorg/radare2-mcp', NULL, 0, 'https://github.com/radareorg.png?size=128', '2026-03-09T05:21:01.953566+00:00'),
  ('fiware-context-broker', 'FIWARE Context Broker', 'FIWARE MCP Server provides a bridge between AI assistants and FIWARE Context Brokers, enabling interaction with IoT data through natural language. This implementation offers tools for checking broker versions, querying entities, and publishing or updating data in the Context Broker using NGSI-LD format. Built with FastMCP, the server includes robust error handling and timeout management, making it valuable for users who need to monitor and control IoT devices or access contextual data without leaving their AI assistant interface.', '@dncampo', 'ai-ml', 'Unknown', 3, 'https://github.com/dncampo/fiware-mcp-server', NULL, 0, 'https://github.com/dncampo.png?size=128', '2026-03-09T05:21:01.953607+00:00'),
  ('bilibili', 'Bilibili', 'Bilibili-mcp-server is a Go-based MCP server that provides a bridge to the Bilibili API, enabling AI assistants to interact with the popular Chinese video-sharing platform. Developed by DnullP, this implementation offers tools for retrieving user profile information, listing followed accounts, and finding videos through both v1 (tools) and v2 (resource) interfaces. The server requires user authentication via cookies stored in a configuration file and leverages the CuteReimu/bilibili Go library for API interactions. It can be compiled for both Windows and Linux environments, making it useful for applications that need to access Bilibili account data or content discovery without direct API integration.', '@dnullp', 'ai-ml', 'Unknown', 4, 'https://github.com/dnullp/bilibili-mcp-server', NULL, 0, 'https://github.com/dnullp.png?size=128', '2026-03-09T05:21:01.953654+00:00'),
  ('docent-image-description', 'Docent (Image Description)', 'A Docent Server implementation that enables AI assistants to generate descriptions of images through the MCP framework. Built with TypeScript and Node.js, this server leverages the FastMCP library and OpenAI''s API to provide image description capabilities. The implementation registers a specialized docent tool that processes image inputs and returns detailed descriptions, making it particularly useful for accessibility applications, content analysis, and enhancing AI interactions with visual media.', '@dongprojectteam', 'development', 'Unknown', 2, 'https://github.com/dongprojectteam/mcp-docent-server', NULL, 0, 'https://github.com/dongprojectteam.png?size=128', '2026-03-09T05:21:01.953684+00:00'),
  ('docfork', 'Docfork', 'This MCP server provides access to up-to-date documentation and code examples for any software library through the Docfork API, enabling AI assistants to retrieve focused documentation based on library name and specific topics. Built by Docfork Corp using TypeScript with the MCP SDK, it features configurable token limits for response size control, automatic library selection based on relevance scoring, topic-focused documentation retrieval, and support for both HTTP and stdio transports with CORS handling for web integration. The implementation includes comprehensive error handling with detailed API response parsing, environment variable configuration for default token limits, and structured responses that explain library selection rationale alongside the requested documentation, making it valuable for developers needing current library documentation during coding sessions, AI assistants providing programming help, and any workflow requiring access to fresh, contextual software library information without manually searching through outdated documentation sites.', '@docfork', 'development', 'Unknown', 433, 'https://github.com/docfork/docfork', 'docfork', 17507, 'https://github.com/docfork.png?size=128', '2026-03-09T05:21:01.953716+00:00'),
  ('dock-ai', 'Dock AI', 'Dock AI is a registry that maps businesses to their available MCP connectors. When an AI agent needs to interact with a real-world business (booking, ordering, shopping), it queries Dock AI to discover which MCP servers can handle that entity. The service returns endpoint information, capabilities, and verification levels for discovered connectors.', '@dock-ai', 'ai-ml', 'Unknown', 2, 'https://github.com/dock-ai/mcp', NULL, 0, 'https://github.com/dock-ai.png?size=128', '2026-03-09T05:21:01.953775+00:00'),
  ('docker-release-information', 'Docker Release Information', 'Provides access to release notes and security information for Docker Desktop releases. Built as a sample implementation for Docker training materials and blog posts, demonstrating how to create MCP servers that integrate with Docker ecosystem data.', '@dockersamples', 'cloud', 'Unknown', 0, 'https://github.com/dockersamples/mcp-docker-release-information', NULL, 0, 'https://github.com/dockersamples.png?size=128', '2026-03-09T05:21:01.953791+00:00'),
  ('docnav', 'DocNav', 'DocNav is an MCP server that enables LLMs to intelligently read, navigate, and analyze long-form documents by breaking them into hierarchical tree structures similar to DOM nodes. The implementation supports Markdown and PDF files through pluggable processors, converting documents into navigable sections with auto-generated UUIDs for security, and provides tools for outline generation, section-by-section reading, content search, and contextual navigation with parent-child-sibling relationships. Built with a modular architecture using Python, it''s particularly valuable for document analysis workflows where LLMs need to understand document structure and navigate large texts systematically rather than processing them as monolithic blocks.', '@shenyimings', 'ai-ml', 'Unknown', 2, 'https://github.com/shenyimings/docnav-mcp', NULL, 0, 'https://github.com/shenyimings.png?size=128', '2026-03-09T05:21:01.953844+00:00'),
  ('docs-rs', 'docs.rs', 'An MCP server that enables searching for Rust crates and their documentation from crates.io and docs.rs. Built with TypeScript and the MCP SDK, it provides four core tools: searching crates by keywords with sorting options, retrieving README/overview content, fetching documentation for specific items (structs, traits, functions, etc.), and searching within a crate''s API surface. The implementation uses web scraping with Cheerio to parse HTML documentation pages and converts them to markdown format, making it valuable for Rust developers who want to explore the ecosystem, understand API usage, or get quick documentation access without leaving their AI assistant interface.', '@nuskey8', 'development', 'Unknown', 24, 'https://github.com/nuskey8/docs-rs-mcp', '@nuskey8/docs-rs-mcp', 971, 'https://github.com/nuskey8.png?size=128', '2026-03-09T05:21:01.953885+00:00'),
  ('doctranslate-io', 'DocTranslate.io', 'This MCP server provides AI assistants with document translation and conversion capabilities through DocTranslate.io''s API, built using Python with FastMCP and supporting multiple document formats including DOCX, PDF, PPTX, and XLSX. The implementation offers six core tools for translating documents with customizable tone and domain settings, converting documents to PPTX format with template selection, translating plain text with bilingual output options, retrieving translation results by task ID, accessing user translation history with filtering, and monitoring credit usage for cost management. Built with comprehensive language support covering 26 languages, flexible processing modes including bilingual text generation, custom dictionary integration, and HTTP-based deployment with API key authentication, it serves content creators needing multilingual document production, international businesses requiring automated document localization workflows, and teams wanting to integrate professional translation services into AI-assisted content management without direct API interaction.', '@thinkprompt', 'productivity', 'Unknown', 7, 'https://github.com/thinkprompt/doctranslateio-mcp', NULL, 0, 'https://github.com/thinkprompt.png?size=128', '2026-03-09T05:21:01.953966+00:00'),
  ('docy-documentation-access', 'Docy (Documentation Access)', 'Docy is an MCP server that provides AI assistants with direct access to technical documentation from configured sources. Built by Oliver Borchers, it uses crawl4ai to scrape documentation websites and diskcache for efficient caching, enabling LLMs to search, retrieve, and navigate through documentation content without leaving the conversation context. The server features hot-reload support for documentation sources, intelligent caching to reduce latency, and can be deployed as a shared SSE server across multiple projects. Particularly valuable for developers who need accurate, real-time documentation access during coding sessions, Docy helps eliminate outdated information and broken links when working with technical frameworks and libraries.', '@oborchers', 'productivity', 'Unknown', 18, 'https://github.com/oborchers/mcp-server-docy', 'mcp-server-docy', 3947, 'https://github.com/oborchers.png?size=128', '2026-03-09T05:21:01.954044+00:00'),
  ('dodo-payments', 'Dodo Payments', 'A Model Context Protocol (MCP) server implementation for Dodo Payments, enabling secure payment processing capabilities for AI applications.', '@dodopayments', 'ai-ml', 'Unknown', 44, 'https://github.com/dodopayments/dodopayments-typescript/tree/HEAD/packages/mcp-server', 'dodopayments-mcp', 22642, 'https://github.com/dodopayments.png?size=128', '2026-03-09T05:21:01.954071+00:00'),
  ('leetcode', 'LeetCode', 'This LeetCode MCP server provides AI assistants with structured access to LeetCode''s problem database, user profiles, and contest information through GraphQL queries. Built with TypeScript and the Model Context Protocol SDK, it offers tools for retrieving daily challenges, searching problems by difficulty and tags, accessing user submissions, and fetching contest rankings. The implementation features comprehensive error handling and a modular architecture with clearly defined resources using custom URI schemes. It''s particularly useful for developers and coding interview candidates who want to explore LeetCode problems, track their progress, or analyze contest performance through natural language interactions.', '@doggybee', 'databases', 'Unknown', 40, 'https://github.com/doggybee/mcp-server-leetcode', NULL, 0, 'https://github.com/doggybee.png?size=128', '2026-03-09T05:21:01.954137+00:00'),
  ('pulumi', 'Pulumi', 'Pulumi MCP Server provides a bridge to the Pulumi Cloud API, enabling AI assistants to manage infrastructure as code through Pulumi stacks. The server exposes capabilities to create new stacks and list existing ones across organizations and projects, with validation using Zod to ensure proper input parameters. Built with TypeScript and the Model Context Protocol SDK, it uses environment variables for authentication and implements both high-level and low-level server interfaces. This implementation is particularly valuable for DevOps workflows where infrastructure management needs to be integrated directly into AI assistant conversations.', '@dogukanakkaya', 'cloud', 'Unknown', 3, 'https://github.com/dogukanakkaya/pulumi-mcp-server', NULL, 0, 'https://github.com/dogukanakkaya.png?size=128', '2026-03-09T05:21:01.954159+00:00'),
  ('ragcode', 'RagCode', 'RagCode transforms repositories into AI-ready codebases through semantic vector search, enabling understanding by meaning rather than keywords. Built in Go with support for Go, PHP (including Laravel), and Python codebases, it uses local Ollama for embeddings and Qdrant for vector storage to maintain complete privacy without external API calls. The server provides semantic search, hybrid search, function details retrieval, type definition lookup, and workspace indexing across multiple languages with automatic workspace detection and per-language collection management.', '@doitmagic', 'development', 'Unknown', 24, 'https://github.com/doitmagic/rag-code-mcp', NULL, 0, 'https://github.com/doitmagic.png?size=128', '2026-03-09T05:21:01.954181+00:00'),
  ('sensei-dojo', 'Sensei (Dojo)', 'Sensei MCP server provides specialized guidance for Dojo development on the Starknet ecosystem, offering expert assistance with Cairo programming and the Entity Component System (ECS) framework. Built with TypeScript and the Model Context Protocol SDK, it loads specialized prompts and resources for different aspects of Dojo development including models, systems, testing, and token standards. The server registers these as tools that Claude can access during conversations, making it particularly valuable for developers building onchain games and applications who need contextual, framework-specific guidance without leaving their development workflow.', '@dojoengine', 'development', 'Unknown', 13, 'https://github.com/dojoengine/sensei-mcp', NULL, 0, 'https://github.com/dojoengine.png?size=128', '2026-03-09T05:21:01.954212+00:00'),
  ('dollhousemcp', 'DollhouseMCP', 'DollhouseMCP enables dynamic AI persona management from markdown files, allowing Claude and other AI assistants to activate and switch between different behavioral personas stored locally or from a GitHub-based marketplace. Built by Mick Darling using TypeScript with the Model Context Protocol SDK, it offers persona activation/deactivation, local persona creation and editing with guided interfaces, marketplace browsing and installation from the DollhouseMCP-Personas repository, user identity management for attribution, and persona validation with comprehensive metadata support including categories, triggers, pricing, and content flags. The implementation features automatic unique ID generation, GitHub API integration for marketplace operations, submission workflows through GitHub issues, and robust persona loading with fallback defaults, making it valuable for AI assistants that need role-playing capabilities, content creators building character libraries, educational applications requiring different teaching styles, and developers who want to customize AI behavior for specific domains or use cases.', '@dollhousemcp', 'development', 'Unknown', 28, 'https://github.com/dollhousemcp/mcp-server', NULL, 0, 'https://github.com/dollhousemcp.png?size=128', '2026-03-09T05:21:01.954250+00:00'),
  ('brave-labs-domain-checker', 'Brave Labs Domain Checker', 'Fast domain availability checker MCP server for AI assistants. Uses a hybrid approach combining DNS lookups with RDAP (and WHOIS fallback) for accurate verification. Supports bulk checking of up to 100 domains in parallel, automatic name expansion across popular TLDs, and filtering by availability status. Provides three checking tools: standard verification, bulk name checking, and fast DNS-only checks. Built by Brave Labs, an Australian technology agency.', '@wearebravelabs', 'ai-ml', 'Unknown', 0, 'https://github.com/wearebravelabs/domain-checker-mcp', NULL, 0, 'https://github.com/wearebravelabs.png?size=128', '2026-03-09T05:21:01.954285+00:00'),
  ('domainkits', 'DomainKits', 'DomainKits provides domain intelligence tools through MCP-compatible clients. It offers tools for searching newly registered domains by keyword with filtering by TLD, length, and date range, performing nameserver reverse lookups to identify domains hosted on specified nameservers, and counting domains across multiple data sources including newly registered, expired, and aged domains. Rate limited to 10 requests per minute per IP with responses limited to 5 domains. NRDS data has a 24-48 hour delay from registration.', '@abtdomain', 'ai-ml', 'Unknown', 3, 'https://github.com/abtdomain/domainkits-mcp', NULL, 0, 'https://github.com/abtdomain.png?size=128', '2026-03-09T05:21:01.954320+00:00'),
  ('airtable', 'Airtable', 'This MCP server, developed by domdomegg, enables AI assistants like Claude to interact with Airtable databases. Built in TypeScript, it provides capabilities for querying and modifying Airtable bases, tables, fields, and records through a standardized interface. The implementation stands out by offering full read/write access to Airtable''s rich data model and metadata. By connecting AI capabilities with structured data in Airtable, this server allows AI systems to analyze, manipulate, and act on user-defined datasets. It is particularly useful for automating data entry workflows, building AI-powered data analysis tools, or creating natural language interfaces to Airtable-based applications.', '@domdomegg', 'databases', 'Unknown', 429, 'https://github.com/domdomegg/airtable-mcp-server', 'airtable-mcp-server', 83918, 'https://github.com/domdomegg.png?size=128', '2026-03-09T05:21:01.954331+00:00'),
  ('computer-use', 'Computer Use', 'Enables complete computer control through screenshots, mouse movements, keyboard input, and clicking. Runs locally using nut.js library to interact with your computer''s input/output devices. Provides a local alternative to Anthropic''s official computer use feature with support for multiple clients including Claude Desktop, Cursor, and Cline.', '@domdomegg', 'ai-ml', 'Unknown', 146, 'https://github.com/domdomegg/computer-use-mcp', NULL, 0, 'https://github.com/domdomegg.png?size=128', '2026-03-09T05:21:01.954362+00:00'),
  ('defuddle-fetch', 'Defuddle Fetch', 'Fetches and processes web content with superior cleaning and extraction compared to Readability-based alternatives. Uses Defuddle to remove clutter while preserving page titles, metadata, and main content. Outputs clean markdown or HTML with support for pagination and rich metadata extraction including author, publication date, and word count.', '@domdomegg', 'ai-ml', 'Unknown', 6, 'https://github.com/domdomegg/defuddle-fetch-mcp-server', NULL, 0, 'https://github.com/domdomegg.png?size=128', '2026-03-09T05:21:01.954395+00:00'),
  ('downdetector', 'Downdetector', 'Enables querying Downdetector for real-time service outage data and status reports across multiple services and regions. Provides tools to check current status and outage reports for any service monitored by Downdetector, supporting multiple country domains including .com, .uk, .it, and .fr.', '@domdomegg', 'ai-ml', 'Unknown', 0, 'https://github.com/domdomegg/downdetector-mcp', NULL, 0, 'https://github.com/domdomegg.png?size=128', '2026-03-09T05:21:01.954421+00:00'),
  ('google-contacts', 'Google Contacts', 'Integrates with Google Contacts API to enable AI systems to list, search, and manage contact information. Supports OAuth authentication for secure access to personal Google Contacts data.', '@domdomegg', 'ai-ml', 'Unknown', 0, 'https://github.com/domdomegg/google-contacts-mcp', NULL, 0, 'https://github.com/domdomegg.png?size=128', '2026-03-09T05:21:01.954497+00:00'),
  ('google-drive', 'Google Drive', 'Provides comprehensive Google Drive integration enabling file and folder management through the Google Drive API. Built by Adam Jones, this TypeScript implementation supports OAuth authentication and offers tools for file operations including upload, download, copy, move, and delete, folder creation, comment workflows with replies and resolution, and granular permission control. Features Drive''s query syntax for advanced filtering, multipart uploads for binary files, and export capabilities for Google Workspace documents, making it valuable for automating document workflows and file organization operations.', '@domdomegg', 'development', 'Unknown', 2, 'https://github.com/domdomegg/google-drive-mcp', NULL, 0, 'https://github.com/domdomegg.png?size=128', '2026-03-09T05:21:01.954567+00:00'),
  ('google-maps-places', 'Google Maps Places', 'Integrates with Google Maps Places API to enable location search and photo retrieval. Provides tools for querying places by text search and fetching place photos. Uses an OAuth proxy architecture to authenticate with Google''s services without storing credentials or state.', '@domdomegg', 'search', 'Unknown', 0, 'https://github.com/domdomegg/google-maps-places-mcp', NULL, 0, 'https://github.com/domdomegg.png?size=128', '2026-03-09T05:21:01.954600+00:00'),
  ('google-sheets', 'Google Sheets', 'Integrates with Google Sheets API to enable comprehensive spreadsheet operations including creating and retrieving spreadsheet metadata, reading and writing cell values across ranges, appending data, clearing ranges, and managing sheets with listing, adding, and deleting capabilities for AI-driven data analysis and collaborative workflows.', '@domdomegg', 'ai-ml', 'Unknown', 2, 'https://github.com/domdomegg/google-sheets-mcp', NULL, 0, 'https://github.com/domdomegg.png?size=128', '2026-03-09T05:21:01.954630+00:00'),
  ('starling-bank', 'Starling Bank', 'Integrates with Starling Bank''s developer API for account management and transactions. Provides tools to view account information, check balances, and execute transactions through the UK digital bank''s API. Built as a third-party integration with emphasis on caution when using AI for financial operations.', '@domdomegg', 'development', 'Unknown', 1, 'https://github.com/domdomegg/starling-bank-mcp', NULL, 0, 'https://github.com/domdomegg.png?size=128', '2026-03-09T05:21:01.954648+00:00'),
  ('airbnb', 'Airbnb', 'MCP server for interacting with Airbnb''s search and listing details functionality. Built by Domoteek, it provides tools for searching vacation rentals with filters like location, dates, and guests, as well as retrieving detailed property information including amenities, policies, and pricing. The implementation handles robots.txt compliance, parses Airbnb''s HTML structure, and formats responses in a clean, consistent way - making it valuable for travel planning assistants and vacation rental analysis tools.', '@domoteek', 'ai-ml', 'Unknown', 1, 'https://github.com/domoteek/mcp-server-airbnb', NULL, 0, 'https://github.com/domoteek.png?size=128', '2026-03-09T05:21:01.954687+00:00'),
  ('mcp-db-utils', 'MCP DB Utils', 'MCP Database Utilities is a unified database access service that supports multiple database types (PostgreSQL, SQLite, and MySQL). Through its abstraction layer design, it provides a simple and unified database operation interface for MCP servers.', '@donghao1393', 'databases', 'Unknown', 87, 'https://github.com/donghao1393/mcp-dbutils', 'mcp-dbutils', 31134, 'https://github.com/donghao1393.png?size=128', '2026-03-09T05:21:01.954700+00:00'),
  ('uart-serial-communication', 'UART Serial Communication', 'Provides direct access to UART/serial communication interfaces for interacting with hardware devices, microcontrollers, and embedded systems. Built with Python using pyserial for robust serial communication, it offers configurable port connections with support for baud rate, data bits, parity, and stop bits settings. Features include port listing, data transmission in both ASCII and binary modes, and interactive terminal sessions with real-time data streaming. The implementation includes comprehensive error handling and connection state management, making it valuable for IoT development, hardware debugging, sensor data collection, and embedded system programming workflows.', '@donnel666', 'development', 'Unknown', 6, 'https://github.com/donnel666/uart-mcp', NULL, 0, 'https://github.com/donnel666.png?size=128', '2026-03-09T05:21:01.954754+00:00'),
  ('onetime-secret', 'OneTime Secret', 'Creates encrypted secrets with configurable expiration times and view limits that self-destruct after viewing, enabling secure one-time sharing of passwords, API keys, or sensitive information.', '@doobidoo', 'security', 'Unknown', 1, 'https://github.com/doobidoo/onetimesecret-mcp', NULL, 0, 'https://github.com/doobidoo.png?size=128', '2026-03-09T05:21:01.954801+00:00'),
  ('iacr-cryptology-eprint-archive', 'IACR Cryptology ePrint Archive', 'This MCP server, developed for the IACR Cryptology ePrint Archive, provides a bridge between AI models and cryptographic research papers. Built with TypeScript and leveraging libraries like axios, cheerio, and xml2js, it offers tools for parsing and retrieving information from the ePrint Archive. The implementation focuses on efficient data extraction and processing, making it accessible for AI assistants or applications needing to analyze or query cryptographic research. It''s particularly useful for tasks like literature reviews, trend analysis in cryptography, or staying updated with the latest cryptographic developments, enabling programmatic access to a vast repository of cryptographic knowledge without requiring deep understanding of web scraping or XML parsing.', '@doomdagadiggiedahdah', 'development', 'Unknown', 2, 'https://github.com/doomdagadiggiedahdah/iacr-mcp-server', NULL, 0, 'https://github.com/doomdagadiggiedahdah.png?size=128', '2026-03-09T05:21:01.954831+00:00'),
  ('claude-web-search', 'Claude Web Search', 'The Claude Web Search MCP server enables AI assistants to perform real-time web searches through Claude''s API. Built with TypeScript and the Model Context Protocol SDK, it provides a standardized interface for querying the web with support for domain filtering (allowed/blocked domains) and configurable result limits. The server automatically configures itself using Claude Desktop''s configuration file or environment variables, making it easy to integrate with existing Claude Desktop installations. This implementation is particularly valuable for use cases requiring up-to-date information beyond an AI''s training data, such as current events, recent developments, or fact verification.', '@doriandarko', 'development', 'Unknown', 50, 'https://github.com/doriandarko/claude-search-mcp', NULL, 0, 'https://github.com/doriandarko.png?size=128', '2026-03-09T05:21:01.954868+00:00'),
  ('sora', 'Sora', 'Provides complete integration with OpenAI''s Sora 2 video generation API through seven specialized tools for creating, remixing, monitoring, and managing videos. The server handles the full video lifecycle from initial generation with customizable parameters (duration, resolution, reference inputs) to status tracking, automatic downloading to local storage, and cleanup operations. Built with TypeScript and the MCP SDK, it supports both stdio transport for Claude Desktop integration and HTTP transport for broader compatibility, making it ideal for content creators, developers, and businesses looking to integrate AI video generation into their workflows with proper file management and API abstraction.', '@doriandarko', 'development', 'Unknown', 210, 'https://github.com/doriandarko/sora-mcp', NULL, 0, 'https://github.com/doriandarko.png?size=128', '2026-03-09T05:21:01.954900+00:00'),
  ('ethereum-address-monitor', 'Ethereum Address Monitor', 'MCP-0x provides real-time Ethereum address information across multiple blockchain networks. Built with Node.js using the FastMCP framework, it offers tools to fetch contract and address details while supporting Server-Sent Events (SSE) for live updates when blockchain data changes. The implementation includes a web demo interface, comprehensive testing scripts, and flexible deployment options through both HTTP and command-line interfaces. This server is particularly valuable for applications requiring continuous monitoring of on-chain activity without polling, making it ideal for DeFi dashboards, wallet applications, and blockchain analytics tools.', '@doronaviguy', 'development', 'Unknown', 0, 'https://github.com/doronaviguy/mpc-0x', NULL, 0, 'https://github.com/doronaviguy.png?size=128', '2026-03-09T05:21:01.954929+00:00'),
  ('jetbrains-ide-websocket-monitor', 'JetBrains IDE WebSocket Monitor', 'A fork of the JetBrains MCP Server that adds WebSocket monitoring capabilities, allowing real-time observation of all MCP tool calls between clients (like Claude Desktop) and JetBrains IDEs. Created by Daniel Ortega, this proxy sidecar maintains full compatibility with the original implementation while broadcasting detailed information about each endpoint call and its arguments through WebSocket on port 27042. It''s particularly useful for developers who need visibility into MCP interactions for debugging, monitoring, or extending IDE integration functionality.', '@dortegau', 'development', 'Unknown', 1, 'https://github.com/dortegau/mcp-proxy-sidecar', 'mcp-proxy-sidecar', 320, 'https://github.com/dortegau.png?size=128', '2026-03-09T05:21:01.954957+00:00'),
  ('domain-search', 'Domain Search', 'A comprehensive domain availability aggregator that checks domains across multiple registrars including Porkbun, Namecheap, and GoDaddy. Provides real-time pricing data, bulk domain searches, TLD metadata, smart domain suggestions, and social media username availability checking. Works out of the box with zero configuration using free RDAP and WHOIS protocols.', '@dorukardahan', 'ai-ml', 'Unknown', 14, 'https://github.com/dorukardahan/domain-search-mcp', NULL, 0, 'https://github.com/dorukardahan.png?size=128', '2026-03-09T05:21:01.954989+00:00'),
  ('twitterapi-io-docs', 'TwitterAPI.io Docs', 'Provides offline access to complete TwitterAPI.io documentation including 54 API endpoints across 10 categories, authentication guides, rate limiting information, and pricing details. Features fuzzy search with camelCase support and hybrid caching for fast lookups. TwitterAPI.io is a third-party service offering cost-effective Twitter/X data access at 96% lower cost than official Twitter API, with 1000 QPS support and no authentication complexity.', '@dorukardahan', 'ai-ml', 'Unknown', 1, 'https://github.com/dorukardahan/twitterapi-io-mcp', 'twitterapi-io-mcp', 1831, 'https://github.com/dorukardahan.png?size=128', '2026-03-09T05:21:01.955025+00:00'),
  ('voicevox', 'VOICEVOX', 'Voicevox-MCP-Server is a TypeScript implementation that connects AI assistants to the VOICEVOX text-to-speech engine. Developed by Dosugamea, this server uses the mcp-framework to expose VOICEVOX''s voice synthesis capabilities through a standardized interface. The implementation supports both default transport mechanisms and Server-Sent Events (SSE) for Windows platforms, with configurable speaker IDs and API endpoints through environment variables. It''s particularly valuable for applications requiring Japanese voice synthesis directly from AI assistant conversations, with Docker support for cross-platform deployment.', '@dosugamea', 'cloud', 'Unknown', 11, 'https://github.com/dosugamea/voicevox-mcp-server', NULL, 0, 'https://github.com/dosugamea.png?size=128', '2026-03-09T05:21:01.955047+00:00'),
  ('dot', 'Dot', 'Dot''s MCP integration enables AI assistants like Claude and ChatGPT to connect directly to your business data sources through secure connections while maintaining all existing permissions and setup. Users generate an MCP token through Dot''s interface and configure their AI client to query business data seamlessly, with support for Claude Desktop, Claude Web, Cursor IDE, ChatGPT Enterprise, and other MCP-compatible clients. The implementation respects all organizational data permissions and includes comprehensive security features like token expiration and audit logging.', '@unknown', 'databases', 'Unknown', 0, 'https://docs.getdot.ai/dot/integrations/mcp', NULL, 0, NULL, '2026-03-09T05:21:01.955060+00:00'),
  ('doubao-image-generation', 'Doubao Image Generation', 'Doubao Image MCP Server provides AI image generation capabilities through ByteDance''s Doubao API, built using the FastMCP framework and Volcengine Python SDK. The implementation exposes image generation tools that allow AI assistants to create images from text prompts, with support for various parameters like image dimensions and quality settings. Designed for content creators and developers who need programmatic access to Doubao''s image generation models, it enables workflows like automated visual content creation, design prototyping, and creative asset generation directly through conversational AI interfaces without requiring manual API integration.', '@suibin521', 'ai-ml', 'Unknown', 3, 'https://github.com/suibin521/doubao-image-mcp-server', 'doubao_image_mcp_server', 0, 'https://github.com/suibin521.png?size=128', '2026-03-09T05:21:01.955105+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('search1api', 'Search1API', 'Doubao Search MCP provides a bridge to Search1API, enabling Claude to perform web searches, crawl websites, extract sitemaps, fetch news articles, and run reasoning tasks through a standardized interface. Built with TypeScript and the Model Context Protocol SDK, it supports multiple search services with configurable parameters like result limits and content crawling depth. The implementation includes specialized tools for image search and a unique feature that integrates with Coze AI to generate search and browse plans, making it particularly valuable for complex research tasks requiring structured exploration of web content.', '@flow-product', 'development', 'Unknown', 1, 'https://github.com/flow-product/doubao-search-mcp', NULL, 0, 'https://github.com/flow-product.png?size=128', '2026-03-09T05:21:01.955135+00:00'),
  ('cyberchef', 'CyberChef', 'CyberChef-MCP converts the popular CyberChef web application into an MCP server, exposing over 300 cryptographic, encoding, compression, and data analysis operations as individual tools for AI agents. Built by doublegate using Node.js and the MCP SDK, it wraps CyberChef''s existing Node.js API to provide both atomic operations (like Base64 encoding or AES decryption) and a meta-tool for executing complex multi-step recipes. The Docker-based implementation includes patches for Node.js v22 compatibility and dynamically generates tool schemas from CyberChef''s operation configuration, making it valuable for cybersecurity analysis, data transformation workflows, and forensic investigations where AI agents need access to specialized encoding and cryptographic functions.', '@doublegate', 'cloud', 'Unknown', 2, 'https://github.com/doublegate/cyberchef-mcp', NULL, 0, 'https://github.com/doublegate.png?size=128', '2026-03-09T05:21:01.955160+00:00'),
  ('unsplash', 'Unsplash', 'Unsplash MCP Server provides a bridge between AI assistants and the Unsplash image search API, enabling image discovery directly within AI workflows. Built with Go using the mark3labs/mcp-go library, it exposes a search_photos tool that supports filtering by keywords, pagination, sorting, color, and orientation parameters. The server requires an Unsplash API access key and is designed for integration with Cursor editor, making it particularly useful for developers and content creators who need to find and incorporate high-quality images into their projects without leaving their AI-assisted environment.', '@douglarek', 'productivity', 'Unknown', 11, 'https://github.com/douglarek/unsplash-mcp-server', NULL, 0, 'https://github.com/douglarek.png?size=128', '2026-03-09T05:21:01.955202+00:00'),
  ('sonarcloud', 'SonarCloud', 'This MCP server provides SonarCloud API integration for fetching and analyzing code quality issues related to pull requests, enabling developers to retrieve detailed issue data with filtering by severity, type, assignee, and status. Built by dozzman using TypeScript with the MCP SDK and Docker support, it offers two core tools for fetching raw SonarCloud issues with extensive parameter support matching the full API specification, and generating high-level issue summaries with metrics like bug counts, vulnerability counts, technical debt, and top violated rules. The implementation features flexible authentication via API tokens, environment variable configuration for organization and project settings, and supports the special ''__me__'' assignee placeholder for filtering issues assigned to the current user, making it valuable for automated code review workflows, quality gate enforcement, and building AI assistants that need direct access to SonarCloud analysis results without manual platform interaction.', '@dozzman', 'cloud', 'Unknown', 4, 'https://github.com/dozzman/sonarcloud-mcp', NULL, 0, 'https://github.com/dozzman.png?size=128', '2026-03-09T05:21:01.955229+00:00'),
  ('djeb', 'dJEB', 'Provides direct access to JEB decompiler functionality for Android APK analysis through a Python-Jython bridge architecture. Exposes tools for decompiling methods and classes, listing and renaming code elements, analyzing cross-references, retrieving manifest and resource files with grep filtering, and performing batch operations on DEX bytecode structures. Built with a socket-based server running inside JEB and a bridge client for Claude Desktop integration, it enables reverse engineering workflows including malware analysis, vulnerability research, and Android application security assessment by allowing natural language queries against decompiled code, resource extraction, and automated refactoring operations.', '@dphoeniixx', 'development', 'Unknown', 11, 'https://github.com/dphoeniixx/djeb_mcp_server', NULL, 0, 'https://github.com/dphoeniixx.png?size=128', '2026-03-09T05:21:01.955274+00:00'),
  ('openstack-commander', 'OpenStack Commander', 'OpenStack MCP Server enables AI assistants to securely execute OpenStack CLI commands through a Spring Boot application. Built by DragomirAlin, it leverages Spring AI''s tool callback functionality to provide a bridge between Claude Desktop and OpenStack resources, allowing users to manage servers, projects, flavors, and images through natural language requests. The implementation handles authentication via application credentials, executes commands with proper environment variables, and includes diagnostics capabilities, making it particularly valuable for cloud administrators who want to interact with their OpenStack infrastructure directly through an AI assistant.', '@dragomiralin', 'productivity', 'Unknown', 19, 'https://github.com/dragomiralin/openstack-mcp-server', NULL, 0, 'https://github.com/dragomiralin.png?size=128', '2026-03-09T05:21:01.955319+00:00'),
  ('kospi-kosdaq-stock-data', 'KOSPI/KOSDAQ Stock Data', 'This MCP server provides real-time access to KOSPI and KOSDAQ stock market data. Developed by Sangrok Mun, it integrates with the pykrx library to offer tools for retrieving ticker symbols, OHLCV data, market capitalization, fundamental metrics, and trading volumes. The implementation is designed for financial analysts, traders, and researchers who need up-to-date South Korean stock market information. It stands out by offering a streamlined interface to complex financial data through simple MCP tools, making it particularly useful for AI assistants and automated trading systems that require quick access to Korean market insights.', '@dragon1086', 'ai-ml', 'Unknown', 63, 'https://github.com/dragon1086/kospi-kosdaq-stock-server', 'kospi-kosdaq-stock-server', 42528, 'https://github.com/dragon1086.png?size=128', '2026-03-09T05:21:01.955364+00:00'),
  ('mixpanel', 'Mixpanel', 'This MCP server implementation provides a bridge to the Mixpanel API, allowing users to query events data, retention, and funnels. Developed by Khoi Le, it uses TypeScript and Node.js to interface with Mixpanel''s analytics platform. The server is designed for use cases requiring on-demand access to Mixpanel data, such as analyzing user cohorts, tracking event trends, or generating custom analytics reports.', '@dragonkhoi', 'development', 'Unknown', 19, 'https://github.com/dragonkhoi/mixpanel-mcp', NULL, 0, 'https://github.com/dragonkhoi.png?size=128', '2026-03-09T05:21:01.955401+00:00'),
  ('ramp', 'Ramp', 'Ramp MCP provides a bridge to the Ramp API, allowing AI assistants to access and interact with Ramp credit card and spend management data. Built by Khoi Le, this TypeScript implementation requires a Ramp API key and client ID for authentication, and can be installed via Smithery or run locally. The server enables users to query their credit card transactions and other Ramp data directly within MCP clients like Cursor or Claude Desktop, making it useful for financial tracking and spend analysis workflows.', '@dragonkhoi', 'development', 'Unknown', 0, 'https://github.com/dragonkhoi/ramp-mcp', NULL, 0, 'https://github.com/dragonkhoi.png?size=128', '2026-03-09T05:21:01.955425+00:00'),
  ('undetected-chromedriver', 'Undetected ChromeDriver', 'MCP-Undetected-Chromedriver provides a server for browser automation that leverages undetected-chromedriver to bypass anti-bot measures on websites. Built with Python, it offers tools for navigation, screenshot capture, element interaction, and data extraction through a structured API. The implementation includes specialized functions for handling iframes, executing JavaScript, and managing browser sessions, making it particularly valuable for web scraping, automated testing, and data collection from sites with sophisticated bot detection mechanisms.', '@dragons96', 'development', 'Unknown', 10, 'https://github.com/dragons96/mcp-undetected-chromedriver', NULL, 0, 'https://github.com/dragons96.png?size=128', '2026-03-09T05:21:01.955451+00:00'),
  ('addtaskmanager', 'addTaskManager', 'MCP server that integrates with the addTaskManager iOS/macOS app through CloudKit, implementing the ADD (Assess-Decide-Do) framework created by Dragos Roua. The implementation enforces strict realm-based restrictions where tasks and projects can only be created/edited in the Assess realm, assigned contexts and due dates in the Decide realm, and marked complete in the Do realm. Built with production-ready CloudKit Web Services integration including Apple ID authentication, session management, and comprehensive security features, it provides AI assistants with structured access to personal productivity data while maintaining the cognitive load management principles of the ADD framework.', '@dragosroua', 'productivity', 'Unknown', 3, 'https://github.com/dragosroua/addtaskmanager-mcp-server', NULL, 0, 'https://github.com/dragosroua.png?size=128', '2026-03-09T05:21:01.955496+00:00'),
  ('code-mode', 'Code Mode', 'Provides sandboxed Python code execution capabilities where AI agents can write and execute Python scripts that orchestrate multiple MCP tool operations. Features a DSpy-powered reasoning system that generates code to accomplish tasks, with configurable sandbox options for network access, environment variables, and file system permissions. Includes policy enforcement for code safety with character and line limits, allowlisted imports, timeout handling, and a local HTTP bridge that allows sandboxed code to securely call external MCP tools.', '@hoangnb24', 'development', 'Unknown', 22, 'https://github.com/hoangnb24/mcp-code-mode', NULL, 0, 'https://github.com/hoangnb24.png?size=128', '2026-03-09T05:21:01.955521+00:00'),
  ('draup', 'Draup', 'Draup provides real-time workforce and labor market intelligence through MCP, enabling AI assistants to access live data on skills, roles, hiring trends, and market insights. The platform aggregates multidimensional data covering over 850 million professional profiles and more than a million companies, enriched with firmographics, tech stack telemetry, and funding events. Data is refreshed daily through streaming Change Data Capture, ensuring AI tools can reason on the latest labor market state.', '@unknown', 'development', 'Unknown', 0, 'https://draup.com/talent/data/model-context-protocol', NULL, 0, NULL, '2026-03-09T05:21:01.955544+00:00'),
  ('grafana', 'Grafana', 'The Grafana MCP Server provides AI assistants with direct access to Grafana''s monitoring and observability capabilities through a comprehensive set of tools for querying metrics, logs, and dashboard data. Built by DrDroidLab, it supports PromQL queries against Prometheus datasources, Loki log queries, dashboard panel execution with template variable support, and metadata retrieval for datasources, folders, and dashboards. The server optimizes time series data to reduce token usage, handles both HTTP and STDIO transports, and includes Docker deployment options with configurable authentication via API keys or environment variables, making it valuable for DevOps workflows, incident response, performance monitoring, and automated observability analysis where AI agents need real-time access to infrastructure metrics and logs.', '@drdroidlab', 'cloud', 'Unknown', 5, 'https://github.com/drdroidlab/grafana-mcp-server', NULL, 0, 'https://github.com/drdroidlab.png?size=128', '2026-03-09T05:21:01.955569+00:00'),
  ('signoz', 'SigNoz', 'This MCP server provides AI assistants with comprehensive access to SigNoz observability data through a Flask-based implementation built by Doctor Droid that supports both HTTP and STDIO transport modes. The implementation offers six core tools including connection testing, dashboard management (listing and fetching detailed panel data), custom metrics querying with PromQL support, and standardized APM metrics collection (request rate, error rate, latency) with hardcoded builder query templates that match SigNoz''s frontend behavior. Built with Docker containerization, configurable SSL verification, and intelligent timestamp handling that defaults to 3-hour lookbacks, it serves DevOps teams needing AI-powered observability analysis, SREs requiring automated dashboard data extraction and incident investigation, and organizations wanting to integrate SigNoz monitoring data into conversational workflows for performance analysis and troubleshooting.', '@drdroidlab', 'cloud', 'Unknown', 13, 'https://github.com/drdroidlab/signoz-mcp-server', NULL, 0, 'https://github.com/drdroidlab.png?size=128', '2026-03-09T05:21:01.955595+00:00'),
  ('dreamfactory', 'DreamFactory', 'DreamFactory MCP Server enables AI assistants like Claude to directly query your databases through DreamFactory''s auto-generated REST APIs. This Node.js server implements the Model Context Protocol (MCP), allowing natural language database interactions while maintaining enterprise-grade security. Connect multiple databases simultaneously, run complex queries using conversational language, and build AI-powered applications without writing custom integrations. Perfect for demos, prototypes, and production systems that need secure AI-to-database communication.', '@dreamfactorysoftware', 'databases', 'Unknown', 6, 'https://github.com/dreamfactorysoftware/df-mcp', NULL, 0, 'https://github.com/dreamfactorysoftware.png?size=128', '2026-03-09T05:21:01.955621+00:00'),
  ('code-graph-context', 'Code Graph Context', 'A highly customizable MCP server that analyzes TypeScript codebases to build rich code graphs. Provides deep contextual understanding of code structure and relationships, enabling language models to better comprehend and work with TypeScript projects.', '@drewdrewh', 'development', 'Unknown', 9, 'https://github.com/drewdrewh/code-graph-context', NULL, 0, 'https://github.com/drewdrewh.png?size=128', '2026-03-09T05:21:01.955643+00:00'),
  ('astro-docs', 'Astro Docs', 'The Astro Docs MCP server provides AI assistants with direct access to Astro documentation, enabling them to help users with Astro-related tasks. Built in TypeScript, it exposes documentation sections as resources with URIs, offers a search tool for finding relevant content, and includes curated prompts for common Astro questions. The server organizes documentation by categories like core concepts, configuration, and deployment, making it valuable for developers seeking assistance with Astro''s component-based architecture, content management features, or deployment options without leaving their AI assistant conversation.', '@dreyfus92', 'development', 'Unknown', 3, 'https://github.com/dreyfus92/astro-docs-mcp', NULL, 0, 'https://github.com/dreyfus92.png?size=128', '2026-03-09T05:21:01.955673+00:00'),
  ('linkedin-profile-scraper', 'LinkedIn Profile Scraper', 'This LinkedIn Profile Scraper leverages FastMCP and the RapidAPI LinkedIn Profile Scraper API to asynchronously retrieve LinkedIn profile data. Built by DrFranko0, it provides a simple tool for fetching comprehensive profile information including skills and other optional data points like certifications, publications, and honors. The implementation uses httpx for making API requests and structures the data retrieval process through a clean interface that can be integrated with Claude Desktop for AI-powered processing. Ideal for applications requiring LinkedIn data analysis without manual scraping, such as recruitment tools, networking applications, or professional data aggregation services.', '@drfranko0', 'ai-ml', 'Unknown', 0, 'https://github.com/drfranko0/mcp', NULL, 0, 'https://github.com/drfranko0.png?size=128', '2026-03-09T05:21:01.955721+00:00'),
  ('things3', 'Things3', 'This MCP server implementation provides integration with the Things3 task management app on macOS. It allows AI assistants to create and manage tasks and projects in Things3 through MCP tools, leveraging AppleScript for data retrieval and x-callback-url for item creation. The server includes specialized functionality for synchronizing projects between Agenda and Things3, making it particularly useful for users who work across both platforms. It enables AI assistants to perform actions like creating new projects, adding to-dos with detailed properties, and listing current tasks, enhancing productivity workflows within the Things3 ecosystem.', '@drjforrest', 'productivity', 'Unknown', 56, 'https://github.com/drjforrest/mcp-things3', NULL, 0, 'https://github.com/drjforrest.png?size=128', '2026-03-09T05:21:01.955762+00:00'),
  ('nexusdb', 'NexusDB', 'Provides comprehensive database management capabilities for NexusDB through an MCP server implementation. Offers tools covering the full spectrum of database operations including schema management (create/drop/modify tables, columns, indexes), data manipulation (CRUD operations with JSON support), query execution with pagination, table maintenance (pack, reindex, recover), and batch transactions. Features robust error handling, configurable connection settings, and specialized NexusDB functionality like table passwords, auto-increment values, and query plan analysis.', '@drpfau', 'databases', 'Unknown', 1, 'https://github.com/drpfau/nxmcp', NULL, 0, 'https://github.com/drpfau.png?size=128', '2026-03-09T05:21:01.955772+00:00'),
  ('productive', 'Productive', 'Provides read-only access to Productive.io project management data including projects, tasks, comments, pages, and team information. Supports searching across content, tracking task history with status and assignment timelines, and accessing activity feeds and checklist items. Built with FastMCP and offers flexible output formats including JSON and token-optimized streaming.', '@druellan', 'productivity', 'Unknown', 0, 'https://github.com/druellan/productive-simple-mcp', NULL, 0, 'https://github.com/druellan.png?size=128', '2026-03-09T05:21:01.955806+00:00'),
  ('drupal-best-practices', 'Drupal Best Practices', 'BestPractices MCP server provides AI assistants with access to curated coding standards, security guidelines, and best practices for Drupal development through a plugin-based architecture. Built by abderrahimghazali, the implementation loads standards from CSV files covering Drupal security, coding conventions, OWASP Top 10 vulnerabilities, accessibility requirements, and API design patterns, with support for full-text search, category filtering, and severity-based prioritization. The server uses an in-memory data store for fast queries and includes comprehensive standards like SQL injection prevention, proper access control implementation, and Drupal-specific best practices, making it valuable for developers who want conversational access to development guidelines during code reviews, security audits, or when learning proper Drupal development patterns.', '@abderrahimghazali', 'databases', 'Unknown', 2, 'https://github.com/abderrahimghazali/bestpractices_mcp', NULL, 0, 'https://github.com/abderrahimghazali.png?size=128', '2026-03-09T05:21:01.955819+00:00'),
  ('msty-studio-desktop-admin', 'Msty Studio Desktop Admin', 'Provides comprehensive administration and automation capabilities for Msty Studio Desktop, enabling database querying, health analysis, local model management, performance benchmarking, conversation analytics, and configuration backup/restore. Supports MLX, LLaMA.cpp, and GGUF models on Apple Silicon for power users managing local LLM workflows.', '@drvbss', 'databases', 'Unknown', 4, 'https://github.com/drvbss/msty-admin-mcp', NULL, 0, 'https://github.com/drvbss.png?size=128', '2026-03-09T05:21:01.955831+00:00'),
  ('reaper', 'Reaper', 'This Reaper MCP server, developed for integration with Claude Desktop, provides a bridge between AI assistants and Reaper digital audio workstation projects. Built with Python and leveraging the MCP protocol, it offers tools for finding and parsing Reaper project files. The implementation focuses on extracting structured data from complex audio projects, making it accessible for AI models to analyze track layouts, plugin chains, automation, and other project elements. It''s particularly useful for tasks like audio production assistance, project organization, or integrating music production workflows into AI-driven systems, enabling assistants to interact with Reaper projects without requiring deep knowledge of the underlying file format.', '@dschuler36', 'development', 'Unknown', 85, 'https://github.com/dschuler36/reaper-mcp-server', NULL, 0, 'https://github.com/dschuler36.png?size=128', '2026-03-09T05:21:01.955942+00:00'),
  ('garmin-connect', 'Garmin Connect', 'This MCP server implementation provides a bridge to the Garmin Connect API, allowing AI assistants to access and analyze personal fitness data. Developed by dshvadskiy, it offers tools for retrieving various health metrics including sleep data, steps, activities, heart rate, and more. The server is designed for use cases requiring detailed analysis of personal health and fitness information, such as tracking workout performance, monitoring sleep patterns, or analyzing long-term fitness trends.', '@dshvadskiy', 'ai-ml', 'Unknown', 8, 'https://github.com/dshvadskiy/garmin_mcp', NULL, 0, 'https://github.com/dshvadskiy.png?size=128', '2026-03-09T05:21:01.955984+00:00'),
  ('zapmail', 'Zapmail', 'Zapmail MCP server that provides natural language access to the complete Zapmail API for domain management, mailbox operations, and email automation workflows. Built with Node.js and featuring 46+ dynamically generated tools, it enables AI assistants to purchase domains with wallet-first logic, create and manage mailboxes in bulk, export to third-party platforms like Reachinbox and Instantly, and execute complex multi-step email campaigns through natural language commands. The implementation includes advanced features like caching, rate limiting, retry logic, and a rules-based planner that can orchestrate complex workflows such as domain purchasing, mailbox creation, and platform integration in a single request, making it ideal for sales teams and marketers managing large-scale cold email operations.', '@dsouzaalan', 'communication', 'Unknown', 1, 'https://github.com/dsouzaalan/zapmail-mcp', 'zapmail-mcp', 436, 'https://github.com/dsouzaalan.png?size=128', '2026-03-09T05:21:01.956020+00:00'),
  ('lanhu', 'Lanhu', 'Integrates with Lanhu, a Chinese product design collaboration platform used by design teams. Provides automated extraction of design specifications, requirements documents, and prototype data from Lanhu URLs through web scraping. Built with Python using Playwright and BeautifulSoup, includes cookie-based authentication for protected projects, Docker deployment support, and team collaboration features including message boards and Feishu notifications. Enables development teams to programmatically access Lanhu design documentation for code generation and project planning.', '@dsphper', 'cloud', 'Unknown', 571, 'https://github.com/dsphper/lanhu-mcp', NULL, 0, 'https://github.com/dsphper.png?size=128', '2026-03-09T05:21:01.956040+00:00'),
  ('steam-web-api', 'Steam Web API', 'A Model Context Protocol (MCP) server that provides Steam gaming context to AI assistants. This service integrates with the Steam API to fetch user gaming information and exposes it through the MCP protocol, allowing AI assistants to access and understand users'' gaming activities and preferences.', '@dsp', 'ai-ml', 'Unknown', 12, 'https://github.com/dsp/mcp-server-steam', NULL, 0, 'https://github.com/dsp.png?size=128', '2026-03-09T05:21:01.956074+00:00'),
  ('microsoft-sentinel', 'Microsoft Sentinel', 'The Microsoft Sentinel MCP Server provides security analysts with direct access to Microsoft Sentinel''s threat hunting and investigation capabilities through the Model Context Protocol. Built by Daniel Streefkerk, this Python implementation integrates with Azure services to enable KQL query execution, analytics rule management, incident investigation, and threat intelligence lookups. The server includes robust authentication handling, caching mechanisms, and error management while offering a comprehensive set of tools for security operations - from basic workspace information retrieval to advanced hunting queries and MITRE ATT&CK framework mappings. It''s designed for security professionals who need to leverage Sentinel''s capabilities within MCP-compatible environments like Claude.', '@dstreefkerk', 'cloud', 'Unknown', 15, 'https://github.com/dstreefkerk/ms-sentinel-mcp-server', NULL, 0, 'https://github.com/dstreefkerk.png?size=128', '2026-03-09T05:21:01.956097+00:00'),
  ('clickhouse-database', 'ClickHouse Database', 'ClickHouse MCP Server enables AI assistants to securely interact with ClickHouse databases through a controlled interface. Built by dubin555, it provides tools for listing tables, reading data, and executing SQL queries while implementing security checks to prevent dangerous operations like INSERT, UPDATE, or DELETE. The server connects to ClickHouse using environment variables or command-line arguments, exposes database schema as resources with detailed table and column descriptions, and returns query results in JSON format. This implementation is particularly valuable for data analysis workflows where users need to explore and query ClickHouse databases without risking data modification.', '@dubin555', 'databases', 'Unknown', 8, 'https://github.com/dubin555/clickhouse_mcp_server', NULL, 0, 'https://github.com/dubin555.png?size=128', '2026-03-09T05:21:01.956108+00:00'),
  ('end-of-life-api', 'End-of-Life API', 'This EOL MCP server, developed by the EOL MCP Server team, provides end-of-life status checks for software using the endoflife.date API. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers a standardized interface for querying software lifecycle information. The implementation focuses on simplicity and ease of use, with proper error handling and TypeScript type safety. It''s particularly useful for developers, system administrators, and AI assistants needing to assess software obsolescence risks, enabling use cases such as dependency management, security auditing, and upgrade planning without directly interacting with the endoflife.date API.', '@ducthinh993', 'development', 'Unknown', 7, 'https://github.com/ducthinh993/mcp-server-endoflife', NULL, 0, 'https://github.com/ducthinh993.png?size=128', '2026-03-09T05:21:01.956220+00:00'),
  ('waha-whatsapp-http-api', 'WAHA (WhatsApp HTTP API)', 'Integrates with WhatsApp through WAHA platform to enable complete messaging automation including sending and receiving media files, managing contacts and groups, handling QR code authentication, and controlling chat operations like archiving and reactions.', '@dudu1111685', 'development', 'Unknown', 4, 'https://github.com/dudu1111685/waha-mcp', NULL, 0, 'https://github.com/dudu1111685.png?size=128', '2026-03-09T05:21:01.956241+00:00'),
  ('instagram-analytics', 'Instagram Analytics', 'This Instagram server, developed for the Model Context Protocol, provides AI assistants with capabilities to interact with Instagram''s features and data. It integrates with Instagram''s API to enable functionalities like retrieving user profiles, posts, and engagement metrics. The server leverages Puppeteer and Playwright for web scraping capabilities, allowing it to access data not readily available through official APIs. By abstracting Instagram interactions, it enables AI systems to analyze social media trends, manage accounts, and gather insights from Instagram content. This implementation is particularly useful for social media managers, marketers, and researchers who want to leverage AI for Instagram analytics, content strategy, and audience engagement analysis.', '@duhlink', 'ai-ml', 'Unknown', 47, 'https://github.com/duhlink/instagram-server-next-mcp', NULL, 0, 'https://github.com/duhlink.png?size=128', '2026-03-09T05:21:01.956290+00:00'),
  ('dummyjson-user-management', 'DummyJSON User Management', 'A Model Context Protocol server implementation built with Spring Boot and Java 21 that provides user management tools for AI assistants. The server integrates with the DummyJSON external API to offer a range of user operations including retrieval, search, creation, updating, and deletion through a standardized MCP interface. It supports both Standard I/O and Server-Sent Events transports in synchronous communication mode, making it suitable for integration with various AI clients that need to perform user management operations.', '@mtwn105', 'ai-ml', 'Unknown', 6, 'https://github.com/mtwn105/mcp-server-spring-java', NULL, 0, 'https://github.com/mtwn105.png?size=128', '2026-03-09T05:21:01.956331+00:00'),
  ('dumpling-ai', 'Dumpling AI', 'This MCP server for Dumpling AI provides a bridge to Dumpling''s data extraction and processing API, enabling AI assistants to perform web searches, scrape content, extract structured data, and process various document formats. Built with TypeScript and the MCP SDK, it offers over 20 specialized tools including Google search, YouTube transcript extraction, document conversion, and AI image generation. The implementation handles authentication through API keys and formats all responses as structured JSON, making it particularly useful for research tasks, content analysis, and accessing real-time web information without direct internet access.', '@dumplingai', 'development', 'Unknown', 29, 'https://github.com/dumplingai/mcp-server-dumplingai', 'mcp-server-dumplingai', 5516, 'https://github.com/dumplingai.png?size=128', '2026-03-09T05:21:01.956360+00:00'),
  ('dune-analytics', 'Dune Analytics', 'MCP Web3 Stats Server provides blockchain data analysis capabilities through the Dune API, allowing LLM agents to access and interpret on-chain information. Developed by Dennison Bertram, it offers tools for examining EVM and Solana wallet balances, transaction histories, token information, NFT collectibles, and token holder distributions. Built with TypeScript and Bun, the server implements a standardized interface that can be integrated with Claude Desktop and other MCP clients, making it particularly valuable for users who need to analyze wallet activities, research specific tokens, or track blockchain transactions through natural language interactions.', '@crazyrabbitltc', 'development', 'Unknown', 4, 'https://github.com/crazyrabbitltc/mcp-web3-stats', 'mcp-web3-stats', 469, 'https://github.com/crazyrabbitltc.png?size=128', '2026-03-09T05:21:01.956393+00:00'),
  ('genesis-world', 'Genesis World', 'Genesis MCP Server provides a bridge between AI assistants and Genesis World simulations, enabling execution of simulation code with customizable parameters. Built with FastMCP, it exposes resources for retrieving world information, tools for running simulations, and prompts for generating simulation templates. The server is containerized with Docker for easy deployment and includes an MCP Inspector for debugging. This implementation is particularly valuable for workflows requiring agent-based simulations, virtual world creation, and analysis of emergent behaviors without leaving the conversation interface.', '@dustland', 'cloud', 'Unknown', 4, 'https://github.com/dustland/genesis-mcp', NULL, 0, 'https://github.com/dustland.png?size=128', '2026-03-09T05:21:01.956436+00:00'),
  ('github-stars', 'GitHub Stars', 'This MCP server provides GitHub stars analysis and timeline tracking capabilities through the GitHub GraphQL API, enabling AI assistants to retrieve user starred repositories, analyze starring patterns over time, and extract technology adoption insights. Built using FastMCP 2.2.0+ with Python 3.11+, it offers tools for fetching starred repositories with pagination support, timeline analysis with monthly activity breakdowns, language distribution analysis, and repository ranking by popularity. The implementation features async/await patterns for performance, TTL caching for API response optimization, structured logging with structlog, robust error handling for GitHub API rate limits and authentication failures, and comprehensive data models using Pydantic for validation, making it valuable for developer research workflows, technology trend analysis, and building AI assistants that need programmatic access to GitHub starring behavior without manual repository browsing.', '@dustyposa', 'development', 'Unknown', 2, 'https://github.com/dustyposa/github-stars-mcp-server', NULL, 0, 'https://github.com/dustyposa.png?size=128', '2026-03-09T05:21:01.956465+00:00'),
  ('eu-ansvar-dutch-law-mcp', 'eu.ansvar/dutch-law-mcp', 'Query Dutch statutes, 202K+ court decisions, EU cross-references, and kamerstukken', '@ansvar-systems', 'development', 'Unknown', 2, 'https://github.com/ansvar-systems/dutch-law-mcp', NULL, 0, 'https://github.com/ansvar-systems.png?size=128', '2026-03-09T05:21:01.956502+00:00'),
  ('duyet-professional-profile', 'Duyet Professional Profile', 'This MCP server provides AI assistants with access to Duyet''s professional information and contact capabilities. Built as a Cloudflare Worker using Hono and the MCP SDK, it offers tools for retrieving Duyet''s CV, recent GitHub activity, latest blog posts from blog.duyet.net, and enables direct messaging for collaboration, job opportunities, or consulting inquiries. The server integrates with Cloudflare D1 for contact storage and includes analytics capabilities, making it useful for AI assistants to naturally discover and present Duyet''s work while facilitating professional connections.', '@duyet', 'cloud', 'Unknown', 2, 'https://github.com/duyet/duyet-mcp-server', NULL, 0, 'https://github.com/duyet.png?size=128', '2026-03-09T05:21:01.956522+00:00'),
  ('siri-shortcuts', 'Siri Shortcuts', 'This MCP server provides access to Siri shortcuts functionality on macOS, allowing AI assistants to list, open, and run shortcuts from the Shortcuts app. It dynamically generates tools for each available shortcut, exposing all shortcuts to the LLM for flexible automation. The server uses the macOS ''shortcuts'' CLI command under the hood and supports both direct text input and file-based input for shortcut execution.', '@dvcrn', 'ai-ml', 'Unknown', 182, 'https://github.com/dvcrn/mcp-server-siri-shortcuts', 'mcp-server-siri-shortcuts', 5615, 'https://github.com/dvcrn.png?size=128', '2026-03-09T05:21:01.956556+00:00'),
  ('amazon-bedrock-nova', 'Amazon Bedrock Nova', 'This MCP server, developed by georgx22, integrates Amazon Bedrock''s Nova Canvas and Nova Reel models to create images and videos. Built with Python and running over SSE, it offers a streamlined interface for AI-powered media generation. The implementation focuses on simplicity and AWS integration, with features like S3 storage and environment variable configuration. It''s particularly useful for developers and content creators looking to leverage advanced AI models for media production, enabling use cases such as automated video creation, image generation for marketing, or AI-assisted visual content development without directly dealing with the complexities of Amazon Bedrock APIs.', '@dvejsada', 'cloud', 'Unknown', 4, 'https://github.com/dvejsada/mcp_media_generator', NULL, 0, 'https://github.com/dvejsada.png?size=128', '2026-03-09T05:21:01.956577+00:00'),
  ('delve', 'Delve', 'Delve MCP server provides a complete interface to the Delve debugger for Go programs through the Model Context Protocol. It implements all major debugging capabilities including starting debug sessions, setting breakpoints, controlling execution flow, and inspecting program state. The server exposes Delve''s functionality as discoverable tools that can be executed by AI assistants, supporting various debug modes (debug, attach, exec, test), core dump analysis, and program tracing. Built with TypeScript using the MCP SDK, it requires Go with Delve installed and optionally Mozilla rr for replay debugging.', '@dwisiswant0', 'development', 'Unknown', 21, 'https://github.com/dwisiswant0/delve-mcp', NULL, 0, 'https://github.com/dwisiswant0.png?size=128', '2026-03-09T05:21:01.956650+00:00'),
  ('terminal-session', 'Terminal Session', 'This MCP server, developed by dwrtz, provides stateful, TUI-compatible terminal sessions for AI assistants. Built with Go and leveraging the mcp-go library, it offers two main tools: ''run'' for executing commands in persistent bash sessions, and ''runScreen'' for interactive TUI applications. The implementation focuses on maintaining session state, handling control sequences, and supporting multi-line outputs. It''s particularly useful for AI systems that need to interact with command-line interfaces, enabling use cases such as file system navigation, text editing in vim, or running interactive programs like Python REPL without losing context between commands.', '@dwrtz', 'ai-ml', 'Unknown', 14, 'https://github.com/dwrtz/mcpterm', NULL, 0, 'https://github.com/dwrtz.png?size=128', '2026-03-09T05:21:01.956697+00:00'),
  ('magic-api', 'Magic-API', 'Magic-API MCP Server provides control over Magic-API development environments through 10 specialized tool modules. Built by Dwsy, it integrates with Magic-API''s REST endpoints and WebSocket debugging interface to offer CRUD operations on API resources, advanced debugging with breakpoints and step execution, documentation access, backup/restore functionality, Java class introspection, and content search across API scripts. The modular architecture supports flexible tool combinations for different deployment scenarios, uses Docker for easy deployment, and provides rich knowledge base integration with Magic-API''s syntax, functions, and best practices for developers building and maintaining Magic-API projects.', '@dwsy', 'cloud', 'Unknown', 22, 'https://github.com/dwsy/magic-api-mcp-server', 'magic-api-mcp-server', 4382, 'https://github.com/dwsy.png?size=128', '2026-03-09T05:21:01.956721+00:00'),
  ('jira-linear', 'Jira & Linear', 'MCP DevTools provides integration with popular issue tracking systems like Jira and Linear, enabling AI assistants to retrieve and interact with tickets directly within conversations. Developed by DX Heroes, this TypeScript-based implementation uses a modular architecture with core components for HTTP client functionality and shared TypeScript configurations. The packages are published to npm and follow conventional commits for versioning, making it easy to incorporate ticket management capabilities into AI workflows that require access to project management data without context switching.', '@dxheroes', 'development', 'Unknown', 13, 'https://github.com/dxheroes/mcp-devtools', '@mcp-devtools/jira', 9284, 'https://github.com/dxheroes.png?size=128', '2026-03-09T05:21:01.956751+00:00'),
  ('background-job', 'Background Job', 'MCP server implementation by Dylan Navajas Gluck that enables asynchronous execution and management of long-running shell commands with full process lifecycle control. Built with Python 3.12+ and FastMCP, the implementation provides seven core tools for background job management: execute commands and get job IDs, monitor status and output with real-time tailing, send input to interactive processes via stdin, and terminate running jobs with graceful cleanup. Features ring-buffered output capture with configurable size limits, concurrent job management with resource constraints, security validation against dangerous command patterns, and comprehensive process monitoring including PID tracking and exit code handling. Designed for development workflows involving build processes, test suites, development servers, or any scenario where AI assistants need to start long-running operations and monitor their progress without blocking on command completion.', '@dylan-gluck', 'development', 'Unknown', 10, 'https://github.com/dylan-gluck/mcp-background-job', 'mcp-background-job', 4602, 'https://github.com/dylan-gluck.png?size=128', '2026-03-09T05:21:01.956782+00:00'),
  ('nhl-stats', 'NHL Stats', 'NHL API server that provides a comprehensive bridge to official NHL web and stats APIs, enabling retrieval of real-time sports data including team standings, player statistics, game schedules, and roster information. Built with TypeScript and the MCP SDK, it offers a flexible, multi-endpoint approach to fetching NHL data with robust error handling and fallback mechanisms for API reliability.', '@dylangroos', 'development', 'Unknown', 4, 'https://github.com/dylangroos/nhl-mcp', NULL, 0, 'https://github.com/dylangroos.png?size=128', '2026-03-09T05:21:01.956808+00:00'),
  ('patchright-stealth-browser', 'Patchright Stealth Browser', 'The Patchright Lite MCP Server provides AI models with stealth browser automation capabilities through a streamlined interface. Built by Dylan Groos, it wraps the Patchright Node.js SDK (an undetected version of Playwright) to avoid anti-bot detection systems while offering four essential tools: browse for navigating to websites, interact for performing actions on web elements, extract for retrieving page content, and close for managing browser instances. The server uses the stdio transport for seamless integration with AI tools and is containerized for easy deployment, making it particularly valuable for AI assistants that need to perform web automation tasks without being detected by anti-bot systems.', '@dylangroos', 'productivity', 'Unknown', 14, 'https://github.com/dylangroos/patchright-mcp-lite', NULL, 0, 'https://github.com/dylangroos.png?size=128', '2026-03-09T05:21:01.956865+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('autogen', 'AutoGen', 'AutoGen MCP Server provides a bridge between the Model Context Protocol and Microsoft''s AutoGen framework, enabling AI assistants to create and manage autonomous agents that can execute code, perform research, and collaborate in multi-agent conversations. Built with TypeScript and Python, this implementation exposes AutoGen''s powerful agent capabilities through standardized tools for creating agents, executing one-on-one chats, running group conversations, and executing predefined workflows like code generation and research tasks. The server handles configuration management, agent lifecycle, and conversation orchestration, making it ideal for developers building complex AI systems that require autonomous problem-solving and multi-agent collaboration.', '@dynamicendpoints', 'development', 'Unknown', 16, 'https://github.com/dynamicendpoints/autogen_mcp', NULL, 0, 'https://github.com/dynamicendpoints.png?size=128', '2026-03-09T05:21:01.956940+00:00'),
  ('bod-25-01-cisa-microsoft-policies', 'BOD 25-01 CISA Microsoft Policies', 'This MCP server, developed by DynamicEndpoints, implements CISA Binding Operational Directive 25-01 security controls for Microsoft 365. It integrates with Microsoft Graph API to enforce and manage security settings, including legacy authentication controls, risk-based access management, multi-factor authentication, application controls, password policies, and privileged role management. The server provides a standardized interface for AI assistants to configure and monitor M365 security settings, abstracting the complexities of Graph API interactions. It is particularly useful for government agencies, security teams, and IT administrators who need to ensure compliance with CISA directives, automate security policy enforcement, and maintain a robust security posture in their M365 environment.', '@dynamicendpoints', 'ai-ml', 'Unknown', 5, 'https://github.com/dynamicendpoints/automated-bod-25-01-cisa-microsoft-policies-mcp', NULL, 0, 'https://github.com/dynamicendpoints.png?size=128', '2026-03-09T05:21:01.956994+00:00'),
  ('cloudflare-backup', 'Cloudflare Backup', 'This Cloudflare to GitHub Backup MCP server, developed by an unnamed author, provides an automated solution for backing up Cloudflare project configurations to GitHub repositories. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers comprehensive backup capabilities for DNS records, Page Rules, Workers, Custom Pages, SSL/TLS settings, Firewall Rules, Access Rules, and Rate Limiting Rules. The server implements error handling, GitHub repository management, and file versioning. By abstracting the complexities of both Cloudflare and GitHub APIs, it enables AI systems to easily manage and version control Cloudflare configurations. This implementation is particularly valuable for DevOps and system administration tasks, facilitating use cases such as disaster recovery, configuration auditing, and multi-environment synchronization.', '@dynamicendpoints', 'cloud', 'Unknown', 0, 'https://github.com/dynamicendpoints/cloudflare-github-backup-mcp', NULL, 0, 'https://github.com/dynamicendpoints.png?size=128', '2026-03-09T05:21:01.957018+00:00'),
  ('huntress', 'Huntress', 'This Huntress API MCP server, developed by the Huntress MCP Server Contributors, enables AI assistants to interact programmatically with Huntress endpoint protection services. It provides tools for account and organization management, agent monitoring, incident report access, and billing information retrieval. The server implements rate limiting and error handling to ensure reliable API interactions. By connecting AI capabilities with Huntress functionality, this implementation empowers assistants to manage cybersecurity operations, analyze threat data, and automate reporting tasks. It is particularly useful for applications requiring real-time security monitoring, incident response coordination, or any scenario where an AI system needs to access and reason about endpoint protection data from Huntress.', '@dynamicendpoints', 'productivity', 'Unknown', 1, 'https://github.com/dynamicendpoints/huntress-mcp-server', NULL, 0, 'https://github.com/dynamicendpoints.png?size=128', '2026-03-09T05:21:01.957065+00:00'),
  ('netlify', 'Netlify', 'This MCP server implementation provides comprehensive tools for working with Netlify through their CLI. Developed by DynamicEndpoints, it enables deploying sites, managing deployments, handling environment variables, DNS settings, serverless functions, forms, plugins, and webhooks. Built using TypeScript and integrating the Model Context Protocol SDK, the server focuses on secure API key management and robust error handling. It offers type-safe parameter validation using Zod and is designed for easy setup within various MCP environments. The implementation is particularly useful for AI applications that need to automate web deployment tasks, manage serverless architectures, or integrate continuous deployment workflows with Netlify''s platform.', '@dynamicendpoints', 'cloud', 'Unknown', 6, 'https://github.com/dynamicendpoints/netlify-mcp-server', NULL, 0, 'https://github.com/dynamicendpoints.png?size=128', '2026-03-09T05:21:01.957086+00:00'),
  ('pocketbase', 'PocketBase', 'This PocketBase MCP server provides a robust interface for AI assistants to interact with PocketBase databases. Built using TypeScript and the PocketBase JavaScript SDK, it offers advanced capabilities for collection management, record operations, user authentication, and database administration. The server abstracts complex PocketBase operations, enabling seamless schema migrations, advanced querying with aggregations, and batch data import/export. It''s particularly valuable for developers building AI-powered applications that require flexible, real-time database operations. This implementation excels in scenarios requiring dynamic schema management, sophisticated data querying, and scalable user authentication, making it ideal for rapidly evolving projects in fields like content management, user analytics, and collaborative data platforms.', '@dynamicendpoints', 'databases', 'Unknown', 69, 'https://github.com/dynamicendpoints/advanced-pocketbase-mcp-server', NULL, 0, 'https://github.com/dynamicendpoints.png?size=128', '2026-03-09T05:21:01.957120+00:00'),
  ('io-github-getdynamoi-dynamoi', 'io.github.getDynamoi/dynamoi', 'Promote music on Spotify and grow YouTube channels through AI-powered Meta and Google ad campaigns.', '@getdynamoi', 'development', 'Unknown', 1, 'https://github.com/getdynamoi/mcp', NULL, 0, 'https://github.com/getdynamoi.png?size=128', '2026-03-09T05:21:01.957149+00:00'),
  ('dynatrace-managed', 'Dynatrace Managed', 'Enables AI assistants to interact with self-hosted Dynatrace Managed environments, providing access to observability data including problems, security vulnerabilities, entities, SLOs, events, logs, and metrics. Designed for organizations running Dynatrace Managed rather than SaaS, using V2 REST APIs for data queries. Supports both local (stdio) and remote (HTTP/SSE) deployment modes.', '@dynatrace-oss', 'ai-ml', 'Unknown', 16, 'https://github.com/dynatrace-oss/dynatrace-managed-mcp', NULL, 0, 'https://github.com/dynatrace-oss.png?size=128', '2026-03-09T05:21:01.957184+00:00'),
  ('dynatrace', 'Dynatrace', 'The Dynatrace MCP server enables real-time observability data access from the Dynatrace platform directly in development workflows. Built by Dynatrace OSS, it provides capabilities for monitoring problems, security vulnerabilities, logs, and metrics through a set of specialized tools that interact with various Dynatrace APIs. The server supports executing DQL queries, sending Slack notifications, creating workflows for problem notifications, and retrieving ownership information for monitored entities. This integration is particularly valuable for developers who need production-level telemetry for early issue detection, security vulnerability assessment, and automated incident response without leaving their IDE.', '@dynatrace-oss', 'development', 'Unknown', 84, 'https://github.com/dynatrace-oss/dynatrace-mcp', '@dynatrace-oss/dynatrace-mcp-server', 286940, 'https://github.com/dynatrace-oss.png?size=128', '2026-03-09T05:21:01.957214+00:00'),
  ('mysql-database-query', 'MySQL Database Query', 'AI-MCP-Server is a Spring Boot application that provides a Model Context Protocol server specifically designed for MySQL query operations. Built using Spring AI (version 1.0.0-M6), it leverages the spring-ai-mcp-server-webmvc-spring-boot-starter to expose MySQL querying capabilities to AI assistants. The server is configured with minimal setup requirements through application.yml, where it''s named ''mysqlQuery-mcp-server'' and can be enabled or disabled as needed. This implementation allows AI assistants to execute and retrieve data from MySQL databases through a standardized protocol interface, making it particularly useful for data analysis and database management tasks without requiring direct database access.', '@dzplus', 'databases', 'Unknown', 1, 'https://github.com/dzplus/ai-mcp-server', NULL, 0, 'https://github.com/dzplus.png?size=128', '2026-03-09T05:21:01.957226+00:00'),
  ('e18e', 'e18e', 'Advises agents on modern and performant JavaScript package alternatives', '@e18e', 'development', 'Unknown', 11, 'https://github.com/e18e/mcp', NULL, 0, 'https://github.com/e18e.png?size=128', '2026-03-09T05:21:01.957258+00:00'),
  ('e2b-ts', 'E2B (TS)', 'This MCP server, developed by e2b-dev, enables AI assistants like Claude to execute code using E2B''s cloud infrastructure. It provides a bridge between natural language interactions and actual code execution, allowing AI models to run and test code snippets in real-time. The server leverages E2B''s secure sandboxed environments to execute code in various languages, with current support for JavaScript and Python. By integrating AI capabilities with E2B''s code execution platform, this implementation enhances the ability of AI assistants to debug, prototype, and demonstrate code concepts. It is particularly useful for scenarios requiring interactive coding sessions, automated testing, or hands-on programming tutorials guided by AI.', '@e2b-dev', 'development', 'Unknown', 382, 'https://github.com/e2b-dev/mcp-server/tree/HEAD/packages/js', NULL, 0, 'https://github.com/e2b-dev.png?size=128', '2026-03-09T05:21:01.957283+00:00'),
  ('e2b-python', 'E2B (Python)', 'This MCP server, developed by E2B, enables AI assistants like Claude to execute code securely in E2B''s cloud infrastructure. It bridges natural language interactions with real-time code execution in sandboxed environments, currently supporting JavaScript and Python. The server integrates with Claude Desktop and can run standalone, providing flexibility for different use cases. By combining AI capabilities with E2B''s code execution platform, this implementation enhances AI assistants'' ability to debug, prototype, and demonstrate coding concepts interactively. It is particularly valuable for scenarios requiring hands-on programming tutorials, automated testing, or interactive coding sessions guided by AI, allowing for more dynamic and practical coding assistance.', '@e2b-dev', 'development', 'Unknown', 382, 'https://github.com/e2b-dev/mcp-server/tree/HEAD/packages/python', NULL, 0, 'https://github.com/e2b-dev.png?size=128', '2026-03-09T05:21:01.957309+00:00'),
  ('ean-search', 'EAN-Search', 'Provides access to the EAN-Search.org product database containing over 1 billion products. Supports barcode lookups including EAN, UPC, GTIN, and ISBN codes, as well as keyword-based product searches. Available as both a local stdio server and a remote streamable HTTP endpoint.', '@eansearch', 'databases', 'Unknown', 2, 'https://github.com/eansearch/eansearch-mcp-server', NULL, 0, 'https://github.com/eansearch.png?size=128', '2026-03-09T05:21:01.957319+00:00'),
  ('earningsfeed', 'EarningsFeed', 'Provides real-time access to SEC filings data through EarningsFeed''s API. Supports retrieval of 10-K annual reports, 10-Q quarterly reports, 8-K current reports, Form 4 insider trading disclosures, and company lookup functionality. Filings appear within seconds of SEC acceptance with no delays.', '@unknown', 'finance', 'Unknown', 0, 'https://earningsfeed.com/mcp', NULL, 0, NULL, '2026-03-09T05:21:01.957358+00:00'),
  ('metabase', 'Metabase', 'MCP server for Metabase integration developed by EaseCloud Technologies that provides AI assistants with comprehensive access to Metabase business intelligence operations through both API key and username/password authentication. The implementation offers complete dashboard management (create, update, delete, execute), question/card operations with query execution, database connectivity with SQL query capabilities, plus user management, collections, and permission controls through a unified tool registry system. Built with TypeScript and featuring Docker deployment options, resource templates for programmatic access, and extensive error handling, it serves teams using Metabase for analytics who want AI assistants to automate report generation, execute ad-hoc queries, manage dashboard configurations, and perform administrative tasks across their business intelligence workflows.', '@easecloudio', 'databases', 'Unknown', 50, 'https://github.com/easecloudio/mcp-metabase-server', '@easecloudio/mcp-metabase-server', 6818, 'https://github.com/easecloudio.png?size=128', '2026-03-09T05:21:01.957368+00:00'),
  ('aem', 'AEM', 'Provides tools for interacting with Adobe Experience Manager (AEM) instances, supporting both AEMaaCS (cloud) and self-hosted deployments. Enables content management, component operations, asset handling, advanced search via QueryBuilder, replication, rollout, text and image extraction from pages, and JCR node access through REST and JSON-RPC APIs.', '@easingthemes', 'development', 'Unknown', 0, 'https://github.com/easingthemes/aem-mcp-server', NULL, 0, 'https://github.com/easingthemes.png?size=128', '2026-03-09T05:21:01.957388+00:00'),
  ('easy-autocad', 'Easy AutoCAD', 'Easy-MCP-AutoCad is a Python-based server for integrating AutoCAD with the Model Context Protocol, enabling programmatic interaction with AutoCAD through libraries like pyautocad and comtypes. The implementation supports database management via SQLAlchemy and provides a flexible framework for automating CAD-related tasks, with deployment capabilities through PyInstaller.', '@zh19980811', 'databases', 'Unknown', 119, 'https://github.com/zh19980811/easy-mcp-autocad', NULL, 0, 'https://github.com/zh19980811.png?size=128', '2026-03-09T05:21:01.957399+00:00'),
  ('mac-letterhead', 'Mac Letterhead', 'Transforms letterhead templates into drag-and-drop applications that automatically apply branding to PDF and Markdown documents. Supports intelligent margin detection within letterhead designs, multiple blending strategies for PDF overlay, and comprehensive Markdown rendering with tables, code blocks, and syntax highlighting.', '@easytocloud', 'development', 'Unknown', 0, 'https://github.com/easytocloud/mac-letterhead', NULL, 0, 'https://github.com/easytocloud.png?size=128', '2026-03-09T05:21:01.957423+00:00'),
  ('echo3d', 'echo3D', 'The Echo3D MCP Server bridges AI assistants with the Echo3D augmented reality platform through a comprehensive Model Context Protocol implementation. This server enables programmatic access to Echo3D''s suite of AR/3D tools and resources, allowing AI assistants to manage 3D assets, query project data, and automate AR content workflows. The implementation features robust authentication using API keys, user credentials, and project security keys to ensure secure access to sensitive AR projects and assets.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('massive-context', 'Massive Context', 'Processes extremely large text contexts (10M+ tokens) using the Recursive Language Model pattern. Strategically chunks content, runs sub-queries on individual chunks, and aggregates results for final synthesis. Supports local inference via Ollama and cloud fallback via Claude SDK, with tools for auto-analysis, context loading, batch sub-queries, and sandboxed Python code execution against loaded context.', '@egoughnour', 'development', 'Unknown', 0, 'https://github.com/egoughnour/massive-context-mcp', NULL, 0, 'https://github.com/egoughnour.png?size=128', '2026-03-09T05:21:01.958575+00:00'),
  ('codecov', 'Codecov', 'Integrates with Codecov to retrieve code coverage metrics. Supports querying repository-level coverage statistics, commit-specific coverage data, and line-by-line file coverage. Works with both codecov.io and self-hosted Codecov instances through configurable base URLs.', '@egulatee', 'development', 'Unknown', 1, 'https://github.com/egulatee/mcp-server-codecov', NULL, 0, 'https://github.com/egulatee.png?size=128', '2026-03-09T05:21:01.958595+00:00'),
  ('spire-xls', 'Spire.XLS', 'This MCP server provides Excel file manipulation through the Spire.XLS library, enabling AI assistants to create, read, modify, and convert Excel workbooks without requiring Microsoft Office installation. Built by E-iceblue using Python with comprehensive Excel operations including data reading/writing, formula application, chart creation, pivot table generation, cell formatting with conditional formatting support, worksheet management, and file conversion to multiple formats (PDF, HTML, CSV, images, XML). The implementation features intelligent header detection for data imports, extensive styling capabilities with fonts/colors/borders, autofilter functionality, JSON import/export, and shape image extraction, making it valuable for data analysis workflows, report generation, dashboard creation, and any automation requiring robust Excel file processing with high-fidelity format conversion capabilities.', '@eiceblue', 'ai-ml', 'Unknown', 6, 'https://github.com/eiceblue/spire-xls-mcp-server', NULL, 0, 'https://github.com/eiceblue.png?size=128', '2026-03-09T05:21:01.958651+00:00'),
  ('nucleus', 'Nucleus', 'Nucleus provides a shared memory system that synchronizes context across multiple AI development tools such as Cursor, Claude Desktop, and Windsurf. It stores persistent knowledge as ''engrams'' in a local .brain/ folder, enabling seamless context continuity when switching between tools. Features include multi-agent synchronization with conflict detection, state and artifact tracking, and security-first hypervisor controls with audit trails. All data remains local with no cloud dependencies.', '@eidetic-works', 'development', 'Unknown', 1, 'https://github.com/eidetic-works/nucleus-mcp', NULL, 0, 'https://github.com/eidetic-works.png?size=128', '2026-03-09T05:21:01.958674+00:00'),
  ('aider-multi-coder', 'Aider Multi-Coder', 'Aider MCP Server provides a bridge between AI assistants and the Aider pair programming tool, enabling parallel execution of multiple coding tasks. Built with Python using the FastMCP framework, it exposes two main tools: code_with_ai for single coding tasks and code_with_multiple_ai for running multiple tasks simultaneously with configurable parallelism. The server manages file access permissions through editable and read-only file lists, supports various AI models through environment variables, and includes comprehensive error handling and performance metrics. It''s particularly valuable for developers who need to accelerate complex coding projects by distributing independent tasks across multiple AI agents without managing the underlying complexities of the Aider CLI tool.', '@eiliyaabedini', 'development', 'Unknown', 10, 'https://github.com/eiliyaabedini/aider-mcp', NULL, 0, 'https://github.com/eiliyaabedini.png?size=128', '2026-03-09T05:21:01.958703+00:00'),
  ('sleeper-fantasy-football', 'Sleeper Fantasy Football', 'MCP server implementation by einreke that provides AI assistants with complete access to the Sleeper Fantasy Football API for retrieving user profiles, league data, rosters, matchups, draft information, and player statistics. Built in Python using the requests library, the implementation offers 18 tools covering the full spectrum of Sleeper''s read-only API including user league management, real-time matchup data, playoff brackets, transaction history, draft picks, and trending player analytics based on add/drop activity. The server requires no API authentication since Sleeper''s API is publicly accessible, includes comprehensive test coverage with both unit tests and smoke tests, and serves fantasy football enthusiasts, sports analysts, and developers building fantasy sports applications who need programmatic access to league management data, player performance metrics, and social fantasy football insights.', '@einreke', 'development', 'Unknown', 5, 'https://github.com/einreke/sleeper-scraper-mcp', NULL, 0, 'https://github.com/einreke.png?size=128', '2026-03-09T05:21:01.958738+00:00'),
  ('interview-roleplay', 'Interview Roleplay', 'This MCP server, developed by Ejb503, provides an AI-powered interview roleplay system. Built with TypeScript using the Model Context Protocol SDK, it enables dynamic simulation of interview scenarios for training and assessment purposes. The implementation focuses on creating realistic conversational exchanges between an AI interviewer and human interviewee, with customizable interview types, questions, and evaluation criteria. It''s particularly useful for job seekers, HR professionals, and career coaches who want to practice and improve interview skills, offering use cases such as mock interviews, feedback generation, and performance analysis without the need for human interviewers.', '@ejb503', 'development', 'Unknown', 5, 'https://github.com/ejb503/systemprompt-mcp-interview', 'systemprompt-mcp-interview', 1718, 'https://github.com/ejb503.png?size=128', '2026-03-09T05:21:01.958797+00:00'),
  ('systemprompt', 'SystemPrompt', 'This SystemPrompt MCP server, developed by SystemPrompt, enables seamless integration of systemprompt.io''s powerful prompt management capabilities into AI workflows. Built with TypeScript and leveraging the Model Context Protocol SDK, it provides tools for creating, managing, and versioning system prompts. The implementation offers features like resource fetching, error handling, and standardized interfaces for prompt operations. It''s particularly useful for AI assistants or applications needing centralized prompt management, enabling tasks like dynamic prompt generation, A/B testing, and prompt versioning without requiring deep knowledge of the underlying SystemPrompt API. When used in conjunction with the multimodal-mcp-client, it provides a complete voice-powered AI workflow solution.', '@ejb503', 'development', 'Unknown', 14, 'https://github.com/ejb503/systemprompt-mcp-core', 'systemprompt-agent-server', 1750, 'https://github.com/ejb503.png?size=128', '2026-03-09T05:21:01.958899+00:00'),
  ('taskchecker', 'TaskChecker', 'SystemPrompt MCP TaskChecker is an enterprise-grade task management server built by SystemPrompt.io that provides intelligent task orchestration, evaluation scoring, and session-based workflow tracking for AI assistants. The implementation features in-memory task storage with automatic cleanup, supports task status transitions (pending/in_progress/completed), includes 0-100 evaluation scoring for completed tasks, and maintains session isolation with configurable timeouts. Built with TypeScript and the MCP SDK, it offers structured task management capabilities through tools for creating task lists, updating task properties, and retrieving status information, making it useful for AI-driven productivity workflows, project management automation, and structured task evaluation in enterprise environments.', '@ejb503', 'development', 'Unknown', 2, 'https://github.com/ejb503/systemprompt-mcp-taskchecker', NULL, 0, 'https://github.com/ejb503.png?size=128', '2026-03-09T05:21:01.958934+00:00'),
  ('ekkos-memory', 'ekkOS Memory', 'Provides persistent memory and learning capabilities for AI assistants across Cursor, Windsurf, VS Code, and Claude Code. Features five core tools: search_memory for finding relevant patterns and past conversations across memory layers, forge_pattern for saving reusable solutions, forge_directive for creating behavior rules with priority levels, recall_conversation for retrieving past discussions, and check_conflict for validating actions against stored rules. Built with dual-path architecture using unified-context API as primary and direct Supabase fallback for resilience.', '@ekkos-technologies-inc', 'databases', 'Unknown', 2, 'https://github.com/ekkos-technologies-inc/ekkos-mcp-server/tree/HEAD/ekkos-memory', NULL, 0, 'https://github.com/ekkos-technologies-inc.png?size=128', '2026-03-09T05:21:01.958992+00:00'),
  ('companies-house', 'Companies House', 'Integrates with the UK Companies House API to provide comprehensive company data including company searches, detailed profiles, officer and director information, filing history, charges, insolvency records, and beneficial ownership data. Supports generating comprehensive due diligence reports combining all available company information. Requires a Companies House API key for access.', '@elankeeran', 'ai-ml', 'Unknown', 0, 'https://github.com/elankeeran/companies-house-mcp-server', NULL, 0, 'https://github.com/elankeeran.png?size=128', '2026-03-09T05:21:01.959023+00:00'),
  ('elastic-email', 'Elastic Email', 'MCP server providing comprehensive email marketing and sending capabilities through Elastic Email''s API. Includes campaign management, contacts management, email sending, audience segments, templates, and API health monitoring. Designed for AI agents and MCP-compatible tools to access full email operations programmatically.', '@elasticemail', 'communication', 'Unknown', 1, 'https://github.com/elasticemail/elasticemail-mcp-server', NULL, 0, 'https://github.com/elasticemail.png?size=128', '2026-03-09T05:21:01.959073+00:00'),
  ('mysql-database-tools', 'MySQL Database Tools', 'Database Tools for Claude AI is an MCP server that enables direct interaction with MySQL databases through a simple interface. Developed by Elberfeld Perez, this implementation allows Claude to execute any valid SQL query, retrieve information about tables, and format results for easy reading. The server uses environment variables for database configuration and provides detailed error handling for query execution failures. Ideal for users who need to analyze database content, check table structures, or perform database operations directly through Claude without switching to another tool.', '@elber-code', 'databases', 'Unknown', 4, 'https://github.com/elber-code/database-tools', NULL, 0, 'https://github.com/elber-code.png?size=128', '2026-03-09T05:21:01.959087+00:00'),
  ('hostbridge', 'HostBridge', 'HostBridge-MCP is a server that simplifies deploying web applications to various hosting environments through a unified interface. It supports multiple frameworks like Wasp and hosting providers including Netlify, Vercel, and traditional shared hosting services. The implementation handles authentication, project creation, building, and deployment operations through a set of MCP tools and resources. Built with Python and the MCP protocol, it abstracts away provider-specific complexities, allowing users to deploy applications with simple commands rather than managing different deployment workflows for each provider. Particularly valuable for developers who want to quickly deploy applications across different hosting environments without leaving their AI assistant conversation.', '@elblanco2', 'cloud', 'Unknown', 1, 'https://github.com/elblanco2/hostbridge-mcp', NULL, 0, 'https://github.com/elblanco2.png?size=128', '2026-03-09T05:21:01.959111+00:00'),
  ('vidu', 'Vidu', 'Vidu MCP Server provides a standardized interface for generating videos from static images using the Vidu AI video generation API. It implements three main tools: image-to-video conversion with customizable parameters like duration and resolution, status checking for ongoing generation tasks, and image uploading capabilities. The server handles all the complexity of API authentication, file management, and asynchronous task processing, making it particularly valuable for applications that need to transform static visual content into dynamic videos without requiring direct API integration.', '@el-el-san', 'productivity', 'Unknown', 3, 'https://github.com/el-el-san/vidu-mcp-server', NULL, 0, 'https://github.com/el-el-san.png?size=128', '2026-03-09T05:21:01.959150+00:00'),
  ('elevenlabs', 'ElevenLabs', 'An ElevenLabs MCP server implementation that provides AI assistants with access to ElevenLabs'' text-to-speech, voice cloning, and conversation AI capabilities. Developed by the ElevenLabs team, this server enables voice synthesis with customizable parameters, audio file handling with similarity detection, and creation of conversational agents with specific voice profiles. The implementation includes utilities for environment configuration, output path management, and Claude Desktop integration, making it particularly useful for applications requiring high-quality voice generation, audio processing, and interactive voice-based AI experiences.', '@elevenlabs', 'ai-ml', 'Unknown', 1247, 'https://github.com/elevenlabs/elevenlabs-mcp', 'elevenlabs-mcp', 96664, 'https://github.com/elevenlabs.png?size=128', '2026-03-09T05:21:01.959194+00:00'),
  ('magento-2-development', 'Magento 2 Development', 'This MCP server provides comprehensive Magento 2 development tools through n98-magerun2 integration, enabling cache management, module operations, system diagnostics, and database interactions. Built by Elgentos, it exposes 30+ tools across categories including cache control (clean, flush, enable/disable), module management (list, create, observer inspection), configuration management (get/set values across scopes), database querying, setup operations (upgrade, DI compilation, static content deployment), and system information retrieval. The implementation uses consistent error handling with helpful guidance for common issues like missing magerun2 installation or incorrect working directories, supports multiple output formats (table, JSON, CSV), and integrates seamlessly with AI platforms like Claude Desktop, Cursor, and Continue.dev, making it valuable for Magento developers who need to perform routine development tasks through conversational interfaces rather than manual command-line operations.', '@elgentos', 'databases', 'Unknown', 32, 'https://github.com/elgentos/magento2-dev-mcp', '@elgentos/magento2-dev-mcp', 892, 'https://github.com/elgentos.png?size=128', '2026-03-09T05:21:01.959209+00:00'),
  ('rocket-chat', 'Rocket.Chat', 'RocketChat MCP server that provides AI assistants with direct integration to RocketChat instances for team communication and collaboration. The implementation uses httpx for async HTTP requests and FastMCP for the server framework, offering tools to list users and channels, send messages to specific channels, retrieve channel message history, create new channels, and get detailed user information. Built to work with local or remote RocketChat deployments through Docker Compose setup, it authenticates using username/password credentials and maintains persistent sessions for reliable API access. Valuable for AI assistants that need to participate in team communications, automate notifications, monitor channel activity, or facilitate cross-team coordination within existing RocketChat workflows.', '@elieworkspace', 'cloud', 'Unknown', 3, 'https://github.com/elieworkspace/rocketchat-mcp', NULL, 0, 'https://github.com/elieworkspace.png?size=128', '2026-03-09T05:21:01.959276+00:00'),
  ('gtd-project-manager', 'GTD Project Manager', 'A GTD (Getting Things Done) project management MCP server that automates the creation of structured project files with YAML frontmatter and markdown templates following the GTD Natural Planning Model. The server validates project metadata against configured areas of focus, prevents duplicate project creation across folders (active, incubator, completed, descoped), and generates appropriate templates based on project type (standard, coordination, habit). It includes project completion functionality that checks for open next actions and moves completed projects with proper date tracking, making it useful for maintaining consistent GTD workflows, automating project lifecycle management, and ensuring proper organization of personal productivity systems.', '@elinsky', 'productivity', 'Unknown', 1, 'https://github.com/elinsky/execution-system-mcp', NULL, 0, 'https://github.com/elinsky.png?size=128', '2026-03-09T05:21:01.959327+00:00'),
  ('npi-registry', 'NPI Registry', 'This MCP server provides healthcare provider lookup capabilities through the National Provider Identifier (NPI) registry, enabling AI assistants to search for individual practitioners and healthcare organizations across the United States. Built by Eliot Kristan using Python with FastMCP and httpx, it offers flexible search functionality with wildcard support for names, organizations, cities, and specialties, along with location-based filtering by state and postal code, and direct NPI number lookup for specific providers. The implementation features comprehensive provider information retrieval including contact details, practice locations, taxonomies, credentials, and organizational hierarchies, with configurable result limits and robust error handling for API interactions, making it valuable for healthcare research workflows, provider verification processes, and building AI assistants that need programmatic access to official healthcare provider data without manual registry navigation.', '@eliotk', 'development', 'Unknown', 1, 'https://github.com/eliotk/npi-registry-mcp-server', 'npi-registry-mcp-server', 913, 'https://github.com/eliotk.png?size=128', '2026-03-09T05:21:01.959360+00:00'),
  ('vllm-benchmark', 'vLLM Benchmark', 'MCP vLLM Benchmarking Tool enables interactive performance testing of vLLM deployments through a simple interface. This proof-of-concept implementation allows users to benchmark language models served by vLLM by specifying endpoints, model names, and test parameters through natural language prompts. The tool leverages code from vLLM''s official benchmarking suite to measure metrics like throughput, latency, and token generation speed across multiple test iterations. Developed by Eliovp-BV as an exploration of MCP capabilities, it''s useful for AI engineers who need to evaluate and compare the performance characteristics of different model deployments.', '@eliovp-bv', 'development', 'Unknown', 4, 'https://github.com/eliovp-bv/mcp-vllm-benchmark', NULL, 0, 'https://github.com/eliovp-bv.png?size=128', '2026-03-09T05:21:01.959386+00:00'),
  ('sqlite-hr-management', 'SQLite HR Management', 'This MCP server provides a complete HR management system built on SQLite, offering tools for employee lifecycle management, organizational structure, leave management, salary administration, and performance tracking. The implementation includes two specialized clients: a basic client for general database operations and an enhanced HR client with natural language processing that interprets user queries and automatically selects appropriate tools based on context. The server supports complex HR workflows including employee onboarding with automatic department/position creation, leave balance calculations with pro-rating, organizational hierarchy visualization, and comprehensive audit logging, making it suitable for small to medium businesses needing a self-contained HR management solution with AI-powered natural language interfaces.', '@elisha1994', 'databases', 'Unknown', 1, 'https://github.com/elisha1994/mcp-llama-sqlite-bridge', NULL, 0, 'https://github.com/elisha1994.png?size=128', '2026-03-09T05:21:01.959398+00:00'),
  ('website-scraper-and-analyzer', 'Website Scraper and Analyzer', 'This Remote MCP Server enables website analysis and content extraction using Cloudflare Workers without requiring authentication. Built with the Model Context Protocol SDK, it leverages Cloudflare''s Browser Rendering and AI capabilities to provide two key tools: analyze_website for scraping and summarizing website content, and ask_q_about_website for answering specific questions about web pages. The implementation includes robust error handling, retry logic for failed requests, and browser session management to ensure reliable performance. Ideal for AI assistants that need to access and analyze web content in real-time without maintaining separate authentication systems.', '@elizabethsiegle', 'cloud', 'Unknown', 6, 'https://github.com/elizabethsiegle/remote-mcp-server-authless-scrape-and-analyze-website', NULL, 0, 'https://github.com/elizabethsiegle.png?size=128', '2026-03-09T05:21:01.959419+00:00'),
  ('unpaywall', 'Unpaywall', 'This MCP server provides access to Unpaywall''s open database of free scholarly articles, enabling AI assistants to find open access versions of academic papers and retrieve publication metadata. Built by ElliotPadfield, it integrates with Unpaywall''s REST API to search for freely available PDFs of research papers that would otherwise be behind paywalls, along with detailed bibliographic information including DOIs, publication venues, and author details. The implementation is particularly useful for researchers, students, and academics who need to locate open access versions of scientific literature for literature reviews, research projects, or educational purposes without subscription barriers.', '@elliotpadfield', 'databases', 'Unknown', 2, 'https://github.com/elliotpadfield/unpaywall-mcp', NULL, 0, 'https://github.com/elliotpadfield.png?size=128', '2026-03-09T05:21:01.959492+00:00'),
  ('toon', 'TOON', 'TOON (Token-Oriented Object Notation) encodes JSON, CSV, XML, HTML tables, and YAML into a compact header-based format where field names are defined once rather than repeated for each record. The server provides tools for encoding data to TOON format, decoding back to JSON, analyzing potential token savings, and automatically optimizing prompts by detecting and converting embedded data sections. Benchmarks show consistent 50-65% token reduction across datasets of varying sizes.', '@elminson', 'development', 'Unknown', 3, 'https://github.com/elminson/toon-mcp', NULL, 0, 'https://github.com/elminson.png?size=128', '2026-03-09T05:21:01.959516+00:00'),
  ('a-stock', 'A-Stock', 'A specialized MCP server for Chinese stock market data analysis, providing tools to retrieve detailed stock information across different levels of depth (brief, medium, full). Built to integrate with a custom data feed system, it enables AI assistants to fetch comprehensive stock data including basic metrics, trading information, financial details, and technical analysis through a standardized interface.', '@elsejj', 'ai-ml', 'Unknown', 419, 'https://github.com/elsejj/mcp-cn-a-stock', NULL, 0, 'https://github.com/elsejj.png?size=128', '2026-03-09T05:21:01.959553+00:00'),
  ('tinydb-emcipi', 'TinyDB Emcipi', 'A TinyDB-based MCP server that provides lightweight JSON database management capabilities through a collection of tools for creating, querying, updating, and managing local databases. The implementation features schema validation, case-insensitive search functionality, and an active database switching mechanism that allows users to work with multiple databases seamlessly. Built with FastMCP and designed for scenarios requiring simple file-based data storage without the overhead of traditional database systems, it''s particularly useful for prototyping, small-scale data management, and applications where SQLite or larger databases would be overkill.', '@elsrjuez', 'databases', 'Unknown', 1, 'https://github.com/elsrjuez/tinydb-emcipi', NULL, 0, 'https://github.com/elsrjuez.png?size=128', '2026-03-09T05:21:01.959564+00:00'),
  ('code-execution-mode', 'Code Execution Mode', 'MCP server providing secure Python code execution in isolated containers while enabling seamless integration with other MCP servers through bridge architecture. Automatically discovers MCP servers from Claude Code and standard configuration locations, then executes Python code in rootless containers (Podman/Docker) with network isolation and resource limits while providing runtime access to discovered MCP servers through generated proxy objects. Features TOON-format response encoding for token efficiency, persistent MCP client sessions, automatic server metadata discovery with tool aliasing, and comprehensive sandbox security including memory limits, process restrictions, and temporary filesystem isolation.', '@elusznik', 'cloud', 'Unknown', 318, 'https://github.com/elusznik/mcp-server-code-execution-mode', NULL, 0, 'https://github.com/elusznik.png?size=128', '2026-03-09T05:21:01.959588+00:00'),
  ('codex-bridge', 'Codex Bridge', 'Codex Bridge MCP server by Shelakh provides a lightweight bridge between Claude and OpenAI''s Codex AI through the official Codex CLI. Built with Python using FastMCP, it offers three core tools: direct Codex consultation, stdin-piped execution for CI/CD workflows, and batch processing for multiple queries. The implementation emphasizes simplicity and reliability with structured JSON output, configurable timeouts, and comprehensive error handling. Designed for developers integrating AI-powered code analysis into their workflows, it enables use cases like automated code reviews, batch file processing, and pipeline-friendly AI assistance without complex API integrations.', '@elyin', 'development', 'Unknown', 81, 'https://github.com/elyin/codex-bridge', 'codex-bridge', 14959, 'https://github.com/elyin.png?size=128', '2026-03-09T05:21:01.959614+00:00'),
  ('gemini-bridge', 'Gemini Bridge', 'This lightweight MCP server by Shelakh provides a direct bridge between Claude and Google''s Gemini AI through the official Gemini CLI, offering two core tools for sending queries with or without file attachments. Built with Python and FastMCP, it executes gemini CLI commands via subprocess with configurable timeouts, normalizes model names (supporting both flash and pro variants), and concatenates file contents directly into prompts for context-aware queries. The implementation prioritizes simplicity over complexity with no caching, sessions, or persistent state, making it ideal for developers who want straightforward access to Gemini''s capabilities from within Claude workflows without additional infrastructure dependencies.', '@elyin', 'ai-ml', 'Unknown', 85, 'https://github.com/elyin/gemini-bridge', 'gemini-bridge', 6444, 'https://github.com/elyin.png?size=128', '2026-03-09T05:21:01.959662+00:00'),
  ('microsoft-365', 'Microsoft 365', 'This Microsoft Graph MCP server by elyx provides AI assistants with comprehensive access to Microsoft 365 services including Outlook email management, calendar operations, contact management, and OneDrive file operations through the Microsoft Graph API. The implementation supports multi-account authentication using MSAL device flow, handles large file uploads with chunked transfer for both OneDrive and email attachments, and includes advanced search capabilities across emails, files, events, and contacts using Microsoft''s modern search APIs. Built with FastMCP and featuring robust error handling with retry logic, rate limiting, and token caching, it''s particularly valuable for users who need to integrate their Microsoft 365 workflows with AI assistants for tasks like email automation, calendar management, document processing, and cross-service data analysis.', '@elyxlz', 'communication', 'Unknown', 40, 'https://github.com/elyxlz/microsoft-mcp', NULL, 0, 'https://github.com/elyxlz.png?size=128', '2026-03-09T05:21:01.959702+00:00'),
  ('emacs', 'Emacs', 'This MCP server provides deep introspection into Emacs environments, enabling AI assistants to access documentation, configuration details, and system information from running Emacs instances. Built by Michael Pontus using Emacs Lisp with JSON-RPC over stdio, it offers tools for querying function and variable documentation, exploring keybindings and modes, searching Info manuals, listing installed packages and loaded features, analyzing hooks and customizations, and inspecting fonts and display capabilities. The implementation runs Emacs in batch mode to serve MCP requests while maintaining access to the full user configuration including Doom Emacs support, making it valuable for AI-assisted Emacs configuration development, package authoring, troubleshooting user setups, and providing contextual help without requiring manual specification of relevant configuration files.', '@mpontus', 'development', 'Unknown', 11, 'https://github.com/mpontus/emacs-mcp', NULL, 0, 'https://github.com/mpontus.png?size=128', '2026-03-09T05:21:01.959733+00:00'),
  ('email-sender', 'Email Sender', 'MCP-Server-Email provides a bridge for language models to compose and send emails with attachments through SMTP servers. Developed by Tian Ming Guang, this server implementation supports multiple email providers (Gmail, Outlook, Yahoo) and offers tools for sending emails with multiple recipients and searching for attachments in specified directories. The server handles secure email transmission, supports various attachment file types (documents, archives, images), and requires environment variables for sender credentials. Ideal for automating email workflows where AI assistants need to compose messages, attach files, and manage email communications without direct access to email services.', '@shy2593666979', 'communication', 'Unknown', 71, 'https://github.com/shy2593666979/mcp-server-email', 'mcp-server-email', 6413, 'https://github.com/shy2593666979.png?size=128', '2026-03-09T05:21:01.959768+00:00'),
  ('source-library', 'Source Library', 'Provides access to rare historical texts from the Embassy of the Free Mind''s collection, including translated Latin and German manuscripts from the 15th-18th centuries covering alchemy, Hermeticism, and Renaissance philosophy. Offers tools to search the library, retrieve passages with academic citations, and fetch detailed book metadata with DOI-backed references through Zenodo.', '@embassy-of-the-free-mind', 'ai-ml', 'Unknown', 0, 'https://github.com/embassy-of-the-free-mind/sourcelibrary-v2/tree/HEAD/mcp-server', NULL, 0, 'https://github.com/embassy-of-the-free-mind.png?size=128', '2026-03-09T05:21:01.959800+00:00'),
  ('crate-public-api', 'Crate Public API', 'Crate-MCP provides a server that exposes Rust crate public APIs to language models through the Model Context Protocol. It offers two main tools: listing all dependencies in a project''s Cargo.lock file and generating comprehensive public API documentation for any specific crate dependency. Built with Rust using cargo''s dependency resolution system and rustdoc JSON generation, it enables AI assistants to understand and reason about Rust library interfaces without requiring direct code access. The implementation handles toolchain management, builds documentation in a workspace-specific target directory, and supports filtering API items with regex patterns.', '@emberian', 'development', 'Unknown', 4, 'https://github.com/emberian/crate-mcp', 'crate-mcp', 0, 'https://github.com/emberian.png?size=128', '2026-03-09T05:21:01.959831+00:00'),
  ('nb', 'nb', 'Provides an interface to the nb command-line note-taking tool, solving shell escaping issues and enabling multi-notebook management. Supports creating, reading, updating, and deleting notes, full-text search, todo tracking, folder organization, bookmarking, and file imports. Uses JSON-based parameters to avoid markdown backtick corruption during shell command substitution.', '@emcd', 'productivity', 'Unknown', 0, 'https://github.com/emcd/nb-mcp-server', NULL, 0, 'https://github.com/emcd.png?size=128', '2026-03-09T05:21:01.959873+00:00'),
  ('rdf-explorer', 'RDF Explorer', 'RDF Explorer is an MCP server that provides a conversational interface for exploring and analyzing RDF-based Knowledge Graphs in either Local File mode or SPARQL Endpoint mode. Developed by Emeka Azuka Okoye, it facilitates communication between AI applications and RDF data through SPARQL queries, full-text search, and graph statistics tools. The server supports both local RDF files and external SPARQL endpoints, offering features like schema exploration, relationship discovery, and graph visualization. Particularly useful for knowledge graph research, semantic web exploration, and AI data preparation workflows where structured graph data needs to be queried conversationally.', '@emekaokoye', 'ai-ml', 'Unknown', 50, 'https://github.com/emekaokoye/mcp-rdf-explorer', NULL, 0, 'https://github.com/emekaokoye.png?size=128', '2026-03-09T05:21:01.959919+00:00'),
  ('sap-commerce-cloud-hybris', 'SAP Commerce Cloud (Hybris)', 'Provides comprehensive integration with SAP Commerce Cloud (Hybris) through both OCC API and HAC (Hybris Administration Console) endpoints. Enables product catalog management, order processing, and administrative operations including FlexibleSearch queries, Groovy script execution, ImpEx data import/export, cron job management, cache operations, and catalog synchronization. Handles HAC authentication with automated CSRF token management and session handling, making it valuable for developers and administrators managing Hybris instances.', '@emenowicz', 'search', 'Unknown', 8, 'https://github.com/emenowicz/hybris-mcp', NULL, 0, 'https://github.com/emenowicz.png?size=128', '2026-03-09T05:21:01.959971+00:00'),
  ('ollama', 'Ollama', 'This MCP server, developed by Matt Green, provides integration with Ollama for local large language model inference. Built using Python and leveraging the MCP CLI, it enables AI assistants to interact with Ollama''s API for listing available models, retrieving model details, and generating text completions. The implementation focuses on providing a standardized interface to Ollama''s capabilities, making it easier to incorporate local LLM inference into AI workflows. It''s particularly useful for developers and researchers who want to leverage locally-run open-source language models, enabling use cases such as private AI assistants, custom model fine-tuning, and AI-augmented development without relying on cloud APIs.', '@emgeee', 'development', 'Unknown', 31, 'https://github.com/emgeee/mcp-ollama', 'mcp-ollama', 11749, 'https://github.com/emgeee.png?size=128', '2026-03-09T05:21:01.960047+00:00'),
  ('protobuf-formatter', 'Protobuf Formatter', 'Protofmt-mcp is an MCP server that formats Protocol Buffer (.proto) files according to standardized conventions. Developed by Ernest Micklei, it leverages the proto and proto-contrib packages to parse and reformat protobuf files with consistent indentation (2 spaces). The server exposes a single tool that accepts a file path parameter, reads the specified .proto file, formats its content, and writes it back to the original location. Designed for integration with code editors like Visual Studio Code, it enables developers to maintain clean, consistently formatted protobuf definitions with minimal configuration.', '@emicklei', 'development', 'Unknown', 1, 'https://github.com/emicklei/protofmt-mcp', NULL, 0, 'https://github.com/emicklei.png?size=128', '2026-03-09T05:21:01.960072+00:00'),
  ('discord-relay', 'Discord Relay', 'This Discord relay MCP server, developed by Emilio Bool, enables AI agents to send messages and prompts to a Discord channel and receive responses. Built with TypeScript and leveraging the Discord.js library, it provides a bridge between MCP-compatible AI systems and Discord''s communication platform. The implementation focuses on simplicity and ease of setup, offering features like customizable message types, action buttons, and timeout handling. It''s particularly useful for developers and researchers working on AI-human interaction, enabling use cases such as automated support systems, community engagement bots, or AI-assisted moderation without dealing directly with Discord''s API complexities.', '@emiliobool', 'development', 'Unknown', 1, 'https://github.com/emiliobool/mcp-relay', NULL, 0, 'https://github.com/emiliobool.png?size=128', '2026-03-09T05:21:01.960128+00:00'),
  ('sqlite', 'SQLite', 'This MCP server implementation, developed by seanivore, provides a SQLite-based storage solution for MCP data. Built with Python and leveraging libraries like mcp and pydantic, it offers a lightweight and portable database option for MCP applications. The implementation focuses on simplicity and ease of use, making it ideal for small to medium-scale projects or as a starting point for more complex MCP data management systems. It supports basic CRUD operations and can be easily integrated into existing MCP workflows. This server is particularly useful for developers looking to quickly set up a local MCP data store, prototype MCP-based applications, or build standalone tools that require persistent storage without the overhead of larger database systems.', '@emiryasar', 'databases', 'Unknown', 39, 'https://github.com/emiryasar/mcp_code_analyzer', NULL, 0, 'https://github.com/emiryasar.png?size=128', '2026-03-09T05:21:01.960139+00:00'),
  ('gemini-code-analysis-openrouter', 'Gemini Code Analysis (OpenRouter)', 'This Gemini MCP server by emmron provides AI-powered codebase analysis through OpenRouter''s API integration, offering comprehensive code quality assessment, security vulnerability scanning, and performance profiling capabilities. The implementation combines static code analysis with advanced features including OWASP Top 10 security mapping, dependency vulnerability scanning with CVE database integration, code similarity detection for clone analysis, and AI-powered code smell detection with automatic fix suggestions. Built with task management functionality and extensive AST-based analysis, it''s particularly valuable for development teams needing automated code review, security auditing, and technical debt assessment across JavaScript/TypeScript codebases with detailed reporting on maintainability metrics, architectural patterns, and optimization recommendations.', '@emmron', 'databases', 'Unknown', 16, 'https://github.com/emmron/gemini-mcp', NULL, 0, 'https://github.com/emmron.png?size=128', '2026-03-09T05:21:01.960205+00:00'),
  ('emqx-tools', 'EMQX Tools', 'This EMQX plugin provides MCP tools for health checking and problem analysis of EMQX MQTT broker clusters, offering API wrappers for cluster status monitoring, connector management, authentication and authorization source inspection, plus network connectivity testing tools. Built in Erlang by Shawn at EMQ Technologies, it integrates directly with EMQX''s internal APIs to expose cluster node information, authenticator/authorization source configurations and statuses, built-in database authorization rules, and TCP connectivity checks across all cluster nodes. The implementation uses the mcp-mqtt-erl library to serve tools over MQTT transport, making it valuable for DevOps teams managing EMQX deployments who need AI-assisted troubleshooting and monitoring capabilities for distributed MQTT infrastructure.', '@emqx', 'databases', 'Unknown', 2, 'https://github.com/emqx/emqx-plugin-mcp-tools', NULL, 0, 'https://github.com/emqx.png?size=128', '2026-03-09T05:21:01.960217+00:00'),
  ('mobile-development-validator', 'Mobile Development Validator', 'Mobile Development Validator prevents unstructured "vibe coding" by enforcing systematic task planning, code validation, and breaking change detection across Flutter/Dart, React Native, iOS, and Android projects. The server provides blocking validation tools that enforce file size limits, widget complexity constraints, architecture patterns, UI state handling requirements, and business logic separation. It includes pre-commit hooks, automated analysis integration, platform-specific configuration validation, and enforced workflow prompts that guide developers through systematic planning and comprehensive quality checks.', '@emran1993', 'development', 'Unknown', 1, 'https://github.com/emran1993/mobile-mcp-validator', NULL, 0, 'https://github.com/emran1993.png?size=128', '2026-03-09T05:21:01.960243+00:00'),
  ('fetch-mozilla-readability', 'Fetch (Mozilla Readability)', 'This Mozilla Readability Parser MCP server, created by Max Zimmer, extracts and transforms webpage content into clean, LLM-optimized Markdown. It uses Mozilla''s Readability algorithm to remove ads, navigation, and non-essential elements while preserving core content structure. The server converts HTML to well-formatted Markdown, returns article metadata, and handles errors gracefully. It integrates with the Model Context Protocol, allowing AI assistants to fetch and parse web content efficiently. This implementation is particularly useful for reducing token usage in LLM processing, ensuring consistent formatting, and providing clean, relevant content for tasks like summarization, analysis, or information extraction from web pages.', '@emzimmer', 'productivity', 'Unknown', 16, 'https://github.com/emzimmer/server-moz-readability', 'server-moz-readability', 4174, 'https://github.com/emzimmer.png?size=128', '2026-03-09T05:21:01.960291+00:00'),
  ('postgresql-database', 'PostgreSQL Database', 'This PostgreSQL MCP server enables AI assistants to interact with PostgreSQL databases through SQL queries. Built with Node.js and the Model Context Protocol SDK, it provides tools for listing database tables, retrieving schema information, and executing custom SQL queries with retry logic for improved reliability. The implementation includes robust error handling, connection pooling, and flexible configuration options that support both environment variables and shell config files for database credentials. It''s particularly useful for data analysis, database exploration, and executing complex queries directly from AI workflows.', '@endaoment', 'databases', 'Unknown', 2, 'https://github.com/endaoment/endaoment-postgres-mcp', NULL, 0, 'https://github.com/endaoment.png?size=128', '2026-03-09T05:21:01.960350+00:00'),
  ('endor-labs', 'Endor Labs', 'The Endor Labs MCP server integrates security scanning directly into IDEs like Cursor and Visual Studio Code, enabling real-time vulnerability detection and security analysis as developers write code. Built around the endorctl CLI tool, it provides four core capabilities: dependency vulnerability checking, vulnerability database lookups, resource context retrieval, and comprehensive security scans that detect open source risks, common security issues, and exposed credentials in Git repositories. The implementation supports configurable language-specific scanning, environment variable customization, and selective tool management, making it valuable for shift-left security practices where developers need immediate feedback on security issues during development rather than waiting for CI/CD pipeline results.', '@unknown', 'databases', 'Unknown', 0, 'https://docs.endorlabs.com/deployment/ide/mcp/', NULL, 0, NULL, '2026-03-09T05:21:01.960361+00:00'),
  ('pagespeed-insights', 'PageSpeed Insights', 'This MCP server, developed by enemyrr, provides integration with Google PageSpeed Insights for web performance analysis. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers a tool for analyzing webpage performance, including loading experience metrics and improvement suggestions. The implementation focuses on delivering concise, actionable insights about web page speed and user experience. By connecting AI models with Google''s performance analysis tools, this server enables scenarios such as automated performance auditing, optimization recommendations, and comparative analysis across multiple web pages. It''s particularly useful for developers, SEO specialists, and AI assistants focused on web performance optimization.', '@enemyrr', 'development', 'Unknown', 8, 'https://github.com/enemyrr/mcp-server-pagespeed', NULL, 0, 'https://github.com/enemyrr.png?size=128', '2026-03-09T05:21:01.960416+00:00'),
  ('gcp', 'GCP', 'Provides a standardized interface for interacting with Google Cloud Platform services through the Model Context Protocol. Built by Enes Bol, this server enables AI assistants to manage and interact with GCP resources across multiple services like Compute Engine, Cloud Run, BigQuery, and Cloud Storage through a consistent, tool-driven approach. Particularly useful for developers and AI assistants seeking programmatic cloud resource management without complex manual configuration.', '@enesbol', 'cloud', 'Unknown', 6, 'https://github.com/enesbol/gcp-mcp', 'gcp-mcp-server', 1381, 'https://github.com/enesbol.png?size=128', '2026-03-09T05:21:01.960433+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('outlook', 'Outlook', 'Enhanced Outlook MCP Server provides a robust bridge to the Microsoft Graph API, enabling AI assistants to interact seamlessly with Outlook email, calendar, and messaging capabilities. Built with a modular architecture, it supports multi-user authentication, comprehensive email management, calendar scheduling, and mail rule configuration through a standardized set of tools. The implementation is particularly valuable for users seeking programmatic control over their Outlook ecosystem through natural language interactions.', '@jibberish69', 'communication', 'Unknown', 17, 'https://github.com/jibberish69/enhanced-outlook-mcp', NULL, 0, 'https://github.com/jibberish69.png?size=128', '2026-03-09T05:21:01.960500+00:00'),
  ('google-cloud-platform', 'Google Cloud Platform', 'This MCP server implementation provides integration with Google Cloud Platform services. Developed by Oluwapelumi Oluwaseyi, it offers tools for interacting with various GCP resources including Compute Engine, Cloud Storage, Cloud Functions, Cloud Run, BigQuery, and more. The server uses official Google Cloud client libraries and implements robust error handling and retry mechanisms. It''s designed for developers looking to leverage GCP capabilities within MCP-based applications and workflows.', '@eniayomi', 'cloud', 'Unknown', 196, 'https://github.com/eniayomi/gcp-mcp', 'gcp-mcp', 18081, 'https://github.com/eniayomi.png?size=128', '2026-03-09T05:21:01.960519+00:00'),
  ('enigma', 'Enigma', 'Provides comprehensive business intelligence data including business identity graphs, revenue metrics, growth signals, technology stack information, transaction analytics, legal entity relationships, government filings, permits, licenses, and KYB verification. Built on Enigma''s foundational ground-truth data spanning 48.9 million brands and locations plus 98 million legal entities across the United States.', '@unknown', 'data-analytics', 'Unknown', 0, 'https://enigma.com', NULL, 0, NULL, '2026-03-09T05:21:01.960576+00:00'),
  ('bci-mcp-brain-computer-interface', 'BCI-MCP (Brain-Computer Interface)', 'BCI-MCP is a Brain-Computer Interface server that enables AI systems to receive and process neural signals through the Model Context Protocol. It supports multiple EEG devices (OpenBCI, Emotiv, NeuroSky), provides real-time signal processing with features like bandpass filtering and event detection, and exposes a WebSocket API for streaming brain activity data. The implementation includes tools for device connection, calibration, data recording, and visualization, making it valuable for creating more intuitive human-AI interactions where brain activity can provide additional context to language models.', '@enkhbold470', 'ai-ml', 'Unknown', 0, 'https://github.com/enkhbold470/bci-mcp', NULL, 0, 'https://github.com/enkhbold470.png?size=128', '2026-03-09T05:21:01.960620+00:00'),
  ('enkryptai', 'EnkryptAI', 'EnkryptAI-MCP is a server implementation that integrates with the EnkryptAI platform, providing AI assistants with tools for managing guardrails, models, deployments, and red team testing. Built using the EnkryptAI SDK, it enables content detection for sensitive material, policy management, model configuration, and deployment orchestration with customizable safety controls. The server is particularly useful for organizations looking to implement robust AI safety measures, test models against various attack vectors, and deploy AI systems with appropriate guardrails to prevent harmful outputs.', '@enkryptai', 'development', 'Unknown', 3, 'https://github.com/enkryptai/enkryptai-mcp-server', NULL, 0, 'https://github.com/enkryptai.png?size=128', '2026-03-09T05:21:01.960647+00:00'),
  ('google-analytics', 'Google Analytics', 'Google Analytics Data API server that enables AI assistants to retrieve analytics data through a standardized interface. Built with TypeScript, it provides tools for running standard and realtime reports with configurable metrics, dimensions and date ranges, while handling authentication via service accounts. Particularly valuable for marketers and analysts who need to access Google Analytics 4 data and metrics directly through conversational AI without manual API configuration.', '@eno-graph', 'development', 'Unknown', 7, 'https://github.com/eno-graph/mcp-server-google-analytics', NULL, 0, 'https://github.com/eno-graph.png?size=128', '2026-03-09T05:21:01.960672+00:00'),
  ('primevue', 'PrimeVue', 'Built by Enolgr, this server extracts and serves PrimeVue component API data through automated TypeScript parsing and web scraping. It processes PrimeVue''s component definitions to create structured datasets containing props, emits, slots, design tokens, and documentation, then exposes this information via MCP tools. The server includes extraction scripts for API definitions, component logic, design tokens, and documentation, making it useful for developers building Vue.js applications who need contextual assistance with PrimeVue''s extensive component library and theming system.', '@enolgr', 'development', 'Unknown', 7, 'https://github.com/enolgr/primevue-mcp', NULL, 0, 'https://github.com/enolgr.png?size=128', '2026-03-09T05:21:01.960701+00:00'),
  ('enterprise-health-servicenow', 'Enterprise Health & ServiceNow', 'This enterprise MCP server provides AI assistants with system health monitoring and ServiceNow integration capabilities through a modular service architecture. Built by the Enterprise Team using Python with FastMCP, Starlette, and psutil, it offers health monitoring tools for CPU usage, memory statistics, system uptime, and platform information, alongside ServiceNow integration for incident management, change request handling, and ticket operations. The implementation features environment-based configuration, Docker containerization, comprehensive health check endpoints, and a base service pattern that enables easy extension with additional enterprise services, making it valuable for IT operations workflows, system monitoring automation, and building AI assistants that need programmatic access to both infrastructure metrics and ITSM platforms.', '@maybeswapnil', 'cloud', 'Unknown', 3, 'https://github.com/maybeswapnil/enterprise-mcp', NULL, 0, 'https://github.com/maybeswapnil.png?size=128', '2026-03-09T05:21:01.960729+00:00'),
  ('io-github-dominic-righthere-envibe', 'io.github.dominic-righthere/envibe', 'Secure permission layer between AI agents and your .env files', '@dominic-righthere', 'development', 'Unknown', 0, 'https://github.com/dominic-righthere/envibe-mcp', NULL, 0, 'https://github.com/dominic-righthere.png?size=128', '2026-03-09T05:21:01.960749+00:00'),
  ('io-github-eox-a-eoxelements', 'io.github.EOX-A/EOxElements', 'A server to provide information about EOxElements custom elements for coding agents.', '@eox-a', 'development', 'Unknown', 27, 'https://github.com/eox-a/eoxelements', NULL, 0, 'https://github.com/eox-a.png?size=128', '2026-03-09T05:21:01.960765+00:00'),
  ('epics-process-variable-bridge', 'EPICS Process Variable Bridge', 'EPICS-MCP-Server provides a bridge between AI assistants and EPICS (Experimental Physics and Industrial Control System) process variables, enabling real-time monitoring and control of industrial systems. Built with Python and pyepics, it exposes tools for getting PV values, setting PV values, and retrieving detailed PV information through a standardized interface. The server implements robust error handling with detailed logging, supports timeout configuration, and can be easily integrated with LangChain-based agents, making it valuable for engineers and operators who need their AI assistants to interact with EPICS-controlled hardware systems without writing custom integration code.', '@jacky1-jiang', 'development', 'Unknown', 3, 'https://github.com/jacky1-jiang/epics-mcp-server', NULL, 0, 'https://github.com/jacky1-jiang.png?size=128', '2026-03-09T05:21:01.960829+00:00'),
  ('device-country', 'Device Country', 'Device Country MCP is a Cloudflare Workers-based tool that provides access to a user''s country location using Cloudflare''s IP geolocation headers. Built with TypeScript and deployed as a Durable Object, it exposes a single tool that returns the country code of the requesting client, making it useful for applications that need to customize content or functionality based on user geography without requiring additional API integrations or complex geolocation services.', '@epicweb-dev', 'cloud', 'Unknown', 3, 'https://github.com/epicweb-dev/device-country-mcp', NULL, 0, 'https://github.com/epicweb-dev.png?size=128', '2026-03-09T05:21:01.960848+00:00'),
  ('epicshop-workshop', 'EpicShop Workshop', 'This is intended to be used within a code editor open in one of the workshops from EpicReact.dev, EpicWeb.dev, or EpicAI.pro (https://github.com/search?q=topic%3Aworkshop+org%3Aepicweb-dev&type=Repositories). It exposes a number of tools, resources, and prompts to help learners ask questions, perform actions, and get quizzed on the material in the workshop learning environment.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('etherscan', 'Etherscan', 'MCP Etherscan Server provides Ethereum blockchain data tools through Etherscan''s API, enabling AI assistants to check ETH balances, view transaction histories, track ERC20 transfers, fetch contract ABIs, monitor gas prices, and resolve ENS names. Built with TypeScript and the Model Context Protocol SDK, it runs on stdio transport for seamless integration with Claude Desktop, making it particularly valuable for users who need to access and analyze blockchain data without leaving their conversation interface.', '@otc-ai', 'development', 'Unknown', 0, 'https://github.com/otc-ai/mcp-otc', NULL, 0, 'https://github.com/otc-ai.png?size=128', '2026-03-09T05:21:01.962165+00:00'),
  ('untappd', 'Untappd', 'Untapped MCP server provides a bridge to the Untappd beer tracking and discovery API, enabling AI assistants to search for beers, retrieve detailed beer and brewery information, and access comprehensive metadata about craft beverages. Built by Adam Lusted, the implementation offers tools for searching beers, retrieving specific beer details, and exploring brewery information through a clean, type-safe TypeScript implementation with robust error handling.', '@etoxin', 'development', 'Unknown', 0, 'https://github.com/etoxin/untapped-mcp', NULL, 0, 'https://github.com/etoxin.png?size=128', '2026-03-09T05:21:01.962191+00:00'),
  ('mlb-stats', 'MLB Stats', 'A comprehensive MLB statistics MCP server built by Ethan Weisberg that provides access to baseball data through the MLB Stats API and pybaseball library, enabling retrieval of Statcast data, FanGraphs statistics, Baseball Reference records, and advanced analytics. The implementation includes tools for player lookups, team statistics, standings, schedules, prospect data, and specialized plotting functions that generate base64-encoded matplotlib visualizations including strike zone plots, spray charts, and batted ball profiles. Features a Next.js client application with OpenAI integration for AI-powered baseball analysis, making it useful for sports analytics, player performance evaluation, team comparisons, and generating data-driven insights about MLB players and teams.', '@etweisberg', 'development', 'Unknown', 17, 'https://github.com/etweisberg/mlb-mcp', NULL, 0, 'https://github.com/etweisberg.png?size=128', '2026-03-09T05:21:01.962222+00:00'),
  ('hypefury', 'Hypefury', 'The Hypefury MCP Server enables AI assistants to authenticate with and schedule posts through the Hypefury platform. It implements two key tools: an authentication function that verifies API credentials and a post scheduling capability that allows direct submission of content to Hypefury''s publishing queue. Built using the Model Context Protocol SDK with a stdio transport layer, this server creates a secure bridge between AI systems and social media management, making it ideal for automated content publishing workflows.', '@eugenechabanov', 'ai-ml', 'Unknown', 1, 'https://github.com/eugenechabanov/hf-mcp', NULL, 0, 'https://github.com/eugenechabanov.png?size=128', '2026-03-09T05:21:01.962261+00:00'),
  ('io-github-matjmat-eulerian-marketing-platform-mcp', 'io.github.matjmat/eulerian-marketing-platform-mcp', 'Provides access to the Eulerian Marketing Platform: analytics, attribution & data activation.', '@euleriantechnologies', 'development', 'Unknown', 1, 'https://github.com/euleriantechnologies/eulerian-marketing-platform-mcp', NULL, 0, 'https://github.com/euleriantechnologies.png?size=128', '2026-03-09T05:21:01.962277+00:00'),
  ('bpftrace', 'bpftrace', 'This MCP server provides AI assistants with Linux kernel tracing capabilities through bpftrace integration, built by eunomia-bpf using Python with FastMCP and asyncio for concurrent execution management. The implementation offers four core tools: probe discovery with filtering support, helper function documentation, asynchronous bpftrace program execution with configurable timeouts, and buffered output retrieval with pagination, all backed by subprocess management that handles sudo authentication and automatic cleanup of execution buffers. Built with in-memory output buffering, timeout protection, and background cleanup tasks, it serves system administrators needing kernel-level debugging through conversational interfaces, performance engineers requiring real-time system call tracing, and developers wanting to integrate eBPF-based monitoring into AI-assisted troubleshooting workflows with automatic result collection and management.', '@eunomia-bpf', 'development', 'Unknown', 64, 'https://github.com/eunomia-bpf/mcptrace', NULL, 0, 'https://github.com/eunomia-bpf.png?size=128', '2026-03-09T05:21:01.962312+00:00'),
  ('epics', 'EPICS', 'EPICS MCP server that provides AI assistants with direct access to EPICS (Experimental Physics and Industrial Control System) Process Variables through the PyEPICS library, supporting both stdio and SSE transport protocols. The implementation offers three core tools for getting PV values, setting PV values, and retrieving PV metadata, with comprehensive error handling for network timeouts and connection issues. Built with Docker support and Smithery configuration, it enables AI-assisted control system monitoring and automation workflows for scientific facilities, industrial automation, and laboratory equipment management where conversational interfaces need programmatic access to EPICS-controlled devices and sensors.', '@eunsang284', 'cloud', 'Unknown', 1, 'https://github.com/eunsang284/epics-mcp-server', NULL, 0, 'https://github.com/eunsang284.png?size=128', '2026-03-09T05:21:01.962337+00:00'),
  ('eu-regulations', 'EU Regulations', 'Query 47 EU regulations (GDPR, NIS2, DORA, AI Act) - 2,438 articles, 3,712 recitals, ISO 27001', '@ansvar-systems', 'ai-ml', 'Unknown', 49, 'https://github.com/ansvar-systems/eu_compliance_mcp', NULL, 0, 'https://github.com/ansvar-systems.png?size=128', '2026-03-09T05:21:01.962360+00:00'),
  ('european-public-transport', 'European Public Transport', 'MCP server for querying public transport data across three European countries (Switzerland, UK, and Belgium) using their respective national APIs. Built by Miro, the implementation provides country-specific tools for searching connections, finding stations, retrieving live departures, and accessing vehicle information through transport.opendata.ch (Switzerland), transportapi.com (UK), and api.irail.be (Belgium). Uses FastMCP framework with aiohttp for async HTTP requests and includes comprehensive error handling, input validation, and testing coverage, making it valuable for travel planning applications, transit apps, or AI assistants that need real-time European public transport information without managing multiple API integrations directly.', '@mirodn', 'development', 'Unknown', 6, 'https://github.com/mirodn/mcp-server-public-transport', 'mcp-server-public-transport', 1887, 'https://github.com/mirodn.png?size=128', '2026-03-09T05:21:01.962391+00:00'),
  ('huggingface-spaces-connector', 'HuggingFace Spaces Connector', 'This MCP server, developed by evalstate, enables AI assistants to seamlessly interact with Hugging Face Spaces. It provides a streamlined setup process where users simply specify desired spaces as arguments, with the server automatically configuring appropriate endpoints. Built for integration with Claude Desktop, it offers capabilities like image generation, vision tasks, text-to-speech, and more through various pre-configured spaces. The implementation handles authentication, file management, and API interactions, abstracting away complexities of working with Hugging Face. It is particularly useful for developers and researchers who want to leverage diverse AI models and tools from Hugging Face Spaces without manual configuration, enabling rapid prototyping and experimentation across a wide range of AI tasks.', '@evalstate', 'productivity', 'Unknown', 382, 'https://github.com/evalstate/mcp-hfspace', '@llmindset/mcp-hfspace', 16056, 'https://github.com/evalstate.png?size=128', '2026-03-09T05:21:01.962472+00:00'),
  ('miro', 'Miro', 'This Miro MCP server, developed by evalstate, enables AI assistants to interact with Miro whiteboards through the Miro API. It provides tools for manipulating boards, creating stickies and shapes, reading content, and performing bulk operations. Built in TypeScript, the implementation exposes Miro''s collaborative features via a standardized MCP interface, allowing analysis within Miro boards. By bridging AI models with Mir''s digital whiteboard platform, this server enhances LLM''s ability to assist with brainstorming, project planning, and visual data organization. It is particularly useful for teams seeking AI-powered collaboration, ideation, and visual information management within their existing MIRO workspaces.', '@evalstate', 'development', 'Unknown', 102, 'https://github.com/evalstate/mcp-miro', NULL, 0, 'https://github.com/evalstate.png?size=128', '2026-03-09T05:21:01.962497+00:00'),
  ('webcam-screenshot-capture', 'Webcam/Screenshot Capture', 'This MCP webcam server, developed by llmindset.co.uk, enables AI models to capture and analyze live webcam images and screenshots. Built with React, Express, and TypeScript, it provides tools for taking webcam snapshots and full-screen captures, with a web interface for testing and configuration. The implementation focuses on simplifying visual input for AI, allowing models to perceive and interact with the user''s environment in real-time. It''s particularly useful for applications requiring visual context, such as AI assistants that can comment on what the user is showing them, analyze objects in view, or provide feedback on the user''s surroundings.', '@evalstate', 'development', 'Unknown', 111, 'https://github.com/evalstate/mcp-webcam', '@llmindset/mcp-webcam', 4667, 'https://github.com/evalstate.png?size=128', '2026-03-09T05:21:01.962524+00:00'),
  ('pcileech', 'PCILeech', 'Wraps PCILeech hardware-based memory access tool, enabling raw memory read/write operations at any physical address. Provides multi-format memory presentation including hex dump, ASCII view, byte arrays, and DWORD arrays optimized for analysis. Designed for security researchers and reverse engineers examining system memory, analyzing malware, or debugging low-level software with DMA-capable hardware.', '@evan7198', 'development', 'Unknown', 16, 'https://github.com/evan7198/mcp_server_pcileech', NULL, 0, 'https://github.com/evan7198.png?size=128', '2026-03-09T05:21:01.962546+00:00'),
  ('personal-health-tracker', 'Personal Health Tracker', 'This personal MCP server, developed for health and well-being tracking, integrates with pandas for data analysis and pydantic for data validation. It uses a command-line interface built with Click and rich for enhanced terminal output. The implementation is designed for individuals who want to track and analyze their personal health data using AI assistance, allowing for natural language queries and visualization of trends. It''s particularly suited for users who prefer local data storage and processing, offering a balance between privacy and powerful analysis capabilities.', '@evangstav', 'ai-ml', 'Unknown', 9, 'https://github.com/evangstav/personal-mcp', NULL, 0, 'https://github.com/evangstav.png?size=128', '2026-03-09T05:21:01.962588+00:00'),
  ('openfga', 'OpenFGA', 'OpenFGA MCP server enables large language models to interact with OpenFGA authorization stores through a standardized protocol. Built by Evan Sims, it provides tools to read, search, and manipulate fine-grained access control policies programmatically, with support for checking permissions, creating relationships, and generating explanations for access decisions.', '@evansims', 'ai-ml', 'Unknown', 9, 'https://github.com/evansims/openfga-mcp', NULL, 0, 'https://github.com/evansims.png?size=128', '2026-03-09T05:21:01.962627+00:00'),
  ('eventcatalog', 'EventCatalog', 'EventCatalog MCP Server provides a standardized interface for AI assistants to interact with event-driven architecture metadata and resources. Built by David Boyne, it enables querying and retrieving information about events, services, domains, queries, commands, and other architectural components through a set of predefined tools and resources. The server dynamically loads catalog information and supports schema retrieval, making it particularly useful for developers and architects seeking to understand and explore complex event-driven systems.', '@event-catalog', 'ai-ml', 'Unknown', 22, 'https://github.com/event-catalog/mcp-server', '@eventcatalog/mcp-server', 2421, 'https://github.com/event-catalog.png?size=128', '2026-03-09T05:21:01.962699+00:00'),
  ('eve-online', 'EVE Online', 'EVE Online MCP server implementation built with TypeScript and the Model Context Protocol SDK, designed to provide AI assistants with access to EVE Online market data and game information. The server uses node-fetch for API interactions and includes Docker containerization for easy deployment, with configuration support through Smithery.ai for streamlined MCP integration. Useful for EVE Online players and developers who want to analyze market trends, check item prices, or integrate game data into their workflows through natural language interactions with AI assistants.', '@kongyo2', 'cloud', 'Unknown', 6, 'https://github.com/kongyo2/eve-online-mcp', NULL, 0, 'https://github.com/kongyo2.png?size=128', '2026-03-09T05:21:01.962721+00:00'),
  ('mistral-ocr', 'Mistral OCR', 'The MCP Mistral OCR server provides optical character recognition capabilities by leveraging Mistral AI''s OCR API. It processes both local files and URLs, supporting various image formats (JPG, PNG, WebP) and PDFs, with results saved as timestamped JSON files. The implementation includes Docker containerization for easy deployment, configurable environment variables for API authentication and file storage, and offers two primary tools: process_local_file for handling files from a configured directory and process_url_file for processing remote documents with explicit file type specification. This server is particularly useful for workflows requiring text extraction from visual documents within AI assistant conversations.', '@everaldo', 'cloud', 'Unknown', 37, 'https://github.com/everaldo/mcp-mistral-ocr', NULL, 0, 'https://github.com/everaldo.png?size=128', '2026-03-09T05:21:01.962743+00:00'),
  ('triagemcp-pe-file-analysis', 'TriageMCP (PE File Analysis)', 'TriageMCP is a server that enables LLMs to perform basic static analysis of PE (Portable Executable) files. It integrates with multiple security tools including detect-it-easy, YARA, capa, floss, and UPX to extract critical information such as import/export tables, section details, metadata, strings, and capabilities. The implementation provides tools for calculating file hashes, analyzing PE structures, scanning with YARA rules, unpacking UPX-compressed executables, and identifying malware capabilities - making it particularly valuable for security analysts who need to quickly triage suspicious Windows executables without manual tool interaction.', '@eversinc33', 'ai-ml', 'Unknown', 76, 'https://github.com/eversinc33/triagemcp', NULL, 0, 'https://github.com/eversinc33.png?size=128', '2026-03-09T05:21:01.962795+00:00'),
  ('everyrow', 'Everyrow', 'AI-powered dataframe operations for transforming, deduplicating, merging, ranking, and screening data with natural language. Built on the Everyrow API, it provides intelligent pandas dataframe operations using qualitative criteria. Requires an EVERYROW_API_KEY from everyrow.io.', '@futuresearch', 'ai-ml', 'Unknown', 17, 'https://github.com/futuresearch/everyrow-sdk/tree/HEAD/everyrow-mcp', NULL, 0, 'https://github.com/futuresearch.png?size=128', '2026-03-09T05:21:01.962823+00:00'),
  ('openapi-proxy', 'OpenAPI Proxy', 'Loads OpenAPI or Swagger specifications from URLs or local files at startup and dynamically generates one tool per API endpoint with full Zod schema validation. Forwards tool calls as HTTP requests to the configured backend API using Streamable HTTP transport. Supports endpoint filtering via include and exclude lists, correlation ID tracking for request logging, and configurable HTML-to-Markdown conversion for response processing. Deployable as a Docker container with pre-built images available on Docker Hub.', '@evilfreelancer', 'cloud', 'Unknown', 9, 'https://github.com/evilfreelancer/openapi-to-mcp', NULL, 0, 'https://github.com/evilfreelancer.png?size=128', '2026-03-09T05:21:01.962844+00:00'),
  ('evolution-whatsapp-api', 'Evolution WhatsApp API', 'A WhatsApp integration server that connects AI assistants to the Evolution API, enabling management of WhatsApp instances and messaging capabilities. This implementation provides tools for creating and managing WhatsApp instances, sending various message types (text, media, stickers, polls, buttons), retrieving contacts and group information, and configuring webhooks. Built with TypeScript and Bun, it uses the Model Context Protocol to expose WhatsApp functionality as tools that can be called programmatically, making it valuable for automated customer service, chatbots, and messaging workflows.', '@aiteks-ltda', 'development', 'Unknown', 25, 'https://github.com/aiteks-ltda/mcp-evolution-whatsapp-api', NULL, 0, 'https://github.com/aiteks-ltda.png?size=128', '2026-03-09T05:21:01.962964+00:00'),
  ('rosetta', 'Rosetta', 'Rosetta is an Excel translation tool that converts text in spreadsheet files to different languages using Claude. It preserves formatting, formulas, merged cells, charts, images, dropdown menus, and rich text styling. The MCP server allows Claude Desktop to translate Excel files directly through natural language commands, supporting features like sheet selection, domain-specific context, and batch processing.', '@ewalid', 'ai-ml', 'Unknown', 2, 'https://github.com/ewalid/rosetta', NULL, 0, 'https://github.com/ewalid.png?size=128', '2026-03-09T05:21:01.962997+00:00'),
  ('exa-web-search', 'Exa Web Search', 'This Exa MCP server, developed by exa-labs, provides an interface for AI assistants like Claude to perform web searches using Exa''s search API. It enables AI agents to query Exa and retrieve structured search results including titles, URLs, and content snippets through a controlled MCP server. Built in TypeScript, the implementation handles API authentication, rate limiting, and error cases. By leveraging Exa''s powerful search capabilities, this server allows AI systems to access real-time web information in a safe and controlled manner. It is particularly useful for AI assistants needing to conduct research, answer questions based on current information, or provide relevant search results to users while maintaining a clear separation between the AI model and external data sources.', '@exa-labs', 'development', 'Unknown', 3947, 'https://github.com/exa-labs/exa-mcp-server', NULL, 0, 'https://github.com/exa-labs.png?size=128', '2026-03-09T05:21:01.963027+00:00'),
  ('exa-ai', 'Exa AI', 'This MCP server provides integration with Exa AI''s search engine for real-time web searching, company research, LinkedIn profile discovery, and deep AI-powered research workflows. Built by dsouza-anush as a Heroku-deployable fork of the original Exa Labs implementation, it offers six specialized tools including web search with live crawling, company information retrieval from business sources, URL content extraction, LinkedIn-specific searches, and an intelligent deep research agent that performs multi-step analysis and synthesis. The implementation features configurable tool selection, comprehensive error handling, request logging, and supports both HTTP and stdio transports, making it valuable for research tasks, business intelligence, competitive analysis, and any use case requiring current web information beyond an AI model''s training data.', '@dsouza-anush', 'productivity', 'Unknown', 1, 'https://github.com/dsouza-anush/exa-mcp-server-heroku', NULL, 0, 'https://github.com/dsouza-anush.png?size=128', '2026-03-09T05:21:01.963076+00:00'),
  ('ohmygpt-flux', 'OhMyGPT Flux', 'OmgFlux MCP Server provides a bridge to the OhMyGPT Flux image generation API, enabling AI assistants to create images based on text prompts. Developed by Exa Labs, it implements a Model Context Protocol server that handles image generation requests with customizable parameters like aspect ratio, safety tolerance, and reference images. The server maintains a cache of recent generations and exposes them as resources, making it particularly useful for workflows requiring high-quality AI image generation directly within conversations without switching contexts.', '@xxpe3', 'ai-ml', 'Unknown', 2, 'https://github.com/xxpe3/omgflux-mcp-server', NULL, 0, 'https://github.com/xxpe3.png?size=128', '2026-03-09T05:21:01.963121+00:00'),
  ('excel-automation', 'Excel Automation', 'This MCP server provides comprehensive Excel file manipulation capabilities through a C++ implementation using OpenXLSX, enabling AI assistants to create, open, edit, and format Excel spreadsheets programmatically. Built with modern C++ and integrated with the cpp-mcp library, it offers extensive functionality including cell value operations, worksheet management, formatting controls (fonts, colors, alignment), row/column operations, range manipulation, and cell merging/unmerging. The implementation wraps OpenXLSX in a clean ExcelOperator class with template-based type safety for different data types, supports both individual cell operations and bulk data operations, and includes advanced styling capabilities for professional spreadsheet creation, making it valuable for automated report generation, data processing workflows, and Excel-based business automation tasks.', '@smilefaace', 'productivity', 'Unknown', 78, 'https://github.com/smilefaace/mcp-excelautocpp', NULL, 0, 'https://github.com/smilefaace.png?size=128', '2026-03-09T05:21:01.963246+00:00'),
  ('excel-data-manager', 'Excel Data Manager', 'MCP Excel Server provides a robust interface for Excel file operations and data analysis through the Model Context Protocol. Developed by yzfly, it enables AI assistants to read, write, and analyze Excel files in various formats (XLSX, CSV, TSV, JSON), offering tools for statistical analysis, data filtering, pivot table creation, and visualization through charts and plots. The server leverages pandas, numpy, matplotlib, and seaborn to perform operations like summary statistics, data quality assessment, and visualization export, making it particularly valuable for data analysis workflows where users need to extract insights from spreadsheets without manual manipulation.', '@yzfly', 'ai-ml', 'Unknown', 83, 'https://github.com/yzfly/mcp-excel-server', 'mcp-excel-server', 7090, 'https://github.com/yzfly.png?size=128', '2026-03-09T05:21:01.963292+00:00'),
  ('things-3', 'Things 3', 'This Things MCP server enables Claude Desktop to interact with the Things 3 task management app, allowing users to create tasks, manage projects, and analyze productivity patterns through natural language. Built with Python and leveraging the Things.py library and URL scheme, it offers two implementation approaches: a standard MCP server and a modern FastMCP version with decorator-based tool registration for better maintainability. The server provides comprehensive task management capabilities including list views, search operations, tag management, and time-based features, making it ideal for users who want AI assistance with their GTD workflows and productivity systems.', '@excelsier', 'productivity', 'Unknown', 32, 'https://github.com/excelsier/things-fastmcp', NULL, 0, 'https://github.com/excelsier.png?size=128', '2026-03-09T05:21:01.963334+00:00'),
  ('terragrunt-documentation', 'Terragrunt Documentation', 'MCP Terragrunt Docs provides a Deno/TypeScript server that exposes Terragrunt documentation and GitHub issues through standardized tools and resources. Built by Excoriate, it fetches content directly from the official Terragrunt GitHub repository, offering tools to list documentation categories, retrieve specific documents, and access open issues. The implementation features robust error handling, fuzzy matching for user queries, and normalized responses, making it valuable for developers seeking contextual information about Terragrunt configuration, features, and known issues without leaving their AI assistant workflow.', '@excoriate', 'development', 'Unknown', 21, 'https://github.com/excoriate/mcp-terragrunt-docs', NULL, 0, 'https://github.com/excoriate.png?size=128', '2026-03-09T05:21:01.963358+00:00'),
  ('executeautomation-database-server', 'ExecuteAutomation Database Server', 'ExecuteAutomation Database Server is an MCP server that provides AI assistants with access to SQLite and SQL Server databases. Developed by ExecuteAutomation, this TypeScript implementation enables database schema inspection and SQL query execution through nine core tools including read/write queries, schema management, and data export capabilities. The server features a modular adapter-based architecture that abstracts database-specific implementations, making it particularly useful for data analysis, database management, and business intelligence workflows where AI assistants need direct database interaction without exposing raw credentials.', '@executeautomation', 'databases', 'Unknown', 315, 'https://github.com/executeautomation/mcp-database-server', NULL, 0, 'https://github.com/executeautomation.png?size=128', '2026-03-09T05:21:01.963370+00:00'),
  ('polyagent-claude-code-agents', 'Polyagent (Claude Code Agents)', 'Polyagent MCP bridges Claude Code''s agent definitions to any MCP client, enabling AI coding assistants like Codex and Gemini CLI to access Claude-style specialized agents. Built by Andrew Konstantinov using FastMCP, it automatically discovers agent files with YAML front matter containing metadata like name, description, model, and tools, then exposes them as MCP resources and prompts. The implementation includes a hybrid YAML parser that gracefully handles both valid YAML and malformed YAML that Claude Code sometimes generates (like unquoted values with colons and literal escape sequences), ensuring compatibility with real-world agent files. Valuable for teams wanting to share and reuse Claude Code agents across different AI development environments without being locked into a single platform.', '@execveat', 'development', 'Unknown', 2, 'https://github.com/execveat/polyagent-mcp', NULL, 0, 'https://github.com/execveat.png?size=128', '2026-03-09T05:21:01.963431+00:00'),
  ('steam', 'Steam', 'This MCP server implementation provides integration with the Steam Web API, allowing AI assistants to access Steam user data, game information, and other Steam-related functionalities. Built using Spring Boot and the Steam Web API Java wrapper, it offers a streamlined interface for querying Steam data. The server is designed for use cases such as analyzing gaming habits, providing game recommendations, or integrating Steam user profiles into AI-assisted applications.', '@exi', 'ai-ml', 'Unknown', 1, 'https://github.com/exi/mcp-steam', NULL, 0, 'https://github.com/exi.png?size=128', '2026-03-09T05:21:01.963470+00:00'),
  ('exoquery', 'ExoQuery', 'ExoQuery is a Kotlin Multiplatform Language-Integrated SQL querying system that validates and executes queries at compile time. The MCP server provides access to ExoQuery documentation, validates Kotlin SQL code against a real compiler, and executes queries in SQLite. Helps AI assistants generate correct ExoQuery syntax by providing real-time compilation feedback and documentation lookup.', '@unknown', 'databases', 'Unknown', 0, 'https://exoquery.com', NULL, 0, NULL, '2026-03-09T05:21:01.963483+00:00'),
  ('exotel', 'Exotel', 'Exotel MCP server implementation that provides AI assistants with comprehensive telecommunications capabilities through the Exotel API, including SMS messaging with DLT compliance, voice calling, call flow management, and bulk communication operations. Built with Spring Boot and Java, the server features callback handling for delivery status tracking, database persistence for communication logs, and integrated audio playback tools for quick media testing. The implementation supports both individual and bulk messaging workflows, call connection between numbers, number metadata lookup, and real-time status monitoring, making it valuable for customer communication automation, marketing campaigns, and building AI assistants that need programmatic access to enterprise telephony services.', '@exotel', 'databases', 'Unknown', 3, 'https://github.com/exotel/exotelmcp', NULL, 0, 'https://github.com/exotel.png?size=128', '2026-03-09T05:21:01.963500+00:00'),
  ('file-merger', 'File Merger', 'Simple utility to combine multiple files into one. Fast, secure, and easy to use.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('google-search', 'Google Search', 'Official Google Search MCP server that provides access to Google''s Custom Search API with automatic API key rotation and intelligent quota management. The implementation supports multiple Google API keys to increase daily search limits beyond the standard 100 free searches per day, automatically rotating between available keys and tracking usage across a global configuration file stored in the user''s home directory. Built with TypeScript and featuring comprehensive search parameters including language targeting, geolocation filtering, date restrictions, file type searches, and site-specific queries, it''s designed for applications requiring high-volume web search capabilities with built-in resilience against quota exhaustion through its multi-key rotation system.', '@fabien-desablens', 'development', 'Unknown', 1, 'https://github.com/fabien-desablens/google-search-mcp', '@kyaniiii/google-search-mcp', 2050, 'https://github.com/fabien-desablens.png?size=128', '2026-03-09T05:21:01.964051+00:00'),
  ('tana-codemode', 'Tana Codemode', 'Enables dynamic TypeScript code execution against Tana''s Local API for flexible knowledge management operations including workspaces, nodes, tags, search, and field management.', '@fabiogaliano', 'development', 'Unknown', 3, 'https://github.com/fabiogaliano/tana-mcp-codemode', NULL, 0, 'https://github.com/fabiogaliano.png?size=128', '2026-03-09T05:21:01.964066+00:00'),
  ('ai-conversation-logger', 'AI Conversation Logger', 'AI Conversation Logger MCP server that automatically captures and organizes AI interactions across multiple platforms including Claude Desktop and Cursor, storing conversations in structured markdown format with project-based organization and automatic tagging. The implementation features intelligent project detection through common indicators like package.json or .git directories, creates daily log files with conversation metadata, and includes hook-based automation that triggers logging when conversations end. Built with TypeScript and designed for developers who want persistent conversation history without manual logging, it supports both local project-based storage and global home directory fallbacks, making it valuable for maintaining context across development sessions and tracking AI-assisted coding workflows over time.', '@fablefang', 'development', 'Unknown', 1, 'https://github.com/fablefang/ai-conversation-logger-mcp', NULL, 0, 'https://github.com/fablefang.png?size=128', '2026-03-09T05:21:01.964097+00:00'),
  ('factor-protocol', 'Factor Protocol', 'Enables AI agents to interact with Factor Protocol''s DeFi vault infrastructure across Arbitrum, Base, and Ethereum networks through specialized tools for vault creation, asset management, and strategy execution. Provides secure wallet management with AES-256-GCM encryption, simulation mode for risk-free testing, and integration with Foundry for advanced blockchain operations. Supports complex DeFi workflows including multi-step strategy building using protocol adapters (Aave, Uniswap, Morpho), automated vault operations, and real-time transaction monitoring.', '@factordao', 'development', 'Unknown', 1, 'https://github.com/factordao/factor-mcp', NULL, 0, 'https://github.com/factordao.png?size=128', '2026-03-09T05:21:01.964144+00:00'),
  ('image-edit-rmcp', 'Image Edit RMCP', 'Rust-based MCP server that integrates with ModelScope APIs to provide comprehensive image editing capabilities including cropping, rotation, OCR text extraction, object detection, and image generation. Features caching optimization and a web interface for accessing image editing functions.', '@factruesolin', 'search', 'Unknown', 1, 'https://github.com/factruesolin/image-edit-rmcp', NULL, 0, 'https://github.com/factruesolin.png?size=128', '2026-03-09T05:21:01.964186+00:00'),
  ('factsets', 'Factsets', 'Provides a local knowledge base system for agents with persistent storage across sessions. Manages facts, resources, skills, and execution logs with automatic staleness detection and tag-based organization. All data is stored in SQLite for durability.', '@joshua-auchincloss', 'databases', 'Unknown', 1, 'https://github.com/joshua-auchincloss/factsets', NULL, 0, 'https://github.com/joshua-auchincloss.png?size=128', '2026-03-09T05:21:01.964197+00:00'),
  ('harmonyos', 'HarmonyOS', 'MCP server for HarmonyOS development - interact with projects, devices, and applications', '@fadinglight9291117', 'development', 'Unknown', 1, 'https://github.com/fadinglight9291117/mcp-harmonyos', NULL, 0, 'https://github.com/fadinglight9291117.png?size=128', '2026-03-09T05:21:01.964210+00:00'),
  ('google-classroom', 'Google Classroom', 'A Google Classroom integration server that enables AI assistants to access and interact with classroom data through the MCP protocol. The server provides tools for retrieving courses, course details, announcements, and assignments using Google''s Classroom API. It handles OAuth2 authentication flow, token management, and permission scopes to securely access user data. The implementation is particularly useful for students and educators who want to check their Google Classroom information, track assignments, and view course announcements directly through AI assistant conversations without switching contexts.', '@faizan45640', 'ai-ml', 'Unknown', 2, 'https://github.com/faizan45640/google-classroom-mcp-server', NULL, 0, 'https://github.com/faizan45640.png?size=128', '2026-03-09T05:21:01.964270+00:00'),
  ('geartrade-technical-analysis', 'GearTrade Technical Analysis', 'GearTrade is a comprehensive technical analysis toolkit for cryptocurrency trading that integrates with blockchain data sources to provide market analysis capabilities. The server offers technical indicators including RSI, EMA, MACD, Bollinger Bands, ATR, and ADX, along with volume analysis tools for buy/sell pressure and liquidity zones. It supports multi-timeframe analysis, Fibonacci retracements, order book depth analysis, and risk management calculations for position sizing and stop loss determination, designed for traders developing algorithmic strategies and conducting market research.', '@fajararrizki', 'development', 'Unknown', 2, 'https://github.com/fajararrizki/mcp-technical-analysis', NULL, 0, 'https://github.com/fajararrizki.png?size=128', '2026-03-09T05:21:01.964327+00:00'),
  ('ai-bridge', 'AI Bridge', 'Secure MCP server by fakoli that bridges Claude Code with OpenAI and Google Gemini APIs, featuring multi-layer security protection including prompt injection detection, content filtering, input sanitization, and configurable rate limiting. The implementation provides granular security controls with basic/moderate/strict modes, supports all major OpenAI models (GPT-4o, o1, o3-mini) and Gemini variants (1.5 Pro/Flash), and includes performance optimizations like pattern caching and early termination for fast validation. Built with comprehensive error handling, structured logging, and extensive test coverage, it serves developers who need secure AI API access with enterprise-grade protection against malicious prompts, content policy violations, and API abuse while maintaining flexibility for legitimate use cases.', '@fakoli', 'development', 'Unknown', 3, 'https://github.com/fakoli/mcp-ai-bridge', NULL, 0, 'https://github.com/fakoli.png?size=128', '2026-03-09T05:21:01.964386+00:00'),
  ('temporal-terraform-orchestrator', 'Temporal Terraform Orchestrator', 'Orchestrates multi-workspace Terraform deployments using Temporal workflows for reliable dependency resolution. Builds dependency DAGs across workspaces, executes them in correct order, propagates outputs between workspaces, runs independent workspaces in parallel, and provides automatic retries and failure recovery through Temporal''s durability features.', '@fakoli', 'cloud', 'Unknown', 2, 'https://github.com/fakoli/ai-driven-temporal-to-iac', NULL, 0, 'https://github.com/fakoli.png?size=128', '2026-03-09T05:21:01.964406+00:00'),
  ('gemini-data-analysis-research', 'Gemini Data Analysis & Research', 'Gemini Data Analysis Research MCP Server provides a bridge to Google''s Gemini AI model, enabling data analysis, email communication, and detailed thinking process generation. This TypeScript implementation offers three main tools: analyze-data for processing Excel/CSV files with statistical analysis and visualization, send-email for dispatching messages with AI-generated subject lines, and generate-thinking for producing comprehensive reasoning outputs. The server handles file processing, data visualization, and AI prompt engineering behind the scenes, making it particularly valuable for researchers and analysts who need to extract insights from datasets, communicate findings via email, or document AI reasoning processes.', '@falahgs', 'development', 'Unknown', 4, 'https://github.com/falahgs/gemini-data-analysis-research-mcp-server', NULL, 0, 'https://github.com/falahgs.png?size=128', '2026-03-09T05:21:01.964438+00:00'),
  ('fal-ai-video-generator', 'Fal.ai Video Generator', 'This MCP server provides a bridge to fal.ai''s video generation models (Luma Ray2 and Kling v1.6 Pro), enabling AI assistants to create videos from text prompts and/or images. It offers two main tools: ''generate-video'' for creating videos with customizable parameters like aspect ratio, resolution, and duration, and ''check-video-status'' for monitoring ongoing generation requests. The implementation handles API authentication, request formatting, and error handling, making it easy for AI systems to leverage powerful video generation capabilities without managing the underlying API complexities.', '@el-el-san', 'ai-ml', 'Unknown', 3, 'https://github.com/el-el-san/fal-mcp-server', NULL, 0, 'https://github.com/el-el-san.png?size=128', '2026-03-09T05:21:01.964529+00:00'),
  ('falkordb', 'FalkorDB', 'FalkorDB MCP Server provides a bridge between AI models and FalkorDB graph databases, enabling natural language querying of graph data. Built with TypeScript and Express, it implements the Model Context Protocol to translate requests into FalkorDB queries and format responses according to MCP standards. The server features authentication via API keys, connection management for multiple FalkorDB instances, and endpoints for executing queries, retrieving metadata, and listing available graphs. It''s particularly valuable for AI applications that need to analyze relationships in graph data, such as knowledge graphs, recommendation systems, or network analysis.', '@falkordb', 'databases', 'Unknown', 31, 'https://github.com/falkordb/falkordb-mcpserver', NULL, 0, 'https://github.com/falkordb.png?size=128', '2026-03-09T05:21:01.964585+00:00'),
  ('queryweaver', 'QueryWeaver', 'QueryWeaver is a text-to-SQL system that combines FastAPI with graph-powered schema understanding using FalkorDB to enable natural language database querying. The implementation features PostgreSQL and MySQL schema loaders that extract database structures into graph representations with vector embeddings, multi-agent query processing pipeline with analysis, relevancy checking, and response formatting agents, and OAuth-based authentication with API token management. Built with a modular architecture supporting both web interface and MCP protocol integration, it enables use cases like business intelligence queries, database exploration, and automated report generation by translating conversational questions into accurate SQL queries while maintaining context across query sessions.', '@falkordb', 'databases', 'Unknown', 717, 'https://github.com/falkordb/queryweaver', NULL, 0, 'https://github.com/falkordb.png?size=128', '2026-03-09T05:21:01.964598+00:00'),
  ('ms-word', 'MS Word', 'This MCP server implementation, developed for Microsoft Office document manipulation, provides a Python-based interface for AI assistants to interact with Word documents. Built using libraries like python-docx and leveraging the Model Context Protocol, it offers tools for reading, writing, and editing .docx files, including handling of text, tables, and images. The implementation focuses on efficient document processing, making it easier for AI models to analyze and generate content in Word format. It''s particularly useful for automating document creation, content analysis, or report generation tasks that require working with structured Word documents, enabling AI to manipulate Office files without needing deep knowledge of the underlying file formats.', '@famano', 'productivity', 'Unknown', 33, 'https://github.com/famano/mcp-server-office', NULL, 0, 'https://github.com/famano.png?size=128', '2026-03-09T05:21:01.964643+00:00'),
  ('perplexity-ai', 'Perplexity AI', 'Perplexity MCP Server provides Claude Desktop with direct access to Perplexity AI''s language models through a lightweight proxy implementation. It offers two main tools: perplexity_ask for single questions using the llama-3.1-sonar-small-128k-online model with web search capabilities, and perplexity_chat for multi-turn conversations using mixtral-8x7b-instruct. The server communicates via stdio transport, requires only a Perplexity API key for authentication, and is designed for easy installation through npm or direct execution, making it ideal for users who need to augment Claude with Perplexity''s specialized search and reasoning capabilities.', '@family-it-guy', 'communication', 'Unknown', 17, 'https://github.com/family-it-guy/perplexity-mcp', NULL, 0, 'https://github.com/family-it-guy.png?size=128', '2026-03-09T05:21:01.964680+00:00'),
  ('u-he-preset-randomizer', 'u-he Preset Randomizer', 'Enables AI assistants to interact with u-he synthesizer preset libraries through natural conversation. Search and browse presets, generate random patches based on statistical distributions from your library, create variations of existing presets, and merge multiple presets together. Works with all u-he synthesizers including Diva, Repro, Zebra, and Hive across all platforms.', '@fannon', 'ai-ml', 'Unknown', 24, 'https://github.com/fannon/u-he-preset-randomizer', NULL, 0, 'https://github.com/fannon.png?size=128', '2026-03-09T05:21:01.964714+00:00'),
  ('redis', 'Redis', 'This Redis MCP server, created by fahrankaz, provides a bridge between Model Context Protocol clients and Redis databases. It supports core Redis operations like GET, SET, SADD, SMEMBERS, ZADD, ZRANGE, ZRANGEBYSCORE, ZREM, HGET, HGETALL, HMSET, DEL, and SCAN. The implementation is designed as a lightweight CLI tool that starts a Node.js server, making it easy to integrate with existing MCP setups. It''s particularly useful for scenarios requiring fast, in-memory data storage and retrieval within AI workflows, such as caching intermediate results or maintaining session state across multiple AI interactions.', '@farhankaz', 'databases', 'Unknown', 6, 'https://github.com/farhankaz/redis-mcp', 'redis-mcp', 4008, 'https://github.com/farhankaz.png?size=128', '2026-03-09T05:21:01.964725+00:00'),
  ('image-processor', 'Image Processor', 'An MCP server that enables AI assistants to fetch, process, and display images from both URLs and local files. Built by FarhaParveen919, this implementation uses FastMCP to expose a tool that handles image retrieval, automatic compression of large images while maintaining quality, and proper formatting for LLM consumption. The server intelligently processes multiple image sources concurrently, handles various image formats, and includes robust error handling and logging - making it particularly valuable for applications where AI assistants need to work with visual content from diverse sources.', '@ia-programming', 'ai-ml', 'Unknown', 17, 'https://github.com/ia-programming/mcp-images', NULL, 0, 'https://github.com/ia-programming.png?size=128', '2026-03-09T05:21:01.964766+00:00'),
  ('data-gov-my', 'Data.gov.my', 'DataGovMY MCP Server provides access to Malaysia''s open government data through a set of specialized tools. Developed by Farid Yusof, it integrates with the data.gov.my API to retrieve various datasets including population statistics, birth records, fuel prices, household income, and vehicle registration information. Each tool implements specific filtering capabilities that allow users to query data by parameters such as date, location, demographics, and other dataset-specific attributes. The server handles API requests, parameter validation, and response formatting, making it particularly valuable for researchers, analysts, and applications requiring access to official Malaysian government statistics.', '@faridyusof727', 'search', 'Unknown', 9, 'https://github.com/faridyusof727/datagovmy-mcp', NULL, 0, 'https://github.com/faridyusof727.png?size=128', '2026-03-09T05:21:01.964825+00:00'),
  ('azure-ai-search', 'Azure AI Search', 'The Azure AI Search MCP server connects Claude Desktop to Azure AI Search services, enabling users to query their search indexes using three distinct methods: keyword search for exact lexical matches, vector search for semantic similarity using embeddings, and hybrid search combining both approaches. Built with Python using the FastMCP framework, it handles authentication through Azure credentials, formats search results in readable markdown, and provides detailed error handling. This implementation is particularly valuable for users who need to retrieve information from their Azure AI Search indexes directly within Claude conversations, making it ideal for research, content discovery, and knowledge management workflows.', '@farzad528', 'cloud', 'Unknown', 54, 'https://github.com/farzad528/mcp-server-azure-ai-agents', NULL, 0, 'https://github.com/farzad528.png?size=128', '2026-03-09T05:21:01.964895+00:00'),
  ('can-bus-simulator', 'CAN Bus Simulator', 'Provides a bridge between CAN bus networks and virtual ECU simulation through DBC (Database CAN) file decoding. Features a complete ECU simulator that generates realistic automotive signals (engine status, ABS, airbag, body control) with configurable transmission rates, plus OBD-II diagnostic request/response handling. Exposes tools for reading CAN frames, decoding signals using DBC definitions, filtering by arbitration ID or signal name, and monitoring specific signals over time, making it valuable for automotive diagnostics, vehicle data analysis, and testing CAN-based applications.', '@farzadnadiri', 'databases', 'Unknown', 3, 'https://github.com/farzadnadiri/mcp-can', NULL, 0, 'https://github.com/farzadnadiri.png?size=128', '2026-03-09T05:21:01.964909+00:00'),
  ('code-line-counter', 'Code Line Counter', 'This MCP server provides code line counting functionality with persistent data storage, tracking total lines, code lines, comment lines, and empty lines across different file types with timestamped entries stored in JSON format. Built with Node.js and the Model Context Protocol SDK, it features a simple architecture with data persistence in a local JSON file and appears designed for development workflow integration where tracking code metrics over time is valuable. The implementation focuses on basic line counting statistics and historical data retention, making it useful for developers monitoring codebase growth, project managers tracking development progress, or automated build systems that need to log code metrics as part of continuous integration pipelines.', '@fashionzzz', 'development', 'Unknown', 1, 'https://github.com/fashionzzz/code-line-counter-mcp', NULL, 0, 'https://github.com/fashionzzz.png?size=128', '2026-03-09T05:21:01.964938+00:00'),
  ('fastalert', 'FastAlert', 'Official MCP server for FastAlert, providing tools to list channels and send notifications.', '@fastalertnow', 'development', 'Unknown', 0, 'https://github.com/fastalertnow/mcp-server', NULL, 0, 'https://github.com/fastalertnow.png?size=128', '2026-03-09T05:21:01.964979+00:00'),
  ('fastmcp-supply-chain-optimizer', 'FastMCP Supply Chain Optimizer', 'FastMCP server implementation by ANSH-RIYAL that demonstrates real-time supply chain optimization using Google Gemini AI for intelligent decision-making across inventory management, warehouse transfers, and reorder recommendations. The implementation processes supply chain events (demand spikes, delays, cost increases) from CSV data through a Flask web interface, using MCP tools for inventory status checking, stock transfer calculations, stockout predictions, and automated reorder suggestions, with Gemini AI analyzing events and executing parallel tool calls for optimization decisions. Built with a complete web dashboard featuring terminal output and action logging, it serves as both a functional supply chain management system and a demonstration of how MCP can integrate AI-powered decision-making with real-time business operations, making it valuable for supply chain managers, logistics coordinators, and developers building AI-driven inventory optimization systems.', '@ansh-riyal', 'development', 'Unknown', 5, 'https://github.com/ansh-riyal/fastmcp', NULL, 0, 'https://github.com/ansh-riyal.png?size=128', '2026-03-09T05:21:01.965102+00:00'),
  ('fastn', 'Fastn', 'Fastn is a dynamic tool registration and execution server that enables seamless integration with services like Claude.ai and Cursor.ai. It provides a unified platform for connecting various services through a simple setup process, with robust logging and error handling capabilities. The server supports integration with platforms like Slack, Notion, and HubSpot, offering developers a flexible API-driven solution for real-time operations.', '@fastnai', 'communication', 'Unknown', 13, 'https://github.com/fastnai/fastn-mcp', NULL, 0, 'https://github.com/fastnai.png?size=128', '2026-03-09T05:21:01.965130+00:00'),
  ('macos-mail-mcp-bridge', 'macOS Mail MCP Bridge', 'Provides direct access to macOS Mail emails by reading .emlx files stored in the local Mail database. Offers tools for retrieving email file paths by Message-ID, finding all emails in a conversation thread, parsing individual email content, and reading entire email conversations. Enables email analysis, conversation summarization, and automated processing workflows without requiring Mail.app to be running.', '@fatbobman', 'databases', 'Unknown', 12, 'https://github.com/fatbobman/mail-mcp-bridge', NULL, 0, 'https://github.com/fatbobman.png?size=128', '2026-03-09T05:21:01.965141+00:00'),
  ('io-github-agencyenterprise-fathom-mcp-server', 'io.github.agencyenterprise/fathom-mcp-server', 'Connect Claude to Fathom meeting recordings, transcripts, and summaries', '@agencyenterprise', 'development', 'Unknown', 8, 'https://github.com/agencyenterprise/fathom-mcp-server', NULL, 0, 'https://github.com/agencyenterprise.png?size=128', '2026-03-09T05:21:01.965157+00:00'),
  ('windows-debugger', 'Windows Debugger', 'A Windows debugger implementation built with C++/CLI that provides tools for reverse engineering and malware analysis. Features a native debugging engine with breakpoint management, memory inspection, disassembly using the Zydis library, and PE file analysis capabilities. Includes both console and UI dispatchers for different interaction modes, with example crackme sessions demonstrating its use for finding valid serial keys and analyzing executable protection schemes. Designed for professional reverse engineers who need programmatic access to low-level debugging functionality.', '@fatmike-gh', 'development', 'Unknown', 9, 'https://github.com/fatmike-gh/mcpdebugger', NULL, 0, 'https://github.com/fatmike-gh.png?size=128', '2026-03-09T05:21:01.965184+00:00'),
  ('code-sage', 'Code Sage', 'Code Sage is a high-performance semantic code search server written in Rust that combines BM25 keyword search with vector embeddings using RRF reranking for hybrid search capabilities. The implementation uses AST-based chunking via tree-sitter to intelligently split code into semantic units (functions, classes, methods) across 60+ programming languages and file types, with character-based fallback for unsupported formats. Built with embedded storage (USearch for vectors, Tantivy for full-text, Sled for metadata) requiring zero external dependencies, it supports multiple embedding providers including OpenAI, LM Studio, and Ollama, with automatic .gitignore respect and custom file extension support. The server exposes tools for code analysis, natural language search, index management, and status checking, making it valuable for code exploration, documentation generation, and development workflows requiring semantic understanding of large codebases.', '@faxioman', 'development', 'Unknown', 5, 'https://github.com/faxioman/code-sage', NULL, 0, 'https://github.com/faxioman.png?size=128', '2026-03-09T05:21:01.965324+00:00'),
  ('venice-browser', 'Venice Browser', 'Browser automation MCP server implementation by Fayeblade1488 that provides AI assistants with web navigation capabilities through Playwright, supporting both line-delimited and content-length JSON-RPC framing protocols. The implementation features headless and headed browser modes, persistent session state management, configurable navigation timeouts, and support for Chromium, Firefox, and WebKit browsers. Built with robust error handling and proper subprocess management, it includes comprehensive testing examples and troubleshooting documentation for protocol corruption and asyncio edge cases. Designed for AI workflows requiring web browsing capabilities like automated testing, data extraction, or interactive web tasks where maintaining browser state across sessions is essential.', '@fayeblade1488', 'development', 'Unknown', 1, 'https://github.com/fayeblade1488/fayeblade_mcp', NULL, 0, 'https://github.com/fayeblade1488.png?size=128', '2026-03-09T05:21:01.965357+00:00'),
  ('flight-search', 'Flight Search', 'Flight Search MCP server that provides AI assistants with real-time flight search capabilities through multiple flight data APIs. Built with TypeScript and FastMCP, it offers tools for searching cheapest flights and nonstop routes, smart calendar-based price discovery across flexible date ranges, comprehensive travel reference data including airports and airlines, flight discovery for popular routes and alternatives, and direct booking URLs with partner tracking. The implementation supports one-click installation via Smithery and manual configuration across major IDEs like Cursor, VS Code, Windsurf, and Cline, making it useful for developers building AI-powered travel planning applications, automated booking systems, and travel recommendation engines without requiring direct API integration knowledge.', '@unknown', 'development', 'Unknown', 0, 'https://flights.fctolabs.com/', NULL, 0, NULL, '2026-03-09T05:21:01.965387+00:00'),
  ('gitingest', 'GitIngest', 'GitIngest MCP provides AI assistants with direct access to GitHub and GitLab repositories, enabling code exploration and analysis without context switching. The server exposes tools for searching repositories, viewing file structures, and reading file contents with syntax highlighting support. Built in Rust with a modular architecture, it handles authentication via environment variables for API rate limits, implements intelligent file filtering with customizable ignore patterns, and supports various Git references (branches, tags, commits). This implementation is particularly valuable for developers who need to explore codebases, understand project structures, or reference specific code snippets during AI-assisted programming tasks.', '@fdionisi', 'development', 'Unknown', 0, 'https://github.com/fdionisi/gitingest-mcp', 'gitingest-mcp', 0, 'https://github.com/fdionisi.png?size=128', '2026-03-09T05:21:01.965411+00:00'),
  ('fear-greed-index', 'Fear & Greed Index', 'This MCP server provides AI assistants with real-time access to the CNN Fear & Greed Index for US stock market sentiment analysis, built using TypeScript with the Model Context Protocol SDK and comprehensive market data fetching from CNN''s production API. The implementation offers a single tool that retrieves the current composite Fear & Greed Index score (0-100 scale) along with seven individual market indicators including S&P 500 momentum, stock price strength and breadth, put/call options ratios, VIX volatility measures, junk bond demand, and safe haven demand, with historical comparisons for previous close, week, month, and year periods. Built with user-agent rotation for reliable data access, Zod schema validation for type safety, and flexible deployment options supporting both stdio and HTTP/SSE transports, it serves financial analysts needing conversational access to market sentiment data, traders requiring AI-assisted market psychology insights, and developers building financial applications that integrate real-time fear and greed metrics into automated decision-making workflows.', '@ycjcl868', 'development', 'Unknown', 4, 'https://github.com/ycjcl868/mcp-server-fear-greed', 'mcp-server-fear-greed', 550, 'https://github.com/ycjcl868.png?size=128', '2026-03-09T05:21:01.965481+00:00'),
  ('jampp-reporting', 'Jampp Reporting', 'Jampp Reporting MCP Server provides direct access to the Jampp Reporting API through a Node.js implementation. It enables Claude to retrieve campaign performance metrics including spend, impressions, clicks, and installs across specified date ranges. The server handles OAuth authentication, token management, and GraphQL query execution behind the scenes, making it easy for marketers and analysts to access advertising campaign data without dealing with API authentication complexities. Developed by FeedMob, it''s particularly valuable for users who need to analyze ad performance trends or generate campaign spending reports.', '@feed-mob', 'ai-ml', 'Unknown', 3, 'https://github.com/feed-mob/fm-mcp-servers/tree/HEAD/src/jampp-reporting', '@feedmob/jampp-reporting', 6131, 'https://github.com/feed-mob.png?size=128', '2026-03-09T05:21:01.965525+00:00'),
  ('kayzen-analytics', 'Kayzen Analytics', 'Kayzen Analytics MCP Server enables Claude Desktop to access and analyze marketing campaign data from the Kayzen API. Developed by FeedMob, it provides tools for listing available reports and fetching report results with date filtering capabilities, along with a specialized prompt for analyzing performance metrics, trends, and optimization opportunities. The implementation authenticates with the Kayzen API using environment variables and handles token management, making it particularly valuable for marketers who need to access campaign analytics data directly within their AI assistant conversations.', '@springwq', 'ai-ml', 'Unknown', 1, 'https://github.com/springwq/kayzen-mcp', '@feedmob-ai/kayzen-mcp', 539, 'https://github.com/springwq.png?size=128', '2026-03-09T05:21:01.965571+00:00'),
  ('kayzen-reporting', 'Kayzen Reporting', 'Kayzen Reporting MCP Server provides a Node.js implementation for accessing the Kayzen Reporting API through Claude Desktop. Developed by FeedMob, this server enables AI assistants to retrieve advertising campaign data through two main tools: listing available reports and fetching detailed report results with optional date filtering. The implementation handles authentication through username/password credentials and manages token-based API access, making it valuable for marketers and analysts who need to analyze advertising performance data from Kayzen''s programmatic advertising platform without manual API interaction.', '@feed-mob', 'ai-ml', 'Unknown', 3, 'https://github.com/feed-mob/fm-mcp-servers/tree/HEAD/src/kayzen-reporting', '@feedmob/kayzen-reporting', 5628, 'https://github.com/feed-mob.png?size=128', '2026-03-09T05:21:01.965613+00:00'),
  ('singular-reporting', 'Singular Reporting', 'Singular Reporting MCP Server provides a Node.js implementation for accessing Singular''s marketing analytics data through Claude Desktop. Developed by FeedMob, this server enables users to create asynchronous reports with customizable date ranges and source filters, check report status, and download CSV results from Singular''s API. The implementation includes three main tools for report creation, status checking, and downloading, making it useful for marketers who need to analyze campaign performance metrics like impressions, clicks, installs, and costs across different apps and sources.', '@feed-mob', 'ai-ml', 'Unknown', 3, 'https://github.com/feed-mob/fm-mcp-servers/tree/HEAD/src/singular-reporting', '@feedmob/singular-reporting', 5014, 'https://github.com/feed-mob.png?size=128', '2026-03-09T05:21:01.965658+00:00'),
  ('fegis-schema-driven-memory', 'FEGIS (Schema-Driven Memory)', 'FEGIS is a schema-driven memory engine that gives LLMs cognitive tools and structured persistent memory. Developed by Perry Golden, it uses Qdrant vector database with FastEmbed for efficient storage and retrieval of information based on predefined archetypes. The system allows models to create, store, and search through structured cognitive artifacts like thoughts, reflections, and decisions using a facet-based organization system. This implementation enables LLMs to maintain context across conversations, build knowledge bases with qualitative dimensions, and create meaningful connections between related ideas - making it particularly valuable for applications requiring persistent memory and structured thinking.', '@p-funk', 'databases', 'Unknown', 22, 'https://github.com/p-funk/fegis', NULL, 0, 'https://github.com/p-funk.png?size=128', '2026-03-09T05:21:01.965669+00:00'),
  ('e2b-code-sandbox', 'E2B Code Sandbox', 'Integrates with E2B''s cloud sandbox infrastructure to provide secure, isolated code execution environments. Offers tools for creating and managing sandboxes with customizable timeouts and templates, executing Python code using Jupyter Notebook syntax, and running shell commands. Useful for AI applications that need to safely execute user-generated code, perform data analysis, or run system commands without compromising the host environment.', '@feifeigood', 'development', 'Unknown', 1, 'https://github.com/feifeigood/code-sandbox-mcp', NULL, 0, 'https://github.com/feifeigood.png?size=128', '2026-03-09T05:21:01.965735+00:00'),
  ('ai-hub', 'AI Hub', 'This MCP AI Hub server by Pengfei Ni provides unified access to 100+ AI providers through LiteLLM integration, enabling seamless switching between OpenAI, Anthropic, Google, Azure, AWS Bedrock, and other AI services through a single configuration file. Built with Python using FastMCP and featuring comprehensive model management with YAML-based configuration, environment variable support, and robust error handling, it offers three core tools for chatting with models, listing available models, and retrieving model information with support for both string and OpenAI message format inputs. The implementation includes extensive testing coverage, multiple transport options (stdio, SSE, HTTP), and flexible deployment configurations, making it ideal for developers building AI applications that need provider flexibility, organizations wanting to avoid vendor lock-in, and teams requiring centralized AI model management across different services without code changes.', '@feiskyer', 'cloud', 'Unknown', 7, 'https://github.com/feiskyer/mcp-ai-hub', 'mcp-ai-hub', 2301, 'https://github.com/feiskyer.png?size=128', '2026-03-09T05:21:01.965756+00:00'),
  ('spec-coding', 'Spec Coding', 'The SpecCoding MCP Server provides a structured workflow for software development that guides users through five sequential stages: feature definition, requirements gathering, design document creation, task list generation, and task execution. Built in C# with .NET, it manages session state across workflow stages and uses templated prompts to ensure consistent documentation and planning artifacts are created before implementation begins. The server enforces proper workflow progression through stage validation, maintains feature context throughout the process, and generates organized output files including requirements documents in EARS format, comprehensive design documents, and actionable task lists that can be executed by coding agents, making it valuable for teams that want to follow a disciplined approach to feature development with proper documentation and planning.', '@feiyun0112', 'development', 'Unknown', 47, 'https://github.com/feiyun0112/spec-coding-mcp', NULL, 0, 'https://github.com/feiyun0112.png?size=128', '2026-03-09T05:21:01.965809+00:00'),
  ('coverctl', 'Coverctl', 'Coverctl enables AI agents to programmatically interact with Go code coverage analysis. The server exposes tools for running coverage tests, analyzing coverage profiles, and recording coverage metrics. Resources provide access to coverage debt metrics, trends over time, threshold recommendations, and configuration details.', '@felixgeelhaar', 'development', 'Unknown', 0, 'https://github.com/felixgeelhaar/coverctl', NULL, 0, 'https://github.com/felixgeelhaar.png?size=128', '2026-03-09T05:21:01.965886+00:00'),
  ('pubmed-medical-literature-research', 'PubMed Medical Literature Research', 'PubMed MCP server provides tools to search, analyze, and retrieve academic medical literature through the NCBI PubMed database. Built with a robust architecture featuring object-oriented design, advanced error handling with retry mechanisms, and performance monitoring, it enables AI assistants to find articles by topics and researchers, retrieve detailed publication information with formatted citations, and analyze researcher publication statistics. The implementation includes structured API responses with rich metadata, making it valuable for medical researchers, academics, and healthcare professionals who need to efficiently access and analyze scientific literature.', '@felixwu1110', 'databases', 'Unknown', 1, 'https://github.com/felixwu1110/pubmed_mcp', NULL, 0, 'https://github.com/felixwu1110.png?size=128', '2026-03-09T05:21:01.965899+00:00'),
  ('controlapi-openapi', 'ControlAPI OpenAPI', 'Transforms any OpenAPI-compliant REST API into MCP tools by loading schema definitions at runtime. Supports dynamic server switching between API endpoints and variable management for authentication tokens and session data. Enables AI assistants to interact with REST APIs through automatically generated tools without custom implementations.', '@fellowabhi', 'ai-ml', 'Unknown', 4, 'https://github.com/fellowabhi/controlapi-openapi-to-mcp', NULL, 0, 'https://github.com/fellowabhi.png?size=128', '2026-03-09T05:21:01.965934+00:00'),
  ('macos-text-to-speech', 'macOS Text-to-Speech', 'Enables text-to-speech output on macOS using the native ''say'' command for converting messages into audible announcements and status updates.', '@fellowgeek', 'development', 'Unknown', 3, 'https://github.com/fellowgeek/mcp-speak', NULL, 0, 'https://github.com/fellowgeek.png?size=128', '2026-03-09T05:21:01.965991+00:00'),
  ('filesystem-rust', 'Filesystem (Rust)', 'This Rust-based MCP filesystem server, developed by Chris Odom, provides a set of filesystem tools for use with Claude Desktop or other MCP clients. Built using the rpc-router library for JSON-RPC routing, it offers functionality like listing prompts, resources, and tools, as well as executing specific filesystem operations. The server implements security measures by restricting operations to user-defined allowed directories. By abstracting filesystem interactions through a standardized MCP interface, it enables AI systems to safely perform file and directory operations. This implementation is particularly useful for applications requiring controlled filesystem access, facilitating use cases such as AI-assisted file management, automated data processing, and secure document handling within specified directories.', '@texasfortress-ai', 'productivity', 'Unknown', 21, 'https://github.com/texasfortress-ai/rs_filesystem', 'rs_filesystem', 0, 'https://github.com/texasfortress-ai.png?size=128', '2026-03-09T05:21:01.966039+00:00'),
  ('cloudinary', 'Cloudinary', 'This Cloudinary MCP server, developed by felores, enables seamless integration of Cloudinary''s image and video upload functionality into AI-assisted workflows. Built with TypeScript and leveraging the @modelcontextprotocol/sdk, it provides a straightforward interface for uploading media to Cloudinary through Claude Desktop and compatible MCP clients. The implementation supports various upload options including file paths, URLs, and base64 data URIs, along with customizable parameters like resource type, public ID, and tags. It''s particularly useful for AI assistants and developers looking to incorporate on-demand media uploads into their applications, allowing for dynamic content creation and management within Cloudinary''s ecosystem.', '@felores', 'development', 'Unknown', 9, 'https://github.com/felores/cloudinary-mcp-server', NULL, 0, 'https://github.com/felores.png?size=128', '2026-03-09T05:21:01.966096+00:00'),
  ('docs-scraper', 'Docs Scraper', 'Documentation scraping server that enables AI assistants to extract structured content from web-based documentation through multiple crawling strategies. Built with Python and the crawl4ai library, it provides tools for single URL crawling, multi-URL batch processing, sitemap-based crawling, and menu-driven navigation extraction, with features like rate limiting, concurrent request handling, and robots.txt compliance. The implementation is particularly valuable for users who need to ingest documentation into AI systems while respecting site access policies and maintaining clean markdown output.', '@felores', 'ai-ml', 'Unknown', 2, 'https://github.com/felores/docs_scraper_mcp', NULL, 0, 'https://github.com/felores.png?size=128', '2026-03-09T05:21:01.966140+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('placid-image-generator', 'Placid Image Generator', 'This Placid.app MCP server, developed by Felipe Restrepo, integrates with Placid''s API to provide image generation capabilities for AI workflows. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers tools for listing templates and generating creatives using dynamic content. The implementation focuses on secure API token management, error handling, and type safety, making it accessible for AI assistants or applications needing to create visual content programmatically. It''s particularly useful for tasks like social media post creation, marketing material generation, or dynamic image production, enabling quick access to Placid''s template-based image creation without requiring deep knowledge of the underlying API complexities.', '@felores', 'development', 'Unknown', 14, 'https://github.com/felores/placid-mcp-server', '@felores/placid-mcp-server', 3839, 'https://github.com/felores.png?size=128', '2026-03-09T05:21:01.966201+00:00'),
  ('image-gen-jimeng-ai', 'Image Gen (Jimeng AI)', 'This MCP server, developed by an unknown author, provides a lightweight implementation for handling MCP requests. Built with Python and leveraging the aiohttp and aiofiles libraries, it offers asynchronous capabilities for efficient request processing. The server focuses on basic functionality, utilizing the fastmcp and mcp libraries for core MCP operations. It''s designed for developers who need a simple, customizable MCP server solution, enabling use cases such as prototyping MCP-based applications, testing MCP integrations, or serving as a foundation for more complex MCP implementations.', '@fengin', 'development', 'Unknown', 218, 'https://github.com/fengin/image-gen-server', NULL, 0, 'https://github.com/fengin.png?size=128', '2026-03-09T05:21:01.966228+00:00'),
  ('search-engines-proxy', 'Search Engines Proxy', 'Search-Server provides a unified interface for AI assistants to access multiple search engines through a standardized API. The implementation integrates with Brave Search, Metaso, and Bocha search services, handling authentication, rate limiting, and response formatting for each provider. Built with Python and modern async libraries like httpx, aiohttp, and Playwright, it abstracts away the complexity of different search APIs while maintaining provider-specific features. This server is particularly valuable for developers who need to incorporate web search capabilities into AI applications without managing multiple search engine integrations separately.', '@fengin', 'ai-ml', 'Unknown', 77, 'https://github.com/fengin/search-server', NULL, 0, 'https://github.com/fengin.png?size=128', '2026-03-09T05:21:01.966274+00:00'),
  ('steam-review', 'Steam Review', 'Steam Review MCP provides AI assistants with access to Steam game reviews and information through a Node.js server implementation. It offers tools to fetch game reviews with customizable parameters (language, filter type, review type) and game details from the Steam Store API, along with pre-built prompts for summarizing reviews and analyzing recent player sentiment. The implementation cleans and formats review text for compatibility with various LLM models, making it particularly valuable for understanding player feedback, identifying game strengths and weaknesses, and tracking changes in player sentiment over time.', '@fenxer', 'ai-ml', 'Unknown', 5, 'https://github.com/fenxer/steam-review-mcp', 'steam-review-mcp', 4169, 'https://github.com/fenxer.png?size=128', '2026-03-09T05:21:01.966317+00:00'),
  ('debate-agent', 'Debate Agent', 'Enables multi-agent debates for code review where multiple language models analyze code changes through structured debate mechanics. Features severity-based scoring for issues, multiple debate modes including adversarial and consensus approaches, and deterministic point-based judging. Integrates with Claude Desktop, Claude CLI, and VS Code to provide collaborative code review workflows through agent competition.', '@ferdiangunawan', 'development', 'Unknown', 2, 'https://github.com/ferdiangunawan/debate-agent-mcp', NULL, 0, 'https://github.com/ferdiangunawan.png?size=128', '2026-03-09T05:21:01.966339+00:00'),
  ('investor-agent-financial-analysis', 'Investor Agent (Financial Analysis)', 'Investor-agent is an MCP server that provides financial analysis tools for Large Language Models, leveraging real-time market data through yfinance and CNN''s Fear & Greed Index. Developed by Ferdous, it offers tools for retrieving detailed ticker reports, options data, price histories, financial statements, institutional ownership, and technical indicators (with optional TA-Lib support). The server implements intelligent caching to reduce redundant API calls and includes rate limiting to prevent overloading external services, making it ideal for investment research, portfolio analysis, and market sentiment evaluation when paired with a trading platform like tasty-agent.', '@ferdousbhai', 'ai-ml', 'Unknown', 312, 'https://github.com/ferdousbhai/investor-agent', 'investor-agent', 35757, 'https://github.com/ferdousbhai.png?size=128', '2026-03-09T05:21:01.966387+00:00'),
  ('black-forest-labs', 'Black Forest Labs', 'Black Forest Labs server provides image generation capabilities through the Black Forest Labs API, supporting all FLUX models including FLUX Dev, Pro, Pro Ultra, and Kontext variants for text-to-image generation. Built by Justin Spahr-Summers at Fern Forest Games using TypeScript, it offers parameter control including dimensions, aspect ratios, safety tolerance, and advanced features like image prompting for Redux workflows and multi-reference inputs for Kontext models. The server automatically polls the BFL API until generation completes and returns signed image URLs valid for 10 minutes, with additional tools for downloading images to disk and resources for checking request status, making it valuable for creative workflows, content generation, and applications requiring high-quality AI-generated imagery.', '@fernforestgames', 'development', 'Unknown', 1, 'https://github.com/fernforestgames/mcp-server-bfl', '@fernforestgames/mcp-server-bfl', 389, 'https://github.com/fernforestgames.png?size=128', '2026-03-09T05:21:01.966419+00:00'),
  ('iterm', 'iTerm', 'iterm-mcp, created by Ferris Lucas, is a Model Context Protocol server that provides direct access to the currently active tab in iTerm. It enables seamless execution of shell commands within the active iTerm session, bridging the gap between AI assistants and terminal operations. This implementation stands out by focusing specifically on iTerm integration, making it particularly useful for developers and system administrators who frequently work in terminal environments. It simplifies workflow automation, remote system management, and interactive scripting tasks by allowing AI systems to directly interact with the user''s terminal session. The server is built with TypeScript, ensuring type safety and easy integration with other JavaScript-based tools and environments.', '@ferrislucas', 'development', 'Unknown', 533, 'https://github.com/ferrislucas/iterm-mcp', 'iterm-mcp', 20167, 'https://github.com/ferrislucas.png?size=128', '2026-03-09T05:21:01.966453+00:00'),
  ('plotnine', 'Plotnine', 'Enables creating publication-quality statistical visualizations through plotnine (Python''s ggplot2 equivalent) with support for 20+ geometry types and multiple data sources including CSV, JSON, Parquet, and Excel files. Features AI-powered template recommendations that analyze data to suggest appropriate visualization patterns, comprehensive theming system with 21 color palettes, and data transformation operations including filtering, grouping, and sorting. Automatically saves plots in PNG, PDF, or SVG formats with detailed error handling and fuzzy matching for typo corrections.', '@fervoyush', 'development', 'Unknown', 6, 'https://github.com/fervoyush/plotnine-mcp', NULL, 0, 'https://github.com/fervoyush.png?size=128', '2026-03-09T05:21:01.966479+00:00'),
  ('google-keep', 'Google Keep', 'Keep-MCP is a Python-based MCP server that provides a bridge to Google Keep, allowing AI assistants to search, create, update, and delete notes. Developed by Jannik Feuerhahn, it uses the gkeepapi library to authenticate with Google''s services via master tokens, and includes safety features that restrict modification operations to notes with a specific ''keep-mcp'' label unless explicitly overridden. The server exposes four main tools for note management while handling authentication and serialization behind the scenes, making it particularly useful for users who want to integrate note-taking capabilities into their AI workflows.', '@feuerdev', 'ai-ml', 'Unknown', 63, 'https://github.com/feuerdev/keep-mcp', 'keep-mcp', 3253, 'https://github.com/feuerdev.png?size=128', '2026-03-09T05:21:01.966523+00:00'),
  ('fewsats', 'Fewsats', 'Fewsats MCP server integrates with the Fewsats payment platform, enabling AI agents to securely make purchases through a simple interface. Built with Python using the FastMCP framework, it exposes four key tools: checking wallet balances, retrieving payment methods, paying for offers using L402 protocol, and accessing payment details. The implementation is designed to run via either uv package manager or pip installation, and requires a Fewsats API key for authentication. This server is particularly valuable for applications where AI agents need to handle financial transactions autonomously while maintaining security and user control over the payment process.', '@fewsats', 'ai-ml', 'Unknown', 21, 'https://github.com/fewsats/fewsats-mcp', 'fewsats-mcp', 10536, 'https://github.com/fewsats.png?size=128', '2026-03-09T05:21:01.966571+00:00'),
  ('sherlock-domains', 'Sherlock Domains', 'Sherlock-MCP is a domain management server that enables AI agents to search, purchase, and manage internet domains through a simple interface. Built by Pol Alvarez, it integrates with the Sherlock Domains API to provide tools for domain availability searches, contact information management, DNS record configuration, and domain purchases with L402 payment processing. The server handles authentication, ICANN registration requirements, and DNS management behind the scenes, making it particularly valuable for AI assistants that need to help users acquire and configure web domains without dealing with the technical complexities of domain registrars.', '@fewsats', 'ai-ml', 'Unknown', 1, 'https://github.com/fewsats/sherlock-mcp', 'sherlock-mcp', 6086, 'https://github.com/fewsats.png?size=128', '2026-03-09T05:21:01.966614+00:00'),
  ('angular-i18n', 'Angular i18n', 'An MCP server for managing Angular internationalization using XLIFF 1.2 and 2.0 formats. Integrates with ng-extract-i18n-merge to automate translation workflows, providing tools to extract i18n strings from Angular templates, list new untranslated units, browse all translation units with pagination, and update translations while automatically setting their state to ''translated''. Designed for developers working on multilingual Angular applications who need to streamline their translation management process.', '@ffeldhaus', 'ai-ml', 'Unknown', 1, 'https://github.com/ffeldhaus/angular-i18n-mcp', NULL, 0, 'https://github.com/ffeldhaus.png?size=128', '2026-03-09T05:21:01.966655+00:00'),
  ('matomo-analytics', 'Matomo Analytics', 'Connects Claude to Matomo Analytics instances through dynamic API introspection. Automatically discovers and exposes 60+ Matomo API methods as tools, covering visitor metrics, page analytics, traffic sources, device detection, geographic data, goals, conversions, and events tracking. Supports both real-time discovery mode and cached OpenAPI spec loading for faster initialization.', '@fgribreau', 'ai-ml', 'Unknown', 6, 'https://github.com/fgribreau/mcp-matomo', NULL, 0, 'https://github.com/fgribreau.png?size=128', '2026-03-09T05:21:01.966690+00:00'),
  ('fibery', 'Fibery', 'Fibery MCP Server provides a flexible integration with the Fibery API, enabling AI assistants to interact with Fibery workspaces through a set of standardized tools. The server supports operations like querying databases, creating and updating entities, retrieving schema information, and managing workflow states. Built for developers and teams using Fibery for project management, it streamlines interactions between AI systems and collaborative work tracking platforms.', '@fibery-inc', 'databases', 'Unknown', 28, 'https://github.com/fibery-inc/fibery-mcp-server', 'fibery-mcp-server', 7806, 'https://github.com/fibery-inc.png?size=128', '2026-03-09T05:21:01.966703+00:00'),
  ('figma-to-flutter', 'Figma to Flutter', 'This Figma-to-Flutter MCP server enables AI assistants to automatically convert Figma designs into Flutter widget code through direct integration with the Figma API. Built with TypeScript and the MCP SDK, it extracts design elements from Figma files, analyzes component structures, and generates corresponding Flutter widgets with proper styling, layout properties, and project organization. The implementation features intelligent design extraction with deduplication of colors, text styles, and components into reusable libraries, automatic categorization of UI elements into Flutter-appropriate widgets (buttons, cards, screens), and generation of complete project structures with proper file organization and imports. It handles complex design hierarchies, converts Figma styling properties to Flutter equivalents, and provides retry mechanisms with rate limiting for robust API interactions, making it particularly useful for Flutter developers who want to accelerate UI development by automatically translating design mockups into production-ready code.', '@mhmzdev', 'development', 'Unknown', 209, 'https://github.com/mhmzdev/figma-flutter-mcp', NULL, 0, 'https://github.com/mhmzdev.png?size=128', '2026-03-09T05:21:01.966764+00:00'),
  ('usewebhook', 'UseWebhook', 'A simple webhook generation tool built by Figstra Software that creates unique webhook endpoints for capturing and inspecting HTTP requests. The server provides a single tool that generates random UUID-based URLs on the usewebhook.com service, returning both a webhook endpoint for receiving requests and a separate inspector URL for viewing captured data. Useful for testing API integrations, debugging webhook deliveries, or quickly setting up temporary endpoints for development workflows without requiring account setup or configuration.', '@figstra', 'development', 'Unknown', 2, 'https://github.com/figstra/usewebhook-mcp', NULL, 0, 'https://github.com/figstra.png?size=128', '2026-03-09T05:21:01.966789+00:00'),
  ('file-ai', 'File AI', 'MCP server implementation that provides AI assistants with access to database schema information and API creation capabilities, featuring tools for schema visualization and API endpoint generation. Based on the included screenshots showing API creation interfaces, database schemas, and integration with development tools like Cursor and Claude, the implementation focuses on streamlining database-driven development workflows by allowing conversational access to schema details and automated API scaffolding. Designed for developers who want to quickly generate APIs from existing database structures or explore schema relationships through natural language queries during development.', '@fileai', 'databases', 'Unknown', 2, 'https://github.com/fileai/file-ai-mcp', NULL, 0, 'https://github.com/fileai.png?size=128', '2026-03-09T05:21:01.966800+00:00'),
  ('files-com', 'Files.com', 'Integrates with the Files.com platform to enable AI-driven file transfer and management operations. Provides tools for uploading and downloading files, querying folder contents, managing users, and orchestrating workflows across multiple cloud storage providers including Amazon S3, Microsoft Azure, Google Cloud, SharePoint, Google Drive, and protocols like SFTP and AS2. Features strict access controls, audit logging, and API key authentication.', '@files-com', 'cloud', 'Unknown', 2, 'https://github.com/files-com/files-mcp', NULL, 0, 'https://github.com/files-com.png?size=128', '2026-03-09T05:21:01.966816+00:00'),
  ('filescope', 'FileScope', 'FileScopeMCP is a TypeScript-based MCP server that analyzes codebases to identify important files based on dependency relationships, providing AI tools with structural understanding of projects. It scans source files to detect imports across multiple languages (JavaScript, TypeScript, Python, C/C++, Rust, Lua, Zig), calculates importance scores (0-10) based on dependency patterns, and generates visualizations using Mermaid diagrams. The implementation features persistent storage of file trees, cross-platform path handling, and tools for querying file importance, finding critical components, and adding human-readable summaries to files, making it valuable for developers who want AI assistants to understand the architecture and significance of different files in their projects.', '@admica', 'development', 'Unknown', 282, 'https://github.com/admica/filescopemcp', NULL, 0, 'https://github.com/admica.png?size=128', '2026-03-09T05:21:01.966847+00:00'),
  ('filesystem-context', 'Filesystem Context', 'Provides secure, read-only filesystem access for AI applications. Features directory operations with recursive traversal, search capabilities including file globbing and regex content searching, file reading with head/tail support, and comprehensive analysis tools for directory statistics and metadata. Includes symlink escape protection, path traversal prevention, and access control for explicitly allowed directories only.', '@j0hanz', 'ai-ml', 'Unknown', 1, 'https://github.com/j0hanz/filesystem-mcp', NULL, 0, 'https://github.com/j0hanz.png?size=128', '2026-03-09T05:21:01.966894+00:00'),
  ('strateegia', 'Strateegia', 'Strateegia MCP Server provides a bridge to the Strateegia API, enabling AI assistants to access and interact with projects and labs through a standardized MCP interface. Built with TypeScript and the Model Context Protocol SDK, it exposes a single tool for listing projects, designed to help users quickly retrieve an overview of their Strateegia workspace. Particularly useful for teams and individuals wanting to integrate their collaborative project data directly into AI workflows.', '@filipecalegario', 'development', 'Unknown', 0, 'https://github.com/filipecalegario/mcp-server-strateegia', 'strateegia-mcp-server', 4942, 'https://github.com/filipecalegario.png?size=128', '2026-03-09T05:21:01.966921+00:00'),
  ('ai-consultant-openrouter', 'AI Consultant (OpenRouter)', 'Built by Filip Krayem, this server provides AI consultation capabilities through OpenRouter''s API, supporting multiple models including GPT-5 Codex, Gemini 2.5 Pro, and Grok Code Fast 1. The implementation features intelligent model selection based on task descriptions, conversation history management, caching, rate limiting, circuit breaker patterns, and retry logic with exponential backoff. It supports both single-model consultations and sequential multi-model workflows, automatically selecting optimal models for coding tasks, complex analysis, or general queries, making it ideal for developers who need reliable AI assistance with robust error handling and performance optimizations.', '@filipkrayem', 'development', 'Unknown', 1, 'https://github.com/filipkrayem/ai-consultant-mcp', 'ai-consultant-mcp', 162, 'https://github.com/filipkrayem.png?size=128', '2026-03-09T05:21:01.966955+00:00'),
  ('worklog', 'Worklog', 'Provides automated work session tracking and logging capabilities by collecting activity data from various development tools and applications. Features a hexagonal architecture with pluggable session collectors for different tools (Claude Code, Cursor, Kiro), storage adapters, and formatting utilities for generating work summaries. Designed for developers who want to automatically capture and analyze their coding sessions, track productivity patterns, and generate detailed work logs without manual time tracking.', '@final0920', 'development', 'Unknown', 2, 'https://github.com/final0920/mcp-worklog', NULL, 0, 'https://github.com/final0920.png?size=128', '2026-03-09T05:21:01.967035+00:00'),
  ('financial-datasets', 'Financial Datasets', 'Financial Datasets MCP Server provides AI assistants with direct access to stock market data through a set of specialized financial tools. Built by Financial Datasets, it enables Claude and other AI assistants to retrieve income statements, balance sheets, cash flow statements, current and historical stock prices, and market news via the Financial Datasets API. The server is designed to run locally using the uv package manager and can be easily integrated with Claude Desktop, making it valuable for financial analysis, investment research, and market monitoring workflows without leaving the conversation interface.', '@financial-datasets', 'ai-ml', 'Unknown', 1538, 'https://github.com/financial-datasets/mcp-server', NULL, 0, 'https://github.com/financial-datasets.png?size=128', '2026-03-09T05:21:01.967085+00:00'),
  ('financial-modeling-prep', 'Financial Modeling Prep', 'Financial Modeling Prep MCP Server provides AI assistants with access to comprehensive financial data through the Financial Modeling Prep API. Built with TypeScript and Node.js, it exposes over 30 specialized client modules covering diverse financial domains including stock quotes, company profiles, financial statements, technical indicators, economic data, and government trading information. The server implements a robust authentication system that supports both direct API key configuration and context-based token passing, making it suitable for both development and production environments. Particularly valuable for financial analysis, investment research, and market monitoring use cases that require real-time and historical financial data.', '@imbenrabi', 'development', 'Unknown', 123, 'https://github.com/imbenrabi/financial-modeling-prep-mcp-server', NULL, 0, 'https://github.com/imbenrabi.png?size=128', '2026-03-09T05:21:01.967117+00:00'),
  ('findmine-shopping-stylist', 'FindMine Shopping Stylist', 'FindMine''s MCP server connects Claude and other AI assistants to FindMine''s product styling API, enabling fashion recommendations and outfit creation. Built with TypeScript and the Model Context Protocol SDK, it provides tools for browsing products, generating outfit recommendations, finding visually similar items, and accessing style guides. The implementation features configurable caching, sample data for development, and customizable style guides, making it ideal for e-commerce platforms wanting to enhance their product discovery with AI-powered fashion styling assistance.', '@findmine', 'development', 'Unknown', 1, 'https://github.com/findmine/findmine-mcp', 'findmine-mcp', 4866, 'https://github.com/findmine.png?size=128', '2026-03-09T05:21:01.967143+00:00'),
  ('findyourfivepm', 'FindYourFivePM', 'FindYourFivePM helps you discover cities experiencing their 5 PM moment across 200,000 locations worldwide. The service provides timezone and location data to find global 5 PM hotspots, useful for remote workers planning international calls, travelers exploring time zones, or anyone seeking virtual happy hour companions.', '@unknown', 'maps-location', 'Unknown', 0, 'https://findyourfivepm.com', NULL, 0, NULL, '2026-03-09T05:21:01.967205+00:00'),
  ('finfeedapi-fx-historical', 'FinFeedAPI FX Historical', 'This MCP server provides access to CoinAPI''s historical cryptocurrency and financial market data. CoinAPI offers comprehensive market data coverage across hundreds of exchanges and thousands of trading pairs. The server enables retrieval of historical price data, trading volumes, and other market metrics for cryptocurrency analysis and research purposes. It''s particularly useful for backtesting trading strategies, market analysis, and financial research applications.', '@unknown', 'development', 'Unknown', 0, 'https://www.pulsemcp.com/servers/finfeed-historical-data', NULL, 0, NULL, '2026-03-09T05:21:01.967230+00:00'),
  ('finfeedapi-stock-api', 'FinFeedAPI Stock API', 'This server integrates with CoinAPI''s financial data service to provide historical stock market information. Created by CoinAPI, it offers access to comprehensive historical stock data through their established financial data infrastructure. The server enables retrieval of historical price data, trading volumes, and other market metrics for stocks and financial instruments.', '@unknown', 'finance', 'Unknown', 0, 'https://www.pulsemcp.com/servers/finfeed-historical-stock-data', NULL, 0, NULL, '2026-03-09T05:21:01.967275+00:00'),
  ('finfeedapi-fx-realtime', 'FinFeedAPI FX Realtime', 'This MCP server provides access to CoinAPI''s comprehensive financial data platform, offering real-time cryptocurrency prices, market data, and trading information. Built by CoinAPI, it enables direct integration with their professional-grade financial data services, supporting various asset classes including cryptocurrencies, exchanges, and market metrics. The server is designed for applications requiring reliable, up-to-date financial market data with enterprise-level API access.', '@unknown', 'finance', 'Unknown', 0, 'https://mcp-realtime.fx.finfeedapi.com/mcp', NULL, 0, NULL, '2026-03-09T05:21:01.967323+00:00'),
  ('finfeedapi-sec-api', 'FinFeedAPI SEC API', 'This server provides access to CoinAPI''s comprehensive cryptocurrency data platform, offering real-time prices, historical market data, exchange information, and trading metrics across thousands of digital assets. Built by CoinAPI, it enables seamless integration with their professional-grade financial data infrastructure, supporting use cases from portfolio tracking to market analysis and trading applications.', '@unknown', 'development', 'Unknown', 0, 'https://mcp.sec.finfeedapi.com/mcp', NULL, 0, NULL, '2026-03-09T05:21:01.967342+00:00'),
  ('finix-payments', 'Finix Payments', 'MCP server implementation for Finix payments API that provides tools for creating and managing buyer/seller identities, generating payment links, and searching Finix documentation. The implementation includes comprehensive seller identity creation with full underwriting data support (business details, financial information, compliance data), streamlined buyer creation, identity listing with filtering capabilities, and payment link generation with configurable pricing and merchant association. Built with TypeScript and featuring environment-based API URL switching (sandbox/production), credential validation, and integrated documentation search through Finix''s search API, it serves developers building payment processing applications, fintech platforms requiring identity management, and businesses needing programmatic access to Finix''s payment infrastructure for onboarding merchants and facilitating transactions.', '@bquigley1', 'development', 'Unknown', 2, 'https://github.com/bquigley1/finix-mcp', NULL, 0, 'https://github.com/bquigley1.png?size=128', '2026-03-09T05:21:01.967374+00:00'),
  ('rethinkdb', 'RethinkDB', 'Provides read-only access to RethinkDB databases with tools for listing databases and tables, querying table data with filtering and ordering, and retrieving metadata including indexes and document counts. Includes configurable safety limits to prevent accidental large data retrievals.', '@finnng', 'databases', 'Unknown', 1, 'https://github.com/finnng/mcp-rethinkdb-server', NULL, 0, 'https://github.com/finnng.png?size=128', '2026-03-09T05:21:01.967385+00:00'),
  ('firebase', 'Firebase', 'Give AI-powered development tools the ability to work with your Firebase projects', '@firebase', 'development', 'Unknown', 4352, 'https://github.com/firebase/firebase-tools', 'firebase-tools', 143654694, 'https://github.com/firebase.png?size=128', '2026-03-09T05:21:01.967399+00:00'),
  ('genkit', 'Genkit', 'This Genkit MCP plugin, developed by Firebase, provides seamless integration between Genkit and the Model Context Protocol (MCP). It enables Genkit developers to both consume MCP tools, prompts, and resources as a client and expose Genkit functionality as an MCP server. The client automatically discovers and registers available MCP actions with Genkit, while the server exposes Genkit tools and prompts via MCP. Built with TypeScript, it offers flexible configuration options for connecting to MCP servers, including local process spawning and remote connections. The implementation handles parsing and coercion of MCP responses for compatibility with Genkit''s structured approach. It is particularly useful for developers looking to extend Genkit''s capabilities with external MCP-compatible services or expose their Genkit-based AI assistants as MCP servers.', '@firebase', 'development', 'Unknown', 5594, 'https://github.com/firebase/genkit/tree/HEAD/js/plugins/mcp', 'genkitx-mcp', 18306, 'https://github.com/firebase.png?size=128', '2026-03-09T05:21:01.967429+00:00'),
  ('fireflies', 'Fireflies', 'Provides access to Fireflies.ai meeting data including complete transcripts, meeting metadata, speaker identification, and AI-generated summaries. Enables querying and analysis of meeting content directly from AI assistants.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://www.pulsemcp.com/servers/fireflies', NULL, 0, NULL, '2026-03-09T05:21:01.967508+00:00'),
  ('fireproof-json-document-store', 'Fireproof JSON Document Store', 'This MCP server, developed by the Fireproof Storage team, integrates a Fireproof database to provide a JSON document store with CRUD operations and querying capabilities. It offers a simple interface for AI assistants to store, retrieve, update, and delete JSON documents, as well as perform queries sorted by any field. The implementation stands out by leveraging Fireproof''s local-first database technology, enabling offline-capable and real-time collaborative features. By connecting AI capabilities with a flexible document store, this server empowers AI systems to manage structured data efficiently. It is particularly useful for applications requiring persistent storage of AI-generated content, collaborative note-taking systems, or any scenario where an AI assistant needs to work with dynamic, structured data.', '@fireproof-storage', 'databases', 'Unknown', 30, 'https://github.com/fireproof-storage/mcp-database-server', NULL, 0, 'https://github.com/fireproof-storage.png?size=128', '2026-03-09T05:21:01.967521+00:00'),
  ('ssl-monitor', 'SSL Monitor', 'SSL certificate monitoring and domain registration information MCP server that provides real-time SSL certificate validation and WHOIS domain lookup capabilities. Built by firesh, the implementation uses both modern RDAP protocol and traditional WHOIS queries as fallback to retrieve comprehensive domain registration data including expiration dates, registrar information, and registrant details, while SSL certificate checking leverages Node.js TLS connections to validate certificate chains and calculate expiration timelines. Designed for system administrators, security teams, and developers who need automated monitoring of domain and certificate lifecycles without manual certificate inspection or complex WHOIS parsing, making it valuable for compliance tracking, security auditing, and proactive renewal management workflows.', '@firesh', 'ai-ml', 'Unknown', 3, 'https://github.com/firesh/sslmon-mcp', 'sslmon-mcp', 681, 'https://github.com/firesh.png?size=128', '2026-03-09T05:21:01.967577+00:00'),
  ('vulnerability-intelligence', 'Vulnerability Intelligence', 'Vulnerability Intelligence MCP Server provides security professionals and developers with tools to analyze and assess security vulnerabilities through a modular architecture. Built by Kirill Markin, this Python-based server exposes eight specialized tools including CVE lookup, CVSS calculation, exploit availability checking, vulnerability timeline tracking, and VEX status verification. The implementation leverages multiple security data sources including the National Vulnerability Database (NVD) to deliver comprehensive vulnerability intelligence, making it particularly valuable for security teams needing to prioritize patches, assess exploit risks, or investigate specific vulnerabilities like Log4Shell.', '@firetix', 'databases', 'Unknown', 9, 'https://github.com/firetix/vulnerability-intelligence-mcp-server', NULL, 0, 'https://github.com/firetix.png?size=128', '2026-03-09T05:21:01.967588+00:00'),
  ('firewalla', 'Firewalla', 'Firewalla MCP server by Alex Mittell that provides real-time network monitoring, security analysis, and firewall management through 28 specialized tools compatible with any MCP client. The implementation integrates with Firewalla''s MSP API v2 to deliver security alert monitoring, bandwidth usage tracking, device status management, rule operations with pause/resume functionality, and geographic threat analysis with location-based filtering. Built with TypeScript and featuring advanced search capabilities with complex query syntax, boolean field translation, cross-reference correlation scoring, and bulk operations for alarm and rule management, it serves network administrators requiring conversational access to firewall data, security teams needing real-time threat analysis, and IT professionals managing multiple Firewalla devices through AI-powered interfaces for network security monitoring and incident response workflows.', '@amittell', 'development', 'Unknown', 20, 'https://github.com/amittell/firewalla-mcp-server', 'firewalla-mcp-server', 1819, 'https://github.com/amittell.png?size=128', '2026-03-09T05:21:01.967624+00:00'),
  ('authenticator-app', 'Authenticator App', 'The Authenticator MCP Server provides AI assistants with secure access to two-factor authentication codes and passwords stored in the Authenticator App. Developed by FirstOrder.AI, this TypeScript implementation exposes three key tools: retrieving 2FA codes, fetching passwords, and listing available accounts for specific websites. The server communicates with the local Authenticator App running on port 43457 and requires an access token for authentication. This integration is particularly valuable for workflows requiring secure login assistance across multiple services without manual code entry or password retrieval, enabling AI assistants to help with authentication while maintaining security through the token-based authorization system.', '@firstorderai', 'development', 'Unknown', 35, 'https://github.com/firstorderai/authenticator_mcp', 'authenticator-mcp', 1107, 'https://github.com/firstorderai.png?size=128', '2026-03-09T05:21:01.967651+00:00'),
  ('fish-audio', 'Fish Audio', 'This MCP server provides text-to-speech capabilities through Fish Audio''s API, enabling AI assistants to generate high-quality speech from text with support for custom voice models and real-time streaming. Built by Daichi Okazaki using TypeScript with the official Fish Audio SDK, it offers two main tools: TTS generation with configurable voice references, audio formats (MP3, WAV, PCM, Opus), and streaming modes, plus voice reference listing for managing multiple voice models through ID, name, or tag selection. The implementation features both HTTP and WebSocket streaming for low-latency audio generation, automatic cross-platform audio playbook (macOS, Windows, Linux), real-time audio streaming with immediate playback, and flexible voice reference management supporting both single and multiple voice configurations, making it valuable for creating conversational AI applications, automated content narration, accessibility tools, and building AI assistants that need high-quality speech synthesis without manual Fish Audio dashboard interaction.', '@da-okazaki', 'development', 'Unknown', 10, 'https://github.com/da-okazaki/mcp-fish-audio-server', '@alanse/fish-audio-mcp-server', 1384, 'https://github.com/da-okazaki.png?size=128', '2026-03-09T05:21:01.967692+00:00'),
  ('mcp-easy-copy', 'MCP Easy Copy', 'MCP Easy Copy is a utility server that simplifies working with Claude Desktop by automatically reading the configuration file and presenting all available MCP services in an easy-to-copy format. Created by fisheep, it solves the problem of having to remember service names or look them up in configuration files by displaying them at the top of the tools list. This is particularly useful when you have many MCP services configured, need to explicitly specify a service name, or are troubleshooting between different services.', '@f-is-h', 'ai-ml', 'Unknown', 3, 'https://github.com/f-is-h/mcp-easy-copy', '@fishes/mcp-easy-copy', 3809, 'https://github.com/f-is-h.png?size=128', '2026-03-09T05:21:01.967731+00:00'),
  ('skill-management', 'Skill Management', 'This skill management server by fkesheh provides a complete system for organizing and executing Claude skills with per-skill environment variables and automatic dependency management. Built with Python and the MCP protocol, it stores skills in a structured directory format with SKILL.md metadata files, supports Python scripts with PEP 723 inline dependencies that auto-install via uv, and includes comprehensive file management tools for creating, reading, updating, and deleting skill files. The server features script execution with environment variable injection, security measures like path traversal prevention, and support for multiple script types including Python and shell scripts, making it useful for developers who want to build reusable automation workflows and maintain organized collections of executable skills.', '@fkesheh', 'development', 'Unknown', 25, 'https://github.com/fkesheh/skill-mcp', 'skill-mcp', 1381, 'https://github.com/fkesheh.png?size=128', '2026-03-09T05:21:01.967800+00:00'),
  ('gencodedoc', 'GenCodeDoc', 'GenCodeDoc provides intelligent project versioning through snapshots with 70% space savings via content deduplication, automated Markdown documentation generation, and advanced version comparison using unified diff, JSON, or semantic (AST) formats. Offers 17 MCP tools accessible via CLI, REST API, or MCP protocol with stdio, SSE, and REST transport support.', '@fkom13', 'development', 'Unknown', 0, 'https://github.com/fkom13/gencodedoc', NULL, 0, 'https://github.com/fkom13.png?size=128', '2026-03-09T05:21:01.967823+00:00'),
  ('sftp-orchestrator', 'SFTP Orchestrator', 'Manages SSH/SFTP connections and executes remote tasks through a persistent queue system. Provides tools for server management, command execution (simple, interactive, and multi-command workflows), file transfers with glob pattern support, system monitoring (CPU, RAM, disk, services), and API health checks. Features hybrid sync/async execution with history tracking and retry capabilities.', '@fkom13', 'productivity', 'Unknown', 0, 'https://github.com/fkom13/mcp-sftp-orchestrator', NULL, 0, 'https://github.com/fkom13.png?size=128', '2026-03-09T05:21:01.967873+00:00'),
  ('philips-hue', 'Philips Hue', 'Integrates with Philips Hue smart lighting systems through automatic mDNS-based bridge discovery and interactive setup tools that guide users through the physical button press authentication process. Provides comprehensive light control including individual lights, zones, and rooms with support for brightness adjustments, color changes, and on/off state management. Uses Philips Hue API v1 with plans to migrate to the hue-sync library for API v2 support, making it useful for home automation workflows and ambient lighting control.', '@fl0p', 'security', 'Unknown', 1, 'https://github.com/fl0p/huemcp', NULL, 0, 'https://github.com/fl0p.png?size=128', '2026-03-09T05:21:01.967966+00:00'),
  ('grok2-image-generator', 'Grok2 Image Generator', 'Grok2 Image MCP Server enables AI assistants to generate images through the Grok2 model using the Model Context Protocol. Built with TypeScript and running on Node.js, this server implementation uses stdio transport to facilitate communication between clients and the image generation capabilities of Grok2. The server is designed for easy integration into existing workflows, making it particularly valuable for applications requiring on-demand image creation from text prompts without complex setup or configuration.', '@fl0w1nd', 'development', 'Unknown', 29, 'https://github.com/fl0w1nd/grok-image-mcp', 'grok2-image-mcp-server', 6972, 'https://github.com/fl0w1nd.png?size=128', '2026-03-09T05:21:01.968000+00:00'),
  ('nmap', 'Nmap', 'Provides network scanning capabilities through nmap integration via HTTP endpoints, enabling network discovery, port scanning, and host enumeration tasks. Built with FastAPI and featuring asynchronous task management using SQLite, the server supports concurrent scanning operations with configurable timeouts and token authentication. Offers quick scan (100 common ports), full scan (all 65,535 ports with service detection), custom scan (arbitrary nmap parameters), and task status/result retrieval for security assessments and infrastructure monitoring workflows.', '@flagify-com', 'databases', 'Unknown', 2, 'https://github.com/flagify-com/nmap-mcp-http', NULL, 0, 'https://github.com/flagify-com.png?size=128', '2026-03-09T05:21:01.968013+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('flashduty', 'Flashduty', 'This MCP server provides incident management capabilities through the Flashduty API, enabling AI assistants to create, acknowledge, resolve, and manage incidents programmatically. Built by the Flashcat team using Go with comprehensive toolsets for members, teams, channels, and incidents, it offers 25+ specialized tools including incident creation with severity assignment, timeline and alert retrieval, responder management, incident merging and commenting, and custom field updates. The implementation features flexible authentication via APP keys, read-only mode support, Docker containerization with multi-platform builds, and robust error handling with structured API responses, making it valuable for automated incident response workflows, on-call management processes, and building AI assistants that need programmatic access to Flashduty''s incident management platform without manual dashboard navigation.', '@flashcatcloud', 'cloud', 'Unknown', 3, 'https://github.com/flashcatcloud/flashduty-mcp-server', NULL, 0, 'https://github.com/flashcatcloud.png?size=128', '2026-03-09T05:21:01.968040+00:00'),
  ('flatfile', 'Flatfile', 'The Flatfile MCP server provides AI assistants with direct access to Flatfile''s data import platform through a TypeScript implementation. Developed by Flatfile, Inc., this server exposes over 200 API endpoints for managing spaces, workbooks, sheets, jobs, users, and data operations on the Flatfile platform. The implementation uses the Model Context Protocol SDK to communicate via stdio, authenticates with the Flatfile API using bearer tokens, and follows a consistent pattern for API interactions with proper error handling. It''s particularly valuable for users who need to programmatically manage data import workflows, validate sheets, and orchestrate data transformations without leaving their conversation context.', '@flatfilers', 'development', 'Unknown', 0, 'https://github.com/flatfilers/mcp-server-flatfile', '@flatfile/mcp-server', 3131, 'https://github.com/flatfilers.png?size=128', '2026-03-09T05:21:01.968070+00:00'),
  ('tasks', 'Tasks', 'This MCP server provides AI assistants with task management capabilities across multiple file formats (Markdown, JSON, YAML), built by Ariel Flesler using TypeScript with FastMCP and featuring five core tools for task setup, searching, adding, updating, and summarization with automatic work-in-progress management. The implementation offers flexible file format support with intelligent parsing, duplicate task handling, batch operations for efficiency, configurable status workflows with automatic transitions between To Do/In Progress/Done states, and both CLI and server modes with HTTP/stdio transport options. Built with comprehensive validation using Zod schemas, Docker deployment support, source file registration with workspace awareness, and published as an npm package with global CLI access, it serves development teams needing conversational task tracking integrated with their existing file-based workflows, project managers requiring AI-driven task organization without switching tools, and teams where natural language interfaces enhance productivity by eliminating manual task file editing.', '@flesler', 'cloud', 'Unknown', 39, 'https://github.com/flesler/mcp-tasks', 'mcp-tasks', 1940, 'https://github.com/flesler.png?size=128', '2026-03-09T05:21:01.968098+00:00'),
  ('fleur-app-launcher', 'Fleur App Launcher', 'Fleur MCP server enables seamless integration with the Fleur application, an app store that allows users to access various applications like Gmail, Linear, and Slack without leaving their chat interface. The implementation provides two main tools: explaining what Fleur is when a user types ''hello fleur'' and opening the Fleur application with platform-specific methods for both macOS and Windows. It includes robust executable detection for Windows systems and handles onboarding state management, making it ideal for enhancing AI assistant capabilities with direct access to external applications.', '@fleuristes', 'communication', 'Unknown', 2, 'https://github.com/fleuristes/fleur-mcp', 'mcp-fleur', 7889, 'https://github.com/fleuristes.png?size=128', '2026-03-09T05:21:01.968135+00:00'),
  ('fhir', 'FHIR', 'This FHIR MCP server, developed by Flexpa, enables seamless integration of FHIR (Fast Healthcare Interoperability Resources) data into AI-assisted workflows. Built with TypeScript and leveraging the @modelcontextprotocol/sdk, it provides a standardized interface for accessing and searching FHIR resources through Claude Desktop and compatible MCP clients. The implementation supports all FHIR resource types available in the connected FHIR server''s CapabilityStatement, offering tools for resource retrieval via URIs and advanced search capabilities. It''s particularly useful for healthcare professionals, researchers, and developers looking to incorporate on-demand access to medical data into their AI-assisted applications, allowing for dynamic querying and analysis of FHIR-compliant healthcare information.', '@flexpa', 'development', 'Unknown', 65, 'https://github.com/flexpa/mcp-fhir', NULL, 0, 'https://github.com/flexpa.png?size=128', '2026-03-09T05:21:01.968167+00:00'),
  ('github-repository-creator', 'GitHub Repository Creator', 'GitHub Repository Creator MCP server that automates the process of creating GitHub repositories by analyzing local codebases and generating intelligent metadata. Built by flickleafy, the implementation uses a sophisticated repository analyzer that detects programming languages, frameworks, project types, and extracts descriptions from README files to automatically generate appropriate repository names, descriptions, topics, and licenses. The server integrates with GitHub CLI for seamless repository creation and provides both interactive and automated workflows, making it valuable for developers who want to quickly publish local projects to GitHub without manually configuring repository settings or writing descriptions from scratch.', '@flickleafy', 'development', 'Unknown', 2, 'https://github.com/flickleafy/mcp-github-repo-creator', NULL, 0, 'https://github.com/flickleafy.png?size=128', '2026-03-09T05:21:01.968196+00:00'),
  ('flightradar24', 'Flightradar24', 'Integrates with the Flightradar24 API to provide comprehensive aviation data including live flight positions, aircraft information, airport details, and historical flight records dating back to May 2016. Supports filtering by callsigns, registrations, routes, aircraft types, altitude ranges, and geographic bounds across 16 specialized tools for live tracking, historical queries, flight summaries, and reference data.', '@flightradar24', 'ai-ml', 'Unknown', 14, 'https://github.com/flightradar24/fr24api-mcp', NULL, 0, 'https://github.com/flightradar24.png?size=128', '2026-03-09T05:21:01.968231+00:00'),
  ('flik', 'Flik', 'Flik - Agentic Product Delivery Platform.', '@pdeloulay', 'aggregators', 'Unknown', 0, 'https://github.com/pdeloulay/flik-mcp', NULL, 0, 'https://github.com/pdeloulay.png?size=128', '2026-03-09T05:21:01.968260+00:00'),
  ('flint-note', 'Flint Note', 'Agent-first note-taking application with MCP server built by Tim Disney that provides AI assistants with complete access to a structured note management system featuring note types, wikilink support, and hybrid search capabilities. The implementation uses TypeScript with SQLite for storage and includes a vault system for managing multiple note collections, automatic link extraction and bidirectional linking, content hash-based optimistic locking for safe concurrent updates, and comprehensive search tools including regex, metadata filtering, and direct SQL queries. Designed for AI workflows requiring structured knowledge management with features like batch operations, note type schemas with custom metadata fields, cross-vault operations, and MCP resources for read-only access to notes and collections, making it valuable for building AI-powered knowledge bases, research workflows, and collaborative note-taking systems where agents need programmatic access to interconnected notes with rich metadata and linking capabilities.', '@disnet', 'databases', 'Unknown', 10, 'https://github.com/disnet/flint-note-mcp', '@flint-note/server', 2608, 'https://github.com/disnet.png?size=128', '2026-03-09T05:21:01.968273+00:00'),
  ('io-github-sind00-flippa-mcp', 'io.github.sind00/flippa-mcp', 'Search, analyze, and evaluate online businesses for sale on Flippa.com marketplace.', '@sind00', 'development', 'Unknown', 1, 'https://github.com/sind00/flippa-mcp', NULL, 0, 'https://github.com/sind00.png?size=128', '2026-03-09T05:21:01.968291+00:00'),
  ('yazio', 'Yazio', 'Integrates with Yazio nutrition tracking app to access daily nutrition summaries, food intake logs, weight tracking, exercise data, and water intake monitoring. Enables searching the Yazio food database and programmatically managing food entries. Uses reverse-engineered API endpoints (unofficial implementation).', '@fliptheweb', 'databases', 'Unknown', 18, 'https://github.com/fliptheweb/yazio-mcp', NULL, 0, 'https://github.com/fliptheweb.png?size=128', '2026-03-09T05:21:01.968302+00:00'),
  ('flipt-feature-flag-management', 'Flipt (Feature Flag Management)', 'Flipt MCP Server provides a bridge between AI assistants and Flipt feature flag management, enabling operations like listing, creating, updating, and deleting namespaces, flags, segments, and rules. Built with TypeScript and the Model Context Protocol SDK, it communicates with the Flipt API through a configurable endpoint and optional authentication token. The server can be deployed via npm or Docker, making it accessible for developers who want to integrate feature flag management into their AI assistant workflows. Particularly useful for evaluating flags for specific entities, toggling features on/off, and managing complex rollout strategies through constraints, variants, and distributions.', '@flipt-io', 'cloud', 'Unknown', 3, 'https://github.com/flipt-io/mcp-server-flipt', '@flipt-io/mcp-server-flipt', 4464, 'https://github.com/flipt-io.png?size=128', '2026-03-09T05:21:01.968328+00:00'),
  ('mysql-manager-qwen', 'MySQL Manager (Qwen)', 'This MCP server provides MySQL database management capabilities through a Mastra-based agent system that integrates with Qwen AI models for intelligent database operations. Built as part of an ECNU lab project, it combines a custom MySQL MCP server with tools for database queries, schema management, and data manipulation, alongside a conversational agent that can understand natural language requests and execute appropriate database operations. The implementation features security controls, pagination support, comprehensive logging, and memory persistence through LibSQL storage, making it valuable for database administration tasks, data analysis workflows, and educational scenarios where users need to interact with MySQL databases through natural language interfaces rather than direct SQL commands.', '@floatdreamwithsong', 'databases', 'Unknown', 3, 'https://github.com/floatdreamwithsong/mysql-mcp-server-qwen-manager', NULL, 0, 'https://github.com/floatdreamwithsong.png?size=128', '2026-03-09T05:21:01.968340+00:00'),
  ('florentine-ai', 'Florentine.ai', 'Connects to MongoDB Atlas or Community Edition databases and enables conversational querying through natural language. Automatically explores schemas, generates aggregation pipelines, and supports vector search with automated embeddings. Provides secure multi-tenant data separation with key/value-based isolation and advanced lookup support across collections.', '@florentine-ai', 'databases', 'Unknown', 6, 'https://github.com/florentine-ai/mcp', NULL, 0, 'https://github.com/florentine-ai.png?size=128', '2026-03-09T05:21:01.968407+00:00'),
  ('imap-mini', 'IMAP Mini', 'Connects to any standard IMAP email server including Gmail, Outlook, Fastmail, and local bridges like ProtonMail Bridge. Provides comprehensive email management with tools for listing, searching, reading, starring, moving, and organizing messages across folders. Supports draft composition and reply drafting while enforcing safety boundaries that block sending and deleting emails. Uses stable globally unique email identifiers that persist across folder moves.', '@florianbuetow', 'communication', 'Unknown', 5, 'https://github.com/florianbuetow/imap-mini-mcp', NULL, 0, 'https://github.com/florianbuetow.png?size=128', '2026-03-09T05:21:01.968435+00:00'),
  ('sflow-airunner', 'SFLOW AIRunner', 'A job scheduling and automation server that executes Claude Code CLI tasks on cron schedules. Features a web dashboard for job management, webhook endpoints for external triggers, and dynamic MCP server creation with automatic credential management. Includes OAuth 2.1 authentication for secure remote access, token usage tracking with cost calculation, and supports both stdio and SSE transports for flexible deployment options.', '@floriansmeyers', 'development', 'Unknown', 24, 'https://github.com/floriansmeyers/sflow-airunner-mcp-prd', NULL, 0, 'https://github.com/floriansmeyers.png?size=128', '2026-03-09T05:21:01.968458+00:00'),
  ('magento-graphql-docs', 'Magento GraphQL Docs', 'An MCP server that provides intelligent search and retrieval capabilities for Magento 2 GraphQL API documentation by ingesting markdown files from the Adobe Commerce WebAPI repository into a SQLite database with full-text search indexing. Built by florinel-chis using FastMCP, it automatically parses documentation files to extract GraphQL schema elements (queries, mutations, types), code examples, and metadata, then exposes tools for searching documentation by keywords, retrieving complete documents, finding GraphQL elements by name or type, browsing tutorials sequentially, and discovering related content through category and keyword matching. The implementation features automatic change detection to avoid unnecessary re-ingestion, configurable result limits, and structured data extraction that makes it useful for developers working with Magento GraphQL APIs who need quick access to documentation, code examples, and schema definitions without manually browsing through extensive documentation repositories.', '@florinel-chis', 'databases', 'Unknown', 8, 'https://github.com/florinel-chis/magento-graphql-docs-mcp', NULL, 0, 'https://github.com/florinel-chis.png?size=128', '2026-03-09T05:21:01.968471+00:00'),
  ('prestashop-documentation', 'PrestaShop Documentation', 'A PrestaShop documentation server providing searchable access to PrestaShop''s official documentation through a locally-indexed SQLite database with FTS5 full-text search. Includes specialized parsers for different documentation types and exposes tools for searching hooks, retrieving documentation, and browsing the complete reference.', '@florinel-chis', 'databases', 'Unknown', 4, 'https://github.com/florinel-chis/prestashop-mcp', NULL, 0, 'https://github.com/florinel-chis.png?size=128', '2026-03-09T05:21:01.968481+00:00'),
  ('shopify-liquid', 'Shopify Liquid', 'Shopify Liquid MCP Server, built by Florinel Chis, provides AI assistants with instant access to comprehensive Shopify Liquid documentation through a local SQLite FTS5 database. The server exposes seven specialized tools for searching and retrieving documentation about Liquid''s 30 tags, 101 filters, and 67 objects, with full-text search capabilities and snippet highlighting. Built using FastMCP, it delivers sub-millisecond response times for offline-first operation, making it ideal for developers building Shopify themes who need quick access to syntax references, examples, and API documentation during development workflows. The implementation ingests markdown files from a structured docs-source directory and supports customization with project-specific documentation.', '@florinel-chis', 'databases', 'Unknown', 2, 'https://github.com/florinel-chis/shopify-liquid-mcp', NULL, 0, 'https://github.com/florinel-chis.png?size=128', '2026-03-09T05:21:01.968492+00:00'),
  ('microsoft-teams', 'Microsoft Teams', 'This MCP server provides Microsoft Teams integration through the Microsoft Graph API, enabling AI assistants to interact with Teams chats, channels, messages, and users. Built by Floris Cornel using TypeScript with Azure identity authentication, it offers tools for searching messages across Teams and chats, retrieving recent messages with advanced filtering, managing mentions and notifications, sending messages to channels and chats, creating new group chats, and comprehensive user/team/channel management operations. The implementation features device code authentication flow for secure Microsoft Graph access, intelligent search capabilities with scope filtering (channels vs chats), message filtering by date ranges and importance levels, and fallback mechanisms when advanced search APIs are unavailable, making it valuable for Teams-heavy organizations that want AI assistance in managing communications, tracking mentions, analyzing message patterns, and automating routine Teams interactions without leaving their AI workflow.', '@floriscornel', 'cloud', 'Unknown', 59, 'https://github.com/floriscornel/teams-mcp', '@floriscornel/teams-mcp', 9343, 'https://github.com/floriscornel.png?size=128', '2026-03-09T05:21:01.968515+00:00'),
  ('sec-edgar', 'SEC EDGAR', 'edgar-sec-mcp is an MCP server that enables AI agents to access and analyze SEC EDGAR filings data. Built by Josh Floth, it provides tools for retrieving proxy statements containing executive compensation information and Form 4 filings for insider trading details. The implementation uses the SEC''s public API with proper user-agent headers, parses HTML tables from filings into CSV format, and handles CIK lookups by ticker symbol with caching support. Particularly valuable for financial analysis workflows that require extracting structured data from regulatory filings without leaving the conversation interface.', '@flothjl', 'ai-ml', 'Unknown', 5, 'https://github.com/flothjl/edgar-sec-mcp', NULL, 0, 'https://github.com/flothjl.png?size=128', '2026-03-09T05:21:01.968561+00:00'),
  ('finance', 'Finance', 'Provides financial research capabilities through composable agent workflows built on the FlowLLM framework. Integrates web search (Dashscope, Tavily), Crawl4AI web scraping, and Tushare financial data APIs to enable deep research on stocks, funds, and other financial instruments. Features ReAct-style agents that iteratively gather evidence through tool calls, extract security codes from natural language queries, and compress multi-step research into structured reports. Includes specialized tools for Chinese A-share market data through TongHuaShun integration.', '@flowllm-ai', 'development', 'Unknown', 18, 'https://github.com/flowllm-ai/finance-mcp', NULL, 0, 'https://github.com/flowllm-ai.png?size=128', '2026-03-09T05:21:01.968587+00:00'),
  ('imagician', 'Imagician', 'Imagician is an MCP server for image editing operations built by Hongyi Wang using the Sharp library. It provides eight core tools for resizing, format conversion (JPEG, PNG, WebP, AVIF), cropping, compression, rotation, flipping, metadata extraction, and batch processing of images. The server handles common image manipulation tasks through a clean API that automatically creates output directories and provides detailed feedback on operations like compression savings and file sizes. Useful for automating image workflows, generating responsive image sets, optimizing images for web deployment, or performing bulk image transformations without requiring external image editing software.', '@flowy11', 'productivity', 'Unknown', 19, 'https://github.com/flowy11/imagician', '@flowy11/imagician', 428, 'https://github.com/flowy11.png?size=128', '2026-03-09T05:21:01.968637+00:00'),
  ('flowzap', 'FlowZap', 'Enables AI assistants to generate interactive workflow and sequence diagrams through FlowZap''s text-based DSL. Provides tools for syntax validation, diagram creation with shareable playground URLs, and documentation retrieval. Supports dual-view rendering where the same code displays as either workflow or sequence diagrams.', '@flowzap-xyz', 'development', 'Unknown', 1, 'https://github.com/flowzap-xyz/flowzap-mcp', NULL, 0, 'https://github.com/flowzap-xyz.png?size=128', '2026-03-09T05:21:01.968657+00:00'),
  ('painter-canvas-drawing', 'Painter (Canvas Drawing)', 'A drawing tool server that provides AI assistants with canvas manipulation capabilities through a simple interface. Built with TypeScript, it enables creating canvases, drawing filled rectangles with custom colors, and exporting the results as PNG images or raw pixel data. Particularly useful for AI assistants that need to create or edit basic images through natural language commands, as demonstrated by the included cowboy drawing example.', '@flrngel', 'development', 'Unknown', 11, 'https://github.com/flrngel/mcp-painter', NULL, 0, 'https://github.com/flrngel.png?size=128', '2026-03-09T05:21:01.968683+00:00'),
  ('better-fetch', 'Better Fetch', 'Advanced web scraping MCP server that provides intelligent website crawling with nested URL fetching and clean markdown conversion. Built with TypeScript using Cheerio for HTML parsing and Turndown for markdown conversion, it offers two main tools: single-page fetching and multi-page crawling with configurable depth limits, domain restrictions, URL filtering patterns, and smart content extraction that removes navigation elements and advertisements. The implementation includes respectful crawling with delays, timeout handling, and generates well-structured documentation with table of contents, making it ideal for creating comprehensive documentation from websites, research data collection, and content migration workflows.', '@flutterninja9', 'development', 'Unknown', 10, 'https://github.com/flutterninja9/better-fetch', 'better-fetch-mcp', 4496, 'https://github.com/flutterninja9.png?size=128', '2026-03-09T05:21:01.968716+00:00'),
  ('kubernetes-manager', 'Kubernetes Manager', 'This MCP server, developed by Flux159, enables AI assistants like Claude to interact with Kubernetes clusters. It provides tools for listing pods, services, deployments, and namespaces, as well as creating and deleting pods. The server integrates with kubectl and automatically connects to the current context, allowing seamless management of Kubernetes resources through natural language commands. By bridging AI capabilities with Kubernetes operations, this implementation facilitates easier cluster management and troubleshooting. It is particularly useful for DevOps teams looking to streamline their Kubernetes workflows, developers needing quick access to cluster information, or system administrators performing routine cluster maintenance tasks through AI-assisted interactions.', '@flux159', 'cloud', 'Unknown', 1339, 'https://github.com/flux159/mcp-server-kubernetes', NULL, 0, 'https://github.com/flux159.png?size=128', '2026-03-09T05:21:01.968739+00:00'),
  ('modal-serverless-python', 'Modal (Serverless Python)', 'This Modal MCP server, developed by the Server Modal team, enables deployment of Python scripts to Modal''s serverless compute platform. It integrates with Modal''s API to provide a streamlined interface for running code in the cloud. The server abstracts the complexities of Modal''s infrastructure, offering operations for script deployment, execution, and result retrieval. By connecting AI systems with Modal''s scalable computing resources, this implementation allows for on-demand execution of Python code without managing servers. It is particularly useful for AI applications requiring distributed computing, data processing pipelines, or any system that needs to run Python scripts efficiently in a cloud environment.', '@flux159', 'development', 'Unknown', 4, 'https://github.com/flux159/mcp-server-modal', NULL, 0, 'https://github.com/flux159.png?size=128', '2026-03-09T05:21:01.968768+00:00'),
  ('flux-image-generator-black-forest-lab', 'FLUX Image Generator (Black Forest Lab)', 'FLUX Image Generator server provides a bridge to Black Forest Lab''s FLUX model for AI image generation. Built with TypeScript and the latest MCP SDK, it exposes tools for generating single images with customizable parameters like dimensions and safety settings, quick image generation with sensible defaults, and batch processing of multiple prompts. The implementation features robust error handling, configurable output paths, and detailed logging, making it valuable for users who need programmatic access to FLUX''s capabilities through natural language requests.', '@frankdeno', 'development', 'Unknown', 1, 'https://github.com/frankdeno/flux-image-generator-mcp', NULL, 0, 'https://github.com/frankdeno.png?size=128', '2026-03-09T05:21:01.968797+00:00'),
  ('dicom-connectivity', 'DICOM Connectivity', 'This MCP server implementation provides DICOM connectivity testing capabilities through a Model Context Protocol interface. Developed by Flux Inc., it offers tools for listing DICOM nodes, performing C-ECHO operations, and managing node configurations. The server is designed for use cases requiring DICOM network testing and diagnostics, such as verifying connectivity to PACS systems or troubleshooting medical imaging workflows.', '@fluxinc', 'development', 'Unknown', 3, 'https://github.com/fluxinc/dicom-mcp-server', NULL, 0, 'https://github.com/fluxinc.png?size=128', '2026-03-09T05:21:01.968821+00:00'),
  ('open-search', 'Open Search', 'This MCP server provides AI assistants with comprehensive web search, academic research, and content extraction capabilities through a free, open-source alternative to paid search APIs, built by Open Search MCP Contributors using TypeScript with dual MCP/HTTP API operation modes. The implementation aggregates multiple search engines (DuckDuckGo, Google, Bing), academic databases (arXiv, PubMed, IEEE), social platforms (Reddit, GitHub), and news sources with intelligent load balancing, health monitoring, and failover mechanisms across distributed Searx clusters. Features advanced PDF processing with OCR support, AI-powered query optimization through local Ollama models (Llama 3.2, Qwen 2.5), semantic search with vector databases, and multi-platform integration for Claude Desktop, Cursor, VSCode, and Windsurf, serving researchers needing comprehensive literature review capabilities, developers requiring real-time technical information gathering, and teams building knowledge-intensive applications without relying on expensive third-party search APIs.', '@flyanima', 'databases', 'Unknown', 2, 'https://github.com/flyanima/open-search-mcp', NULL, 0, 'https://github.com/flyanima.png?size=128', '2026-03-09T05:21:01.968880+00:00'),
  ('flyto-core', 'Flyto Core', 'Secure execution engine for AI agents. 300+ modules, SSRF protection, secrets proxy.', '@flytohub', 'ai-ml', 'Unknown', 208, 'https://github.com/flytohub/flyto-core', NULL, 0, 'https://github.com/flytohub.png?size=128', '2026-03-09T05:21:01.968904+00:00'),
  ('flyto-indexer', 'Flyto Indexer', 'Code intelligence MCP server: impact analysis, dependency graphs, dead code detection.', '@flytohub', 'development', 'Unknown', 3, 'https://github.com/flytohub/flyto-indexer', NULL, 0, 'https://github.com/flytohub.png?size=128', '2026-03-09T05:21:01.968922+00:00'),
  ('datafocus', 'Datafocus', 'A Model Context Protocol (MCP) server enables artificial intelligence assistants to directly query data results. Users obtain data results in natural language.', '@focussearch', 'ai-ml', 'Unknown', 14, 'https://github.com/focussearch/focus_mcp_data', NULL, 0, 'https://github.com/focussearch.png?size=128', '2026-03-09T05:21:01.968946+00:00'),
  ('focus-sql', 'Focus SQL', 'Focus MCP SQL Server enables AI assistants to convert natural language queries into SQL by registering database schema information and handling text-to-SQL conversions. Built by DataFocus, it implements the Model Context Protocol using Spring Boot and exposes tools for registering tables, columns, and relationships, as well as initiating and continuing text-to-SQL conversations. The server runs on stdio transport for seamless integration with AI assistants and provides a structured approach to database schema representation, making it particularly valuable for users who need to query databases using natural language without writing SQL manually.', '@focussearch', 'databases', 'Unknown', 38, 'https://github.com/focussearch/focus_mcp_sql', NULL, 0, 'https://github.com/focussearch.png?size=128', '2026-03-09T05:21:01.968957+00:00'),
  ('adzuna-job-search', 'Adzuna Job Search', 'Integrates with the Adzuna Job Search API to provide comprehensive job market intelligence. Offers tools for searching millions of job listings with filters for location, salary, and job type, plus salary analytics including distribution data, regional comparisons, and historical trends. Supports employer research to identify top hiring companies across 12 international markets with local currency support.', '@folathecoder', 'search', 'Unknown', 10, 'https://github.com/folathecoder/adzuna-job-search-mcp', NULL, 0, 'https://github.com/folathecoder.png?size=128', '2026-03-09T05:21:01.968995+00:00'),
  ('folderr', 'Folderr', 'This Folderr MCP server, developed by santiq, provides a bridge to interact with Folderr''s API, specifically for managing and communicating with Folderr Assistants. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers tools for authentication, listing assistants, and sending questions to specific assistants. The server implements error handling and configuration management, storing settings in a config.json file. By abstracting the complexities of the Folderr API, it enables AI systems to easily interact with Folderr''s assistant ecosystem. This implementation is particularly valuable for applications requiring programmatic access to Folderr Assistants, facilitating use cases such as automated task delegation, multi-assistant orchestration, and AI-enhanced workflow management.', '@folderr-tech', 'development', 'Unknown', 2, 'https://github.com/folderr-tech/folderr-mcp-server', '@folderr/folderr-mcp-server', 3683, 'https://github.com/folderr-tech.png?size=128', '2026-03-09T05:21:01.969027+00:00'),
  ('nature-vision', 'Nature Vision', 'Identifies biological species from images using the Nature Vision API. Supports recognition across multiple categories including plants, bugs, birds, mammals, reptiles, amphibians, molluscs, and fungi, returning scientific Latin nomenclature with confidence scores for each identification.', '@fonkychen', 'media', 'Unknown', 0, 'https://github.com/fonkychen/nature-vision-mcp', NULL, 0, 'https://github.com/fonkychen.png?size=128', '2026-03-09T05:21:01.969073+00:00'),
  ('fooddata-central', 'FoodData Central', 'A Model Context Protocol server that provides access to the USDA''s FoodData Central database, allowing AI assistants to search for foods and retrieve detailed nutritional information. The implementation supports searching by keywords, retrieving food details by ID, accessing multiple foods simultaneously, and listing foods with pagination options. It exposes both MCP resources for direct data access and tools for more complex search operations, making it useful for nutrition analysis, meal planning, and dietary information retrieval applications.', '@jlfwong', 'databases', 'Unknown', 10, 'https://github.com/jlfwong/food-data-central-mcp-server', NULL, 0, 'https://github.com/jlfwong.png?size=128', '2026-03-09T05:21:01.969084+00:00'),
  ('open-meteo-weather', 'Open-Meteo Weather', 'This weather server integrates with the Open-Meteo API to provide current weather data retrieval with user authentication via GitHub OAuth 2.0. Built with Express.js and SQLite, it features location management capabilities allowing users to save custom location labels (like ''home'' or ''office'') for quick weather lookups, supports both Celsius and Fahrenheit units, and includes OAuth 2.0 server implementation with PKCE support for secure client authentication. The server provides tools for weather retrieval, location management, and user profile access, making it useful for personal weather tracking applications and demonstrating OAuth-secured MCP server patterns.', '@f', 'databases', 'Unknown', 12, 'https://github.com/f/komunite-mcp-bootcamp-weather-mcp', NULL, 0, 'https://github.com/f.png?size=128', '2026-03-09T05:21:01.969143+00:00'),
  ('foqal', 'Foqal', 'Foqal transforms Slack and Microsoft Teams into comprehensive support platforms for IT helpdesk, customer support, and HR operations. The MCP server enables AI assistants to create and manage tickets, access user information and request histories, update ticket statuses, execute workflow automations, and search knowledge base articles. Integrates with enterprise tools including Okta, Google Admin, Zendesk, Salesforce, Atlassian, and ServiceNow.', '@foqal', 'communication', 'Unknown', 0, 'https://github.com/foqal/mcp', NULL, 0, 'https://github.com/foqal.png?size=128', '2026-03-09T05:21:01.969175+00:00'),
  ('markdown-toc', 'Markdown TOC', 'A markdown table of contents extraction and generation server that parses markdown documents to extract existing heading structures and generate formatted TOCs. Built by ForceInjection, it includes a dedicated extractor module for parsing markdown headers, comprehensive test coverage with edge case handling, and shell scripts for easy deployment management. The implementation supports various markdown heading formats and provides structured TOC output with robust error handling, making it useful for documentation management, content organization, and automated markdown processing workflows.', '@forceinjection', 'development', 'Unknown', 1, 'https://github.com/forceinjection/markdown-mcp', NULL, 0, 'https://github.com/forceinjection.png?size=128', '2026-03-09T05:21:01.969206+00:00'),
  ('forex-gpt', 'Forex-GPT', 'Provides technical analysis and trading signals across 127+ financial instruments including forex pairs, cryptocurrencies, commodities, indices, and bonds. Offers multi-timeframe analysis, watchlist management, and real-time market insights through natural language interaction. Includes sentiment scoring, market scanning, and automated daily analysis.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://forex-gpt.ai', NULL, 0, NULL, '2026-03-09T05:21:01.969239+00:00'),
  ('mcp-registry', 'MCP Registry', 'Provides tools to interact with the Model Context Protocol Registry, enabling discovery and searching of available MCP servers. Supports pagination with configurable result limits (1-100, default 50), cursor-based navigation, and custom registry endpoints. Returns server metadata optimized for semantic analysis and exploration.', '@formulahendry', 'ai-ml', 'Unknown', 4, 'https://github.com/formulahendry/mcp-server-mcp-registry', NULL, 0, 'https://github.com/formulahendry.png?size=128', '2026-03-09T05:21:01.969292+00:00'),
  ('spec-driven-development', 'Spec-Driven Development', 'A spec-driven development MCP server by Jun Han that provides three sequential prompts to guide software development from high-level requirements through to code generation. The server offers prompts for generating requirements documents using EARS format, creating design documents from requirements, and finally generating code from design specifications, supporting a structured waterfall-style development workflow. Built with TypeScript and supporting both stdio and HTTP transports, it''s particularly useful for developers who prefer a methodical, documentation-first approach to building applications where each phase builds upon the previous one''s output.', '@formulahendry', 'development', 'Unknown', 427, 'https://github.com/formulahendry/mcp-server-spec-driven-development', 'mcp-server-spec-driven-development', 1689, 'https://github.com/formulahendry.png?size=128', '2026-03-09T05:21:01.969319+00:00'),
  ('timelooker', 'TimeLooker', 'TimeLooker is an intelligent web monitoring system that combines MCP server capabilities with AWS Lambda deployment for automated search task execution and change detection. Built by fortnightly-devs using Python with Anthropic Claude API integration, it enables users to create paid monitoring tasks through x402 payment protocol that automatically search the web at specified intervals, use AI-powered duplicate detection to identify genuinely new results, and send email notifications when changes are found. The implementation features both local SQLite and cloud PostgreSQL database support, dynamic Lambda function deployment with EventBridge scheduling, SES email templating, and a FastAPI service layer, making it valuable for job search monitoring, product release tracking, academic opportunity discovery, and any scenario requiring intelligent automated web surveillance with payment-gated task creation.', '@fortnightly-devs', 'databases', 'Unknown', 2, 'https://github.com/fortnightly-devs/mcp-x402-task-scheduler', NULL, 0, 'https://github.com/fortnightly-devs.png?size=128', '2026-03-09T05:21:01.969331+00:00'),
  ('forward-networks', 'Forward Networks', 'This MCP server provides complete Forward Networks API integration for network analysis, path tracing, and device management, enabling AI-powered query discovery through semantic search of NQE (Network Query Engine) queries with embedding-based similarity matching. Built using Go with the mcp-golang library, it offers 25+ tools covering network topology analysis, path search with traffic simulation, device inventory management, configuration auditing, snapshot comparison, and intelligent query recommendations through a curated library of executable network analysis queries. The implementation features semantic caching for performance optimization, offline AI search capabilities with pre-generated embeddings, comprehensive error handling with TLS certificate support, and workflow-based prompts for guided network discovery, making it valuable for network troubleshooting, compliance auditing, infrastructure planning, and building AI assistants that need deep network visibility without manual platform access.', '@forwardnetworks', 'development', 'Unknown', 4, 'https://github.com/forwardnetworks/forward-mcp', NULL, 0, 'https://github.com/forwardnetworks.png?size=128', '2026-03-09T05:21:01.969410+00:00'),
  ('binary-ninja', 'Binary Ninja', 'Binary Ninja MCP provides a bridge between the Binary Ninja reverse engineering platform and large language models through a HTTP server that exposes binary analysis capabilities. The plugin enables users to perform tasks like listing functions, decompiling code, renaming symbols, and analyzing binary structures directly through LLM interfaces. Built with Python 3.12, it features a modular architecture with separate components for binary operations, API endpoints, and server management. The implementation is particularly optimized for Claude Desktop integration, allowing reverse engineers to leverage AI assistance for complex binary analysis workflows without leaving their development environment.', '@fosdickio', 'development', 'Unknown', 255, 'https://github.com/fosdickio/binary_ninja_mcp', NULL, 0, 'https://github.com/fosdickio.png?size=128', '2026-03-09T05:21:01.969437+00:00'),
  ('foundry-toolkit', 'Foundry Toolkit', 'Foundry MCP Server provides AI assistants with complete access to the Foundry blockchain development toolkit, enabling smart contract deployment, testing, and analysis through Cast, Anvil, and Forge integration. Built by Pranesh ASP, the implementation manages a persistent workspace at ~/.mcp-foundry-workspace, supports local Anvil instances and remote EVM networks, and includes advanced bytecode analysis through Heimdall-rs for disassembly, decompilation, and transaction inspection. Designed for developers who want conversational access to Ethereum development workflows without manual command-line operations, supporting everything from balance queries and contract calls to script execution and detailed transaction analysis across multiple EVM-compatible chains.', '@praneshasp', 'development', 'Unknown', 241, 'https://github.com/praneshasp/foundry-mcp-server', '@pranesh.asp/foundry-mcp-server', 1116, 'https://github.com/praneshasp.png?size=128', '2026-03-09T05:21:01.969466+00:00'),
  ('foundry-vtt', 'Foundry VTT', 'Foundry VTT MCP Bridge by Adam Dooley that connects Claude Desktop with Foundry Virtual Tabletop game sessions through a Socket.IO-based server and Foundry module combination. The implementation provides AI assistants with access to live game data including character sheets with stats/items/effects, scene information with tokens and maps, compendium searches across game systems, world metadata, and user information, enabling use cases like character analysis, rules lookups, campaign planning, and real-time game assistance. Built with TypeScript and featuring a Windows installer with automated Claude Desktop configuration, shared type definitions with Zod validation, and comprehensive error handling, it serves GMs and players who want AI integration for D&D/Pathfinder sessions, campaign management, and rules assistance without manual data entry.', '@adambdooley', 'development', 'Unknown', 36, 'https://github.com/adambdooley/foundry-vtt-mcp', NULL, 0, 'https://github.com/adambdooley.png?size=128', '2026-03-09T05:21:01.969504+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('foxit-pdf-api', 'Foxit PDF API', 'Provides access to Foxit''s cloud-based PDF Services API capabilities for automated document processing. Enables PDF creation, conversion between formats, document manipulation (merge, extract, compress), protection, and optimization. Requires Foxit cloud API credentials from the developer portal.', '@foxitsoftware', 'development', 'Unknown', 10, 'https://github.com/foxitsoftware/foxit-pdf-api-mcp-server', NULL, 0, 'https://github.com/foxitsoftware.png?size=128', '2026-03-09T05:21:01.969588+00:00'),
  ('prompts-chat', 'Prompts.chat', 'Acts as a proxy server that forwards requests to the prompts.chat API, providing access to a curated collection of thousands of AI prompts. Implements both the prompts protocol for listing and retrieving prompts, as well as custom tools for searching prompts by keyword with filtering options (type, category, tag) and fetching individual prompts by ID. Supports automatic variable substitution for template prompts containing ${variable} syntax.', '@f', 'communication', 'Unknown', 25, 'https://github.com/f/prompts.chat-mcp', NULL, 0, 'https://github.com/f.png?size=128', '2026-03-09T05:21:01.969620+00:00'),
  ('midnight-next-js', 'Midnight + Next.js', 'Provides development tools for Midnight Network blockchain applications. Includes smart contract compilation, deployment, and analysis for Compact contracts, wallet management for tDUST tokens, network querying, and documentation search. Also integrates Next.js DevTools for building decentralized applications with features like browser automation and dev server discovery.', '@fractionestate', 'development', 'Unknown', 0, 'https://github.com/fractionestate/midnight-nextjs-mcp', NULL, 0, 'https://github.com/fractionestate.png?size=128', '2026-03-09T05:21:01.969641+00:00'),
  ('cloudflare-ai-to-markdown', 'Cloudflare AI to Markdown', 'MCP Server to Markdown provides a bridge between Claude and Cloudflare''s AI services, enabling the conversion of various file formats to markdown descriptions. This implementation authenticates with Cloudflare using API credentials, supports multiple file types including PDFs, images, HTML, and Office documents, and handles file uploads through a secure curl-based approach. The server exposes a single tool that processes files by sending them to Cloudflare''s tomarkdown API endpoint and returns structured descriptions with metadata. Particularly valuable for workflows that require detailed content analysis and documentation generation without leaving the conversation interface.', '@fradser', 'cloud', 'Unknown', 35, 'https://github.com/fradser/mcp-server-to-markdown', 'mcp-server-to-markdown', 410, 'https://github.com/fradser.png?size=128', '2026-03-09T05:21:01.969663+00:00'),
  ('local-web-search', 'Local Web Search', 'This MCP server implementation provides a local web search capability, integrating with a headless browser to perform Google searches and extract content from web pages. Developed by Frad Lee, it offers features such as customizable search queries, result limiting, domain exclusion, and content truncation. The server uses the Readability library to clean and parse web content, converting it to markdown format. It''s designed for AI assistants and other MCP-compatible clients that require up-to-date web information without direct internet access. The implementation is particularly useful for tasks like research, content aggregation, and information retrieval across various domains.', '@fradser', 'productivity', 'Unknown', 10, 'https://github.com/fradser/mcp-server-local-web-search', NULL, 0, 'https://github.com/fradser.png?size=128', '2026-03-09T05:21:01.969709+00:00'),
  ('sequential-thinking-multi-agent-system', 'Sequential Thinking Multi-Agent System', 'Sequential Thinking Multi-Agent System (MAS) implements a coordinated team of specialized AI agents to break down complex problems through structured thinking steps. Built by Frad LEE using the Agno framework and DeepSeek models, this server orchestrates a Team Coordinator, Strategic Planner, Researcher (with Exa search capabilities), Core Analyzer, Quality Controller, and Integration Specialist working in parallel to process thoughts with greater depth than single-agent approaches. The implementation supports revision steps, branching analysis paths, and provides detailed guidance throughout the thinking process, making it particularly valuable for multi-disciplinary problem solving requiring diverse expertise and comprehensive analysis.', '@fradser', 'ai-ml', 'Unknown', 289, 'https://github.com/fradser/mcp-server-mas-sequential-thinking', 'mcp-server-mas-sequential-thinking', 7065, 'https://github.com/fradser.png?size=128', '2026-03-09T05:21:01.969761+00:00'),
  ('fragments', 'Fragments', 'Design system MCP with 9 tools for component discovery, rendering, and a11y auditing.', '@conanmcn', 'ai-ml', 'Unknown', 3, 'https://github.com/conanmcn/fragments/tree/HEAD/packages/mcp', NULL, 0, 'https://github.com/conanmcn.png?size=128', '2026-03-09T05:21:01.969784+00:00'),
  ('bloom-growth', 'Bloom Growth', 'This MCP server implementation provides a bridge to the Bloom Growth GraphQL API, enabling AI assistants to interact with Bloom''s growth management platform. Developed by Franccesco Orozco, it utilizes the MCP framework to expose Bloom''s functionality through a standardized interface. The server supports authentication via environment variables and includes error handling capabilities. It''s particularly useful for AI-assisted workflows requiring integration with growth management and analytics tools.', '@franccesco', 'ai-ml', 'Unknown', 0, 'https://github.com/franccesco/bloomy-mcp', NULL, 0, 'https://github.com/franccesco.png?size=128', '2026-03-09T05:21:01.969821+00:00'),
  ('hex', 'Hex', 'This MCP server implementation provides a bridge to the Hex API, enabling AI assistants to interact with Hex projects. Developed by Franccesco, it utilizes the httpx library for making HTTP requests and integrates with the MCP CLI. The server offers tools for retrieving project details, listing projects, viewing and managing project runs, and executing projects with custom parameters. It''s designed for use cases requiring automated data analysis, report generation, or integration of Hex workflows into AI-assisted applications.', '@franccesco', 'productivity', 'Unknown', 5, 'https://github.com/franccesco/hex-mcp', NULL, 0, 'https://github.com/franccesco.png?size=128', '2026-03-09T05:21:01.969873+00:00'),
  ('transaction-categorizer', 'Transaction Categorizer', 'The Transaction Categoriser MCP server provides AI assistants with the ability to process and organize financial transaction data. Built with Python using the FastMCP framework, it reads transaction files from a specified folder and categorizes them into predefined expense categories (such as Food/drinks, Transportation, Utilities) and income categories (Paycheck, Rental income, Other). The server outputs the categorized transactions in CSV format with date, amount, description, and category fields, making it particularly useful for personal finance management, expense tracking, and financial data organization within AI assistant conversations.', '@francesliang', 'ai-ml', 'Unknown', 0, 'https://github.com/francesliang/custom_mcp_servers', NULL, 0, 'https://github.com/francesliang.png?size=128', '2026-03-09T05:21:01.969920+00:00'),
  ('rocketmq', 'RocketMQ', 'A Message Context Protocol (MCP) server implementation for RocketMQ, allowing AI applications to interact with RocketMQ message queues.', '@francisoliverlee', 'ai-ml', 'Unknown', 4, 'https://github.com/francisoliverlee/rocketmq-mcp', NULL, 0, 'https://github.com/francisoliverlee.png?size=128', '2026-03-09T05:21:01.969945+00:00'),
  ('snippets', 'Snippets', 'Stores, searches, and manages code snippets using AI-powered semantic search combined with traditional keyword matching. Built using the Xenova/all-MiniLM-L6-v2 model for vector embeddings, it provides tools for adding snippets with automatic language detection, updating and deleting snippets with re-embedding when needed, and hybrid search that combines semantic similarity (70% weight) with keyword matching (30% weight) across code, descriptions, tags, and language fields. The implementation uses JSON-based storage with cached embeddings for fast retrieval, supports filtering by tags, language, and date ranges, and requires no external database setup.', '@freakynit', 'databases', 'Unknown', 1, 'https://github.com/freakynit/snippets-mcp', NULL, 0, 'https://github.com/freakynit.png?size=128', '2026-03-09T05:21:01.969956+00:00'),
  ('fred-federal-reserve-economic-data', 'FRED (Federal Reserve Economic Data)', 'FRED MCP Server provides AI assistants with access to Federal Reserve Economic Data through a secure proxy interface. Built with Python using the mcp-server library, it offers tools for searching, retrieving, and analyzing economic data series with features like rate limiting and caching. The implementation includes specialized tools for comparing multiple indicators, calculating statistics, and detecting trends in time series data. It also provides prompt templates to guide users in effectively utilizing FRED data for economic analysis. Particularly valuable for applications requiring real-time economic data analysis, financial research, and macroeconomic trend identification.', '@milind-kulshrestha', 'ai-ml', 'Unknown', 2, 'https://github.com/milind-kulshrestha/fred_mcp_server', NULL, 0, 'https://github.com/milind-kulshrestha.png?size=128', '2026-03-09T05:21:01.970006+00:00'),
  ('headline-vibes', 'Headline Vibes', 'This MCP server, developed by Fred Em, provides sentiment analysis for news headlines from major US publications. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers tools for analyzing headline sentiment on specific dates or using natural language queries. The implementation focuses on providing a normalized sentiment score, source distribution information, and sample headlines. By connecting AI models with current news sentiment data, this server enables sophisticated analysis of media trends and public opinion. It''s particularly useful for applications and AI assistants that require insights into news sentiment, supporting use cases such as market analysis, public relations monitoring, and social media trend forecasting.', '@fred-em', 'development', 'Unknown', 6, 'https://github.com/fred-em/headline-vibes', NULL, 0, 'https://github.com/fred-em.png?size=128', '2026-03-09T05:21:01.970036+00:00'),
  ('fred-macroeconomic-data', 'FRED Macroeconomic Data', 'A Federal Reserve Economic Data (FRED) MCP server that provides access to macroeconomic indicators through Claude and other LLM clients. The implementation connects to the FRED API to retrieve real-time economic data series including GDP, employment statistics, inflation metrics, and monetary policy indicators. It offers tools for searching FRED series by description and fetching time-series data with customizable parameters. This server enables AI assistants to incorporate authoritative economic data into analyses, visualizations, and forecasts without requiring users to manually retrieve or format the information.', '@hungson175', 'ai-ml', 'Unknown', 10, 'https://github.com/hungson175/wm_mcp', NULL, 0, 'https://github.com/hungson175.png?size=128', '2026-03-09T05:21:01.970083+00:00'),
  ('multi-llm-api-gateway', 'Multi-LLM API Gateway', 'This MCP server implementation enables AI assistants to interact with multiple language model APIs through a unified interface. Built with Python using FastAPI, it supports both OpenAI and Anthropic models, allowing seamless switching between different AI providers. The server handles API authentication, request formatting, and streaming responses, while the accompanying client script provides a simple way to connect to the server. This implementation is particularly useful for developers who need to work with multiple AI models or want to create applications that can easily switch between different AI services without changing their core integration code.', '@freedanfan', 'development', 'Unknown', 10, 'https://github.com/freedanfan/mcp_server', NULL, 0, 'https://github.com/freedanfan.png?size=128', '2026-03-09T05:21:01.970111+00:00'),
  ('db-connector-mysql-postgresql', 'DB Connector (MySQL/PostgreSQL)', 'DB-MCP-Server provides a database connectivity layer for AI assistants through the Model Context Protocol, enabling direct interaction with MySQL and PostgreSQL databases. Built in Go, it supports both local stdio and production SSE transport modes, with configurable database connections through environment variables. The server can be deployed using Docker for easy integration into existing workflows, making it ideal for AI applications that need to query, analyze, or manipulate structured data stored in relational databases without requiring separate database access tools.', '@freepeak', 'databases', 'Unknown', 351, 'https://github.com/freepeak/db-mcp-server', NULL, 0, 'https://github.com/freepeak.png?size=128', '2026-03-09T05:21:01.970123+00:00'),
  ('freepik', 'Freepik', 'This MCP server provides integration with Freepik''s API for accessing icons, resources, and AI-powered image generation capabilities. Built using Python with FastMCP and httpx, it offers tools for searching and downloading icons, managing resources, AI image classification, and advanced text-to-image generation through Freepik''s Mystic AI service with polling-based job completion. The implementation features dynamic API key configuration, OpenAPI specification caching, custom route mapping for security, and specialized handling of asynchronous AI operations, making it valuable for automated design workflows, content creation pipelines, and building AI assistants that need access to Freepik''s extensive design asset library and AI generation tools.', '@freepik-company', 'development', 'Unknown', 32, 'https://github.com/freepik-company/freepik-mcp', NULL, 0, 'https://github.com/freepik-company.png?size=128', '2026-03-09T05:21:01.970152+00:00'),
  ('pdf-search', 'PDF Search', 'This PDF Search extension for Zed, developed by stano, enables semantic searching of PDF documents and integrates results with Zed''s AI Assistant. It uses a Qdrant vector database for storing document embeddings and OpenAI''s API for generating them. The extension implements a RAG-style approach, allowing users to query PDF content through Zed''s interface. Built with Rust and Python, it offers a unique combination of Zed integration and semantic PDF search capabilities. This tool is particularly useful for researchers, students, or professionals who frequently work with PDF documents and need quick, context-aware access to their contents within their coding environment.', '@freespirit', 'databases', 'Unknown', 3, 'https://github.com/freespirit/pdfsearch-zed', 'pdfsearch', 0, 'https://github.com/freespirit.png?size=128', '2026-03-09T05:21:01.970216+00:00'),
  ('12306-railway', '12306 Railway', 'This MCP server provides integration with China''s 12306 railway ticket booking system, enabling AI assistants to search for train tickets, check schedules, and retrieve route information across the Chinese railway network. Built with TypeScript and using axios for HTTP requests, it interfaces with the official 12306 API to fetch real-time ticket availability, pricing information across different seat classes, and detailed station data including departure/arrival times and journey durations. The implementation includes support for both direct routes and interline connections, comprehensive data parsing for ticket information and station details, and date handling with timezone support, making it valuable for travel planning applications that need to help users navigate China''s extensive high-speed rail system and book appropriate train tickets.', '@freestylefly', 'development', 'Unknown', 12, 'https://github.com/freestylefly/12306-mcp', '12306-mcp', 41490, 'https://github.com/freestylefly.png?size=128', '2026-03-09T05:21:01.970249+00:00'),
  ('autoform-slovensko-digital', 'Autoform (Slovensko.Digital)', 'Integrates with the Autoform API from Slovensko.Digital to search and retrieve information about Slovak corporate entities. Built by freevision, this Python-based server enables searches by company name, identification number (IČO), or other criteria with support for filtering active companies and limiting result sets. Returns structured data including company details, addresses, registration information, and tax IDs. Handles authentication through environment variables or HTTP headers with comprehensive error handling and sanitized logging to prevent token leakage.', '@freevisionsk', 'development', 'Unknown', 7, 'https://github.com/freevisionsk/autoform-mcp', NULL, 0, 'https://github.com/freevisionsk.png?size=128', '2026-03-09T05:21:01.970287+00:00'),
  ('french-business-search', 'French Business Search', 'Data Gouv MCP Server provides a bridge to the French government''s data APIs, specifically enabling searches for detailed company information through the API Recherche Entreprises. Built by csonigo, this server implements the HTTP+SSE transport protocol and exposes a single tool that retrieves comprehensive business details including names, addresses, directors, and sector information when provided with a search query. The implementation is designed to run locally with Node.js and can be easily configured with any MCP client, making it valuable for workflows requiring access to official French business registry data without leaving the conversation interface.', '@csonigo', 'ai-ml', 'Unknown', 11, 'https://github.com/csonigo/datagouv-mcp-server', NULL, 0, 'https://github.com/csonigo.png?size=128', '2026-03-09T05:21:01.970337+00:00'),
  ('texas-hold-em-poker', 'Texas Hold''em Poker', 'Texas Hold''em poker game server that enables AI agents to play poker through a standardized interface. Built with Node.js and TypeScript, it implements core poker game mechanics including betting rounds, hand evaluation, and multi-player table management. The server exposes tools for joining tables, placing bets, performing poker actions like check/fold/raise, and receiving real-time game state updates, making it valuable for training AI agents in strategic decision making and testing poker playing capabilities.', '@freshlife001', 'development', 'Unknown', 2, 'https://github.com/freshlife001/mcp_poker', NULL, 0, 'https://github.com/freshlife001.png?size=128', '2026-03-09T05:21:01.970364+00:00'),
  ('onenote-graph-api', 'OneNote Graph API', 'A Microsoft OneNote integration that enables AI agents to read and create notebooks, sections, and pages through the Microsoft Graph API. Uses Azure AD Device Code Flow for authentication with automatic token caching, making it accessible for desktop applications without requiring complex OAuth redirects. Provides tools for listing notebooks, sections, and pages, reading page content, and creating new OneNote structures with proper HTML formatting.', '@freshsk', 'cloud', 'Unknown', 1, 'https://github.com/freshsk/mcp_onenote', NULL, 0, 'https://github.com/freshsk.png?size=128', '2026-03-09T05:21:01.970381+00:00'),
  ('outlook-calendar', 'Outlook Calendar', 'A Microsoft Outlook integration server that provides access to email and calendar operations through Azure AD device code authentication with persistent token caching. Built with Node.js and the Microsoft Graph API, it offers mail tools for listing inbox messages, reading full email content, and sending new emails, plus calendar tools for viewing upcoming events and creating new meetings with automatic Microsoft Teams integration.', '@freshsk', 'cloud', 'Unknown', 1, 'https://github.com/freshsk/mcp_outlook_calendar', NULL, 0, 'https://github.com/freshsk.png?size=128', '2026-03-09T05:21:01.970398+00:00'),
  ('vibe-coder-ai-assisted-development', 'Vibe Coder (AI-Assisted Development)', 'Vibe Coder MCP Server provides a suite of AI-assisted development tools for semantic routing, code generation, refactoring, and project management. Built with TypeScript and Node.js, it leverages OpenRouter to connect with LLM services like Gemini and Perplexity for tasks ranging from research to code stub generation. The implementation features a hybrid matching system for intelligent request routing, sequential thinking for complex reasoning, and specialized tools for Git integration, dependency analysis, and workflow automation. This server is particularly valuable for developers seeking to streamline their workflow with AI assistance while maintaining a structured approach to software development tasks.', '@freshtechbro', 'development', 'Unknown', 97, 'https://github.com/freshtechbro/vibe-coder-mcp', NULL, 0, 'https://github.com/freshtechbro.png?size=128', '2026-03-09T05:21:01.970449+00:00'),
  ('inked-writing-assistant', 'Inked (Writing Assistant)', 'This Inked MCP server, developed by the Model Context Protocol team, provides tools for managing and generating long-form content through drafts. Built with TypeScript and leveraging SQLite or PostgreSQL for storage, it offers features like draft versioning, chapter organization, and multiple output formats including Markdown and plain text. The implementation focuses on intuitive conversation-based drafting and revision workflows. It''s particularly useful for AI assistants or applications supporting novelists, report writers, and other long-form content creators, enabling efficient content development without requiring deep knowledge of document formatting or version control systems.', '@coldielb', 'databases', 'Unknown', 16, 'https://github.com/coldielb/inked', NULL, 0, 'https://github.com/coldielb.png?size=128', '2026-03-09T05:21:01.970464+00:00'),
  ('netbox-infrastructure', 'NetBox Infrastructure', 'A NetBox infrastructure MCP server that provides secure access to network device, virtual machine, IP address, and VLAN data through HashiCorp Vault JIT token authentication and PostgreSQL-backed state confidence scoring. Built with multiple server variants including LLM-optimized and structured protocol implementations, it features performance optimizations like connection pooling, response caching, and retry strategies, plus tooling for hosts, VMs, IP addresses, and VLANs with optional certainty metadata. The implementation supports both development and production environments with extensive testing, CI/CD workflows, and devcontainer setup, making it useful for network automation, infrastructure monitoring, AI-assisted network management, and building network-aware applications that require reliable, authenticated access to NetBox data.', '@fringemonkey', 'databases', 'Unknown', 2, 'https://github.com/fringemonkey/mcp-dc', NULL, 0, 'https://github.com/fringemonkey.png?size=128', '2026-03-09T05:21:01.970476+00:00'),
  ('tealmcp-lua-code-execution', 'TealMCP (Lua Code Execution)', 'TealMCP is a Lua-based server implementation written in Teal (a typed dialect of Lua) that provides sandboxed code execution environments with session management, package management via LuaRocks, and filesystem operations. Built with a dependency injection container architecture, it supports both stdio and HTTPS transport modes, features persistent session state with snapshot capabilities, and includes tools for evaluating Lua code, managing rock dependencies, and performing file operations within isolated session environments. The implementation emphasizes type safety through Teal''s static typing system and provides a complete runtime environment for executing Lua code safely with configurable I/O permissions, making it useful for educational coding assistance, data analysis workflows, and prototyping Lua applications with proper isolation.', '@frityet', 'development', 'Unknown', 1, 'https://github.com/frityet/tealmcp', NULL, 0, 'https://github.com/frityet.png?size=128', '2026-03-09T05:21:01.970511+00:00'),
  ('ai-session-bridge', 'AI Session Bridge', 'AI Session Bridge provides cross-tool access to AI conversation history from VS Code Copilot, Cursor, and Rovodev sessions through a unified interface. The implementation scans workspace-specific storage directories, parses different session formats (JSON files, SQLite databases), and offers tools for listing, searching, and retrieving full conversation context with built-in content filtering for sensitive data. Designed for developers who want to maintain conversation continuity across different coding assistants, it enables use cases like resuming interrupted conversations, searching past interactions for solutions, and providing context from previous sessions to new conversations.', '@frknyldz', 'databases', 'Unknown', 4, 'https://github.com/frknyldz/ai-session-bridge', NULL, 0, 'https://github.com/frknyldz.png?size=128', '2026-03-09T05:21:01.970523+00:00'),
  ('expo-android', 'Expo Android', 'Provides Android device automation through ADB integration. Enables UI hierarchy inspection, touch interactions (tap, swipe, long-press), text input, element search by text or resource ID, screenshot capture, app launching, and key event sending for mobile testing and development workflows.', '@frndchagas', 'development', 'Unknown', 3, 'https://github.com/frndchagas/expo-android', NULL, 0, 'https://github.com/frndchagas.png?size=128', '2026-03-09T05:21:01.970552+00:00'),
  ('npm-run', 'npm-run', 'Automatically detects and exposes npm package.json scripts as callable tools, enabling AI agents to build, test, and deploy projects using existing project scripts. Supports npm, pnpm, yarn, and bun package managers with configurable access control for whitelisting or blacklisting specific scripts.', '@fstubner', 'development', 'Unknown', 3, 'https://github.com/fstubner/npm-run-mcp-server', NULL, 0, 'https://github.com/fstubner.png?size=128', '2026-03-09T05:21:01.970662+00:00'),
  ('fugle-taiwan-stock-market-data', 'Fugle Taiwan Stock Market Data', 'This MCP server provides AI assistants with access to Fugle''s Taiwan stock market data through a comprehensive set of tools covering historical candles and statistics, real-time intraday quotes and trading data, and market snapshot information including active stocks and price movers. Built by Fortuna Intelligence Co., Ltd. using TypeScript with the @fugle/marketdata SDK and Model Context Protocol SDK, it organizes market data functionality into three main categories: historical data analysis, intraday trading information (quotes, tickers, trades, volumes), and market snapshots for quick market overviews. The implementation includes JSON reference files for data validation, TypeScript compilation with file permissions handling, and MCP inspector support for development, making it valuable for financial analysis workflows, algorithmic trading research, and building AI assistants that need programmatic access to Taiwan stock market data without manual data retrieval.', '@fugle-dev', 'development', 'Unknown', 6, 'https://github.com/fugle-dev/fugle-marketdata-mcp-server', NULL, 0, 'https://github.com/fugle-dev.png?size=128', '2026-03-09T05:21:01.970696+00:00'),
  ('privategpt', 'privateGPT', 'This MCP server implementation enables seamless integration between privateGPT and MCP-compatible applications. It provides a robust set of features including chat management, knowledge source organization, group-based permissions, and secure communication protocols. The server supports multiple programming languages through various client implementations, making it versatile for diverse AI-driven projects that require privateGPT''s capabilities within an MCP framework.', '@fujitsu-ai', 'communication', 'Unknown', 5, 'https://github.com/fujitsu-ai/mcp-server-for-mas-developments', NULL, 0, 'https://github.com/fujitsu-ai.png?size=128', '2026-03-09T05:21:01.970730+00:00'),
  ('fulcra-context', 'Fulcra Context', 'This MCP server provides access to Fulcra Context personal data through the Fulcra API, enabling AI assistants to retrieve health metrics, workout data, sleep cycles, location information, and user profile details with OAuth2 authentication. Built by Brandon Creighton at Fulcra Dynamics using Python with FastMCP and FastAPI, it operates in both stdio mode for local connections and HTTP mode for remote access via a public instance at mcp.fulcradynamics.com, handling OAuth2 token exchange while maintaining security by not leaking tokens to MCP clients. The implementation offers tools for querying time-series health data, retrieving workout summaries, analyzing sleep patterns, accessing location history with reverse geocoding, and browsing available metrics catalogs, making it valuable for personal health analysis, fitness tracking integration, location-based insights, and any use case requiring structured access to personal quantified-self data from Apple Health and other connected sources.', '@fulcradynamics', 'ai-ml', 'Unknown', 3, 'https://github.com/fulcradynamics/fulcra-context-mcp', 'fulcra-context-mcp', 1591, 'https://github.com/fulcradynamics.png?size=128', '2026-03-09T05:21:01.970791+00:00'),
  ('funnel', 'Funnel', 'MCP Funnel is a TypeScript-based proxy server built by Christoph Schramm that aggregates multiple MCP servers while dramatically reducing context token usage through intelligent tool filtering and dynamic discovery. The implementation features a "hacky discovery" mode that exposes only 3-4 core tools (discover_tools_by_words, get_tool_schema, bridge_tool_request) instead of potentially hundreds from connected servers, allowing AI assistants to search for and dynamically enable only the tools they need at runtime. Built with comprehensive toolset management, pattern-based filtering with wildcard support, real-time web dashboard for monitoring and configuration, and robust error handling with detailed logging, it solves the critical problem of context window bloat when working with many MCP servers simultaneously, making it ideal for production deployments where token efficiency and selective tool exposure are essential for maintaining responsive AI interactions.', '@chris-schra', 'development', 'Unknown', 150, 'https://github.com/chris-schra/mcp-funnel', 'mcp-funnel', 1292, 'https://github.com/chris-schra.png?size=128', '2026-03-09T05:21:01.970831+00:00'),
  ('faker', 'Faker', 'A TypeScript-based MCP server that generates realistic fake data using Faker.js, supporting person records (names, emails, addresses, phone numbers), company data (names, industries, contact info), custom pattern-based generation (regex, enums, ranges, format templates), and structured datasets with referential integrity between related entities. Features reproducible generation through seed management, multi-locale support (English, French, German, Spanish, Japanese), and batch processing for large datasets up to 10,000 records. Useful for populating test databases, creating demo data, API testing scenarios, and generating complex relational datasets for development and testing workflows.', '@funsjanssen', 'databases', 'Unknown', 4, 'https://github.com/funsjanssen/faker-mcp', NULL, 0, 'https://github.com/funsjanssen.png?size=128', '2026-03-09T05:21:01.970842+00:00'),
  ('cosense', 'Cosense', 'This cosense MCP server, developed by funwarioisii, integrates the cosense platform with the Model Context Protocol, enabling AI assistants to access and interact with cosense project data. Built using TypeScript and the @modelcontextprotocol/sdk, it currently offers a ''Get Page'' feature for retrieving project information. The server simplifies interaction with cosense''s API, allowing AI systems to incorporate project management and collaboration data into their workflows. It supports both public and private cosense projects through configurable environment variables. This implementation is particularly useful for project managers, team leads, and AI developers working on productivity tools, facilitating use cases such as project status reporting, task management, and automated project analysis within the cosense ecosystem.', '@funwarioisii', 'development', 'Unknown', 1, 'https://github.com/funwarioisii/cosense-mcp-server', NULL, 0, 'https://github.com/funwarioisii.png?size=128', '2026-03-09T05:21:01.970885+00:00'),
  ('mongodb-lens', 'MongoDB Lens', 'MongoDB Lens is an MCP server that provides AI assistants with direct access to MongoDB databases for exploration and analysis. Built with Node.js and the Model Context Protocol SDK, it enables browsing databases and collections, executing queries with filters and projections, running aggregation pipelines, analyzing schemas, managing indexes, and optimizing query performance. The implementation includes specialized tools for inferring collection schemas, explaining query execution plans, and generating recommendations for database optimization, making it valuable for database exploration, performance tuning, and schema design assistance within AI workflows.', '@furey', 'databases', 'Unknown', 199, 'https://github.com/furey/mongodb-lens', NULL, 0, 'https://github.com/furey.png?size=128', '2026-03-09T05:21:01.970897+00:00'),
  ('fused-udf', 'Fused UDF', 'Fused MCP is a Python-based implementation that enables data scientists to easily connect Claude and other LLMs to executable Python code through User Defined Functions (UDFs). Built by Fused Labs, it provides a simple workflow for setting up MCP servers that can run either locally or remotely, with pre-built agents for common tasks like retrieving current time and fetching news. The repository includes step-by-step notebooks for both using existing functions and creating custom agents, making it particularly valuable for data scientists who want to extend their LLMs with Python capabilities without leaving their conversation interface.', '@fusedio', 'development', 'Unknown', 26, 'https://github.com/fusedio/fused-mcp', NULL, 0, 'https://github.com/fusedio.png?size=128', '2026-03-09T05:21:01.970923+00:00'),
  ('fusionauth', 'FusionAuth', 'Provides access to the FusionAuth identity platform API, enabling AI assistants to manage authentication, users, applications, tenants, identity providers, and cryptographic keys. Auto-generated from the FusionAuth OpenAPI specification with over 300 API endpoints available as callable tools. Supports configurable tool restrictions and read-only mode for security. Designed for local development and testing instances only.', '@fusionauth', 'development', 'Unknown', 0, 'https://github.com/fusionauth/fusionauth-mcp-api', NULL, 0, 'https://github.com/fusionauth.png?size=128', '2026-03-09T05:21:01.970944+00:00'),
  ('fusionauth-documentation', 'FusionAuth Documentation', 'Provides programmatic access to FusionAuth''s customer identity and access management (CIAM) platform. Enables interaction with authentication, authorization, user management, and security features through the FusionAuth API.', '@unknown', 'security', 'Unknown', 0, 'https://ai.fusionauth.dev/mcp/docs', NULL, 0, NULL, '2026-03-09T05:21:01.970982+00:00'),
  ('pdf-to-markdown-converter', 'PDF to Markdown Converter', 'PDF to Markdown Conversion Service provides a bridge to the MinerU API for converting PDF documents to Markdown format. This implementation uses the Model Context Protocol to expose PDF conversion capabilities, allowing users to transform complex PDF documents into clean, editable Markdown text while preserving the document structure. The service handles API authentication, file processing, and stores converted files in a configurable output directory, making it valuable for content migration, documentation workflows, and making PDF content more accessible and editable.', '@futureunreal', 'file-systems', 'Unknown', 28, 'https://github.com/futureunreal/mcp-pdf2md', NULL, 0, 'https://github.com/futureunreal.png?size=128', '2026-03-09T05:21:01.971035+00:00'),
  ('whatsapp-web', 'WhatsApp Web', 'WhatsApp Web MCP provides a bridge between WhatsApp Web and AI models using the Model Context Protocol, enabling AI assistants like Claude to interact with WhatsApp through a standardized interface. The server offers two operational modes: a standalone mode that directly connects to WhatsApp Web, and an API client mode that connects to a separate WhatsApp API server. It exposes WhatsApp functionality through MCP tools and resources for sending messages, managing groups, searching contacts, and retrieving chat history, making it valuable for automating WhatsApp interactions and enhancing conversational AI capabilities without leaving the assistant interface.', '@fyimail', 'communication', 'Unknown', 6, 'https://github.com/fyimail/whatsapp-mcp2', NULL, 0, 'https://github.com/fyimail.png?size=128', '2026-03-09T05:21:01.971074+00:00'),
  ('macos-defaults', 'macOS Defaults', 'This MCP server, developed by Wes Higbee, enables AI assistants to interact with macOS system preferences through the ''defaults'' command. It provides tools for listing domains, finding settings, reading preference values, and writing new settings. The server implements subprocess calls to execute system commands, offering a straightforward interface for AI systems to query and modify macOS configurations. By connecting AI capabilities with low-level system operations, this implementation empowers AI assistants to perform tasks like customizing user interfaces, adjusting system behaviors, or troubleshooting macOS issues. It is particularly useful for applications requiring automated macOS configuration, user preference management, or any scenario where an AI system needs to interact with and reason about macOS system settings.', '@g0t4', 'productivity', 'Unknown', 11, 'https://github.com/g0t4/mcp-server-macos-defaults', 'mcp-server-macos-defaults', 4930, 'https://github.com/g0t4.png?size=128', '2026-03-09T05:21:01.971120+00:00'),
  ('memory-by-file', 'Memory by File', 'This MCP server for memory management, developed by an unnamed creator, provides a simple interface for AI assistants to store and retrieve contextual information in a text file. It integrates with the Model Context Protocol to offer operations for adding, searching, deleting, and listing memories. The server handles file I/O operations and implements basic text-based storage, allowing AI systems to maintain persistent context across conversations without complex database setups. By focusing on simplicity and ease of use, this implementation enables quick deployment for scenarios requiring lightweight, file-based memory storage. It is particularly useful for chatbots, personal assistants, or any application where an AI needs to recall information from previous interactions.', '@g0t4', 'databases', 'Unknown', 7, 'https://github.com/g0t4/mcp-server-memory-file', NULL, 0, 'https://github.com/g0t4.png?size=128', '2026-03-09T05:21:01.971132+00:00'),
  ('cli', 'CLI', 'This MCP server, developed by g0t4, enables AI assistants to execute system commands and run scripts on the host machine. It provides tools for running individual shell commands and executing multi-line scripts in various languages like bash, fish, and Python. Built in JavaScript, the implementation exposes local system functionality via a standardized MCP interface, allowing Claude to interact directly with the host operating system. By bridging AI models with the local command line, this server enhances Claude''s ability to perform system administration tasks, automate workflows, and execute code snippets. It is particularly useful for developers and power users seeking AI-powered assistance with command-line operations, scripting, and system automation tasks. The implementation emphasizes security, recommending careful review of commands before execution.', '@g0t4', 'development', 'Unknown', 225, 'https://github.com/g0t4/mcp-server-commands', 'mcp-server-commands', 29364, 'https://github.com/g0t4.png?size=128', '2026-03-09T05:21:01.971162+00:00'),
  ('zeek', 'Zeek', 'Zeek-MCP provides a bridge between AI assistants and the Zeek network security monitor through the Model Context Protocol. It offers tools for executing Zeek analysis on PCAP files and parsing the resulting log files into structured data formats. The implementation handles the complete workflow from running Zeek commands to cleaning up previous log files and converting the tabular output into pandas DataFrames for easier analysis. Built with Python and FastMCP, it supports both stdio and Server-Sent Events (SSE) transport methods, making it particularly valuable for network security analysis, traffic monitoring, and intrusion detection tasks without requiring users to interact directly with Zeek''s command-line interface.', '@gabbo01', 'productivity', 'Unknown', 5, 'https://github.com/gabbo01/zeek-mcp', NULL, 0, 'https://github.com/gabbo01.png?size=128', '2026-03-09T05:21:01.971248+00:00'),
  ('freedcamp', 'Freedcamp', 'This MCP server provides direct integration with Freedcamp''s task management platform, enabling AI assistants to create, update, list, and delete tasks through both traditional STDIO transport for IDE integrations and modern HTTP transport for web deployments. Built by Gabe Albert, it supports bulk operations for efficient task management, uses secure HMAC-SHA1 authentication with API keys, and includes comprehensive input validation using Zod schemas. The implementation is particularly useful for teams managing projects in Freedcamp who want AI-powered task management through conversational interfaces in tools like Claude Desktop, Cursor, or containerized cloud environments.', '@gabeosx', 'productivity', 'Unknown', 2, 'https://github.com/gabeosx/freedmcpcamp', 'freedcamp-mcp', 2780, 'https://github.com/gabeosx.png?size=128', '2026-03-09T05:21:01.971289+00:00'),
  ('animagine-xl', 'Animagine XL', 'FastMCP server for the Animagine XL 4.0 image generation model, providing specialized tools for prompt engineering (validation, optimization, explanation), checkpoint and LoRA model management, and GPU-accelerated image generation with both text-to-image and image-to-image capabilities. Accessible via MCP protocol for AI agents or REST API for web/CLI tools.', '@gabrielalmir', 'ai-ml', 'Unknown', 1, 'https://github.com/gabrielalmir/mcp-animaginexl', NULL, 0, 'https://github.com/gabrielalmir.png?size=128', '2026-03-09T05:21:01.971323+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('twilio-sms', 'Twilio SMS', 'This Twilio MCP server enables AI assistants to send SMS messages and retrieve message logs through the Twilio API. Built with Python using the FastMCP framework, it provides two main tools: ''textme'' for sending text messages to specified phone numbers and ''msglogs'' for retrieving message history. The implementation handles Twilio authentication through environment variables and includes phone number formatting validation. It''s particularly useful for workflows requiring programmatic SMS communication, notification systems, or monitoring message delivery status without leaving the conversation interface.', '@gabriel-paulos', 'communication', 'Unknown', 0, 'https://github.com/gabriel-paulos/twilio-mcp-python', NULL, 0, 'https://github.com/gabriel-paulos.png?size=128', '2026-03-09T05:21:01.971354+00:00'),
  ('pyrestoolbox', 'pyResToolbox', 'A FastMCP server that provides access to reservoir engineering calculations through the pyResToolbox library, exposing 47 tools across oil PVT properties (bubble point, solution GOR, formation volume factors, viscosity), gas PVT properties (Z-factor, critical properties, compressibility), inflow performance modeling (radial and linear flow for oil and gas wells), simulation support (relative permeability tables, aquifer influence functions, Rachford-Rice flash calculations), brine properties, reservoir heterogeneity analysis, and component library access. Built by Gabriel Serrao with comprehensive Pydantic validation models, Docker deployment support, and fixes for upstream pyResToolbox bugs including a standalone gas gradient-to-specific gravity implementation, enabling petroleum engineering workflows for PVT analysis, well performance optimization, reservoir simulation preparation, and production forecasting using field units throughout.', '@gabrielserrao', 'cloud', 'Unknown', 27, 'https://github.com/gabrielserrao/pyrestoolbox-mcp', NULL, 0, 'https://github.com/gabrielserrao.png?size=128', '2026-03-09T05:21:01.971381+00:00'),
  ('web-search-brave', 'Web Search (Brave)', 'A web search tool for the Model Context Protocol that provides real-time information retrieval using the Brave Search API. Designed with intelligent query categorization to proactively determine when web search is necessary, such as for current events, weather, sports scores, and time-sensitive information. Supports dynamic provider configuration and offers robust error handling to ensure reliable search capabilities across various query types.', '@gabrimatic', 'search', 'Unknown', 13, 'https://github.com/gabrimatic/mcp-web-search-tool', NULL, 0, 'https://github.com/gabrimatic.png?size=128', '2026-03-09T05:21:01.971431+00:00'),
  ('mytaskly', 'MyTaskly', 'Integrates with the MyTaskly task management application, enabling task creation, organization, and analysis through natural language. Supports voice-optimized workflows, automatic categorization, deadline tracking, and bulk operations. Requires self-hosted FastAPI backend with OAuth 2.1 authentication.', '@gabry848', 'productivity', 'Unknown', 2, 'https://github.com/gabry848/mytaskly-mcp', NULL, 0, 'https://github.com/gabry848.png?size=128', '2026-03-09T05:21:01.971460+00:00'),
  ('bitget-trading', 'Bitget Trading', 'This MCP server provides complete trading functionality for Bitget cryptocurrency exchange, built by Yury Gagarin using TypeScript with comprehensive REST API integration and WebSocket support for real-time data streaming. The implementation automatically detects spot versus futures trading contexts, offers 15+ specialized tools covering market data retrieval (prices, tickers, order books, candlestick charts), account management (balances, positions), order execution (place, cancel, query orders), and futures-specific operations (leverage setting, margin info), plus WebSocket subscriptions for live price feeds and order book updates. Features include intelligent caching with TTL expiration, exponential backoff retry logic, rate limiting protection, and robust error handling with custom exception classes, making it valuable for algorithmic trading systems, portfolio management applications, and AI assistants that need programmatic access to Bitget''s spot and derivatives markets with both historical data analysis and real-time trading capabilities.', '@gagarinyury', 'development', 'Unknown', 3, 'https://github.com/gagarinyury/mcp-bitget-trading', NULL, 0, 'https://github.com/gagarinyury.png?size=128', '2026-03-09T05:21:01.971501+00:00'),
  ('ck-ask', 'CK-ASK', 'CK-ASK is an AI conversation pause tool that enables interruption and user input during AI-driven development workflows. It allows AI assistants to wait for human instructions by pausing responses and collecting feedback before continuation. The tool operates in two modes: terminal mode for direct command-line input prompts, and dialog mode providing a visual popup interface through a VS Code extension. It integrates with various AI coding assistants including Windsurf and Cursor editors.', '@gagmeng', 'development', 'Unknown', 5, 'https://github.com/gagmeng/ck-ask', NULL, 0, 'https://github.com/gagmeng.png?size=128', '2026-03-09T05:21:01.971524+00:00'),
  ('niivue', 'Niivue', 'Provides access to Niivue neuroimaging documentation and API reference materials. Fetches documentation from the Niivue GitHub repository, parses JSDoc comments from TypeScript source code, and maintains a local cache with BM25 indexing for quick retrieval. Supports both pure BM25 search and hybrid search combining BM25 with semantic embeddings using the all-MiniLM-L6-v2 model, offering tools for documentation overview, search, page retrieval, and API method lookup.', '@gaiborjosue', 'development', 'Unknown', 1, 'https://github.com/gaiborjosue/niivue-mcp', NULL, 0, 'https://github.com/gaiborjosue.png?size=128', '2026-03-09T05:21:01.971544+00:00'),
  ('web-to-ios-converter', 'Web to iOS Converter', 'Web to iOS Converter provides automated conversion of web applications to iOS apps using Capacitor, built by Gaku52 with TypeScript and comprehensive framework detection capabilities. The server analyzes web projects to identify frameworks (Vite, Next.js, Create React App), detects routing configurations and build settings, then generates tailored Capacitor configurations, iOS migration specifications, and complete setup guides with framework-specific optimizations. It includes built-in troubleshooting resources and handles complex scenarios like Next.js static exports, API route detection, and build output directory configuration, making it valuable for developers converting existing web applications to native iOS apps without manual configuration overhead.', '@gaku52', 'development', 'Unknown', 1, 'https://github.com/gaku52/web-to-ios-mcp', NULL, 0, 'https://github.com/gaku52.png?size=128', '2026-03-09T05:21:01.971575+00:00'),
  ('galaxy', 'Galaxy', 'MCP server for Galaxy bioinformatics platform - connect, execute tools, and manage workflows', '@galaxyproject', 'aggregators', 'Unknown', 25, 'https://github.com/galaxyproject/galaxy-mcp', NULL, 0, 'https://github.com/galaxyproject.png?size=128', '2026-03-09T05:21:01.971611+00:00'),
  ('api-test-framework', 'API Test Framework', 'A YAML-declarative API testing framework designed for AI coding assistants. Enables developers to define REST API test cases in YAML format, reducing token consumption when working with AI tools. Supports pytest integration, MySQL database operations, DingTalk notifications, and HTML report generation with Allure.', '@galaxyxieyu', 'databases', 'Unknown', 24, 'https://github.com/galaxyxieyu/api-test-mcp', NULL, 0, 'https://github.com/galaxyxieyu.png?size=128', '2026-03-09T05:21:01.971623+00:00'),
  ('galileo', 'Galileo', 'The Galileo MCP server enables seamless integration between AI-powered IDEs like Cursor and VS Code with Galileo''s evaluation and observability platform. Through natural conversation with AI assistants, developers can create synthetic datasets, manage prompt templates, set up experiments, analyze log streams for insights and improvements, and get step-by-step integration guides for adding Galileo observability to OpenAI and LangChain applications. The server provides direct access to Galileo''s capabilities from the development environment, making it useful for AI application development workflows, performance monitoring, and iterative improvement of LLM-powered systems.', '@rungalileo', 'development', 'Unknown', 5, 'https://github.com/rungalileo/docs-official', NULL, 0, 'https://github.com/rungalileo.png?size=128', '2026-03-09T05:21:01.971650+00:00'),
  ('sagemath', 'SageMath', 'This server provides local SageMath integration through two core tools: version checking and code evaluation with configurable timeouts. The implementation spawns SageMath processes to execute mathematical computations, writes code to temporary files for execution, and returns structured results including stdout, stderr, exit codes, and execution timing. Built with TypeScript and supporting both HTTP and stdio transports, it includes test clients for lattice operations and mathematical computations, making it useful for mathematical research, computational algebra, and educational applications requiring access to SageMath''s extensive mathematical libraries.', '@galoishlee', 'development', 'Unknown', 8, 'https://github.com/galoishlee/mcp-server-sagemath', NULL, 0, 'https://github.com/galoishlee.png?size=128', '2026-03-09T05:21:01.971676+00:00'),
  ('ludo-game-assets', 'Ludo Game Assets', 'Ludo Game Assets provides AI-powered generation of game development assets through the Ludo AI platform. Supports creating sprites, icons, backgrounds, UI assets, textures, 3D GLB models with PBR textures, animated spritesheets, short videos, sound effects, background music, and character voices. Offers multiple art styles including pixel art, low poly, cartoonish, and stylized 3D, with configurable perspectives and aspect ratios.', '@ludo-ai', 'development', 'Unknown', 1, 'https://github.com/ludo-ai/ludo-mcp', NULL, 0, 'https://github.com/ludo-ai.png?size=128', '2026-03-09T05:21:01.971701+00:00'),
  ('game-thinking', 'Game Thinking', 'Game Thinking MCP Server provides a structured tool for dynamic and iterative game design problem-solving, enabling developers to adjust game mechanics, explore alternative gameplay scenarios, and build cohesive game designs through a sequential thinking process. Built with TypeScript and integrating Three.js game engine capabilities, it supports iterative game concept development with flexible branching and revision strategies.', '@mahecode', 'development', 'Unknown', 6, 'https://github.com/mahecode/gamethinking-mcp-server', NULL, 0, 'https://github.com/mahecode.png?size=128', '2026-03-09T05:21:01.971750+00:00'),
  ('openstreetmap-tagging-schema', 'OpenStreetMap Tagging Schema', 'Bridges AI agents with OpenStreetMap''s comprehensive tagging knowledge base. Provides tools for validating tags, querying allowed values, searching presets, and suggesting improvements. Built on the official @openstreetmap/id-tagging-schema library with 7 tools organized into tag query, preset discovery, and validation categories.', '@gander-tools', 'ai-ml', 'Unknown', 6, 'https://github.com/gander-tools/osm-tagging-schema-mcp', NULL, 0, 'https://github.com/gander-tools.png?size=128', '2026-03-09T05:21:01.971783+00:00'),
  ('javascript-sandbox', 'JavaScript Sandbox', 'This JavaScript sandbox MCP server, developed by an unknown author, provides a secure environment for executing JavaScript code within defined constraints. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers a tool for running arbitrary JavaScript with configurable time and memory limits. The implementation focuses on isolation and security, utilizing the vm2 library to create a controlled execution context. It''s particularly useful for tasks like code testing, algorithm evaluation, or providing a safe playground for AI models to experiment with JavaScript, enabling assistants to execute and analyze JavaScript code without risking system integrity or resource exhaustion.', '@garc33', 'development', 'Unknown', 5, 'https://github.com/garc33/js-sandbox-mcp-server', 'js-sandbox-mcp-server', 3987, 'https://github.com/garc33.png?size=128', '2026-03-09T05:21:01.971943+00:00'),
  ('jina-ai-web-search', 'Jina AI Web Search', 'This Java-based MCP server integrates with Jina AI''s web search and content fetching APIs, enabling Claude to perform web searches and extract content from URLs. Built with Spring Boot and Retrofit2, it exposes two primary tools: one for searching the web and retrieving SERP results, and another for reading and extracting content from specific URLs. The implementation uses Spring AI''s tool annotation system to make these capabilities available through the MCP protocol, making it useful for research tasks, content aggregation, and information retrieval directly within Claude conversations without requiring users to manually search or visit websites.', '@garcheng', 'productivity', 'Unknown', 4, 'https://github.com/garcheng/mcp-server-jina-java', NULL, 0, 'https://github.com/garcheng.png?size=128', '2026-03-09T05:21:01.971986+00:00'),
  ('enhanced-postgresql', 'Enhanced PostgreSQL', 'Enhanced PostgreSQL MCP Server provides both read and write access to PostgreSQL databases, extending the original read-only implementation by Anthropic. Developed by Gareth Cottrell, it enables LLMs to not only query database schemas and execute read operations but also modify data through insert, update, and delete operations, as well as manage database schema objects like tables, functions, triggers, and indexes. The server implements proper transaction handling with COMMIT/ROLLBACK mechanisms and uses parameterized queries for data modification operations to prevent SQL injection, making it suitable for AI assistants that need to interact with PostgreSQL databases for both data analysis and database management tasks.', '@garethcott', 'databases', 'Unknown', 11, 'https://github.com/garethcott/enhanced-postgres-mcp-server', NULL, 0, 'https://github.com/garethcott.png?size=128', '2026-03-09T05:21:01.972000+00:00'),
  ('garmin-connect-china', 'Garmin Connect (China)', 'Garmin CN MCP Server enables AI assistants to interact with the Garmin Connect platform for Chinese users. Built with Python 3.13 and FastMCP, it authenticates with the Garmin CN API using email/password credentials and securely stores OAuth tokens for subsequent sessions. The implementation handles MFA authentication when required and provides a bridge to Garmin''s health and fitness data. This server is particularly valuable for applications requiring access to fitness tracking, health metrics, and activity data from Garmin devices through the Chinese version of Garmin Connect.', '@guaidaoyiyoudao', 'communication', 'Unknown', 1, 'https://github.com/guaidaoyiyoudao/garmincn-mcp', 'mcp-server-garmincn', 841, 'https://github.com/guaidaoyiyoudao.png?size=128', '2026-03-09T05:21:01.972031+00:00'),
  ('dall-e', 'DALL-E', 'DALL-E MCP Server enables AI assistants to generate images using OpenAI''s DALL-E API. It supports creating images with DALL-E 2 or DALL-E 3, editing existing images (DALL-E 2 only), and creating variations of images (DALL-E 2 only). The server is configured with an OpenAI API key and offers flexible options for image generation including model selection, size, quality, style, and custom save locations. Particularly useful for workflows requiring image generation capabilities directly within AI assistant conversations.', '@garoth', 'ai-ml', 'Unknown', 9, 'https://github.com/garoth/dalle-mcp', NULL, 0, 'https://github.com/garoth.png?size=128', '2026-03-09T05:21:01.972070+00:00'),
  ('sendgrid', 'SendGrid', 'This MCP server implementation provides integration with SendGrid''s Marketing API, enabling AI assistants to manage email marketing campaigns and contact lists. Developed by Garoth, it offers tools for contact management, list operations, email sending, template creation, and analytics. Built with TypeScript and leveraging the SendGrid SDK, the server focuses on supporting modern SendGrid features like dynamic templates and the Single Sends API. It is particularly useful for AI applications that need to automate email marketing tasks, manage subscriber lists, or integrate email communications into their workflows. The implementation includes robust error handling and environment variable management for secure API key storage.', '@garoth', 'development', 'Unknown', 23, 'https://github.com/garoth/sendgrid-mcp', NULL, 0, 'https://github.com/garoth.png?size=128', '2026-03-09T05:21:01.972099+00:00'),
  ('sleep', 'Sleep', 'This MCP server implementation provides a simple sleep/wait tool, allowing AI agents to introduce delays between operations. Developed by Garoth, it offers a single ''sleep'' tool that waits for a specified duration in milliseconds. Built with TypeScript and integrating the Model Context Protocol SDK, the server focuses on ease of use and configuration. It is particularly useful for scenarios requiring timed delays, such as spacing out API calls, testing eventually consistent systems, or simulating time-dependent processes. The implementation includes Jest-based tests to verify sleep functionality with various durations and supports easy deployment through npm scripts.', '@garoth', 'development', 'Unknown', 18, 'https://github.com/garoth/sleep-mcp', NULL, 0, 'https://github.com/garoth.png?size=128', '2026-03-09T05:21:01.972127+00:00'),
  ('wolframalpha-llm', 'WolframAlpha LLM', 'This MCP server implementation provides a bridge to WolframAlpha''s LLM API, enabling AI assistants to leverage WolframAlpha''s computational knowledge engine for complex mathematical and scientific queries. Developed by Garoth, it offers tools for asking questions, getting simplified answers, and validating API keys. The server is built using TypeScript and integrates with the Model Context Protocol SDK. It focuses on structured, LLM-friendly responses and supports both detailed and simplified outputs. This implementation is particularly useful for AI applications requiring advanced computational capabilities, data analysis, or access to WolframAlpha''s vast knowledge base across various scientific and mathematical domains.', '@garoth', 'development', 'Unknown', 48, 'https://github.com/garoth/wolframalpha-llm-mcp', NULL, 0, 'https://github.com/garoth.png?size=128', '2026-03-09T05:21:01.972157+00:00'),
  ('shipxy', 'ShipXY', 'This MCP server provides AI assistants with access to ShipXY''s maritime vessel tracking API, built by garrettXu using Python with httpx for HTTP requests and requiring a ShipXY API key for authentication. The implementation offers ship tracking capabilities through the ShipXY service, allowing users to query vessel positions, movements, and maritime data programmatically. Serves developers building maritime applications, logistics companies needing vessel tracking integration, and shipping industry professionals requiring real-time ship location data through conversational AI interfaces.', '@garrettxu', 'development', 'Unknown', 9, 'https://github.com/garrettxu/mcp-shipxy-api', NULL, 0, 'https://github.com/garrettxu.png?size=128', '2026-03-09T05:21:01.972183+00:00'),
  ('serper-google-search', 'Serper (Google Search)', 'A MCP server for Serper that enables AI assistants to perform Google searches via the Serper API. Developed by Gary Meng, this implementation provides a simple interface for querying Google search results with support for various parameters including location, language, and time period filters. The server is designed to be easily integrated with Claude and other AI applications through standard MCP configuration, allowing models to retrieve up-to-date information from the web without direct internet access.', '@garylab', 'ai-ml', 'Unknown', 28, 'https://github.com/garylab/serper-mcp-server', 'serper-mcp-server', 22725, 'https://github.com/garylab.png?size=128', '2026-03-09T05:21:01.972222+00:00'),
  ('gas-library-hub', 'GAS Library Hub', 'Search and discover Google Apps Script libraries with AI-generated summaries. Provides tools to search available GAS libraries and retrieve detailed library information through a remote MCP endpoint, enabling AI assistants to help developers find and evaluate Google Apps Script libraries for their projects.', '@wywy-llc', 'productivity', 'Unknown', 0, 'https://github.com/wywy-llc/gas-library-hub', NULL, 0, 'https://github.com/wywy-llc.png?size=128', '2026-03-09T05:21:01.972251+00:00'),
  ('gatewaystack-chatgpt-starter', 'GatewayStack ChatGPT Starter', 'OAuth-protected gateway implementation that provides secure tool execution with JWT-based authentication and authorization. Built as a starter template by David Crowe (creator of GatewayStack), it integrates with OAuth providers like Auth0, Clerk, Google, and Okta to verify bearer tokens and enforce scope-based permissions before proxying tool calls to backend services. Features automatic OIDC discovery, WWW-Authenticate header generation for ChatGPT OAuth flows, and flexible deployment options supporting both local development and Cloud Run production environments with built-in request logging and error handling.', '@davidcrowe', 'development', 'Unknown', 1, 'https://github.com/davidcrowe/gatewaystack-chatgpt-starter', NULL, 0, 'https://github.com/davidcrowe.png?size=128', '2026-03-09T05:21:01.972281+00:00'),
  ('acms', 'ACMS', 'ACMS is a Model Context Protocol (MCP) server that provides programmatic access to Apple''s container CLI tool on macOS. Built by gattjoe, it offers 50+ container operations across 9 functional categories and supports both local and remote HTTP/S access. The implementation includes comprehensive testing framework and proper project structure with Apache 2.0 licensing.', '@gattjoe', 'development', 'Unknown', 3, 'https://github.com/gattjoe/acms', NULL, 0, 'https://github.com/gattjoe.png?size=128', '2026-03-09T05:21:01.972306+00:00'),
  ('lit', 'Lit', 'Integrates with arXiv and DBLP academic databases to accelerate research workflows. Provides advanced search capabilities across both platforms with metadata retrieval, PDF access, and AI-powered research prompts that generate comprehensive summaries and identify related topics for efficient literature reviews.', '@gauravfs-14', 'databases', 'Unknown', 1, 'https://github.com/gauravfs-14/lit-mcp', NULL, 0, 'https://github.com/gauravfs-14.png?size=128', '2026-03-09T05:21:01.972316+00:00'),
  ('infrastructure-archaeology', 'Infrastructure Archaeology', 'Infrastructure archaeology tool that helps track down who created AWS resources and when by searching CloudTrail logs. Supports EC2 instances, RDS databases, and S3 buckets, providing creator information, timestamps, creation methods (Console, Terraform, CLI, etc.), and source IP addresses. Useful for infrastructure auditing, compliance tracking, and debugging resource ownership in AWS environments where resources lack proper tagging or documentation.', '@gautamrajur', 'databases', 'Unknown', 1, 'https://github.com/gautamrajur/infra-archaeology-mcp', NULL, 0, 'https://github.com/gautamrajur.png?size=128', '2026-03-09T05:21:01.972327+00:00'),
  ('pdf2md', 'PDF2MD', 'PDF2MD MCP server by Gavin Huang that converts PDF files to Markdown format using AI sampling capabilities through the FastMCP framework. The implementation supports both local file paths and URLs, features incremental conversion that can resume from where it left off by detecting existing page markers, and uses pymupdf4llm for PDF content extraction with fallback handling when AI sampling is unavailable. Built with comprehensive error handling for network issues, file permissions, and invalid formats, it serves developers building document processing workflows, content management systems requiring PDF-to-Markdown conversion, and AI applications that need to extract and format PDF content for further analysis or storage.', '@gavinhuang', 'development', 'Unknown', 1, 'https://github.com/gavinhuang/pdf2md-mcp', 'pdf2md-mcp', 1192, 'https://github.com/gavinhuang.png?size=128', '2026-03-09T05:21:01.972355+00:00'),
  ('horoscope', 'Horoscope', 'Horoscope Serve is a TypeScript-based MCP server that provides astrological horoscope functionality through a standardized interface. Built by Freddie, this implementation leverages the Model Context Protocol SDK to expose horoscope-related tools that can be discovered and executed by AI assistants. The server is designed to be run as a command-line application, with the compiled JavaScript executable available through npm. It''s suitable for applications that want to incorporate astrological predictions and insights into AI-powered conversations or workflows.', '@gbcui', 'development', 'Unknown', 4, 'https://github.com/gbcui/horoscope-serve', NULL, 0, 'https://github.com/gbcui.png?size=128', '2026-03-09T05:21:01.972384+00:00'),
  ('n8n-workflow-summarizer', 'N8N Workflow Summarizer', 'N8N Workflow Summarizer MCP Tool analyzes and simplifies complex n8n workflow JSON files into clear, concise markdown summaries. It extracts key information about nodes, connections, and functionality using OpenAI''s models, with intelligent handling of large workflows through progressive simplification and fallback options. The tool identifies specialized components like AI/agent nodes and database connections, extracts prompts, and even generates conceptual Python code that replicates the workflow''s functionality - making it particularly valuable for understanding and documenting complex automation workflows.', '@gblack686', 'databases', 'Unknown', 1, 'https://github.com/gblack686/n8n-workflow-summarizer-mcp', NULL, 0, 'https://github.com/gblack686.png?size=128', '2026-03-09T05:21:01.972399+00:00'),
  ('architecture-blueprints', 'Architecture Blueprints', 'Provides architecture blueprints and validation tools for full-stack development with Python/FastAPI backends and React/TypeScript frontends. Exposes documentation on layered architecture principles, design patterns like Context+Hook and Service Registry, and SOLID principles as MCP resources. Includes tools for querying patterns, checking layer violations, validating file placement, and reviewing component architecture.', '@gbrbks', 'development', 'Unknown', 1, 'https://github.com/gbrbks/architecture_mcp', NULL, 0, 'https://github.com/gbrbks.png?size=128', '2026-03-09T05:21:01.972422+00:00'),
  ('conceal', 'Conceal', 'An MCP proxy server that performs pseudo-anonymization of personally identifiable information (PII) before data reaches external AI providers like Claude, ChatGPT, or Gemini. Built in Rust by Gianluca Brigandi, it intercepts MCP communications and uses configurable regex patterns combined with optional Ollama LLM-based detection to identify PII such as emails, phone numbers, SSNs, and IP addresses, then consistently replaces them with realistic fake data while maintaining semantic meaning and data relationships. The implementation includes a SQLite-backed mapping store for consistent anonymization across sessions, supports multiple detection modes (regex-only, LLM-only, or hybrid), and is designed for organizations that need to analyze sensitive data with AI assistants while preserving privacy and regulatory compliance.', '@gbrigandi', 'databases', 'Unknown', 11, 'https://github.com/gbrigandi/mcp-server-conceal', NULL, 0, 'https://github.com/gbrigandi.png?size=128', '2026-03-09T05:21:01.972434+00:00'),
  ('cortex-threat-intelligence', 'Cortex Threat Intelligence', 'MCP Server Cortex is a bridge implementation that exposes Cortex threat intelligence analyzer functionalities as tools for AI models and automation scripts. Developed by Gianluca Brigandi under MIT license, it provides tools for analyzing IP addresses, domains, URLs, and email addresses using popular security services like AbuseIPDB, AbuseFinder, and VirusTotal through a Cortex instance. The server handles the complete workflow of submitting analysis jobs to Cortex, polling for completion, and returning structured reports, making it particularly valuable for security analysts who need to integrate threat intelligence capabilities into AI assistants for automated security assessments and investigations.', '@gbrigandi', 'communication', 'Unknown', 13, 'https://github.com/gbrigandi/mcp-server-cortex', NULL, 0, 'https://github.com/gbrigandi.png?size=128', '2026-03-09T05:21:01.972472+00:00'),
  ('io-github-eoinjordan-gbstudio-claude-mcp', 'io.github.eoinjordan/gbstudio-claude-mcp', 'Create and modify GB Studio projects with MCP tools for scenes, actors, assets, and validation.', '@eoinjordan', 'development', 'Unknown', 3, 'https://github.com/eoinjordan/gb-studio-agent', NULL, 0, 'https://github.com/eoinjordan.png?size=128', '2026-03-09T05:21:01.972491+00:00'),
  ('google-cloud-cli', 'Google Cloud CLI', 'Enables interaction with Google Cloud via the gcloud CLI using natural language prompts. Provides secure command execution with permission restrictions that prevent unsuitable operations while respecting the active gcloud account''s permissions. Includes additional servers for observability and storage operations.', '@googleapis', 'ai-ml', 'Unknown', 700, 'https://github.com/googleapis/gcloud-mcp', NULL, 0, 'https://github.com/googleapis.png?size=128', '2026-03-09T05:21:01.972561+00:00'),
  ('asterisk-phone-system', 'Asterisk Phone System', 'This Asterisk S2S MCP server by @grec0 provides AI assistants with direct access to phone call operations through integration with an Asterisk-based phone system API. The implementation enables making outbound calls with customizable purposes and contexts, monitoring active calls, retrieving conversation history and results, and accessing comprehensive system metrics and logs through a RESTful API interface. Built with TypeScript and featuring comprehensive test coverage, it''s designed for business automation workflows where AI assistants need to initiate phone communications, track call outcomes, and analyze telephony system performance without manual intervention.', '@gcorroto', 'development', 'Unknown', 5, 'https://github.com/gcorroto/mcp-s2s-asterisk', '@grec0/mcp-s2s-asterisk', 4569, 'https://github.com/gcorroto.png?size=128', '2026-03-09T05:21:01.972596+00:00'),
  ('pymol', 'PyMOL', 'The PyMOL MCP server provides a bridge between Claude and the PyMOL molecular visualization software, enabling interactive protein structure analysis through a comprehensive set of tools. Built with Python using the FastMCP framework, it offers capabilities for loading structures from PDB files, manipulating visualizations with different representations and colors, measuring molecular distances and angles, and rendering high-quality images. The implementation includes robust error handling and logging, making it particularly valuable for researchers and educators who need to analyze protein structures, examine binding sites, or create publication-quality molecular visualizations through natural language instructions.', '@gdamitha', 'ai-ml', 'Unknown', 0, 'https://github.com/gdamitha/mcp_claude', NULL, 0, 'https://github.com/gdamitha.png?size=128', '2026-03-09T05:21:01.972647+00:00'),
  ('software-development-prompts', 'Software Development Prompts', 'MCP Prompt Server is a Node.js-based server that provides a collection of pre-defined YAML prompts for common software development tasks. It integrates with the Model Context Protocol SDK to expose these prompts as tools, including code review, refactoring, API documentation, test case generation, and project architecture assistance. The server is designed to be easily configurable through a JSON configuration file and can be integrated into existing development workflows, making it particularly valuable for developers looking to streamline repetitive writing and coding tasks through AI assistance.', '@gdli6177', 'development', 'Unknown', 241, 'https://github.com/gdli6177/mcp-prompt-server', NULL, 0, 'https://github.com/gdli6177.png?size=128', '2026-03-09T05:21:01.972707+00:00'),
  ('io-github-drhelius-gearlynx', 'io.github.drhelius/gearlynx', 'MCP server for Gearlynx Atari Lynx emulator', '@unknown', 'development', 'Unknown', 0, 'https://www.pulsemcp.com/servers/gearlynx', NULL, 0, NULL, '2026-03-09T05:21:01.972794+00:00'),
  ('amap-gaode-maps', 'AMap (Gaode Maps)', 'AmapMCPServer provides two specialized MCP servers for interacting with AMap (Gaode Maps) API services in China. The coordinate server enables location-based operations including coordinate conversion between different systems (GPS, mapbar, baidu) and place searching by keywords, proximity, or within polygons. The route server complements this with transportation planning tools for walking, driving, transit, and bicycling routes between locations. Both servers require an AMap API key and are designed to work with Claude Desktop, making them valuable for applications needing Chinese mapping services.', '@gebabygeegee', 'ai-ml', 'Unknown', 3, 'https://github.com/gebabygeegee/amapmcpserver', NULL, 0, 'https://github.com/gebabygeegee.png?size=128', '2026-03-09T05:21:01.972836+00:00'),
  ('geekbot', 'Geekbot', 'Geekbot MCP server integrates with the Geekbot API to provide AI assistants with access to standup meeting data and reports. Developed by Savvas Papadopoulos at Geekbot, this Python implementation offers tools to fetch standup configurations and detailed reports with filtering capabilities by date ranges and users. The server includes templating for structured data presentation and specialized prompts for generating weekly rollup reports, making it particularly useful for teams wanting to analyze standup patterns or create automated summaries of team activities.', '@geekbot-com', 'ai-ml', 'Unknown', 18, 'https://github.com/geekbot-com/geekbot-mcp', NULL, 0, 'https://github.com/geekbot-com.png?size=128', '2026-03-09T05:21:01.972917+00:00'),
  ('minesweeper-rails', 'Minesweeper Rails', 'Provides access to a Minesweeper Rails API for game management including starting games, checking state, opening/flagging/chording cells, and ending games.', '@geeknees', 'ai-ml', 'Unknown', 2, 'https://github.com/geeknees/minesweeper-mcp', NULL, 0, 'https://github.com/geeknees.png?size=128', '2026-03-09T05:21:01.972944+00:00'),
  ('knowledge-base', 'Knowledge Base', 'The KB-MCP-Server is a Python implementation of a Model Context Protocol server designed to interact with knowledge bases. Developed by Geeksfino, it provides a structured way for AI assistants to query and retrieve information from connected knowledge sources. The server likely supports operations such as searching documents, retrieving specific information, and possibly updating knowledge repositories. This implementation would be valuable for applications requiring AI systems to access and utilize structured knowledge repositories in their workflows.', '@geeksfino', 'ai-ml', 'Unknown', 66, 'https://github.com/geeksfino/kb-mcp-server', NULL, 0, 'https://github.com/geeksfino.png?size=128', '2026-03-09T05:21:01.972986+00:00'),
  ('memoer-persistent-memory-storage', 'Memoer (Persistent Memory Storage)', 'Memoer-MCP is a server implementation that provides memory storage capabilities for AI assistants. It allows agents to create and retrieve memories through a standardized interface, storing content in a SQLite database with Prisma ORM. The server features tools for creating memories associated with specific apps/agents and retrieving memories with filtering options by app name, category, and result limits. Developed by Ge Li under MIT license, it includes automatic database setup and migration handling, making it particularly valuable for AI assistants that need persistent memory across conversations without requiring complex external storage configuration.', '@geli2001', 'databases', 'Unknown', 9, 'https://github.com/geli2001/memoer-mcp', 'memoer-mcp', 1554, 'https://github.com/geli2001.png?size=128', '2026-03-09T05:21:01.973055+00:00'),
  ('tft', 'TFT', 'A TypeScript implementation of an MCP server for Teamfight Tactics (TFT) game data. This server provides information about TFT champions, items, and other game elements to be used with Claude via the Model Context Protocol.', '@geli2001', 'development', 'Unknown', 9, 'https://github.com/geli2001/tft-mcp-server', 'mcp-server-tft', 868, 'https://github.com/geli2001.png?size=128', '2026-03-09T05:21:01.973154+00:00'),
  ('gemini-ai', 'Gemini AI', 'MCP-Gemini-Server provides a robust interface to Google''s Gemini AI models through a collection of specialized tools. Built with TypeScript and the Model Context Protocol SDK, it enables AI assistants to leverage Gemini''s capabilities including content generation, chat functionality, function calling, and file/cache management. The server implements both streaming and non-streaming content generation, supports stateful chat sessions with function execution, and offers comprehensive file and cache operations for optimizing performance. This implementation stands out by providing fine-grained control over generation parameters, safety settings, and tool configurations while handling error cases gracefully. It''s particularly valuable for developers building AI applications that need direct access to Gemini''s advanced features through a standardized protocol.', '@bsmi021', 'development', 'Unknown', 35, 'https://github.com/bsmi021/mcp-gemini-server', NULL, 0, 'https://github.com/bsmi021.png?size=128', '2026-03-09T05:21:01.973188+00:00'),
  ('gemini-2-5-flash-image', 'Gemini 2.5 Flash Image', 'MCP server for Google Gemini 2.5 Flash Image preview that provides AI assistants with text-to-image generation, image editing, composition, and style transfer capabilities through four specialized tools. The implementation supports both base64 and file path inputs for images, includes optional file saving functionality, and offers flexible transport options (stdio/HTTP) with comprehensive error handling and response formatting. Built with TypeScript and the MCP SDK, it serves users who need programmatic access to Gemini''s image generation capabilities for creative workflows, content creation, and automated image processing tasks that require combining multiple images or applying style transformations.', '@nanameru', 'development', 'Unknown', 3, 'https://github.com/nanameru/gemini-2.5-flash-image-mcp', '@taiyokimura/gemini-2-5-flash-mcp', 239, 'https://github.com/nanameru.png?size=128', '2026-03-09T05:21:01.973221+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('gemini-cli-orchestrator', 'Gemini CLI Orchestrator', 'A pure metaprompting MCP server that teaches AI agents how to collaborate effectively with Google''s Gemini CLI through strategic guidance rather than direct execution. Built by Danny Nguyen, this implementation provides no execution logic whatsoever - instead it returns intelligent prompts and frameworks that guide agents through sequential analysis workflows, ReAct loops, and synthesis strategies optimized for Gemini''s 1M+ token context window. The server emphasizes Gemini 2.5 Flash model usage for better availability and cost-effectiveness, while teaching agents advanced techniques like complete subsystem aggregation, iterative reasoning patterns, and multi-perspective analysis synthesis for security reviews, architecture analysis, and debugging workflows.', '@dnnyngyen', 'development', 'Unknown', 25, 'https://github.com/dnnyngyen/gemini-cli-orchestrator', NULL, 0, 'https://github.com/dnnyngyen.png?size=128', '2026-03-09T05:21:01.973255+00:00'),
  ('gemini-cloud-assist', 'Gemini Cloud Assist', 'Official Google Cloud Platform integration providing AI assistants with advanced troubleshooting and resource analysis capabilities through the Gemini Cloud Assist API. Built by Google LLC using TypeScript, it enables creation and management of structured investigations that automatically analyze GCP environments, correlate logs and events, generate hypotheses about issues, and provide detailed troubleshooting reports with links to relevant Cloud Console pages. The server also includes an intelligent resource search tool that can query and analyze information across multiple GCP services including Compute, CloudSQL, and Containers, making it valuable for DevOps teams, SREs, and cloud engineers who need to quickly diagnose complex infrastructure problems, understand resource relationships, and get actionable insights for resolving GCP-related issues.', '@googlecloudplatform', 'databases', 'Unknown', 53, 'https://github.com/googlecloudplatform/gemini-cloud-assist-mcp', '@google-cloud/gemini-cloud-assist-mcp', 1125, 'https://github.com/googlecloudplatform.png?size=128', '2026-03-09T05:21:01.973269+00:00'),
  ('io-github-wolfe-jam-gemini-faf-mcp', 'io.github.Wolfe-Jam/gemini-faf-mcp', 'FAF Source of Truth for Gemini. Read project DNA from .faf files. Ecosystem: #2759', '@wolfe-jam', 'development', 'Unknown', 1, 'https://github.com/wolfe-jam/gemini-faf-mcp', NULL, 0, 'https://github.com/wolfe-jam.png?size=128', '2026-03-09T05:21:01.973284+00:00'),
  ('wechat-moments', 'WeChat Moments', 'MCP Wechat Moments Server enables AI assistants to publish content to WeChat Moments on macOS through AppleScript automation. Developed by Gemini Wen, it uses cliclick to emulate mouse events and can be configured for auto-publishing via environment variables. The server integrates with clients like Cherry Studio, providing a programmatic interface to WeChat''s social sharing functionality without requiring direct API access. This implementation is particularly useful for social media management workflows where automated posting to WeChat''s popular Moments feature is needed.', '@geminiwen', 'communication', 'Unknown', 6, 'https://github.com/geminiwen/mcp-wechat-moments', 'mcp-wechat-moments', 3297, 'https://github.com/geminiwen.png?size=128', '2026-03-09T05:21:01.973348+00:00'),
  ('toolbox-for-databases', 'Toolbox for Databases', 'Toolbox is an MCP server implementation that enables AI assistants to interact with various database systems including PostgreSQL, MySQL, SQL Server, Neo4j, Dgraph, and Spanner. Developed by Google''s SenseAI team, it provides a configurable interface for executing pre-defined queries against databases through a YAML-based configuration system. The implementation features telemetry integration, authentication services, and support for both HTTP and SSE transport protocols. Toolbox is particularly useful for AI applications that need to retrieve or manipulate data from multiple database types without exposing direct database access, making it ideal for creating secure, controlled database interfaces for generative AI applications.', '@googleapis', 'databases', 'Unknown', 13309, 'https://github.com/googleapis/genai-toolbox', NULL, 0, 'https://github.com/googleapis.png?size=128', '2026-03-09T05:21:01.973360+00:00'),
  ('generect', 'Generect', 'Generect provides real-time B2B lead generation and company search through the Generect Live API. Search for qualified leads and companies using ICP filters, generate verified email addresses, retrieve LinkedIn profile data, and enrich contact information. The platform delivers up-to-date contact data pulled directly from social media and public sources with email validation.', '@generect', 'communication', 'Unknown', 1, 'https://github.com/generect/generect_mcp', NULL, 0, 'https://github.com/generect.png?size=128', '2026-03-09T05:21:01.973467+00:00'),
  ('discord-webhooks', 'Discord Webhooks', 'This Discord webhook MCP server, developed by genm, enables seamless integration between AI agents and Discord channels. Built with TypeScript and leveraging the Model Context Protocol SDK, it provides a straightforward way to send messages, including custom usernames and avatars, to Discord webhooks. The implementation focuses on simplicity and ease of use, offering a command-line interface for quick setup and deployment. It''s particularly useful for developers and teams looking to incorporate AI-generated content or notifications into their Discord workflows, enabling use cases such as automated updates, AI-assisted moderation, or interactive chatbots without dealing directly with Discord''s API complexities.', '@genm', 'development', 'Unknown', 0, 'https://github.com/genm/mcp-server-discord-webhook', NULL, 0, 'https://github.com/genm.png?size=128', '2026-03-09T05:21:01.973497+00:00'),
  ('switchbot', 'SwitchBot', 'This SwitchBot MCP server, developed by the GenM team, enables AI assistants to control SwitchBot devices through the SwitchBot API. Built with TypeScript and leveraging the Model Context Protocol SDK, it provides tools for device discovery, status monitoring, and command execution. The implementation focuses on simplifying smart home automation, making it easier for AI models to interact with physical devices. It''s particularly useful for enhancing AI-driven home management, energy optimization, or creating custom automation routines, enabling seamless integration of AI capabilities with SwitchBot''s ecosystem without requiring deep knowledge of the SwitchBot API.', '@genm', 'development', 'Unknown', 5, 'https://github.com/genm/switchbot-mcp', NULL, 0, 'https://github.com/genm.png?size=128', '2026-03-09T05:21:01.973524+00:00'),
  ('biomcp-biomedical-database-integration', 'BioMCP (Biomedical Database Integration)', 'BioMCP is a server implementation that provides structured access to key biomedical databases through a unified interface. Developed by GenomOncology, it connects to ClinicalTrials.gov, PubMed (via PubTator3), and MyVariant.info to enable searching and retrieving information about clinical trials, research articles, and genetic variants. The server exposes these capabilities as MCP tools that can be used by AI assistants to access up-to-date biomedical data, overcoming knowledge cutoff limitations. BioMCP handles entity normalization, intelligent rendering of complex data as Markdown, and transparent attribution of sources, making it valuable for biomedical research, clinical decision support, and literature review workflows.', '@genomoncology', 'databases', 'Unknown', 454, 'https://github.com/genomoncology/biomcp', 'biomcp-python', 108175, 'https://github.com/genomoncology.png?size=128', '2026-03-09T05:21:01.973538+00:00'),
  ('pfsense', 'pfSense', 'This pfSense MCP server enables natural language control of pfSense firewall systems through multiple connection methods (REST API, XML-RPC, SSH) with a hierarchical permission model supporting five access levels from read-only monitoring to emergency response capabilities. Built by GenSecAI, it provides security operations like IP blocking and firewall rule management, compliance checking for frameworks like PCI-DSS and HIPAA, threat analysis, and emergency incident response tools including network isolation and panic mode activation. The implementation integrates with Claude Desktop and other MCP clients through both stdio and HTTP modes, making it valuable for security teams who need conversational interfaces for firewall management, compliance auditing, and incident response workflows without requiring deep pfSense CLI knowledge.', '@gensecaihq', 'ai-ml', 'Unknown', 39, 'https://github.com/gensecaihq/pfsense-mcp-server', NULL, 0, 'https://github.com/gensecaihq.png?size=128', '2026-03-09T05:21:01.973592+00:00'),
  ('sonicwall', 'SonicWall', 'SonicWall MCP server that provides AI assistants with access to SonicWall firewall log analysis and security monitoring through comprehensive API integration supporting both SonicOS 7.x and 8.x versions. Built by GenSecAI using TypeScript with enhanced log parsing capabilities, the implementation offers tools for natural language log analysis, threat detection, connection searching, security statistics, and data export in multiple formats (JSON/CSV), with intelligent caching and sample data fallbacks for development environments. The server includes version-specific endpoint support, enhanced parsing for SonicOS 8.x features like Capture ATP and cloud management fields, and Docker deployment options, serving security analysts who need conversational access to firewall data, IT administrators requiring automated log analysis workflows, and security teams building incident response systems that leverage SonicWall''s comprehensive logging and threat detection capabilities.', '@gensecaihq', 'cloud', 'Unknown', 4, 'https://github.com/gensecaihq/sonicwall-mcp-server', NULL, 0, 'https://github.com/gensecaihq.png?size=128', '2026-03-09T05:21:01.973619+00:00'),
  ('gentoro', 'Gentoro', 'Integration with Gentoro. Allow for agents, tools and their underlying functionality to be fully controlled at the level of Gentoro''s bridge which allows you to enable and disable tools per design.', '@gentoro-gt', 'development', 'Unknown', 6, 'https://github.com/gentoro-gt/mcp-nodejs-server', '@gentoro/mcp-nodejs-server', 1050, 'https://github.com/gentoro-gt.png?size=128', '2026-03-09T05:21:01.973670+00:00'),
  ('svgmaker', 'SVGMaker', 'The SVGMaker MCP Server provides AI assistants with direct access to SVGMaker''s API for generating, editing, and converting SVG images through natural language commands. Built by Genwave LLC, it exposes three core tools: generating SVGs from text descriptions with customizable quality and aspect ratio settings, editing existing images or SVGs based on modification prompts, and converting bitmap images to vector format. The server includes comprehensive progress reporting during long-running operations, robust file path validation for security, and detailed logging capabilities, making it valuable for creating scalable graphics, converting legacy images to vector format, and automating design workflows without requiring direct API integration knowledge.', '@genwavellc', 'ai-ml', 'Unknown', 43, 'https://github.com/genwavellc/svgmaker-mcp', '@genwave/svgmaker-mcp', 2353, 'https://github.com/genwavellc.png?size=128', '2026-03-09T05:21:01.973720+00:00'),
  ('io-github-houtini-ai-geo-analyzer', 'io.github.houtini-ai/geo-analyzer', 'AI search optimization analysis with actionable findings and gap analysis', '@houtini-ai', 'development', 'Unknown', 13, 'https://github.com/houtini-ai/geo-analyzer', NULL, 0, 'https://github.com/houtini-ai.png?size=128', '2026-03-09T05:21:01.973736+00:00'),
  ('devici', 'Devici', 'This Devici MCP server provides complete API integration with the Devici threat modeling platform, enabling AI assistants to manage security workflows through natural language interactions. Built by Geoff Whittington using FastMCP and httpx, it offers tools for user and team management, collection and threat model creation, component analysis, threat identification, mitigation planning, and dashboard reporting across the entire threat modeling lifecycle. The implementation supports OAuth2 authentication and covers all major Devici API endpoints, making it valuable for security teams who want to automate threat modeling processes, generate security reports, and manage enterprise security assessments through conversational interfaces rather than manual platform navigation.', '@sdelements', 'ai-ml', 'Unknown', 4, 'https://github.com/sdelements/devici-mcp', NULL, 0, 'https://github.com/sdelements.png?size=128', '2026-03-09T05:21:01.973791+00:00'),
  ('sd-elements', 'SD Elements', 'This SD Elements MCP server provides comprehensive API integration with Security Compass''s SD Elements security development lifecycle platform, enabling AI assistants to interact with security projects, applications, countermeasures, and user management through natural language commands. Built with Python using the MCP protocol, requests library, and pydantic for validation, it offers 15+ tools covering project lifecycle management (create, update, delete projects), security assessment workflows (list and update countermeasures), application portfolio management, and administrative functions like user and business unit operations. The implementation is particularly valuable for DevSecOps workflows where security teams need to automate security requirement tracking, manage compliance countermeasures, and integrate security assessments into development processes through conversational interfaces rather than manual platform navigation.', '@sdelements', 'development', 'Unknown', 8, 'https://github.com/sdelements/sde-mcp', NULL, 0, 'https://github.com/sdelements.png?size=128', '2026-03-09T05:21:01.973827+00:00'),
  ('3d-asset-processing', '3D Asset Processing', 'A 3D asset processing MCP server that provides analysis, validation, and optimization tools for glTF/GLB 3D models through integration with gltf-pipeline and gltf-transform libraries. The implementation offers four main tools: model analysis for detailed geometry and material statistics, validation using the official gltf-validator with compatibility checks across platforms, basic processing via gltf-pipeline for format conversion and simple compression, and advanced processing through gltf-transform for Meshopt/Draco compression, texture optimization, and geometry simplification. Built with TypeScript and featuring smart caching, temporary file management, and support for local files, URLs, and base64 data inputs, it''s useful for 3D content pipelines, asset optimization workflows, and ensuring model compatibility across web, mobile, and game engine platforms.', '@geolibra', 'development', 'Unknown', 0, 'https://github.com/geolibra/3d-asset-processing-mcp', '3d-asset-processing-mcp', 1027, 'https://github.com/geolibra.png?size=128', '2026-03-09T05:21:01.973874+00:00'),
  ('hacker-news-companion', 'Hacker News Companion', 'HN Companion MCP is a server that fetches and processes Hacker News discussions, preparing them for Claude to generate high-quality summaries. It analyzes the hierarchical structure of comments, scores them based on community engagement metrics (upvotes, downvotes, replies), and formats the data optimally for summarization. The implementation includes both a CLI for direct use and a JSON-RPC server that follows the Model Context Protocol specification, making it particularly valuable for users who want to quickly understand key insights from lengthy HN threads without reading all comments.', '@georgeck', 'ai-ml', 'Unknown', 0, 'https://github.com/georgeck/hn-companion-mcp', NULL, 0, 'https://github.com/georgeck.png?size=128', '2026-03-09T05:21:01.973947+00:00'),
  ('gemini-2-0-flash', 'Gemini 2.0 Flash', 'Gemini MCP Server provides a TypeScript implementation that integrates Google''s Gemini 2.0 Flash model with Claude Desktop through the Model Context Protocol. Developed by GeorgeJeffers under MIT license, it establishes a bidirectional communication channel between Claude and Gemini using direct API calls rather than deprecated SDKs. The server maintains conversation context for natural interactions, implements stdio transport for seamless integration, and exposes a generate_text tool with configurable parameters like temperature and token limits. This implementation is particularly valuable for users who want to leverage Gemini''s capabilities directly from Claude without switching interfaces or managing separate API interactions.', '@ia-entertainment-git-organization', 'development', 'Unknown', 3, 'https://github.com/ia-entertainment-git-organization/gemini-mcp-server', NULL, 0, 'https://github.com/ia-entertainment-git-organization.png?size=128', '2026-03-09T05:21:01.973980+00:00'),
  ('gemini-pro', 'Gemini Pro', 'This TypeScript-based MCP server, developed by GeorgeJeffers, integrates Google''s Gemini Pro model with the Model Context Protocol. Built using the @modelcontextprotocol/sdk and @google/generative-ai libraries, it provides a standardized interface for leveraging Gemini''s text generation capabilities. The implementation focuses on simplicity and ease of integration, offering straightforward setup via Claude Desktop. It''s particularly useful for developers looking to incorporate Gemini''s AI capabilities into MCP-compatible applications, enabling use cases such as content generation, language translation, and conversational AI without directly dealing with the complexities of the Gemini API.', '@georgejeffers', 'development', 'Unknown', 12, 'https://github.com/georgejeffers/gemini-mcp-server', NULL, 0, 'https://github.com/georgejeffers.png?size=128', '2026-03-09T05:21:01.974009+00:00'),
  ('elevenlabs-text-to-speech', 'ElevenLabs Text-to-Speech', 'This MCP server integrates ElevenLabs'' text-to-speech capabilities with Cursor through the Model Context Protocol. It allows AI assistants to convert text to speech using ElevenLabs'' advanced voice synthesis technology. The implementation includes features like voice selection, model choice, and a web interface for testing and configuration. It''s designed for use cases requiring high-quality, customizable voice output in AI interactions.', '@georgi-io', 'development', 'Unknown', 1, 'https://github.com/georgi-io/jessica', NULL, 0, 'https://github.com/georgi-io.png?size=128', '2026-03-09T05:21:01.974087+00:00'),
  ('geoserver-cloud', 'GeoServer Cloud', 'MCP server for managing GeoServer workspaces, datastores, layers, and styles', '@ronitjadhav', 'maps-location', 'Unknown', 0, 'https://github.com/ronitjadhav/geoservercloud-mcp', NULL, 0, 'https://github.com/ronitjadhav.png?size=128', '2026-03-09T05:21:01.974119+00:00'),
  ('company-lens', 'Company Lens', 'Provides access to Japanese company information and corporate data. Enables searching and retrieving details about companies registered in Japan, useful for business research and analysis tasks.', '@gepuro', 'databases', 'Unknown', 0, 'https://github.com/gepuro/company-lens-mcp-registry', NULL, 0, 'https://github.com/gepuro.png?size=128', '2026-03-09T05:21:01.974130+00:00'),
  ('qdrant-retrieve', 'Qdrant Retrieve', 'An MCP server that enables semantic search capabilities through Qdrant vector database integration. It allows AI assistants to retrieve semantically similar documents across multiple collections using natural language queries, with configurable result counts and collection source tracking. The server supports both stdio and HTTP transports, includes REST API endpoints with OpenAPI documentation, and uses embedding models like Xenova/all-MiniLM-L6-v2 to generate vector representations for similarity matching. Particularly useful for knowledge retrieval workflows where semantic understanding is more important than exact keyword matching.', '@gergelyszerovay', 'databases', 'Unknown', 0, 'https://github.com/gergelyszerovay/mcp-server-qdrant-retrieve', '@gergelyszerovay/mcp-server-qdrant-retrive', 236, 'https://github.com/gergelyszerovay.png?size=128', '2026-03-09T05:21:01.974212+00:00'),
  ('callcenter-js-voip-telephony', 'CallCenter.js VoIP Telephony', 'AI-powered VoIP agent system built by Torben Gerkensmeyer that enables making phone calls with OpenAI''s real-time voice API through SIP-based telephony infrastructure. The implementation features native G.722 wideband audio codec support for high-quality voice transmission, comprehensive SIP provider profiles for Fritz!Box, Asterisk, Cisco CUCM, and 3CX systems, and intelligent call brief processing that converts simple text descriptions into detailed AI agent instructions using a meta-prompt system. Built with TypeScript and Node.js native addons, it includes advanced features like automatic transport fallback, connection management with provider-specific error handling, audio resampling between different sample rates, and performance monitoring, making it valuable for businesses automating phone-based customer service, appointment booking systems, or any scenario requiring AI agents to conduct natural voice conversations over traditional phone networks.', '@gerkensm', 'development', 'Unknown', 17, 'https://github.com/gerkensm/callcenter.js-mcp', NULL, 0, 'https://github.com/gerkensm.png?size=128', '2026-03-09T05:21:01.974246+00:00'),
  ('german-law', 'German Law', 'Query German statutes, case law, and preparatory works from gesetze-im-internet.de.', '@ansvar-systems', 'development', 'Unknown', 2, 'https://github.com/ansvar-systems/german-law-mcp', NULL, 0, 'https://github.com/ansvar-systems.png?size=128', '2026-03-09T05:21:01.974285+00:00'),
  ('minecraft-bot-control', 'Minecraft Bot Control', 'This MCP server for Minecraft, developed by Gerred Dillon, integrates Mineflayer to enable AI control of Minecraft bots through a standardized JSON-RPC interface. Built with TypeScript and leveraging the Model Context Protocol SDK, it provides tools for navigation, block manipulation, inventory management, and real-time game state monitoring. The server implements error handling, environment configuration, and uses Jest for testing. By abstracting Minecraft''s complexities, it allows AI systems to easily interact within the game world. This implementation is particularly valuable for applications requiring programmatic Minecraft control, facilitating use cases such as automated building, resource gathering, and bot-assisted gameplay.', '@gerred', 'development', 'Unknown', 38, 'https://github.com/gerred/mcpmc', '@gerred/mcpmc', 1137, 'https://github.com/gerred.png?size=128', '2026-03-09T05:21:01.974415+00:00'),
  ('swift-package-manager-dependencies', 'Swift Package Manager Dependencies', 'An MCP server for searching and exploring Swift Package Manager dependencies in Xcode and SPM projects. Built with Rust for performance, it solves the problem that SPM dependencies are typically stored in hidden folders like DerivedData that coding agents cannot easily access. The server provides tools to list dependencies with their versions and disk locations, search through dependency source code using ripgrep with regex support, browse files within dependencies, and read specific files with optional sed processing. It includes intelligent caching based on Package.resolved files and supports both pure SPM projects and Xcode workspaces, making it valuable for Swift developers who need AI assistance with understanding or debugging third-party dependencies.', '@getcmd-dev', 'development', 'Unknown', 3, 'https://github.com/getcmd-dev/spm-dependencies-mcp', NULL, 0, 'https://github.com/getcmd-dev.png?size=128', '2026-03-09T05:21:01.974500+00:00'),
  ('unified-tool-kit', 'Unified Tool Kit', 'MCP Tool Kit provides a unified server implementation for Claude AI assistants with over 100 integrated tools spanning file operations, web search, browser automation, data analysis, and document management. Built by getfounded, it uses a modular architecture that reduces cognitive load on Claude by encapsulating domain knowledge in vertical agents that handle complex workflows internally. The Docker-based deployment makes it easy to set up and configure with API keys for services like Brave Search, NewsAPI, and FRED economic data, enabling powerful capabilities for tasks ranging from market analysis to presentation creation without requiring Claude to coordinate individual tool calls.', '@getfounded', 'cloud', 'Unknown', 107, 'https://github.com/getfounded/mcp-tool-kit', 'mcptoolkit', 5085, 'https://github.com/getfounded.png?size=128', '2026-03-09T05:21:01.974527+00:00'),
  ('goodreads', 'Goodreads', 'This MCP server provides AI assistants with access to Goodreads book data through integration with a GetGather service, enabling retrieval of personal book libraries and reading information. Built using Python with FastMCP and the requests library, it requires Goodreads account credentials and connects to a configurable GetGather host service (defaulting to localhost:8000) to fetch book data through authenticated API calls. The implementation supports both CLI usage for direct book retrieval and MCP server mode for Claude Desktop integration via environment variable configuration, making it valuable for book recommendation workflows, reading list management, and building AI assistants that need programmatic access to personal Goodreads data without manual library browsing.', '@remotebrowser', 'development', 'Unknown', 6, 'https://github.com/remotebrowser/mcp-getgather-goodreads', 'goodreads-mcp', 2643, 'https://github.com/remotebrowser.png?size=128', '2026-03-09T05:21:01.974556+00:00'),
  ('crisp', 'Crisp', 'Connects to the Crisp customer messaging platform to manage support conversations, send and retrieve messages, and monitor chat activity. Provides tools for conversation state management, visitor tracking, operator assignment, and segment tagging. Requires Crisp API credentials (identifier, key, and website ID) obtained through the Crisp Marketplace plugin system.', '@getlate-dev', 'communication', 'Unknown', 8, 'https://github.com/getlate-dev/crisp-mcp', NULL, 0, 'https://github.com/getlate-dev.png?size=128', '2026-03-09T05:21:01.974582+00:00'),
  ('getmailer', 'GetMailer', 'Integrates with GetMailer''s email infrastructure to send transactional emails programmatically. Provides tools for email sending, template management, domain verification, delivery tracking, suppression list handling, and batch email processing.', '@getplatform', 'communication', 'Unknown', 0, 'https://github.com/getplatform/getmailer-mcp', NULL, 0, 'https://github.com/getplatform.png?size=128', '2026-03-09T05:21:01.974603+00:00'),
  ('getweb', 'GetWeb', 'MCP-GetWeb server by Ivan Mezentsev provides AI assistants with comprehensive web search and content extraction capabilities through seven specialized tools integrating DuckDuckGo HTML scraping, Google Programmable Search Engine API, Felo AI search, Jina Reader API, and custom URL fetching with content extraction controls. Built in Rust with extensive caching, user agent rotation, and robust error handling, the implementation offers both basic web search across multiple engines and advanced content processing including metadata extraction, HTML-to-Markdown conversion, and configurable text extraction with main content detection and tag filtering. Designed for AI applications requiring reliable web research capabilities, real-time information retrieval, and flexible content processing workflows where multiple search engines and extraction methods provide redundancy and specialized functionality for different types of web content.', '@ivan-mezentsev', 'ai-ml', 'Unknown', 13, 'https://github.com/ivan-mezentsev/mcp-getweb', 'mcp-getweb', 1004, 'https://github.com/ivan-mezentsev.png?size=128', '2026-03-09T05:21:01.974659+00:00'),
  ('whatsapp-desktop', 'WhatsApp Desktop', 'WhatsApp MCP Server enables programmatic interaction with the WhatsApp desktop application on macOS through AppleScript automation. It provides tools for sending messages to contacts, checking WhatsApp status, and explaining contact listing limitations. The implementation uses keyboard shortcuts and UI automation to navigate the WhatsApp interface, with comprehensive error handling and logging. Designed specifically for macOS users, it requires the WhatsApp desktop application to be installed and serves as a bridge between AI assistants like Claude and the user''s WhatsApp account.', '@gfb-47', 'communication', 'Unknown', 5, 'https://github.com/gfb-47/whatsapp-mcp-server', NULL, 0, 'https://github.com/gfb-47.png?size=128', '2026-03-09T05:21:01.974692+00:00'),
  ('coding-standards', 'Coding Standards', 'This MCP server provides tools for accessing coding style guidelines and best practices for Java, Python, and React. It offers a standardized interface for retrieving language-specific style guides and application best practices in Markdown format. The server is designed to enhance development workflows by providing easy access to coding standards, making it particularly useful for teams looking to maintain consistent code quality across projects.', '@ggerve', 'development', 'Unknown', 16, 'https://github.com/ggerve/coding-standards-mcp', NULL, 0, 'https://github.com/ggerve.png?size=128', '2026-03-09T05:21:01.974714+00:00'),
  ('haiku-rag', 'Haiku RAG', 'Retrieval-augmented generation system providing hybrid search combining vector and full-text search with Reciprocal Rank Fusion. Features multi-agent research workflows for planning, searching, evaluating, and synthesizing information with citations. Supports 40+ file formats including PDF, DOCX, HTML, and Markdown. Works locally with embedded LanceDB or supports cloud storage on S3, GCS, and Azure.', '@ggozad', 'cloud', 'Unknown', 491, 'https://github.com/ggozad/haiku.rag', NULL, 0, 'https://github.com/ggozad.png?size=128', '2026-03-09T05:21:01.974730+00:00'),
  ('metasploit-framework', 'Metasploit Framework', 'MetasploitMCP is a server implementation that provides AI assistants with a secure interface to Metasploit Framework''s penetration testing capabilities. Developed by GH05TCREW, this Python-based server uses FastAPI and the pymetasploit3 library to expose Metasploit functionality through MCP tools including exploit execution, payload generation, session management, and post-exploitation modules. The implementation handles both synchronous and asynchronous command execution, manages console sessions carefully, and includes robust error handling and logging, making it particularly valuable for security professionals who want to leverage AI assistance for penetration testing workflows while maintaining precise control over Metasploit operations.', '@gh05tcrew', 'development', 'Unknown', 518, 'https://github.com/gh05tcrew/metasploitmcp', NULL, 0, 'https://github.com/gh05tcrew.png?size=128', '2026-03-09T05:21:01.974759+00:00'),
  ('musescore', 'MuseScore', 'This MCP server provides programmatic control of MuseScore music notation software through a WebSocket-based bridge, enabling AI assistants to compose, edit, and analyze musical scores directly within the MuseScore application. Built by George Chen using Python with FastMCP and a custom QML plugin for MuseScore 3.0, it offers comprehensive music editing capabilities including note and rest insertion with precise duration control, cursor navigation across measures and staves, tuplet creation, lyrics addition, instrument management, and time signature modifications. The implementation features a modular architecture with organized tool categories, robust cursor state management with automatic selection synchronization, sequence processing for batch operations, and real-time communication between the MCP server and MuseScore through WebSocket connections, making it valuable for AI-assisted music composition workflows, automated score generation, music theory education applications, and building AI tools that need direct integration with professional music notation software.', '@ghchen99', 'development', 'Unknown', 22, 'https://github.com/ghchen99/mcp-musescore', NULL, 0, 'https://github.com/ghchen99.png?size=128', '2026-03-09T05:21:01.974799+00:00'),
  ('ghibli-video-generator', 'Ghibli Video Generator', 'mcp-server-ghibli-video is a TypeScript-based MCP server that provides AI image and video generation capabilities through the GPT4O Image Generator API. Developed by MichaelYangjson, this implementation offers tools for converting static images into animated videos in Ghibli style, checking API credit balances, and monitoring task status. The server communicates over stdio, making it compatible with Claude Desktop through a simple configuration, and includes debugging support via MCP Inspector. It''s particularly useful for users wanting to create Ghibli-style animations from existing images without implementing complex video generation logic themselves.', '@michaelyangjson', 'development', 'Unknown', 4, 'https://github.com/michaelyangjson/mcp-ghibli-video', '@openmcprouter/mcp-server-ghibli-video', 3742, 'https://github.com/michaelyangjson.png?size=128', '2026-03-09T05:21:01.974828+00:00'),
  ('magentaa11y', 'MagentaA11y', 'Queries the MagentaA11y accessibility knowledge base to provide testing criteria for web and native mobile components. Supports multiple output formats including Gherkin-style acceptance criteria, condensed summaries, and platform-specific developer notes. Includes tools for listing components, retrieving detailed criteria, and searching by keyword.', '@joe-watkins', 'development', 'Unknown', 2, 'https://github.com/joe-watkins/magentaa11y-mcp', NULL, 0, 'https://github.com/joe-watkins.png?size=128', '2026-03-09T05:21:01.974893+00:00'),
  ('berlin-services', 'Berlin Services', 'Connects to Berlin''s official city services API to provide access to municipal administrative services and forms. Supports searching and browsing services by category, retrieving service details and prerequisites, and discovering associated PDF forms. Includes PDF processing capabilities for extracting fillable fields, completing forms, previewing pages, and managing filled documents. Features dual-layer caching with offline fallback for resilient operation.', '@manancoder29', 'ai-ml', 'Unknown', 4, 'https://github.com/manancoder29/berlin-services-mcp-server', NULL, 0, 'https://github.com/manancoder29.png?size=128', '2026-03-09T05:21:01.974929+00:00'),
  ('ghost-security', 'Ghost Security', 'Enables interaction with the Ghost Security platform through standardized tools. Access security findings and vulnerabilities discovered in code repositories, manage code review data, query project and repository information, and update the status of security issues. Supports filtering, pagination, and sorting across multiple repositories.', '@ghostsecurity', 'development', 'Unknown', 2, 'https://github.com/ghostsecurity/ghost-mcp-server', NULL, 0, 'https://github.com/ghostsecurity.png?size=128', '2026-03-09T05:21:01.974951+00:00'),
  ('xportalx', 'xPortalX', 'xPortalX is a hosted MCP server that provides AI agents with web interaction and crypto payment capabilities. It offers tools for fetching API data, scraping web pages, crawling websites, and AI-powered structured data extraction. The server integrates with DexScreener and Coinbase for real-time cryptocurrency pricing and includes x402 payment protocol support for accessing paid APIs with automatic stablecoin payments on Base.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://xprtlai.com', NULL, 0, NULL, '2026-03-09T05:21:01.975006+00:00'),
  ('duckduckgo-search', 'DuckDuckGo Search', 'MCP DuckDuckGo Search Plugin, developed by Gianluca Mazza, provides web search functionality using DuckDuckGo''s public interface. It offers advanced features like detailed result exploration, related searches, pagination, and content extraction. The plugin is designed for seamless integration with Claude Code and other MCP-compatible clients, making it ideal for AI-assisted research and information gathering tasks.', '@gianlucamazza', 'development', 'Unknown', 11, 'https://github.com/gianlucamazza/mcp-duckduckgo', NULL, 0, 'https://github.com/gianlucamazza.png?size=128', '2026-03-09T05:21:01.975028+00:00'),
  ('python-toolbox', 'Python Toolbox', 'This MCP server implementation provides a comprehensive set of Python development tools, enabling AI assistants to effectively work with Python code and projects. Developed by Gianluca Mazza, it offers features for file operations, code analysis, project management, and safe code execution within a controlled environment. The server is designed for use cases requiring advanced Python development capabilities, such as code refactoring, dependency management, and automated testing in AI-assisted programming workflows.', '@gianlucamazza', 'development', 'Unknown', 8, 'https://github.com/gianlucamazza/mcp_python_toolbox', NULL, 0, 'https://github.com/gianlucamazza.png?size=128', '2026-03-09T05:21:01.975054+00:00'),
  ('kokoro-tts', 'Kokoro TTS', 'This MCP server implementation provides text-to-speech capabilities using the Kokoro TTS engine. It exposes a single tool for generating speech from text, with options for customizing voice, speed, and output format. The server supports cross-platform audio playback and can save generated audio to files, making it useful for applications requiring high-quality speech synthesis.', '@giannisanni', 'file-systems', 'Unknown', 10, 'https://github.com/giannisanni/kokoro-tts-mcp', NULL, 0, 'https://github.com/giannisanni.png?size=128', '2026-03-09T05:21:01.975098+00:00'),
  ('gibson-ai', 'Gibson AI', 'The GibsonAI MCP server enables development environments like Cursor to interact with your GibsonAI cloud databases through natural language. You can now design and manage production-grade databases without leaving your IDE.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('xcode-project-manager', 'Xcode Project Manager', 'This MCP server provides programmatic manipulation of Xcode project files (.xcodeproj) through 21 specialized tools built with Swift and leveraging the tuist/xcodeproj library for reliable project file handling. Created by Kohki Miki and distributed via Docker, it enables AI assistants to create new Xcode projects, manage targets and build configurations, add/remove files and dependencies, modify build settings, create groups, and automate common Xcode project tasks without requiring direct Xcode interaction. The implementation supports both project inspection operations (listing targets, files, build configurations) and modification operations (adding frameworks, build phases, duplicating targets), making it valuable for iOS/macOS development automation, project scaffolding, CI/CD pipeline integration, and batch project modifications across multiple Xcode projects.', '@giginet', 'cloud', 'Unknown', 121, 'https://github.com/giginet/xcodeproj-mcp-server', NULL, 0, 'https://github.com/giginet.png?size=128', '2026-03-09T05:21:01.975258+00:00'),
  ('enhanced-home-assistant', 'Enhanced Home Assistant', 'An enhanced Home Assistant MCP server built by gilberth that provides comprehensive smart home automation control through a rich set of tools for managing entities, devices, automations, history analysis, and system monitoring. The implementation features domain-specific device controls for lights, climate, media players, and covers with advanced parameters, bulk operations for managing multiple entities simultaneously, detailed historical analysis with state change tracking, and resource-based URI access patterns for efficient data retrieval. Built with TypeScript and designed for Smithery compatibility, it includes minimal tool registration to prevent timeout during scanning, extensive filtering and search capabilities across all entity operations, and specialized tools for troubleshooting, configuration validation, and system health monitoring, making it useful for AI-assisted home automation management, energy optimization analysis, and comprehensive smart home system administration.', '@gilberth', 'development', 'Unknown', 2, 'https://github.com/gilberth/enhanced-homeassistant-mcp', NULL, 0, 'https://github.com/gilberth.png?size=128', '2026-03-09T05:21:01.975297+00:00'),
  ('message-notifications', 'Message Notifications', 'This MCP server provides AI assistants with multi-channel notification capabilities through desktop notifications, email, and API endpoints, built by gimjin using TypeScript with the Model Context Protocol SDK. The implementation offers a single ''notify'' tool that simultaneously sends notifications across all configured channels, supporting SMTP email delivery via RFC2396 URL format, desktop notifications through node-notifier, and HTTP POST requests to custom API endpoints. It serves developers building AI workflows that need user alerts for long-running tasks, teams requiring notification automation for AI assistant interactions, and applications needing cross-platform notification delivery without manual monitoring of AI task completion status.', '@gimjin', 'development', 'Unknown', 8, 'https://github.com/gimjin/message-mcp', 'message-mcp', 2331, 'https://github.com/gimjin.png?size=128', '2026-03-09T05:21:01.975328+00:00'),
  ('unreal-engine-5', 'Unreal Engine 5', 'Provides AI-powered automation for Unreal Engine 5 through a comprehensive bridge between AI assistants and the Unreal Editor. The system consists of a C++ plugin that runs inside Unreal Engine and a Python server that communicates via socket connections, enabling real-time manipulation of actors, blueprints, PCG (Procedural Content Generation) graphs, and Python script execution within the editor. Includes a RAG system using BM25 search over Unreal Engine API documentation to help generate contextually appropriate code and commands. Supports complex game development workflows including blueprint node graph creation, World Partition actor management, Gameplay Ability System integration, and procedural content generation.', '@gimmedg', 'development', 'Unknown', 3, 'https://github.com/gimmedg/unrealengine5-mcp', NULL, 0, 'https://github.com/gimmedg.png?size=128', '2026-03-09T05:21:01.975358+00:00'),
  ('gimp', 'GIMP', 'GIMP MCP server by maorcc that enables conversational control of GIMP 3.0 through natural language commands, bridging the gap between GIMP''s powerful image editing capabilities and AI assistants. The implementation consists of a GIMP plugin that creates a socket server inside GIMP to execute Python-Fu commands, paired with an MCP server that translates conversational requests into precise GIMP API operations using PyGObject bindings. Built with FastMCP and designed for both non-technical users who want to edit images through simple descriptions like ''brighten the background and add a vintage filter'' and professionals seeking faster multi-step workflows than traditional point-and-click methods, the server exposes all GIMP features through a single call_api tool with comprehensive documentation and recipe patterns for common operations like drawing, color manipulation, layer management, and complex artistic modifications.', '@maorcc', 'ai-ml', 'Unknown', 57, 'https://github.com/maorcc/gimp-mcp', NULL, 0, 'https://github.com/maorcc.png?size=128', '2026-03-09T05:21:01.975414+00:00'),
  ('postman-tool-generation', 'Postman Tool Generation', 'This MCP server, developed by Giovanni Cocco, integrates the Postman Tool Generation API with AI agents. Built with TypeScript and leveraging the Model Context Protocol SDK, it enables the conversion of Postman collections and requests into type-safe code for various AI frameworks. The implementation focuses on generating AI tools from API endpoints, supporting multiple languages and frameworks like OpenAI, Mistral, and LangChain. It''s particularly useful for developers and teams looking to streamline the process of creating AI-powered tools from existing API documentation, enabling use cases such as rapid prototyping, automated code generation, and seamless integration of APIs into AI workflows without directly dealing with the complexities of the Postman API.', '@giovannicocco', 'development', 'Unknown', 13, 'https://github.com/giovannicocco/mcp-server-postman-tool-generation', NULL, 0, 'https://github.com/giovannicocco.png?size=128', '2026-03-09T05:21:01.975443+00:00'),
  ('stock-analysis-india', 'Stock Analysis (India)', 'This is an MCP server that provides access to real-time and historical Indian stock data using the Yahoo Finance API. It allows stock data retrieval to be used as context by local LLMs via Claude Desktop, Cursor, and other MCP-compatible agents.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('endnote-mcp', 'EndNote MCP', 'Search, cite, and read PDFs from your EndNote library in Claude Desktop.', '@gokmengokhan', 'ai-ml', 'Unknown', 3, 'https://github.com/gokmengokhan/endnote-mcp', NULL, 0, 'https://github.com/gokmengokhan.png?size=128', '2026-03-09T05:21:01.977067+00:00'),
  ('test-coverage', 'Test Coverage', 'Provides instant, reliable test coverage data for any programming language based on LCOV format files. Enables agents to monitor test coverage during development sessions without wasting tokens on excessive file reading. Includes tools for retrieving overall coverage metrics, file-level statistics, and uncovered line ranges with support for multiple coverage formats and configurable thresholds.', '@goldbergyoni', 'development', 'Unknown', 40, 'https://github.com/goldbergyoni/test-coverage-mcp', NULL, 0, 'https://github.com/goldbergyoni.png?size=128', '2026-03-09T05:21:01.977087+00:00'),
  ('gologin', 'GoLogin', 'This MCP server provides dynamic integration with the GoLogin API for managing anti-detect browser profiles and automation workflows. Built using TypeScript with the Model Context Protocol SDK, it automatically loads the GoLogin OpenAPI specification and dynamically generates tools for all available API endpoints, enabling operations like creating and configuring browser profiles, managing proxy settings, customizing fingerprints, organizing profiles into folders, and controlling browser sessions. The implementation features automatic OpenAPI-to-JSON schema conversion, dynamic tool generation from API specifications, Bearer token authentication, and comprehensive parameter handling for path, query, and body parameters, making it valuable for web scraping automation, multi-account management, privacy-focused browsing workflows, and building AI assistants that need programmatic control over anti-detect browser infrastructure without manual GoLogin dashboard access.', '@gologinapp', 'development', 'Unknown', 12, 'https://github.com/gologinapp/gologin-mcp', 'gologin-mcp', 4953, 'https://github.com/gologinapp.png?size=128', '2026-03-09T05:21:01.977159+00:00'),
  ('lens', 'Lens', 'Lens is an MCP proxy server that solves the tool discovery problem by wrapping upstream MCP servers (currently GitHub) with a simplified interface. Instead of exposing dozens of tools directly, it provides three meta-tools: search_tools for keyword-based discovery, describe_tool for retrieving schemas, and execute_tool for running discovered tools. The proxy auto-activates underlying tools during sessions as they''re executed, keeping the initial context window minimal while maintaining full functionality.', '@golovatskygroup', 'development', 'Unknown', 4, 'https://github.com/golovatskygroup/mcp-lens', NULL, 0, 'https://github.com/golovatskygroup.png?size=128', '2026-03-09T05:21:01.977180+00:00'),
  ('pylpex', 'Pylpex', 'An MCP server for the Pylpex programming language interpreter, built by Golto using FastMCP. The server provides tools for executing Pylpex code, tokenizing source code for analysis, managing interpreter state with variable inspection and reset capabilities, along with resources containing language documentation and code examples. Pylpex appears to be a custom programming language with Python-like syntax that supports functions, loops, conditionals, and basic data structures, making this server useful for educational programming environments, language experimentation, or integrating custom scripting capabilities into AI-assisted development workflows.', '@golto', 'development', 'Unknown', 1, 'https://github.com/golto/pylpex-mcp', NULL, 0, 'https://github.com/golto.png?size=128', '2026-03-09T05:21:01.977208+00:00'),
  ('gomarble', 'GoMarble', 'Provides a unified interface for accessing and analyzing marketing performance data across multiple platforms including Meta Ads, Google Ads, Google Analytics 4, and Shopify. Enables retrieval of ad account data, campaign metrics, analytics insights, and e-commerce performance data with OAuth 2.0 authentication and encrypted credential storage. Offers both hosted remote access and open-source implementations for individual platforms.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://apps.gomarble.ai/mcp-api/sse', NULL, 0, NULL, '2026-03-09T05:21:01.977242+00:00'),
  ('google-analytics-4', 'Google Analytics 4', 'This Google Analytics 4 MCP server provides programmatic access to GA4 data through seven specialized tools including property management, page views, user metrics, events, traffic sources, device analytics, and comprehensive custom reporting via the Google Analytics Data API and Admin API. Built by GoMarble AI, it features automatic OAuth 2.0 authentication with token refresh, eliminating the need for manual credential management while supporting both hierarchical account/property discovery and flexible report generation with custom metrics, dimensions, filtering, and sorting capabilities. The implementation is particularly valuable for marketing analytics, website performance monitoring, and automated reporting workflows where users need seamless access to GA4 insights without complex API integration.', '@gomarble-ai', 'ai-ml', 'Unknown', 13, 'https://github.com/gomarble-ai/google-analytics-mcp-server', NULL, 0, 'https://github.com/gomarble-ai.png?size=128', '2026-03-09T05:21:01.977294+00:00'),
  ('facebook-ads', 'Facebook Ads', 'Facebook Ads MCP Server provides programmatic access to Facebook''s advertising platform through a Python-based interface. This implementation enables AI assistants to retrieve and analyze ad account data, campaign metrics, ad sets, creatives, and performance insights using the Facebook Graph API. The server requires a Facebook access token with appropriate permissions and exposes over 20 specialized tools for operations ranging from basic account listing to detailed performance analysis with customizable time ranges, breakdowns, and attribution settings. It''s particularly valuable for marketers and analysts who need to monitor campaign performance, extract advertising insights, or manage Facebook ad objects through AI assistants.', '@gomarble-ai', 'ai-ml', 'Unknown', 246, 'https://github.com/gomarble-ai/facebook-ads-mcp-server', NULL, 0, 'https://github.com/gomarble-ai.png?size=128', '2026-03-09T05:21:01.977341+00:00'),
  ('taiwan-weather', 'Taiwan Weather', 'Provides 36-hour weather forecasts for Taiwan''s counties and cities through the Central Weather Administration API. Returns detailed forecast data including temperature, weather conditions, and precipitation probability in JSON format. Includes comprehensive setup documentation with API key configuration and troubleshooting guides.', '@gonetone', 'ai-ml', 'Unknown', 7, 'https://github.com/gonetone/mcp-server-taiwan-weather', NULL, 0, 'https://github.com/gonetone.png?size=128', '2026-03-09T05:21:01.977431+00:00'),
  ('audio-interface', 'Audio Interface', 'The Audio MCP Server provides audio input/output capabilities for AI assistants like Claude, enabling them to interact with computer audio systems. Built with Python using sounddevice and soundfile libraries, it offers tools to list audio devices, record from microphones, play recordings, and handle audio files. The implementation includes features for device selection, customizable recording parameters, and temporary file management for audio storage. This server is particularly useful for voice interaction workflows, audio analysis, and creating more accessible AI experiences through spoken communication.', '@gongrzhe', 'ai-ml', 'Unknown', 8, 'https://github.com/gongrzhe/audio-mcp-server', NULL, 0, 'https://github.com/gongrzhe.png?size=128', '2026-03-09T05:21:01.977478+00:00'),
  ('image-generation-flux', 'Image Generation (Flux)', 'Image Generation MCP Server provides a bridge between Claude and the Replicate API, enabling AI assistants to generate images using the Flux model directly within conversations. The server exposes a single tool that processes image generation requests with customizable parameters like prompts, seeds, aspect ratios, and output formats, then handles the asynchronous generation process by polling the Replicate API until completion. Built with TypeScript and running on stdio transport, it''s particularly valuable for creative workflows that require image generation capabilities without leaving the conversation interface.', '@gongrzhe', 'development', 'Unknown', 50, 'https://github.com/gongrzhe/image-generation-mcp-server', NULL, 0, 'https://github.com/gongrzhe.png?size=128', '2026-03-09T05:21:01.977569+00:00'),
  ('json-manipulation', 'JSON Manipulation', 'This JSON MCP server, developed by gongrzhe, provides a standardized interface for querying and manipulating JSON data using JSONPath syntax. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers an extensive set of tools for array operations, string manipulation, numeric calculations, date handling, and data aggregation. The server implements error handling and supports various data sources through URL inputs. By abstracting complex JSON operations, it enables AI systems to easily process and analyze structured data. This implementation is particularly valuable for applications requiring programmatic JSON manipulation, facilitating use cases such as data extraction, transformation, and analysis across diverse JSON-based datasets.', '@gongrzhe', 'development', 'Unknown', 89, 'https://github.com/gongrzhe/json-mcp-server', '@gongrzhe/server-json-mcp', 9123, 'https://github.com/gongrzhe.png?size=128', '2026-03-09T05:21:01.977598+00:00'),
  ('langflow-document-qa', 'Langflow Document QA', 'Langflow-DOC-QA-SERVER is a Model Context Protocol server that connects AI assistants to a Langflow-powered document question-answering system. The implementation exposes a single tool called ''query_docs'' that forwards user queries to a Langflow API endpoint, which processes document-based questions using a Mistral model. The server runs on stdio transport for seamless integration with Claude Desktop, making it particularly valuable for workflows that require document-based information retrieval without leaving the conversation interface.', '@gongrzhe', 'ai-ml', 'Unknown', 15, 'https://github.com/gongrzhe/langflow-doc-qa-server', NULL, 0, 'https://github.com/gongrzhe.png?size=128', '2026-03-09T05:21:01.977639+00:00'),
  ('office-word', 'Office Word', 'Integrates with Microsoft Word documents to create, read, manipulate content including headings, paragraphs, tables, images, apply rich formatting, manage document protection with password encryption, extract comments, and convert to PDF format.', '@ihatesea69', 'ai-ml', 'Unknown', 1, 'https://github.com/ihatesea69/office-word-mcp', NULL, 0, 'https://github.com/ihatesea69.png?size=128', '2026-03-09T05:21:01.977673+00:00'),
  ('quickchart', 'QuickChart', 'This MCP server implementation provides integration with QuickChart, a service for generating charts and graphs. Developed by GongRzhe, it offers a bridge between AI assistants and QuickChart''s API, enabling the creation of visual data representations. Built with TypeScript and leveraging the Model Context Protocol SDK, the server focuses on simplifying chart generation tasks. It is particularly useful for AI applications that need to produce data visualizations on-the-fly, such as report generators, dashboard creators, or data analysis tools.', '@gongrzhe', 'development', 'Unknown', 159, 'https://github.com/gongrzhe/quickchart-mcp-server', NULL, 0, 'https://github.com/gongrzhe.png?size=128', '2026-03-09T05:21:01.977697+00:00'),
  ('terminal-controller', 'Terminal Controller', 'Terminal Controller is an MCP server that enables secure terminal command execution, directory navigation, and file system operations through a standardized interface. It implements several tools for executing commands, managing directories, and tracking command history, with built-in security measures to prevent dangerous operations. The server is designed to work across Windows and UNIX-based systems, making it versatile for various terminal-based tasks and integrations with AI-assisted workflows.', '@gongrzhe', 'productivity', 'Unknown', 99, 'https://github.com/gongrzhe/terminal-controller-mcp', NULL, 0, 'https://github.com/gongrzhe.png?size=128', '2026-03-09T05:21:01.977749+00:00'),
  ('google-maps-travel-planner', 'Google Maps (Travel Planner)', 'This Travel Planner MCP server, developed by Gongrzhe Inc., integrates with Google Maps services to enable AI-driven travel planning and itinerary management. Built with TypeScript and leveraging the Model Context Protocol SDK, it provides tools for location search, place details lookup, route calculation, and timezone information retrieval. The server implements core travel planning functionality like creating personalized itineraries, optimizing existing plans, searching attractions, and finding transport and accommodation options. By abstracting the complexities of travel APIs, it allows AI systems to easily plan and manage trips. This implementation is particularly valuable for applications requiring automated travel assistance, facilitating use cases such as personalized vacation planning, business trip optimization, and travel recommendation systems.', '@gongrzhe', 'development', 'Unknown', 95, 'https://github.com/gongrzhe/travel-planner-mcp-server', '@gongrzhe/server-travelplanner-mcp', 15900, 'https://github.com/gongrzhe.png?size=128', '2026-03-09T05:21:01.977788+00:00'),
  ('yolo-computer-vision', 'YOLO Computer Vision', 'The YOLO MCP Server enables AI assistants to perform computer vision tasks using state-of-the-art YOLO (You Only Look Once) models. Built with Python using FastMCP and Ultralytics, it provides tools for object detection, segmentation, classification, and pose estimation on images, as well as real-time camera analysis. The implementation offers both direct model integration and CLI-based approaches, supports model training and validation, and includes comprehensive image analysis that combines multiple model results. This server bridges the gap between AI assistants and computer vision capabilities, making it valuable for applications requiring visual understanding of user-provided images or camera feeds.', '@gongrzhe', 'productivity', 'Unknown', 29, 'https://github.com/gongrzhe/yolo-mcp-server', NULL, 0, 'https://github.com/gongrzhe.png?size=128', '2026-03-09T05:21:01.977833+00:00'),
  ('bos-basic-orchestration-system', 'BOS (Basic Orchestration System)', 'MCP-BOS is a modular server implementation that provides a structured framework for building and managing MCP modules. It features a core system for loading, registering, and managing modules through a configuration-based approach, allowing developers to easily extend functionality by adding new modules to the system. The implementation includes a simple module interface, configuration management, and server components that work together to create a flexible foundation for MCP services. The project is designed with Python 3.13 compatibility and includes example modules like ''hello_world'' to demonstrate the implementation pattern.', '@gooboot', 'development', 'Unknown', 3, 'https://github.com/gooboot/mcp-bos', NULL, 0, 'https://github.com/gooboot.png?size=128', '2026-03-09T05:21:01.977874+00:00'),
  ('welcome-text-generator', 'Welcome Text Generator', 'Automatically generates professional onboarding messages for new employees. Extracts structured data from free-text employee information and creates customizable welcome texts using a modular template system with multiple text variants. Includes tools for text analysis, template generation, and employee data management.', '@goodfel10w', 'development', 'Unknown', 0, 'https://github.com/goodfel10w/welcometextgenerator', NULL, 0, 'https://github.com/goodfel10w.png?size=128', '2026-03-09T05:21:01.977940+00:00'),
  ('safe-mcp-google-analytics', 'Safe MCP Google Analytics', 'Integrates with Google Analytics 4 to enable natural language querying of website traffic metrics, user behavior data, conversion tracking, and campaign performance. Provides executive summaries, landing page analysis, funnel drop-off detection, and optimization recommendations. Hosted service with read-only GA4 access, AES-256 encryption, zero data storage, and GDPR-compliant EU data residency.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://safe-mcp.com', NULL, 0, NULL, '2026-03-09T05:21:01.978014+00:00'),
  ('google-apps-script-api', 'Google Apps Script API', 'This MCP server provides access to the Google Apps Script API through 17 specialized tools covering project management, deployment operations, content updates, version control, process monitoring, and script execution. Built with Node.js and featuring OAuth 2.0 authentication with automatic token refresh, comprehensive logging capabilities, and enhanced error handling, it enables developers to programmatically manage Apps Script projects including creating and updating scripts, managing deployments, monitoring execution processes, and retrieving project metrics. The implementation supports both STDIO and SSE transport modes and is valuable for automating Apps Script workflows, CI/CD pipelines, project monitoring, and bulk operations across multiple script projects.', '@mohalmah', 'productivity', 'Unknown', 39, 'https://github.com/mohalmah/google-appscript-mcp-server', NULL, 0, 'https://github.com/mohalmah.png?size=128', '2026-03-09T05:21:01.978062+00:00'),
  ('google-cloud-run', 'Google Cloud Run', 'This MCP server enables AI agents to deploy applications directly to Google Cloud Run through a comprehensive set of deployment tools. Developed by Google Cloud Platform, it provides both local and remote deployment capabilities, supporting file-based deployments (from local filesystem or provided content), automatic project creation with billing account attachment, and service management operations like listing and inspecting Cloud Run services. The implementation handles the complete deployment pipeline including source code packaging, Cloud Build integration for containerization (supporting both Dockerfile and buildpack approaches), Artifact Registry management, and Cloud Run service provisioning with automatic API enablement and resource setup. Designed for AI-assisted development workflows, it allows developers to deploy applications through natural language commands while maintaining proper authentication and project isolation, making it valuable for rapid prototyping, automated deployment pipelines, and AI-powered development environments.', '@googlecloudplatform', 'cloud', 'Unknown', 551, 'https://github.com/googlecloudplatform/cloud-run-mcp', NULL, 0, 'https://github.com/googlecloudplatform.png?size=128', '2026-03-09T05:21:01.978130+00:00'),
  ('google-maps-platform-code-assist', 'Google Maps Platform Code Assist', 'This MCP server provides integration with the Perplexity AI API, enabling advanced web search and research capabilities through Perplexity''s AI-powered search engine that combines real-time web data with large language models. Built with TypeScript and featuring configurable models (including sonar-small-online, sonar-medium-online, and sonar-large-online), custom system prompts, and structured response formatting, it offers an alternative to traditional search engines by providing AI-synthesized answers with source citations and follow-up questions. The implementation requires a Perplexity API key and supports various search parameters including temperature control and response customization, making it valuable for research tasks, fact-checking, content creation, and applications where users need intelligent search results that go beyond simple keyword matching to provide contextual understanding and analysis.', '@unknown', 'development', 'Unknown', 0, 'https://developers.google.com/maps/ai/mcp', '@googlemaps/code-assist-mcp', 23343, NULL, '2026-03-09T05:21:01.978232+00:00'),
  ('google-programmable-search-engine', 'Google Programmable Search Engine', 'Google PSE MCP Server provides a bridge between AI assistants and Google Programmable Search Engine, enabling web search capabilities through the Model Context Protocol. The implementation exposes a search tool that supports query parameters including pagination, result size, language restrictions, and safe search filtering. Built with TypeScript and the MCP SDK, it handles authentication with Google API keys and custom search engine IDs, making it ideal for applications requiring web search functionality without direct API integration.', '@rendyfebry', 'development', 'Unknown', 10, 'https://github.com/rendyfebry/google-pse-mcp', 'google-pse-mcp', 4470, 'https://github.com/rendyfebry.png?size=128', '2026-03-09T05:21:01.978291+00:00'),
  ('google-workspace-developer-tools', 'Google Workspace Developer Tools', 'Official Google server that provides tools for searching and retrieving Google Workspace developer documentation, API references, and code snippets. Enables developers and AI agents to access up-to-date information about Google Workspace APIs and services including Gmail, Calendar, Drive, Docs, Sheets, and more.', '@unknown', 'development', 'Unknown', 0, 'https://developers.google.com/workspace/guides/developer-tools', NULL, 0, NULL, '2026-03-09T05:21:01.978444+00:00'),
  ('gopher-ai-twitter-search', 'Gopher AI (Twitter Search)', 'Gopher MCP Server provides access to Twitter search capabilities through the Gopher AI API, enabling natural language queries to retrieve relevant Twitter posts with metadata and relevance scores. Built by gopher-lab using Go and the MCP SDK, it implements an asynchronous polling mechanism that initiates searches via the Gopher AI platform and retrieves results once processing completes, with configurable result limits and error handling. The server is valuable for social media analysis, trend monitoring, sentiment analysis, and research applications where access to Twitter content based on specific queries or topics is needed.', '@gopher-lab', 'ai-ml', 'Unknown', 2, 'https://github.com/gopher-lab/gopher-mcp-server', NULL, 0, 'https://github.com/gopher-lab.png?size=128', '2026-03-09T05:21:01.978493+00:00'),
  ('algorand', 'Algorand', 'Algorand MCP server provides a robust toolkit for AI agents to interact with the Algorand blockchain, enabling operations like account creation, asset management, smart contract deployment, and transaction execution. Built by GoPlausible, this TypeScript-based implementation offers a standardized interface for blockchain interactions, specifically targeting AI development tools like Claude Desktop and Cursor. The server simplifies complex blockchain tasks through a comprehensive set of tools and resources, making Algorand blockchain capabilities accessible to AI assistants.', '@goplausible', 'development', 'Unknown', 40, 'https://github.com/goplausible/algorand-mcp', 'algorand-mcp', 3229, 'https://github.com/goplausible.png?size=128', '2026-03-09T05:21:01.978546+00:00'),
  ('gopluto-ai', 'GoPluto AI', 'GoPluto MCP Server provides AI assistants with access to the GoPluto API through a bridge implementation that supports both stdio and HTTP transport modes. Built by GoPluto, it uses Server-Sent Events (SSE) for real-time communication and requires API key authentication to connect to the GoPluto service at api.gopluto.ai/mcp. The server is designed for integration with Claude Desktop and other MCP clients, offering a standardized way to access GoPluto''s capabilities through the Model Context Protocol framework with configurable transport options and robust authentication handling.', '@gopluto-ai', 'ai-ml', 'Unknown', 2, 'https://github.com/gopluto-ai/gopluto-ai-mcp', NULL, 0, 'https://github.com/gopluto-ai.png?size=128', '2026-03-09T05:21:01.978585+00:00'),
  ('goreleaser', 'GoReleaser', 'A Model Context Protocol server for GoReleaser that provides AI assistants with tools and documentation to understand and work with GoReleaser configurations. Built by the GoReleaser team, it offers configuration validation to check for errors and deprecated options, deprecation fixes with detailed instructions for modernizing configurations, embedded access to GoReleaser documentation through MCP resources, and an update prompt for automated configuration modernization. The server integrates directly with GoReleaser Pro''s configuration parsing and validation engine, making it useful for maintaining release pipelines, updating legacy configurations, and getting contextual help while working with GoReleaser setups in AI-assisted development workflows.', '@goreleaser', 'development', 'Unknown', 21, 'https://github.com/goreleaser/mcp', NULL, 0, 'https://github.com/goreleaser.png?size=128', '2026-03-09T05:21:01.978613+00:00'),
  ('gossiper-shopify-admin', 'Gossiper Shopify Admin', 'Connects AI agents to Shopify''s Admin API through Gossiper''s MCP integration platform. Enables managing products, orders, customers, and inventory through natural conversation. Features built-in guardrails for safe administration, reduced token usage through efficient backend operations, and supports multiple AI assistants including Claude, ChatGPT, and Mistral.', '@unknown', 'communication', 'Unknown', 0, 'https://gossiper.ai', NULL, 0, NULL, '2026-03-09T05:21:01.978641+00:00'),
  ('fetch', 'Fetch', 'Fetch MCP Server provides functionality to retrieve web content in various formats including HTML, JSON, plain text, and Markdown. It offers four tools: fetch_html for raw HTML content, fetch_json for parsed JSON data, fetch_txt for plain text with HTML tags removed, and fetch_markdown for content converted to Markdown format. Built with TypeScript using the Model Context Protocol SDK, JSDOM for HTML parsing, and TurndownService for Markdown conversion, this implementation is particularly useful for workflows requiring web content extraction and transformation without leaving the conversation interface.', '@goswamig', 'development', 'Unknown', 3, 'https://github.com/goswamig/fetch-mcp', NULL, 0, 'https://github.com/goswamig.png?size=128', '2026-03-09T05:21:01.978667+00:00'),
  ('bigquery-analysis', 'BigQuery Analysis', 'The BigQuery Analysis MCP Server provides tools for safely executing SQL queries on Google BigQuery datasets. It offers two main capabilities: performing dry runs to validate queries and estimate their processing size, and executing validated queries with built-in safeguards that prevent data manipulation language (DML) statements and limit query size to 1 TB. The server uses application default credentials for authentication and returns query results in JSON format, making it ideal for data analysts and developers who need to perform controlled analytics operations on large datasets without risking costly or destructive operations.', '@gotalab', 'databases', 'Unknown', 2, 'https://github.com/gotalab/bigquery-analysis-mcp-server', NULL, 0, 'https://github.com/gotalab.png?size=128', '2026-03-09T05:21:01.978678+00:00'),
  ('gotohuman', 'gotoHuman', 'gotoHuman MCP Server enables AI agents to request human reviews through the gotoHuman platform, creating an asynchronous workflow for content approval and critical action validation. The server provides three main tools: listing available review forms, fetching form schemas, and submitting review requests that appear in the user''s gotoHuman inbox. Built with TypeScript using the Model Context Protocol SDK, it integrates with the gotoHuman API to facilitate human-in-the-loop processes for autonomous agents and AI automations, with webhook-based responses that allow workflows to continue after human approval.', '@gotohuman', 'development', 'Unknown', 52, 'https://github.com/gotohuman/gotohuman-mcp-server', NULL, 0, 'https://github.com/gotohuman.png?size=128', '2026-03-09T05:21:01.978706+00:00'),
  ('dify-workflows', 'Dify Workflows', 'This Dify Workflow MCP server, developed by an unnamed creator, integrates with the Dify API to enable AI-driven workflow execution. Built with Go and leveraging the MCP-Go library, it provides tools for listing authorized workflows and executing specified workflows with custom inputs. The server implements environment-based configuration, allowing for flexible API key and workflow name management. By abstracting the complexities of Dify API interactions, it enables AI systems to easily trigger and manage complex workflows. This implementation is particularly valuable for applications requiring programmatic access to Dify workflows, facilitating use cases such as automated task execution, multi-step data processing, and AI-driven decision making across various domains.', '@gotoolkits', 'productivity', 'Unknown', 59, 'https://github.com/gotoolkits/mcp-difyworkflow-server', NULL, 0, 'https://github.com/gotoolkits.png?size=128', '2026-03-09T05:21:01.978749+00:00'),
  ('wecom', 'WeCom', 'This WeCom bot MCP server, developed by an unnamed author, provides a bridge between MCP and WeCom (WeChat Work) group messaging. Built with Go and leveraging the mcp-go library, it offers tools for sending various message types including text, markdown, images, news articles, and template cards to WeCom groups. The implementation also supports file uploads and mentions specific users or mobile numbers. It''s designed for easy integration into workflows requiring team communication, making it particularly useful for developers and teams looking to automate notifications, share updates, or integrate WeCom messaging into their AI-assisted applications.', '@gotoolkits', 'communication', 'Unknown', 35, 'https://github.com/gotoolkits/mcp-wecombot-server', NULL, 0, 'https://github.com/gotoolkits.png?size=128', '2026-03-09T05:21:01.978786+00:00'),
  ('go-unifi', 'Go UniFi', 'Provides comprehensive management of UniFi Network Controller infrastructure. Supports site, device, client, network, port forwarding, DNS, and firewall operations including both v1 and v2 firewall rules with IPv6 support. Offers lazy mode with meta-tools for token efficiency and eager mode exposing all operations directly, with automatic ID-to-name resolution and per-request caching.', '@claytono', 'development', 'Unknown', 1, 'https://github.com/claytono/go-unifi-mcp', NULL, 0, 'https://github.com/claytono.png?size=128', '2026-03-09T05:21:01.978865+00:00'),
  ('github-pull-request', 'GitHub Pull Request', 'GitHub PR MCP server enables AI assistants to retrieve detailed information about GitHub pull requests, including files, diffs, comments, and reviews. Built with TypeScript and the Octokit REST API, it provides a single tool that accepts repository owner, name, pull request number, and an optional GitHub token for authentication. The server returns structured JSON data that can be used for code review assistance, PR summarization, or change analysis workflows without requiring direct GitHub API integration in client applications.', '@gourav221b', 'development', 'Unknown', 6, 'https://github.com/gourav221b/github-pr-mcp-server', NULL, 0, 'https://github.com/gourav221b.png?size=128', '2026-03-09T05:21:01.978890+00:00'),
  ('glasses', 'Glasses', 'This MCP server provides website screenshot capabilities using Puppeteer for headless Chrome automation, enabling AI assistants to capture visual snapshots of web pages with configurable device emulation and output formats. Built by Abderrahmane Gourragui with TypeScript and the Model Context Protocol SDK, it features device emulation for various screen sizes (iOS, Android, tablets, laptops with different DPI settings), support for both PNG and JPEG formats, full-page or viewport-only capture options, and robust error handling with comprehensive logging. The implementation uses Puppeteer''s headless Chrome instance with sandbox-disabled arguments for compatibility, waits for network idle before capturing to ensure complete page loads, and automatically handles file path extensions based on the selected format, making it valuable for web development workflows, automated testing documentation, content auditing, and building AI assistants that need programmatic access to visual web page content without manual browser navigation.', '@gourraguis', 'development', 'Unknown', 10, 'https://github.com/gourraguis/glasses-mcp', 'glasses-mcp', 676, 'https://github.com/gourraguis.png?size=128', '2026-03-09T05:21:01.978923+00:00'),
  ('wiz-smart-lights', 'Wiz Smart Lights', 'Provides direct UDP control over Wiz smart light bulbs using their native protocol on port 38899. Exposes tools for retrieving current bulb state (including RGB values, brightness, scene settings, and connection info) and changing RGB values with optional dimming control. Features normalized status objects that map raw bulb responses to structured data models, including a comprehensive scene mapping for predefined lighting modes like Ocean, Romance, and Focus. Useful for home automation, mood lighting control, or integrating Wiz bulbs into larger smart home workflows.', '@gowtham3105', 'browser-automation', 'Unknown', 1, 'https://github.com/gowtham3105/wiz-mcp-server', NULL, 0, 'https://github.com/gowtham3105.png?size=128', '2026-03-09T05:21:01.979051+00:00'),
  ('puppeteer-extra-stealth', 'Puppeteer Extra Stealth', 'MCP Puppeteer-Extra provides enhanced browser automation capabilities using Puppeteer-Extra with Stealth Plugin, enabling LLMs to interact with web pages while avoiding detection as automation. Built by Gpaul (Faldin), it offers a suite of tools for navigating websites, capturing screenshots, interacting with elements (click, fill, select, hover), and executing JavaScript in the browser console. The implementation is containerized with Docker for easy deployment and includes resource endpoints for accessing screenshots and console logs, making it particularly valuable for web scraping, testing, and automation workflows that require human-like browser interactions.', '@gpaul-faldin', 'cloud', 'Unknown', 2, 'https://github.com/gpaul-faldin/mcp_puppeteer_extra', NULL, 0, 'https://github.com/gpaul-faldin.png?size=128', '2026-03-09T05:21:01.979076+00:00'),
  ('typescript-prompt-development', 'TypeScript Prompt Development', 'MCP Prompt LocalDev provides a development environment for creating and testing custom prompts using the Model Context Protocol. Built by gpaul, it offers a TypeScript-based framework with three pre-configured prompt templates for API architecture planning, GitHub workflow setup, and new project initialization. The implementation includes robust development tooling with ESLint, Prettier, Jest for testing, and Husky for pre-commit hooks that ensure code quality. This server is particularly valuable for developers who want to create, test, and refine structured prompts locally before deploying them in production environments.', '@gpaul-mcp', 'development', 'Unknown', 2, 'https://github.com/gpaul-mcp/mcp_prompt_localdev', NULL, 0, 'https://github.com/gpaul-mcp.png?size=128', '2026-03-09T05:21:01.979100+00:00'),
  ('ravelry', 'Ravelry', 'MCP Ravelry provides a bridge to the Ravelry API for knitting and crochet pattern discovery, enabling users to search patterns, retrieve detailed information about specific patterns, and fetch multiple pattern details in a single request. Built by gpaul (Faldin), it authenticates with Ravelry using basic authentication and transforms API responses into structured data that''s easier to consume. The implementation is written in TypeScript with a robust development environment including ESLint, Prettier, and Jest for testing, making it ideal for crafters who want to explore knitting and crochet patterns without leaving their conversation interface.', '@gpaul-mcp', 'development', 'Unknown', 2, 'https://github.com/gpaul-mcp/mcp_ravelry', NULL, 0, 'https://github.com/gpaul-mcp.png?size=128', '2026-03-09T05:21:01.979126+00:00'),
  ('thingiverse', 'Thingiverse', 'MCP Thingiverse provides a bridge to the Thingiverse API, enabling AI assistants to search, browse, and retrieve 3D model information from the popular 3D printing community. Built by gpaul, it uses Puppeteer to interact with Thingiverse''s API endpoints, offering tools for discovering random models, searching by terms or categories, retrieving detailed model information including files, and browsing featured content. The implementation is structured as a TypeScript Node.js application with comprehensive error handling and testing, making it valuable for 3D printing enthusiasts who want to find models, compare options, or explore trending designs without leaving their conversation interface.', '@gpaul-mcp', 'development', 'Unknown', 5, 'https://github.com/gpaul-mcp/mcp_thingiverse', NULL, 0, 'https://github.com/gpaul-mcp.png?size=128', '2026-03-09T05:21:01.979154+00:00'),
  ('claude-code-prompt-engineer', 'Claude Code Prompt Engineer', 'Advanced prompt engineering MCP server for Claude Code that automatically detects and optimizes natural language requests into structured, task-specific prompts with interactive refinement capabilities. Built by Clark Everson, the implementation uses pattern matching to detect programming languages and task types (debug, test, refactor, explain, architecture), then generates optimized prompts with Claude Code-specific instructions and tool usage recommendations without requiring external API dependencies. Features interactive Q&A sessions for ambiguous requests, automatic language detection across 10+ programming languages, and built-in intelligence that works entirely with Claude Code''s native capabilities, making it valuable for developers who want to maximize the effectiveness of their Claude Code interactions through better prompt structure and context.', '@gr3enarr0w', 'development', 'Unknown', 13, 'https://github.com/gr3enarr0w/cc_peng_mcp', NULL, 0, 'https://github.com/gr3enarr0w.png?size=128', '2026-03-09T05:21:01.979187+00:00'),
  ('ipybox', 'ipybox', 'ipybox provides secure Python code execution in Docker containers with stateful IPython kernels, built by Gradion AI for AI agents that need safe code execution environments. The implementation combines Docker isolation with dual-server architecture: Jupyter Kernel Gateway manages IPython kernels for persistent code execution while a FastAPI resource server handles file operations, module introspection, and MCP tool integration through auto-generated Python client functions. Features include configurable network firewalls restricting outbound traffic to whitelisted domains, real-time output streaming with image support, bidirectional file transfers, and seamless integration of both local (stdio) and remote (HTTP/SSE) MCP servers, making it valuable for data analytics workflows, automated testing, and AI agent code actions that require isolated execution environments.', '@gradion-ai', 'cloud', 'Unknown', 69, 'https://github.com/gradion-ai/ipybox', 'ipybox', 44134, 'https://github.com/gradion-ai.png?size=128', '2026-03-09T05:21:01.979212+00:00'),
  ('pubmed-search', 'PubMed Search', 'This MCP server provides tools for searching and retrieving academic papers from the PubMed database. It implements two main functions: searching PubMed by keywords in titles/abstracts or author names, and fetching detailed paper information including titles, authors, journals, abstracts, and DOIs. The server uses the NCBI E-utilities API to query PubMed and parse XML responses, making it valuable for researchers, students, or AI assistants that need to access scientific literature in the biomedical field.', '@gradusnikov', 'databases', 'Unknown', 6, 'https://github.com/gradusnikov/pubmed-search-mcp-server', NULL, 0, 'https://github.com/gradusnikov.png?size=128', '2026-03-09T05:21:01.979264+00:00'),
  ('grafana-tempo', 'Grafana Tempo', 'Simple Tempo MCP server that provides integration with Grafana Tempo for distributed tracing analysis through two core tools: tempo_query for searching traces and tempo_trace_detail for retrieving detailed trace information. Built by Elchin Habibov in Go with Docker support, the implementation connects to Tempo instances via configurable TEMPO_URL environment variable and includes Claude Desktop configuration examples for both direct binary execution and Docker-based deployment. Designed for developers and DevOps engineers who need conversational access to distributed tracing data for debugging microservices, analyzing performance bottlenecks, and investigating system issues without manually navigating Tempo''s web interface.', '@c3ptv3', 'cloud', 'Unknown', 2, 'https://github.com/c3ptv3/simple-tempo-mcp-server', NULL, 0, 'https://github.com/c3ptv3.png?size=128', '2026-03-09T05:21:01.979309+00:00'),
  ('grafbase', 'Grafbase', 'Grafbase CLI is a command-line tool for managing GraphQL APIs, with features for local development, federation, and deployment. Written in Rust, it provides commands for creating, publishing, and checking GraphQL schemas, managing subgraphs in federated architectures, and working with extensions. The CLI supports various connectors including GraphQL, OpenAPI, and MongoDB, handles authentication workflows, and includes developer-friendly features like hot reloading and schema validation. Particularly valuable for developers building federated GraphQL APIs who need a robust local development environment with production deployment capabilities.', '@grafbase', 'databases', 'Unknown', 1217, 'https://github.com/grafbase/grafbase', NULL, 0, 'https://github.com/grafbase.png?size=128', '2026-03-09T05:21:01.979327+00:00'),
  ('nexus', 'Nexus', 'Nexus is an AI router built by Grafbase that aggregates multiple MCP servers and LLM providers (OpenAI, Anthropic, Google Vertex AI) through a unified HTTP interface, transforming from a simple MCP router into a full-featured AI gateway. It features comprehensive rate limiting with token-based quotas, stateless JWT-based authentication, tool discovery via Tantivy search indexing, and support for both STDIO and HTTP MCP server protocols with OAuth2 token forwarding. The implementation includes Docker deployment, Redis-backed distributed rate limiting, bring-your-own-key functionality for secure API key management, and extensive integration testing, making it valuable for organizations needing centralized AI resource management, multi-tenant AI applications requiring usage controls, and enterprises seeking to aggregate diverse AI tools and models behind a single authenticated endpoint.', '@nexus-router', 'databases', 'Unknown', 477, 'https://github.com/nexus-router/nexus', NULL, 0, 'https://github.com/nexus-router.png?size=128', '2026-03-09T05:21:01.979342+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('claude-code-enhanced', 'Claude Code Enhanced', 'Claude Code MCP is a server implementation that enables AI assistants to execute code, manage files, run Git operations, and perform terminal commands through the Claude CLI. Developed by Peter Steinberger under MIT license, it features a robust task orchestration system with the ''Boomerang'' pattern for complex workflows, integration with Roo Code modes for specialized agent roles, and intelligent retry mechanisms for handling transient errors. The server includes a heartbeat system to prevent client timeouts during long-running operations, comprehensive health monitoring, and configurable execution parameters through environment variables. Particularly valuable for developers who need to perform complex multi-step file operations, code refactoring, and Git workflows directly through AI assistants.', '@grahama1970', 'development', 'Unknown', 106, 'https://github.com/grahama1970/claude-code-mcp-enhanced', NULL, 0, 'https://github.com/grahama1970.png?size=128', '2026-03-09T05:21:01.979371+00:00'),
  ('mcpizza-domino-s-pizza', 'MCPizza (Domino''s Pizza)', 'This MCP server enables AI assistants to order pizza through the unofficial Domino''s API, providing tools for store location, menu browsing, order management, and payment processing. Built with Python using the pizzapi library, it offers comprehensive pizza ordering functionality including finding nearby stores, searching menus, adding items to cart, setting customer information, applying coupons, and placing orders with both cash and card payment options. The implementation includes safety features like order preview mode and configurable limits, making it valuable for food ordering automation, restaurant integration workflows, and demonstrating real-world API interactions through conversational interfaces.', '@grahammcbain', 'ai-ml', 'Unknown', 10, 'https://github.com/grahammcbain/mcpizza', NULL, 0, 'https://github.com/grahammcbain.png?size=128', '2026-03-09T05:21:01.979418+00:00'),
  ('blacksmith-ci', 'Blacksmith CI', 'Connects to Blacksmith CI to provide tools for listing and inspecting workflow runs, jobs, and logs. Includes test analytics capabilities such as detecting flaky tests, comparing test failures between runs, tracking test history, and analyzing failure patterns. Also provides usage and billing tools for monitoring core usage, cache statistics, and invoice amounts. Authenticates via session cookie with automatic extraction from Chrome.', '@grahamnotgrant', 'development', 'Unknown', 1, 'https://github.com/grahamnotgrant/blacksmith-mcp', NULL, 0, 'https://github.com/grahamnotgrant.png?size=128', '2026-03-09T05:21:01.979444+00:00'),
  ('grain', 'Grain', 'Official Grain MCP server that provides secure access to your meeting data, notes, transcripts, deals, and coaching scorecard information. Includes built-in MCP Prompts for generating one-click reports including weekly "Voice of the Customer" sentiment and request tracking, Pipeline IQ analysis for identifying high-opportunity and at-risk deals, SPICED/MEDDICC reports for deep deal understanding across meetings, and Sales Skill Scorecards for evaluating and tracking team performance over time. Works with Claude Integrations, Cursor, Windsurf, and other MCP-compatible clients.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://grain.com/release-note/06-18-2025', NULL, 0, NULL, '2026-03-09T05:21:01.979485+00:00'),
  ('gralio', 'Gralio', 'Turn your LLM into the ultimate software research assistant—free from polluted web searches and marketing noise. All accessible via our free Gralio MCP endpoint.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('daipendency-public-api-docs', 'Daipendency (Public API docs)', 'This MCP server, developed by Gus Narea, provides a standardized interface for extracting documentation and public API information from dependencies in local projects. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers a tool called ''get_dependency_docs'' that simplifies the process of retrieving dependency documentation. The implementation focuses on enhancing developer productivity by automating the extraction of dependency information, which is particularly useful for projects with complex dependency structures. It''s designed for developers and AI agents working on code analysis, documentation generation, or dependency management tasks, enabling use cases such as automated code review, intelligent API suggestions, and streamlined project documentation without manually navigating through dependency files.', '@daipendency', 'development', 'Unknown', 59, 'https://github.com/daipendency/daipendency-mcp', NULL, 0, 'https://github.com/daipendency.png?size=128', '2026-03-09T05:21:01.981189+00:00'),
  ('grok-x-com', 'Grok X.com', 'Provides real-time X.com search capabilities through xAI''s Grok API, enabling search of posts, users, conversation threads, and trending topics for social media monitoring, trend analysis, and content discovery.', '@guzus', 'ai-ml', 'Unknown', 2, 'https://github.com/guzus/grok-mcp', NULL, 0, 'https://github.com/guzus.png?size=128', '2026-03-09T05:21:01.981270+00:00'),
  ('grist', 'Grist', 'Provides tools to interact with Grist, a collaborative spreadsheet-database platform. Enables workspace and document management, table operations with SQL query support including JOINs and aggregations, record management with upsert capabilities, schema modifications, page layouts, and webhook configuration. Supports both Grist cloud instances and self-hosted deployments.', '@gwhthompson', 'databases', 'Unknown', 0, 'https://github.com/gwhthompson/grist-mcp-server', NULL, 0, 'https://github.com/gwhthompson.png?size=128', '2026-03-09T05:21:01.981280+00:00'),
  ('gwiz', 'Gwiz', 'Integrates Gmail with AI assistants through the Model Context Protocol. Provides email search using dense and sparse embeddings, bulk unsubscribe, package tracking, OTP extraction, AI-powered email labeling, contact enrichment, and community-created custom agents for tasks like auto-archiving receipts or generating weekly summaries. Includes an NPM package for building custom agents and a CLI tool for conversational email queries.', '@unknown', 'development', 'Unknown', 0, 'https://gwiz.ai', NULL, 0, NULL, '2026-03-09T05:21:01.981300+00:00'),
  ('transistor-fm', 'Transistor.fm', 'This Transistor.fm MCP server, developed by Guido X Jansen, provides a comprehensive integration with the Transistor podcast hosting platform API. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers tools for managing podcasts, episodes, analytics, and private subscribers. The implementation stands out by providing a user-friendly interface for complex podcast management operations, including audio file uploads, episode publishing, and webhook management. It''s particularly useful for podcast creators, content managers, or AI assistants needing to automate podcast workflows, analyze listener data, or manage multiple shows programmatically. The server''s design prioritizes ease of use while maintaining full access to Transistor''s feature set, making it ideal for both individual podcasters and larger podcast networks.', '@gxjansen', 'development', 'Unknown', 1, 'https://github.com/gxjansen/transistor-mcp', NULL, 0, 'https://github.com/gxjansen.png?size=128', '2026-03-09T05:21:01.981335+00:00'),
  ('short-video-maker', 'Short Video Maker', 'Short Video Maker is an automated video creation tool that generates short-form content for platforms like TikTok, Instagram Reels, and YouTube Shorts. Built by David Gyori, it combines text-to-speech (Kokoro), automatic caption generation (Whisper), background video selection (Pexels API), and music to create professional-looking videos from simple text inputs. The implementation exposes both REST API and Model Context Protocol endpoints, allowing AI assistants to generate videos by providing scenes with text and search terms. It features Docker support with CPU and CUDA variants, making it accessible for users with different hardware capabilities while maintaining memory efficiency.', '@gyoridavid', 'cloud', 'Unknown', 1004, 'https://github.com/gyoridavid/short-video-maker', 'short-video-maker', 3255, 'https://github.com/gyoridavid.png?size=128', '2026-03-09T05:21:01.981406+00:00'),
  ('loan-and-credit-management', 'Loan and Credit Management', 'Built by Kevin from Gientech using Java 17, Spring AI MCP Server WebMVC, and MyBatis Plus, this server provides access to a loan and credit management system through a Spring Boot application with H2 database backend. It exposes loan-related business operations through two main providers: LoanCreditProvider for credit assessments and loan management, and MarketingProvider for customer outreach. The system manages entities including customers, loan products, contracts, repayment plans, overdue records, and credit assessments, making it valuable for financial institutions needing loan processing, credit risk analysis, customer relationship management, and automated decision-making in lending workflows.', '@gyzhang', 'databases', 'Unknown', 3, 'https://github.com/gyzhang/mcp4ail', NULL, 0, 'https://github.com/gyzhang.png?size=128', '2026-03-09T05:21:01.981419+00:00'),
  ('dvmcp', 'DVMCP', 'A decentralized bridge connecting Model Context Protocol (MCP) servers to Nostr''s Data Vending Machine (DVM) ecosystem, enabling AI and computational tools to be discovered and utilized across a distributed network. The implementation provides tool discovery through NIP-89 announcements and direct requests, supports tool execution via Nostr events, and handles job status updates, creating a standardized protocol for exposing and consuming computational services in a decentralized environment.', '@gzuuus', 'ai-ml', 'Unknown', 28, 'https://github.com/gzuuus/dvmcp', '@dvmcp/bridge', 3432, 'https://github.com/gzuuus.png?size=128', '2026-03-09T05:21:01.981513+00:00'),
  ('powerpoint-manager', 'PowerPoint Manager', 'The MCP PPTX Server provides Claude with tools to create and manipulate PowerPoint presentations through a structured interface. Built using FastMCP, it offers comprehensive functionality for generating professional slides with customizable layouts, themes, and formatting options. Users can create complete presentations, add individual slides, apply professional themes, and generate slide previews as images. The implementation handles text formatting, bullet points, and slide layouts intelligently, saving presentations to an accessible user directory, making it particularly valuable for workflows requiring document generation without manual PowerPoint interaction.', '@h4ck4life', 'ai-ml', 'Unknown', 3, 'https://github.com/h4ck4life/mcp-pptx-server', NULL, 0, 'https://github.com/h4ck4life.png?size=128', '2026-03-09T05:21:01.981574+00:00'),
  ('rimcp-hybrid', 'RiMCP Hybrid', 'RiMCP Hybrid is a specialized MCP server developed by Hur Lu that provides AI-powered code search and retrieval capabilities for RimWorld game modding projects. Built in C# with .NET 8.0, it combines lexical search using Lucene.Net with semantic search powered by HuggingFace transformers (e5-base-v2 embeddings), creating a hybrid RAG system that indexes both C# source code and XML definition files. The implementation features incremental indexing with file change detection, graph-based relationship tracking between code symbols, and a persistent Python embedding server for fast semantic queries, making it valuable for mod developers seeking AI assistance with understanding complex codebases and finding usage patterns across the extensive RimWorld modding ecosystem.', '@h7lu', 'development', 'Unknown', 39, 'https://github.com/h7lu/rimcp_hybrid', NULL, 0, 'https://github.com/h7lu.png?size=128', '2026-03-09T05:21:01.981602+00:00'),
  ('deep-code-reasoning', 'Deep Code Reasoning', 'This MCP server enables intelligent routing between Claude Code and Google''s Gemini AI for complementary code analysis, treating LLMs as heterogeneous microservices where each handles tasks suited to their strengths. Built by Jonathan Haas using TypeScript with Google''s Generative AI SDK, it provides both traditional single-shot analysis tools and conversational AI-to-AI dialogue capabilities that allow Claude and Gemini to engage in multi-turn problem-solving sessions. The implementation leverages Gemini 2.5 Pro Preview''s 1M token context window for analyzing large codebases, distributed system traces, and cross-service impact analysis that exceeds Claude''s context limits, while Claude handles local-context operations and incremental patches. It includes security features like prompt injection protection, path traversal prevention, and input sanitization, making it valuable for debugging complex distributed systems, performance regression hunting, and hypothesis-driven analysis where extensive code execution and correlation across multiple services is required.', '@haasonsaas', 'development', 'Unknown', 102, 'https://github.com/haasonsaas/deep-code-reasoning-mcp', NULL, 0, 'https://github.com/haasonsaas.png?size=128', '2026-03-09T05:21:01.981638+00:00'),
  ('omni-lpr', 'Omni-LPR', 'Provides automatic license plate recognition (ALPR) capabilities through both REST API and Model Context Protocol interfaces. Offers tools for detecting and recognizing license plates in images, with support for multiple hardware acceleration options including ONNX, OpenVINO, and CUDA. Designed for self-hosting with asynchronous I/O for handling concurrent requests.', '@habedi', 'media', 'Unknown', 22, 'https://github.com/habedi/omni-lpr', NULL, 0, 'https://github.com/habedi.png?size=128', '2026-03-09T05:21:01.981747+00:00'),
  ('themeparks-wiki', 'ThemeParks.wiki', 'This is an MCP Server that exposes data from the ThemeParks.wiki API as tools.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('interactive-brokers', 'Interactive Brokers', 'Provides access to Interactive Brokers trading capabilities through the TWS API, built with FastMCP and the ibapi library. Offers comprehensive trading functionality including real-time market data retrieval, historical price analysis, account management, position tracking, order placement and management, and options chain analysis, all wrapped in async-friendly tools with robust connection management and heartbeat monitoring. Features configurable safety controls like read-only mode and short-selling restrictions, making it useful for algorithmic trading development, portfolio analysis, market research, and automated trading strategies while maintaining proper risk management controls.', '@happy-shine', 'development', 'Unknown', 18, 'https://github.com/happy-shine/ibkr_mcp', NULL, 0, 'https://github.com/happy-shine.png?size=128', '2026-03-09T05:21:01.983139+00:00'),
  ('servicenow', 'ServiceNow', 'Enables AI assistants to interact with ServiceNow instances through a metadata-driven architecture. Supports multiple ServiceNow instances simultaneously with automatic schema discovery and optimized tool generation. Provides comprehensive CRUD operations, batch processing, workflow management, and script synchronization across ServiceNow tables.', '@happy-technologies-llc', 'ai-ml', 'Unknown', 25, 'https://github.com/happy-technologies-llc/mcp-servicenow-nodejs', NULL, 0, 'https://github.com/happy-technologies-llc.png?size=128', '2026-03-09T05:21:01.983169+00:00'),
  ('repository-search', 'Repository Search', 'This MCP server implementation provides a file search functionality for text content within a specified repository. Developed with TypeScript and utilizing the Model Context Protocol SDK, it offers efficient searching capabilities while respecting ignore patterns defined in a .reposearchignore file. The server is designed to work in Node.js environments and includes features for file traversal, content matching, and result filtering. It''s particularly useful for AI applications or development tools that require quick and accurate text searches across codebases or document repositories. The implementation focuses on performance and configurability, making it suitable for both small-scale projects and larger, more complex file systems.', '@astricaelus', 'development', 'Unknown', 9, 'https://github.com/astricaelus/mcp-server-reposearch', NULL, 0, 'https://github.com/astricaelus.png?size=128', '2026-03-09T05:21:01.983200+00:00'),
  ('sandbox-fusion', 'Sandbox Fusion', 'The Sandbox Fusion MCP server provides AI assistants with access to the Sandbox Fusion environment through a Python-based implementation. Built using the MCP and Sandbox Fusion packages, this server runs in a dedicated Conda environment and handles communication between AI models and the sandbox environment. The implementation includes a simple launch script for environment activation and server startup, making it easy to deploy for developers working with AI agents that need to interact with simulated environments for testing, training, or demonstration purposes.', '@astricaelus', 'development', 'Unknown', 3, 'https://github.com/astricaelus/sandbox-fusion-mcp', NULL, 0, 'https://github.com/astricaelus.png?size=128', '2026-03-09T05:21:01.983232+00:00'),
  ('azure-resource-graph', 'Azure Resource Graph', 'Azure Resource Graph MCP Server provides a bridge between AI assistants and Azure''s Resource Graph API, enabling users to query and retrieve detailed information about Azure resources across subscriptions. Built with TypeScript and leveraging the Model Context Protocol, it authenticates using DefaultAzureCredential and offers both default and custom query capabilities through a simple tool interface. This implementation is particularly valuable for cloud administrators and developers who need to quickly analyze their Azure infrastructure, inventory resources, or troubleshoot configuration issues without leaving their IDE environment.', '@hardik-id', 'cloud', 'Unknown', 17, 'https://github.com/hardik-id/azure-resource-graph-mcp-server', NULL, 0, 'https://github.com/hardik-id.png?size=128', '2026-03-09T05:21:01.983292+00:00'),
  ('excel', 'Excel', 'Excel MCP Server provides Excel file manipulation capabilities without requiring Microsoft Excel installation. Built by Haris, it leverages OpenPyXL to enable workbook creation, data manipulation, formatting, and advanced features like charts and pivot tables. The server can be configured through environment variables and started in SSE mode, making it accessible from various clients including Cursor IDE. With comprehensive error handling and a rich set of tools documented in TOOLS.md, it''s ideal for workflows requiring Excel operations directly within AI assistant conversations.', '@fish0710', 'ai-ml', 'Unknown', 9, 'https://github.com/fish0710/excel-mcp', NULL, 0, 'https://github.com/fish0710.png?size=128', '2026-03-09T05:21:01.983360+00:00'),
  ('excel-file-manipulation', 'Excel File Manipulation', 'This Excel MCP server by haris-musa enables AI assistants to manipulate Excel files without requiring Microsoft Excel installation, using the openpyxl library for comprehensive workbook operations. The implementation provides 25+ tools covering workbook creation, data reading/writing with validation metadata, rich formatting with conditional rules, formula application with syntax validation, chart generation, pivot table creation, and native Excel table support. Key differentiators include intelligent data validation detection that exposes dropdown lists and constraint rules to AI assistants, dual transport support (stdio/SSE) with configurable file path handling, and robust error handling with custom exception types, making it valuable for automating Excel-based workflows, data analysis tasks, and report generation where users need programmatic Excel manipulation through natural language interactions.', '@haris-musa', 'productivity', 'Unknown', 3427, 'https://github.com/haris-musa/excel-mcp-server', 'excel-mcp-server', 443885, 'https://github.com/haris-musa.png?size=128', '2026-03-09T05:21:01.983417+00:00'),
  ('postgresql-multi-schema', 'PostgreSQL Multi-Schema', 'This MCP server provides read-only access to PostgreSQL databases with enhanced multi-schema support. It enables AI assistants to inspect database schemas across multiple namespaces, execute read-only queries, and maintain schema isolation. The server supports explicit schema specification, cross-schema discovery, and metadata security, making it ideal for scenarios requiring controlled access to complex database structures across multiple schemas.', '@harjjotsinghh', 'databases', 'Unknown', 3, 'https://github.com/harjjotsinghh/mcp-server-postgres-multi-schema', 'mcp-server-postgres-multi-schema', 4710, 'https://github.com/harjjotsinghh.png?size=128', '2026-03-09T05:21:01.983436+00:00'),
  ('google-flights', 'Google Flights', 'Integrates with Google Flights through SerpAPI (with fast-flights as a fallback) to provide comprehensive flight search capabilities through natural language interactions. Offers specialized search tools for one-way, round-trip, multi-city, and date-range queries with filtering options for airlines, stops, departure times, and seat classes. Includes utility functions for airport lookup, price comparison across nearby airports, and Google Flights URL generation for direct booking, along with curated prompt templates for common travel scenarios like business trips, family vacations, budget backpacking, and last-minute travel.', '@haroldleo', 'ai-ml', 'Unknown', 1, 'https://github.com/haroldleo/google-flights-mcp', NULL, 0, 'https://github.com/haroldleo.png?size=128', '2026-03-09T05:21:01.983482+00:00'),
  ('bbs', 'BBS', 'A message board system built in Go that provides both CLI and TUI interfaces alongside MCP server capabilities. Features a SQLite-backed architecture with support for topics, threads, and messages, plus optional encrypted synchronization through the Sweet vault system for multi-device access. Built with Cobra for CLI commands, Bubble Tea for the terminal interface, and the official MCP Go SDK, enabling forum-style discussions through standardized tools while maintaining human-friendly interfaces for direct interaction.', '@harperreed', 'databases', 'Unknown', 1, 'https://github.com/harperreed/bbs-mcp', NULL, 0, 'https://github.com/harperreed.png?size=128', '2026-03-09T05:21:01.983493+00:00'),
  ('visuals-mcp', 'Visuals MCP', 'MCP server for interactive visualizations: tables, images, trees, lists, master-detail.', '@harrybin', 'ai-ml', 'Unknown', 1, 'https://github.com/harrybin/visuals-mcp', NULL, 0, 'https://github.com/harrybin.png?size=128', '2026-03-09T05:21:01.983518+00:00'),
  ('esa-io', 'Esa.io', 'ESA MCP Server provides integration with the esa.io knowledge management platform, enabling AI assistants to search, read, create, update, and delete posts and comments. This TypeScript implementation offers tools for querying posts with advanced search parameters, managing post content with support for tags and categories, and interacting with comment threads. The server connects to the ESA API using environment variables for authentication and team selection, making it particularly useful for teams that use esa.io for documentation, knowledge sharing, and collaborative content management.', '@harukikaneko', 'development', 'Unknown', 3, 'https://github.com/harukikaneko/esa-mcp', NULL, 0, 'https://github.com/harukikaneko.png?size=128', '2026-03-09T05:21:01.983604+00:00'),
  ('adc-enterprise-orchestration', 'ADC Enterprise Orchestration', 'Enterprise orchestration system built with Python and Ollama that coordinates multiple specialized servers for different AI tasks. The implementation features an intelligent host that automatically routes queries to appropriate specialized servers, each providing domain-specific tools like code quality analysis with bug detection, advanced sentiment classification with emotion detection, document summarization with entity extraction, and knowledge base search with question answering. Includes a Flask web interface for real-time workflow visualization, JSON-RPC 2.0 compliant communication, and comprehensive analytics for enterprise development workflows, automated code review processes, customer feedback analysis, and intelligent document management.', '@harunraseed07', 'development', 'Unknown', 5, 'https://github.com/harunraseed07/adc_mcp_project', NULL, 0, 'https://github.com/harunraseed07.png?size=128', '2026-03-09T05:21:01.983633+00:00'),
  ('hashnet', 'HashNet', 'MCP server for Hashgraph Online''s Registry Broker that enables universal AI agent discovery and communication. Supports searching and connecting to agents across multiple protocols including MCP, NANDA, A2A, and OpenRouter. Provides agent registration pipelines, HCS-11 registration, chat sessions, operations monitoring, and credit management. Built with FastMCP and supports both stdio and HTTP streaming transports.', '@hashgraph-online', 'communication', 'Unknown', 10, 'https://github.com/hashgraph-online/hashnet-mcp-js', NULL, 0, 'https://github.com/hashgraph-online.png?size=128', '2026-03-09T05:21:01.983683+00:00'),
  ('ragstack', 'RAGStack', 'Provides tools to interact with a RAGStack serverless knowledge base deployed on AWS. Supports searching stored documents, chatting with context-aware RAG responses, uploading new documents and media for processing, and scraping web content into the knowledge base. Connects to your RAGStack instance via GraphQL API endpoint and integrates with AWS services including Lambda, S3, DynamoDB, and Bedrock.', '@hatmanstack', 'cloud', 'Unknown', 7, 'https://github.com/hatmanstack/ragstack-lambda', NULL, 0, 'https://github.com/hatmanstack.png?size=128', '2026-03-09T05:21:01.983700+00:00'),
  ('hana-cloud-ml-bridge', 'HANA Cloud ML Bridge', 'HANA Cloud MCP Server provides a bridge between SAP HANA Cloud databases and Cursor IDE for machine learning operations. It implements a three-layer architecture (Models, Contexts, and Protocols) that enables managing predictive models, execution contexts, and standardized communication protocols through a RESTful API. The server handles both inference and training operations, supports SQL and Python-based protocol handlers, and includes features for health monitoring and database schema initialization, making it ideal for organizations using HANA Cloud for data science workflows.', '@hatrigt', 'databases', 'Unknown', 35, 'https://github.com/hatrigt/hana-mcp-server', NULL, 0, 'https://github.com/hatrigt.png?size=128', '2026-03-09T05:21:01.983712+00:00'),
  ('hats-protocol', 'Hats Protocol', 'Hats Protocol MCP server by Dennison Bertram that provides complete organizational role management through the Hats Protocol across multiple blockchain networks including Ethereum, Polygon, Arbitrum, Optimism, Base, and Gnosis Chain. The implementation combines the Hats Protocol SDK with subgraph queries to offer hat creation, minting, burning, and transfer operations, plus permission checking, organizational structure visualization, and guided workflows through built-in prompts for common scenarios like organization setup and role auditing. Features external transaction signing for hardware wallet compatibility, multi-chain RPC management with fallback endpoints, and intelligent caching, making it valuable for DAOs managing hierarchical role structures, governance systems requiring on-chain permission verification, and organizations transitioning to decentralized role-based access control with blockchain-native identity management.', '@dennisonbertram', 'ai-ml', 'Unknown', 9, 'https://github.com/dennisonbertram/mcp-hats', NULL, 0, 'https://github.com/dennisonbertram.png?size=128', '2026-03-09T05:21:01.983771+00:00'),
  ('headless-ida-pro', 'Headless IDA Pro', 'Headless IDA MCP Server provides remote binary analysis capabilities through IDA Pro''s headless mode, exposing powerful reverse engineering tools via the Model Context Protocol. Built upon work from mrexodia''s ida-pro-mcp and DennyDai''s headless-ida library, this server enables AI agents to programmatically analyze binaries, decompile functions, manipulate code elements, and extract critical information from executable files. The implementation includes tools for function management, disassembly, decompilation, cross-reference analysis, and code annotation, making it valuable for security researchers and reverse engineers who want to integrate automated binary analysis into their AI-powered workflows.', '@cnitlrt', 'development', 'Unknown', 33, 'https://github.com/cnitlrt/headless-ida-mcp-server', NULL, 0, 'https://github.com/cnitlrt.png?size=128', '2026-03-09T05:21:01.983923+00:00'),
  ('healthnote-nip-101h', 'HealthNote (NIP-101h)', 'NIP-101h MCP server provides tools for working with health and fitness data on the Nostr decentralized protocol, developed by HealthNote Labs as part of their modular health data framework. The implementation enables AI assistants to discover available health metrics (weight, steps, heart rate, etc.), prepare standardized NIP-101h events for publishing, and generate instructions for fetching encrypted user health data from Nostr relays. Built with TypeScript and featuring automatic parsing of NIP-101h specifications, it supports privacy-preserving health data workflows where users maintain control over their sensitive information while enabling interoperability between health applications through standardized event formats.', '@healthnotelabs', 'development', 'Unknown', 3, 'https://github.com/healthnotelabs/modular-health-nips/tree/HEAD/packages/healthnote-api', NULL, 0, 'https://github.com/healthnotelabs.png?size=128', '2026-03-09T05:21:01.983960+00:00'),
  ('hebcal-jewish-calendar', 'Hebcal (Jewish Calendar)', 'Hebcal MCP is a server implementation that extends the Model Context Protocol to provide Hebrew calendar functionality for AI assistants. Developed by Michael J. Radwin, it offers tools for converting between Gregorian and Hebrew dates, calculating yahrzeits (death anniversaries), and determining Torah portions for specific dates. The server leverages the established @hebcal libraries to perform accurate calendar calculations while handling both Israeli and Diaspora Torah reading schedules. This implementation is particularly valuable for users who need to access Jewish calendar information and religious observances directly through their AI assistant interface.', '@hebcal', 'productivity', 'Unknown', 4, 'https://github.com/hebcal/hebcal-mcp', NULL, 0, 'https://github.com/hebcal.png?size=128', '2026-03-09T05:21:01.984003+00:00'),
  ('jmcomic', 'JMComic', 'JMComic provides MCP server integration for the JMComic-Crawler-Python library, enabling manga searching, downloading, and collection management through natural language commands. The implementation includes tools for album searching, batch downloading, configuration management, and ranking tracking, with built-in support for proxies, authentication, and advanced download options like PDF generation and file compression.', '@hect0x7', 'search', 'Unknown', 14, 'https://github.com/hect0x7/jmcomic-ai', NULL, 0, 'https://github.com/hect0x7.png?size=128', '2026-03-09T05:21:01.984044+00:00'),
  ('hedera', 'Hedera', 'Hedera MCP Server provides a lightweight blockchain interaction toolkit for creating Hedera wallets, checking account balances, building transactions, and sending signed transactions. Built with TypeScript and the Hedera SDK, it offers a streamlined interface for developers to perform core blockchain operations through a Model Context Protocol server. The implementation is particularly useful for developers building decentralized applications or testing Hedera network interactions without complex blockchain management overhead.', '@hedera-dev', 'development', 'Unknown', 3, 'https://github.com/hedera-dev/hts-mcp-server', NULL, 0, 'https://github.com/hedera-dev.png?size=128', '2026-03-09T05:21:01.984070+00:00'),
  ('mariadb', 'MariaDB', 'MariaDB MCP Server provides a bridge between Claude and MariaDB databases, enabling read-only SQL query execution directly within conversations. Developed by HeejunShin, this implementation authenticates with MariaDB using environment variables or command-line arguments, exposes database schema information as resources, and includes safety measures that restrict operations to SELECT, SHOW, DESCRIBE, and EXPLAIN statements. The server formats query results as formatted tables, making it particularly valuable for data exploration and analysis workflows without leaving the conversation interface.', '@abel9851', 'databases', 'Unknown', 19, 'https://github.com/abel9851/mcp-server-mariadb', 'mcp-server-mariadb', 4220, 'https://github.com/abel9851.png?size=128', '2026-03-09T05:21:01.984080+00:00'),
  ('linear-regression', 'Linear Regression', 'A Python implementation of linear regression using the Model Context Protocol (MCP) framework. This project demonstrates how to apply linear regression techniques within the MCP architecture.', '@heetvekariya', 'productivity', 'Unknown', 11, 'https://github.com/heetvekariya/linear-regression-mcp', NULL, 0, 'https://github.com/heetvekariya.png?size=128', '2026-03-09T05:21:01.984107+00:00'),
  ('shadcn-ui', 'Shadcn UI', 'Shadcn UI MCP Server provides tools for managing and installing UI components from the shadcn/ui library directly through AI assistants. Developed by heilgar under the MIT license, it offers functionality for listing available components and blocks, retrieving their documentation, and generating installation commands with support for multiple package managers (npm, pnpm, yarn, bun). The server fetches component data from the shadcn/ui website and GitHub repository, caches it for efficiency, and formats responses appropriately for consumption by AI tools. This implementation is particularly valuable for developers who want to streamline their workflow by integrating shadcn/ui component management directly into their AI-assisted development environment.', '@heilgar', 'development', 'Unknown', 22, 'https://github.com/heilgar/shadcn-ui-mcp-server', '@heilgar/shadcn-ui-mcp-server', 19396, 'https://github.com/heilgar.png?size=128', '2026-03-09T05:21:01.984134+00:00'),
  ('io-github-lchampz-heimdall', 'io.github.lchampz/heimdall', '🛡️ MCP Heimdall - Advanced Environment Architect & Diagnostic Tool.', '@lchampz', 'development', 'Unknown', 0, 'https://github.com/lchampz/mcp-heimdall', NULL, 0, 'https://github.com/lchampz.png?size=128', '2026-03-09T05:21:01.984152+00:00'),
  ('calculator', 'Calculator', 'MCP Server Calculator provides a simple mathematical expression evaluation service using Python''s AST module for secure parsing and calculation. Built by He Jie, it exposes a single ''calculate'' tool that safely evaluates mathematical expressions without using Python''s built-in eval() function, supporting basic operations like addition, subtraction, multiplication, division, and exponentiation. The implementation uses FastMCP for server functionality and is packaged for easy installation via pip, making it ideal for workflows requiring quick calculations without leaving the conversation interface.', '@githejie', 'development', 'Unknown', 146, 'https://github.com/githejie/mcp-server-calculator', 'mcp-server-calculator', 450443, 'https://github.com/githejie.png?size=128', '2026-03-09T05:21:01.984254+00:00'),
  ('jenkins', 'Jenkins', 'This Jenkins MCP server, developed by Hekmon, provides AI assistants with a standardized interface to interact with Jenkins CI/CD pipelines. Built using TypeScript and leveraging the Model Context Protocol SDK, it offers capabilities for managing and querying Jenkins jobs, builds, and artifacts. The server implements a simple notes system to demonstrate core MCP concepts, including resource management, tool execution, and prompt generation. It''s designed for flexibility, supporting various Jenkins configurations through JSON-based settings. This implementation is particularly valuable for DevOps teams and AI researchers working on automated software delivery, enabling use cases such as intelligent build monitoring, test result analysis, and deployment orchestration within Jenkins environments.', '@hekmon8', 'development', 'Unknown', 14, 'https://github.com/hekmon8/jenkins-server-mcp', NULL, 0, 'https://github.com/hekmon8.png?size=128', '2026-03-09T05:21:01.984284+00:00'),
  ('openbim', 'OpenBIM', 'A specialized MCP server for Building Information Modeling (BIM) workflows that converts Industry Foundation Classes (IFC) files to the efficient fragment format using the @thatopen/fragments library, then enables querying of BIM elements by category (walls, doors, windows, etc.) with configurable attributes and relations. Built by Helen Kwok, this implementation bridges traditional BIM file formats with modern web-based processing, making it valuable for architects, engineers, and construction professionals who need to programmatically analyze building data, extract specific building components, or integrate BIM information into AI-assisted design workflows without requiring specialized CAD software.', '@helenkwok', 'development', 'Unknown', 32, 'https://github.com/helenkwok/openbim-mcp', NULL, 0, 'https://github.com/helenkwok.png?size=128', '2026-03-09T05:21:01.984392+00:00'),
  ('kodit', 'Kodit', 'This MCP server provides AI-powered code indexing and semantic search capabilities for software development workflows, enabling AI assistants to understand and retrieve relevant code snippets from local directories and Git repositories. Built by Helix.ML using Python with FastAPI, SQLAlchemy, tree-sitter for code parsing, and support for both local embedding models and OpenAI''s API, it extracts method-level code snippets using language-specific queries, creates semantic embeddings and BM25 keyword indexes, and offers hybrid search combining vector similarity with keyword matching through reciprocal rank fusion. The implementation supports multiple deployment modes including CLI tools for manual indexing and search, MCP server for AI assistant integration, and optional VectorChord PostgreSQL extension for production-scale performance, making it valuable for AI coding assistants that need contextual code understanding, developer workflows requiring semantic code search across large codebases, and scenarios where AI needs to reference existing implementations when generating new code.', '@helixml', 'databases', 'Unknown', 116, 'https://github.com/helixml/kodit', 'kodit', 43115, 'https://github.com/helixml.png?size=128', '2026-03-09T05:21:01.984409+00:00'),
  ('hell-admin', 'Hellō Admin', 'Provides application management for the Hellō identity and SSO platform. Supports creating applications, updating configurations, generating OAuth client secrets, and uploading logos with automatic light/dark theme support. All operations include complete developer context including profile, teams, and applications. Supports both local (stdio) and remote (HTTP) transports.', '@hellocoop', 'file-systems', 'Unknown', 4, 'https://github.com/hellocoop/admin-mcp', NULL, 0, 'https://github.com/hellocoop.png?size=128', '2026-03-09T05:21:01.984461+00:00'),
  ('limelink', 'Limelink', 'MCP server for Limelink dynamic links with deep linking, social previews, and UTM tracking.', '@hellovelop', 'development', 'Unknown', 0, 'https://github.com/hellovelop/limelink-mcp-server', NULL, 0, 'https://github.com/hellovelop.png?size=128', '2026-03-09T05:21:01.984613+00:00'),
  ('openrouter', 'OpenRouter', 'This OpenRouter MCP server, developed by bossying, provides a unified interface for accessing various AI models through OpenRouter.ai. Built with TypeScript and leveraging the OpenAI SDK, it offers tools for model management, chat completion, and detailed model information retrieval. The server implements intelligent rate limiting, caching, and error handling to optimize API usage. Key features include model search, capability validation, and default model configuration. By abstracting the complexities of API communication and model selection, it enables AI systems to easily leverage a wide range of language models. This implementation is particularly valuable for applications requiring flexible access to multiple AI models, facilitating use cases such as chatbots, content generation, and AI-assisted analysis across various domains and capabilities.', '@heltonteixeira', 'development', 'Unknown', 60, 'https://github.com/heltonteixeira/openrouterai', NULL, 0, 'https://github.com/heltonteixeira.png?size=128', '2026-03-09T05:21:01.984646+00:00'),
  ('interactive-html-ui', 'Interactive HTML UI', 'A demonstration server showcasing interactive HTML UI capabilities through the SEP-1865 specification. Provides a complete reference implementation of serving HTML+MCP content with example tools for calculations, greetings, and time retrieval. Features both a standalone dashboard UI and a host application that can render and interact with the served UIs in sandboxed iframes, making it useful for developers learning to build servers with interactive web interfaces or prototyping UI-enabled applications.', '@hemanth', 'development', 'Unknown', 11, 'https://github.com/hemanth/mcp-ext-apps', NULL, 0, 'https://github.com/hemanth.png?size=128', '2026-03-09T05:21:01.984672+00:00'),
  ('cosmosdb', 'CosmosDB', 'This MCP server provides comprehensive Azure CosmosDB database analysis and operations through direct integration with the Azure Cosmos SDK, offering 8 specialized tools for database exploration, container management, document querying, and schema analysis. Built with TypeScript and featuring modular tool architecture, it enables database listing, container statistics with partition key analysis, SQL query execution with performance metrics, document retrieval by ID or filters, and automated schema discovery that analyzes document structures and data types across sample sets. The implementation includes robust error handling, connection management with configurable retry policies, and detailed logging for debugging, making it ideal for database administrators, developers, and AI assistants who need programmatic access to CosmosDB operations for data exploration, performance monitoring, and database management tasks.', '@hendrickcastro', 'databases', 'Unknown', 1, 'https://github.com/hendrickcastro/mcpcosmosdb', NULL, 0, 'https://github.com/hendrickcastro.png?size=128', '2026-03-09T05:21:01.984686+00:00'),
  ('mcpql-sql-server', 'MCPQL (SQL Server)', 'This MCP server provides AI assistants with direct access to SQL Server databases through 10 specialized tools covering table analysis, stored procedure inspection, data preview with filtering, column statistics, query execution, and comprehensive database object search. Built by Hendrick Castro using TypeScript with the mssql library and Model Context Protocol SDK, it supports multiple authentication methods (SQL, Windows, Azure AD), connection pooling, and parameterized queries for security, organizing database functionality into categories for structural analysis (table schemas, indexes, constraints), code analysis (stored procedure parameters, dependencies, definitions), data operations (preview, statistics, sample values), and search capabilities (object names, definitions, dependencies). The implementation includes comprehensive error handling, parallel query execution for performance, and supports both local SQL Server instances and Azure SQL Database, making it valuable for database documentation workflows, data exploration tasks, and building AI assistants that need programmatic access to SQL Server metadata and data without manual database management tools.', '@hendrickcastro', 'databases', 'Unknown', 12, 'https://github.com/hendrickcastro/mcpql', NULL, 0, 'https://github.com/hendrickcastro.png?size=128', '2026-03-09T05:21:01.984701+00:00'),
  ('apple-notes', 'Apple Notes', 'Integrates with Apple Notes on macOS through AppleScript, providing comprehensive note management including create, read, update, delete, and move operations. Supports folder management, keyword search, and hierarchy visualization. Works with Claude Desktop, Continue.dev, and other MCP-compatible clients.', '@henilcalagiya', 'ai-ml', 'Unknown', 40, 'https://github.com/henilcalagiya/mcp-apple-notes', NULL, 0, 'https://github.com/henilcalagiya.png?size=128', '2026-03-09T05:21:01.984743+00:00'),
  ('postgresql-database-manager', 'PostgreSQL Database Manager', 'PostgreSQL MCP Server provides a comprehensive set of tools for PostgreSQL database management through the Model Context Protocol. It enables analyzing database configurations, debugging issues, managing schemas, migrating data, and monitoring performance metrics. The server implements connection pooling for efficient resource management, supports various PostgreSQL operations including table creation, data export/import, function management, and Row-Level Security policies. Built with TypeScript and Node.js, it offers platform-specific setup instructions and detailed documentation, making it valuable for developers who need to interact with PostgreSQL databases directly within AI assistant workflows without requiring separate database management tools.', '@henkdz', 'databases', 'Unknown', 170, 'https://github.com/henkdz/postgresql-mcp-server', NULL, 0, 'https://github.com/henkdz.png?size=128', '2026-03-09T05:21:01.984820+00:00'),
  ('selfhosted-supabase', 'Selfhosted Supabase', 'The Self-Hosted Supabase MCP server provides a bridge between MCP clients and self-hosted Supabase instances, enabling database introspection and management directly from development environments. Built from scratch by HenkDz, it offers tools for querying database schemas, managing migrations, inspecting connections, handling auth users, and interacting with storage buckets through a streamlined interface focused on single-project environments. Unlike the official cloud server, this implementation avoids multi-project complexities while maintaining core functionality through both RPC calls and direct database connections, making it ideal for developers working with local or privately hosted Supabase projects.', '@henkdz', 'databases', 'Unknown', 117, 'https://github.com/henkdz/selfhosted-supabase-mcp', NULL, 0, 'https://github.com/henkdz.png?size=128', '2026-03-09T05:21:01.984831+00:00'),
  ('yuque', 'Yuque', 'Yuque MCP Server provides a bridge between AI models and the Yuque knowledge base platform through the Model Context Protocol. Built by HenryHaoson, it enables AI assistants to perform document management operations (create, read, update, delete), search content, and retrieve team statistics via Yuque''s API. The server can be deployed as a Docker container or run locally in either HTTP or CLI mode, with flexible configuration options including dynamic API token setting via query parameters. This implementation is particularly valuable for workflows requiring knowledge management, document collaboration, and team analytics within the Yuque ecosystem.', '@henryhaoson', 'cloud', 'Unknown', 52, 'https://github.com/henryhaoson/yuque-mcp-server', NULL, 0, 'https://github.com/henryhaoson.png?size=128', '2026-03-09T05:21:01.984868+00:00'),
  ('titan-memory', 'Titan Memory', 'This MCP server, developed by Henry Hawke, provides enhanced Titan Memory capabilities for AI agents. Built with TypeScript and leveraging TensorFlow.js, it offers improved context retention and retrieval through neural network-based memory encoding. The implementation focuses on optimizing long-term information storage and recall for conversational AI, enabling more coherent and contextually-aware interactions. It''s particularly useful for applications requiring persistent memory across multiple conversations or complex, multi-step tasks where traditional context windows fall short.', '@henryhawke', 'development', 'Unknown', 89, 'https://github.com/henryhawke/mcp-titan', NULL, 0, 'https://github.com/henryhawke.png?size=128', '2026-03-09T05:21:01.984898+00:00'),
  ('wolfram-alpha', 'Wolfram Alpha', 'A Wolfram Alpha MCP server that provides access to Wolfram''s computational knowledge engine through natural language queries, enabling mathematical calculations, scientific data retrieval, and factual information lookup. Built using the Model Context Protocol SDK and axios for HTTP requests, it exposes two tools: wolfram_query for general queries and wolfram_query_with_assumptions for handling ambiguous queries that require clarification. The implementation includes comprehensive error handling for API authentication, timeout management, and query interpretation issues, along with support for various Wolfram Alpha API parameters like units, currency, location, and image dimensions, making it useful for educational applications, research workflows, and AI assistants that need access to computational and factual knowledge.', '@henryhawke', 'ai-ml', 'Unknown', 5, 'https://github.com/henryhawke/wolfram-llm-mcp', NULL, 0, 'https://github.com/henryhawke.png?size=128', '2026-03-09T05:21:01.984950+00:00'),
  ('salesforce-atlassian-supabase', 'Salesforce, Atlassian, Supabase', 'This server provides integration capabilities across Salesforce, Atlassian (Jira/Confluence), Supabase, and analytics platforms, enabling full CRUD operations on CRM data, issue tracking, knowledge base management, and document storage. Built with TypeScript, it features extensive API logging and analytics tracking through Supabase, supports both tools for direct operations and resources for browsing available data across all connected platforms. The implementation includes robust error handling, credential management through environment variables, and utility functions for calculations, date formatting, UUID generation, and HTTP requests, making it valuable for enterprise workflows that need to manage customer data, track project progress, and maintain organizational knowledge bases in a unified interface.', '@henrymclane09', 'databases', 'Unknown', 1, 'https://github.com/henrymclane09/mcptest', NULL, 0, 'https://github.com/henrymclane09.png?size=128', '2026-03-09T05:21:01.984968+00:00'),
  ('io-github-btouchard-herald', 'io.github.btouchard/herald', 'Stop copy-pasting between Claude Chat and Claude Code.', '@kolapsis', 'development', 'Unknown', 36, 'https://github.com/kolapsis/herald', NULL, 0, 'https://github.com/kolapsis.png?size=128', '2026-03-09T05:21:01.984986+00:00'),
  ('herd', 'Herd', 'Herd’s MCP Server allows you to securely expose your favorite web applications to your agents and LLMs through local browser automation. Using MCP, you can create a secure bridge between AI models and your favorite websites without sharing credentials or running browsers in the cloud.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://herd.garden', NULL, 0, NULL, '2026-03-09T05:21:01.985019+00:00'),
  ('audio-player', 'Audio Player', 'Audio Player MCP Server enables Claude to control audio playback on your computer through a secure, directory-isolated interface. Built with Python using the FastMCP framework and pygame for audio handling, it provides tools to play MP3, WAV, and OGG files, list available audio in a designated directory, and stop playback. The implementation includes safety features like stdout redirection and path validation to prevent unauthorized file access, making it ideal for users who want to integrate audio controls directly into their Claude conversations without leaving the interface.', '@here-and-tomorrow-llc', 'ai-ml', 'Unknown', 5, 'https://github.com/here-and-tomorrow-llc/audio-player-mcp', NULL, 0, 'https://github.com/here-and-tomorrow-llc.png?size=128', '2026-03-09T05:21:01.985059+00:00'),
  ('optimized-memory', 'Optimized Memory', 'This optimized memory MCP server, developed by Herman Wong, provides a persistent knowledge graph for AI systems using SQLite as a backend. Built with Python and leveraging libraries like aiofiles and mcp, it offers tools for creating, updating, and querying entities, relations, and observations in a graph structure. The server is designed for efficient memory management and seamless integration with Claude Desktop. By abstracting knowledge storage and retrieval into a standardized MCP interface, it enables AI assistants to maintain context and personalize interactions across conversations. This implementation is particularly useful for applications requiring long-term memory and relationship modeling, such as personalized chat systems, knowledge management tools, or AI-powered personal assistants.', '@agentwong', 'databases', 'Unknown', 7, 'https://github.com/agentwong/optimized-memory-mcp-server', NULL, 0, 'https://github.com/agentwong.png?size=128', '2026-03-09T05:21:01.985070+00:00'),
  ('heroku', 'Heroku', 'A server implementation of the Model Context Protocol (MCP) for Heroku, allowing integration between MCP clients and Heroku services.', '@heroku', 'ai-ml', 'Unknown', 74, 'https://github.com/heroku/heroku-mcp-server', NULL, 0, 'https://github.com/heroku.png?size=128', '2026-03-09T05:21:01.985093+00:00'),
  ('github-review', 'GitHub Review', 'This GitHub MCP server provides AI assistants with direct access to GitHub''s API for pull request analysis and code review operations. Built by Heru Joko Priyo Utomo using Node.js and the Octokit library, it enables comprehensive PR analysis including file changes, commit history, repository information retrieval, and posting review comments directly to GitHub. The implementation includes built-in code review guidelines and prompts to help AI assistants perform thorough technical reviews, making it particularly useful for automated code review workflows, PR analysis, and development team collaboration where AI assistants need to interact with GitHub repositories and provide structured feedback on code changes.', '@heruujoko', 'development', 'Unknown', 5, 'https://github.com/heruujoko/github-review-mcp', NULL, 0, 'https://github.com/heruujoko.png?size=128', '2026-03-09T05:21:01.985119+00:00'),
  ('mcp-tool-factory', 'MCP Tool Factory', 'MCP Tool Factory is a meta-tool that generates complete MCP servers from various input sources. It accepts natural language tool specifications, OpenAPI 3.0+ definitions, or database schemas (SQLite/PostgreSQL) and produces fully functional TypeScript MCP servers with testing, containerization, and CI/CD workflows included. Supports multiple LLM providers including Claude, OpenAI GPT, and Google Gemini.', '@heshamfs', 'databases', 'Unknown', 1, 'https://github.com/heshamfs/mcp-tool-factory-ts', NULL, 0, 'https://github.com/heshamfs.png?size=128', '2026-03-09T05:21:01.985130+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('python-code-explorer', 'Python Code Explorer', 'This Python MCP server extracts and analyzes Python code structures, focusing on import/export relationships between files. It intelligently navigates codebases to identify related files, prioritizes the most relevant code sections to stay within token limits, and automatically includes README files for better context. The implementation features a CodeGrapher class that builds a comprehensive graph of code references, making it ideal for AI assistants that need to understand Python projects holistically without exceeding context windows.', '@hesiod-au', 'development', 'Unknown', 6, 'https://github.com/hesiod-au/python-mcp', NULL, 0, 'https://github.com/hesiod-au.png?size=128', '2026-03-09T05:21:01.985159+00:00'),
  ('file-system-observer', 'File System Observer', 'MCP Observer Server is a file system monitoring server that watches for file changes and sends real-time notifications to connected clients using the watchdog library. The implementation provides tools for subscribing to specific files or directories, listing currently monitored paths, and accessing file contents through resources, with automatic notifications sent when watched files are modified. It features a development-friendly setup with a default watched.txt file and supports both tool-based subscriptions and resource-based monitoring, making it useful for scenarios like live document editing, configuration file monitoring, or any workflow requiring real-time file system change detection.', '@hesreallyhim', 'development', 'Unknown', 22, 'https://github.com/hesreallyhim/mcp-observer-server', NULL, 0, 'https://github.com/hesreallyhim.png?size=128', '2026-03-09T05:21:01.985188+00:00'),
  ('isitdown', 'IsItDown', 'This MCP server checks the status of websites by querying isitdownrightnow.com. Developed by Really Him, it provides a simple interface to determine if a given website is currently up or down, along with the last known downtime. The server is useful for monitoring website availability, troubleshooting connectivity issues, or integrating website status checks into larger systems or workflows.', '@hesreallyhim', 'ai-ml', 'Unknown', 2, 'https://github.com/hesreallyhim/mcp-server-isitdown', NULL, 0, 'https://github.com/hesreallyhim.png?size=128', '2026-03-09T05:21:01.985222+00:00'),
  ('pyautogui', 'PyAutoGUI', 'MCP-PyAutoGUI-Server provides automated GUI testing and control capabilities through a Python-based interface. Developed by He Tao, this server wraps the PyAutoGUI library to enable AI assistants to control mouse movements, simulate keyboard input, take screenshots, and find images on screen across Windows, macOS, and Linux. The implementation offers tools for precise cursor positioning, clicking, typing text, pressing hotkeys, and screen analysis through a standardized protocol. It''s particularly useful for automating repetitive GUI tasks, creating test scripts, or allowing AI systems to interact directly with desktop applications through visual interfaces.', '@hetaobackend', 'development', 'Unknown', 40, 'https://github.com/hetaobackend/mcp-pyautogui-server', 'mcp-pyautogui-server', 3081, 'https://github.com/hetaobackend.png?size=128', '2026-03-09T05:21:01.985251+00:00'),
  ('heurist-mesh-web3-tools', 'Heurist Mesh (Web3 Tools)', 'Heurist Mesh MCP Server connects Claude to the Heurist Mesh network of specialized Web3 and blockchain tools through the Model Context Protocol. This implementation provides access to various agents including CoinGecko for cryptocurrency data, DexScreener for trading pair information, GoPlus for token security analysis, and search capabilities through Exa and Firecrawl. Built by Heurist AI, the server supports both SSE and stdio transports, making it compatible with Claude in Cursor, Claude Desktop, and other MCP-compatible interfaces. Users can access multiple blockchain services with a single API key, making it ideal for cryptocurrency research, token security verification, and Web3 data analysis workflows.', '@heurist-network', 'ai-ml', 'Unknown', 63, 'https://github.com/heurist-network/heurist-mesh-mcp-server', NULL, 0, 'https://github.com/heurist-network.png?size=128', '2026-03-09T05:21:01.985299+00:00'),
  ('eventwhisper-windows-event-logs', 'EventWhisper (Windows Event Logs)', 'EventWhisper is an MCP server by Maurice Fielenbach that provides AI assistants with access to Windows Event Log (.evtx) files through Python''s evtx library and fastmcp framework. The implementation offers tools for discovering EVTX files in directories, querying events with filters for time ranges, event IDs, and text content, and projecting specific fields from event data. Built with comprehensive normalization utilities for handling various input formats and robust error handling, it enables AI systems to analyze Windows system logs for security investigations, troubleshooting system issues, and forensic analysis workflows.', '@hexastrike', 'productivity', 'Unknown', 41, 'https://github.com/hexastrike/eventwhisper', NULL, 0, 'https://github.com/hexastrike.png?size=128', '2026-03-09T05:21:01.985342+00:00'),
  ('neural-memory', 'Neural Memory', 'A knowledge graph-powered memory system that transforms developer interactions into structured entities stored in Neo4j, using Gemini LLM for intelligent extraction of goals, constraints, preferences, pain points, and strategies from natural language requests. The system provides context-aware retrieval through graph traversal, fulltext search, and impact analysis to help AI assistants maintain long-term project memory and understand relationships between code artifacts, user preferences, and project objectives. Built with FastMCP and designed for IDE integration, it enables persistent knowledge accumulation across coding sessions while supporting code indexing, entity linking, and automated relationship inference.', '@hexecu', 'development', 'Unknown', 14, 'https://github.com/hexecu/mcp-neuralmemory', NULL, 0, 'https://github.com/hexecu.png?size=128', '2026-03-09T05:21:01.985416+00:00'),
  ('code-backup', 'Code Backup', 'MCP Backup Server provides a specialized backup and restoration system for AI agents and code editing tools, preserving both file content and agent context. Developed by Rob McGlade, it creates targeted, timestamped backups with metadata that captures the reasoning behind changes, making it ideal for creating safety checkpoints before risky edits. The server supports individual file and folder operations with pattern filtering, maintains version history, and includes emergency backup capabilities. Unlike Git, it focuses on quick, contextual snapshots rather than comprehensive version control, making it particularly valuable for AI agents making critical code changes in editors like Cursor and Windsurf.', '@hexitex', 'development', 'Unknown', 12, 'https://github.com/hexitex/mcp-backup-server', NULL, 0, 'https://github.com/hexitex.png?size=128', '2026-03-09T05:21:01.985445+00:00'),
  ('heygen', 'HeyGen', 'HeyGen MCP Server enables Claude Desktop and other MCP clients to generate AI avatar videos through the HeyGen API. It provides tools for retrieving available voices and avatars, generating videos with specified avatars and voices, and checking video generation status. The implementation handles API authentication, request formatting, and response parsing, making it easy for users to create professional AI videos directly from their AI assistant without dealing with the underlying API complexity.', '@heygen-com', 'ai-ml', 'Unknown', 44, 'https://github.com/heygen-com/heygen-mcp', 'heygen-mcp', 12110, 'https://github.com/heygen-com.png?size=128', '2026-03-09T05:21:01.985520+00:00'),
  ('jianying', 'JianYing', 'This MCP server provides programmatic access to JianYing (剪映) video editing functionality through Python automation and UI control. Built with comprehensive tools for draft management, media handling (video, audio, text), track operations, and export capabilities, it integrates with JianYing''s desktop application using UI automation libraries like uiautomation and media processing tools like imageio and pymediainfo. The implementation includes validation systems for material overlap detection, effect management, and time formatting utilities, making it suitable for automated video editing workflows, batch processing of media content, and programmatic creation of video projects without manual interface interaction.', '@hey-jian-wei', 'productivity', 'Unknown', 204, 'https://github.com/hey-jian-wei/jianying-mcp', NULL, 0, 'https://github.com/hey-jian-wei.png?size=128', '2026-03-09T05:21:01.985578+00:00'),
  ('heyoncall', 'HeyOnCall', 'Provides phone notification capabilities for AI agents through HeyOnCall''s hosted paging service, enabling agents like Claude Code and Cursor to alert users when tasks are completed or assistance is needed. Built by Mike Robbins to address the challenge of managing long-running agentic workflows without being chained to the desk, the server integrates with HeyOnCall''s free iOS and Android apps to deliver critical or non-critical notifications that can bypass do-not-disturb settings. The implementation requires no local installation as it''s hosted within HeyOnCall''s API server, with each MCP instance scoped to a single trigger for security, making it valuable for developers who want to step away from their computers while agents work on extended programming tasks or side projects.', '@unknown', 'development', 'Unknown', 0, 'https://heyoncall.com/blog/mcp-server-for-paging-a-human', NULL, 0, NULL, '2026-03-09T05:21:01.985606+00:00'),
  ('coinmarketcap-fear-greed-index', 'CoinMarketCap Fear & Greed Index', 'CoinMarketCap Universal MCP Server provides access to cryptocurrency data through a comprehensive set of tools that interact with the CoinMarketCap API. It features smart caching to reduce API calls, detailed error handling, and exposes tools for accessing cryptocurrency listings, quotes, exchange information, global market metrics, and the Fear & Greed Index. The implementation is built with TypeScript for type safety and follows a modular design pattern that makes it easy to extend. Particularly valuable for developers and analysts who need real-time cryptocurrency data directly within their Cursor environment.', '@heyzgj', 'development', 'Unknown', 2, 'https://github.com/heyzgj/mcp-feargreedindex', NULL, 0, 'https://github.com/heyzgj.png?size=128', '2026-03-09T05:21:01.985638+00:00'),
  ('godot-engine', 'Godot Engine', 'Bidirectional integration between Claude AI and Godot game engine through WebSocket-based architecture. Built with FastMCP and custom Godot addon, provides tools for creating and manipulating scene nodes, editing GDScript files, managing project resources, and executing arbitrary editor scripts. Offers real-time resources for accessing current scene structure, project settings, and editor state. Features modular command system with comprehensive error handling, editor integration through dock panel UI, and support for complex operations like creating complete game features.', '@hhhh124hhhh', 'development', 'Unknown', 19, 'https://github.com/hhhh124hhhh/godot-mcp', NULL, 0, 'https://github.com/hhhh124hhhh.png?size=128', '2026-03-09T05:21:01.985662+00:00'),
  ('tripadvisor-vacation-planner', 'TripAdvisor Vacation Planner', 'This MCP server provides access to TripAdvisor data for planning vacations, finding attractions, restaurants, and hotels. It integrates with the TripAdvisor API to offer search functionality, detailed location information, photos, and reviews. The server includes tools for location searches, nearby discovery, and an interactive vacation planning prompt. It''s designed for use cases like creating personalized travel itineraries, exploring destinations, and making informed decisions about accommodations and activities.', '@hhw67865', 'ai-ml', 'Unknown', 2, 'https://github.com/hhw67865/tripadvisor-mcp-server', NULL, 0, 'https://github.com/hhw67865.png?size=128', '2026-03-09T05:21:01.985705+00:00'),
  ('goal-story', 'Goal Story', 'Goal Story MCP enables AI assistants to interact with a goal visualization and achievement platform through a comprehensive API. Built by @hichana, it provides tools for managing personal goals, breaking them down into actionable steps, and creating personalized stories that visualize successful outcomes based on users'' beliefs and motivations. The implementation connects to the Goal Story backend service, handling authentication and data formatting, making it ideal for personal development workflows where visualization and narrative-driven approaches enhance motivation and goal attainment.', '@hichana', 'development', 'Unknown', 17, 'https://github.com/hichana/goalstory-mcp', 'goalstory-mcp', 2314, 'https://github.com/hichana.png?size=128', '2026-03-09T05:21:01.985731+00:00'),
  ('sakura-cloud', 'Sakura Cloud', 'A Sakura Cloud MCP server implementation that enables AI assistants to interact with Sakura Cloud infrastructure through a standardized interface. The server provides access to various Sakura Cloud resources (servers, disks, networks) and tools for managing these resources, with special focus on AppRun containerized applications. It handles authentication via API tokens, supports zone-specific operations across different data centers, and includes public pricing information that can be accessed without authentication. Designed for integration with Claude Desktop, it allows AI assistants to perform infrastructure management tasks through natural language.', '@hidenorigoto', 'productivity', 'Unknown', 11, 'https://github.com/hidenorigoto/sacloud-mcp', NULL, 0, 'https://github.com/hidenorigoto.png?size=128', '2026-03-09T05:21:01.985772+00:00'),
  ('hide-headless-ide', 'Hide (Headless IDE)', 'This MCP server, developed by Artem Moskvin, provides a persistent environment for executing Python code and shell commands within AI conversations. Built with Python and leveraging tools from Anthropic''s computer-use-demo, it offers a String Replace Editor for file manipulation and a Bash tool for running shell commands. The implementation stands out by providing a stateful workspace that persists across interactions, enabling complex multi-step tasks. It''s particularly useful for developers and system administrators who need to perform file operations, run scripts, or manage systems through AI-assisted workflows, allowing for seamless integration of coding and system management tasks into conversational AI interfaces.', '@hide-org', 'development', 'Unknown', 11, 'https://github.com/hide-org/hide-mcp', NULL, 0, 'https://github.com/hide-org.png?size=128', '2026-03-09T05:21:01.985802+00:00'),
  ('microsoft-entra-id', 'Microsoft Entra ID', 'The EntraID MCP Server provides AI assistants with direct access to Microsoft Entra ID (formerly Azure AD) resources through the Microsoft Graph API. Built with Python 3.10 and the msgraph-sdk, it exposes a comprehensive set of tools for managing users, groups, applications, service principals, and security features including MFA status, conditional access policies, and sign-in logs. The implementation handles authentication via client credentials, includes robust error handling with detailed logging, and supports common administrative tasks like password resets and group management. This server is particularly valuable for IT administrators and security teams who need to query and manage their Microsoft Entra ID environment through natural language interactions without switching context to the Azure portal.', '@hieuttmmo', 'cloud', 'Unknown', 36, 'https://github.com/hieuttmmo/entraid-mcp-server', NULL, 0, 'https://github.com/hieuttmmo.png?size=128', '2026-03-09T05:21:01.985824+00:00'),
  ('github-pr-diff', 'GitHub PR Diff', 'This GitHub MCP server, developed using TypeScript and the Highlight AI MCP SDK, provides a streamlined interface for AI agents to interact with GitHub''s Pull Request functionality. It focuses specifically on extracting diff content from Pull Requests, offering a simple yet powerful tool for code analysis and review automation. The implementation leverages the GitHub REST API v3 and includes robust error handling and input validation. It''s particularly useful for developers and teams looking to integrate automated code review processes, enabling use cases such as AI-assisted code analysis, change impact assessment, and automated documentation updates without directly dealing with GitHub API complexities.', '@highlight-ing', 'development', 'Unknown', 2, 'https://github.com/highlight-ing/highlight-github-mcp', NULL, 0, 'https://github.com/highlight-ing.png?size=128', '2026-03-09T05:21:01.985848+00:00'),
  ('youtube-transcript-extractor', 'YouTube Transcript Extractor', 'This YouTube MCP server, developed using TypeScript and the Highlight AI MCP SDK, enables AI agents to extract transcripts from YouTube videos. It provides a standardized interface for retrieving transcript text from various YouTube URL formats, including standard, shortened, and embed links. The implementation focuses on simplicity and error handling, offering functionality to fetch English transcripts from videos with captions enabled. It''s particularly useful for applications requiring automated content analysis, such as sentiment analysis, topic extraction, or summarization of YouTube videos, without directly dealing with YouTube''s API complexities. The server supports Node.js >=18.0.0 and uses the youtube-transcript library for transcript retrieval, making it a practical solution for integrating YouTube content into AI-driven workflows.', '@highlight-ing', 'development', 'Unknown', 2, 'https://github.com/highlight-ing/highlight-youtube-mcp', NULL, 0, 'https://github.com/highlight-ing.png?size=128', '2026-03-09T05:21:01.985897+00:00'),
  ('firebase-admin-sdk', 'Firebase Admin SDK', 'Django-based Firebase MCP server that integrates Firebase Admin SDK capabilities into Django applications, providing tools for Firebase Authentication (token verification, custom token creation, user management), Firestore database operations (document CRUD, collection queries), and Cloud Storage file management. Built by Highpolar Softwares, it offers both HTTP and stdio transport options with a custom Django management command for server execution, making it valuable for Django developers who need to expose Firebase backend services to AI assistants for user management, data operations, and file handling workflows without leaving their Django environment.', '@highpolar-softwares', 'databases', 'Unknown', 1, 'https://github.com/highpolar-softwares/django-firebase-mcp', NULL, 0, 'https://github.com/highpolar-softwares.png?size=128', '2026-03-09T05:21:01.985910+00:00'),
  ('higress-api-gateway', 'Higress API Gateway', 'Higress OPS MCP Server enables comprehensive configuration and management of Higress, a cloud-native API gateway, through a well-designed agent flow architecture. Built with Python using FastMCP, the server exposes tools for managing routes, service sources, and plugins like request-blocking, while the client leverages LangGraph and LangChain MCP Adapters to provide an interactive interface with human confirmation for sensitive operations. This implementation is ideal for DevOps teams needing to automate Higress configuration tasks through natural language commands while maintaining security through human-in-the-loop validation.', '@higress-group', 'productivity', 'Unknown', 22, 'https://github.com/higress-group/higress-ops-mcp-server', NULL, 0, 'https://github.com/higress-group.png?size=128', '2026-03-09T05:21:01.985953+00:00'),
  ('himarket', 'HiMarket', 'HiMarket is an enterprise-level AI capability marketplace and developer ecosystem hub built by the Higress group, providing a comprehensive platform for packaging, publishing, managing, and operating AI assets like Model APIs, MCP Servers, and Agent APIs through standardized product formats. The implementation features a multi-module Spring Boot backend with JPA persistence, JWT authentication, and gateway integrations for APIG and Higress, paired with React-based admin and frontend portals for managing developers, consumers, API products, and subscriptions. It supports both REST APIs and MCP Server products with configurable authentication schemes (API Key, HMAC, JWT), portal customization with OIDC integration, and automated approval workflows, making it suitable for organizations building internal AI marketplaces or managing complex API ecosystems with developer onboarding and subscription management.', '@higress-group', 'development', 'Unknown', 920, 'https://github.com/higress-group/himarket', NULL, 0, 'https://github.com/higress-group.png?size=128', '2026-03-09T05:21:01.985984+00:00'),
  ('obsidian-pdf-evidence', 'Obsidian PDF Evidence', 'An Obsidian plugin that exposes PDF evidence and vault context through an MCP bridge. Enables extraction of text from PDFs, searching for specific snippets, and generating PDF++ citations with precise page and selection coordinates using fuzzy matching algorithms. Provides comprehensive vault operations including markdown file management, Dataview queries, and content search. Includes a sidebar panel for displaying answers with evidence links and supports both direct HTTP API access and MCP client integration through a bundled bridge server.', '@hi-jin', 'search', 'Unknown', 1, 'https://github.com/hi-jin/obsidian-pdf-evidence', NULL, 0, 'https://github.com/hi-jin.png?size=128', '2026-03-09T05:21:01.986069+00:00'),
  ('himalayas-remote-jobs', 'Himalayas Remote Jobs', 'Access tens of thousands of remote job listings and company information. ', '@himalayas-app', 'development', 'Unknown', 13, 'https://github.com/himalayas-app/himalayas-mcp', NULL, 0, 'https://github.com/himalayas-app.png?size=128', '2026-03-09T05:21:01.986103+00:00'),
  ('mo-bus', 'Mo Bus', 'Provides comprehensive access to Odisha''s Mo Bus public transportation system through integration with a complete database of 84 routes, 1050+ stops, and fare structures across 18+ cities including Bhubaneswar, Cuttack, and Puri. Features intelligent journey planning with transfer optimization, multi-source geocoding using both SerpAPI and OpenStreetMap for accurate location finding, real-time fare calculation based on distance slabs, and detailed route information with stop sequences and timing estimates. Built with FastMCP framework for seamless integration with AI assistants.', '@himanshumohanty-git24', 'databases', 'Unknown', 2, 'https://github.com/himanshumohanty-git24/mobusmcp', NULL, 0, 'https://github.com/himanshumohanty-git24.png?size=128', '2026-03-09T05:21:01.986115+00:00'),
  ('osint-toolkit', 'OSINT Toolkit', 'MCP OSINT Server provides a suite of network reconnaissance tools for open-source intelligence gathering through a unified interface. Built by Himanshu Sanecha using the FastMCP framework, it integrates common OSINT utilities including WHOIS lookups, Nmap scans, DNS reconnaissance (via dnsrecon, dig, and host), and domain typosquatting detection with dnstwist. The implementation runs these tools either individually or concurrently through a parallel execution feature, making it ideal for security researchers, network administrators, and digital investigators who need quick access to domain intelligence without switching between multiple command-line tools.', '@himanshusanecha', 'development', 'Unknown', 43, 'https://github.com/himanshusanecha/mcp-osint-server', NULL, 0, 'https://github.com/himanshusanecha.png?size=128', '2026-03-09T05:21:01.986141+00:00'),
  ('microcms', 'microCMS', 'This MCP server provides complete microCMS headless CMS integration, enabling AI assistants to perform full CRUD operations on content and manage media assets through both the Content API and Management API. Built by himaratsu using TypeScript with the microCMS JavaScript SDK, it offers eight core tools including content listing with filtering and pagination, individual content retrieval, content creation/updating/patching with support for rich text and image fields, content deletion, media file retrieval with pagination tokens, and media upload via base64 data or external URLs. The implementation supports all microCMS query parameters including draft previews, field selection, reference depth expansion, and comprehensive field type specifications for images, rich editor content, dates, and content references, making it valuable for content management workflows, automated publishing, and headless CMS integration scenarios.', '@microcmsio', 'development', 'Unknown', 20, 'https://github.com/microcmsio/microcms-mcp-server', 'microcms-mcp-server', 4489, 'https://github.com/microcmsio.png?size=128', '2026-03-09T05:21:01.986176+00:00'),
  ('pathfinder', 'Pathfinder', 'Pathfinder bridges MCP clients to Language Server Protocol (LSP) servers, enabling AI assistants to access jump-to-definition and other LSP features across multiple programming languages. Built in Rust, it spawns and manages individual LSP server processes (like rust-analyzer, pyright, or typescript-language-server), handles the JSON-RPC communication protocol, and exposes LSP functionality through MCP tools with automatic retry logic for indexing delays. Each pathfinder instance manages one LSP server and supports multiple file extensions, making it useful for code navigation, symbol lookup, and understanding code relationships in development workflows.', '@himkt', 'development', 'Unknown', 4, 'https://github.com/himkt/pathfinder', NULL, 0, 'https://github.com/himkt.png?size=128', '2026-03-09T05:21:01.986206+00:00'),
  ('hatago-hub', 'Hatago Hub', 'Hatago Hub is a lightweight hub server that provides unified management for multiple MCP servers, enabling centralized access from development tools like Claude Code, Cursor, and VS Code. It supports both local MCPs and remote Streamable HTTP/SSE MCPs in a single configuration file, with environment variable expansion and tag-based filtering. The hub avoids tool name collisions by using the serverId_toolName format as the public name for clients while delegating execution to the original MCP server using its native tool name.', '@himorishige', 'development', 'Unknown', 27, 'https://github.com/himorishige/hatago-mcp-hub', NULL, 0, 'https://github.com/himorishige.png?size=128', '2026-03-09T05:21:01.986229+00:00'),
  ('io-github-rbfinch-hindsight-mcp', 'io.github.Rbfinch/hindsight-mcp', 'MCP server for AI-assisted coding with development history: git, tests, Copilot.', '@rbfinch', 'development', 'Unknown', 2, 'https://github.com/rbfinch/hindsight-mcp', NULL, 0, 'https://github.com/rbfinch.png?size=128', '2026-03-09T05:21:01.986246+00:00'),
  ('private-github-search', 'Private GitHub Search', 'MCP Private GitHub Search server provides AI assistants with targeted access to a specific private GitHub repository through authenticated API integration. Developed by Hint Services using TypeScript and the Octokit REST client, it offers tools for file content retrieval, code search, issue search, and detailed commit history with file diffs over configurable time periods. The implementation focuses on a single pre-configured repository (defined via environment variables), includes built-in rate limiting and error handling, and emphasizes showing actual code changes through its commit history tool that fetches detailed diffs by default. This makes it particularly valuable for code review workflows, development activity tracking, and repository analysis where AI assistants need deep access to private repository data without broader GitHub permissions.', '@hint-services', 'development', 'Unknown', 8, 'https://github.com/hint-services/obsidian-github-mcp', 'mcp-private-github-search', 4594, 'https://github.com/hint-services.png?size=128', '2026-03-09T05:21:01.986275+00:00'),
  ('tts-say', 'TTS Say', 'This MCP server, developed by hirokidaichi, enables text-to-speech functionality for AI agents. Built with TypeScript and leveraging the Model Context Protocol SDK, it integrates with OpenAI''s API and a local sound playback library to convert text into audible speech. The implementation focuses on providing a simple interface for text-to-speech conversion, offering functionality to generate and play audio from text input. It''s particularly useful for applications requiring voice output capabilities, enabling use cases such as AI-powered voice assistants, accessibility tools for visually impaired users, or audio content generation without the need for complex audio processing setups.', '@hirokidaichi', 'development', 'Unknown', 6, 'https://github.com/hirokidaichi/mcp-tts-say', NULL, 0, 'https://github.com/hirokidaichi.png?size=128', '2026-03-09T05:21:01.986304+00:00'),
  ('mypc', 'MyPC', 'Windows PC automation server that provides secure desktop control through zone-based permissions, enabling screenshot capture, file management, window manipulation, system monitoring, and remote execution while restricting write operations to designated directories.', '@hisence999', 'file-systems', 'Unknown', 1, 'https://github.com/hisence999/mypc-mcp', NULL, 0, 'https://github.com/hisence999.png?size=128', '2026-03-09T05:21:01.986376+00:00'),
  ('youtube-player', 'YouTube Player', 'Enables searching YouTube videos via the Data API v3 and playing results in the default browser. Provides two core tools: searchVideos for finding videos by query with metadata including titles, channels, and thumbnails, and playPlaylist for opening videos as browser playlists. Creates temporary playlists for multiple videos, supporting music discovery, educational content curation, and entertainment workflows.', '@hitendrapal3', 'ai-ml', 'Unknown', 1, 'https://github.com/hitendrapal3/youtubemcp', NULL, 0, 'https://github.com/hitendrapal3.png?size=128', '2026-03-09T05:21:01.986410+00:00'),
  ('grabmaps', 'GrabMaps', 'GrabMaps MCP server by hithereiamaliff that integrates Southeast Asian mapping services through AWS Location Service, providing AI assistants with access to GrabMaps'' Places API for geocoding and place search, Routes API for navigation and route calculation, and Maps API for tile rendering and visualization. Built with TypeScript and designed specifically for the eight countries where GrabMaps operates (Malaysia, Singapore, Thailand, Myanmar, Cambodia, Vietnam, Philippines, and Indonesia), the implementation includes intelligent country detection from search queries, comprehensive route matrix calculations, and official MapLibre GL integration for map visualization. The server addresses the gap in Southeast Asian mapping coverage compared to global providers, making it valuable for applications requiring accurate local business data, route planning, and location intelligence in the GrabMaps coverage region, with particular strength in urban areas and commercial points of interest across these markets.', '@hithereiamaliff', 'cloud', 'Unknown', 2, 'https://github.com/hithereiamaliff/mcp-grabmaps', 'mcp-grabmaps', 119, 'https://github.com/hithereiamaliff.png?size=128', '2026-03-09T05:21:01.986432+00:00'),
  ('keywords-everywhere', 'Keywords Everywhere', 'Provides access to the Keywords Everywhere API for SEO research and keyword analysis.', '@hithereiamaliff', 'search', 'Unknown', 4, 'https://github.com/hithereiamaliff/mcp-keywords-everywhere', NULL, 0, 'https://github.com/hithereiamaliff.png?size=128', '2026-03-09T05:21:01.986453+00:00'),
  ('malaysia-open-data', 'Malaysia Open Data', 'Official Malaysia Open Data MCP server that provides unified access to Malaysia''s government data ecosystem through the data.gov.my and open.dosm.gov.my platforms. Built with TypeScript and deployed via Smithery, it exposes tools for searching datasets and dashboards, retrieving weather forecasts and warnings, accessing public transportation data via GTFS feeds, and querying economic statistics from the Department of Statistics Malaysia. The implementation uses a hybrid architecture with pre-generated static indexes for fast searching combined with dynamic API calls for detailed data retrieval, making it valuable for researchers, analysts, and developers working with Malaysian demographic, economic, transportation, and environmental data without manually navigating multiple government portals.', '@hithereiamaliff', 'development', 'Unknown', 2, 'https://github.com/hithereiamaliff/mcp-datagovmy', 'mcp-datagovmy', 118, 'https://github.com/hithereiamaliff.png?size=128', '2026-03-09T05:21:01.986487+00:00'),
  ('nextcloud', 'Nextcloud', 'A comprehensive Nextcloud MCP server built by hithereiamaliff that provides 30+ tools for seamless integration with Nextcloud instances, covering Notes, Calendar, Contacts, Tables, and WebDAV operations with advanced unified search capabilities. The implementation features a sophisticated file indexing system with content extraction for text, code, and configuration files, intelligent caching with TTL management, and a relevance-scoring search engine that supports filename, content, and metadata searches across the entire Nextcloud filesystem. It includes robust error handling with ETag conflict resolution for Notes operations, WebDAV recursive directory traversal with configurable depth limits, and optimized search performance through lazy client initialization and session-based caching, making it useful for AI-assisted file management, automated content organization, calendar scheduling, contact management, and data analysis workflows in Nextcloud environments.', '@hithereiamaliff', 'development', 'Unknown', 28, 'https://github.com/hithereiamaliff/mcp-nextcloud', NULL, 0, 'https://github.com/hithereiamaliff.png?size=128', '2026-03-09T05:21:01.986518+00:00'),
  ('anubis', 'Anubis', 'Anubis is an intelligent AI workflow orchestration system built by Hive Academy that transforms chaotic AI coding sessions into structured, multi-role workflows with perfect context retention. The system implements a sophisticated role-based architecture where AI agents transition between specialized roles (Boomerang orchestrator, Architect designer, Senior Developer implementer, Code Review validator, and Integration Engineer) with each role having defined responsibilities, capabilities, and transition criteria. Built on NestJS with Prisma and SQLite, it provides comprehensive task management, subtask creation with dependency tracking, research report generation, code review workflows, and completion reporting, while maintaining detailed execution state and progress tracking throughout the entire development lifecycle.', '@hive-academy', 'databases', 'Unknown', 124, 'https://github.com/hive-academy/anubis-mcp', '@hive-academy/anubis', 6809, 'https://github.com/hive-academy.png?size=128', '2026-03-09T05:21:01.986533+00:00'),
  ('hiveflow', 'HiveFlow', 'Official HiveFlow MCP server that enables AI assistants to automate workflows and manage flows through the HiveFlow platform. Built by the HiveFlow team using Node.js with dependencies on the Model Context Protocol SDK, Axios for HTTP requests, and Commander for CLI functionality, this server provides a bridge between MCP-compatible AI assistants like Claude and Cursor and HiveFlow''s workflow automation capabilities. The implementation supports both programmatic execution and command-line usage, making it valuable for users who want to trigger automated workflows, manage business processes, or integrate workflow automation directly into their AI assistant interactions without manually accessing the HiveFlow web interface.', '@hiveflowai', 'ai-ml', 'Unknown', 4, 'https://github.com/hiveflowai/hiveflow-mcp-server', '@hiveflow/mcp-server', 134, 'https://github.com/hiveflowai.png?size=128', '2026-03-09T05:21:01.986581+00:00'),
  ('hivemind', 'Hivemind', 'Hivemind transforms Obsidian worldbuilding vaults into queryable knowledge graphs with automatic entity detection, relationship mapping, and optional ComfyUI integration for generating consistent creative content. Acts as an AI Firewall to ground assistants in user-controlled notes rather than hallucinated information.', '@hiveforge-sh', 'development', 'Unknown', 4, 'https://github.com/hiveforge-sh/hivemind', NULL, 0, 'https://github.com/hiveforge-sh.png?size=128', '2026-03-09T05:21:01.986601+00:00'),
  ('hive-crypto', 'Hive Crypto', 'This MCP server provides Ruby development environment management through integration with rbenv, the popular Ruby version manager. Built to streamline Ruby version switching and gem management workflows, it offers tools for listing available Ruby versions, installing specific versions, setting global and local Ruby versions, and managing gemsets across different projects. The implementation leverages rbenv''s robust version isolation capabilities and integrates with the Ruby ecosystem''s package management through bundler integration, making it valuable for Ruby developers working on multiple projects with different version requirements, DevOps teams managing Ruby deployments across environments, and development workflows that require automated Ruby environment provisioning.', '@hive-intel', 'development', 'Unknown', 14, 'https://github.com/hive-intel/hive-crypto-mcp', NULL, 0, 'https://github.com/hive-intel.png?size=128', '2026-03-09T05:21:01.986627+00:00'),
  ('io-github-quantulabs-hivemind', 'io.github.QuantuLabs/hivemind', 'Query multiple AI models (OpenAI, Anthropic, Google) for consensus responses.', '@quantulabs', 'development', 'Unknown', 1, 'https://github.com/quantulabs/hivemind', NULL, 0, 'https://github.com/quantulabs.png?size=128', '2026-03-09T05:21:01.986642+00:00'),
  ('rollbar', 'Rollbar', 'MCP Rollbar Server provides a bridge to the Rollbar error tracking platform, enabling AI assistants to monitor and analyze application errors. Developed by hiyorineko, this TypeScript implementation supports retrieving error items with filtering options, accessing detailed error information, viewing error occurrences, managing projects and environments, tracking deployments, and listing users. The server requires Rollbar API tokens (project and/or account level) and can be deployed via npm, locally, or with Docker, making it particularly valuable for developers who need to troubleshoot application issues, monitor error trends, or track deployment impacts through AI assistants.', '@hiyorineko', 'cloud', 'Unknown', 6, 'https://github.com/hiyorineko/mcp-rollbar-server', '@hiyorineko/mcp-rollbar-server', 5229, 'https://github.com/hiyorineko.png?size=128', '2026-03-09T05:21:01.986665+00:00'),
  ('draw-flow', 'Draw Flow', 'Enables AI agents to create, modify, and export draw.io diagrams through natural language commands. Features include real-time browser visualization, version history with visual thumbnails for restoring previous states, and support for various diagram types including flowcharts and architecture diagrams. Self-contained with an embedded HTTP server that requires no external dependencies.', '@hj1003862396', 'ai-ml', 'Unknown', 0, 'https://github.com/hj1003862396/draw-flow-mcp-server', NULL, 0, 'https://github.com/hj1003862396.png?size=128', '2026-03-09T05:21:01.986697+00:00'),
  ('dify-workflow', 'Dify Workflow', 'MCP Server transforms Dify workflow applications into MCP-compatible servers, allowing AI assistants to interact with custom functions defined in Dify. Developed by hjlarry, this plugin enables users to create simple workflow apps in Dify, expose them as endpoints with structured input schemas, and then connect these endpoints to MCP clients like Cursor. The implementation requires minimal setup - just creating a workflow in Dify, adding an endpoint that selects the app, and copying the endpoint URL to the MCP client - making it an efficient bridge between Dify''s workflow capabilities and MCP-enabled AI assistants.', '@hjlarry', 'ai-ml', 'Unknown', 63, 'https://github.com/hjlarry/dify-plugin-mcp_server', NULL, 0, 'https://github.com/hjlarry.png?size=128', '2026-03-09T05:21:01.986740+00:00'),
  ('ezanvakti', 'EzanVakti', 'Islamic prayer times MCP server that integrates with Turkey''s official EzanVakti API from the Directorate of Religious Affairs, providing access to accurate prayer schedules across multiple countries with hierarchical location browsing through countries, cities, and districts. Built in C# with .NET 8.0 and proper dependency injection, the implementation offers six core tools including country/city/district lookup, monthly prayer time retrieval, smart city search, and today''s prayer times, handling both Hijri and Gregorian date formats with comprehensive prayer data including Imsak, sunrise, Dhuhr, Asr, Maghrib, and Isha times. Designed for Islamic applications, travel planning, and religious observance tools that need reliable prayer time data with built-in rate limiting awareness and robust error handling for production use.', '@hkilimci', 'ai-ml', 'Unknown', 1, 'https://github.com/hkilimci/ezanvakti.mcp.server', NULL, 0, 'https://github.com/hkilimci.png?size=128', '2026-03-09T05:21:01.986789+00:00'),
  ('hong-kong-creative-goods-trade', 'Hong Kong Creative Goods Trade', 'Hong Kong recreation MCP server by Neo Chow that provides AI assistants with access to creative goods trade statistics from Hong Kong''s Culture, Sports and Tourism Bureau through a single specialized tool. The implementation fetches CSV data from the CCID website and processes domestic exports, re-exports, and imports data across eight creative industry categories (advertising, architecture, design, digital entertainment, film & television, music, printing & publishing, and overall creative goods) with optional year-range filtering and data cleaning that handles missing values and converts percentages to numeric format. Built using FastMCP with Docker support and comprehensive testing, it serves researchers analyzing Hong Kong''s creative economy trends, policy makers requiring trade statistics for cultural industries, and analysts studying the economic impact of creative goods in the region.', '@hkopenai', 'cloud', 'Unknown', 1, 'https://github.com/hkopenai/hk-recreation-mcp-server', 'hkopenai.hk_recreation_mcp_server', 0, 'https://github.com/hkopenai.png?size=128', '2026-03-09T05:21:01.986817+00:00'),
  ('hong-kong-immigration-department', 'Hong Kong Immigration Department', 'This MCP server provides access to Hong Kong transportation data through the FastMCP framework, specifically offering daily passenger traffic statistics from Hong Kong Immigration Department control points since 2021. Built by Neo Chow, it fetches real-time CSV data and breaks down passenger flows by visitor types (Hong Kong Residents, Mainland Visitors, Other Visitors) across different control points and directions, with flexible date range filtering that defaults to the last 7 days when no dates are specified. The implementation supports both stdio and SSE transport modes and is particularly useful for analyzing border crossing patterns, tourism trends, and transportation planning in Hong Kong.', '@hkopenai', 'ai-ml', 'Unknown', 3, 'https://github.com/hkopenai/hk-transportation-mcp-server', 'hkopenai.hk_transportation_mcp_server', 0, 'https://github.com/hkopenai.png?size=128', '2026-03-09T05:21:01.986883+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('gopls', 'Gopls', 'MCP-Gopls is a server implementation that bridges the Go Programming Language Server (gopls) with the Model Context Protocol, enabling AI assistants to perform advanced code analysis on Go projects. It provides tools for code navigation (go-to-definition, find references), code completion, hover documentation, diagnostic error checking, and test coverage analysis. The server manages communication with the gopls language server through JSON-RPC, handling initialization, reconnection, and message formatting to make Go''s powerful static analysis capabilities accessible through a standardized MCP interface.', '@hloiseau', 'development', 'Unknown', 69, 'https://github.com/hloiseau/mcp-gopls', NULL, 0, 'https://github.com/hloiseau.png?size=128', '2026-03-09T05:21:01.986909+00:00'),
  ('crossref-citation', 'Crossref Citation', 'Resolves academic paper citations through the Crossref API with smart input parsing for DOIs, arXiv IDs, PMIDs, and bibliographic queries. Supports multiple output formats including CSL-JSON, BibTeX, RIS, and formatted text. Includes caching and retry logic with exponential backoff for reliable citation retrieval.', '@h-lu', 'development', 'Unknown', 2, 'https://github.com/h-lu/crossref-cite-mcp', NULL, 0, 'https://github.com/h-lu.png?size=128', '2026-03-09T05:21:01.986969+00:00'),
  ('paper-find', 'Paper Find', 'Integrates with arXiv, Semantic Scholar, PubMed, bioRxiv, medRxiv, CrossRef, IACR ePrint Archive, Google Scholar, and RePEc to provide unified academic paper discovery and retrieval. Supports PDF downloading, full-text extraction using PyMuPDF4LLM for markdown conversion, and detailed metadata retrieval including citations, keywords, and publication history. The server offers both compact and detailed search modes to balance speed versus completeness, handles various paper identifier formats (DOIs, arXiv IDs, PubMed IDs), and includes robust error handling with network timeout management.', '@h-lu', 'databases', 'Unknown', 4, 'https://github.com/h-lu/paper-find-mcp', NULL, 0, 'https://github.com/h-lu.png?size=128', '2026-03-09T05:21:01.986980+00:00'),
  ('paperlib', 'Paperlib', 'Integrates with PostgreSQL and MinIO to provide research paper management with PDF import, semantic search, knowledge graph construction, and automated literature review workflows using graph-based relationship mapping and community detection.', '@h-lu', 'databases', 'Unknown', 0, 'https://github.com/h-lu/paperlib-mcp', NULL, 0, 'https://github.com/h-lu.png?size=128', '2026-03-09T05:21:01.986990+00:00'),
  ('aleph', 'Aleph', 'Implements Recursive Language Models (RLMs) for unbounded context processing by letting LLMs programmatically interact with large documents through a sandboxed Python REPL environment. Rather than solving context limits at the architecture level, Aleph enables models to partition context and make recursive calls to themselves, using tools like search, peek, lines, chunk, sub_query, and sub_aleph to iteratively explore and reason over massive inputs. Supports both standalone usage and MCP server mode with full trajectory logging and provenance tracking, making it ideal for document analysis, multi-document QA, and complex reasoning tasks that exceed traditional context windows.', '@hmbown', 'productivity', 'Unknown', 173, 'https://github.com/hmbown/aleph', NULL, 0, 'https://github.com/hmbown.png?size=128', '2026-03-09T05:21:01.987034+00:00'),
  ('attio', 'Attio', 'This MCP server, developed by @hmk, provides integration with Attio, an AI-native CRM platform. Built with TypeScript and leveraging the Model Context Protocol SDK, it enables AI assistants like Claude to interact with Attio''s API for reading company records and notes, as well as writing company notes. The implementation focuses on providing a standardized interface for CRM operations, with potential for expansion to other Attio activities. It''s particularly useful for AI-assisted customer relationship management, enabling use cases such as automated data retrieval, note-taking during customer interactions, and AI-enhanced CRM analysis without directly navigating Attio''s interface.', '@hmk', 'development', 'Unknown', 15, 'https://github.com/hmk/attio-mcp-server', 'attio-mcp-server', 11796, 'https://github.com/hmk.png?size=128', '2026-03-09T05:21:01.987062+00:00'),
  ('hmr-docs', 'HMR Docs', 'This MCP server provides access to HMR (Hot Module Replacement) documentation for reactive programming and hot reloading in Python through a streamable HTTP protocol endpoint. Built to serve guides, examples, conceptual explanations, architecture overviews, and complete HMR library source code, it integrates with popular development environments like Cursor, Claude Code, and VS Code through direct configuration or the mcp-remote CLI proxy. The implementation focuses on making HMR documentation easily accessible to AI assistants, with planned features including integration library docs and a built-in AI assistant for HMR concepts, making it valuable for Python developers working with reactive programming patterns and hot reloading workflows.', '@unknown', 'development', 'Unknown', 0, 'https://pyth-on-line.promplate.dev/hmr/mcp', NULL, 0, NULL, '2026-03-09T05:21:01.987122+00:00'),
  ('stock-analyzer-tingo', 'Stock Analyzer (Tingo)', 'This MCP trader server, developed by Seth Hobson, provides technical analysis capabilities for stock traders. It integrates with the Tiingo API to fetch financial data and leverages libraries like pandas and TA-Lib to perform comprehensive technical analysis on stocks. The server offers a single ''analyze-stock'' tool that takes a stock symbol and returns key technical indicators including moving averages, momentum oscillators, and volume metrics. Built with Python and designed to run as a local MCP server, it''s particularly useful for AI assistants or applications needing to generate detailed technical analysis reports or make data-driven trading recommendations based on current market data.', '@wshobson', 'ai-ml', 'Unknown', 260, 'https://github.com/wshobson/mcp-trader', NULL, 0, 'https://github.com/wshobson.png?size=128', '2026-03-09T05:21:01.987168+00:00'),
  ('rembg', 'Rembg', 'This rembg MCP server by Cory provides AI-powered background removal capabilities through integration with the rembg library, offering both single image processing and batch folder operations with support for 20+ specialized models including U2Net, BiRefNet, and SAM variants optimized for different use cases like portraits, anime, clothing, and general objects. Built with Python and featuring automatic model detection, configurable alpha matting for edge refinement, mask-only output options, and comprehensive error handling, it supports all major image formats and includes setup scripts for easy deployment. The implementation caches model sessions for performance, provides detailed model descriptions to help users choose the right algorithm for their content type, and handles both CPU and GPU acceleration, making it valuable for content creators automating image editing workflows, e-commerce platforms processing product photos, and developers building applications that require intelligent background removal with fine-tuned model selection.', '@holocode-ai', 'development', 'Unknown', 2, 'https://github.com/holocode-ai/rembg-mcp', NULL, 0, 'https://github.com/holocode-ai.png?size=128', '2026-03-09T05:21:01.987236+00:00'),
  ('my-apple-remembers', 'My Apple Remembers', 'A simple MCP server that enables AI assistants to access and save memories from Apple Notes on remote macOS systems via SSH connections. The implementation provides two core tools: memory recall for accessing notes, calendar events, messages, and files through AppleScript commands, and memory persistence for saving important information to Apple Notes with timestamped entries. Built with Docker support and minimal setup requirements (just enabling Remote Login on the target Mac), it''s particularly useful for users who want their AI assistant to remember context across conversations by leveraging their existing Apple Notes as a persistent memory store, with the flexibility to connect to any macOS machine over SSH including localhost configurations.', '@honeybluesky', 'cloud', 'Unknown', 10, 'https://github.com/honeybluesky/my-apple-remembers', NULL, 0, 'https://github.com/honeybluesky.png?size=128', '2026-03-09T05:21:01.987298+00:00'),
  ('solana-fender', 'Solana Fender', 'Anchor-MCP is a Rust CLI server that enables AI IDEs like Cursor or Windsurf to more effectively write Solana Anchor programs by providing security analysis capabilities. Developed by Cian (github.com/cianyyz), it implements the Model Context Protocol to expose tools for checking Anchor programs and files against Solana Fender security checks. The server processes JSON-RPC requests, allowing AI assistants to identify potential vulnerabilities in Solana smart contracts without leaving their development environment, making it particularly valuable for blockchain developers who want to ensure their code meets security standards before deployment.', '@honey-guard', 'development', 'Unknown', 3, 'https://github.com/honey-guard/anchor-mcp', 'anchor-mcp', 0, 'https://github.com/honey-guard.png?size=128', '2026-03-09T05:21:01.987349+00:00'),
  ('aligo-sms', 'Aligo SMS', 'This MCP server integrates with the Aligo SMS API, allowing AI assistants to send text messages directly through the Aligo platform. Built by Seungwon Hong, it leverages the Model Context Protocol to expose SMS functionality as tools that can be called programmatically. The server requires Aligo API credentials and supports both test and production modes, making it useful for applications that need to send notifications, alerts, or communication messages without leaving the AI assistant conversation.', '@hongsw', 'development', 'Unknown', 0, 'https://github.com/hongsw/aligo-sms-mcp-server', NULL, 0, 'https://github.com/hongsw.png?size=128', '2026-03-09T05:21:01.987374+00:00'),
  ('hopx', 'Hopx', 'Enables code execution in secure, isolated cloud sandboxes. Supports Python, JavaScript, Bash, and Go with pre-installed data analysis libraries (pandas, numpy, matplotlib). Sandboxes spin up in ~100ms and auto-destroy after use, providing cost-effective execution for AI assistants.', '@hopx-ai', 'development', 'Unknown', 172, 'https://github.com/hopx-ai/mcp', NULL, 0, 'https://github.com/hopx-ai.png?size=128', '2026-03-09T05:21:01.987425+00:00'),
  ('command-proxy', 'Command Proxy', 'MCP Command Proxy is a server that acts as a proxy for CLI commands, specifically optimized for Expo development but adaptable to any command-line application. Built with TypeScript and the Model Context Protocol SDK, it runs commands in a pseudo-terminal, captures output in a configurable circular buffer, and provides tools for AI assistants to retrieve logs, send key presses to the running process, and check process status. The implementation enables AI assistants like Claude to interact with and troubleshoot command-line applications, making it particularly valuable for developers working with interactive CLI tools who want AI assistance with log analysis and process management.', '@hormold', 'development', 'Unknown', 12, 'https://github.com/hormold/mcp-command-proxy', 'mcp-command-proxy', 1565, 'https://github.com/hormold.png?size=128', '2026-03-09T05:21:01.987452+00:00'),
  ('esp-idf', 'ESP-IDF', 'ESP-MCP provides a specialized interface for building ESP-IDF projects with integrated error handling and logging capabilities. The implementation offers a single tool that executes ESP-IDF build commands in a project directory, capturing both standard output and error streams for analysis. It handles the ESP-IDF environment setup automatically by sourcing the required export script before running build commands. This server is particularly valuable for developers working with ESP32 microcontrollers who want to streamline their build process and get automatic issue fixing based on build logs without leaving their AI assistant interface.', '@horw', 'development', 'Unknown', 136, 'https://github.com/horw/esp-mcp', NULL, 0, 'https://github.com/horw.png?size=128', '2026-03-09T05:21:01.987482+00:00'),
  ('google-spreadsheets', 'Google Spreadsheets', 'Spreadsheet-MCP-Server provides integration with Google Spreadsheets through the Model Context Protocol, allowing AI assistants to interact with spreadsheet data programmatically. Built with TypeScript and leveraging the MCP SDK, this server implementation offers tools for retrieving and manipulating spreadsheet content through a standardized API. The server architecture includes utilities for formatting data and connecting to spreadsheet services, with comprehensive test coverage ensuring reliability. It''s particularly useful for applications requiring data analysis, reporting, or any workflow that needs to access or update information stored in spreadsheets without manual intervention.', '@hosakakeigo', 'development', 'Unknown', 1, 'https://github.com/hosakakeigo/spreadsheet-mcp-server', NULL, 0, 'https://github.com/hosakakeigo.png?size=128', '2026-03-09T05:21:01.988055+00:00'),
  ('gensokyo', 'Gensokyo', 'Gensokyo-MCP is a Go-based MCP server that bridges chat bot platforms with the Model Context Protocol, featuring cross-platform compilation support for Linux, macOS, Windows, and Android. The implementation includes comprehensive message processing for both group and direct messages, WebSocket client connectivity, image compression and format conversion capabilities, and platform-specific restart mechanisms. Built with a modular architecture using packages for configuration management, API calls, logging, and bot statistics, it enables AI assistants to interact with chat platforms while handling media processing and maintaining persistent connections across different operating systems.', '@hoshinonyaruko', 'communication', 'Unknown', 34, 'https://github.com/hoshinonyaruko/gensokyo-mcp', NULL, 0, 'https://github.com/hoshinonyaruko.png?size=128', '2026-03-09T05:21:01.988099+00:00'),
  ('hostinger-api', 'Hostinger API', 'This MCP server provides AI assistants with direct access to Hostinger''s API for comprehensive web hosting management, featuring over 100 specialized tools organized into billing, DNS, domain, and VPS management categories. Built by Hostinger''s VPS team with Node.js and TypeScript, it supports both stdio and SSE transport modes, includes robust authentication with API token management, and enables operations like domain registration and availability checking, DNS zone record manipulation, VPS creation and management, firewall configuration, backup operations, and billing subscription handling. The implementation uses OpenAPI-generated tool schemas with proper parameter validation and error handling, supports both development and production deployment scenarios, and makes Hostinger''s full hosting platform accessible through natural language interaction, making it valuable for automated hosting workflows, infrastructure management, and building AI assistants that need programmatic access to web hosting services without manual control panel navigation.', '@hostinger', 'development', 'Unknown', 61, 'https://github.com/hostinger/api-mcp-server', 'hostinger-api-mcp', 30623, 'https://github.com/hostinger.png?size=128', '2026-03-09T05:21:01.988135+00:00'),
  ('seo-checker', 'SEO Checker', 'Professional SEO analysis server built with FastMCP that provides detailed website optimization insights including title tags, meta descriptions, header structure, content quality, image optimization, technical SEO factors, and social media tags. The implementation features both local and remote deployment options with Docker support for hosting platforms like Hostinger, offering comprehensive scoring algorithms that evaluate pages across multiple SEO dimensions and generate actionable recommendations for improving search engine visibility. Designed for SEO professionals, web developers, and content creators who need programmatic access to detailed website analysis through tools like analyze_seo for full reports, seo_quick_check for rapid assessments, and seo_meta_tags_check for focused meta tag analysis.', '@hostinger', 'cloud', 'Unknown', 22, 'https://github.com/hostinger/selfhosted-mcp-server-template', NULL, 0, 'https://github.com/hostinger.png?size=128', '2026-03-09T05:21:01.988163+00:00'),
  ('io-github-michael-denyer-hot-memory-mcp', 'io.github.michael-denyer/hot-memory-mcp', 'Two-tier memory: hot cache (0ms) + semantic search. Self-organizing.', '@michael-denyer', 'development', 'Unknown', 3, 'https://github.com/michael-denyer/memory-mcp', NULL, 0, 'https://github.com/michael-denyer.png?size=128', '2026-03-09T05:21:01.988180+00:00'),
  ('bytedance-hot-news', 'ByteDance Hot News', 'MCP Hot News Server provides AI assistants with access to real-time news and trending topics through a standardized interface. Developed by ByteDance (wudalu), this Python implementation includes both server and client components with LangChain adapter support for easy integration into existing AI workflows. The server enables AI agents to fetch current news stories, analyze trending topics, and provide up-to-date information to users, making it valuable for building news-aware chatbots, content generation systems, and applications requiring current events context.', '@wudalu', 'development', 'Unknown', 3, 'https://github.com/wudalu/mcp-hot-news-server', NULL, 0, 'https://github.com/wudalu.png?size=128', '2026-03-09T05:21:01.988207+00:00'),
  ('knowledge-graph-toolkit', 'Knowledge Graph Toolkit', 'Built on FastMCP 2.0, this MCP server enables AI to autonomously select and execute tools through function calling. Provides database operations for employee and department queries, knowledge base management with vector search via ChromaDB, knowledge graph construction with entity extraction and relationship building, mathematical calculations, time operations, and API integrations. Features a decoupled architecture supporting independent deployment of MCP server and web interface components.', '@houmingya', 'databases', 'Unknown', 1, 'https://github.com/houmingya/llm_mcp_tools', NULL, 0, 'https://github.com/houmingya.png?size=128', '2026-03-09T05:21:01.988223+00:00'),
  ('fan-out-query-analyser', 'Fan Out Query Analyser', 'Analyzes web content to discover query coverage using the same fan-out techniques AI search engines use internally. Supports three analysis modes: content-only inference from article structure, hybrid mode combining content with keyword variants, and keyword-only query generation. Generates 5-8 types of query variants (equivalent, specification, follow-up, comparison, clarification) and provides coverage scores with evidence quotes, specific gaps, and actionable recommendations for optimizing content visibility in generative AI search engines.', '@houtini-ai', 'ai-ml', 'Unknown', 7, 'https://github.com/houtini-ai/fanout-mcp', NULL, 0, 'https://github.com/houtini-ai.png?size=128', '2026-03-09T05:21:01.988264+00:00'),
  ('google-knowledge-graph', 'Google Knowledge Graph', 'MCP server for Google''s free public Knowledge Graph Search API. Search for structured entity information about people, places, organizations, and concepts.', '@houtini-ai', 'search', 'Unknown', 7, 'https://github.com/houtini-ai/google-knowledge-graph-mcp', NULL, 0, 'https://github.com/houtini-ai.png?size=128', '2026-03-09T05:21:01.988365+00:00'),
  ('houtini-lm', 'Houtini LM', 'Houtini LM is an MCP server that provides expert prompt engineering capabilities through LM Studio integration, featuring 35+ specialized functions for code analysis, generation, and creative tasks. Built with TypeScript and a modern plugin architecture, it offers intelligent context window management with automatic chunking for large codebases, comprehensive security validation with path traversal protection, and caching for performance optimization. The implementation includes analysis functions for code quality, security audits, and project structure evaluation, generation tools for unit tests, documentation, and WordPress themes, plus creative functions for games and CSS art generation. Designed for developers working with local AI models who need reliable, secure access to advanced prompting capabilities without cloud dependencies, it enables use cases like automated code review, documentation generation, security analysis, and rapid prototyping through Claude Desktop integration.', '@houtini-ai', 'development', 'Unknown', 10, 'https://github.com/houtini-ai/lm', '@houtini/lm', 2169, 'https://github.com/houtini-ai.png?size=128', '2026-03-09T05:21:01.988398+00:00'),
  ('hoverfly', 'Hoverfly', 'This Hoverfly MCP server by Kapish Malik provides AI assistants with direct control over Hoverfly, a service virtualization tool for creating HTTP/HTTPS mocks and stubs during development and testing. The implementation exposes core Hoverfly operations including server lifecycle management (start/stop), mock API creation through detailed request-response pair definitions, simulation management, and status monitoring, all accessible through natural language interactions. Built with Spring Boot and the Spring AI MCP framework, it runs Hoverfly in webserver mode on port 8500 with admin controls on port 8888, making it valuable for developers and testers who need to quickly set up and manage API mocks for integration testing, service isolation, or simulating external dependencies without manual Hoverfly configuration.', '@kapishmalik', 'development', 'Unknown', 8, 'https://github.com/kapishmalik/hoverfly-mcp-server', NULL, 0, 'https://github.com/kapishmalik.png?size=128', '2026-03-09T05:21:01.988427+00:00'),
  ('howrisky', 'HowRisky', 'Bridges HowRisky''s proprietary financial risk analysis API to provide Monte Carlo simulations with fat-tail modeling. Offers 8 specialized tools including CVaR/VaR calculations, ruin probability analysis, multi-portfolio comparisons, and text-to-portfolio conversion. Uses proprietary KDE algorithms to model fat-tail distributions for more accurate crash risk assessment. Supports tax-aware calculations across 15+ countries for portfolio analysis, startup equity valuation, real estate investment analysis, and Kelly criterion betting strategies.', '@howrisky', 'ai-ml', 'Unknown', 1, 'https://github.com/howrisky/howrisky-mcp-server', NULL, 0, 'https://github.com/howrisky.png?size=128', '2026-03-09T05:21:01.988495+00:00'),
  ('the-odds-api', 'The Odds API', 'Wagyu Sports MCP Server provides a bridge between AI assistants and The Odds API, enabling access to sports betting data including available sports, odds, and quota information. The server supports both test mode with mock data and live mode with real API calls, making it suitable for development without consuming API credits. Built with Python using the FastMCP framework, it features configurable authentication, comprehensive error handling, and tools for retrieving sports lists, game odds with customizable parameters, and API quota tracking. This implementation is particularly valuable for sports bettors who want to compare odds across multiple bookmakers, track line movements, or analyze betting trends directly through conversational AI.', '@hrgarber', 'development', 'Unknown', 2, 'https://github.com/hrgarber/wagyu_mcp_hackathon/tree/HEAD/wagyu_sports', NULL, 0, 'https://github.com/hrgarber.png?size=128', '2026-03-09T05:21:01.988571+00:00'),
  ('payman-ai', 'Payman AI', 'Payman AI MCP Server provides a bridge to Payman AI''s payment processing API, enabling AI assistants to create payees, search existing payees, send payments, and check balances through natural language prompts. Built with TypeScript using the Model Context Protocol SDK, it authenticates with the Payman API using API keys and exposes four specialized tools that handle the core payment operations. The server runs on stdio transport, making it compatible with Claude Desktop and Cursor, and is particularly useful for developers who want to integrate payment functionality into their AI assistant workflows without switching context to a separate payment interface.', '@hrishi0102', 'development', 'Unknown', 3, 'https://github.com/hrishi0102/payman_mcp', NULL, 0, 'https://github.com/hrishi0102.png?size=128', '2026-03-09T05:21:01.988599+00:00'),
  ('aws-cost-explorer', 'AWS Cost Explorer', 'This serverless MCP server implementation provides AI assistants with AWS Cost Explorer capabilities through a complete OAuth 2.0 authenticated infrastructure built on AWS Lambda, CloudFront, and Cognito. Built using TypeScript with AWS CDK for infrastructure as code, it features seven specialized cost analysis tools including cost and usage retrieval, forecasting, dimension discovery, and cost comparison drivers, all accessible through natural language prompts with proper filtering and grouping capabilities. The implementation includes custom streamable HTTP transport with Server-Sent Events for real-time communication, RFC-compliant OAuth 2.0 flows with dynamic client registration, and session management optimized for serverless environments, making it valuable for financial analysis workflows, cloud cost optimization, and building AI assistants that need programmatic access to AWS billing data without manual console navigation.', '@hteek', 'cloud', 'Unknown', 3, 'https://github.com/hteek/serverless-mcp', NULL, 0, 'https://github.com/hteek.png?size=128', '2026-03-09T05:21:01.988762+00:00'),
  ('html-css-to-image', 'HTML/CSS to Image', 'Integrates with the HTML/CSS to Image API to generate images from HTML and CSS code or capture screenshots of URLs. Supports customizable parameters including viewport size, device scale, JavaScript delays, and CSS selectors for targeting specific page elements. Includes batch generation for creating multiple images in a single request and template management for reusable designs.', '@unknown', 'development', 'Unknown', 0, 'https://htmlcsstoimage.com/', NULL, 0, NULL, '2026-03-09T05:21:01.988786+00:00'),
  ('figma-import-designs', 'Figma (Import Designs)', 'html.to.design is a Figma plugin that comes with a MCP server endpoint. You can send HTML designs to Figma and they get translated into Figma layers instantly. This MCP is fast because it uses HTML as the communication medium to Figma and secure because it doesn''t read data from the Figma canvas. Your designs on Figma are always private.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://html.to.design', NULL, 0, NULL, '2026-03-09T05:21:01.988815+00:00'),
  ('ht-terminal', 'HT Terminal', 'This MCP server provides AI assistants with direct access to headless terminal sessions through a high-performance Rust implementation that integrates the HT (headless terminal) library via git submodule. Built by Memex Tech using Rust with tokio for async operations and direct HT library integration, it offers six core tools for terminal automation: session creation with optional web server preview, keystroke sending with special key support, terminal snapshots, command execution with output capture, session listing, and session management. The implementation delivers significant performance improvements over TypeScript equivalents (40x faster startup, 70% less memory usage) while providing a single 4.7MB binary deployment, cross-platform support including Windows, and optional live terminal preview through HT''s native web server, making it valuable for terminal automation workflows, headless server management, and building AI assistants that need programmatic terminal access without manual SSH or console interaction.', '@memextech', 'development', 'Unknown', 209, 'https://github.com/memextech/ht-mcp', NULL, 0, 'https://github.com/memextech.png?size=128', '2026-03-09T05:21:01.988847+00:00'),
  ('clockify', 'Clockify', 'Clockify MCP Server integrates with the Clockify time tracking API, allowing AI assistants to manage time entries through natural language prompts. Developed by https-eduardo, this TypeScript implementation provides tools for creating billable time entries, retrieving workspace information, listing projects, and accessing user data. The server handles authentication via Clockify API tokens and exposes four main tools that abstract the complexity of the Clockify API, making it particularly valuable for users who want to log their work hours without leaving their AI assistant interface. Future implementations will include deleting and editing time entries.', '@https-eduardo', 'development', 'Unknown', 16, 'https://github.com/https-eduardo/clockify-mcp-server', NULL, 0, 'https://github.com/https-eduardo.png?size=128', '2026-03-09T05:21:01.988920+00:00'),
  ('feishu-markdown', 'Feishu Markdown', 'Provides tools to convert Markdown documents into Feishu (Lark) native document format. Supports rich content including images, Mermaid flowcharts, and standard Markdown formatting. Enables AI assistants to create and format documents compatible with the Feishu enterprise collaboration platform.', '@huandu', 'ai-ml', 'Unknown', 7, 'https://github.com/huandu/feishu-markdown', NULL, 0, 'https://github.com/huandu.png?size=128', '2026-03-09T05:21:01.988975+00:00'),
  ('scanpy', 'Scanpy', 'SCMCP is an MCP server that provides natural language access to single-cell RNA sequencing analysis through the Scanpy library. Developed by Shenghui Huang, it exposes a comprehensive set of tools organized into modules for input/output operations, preprocessing, visualization, trajectory inference, and utility functions. The server supports both stdio and server-sent events (SSE) transport protocols, making it flexible for different integration scenarios. SCMCP handles AnnData objects internally, allowing users to perform complex bioinformatics workflows like clustering, dimensionality reduction, differential expression analysis, and cell type annotation through conversational interfaces, making it particularly valuable for researchers who want to analyze single-cell data without writing code.', '@huang-sh', 'development', 'Unknown', 12, 'https://github.com/huang-sh/scmcp', NULL, 0, 'https://github.com/huang-sh.png?size=128', '2026-03-09T05:21:01.989016+00:00'),
  ('halo', 'Halo', 'A Python-based MCP server that provides AI-powered content management for Halo blog systems through post, category, tag, and attachment management tools. Built with async HTTP client architecture and robust error handling, it supports both token and password authentication, automatic Markdown-to-HTML conversion, draft management, and publishing workflows. The implementation includes specialized tools for creating, updating, and managing blog posts with features like automatic slug generation, category/tag assignment, and content validation, making it useful for AI assistants that need to manage Halo-based blogs, automate content publishing workflows, or provide intelligent blog administration capabilities.', '@huangwh826', 'ai-ml', 'Unknown', 10, 'https://github.com/huangwh826/halo-mcp-server', 'halo-mcp-server', 4088, 'https://github.com/huangwh826.png?size=128', '2026-03-09T05:21:01.989064+00:00'),
  ('ip-address-lookup', 'IP Address Lookup', 'IP-MCP-Server provides a simple tool for obtaining the public IP address of the current machine through an external API service. Built with FastMCP and httpx, this lightweight server exposes a single asynchronous function that queries ipify.org and returns the IP in JSON format. The implementation runs over stdio transport, making it ideal for integration with AI assistants or applications that need to determine their external network identity without complex configuration.', '@huangxinping', 'ai-ml', 'Unknown', 0, 'https://github.com/huangxinping/ip-mcp-server', NULL, 0, 'https://github.com/huangxinping.png?size=128', '2026-03-09T05:21:01.989100+00:00'),
  ('heliospice', 'HelioSPICE', 'Spacecraft ephemeris made easy — auto-managed SPICE kernels for heliophysics.', '@huangzesen', 'development', 'Unknown', 0, 'https://github.com/huangzesen/heliospice', NULL, 0, 'https://github.com/huangzesen.png?size=128', '2026-03-09T05:21:01.989151+00:00'),
  ('huaqiu-kicad', 'Huaqiu KiCad', 'Integrates with KiCad PCB and schematic editors by exposing the KiCad IPC API as tools. Distributed as a custom KiCad build by Huaqiu Electronics (NextPCB), it enables bidirectional communication between editors and external tools for PCB design, schematic analysis, and component management. The server connects through IPC channels that initialize automatically when the KiCad editor launches.', '@huaqiu-electronics', 'development', 'Unknown', 2, 'https://github.com/huaqiu-electronics/kicad-mcp', NULL, 0, 'https://github.com/huaqiu-electronics.png?size=128', '2026-03-09T05:21:01.989211+00:00'),
  ('hubble-ai-solana', 'Hubble AI (Solana)', 'Hubble AI MCP Server provides a bridge to Solana blockchain data and visualization capabilities through natural language queries. It implements three main tools: searching Hubble for blockchain analytics, generating charts with QuickChart, and downloading chart images to local files. The server uses a modular architecture with separate services for Hubble API interactions and chart generation, making it particularly valuable for AI assistants that need to analyze and visualize Solana blockchain data, including transaction patterns, price movements, and token holder distributions.', '@hubblevision', 'ai-ml', 'Unknown', 6, 'https://github.com/hubblevision/hubble-ai-mcp', 'hubble-mcp-tool', 5491, 'https://github.com/hubblevision.png?size=128', '2026-03-09T05:21:01.989255+00:00'),
  ('hub-tools', 'Hub Tools', 'This MCP server provides HTTP-based access to the MCP Hub database for discovering and searching Model Context Protocol implementations. Built by the MCP Hub Team and hosted at aimcp.info, it offers tools for keyword-based searching of MCPs with configurable result limits and retrieving detailed information about specific MCPs using their UUID identifiers. The implementation uses HTTP transport with server-sent events, requires API key authentication obtained through user accounts, and serves as a centralized discovery mechanism for developers looking to find and integrate existing MCP servers into their applications.', '@hekmon8', 'databases', 'Unknown', 2, 'https://github.com/hekmon8/mcp-hub-tools', NULL, 0, 'https://github.com/hekmon8.png?size=128', '2026-03-09T05:21:01.989303+00:00'),
  ('pdf-tools', 'PDF Tools', 'TypeScript-based PDF manipulation server built with pdf-lib and pdf-parse libraries. Provides tools for merging multiple PDFs, splitting documents into individual pages, extracting specific pages or text content, removing unwanted pages, reordering page sequences, and retrieving document metadata. Useful for document processing workflows like extracting sections from reports, preparing redacted versions, or analyzing document content programmatically.', '@h-ucchi', 'development', 'Unknown', 1, 'https://github.com/h-ucchi/pdf-mcp-server', NULL, 0, 'https://github.com/h-ucchi.png?size=128', '2026-03-09T05:21:01.989327+00:00'),
  ('bilibili-search', 'Bilibili Search', 'Bilibili MCP Server provides a simple interface to the Bilibili API, enabling search functionality across the popular Chinese video platform. Built with FastMCP, it exposes a single tool that allows querying the Bilibili search API with optional authentication via session data cookies. The implementation is lightweight, requiring only Python 3.12 and minimal dependencies (mcp[cli] and requests), making it ideal for workflows that need to retrieve video content, user information, or other searchable data from Bilibili without leaving the conversation interface.', '@huccihuang', 'search', 'Unknown', 180, 'https://github.com/huccihuang/bilibili-mcp-server', NULL, 0, 'https://github.com/huccihuang.png?size=128', '2026-03-09T05:21:01.989378+00:00'),
  ('hugging-face', 'Hugging Face', 'This MCP server provides comprehensive access to Hugging Face''s ecosystem through multiple transport protocols (STDIO, SSE, HTTP) with both built-in tools for searching spaces, models, datasets, and papers, plus dynamic integration with Gradio-based MCP servers hosted on Hugging Face Spaces. Built by Hugging Face using TypeScript with a React-based web interface for tool management, it offers semantic search across the Hub''s content, detailed information retrieval for specific resources, space duplication capabilities, and a proxy architecture that automatically discovers and registers remote tools from configured Gradio endpoints. The implementation includes intelligent tool selection strategies with bouquet-based filtering, transport metrics tracking, and support for both stateful session-based and stateless JSON modes, making it valuable for AI assistants that need to discover ML resources, manage Hugging Face workflows, or dynamically extend capabilities by connecting to community-built tools hosted as Spaces.', '@huggingface', 'development', 'Unknown', 204, 'https://github.com/huggingface/hf-mcp-server', NULL, 0, 'https://github.com/huggingface.png?size=128', '2026-03-09T05:21:01.989438+00:00'),
  ('hugging-face-spaces', 'Hugging Face Spaces', 'MCP-HFSpace provides a bridge between Claude Desktop and Hugging Face Spaces, allowing AI assistants to interact with machine learning models hosted on Hugging Face. Built by Shaun Smith, this Node.js implementation automatically discovers and exposes Gradio endpoints as MCP tools, handling parameter conversion, file uploads, and progress notifications. It supports various output types including text, images, and audio files, with special handling for Claude Desktop compatibility. The server runs locally using stdio transport, making it ideal for workflows requiring access to specialized AI models without leaving the conversation interface.', '@xiyuefox', 'ai-ml', 'Unknown', 0, 'https://github.com/xiyuefox/mcp-hfspace', NULL, 0, 'https://github.com/xiyuefox.png?size=128', '2026-03-09T05:21:01.989484+00:00'),
  ('agent-skill-kit', 'Agent Skill Kit', 'Framework for exposing local Python automation skills as MCP tools. Includes built-in skills for repository visualization, HackerNews trends, avatar generation, and an Architect skill that generates new automation workflows from natural language. Skills are self-contained Python scripts with YAML metadata, providing clean markdown output without requiring API keys or external authentication.', '@hughknightoce', 'ai-ml', 'Unknown', 1, 'https://github.com/hughknightoce/agent-skill-kit-ask-', NULL, 0, 'https://github.com/hughknightoce.png?size=128', '2026-03-09T05:21:01.989522+00:00'),
  ('wordware', 'Wordware', 'This MCP server implementation provides a bridge to Wordware''s deployed flows, enabling integration of Wordware tools directly within Claude conversations. Developed by Hugo Biais, it offers capabilities for founder research, lead enrichment, saving to Notion, and task solving with Google search and API capabilities. Built using TypeScript and the Model Context Protocol SDK, the server focuses on secure environment variable management and easy setup within the Claude Desktop environment. It is particularly useful for AI applications that need to automate research, enrich sales data, or integrate with external tools like Notion. The implementation includes a tool for dynamically adding new Wordware flows, enhancing its extensibility for future use cases.', '@hugobiais', 'development', 'Unknown', 0, 'https://github.com/hugobiais/wordware-mcp', NULL, 0, 'https://github.com/hugobiais.png?size=128', '2026-03-09T05:21:01.989553+00:00'),
  ('clojure-repl', 'Clojure REPL', 'This Clojure-based MCP implementation, developed by Hugo Duncan, exposes Clojure REPL functionality over an SSE transport. Built with compatibility for Anthropic''s MCP specification in mind, it provides both client and server components for MCP communication. The project emphasizes simplicity and reliability, offering a straightforward setup process and integration with Claude Desktop via mcp-proxy. It''s particularly useful for developers looking to leverage Clojure''s interactive programming capabilities within an MCP ecosystem, enabling use cases such as remote code execution, interactive data analysis, and AI-assisted Clojure development without directly dealing with the complexities of SSE or MCP implementation details.', '@hugoduncan', 'development', 'Unknown', 57, 'https://github.com/hugoduncan/mcp-clj', NULL, 0, 'https://github.com/hugoduncan.png?size=128', '2026-03-09T05:21:01.989579+00:00'),
  ('audio-analysis', 'Audio Analysis', 'MCP Music Analysis provides audio analysis capabilities using librosa, enabling users to extract features like tempo, duration, spectral characteristics, and beat information from audio files. Built by hugohow, it supports analyzing local audio files, YouTube links, or direct audio URLs, and includes visualization tools for spectrograms, waveforms, and chromagrams. The implementation is designed for Claude Desktop integration and is particularly valuable for music analysis workflows where understanding audio characteristics enhances the conversation experience.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://www.pulsemcp.com/servers/hugohow-audio-analysis', NULL, 0, NULL, '2026-03-09T05:21:01.989628+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('music-analysis', 'Music Analysis', 'MCP Music Analysis integrates librosa''s audio processing capabilities with FastMCP to provide detailed audio feature extraction directly within AI conversations. Created by Hugo How-Choong, this server implementation offers 13 specialized tools for analyzing music and audio files, including tempo detection, spectral analysis, MFCC computation, and onset detection. Users can simply provide a file path to extract musical characteristics without leaving their conversation interface, making it ideal for musicians, audio engineers, and music analysts who need quick insights into audio properties.', '@hugohow', 'ai-ml', 'Unknown', 21, 'https://github.com/hugohow/mcp-music-analysis', NULL, 0, 'https://github.com/hugohow.png?size=128', '2026-03-09T05:21:01.989673+00:00'),
  ('macpilot', 'MacPilot', 'MacPilot CLI is a Swift-based MCP server that enables AI assistants to control macOS systems through native accessibility and screen capture APIs. Built using the mcp-swift-sdk, it provides tools for mouse control, screen capture, text input, shell command execution, and application management, requiring macOS 14.0+ and appropriate system permissions for accessibility and screen recording. Designed for automation workflows where AI assistants need direct interaction with the macOS desktop environment, making it valuable for tasks like UI testing, system administration, and desktop automation that would otherwise require manual intervention.', '@huhu415', 'development', 'Unknown', 16, 'https://github.com/huhu415/macpilotcli', NULL, 0, 'https://github.com/huhu415.png?size=128', '2026-03-09T05:21:01.989702+00:00'),
  ('io-github-dearlordylord-huly-mcp', 'io.github.dearlordylord/huly-mcp', 'MCP server for Huly integration', '@dearlordylord', 'development', 'Unknown', 4, 'https://github.com/dearlordylord/huly-mcp', NULL, 0, 'https://github.com/dearlordylord.png?size=128', '2026-03-09T05:21:01.989719+00:00'),
  ('human-in-the-loop-discord', 'Human-in-the-Loop (Discord)', 'This human-in-the-loop MCP server by KOBA789 enables AI assistants to request information from humans via Discord when they need data that isn''t publicly available or documented. Built in Rust using the serenity Discord library and rust-mcp-sdk, it provides a single ''ask_human'' tool that creates Discord threads for each question, mentions the specified user, and waits for their response before returning the answer to the AI assistant. The implementation is particularly valuable for scenarios where AI assistants need personal preferences, project-specific context, local environment details, or other human-only knowledge that can''t be found in documentation or public sources.', '@koba789', 'communication', 'Unknown', 220, 'https://github.com/koba789/human-in-the-loop', NULL, 0, 'https://github.com/koba789.png?size=128', '2026-03-09T05:21:01.989757+00:00'),
  ('textarttools', 'TextArtTools', 'Transforms text using Unicode styles and creates ASCII art banners. Provides 23 Unicode text styles including bold, italic, cursive, and fraktur, plus 322+ ASCII art fonts for stylized text banners. Deployed on Cloudflare Workers for global edge performance.', '@humanjesse', 'cloud', 'Unknown', 3, 'https://github.com/humanjesse/textarttools-mcp', NULL, 0, 'https://github.com/humanjesse.png?size=128', '2026-03-09T05:21:01.989772+00:00'),
  ('bocha-web-search', 'Bocha Web Search', 'MCP-Bocha is a server that connects AI assistants to Bocha AI''s web search capabilities, enabling them to retrieve up-to-date information from the internet. Developed by HumanSean under the MIT license, it provides a single tool for performing web searches with customizable parameters including freshness filters, domain inclusion/exclusion, and result summarization. The implementation is built with TypeScript using the FastMCP framework and communicates via stdio transport, making it particularly valuable for AI agents that need to access current web information for research, fact-checking, or answering time-sensitive queries.', '@intounknown', 'development', 'Unknown', 3, 'https://github.com/intounknown/mcp-bocha', '@humansean/mcp-bocha', 4662, 'https://github.com/intounknown.png?size=128', '2026-03-09T05:21:01.989801+00:00'),
  ('hummingbot', 'Hummingbot', 'Enables AI assistants to interact with Hummingbot for automated cryptocurrency trading across multiple exchanges. Provides tools for managing trading bots, executing orders, monitoring balances and positions, accessing real-time market data including prices and order books, and analyzing portfolio performance. Supports configuration of multiple Hummingbot API instances for multi-deployment environments.', '@hummingbot', 'ai-ml', 'Unknown', 49, 'https://github.com/hummingbot/mcp', NULL, 0, 'https://github.com/hummingbot.png?size=128', '2026-03-09T05:21:01.989866+00:00'),
  ('dingding-dingtalk', 'DingDing (DingTalk)', 'The mcp-dingdingbot-server provides a bridge between AI assistants and DingDing (DingTalk) messaging platform, enabling automated notifications through DingDing''s bot API. Built in Go using the mcp-go library, it supports multiple message formats including text, markdown, images, news links, and template cards. The implementation includes signature verification for enhanced security, file upload capabilities, and comprehensive testing with both unit and integration tests. This server is particularly useful for workflows requiring automated alerts, team notifications, or integration of AI-generated content into DingDing group chats.', '@hundunonline', 'development', 'Unknown', 21, 'https://github.com/hundunonline/mcp-dingdingbot-server', NULL, 0, 'https://github.com/hundunonline.png?size=128', '2026-03-09T05:21:01.989909+00:00'),
  ('tasks-organizer', 'Tasks Organizer', 'This MCP server converts Cursor agent plans into markdown task lists. Developed by Claude, it integrates with the MCP framework and uses Python with the markdown library. The server is designed for organizing and structuring AI-generated project plans, making them more readable and actionable for users working with Cursor or similar AI planning tools.', '@rohanpatriot', 'productivity', 'Unknown', 12, 'https://github.com/rohanpatriot/mcp-tasks-organizer', NULL, 0, 'https://github.com/rohanpatriot.png?size=128', '2026-03-09T05:21:01.989971+00:00'),
  ('huoshui-fetch', 'Huoshui Fetch', 'Provides comprehensive tools for web content processing including URL fetching with authentication support, HTML-to-markdown conversion, content sanitization, and intelligent data extraction for articles, metadata, images, and structured data.', '@huoshuiai42', 'ai-ml', 'Unknown', 0, 'https://github.com/huoshuiai42/huoshui-fetch', NULL, 0, 'https://github.com/huoshuiai42.png?size=128', '2026-03-09T05:21:01.989998+00:00'),
  ('huoshui-pdf-translator', 'Huoshui PDF Translator', 'Intelligent PDF translation server specializing in academic papers with mathematical formulas. Provides context-aware translation between Chinese and English while preserving document layout and mathematical notation. Built on the FastMCP framework with support for flexible file path handling and translation status monitoring.', '@huoshuiai42', 'file-systems', 'Unknown', 0, 'https://github.com/huoshuiai42/huoshui-pdf-translator', NULL, 0, 'https://github.com/huoshuiai42.png?size=128', '2026-03-09T05:21:01.990040+00:00'),
  ('huoshui-pdf-converter', 'Huoshui PDF Converter', 'Provides high-quality conversion between PDF and Markdown formats with full Unicode/CJK character support. Features automatic font detection for different languages, image extraction from PDFs, and customizable PDF output options. Uses multiple conversion engines (PyMuPDF, ReportLab, xhtml2pdf, fpdf2) intelligently selected based on content characteristics.', '@huoshuiai42', 'development', 'Unknown', 0, 'https://github.com/huoshuiai42/huoshui-pdf-converter', NULL, 0, 'https://github.com/huoshuiai42.png?size=128', '2026-03-09T05:21:01.990063+00:00'),
  ('huoshui-file-converter', 'Huoshui File Converter', 'Provides secure document format conversion within a specified working directory. Supports converting between Markdown, DOCX, HTML, PDF, and TXT formats with built-in path validation to prevent directory traversal attacks. Includes intelligent file format detection and optimized performance for large directories with configurable file limits.', '@huoshuiai42', 'ai-ml', 'Unknown', 0, 'https://github.com/huoshuiai42/huoshui-file-converter', NULL, 0, 'https://github.com/huoshuiai42.png?size=128', '2026-03-09T05:21:01.990094+00:00'),
  ('huoshui-file-search', 'Huoshui File Search', 'Provides fast file search capabilities for macOS by leveraging the native Spotlight index through the mdfind command. Supports path-based search restrictions, case-sensitive and case-insensitive filtering, regular expression matching for results, and configurable sorting by name, size, or date. Returns clean JSON-structured responses with configurable result limits.', '@huoshuiai42', 'ai-ml', 'Unknown', 0, 'https://github.com/huoshuiai42/huoshui-file-search', NULL, 0, 'https://github.com/huoshuiai42.png?size=128', '2026-03-09T05:21:01.990128+00:00'),
  ('hasura-graphql', 'Hasura GraphQL', 'This advanced Hasura GraphQL MCP server enables AI agents to interact with Hasura GraphQL endpoints through a rich set of tools. It provides capabilities for schema introspection, executing read-only queries and mutations, listing tables and their structures, previewing data samples, performing aggregations, and checking service health. The implementation handles authentication via admin secrets, performs basic security checks on operations, and exposes the complete GraphQL schema as a resource, making it ideal for AI assistants that need to dynamically discover and leverage database structures based on natural language requests.', '@husamabusafa', 'databases', 'Unknown', 20, 'https://github.com/husamabusafa/hasura_mcp', NULL, 0, 'https://github.com/husamabusafa.png?size=128', '2026-03-09T05:21:01.990194+00:00'),
  ('image-placeholder', 'Image Placeholder', 'This MCP Image Placeholder Server, developed by Husni Adil Makmur, provides a simple way to generate placeholder images for testing and development purposes. Built with Python and leveraging the FastMCP framework, it offers a single tool for creating image URLs from two popular providers: placehold.co and Lorem Picsum. The implementation focuses on ease of use, allowing customization of image dimensions within specified limits. By providing a standardized interface for placeholder image generation, this server enables quick integration into development workflows, prototyping, and UI testing scenarios. It''s particularly useful for developers and designers who need consistent, on-demand placeholder images in their projects.', '@husniadil', 'development', 'Unknown', 11, 'https://github.com/husniadil/mcp-image-placeholder', NULL, 0, 'https://github.com/husniadil.png?size=128', '2026-03-09T05:21:01.990261+00:00'),
  ('mermaid', 'Mermaid', 'This MCP server provides AI assistants with Mermaid diagram generation capabilities, built by hustcc and BQXBQX using TypeScript with the Model Context Protocol SDK and mermaid-isomorphic for server-side rendering. The implementation offers a single tool for creating diagrams by accepting Mermaid syntax along with customization options for themes (default, base, forest, dark, neutral), background colors, and output formats (PNG images, SVG strings, or raw Mermaid syntax), featuring input validation through Zod schemas and multiple transport protocols including stdio, SSE, and HTTP streamable. Built with Docker containerization, comprehensive testing infrastructure, and flexible deployment options, it serves developers creating visual documentation from conversational queries, technical writers generating flowcharts and system diagrams, and business users building process documentation without direct Mermaid API interaction.', '@hustcc', 'cloud', 'Unknown', 463, 'https://github.com/hustcc/mcp-mermaid', NULL, 0, 'https://github.com/hustcc.png?size=128', '2026-03-09T05:21:01.990317+00:00'),
  ('chinese-stock-market-data-akshare-tushare', 'Chinese Stock Market Data (AkShare & Tushare)', 'This server provides access to Chinese stock market data through integration with multiple financial data providers including AkShare and Tushare, plus Tavily for news aggregation. Built with FastAPI and featuring real-time data streaming via Server-Sent Events, it offers market data retrieval, fundamental analysis, and news monitoring capabilities. The implementation uses Redis for caching, supports both REST API and MCP protocol access, and is containerized with Docker. It includes a web dashboard for visualization and management, making it valuable for financial analysis workflows, investment research, and building applications that need access to Chinese stock market data and real-time financial information.', '@huweihua123', 'databases', 'Unknown', 100, 'https://github.com/huweihua123/stock-mcp', NULL, 0, 'https://github.com/huweihua123.png?size=128', '2026-03-09T05:21:01.990335+00:00'),
  ('autocad-lt-autolisp', 'AutoCAD LT AutoLISP', 'AutoCAD LT AutoLISP MCP Server enables natural language control of AutoCAD LT 2024/2025 through AutoLISP code generation and execution. It bridges Claude or other LLM clients with AutoCAD LT by providing tools for creating engineering drawings, including process equipment symbols (pumps, vessels, heat exchangers), piping connections, and complete process diagrams. The server uses keyboard simulation to send commands to AutoCAD, making it particularly valuable for engineers who need to create technical drawings through conversational prompts without manual CAD operations.', '@puran-water', 'development', 'Unknown', 166, 'https://github.com/puran-water/autocad-mcp', NULL, 0, 'https://github.com/puran-water.png?size=128', '2026-03-09T05:21:01.990362+00:00'),
  ('mathcad-prime', 'MathCAD Prime', 'A specialized MCP server that provides deep integration with PTC MathCAD Prime, enabling AI assistants to interact with MathCAD worksheets through a comprehensive set of tools for worksheet management, input/output manipulation, and calculation control. Built using the MathcadPy library and FastMCP framework, this implementation supports Windows-based MathCAD automation, offering capabilities like opening/closing worksheets, setting inputs, retrieving outputs, and performing unit conversions, making it particularly valuable for engineering, scientific, and computational workflows.', '@puran-water', 'ai-ml', 'Unknown', 7, 'https://github.com/puran-water/mathcad-mcp', NULL, 0, 'https://github.com/puran-water.png?size=128', '2026-03-09T05:21:01.990404+00:00'),
  ('onenote-browser', 'OneNote Browser', 'OneNote MCP server enables AI assistants to browse and interact with shared OneNote notebooks through browser automation. Built with Playwright and Node.js, it provides tools for navigating notebook hierarchies, reading/writing pages, capturing diagrams and images, and maintaining session state. The implementation focuses on working with publicly shared notebooks that don''t require authentication, making it ideal for collaborative note-taking and knowledge management scenarios where AI assistants need direct access to OneNote content.', '@hwillgit', 'ai-ml', 'Unknown', 4, 'https://github.com/hwillgit/onenote-mcp', NULL, 0, 'https://github.com/hwillgit.png?size=128', '2026-03-09T05:21:01.990445+00:00'),
  ('research-notion', 'Research Notion', 'This MCP server, developed by Hikari YANAGAWA, integrates with Notion to enable survey data retrieval and creation of survey pages. Built with Python and leveraging libraries like Anthropic, OpenAI, and Pydantic, it provides a standardized interface for AI-powered survey operations. The implementation focuses on bridging AI language models with Notion''s database capabilities, allowing for automated survey management and analysis. By connecting to a specified Notion database, this server enables use cases such as generating survey questions, storing responses, and analyzing results, making it particularly useful for research projects that require dynamic survey creation and data collection.', '@h-yanagawa', 'databases', 'Unknown', 1, 'https://github.com/h-yanagawa/research-mcp-server', NULL, 0, 'https://github.com/h-yanagawa.png?size=128', '2026-03-09T05:21:01.990456+00:00'),
  ('hydrolix', 'Hydrolix', 'Provides direct access to Hydrolix time-series databases through ClickHouse SQL queries, enabling AI assistants to explore and analyze large-scale time-series data stored in Hydrolix clusters. Built by Hydrolix, the server offers three core tools: listing databases and tables with schema information including comments and primary keys, and executing SELECT queries with built-in safety guards like read-only mode, query timeouts, and result limits. The implementation includes performance optimizations specifically for time-series workloads, encouraging queries with timestamp-based filters and LIMIT clauses to ensure efficient execution, making it valuable for log analysis, metrics exploration, IoT data investigation, and other time-series analytics use cases where users need to query large datasets without writing complex database connection code.', '@hydrolix', 'databases', 'Unknown', 8, 'https://github.com/hydrolix/mcp-hydrolix', 'mcp-hydrolix', 5996, 'https://github.com/hydrolix.png?size=128', '2026-03-09T05:21:01.990467+00:00'),
  ('xingchen-workflow-orchestration', 'Xingchen Workflow Orchestration', 'Xingchen-MCP-Server provides a bridge between AI assistants and iFlytek''s workflow orchestration system, enabling access to complex workflow capabilities through simple MCP tools. Developed by hygao1024, this implementation connects to iFlytek workflows defined in a configuration file, allowing assistants to trigger sophisticated process flows that support sequential, parallel, loop, and nested execution modes. The server handles authentication with API keys and transforms user inputs into appropriate workflow calls, making it valuable for users who need to leverage iFlytek''s Model of Models (MoM) hybrid architecture and 14 different node types for complex business automation tasks without leaving their AI assistant interface.', '@hygao1024', 'productivity', 'Unknown', 3, 'https://github.com/hygao1024/xingchen-mcp-server', NULL, 0, 'https://github.com/hygao1024.png?size=128', '2026-03-09T05:21:01.990527+00:00'),
  ('folo-rss-reader', 'Folo RSS Reader', 'Folo-MCP is a server implementation that provides AI assistants with access to the Folo RSS reader platform through a set of specialized tools. Developed by Stephen Zhou, it enables querying and managing feed subscriptions, retrieving entries with various filtering options, checking unread counts, accessing feed information, and marking entries as read. The server authenticates with Folo''s API using a session token and transforms requests into appropriate API calls, returning structured responses optimized for AI consumption. Ideal for users who want to integrate their RSS reading workflow with AI assistants for content discovery, organization, and management.', '@hyoban', 'ai-ml', 'Unknown', 15, 'https://github.com/hyoban/folo-mcp', 'folo-mcp', 4350, 'https://github.com/hyoban.png?size=128', '2026-03-09T05:21:01.990574+00:00'),
  ('hypabase', 'Hypabase', 'Hypabase is a Python hypergraph library that stores and queries relationships involving multiple entities simultaneously. Unlike traditional graphs where edges connect exactly two nodes, Hypabase supports hyperedges connecting any number of nodes in a single relationship. It provides tools for node and edge management, traversal, path finding, and provenance-based filtering with source and confidence metadata. All data is persisted locally in SQLite with namespace isolation for scoped databases.', '@hypabase', 'databases', 'Unknown', 11, 'https://github.com/hypabase/hypabase', NULL, 0, 'https://github.com/hypabase.png?size=128', '2026-03-09T05:21:01.990584+00:00'),
  ('droidmind', 'DroidMind', 'DroidMind enables AI assistants to control and interact with Android devices through a secure, standardized interface. Built with Python and the Model Context Protocol, it provides tools for device management, app installation, UI automation, file operations, and system diagnostics. The implementation features a robust security layer that prevents dangerous operations, supports both stdio and SSE transport modes, and includes comprehensive test coverage. DroidMind is particularly valuable for developers, testers, and power users who need to debug, analyze, or control Android devices directly through conversational AI without switching to dedicated ADB tools.', '@hyperb1iss', 'development', 'Unknown', 356, 'https://github.com/hyperb1iss/droidmind', NULL, 0, 'https://github.com/hyperb1iss.png?size=128', '2026-03-09T05:21:01.990612+00:00'),
  ('hyperbolic-gpu', 'Hyperbolic GPU', 'This MCP server provides GPU cloud management and SSH connectivity for Hyperbolic''s decentralized GPU network, enabling AI assistants to discover available GPU instances, rent compute resources, and execute remote commands on rented hardware. Built by Hyperbolic Labs using TypeScript with the MCP SDK, node-ssh, and direct API integration, it features real-time GPU marketplace querying with detailed hardware specifications (VRAM, CPU cores, RAM, storage), automated instance provisioning with startup delays, SSH connection management with private key authentication, and remote command execution capabilities. The implementation includes comprehensive instance lifecycle management from rental to termination, connection status monitoring, and structured JSON responses for all operations, making it valuable for AI researchers needing on-demand GPU access, developers requiring scalable compute for machine learning workloads, and automated workflows that need to provision, configure, and manage cloud GPU resources programmatically.', '@hyperboliclabs', 'development', 'Unknown', 19, 'https://github.com/hyperboliclabs/hyperbolic-mcp', NULL, 0, 'https://github.com/hyperboliclabs.png?size=128', '2026-03-09T05:21:01.990653+00:00'),
  ('hyperbrowser', 'Hyperbrowser', 'Hyperbrowser MCP Server provides web browsing capabilities for AI assistants through the Model Context Protocol, enabling scraping, structured data extraction, and web crawling. Built by hyperbrowserai, it offers tools to extract content in various formats (markdown, HTML, links, screenshots), follow links with customizable crawling parameters, and execute browser-based tasks. The server requires an API key for authentication and can be run in standard mode or with Server-Sent Events (SSE) for real-time communication, making it ideal for AI workflows requiring web content analysis, data collection, or automated browsing.', '@hyperbrowserai', 'productivity', 'Unknown', 742, 'https://github.com/hyperbrowserai/mcp', 'hyperbrowser-mcp', 53041, 'https://github.com/hyperbrowserai.png?size=128', '2026-03-09T05:21:01.990695+00:00'),
  ('node-js-debugger', 'Node.js Debugger', 'MCP NodeJS Debugger connects Claude Code to Node.js''s built-in Inspector Protocol, enabling real-time debugging capabilities directly within AI conversations. Developed by Hyperdrive, this tool allows users to set breakpoints, inspect variables, evaluate expressions, and step through code execution while a Node.js application is running in debug mode. The implementation includes continuous connection retry logic and comprehensive runtime state analysis features, making it particularly valuable for troubleshooting issues, understanding application behavior, and testing potential fixes without leaving the Claude interface.', '@workbackai', 'development', 'Unknown', 303, 'https://github.com/workbackai/mcp-nodejs-debugger', '@hyperdrive-eng/mcp-nodejs-debugger', 8409, 'https://github.com/workbackai.png?size=128', '2026-03-09T05:21:01.990722+00:00'),
  ('hypernym-semantic-analysis', 'Hypernym Semantic Analysis', 'This MCP server, developed by Hypernym AI, provides semantic text analysis and compression tools. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers two main functions: full semantic analysis of text including categorization and compression metrics, and direct text compression that maintains semantic meaning. The implementation focuses on preserving core meaning while maintaining readability, with configurable compression ratios and semantic similarity targets. It''s particularly useful for applications requiring advanced text processing, enabling use cases such as content summarization, semantic search optimization, and efficient text storage without compromising on meaning.', '@bmorphism', 'development', 'Unknown', 6, 'https://github.com/bmorphism/hypernym-mcp-server', NULL, 0, 'https://github.com/bmorphism.png?size=128', '2026-03-09T05:21:01.990752+00:00'),
  ('qasphere', 'QASphere', 'QA Sphere is a modern test management system designed to streamline the testing process in software development. It provides comprehensive tools for organizing, tracking, and analyzing test cases, making it easier for teams to maintain high-quality testing practices. The system offers intuitive test case organization, real-time collaboration features, and detailed reporting capabilities.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('pentestthinking', 'PentestThinking', 'PentestThinkingMCP is an advanced reasoning engine for penetration testing that implements both Beam Search and Monte Carlo Tree Search (MCTS) algorithms to systematically analyze and plan multi-stage attack paths. Built by ibrahimsaleem as the foundational implementation for the LIMA research paper on leveraging LLMs for initial machine access, it transforms standard language models into structured pentest advisors by scoring attack steps, recommending appropriate tools (nmap, metasploit, linpeas), and maintaining tree-based attack progression with statistical analysis. The system excels at automated vulnerability chaining, exploit pathfinding optimization, and red team strategy development, making it particularly useful for CTF challenges, Hack The Box machines, and real-world penetration testing scenarios where methodical attack planning and decision tree exploration are critical.', '@ibrahimsaleem', 'development', 'Unknown', 28, 'https://github.com/ibrahimsaleem/pentestthinkingmcp', NULL, 0, 'https://github.com/ibrahimsaleem.png?size=128', '2026-03-09T05:21:01.991405+00:00'),
  ('opensearch', 'OpenSearch', 'This MCP server implementation provides a bridge to OpenSearch, enabling AI assistants to perform powerful search and analytics operations. Developed by ibrooksSDX, it integrates with OpenSearch to offer functionalities like full-text search, data aggregation, and real-time analytics. The server is designed to work with various MCP-compatible clients, offering a straightforward setup process using Docker for easy deployment. It''s particularly useful for applications requiring advanced search capabilities, log analytics, or real-time data exploration. The implementation focuses on efficient query handling and secure authentication, making it suitable for both development and production environments where robust search and analytics are needed.', '@ibrookssdx', 'cloud', 'Unknown', 4, 'https://github.com/ibrookssdx/mcp-server-opensearch', NULL, 0, 'https://github.com/ibrookssdx.png?size=128', '2026-03-09T05:21:01.991429+00:00'),
  ('io-github-stayce-icd-mcp', 'io.github.stayce/icd-mcp', 'WHO ICD-10/ICD-11 diagnosis codes. Lookup, search, chapters via official WHO API.', '@stayce', 'development', 'Unknown', 1, 'https://github.com/stayce/icd-mcp-cloudflare', NULL, 0, 'https://github.com/stayce.png?size=128', '2026-03-09T05:21:01.991446+00:00'),
  ('files-stdio', 'Files Stdio', 'Provides sandboxed file system access with advanced pattern matching and content manipulation capabilities. Features checksum-based file integrity verification, multi-mount directory support, and specialized tools for Obsidian/Markdown workflows including wikilink, tag, and task pattern recognition. Supports line-based and pattern-based file editing with dry-run previews, comprehensive search across directories with regex and fuzzy matching modes, and built-in safety mechanisms to prevent directory traversal attacks.', '@iceener', 'communication', 'Unknown', 23, 'https://github.com/iceener/files-stdio-mcp-server', NULL, 0, 'https://github.com/iceener.png?size=128', '2026-03-09T05:21:01.991478+00:00'),
  ('tesla-tessie', 'Tesla (Tessie)', 'Provides secure Tesla vehicle control and monitoring through the Tessie API, offering two primary tools: tesla_state for retrieving comprehensive vehicle information (battery level, location, climate, charging status) and tesla_command for executing vehicle operations (lock/unlock, climate control, charging management). Built with a dual-runtime architecture supporting both Node.js and Cloudflare Workers deployment, featuring bearer token authentication, rate limiting, and encrypted token storage.', '@iceener', 'cloud', 'Unknown', 10, 'https://github.com/iceener/tesla-streamable-mcp-server', NULL, 0, 'https://github.com/iceener.png?size=128', '2026-03-09T05:21:01.991573+00:00'),
  ('io-github-stayce-icf-mcp', 'io.github.stayce/icf-mcp', 'WHO ICF classification codes for health and disability. Lookup, search, browse via WHO API.', '@stayce', 'development', 'Unknown', 1, 'https://github.com/stayce/icf-mcp-cloudflare', NULL, 0, 'https://github.com/stayce.png?size=128', '2026-03-09T05:21:01.991590+00:00'),
  ('stable-diffusion-webui', 'Stable Diffusion WebUI', 'A server that provides text-to-image generation capabilities by integrating with Stable Diffusion WebUI (ForgeUI/AUTOMATIC-1111). It exposes a single tool for generating images with extensive parameter control including prompts, negative prompts, sampling steps, dimensions, and more. The implementation handles authentication, manages output directories, and embeds generation parameters as image metadata. Built for users who want to generate AI art through natural language requests while maintaining fine-grained control over the generation process.', '@ichigo3766', 'ai-ml', 'Unknown', 30, 'https://github.com/ichigo3766/image-gen-mcp', 'image-gen', 0, 'https://github.com/ichigo3766.png?size=128', '2026-03-09T05:21:01.991632+00:00'),
  ('iconfont', 'Iconfont', 'This iconfont-mcp server provides AI assistants with access to Iconfont.cn''s icon search functionality through a TypeScript implementation that queries the Chinese icon platform''s API. Built by zys8119, it enables searching for icons by name and type, returning icon data from one of China''s largest icon libraries. The implementation includes hardcoded authentication cookies for API access and supports filtered searches by icon type, making it useful for design workflows, UI development, and applications requiring access to Chinese iconography and design assets.', '@zys8119', 'development', 'Unknown', 2, 'https://github.com/zys8119/iconfont-mcp', 'iconfont-mcp', 360, 'https://github.com/zys8119.png?size=128', '2026-03-09T05:21:01.991656+00:00'),
  ('icons8', 'Icons8', 'Icons8 MCP Server gives AI coding environments instant access to 368,865+ Icons8 icons across 116 design styles. Connect your Claude, Cursor, Windsurf, VS Code, or any SSE-capable MCP host to stream high-res PNGs for free or unlock full SVG delivery with an API key—ideal for prototyping, production code, and rapid UI experiments.', '@icons8', 'development', 'Unknown', 2, 'https://github.com/icons8/icons8-mcp', NULL, 0, 'https://github.com/icons8.png?size=128', '2026-03-09T05:21:01.991681+00:00'),
  ('youtube-data', 'YouTube Data', 'YouTube MCP Server provides a robust interface to the YouTube Data API, enabling AI assistants to retrieve and analyze video content, transcripts, channel statistics, and engagement metrics. Built with TypeScript and Node.js, it offers tools for searching videos, accessing captions with multi-language support, analyzing channel growth, and discovering trending content across different regions and categories. The implementation handles pagination for large result sets, provides detailed error handling, and includes environment variable configuration for API keys, making it particularly valuable for content research, video analysis, and trend identification workflows without leaving the conversation interface.', '@icraft2170', 'development', 'Unknown', 58, 'https://github.com/icraft2170/youtube-data-mcp-server', 'youtube-data-mcp-server', 49589, 'https://github.com/icraft2170.png?size=128', '2026-03-09T05:21:01.991718+00:00'),
  ('ida-pro', 'IDA Pro', 'IDA Pro MCP server enables AI assistants to interact with IDA Pro for reverse engineering and binary analysis tasks. Created by Florian Drechsler, it provides a secure bridge between AI and IDA Pro through a remote control plugin that exposes key functionality like script execution, string/function analysis, and disassembly via HTTP endpoints. The implementation features robust error handling, automatic dialog suppression, and timeouts to ensure stable operation when automating IDA Pro tasks, making it valuable for security researchers and reverse engineers who want to leverage AI assistance while analyzing binaries.', '@fdrechsler', 'productivity', 'Unknown', 92, 'https://github.com/fdrechsler/mcp-server-idapro', NULL, 0, 'https://github.com/fdrechsler.png?size=128', '2026-03-09T05:21:01.991779+00:00'),
  ('idealift', 'IdeaLift', 'IdeaLift is a decision intelligence platform by Startvest that helps product teams track ideas, decisions, and customer signals. The MCP server enables AI assistants to interact with IdeaLift''s idea management system through natural language queries, supporting operations like creating and searching ideas, tracking decision rationale, managing customer signals, and surfacing trending patterns across communication channels. The server exposes 12 tools and 4 resource types for comprehensive idea lifecycle management.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://idealift.startvest.ai', NULL, 0, NULL, '2026-03-09T05:21:01.991815+00:00'),
  ('dino-x', 'DINO-X', 'This DINO-X MCP server by IDEA Research provides AI agents with real-world visual perception capabilities through the DINO-X computer vision API, enabling object detection, localization, human pose estimation, and image captioning. The implementation offers three core detection modes: text-prompted object detection for finding specific items, universal object detection for comprehensive scene analysis, and human pose keypoint detection with 17-point skeletal tracking, all with optional detailed descriptions and visualization capabilities that save annotated images with bounding boxes and labels. Built with TypeScript and the canvas library for image processing, it integrates with DeepDataSpace''s hosted DINO-X API and includes robust error handling, task polling for asynchronous processing, and flexible output formatting, making it valuable for AI applications requiring visual understanding, accessibility tools, security monitoring, sports analysis, and automated content moderation workflows.', '@idea-research', 'development', 'Unknown', 112, 'https://github.com/idea-research/dino-x-mcp', '@deepdataspace/dinox-mcp', 1390, 'https://github.com/idea-research.png?size=128', '2026-03-09T05:21:01.991874+00:00'),
  ('emojikey-via-supabase', 'Emojikey (via Supabase)', 'This MCP server, developed by Identimoji, provides a mechanism for persisting LLM interaction styles using emojikeys. It integrates with Supabase for data storage and retrieval, allowing AI assistants to save and recall specific interaction patterns or personas. The server exposes a standardized interface for managing emojikey-based styles, abstracting the complexities of database operations. By enabling the persistence of interaction styles, this implementation facilitates consistent user experiences across multiple conversations or sessions. It is particularly useful for applications requiring personalized AI interactions, such as customer support chatbots, virtual assistants, or any AI system that needs to maintain distinct communication styles for different contexts or users.', '@identimoji', 'databases', 'Unknown', 4, 'https://github.com/identimoji/mcp-server-emojikey', '@identimoji/mcp-server-emojikey', 3999, 'https://github.com/identimoji.png?size=128', '2026-03-09T05:21:01.991890+00:00'),
  ('standards-finder', 'Standards Finder', 'Standards Finder provides comprehensive access to IETF RFCs, Internet Drafts, and OpenID Foundation specifications through a zero-dependency Python MCP server that uses only standard library components. Built by identitymonk as an extension of mjpitz/mcp-rfc, it offers 9 tools for fetching documents, searching by keyword, extracting specific sections, and retrieving complete working group document collections with automatic version detection and smart filtering of expired drafts. The implementation supports both stdio and HTTP transport modes, includes intelligent caching and progress notifications, and features enhanced parsing capabilities for multiple document formats, making it valuable for developers researching web standards, security protocols, authentication specifications, or building applications that need access to authoritative technical documentation from standards bodies.', '@identitymonk', 'development', 'Unknown', 7, 'https://github.com/identitymonk/mcp-standard-finder', NULL, 0, 'https://github.com/identitymonk.png?size=128', '2026-03-09T05:21:01.991928+00:00'),
  ('influxdb', 'InfluxDB', 'InfluxDB MCP Server provides a bridge between AI assistants and InfluxDB time-series databases, enabling operations like querying measurements, writing data, and managing buckets and organizations. Developed by Sam Coward, this implementation exposes InfluxDB''s functionality through four resources and four tools, with additional prompts for Flux query examples and Line Protocol formatting guidance. The server authenticates via environment variables and includes comprehensive error handling and logging for reliability. It''s particularly valuable for developers and data analysts who need to interact with time-series data through AI assistants for monitoring, visualization, and data management tasks.', '@idoru', 'databases', 'Unknown', 31, 'https://github.com/idoru/influxdb-mcp-server', 'influxdb-mcp-server', 3054, 'https://github.com/idoru.png?size=128', '2026-03-09T05:21:01.991969+00:00'),
  ('arcade-games-archive-org', 'Arcade Games (Archive.org)', 'An MCP server that enables browsing and playing classic arcade games from archive.org. Implements strict rights verification through a curated allowlist of 18 verified titles including DOOM, Wolfenstein 3D, Commander Keen, Duke Nukem, and others with documented distribution rights (shareware, freeware, public domain). Fetches game HTML from archive.org and processes it to work within sandboxed iframes, serving playable games through a dynamic MCP Apps resource.', '@idosal', 'ai-ml', 'Unknown', 2, 'https://github.com/idosal/mcp-apps-arcade', NULL, 0, 'https://github.com/idosal.png?size=128', '2026-03-09T05:21:01.992010+00:00'),
  ('gitmcp-github-to-mcp', 'GitMCP (GitHub to MCP)', 'Transforms any GitHub project (repositories or GitHub pages) into a documentation hub. It allows AI tools like Cursor to access up-to-date documentation and code, ending hallucinations seamlessly.', '@idosal', 'development', 'Unknown', 7720, 'https://github.com/idosal/git-mcp', NULL, 0, 'https://github.com/idosal.png?size=128', '2026-03-09T05:21:01.992030+00:00'),
  ('uk-parliament', 'UK Parliament', 'This MCP server provides access to UK Parliamentary data through the Parliament API and semantic search capabilities over Hansard debates and Parliamentary Questions. Built by i.AI using Python with FastAPI and Elasticsearch, it offers 11 specialized tools including constituency and member searches, election results, government/opposition post listings, and semantic search through parliamentary debates and written questions using Azure OpenAI embeddings. The implementation features automated daily data ingestion via AWS Lambda, comprehensive member information with voting records and interests, flexible date-based searches with natural language parsing, and full AWS deployment with Terraform infrastructure, making it valuable for political research, parliamentary monitoring, policy analysis workflows, and building AI assistants that need programmatic access to UK Parliament data without manual website navigation.', '@i-dot-ai', 'cloud', 'Unknown', 21, 'https://github.com/i-dot-ai/parliament-mcp', NULL, 0, 'https://github.com/i-dot-ai.png?size=128', '2026-03-09T05:21:01.992052+00:00'),
  ('wechat-summarizer', 'WeChat Summarizer', 'This MCP server, developed by idoubi, enables AI assistants to query and summarize chat messages stored in a local database. Built in TypeScript, it integrates with Claude Desktop and provides a standardized interface for retrieving conversation history. The implementation stands out by offering flexible querying options and the ability to generate summaries based on custom prompts. By bridging AI models with chat logs, this server allows AI systems to analyze conversation patterns, extract insights, and provide context-aware responses. It is particularly useful for personal knowledge management, conversation analysis, and building more contextually-aware AI assistants that can reference and learn from past interactions.', '@chatmcp', 'databases', 'Unknown', 1035, 'https://github.com/chatmcp/mcp-server-chatsum', NULL, 0, 'https://github.com/chatmcp.png?size=128', '2026-03-09T05:21:01.992063+00:00'),
  ('party-time', 'Party Time', 'The Party Time MCP server is a simple implementation that responds with ''It''s Party Time'' when queried about the current time. It registers a single tool called ''get-time'' and communicates via stdin/stdout, making it easy to integrate with Claude Desktop. The server demonstrates basic MCP protocol compliance, including initialization, tool discovery, and execution, while providing a fun, lighthearted example for developers to build upon.', '@idyll', 'development', 'Unknown', 1, 'https://github.com/idyll/party-time-mcp', NULL, 0, 'https://github.com/idyll.png?size=128', '2026-03-09T05:21:01.992085+00:00'),
  ('iflytek-workflow', 'iFlytek Workflow', 'A server implementation that enables AI assistants to interact with iFlytek''s workflow orchestration platform. Built on a Model of Models hybrid architecture, it supports 14 types of workflow nodes for tasks like sequential execution, parallel processing, and iterative loops. The implementation provides streaming output via hooks and allows complex variable I/O between nodes, making it well-suited for automating multi-step business processes through natural language interaction.', '@iflytek', 'productivity', 'Unknown', 27, 'https://github.com/iflytek/ifly-workflow-mcp-server', NULL, 0, 'https://github.com/iflytek.png?size=128', '2026-03-09T05:21:01.992125+00:00'),
  ('image-extractor', 'Image Extractor', 'MCP Image Extractor is a server that enables AI models to process and analyze images by extracting them from URLs or base64-encoded data. It provides three main tools: extract_image_from_url for retrieving images from web sources, extract_image_from_base64 for processing already encoded images, and save_screenshot for storing images to disk. Built with TypeScript and using the Sharp library for image processing, it includes features like image resizing, format conversion, and domain filtering for security. The implementation can be deployed locally or via Docker, making it ideal for workflows where visual content analysis is needed within AI conversations.', '@ifmelate', 'cloud', 'Unknown', 20, 'https://github.com/ifmelate/mcp-image-extractor', NULL, 0, 'https://github.com/ifmelate.png?size=128', '2026-03-09T05:21:01.992146+00:00'),
  ('vim', 'Vim', 'Enables interaction with Vim and Neovim editor instances through natural language. Query buffer and window state, execute Vim commands, perform semantic searches of help documentation, and generate macros from descriptions. Works with both Vim 8+ (with channel support) and Neovim 0.5+, communicating through Unix domain sockets to manage multiple editor sessions.', '@iggredible', 'ai-ml', 'Unknown', 3, 'https://github.com/iggredible/vim-mcp', NULL, 0, 'https://github.com/iggredible.png?size=128', '2026-03-09T05:21:01.992214+00:00'),
  ('g-oportail', 'Géoportail', 'An experimental MCP server providing spatial context through integration with French geographic data services from the Géoportail (GPF). Built by MBorne at IGN, it offers tools for geocoding, altitude lookup, administrative boundary queries, cadastral parcel information, and urban planning data retrieval, along with WFS (Web Feature Service) capabilities for searching and describing geographic feature types. The server supports both stdio and HTTP transport modes with Docker deployment, includes distance calculation utilities using JSTS geometry operations, and features comprehensive test coverage for French locations, making it useful for applications requiring detailed French geographic context, spatial analysis, and integration with official French mapping services.', '@ignfab', 'cloud', 'Unknown', 3, 'https://github.com/ignfab/geocontext', '@ignfab/geocontext', 552, 'https://github.com/ignfab.png?size=128', '2026-03-09T05:21:01.992247+00:00'),
  ('ignission', 'Ignission', 'Provides analytics and insights for TikTok content creators and businesses. Analyzes video performance data, identifies audience engagement patterns, and generates content strategy recommendations based on historical performance metrics.', '@ignission-io', 'media', 'Unknown', 0, 'https://github.com/ignission-io/mcp', NULL, 0, 'https://github.com/ignission-io.png?size=128', '2026-03-09T05:21:01.992295+00:00'),
  ('unity-editor', 'Unity Editor', 'UnityMCP enables seamless integration between Unity Editor and AI assistants through the Model Context Protocol. It consists of a C# Unity plugin that monitors editor state and executes commands, paired with a TypeScript MCP server that exposes Unity functionality through standardized tools. The implementation provides real-time access to scene hierarchies, project structures, and GameObject manipulation, allowing AI assistants to retrieve editor state, execute C# code directly in the editor, and access Unity logs. This makes it particularly valuable for AI-assisted game development workflows, automated testing, and interactive debugging sessions.', '@igordias2', 'development', 'Unknown', 0, 'https://github.com/igordias2/unitymcp', NULL, 0, 'https://github.com/igordias2.png?size=128', '2026-03-09T05:21:01.992322+00:00'),
  ('catalog', 'Catalog', 'Integrates with Catalog''s data management platform at studio.igot.ai, enabling natural language operations for data catalog discovery, master data management, and automated AI transformation workflows. Provides tools for listing catalogs and collections, exploring schema attributes with prompt templates, managing data assets, and ingesting plain text data with optional AI processing. Built with TypeScript and the MCP SDK, supports enterprise data workflows through API key authentication and structured data operations across catalogs, collections, and master data tables.', '@igot-ai', 'development', 'Unknown', 1, 'https://github.com/igot-ai/datalog-studio', NULL, 0, 'https://github.com/igot-ai.png?size=128', '2026-03-09T05:21:01.992349+00:00'),
  ('south-asia', 'South Asia', 'A server implementation for the IGS South Asia team that provides tools and utilities for their specific needs. Built with Python and the MCP protocol, it exposes a basic hello world endpoint and follows a modular structure with handlers, models and services. Currently in early development with minimal functionality implemented.', '@igs-pochenkuo', 'development', 'Unknown', 0, 'https://github.com/igs-pochenkuo/southasia_mcp', NULL, 0, 'https://github.com/igs-pochenkuo.png?size=128', '2026-03-09T05:21:01.992371+00:00'),
  ('ios-mobile-automation', 'iOS Mobile Automation', 'Mobile automation MCP server built with FastMCP 2.0 that provides iOS automation capabilities through Appium and XCUITest integration. The implementation offers tools for taking screenshots, launching apps, finding and tapping UI elements, and performing text input on iOS simulators, with a modular architecture supporting shared utilities for cross-platform expansion to Android in the future. Designed for developers and QA engineers who need conversational access to mobile app testing and automation workflows without manually writing Appium scripts, enabling AI assistants to interact with iOS applications through natural language commands while handling the underlying WebDriver complexity.', '@ihacksubhodip', 'development', 'Unknown', 30, 'https://github.com/ihacksubhodip/mobile-automation-mcp-server', NULL, 0, 'https://github.com/ihacksubhodip.png?size=128', '2026-03-09T05:21:01.992405+00:00'),
  ('aws-sdk', 'AWS SDK', 'AWS-MCP is a server implementation that enables AI assistants to interact directly with AWS services through the AWS SDK v2. It provides tools for running AWS code, listing available credentials/profiles, and selecting profiles for authentication (including SSO support). The server handles credential management, executes JavaScript code in a sandboxed environment, and returns formatted results from AWS API calls. This implementation is particularly valuable for users who need to query their AWS environment, manage resources, or analyze cloud infrastructure without leaving their AI assistant conversation.', '@ihatesea69', 'cloud', 'Unknown', 6, 'https://github.com/ihatesea69/aws-mcp-server', NULL, 0, 'https://github.com/ihatesea69.png?size=128', '2026-03-09T05:21:01.992422+00:00'),
  ('hledger', 'HLedger', 'This MCP server provides a bridge to HLedger accounting software, enabling interaction with plain-text accounting journals through financial reporting and transaction management tools. Built with TypeScript and featuring 19+ HLedger commands including balance reports, income statements, cash flow analysis, and transaction queries, it supports both read-only operations for financial analysis and write operations for adding transactions, importing data, and performing journal maintenance with automatic backup creation. The implementation includes robust validation, configurable read-only modes, and resource discovery that automatically registers journal files as MCP resources, making it valuable for bookkeepers managing financial records, developers building accounting workflows, and systems that need access to double-entry bookkeeping data without manual HLedger command-line interaction.', '@iiatlas', 'development', 'Unknown', 49, 'https://github.com/iiatlas/hledger-mcp', '@iiatlas/hledger-mcp', 711, 'https://github.com/iiatlas.png?size=128', '2026-03-09T05:21:01.992540+00:00'),
  ('multi-jira', 'Multi-Jira', 'Connects to multiple Jira instances through a single server with OAuth 2.0 authentication and encrypted token storage, enabling seamless account switching and issue management across different organizational tenants. Supports integration with Cursor, Claude Code, and Codex CLI.', '@iipanda', 'development', 'Unknown', 2, 'https://github.com/iipanda/mcp-multi-jira', NULL, 0, 'https://github.com/iipanda.png?size=128', '2026-03-09T05:21:01.992559+00:00'),
  ('investment-portfolio-manager', 'Investment Portfolio Manager', 'The Investment Portfolio Manager MCP Server implements a clean, modular architecture for analyzing and managing user''s Investment Portfolio. The core server component handles protocol negotiation, client connections, and message routing, with support for both stdio and Server-Sent Events (SSE) transports. We organized functionality into specialized modules:
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('img-src-io', 'img-src.io', 'Integrates with the img-src.io Image CDN to manage images programmatically. Supports uploading images from files, URLs, or base64 data, searching and listing stored images, retrieving image metadata, generating optimized CDN URLs with real-time transformations, and checking account usage and settings. Requires an img-src.io API key for authentication.', '@img-src-io', 'search', 'Unknown', 0, 'https://github.com/img-src-io/mcp', NULL, 0, 'https://github.com/img-src-io.png?size=128', '2026-03-09T05:21:01.993188+00:00'),
  ('nmap-scanner', 'Nmap Scanner', 'Nmap MCP Server provides a secure, controlled interface for running network scans through nmap, enabling AI assistants to perform targeted network reconnaissance and analysis. It exposes tools for running scans, retrieving scan details, and generating AI-powered insights about network infrastructure, with built-in rate limiting and security safeguards to prevent misuse. Particularly useful for network administrators, security researchers, and penetration testers who want to leverage AI assistance in network exploration and vulnerability assessment.', '@imjdl', 'development', 'Unknown', 14, 'https://github.com/imjdl/nmap-mcpserver', NULL, 0, 'https://github.com/imjdl.png?size=128', '2026-03-09T05:21:01.993228+00:00'),
  ('elasticsearch-7-x', 'Elasticsearch 7.x', 'This MCP server implementation provides integration with Elasticsearch 7.x, allowing for efficient interaction and data management within Elasticsearch clusters. Developed by imlewc, it utilizes FastMCP and offers a streamlined interface for Elasticsearch operations through the MCP protocol. The server is particularly useful for projects requiring robust search and analytics capabilities while leveraging the MCP ecosystem.', '@imlewc', 'productivity', 'Unknown', 7, 'https://github.com/imlewc/elasticsearch7-mcp-server', NULL, 0, 'https://github.com/imlewc.png?size=128', '2026-03-09T05:21:01.993263+00:00'),
  ('mitre-att-ck', 'MITRE ATT&CK', 'Provides machine-callable access to the MITRE ATT&CK threat intelligence framework. Enables querying of adversary tactics, techniques, and procedures across Enterprise, Mobile, and ICS domains. Uses the official mitreattack-python library to deliver structured threat intelligence data including techniques, groups, software, mitigations, and relationships.', '@imouiche', 'ai-ml', 'Unknown', 2, 'https://github.com/imouiche/complete-mitre-attack-mcp-server', NULL, 0, 'https://github.com/imouiche.png?size=128', '2026-03-09T05:21:01.993306+00:00'),
  ('io-github-shashwatgtm-impact-mcp-server', 'io.github.shashwatgtm/impact-mcp-server', 'IMPACT Framework - B2B Positioning & Messaging Tools by Shashwat Ghosh', '@shashwatgtm', 'development', 'Unknown', 0, 'https://github.com/shashwatgtm/impact-mcp-server', NULL, 0, 'https://github.com/shashwatgtm.png?size=128', '2026-03-09T05:21:01.993321+00:00'),
  ('io-github-agent-polis-impact-preview', 'io.github.agent-polis/impact-preview', 'Impact preview for AI agents - see what changes before any action executes.', '@agent-polis', 'development', 'Unknown', 1, 'https://github.com/agent-polis/impact-preview', NULL, 0, 'https://github.com/agent-polis.png?size=128', '2026-03-09T05:21:01.993336+00:00'),
  ('status-observer', 'Status Observer', 'MCP Status Observer provides real-time monitoring of operational status for major digital platforms like GitHub, Slack, Discord, and others through a TypeScript implementation that fetches data from various status APIs. It parses platform-specific response formats to deliver standardized status information including overall health, component details, and recent incidents. The server exposes a simple command interface that allows Claude Desktop users to query individual platform statuses or get a consolidated overview of all monitored services. Particularly valuable for IT professionals, developers, and system administrators who need to quickly assess service disruptions across multiple critical platforms without visiting separate status pages.', '@imprvhub', 'development', 'Unknown', 6, 'https://github.com/imprvhub/mcp-status-observer', NULL, 0, 'https://github.com/imprvhub.png?size=128', '2026-03-09T05:21:01.993398+00:00'),
  ('codemode-sqlite', 'Codemode SQLite', 'Provides SQLite database access through two modes: standard MCP tool calls and an experimental ''codemode'' where LLMs generate complete Go programs executed in a sandboxed interpreter. Supports CRUD operations, arbitrary SQL queries, and multiple transports including STDIO and HTTP.', '@imran31415', 'databases', 'Unknown', 6, 'https://github.com/imran31415/codemode-sqlite-mcp', NULL, 0, 'https://github.com/imran31415.png?size=128', '2026-03-09T05:21:01.993409+00:00'),
  ('splitwise', 'Splitwise', 'A Ruby-based MCP server that provides comprehensive access to the Splitwise API for expense sharing and group financial management. Built using the fast-mcp gem, it offers tools for managing friends, groups, expenses, comments, and notifications, with intelligent fuzzy matching for resolving entity names to IDs using the Amatch library.', '@imtheaman', 'development', 'Unknown', 4, 'https://github.com/imtheaman/splitwise_mcp', NULL, 0, 'https://github.com/imtheaman.png?size=128', '2026-03-09T05:21:01.993472+00:00'),
  ('hr-policy-chatbot', 'HR Policy Chatbot', 'RagChatbot_MCPServer is a localhost MCP server implementation that enables a RAG-based HR chatbot to provide workplace rules information from PDF documents. Built with OpenAI models and LangChain utilities, the server orchestrates document indexing, retrieval, and answer generation through function calling. It features PDF parsing, text chunking with RecursiveCharacterTextSplitter, document indexing with OpenAIEmbeddings, and similarity search to retrieve relevant content. The implementation includes a Streamlit interface for user interaction and supports email sending capabilities, making it particularly useful for HR departments needing to provide policy information from documentation.', '@imvirtue', 'communication', 'Unknown', 6, 'https://github.com/imvirtue/ragchatbot_mcpserver', NULL, 0, 'https://github.com/imvirtue.png?size=128', '2026-03-09T05:21:01.993507+00:00'),
  ('incode', 'Incode', 'Integrates with Incode''s identity verification platform to provide KYC and identity verification capabilities. Supports generating verification sessions, checking completion status, retrieving verification scores, and validating authentication tokens for verified users.', '@incodetechnologies', 'development', 'Unknown', 0, 'https://github.com/incodetechnologies/incode-idv-mcp', NULL, 0, 'https://github.com/incodetechnologies.png?size=128', '2026-03-09T05:21:01.993556+00:00'),
  ('openai-image-generation', 'OpenAI Image Generation', 'OpenAI Image Generation MCP Server provides tools for generating and editing images using OpenAI''s gpt-image-1 model through a standardized interface. Built by IncomeStreamSurfer, it implements two main tools: generate_image for creating new images from text prompts, and edit_image for modifying existing images or performing inpainting with masks. The server handles all aspects of the OpenAI API interaction, including proper error handling, image saving to local storage, and filename generation. It''s particularly valuable for developers who want to integrate OpenAI''s image generation capabilities into AI assistant workflows without managing the complexities of the OpenAI API directly.', '@incomestreamsurfer', 'ai-ml', 'Unknown', 16, 'https://github.com/incomestreamsurfer/chatgpt-native-image-gen-mcp', NULL, 0, 'https://github.com/incomestreamsurfer.png?size=128', '2026-03-09T05:21:01.993601+00:00'),
  ('roo-code-memory-bank', 'Roo Code Memory Bank', 'Roo Code Memory Bank MCP Server implements a file-based project context management system that enables AI assistants to maintain persistent memory across sessions. Built by IncomeStreamSurfer, it provides tools for initializing a structured memory bank with standard markdown files (productContext, activeContext, progress, decisionLog, systemPatterns), checking memory bank status, reading file contents, and appending timestamped entries to specific sections. The server uses Node.js with TypeScript and the MCP SDK to handle file operations asynchronously, making it particularly valuable for developers and AI assistants working on complex projects that require maintaining context and decision history over time.', '@incomestreamsurfer', 'development', 'Unknown', 57, 'https://github.com/incomestreamsurfer/roo-code-memory-bank-mcp-server', NULL, 0, 'https://github.com/incomestreamsurfer.png?size=128', '2026-03-09T05:21:01.993633+00:00'),
  ('index9', 'Index9', 'Provides up-to-date pricing, specifications, and capabilities for 300+ language models from OpenRouter. Search models by natural language queries or filters, get detailed metadata including pricing and context limits, and optionally test models with live API requests to compare outputs and latency.', '@index9-org', 'development', 'Unknown', 1, 'https://github.com/index9-org/mcp', NULL, 0, 'https://github.com/index9-org.png?size=128', '2026-03-09T05:21:01.993684+00:00'),
  ('index-network-user-profile', 'Index Network User Profile', 'A privacy-focused user profile management server built by Index Network that stores user preferences, display names, pronouns, and notes in volatile memory with strict consent requirements. The server implements explicit consent validation where profile data is only stored after users explicitly agree in the conversation, and includes tools for retrieving, updating, and deleting stored profiles using user-provided keys. It runs on Express with CORS support for browser compatibility and includes additional demo tools like health checks, echo functionality, and basic search capabilities, making it suitable for ChatGPT integrations where personalized interactions require temporary user context storage without persistent data retention.', '@indexnetwork', 'communication', 'Unknown', 3, 'https://github.com/indexnetwork/mcp', NULL, 0, 'https://github.com/indexnetwork.png?size=128', '2026-03-09T05:21:01.993727+00:00'),
  ('ios-simulator-automation-idb', 'iOS Simulator Automation (IDB)', 'A Model Context Protocol server for iOS simulator automation via Facebook''s IDB tool, enabling AI assistants to control iOS simulators using natural language commands. Developed by Inditex Tech, this TypeScript implementation provides a comprehensive command system for managing simulator sessions, launching apps, capturing screenshots, and performing UI interactions. The architecture includes a natural language parser that converts instructions into structured commands, an orchestrator that manages command execution, and an IDB manager that interfaces with the iOS simulator. This server is particularly useful for automated testing of iOS applications, UI validation, and creating interactive demos without requiring direct access to physical devices.', '@inditextech', 'development', 'Unknown', 298, 'https://github.com/inditextech/mcp-server-simulator-ios-idb', NULL, 0, 'https://github.com/inditextech.png?size=128', '2026-03-09T05:21:01.993759+00:00'),
  ('uniprof', 'UniProf', 'UniProf provides a unified interface for CPU profiling across Python, Node.js, Ruby, PHP, JVM, .NET, and native applications. It automatically detects the appropriate profiler for each runtime, standardizes output formats, and identifies performance hotspots through statistical analysis. Supports both containerized and host-based profiling modes, with built-in flamegraph visualization.', '@indragiek', 'ai-ml', 'Unknown', 396, 'https://github.com/indragiek/uniprof', NULL, 0, 'https://github.com/indragiek.png?size=128', '2026-03-09T05:21:01.993811+00:00'),
  ('mcpshell', 'MCPShell', 'MCPShell provides a secure bridge between LLMs and operating system commands through a configurable YAML-based interface. Developed by Alvaro, it features constraint-based security using CEL expressions to validate parameters before execution, multiple sandboxing options (including macOS sandbox-exec and Linux firejail), template-based command generation, and robust error handling. The implementation supports both direct command execution and server mode, making it particularly valuable for scenarios where AI assistants need controlled access to system utilities, diagnostics tools, or administrative functions without compromising security.', '@inercia', 'ai-ml', 'Unknown', 58, 'https://github.com/inercia/mcpshell', NULL, 0, 'https://github.com/inercia.png?size=128', '2026-03-09T05:21:01.993869+00:00'),
  ('mitto', 'Mitto', 'Control your AI coding agents on the go (from Mac, Web, Mobile Phone, etc).', '@inercia', 'ai-ml', 'Unknown', 17, 'https://github.com/inercia/mitto', NULL, 0, 'https://github.com/inercia.png?size=128', '2026-03-09T05:21:01.993890+00:00'),
  ('x', 'X', 'Integrates with the X (Twitter) API through OAuth authentication to provide comprehensive platform interaction including posting tweets, replying, quoting, retweeting, liking, searching content, retrieving timelines and mentions, managing followers, uploading media, and accessing post analytics with pagination and rate limiting support.', '@infatoshi', 'search', 'Unknown', 32, 'https://github.com/infatoshi/x-mcp', NULL, 0, 'https://github.com/infatoshi.png?size=128', '2026-03-09T05:21:01.993925+00:00'),
  ('claude-lmstudio-bridge', 'Claude-LMStudio Bridge', 'Claude-LMStudio Bridge enables Claude to interact with local LLMs running in LM Studio through a robust MCP server implementation. It provides tools for checking connectivity, listing available models, generating text, and handling chat completions with local models. The bridge uses httpx for API communication with LM Studio''s server, supports customizable parameters like temperature and token limits, and includes comprehensive error handling. Particularly valuable for users who want to leverage their local models'' capabilities directly within Claude conversations, reducing reliance on cloud-based LLMs while maintaining a seamless conversation experience.', '@infinitimeless', 'communication', 'Unknown', 13, 'https://github.com/infinitimeless/claude-lmstudio-bridge', NULL, 0, 'https://github.com/infinitimeless.png?size=128', '2026-03-09T05:21:01.993965+00:00'),
  ('lm-studio', 'LM Studio', 'LMStudio-MCP creates a bridge between Claude and locally running LLM models via LM Studio, allowing Claude to interact with private models running on your machine. The server exposes tools to check API health, list available models, identify the currently loaded model, and generate completions using local models through LM Studio''s OpenAI-compatible API endpoints. This enables users to leverage their own models through Claude''s interface, combining Claude''s capabilities with private, locally-hosted language models.', '@infinitimeless', 'ai-ml', 'Unknown', 140, 'https://github.com/infinitimeless/lmstudio-mcp', NULL, 0, 'https://github.com/infinitimeless.png?size=128', '2026-03-09T05:21:01.994004+00:00'),
  ('infisical-secrets-management', 'Infisical (Secrets Management)', 'Infisical MCP Server provides a secure bridge to the Infisical secrets management platform, enabling AI assistants to perform operations like creating, updating, and retrieving secrets through function calling. Developed by Infisical Inc, this TypeScript implementation authenticates via Machine Identity universal auth and exposes tools for managing secrets, projects, environments, folders, and team members. The server runs on stdio transport and can be easily integrated with Claude Desktop or debugged using the MCP Inspector, making it particularly useful for applications that need to securely access and manage sensitive configuration data without exposing credentials directly.', '@infisical', 'development', 'Unknown', 37, 'https://github.com/infisical/infisical-mcp-server', '@infisical/mcp', 2209, 'https://github.com/infisical.png?size=128', '2026-03-09T05:21:01.994064+00:00'),
  ('spira', 'Spira', 'Integrates with Spira ALM platform (SpiraTest, SpiraTeam, SpiraPlan editions) to manage tasks, requirements, incidents, test cases, test sets, and CI/CD builds. Provides operations for retrieving product specifications and recording automation results. Supports requirements traceability, test case management, and exploratory testing workflows.', '@inflectra', 'development', 'Unknown', 0, 'https://github.com/inflectra/mcp-server-spira', NULL, 0, 'https://github.com/inflectra.png?size=128', '2026-03-09T05:21:01.994084+00:00'),
  ('infobip', 'Infobip', 'Collection of example client implementations demonstrating how to integrate Infobip''s SMS MCP server across multiple AI frameworks and programming languages. Includes working examples for OpenAI Agents SDK (Python and JavaScript), Semantic Kernel (Python and C#), LangGraph SDK, and Spring AI (Java), each showcasing how to build conversational AI agents that can send SMS messages through the Infobip platform. The examples provide complete setup instructions, environment configuration, and ready-to-run code for developers looking to integrate SMS capabilities into their AI applications using their preferred framework and language.', '@infobip', 'development', 'Unknown', 25, 'https://github.com/infobip/mcp', NULL, 0, 'https://github.com/infobip.png?size=128', '2026-03-09T05:21:01.994108+00:00'),
  ('immunefi', 'Immunefi', 'Built by the infosec-us-team using FastMCP, this server provides cached access to Immunefi bug bounty program data through an API that refreshes every 6 hours. It offers 15 specialized tools for searching programs, retrieving assets in scope, bounty amounts, rewards structures, impact categories, KYC requirements, launch dates, and filtering by language, ecosystem, or bounty ranges. The implementation includes GitHub repository extraction from program data, robust input validation with alphanumeric project ID checks, and detailed error handling, making it valuable for security researchers conducting reconnaissance on bug bounty programs, analyzing reward structures across different protocols, and identifying potential targets based on specific criteria.', '@infosec-us-team', 'development', 'Unknown', 3, 'https://github.com/infosec-us-team/immunefi-mcp-server-unofficial', NULL, 0, 'https://github.com/infosec-us-team.png?size=128', '2026-03-09T05:21:01.994134+00:00'),
  ('infrahub', 'Infrahub', 'Connects to Infrahub, an AI-ready data management platform for infrastructure automation at scale. Provides read and write access to infrastructure state through a consistent, audited interface. Supports version control natively integrated into its graph database for managing networks, data centers, and cloud infrastructure.', '@opsmill', 'databases', 'Unknown', 4, 'https://github.com/opsmill/infrahub-mcp', NULL, 0, 'https://github.com/opsmill.png?size=128', '2026-03-09T05:21:01.994144+00:00'),
  ('infranodus', 'InfraNodus', 'An MCP server that integrates InfraNodus knowledge graph and network analysis capabilities, enabling AI assistants to transform unstructured text into structured insights using advanced graph theory algorithms. The server provides 23 specialized tools for generating knowledge graphs, detecting content gaps between topical clusters, analyzing existing InfraNodus graphs, comparing texts for similarities and differences, performing SEO analysis through Google search data, and managing persistent knowledge graph memories with entity extraction. Built with TypeScript and featuring progress tracking, it supports both temporary analysis and permanent graph storage in InfraNodus accounts, making it useful for research workflows, content development, competitive analysis, and building AI assistants that can maintain and query complex relational knowledge bases.', '@infranodus', 'development', 'Unknown', 70, 'https://github.com/infranodus/mcp-server-infranodus', 'infranodus-mcp-server', 2713, 'https://github.com/infranodus.png?size=128', '2026-03-09T05:21:01.994173+00:00'),
  ('consumer-financial-protection-bureau-complaints', 'Consumer Financial Protection Bureau Complaints', 'Consumer Complaint Database MCP Server provides access to the Consumer Financial Protection Bureau''s complaint database, allowing AI assistants to search and retrieve banking and financial service complaints. The implementation focuses on mortgage complaints from specific financial institutions like PNC Bank, enabling users to query by company, product type, and limit result size. Built with Python using httpx for API communication and the MCP framework, it transforms raw complaint data into structured objects with proper date handling. This tool is particularly valuable for financial research, consumer advocacy, and understanding patterns in customer issues with financial institutions.', '@ingeniousidiocy', 'databases', 'Unknown', 3, 'https://github.com/ingeniousidiocy/consumer-complaint-database-mcp', NULL, 0, 'https://github.com/ingeniousidiocy.png?size=128', '2026-03-09T05:21:01.994186+00:00'),
  ('screen-monitor', 'Screen Monitor', 'ScreenMonitorMCP is a screen monitoring and analysis server that captures screenshots and provides AI-powered image analysis through OpenAI''s vision models, built with Python using FastAPI, MSS for screen capture, and multiple OCR engines (Tesseract, EasyOCR). The implementation features real-time monitoring capabilities, UI element detection, predictive intelligence for user behavior analysis, and a modular AI provider system that supports custom base URLs for OpenAI-compatible APIs. Designed for automation workflows, accessibility testing, user behavior analysis, and building AI assistants that need visual understanding of desktop applications and screen content.', '@inkbytefo', 'development', 'Unknown', 71, 'https://github.com/inkbytefo/screenmonitormcp', NULL, 0, 'https://github.com/inkbytefo.png?size=128', '2026-03-09T05:21:01.994215+00:00'),
  ('inkdrop', 'Inkdrop', 'Inkdrop MCP Server provides a bridge between Claude Desktop and the Inkdrop note-taking application through the Model Context Protocol. Built by Takuya Matsuyama, it enables Claude to interact with Inkdrop''s local HTTP server API, allowing users to search, read, create, and update notes directly within Claude conversations. The server offers seven tools for managing notes, notebooks, and tags, making it valuable for workflows that require accessing and manipulating Markdown notes without leaving the AI assistant interface. Configuration requires setting up Inkdrop''s local HTTP server and providing authentication credentials in Claude''s desktop config file.', '@inkdropapp', 'ai-ml', 'Unknown', 52, 'https://github.com/inkdropapp/mcp-server', '@inkdropapp/mcp-server', 5590, 'https://github.com/inkdropapp.png?size=128', '2026-03-09T05:21:01.994260+00:00'),
  ('inkeep-rag', 'Inkeep RAG', 'Inkeep MCP Server enables Claude to search and retrieve relevant documentation through Inkeep''s RAG API. The server exposes a single ''rag-search'' tool that queries Inkeep''s API using the OpenAI client library, returning structured citation data compatible with Claude''s citation format. It requires an Inkeep account and API key, and is configured through environment variables. This implementation is particularly valuable for workflows where users need to reference documentation without leaving their conversation with Claude, making it ideal for technical support, developer assistance, and knowledge-based interactions.', '@inkeep', 'ai-ml', 'Unknown', 24, 'https://github.com/inkeep/mcp-server-python', NULL, 0, 'https://github.com/inkeep.png?size=128', '2026-03-09T05:21:01.994306+00:00'),
  ('inkog', 'Inkog', 'Inkog is an AI security platform that scans AI agents and MCP servers for vulnerabilities before deployment. It detects security flaws like prompt injection, token bombing, infinite recursion, and data leakage risks. The platform supports compliance reporting aligned with EU AI Act, NIST AI RMF, ISO 42001, and OWASP LLM Top 10 standards. Works across 15+ frameworks including LangChain, CrewAI, LangGraph, PydanticAI, n8n, and Flowise.', '@inkog-io', 'cloud', 'Unknown', 1, 'https://github.com/inkog-io/inkog-mcp', NULL, 0, 'https://github.com/inkog-io.png?size=128', '2026-03-09T05:21:01.994321+00:00'),
  ('mobi', 'Mobi', 'MCP server that enables AI assistants to interact with Mobi knowledge management platform instances through semantic data operations including ontology management, SHACL shapes validation, and catalog searching. Built by inovexcorp, the implementation provides tools for searching records and entities across catalogs, fetching ontology data in various RDF formats, creating new ontology records from RDF strings, and managing version control through git-inspired branching operations. Designed for knowledge engineers and semantic web developers who need conversational access to Mobi''s catalog-driven workflows without manual navigation of the platform interface, supporting both stdio and SSE transport modes with Docker containerization for easy deployment.', '@inovexcorp', 'cloud', 'Unknown', 2, 'https://github.com/inovexcorp/mobi-mcp', NULL, 0, 'https://github.com/inovexcorp.png?size=128', '2026-03-09T05:21:01.994347+00:00'),
  ('google-meet-calendar', 'Google Meet & Calendar', 'A Google Meet and Calendar integration server built by INSIDE-HAIR that provides 23+ validated tools for managing Google Calendar events and Google Meet spaces through both Calendar API v3 and Meet API v2. The implementation supports multiple authentication methods (direct tokens, file-based OAuth, legacy credentials), comprehensive Zod validation schemas with business logic enforcement, and includes advanced monitoring capabilities with health checks, metrics collection, and Prometheus integration. Features Docker deployment options, Smithery platform compatibility, and extensive error handling optimized for AI assistance, making it useful for automated meeting scheduling, calendar management workflows, conference recording and transcript retrieval, and AI-powered productivity applications that need deep Google Workspace integration.', '@inside-hair', 'cloud', 'Unknown', 2, 'https://github.com/inside-hair/mcp-google-calendar-and-meet', NULL, 0, 'https://github.com/inside-hair.png?size=128', '2026-03-09T05:21:01.994375+00:00'),
  ('insightslibrary', 'InsightsLibrary', 'InsightsLibrary is a plug-and-play knowledge base MCP server that provides access to over 10,000 high-quality insight reports stored locally for secure data handling. Built by Shawn Hui, it offers comprehensive search and retrieval capabilities through file-based and content-based agents that support keyword matching with AND/OR logic, publisher filtering, date range queries, and full-text content search with pagination. The implementation uses TinyDB for local storage, integrates with PDF processing through PyMuPDF, and includes intelligent sorting by relevance or publication date, making it valuable for research workflows, market analysis, and knowledge management tasks where users need to quickly discover and access relevant business insights from a curated document collection.', '@v587d', 'productivity', 'Unknown', 3, 'https://github.com/v587d/insightslibrary', NULL, 0, 'https://github.com/v587d.png?size=128', '2026-03-09T05:21:01.994424+00:00'),
  ('io-github-gridinsoft-inspector', 'io.github.gridinsoft/inspector', 'Website safety and trust analysis. Verify domain reputation and detect phishing with GridinSoft.', '@gridinsoft', 'development', 'Unknown', 0, 'https://github.com/gridinsoft/mcp-inspector', NULL, 0, 'https://github.com/gridinsoft.png?size=128', '2026-03-09T05:21:01.994440+00:00'),
  ('inspector-apm', 'Inspector APM', 'Inspector MCP server by Valerio Barbera that provides AI assistants with direct access to Inspector APM (Application Performance Monitoring) data for debugging and performance analysis. Built with PHP using the php-mcp/server library and Guzzle HTTP client, it integrates with Inspector''s REST API to retrieve production errors, transaction performance data, and detailed execution timelines. The implementation offers four main tools: retrieving recent production errors with AI-powered fix suggestions, analyzing individual errors with stack traces and code context, identifying worst-performing transactions with categorization by criticality, and examining detailed transaction timelines including database queries and N+1 detection. Designed for developers and DevOps teams who need conversational access to production monitoring data, enabling use cases like proactive debugging, performance optimization, and incident response without manually navigating the Inspector dashboard.', '@inspector-apm', 'databases', 'Unknown', 7, 'https://github.com/inspector-apm/mcp-server', NULL, 0, 'https://github.com/inspector-apm.png?size=128', '2026-03-09T05:21:01.994452+00:00'),
  ('inspektor-gadget', 'Inspektor Gadget', 'AI-powered debugging and inspection server for Kubernetes clusters using Inspektor Gadget, providing intelligent gadget discovery, deployment management, and real-time system monitoring through natural language commands. The implementation automatically discovers available gadgets from Artifact Hub, manages Inspektor Gadget deployment via Helm, and dynamically registers each gadget as an MCP tool with intelligent output summarization and background execution capabilities. Built by the Inspektor Gadget team with comprehensive Kubernetes integration including RBAC support and security controls, it enables developers to troubleshoot cluster issues, monitor network traffic, trace system calls, and analyze performance bottlenecks through conversational AI interfaces without requiring deep knowledge of eBPF or gadget syntax.', '@inspektor-gadget', 'cloud', 'Unknown', 22, 'https://github.com/inspektor-gadget/ig-mcp-server', NULL, 0, 'https://github.com/inspektor-gadget.png?size=128', '2026-03-09T05:21:01.994479+00:00'),
  ('kakao-talk', 'Kakao Talk', 'The Kakao MCP server enables AI assistants to send various message templates to Kakao Talk users through the Kakao API. Developed by Donggeon Lee, this implementation provides tools for sending text, feed, list, location, calendar, and commerce templates with OAuth2 authentication handling. The server manages credential storage, token refresh, and user authentication flows while exposing a structured interface for each template type. It''s particularly valuable for users who need to send rich, interactive messages to Kakao Talk contacts without leaving their conversation context, making it ideal for notification workflows, content sharing, and social engagement.', '@inspirit941', 'productivity', 'Unknown', 14, 'https://github.com/inspirit941/kakao-bot-mcp-server', NULL, 0, 'https://github.com/inspirit941.png?size=128', '2026-03-09T05:21:01.994522+00:00'),
  ('instagit', 'Instagit', 'Instagit enables coding agents to analyze any public Git repository with precision. Instead of relying on outdated documentation or training data, agents can query actual source code to get real function signatures, data flows, and implementation patterns with exact file paths and line numbers. Supports library integration analysis, version migration, cross-repository debugging, and code generation based on actual implementations. An optional API key from instagit.com unlocks higher rate limits and faster analysis.', '@instalabsai', 'development', 'Unknown', 15, 'https://github.com/instalabsai/instagit', NULL, 0, 'https://github.com/instalabsai.png?size=128', '2026-03-09T05:21:01.994544+00:00'),
  ('instagram-direct-messages', 'Instagram Direct Messages', 'Instagram DM MCP Server enables AI assistants to read and send Instagram direct messages through Claude Desktop. Built with Python using the FastMCP framework and instagrapi library, it provides tools to retrieve recent messages with comprehensive thread information and send new messages to Instagram users. The server authenticates using Instagram cookies (session ID, CSRF token, and user ID) which can be provided through environment variables, command-line arguments, or a configuration file. The implementation includes a CLI for easy setup and installation, making it ideal for users who want to manage their Instagram conversations directly through their AI assistant without switching applications.', '@taskmaster-ai', 'ai-ml', 'Unknown', 18, 'https://github.com/taskmaster-ai/insta-mcp', 'instagram-dm-mcp', 1555, 'https://github.com/taskmaster-ai.png?size=128', '2026-03-09T05:21:01.994594+00:00'),
  ('install-md', 'install.md', 'Transform complex software installations into simple, guided experiences that work seamlessly with modern coding agents. Create interactive guides as MCP servers that instruct AI assistants on how to integrate SDKs, libraries, APIs, frameworks, CLIs and other software into codebases.', '@unknown', 'development', 'Unknown', 0, 'https://install.md', NULL, 0, NULL, '2026-03-09T05:21:01.994613+00:00'),
  ('ai-prompts-finder', 'AI Prompts Finder', 'AI-Prompts-MCP is a server implementation that provides a standardized interface for finding and retrieving AI prompts based on specific rules or search criteria. Built with TypeScript and the Model Context Protocol SDK, it exposes a ''findrule'' tool that allows AI assistants to search through a collection of prompts using Fuse.js for fuzzy matching. The server uses SSE transport for real-time communication, maintains heartbeat connections, and integrates with an external API to fetch prompt data. This implementation is particularly valuable for developers and AI users who need to quickly access relevant prompts without leaving their AI assistant conversation.', '@instructa', 'development', 'Unknown', 18, 'https://github.com/instructa/ai-prompts-mcp', NULL, 0, 'https://github.com/instructa.png?size=128', '2026-03-09T05:21:01.994641+00:00'),
  ('youtube-music', 'YouTube Music', 'MCP YouTube Music is a server implementation that enables AI assistants to search for and play music tracks through YouTube Music. Developed by Instructa, this Node.js-based server provides two primary tools: one for searching tracks by name and returning detailed results, and another for automatically opening the top search result in the user''s default browser. The implementation handles cross-platform browser launching (macOS, Windows, Linux) and communicates with the YouTube Data API using an API key. It''s particularly useful for voice assistants or chatbots that need to respond to music playback requests without requiring users to manually search for songs.', '@instructa', 'communication', 'Unknown', 9, 'https://github.com/instructa/mcp-youtube-music', NULL, 0, 'https://github.com/instructa.png?size=128', '2026-03-09T05:21:01.994676+00:00'),
  ('integration-app', 'Integration.app', 'This Integration App MCP server, developed by an unnamed author, provides a bridge between AI assistants and Integration App''s workflow automation capabilities. Built with TypeScript and leveraging the Model Context Protocol SDK, it exposes Integration App actions as tools for AI models. The implementation focuses on simplifying interactions with Integration App''s API, making it accessible for AI models to trigger and manage automated workflows. It''s particularly useful for tasks like data synchronization, process automation, or integrating various SaaS applications, enabling AI assistants to orchestrate complex business processes without requiring deep knowledge of individual API complexities.', '@membranehq', 'development', 'Unknown', 34, 'https://github.com/membranehq/mcp-server', NULL, 0, 'https://github.com/membranehq.png?size=128', '2026-03-09T05:21:01.994706+00:00'),
  ('skillz', 'Skillz', 'Created by Eleanor Berger, this server enables execution of local Anthropic-style skills through a structured directory-based approach. Each skill is defined by a SKILL.md file containing YAML front matter with metadata and Markdown instructions. The server automatically discovers skills, validates their structure, and exposes each as a tool that can either return skill instructions for AI model consumption or execute associated scripts in sandboxed temporary environments. Built with FastMCP and featuring security measures like path traversal prevention and restricted execution environments, it supports configurable payloads including files, arguments, environment variables, and stdin with proper isolation and timeout controls.', '@intellectronica', 'ai-ml', 'Unknown', 373, 'https://github.com/intellectronica/skillz', NULL, 0, 'https://github.com/intellectronica.png?size=128', '2026-03-09T05:21:01.994755+00:00'),
  ('intelliglow-smart-lighting', 'IntelliGlow Smart Lighting', 'This MCP server provides intelligent smart lighting control through UDP network communication, enabling AI assistants to discover, connect to, and control physical smart bulbs on local networks with voice command integration. Built with Python using asyncio and FastMCP, it offers comprehensive bulb management including network discovery across IP ranges, real-time status monitoring, RGB color control, brightness adjustment, and power management through UDP packet communication. The implementation features automatic bulb discovery, persistent connection management, voice interface integration with speech recognition, and robust error handling with retry mechanisms, making it valuable for home automation workflows, IoT device management, and voice-controlled lighting systems where AI assistants need direct hardware integration.', '@shree-bd', 'communication', 'Unknown', 1, 'https://github.com/shree-bd/intelliglow-ai-voice-mcp-iot-platform', NULL, 0, 'https://github.com/shree-bd.png?size=128', '2026-03-09T05:21:01.994800+00:00'),
  ('interactive-feedback', 'Interactive Feedback', 'Interactive Feedback MCP provides a Node.js-based server that enables AI assistants to request human feedback during task execution through a modern web interface. The implementation launches a browser-based UI where users can run commands, view console output in real-time via WebSocket connections, and provide interactive feedback that gets returned to the AI assistant as structured JSON data. Built with Express, WebSocket support, and cross-platform process management, it''s designed for human-in-the-loop workflows where AI assistants need user validation, approval, or additional input before proceeding with tasks, making it valuable for code review processes, deployment confirmations, and iterative development scenarios.', '@zivhdinfo', 'development', 'Unknown', 26, 'https://github.com/zivhdinfo/interactive-feedback-mcp-nodejs', NULL, 0, 'https://github.com/zivhdinfo.png?size=128', '2026-03-09T05:21:01.994829+00:00'),
  ('interview-mode', 'Interview Mode', 'Turns Claude into a structured interviewer that gets smarter with every conversation. Provides tools to start interview sessions with loaded checkpoints and recommended discussion paths, record questions and decisions with checkpoint tracking, review progress with topics ranked by Bayesian scoring, and conclude sessions while uploading metadata for system evolution. Automatically discovers important discussion topics and ranks them by effectiveness across sessions.', '@teabagkim', 'development', 'Unknown', 0, 'https://github.com/teabagkim/claude-interview-mode', NULL, 0, 'https://github.com/teabagkim.png?size=128', '2026-03-09T05:21:01.994882+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('context-sync', 'Context Sync', 'Context Sync provides a local-first, persistent memory layer for AI development tools using SQLite storage. It enables AI assistants to maintain project context, conversations, and decisions across multiple sessions and platforms. Features include cross-chat memory, todo management, file operations with approval workflows, git integration, and Notion sync capabilities.', '@intina47', 'databases', 'Unknown', 120, 'https://github.com/intina47/context-sync', NULL, 0, 'https://github.com/intina47.png?size=128', '2026-03-09T05:21:01.994897+00:00'),
  ('lemon-squeezy', 'Lemon Squeezy', 'Provides complete access to the Lemon Squeezy payment platform API, enabling management of stores, customers, products, orders, subscriptions, discounts, license keys, and webhooks. Features optional Salesforce CRM integration that automatically syncs customer data from payments to leads using AWS Secrets Manager for secure credential storage and JWT authentication. Supports both production and test environments for e-commerce automation, subscription management, customer relationship workflows, and payment processing integrations.', '@intrepidservicesllc', 'cloud', 'Unknown', 2, 'https://github.com/intrepidservicesllc/lemonsqueezy-mcp-server', NULL, 0, 'https://github.com/intrepidservicesllc.png?size=128', '2026-03-09T05:21:01.994915+00:00'),
  ('internet-speed-test', 'Internet Speed Test', 'Internet Speed Test MCP Server provides a set of tools for measuring network performance metrics including download speed, upload speed, latency, and jitter. Built with Python using the FastMCP framework, it offers individual measurement functions as well as a comprehensive test that returns all metrics in a single call. The server uses configurable test endpoints that can be customized through environment variables or the smithery.yaml configuration, making it adaptable to different testing scenarios and network environments. It''s particularly valuable for AI models and agents that need to diagnose connection issues, verify network performance, or collect internet quality metrics without requiring complex setup or specialized hardware.', '@inventer-dev', 'development', 'Unknown', 12, 'https://github.com/inventer-dev/mcp-internet-speed-test', NULL, 0, 'https://github.com/inventer-dev.png?size=128', '2026-03-09T05:21:01.994946+00:00'),
  ('investigation-game', 'Investigation Game', 'Find out who killed Claude by interrogating the LLM driven suspects.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://investigation-game.skybridge.tech', NULL, 0, NULL, '2026-03-09T05:21:01.994967+00:00'),
  ('io-aerospace', 'IO Aerospace', 'An MCP server implementation developed by IO Aerospace, written in C#. This server provides integration capabilities for aerospace-related services and data through the Model Context Protocol.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://www.io-aerospace.org/ai', NULL, 0, NULL, '2026-03-09T05:21:01.994991+00:00'),
  ('backstage', 'Backstage', 'Backstage MCP is a Quarkus-based server that enables AI agents like Goose to interact with Backstage, the open-source developer portal platform. It provides tools for listing available templates and instantiating new projects directly from the command line, leveraging Quarkus Backstage for API communication. The implementation requires a Backstage installation with Service-to-Service authentication enabled, making it particularly useful for developers who want to automate project creation workflows through conversational AI interfaces.', '@iocanel', 'productivity', 'Unknown', 13, 'https://github.com/iocanel/backstage-mcp', NULL, 0, 'https://github.com/iocanel.png?size=128', '2026-03-09T05:21:01.995031+00:00'),
  ('azure-assistant', 'Azure Assistant', 'This Azure Assistant MCP server by iOSDevil provides intelligent Azure resource querying by generating and executing Azure Resource Graph (ARG) KQL queries from natural language questions. Built with multi-tenant support through service principal authentication, it features automatic tenant detection from query context, management group scoping for enterprise environments, and heuristic natural-language-to-KQL conversion for common scenarios like finding stopped VMs, public IPs, unencrypted storage accounts, and Key Vault configurations. The implementation includes subscription auto-discovery, diagnostic tools for troubleshooting scope and permissions, and cross-tenant VM counting capabilities, making it ideal for Azure administrators, cloud architects, and DevOps teams who need conversational access to Azure resource inventory and compliance checking across multiple tenants and subscriptions.', '@andrewstephenson-v1', 'cloud', 'Unknown', 2, 'https://github.com/andrewstephenson-v1/azure-assistant-mcp', NULL, 0, 'https://github.com/andrewstephenson-v1.png?size=128', '2026-03-09T05:21:01.995055+00:00'),
  ('ip2location-io', 'IP2Location.io', 'This MCP server provides IP geolocation services through integration with the IP2Location.io API, enabling AI agents to retrieve detailed location and network information for any IPv4 or IPv6 address. Built by IP2Location using Python with FastMCP and httpx, it offers a single comprehensive tool that returns geographic data (country, region, city, coordinates, timezone), network details (ASN, ISP, domain), mobile information (MCC, MNC, carrier), security insights (proxy detection, threat analysis), and additional metadata like currency, language, and weather information. The implementation supports both free tier usage (1,000 queries/day) and API key authentication for enhanced limits (50,000 queries/month), making it valuable for security analysis, fraud detection, content localization, network troubleshooting, and building location-aware applications without manual IP lookup processes.', '@ip2location', 'development', 'Unknown', 12, 'https://github.com/ip2location/mcp-ip2location-io', NULL, 0, 'https://github.com/ip2location.png?size=128', '2026-03-09T05:21:01.995087+00:00'),
  ('gw150914-signal-search', 'GW150914 Signal Search', 'This gravitational wave signal detection MCP server provides AI assistants with complete access to LIGO-Virgo gravitational wave data analysis through PyCBC and GWpy integration. Built by He Wang for the GW150914 event analysis, it implements a full matched filtering pipeline including data fetching from GWOSC, preprocessing with high-pass filtering, template generation with sky localization parameters, network SNR calculation across multiple detectors, and visualization capabilities. The implementation features an optimization client that uses OpenAI models to iteratively search the 4D parameter space (mass1, mass2, right ascension, declination) to maximize detection SNR, with convergence monitoring and result persistence. It supports multi-detector network analysis for LIGO Hanford, LIGO Livingston, and Virgo detectors, making it useful for gravitational wave researchers, students learning GW data analysis, and AI-assisted parameter optimization workflows in astrophysics.', '@iphysresearch', 'ai-ml', 'Unknown', 4, 'https://github.com/iphysresearch/gw150914-mcp-signal-search', NULL, 0, 'https://github.com/iphysresearch.png?size=128', '2026-03-09T05:21:01.995151+00:00'),
  ('iplocate', 'IPLocate', 'Official IPLocate.io MCP server that provides comprehensive IP address intelligence including geolocation, network information, privacy detection, and abuse contacts through the IPLocate.io API. Built with TypeScript and the MCP SDK, it offers six specialized tools for different aspects of IP analysis (location, privacy/security, network/ASN, company data, and abuse contacts) plus four pre-configured prompts for common investigation workflows like security analysis and IP comparison. Designed for cybersecurity professionals, network administrators, and developers who need reliable IP data for threat detection, fraud prevention, compliance monitoring, and general network analysis without requiring direct API integration.', '@iplocate', 'development', 'Unknown', 16, 'https://github.com/iplocate/mcp-server-iplocate', '@iplocate/mcp-server', 761, 'https://github.com/iplocate.png?size=128', '2026-03-09T05:21:01.995181+00:00'),
  ('bamm-fraxtal-defi', 'BAMM (Fraxtal DeFi)', 'MCP-BAMM is a server implementation for interacting with Borrow Automated Market Maker (BAMM) contracts on the Fraxtal blockchain. Developed by IQAI, it provides tools for managing BAMM positions, lending Fraxswap LP tokens, borrowing against collateral, and performing other DeFi operations through a standardized interface. The server uses TypeScript with Viem for blockchain interactions and implements secure transaction handling with proper token approvals and balance checks. It''s particularly valuable for DeFi applications that need programmatic access to BAMM protocol functions through AI assistants or other MCP-compatible clients.', '@iqaicom', 'development', 'Unknown', 1, 'https://github.com/iqaicom/mcp-bamm', '@iqai/mcp-bamm', 4783, 'https://github.com/iqaicom.png?size=128', '2026-03-09T05:21:01.995212+00:00'),
  ('iq-wiki', 'IQ.wiki', 'MCP-IQWiki is a TypeScript server that provides structured access to IQ.wiki''s blockchain encyclopedia data through GraphQL. Developed by IQAI, it offers four key tools: retrieving specific wikis by ID, listing wikis created or edited by a user, and obtaining detailed wiki activity histories with metadata about content changes. The implementation uses a clean service-based architecture with GraphQL queries to the Everipedia backend, making it particularly useful for AI assistants that need to reference or analyze blockchain and cryptocurrency information from authoritative sources.', '@iqaicom', 'development', 'Unknown', 1, 'https://github.com/iqaicom/mcp-iqwiki', '@iqai/mcp-iqwiki', 3904, 'https://github.com/iqaicom.png?size=128', '2026-03-09T05:21:01.995275+00:00'),
  ('upbit', 'Upbit', 'Fast MCP server for interacting with Upbit cryptocurrency exchange, built by IQ AI using TypeScript and the fastmcp framework. Provides both public market data access (ticker prices, orderbooks, recent trades) and optional private trading functionality (account balances, order management, trade execution) with JWT-based authentication and configurable safety controls. The implementation uses axios with retry logic for reliable API communication, Zod for parameter validation, and includes comprehensive order management tools supporting limit, market, and price-based order types, making it valuable for cryptocurrency trading bots, portfolio management systems, and financial analysis workflows requiring programmatic access to Korean crypto markets.', '@iqaicom', 'development', 'Unknown', 2, 'https://github.com/iqaicom/mcp-upbit', '@iqai/mcp-upbit', 348, 'https://github.com/iqaicom.png?size=128', '2026-03-09T05:21:01.995306+00:00'),
  ('mlflow', 'MLflow', 'MLflow MCP Server provides a natural language interface to MLflow tracking servers through the Model Context Protocol. It exposes core MLflow functionality as standardized tools that AI assistants can use to query and manage machine learning experiments and models. The server connects to a local MLflow instance and offers tools for listing registered models, exploring experiments, retrieving detailed model information, and checking system status - making it valuable for data scientists who want to interact with their MLflow environment using conversational AI rather than programming interfaces.', '@irahulpandey', 'ai-ml', 'Unknown', 10, 'https://github.com/irahulpandey/mlflowmcpserver', NULL, 0, 'https://github.com/irahulpandey.png?size=128', '2026-03-09T05:21:01.995353+00:00'),
  ('promptlab', 'PromptLab', 'PromptLab transforms basic user queries into optimized prompts for AI systems by automatically detecting content type and applying tailored templates from a YAML-based system. The server implementation uses FastMCP to expose specialized tools for generating enhanced prompts across four categories: essays, emails, technical explanations, and creative writing. With its modular architecture, PromptLab enables non-technical users to create and manage prompt templates, ultimately producing higher-quality AI responses through better-structured inputs.', '@irahulpandey', 'communication', 'Unknown', 7, 'https://github.com/irahulpandey/promptlab', NULL, 0, 'https://github.com/irahulpandey.png?size=128', '2026-03-09T05:21:01.995386+00:00'),
  ('persistproc', 'Persistproc', 'This MCP server provides AI assistants with persistent process management capabilities for multi-agent development workflows, built by Steve Landey using Python with FastMCP and rich console output to enable natural language control over long-running development processes like servers, build watchers, and background tasks. The implementation offers unified process control through start/stop/restart operations with custom labeling, real-time output streaming and capture, process discovery and filtering, and robust cleanup handling, featuring both command-line interface and MCP server modes with JSON/text output formats and comprehensive logging to isolated data directories. Built with subprocess management using process groups for clean termination, file-based log capture with streaming support, environment variable injection, and extensive test coverage using pytest with real process lifecycle testing, it serves development teams needing conversational access to background process orchestration, DevOps engineers requiring AI-driven service management, and multi-agent workflows where natural language interfaces enhance development productivity without manual process juggling across terminal sessions.', '@irskep', 'development', 'Unknown', 6, 'https://github.com/irskep/persistproc', 'persistproc', 2008, 'https://github.com/irskep.png?size=128', '2026-03-09T05:21:01.995485+00:00'),
  ('brave-search-sse', 'Brave Search SSE', 'Brave Search MCP with SSE provides real-time search capabilities through the Brave Search API, delivering results via Server-Sent Events (SSE) for immediate display. Built by Isaac Gounton, it exposes both a standard MCP tool interface for web searches and a dedicated SSE endpoint that maintains persistent connections with clients, broadcasting search results as they arrive. The implementation is containerized with Docker, configured through environment variables, and designed for easy deployment to Coolify. This server is particularly valuable for applications requiring live search results without polling, such as real-time monitoring dashboards or collaborative search interfaces.', '@isaacgounton', 'cloud', 'Unknown', 0, 'https://github.com/isaacgounton/brave-search-mcp-sse', NULL, 0, 'https://github.com/isaacgounton.png?size=128', '2026-03-09T05:21:01.995509+00:00'),
  ('solesonic', 'Solesonic', 'A Spring Boot-based MCP server implementation that demonstrates HTTP-based Model Context Protocol integration using Spring AI''s MCP server starter. Built with Java 24 and Maven, it features OAuth2 JWT authentication through AWS Cognito, requiring tokens with MCP_INVOKE scope and api://solesonic-mcp audience for secure access. The server exposes a simple echo tool called ''message_me'' that returns user messages, serving as a foundation for building more complex MCP servers with Spring''s dependency injection and security features. Includes configuration for local development with .env file support and can be integrated with MCP clients like Claude Desktop or the MCP Inspector for testing and interaction.', '@isaacpeel', 'cloud', 'Unknown', 3, 'https://github.com/isaacpeel/solesonic-mcp-server', NULL, 0, 'https://github.com/isaacpeel.png?size=128', '2026-03-09T05:21:01.995540+00:00'),
  ('google-drive-sheets', 'Google Drive & Sheets', 'This Google Drive MCP server, developed by Phil Isaac, enables seamless integration of Google Drive and Sheets functionality into AI-assisted workflows. Built with TypeScript and leveraging the @modelcontextprotocol/sdk, it provides a standardized interface for accessing and manipulating Google Drive files and Sheets data through Claude Desktop and compatible MCP clients. The implementation supports file listing, reading, and writing operations, as well as specialized tools for interacting with Google Sheets. It''s particularly useful for developers and businesses looking to incorporate on-demand access to cloud-stored documents and spreadsheets into their AI-assisted applications, allowing for dynamic querying and manipulation of Google Drive content.', '@isaacphi', 'development', 'Unknown', 270, 'https://github.com/isaacphi/mcp-gdrive', '@isaacphi/mcp-gdrive', 17708, 'https://github.com/isaacphi.png?size=128', '2026-03-09T05:21:01.995598+00:00'),
  ('langchain-typescript', 'LangChain (TypeScript)', 'This LangChain.js client for Model Context Protocol, developed by Isaac Wasserman, provides a TypeScript port of the original Python implementation. It enables seamless integration of MCP tools with LangChain.js workflows, allowing developers to leverage MCP''s capabilities within JavaScript and TypeScript environments. The client initializes an MCP toolkit, extracts LangChain-compatible tools, and facilitates their use with LangChain agents. By bridging MCP and LangChain.js, this implementation expands the ecosystem of AI tools available to JavaScript developers, enabling the creation of more powerful and flexible AI applications. It is particularly useful for building chatbots, question-answering systems, and other AI-powered applications that require access to external tools and APIs within a JavaScript runtime.', '@isaacwasserman', 'development', 'Unknown', 35, 'https://github.com/isaacwasserman/mcp-langchain-ts-client', 'mcp-langchain-ts-client', 2490, 'https://github.com/isaacwasserman.png?size=128', '2026-03-09T05:21:01.995702+00:00'),
  ('vega-lite-data-visualization', 'Vega-Lite Data Visualization', 'This MCP server, developed by Isaac Wasserman, enables AI assistants like Claude to create data visualizations using Vega-Lite syntax. Built in Python, it provides two core functions: saving data tables and generating visualizations from that data. The implementation stands out by leveraging the expressive power of Vega-Lite for creating a wide range of chart types. By connecting AI capabilities with data visualization, this server enables AI systems to analyze and present data visually. It is particularly useful for scenarios like exploratory data analysis, creating reports with charts, and building AI assistants that can generate insightful data visualizations on demand.', '@isaacwasserman', 'development', 'Unknown', 96, 'https://github.com/isaacwasserman/mcp-vegalite-server', NULL, 0, 'https://github.com/isaacwasserman.png?size=128', '2026-03-09T05:21:01.995740+00:00'),
  ('kolada', 'Kolada', 'Provides access to 5,000+ Key Performance Indicators across 264 operating areas for all Swedish municipalities and regions through Kolada, Sweden''s comprehensive open data source for municipal and regional statistics. Covers education, healthcare, environment, economics, and more with standardized metrics updated annually.', '@isakskogstad', 'data-analytics', 'Unknown', 10, 'https://github.com/isakskogstad/kolada-mcp', NULL, 0, 'https://github.com/isakskogstad.png?size=128', '2026-03-09T05:21:01.995791+00:00'),
  ('oecd', 'OECD', 'Provides access to comprehensive economic and statistical datasets from the Organisation for Economic Co-operation and Development (OECD) covering 38 member countries. Enables querying and analysis across economy, employment, trade, health, education, environment, and more via the SDMX API. Includes tools for dataset discovery, metadata retrieval, and statistical data queries with no authentication required.', '@isakskogstad', 'development', 'Unknown', 1, 'https://github.com/isakskogstad/oecd-mcp', NULL, 0, 'https://github.com/isakskogstad.png?size=128', '2026-03-09T05:21:01.995811+00:00'),
  ('statistics-sweden', 'Statistics Sweden', 'Provides access to Statistics Sweden''s comprehensive database with over 1,200 statistical tables covering demographics across 312+ regions, economic indicators including GDP and business statistics, environmental sustainability metrics, labor market data, and education statistics. Features natural language search, fuzzy matching for Swedish place names, and region code resolution. Data updated through November 2025.', '@isakskogstad', 'databases', 'Unknown', 7, 'https://github.com/isakskogstad/scb-mcp', NULL, 0, 'https://github.com/isakskogstad.png?size=128', '2026-03-09T05:21:01.995824+00:00'),
  ('canon-camera-control', 'Canon Camera Control', 'This MCP server provides direct control over Canon cameras through the Canon Camera Control API (CCAPI), enabling AI assistants to remotely adjust shooting settings like aperture, shutter speed, and ISO, as well as retrieve live view images for real-time feedback. Built with Python using FastMCP and the requests library, it includes intelligent image compression to keep live view images under 1MB for efficient transmission while maintaining quality through progressive JPEG compression and resizing. The implementation is valuable for photography workflows where AI assistants need to help users adjust camera settings based on lighting conditions or creative requirements, with live view capability allowing immediate visual confirmation of setting changes.', '@ish-joshi', 'ai-ml', 'Unknown', 1, 'https://github.com/ish-joshi/canon-camera-mcp', NULL, 0, 'https://github.com/ish-joshi.png?size=128', '2026-03-09T05:21:01.995885+00:00'),
  ('leonardo-ai', 'Leonardo AI', 'This MCP server provides Leonardo AI integration for image generation workflows, built by Ish Joshi using Python with the leonardo-ai-sdk and FastMCP framework. It offers tools for creating image generation jobs with customizable parameters, browsing available AI models with descriptions and IDs, checking job status and completion, retrieving user generation history, and managing user authentication through the Leonardo API. The implementation supports both HTTP and stdio transport modes for flexibility with different client types, making it valuable for AI assistants that need to generate images, iterate on visual concepts, or integrate Leonardo AI''s capabilities into creative workflows where users want to leverage specific models for different artistic styles and generation tasks.', '@ish-joshi', 'productivity', 'Unknown', 2, 'https://github.com/ish-joshi/leonardo-mcp-server', NULL, 0, 'https://github.com/ish-joshi.png?size=128', '2026-03-09T05:21:01.995934+00:00'),
  ('isms', 'ISMS', 'An Information Security Management System (ISMS) MCP server that provides AI-powered tools for risk analysis, policy management, and incident response. Built with FastAPI and SQLAlchemy, it integrates Mistral AI and Qdrant for intelligent security workflows, enabling automated risk assessment, policy suggestion updates, and contextual incident guidance across different security domains.', '@karthikkrs', 'databases', 'Unknown', 1, 'https://github.com/karthikkrs/isms-mcp-project', NULL, 0, 'https://github.com/karthikkrs.png?size=128', '2026-03-09T05:21:01.996055+00:00'),
  ('isolator', 'Isolator', 'Isolator MCP provides secure code execution capabilities for Python, Go, and JavaScript through Docker containerization. Built by Ompragash, it combines a TypeScript MCP server with a Go CLI tool that creates ephemeral containers with strict security constraints including network isolation, read-only filesystems, resource limits, and dropped Linux capabilities. The implementation supports both direct code execution and predefined code snippets, uses tar streaming to copy files into containers without bind mounts to avoid permission issues, and returns structured execution results with stdout, stderr, and status information, making it ideal for AI assistants that need to safely execute user-provided code in sandboxed environments.', '@ompragash', 'cloud', 'Unknown', 2, 'https://github.com/ompragash/isolator-mcp', NULL, 0, 'https://github.com/ompragash.png?size=128', '2026-03-09T05:21:01.996078+00:00'),
  ('israeli-bank-scrapers', 'Israeli Bank Scrapers', 'Israeli Bank MCP is a TypeScript server that connects AI assistants to Israeli banking data through the Model Context Protocol. It leverages the israeli-bank-scrapers library to provide secure access to transactions from all major Israeli banks and credit card companies. The server offers three main functionalities: listing available banks with their required credentials, fetching account transactions with flexible date ranges, and handling two-factor authentication. This implementation is particularly useful for financial analysis, expense tracking, and automated financial management across multiple Israeli financial institutions.', '@mottibec', 'development', 'Unknown', 23, 'https://github.com/mottibec/israeli-bank-mcp', NULL, 0, 'https://github.com/mottibec.png?size=128', '2026-03-09T05:21:01.996110+00:00'),
  ('israeli-land-authority', 'Israeli Land Authority', 'This MCP server provides AI assistants with access to Israeli Land Authority tender data through their public API, built using Python with FastMCP, Pydantic models, and comprehensive Hebrew text handling. The implementation offers eight core tools for searching land tenders with complex filtering (types, regions, dates, settlement codes), retrieving detailed tender information including guarantees and documents, accessing active tenders and recent results, obtaining geographic mapping data, and converting Hebrew settlement names to official Kod Yeshuv codes used by Israeli government systems. Built with automatic rate limiting, structured data validation, settlement code conversion utilities, and extensive test coverage including performance monitoring, it serves real estate developers tracking land opportunities in Israel, legal professionals monitoring tender publications and deadlines, and government contractors needing conversational access to Israeli Land Authority data without direct API integration.', '@barvhaim', 'development', 'Unknown', 14, 'https://github.com/barvhaim/remy-mcp', NULL, 0, 'https://github.com/barvhaim.png?size=128', '2026-03-09T05:21:01.996149+00:00'),
  ('issuebadge', 'IssueBadge', 'This MCP server provides a bridge between AI assistants and IssueBadge, enabling integration for issue tracking and badge management workflows. Built as a Node.js Express server using axios for HTTP requests, body-parser for request handling, and uuid for unique identifier generation, it facilitates communication between Claude and IssueBadge''s API endpoints. The implementation is designed for teams and developers who need AI-powered assistance with issue management, project tracking, and badge-based workflow automation within their development processes.', '@issuebadge', 'development', 'Unknown', 0, 'https://github.com/issuebadge/mcpserver', NULL, 0, 'https://github.com/issuebadge.png?size=128', '2026-03-09T05:21:01.996174+00:00'),
  ('mcp-advisor', 'MCP Advisor', 'MCP Advisor is a discovery and recommendation service that helps AI assistants find and understand available MCP services based on natural language queries. Built with a modular architecture, it supports multiple search backends including OceanBase for vector search and Meilisearch for text search, allowing users to explore MCP servers by semantic similarity. The implementation features flexible transport options (stdio, SSE, REST), comprehensive environment variable configuration, and GitHub README fetching capabilities, making it particularly useful for AI assistants that need to discover the right tools for specific tasks without leaving their conversation context.', '@istarwyh', 'development', 'Unknown', 82, 'https://github.com/istarwyh/mcpadvisor', '@xiaohui-wang/mcpadvisor', 9819, 'https://github.com/istarwyh.png?size=128', '2026-03-09T05:21:01.996199+00:00'),
  ('graphiti-pro', 'Graphiti Pro', 'Graphiti MCP Pro server implementation by itcook that provides AI assistants with persistent memory capabilities through a knowledge graph built on Neo4j, featuring episode-based memory storage, entity relationship tracking, and semantic search across nodes and facts with temporal metadata support. The implementation includes a comprehensive web-based management dashboard with real-time logging, token usage analytics, and configuration management, plus asynchronous task processing for memory operations with queue management and worker coordination. Built with FastAPI and React, it supports multiple LLM providers through OpenAI-compatible APIs, includes encrypted credential storage, and provides both HTTP and stdio transports, making it valuable for AI applications requiring long-term memory persistence, relationship discovery, and administrative oversight of memory operations across different conversation contexts and user groups.', '@itcook', 'productivity', 'Unknown', 38, 'https://github.com/itcook/graphiti-mcp-pro', NULL, 0, 'https://github.com/itcook.png?size=128', '2026-03-09T05:21:01.996311+00:00'),
  ('alchemy-sdk', 'Alchemy SDK', 'This MCP server implementation provides integration with the Alchemy SDK, enabling blockchain and NFT operations. It offers a range of tools including retrieving NFT metadata, fetching token balances, and querying blockchain data. The server is built using TypeScript and leverages the @modelcontextprotocol/sdk for MCP compatibility. It''s particularly useful for applications requiring blockchain data access and NFT-related functionalities within an MCP framework.', '@itsanishjain', 'development', 'Unknown', 0, 'https://github.com/itsanishjain/alchemy-sdk-mcp', NULL, 0, 'https://github.com/itsanishjain.png?size=128', '2026-03-09T05:21:01.996372+00:00'),
  ('litellm', 'LiteLLM', 'This LiteLLM MCP server integrates the LiteLLM library to provide a standardized interface for AI assistants to interact with OpenAI language models. Built using Python and leveraging libraries like Pydantic and FastAPI, it abstracts the complexities of the OpenAI API, handling authentication, request formatting, and response parsing. The server offers text completion capabilities with customizable parameters, enabling AI systems to generate human-like text across various applications. It''s designed for developers and researchers who need flexible access to state-of-the-art language models, facilitating use cases such as chatbots, content generation, and natural language processing tasks. The implementation''s focus on LiteLLM allows for potential future expansion to support additional model providers beyond OpenAI.', '@opencnid', 'communication', 'Unknown', 7, 'https://github.com/opencnid/mcp-server-litellm', NULL, 0, 'https://github.com/opencnid.png?size=128', '2026-03-09T05:21:01.996415+00:00'),
  ('vercel-ai', 'Vercel AI', 'This OpenAI and Mistral MCP server implementation leverages the Vercel AI SDK to provide a unified interface for interacting with multiple AI models. It supports OpenAI''s GPT-4 and GPT-3.5 series, as well as Mistral''s large and small models, offering features like structured output, system prompts, and safe prompts. Built with TypeScript and designed for Node.js environments, this server stands out by combining two leading AI providers in a single, easy-to-use package. It''s particularly useful for developers looking to integrate advanced language models into their applications, enabling seamless switching between providers and models to suit different use cases, from content generation to complex reasoning tasks.', '@opencnid', 'cloud', 'Unknown', 9, 'https://github.com/opencnid/mcp-vercel-ai', NULL, 0, 'https://github.com/opencnid.png?size=128', '2026-03-09T05:21:01.996439+00:00'),
  ('knowledge-graph', 'Knowledge Graph', 'Knowledge Graph Memory Server provides persistent memory for Claude through a local knowledge graph, allowing the AI to remember information across conversations. Developed by itseasy21 as a fork of the original Memory Server, it stores data as entities with observations and relations between them, enabling structured information retrieval and complex knowledge representation. The implementation supports customizable memory paths, cross-platform compatibility, and offers a comprehensive API for creating, updating, and querying graph elements, making it ideal for personalized chat experiences where context retention is essential.', '@itseasy21', 'communication', 'Unknown', 58, 'https://github.com/itseasy21/mcp-knowledge-graph', '@itseasy21/mcp-knowledge-graph', 20500, 'https://github.com/itseasy21.png?size=128', '2026-03-09T05:21:01.996477+00:00'),
  ('agent-knowledge', 'Agent Knowledge', 'This MCP server provides AI knowledge management capabilities through Elasticsearch integration, file system operations, and version control, offering 31 specialized tools across document indexing with schema validation, comprehensive file operations within sandboxed directories, and Git/SVN version control workflows. Built by the Agent Knowledge MCP Contributors using Python with strict security controls and configurable validation modes, it features auto-setup capabilities for Elasticsearch via Docker, document template creation for knowledge bases, path normalization and security restrictions, and flexible configuration management with backward compatibility for deprecated tools. The implementation supports cross-platform operations with robust error handling, making it valuable for building AI assistants that need structured knowledge storage, automated document management workflows, and version-controlled file operations without manual database or file system navigation.', '@itshare4u', 'databases', 'Unknown', 29, 'https://github.com/itshare4u/agentknowledgemcp', 'agent-knowledge-mcp', 37596, 'https://github.com/itshare4u.png?size=128', '2026-03-09T05:21:01.996489+00:00'),
  ('its-just-ui', 'its-just-ui', 'MCP server for the its-just-ui React component library that enables AI assistants to generate, customize, and document UI components through natural language interactions. Built with TypeScript and the MCP SDK, it provides tools for component generation with props and styling, form creation with validation, responsive layout generation, theme configuration, Tailwind CSS utility class generation, and comprehensive component documentation with accessibility information. The implementation includes a complete component registry covering core UI elements like buttons and inputs, data display components like tables and cards, and layout components like dialogs, making it valuable for developers who want AI-assisted React component development and UI prototyping workflows.', '@its-just-ui', 'development', 'Unknown', 4, 'https://github.com/its-just-ui/its-just-mcp', 'its-just-mcp', 790, 'https://github.com/its-just-ui.png?size=128', '2026-03-09T05:21:01.996521+00:00'),
  ('pyth-network', 'Pyth Network', 'Provides real-time access to Pyth Network''s decentralized oracle price feeds via the Hermes API, enabling access to 1,930+ price feeds across 107+ blockchains from 125+ first-party financial institutions. The server offers five core tools for searching price feeds, fetching latest prices, retrieving historical data, accessing publisher stake caps, and calculating time-weighted average prices (TWAP) with custom windows. Built by @itsomsarraf with both official MCP protocol and FastMCP implementations, it delivers clean parsed data by default (no binary clutter) and uses universal price feed IDs that work across all supported blockchains, making it ideal for trading bots, financial analysis, and autonomous systems requiring reliable market data.', '@itsomsarraf', 'development', 'Unknown', 4, 'https://github.com/itsomsarraf/pyth-network-mcp', NULL, 0, 'https://github.com/itsomsarraf.png?size=128', '2026-03-09T05:21:01.996554+00:00'),
  ('jmx-management', 'JMX Management', 'This JMX MCP server by itz4blitz bridges Java Management Extensions (JMX) with AI assistants, enabling natural language monitoring and management of Java applications through their exposed MBeans. The implementation provides comprehensive JMX operations as MCP tools (getAttribute, setAttribute, invoke operations) and exposes JMX attributes as dynamic resources, supporting both local JVM connections via the Attach API and remote JMX connections with authentication. Key differentiators include multi-connection support for managing multiple Java applications simultaneously, automatic MBean discovery with configurable filtering patterns, built-in security validation to prevent dangerous operations, and specialized configuration profiles for different deployment scenarios (STDIO for Claude Desktop, Docker for containerized environments, and production-ready remote monitoring setups), making it valuable for DevOps teams and Java developers who need AI-powered application monitoring, performance analysis, and operational management of JVM-based systems.', '@itz4blitz', 'cloud', 'Unknown', 8, 'https://github.com/itz4blitz/jmx-mcp', NULL, 0, 'https://github.com/itz4blitz.png?size=128', '2026-03-09T05:21:01.996701+00:00'),
  ('grareco-grammar-recommendations', 'GraReco (Grammar Recommendations)', 'MCP_GraReco is a server that provides AI assistants with grammar recommendation capabilities through the Anthropic Claude API. Built with TypeScript and Express, it processes text inputs using specialized prompts (elementary, standard, and timeline) to generate grammar corrections and recommendations. The server implements Server-Sent Events (SSE) for real-time communication, containerizes the application with Docker for easy deployment, and includes configurable parameters for the Anthropic model. This implementation is particularly valuable for users who need grammar assistance without leaving their AI assistant interface.', '@iuill', 'cloud', 'Unknown', 0, 'https://github.com/iuill/mcp_grareco', NULL, 0, 'https://github.com/iuill.png?size=128', '2026-03-09T05:21:01.996724+00:00'),
  ('apache-druid', 'Apache Druid', 'This MCP server provides AI assistants with direct access to Apache Druid cluster operations through 40+ specialized tools covering data querying, ingestion management, cluster monitoring, and administrative tasks. Built by iunera using Java Spring Boot with the Spring AI MCP framework, it connects to Druid''s REST APIs with support for SSL/TLS, basic authentication, and both STDIO and SSE transport modes, offering tools for SQL query execution including multi-stage queries, datasource and segment management, supervisor and task control, retention policy configuration, lookup management, compaction operations, and health monitoring with diagnostic capabilities. The implementation includes configurable prompt templates for operational guidance, Docker containerization, extensive integration tests with mock and real Druid clusters, and supports both development and production deployments with security configurations, making it valuable for data engineering workflows, cluster administration, and building AI assistants that need programmatic access to Druid analytics databases without manual web console navigation.', '@iunera', 'databases', 'Unknown', 11, 'https://github.com/iunera/druid-mcp-server', NULL, 0, 'https://github.com/iunera.png?size=128', '2026-03-09T05:21:01.996739+00:00'),
  ('unity-probuilder', 'Unity ProBuilder', 'Unity ProBuilder provides tools for Unity''s ProBuilder package, enabling AI agents to create and manipulate 3D geometry directly within Unity projects. Built by IvanMurzak, it exposes ProBuilder''s mesh editing capabilities including shape creation, face extrusion, edge beveling, geometry bridging, and material assignment through standardized interfaces. The implementation includes comprehensive mesh analysis tools and supports both primitive shape generation and custom polygonal modeling, making it valuable for level design, rapid prototyping, and procedural content generation workflows in Unity game development.', '@ivanmurzak', 'development', 'Unknown', 27, 'https://github.com/ivanmurzak/unity-ai-probuilder', NULL, 0, 'https://github.com/ivanmurzak.png?size=128', '2026-03-09T05:21:01.996788+00:00'),
  ('keyphrases', 'Keyphrases', 'A keyphrase extraction server that uses BERT-based sentence transformers and spaCy tokenization to identify and extract meaningful keyphrases from text documents. Built by Ivan Rublev, it leverages the KeyBERT library with multilingual MiniLM models for semantic understanding and supports customizable stop word filtering, configurable keyphrase counts, and GPU acceleration when available. The implementation includes comprehensive file access controls through directory allowlists, handles multiple text formats, and provides both CLI and HTTP server modes with Docker deployment support. Useful for content analysis, document summarization, SEO keyword research, or any application requiring automated extraction of key concepts from textual content.', '@ivanrublev', 'cloud', 'Unknown', 1, 'https://github.com/ivanrublev/keyphrases-mcp', 'keyphrases-mcp', 981, 'https://github.com/ivanrublev.png?size=128', '2026-03-09T05:21:01.996812+00:00'),
  ('expr-lang', 'Expr-Lang', 'MCP Expr-Lang provides a powerful expression evaluation tool for Claude Desktop, integrating the expr-lang engine for complex data manipulations directly within Claude conversations. Developed by Ivan Saorin, this Go-based server enables users to evaluate mathematical expressions, transform arrays and objects, perform string operations, and apply conditional logic through a simple interface. The implementation supports a wide range of operations from basic arithmetic to complex data sorting and filtering, making it particularly useful for data analysis, calculations, and transformations without leaving the AI assistant environment.', '@ivan-saorin', 'ai-ml', 'Unknown', 1, 'https://github.com/ivan-saorin/mcp-expr-lang', NULL, 0, 'https://github.com/ivan-saorin.png?size=128', '2026-03-09T05:21:01.996870+00:00'),
  ('html-to-pdf-generator', 'HTML-to-PDF Generator', 'This PDF generator MCP server combines PDFKit and Puppeteer to offer versatile PDF creation capabilities for AI assistants. It provides a streamlined interface for generating PDFs from various sources, including HTML content and programmatically defined layouts. The server abstracts away the complexities of PDF generation, allowing AI systems to create documents, reports, or web page snapshots without direct interaction with the underlying libraries. By integrating both PDFKit for fine-grained control and Puppeteer for web-based content, this implementation offers flexibility for a wide range of PDF generation use cases, from creating dynamic reports to archiving web content in PDF format.', '@ivarvd-hldng', 'ai-ml', 'Unknown', 1, 'https://github.com/ivarvd-hldng/pdf-generator-mcp-server', NULL, 0, 'https://github.com/ivarvd-hldng.png?size=128', '2026-03-09T05:21:01.996917+00:00'),
  ('new-relic-logs', 'New Relic Logs', 'This New Relic MCP server provides a bridge between AI assistants and New Relic''s log querying capabilities. Built with Python and leveraging libraries like httpx and FastMCP, it offers a tool for executing NRQL queries against New Relic logs. The implementation focuses on simplifying interactions with New Relic''s GraphQL API, making it accessible for AI models to analyze application logs and metrics. It''s particularly useful for tasks like performance monitoring, error tracking, or generating insights from log data, enabling assistants to query New Relic logs without requiring deep knowledge of the underlying API complexities.', '@ivlad003', 'productivity', 'Unknown', 28, 'https://github.com/ivlad003/mcp_newrelic', NULL, 0, 'https://github.com/ivlad003.png?size=128', '2026-03-09T05:21:01.996958+00:00'),
  ('contentful-management', 'Contentful Management', 'This MCP server, developed by ivo-toby, integrates with Contentful''s Content Management API to enable AI assistants to manage content across spaces and environments. It provides tools for CRUD operations on entries and assets, content type management, localization support, and publishing workflows. The implementation offers a visual inspector for debugging and testing. By connecting AI capabilities with Contentful''s headless CMS, this server empowers AI systems to handle complex content management tasks. It is particularly useful for applications in content creation, website management, or any scenario where an AI assistant needs to work with structured content in a headless CMS.', '@ivo-toby', 'development', 'Unknown', 61, 'https://github.com/ivo-toby/contentful-mcp', '@ivotoby/contentful-management-mcp-server', 11167, 'https://github.com/ivo-toby.png?size=128', '2026-03-09T05:21:01.997038+00:00'),
  ('apifox', 'Apifox', 'Provides comprehensive integration with Apifox API testing and documentation platform. Enables management of API endpoints, data schemas, folder organization, tags, and configuration settings through modular tools. Includes API documentation audit capabilities to enforce completeness standards. Supports multiple deployment methods including Docker, pip, and uv package managers with detailed setup documentation.', '@iwen-conf', 'cloud', 'Unknown', 27, 'https://github.com/iwen-conf/apifox-mcp', NULL, 0, 'https://github.com/iwen-conf.png?size=128', '2026-03-09T05:21:01.997174+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('btc', 'BTC', 'Retrieves real-time Bitcoin pricing information from the Binance API. Offers endpoints for current BTC prices, health monitoring, and available tool listing. Deployed as a web service with REST API access.', '@iworkist', 'ai-ml', 'Unknown', 0, 'https://github.com/iworkist/btcmcp', NULL, 0, 'https://github.com/iworkist.png?size=128', '2026-03-09T05:21:01.997197+00:00'),
  ('code-scanner', 'Code Scanner', 'Code Scanner Server is a versatile tool that analyzes source code to extract structural information like classes, functions, and variables across multiple programming languages (JavaScript, TypeScript, C#, PHP, Python, and CSS). It operates both as a CLI tool and an MCP server, respecting .gitignore rules while providing detailed output in XML, Markdown, or JSON formats. The implementation leverages Tree-sitter for robust parsing and offers flexible filtering options by definition type, modifiers, name patterns, and file paths, making it valuable for code exploration, documentation generation, and providing context to AI assistants about codebases.', '@ixe1', 'development', 'Unknown', 3, 'https://github.com/ixe1/code-scanner-server', NULL, 0, 'https://github.com/ixe1.png?size=128', '2026-03-09T05:21:01.997223+00:00'),
  ('pytorch-hud', 'PyTorch HUD', 'This PyTorch HUD API implementation provides a Python library and MCP server for accessing PyTorch''s CI/CD analytics data, enabling developers to investigate build failures and trunk health issues. Built with FastMCP, it offers tools for retrieving workflow and job information, analyzing large log files efficiently, executing ClickHouse queries against CI metrics, and monitoring resource utilization. The server exposes both synchronous and asynchronous functions through a standardized interface, making it valuable for PyTorch contributors debugging CI failures, investigating test flakiness, or analyzing performance trends across the CI infrastructure.', '@izaitsevfb', 'development', 'Unknown', 4, 'https://github.com/izaitsevfb/claude-pytorch-treehugger', NULL, 0, 'https://github.com/izaitsevfb.png?size=128', '2026-03-09T05:21:01.997250+00:00'),
  ('pluggable-knowledge-graph-memory', 'Pluggable Knowledge Graph Memory', 'This MCP server implementation provides a pluggable knowledge graph memory server, forked from the official version. It maintains the same interfaces as the original while offering enhanced flexibility through its pluggable architecture. The implementation is built using TypeScript and includes configuration for building, testing, and packaging the server. It''s designed for use cases requiring customizable knowledge graph storage and retrieval within MCP-compatible systems.', '@izumisy', 'development', 'Unknown', 54, 'https://github.com/izumisy/mcp-duckdb-memory-server', NULL, 0, 'https://github.com/izumisy.png?size=128', '2026-03-09T05:21:01.997278+00:00'),
  ('superfetch', 'SuperFetch', 'Fetches, extracts, and transforms web content using Mozilla Readability. Provides structured content extraction as JSONL semantic blocks, markdown conversion, hyperlink discovery with classification, and batch URL processing. Includes caching, SSRF protection, retry logic, and rate limiting.', '@j0hanz', 'search', 'Unknown', 0, 'https://github.com/j0hanz/fetch-url-mcp', NULL, 0, 'https://github.com/j0hanz.png?size=128', '2026-03-09T05:21:01.997388+00:00'),
  ('elasticsearch-knowledge-graph', 'Elasticsearch Knowledge Graph', 'This Elasticsearch-based knowledge graph implementation for MCP replaces the previous JSON file-based approach with a scalable, performant solution. It provides distributed storage for entities and relations, advanced search capabilities with fuzzy matching and relevancy ranking, and complete CRUD operations. The system tracks access patterns to prioritize recently viewed and important entities, simulating memory-like behavior where important, recent, and frequently accessed information rises to the top. Built with TypeScript and the Elasticsearch client, it includes tools for migration, management, and maintenance through a comprehensive admin CLI.', '@j3k0', 'development', 'Unknown', 18, 'https://github.com/j3k0/mcp-brain-tools', NULL, 0, 'https://github.com/j3k0.png?size=128', '2026-03-09T05:21:01.997421+00:00'),
  ('impart-agent-orchestrator', 'Impart Agent Orchestrator', 'An MCP server for AI agent orchestration that integrates Claude Code, Codex CLI, and Gemini CLI as specialized expert agents through the Vercel AI SDK framework. Provides three execution modes: synchronous calls for immediate results, asynchronous calls for non-blocking operations with task tracking, and batch processing for parallel agent execution. Each agent is configured as an expert (Advisor, Researcher, Explorer, Frontend Engineer, Document Writer) with specific system prompts, making it useful for complex workflows requiring multiple AI perspectives.', '@j3n5en', 'cloud', 'Unknown', 9, 'https://github.com/j3n5en/impart-mcp', NULL, 0, 'https://github.com/j3n5en.png?size=128', '2026-03-09T05:21:01.997468+00:00'),
  ('milestoner', 'Milestoner', 'Helps developers share their build-in-public journey by automatically pulling context from git history and generating milestone updates for social platforms. Analyzes recent commits, groups activity by day, and provides structured context for drafting platform-appropriate posts with optimal timing suggestions based on engagement research. Currently supports Bluesky with extensible platform architecture, includes post scheduling capabilities, and stores credentials securely with restricted file permissions.', '@j3r3my97', 'development', 'Unknown', 1, 'https://github.com/j3r3my97/milestoner', NULL, 0, 'https://github.com/j3r3my97.png?size=128', '2026-03-09T05:21:01.997491+00:00'),
  ('shared-knowledge-rag', 'Shared Knowledge RAG', 'Shared Knowledge MCP Server enables AI assistants to access and retrieve information from various vector stores, supporting RAG (Retrieval Augmented Generation) workflows. The implementation supports multiple vector store backends including HNSWLib, Weaviate, and others, with a flexible architecture that allows easy switching between them through environment variables. Built with TypeScript and LangChain, it provides a unified interface for knowledge retrieval regardless of the underlying storage technology, making it particularly valuable for applications that need to augment AI responses with domain-specific knowledge without requiring complex integration work for each vector database type.', '@j5ik2o', 'databases', 'Unknown', 4, 'https://github.com/j5ik2o/shared-knowledge-mcp', NULL, 0, 'https://github.com/j5ik2o.png?size=128', '2026-03-09T05:21:01.997503+00:00'),
  ('wiki-js', 'Wiki.js', 'MCP server implementation that provides AI assistants with comprehensive access to Wiki.js instances through GraphQL API integration, supporting both HTTP and stdio transports with Docker containerization. The implementation features full CRUD operations for wiki pages including search, retrieval by path or ID, creation, updating, deletion, and moving, plus page tree navigation and tag management, all with proper authentication via API keys and fallback mechanisms for GraphQL compatibility issues. Built with Python using FastMCP and httpx with extensive test coverage, it serves teams who need AI-powered wiki content management, documentation workflows, and knowledge base integration with robust error handling and production-ready deployment options through Docker Compose.', '@jaalbin24', 'cloud', 'Unknown', 9, 'https://github.com/jaalbin24/wikijs-mcp-server', NULL, 0, 'https://github.com/jaalbin24.png?size=128', '2026-03-09T05:21:01.997555+00:00'),
  ('mcp-reasoner', 'MCP Reasoner', 'This MCP reasoner, developed by Jacck, provides a systematic approach to problem-solving using beam search and thought evaluation. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers capabilities for exploring multiple solution paths, scoring thoughts, and managing tree-based reasoning states. The reasoner implements a configurable beam width, depth-limited search, and statistical analysis of the reasoning process. It''s designed for tackling complex problems that require step-by-step analysis, such as mathematical puzzles, logical deductions, and multi-stage planning tasks. This implementation is particularly valuable for enhancing AI assistants'' problem-solving abilities in scenarios requiring structured thinking and exploration of multiple solution strategies.', '@jacck', 'development', 'Unknown', 277, 'https://github.com/jacck/mcp-reasoner', NULL, 0, 'https://github.com/jacck.png?size=128', '2026-03-09T05:21:01.997586+00:00'),
  ('or-tools', 'OR-Tools', 'This MCP server implementation, developed by Jacck, integrates Google''s OR-Tools constraint programming solver with Large Language Models. It enables AI models to submit, validate, and solve constraint satisfaction and optimization problems using a standardized JSON-based model specification. The server supports integer and boolean variables, linear constraints using OR-Tools method syntax, and linear optimization objectives. It''s designed for use with Claude Desktop and can handle a variety of problem types including portfolio selection and knapsack problems. This implementation is particularly useful for AI-assisted decision making in logistics, resource allocation, and operations research, where complex constraints need to be modeled and solved efficiently.', '@jacck', 'productivity', 'Unknown', 17, 'https://github.com/jacck/mcp-ortools', NULL, 0, 'https://github.com/jacck.png?size=128', '2026-03-09T05:21:01.997628+00:00'),
  ('ticktick', 'TickTick', 'TickTick MCP Server provides integration with the TickTick task management API, enabling AI assistants to create, read, update, and delete tasks and projects. The implementation handles OAuth2 authentication flow with automatic token refresh, securely storing credentials in environment variables. Built by Jaesung Park, it features a comprehensive client that abstracts away API complexities and includes a CLI utility for easy authentication setup. This server is ideal for productivity workflows that need to programmatically manage tasks, track projects, or automate task creation based on AI-generated content.', '@jacepark12', 'productivity', 'Unknown', 256, 'https://github.com/jacepark12/ticktick-mcp', NULL, 0, 'https://github.com/jacepark12.png?size=128', '2026-03-09T05:21:01.997668+00:00'),
  ('slack-cli', 'Slack CLI', 'Provides a command-line interface and server for comprehensive Slack workspace management. Supports full CRUD operations on channels, messages, users, files, and reactions with JSON-first structured output designed for reliable LLM agent interaction. Features automatic pagination, rate limit retries with backoff, structured error codes, and a read-only mode that prevents accidental write operations. Installable via Homebrew, go install, or building from source.', '@jackchuka', 'development', 'Unknown', 2, 'https://github.com/jackchuka/slackcli', NULL, 0, 'https://github.com/jackchuka.png?size=128', '2026-03-09T05:21:01.997721+00:00'),
  ('ai-group-markdown-to-word', 'AI Group Markdown to Word', 'Converts Markdown documents to professionally formatted Word (.docx) files with comprehensive styling capabilities. Supports mathematical formulas, table processing with preset styles, local and remote image embedding, headers and footers with page numbers, table of contents generation, and watermarks. Provides both STDIO and Streamable HTTP transports for flexible integration.', '@jackdark425', 'ai-ml', 'Unknown', 8, 'https://github.com/jackdark425/aigroup-mdtoword-mcp', NULL, 0, 'https://github.com/jackdark425.png?size=128', '2026-03-09T05:21:01.997755+00:00'),
  ('aruba-email-calendar', 'Aruba Email & Calendar', 'Integrates with Aruba email services via IMAP, SMTP, and CalDAV protocols. Enables reading, searching, and sending emails through Aruba''s Italian hosting platform. Supports secure SSL/TLS connections with local credential storage.', '@jackfioru92', 'communication', 'Unknown', 2, 'https://github.com/jackfioru92/mcp-aruba-email', NULL, 0, 'https://github.com/jackfioru92.png?size=128', '2026-03-09T05:21:01.997775+00:00'),
  ('looking-glass', 'Looking Glass', 'This MCP server provides network probing capabilities through Looking Glass (LG) vantage points, enabling AI assistants to perform ping, traceroute, and BGP queries from distributed network locations worldwide. Built by Jackie-shi using Python with FastMCP and httpx, it offers three core tools: user-defined VP selection for targeted probing from specific network locations, automatic VP selection where the platform chooses optimal vantage points based on quantity requirements, and comprehensive LG listing to discover available network measurement points. The implementation connects to a local API service running on localhost:44332 that manages the actual network probing operations, includes a comprehensive database of LG endpoints with their specific command formats and ASN information covering major ISPs and hosting providers globally, and features robust error handling with extended timeouts for network operations, making it valuable for network troubleshooting workflows, connectivity analysis, BGP route investigation, and building AI assistants that need programmatic access to distributed network measurement capabilities without manual Looking Glass interface navigation.', '@jackie-shi', 'databases', 'Unknown', 4, 'https://github.com/jackie-shi/looking-glass-mcp', NULL, 0, 'https://github.com/jackie-shi.png?size=128', '2026-03-09T05:21:01.997788+00:00'),
  ('biorxiv', 'bioRxiv', 'This MCP server provides a specialized interface for searching and retrieving scientific articles from bioRxiv, a popular preprint server for biological sciences. Built with Python using the FastMCP framework, it offers three main tools: keyword-based searching, advanced searching with multiple parameters (including author, date range, and section filters), and metadata retrieval using DOIs. The implementation handles asynchronous processing through asyncio and includes comprehensive error handling and logging, making it particularly useful for researchers, AI assistants, and applications that need programmatic access to the latest biological research preprints.', '@jackkuo666', 'development', 'Unknown', 21, 'https://github.com/jackkuo666/biorxiv-mcp-server', NULL, 0, 'https://github.com/jackkuo666.png?size=128', '2026-03-09T05:21:01.997816+00:00'),
  ('medrxiv-research', 'medRxiv Research', 'This MCP server provides a specialized interface for searching and retrieving medical research articles from medRxiv, a preprint server for health sciences. Built with Python using the FastMCP framework, it offers three main tools: keyword-based article searching, advanced searching with multiple parameters (including author, date range, and section filters), and metadata retrieval using DOIs. The implementation handles asynchronous processing through asyncio and includes comprehensive error handling and logging, making it particularly useful for AI assistants and researchers needing to access up-to-date medical research without leaving their workflow.', '@jackkuo666', 'ai-ml', 'Unknown', 7, 'https://github.com/jackkuo666/medrxiv-mcp-server', NULL, 0, 'https://github.com/jackkuo666.png?size=128', '2026-03-09T05:21:01.997900+00:00'),
  ('codechecker', 'CodeChecker', 'CodeChecker MCP is a code review tool designed for integration with Cursor IDE, leveraging OpenAI''s GPT models for intelligent code analysis. Developed by Jack Landis, it offers real-time code review capabilities, supporting both SSE and stdio transport modes. The server analyzes code snippets against provided context, offering specific improvement suggestions and determining if the code meets stated goals. It''s particularly useful for developers seeking AI-assisted code reviews within their IDE workflow.', '@jacklandis29', 'development', 'Unknown', 3, 'https://github.com/jacklandis29/codechecker-mcp', NULL, 0, 'https://github.com/jacklandis29.png?size=128', '2026-03-09T05:21:01.997983+00:00'),
  ('pullpush-reddit', 'PullPush Reddit', 'Provides access to Reddit''s historical data through the PullPush.io API, enabling search across comments and submissions without requiring authentication. The server implements two core tools for searching Reddit content with flexible filtering options including subreddit, author, date ranges, score thresholds, and keyword queries. Built with TypeScript and featuring an auto-registration system for modular tool loading, it''s particularly useful for researchers, content creators, or developers who need to analyze Reddit discussions, track user activity, or gather historical social media data that may no longer be available through Reddit''s official API.', '@jacklenzotti', 'development', 'Unknown', 0, 'https://github.com/jacklenzotti/pullpush-mcp', NULL, 0, 'https://github.com/jacklenzotti.png?size=128', '2026-03-09T05:21:01.998014+00:00'),
  ('actionkit-slack', 'ActionKit (Slack)', 'ActionKit MCP server enables Claude Desktop to interact with Slack through ActionKit''s API. Built with TypeScript and JWT authentication, it filters available actions to Slack-specific tools and handles user authentication through the Paragon Connect Portal. This implementation is particularly valuable for users who want to automate Slack operations directly through Claude without managing separate API credentials.', '@jackmuva', 'development', 'Unknown', 1, 'https://github.com/jackmuva/mcp-actionkit', NULL, 0, 'https://github.com/jackmuva.png?size=128', '2026-03-09T05:21:01.998039+00:00'),
  ('m-pesa-daraja', 'M-Pesa Daraja', 'Provides access to Safaricom''s M-Pesa Daraja API documentation through a comprehensive implementation that includes both a Python web scraper for extracting documentation and a TypeScript server for serving it. The scraper authenticates with and downloads complete documentation for Daraja APIs covering payment processing, transaction management, and business operations, converting HTML to markdown with local image references. The server offers search capabilities with API categorization, complete documentation retrieval, enhanced summaries with endpoints, multi-API comparison tools, and usage statistics tracking, making it ideal for developers building M-Pesa integrations in Kenya''s mobile money ecosystem.', '@jackscodevault', 'development', 'Unknown', 14, 'https://github.com/jackscodevault/mpesa-daraja-mcp', NULL, 0, 'https://github.com/jackscodevault.png?size=128', '2026-03-09T05:21:01.998068+00:00'),
  ('page-image-scanner', 'Page/Image Scanner', 'This MCP server provides scanner integration through the SANE (Scanner Access Now Easy) framework, enabling document capture with support for ADF (Automatic Document Feeder), duplex scanning, and configurable page sizes. Built with TypeScript and featuring both stdio and HTTP transports, it offers tools for device discovery, scan job management with real-time status tracking, and automatic document assembly from individual pages into multi-page TIFF files. The implementation includes intelligent device selection that prefers ADF-capable scanners over cameras, configurable document break policies for batch processing, and comprehensive job tracking with manifest files and event logs, making it valuable for digitizing physical documents, automating batch scanning workflows, and building document management systems that require programmatic scanner control.', '@jacksenechal', 'development', 'Unknown', 5, 'https://github.com/jacksenechal/scan-mcp', 'scan-mcp', 462, 'https://github.com/jacksenechal.png?size=128', '2026-03-09T05:21:01.998097+00:00'),
  ('obsidian-tools', 'Obsidian Tools', 'This Obsidian MCP tools collection, developed by 2XR, provides a set of Model Context Protocol utilities tailored for integration with the Obsidian note-taking application. Built using TypeScript and leveraging modern JavaScript features, it offers a modular structure with workspaces for different tools. The implementation focuses on enhancing Obsidian''s capabilities through AI-powered functionalities, potentially including features like intelligent note linking, content generation, or knowledge graph analysis. By bridging Obsidian''s powerful note organization system with MCP''s standardized AI communication, this toolkit enables users to augment their personal knowledge management workflows with advanced AI assistance. It is particularly suited for researchers, writers, and knowledge workers looking to leverage AI within their existing Obsidian setups for tasks such as information synthesis, idea generation, and content organization.', '@jacksteamdev', 'development', 'Unknown', 629, 'https://github.com/jacksteamdev/obsidian-mcp-tools', NULL, 0, 'https://github.com/jacksteamdev.png?size=128', '2026-03-09T05:21:01.998132+00:00'),
  ('workato', 'Workato', 'Workato MCP Server provides a bridge between Claude and the Workato automation platform API, enabling AI assistants to manage integration recipes, connections, and workflows. Built with TypeScript, it implements over 20 tools for operations like listing and creating recipes, managing connections, organizing folders, monitoring jobs, and working with tags. The server authenticates with Workato using an API token and transforms all responses into a consistent format, making it ideal for automating integration workflows, monitoring recipe execution, and managing integration assets directly from AI conversations without switching contexts.', '@jacobgoren-sb', 'development', 'Unknown', 3, 'https://github.com/jacobgoren-sb/workato-mcp-server', NULL, 0, 'https://github.com/jacobgoren-sb.png?size=128', '2026-03-09T05:21:01.998169+00:00'),
  ('memex', 'Memex', 'MEMEX is an MCP server for managing a knowledge base of technical guides and contexts (prompts/personas/conventions), inspired by Vannevar Bush''s vision of augmented memory. Built in PHP with Symfony components, it provides tools for creating, retrieving, updating, deleting, listing, and semantically searching markdown-based content stored in a local file system structure. The implementation uses vector embeddings for semantic search capabilities and supports both guides (technical documentation) and contexts (AI prompts and personas), making it useful for developers and teams who want to maintain and query their accumulated knowledge and AI interaction patterns through a structured, searchable interface.', '@jacquesbh', 'ai-ml', 'Unknown', 6, 'https://github.com/jacquesbh/memex-mcp', NULL, 0, 'https://github.com/jacquesbh.png?size=128', '2026-03-09T05:21:01.998216+00:00'),
  ('web-fetcher', 'Web Fetcher', 'Fetcher MCP is a server that enables AI assistants to retrieve web page content using Playwright''s headless browser capabilities. It excels at handling dynamic JavaScript-heavy websites by executing client-side code, and includes intelligent content extraction through Mozilla''s Readability algorithm to remove ads and non-essential elements. The implementation offers both single URL and batch fetching tools, supports HTML or Markdown output formats, and automatically blocks unnecessary resources like images and stylesheets to improve performance. This tool is particularly valuable for research workflows, content analysis, and information gathering that requires processing of modern web applications.', '@jae-jae', 'development', 'Unknown', 1002, 'https://github.com/jae-jae/fetcher-mcp', 'fetcher-mcp', 157281, 'https://github.com/jae-jae.png?size=128', '2026-03-09T05:21:01.998247+00:00'),
  ('climatiq', 'Climatiq', 'Climatiq MCP Server provides a bridge to the Climatiq API for calculating carbon emissions across various domains like electricity usage, travel, cloud computing, and procurement. Built by Jagan Shanmugam, it exposes a rich set of tools that enable AI assistants to perform precise carbon footprint calculations using detailed emission factors from the Climatiq database. The implementation is particularly valuable for organizations and individuals seeking to understand and quantify their environmental impact through standardized, data-driven carbon measurement.', '@jagan-shanmugam', 'databases', 'Unknown', 8, 'https://github.com/jagan-shanmugam/climatiq-mcp-server', NULL, 0, 'https://github.com/jagan-shanmugam.png?size=128', '2026-03-09T05:21:01.998311+00:00'),
  ('qwen-code', 'Qwen Code', 'A Model Context Protocol server that bridges AI assistants with Qwen''s code analysis capabilities through the Qwen CLI. Built by Jaggerxtrm, it provides three main tools: ask-qwen for querying Qwen AI with file reference support using @filename syntax, plus simple ping and help utilities. The implementation features automatic model fallback from primary to backup models on quota errors, sandbox mode for safe code execution, configurable approval modes (plan/default/auto-edit/yolo), and progress tracking with timeout handling. Useful for AI-assisted code review, codebase exploration, automated refactoring workflows, and integrating Qwen''s large context window capabilities into development environments.', '@jaggerxtrm', 'development', 'Unknown', 3, 'https://github.com/jaggerxtrm/qwen-mcp-tool', '@jaggerxtrm/qwen-mcp-tool', 215, 'https://github.com/jaggerxtrm.png?size=128', '2026-03-09T05:21:01.998339+00:00'),
  ('stack-exchange', 'Stack Exchange', 'Stack Exchange MCP Server provides a bridge between AI assistants and Stack Exchange sites like StackOverflow, enabling search and retrieval of questions, answers, and tags. The server implements caching to reduce API calls, formats content for LLM consumption, and handles rate limiting to stay within Stack Exchange API constraints. It exposes endpoints for searching questions, retrieving question details with answers, listing available Stack Exchange sites, and fetching popular tags, making it valuable for developers seeking programming help or technical information without leaving their AI assistant interface.', '@jagreetdg', 'ai-ml', 'Unknown', 2, 'https://github.com/jagreetdg/re-stack-mcp', NULL, 0, 'https://github.com/jagreetdg.png?size=128', '2026-03-09T05:21:01.998385+00:00'),
  ('jmap-fastmail', 'JMAP (Fastmail)', 'JMAP-MCP is a connector that enables AI assistants to read and search emails through the JMAP (JSON Mail Access Protocol) standard, specifically designed for integration with Fastmail servers. Built by Jahfer Husain, the implementation provides three core tools: retrieving mailbox lists, searching emails with extensive filtering options including date ranges, keywords, attachments, and full-text search, and fetching complete email content including text and HTML bodies. The server handles complex email operations like thread collapsing, cross-mailbox searches, and blob content downloading, making it valuable for users who want conversational access to their email data without manual inbox management or complex JMAP API interactions.', '@jahfer', 'communication', 'Unknown', 5, 'https://github.com/jahfer/jmap-mcp-server', '@jahfer/jmap-mcp-server', 507, 'https://github.com/jahfer.png?size=128', '2026-03-09T05:21:01.998421+00:00'),
  ('json-schema-manager', 'JSON Schema Manager', 'This JSON Schema MCP Server manages JSON schemas and generates instances from them, providing a structured way to create, store, and retrieve schemas with custom properties. Built with FastMCP, it offers resources for accessing specific schemas by ID and listing all available schemas, along with tools for creating new schemas with customizable properties and generating JSON instances with default or user-provided values. The implementation stores schemas as JSON files with unique IDs, making it ideal for applications that need to maintain consistent data structures or generate template-based JSON documents.', '@jaho5', 'ai-ml', 'Unknown', 4, 'https://github.com/jaho5/json-schema-mcp', NULL, 0, 'https://github.com/jaho5.png?size=128', '2026-03-09T05:21:01.998464+00:00'),
  ('deno-playwright', 'Deno Playwright', 'This Playwright-based MCP server, developed by Jake Dahn, provides browser automation capabilities for AI assistants. It integrates with the Playwright library to offer tools for web navigation, interaction, and data extraction. The server exposes functions like page navigation, element clicking, form filling, and JavaScript execution as MCP tools. By connecting AI capabilities with browser automation, this implementation enables assistants to perform web-based tasks, gather information from websites, and interact with web applications. It is particularly useful for applications requiring web scraping, automated testing, or any scenario where an AI system needs to navigate and interact with web content programmatically.', '@jakedahn', 'development', 'Unknown', 12, 'https://github.com/jakedahn/deno2-playwright-mcp-server', NULL, 0, 'https://github.com/jakedahn.png?size=128', '2026-03-09T05:21:01.998519+00:00'),
  ('codegraph', 'CodeGraph', 'This MCP server provides high-performance code intelligence and semantic search capabilities through a Rust-based architecture that integrates RocksDB for graph storage, FAISS for vector indexing, and tree-sitter for AST parsing across multiple programming languages. Built with a focus on scalability and performance, it features real-time code analysis with incremental updates, multi-agent coordination through WebSocket transport, embedding generation with support for both local models and OpenAI APIs, and comprehensive monitoring with Prometheus metrics and Grafana dashboards. The implementation includes production-ready deployment configurations with Docker containerization, Kubernetes manifests, automated backup systems, and security hardening, making it suitable for large-scale code analysis workflows, AI-assisted development tools, and enterprise code intelligence platforms that require fast semantic search across extensive codebases.', '@jakedismo', 'cloud', 'Unknown', 152, 'https://github.com/jakedismo/codegraph-rust', NULL, 0, 'https://github.com/jakedismo.png?size=128', '2026-03-09T05:21:01.998545+00:00'),
  ('kuzumem', 'KuzuMem', 'KuzuMem-MCP provides distributed graph memory bank storage for coding agents using KuzuDB, built with TypeScript and featuring a comprehensive workflow state machine that enforces structured development phases (ANALYZE, BLUEPRINT, CONSTRUCT, VALIDATE, ROLLBACK). The implementation offers 12 unified tools for managing architectural decisions, component dependencies, file tracking, and context logging, with specialized agent modes for different development roles (architect, code, debug) and AI-powered memory optimization using OpenAI and Anthropic models. Features include graph algorithms for dependency analysis, cycle detection, full-text search across entities, and persistent memory across sessions, making it valuable for teams building complex software systems where maintaining architectural context and decision history across multiple AI agents is critical for long-term project success.', '@jakedismo', 'development', 'Unknown', 26, 'https://github.com/jakedismo/kuzumem-mcp', NULL, 0, 'https://github.com/jakedismo.png?size=128', '2026-03-09T05:21:01.998590+00:00'),
  ('master-mcp-proxy', 'Master MCP Proxy', 'Master MCP Server is a production-ready OAuth-enabled proxy that aggregates multiple MCP backends into a unified interface with advanced routing, load balancing, and authentication capabilities. Built with TypeScript for both Node.js and Cloudflare Workers runtimes, it features circuit breakers, retry policies, health-based load balancing, delegated OAuth flows for GitHub/Google integration, encrypted token storage, and comprehensive monitoring with metrics collection. The implementation supports multi-server deployments with Docker/Koyeb configurations, provides a complete OAuth web interface for authorization flows, and includes security hardening with audit logging and input validation, making it ideal for enterprise environments that need to expose multiple MCP services through a single authenticated gateway with high availability and resilience.', '@jakedismo', 'cloud', 'Unknown', 2, 'https://github.com/jakedismo/master-mcp-server', NULL, 0, 'https://github.com/jakedismo.png?size=128', '2026-03-09T05:21:01.998617+00:00'),
  ('cli-exec', 'CLI Exec', 'This MCP server implementation provides powerful CLI command execution capabilities, enabling structured output for shell commands. Developed by Model Context Protocol, it offers tools for executing raw and chained commands in specific working directories, with features like timeout handling, ANSI code stripping, and comprehensive error management. The server is designed for use cases requiring programmatic access to shell operations, such as automated system administration, DevOps workflows, or integrating command-line tools into AI-assisted processes.', '@jakenuts', 'development', 'Unknown', 9, 'https://github.com/jakenuts/mcp-cli-exec', 'mcp-cli-exec', 5411, 'https://github.com/jakenuts.png?size=128', '2026-03-09T05:21:01.998643+00:00'),
  ('solarwinds-observability-logs', 'SolarWinds Observability Logs', 'This MCP server implementation provides integration with SolarWinds Observability logs. Developed by jakenuts, it offers tools for searching and visualizing log data, including advanced filtering options and customizable time ranges. The server is designed to facilitate log analysis and monitoring within the MCP ecosystem, making it particularly useful for DevOps and IT operations teams working with SolarWinds Observability.', '@jakenuts', 'search', 'Unknown', 3, 'https://github.com/jakenuts/mcp-solarwinds', 'mcp-solarwinds', 5427, 'https://github.com/jakenuts.png?size=128', '2026-03-09T05:21:01.998691+00:00'),
  ('umami-analytics', 'Umami Analytics', 'This MCP server implementation provides a bridge to Umami analytics data, enabling AI assistants to analyze website performance and user behavior. Developed by jakeyShakey, it offers tools for retrieving website statistics, metrics, pageview data, and user session information. The server integrates with the Umami API and incorporates semantic search capabilities for efficient analysis of user journeys. It also features web crawling functionality to capture screenshots and HTML source code of webpages. Built with Python and designed for easy setup within Claude Desktop, this implementation is particularly useful for generating data-driven insights, creating custom analytics dashboards, and improving website performance based on user interaction patterns.', '@jakeyshakey', 'development', 'Unknown', 7, 'https://github.com/jakeyshakey/umami_mcp_server', NULL, 0, 'https://github.com/jakeyshakey.png?size=128', '2026-03-09T05:21:01.998777+00:00'),
  ('fortnox', 'Fortnox', 'An MCP server for integrating with the Fortnox Swedish accounting system. Enables LLMs to interact with Fortnox for managing invoices, customers, suppliers, orders, accounts, vouchers, and provides business intelligence analytics. Supports both a hosted remote mode (via Vercel with OAuth browser authorization) and a local self-hosted mode using your own Fortnox API credentials.', '@erp-mafia', 'cloud', 'Unknown', 10, 'https://github.com/erp-mafia/fortnox-mcp', NULL, 0, 'https://github.com/erp-mafia.png?size=128', '2026-03-09T05:21:01.998794+00:00'),
  ('sage-gemini-2-5-pro', 'Sage (Gemini 2.5 Pro)', 'MCP-Sage provides tools for sending prompts to Gemini 2.5 Pro with full context from specified files and directories. It implements two key tools: ''second-opinion'' for getting alternative perspectives on code with complete file context, and ''expert-review'' for receiving code improvement suggestions formatted as SEARCH/REPLACE blocks. Built to complement Claude Code''s limited context window, this TypeScript implementation handles file packing, token counting, and gitignore-aware recursive directory traversal, making it particularly valuable for developers seeking second opinions or detailed code reviews on complex codebases.', '@jalehman', 'development', 'Unknown', 7, 'https://github.com/jalehman/mcp-sage', NULL, 0, 'https://github.com/jalehman.png?size=128', '2026-03-09T05:21:01.998882+00:00'),
  ('chessagine-stockfish', 'ChessAgine (Stockfish)', 'ChessAgine provides deep chess analysis capabilities through integration with the Stockfish engine and positional evaluation tools. Built by Jalp using the Mastra framework, it offers engine analysis, theme-based position scoring across material/mobility/space/positional/king safety dimensions, variation comparison, and detailed board state analysis with pawn structure evaluation and piece attack/defense relationships. The implementation generates natural language descriptions of chess positions and tracks how strategic themes evolve across move sequences, making it valuable for chess coaching, game analysis, educational content creation, and building chess-aware applications that provide meaningful strategic insights beyond basic move suggestions.', '@jalpp', 'development', 'Unknown', 19, 'https://github.com/jalpp/chessagine-mcp', NULL, 0, 'https://github.com/jalpp.png?size=128', '2026-03-09T05:21:01.998915+00:00'),
  ('journald', 'journald', 'Provides programmatic access to systemd journal logs through MCP resources and tools. Supports filtering by unit, identifier, message content, and time ranges. Features natural language datetime parsing for queries like ''yesterday at 3pm'' or ''2 hours ago''.', '@james116blue', 'development', 'Unknown', 1, 'https://github.com/james116blue/journald-mcp-server', NULL, 0, 'https://github.com/james116blue.png?size=128', '2026-03-09T05:21:01.998971+00:00'),
  ('magic-the-gathering', 'Magic: The Gathering', 'This Magic: The Gathering MCP server, developed by james2037, provides a robust interface for accessing card data, rules, and set information. Built with PHP and leveraging the MTG SDK, it offers tools for card searches, detailed card information retrieval, and access to comprehensive rules. The implementation stands out by combining multiple MTG data sources into a unified MCP interface, making it ideal for AI assistants or applications needing quick access to MTG information. It''s particularly useful for tasks like deck building, rules clarification, or card analysis, enabling programmatic access to MTG data without requiring deep knowledge of individual APIs or data sources.', '@james2037', 'development', 'Unknown', 2, 'https://github.com/james2037/mcp-gatherer', NULL, 0, 'https://github.com/james2037.png?size=128', '2026-03-09T05:21:01.999005+00:00'),
  ('tlon-urbit-messenger', 'Tlon Urbit Messenger', 'Tlon MCP Server provides a bridge between AI assistants and Urbit''s social networking services, enabling direct message communication through Tlon''s agents. Built using FastMCP and the Urbit HTTP API, it offers tools for sending direct messages, retrieving conversation history, and managing contacts with support for both ship IDs and human-readable nicknames. The server handles authentication to Urbit ships, resolves nicknames to proper ship addresses, and formats message data for readability. It''s particularly valuable for users who want to interact with their Urbit communications through natural language interfaces without managing the complexities of Urbit''s addressing system directly.', '@jamesacklin', 'ai-ml', 'Unknown', 5, 'https://github.com/jamesacklin/tlon-mcp-server', NULL, 0, 'https://github.com/jamesacklin.png?size=128', '2026-03-09T05:21:01.999054+00:00'),
  ('prediction-markets-polymarket-predictit-kalshi', 'Prediction Markets (Polymarket, PredictIt, Kalshi)', 'A prediction market server that provides real-time data from Polymarket, PredictIt, and Kalshi through three core functions: fetching Polymarket markets with calculated odds and keyword filtering, retrieving open PredictIt markets with contract pricing, and accessing Kalshi events data. Built with TypeScript and superagent for HTTP requests, it includes comprehensive type definitions for each platform''s API responses and automatically filters for active markets only. The server calculates probability odds for Polymarket tokens and includes a postinstall setup script for Claude integration, making it useful for market analysis, trading research, and building prediction market applications that need unified access to multiple platforms.', '@jamesanz', 'development', 'Unknown', 32, 'https://github.com/jamesanz/prediction-market-mcp', 'prediction-markets-mcp', 671, 'https://github.com/jamesanz.png?size=128', '2026-03-09T05:21:01.999086+00:00'),
  ('us-legal', 'US Legal', 'A US legal data MCP server that provides access to multiple government legal databases including Congress.gov for bills and votes, Federal Register for regulatory documents, US Code sections, CourtListener for judicial opinions, and Regulations.gov for public comments. Built by James Sangalli, it implements intelligent relevance scoring algorithms to filter and rank search results across different legal document types, with support for API keys where required and graceful error handling for various government API limitations. The server enables AI assistants to research legislation, track regulatory changes, analyze court decisions, and explore legal precedents, making it useful for legal research, policy analysis, compliance monitoring, and educational applications in law and government.', '@jamesanz', 'databases', 'Unknown', 16, 'https://github.com/jamesanz/us-legal-mcp', NULL, 0, 'https://github.com/jamesanz.png?size=128', '2026-03-09T05:21:01.999098+00:00'),
  ('m-pesa-safaricom-daraja-api', 'M-Pesa (Safaricom Daraja API)', 'DarajaMCP provides a bridge to the Safaricom M-Pesa mobile payment API, enabling AI assistants to initiate STK Push transactions directly from conversations. Built on FastMCP, it handles authentication with the Daraja API and manages the complete payment flow, from generating access tokens to processing transaction requests. The implementation is particularly valuable for applications requiring seamless mobile payment integration in Kenya, allowing users to authorize payments on their mobile devices without leaving their conversation with an AI assistant.', '@jameskanyiri', 'ai-ml', 'Unknown', 14, 'https://github.com/jameskanyiri/darajamcp', NULL, 0, 'https://github.com/jameskanyiri.png?size=128', '2026-03-09T05:21:01.999141+00:00'),
  ('tavily', 'Tavily', 'Tavily MCP server that provides AI assistants with access to Tavily''s web intelligence platform through four core tools: search for real-time web queries with filtering by topic, time range, and domains; extract for pulling content from specific URLs; crawl for structured website exploration following internal links with configurable depth and breadth; and map for discovering site architecture and navigation paths. Built by jameskanyiri with comprehensive parameter support including country-specific search boosting, content format options (markdown/text), domain filtering, and extraction depth controls, the implementation uses FastAPI with SSE and StreamableHTTP transports for flexible client integration. Designed for AI applications requiring robust web research capabilities, competitive intelligence gathering, content discovery workflows, and website analysis tasks where structured crawling and extraction are preferred over simple search results.', '@jameskanyiri', 'productivity', 'Unknown', 1, 'https://github.com/jameskanyiri/tavily_mcp_server', NULL, 0, 'https://github.com/jameskanyiri.png?size=128', '2026-03-09T05:21:01.999193+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('monkey', 'Monkey', 'MonkeyMCP is a .NET 9.0 server implementation that provides access to monkey data through a simple API. It features two main tools: GetMonkeys for retrieving a complete list of monkeys and GetMonkey for finding specific monkeys by name. The implementation uses System.Text.Json for serialization and includes a caching mechanism for improved performance. Built with Microsoft.Extensions.Hosting, it demonstrates how to create custom MCP tools with proper documentation and dependency injection, making it ideal for developers looking to build their own MCP servers or integrate monkey data into AI assistants.', '@jamesmontemagno', 'development', 'Unknown', 120, 'https://github.com/jamesmontemagno/monkeymcp', NULL, 0, 'https://github.com/jamesmontemagno.png?size=128', '2026-03-09T05:21:01.999219+00:00'),
  ('draw-things', 'Draw Things', 'Integrates with the Draw Things application to provide local AI image generation capabilities on Apple Silicon Macs. Supports text-to-image generation and image-to-image transformations using locally loaded Stable Diffusion models. Provides tools for checking API status, retrieving configuration, and generating images with configurable parameters including dimensions, steps, guidance scale, and seed control.', '@james-see', 'ai-ml', 'Unknown', 2, 'https://github.com/james-see/mcp-drawthings', NULL, 0, 'https://github.com/james-see.png?size=128', '2026-03-09T05:21:01.999252+00:00'),
  ('wordpress-trac', 'WordPress Trac', 'This MCP server provides AI assistants with access to WordPress.org Trac data through public CSV and RSS endpoints, built by James LePage using TypeScript and deployed on Cloudflare Workers for global edge performance. The implementation offers five core tools for searching through 60,000+ WordPress tickets with intelligent filtering, retrieving detailed ticket information including metadata and comments, accessing changeset information with full diff content, monitoring recent development activity through timeline feeds, and extracting project metadata like components and milestones. Built with custom XML-RPC client implementation, robust CSV parsing with fallback mechanisms, HTML scraping for changeset data, and WordPress-branded UI styling, it serves WordPress core contributors needing conversational access to development history, plugin developers researching similar issues and solutions, and AI assistants requiring comprehensive WordPress ecosystem knowledge for development guidance and issue tracking.', '@jameswlepage', 'cloud', 'Unknown', 9, 'https://github.com/jameswlepage/trac-mcp', NULL, 0, 'https://github.com/jameswlepage.png?size=128', '2026-03-09T05:21:01.999278+00:00'),
  ('defectdojo', 'DefectDojo', 'DefectDojo MCP server provides a bridge to the DefectDojo vulnerability management system, enabling AI assistants to interact with security findings, products, and engagements. Developed by jamiesonio, this implementation offers tools for retrieving, searching, and updating vulnerability data through an asynchronous HTTP client that handles authentication and error management. The server exposes specialized functions for managing security findings (including status updates and note addition), listing products, and handling engagement lifecycle operations. Built with Python 3.12 and the FastMCP framework, it''s particularly valuable for security teams who want to integrate vulnerability management workflows into their AI assistant interactions.', '@jamiesonio', 'ai-ml', 'Unknown', 11, 'https://github.com/jamiesonio/defectdojo-mcp', 'defectdojo-mcp', 1919, 'https://github.com/jamiesonio.png?size=128', '2026-03-09T05:21:01.999325+00:00'),
  ('forevervm', 'ForeverVM', 'foreverVM provides an API for running arbitrary, stateful Python code securely.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('knowledge-base-retrieval', 'Knowledge Base Retrieval', 'This MCP server, developed by Jean Ibarz, provides tools for listing and retrieving content from different knowledge bases. Built with TypeScript and leveraging libraries like Faiss and Hugging Face, it offers functionality to access and search through structured knowledge repositories. The implementation focuses on efficient retrieval and vectorization of knowledge base content, enabling AI models to query and utilize diverse information sources. By connecting AI systems with organized knowledge stores, this server facilitates use cases such as question answering, information retrieval, and knowledge-based reasoning, making it particularly useful for applications requiring access to curated information across multiple domains.', '@jeanibarz', 'development', 'Unknown', 41, 'https://github.com/jeanibarz/knowledge-base-mcp-server', NULL, 0, 'https://github.com/jeanibarz.png?size=128', '2026-03-09T05:21:02.001147+00:00'),
  ('prometheus-alertmanager', 'Prometheus Alertmanager', 'A Model Context Protocol (MCP) server for Prometheus Alertmanager.', '@jeanlopezxyz', 'data-analytics', 'Unknown', 0, 'https://github.com/jeanlopezxyz/mcp-alertmanager', NULL, 0, 'https://github.com/jeanlopezxyz.png?size=128', '2026-03-09T05:21:02.001206+00:00'),
  ('prometheus-monitoring', 'Prometheus Monitoring', 'A Model Context Protocol (MCP) server for Prometheus monitoring.', '@jeanlopezxyz', 'data-analytics', 'Unknown', 0, 'https://github.com/jeanlopezxyz/mcp-prometheus', NULL, 0, 'https://github.com/jeanlopezxyz.png?size=128', '2026-03-09T05:21:02.001241+00:00'),
  ('homebrew', 'Homebrew', 'This Homebrew MCP server by Alex Jeannier provides direct package management capabilities for macOS systems by exposing Homebrew commands as individual MCP tools. The implementation executes real ''brew'' commands via subprocess for operations like install, uninstall, search, info, upgrade, list, doctor, reinstall, and outdated, with comprehensive JSON logging of all requests and results to homebrew_mcp.log. Built using FastMCP with a functional programming approach, it enables AI assistants to perform system-level package management tasks, check for outdated software, diagnose Homebrew issues, and maintain macOS development environments through natural language interactions.', '@jeannier', 'development', 'Unknown', 25, 'https://github.com/jeannier/homebrew-mcp', NULL, 0, 'https://github.com/jeannier.png?size=128', '2026-03-09T05:21:02.001271+00:00'),
  ('smartlead', 'Smartlead', 'Smartlead MCP Server provides a structured interface to the Smartlead email marketing API, organizing capabilities into logical categories like campaign management, lead handling, and email delivery. Developed by Jonathan Politzki, it implements a tiered licensing system (Free, Basic, Premium) that controls access to advanced features such as client management, webhooks, and smart delivery tools. The server supports multiple operation modes including standard STDIO communication and Server-Sent Events for web clients, with optional Supergateway integration for enhanced functionality. Particularly valuable for businesses managing email campaigns, lead tracking, and email deliverability optimization through a standardized protocol.', '@jonathan-politzki', 'communication', 'Unknown', 17, 'https://github.com/jonathan-politzki/smartlead-mcp-server', NULL, 0, 'https://github.com/jonathan-politzki.png?size=128', '2026-03-09T05:21:02.001305+00:00'),
  ('writer-blog-search-substack-medium', 'Writer Blog Search (Substack & Medium)', 'Writer Context Tool provides a Python-based MCP server that enables Claude to access and search through a writer''s content from Substack and Medium blogs. The implementation uses RSS feeds to scrape blog posts, stores them in a persistent disk cache, and generates embeddings for semantic search capabilities. It exposes tools for refreshing content and searching writing by topic, while also providing individual essays as resources that Claude can access directly. Built with asyncio, sentence-transformers, and diskcache, it''s designed for writers who want Claude to reference their published work during conversations, with support for customizable caching duration and similarity thresholds.', '@jonathan-politzki', 'ai-ml', 'Unknown', 28, 'https://github.com/jonathan-politzki/mcp-writer-substack', NULL, 0, 'https://github.com/jonathan-politzki.png?size=128', '2026-03-09T05:21:02.001358+00:00'),
  ('elastic-semantic-search', 'Elastic Semantic Search', 'This MCP server implementation provides semantic search functionality for Search Labs blog posts using Elasticsearch. It offers a single tool for performing semantic searches across blog content, returning formatted results including titles, URLs, and relevant text snippets. The server is designed to integrate easily with Elasticsearch and can be useful for applications requiring advanced content discovery and retrieval from blog repositories.', '@jedrazb', 'search', 'Unknown', 3, 'https://github.com/jedrazb/elastic-semantic-search-mcp-server', NULL, 0, 'https://github.com/jedrazb.png?size=128', '2026-03-09T05:21:02.001441+00:00'),
  ('kivv', 'Kivv', 'Automates arXiv paper discovery through scheduled daily collection with Claude-powered relevance scoring and summarization. Built on Cloudflare Workers infrastructure using TypeScript, Hono, and Cloudflare D1/KV/R2 services. Supports multiple users with isolated data access and personalized research topics, generates RSS/Atom feeds for paper libraries, and includes comprehensive security measures with parameterized SQL queries and user authentication. Provides tools for searching papers, managing reading status, and accessing summaries through Claude Desktop integration.', '@jeffaf', 'databases', 'Unknown', 1, 'https://github.com/jeffaf/kivv', NULL, 0, 'https://github.com/jeffaf.png?size=128', '2026-03-09T05:21:02.001455+00:00'),
  ('four-in-a-row', 'Four-in-a-Row', 'This MCP server implements a Four-in-a-Row (Connect Four) game service using Spring Boot and Spring AI, providing tools for creating games, making moves, checking win conditions, and managing game state through a RESTful interface. Built by Microsoft Germany CSU as a demonstration of custom MCP server capabilities, it features comprehensive game logic with support for custom board dimensions, player turn management, win detection across horizontal/vertical/diagonal patterns, and persistent game storage with UUID-based game identification. The implementation is valuable for educational purposes showing MCP integration patterns, game development tutorials, or as a foundation for building more complex turn-based gaming applications with AI assistant integration.', '@jeffreygroneberg', 'development', 'Unknown', 2, 'https://github.com/jeffreygroneberg/mcp-fiar', NULL, 0, 'https://github.com/jeffreygroneberg.png?size=128', '2026-03-09T05:21:02.001484+00:00'),
  ('github-repository-inspector', 'GitHub Repository Inspector', 'The MCP-Inspector server enables AI assistants like Claude to interact with GitHub repositories through a Python Flask implementation. It provides endpoints for discovering and executing operations such as repository searching, issue management, and pull request handling. The server authenticates with GitHub using a personal access token and formats responses in a structured way that makes repository data easily accessible within AI conversations. This implementation is particularly useful for developers who want to analyze repositories, manage issues, or monitor pull requests without leaving their AI assistant interface.', '@jehan26', 'development', 'Unknown', 0, 'https://github.com/jehan26/mcp-inspector-v0.6.0', NULL, 0, 'https://github.com/jehan26.png?size=128', '2026-03-09T05:21:02.001510+00:00'),
  ('capacities', 'Capacities', 'This MCP server provides complete integration with the Capacities knowledge management platform, enabling AI assistants to interact with personal knowledge spaces through the official Capacities API. Built by Jem Gold using TypeScript with FastMCP and Zod validation, it offers tools for listing and exploring spaces, searching content across knowledge bases with advanced filtering, saving weblinks with metadata and tags, and adding content to daily notes, plus structured prompts for creating daily summaries, research notes, and meeting notes. The implementation includes proper error handling for API responses, rate limit awareness, and support for both read-only operations like search and write operations like content creation, making it valuable for knowledge workers managing research workflows, students organizing academic materials, and anyone using Capacities who wants AI assistance with content discovery, organization, and daily note-taking.', '@jem-computer', 'development', 'Unknown', 35, 'https://github.com/jem-computer/capacities-mcp', NULL, 0, 'https://github.com/jem-computer.png?size=128', '2026-03-09T05:21:02.001582+00:00'),
  ('jenkins-ci-cd', 'Jenkins CI/CD', 'Jenkins MCP server implementation by Ashwini Ghuge that provides AI assistants with complete access to Jenkins CI/CD operations through comprehensive job management, build monitoring, and pipeline execution capabilities. Built with Python using FastMCP and featuring a multi-tier intelligent caching system, the implementation supports triggering jobs with parameter processing, real-time build status tracking, console log access, artifact management, and batch operations with priority queuing. The server includes advanced features like smart caching that differentiates between running and completed builds, CSRF protection with automatic crumb handling, nested job support for Jenkins folder structures, and pipeline stage-by-stage execution tracking, making it valuable for DevOps teams managing complex CI/CD workflows, developers needing programmatic Jenkins access for build automation, and organizations requiring AI-assisted monitoring and management of their Jenkins infrastructure.', '@ashwinighuge3012', 'development', 'Unknown', 12, 'https://github.com/ashwinighuge3012/jenkins-mcp-server', '@ashwinighuge/jenkins-mcp-server', 1239, 'https://github.com/ashwinighuge3012.png?size=128', '2026-03-09T05:21:02.001655+00:00'),
  ('sql-server-pro', 'SQL Server Pro', 'This MCP server provides comprehensive database access to Microsoft SQL Server instances through pyodbc, enabling AI assistants to inspect schemas, execute queries, and manage database objects including tables, stored procedures, views, and indexes. Built with extensive tool coverage for both read and write operations, it supports connection string configuration through environment variables, offers detailed schema introspection capabilities, and includes specialized tools for stored procedure management with parameter discovery and execution. The implementation provides safety through query type validation, separating read-only SELECT operations from write operations like INSERT/UPDATE/DELETE, and includes comprehensive database object management tools for creating, modifying, and deleting procedures, views, and indexes, making it valuable for database administration tasks, data analysis workflows, and applications requiring deep SQL Server integration.', '@jensenloke', 'databases', 'Unknown', 7, 'https://github.com/jensenloke/mcp-sqlserver-pro', 'mssql-mcp-server', 25904, 'https://github.com/jensenloke.png?size=128', '2026-03-09T05:21:02.001667+00:00'),
  ('jentic', 'Jentic', 'Jentic SDK is a comprehensive library for discovering and executing APIs and workflows through LLM-compatible tools. Developed by Jentic Labs, it consists of two main components: a Python SDK for generating tool definitions compatible with Anthropic Claude and OpenAI models, and an MCP adapter that enables AI assistants to search for API capabilities, load execution information, and execute operations or workflows. The SDK leverages the Open Agentic Knowledge (OAK) repository for API data and includes features like caching, authentication handling, and standardized result formatting, making it particularly valuable for developers building AI agents that need to interact with external APIs without leaving the conversation context.', '@jentic', 'development', 'Unknown', 23, 'https://github.com/jentic/jentic-sdks', NULL, 0, 'https://github.com/jentic.png?size=128', '2026-03-09T05:21:02.001740+00:00'),
  ('kakao-maps', 'Kakao Maps', 'Kakao API MCP Server provides a bridge to Kakao Maps API services, enabling AI assistants to access location-based data through the Model Context Protocol. Built with TypeScript and Express, it supports both HTTP and stdio communication modes, making it compatible with various MCP client implementations. The server requires a Kakao API key for authentication, which is configured either through command-line arguments or environment variables. This implementation is particularly useful for applications needing geolocation services, address lookup, or map-related functionality within conversational AI interfaces.', '@jeong-sik', 'development', 'Unknown', 15, 'https://github.com/jeong-sik/kakao-api-mcp-server', NULL, 0, 'https://github.com/jeong-sik.png?size=128', '2026-03-09T05:21:02.001770+00:00'),
  ('jepto', 'Jepto', 'Provides access to client knowledgebase and analytics for connected marketing data sources. Integrates with Google Analytics, Google Ads, Facebook Ads, Microsoft Ads, and other marketing platforms to enable cross-channel data analysis and reporting. Enables querying metrics, generating reports, and accessing client notes through conversational interfaces.', '@unknown', 'data-analytics', 'Unknown', 0, 'https://www.jepto.com', NULL, 0, NULL, '2026-03-09T05:21:02.001822+00:00'),
  ('paperpal', 'PaperPal', 'Paperpal is an MCP extension that connects LLMs to academic research sources, enabling users to search and discuss scientific papers from arXiv and Hugging Face. Developed by Jeremy Pinto, it provides tools for semantic paper searches and retrieving detailed paper information, making it ideal for researchers writing literature reviews, exploring new research, or organizing academic ideas. The implementation uses FastMCP with asynchronous HTTP requests to efficiently fetch and parse paper data, presenting results in a structured format that LLMs can easily process and discuss with users.', '@jerpint', 'ai-ml', 'Unknown', 10, 'https://github.com/jerpint/paperpal', NULL, 0, 'https://github.com/jerpint.png?size=128', '2026-03-09T05:21:02.001954+00:00'),
  ('kubernetes-natural-language-commander', 'Kubernetes Natural Language Commander', 'Kube Core MCP is a Kubernetes command processing service that converts natural language requests into valid kubectl commands. Built with FastAPI and integrated with AWS Bedrock for LLM processing, it provides secure command validation, execution, and analysis of Kubernetes resources. The implementation features two security modes (STRICT and PERMISSIVE), comprehensive pod state analysis for troubleshooting, and context-aware conversation handling to maintain continuity across interactions. It''s particularly valuable for Kubernetes administrators who want to interact with their clusters using natural language queries without memorizing complex kubectl syntax.', '@jess321995', 'cloud', 'Unknown', 1, 'https://github.com/jess321995/kube-core-mcp', NULL, 0, 'https://github.com/jess321995.png?size=128', '2026-03-09T05:21:02.001997+00:00'),
  ('wazuh-opensearch-analytics', 'Wazuh OpenSearch Analytics', 'MCP-OpenSearch-JS is a server that enables AI assistants to query and analyze Wazuh security logs stored in OpenSearch databases. The implementation provides tools for searching alerts, exploring field values, monitoring logs in real-time, visualizing alert trends, and retrieving detailed information about specific security events. Built with FastMCP and the OpenSearch client library, it features robust error handling, progress reporting for long-running operations, and configurable timeouts to prevent connection issues. This server is particularly valuable for security analysts who need to investigate security incidents, generate statistics on alert patterns, or monitor security events without leaving their AI assistant interface.', '@cyberbalsa', 'databases', 'Unknown', 2, 'https://github.com/cyberbalsa/mcp-opensearch-js', NULL, 0, 'https://github.com/cyberbalsa.png?size=128', '2026-03-09T05:21:02.002009+00:00'),
  ('jetbrains-ide-plugin', 'JetBrains IDE Plugin', 'This JetBrains MCP Server Plugin, developed by JetBrains, enables seamless integration between Large Language Models and JetBrains IDEs. It provides a server-side implementation for handling MCP requests and exposes extension points for custom tool development. The plugin integrates with JetBrains IDE services and leverages the IntelliJ Platform SDK. It stands out by offering a flexible architecture that allows third-party plugins to implement their own MCP tools through a well-defined extension system. This implementation is particularly useful for developers looking to enhance their JetBrains IDE workflow with AI-powered features, such as code generation, refactoring assistance, or custom language model interactions tailored to specific development tasks.', '@jetbrains', 'development', 'Unknown', 127, 'https://github.com/jetbrains/mcp-server-plugin', NULL, 0, 'https://github.com/jetbrains.png?size=128', '2026-03-09T05:21:02.002038+00:00'),
  ('jetbrains-ide', 'JetBrains IDE', 'This MCP proxy server, developed by JetBrains, enables AI assistants like Claude to interact with JetBrains IDEs. Built with Node.js, it acts as a bridge between Claude Desktop and JetBrains IDE plugins, allowing AI models to access IDE functionality and project data. The implementation stands out by providing deep integration with JetBrains'' powerful development environments, supporting multiple concurrent IDE instances. By connecting AI capabilities with professional coding tools, this server enables AI systems to assist in code analysis, refactoring, and development tasks. It is particularly useful for scenarios like code reviews, bug detection, and building AI coding assistants that can understand and contribute to software projects within JetBrains IDEs.', '@jetbrains', 'development', 'Unknown', 943, 'https://github.com/jetbrains/mcp-jetbrains', '@jetbrains/mcp-proxy', 106514, 'https://github.com/jetbrains.png?size=128', '2026-03-09T05:21:02.002064+00:00'),
  ('mlcbakery', 'MLCBakery', 'MLCBakery MCP Server provides a bridge between AI assistants and machine learning datasets through the Model Context Protocol. Built by Jonathan Lebensold, this implementation enables MCP-compatible clients to search, validate, and retrieve ML Croissant metadata for datasets stored in the MLCBakery system. The server exposes tools for dataset discovery, preview generation, and metadata validation, making it particularly valuable for researchers and data scientists who need to reference or validate machine learning datasets during AI-assisted workflows without switching contexts.', '@jettyio', 'ai-ml', 'Unknown', 6, 'https://github.com/jettyio/mlcbakery', NULL, 0, 'https://github.com/jettyio.png?size=128', '2026-03-09T05:21:02.002112+00:00'),
  ('webresearch', 'WebResearch', 'MCP-WebResearch provides AI assistants with web browsing capabilities for conducting research through a Playwright-powered browser. It offers tools for Google searching, visiting webpages, and capturing screenshots, with content automatically converted to clean markdown format. The implementation handles common web challenges like consent dialogs and bot detection, while maintaining a research session that tracks visited pages and screenshots. Particularly useful for workflows requiring iterative research, source citation, and visual context from web content.', '@jevy', 'ai-ml', 'Unknown', 0, 'https://github.com/jevy/mcp-webresearch', NULL, 0, 'https://github.com/jevy.png?size=128', '2026-03-09T05:21:02.002154+00:00'),
  ('mssql-database-manager', 'MSSQL Database Manager', 'This MSSQL MCP server, created by Jexin Sam, enables secure interaction between AI assistants and Microsoft SQL Server databases. Built with Python and leveraging the Model Context Protocol, it provides a controlled interface for listing tables, reading data, and executing SQL queries. The implementation focuses on safety and structure, offering a standardized way to explore and analyze MSSQL databases. It''s particularly useful for applications requiring AI-driven database operations, enabling use cases such as automated data analysis, dynamic reporting, and intelligent database exploration without direct exposure to SQL Server complexities.', '@jexinsam', 'databases', 'Unknown', 54, 'https://github.com/jexinsam/mssql_mcp_server', 'mssql_mcp_server', 0, 'https://github.com/jexinsam.png?size=128', '2026-03-09T05:21:02.002167+00:00'),
  ('australian-postcodes', 'Australian Postcodes', 'Australian Postcodes MCP server by jezweb that provides fast, comprehensive postcode and suburb lookup services for Australia with advanced fuzzy matching and phonetic search capabilities. Built with FastMCP and SQLite, the implementation loads ~17,000 Australian postcodes from GitHub CSV data and offers 16 specialized tools including exact searches, spelling validation, autocomplete, LGA (Local Government Area) queries, geographic radius searches, and voice-friendly phonetic matching using Double Metaphone encoding. The server features intelligent compound word handling for suburbs like "Newcastle" vs "New Castle", configurable similarity thresholds, and comprehensive analytics tools for state statistics and regional searches, making it valuable for address validation systems, location-based applications, voice assistants processing Australian addresses, and any application requiring robust Australian geographic data with tolerance for misspellings and variations in suburb names.', '@jezweb', 'databases', 'Unknown', 5, 'https://github.com/jezweb/australian-postcodes-mcp', NULL, 0, 'https://github.com/jezweb.png?size=128', '2026-03-09T05:21:02.002178+00:00'),
  ('smart-prompts', 'Smart Prompts', 'This Smart Prompts MCP server by jezweb provides intelligent prompt management and discovery by fetching prompts directly from GitHub repositories with no local storage required. The implementation features enhanced GitHub integration with recursive directory traversal, semantic search capabilities, prompt composition tools, and usage analytics, while supporting both public and private repositories through token authentication. Built with TypeScript and offering comprehensive MCP protocol support including resources, prompts, and tools, it enables AI assistants to dynamically discover, search, and compose prompts from version-controlled repositories, making it valuable for teams that want to share and collaborate on prompt libraries through GitHub while maintaining intelligent discovery and composition workflows.', '@jezweb', 'development', 'Unknown', 13, 'https://github.com/jezweb/smart-prompts-mcp', NULL, 0, 'https://github.com/jezweb.png?size=128', '2026-03-09T05:21:02.002228+00:00'),
  ('iphone-mirroir', 'iPhone Mirroir', 'Enables control of a real iPhone through macOS iPhone Mirroring. Provides tools for taking screenshots, tapping, swiping, typing, and describing screen contents via OCR. Supports multi-step automation through YAML-based scenarios, app launching, and recording. Requires macOS with iPhone Mirroring enabled.', '@jfarcand', 'ai-ml', 'Unknown', 31, 'https://github.com/jfarcand/mirroir-mcp', NULL, 0, 'https://github.com/jfarcand.png?size=128', '2026-03-09T05:21:02.002261+00:00'),
  ('wildfly', 'WildFly', 'This WildFly MCP server, developed by the WildFly team, provides a Java-based interface for AI assistants to interact with and manage WildFly application servers. Built using Quarkus and leveraging the Model Context Protocol, it offers tools for monitoring server status, resource consumption, log analysis, and configuration management. The implementation focuses on simplifying WildFly server administration through natural language interactions, making it easier for AI models to assist in troubleshooting, performance monitoring, and server management tasks. It''s particularly useful for DevOps teams and system administrators who want to integrate AI assistance into their WildFly server management workflows, enabling efficient server diagnostics and configuration without requiring deep knowledge of WildFly''s management interfaces.', '@wildfly-extras', 'productivity', 'Unknown', 7, 'https://github.com/wildfly-extras/wildfly-mcp', NULL, 0, 'https://github.com/wildfly-extras.png?size=128', '2026-03-09T05:21:02.002308+00:00'),
  ('jfrog', 'JFrog', 'JFrog MCP Server provides a bridge to the JFrog Platform, enabling AI assistants to interact with Artifactory repositories, builds, security scanning, and release management. Developed by JFrog LTD, this TypeScript implementation exposes over 20 specialized tools for operations like repository creation, build tracking, package vulnerability scanning, and release bundle distribution. The server authenticates via JFrog access tokens and handles errors gracefully with detailed messages. Particularly valuable for DevOps teams and developers who want to leverage AI assistants for artifact management, security analysis, and release automation without switching context to the JFrog web interface.', '@jfrog', 'development', 'Unknown', 112, 'https://github.com/jfrog/mcp-jfrog', NULL, 0, 'https://github.com/jfrog.png?size=128', '2026-03-09T05:21:02.002336+00:00'),
  ('jfrog-artifactory', 'JFrog Artifactory', 'This MCP server provides integration with JFrog''s Artifactory and platform ecosystem, enabling AI assistants to interact with artifact repositories, package management, and DevOps automation tools. The implementation allows access to JFrog''s APIs for managing binary artifacts, container images, build information, and security scanning results across different repository types and deployment pipelines. Useful for DevOps teams and developers who need AI assistance with artifact lifecycle management, dependency analysis, security vulnerability assessment, and CI/CD pipeline optimization within JFrog-based infrastructure.', '@jfrog', 'development', 'Unknown', 4, 'https://github.com/jfrog/jfrog-mcp-server', NULL, 0, 'https://github.com/jfrog.png?size=128', '2026-03-09T05:21:02.002363+00:00'),
  ('websharp', 'WebSharp', 'Performs web searches using SearXNG metasearch engine and extracts readable article content from web pages using SmartReader. Supports configurable search parameters including result limits, categories, and language preferences. Concurrent URL processing with automatic language detection and content extraction.', '@jgador', 'search', 'Unknown', 1, 'https://github.com/jgador/websharp', NULL, 0, 'https://github.com/jgador.png?size=128', '2026-03-09T05:21:02.002397+00:00'),
  ('clicksend', 'ClickSend', 'This ClickSend MCP server, developed by J-Gal02, enables AI agents to interact with ClickSend''s SMS and Text-to-Speech (TTS) call services. Built with TypeScript and leveraging the Model Context Protocol SDK, it provides a streamlined interface for sending SMS messages and initiating TTS calls. The implementation focuses on simplifying communication tasks, offering a bridge between AI systems and ClickSend''s API. It''s particularly useful for businesses and developers looking to integrate automated messaging and voice communication into their AI workflows, enabling use cases such as automated notifications, appointment reminders, and voice-based information delivery without directly dealing with ClickSend''s API complexities.', '@j-gal02', 'development', 'Unknown', 3, 'https://github.com/j-gal02/clicksend-mcp', NULL, 0, 'https://github.com/j-gal02.png?size=128', '2026-03-09T05:21:02.002427+00:00'),
  ('epss-exploit-prediction-scoring-system', 'EPSS (Exploit Prediction Scoring System)', 'The EPSS MCP server provides AI assistants with access to vulnerability intelligence by integrating data from the NVD API and EPSS scoring system. Developed by Jerry Gamblin, this implementation fetches detailed CVE information including descriptions, CWEs, CVSS scores, and EPSS percentiles that indicate exploitation likelihood within 30 days. The server supports deployment via Docker for Open-WebUI integration or direct connection to VS Code through the Microsoft Copilot Labs extension, making it valuable for cybersecurity professionals who need to prioritize vulnerability remediation efforts based on exploitation probability without switching contexts.', '@jgamblin', 'cloud', 'Unknown', 13, 'https://github.com/jgamblin/epss-mcp', NULL, 0, 'https://github.com/jgamblin.png?size=128', '2026-03-09T05:21:02.002455+00:00'),
  ('microsoft-security-copilot', 'Microsoft Security Copilot', 'A Python-based MCP server that provides integration between Microsoft Security Copilot and Microsoft Sentinel using Azure Identity Authentication. Developed by Jaime Guimera Coll, this implementation enables running KQL queries against Sentinel workspaces, managing Security Copilot skillsets/plugins, and executing prompts within Security Copilot. The server uses FastMCP for the transport layer and supports multiple authentication methods including interactive browser, client secret, and managed identity. It''s particularly useful for security professionals developing, testing, and deploying Security Copilot KQL skills, allowing for seamless workflow from development to production environments.', '@jguimera', 'cloud', 'Unknown', 20, 'https://github.com/jguimera/securitycopilotmcpserver', NULL, 0, 'https://github.com/jguimera.png?size=128', '2026-03-09T05:21:02.002475+00:00'),
  ('codebase-context', 'Codebase Context', 'Codebase indexing and search via WASM tree-sitter. Works on ARM64 and x86_64.', '@jhackman2019', 'development', 'Unknown', 0, 'https://github.com/jhackman2019/codebase-context-mcp', NULL, 0, 'https://github.com/jhackman2019.png?size=128', '2026-03-09T05:21:02.002490+00:00'),
  ('openscad-3d-model-generator', 'OpenSCAD 3D Model Generator', 'OpenSCAD MCP Server enables AI assistants to create and manipulate 3D models through natural language descriptions, leveraging a pipeline that generates images with Venice.ai, segments objects with SAM2, creates 3D models with threestudio, and converts them to parametric OpenSCAD code. The implementation supports multiple export formats (3MF, AMF, CSG) that preserve parametric properties for 3D printing, includes validation tools for printer compatibility with Prusa and Bambu systems, and provides visualization capabilities for multi-angle previews - making it particularly valuable for users who need to create customizable 3D models without manual CAD work.', '@jhacksman', 'development', 'Unknown', 132, 'https://github.com/jhacksman/openscad-mcp-server', NULL, 0, 'https://github.com/jhacksman.png?size=128', '2026-03-09T05:21:02.002518+00:00'),
  ('hirebase-job-search', 'HireBase Job Search', 'HireBase MCP Server provides tools to interact with the HireBase Job API, enabling AI assistants to search for jobs based on various criteria and retrieve detailed job information. Developed by Jake Gaylor under the MIT license, this Python implementation offers two main tools - search_jobs with extensive filtering options (keywords, location, salary, etc.) and get_job for retrieving specific job details - plus a prompt generator to help create structured candidate profiles. The server is designed for easy integration with Claude Desktop and Cursor, making it particularly valuable for job seekers and career advisors who need access to current job market data.', '@jhgaylor', 'ai-ml', 'Unknown', 10, 'https://github.com/jhgaylor/hirebase-mcp', 'hirebase-mcp', 10202, 'https://github.com/jhgaylor.png?size=128', '2026-03-09T05:21:02.002588+00:00'),
  ('microsoft-todo', 'Microsoft Todo', 'This Microsoft Todo MCP service enables Claude to interact with Microsoft Todo tasks through natural language. Built by jhirono, it provides tools for viewing task lists, creating tasks with due dates and priorities, managing checklist items, and checking authentication status. The implementation uses Microsoft Graph API with OAuth 2.0 authentication, storing tokens locally with automatic refresh capabilities. It''s particularly useful for users who want to manage their Microsoft Todo tasks directly from Claude without switching applications.', '@jhirono', 'productivity', 'Unknown', 20, 'https://github.com/jhirono/todomcp', NULL, 0, 'https://github.com/jhirono.png?size=128', '2026-03-09T05:21:02.002626+00:00'),
  ('elenchus', 'Elenchus', 'Elenchus is an adversarial verification system that orchestrates multi-round code review sessions between verifier and critic roles to systematically identify security, correctness, reliability, maintainability, and performance issues. It provides state management, context sharing, and automated verification loops through MCP tools, with advanced features like differential analysis for incremental verification, response caching to reduce token usage, function-level code chunking for large codebases, and quality safeguards including periodic full verification and confidence scoring. Designed for thorough code verification workflows where multiple AI agents collaborate to catch issues that single-pass reviews might miss.', '@jhlee0409', 'development', 'Unknown', 4, 'https://github.com/jhlee0409/elenchus-mcp', NULL, 0, 'https://github.com/jhlee0409.png?size=128', '2026-03-09T05:21:02.002658+00:00'),
  ('overseerr', 'Overseerr', 'This Overseerr MCP server by jhomen368 provides direct integration to Overseerr instances for media management and automation. The server offers eight specialized tools including media search across movies/TV shows/people, media request submission with support for specific seasons and quality profiles, request management with approval/decline capabilities, and detailed media information retrieval from TMDB. Built with TypeScript and featuring both stdio and HTTP transport modes, Docker support, and comprehensive error handling, it enables automated media discovery and request workflows in Plex/Jellyfin environments, making it useful for building intelligent media recommendation systems, automated request processing, and voice-controlled media management interfaces.', '@jhomen368', 'cloud', 'Unknown', 6, 'https://github.com/jhomen368/overseerr-mcp', '@jhomen368/overseerr-mcp', 1347, 'https://github.com/jhomen368.png?size=128', '2026-03-09T05:21:02.002685+00:00'),
  ('opencti', 'OpenCTI', 'Provides programmatic access to OpenCTI threat intelligence platforms through specialized tools for querying malware, threat actors, attack patterns, vulnerabilities, and campaigns. Enables sector-based threat analysis, relationship traversal between STIX entities, temporal report queries, and comprehensive threat actor profiling. Features both forward and reverse relationship mapping, fuzzy search capabilities, and configurable result limits. Designed for cybersecurity analysts conducting threat research, incident response teams building threat profiles, and security operations centers performing sector-specific threat assessments.', '@jhuntinfosec', 'development', 'Unknown', 1, 'https://github.com/jhuntinfosec/mcp-opencti', NULL, 0, 'https://github.com/jhuntinfosec.png?size=128', '2026-03-09T05:21:02.002714+00:00'),
  ('appinsight-app-store-play-store', 'AppInsight (App Store / Play Store)', 'An MCP server that provides comprehensive market intelligence by analyzing data from both the Apple App Store and Google Play Store. Get insights about apps, market trends, competitors, and user feedback across the major mobile app marketplaces.', '@jiantaofu', 'maps-location', 'Unknown', 21, 'https://github.com/jiantaofu/appinsightmcp', '@jeromyfu/app-insight-mcp', 4191, 'https://github.com/jiantaofu.png?size=128', '2026-03-09T05:21:02.002773+00:00'),
  ('abaqus-cae-gui-automation', 'Abaqus/CAE GUI Automation', 'Abaqus MCP Server enables AI assistants to interact with running Abaqus/CAE finite element analysis software through GUI automation. Built with Python using pywinauto and the FastMCP framework, it provides tools to execute Python scripts within an existing Abaqus session via the ''File -> Run Script...'' menu and retrieve message log information from the Abaqus interface. The implementation uses window detection and UI control manipulation to automate interactions that would normally require manual input, making it valuable for engineers and analysts who want to programmatically control Abaqus/CAE operations through AI assistance without modifying the core application.', '@jianzhichun', 'ai-ml', 'Unknown', 47, 'https://github.com/jianzhichun/abaqus-mcp-server', NULL, 0, 'https://github.com/jianzhichun.png?size=128', '2026-03-09T05:21:02.002819+00:00'),
  ('waveform', 'Waveform', 'Reads and analyzes VCD and FST waveform files from digital circuit simulations. Provides tools for signal listing with hierarchical filtering, value reading at specific timepoints, metadata retrieval, event detection within time ranges, and complex conditional expression evaluation across signals for hardware verification and debugging workflows.', '@jiegec', 'development', 'Unknown', 17, 'https://github.com/jiegec/waveform-mcp', NULL, 0, 'https://github.com/jiegec.png?size=128', '2026-03-09T05:21:02.002890+00:00'),
  ('mytrip-ai-studio-serpapi-travel', 'MyTrip AI Studio (SerpAPI Travel)', 'Easy My Trip MCP Server provides AI assistants with comprehensive travel planning capabilities through six specialized servers that integrate with SerpAPI and other services. Built with FastMCP, it offers flight search and comparison, hotel booking with filtering by price/rating/amenities, event discovery and categorization, weather forecasting, currency conversion and stock market data, and geocoding with distance calculations. The implementation stores search results locally for detailed analysis and comparison, includes sophisticated filtering tools for each service type, and provides structured prompts for travel planning workflows, making it valuable for travel agents, trip planners, and users who need integrated access to flights, accommodations, local events, weather conditions, and location data in a single interface.', '@jigarvyasidea', 'ai-ml', 'Unknown', 0, 'https://github.com/jigarvyasidea/mytrip-ai-studio', NULL, 0, 'https://github.com/jigarvyasidea.png?size=128', '2026-03-09T05:21:02.002946+00:00'),
  ('file-system', 'File System', 'This MCP server provides AI assistants with secure file system operations through a complete set of tools for reading, writing, copying, moving, and deleting files, plus directory management and advanced search capabilities including regex pattern matching and content searching across files. Built by Jihad Khawaja using .NET 8.0 and C# 12.0, it features Docker support, structured JSON responses, path validation to prevent directory traversal attacks, and comprehensive error handling. Serves developers needing AI-powered file management automation, teams requiring programmatic file system access through conversational interfaces, and applications that need to perform bulk file operations while maintaining security through proper path validation and permission respect.', '@jihadkhawaja', 'cloud', 'Unknown', 1, 'https://github.com/jihadkhawaja/mcp.filesystem', NULL, 0, 'https://github.com/jihadkhawaja.png?size=128', '2026-03-09T05:21:02.002971+00:00'),
  ('jij-mathematical-and-quantum-computing-platform', 'Jij Mathematical and Quantum Computing Platform', 'Jij MCP Server provides specialized tools for mathematical optimization using JijModeling and quantum computing with Qiskit, designed to bridge the gap between AI models trained on older Qiskit versions and modern v1/v2 implementations. Built by Jij Inc., the implementation offers JijModeling syntax guidance, code validation, and step-by-step workflow assistance for optimization problems, alongside Qiskit migration guides, API reference access, IBM Quantum Learning Hub tutorial integration, and static code checking in isolated virtual environments. The server addresses the specific challenge that AI models often generate outdated Qiskit code by providing migration resources and automated compatibility testing, making it valuable for researchers and developers working on optimization problems and quantum algorithms who need reliable code generation and validation across both domains.', '@jij-inc', 'development', 'Unknown', 3, 'https://github.com/jij-inc/jij-mcp-server', NULL, 0, 'https://github.com/jij-inc.png?size=128', '2026-03-09T05:21:02.003006+00:00'),
  ('google-toolbox', 'Google Toolbox', 'py-mcp-google-toolbox provides AI assistants with powerful tools to interact with Google services including Gmail, Calendar, Drive, and Search. Built by Anthony Kim, this server implementation authenticates with Google APIs using OAuth 2.0 and exposes structured endpoints for email operations (reading, searching, sending), calendar management, file access, and web searches. The toolbox handles all the complexities of Google API integration, credential management, and token refreshing, making it particularly valuable for AI assistants that need to perform real-world tasks like managing communications, scheduling events, accessing documents, or retrieving information from the web without directly managing Google API connections.', '@jikime', 'communication', 'Unknown', 10, 'https://github.com/jikime/py-mcp-google-toolbox', NULL, 0, 'https://github.com/jikime.png?size=128', '2026-03-09T05:21:02.003041+00:00'),
  ('korean-weather', 'Korean Weather', 'The py-mcp-ko-weather server provides access to Korean weather data through a clean API interface. Developed by Anthony Kim, this implementation uses asynchronous HTTP requests to fetch weather information, with proper error handling and timeout management. The server includes utilities for coordinate conversion and API authentication, making it particularly useful for applications that need reliable Korean meteorological data integration.', '@jikime', 'security', 'Unknown', 6, 'https://github.com/jikime/py-mcp-ko-weather', NULL, 0, 'https://github.com/jikime.png?size=128', '2026-03-09T05:21:02.003099+00:00'),
  ('naver-search', 'Naver Search', 'Naver Search MCP Server provides AI agents with access to Naver''s search APIs, enabling searches across multiple categories including blogs, news, books, images, and shopping items. Built by Anthony Kim, it implements structured responses optimized for LLM consumption, supports pagination, and includes specialized features like adult content checking and keyboard input error correction. The server is designed with Python 3.12+ and requires Naver Developer API credentials, making it particularly valuable for applications needing Korean-language search capabilities without directly managing the complexities of Naver''s API integration.', '@jikime', 'ai-ml', 'Unknown', 3, 'https://github.com/jikime/py-mcp-naver-search', NULL, 0, 'https://github.com/jikime.png?size=128', '2026-03-09T05:21:02.003146+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('cisco-aci', 'Cisco ACI', 'Integrates with Cisco ACI (Application Centric Infrastructure) fabrics through the APIC REST API, providing comprehensive network automation capabilities for managing tenants, application profiles, endpoint groups, bridge domains, VRFs, and contracts. Built with TypeScript and supports both username/password and X.509 certificate authentication for secure access. Features configurable tool selection modes to balance between core functionality and extended capabilities, with robust error handling and automatic session management for production network automation workflows.', '@jim-coyne', 'development', 'Unknown', 2, 'https://github.com/jim-coyne/aci_mcp', NULL, 0, 'https://github.com/jim-coyne.png?size=128', '2026-03-09T05:21:02.003175+00:00'),
  ('cisco-intersight', 'Cisco Intersight', 'A TypeScript-based server that provides complete access to Cisco Intersight''s infrastructure management API through 30+ specialized tools covering inventory discovery, alarm monitoring, policy management, resource pools, and server profile orchestration. Built with robust authentication supporting both RSA and ECDSA API keys, it enables datacenter automation including server provisioning, policy creation and attachment, pool management for IP/MAC/UUID/WWNN/WWPN resources, and real-time infrastructure monitoring with alarm acknowledgment capabilities. The implementation features structured TypeScript interfaces for all Intersight object types and supports advanced OData filtering, making it useful for automated infrastructure provisioning workflows, datacenter health monitoring, policy-as-code implementations, and AI-assisted server lifecycle management.', '@jim-coyne', 'development', 'Unknown', 7, 'https://github.com/jim-coyne/intersight_mcp', NULL, 0, 'https://github.com/jim-coyne.png?size=128', '2026-03-09T05:21:02.003208+00:00'),
  ('cisco-hyperfabric', 'Cisco Hyperfabric', 'Integrates with Cisco Hyperfabric infrastructure APIs to enable network automation and management for data center switching fabrics. Dynamically generates tools from OpenAPI specifications to support topology configuration, node and interface management, VXLAN overlay networking, routing domain isolation, and link aggregation. Provides bearer token authentication for secure API access.', '@jim-coyne', 'ai-ml', 'Unknown', 2, 'https://github.com/jim-coyne/hyperfabric_mcp', NULL, 0, 'https://github.com/jim-coyne.png?size=128', '2026-03-09T05:21:02.003240+00:00'),
  ('dice-rolling', 'Dice Rolling', 'This MCP server provides AI assistants with advanced dice rolling capabilities for tabletop gaming and RPGs, built using TypeScript with Next.js and comprehensive gaming mechanics support. The implementation offers tools for rolling dice using standard notation with features like advantage/disadvantage mechanics (2d20kh1), exploding dice, reroll mechanics, keep/drop highest/lowest, success counting, and support for special dice types including fudge dice and percentile dice, along with validation tools for explaining dice notation without rolling. Built with cryptographically secure random number generation, extensive input validation with safety limits, and statistical analysis capabilities, it serves tabletop gaming communities needing authentic dice mechanics, AI assistants supporting RPG sessions, and developers building gaming applications that require reliable and feature-rich dice rolling functionality with proper D&D 5e advantage/disadvantage implementation.', '@jimmcq', 'development', 'Unknown', 7, 'https://github.com/jimmcq/dice-rolling-mcp', NULL, 0, 'https://github.com/jimmcq.png?size=128', '2026-03-09T05:21:02.003275+00:00'),
  ('lemonade-stand', 'Lemonade Stand', 'Lemonade Stand MCP Server provides a custom game interface for Claude Desktop, allowing users to play the classic Lemonade Stand business simulation game directly within their AI assistant. Built with Node.js using the Model Context Protocol SDK, this implementation enables Claude to manage game state, process player decisions, and deliver an interactive gaming experience without requiring external applications. The server is designed for easy setup through a simple configuration file and offers a nostalgic gaming experience while demonstrating how MCP can be used for entertainment applications beyond productivity tools.', '@jimmcq', 'ai-ml', 'Unknown', 7, 'https://github.com/jimmcq/lemonade-stand-mcp-server', NULL, 0, 'https://github.com/jimmcq.png?size=128', '2026-03-09T05:21:02.003319+00:00'),
  ('fireproof-json-database', 'Fireproof JSON Database', 'This MCP server, developed by Jim Pick, integrates Fireproof JSON document databases with the Model Context Protocol. Built with TypeScript and leveraging Fireproof''s decentralized database capabilities, it provides a standardized interface for CRUD operations and querying on JSON documents. The server implements multi-database support, allowing AI systems to interact with collections of Fireproof databases through a unified API. By abstracting the complexities of decentralized data storage, it enables seamless integration of structured data operations into AI workflows. This implementation is particularly valuable for applications requiring scalable, decentralized data management, facilitating use cases such as collaborative document editing, distributed content management, and AI-driven data analysis across multiple databases.', '@jimpick', 'databases', 'Unknown', 0, 'https://github.com/jimpick/mcp-json-db-collection-server', NULL, 0, 'https://github.com/jimpick.png?size=128', '2026-03-09T05:21:02.003384+00:00'),
  ('jina-ai', 'Jina AI', 'This MCP server, developed by Jina AI, integrates with Jina''s AI services to provide seamless access to advanced language models and multimodal AI capabilities. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers a standardized interface for interacting with Jina''s AI ecosystem. The implementation focuses on efficient handling of AI requests and responses, making it ideal for developers building applications that require natural language processing, image analysis, or other AI-powered features. Its modular design allows for easy extension and customization, catering to a wide range of AI-driven use cases from chatbots to content generation systems.', '@sheshiyer', 'development', 'Unknown', 4, 'https://github.com/sheshiyer/jina-ai-mcp-multimodal-search', NULL, 0, 'https://github.com/sheshiyer.png?size=128', '2026-03-09T05:21:02.003411+00:00'),
  ('jina-ai-reader', 'Jina AI Reader', 'This lightweight MCP server by jSwords91 provides web content extraction capabilities through Jina AI''s r.jina.ai service, which converts web pages into clean Markdown format optimized for LLM consumption. The implementation features automatic content hashing and caching with stable URI assignment, token counting using tiktoken, and change detection to track content updates over time. Built as a minimal alternative to existing fetch MCP servers, it''s particularly useful for AI assistants that need to access and process web content in a token-aware manner with built-in caching to avoid redundant requests.', '@jswords91', 'ai-ml', 'Unknown', 1, 'https://github.com/jswords91/jina-ai-mcp', NULL, 0, 'https://github.com/jswords91.png?size=128', '2026-03-09T05:21:02.003454+00:00'),
  ('rootdata', 'RootData', 'RootData MCP Server provides a bridge to the RootData API, enabling AI assistants to search and retrieve detailed information about blockchain projects, venture capital organizations, and industry professionals. The server exposes three main tools: searching for entities by keywords, fetching comprehensive project details by ID, and retrieving organization information with optional team and investment data. Built with FastMCP and async HTTP requests, it handles authentication and error management while delivering structured JSON responses, making it valuable for crypto research, investment analysis, and blockchain ecosystem exploration.', '@jincai', 'productivity', 'Unknown', 6, 'https://github.com/jincai/rootdata-mcp-server', NULL, 0, 'https://github.com/jincai.png?size=128', '2026-03-09T05:21:02.003498+00:00'),
  ('agent-mux', 'Agent Mux', 'Agent Mux provides a tmux-backed agent pool for orchestrating multiple interactive CLI agents within organized project workspaces. The implementation uses tmux sessions as projects and tmux windows as individual agents, with persistent logging and a registry system for tracking agent metadata. It enables spawning agents with custom commands, sending text input, reading output via capture-pane, and managing agent lifecycles through project and agent management tools.', '@jinchenggao-infty', 'productivity', 'Unknown', 5, 'https://github.com/jinchenggao-infty/agent-mux', NULL, 0, 'https://github.com/jinchenggao-infty.png?size=128', '2026-03-09T05:21:02.003533+00:00'),
  ('ccx', 'CCX', 'CCX is a lightweight MCP framework that enables Claude Code to invoke external AI tools via standardized servers. It provides three specialized MCP servers: a Gemini server for invoking Google''s Gemini CLI with session management, an email notification server for SMTP-based alerts, and a Codex server for multi-turn conversations with OpenAI''s Codex CLI. Each server operates through clean request/response patterns with minimal configuration requirements.', '@jinchenggao-infty', 'development', 'Unknown', 3, 'https://github.com/jinchenggao-infty/ccx-claude-context-exchange', NULL, 0, 'https://github.com/jinchenggao-infty.png?size=128', '2026-03-09T05:21:02.003555+00:00'),
  ('rhino-8', 'Rhino 8', 'RhinoMCP is a plugin for Rhino 8 that implements the Model Context Protocol, enabling AI assistants to interact with Rhino''s 3D modeling environment. The plugin creates a server that exposes Rhino''s functionality through MCP, allowing for programmatic control of modeling operations. Built on the C# SDK for MCP, it features start and stop commands to manage the server connection, making it useful for automating design workflows and enabling conversational interfaces to control Rhino.', '@jingcheng-chen', 'ai-ml', 'Unknown', 308, 'https://github.com/jingcheng-chen/rhinomcp', NULL, 0, 'https://github.com/jingcheng-chen.png?size=128', '2026-03-09T05:21:02.003592+00:00'),
  ('jinko', 'Jinko', 'Jinko transforms ChatGPT into a personalized travel planning tool. Find and compare flights from hundreds of airlines, book unique experiences and adventures, and discover accommodations tailored to your budget and preferences. The service generates travel recommendations based on live pricing and availability data.', '@unknown', 'communication', 'Unknown', 0, 'https://www.gojinko.com', NULL, 0, NULL, '2026-03-09T05:21:02.003616+00:00'),
  ('io-github-nk3750-jitapi', 'io.github.nk3750/jitapi', 'Turn any OpenAPI spec into an executable agent interface using graphs and semantic search.', '@nk3750', 'development', 'Unknown', 3, 'https://github.com/nk3750/jitapi', NULL, 0, 'https://github.com/nk3750.png?size=128', '2026-03-09T05:21:02.003742+00:00'),
  ('web-crawler', 'Web Crawler', 'This web crawler MCP server, implemented in TypeScript, provides a flexible and configurable tool for crawling websites and extracting content. It integrates with the Model Context Protocol SDK and uses libraries like Axios and Cheerio for efficient web scraping. The crawler respects robots.txt rules, handles concurrent requests, and offers customizable depth, delay, and timeout settings. It stands out by providing a simple JSON interface for initiating crawls and retrieving structured results, making it ideal for AI systems or applications that need to gather web content programmatically. Use cases include data collection for training models, content aggregation, or web monitoring tasks.', '@jitsmaster', 'development', 'Unknown', 1, 'https://github.com/jitsmaster/webscrapemcpserver', NULL, 0, 'https://github.com/jitsmaster.png?size=128', '2026-03-09T05:21:02.003772+00:00'),
  ('ghost-bridge', 'Ghost Bridge', 'Ghost Bridge enables developers to debug production JavaScript applications directly through Chrome DevTools integration without requiring application restart. It provides tools for real-time code inspection, DOM manipulation, network request analysis, and runtime behavior analysis on minified code without source maps. The server communicates with a Chrome MV3 extension via WebSocket to access Chrome Debugger Protocol.', '@jiujiubanban', 'development', 'Unknown', 1, 'https://github.com/jiujiubanban/ghost-bridge-mcp', NULL, 0, 'https://github.com/jiujiubanban.png?size=128', '2026-03-09T05:21:02.003793+00:00'),
  ('dynamodb-readonly', 'DynamoDB Readonly', 'A read-only MCP server for querying AWS DynamoDB databases, enabling natural language interactions with database tables through tools like listing tables, scanning data, querying with conditions, and retrieving table schemas. Built by Yunjik Kim, this implementation provides a standardized interface for LLMs to explore and extract information from DynamoDB without requiring direct database access or complex query writing.', '@jjikky', 'databases', 'Unknown', 2, 'https://github.com/jjikky/dynamo-readonly-mcp', 'dynamo-readonly-mcp', 4928, 'https://github.com/jjikky.png?size=128', '2026-03-09T05:21:02.003804+00:00'),
  ('korean-stock-market-dart-krx', 'Korean Stock Market (DART & KRX)', 'Korea Stock MCP provides access to Korean stock market data through integration with DART (Korea''s electronic disclosure system) and KRX (Korea Exchange) APIs. Built by jjlabsio using TypeScript and the MCP SDK, it offers financial data retrieval including company information, trading data, financial statements, disclosure documents, and market classifications for KOSPI, KOSDAQ, and KONEX markets. The server requires API keys for both DART and KRX services and includes utilities for XML parsing, ZIP file handling, and structured data validation using Zod schemas, making it valuable for financial analysis, investment research, and Korean market monitoring use cases.', '@jjlabsio', 'development', 'Unknown', 36, 'https://github.com/jjlabsio/korea-stock-mcp', 'korea-stock-mcp', 1228, 'https://github.com/jjlabsio.png?size=128', '2026-03-09T05:21:02.003835+00:00'),
  ('qgis', 'QGIS', 'QGIS MCP provides a bridge between AI assistants and QGIS (Quantum GIS) through a socket-based server-client architecture. The implementation consists of a QGIS plugin that runs a server inside the GIS application, exposing geospatial capabilities like adding layers, executing processing algorithms, and rendering maps, while an MCP server component translates these capabilities into tools that can be called by AI assistants. This enables AI systems to perform complex GIS operations such as loading projects, manipulating vector and raster data, and generating map visualizations without requiring direct QGIS knowledge.', '@jjsantos01', 'productivity', 'Unknown', 823, 'https://github.com/jjsantos01/qgis_mcp', NULL, 0, 'https://github.com/jjsantos01.png?size=128', '2026-03-09T05:21:02.003889+00:00'),
  ('artifex', 'Artifex', 'Provides image generation capabilities through multiple providers including Antigravity (Google''s Gemini 3 Pro Image) and OpenAI DALL-E with session-based character consistency, multiple aspect ratios, image editing, and multi-image generation for creative workflows.', '@jkalasas', 'ai-ml', 'Unknown', 7, 'https://github.com/jkalasas/artifex-mcp', NULL, 0, 'https://github.com/jkalasas.png?size=128', '2026-03-09T05:21:02.003920+00:00'),
  ('bear', 'Bear', 'This MCP server, developed by Junpei Kawamoto, provides a standardized interface for interacting with Bear note-taking software. Built with Python and leveraging FastAPI, it offers tools for managing notes, tags, and other Bear-specific features. The implementation focuses on exposing Bear''s functionality through a consistent MCP interface, enabling AI models to perform note creation, search, and organization operations. By connecting AI assistants with Bear''s robust note-taking capabilities, this server facilitates sophisticated knowledge management scenarios like automated note creation, content categorization, and information retrieval. It''s particularly valuable for users and applications aiming to enhance personal knowledge management through AI-powered interactions with Bear.', '@jkawamoto', 'ai-ml', 'Unknown', 67, 'https://github.com/jkawamoto/mcp-bear', NULL, 0, 'https://github.com/jkawamoto.png?size=128', '2026-03-09T05:21:02.003969+00:00'),
  ('florence-2', 'Florence-2', 'This MCP server implementation provides a bridge to Florence-2, a powerful image processing model. Developed by Junpei Kawamoto, it enables AI assistants to perform advanced image analysis and manipulation tasks. The server utilizes PyTorch and Hugging Face''s Transformers library to leverage Florence-2''s capabilities. It''s designed for seamless integration into existing AI workflows, making it particularly useful for applications requiring sophisticated image understanding, such as visual question answering, image captioning, or content-based image retrieval. The implementation focuses on efficient processing and easy deployment, with support for various Python environments and package management systems.', '@jkawamoto', 'productivity', 'Unknown', 6, 'https://github.com/jkawamoto/mcp-florence2', NULL, 0, 'https://github.com/jkawamoto.png?size=128', '2026-03-09T05:21:02.004012+00:00'),
  ('memos', 'Memos', 'Integrates with Memos, an open-source self-hosted note-taking service. Enables creation of memos with customizable visibility settings (private, protected, or public) and attachment of files via Base64-encoded data or URLs. Provides seamless note management and organization for Memos instances.', '@jkawamoto', 'development', 'Unknown', 0, 'https://github.com/jkawamoto/mcp-memos', NULL, 0, 'https://github.com/jkawamoto.png?size=128', '2026-03-09T05:21:02.004033+00:00'),
  ('youtube-transcripts', 'YouTube Transcripts', 'This MCP server, developed by Junpei Kawamoto, provides integration with YouTube''s transcript API to retrieve captions for given video URLs. Built with Python and leveraging libraries like mcp and youtube-transcript-api, it offers a straightforward way to access video transcripts through a standardized interface. The implementation focuses on simplicity and ease of use, making it compatible with both Goose CLI and Goose Desktop. By connecting AI models with YouTube''s vast repository of video content, this server enables scenarios such as content analysis, subtitle generation, and information extraction from video sources. It''s particularly useful for applications and AI assistants that need to process or reference spoken content from YouTube videos.', '@jkawamoto', 'ai-ml', 'Unknown', 335, 'https://github.com/jkawamoto/mcp-youtube-transcript', NULL, 0, 'https://github.com/jkawamoto.png?size=128', '2026-03-09T05:21:02.004080+00:00'),
  ('ai-assisted-insights-agent', 'AI-Assisted Insights Agent', 'Translates natural language questions into accurate, explainable SQL queries and data insights. Connects to various data sources including PostgreSQL, Snowflake, BigQuery, and Redshift, providing configurable metric definitions, business glossary mappings, and data quality validation. Features query history tracking, template management, metric comparison tools, and integration examples for Claude Desktop, Jupyter notebooks, and Python applications.', '@jkelleman', 'databases', 'Unknown', 2, 'https://github.com/jkelleman/ai-assisted-insights-agent', NULL, 0, 'https://github.com/jkelleman.png?size=128', '2026-03-09T05:21:02.004094+00:00'),
  ('semantic-metrics-modeling-assistant', 'Semantic Metrics Modeling Assistant', 'A semantic metrics modeling assistant that helps data teams manage metric definitions with governance, quality assessment, and visualization capabilities. The system provides a database for storing metric definitions with change history tracking, calculates dynamic trust scores based on factors like test coverage, usage patterns, freshness, and documentation quality, and exports metrics to popular BI tools like Looker, Tableau, and dbt. Includes lineage visualization through ASCII trees and Mermaid diagrams, metric validation, and impact analysis for downstream dependencies.', '@jkelleman', 'databases', 'Unknown', 3, 'https://github.com/jkelleman/semantic-metrics-modeling-assistant', NULL, 0, 'https://github.com/jkelleman.png?size=128', '2026-03-09T05:21:02.004106+00:00'),
  ('hangul-word-processor', 'Hangul Word Processor', 'HWP MCP Server provides a bridge between AI assistants and Hangul Word Processor (HWP) documents, enabling document manipulation through a standardized interface. The implementation supports both Python (Flask-based) and Node.js versions, utilizing the HWP COM interface via pywin32 or winax respectively to control document operations. This server allows AI assistants to create, edit, and format Korean documents in the proprietary HWP format, making it particularly valuable for workflows involving Korean language document processing that require direct interaction with the Hangul Office suite.', '@jkf87', 'ai-ml', 'Unknown', 219, 'https://github.com/jkf87/hwp-mcp', NULL, 0, 'https://github.com/jkf87.png?size=128', '2026-03-09T05:21:02.004148+00:00'),
  ('qanon', 'QAnon', 'A Python-based MCP server that provides access to QAnon posts and related conspiracy theory content. This server allows AI models to retrieve information about QAnon posts, drops, and conspiracy theories when prompted by users.', '@jkingsman', 'ai-ml', 'Unknown', 2, 'https://github.com/jkingsman/qanon-mcp-server', 'qanon_mcp', 0, 'https://github.com/jkingsman.png?size=128', '2026-03-09T05:21:02.004173+00:00'),
  ('schwab', 'Schwab', 'Schwab MCP Server provides a bridge between Claude and the Schwab API, enabling access to financial account information, stock quotes, and transaction history directly within conversations. Built by jkoelker, it authenticates with Schwab using OAuth tokens and exposes nine tools for retrieving account details, positions, user preferences, quotes, orders, and transactions. The server runs on stdio transport, making it compatible with Claude Desktop integration, and includes robust error handling for authentication and API failures. Particularly valuable for financial advisors and investors who need to access Schwab account information without leaving their conversation interface.', '@jkoelker', 'ai-ml', 'Unknown', 34, 'https://github.com/jkoelker/schwab-mcp', NULL, 0, 'https://github.com/jkoelker.png?size=128', '2026-03-09T05:21:02.004218+00:00'),
  ('myai-memory', 'myAI Memory', 'myAI Memory Sync is an MCP server that synchronizes personal memory templates across different Claude interfaces, including Claude Desktop, Claude Web, and Windsurf. Built with TypeScript, it provides tools for retrieving, updating, and managing structured memory sections through both stdio and HTTP transports. The implementation features robust error handling, emergency synchronization capabilities, and natural language parsing to convert unstructured text into formatted template sections. It''s particularly valuable for maintaining consistent user preferences, personal information, and response styles across multiple AI platforms without manual copying.', '@jktfe', 'development', 'Unknown', 8, 'https://github.com/jktfe/myaimemory-mcp', NULL, 0, 'https://github.com/jktfe.png?size=128', '2026-03-09T05:21:02.004247+00:00'),
  ('servemyapi-macos-keychain', 'ServeMyAPI (macOS Keychain)', 'ServeMyAPI is a macOS-specific MCP server that securely stores and retrieves API keys using the native macOS Keychain. Developed by James King, it solves the common problem of managing sensitive credentials across multiple projects without exposing them in .env files. The server provides tools for storing, retrieving, listing, and deleting API keys through a consistent interface, making them accessible to AI assistants via natural language requests. This implementation is particularly valuable for developers who want to maintain security while allowing their AI tools to access necessary API credentials without manual intervention.', '@jktfe', 'productivity', 'Unknown', 23, 'https://github.com/jktfe/servemyapi', NULL, 0, 'https://github.com/jktfe.png?size=128', '2026-03-09T05:21:02.004292+00:00'),
  ('paelladoc', 'Paelladoc', 'PAELLADOC is a documentation-focused MCP server implementation that enables AI assistants to generate structured documentation for software projects. Built with a hexagonal architecture in Python, it provides tools for code analysis, template management, and documentation generation through commands like PAELLA (project initialization), CONTINUE (resume work), and GENERATE_DOC (create documentation from code). The system maintains project memory in SQLite, supports various programming styles and Git workflows, and includes a comprehensive template library organized by MECE principles. Particularly valuable for teams seeking consistent documentation practices across different project types, from frontend React applications to Chrome extensions.', '@jlcases', 'databases', 'Unknown', 342, 'https://github.com/jlcases/paelladoc', 'paelladoc', 5492, 'https://github.com/jlcases.png?size=128', '2026-03-09T05:21:02.004304+00:00'),
  ('odoo-assistant', 'Odoo Assistant', 'Provides direct integration with Odoo ERP systems via XML-RPC, offering specialized tools for model introspection, data operations, and workflow automation. Features comprehensive model discovery tools for exploring Odoo''s structure, operational tools for search and CRUD operations with validation, and workflow tools for executing business actions like confirming orders or posting invoices. Includes a documentation system for storing reusable standard operating procedures (SOPs) and supports both stdio and HTTP transports. Compatible with Odoo versions 14 through 19.', '@jldb-xyz', 'ai-ml', 'Unknown', 4, 'https://github.com/jldb-xyz/odoo-assistant-mcp', NULL, 0, 'https://github.com/jldb-xyz.png?size=128', '2026-03-09T05:21:02.004351+00:00'),
  ('pokemon-tcg-card-search', 'Pokemon TCG Card Search', 'This Pokemon TCG Card Search MCP server enables Claude to search and display Pokemon Trading Card Game cards with rich filtering capabilities. Built with TypeScript and the Model Context Protocol SDK, it interfaces with the Pokemon TCG API to provide detailed card information including images, stats, and pricing data. The implementation supports advanced search syntax with features like exact matching, wildcards, range queries, and multiple filter combinations for attributes such as card name, type, subtype, legality, and more. It''s particularly useful for Pokemon TCG enthusiasts who want to quickly find specific cards, check card legalities for tournament play, or explore card collections through natural language queries.', '@jlgrimes', 'development', 'Unknown', 8, 'https://github.com/jlgrimes/ptcg-mcp', NULL, 0, 'https://github.com/jlgrimes.png?size=128', '2026-03-09T05:21:02.004396+00:00'),
  ('sanity-io', 'Sanity.io', 'This MCP server provides tools for managing draft posts in a Sanity.io project. It allows creating, listing, and publishing draft posts through a simple API interface. The server integrates with Sanity.io''s content management system, offering a streamlined workflow for content creators and editors working with draft content in Sanity-powered websites or applications.', '@jlmelis', 'productivity', 'Unknown', 1, 'https://github.com/jlmelis/sanity-mcp-server', NULL, 0, 'https://github.com/jlmelis.png?size=128', '2026-03-09T05:21:02.004429+00:00'),
  ('secondhand-marketplace-search', 'Secondhand Marketplace Search', 'Provides unified search capabilities across multiple secondhand marketplaces including Facebook Marketplace, eBay, and Depop through a single interface. Uses Facebook''s internal GraphQL API for location-based searches without authentication, eBay''s official Browse API with OAuth credentials, and Puppeteer-based browser automation for Depop with advanced filtering options. Supports comprehensive search parameters including price ranges, conditions, categories, sizes, and colors, plus detailed listing retrieval with full descriptions, images, seller information, and shipping details.', '@jlsookiki', 'ai-ml', 'Unknown', 5, 'https://github.com/jlsookiki/secondhand-mcp', NULL, 0, 'https://github.com/jlsookiki.png?size=128', '2026-03-09T05:21:02.004472+00:00'),
  ('whatsapp', 'WhatsApp', 'WhatsApp MCP Server connects AI agents to personal WhatsApp accounts using TypeScript and the Baileys library. It stores messages and authentication locally in SQLite and provides tools for searching contacts, retrieving message history, listing chats, and sending messages. The implementation includes QR code authentication, real-time event handling, and comprehensive privacy controls, making it ideal for users who want their AI assistants to interact with WhatsApp conversations without compromising data security.', '@jlucaso1', 'databases', 'Unknown', 48, 'https://github.com/jlucaso1/whatsapp-mcp-ts', NULL, 0, 'https://github.com/jlucaso1.png?size=128', '2026-03-09T05:21:02.004483+00:00'),
  ('remote-docker', 'Remote Docker', 'Docker MCP provides AI-powered Docker management across multiple remote hosts through SSH connections, enabling container lifecycle management, Docker Compose stack operations, and data migration between hosts. Built with FastMCP and featuring containerized rsync transfers to solve permission issues, it supports automatic host discovery from SSH configs, persistent compose file storage, port conflict detection, and comprehensive cleanup operations. The implementation includes OAuth authentication, rate limiting, hot-reload configuration, and safety mechanisms to prevent destructive operations, making it valuable for managing distributed Docker environments, migrating workloads between servers, and providing AI assistants with secure access to containerized infrastructure across development, staging, and production environments.', '@jmagar', 'cloud', 'Unknown', 3, 'https://github.com/jmagar/docker-mcp', NULL, 0, 'https://github.com/jmagar.png?size=128', '2026-03-09T05:21:02.004509+00:00'),
  ('gotify', 'Gotify', 'Integrates with self-hosted Gotify notification servers to send push notifications with configurable priority, manage applications and clients, retrieve messages and server health status, and delete messages and applications. Supports both SSE and stdio transports.', '@jmagar', 'development', 'Unknown', 2, 'https://github.com/jmagar/gotify-mcp', NULL, 0, 'https://github.com/jmagar.png?size=128', '2026-03-09T05:21:02.004569+00:00'),
  ('google-news-trends', 'Google News & Trends', 'Google News Trends MCP server that provides access to Google News RSS feeds and Google Trends data through a Python implementation using the gnews and trendspy libraries. The server offers tools to search for news articles by keyword, location, or topic, retrieve top news stories, and fetch trending search terms by geographic region, with optional article summarization using either LLM sampling or NLP processing via newspaper4k. Built with FastMCP and featuring robust web scraping capabilities including Playwright fallback for difficult-to-scrape sites, it''s designed for news monitoring, trend analysis, and content research workflows where users need structured access to current news data and search trends.', '@jmanek', 'ai-ml', 'Unknown', 68, 'https://github.com/jmanek/google-news-trends-mcp', 'google-news-trends-mcp', 14663, 'https://github.com/jmanek.png?size=128', '2026-03-09T05:21:02.004619+00:00'),
  ('dart', 'Dart', 'This MCP server implementation provides a bridge between AI assistants and the Dart task management system. Developed by jmanhype, it offers tools for task creation, document handling, workspace organization, and integration with Dartboard features. Built using TypeScript and Node.js, with Python dependencies for the Dart SDK, the server focuses on secure API token management and easy setup. It is particularly useful for AI applications that need to automate project management tasks, organize documents, or integrate task tracking into their workflows. The implementation leverages the Model Context Protocol SDK and provides a flexible interface for executing Dart-related operations, making it ideal for enhancing AI-driven productivity and collaboration tools.', '@jmanhype', 'development', 'Unknown', 5, 'https://github.com/jmanhype/dart-mcp-server', NULL, 0, 'https://github.com/jmanhype.png?size=128', '2026-03-09T05:21:02.004650+00:00'),
  ('flux-studio', 'Flux Studio', 'MCP Flux Studio bridges Flux''s advanced image generation capabilities to AI coding assistants in Cursor and Windsurf (Codeium) IDEs. This TypeScript server implementation exposes four tools through the Model Context Protocol: text-to-image generation, image-to-image transformation, inpainting with customizable masks, and structural control generation (canny, depth, pose). It works by translating MCP tool calls into commands for the Flux CLI, executing them via Python, and returning the results to the IDE. Particularly valuable for developers who need to generate or manipulate images directly within their coding workflow without switching contexts.', '@jmanhype', 'development', 'Unknown', 24, 'https://github.com/jmanhype/mcp-flux-studio', NULL, 0, 'https://github.com/jmanhype.png?size=128', '2026-03-09T05:21:02.004679+00:00'),
  ('vggt-mps', 'VGGT-MPS', 'This VGGT-MPS server provides 3D vision and reconstruction capabilities optimized for Apple Silicon through MPS acceleration, implementing the VGGT (Vision-based Geometry and Tracking Transformer) model for multi-view 3D reconstruction from image sequences. Built with PyTorch and FastMCP, it offers tools for camera pose estimation, depth prediction, 3D point cloud generation, and point tracking across video frames, featuring specialized MPS optimizations for efficient inference on Apple''s Metal Performance Shaders framework. The implementation includes Gradio web interfaces, COLMAP integration for structure-from-motion workflows, and sparse attention mechanisms for scaling to large image collections, making it valuable for researchers and developers working on 3D computer vision applications who need GPU-accelerated reconstruction on Mac hardware without CUDA dependencies.', '@jmanhype', 'communication', 'Unknown', 86, 'https://github.com/jmanhype/vggt-mps', NULL, 0, 'https://github.com/jmanhype.png?size=128', '2026-03-09T05:21:02.004725+00:00'),
  ('jmap-email', 'JMAP Email', 'This MCP server provides email management capabilities through JMAP (JSON Meta Application Protocol) integration, built by Wyatt Johnson using Deno and the jmap-jam client library. It offers tools for email search and retrieval, mailbox management, email actions (marking, moving, deleting), and email composition with reply functionality, automatically adapting to server capabilities and read-only account restrictions. The implementation works with any JMAP-compliant email server including Cyrus IMAP, Stalwart Mail Server, FastMail, and Apache James, making it valuable for AI assistants that need programmatic email access with proper JMAP RFC 8620/8621 compliance and functional programming patterns throughout.', '@wyattjoh', 'communication', 'Unknown', 164, 'https://github.com/wyattjoh/jmap-mcp', NULL, 0, 'https://github.com/wyattjoh.png?size=128', '2026-03-09T05:21:02.004761+00:00'),
  ('signaturit', 'Signaturit', 'Signaturit Tools Demo is an MCP server that integrates with the Signaturit API, enabling AI assistants to manage electronic signatures and contacts through natural language commands. Built with Go using the mark3labs/mcp-go library, this implementation provides tools for creating, tracking, and managing digital signature workflows, as well as handling contact information within the Signaturit platform. The server exposes functionality for signature creation, status checking, reminders, and cancellation, along with comprehensive contact management operations, making it ideal for businesses looking to automate document signing processes through conversational AI interfaces.', '@jmartin82', 'development', 'Unknown', 1, 'https://github.com/jmartin82/signaturit-mcp', NULL, 0, 'https://github.com/jmartin82.png?size=128', '2026-03-09T05:21:02.004785+00:00'),
  ('markdown-web-crawl', 'Markdown Web Crawl', 'This MCP implementation, developed by JMH, is a Python-based web crawler designed for extracting and saving website content as markdown files. It offers features like website structure mapping, batch URL processing, and configurable output settings. The project integrates with FastMCP for easy installation and deployment, and leverages libraries such as BeautifulSoup and requests for efficient web scraping. Its focus on markdown output and straightforward configuration makes it particularly suitable for content aggregation, site archiving, or building knowledge bases from web sources. The crawler''s ability to create content indexes and its support for concurrent requests set it apart as a tool for both small-scale personal projects and larger data collection tasks.', '@jmh108', 'development', 'Unknown', 4, 'https://github.com/jmh108/md-webcrawl-mcp', NULL, 0, 'https://github.com/jmh108.png?size=128', '2026-03-09T05:21:02.004815+00:00'),
  ('readability-fetch-parse', 'Readability (Fetch & Parse)', 'This Python-based MCP server, developed by JMH, provides a robust solution for extracting and transforming webpage content into clean, LLM-optimized Markdown. Built on FastMCP and integrating libraries like readability-lxml and html2text, it offers a single powerful tool for fetching, parsing, and converting web content. The implementation stands out by removing non-essential elements like ads and navigation, while preserving key metadata such as title, excerpt, and author. It''s particularly useful for developers and researchers who need to process web content for AI analysis, content aggregation, or data extraction tasks, offering a more refined and consistent output compared to simple web scraping methods.', '@jmh108', 'productivity', 'Unknown', 4, 'https://github.com/jmh108/mcp-server-readability-python', NULL, 0, 'https://github.com/jmh108.png?size=128', '2026-03-09T05:21:02.004870+00:00'),
  ('security-infrastructure', 'Security Infrastructure', 'This security infrastructure MCP server provides unified access to three major security platforms - Splunk SIEM, CrowdStrike EDR, and Microsoft MISP - through a comprehensive web interface and backend API integration. Built with Python async/await patterns and featuring both MCP server implementations and a React-based documentation frontend, it enables security analysts to perform cross-platform threat hunting, search security events, retrieve detections, and query threat intelligence through natural language interactions. The implementation includes Docker containerization, comprehensive test coverage, and a live documentation site with interactive code examples, making it valuable for SOC operations where analysts need to correlate data across multiple security tools without switching between different vendor interfaces.', '@jmstar85', 'cloud', 'Unknown', 21, 'https://github.com/jmstar85/securityinfrastructure', NULL, 0, 'https://github.com/jmstar85.png?size=128', '2026-03-09T05:21:02.004934+00:00'),
  ('french-legal-research', 'French Legal Research', 'A French legal research MCP server that integrates with both the Légifrance and Judilibre APIs to provide access to French legal documents, case law, and jurisprudence. Created by Jean-Michel Tanguy, it bridges these official French government legal databases through a unified interface, enabling search and retrieval of legal texts, court decisions, and regulatory documents. The implementation includes specialized input/output handling for legal search queries and supports both development and production environments through comprehensive configuration options, making it useful for legal research, compliance analysis, and building French law-focused applications.', '@jmtanguy', 'databases', 'Unknown', 10, 'https://github.com/jmtanguy/droit-francais-mcp', NULL, 0, 'https://github.com/jmtanguy.png?size=128', '2026-03-09T05:21:02.004954+00:00'),
  ('mist-cash', 'MIST.cash', 'Integrates with MIST.cash SDK to enable privacy-preserving payments on Starknet blockchain. Provides tools for generating transaction secrets using claiming keys and recipient addresses, calculating transaction hashes, fetching transaction assets, verifying transaction existence for fully private transactions, and retrieving Chamber contract configuration. Supports multiple tokens including ETH, USDC, USDT, and DAI with robust validation using Zod schemas and retry logic with exponential backoff for network operations.', '@joadataarg', 'ai-ml', 'Unknown', 1, 'https://github.com/joadataarg/mcp-mistcash', NULL, 0, 'https://github.com/joadataarg.png?size=128', '2026-03-09T05:21:02.004994+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('job-stock-analysis-nse', 'Job & Stock Analysis (NSE)', 'Multi-component MCP server implementation by Somnath Chattaraj that combines job search capabilities with NSE stock recommendations using Google Gemini AI and web scraping. The implementation includes two distinct components: a Python-based bearer token server that provides job finding tools with web scraping, image processing, and a multi-agent stock analysis workflow using LangChain and LangGraph, plus a TypeScript-based GitHub OAuth server deployed on Cloudflare Workers that demonstrates user authentication and access control for MCP tools. The OAuth component showcases how to restrict tool access based on GitHub user identity, while the job/stock server integrates with Bright Data for web scraping and uses Gemini''s multi-agent approach for comprehensive Indian stock market analysis including price predictions and trading recommendations.', '@somnath-chattaraj', 'cloud', 'Unknown', 1, 'https://github.com/somnath-chattaraj/mcp-server', NULL, 0, 'https://github.com/somnath-chattaraj.png?size=128', '2026-03-09T05:21:02.005020+00:00'),
  ('claude-todo-emulator', 'Claude Todo Emulator', 'This MCP server by Joe Haddad emulates Claude Code''s task management system, providing persistent todo functionality for AI coding assistants in IDEs like Cursor, Windsurf, and others. The implementation features two core tools - TodoRead for retrieving current tasks and TodoWrite for complete list replacement - with built-in validation ensuring unique IDs, required fields, and business rules like allowing only one in-progress task at a time. It automatically creates workspace-local .mcp-todos.json files with proper gitignore integration and includes Cursor-specific rule files, making it valuable for developers who want AI assistants to maintain persistent task lists across coding sessions without relying on external services.', '@joehaddad2000', 'development', 'Unknown', 25, 'https://github.com/joehaddad2000/claude-todo-emulator', 'claude-todo-emulator', 7854, 'https://github.com/joehaddad2000.png?size=128', '2026-03-09T05:21:02.005076+00:00'),
  ('wikidata', 'Wikidata', 'MCP server implementation for Wikidata access, providing tools to search entities, retrieve detailed information, execute SPARQL queries, explore entity relations, and find items by property values. Built with Python using httpx for API communication and pydantic for configuration management, it offers both simplified and full-format entity data retrieval with configurable rate limiting, caching, and language support. Useful for knowledge graph exploration, fact-checking workflows, research applications, and any use case requiring structured access to Wikidata''s vast repository of linked open data through natural language interactions.', '@joelgombin', 'ai-ml', 'Unknown', 4, 'https://github.com/joelgombin/mcp-wikidata', NULL, 0, 'https://github.com/joelgombin.png?size=128', '2026-03-09T05:21:02.005120+00:00'),
  ('logseq-knowledge-graph', 'Logseq Knowledge Graph', 'Logseq MCP Tools provides AI assistants with structured access to Logseq knowledge graphs through a comprehensive set of tools for retrieving, analyzing, and manipulating data. Built with TypeScript using the Model Context Protocol SDK, it enables capabilities like retrieving page content, generating journal summaries, analyzing graph connections, identifying knowledge gaps, and suggesting potential connections between concepts. The implementation includes sophisticated natural language date parsing, DataScript query capabilities, and detailed content analysis features. It''s particularly valuable for users who want to leverage AI assistants to explore, organize, and gain insights from their personal knowledge bases without leaving their conversational interface.', '@joelhooks', 'development', 'Unknown', 66, 'https://github.com/joelhooks/logseq-mcp-tools', NULL, 0, 'https://github.com/joelhooks.png?size=128', '2026-03-09T05:21:02.005154+00:00'),
  ('tldraw-agent', 'Tldraw Agent', 'Converts natural language prompts into visual diagrams including architecture diagrams, flowcharts, and entity relationship diagrams. Uses LLM-powered layout generation with tldraw for rendering and Playwright for headless browser capture. Supports multiple interfaces: CLI, TypeScript library, and stdio-based MCP tool. Requires an AI Gateway API key for LLM access.', '@joelhooks', 'development', 'Unknown', 4, 'https://github.com/joelhooks/tldraw-agent', NULL, 0, 'https://github.com/joelhooks.png?size=128', '2026-03-09T05:21:02.005175+00:00'),
  ('comfyui', 'ComfyUI', 'This MCP server implementation provides a bridge between ComfyUI and MCP clients for image generation tasks. It uses WebSockets for communication, allowing clients to send image generation requests with customizable parameters like prompt, width, and height. The server processes these requests through ComfyUI and returns the generated image URL. It''s designed for easy integration into applications requiring on-demand AI image generation capabilities.', '@joenorton', 'productivity', 'Unknown', 213, 'https://github.com/joenorton/comfyui-mcp-server', NULL, 0, 'https://github.com/joenorton.png?size=128', '2026-03-09T05:21:02.005209+00:00'),
  ('joern-code-analysis', 'Joern (Code Analysis)', 'Joern-MCP is a server implementation that provides AI assistants with access to Joern''s code analysis capabilities through a Python interface. This server enables querying and analyzing Code Property Graphs (CPGs) by exposing tools for loading CPGs, retrieving method and class code, examining call relationships, and executing custom queries against the Joern backend. Built on the FastMCP framework, it handles communication with a remote Joern instance via HTTP requests, making it particularly valuable for security researchers and developers who need to perform static code analysis, identify vulnerabilities, or understand code structure and dependencies through AI assistants.', '@sfncat', 'development', 'Unknown', 38, 'https://github.com/sfncat/mcp-joern', NULL, 0, 'https://github.com/sfncat.png?size=128', '2026-03-09T05:21:02.005236+00:00'),
  ('joe-sandbox-cloud', 'Joe Sandbox Cloud', 'This Joe Sandbox Cloud MCP server by Joe Security LLC provides AI agents with malware analysis capabilities through the Joe Sandbox Cloud API, offering tools for file and URL submission, analysis querying, IOC extraction (domains, IPs, URLs, signatures), AI-powered threat summaries, and artifact downloads (unpacked files, PCAP network captures). Built with Python using FastMCP and featuring async report caching, XML parsing for detailed analysis data, process tree extraction, and comprehensive error handling, the implementation supports both immediate and polling-based analysis workflows with configurable parameters for sandbox environments. The server integrates with Claude Desktop through API key authentication and Terms & Conditions acceptance, making it valuable for threat intelligence gathering, malware research, incident response automation, and building AI assistants that need professional-grade dynamic and static malware analysis capabilities with detailed behavioral insights.', '@joesecurity', 'development', 'Unknown', 9, 'https://github.com/joesecurity/joesandboxmcp', NULL, 0, 'https://github.com/joesecurity.png?size=128', '2026-03-09T05:21:02.005278+00:00'),
  ('qiniu-cloud-storage', 'Qiniu Cloud Storage', 'Qiniu MCP Server provides a bridge to Qiniu Cloud Storage services, enabling AI assistants to upload files to the cloud and retrieve public URLs. Built with FastMCP and the Qiniu Python SDK, this implementation exposes a single tool for file uploading that handles authentication, generates unique file keys, and manages the upload process. The server uses environment variables for configuration of access credentials and bucket settings, making it valuable for applications that need to store and share files through Qiniu''s object storage infrastructure.', '@joeseesun', 'ai-ml', 'Unknown', 28, 'https://github.com/joeseesun/qiniu-mcp-joe', NULL, 0, 'https://github.com/joeseesun.png?size=128', '2026-03-09T05:21:02.005320+00:00'),
  ('seedream-volcengine', 'Seedream (Volcengine)', 'Integrates with Volcengine''s Seedream 4.0 image generation API to provide text-to-image generation, image-to-image transformation, multi-image fusion capabilities, and sequential generation workflows. Features 8 preset style templates including trendy party, WeChat cover, and cyberpunk themes, with automatic local image saving organized by date, optional Qiniu cloud storage integration for permanent public URLs, and configurable prompt templates with robust error handling and retry mechanisms.', '@joeseesun', 'communication', 'Unknown', 17, 'https://github.com/joeseesun/seedream_mcp', NULL, 0, 'https://github.com/joeseesun.png?size=128', '2026-03-09T05:21:02.005359+00:00'),
  ('coding-with-perplexity-ai', 'Coding With Perplexity AI', 'This MCP server, developed by Joe Wilson, integrates Perplexity AI with the Model Context Protocol to provide intelligent coding assistance. Built with TypeScript and leveraging the MCP SDK, it offers a streamlined interface for AI-powered code analysis, generation, and problem-solving. The server implements robust error handling, asynchronous operations, and configurable settings for API keys. By combining Perplexity''s advanced language understanding with MCP''s standardized communication protocol, this implementation enables AI assistants to provide context-aware coding support across various programming languages and project structures. It is particularly useful for developers seeking AI-enhanced productivity in tasks such as code review, refactoring, and debugging, as well as for creating intelligent coding tools and IDE plugins.', '@politwit1984', 'development', 'Unknown', 14, 'https://github.com/politwit1984/mcp-perplexity-server', NULL, 0, 'https://github.com/politwit1984.png?size=128', '2026-03-09T05:21:02.005389+00:00'),
  ('second-opinion-code-assistant', 'Second Opinion (Code Assistant)', 'This MCP server, developed by Joe Wilson, combines insights from Google''s Gemini AI, Stack Overflow, and Perplexity AI to provide enhanced coding assistance. Built with TypeScript and the MCP SDK, it offers automatic language detection, code snippet extraction, and git-aware context gathering. The implementation stands out by synthesizing multiple AI and knowledge sources into structured, markdown-formatted solutions. It''s particularly useful for developers seeking comprehensive answers to coding problems, best practices, and alternative approaches, enabling more informed decision-making during the development process.', '@politwit1984', 'development', 'Unknown', 15, 'https://github.com/politwit1984/second-opinion-mcp-server', NULL, 0, 'https://github.com/politwit1984.png?size=128', '2026-03-09T05:21:02.005418+00:00'),
  ('clojure-nrepl', 'Clojure nREPL', 'This nREPL MCP server implementation enables interaction between Anthropic Claude MCP clients and running Clojure nREPL instances. Developed by Johan Codinha, it provides functionalities such as Clojure code evaluation, namespace listing, and public var inspection. The server is designed to work seamlessly with Claude Desktop and CLine in VSCode, offering a bridge between AI assistants and Clojure development environments. It''s particularly useful for AI-assisted Clojure development, interactive code exploration, and integrating Clojure capabilities into AI workflows. The implementation emphasizes ease of setup and use, with support for both quick npx execution and manual installation options.', '@johancodinha', 'development', 'Unknown', 35, 'https://github.com/johancodinha/nrepl-mcp-server', 'nrepl-mcp-server', 3972, 'https://github.com/johancodinha.png?size=128', '2026-03-09T05:21:02.005445+00:00'),
  ('codesys', 'CODESYS', 'CODESYS MCP Toolkit provides AI assistants with direct integration to CODESYS V3 automation programming environments through Python scripting. Developed by johannesPettersson80, it enables seamless project management including opening/creating projects, POU (Program Organization Unit) creation and editing, code manipulation for declaration and implementation sections, and compilation tasks. The implementation uses CODESYS''s built-in scripting engine to execute operations via temporary Python scripts, handling path resolution, project state management, and robust error handling with retry logic. This toolkit is particularly valuable for automating PLC development workflows, standardizing function block libraries, and integrating CODESYS projects into CI/CD pipelines or AI-assisted programming environments.', '@johannespettersson80', 'development', 'Unknown', 31, 'https://github.com/johannespettersson80/codesys-mcp-toolkit', '@codesys/mcp-toolkit', 4546, 'https://github.com/johannespettersson80.png?size=128', '2026-03-09T05:21:02.005499+00:00'),
  ('microsoft-teams-notifications', 'Microsoft Teams Notifications', 'A Microsoft Teams notification server that enables sending markdown-formatted messages to a specified Teams channel using Azure AD authentication. Developed by John Miller, this MCP server provides a streamlined way to send notifications from development environments, with a specific focus on integration with VS Code Insiders. Useful for teams wanting to centralize communication and automate status updates directly from their development workflow.', '@therealjohn', 'cloud', 'Unknown', 2, 'https://github.com/therealjohn/microsoft-teams-mcp', NULL, 0, 'https://github.com/therealjohn.png?size=128', '2026-03-09T05:21:02.005545+00:00'),
  ('geth-proxy', 'Geth Proxy', 'This MCP server by John H. Mitander provides a proxy bridge to Ethereum JSON-RPC endpoints, specifically designed for Geth nodes, enabling AI assistants to query blockchain data and execute Ethereum operations through a comprehensive set of tools. The implementation exposes standard Ethereum RPC methods (eth_blockNumber, eth_getBalance, eth_call, etc.) alongside Geth-specific admin, debug, and transaction pool APIs, with built-in safety features like disabled transaction broadcasting by default and automatic hex-to-decimal conversions for better readability. It includes both canonical JSON-RPC method names and friendly aliases (getBalance, getBlock, etc.), making it accessible for blockchain analysis, DeFi interactions, node monitoring, and Ethereum development workflows where AI agents need programmatic access to on-chain data.', '@john0n1', 'development', 'Unknown', 2, 'https://github.com/john0n1/ethereum-mcp', NULL, 0, 'https://github.com/john0n1.png?size=128', '2026-03-09T05:21:02.005577+00:00'),
  ('code-indexer', 'Code Indexer', 'Code Index MCP enables large language models to index, search, and analyze code in project directories. It provides tools for navigating file structures, searching for patterns in code, generating file summaries, and analyzing code complexity across multiple programming languages. The implementation uses UV for dependency management, stores project settings persistently in a .code_indexer folder, and integrates easily with Claude Desktop through a simple configuration process, making it ideal for developers who need to analyze codebases without leaving their AI assistant interface.', '@johnhuang316', 'development', 'Unknown', 812, 'https://github.com/johnhuang316/code-index-mcp', NULL, 0, 'https://github.com/johnhuang316.png?size=128', '2026-03-09T05:21:02.005642+00:00'),
  ('traktamente-swedish-travel-expenses', 'Traktamente (Swedish Travel Expenses)', 'Swedish traktamente (per diem) rates server providing access to official travel expense rates from Skatteverket (Swedish Tax Agency). Supports stdio and HTTP transports with Docker containerization and Cloudflare Workers deployment for scalable web access. Built with MCP SDK and Zod for schema validation using Bun runtime. Enables AI assistants to retrieve current Swedish business travel allowance rates for expense calculations, tax compliance, and travel planning.', '@johnie', 'cloud', 'Unknown', 1, 'https://github.com/johnie/traktamente-mcp', NULL, 0, 'https://github.com/johnie.png?size=128', '2026-03-09T05:21:02.005661+00:00'),
  ('netskope', 'Netskope', 'This Netskope MCP implementation, developed by John Neerdael, provides integration with the Netskope API for managing private access infrastructure. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers tools for publisher lifecycle management, private app configuration, policy creation, and traffic diagnostics. The implementation focuses on simplifying Netskope operations through a standardized MCP interface, with features like caching and retry logic. It''s particularly useful for network administrators and security teams needing to automate Netskope NPA tasks, enabling use cases such as infrastructure validation, policy enforcement, and access control management without directly dealing with the complexities of the Netskope API.', '@johnneerdael', 'development', 'Unknown', 6, 'https://github.com/johnneerdael/ns-private-access-mcp', '@johnneerdael/netskope-mcp', 2088, 'https://github.com/johnneerdael.png?size=128', '2026-03-09T05:21:02.005692+00:00'),
  ('swagger-explorer', 'Swagger Explorer', 'This Swagger Explorer MCP, developed by John Neerdael, enables AI agents to analyze and interact with Swagger/OpenAPI specifications. Built with TypeScript and leveraging Playwright for web scraping, it provides tools for extracting API endpoints, schemas, and documentation from Swagger UI interfaces. The implementation focuses on dynamic exploration of APIs, offering functionality to filter endpoints by HTTP method and analyze response schemas. It''s particularly useful for developers and AI assistants working with unfamiliar APIs, enabling use cases such as API integration planning, documentation review, and schema validation without manual parsing of Swagger specifications.', '@johnneerdael', 'development', 'Unknown', 20, 'https://github.com/johnneerdael/swagger-mcp', NULL, 0, 'https://github.com/johnneerdael.png?size=128', '2026-03-09T05:21:02.005722+00:00'),
  ('xcsift', 'xcsift', 'Wraps the xcsift CLI tool to parse Xcode build output into structured, token-efficient JSON or TOON formats, automatically managing the binary and providing tools to execute build commands with automatic parsing and extract specific errors, warnings, and test failures with file/line details.', '@johnnyclem', 'development', 'Unknown', 4, 'https://github.com/johnnyclem/xcsift-mcp', NULL, 0, 'https://github.com/johnnyclem.png?size=128', '2026-03-09T05:21:02.005742+00:00'),
  ('sqlite-node-js', 'SQLite (Node.js)', 'This Node.js MCP SQLite server, developed as an alternative to the Python reference implementation, provides a lightweight database solution for environments where Python''s UVX runner is unavailable. Built with TypeScript and leveraging the @modelcontextprotocol/sdk, it offers seamless integration with tools like Claude Desktop and LibreChat. The server implements core SQLite functionality through the sqlite3 package, enabling AI assistants to perform database operations via MCP. Its npx-based execution model simplifies deployment and usage across different Node.js environments. This implementation is particularly valuable for developers seeking a JavaScript-based MCP SQLite solution, facilitating use cases such as local data storage, simple database management, and integration of SQLite capabilities into Node.js-based AI applications.', '@johnnyoshika', 'databases', 'Unknown', 16, 'https://github.com/johnnyoshika/mcp-server-sqlite-npx', 'mcp-server-sqlite-npx', 12495, 'https://github.com/johnnyoshika.png?size=128', '2026-03-09T05:21:02.005754+00:00'),
  ('dgraph', 'Dgraph', 'Dgraph MCP Server provides a bridge between language models and Dgraph graph databases, enabling AI assistants to execute DQL queries, perform mutations, and manage database schemas. Built in Go using the mcp-go library, it exposes specialized tools for database operations and includes a resource endpoint for retrieving schema information. The implementation features a Docker-based deployment option with a complete Dgraph environment and includes example code for both simple database operations and a more complex movie database application. Ideal for developers who want to leverage AI assistants for graph database interactions without switching context to separate database tools.', '@johnymontana', 'databases', 'Unknown', 3, 'https://github.com/johnymontana/dgraph-mcp-server', NULL, 0, 'https://github.com/johnymontana.png?size=128', '2026-03-09T05:21:02.005814+00:00'),
  ('pyghidra-lite', 'PyGhidra Lite', 'Lightweight MCP server for Ghidra-based reverse engineering with iOS, Linux, and game file support. Provides token-efficient decompilation, Swift/ObjC analysis, ELF/Mach-O binary support, and async progress tracking.', '@johnzfitch', 'file-systems', 'Unknown', 33, 'https://github.com/johnzfitch/pyghidra-lite', NULL, 0, 'https://github.com/johnzfitch.png?size=128', '2026-03-09T05:21:02.005863+00:00'),
  ('xero-accounting', 'Xero Accounting', 'Xero MCP Server enables Claude to interact with Xero Accounting Software through a set of tools that access financial data. Developed by John Zhang, it provides authenticated access to Xero''s API for retrieving accounts, bank transactions, contacts, invoices, journals, organizations, payments, and quotes. The implementation uses OAuth2 authentication and handles API session management, making it valuable for financial analysis, bookkeeping tasks, and accounting workflows without leaving the conversation interface. Future development plans include adding transaction creation capabilities.', '@john-zhang-dev', 'development', 'Unknown', 18, 'https://github.com/john-zhang-dev/xero-mcp', 'xero-mcp', 5624, 'https://github.com/john-zhang-dev.png?size=128', '2026-03-09T05:21:02.005892+00:00'),
  ('readme-generator', 'README Generator', 'A README generator MCP server that automatically analyzes project directories to create well-formatted, professional README.md files with badges, emojis, and comprehensive sections. The server provides four tools: reading project structure with configurable depth and ignore patterns, reading individual files, analyzing projects to extract metadata from package.json and detect technologies (Node.js, TypeScript, Python, Rust, Go, Java, Docker), and generating complete READMs with installation instructions, usage examples, project structure visualization, and dependency listings. Built with TypeScript and the MCP SDK, it supports multiple programming languages and automatically formats directory structures, making it useful for developers who want to quickly generate professional documentation for their projects without manual formatting.', '@jojoslice', 'cloud', 'Unknown', 1, 'https://github.com/jojoslice/readme-gen-mcp-server', NULL, 0, 'https://github.com/jojoslice.png?size=128', '2026-03-09T05:21:02.005918+00:00'),
  ('containerd', 'Containerd', 'MCP-Containerd provides a bridge to Containerd''s Container Runtime Interface (CRI), enabling AI assistants to manage containers and pods through natural language commands. Built in Rust using the RMCP library, it offers tools for listing, creating, and removing containers and pods, with support for image management operations. The implementation connects to Containerd''s Unix socket and exposes its functionality through a standardized protocol, making it particularly useful for DevOps workflows where users need to monitor or manipulate container environments without remembering complex CLI commands.', '@jokemanfire', 'ai-ml', 'Unknown', 55, 'https://github.com/jokemanfire/mcp-containerd', 'mcp-containerd', 0, 'https://github.com/jokemanfire.png?size=128', '2026-03-09T05:21:02.005963+00:00'),
  ('software-planning', 'Software Planning', 'Software Planning MCP provides a structured approach for AI assistants to plan and organize software development projects. Built with Python using the FastMCP framework, it enables models to break down complex software tasks into manageable components, define project structures, and create implementation roadmaps. The server can be deployed via Docker or run locally, making it flexible for integration into various development workflows where systematic project planning and architecture design are needed.', '@wang-guanye', 'cloud', 'Unknown', 3, 'https://github.com/wang-guanye/software-planning-mcp', NULL, 0, 'https://github.com/wang-guanye.png?size=128', '2026-03-09T05:21:02.005987+00:00'),
  ('jolt-transform-web', 'JOLT Transform Web', 'An MCP server that provides Bazaarvoice JOLT transformation capabilities.', '@halversondm', 'search', 'Unknown', 0, 'https://github.com/halversondm/jolt-transform-web', NULL, 0, 'https://github.com/halversondm.png?size=128', '2026-03-09T05:21:02.006011+00:00'),
  ('playmcp-playwright-browser-automation', 'PlayMCP (Playwright Browser Automation)', 'This MCP server provides comprehensive browser automation capabilities using Playwright, enabling AI assistants to interact with web pages through a full suite of browser controls including navigation, clicking, typing, scrolling, and screenshot capture. Built with TypeScript and offering both headless and visual browser modes with debug logging, it provides extensive page content extraction tools for HTML source, text content, links, images, forms, meta tags, scripts, and stylesheets, plus the ability to execute arbitrary JavaScript code on pages and return results. The implementation maintains browser state across operations, includes detailed error handling with helpful suggestions, and supports both standard MCP protocol and legacy command formats, making it valuable for web scraping, automated testing, form filling, content analysis, and any scenario where AI assistants need to programmatically interact with websites and extract structured data from web pages.', '@jomon003', 'development', 'Unknown', 11, 'https://github.com/jomon003/playmcp', NULL, 0, 'https://github.com/jomon003.png?size=128', '2026-03-09T05:21:02.006046+00:00'),
  ('claude-code-agent', 'Claude Code Agent', 'A Claude Code Agent MCP server implementation that provides persistent memory management and project automation capabilities through a custom memory-dump server and integration with n8n workflow automation. The implementation features token-based authentication, automated memory dumps with cron scheduling, and comprehensive project state tracking including todos, project status, and knowledge management. Built with Node.js and the MCP SDK, it includes Windows-compatible automation scripts, Docker support for n8n integration, and multiple MCP servers (filesystem, memory, and custom memory-dump) working together to create a complete development workflow system for AI-assisted coding projects.', '@jomynn', 'cloud', 'Unknown', 3, 'https://github.com/jomynn/claude-code-agent-mcp-server', NULL, 0, 'https://github.com/jomynn.png?size=128', '2026-03-09T05:21:02.006071+00:00'),
  ('command-shell', 'Command Shell', 'A command execution server that provides secure shell command execution, directory navigation, and interactive program automation through pexpect integration. Built by Jon Allen, it features configurable command blocking and file access restrictions via TOML configuration, with safety controls that can be overridden when needed. The server includes tools for running shell commands with stdin support, changing directories with environment variable expansion, and automating interactive programs through expect/send sequences. Useful for system administration tasks, development workflows, and command-line tool interaction while maintaining security boundaries through customizable restrictions on dangerous commands and sensitive files.', '@jon2allen', 'development', 'Unknown', 1, 'https://github.com/jon2allen/mcp_command_serv', NULL, 0, 'https://github.com/jon2allen.png?size=128', '2026-03-09T05:21:02.006102+00:00'),
  ('rednote-xiaohongshu', 'RedNote (Xiaohongshu)', 'RedNote MCP provides a bridge to Xiaohongshu (Red Note) content, enabling AI assistants to access and interact with this popular Chinese social media platform. Built with TypeScript and Playwright, it handles authentication through cookie management, offers tools for retrieving note details, and includes robust logging capabilities with platform-specific storage paths. This implementation is particularly valuable for users who need to analyze trends, gather content, or monitor activity on Xiaohongshu without manual browsing.', '@jonafly', 'development', 'Unknown', 7, 'https://github.com/jonafly/rednote-mcp', NULL, 0, 'https://github.com/jonafly.png?size=128', '2026-03-09T05:21:02.006129+00:00'),
  ('pbixray', 'PBIXRay', 'PBIXRay MCP Server provides a bridge to analyze Power BI (.pbix) files through a Python-based interface. Developed by jonaolden, this implementation exposes PBIXRay''s capabilities as tools for exploring data models, querying languages (DAX and Power Query), and analyzing data structures with features like pagination and filtering. The server handles large file processing asynchronously with progress reporting, making it particularly valuable for data analysts and BI professionals who need to extract insights from Power BI files through AI assistants without switching tools.', '@jonaolden', 'ai-ml', 'Unknown', 39, 'https://github.com/jonaolden/pbixray-mcp-server', NULL, 0, 'https://github.com/jonaolden.png?size=128', '2026-03-09T05:21:02.006171+00:00'),
  ('power-bi-tabular', 'Power BI Tabular', 'The Tabular MCP Server (MCPBI) connects AI assistants to locally running Power BI Desktop tabular models via ADOMD.NET, enabling direct interaction with Power BI data models for DAX query execution and metadata retrieval. Built in C# for Windows environments, it provides predefined tools for exploring measures, tables, relationships, and data previews, plus flexible DAX query execution with full DEFINE block support for advanced analysis. The server includes automatic Power BI instance discovery, comprehensive security validation, enhanced error reporting with query context, and specialized prompts for DAX debugging, measure design, and relationship analysis, making it valuable for Power BI developers who need AI assistance with DAX development, model optimization, and troubleshooting complex calculations.', '@jonaolden', 'development', 'Unknown', 19, 'https://github.com/jonaolden/mcpbi', NULL, 0, 'https://github.com/jonaolden.png?size=128', '2026-03-09T05:21:02.006204+00:00'),
  ('openrouter-image-analysis', 'OpenRouter Image Analysis', 'OpenRouter Image MCP provides advanced image analysis capabilities through OpenRouter''s vision models, supporting multiple input formats including base64, file paths, and URLs. Built by JonathanJude using TypeScript and the MCP SDK, it offers three specialized tools: general image analysis, webpage screenshot analysis with focus areas like layout and accessibility, and mobile app screenshot analysis with platform-specific evaluation against iOS/Android design guidelines. The implementation includes robust error handling with timeouts, image validation and processing with Sharp, comprehensive logging, and structured JSON output options, making it valuable for UI/UX analysis, accessibility auditing, design review workflows, and any use case requiring detailed visual content understanding through state-of-the-art vision models.', '@jonathanjude', 'development', 'Unknown', 4, 'https://github.com/jonathanjude/openrouter-image-mcp', 'openrouter-image-mcp', 1570, 'https://github.com/jonathanjude.png?size=128', '2026-03-09T05:21:02.006240+00:00'),
  ('osmosis', 'Osmosis', 'Provides a bridge to the Osmosis blockchain protocol, enabling AI assistants to interact with decentralized finance capabilities like token swaps and account management. Built by Jon Ator, it exposes tools for querying balances, getting swap quotes, and executing trades through a standardized interface that handles transaction signing and broadcasting. Particularly valuable for users who want to perform DeFi operations through natural language interaction without dealing with low-level blockchain details.', '@jonator', 'ai-ml', 'Unknown', 9, 'https://github.com/jonator/osmosis-agent-toolkit/tree/HEAD/packages/mcp', '@osmosis-agent-toolkit/mcp', 361, 'https://github.com/jonator.png?size=128', '2026-03-09T05:21:02.006278+00:00'),
  ('openpyxl-excel', 'OpenPyXL Excel', 'OpenPyXL MCP Server provides a thin wrapper around the OpenPyXL Python library that enables Claude and other MCP clients to interact with Excel files. Created by Jonas Neubert, this implementation offers tools for retrieving cell values, searching within ranges, examining cell details including formatting and formulas, and listing worksheet information. It''s particularly useful for data analysis workflows where AI assistants need to extract, search, or analyze information from Excel workbooks without requiring users to manually copy spreadsheet content.', '@jonemo', 'ai-ml', 'Unknown', 18, 'https://github.com/jonemo/openpyxl-mcp-server', NULL, 0, 'https://github.com/jonemo.png?size=128', '2026-03-09T05:21:02.006323+00:00'),
  ('net', '.NET', 'Provides natural language access to .NET SDK capabilities including project creation from templates, NuGet package management, build and test automation, Entity Framework Core database operations, and security features like certificate management and user secrets. Translates conversational requests into structured .NET operations with comprehensive error handling and automatic secret redaction.', '@jongalloway', 'databases', 'Unknown', 6, 'https://github.com/jongalloway/dotnet-mcp', NULL, 0, 'https://github.com/jongalloway.png?size=128', '2026-03-09T05:21:02.006347+00:00'),
  ('coderag', 'CodeRAG', 'This MCP server provides comprehensive code analysis and graph-based exploration of software projects by parsing TypeScript, JavaScript, Java, and Python codebases into a Neo4J graph database. Built by Jonathan Crabtree using TypeScript with the MCP SDK and Neo4J driver, it extracts code entities (classes, methods, functions, interfaces) and their relationships (inheritance, method calls, dependencies) while capturing rich metadata including annotations, decorators, and framework usage patterns. The implementation offers both STDIO and HTTP/SSE transport modes, includes 18 analysis tools for calculating software quality metrics (CK metrics suite, package coupling, architectural issues), and provides guided prompts for dependency analysis and inheritance exploration, making it valuable for understanding large codebases, identifying architectural problems, refactoring legacy systems, and performing code quality assessments through AI-powered graph traversal and relationship analysis.', '@jonnoc', 'databases', 'Unknown', 15, 'https://github.com/jonnoc/coderag', NULL, 0, 'https://github.com/jonnoc.png?size=128', '2026-03-09T05:21:02.006359+00:00'),
  ('databeak', 'DataBeak', 'Provides comprehensive CSV file operations including loading, transforming, analyzing, and exporting tabular data. Built with FastMCP and pandas, it offers statistical analysis capabilities including correlation matrices, outlier detection, and value frequency analysis. Features secure expression evaluation to prevent code injection attacks, unified header configuration across all CSV loading functions, and session-based data management with automatic cleanup. Supports loading from files, URLs, or direct content with configurable delimiters and encoding detection.', '@jonpspri', 'development', 'Unknown', 2, 'https://github.com/jonpspri/databeak', NULL, 0, 'https://github.com/jonpspri.png?size=128', '2026-03-09T05:21:02.006464+00:00'),
  ('tmux', 'Tmux', 'This MCP server implementation provides programmatic control over tmux sessions, allowing AI assistants to interact with and manipulate tmux environments. Developed by jonrad, it leverages the libtmux library to execute tmux commands through a simple interface. The server exposes a single tool that can run arbitrary tmux commands, effectively wrapping the tmux CLI. While currently a proof of concept, it demonstrates the potential for AI-driven terminal session management. This implementation is particularly useful for scenarios requiring automated tmux session control, such as remote system administration, development environment setup, or complex terminal-based workflows.', '@jonrad', 'development', 'Unknown', 7, 'https://github.com/jonrad/tmux-mcp', NULL, 0, 'https://github.com/jonrad.png?size=128', '2026-03-09T05:21:02.006493+00:00'),
  ('superdesign', 'Superdesign', 'This MCP server brings Superdesign''s AI design agent capabilities to Claude Code as native tools, operating as a design orchestrator that provides structured specifications for the IDE''s LLM to execute rather than generating designs directly. Built with TypeScript and the MCP SDK, it eliminates the need for separate API keys by leveraging Claude Code''s existing LLM connection, offering tools for UI design generation, wireframes, components (HTML/React/Vue), logos, SVG icons, design iteration, and design system extraction from screenshots. The implementation includes an interactive HTML gallery with auto-refresh capabilities for viewing all created designs, automatic file organization in a visible superdesign/ directory, and maintains all of Superdesign''s design methodology while providing seamless integration without manual prompt copying, making it valuable for developers who want sophisticated design capabilities directly within their Claude Code workflow.', '@jonthebeef', 'development', 'Unknown', 68, 'https://github.com/jonthebeef/superdesign-mcp-claude-code', NULL, 0, 'https://github.com/jonthebeef.png?size=128', '2026-03-09T05:21:02.006526+00:00'),
  ('canvas-student', 'Canvas Student', 'Canvas Student MCP provides a bridge to Canvas LMS, enabling students to interact with their course data through Claude. Built as a lightweight Python tool using the FastMCP framework, it exposes tools for retrieving courses, assignments, files, quizzes, and to-do items with rich, Claude-optimized formatting. Particularly valuable for students who want to quickly access and manage their academic information without navigating multiple interfaces.', '@jon-vii', 'ai-ml', 'Unknown', 2, 'https://github.com/jon-vii/canvas-student-mcp/tree/HEAD/src/canvas-student', NULL, 0, 'https://github.com/jon-vii.png?size=128', '2026-03-09T05:21:02.006566+00:00'),
  ('slopwatch', 'SlopWatch', 'This MCP server provides AI accountability tracking by monitoring what AI assistants claim to implement versus what they actually deliver, built by JoodasCode using Node.js with the Model Context Protocol SDK. The implementation offers tools for registering implementation claims with file content snapshots, verifying actual changes through content analysis and keyword matching, and generating .cursorrules files to enforce accountability workflows in development environments. Built with crypto-based file hashing, confidence scoring algorithms, and minimal response formatting, it serves developers wanting to track AI coding accuracy, teams requiring verification of AI-generated implementations, and organizations needing automated accountability measures for AI-assisted development workflows.', '@joodascode', 'development', 'Unknown', 6, 'https://github.com/joodascode/slopwatch', 'slopwatch-mcp-server', 1553, 'https://github.com/joodascode.png?size=128', '2026-03-09T05:21:02.006597+00:00'),
  ('backlog', 'Backlog', 'Backlog MCP Server provides a bridge to the Backlog project management API, enabling AI assistants to interact with project tracking, issue management, and collaboration features. Built with TypeScript and the MCP SDK, it allows querying and manipulating project data through a standardized interface, making it useful for developers and project managers who want to streamline workflow interactions through conversational AI.', '@jootsuki', 'development', 'Unknown', 6, 'https://github.com/jootsuki/backlog-mcp-server', NULL, 0, 'https://github.com/jootsuki.png?size=128', '2026-03-09T05:21:02.006622+00:00'),
  ('unified-tools', 'Unified Tools', 'A unified MCP server with a pluggable tool architecture that provides a framework for dynamically loading and executing multiple tools through a single server instance. Built with TypeScript and Express, it includes core tools for mathematical expression evaluation, testing and debugging operations, and timezone conversion and formatting. The server features automatic tool discovery, comprehensive input validation with Zod schemas, health checking capabilities, and optional Bearer token authentication.', '@jorben', 'development', 'Unknown', 1, 'https://github.com/jorben/mcp-server', NULL, 0, 'https://github.com/jorben.png?size=128', '2026-03-09T05:21:02.006647+00:00'),
  ('skinny-jeans', 'Skinny Jeans', 'Skinny Jeans provides tools for optimizing token consumption when reading files. It uses TOON (Token-Oriented Object Notation) encoding to compress JSON files, strips comments from code, and minifies markdown by removing frontmatter and badges. Offers specialized tools for reading files with automatic optimization, JSON-to-TOON conversion, token count estimation, compact directory listings, and project-wide savings analysis. Achieves approximately 40-60% savings for JSON, 15-30% for markdown, and 10-20% for code files.', '@jordan112', 'development', 'Unknown', 1, 'https://github.com/jordan112/skinny-jeans', NULL, 0, 'https://github.com/jordan112.png?size=128', '2026-03-09T05:21:02.006670+00:00'),
  ('kuzudb', 'KuzuDB', 'MCP server implementation by jordanburke that provides AI assistants with direct access to Kuzu graph databases through Cypher query execution, schema introspection, and database management operations. Built with TypeScript and featuring comprehensive error handling, the implementation includes multi-agent coordination through file-based write locking to handle Kuzu''s single-writer limitation, automatic connection recovery with exponential backoff, and workarounds for specific Kuzu DDL bugs including timeout handling for hanging getAll() operations. The server supports multiple deployment modes including HTTP transport for web integration, Docker containerization, and Smithery platform deployment, with built-in database templates for movies, social networks, and financial data, making it valuable for developers building graph-based AI applications, teams requiring shared persistent memory across multiple AI agents, and organizations needing robust graph database integration with automatic failure recovery and concurrent access management.', '@jordanburke', 'databases', 'Unknown', 8, 'https://github.com/jordanburke/kuzudb-mcp-server', 'kuzudb-mcp-server', 2135, 'https://github.com/jordanburke.png?size=128', '2026-03-09T05:21:02.006711+00:00'),
  ('doordash-drive-api', 'DoorDash Drive API', 'DoorDash MCP Server provides a bridge to the DoorDash Drive API, enabling AI assistants to manage delivery services through a standardized interface. Developed by Jordan Dalton, this TypeScript implementation offers tools for creating delivery quotes, managing deliveries, handling business operations, and store management. The server requires a DoorDash API key for authentication and handles all API requests with proper error management. It''s particularly useful for applications that need to integrate with DoorDash''s delivery infrastructure for last-mile logistics without writing complex API interaction code.', '@jordandalton', 'development', 'Unknown', 21, 'https://github.com/jordandalton/doordash-mcp-server', NULL, 0, 'https://github.com/jordandalton.png?size=128', '2026-03-09T05:21:02.006769+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('laravel-forge', 'Laravel Forge', 'A minimal Laravel Forge MCP server built by Jordan Dalton that provides a single focused tool for deploying sites through the Forge API. The implementation takes a deliberately simple approach to solve one specific problem - triggering deployments - rather than attempting to cover the full Forge API surface area. Configured through environment variables for API key, server ID, and site ID, it''s designed for developers who need quick deployment capabilities integrated into their AI assistant workflows without the complexity of a full-featured Forge integration.', '@jordandalton', 'ai-ml', 'Unknown', 1, 'https://github.com/jordandalton/laravel-forge-mcp-server', NULL, 0, 'https://github.com/jordandalton.png?size=128', '2026-03-09T05:21:02.006810+00:00'),
  ('world-cup-2026', 'World Cup 2026', 'FIFA World Cup 2026 data: matches, teams, venues, city guides, fan zones, and more.', '@jordanlyall', 'development', 'Unknown', 3, 'https://github.com/jordanlyall/wc26-mcp', NULL, 0, 'https://github.com/jordanlyall.png?size=128', '2026-03-09T05:21:02.006846+00:00'),
  ('iot-home-automation', 'IoT Home Automation', 'The IoT MCP Server provides a standardized interface for controlling smart devices through MQTT protocol, with a companion Memory MCP Server that enables long-term memory storage and semantic search capabilities. The implementation features a light bulb simulator for testing, supports real-time device state monitoring, and includes tools for sending commands (turn on/off, toggle), querying device states, and subscribing to updates. The memory component, built with Mem0, allows saving information to persistent storage and retrieving it through semantic search, making this implementation particularly valuable for home automation systems that need to maintain context across interactions.', '@jordy33', 'development', 'Unknown', 2, 'https://github.com/jordy33/iot_mcp_server', NULL, 0, 'https://github.com/jordy33.png?size=128', '2026-03-09T05:21:02.006898+00:00'),
  ('codeql', 'CodeQL', 'CodeQL MCP Server provides a bridge to the CodeQL static analysis engine, enabling AI assistants to analyze codebases for security vulnerabilities and quality issues. The implementation offers tools for registering CodeQL databases, evaluating queries against codebases, decoding query results, and performing quick evaluations of specific classes or predicates. Built with Python using the FastMCP framework, it exposes a simple API that handles the complexities of CodeQL operations while providing structured results that can be easily interpreted by language models. This server is particularly valuable for security researchers and developers who want to leverage AI assistants for code analysis without directly interacting with the CodeQL CLI.', '@jordyzomer', 'databases', 'Unknown', 139, 'https://github.com/jordyzomer/codeql-mcp', NULL, 0, 'https://github.com/jordyzomer.png?size=128', '2026-03-09T05:21:02.006909+00:00'),
  ('deutsche-bahn-timetable', 'Deutsche Bahn Timetable', 'DB-Timetable-MCP is a server that connects AI assistants to the Deutsche Bahn timetable API, enabling real-time access to German railway information. Developed by Nils Jorek, this TypeScript implementation provides tools for retrieving current timetables, planned schedules, recent changes, and finding stations through a standardized interface. The server authenticates with the DB API Marketplace using client credentials, transforms natural language requests into appropriate API calls, and returns formatted XML responses. It''s particularly valuable for travel planning, commute monitoring, or transportation analysis without leaving the AI assistant conversation.', '@jorekai', 'development', 'Unknown', 13, 'https://github.com/jorekai/db-timetable-mcp', NULL, 0, 'https://github.com/jorekai.png?size=128', '2026-03-09T05:21:02.006939+00:00'),
  ('uniprot', 'UniProt', 'A UniProt MCP server built by Jose Duarte that provides read-only access to the UniProtKB protein database through five core tools: fetch_entry for complete protein entries, get_sequence for protein sequences, search_uniprot for filtered searches, map_ids for converting between 200+ database identifier types, and fetch_entry_flatfile for historical entry versions. The implementation features retry logic with exponential backoff, progress reporting for long-running ID mapping jobs, both stdio and HTTP transports with CORS support, and structured Pydantic models for type-safe responses. Useful for bioinformatics workflows, protein research, database integration projects, and AI agents that need reliable access to curated protein data from one of the world''s primary protein sequence databases.', '@josefdc', 'databases', 'Unknown', 2, 'https://github.com/josefdc/uniprot-mcp', 'uniprot-mcp', 826, 'https://github.com/josefdc.png?size=128', '2026-03-09T05:21:02.006949+00:00'),
  ('datto-rmm', 'Datto RMM', 'Provides direct access to Datto RMM through a comprehensive implementation that enables device management, alert monitoring, job scheduling, and audit operations. Part of a complete toolkit that includes auto-generated TypeScript and Rust API clients, the server handles OAuth authentication automatically and supports all six Datto RMM regional platforms (Pinotage, Merlot, Concord, Vidal, Zinfandel, Syrah). Useful for MSPs and IT administrators who want to query device status, resolve alerts, manage sites, and execute quick jobs without switching between interfaces.', '@josh-fisher', 'development', 'Unknown', 3, 'https://github.com/josh-fisher/datto-rmm/tree/HEAD/apps/mcp-server', NULL, 0, 'https://github.com/josh-fisher.png?size=128', '2026-03-09T05:21:02.006977+00:00'),
  ('crucible', 'Crucible', 'Crucible is an MCP server for browser automation using Ferrum and headless Chrome. It provides comprehensive web interaction capabilities including navigation, element interaction, content extraction, cookie management, and file downloads. The server supports multiple named browser sessions for parallel automation workflows and features stealth mode with three profiles (minimal, moderate, maximum) that apply evasion techniques to bypass bot detection systems. Designed for AI agent control, web scraping, and testing workflows.', '@joshfng', 'development', 'Unknown', 4, 'https://github.com/joshfng/crucible', NULL, 0, 'https://github.com/joshfng.png?size=128', '2026-03-09T05:21:02.007003+00:00'),
  ('formula-1-fastf1', 'Formula 1 (FastF1)', 'MCP server implementation that provides Formula 1 data access through the FastF1 Python package, offering tools to retrieve race schedules, session results, driver and constructor standings, and detailed lap timing data with telemetry information. The implementation features dual-mode operation supporting both standard MCP protocol and HTTP streaming with OAuth 2.0 authentication, includes comprehensive caching for F1 data, and provides detailed JSON responses for all major F1 data types from practice sessions through race results. Designed for F1 enthusiasts, data analysts, and developers building racing applications who need programmatic access to official F1 timing data, historical race information, and real-time telemetry for analysis, visualization, or integration into broader motorsport workflows.', '@josh-mantel', 'development', 'Unknown', 0, 'https://github.com/josh-mantel/mcp-f1', NULL, 0, 'https://github.com/josh-mantel.png?size=128', '2026-03-09T05:21:02.007041+00:00'),
  ('exiftool', 'ExifTool', 'Wraps ExifTool functionality to enable reading, writing, and removing metadata from images, videos, audio files, documents, and archives. Supports formats including RAW, JPEG, PNG, MP4, MOV, MP3, FLAC, PDF, and Office files. Provides tools for extracting metadata tags, updating metadata with automatic backups, removing specific or all metadata, and listing supported file types.', '@joshmsimpson', 'file-systems', 'Unknown', 0, 'https://github.com/joshmsimpson/exiftool_mcp', NULL, 0, 'https://github.com/joshmsimpson.png?size=128', '2026-03-09T05:21:02.007123+00:00'),
  ('applescript', 'AppleScript', 'This AppleScript MCP framework, developed by Josh Rutkowski, enables seamless integration of AppleScript capabilities with the Model Context Protocol. It leverages TypeScript and the MCP SDK to provide a robust interface for interacting with macOS applications and system functions through natural language. The implementation is designed for developers looking to incorporate AI-driven automation and control of macOS environments, making it particularly useful for creating intelligent assistants, workflow automation tools, or AI-enhanced macOS applications. Its focus on AppleScript integration sets it apart by offering unique access to macOS-specific functionality within the MCP ecosystem.', '@joshrutkowski', 'development', 'Unknown', 365, 'https://github.com/joshrutkowski/applescript-mcp', NULL, 0, 'https://github.com/joshrutkowski.png?size=128', '2026-03-09T05:21:02.007151+00:00'),
  ('datetime', 'DateTime', 'Provides date and time utilities with timezone support, date parsing, and monotonic time tracking for reliable timestamp generation across different timezones.', '@joshuaboys', 'development', 'Unknown', 6, 'https://github.com/joshuaboys/datetime-mcp', NULL, 0, 'https://github.com/joshuaboys.png?size=128', '2026-03-09T05:21:02.007205+00:00'),
  ('django-shell', 'Django Shell', 'This Django MCP server provides a stateful Python shell environment specifically configured for Django development, enabling AI assistants to execute Django ORM operations, explore models, and interact with Django applications through persistent sessions. Built by Josh Thomas using FastMCP, it offers two core tools: django_shell for executing Python code with full Django context and django_reset for clearing session state, with intelligent formatting for querysets and comprehensive error handling. The implementation maintains execution history, supports both synchronous and asynchronous operations, and includes robust testing with multiple Django/Python version compatibility, making it valuable for AI-assisted Django development, database exploration, and automated Django application management workflows.', '@joshuadavidthomas', 'databases', 'Unknown', 40, 'https://github.com/joshuadavidthomas/mcp-django', 'mcp-django-shell', 6675, 'https://github.com/joshuadavidthomas.png?size=128', '2026-03-09T05:21:02.007223+00:00'),
  ('mac-apps-launcher', 'Mac Apps Launcher', 'This MCP server, developed by JoshuaRileyDev, enables AI assistants like Claude to launch and manage macOS applications. Built in JavaScript, it provides capabilities for listing installed applications, launching apps by name, and opening files with specific applications. The implementation stands out by offering a simple interface to interact with the macOS application ecosystem. By connecting AI capabilities with native desktop functionality, this server enables AI systems to control and utilize macOS software. It is particularly useful for automating workflows, integrating AI assistants with desktop applications, and building voice-controlled or AI-driven interfaces for macOS.', '@joshuarileydev', 'development', 'Unknown', 18, 'https://github.com/joshuarileydev/mac-apps-launcher', '@joshuarileydev/mac-apps-launcher-mcp-server', 446, 'https://github.com/joshuarileydev.png?size=128', '2026-03-09T05:21:02.007349+00:00'),
  ('supabase-management', 'Supabase Management', 'This MCP server, developed by JoshuaRileyDev, provides AI assistants like Claude with programmatic access to the Supabase Management API. It offers tools for managing Supabase projects and organizations, including listing, creating, and deleting projects, retrieving API keys, and handling organization details. The server is designed for easy integration with AI models through a standardized interface. By bridging AI capabilities with Supabase''s backend-as-a-service platform, this implementation enables AI-assisted database and project management. It is particularly useful for scenarios requiring automated project setup, API key management, or AI-guided database administration in applications leveraging Supabase''s infrastructure.', '@joshuarileydev', 'databases', 'Unknown', 50, 'https://github.com/joshuarileydev/supabase-mcp-server', '@joshuarileydev/supabase-mcp-server', 7349, 'https://github.com/joshuarileydev.png?size=128', '2026-03-09T05:21:02.007362+00:00'),
  ('cia-world-factbook', 'CIA World Factbook', 'This minimal MCP implementation, developed by an unknown author, provides a basic structure for a project using the MIT license. It includes a .gitignore file to exclude node_modules and build directories from version control, indicating a Node.js-based project with a build process. The implementation''s simplicity makes it a good starting point for developers looking to create custom MCP servers or clients with full control over the implementation details. It''s particularly suitable for projects that require a clean slate to build upon, allowing for easy integration of specific APIs or services as needed.', '@joshuatanderson', 'development', 'Unknown', 0, 'https://github.com/joshuatanderson/factbook-mcp', NULL, 0, 'https://github.com/joshuatanderson.png?size=128', '2026-03-09T05:21:02.007386+00:00'),
  ('browserplex', 'Browserplex', 'Browserplex is an MCP server for managing multiple concurrent named browser sessions built on Playwright. It supports Chromium, Firefox, WebKit, and Camoufox (stealth Firefox) browsers. Key features include isolated session management, screenshot capture with automatic LLM-optimized resizing, structured content extraction preserving semantic markup, comprehensive browser interactions (clicking, typing, JavaScript evaluation), tab management, and console/network debugging capabilities. Solves the limitation of standard Playwright MCP servers which don''t support concurrent multi-user sessions.', '@joshuavial', 'development', 'Unknown', 2, 'https://github.com/joshuavial/browserplex', NULL, 0, 'https://github.com/joshuavial.png?size=128', '2026-03-09T05:21:02.007418+00:00'),
  ('juce-docs', 'JUCE Docs', 'Provides direct access to JUCE Framework C++ class documentation through an MCP server, enabling developers to retrieve, search, and explore JUCE class details programmatically. Built by Julius Smith, the server parses HTML documentation from Stanford CCRMA''s website, converting class information into markdown-formatted resources that can be easily queried by AI development tools. Useful for developers seeking quick, structured access to JUCE framework documentation during coding and learning.', '@josmithiii', 'development', 'Unknown', 14, 'https://github.com/josmithiii/mcp-servers-jos/tree/HEAD/juce-docs-mcp-server', NULL, 0, 'https://github.com/josmithiii.png?size=128', '2026-03-09T05:21:02.007470+00:00'),
  ('bonsai-bim-blender-ifc', 'Bonsai BIM (Blender IFC)', 'Bonsai_mcp is a specialized MCP server that connects Claude to Blender, enabling direct interaction with IFC (Industry Foundation Classes) models through the Bonsai BIM addon. It provides five dedicated IFC tools for querying project information, listing entities, examining properties, exploring spatial structures, and analyzing relationships between building elements. The implementation includes both a Blender addon that creates a socket server within Blender and a Python MCP server that implements the protocol, making it particularly valuable for architects, engineers, and construction professionals who need to analyze and interact with building information models through natural language.', '@jotaderodriguez', 'development', 'Unknown', 44, 'https://github.com/jotaderodriguez/bonsai_mcp', NULL, 0, 'https://github.com/jotaderodriguez.png?size=128', '2026-03-09T05:21:02.007502+00:00'),
  ('jotai-documentation', 'Jotai Documentation', 'Jotai MCP Server provides AI assistants with access to Jotai documentation resources. Developed by Daishi Kato, this Node.js implementation fetches and serves the main Jotai README and a curated tips document through a simple interface. The server exposes two resources: ''readme'' and ''tips'', which retrieve content directly from GitHub repositories and make it available in a structured format. It''s particularly useful for developers working with the Jotai state management library who need quick access to documentation and best practices without leaving their development environment.', '@jotaijs', 'development', 'Unknown', 29, 'https://github.com/jotaijs/jotai-mcp-server', 'jotai-mcp-server', 794, 'https://github.com/jotaijs.png?size=128', '2026-03-09T05:21:02.007528+00:00'),
  ('jotform', 'JotForm', 'Provides AI assistants with direct access to Kubernetes clusters through kubectl commands, enabling comprehensive cluster management and monitoring capabilities. Built to bridge the gap between AI-powered automation and Kubernetes operations, it exposes kubectl functionality through a secure MCP interface, allowing assistants to query cluster state, manage resources, troubleshoot issues, and perform administrative tasks. The implementation supports all standard kubectl operations including resource creation, deletion, scaling, and inspection, making it valuable for DevOps workflows, automated cluster monitoring, troubleshooting assistance, and enabling AI assistants to help with Kubernetes administration tasks without requiring users to manually run kubectl commands.', '@unknown', 'cloud', 'Unknown', 0, 'https://www.jotform.com/developers/mcp/', NULL, 0, NULL, '2026-03-09T05:21:02.007550+00:00'),
  ('jekyll-blog', 'Jekyll Blog', 'Indexes and searches Jekyll blog content by parsing YAML front matter from Markdown and AsciiDoc files. Provides tools for keyword-based search across posts, retrieving full content by slug, listing categories and tags with counts, and comparing draft content against published posts to detect potential duplicates. Enables content analysis, blog organization, and AI-assisted writing workflows for Jekyll-based blogs.', '@jottinger', 'ai-ml', 'Unknown', 1, 'https://github.com/jottinger/jekyll-mcp-server', NULL, 0, 'https://github.com/jottinger.png?size=128', '2026-03-09T05:21:02.007586+00:00'),
  ('neo4j-knowledge-graph', 'Neo4j Knowledge Graph', 'MCP Neo4j Memory Server provides a knowledge graph storage solution for AI assistants using Neo4j as the backend database. Built by JovanHsu, this implementation enables storing and retrieving contextual information in a graph structure, making it particularly effective for maintaining complex relationships between data points. The server integrates with the Model Context Protocol SDK and uses Fuse.js for fuzzy searching capabilities, allowing AI models to efficiently query and update their memory. Ideal for applications requiring persistent memory across conversations and sophisticated knowledge representation.', '@jovanhsu', 'databases', 'Unknown', 22, 'https://github.com/jovanhsu/mcp-neo4j-memory-server', NULL, 0, 'https://github.com/jovanhsu.png?size=128', '2026-03-09T05:21:02.007598+00:00'),
  ('timeplus', 'Timeplus', 'This MCP server implementation provides a bridge to Timeplus, enabling AI assistants to execute SQL queries and retrieve database information. Developed by Jove Zhong, it offers tools for running select queries, listing databases, and listing tables within a specified database. The server is designed to work with Python 3.13 and utilizes the timeplus-connect library for API interactions. It focuses on read-only operations to ensure data safety and includes configuration options for easy integration with Claude Desktop. The implementation is particularly useful for AI applications requiring real-time analytics or data exploration capabilities within Timeplus environments.', '@timeplus-io', 'databases', 'Unknown', 12, 'https://github.com/timeplus-io/mcp-timeplus', 'mcp-timeplus', 5654, 'https://github.com/timeplus-io.png?size=128', '2026-03-09T05:21:02.007656+00:00'),
  ('chinese-legal-database', 'Chinese Legal Database', 'Provides access to Chinese legal regulations and laws through a structured database interface, enabling legal research and compliance queries within the Chinese legal system. Integrates with a local regulations database and uses FastMCP for efficient data retrieval operations. Designed for legal professionals, compliance teams, and applications requiring access to current Chinese legal documentation and regulatory frameworks.', '@joy7758', 'databases', 'Unknown', 5, 'https://github.com/joy7758/mcp-legal-china', NULL, 0, 'https://github.com/joy7758.png?size=128', '2026-03-09T05:21:02.007667+00:00'),
  ('pokemon-vgc-damage-calculator', 'Pokemon VGC Damage Calculator', 'This MCP server provides Pokemon VGC damage calculation capabilities through integration with the @smogon/calc library, enabling AI assistants to compute battle damage, KO chances, and detailed combat scenarios for competitive Pokemon play. Built using TypeScript with the MCP SDK and deployed on Vercel, it accepts comprehensive Pokemon data including stats, abilities, items, natures, EVs/IVs, status conditions, and battlefield modifiers like weather, terrain, and entry hazards, then returns precise damage ranges with descriptive battle text and knockout probabilities. The implementation supports both Singles and Doubles formats with full VGC ruleset compatibility, making it valuable for competitive Pokemon players analyzing team matchups, content creators explaining battle mechanics, and strategists optimizing Pokemon builds and movesets for tournament play.', '@jpbullalayao', 'cloud', 'Unknown', 1, 'https://github.com/jpbullalayao/pokemon-vgc-calc-mcp', 'pokemon-vgc-calc-mcp', 3670, 'https://github.com/jpbullalayao.png?size=128', '2026-03-09T05:21:02.007691+00:00'),
  ('pokepaste', 'Pokepaste', 'This MCP server enables AI assistants to create and share Pokemon team compositions by converting structured Pokemon set data into Pokepaste URLs. Built using TypeScript with the @pkmn/sets library for Pokemon showdown format conversion, it accepts detailed Pokemon configurations including stats, moves, abilities, items, and competitive metadata like EVs/IVs, then automatically uploads the formatted team data to pokepast.es and returns a shareable link. The implementation includes comprehensive input validation with Zod schemas, handles optional fields like shiny status and Tera types, and supports team metadata like titles and author information, making it valuable for competitive Pokemon players, team builders, and content creators who need to quickly share and collaborate on Pokemon team strategies.', '@jpbullalayao', 'development', 'Unknown', 1, 'https://github.com/jpbullalayao/pokemon-paste-mcp', 'pokemon-paste-mcp', 3566, 'https://github.com/jpbullalayao.png?size=128', '2026-03-09T05:21:02.007723+00:00'),
  ('file-modifier', 'File Modifier', 'This MCP server for file modifications, developed by jpinillagoshawk, enables AI assistants to perform targeted edits on text files. It integrates with the Model Context Protocol to provide operations for adding, replacing, and deleting content at specific locations within files. The server handles UTF-8 encoding and exposes a simple API for common file modification tasks. By abstracting file I/O operations, this implementation allows AI systems to make precise changes to documents without direct file system access. It is particularly useful for scenarios requiring automated document updates, code refactoring, or any application where an AI assistant needs to modify text files programmatically.', '@jpinillagoshawk', 'development', 'Unknown', 2, 'https://github.com/jpinillagoshawk/mcp-server-file-modifier', NULL, 0, 'https://github.com/jpinillagoshawk.png?size=128', '2026-03-09T05:21:02.007750+00:00'),
  ('cypress-test-generator', 'Cypress Test Generator', 'MCP server implementation by Juan P. Realini that generates Cypress page objects and test scripts by analyzing web pages through automated browser interaction. The implementation uses Puppeteer to navigate to specified URLs, extract DOM elements and their properties, and leverages Cheerio for HTML parsing to identify testable components like forms, buttons, and interactive elements. Built with the Model Context Protocol SDK and designed for QA engineers and developers who need to quickly scaffold Cypress test automation code, the server provides a ''generateLocator'' tool that takes a URL parameter and returns structured page object models with appropriate selectors and test patterns, streamlining the process of creating maintainable end-to-end test suites for web applications.', '@jprealini', 'development', 'Unknown', 17, 'https://github.com/jprealini/cypress-mcp', '@jprealini/cypress-mcp', 3134, 'https://github.com/jprealini.png?size=128', '2026-03-09T05:21:02.007808+00:00'),
  ('omnifocus-enhanced', 'OmniFocus Enhanced', 'This MCP server provides AI assistants with complete OmniFocus task management capabilities on macOS, featuring comprehensive CRUD operations for tasks and projects, advanced perspective views (Inbox, Flagged, Forecast, Tags), batch operations, and custom perspective querying. Built using TypeScript with AppleScript integration for native OmniFocus automation, it supports subtask hierarchies, tag management, date handling, project organization with folders, and sophisticated filtering with status, date range, and search criteria. The implementation includes specialized tools for productivity workflows like viewing today''s completed tasks, managing recurring items, and accessing user-defined perspectives, making it valuable for AI-powered task management, productivity automation, and building assistants that need programmatic access to OmniFocus data without manual app interaction.', '@jqlts1', 'development', 'Unknown', 34, 'https://github.com/jqlts1/omnifocus-mcp-enhanced', 'omnifocus-mcp-enhanced', 1914, 'https://github.com/jqlts1.png?size=128', '2026-03-09T05:21:02.007843+00:00'),
  ('diy-helper-building-codes', 'DIY Helper Building Codes', 'Provides building code lookup and compliance checking for residential construction projects, integrating with the National Electrical Code (NEC), International Residential Code (IRC), and International Plumbing Code (IPC). Features natural language code search, specific section retrieval, compliance verification for described scenarios, and category browsing through a JSON-based database with plans to migrate to vector search. Useful for DIY enthusiasts, contractors, and construction guidance while emphasizing the need for professional verification and local jurisdiction compliance.', '@jrszilard', 'databases', 'Unknown', 1, 'https://github.com/jrszilard/diy-helper-mcp-servers', NULL, 0, 'https://github.com/jrszilard.png?size=128', '2026-03-09T05:21:02.007866+00:00'),
  ('globalping', 'Globalping', 'Globalping MCP Server provides AI assistants with direct access to Globalping''s globally distributed network monitoring capabilities through Cloudflare Workers. It enables running network diagnostics like ping, traceroute, DNS lookups, MTR tests, and HTTP requests from probes located worldwide, with results formatted for easy analysis. The implementation includes OAuth authentication with Globalping, caching of measurement results, and tools for comparing network performance across different locations. Built on the Hono framework with TypeScript, it''s particularly valuable for network engineers, system administrators, and developers who need to diagnose connectivity issues, benchmark CDN performance, or analyze global network routing without switching context.', '@jsdelivr', 'cloud', 'Unknown', 48, 'https://github.com/jsdelivr/globalping-mcp-server', NULL, 0, 'https://github.com/jsdelivr.png?size=128', '2026-03-09T05:21:02.007892+00:00'),
  ('cluster-api', 'Cluster API', 'This MCP server provides a secure bridge between AI agents and Kubernetes Cluster API (CAPI) management clusters, enabling programmatic creation, scaling, and management of Kubernetes clusters across cloud providers through seven specialized tools including cluster lifecycle operations, node management, and kubeconfig retrieval. Built by jsell-rh using Go with comprehensive security controls, provider abstraction, and asynchronous operation handling, it translates high-level MCP tool calls into declarative Kubernetes API operations while monitoring cluster status until completion. The implementation features AWS provider support with extensible provider interface, robust authentication and input validation, structured error handling with sanitized client responses, and comprehensive observability through Prometheus metrics and structured logging, making it valuable for AI-assisted infrastructure automation, multi-cloud cluster management workflows, and building AI tools that need programmatic access to enterprise Kubernetes infrastructure without manual cluster management interfaces.', '@jsell-rh', 'cloud', 'Unknown', 1, 'https://github.com/jsell-rh/capi-mcp', NULL, 0, 'https://github.com/jsell-rh.png?size=128', '2026-03-09T05:21:02.007915+00:00'),
  ('jser-info', 'JSer.info', 'The JSer.info MCP server provides AI assistants with access to JavaScript ecosystem data through a specialized API. Developed by azu, this implementation leverages the @jser/data-fetcher and @jser/stat libraries to expose JSer.info''s curated JavaScript news and statistics. The server is designed to run both as a Node.js application and as a Cloudflare Worker, with endpoints for Server-Sent Events (/sse) and MCP interactions (/mcp). It''s particularly valuable for developers and teams who need to stay updated on JavaScript trends, research library popularity, or track ecosystem changes without manually searching through multiple sources.', '@jser', 'cloud', 'Unknown', 22, 'https://github.com/jser/mcp', '@jser/mcp', 379, 'https://github.com/jser.png?size=128', '2026-03-09T05:21:02.007936+00:00'),
  ('sketch-context', 'Sketch Context', 'Sketch Context MCP server by Joshua Miller that bridges Sketch design files with AI-powered development workflows through a dual-component architecture consisting of a Node.js server implementing MCP protocol and a native Sketch plugin with WebSocket communication. The implementation supports both local .sketch files and Sketch Cloud documents via API authentication, providing tools for file parsing, component extraction, layer selection management, and real-time design element creation (rectangles, text) directly from AI assistants. Built with Express, WebSocket support, and comprehensive error handling, it enables designers and developers to seamlessly integrate Sketch designs into code generation workflows, allowing AI assistants to reference specific design elements by ID, extract component information, and even create new design elements through natural language commands in IDEs like Cursor.', '@jshmllr', 'development', 'Unknown', 66, 'https://github.com/jshmllr/sketch-context-mcp', 'sketch-context-mcp', 417, 'https://github.com/jshmllr.png?size=128', '2026-03-09T05:21:02.007968+00:00'),
  ('json-skeleton', 'JSON Skeleton', 'The JSON Skeleton MCP Server creates lightweight "skeleton" representations of large JSON files by truncating string values, deduplicating array items based on their structure, and optionally showing only data types instead of values. It intelligently preserves the complete JSON structure while dramatically reducing file size, making it particularly useful for understanding API responses or data schemas that exceed AI model context limits. The server offers configurable string truncation lengths and a ultra-compact type-only mode that replaces all values with their type names (str, int, bool, etc.), enabling developers to quickly grasp data structure without processing massive payloads.', '@jskorlol', 'ai-ml', 'Unknown', 6, 'https://github.com/jskorlol/json-skeleton-mcp', NULL, 0, 'https://github.com/jskorlol.png?size=128', '2026-03-09T05:21:02.008024+00:00'),
  ('laravel-helper-tools', 'Laravel Helper Tools', 'This MCP server implementation provides tools for Laravel development, including log file analysis, error tracking, and Artisan command execution. It integrates with Laravel projects by utilizing environment variables to locate and interact with the Laravel directory. The server offers functionalities such as tailing log files, searching for errors within specified time windows, and displaying model details with a focus on relationships. It''s designed for developers working on Laravel applications who need quick access to logs and common Laravel operations through an MCP interface.', '@jsonallen', 'development', 'Unknown', 12, 'https://github.com/jsonallen/laravel-mcp', NULL, 0, 'https://github.com/jsonallen.png?size=128', '2026-03-09T05:21:02.008049+00:00'),
  ('json-resume-enhancer', 'JSON Resume Enhancer', 'This MCP server implementation enhances JSON Resumes with GitHub project information. It analyzes the user''s current codebase, fetches existing resumes from GitHub gists, and uses OpenAI''s API to intelligently update the resume with relevant project details. The server offers tools for codebase analysis, resume checking, and resume enhancement, making it useful for developers looking to automatically keep their professional profiles up-to-date with their latest work.', '@jsonresume', 'development', 'Unknown', 60, 'https://github.com/jsonresume/mcp', '@jsonresume/mcp', 5964, 'https://github.com/jsonresume.png?size=128', '2026-03-09T05:21:02.008121+00:00'),
  ('binassist-binary-ninja', 'BinAssist (Binary Ninja)', 'BinAssistMCP provides a complete bridge between Binary Ninja and Large Language Models through dual transport support (SSE and STDIO), enabling AI-assisted reverse engineering workflows. Built by Jason Tang using Python with FastMCP, it exposes over 40 Binary Ninja tools including decompilation, IL analysis, symbol management, type system manipulation, and cross-reference analysis, while supporting multi-binary sessions with automatic context management. The implementation integrates directly as a Binary Ninja plugin with auto-startup capabilities and configurable settings, making it valuable for security researchers, malware analysts, and reverse engineers who want to leverage AI assistance for binary analysis tasks like vulnerability research, code understanding, and automated documentation generation.', '@jtang613', 'development', 'Unknown', 20, 'https://github.com/jtang613/binassistmcp', NULL, 0, 'https://github.com/jtang613.png?size=128', '2026-03-09T05:21:02.008180+00:00'),
  ('gnu-debugger-gdb', 'GNU Debugger (GDB)', 'GDB MCP server by Jason Tang that enables AI assistants to interact with the GNU Debugger through a standardized interface. Built with Python using FastMCP and GDB''s Python API, it provides a single tool for executing arbitrary GDB commands within debugging sessions. The implementation runs as a background SSE server thread within GDB itself, using thread-safe command execution to bridge between the MCP protocol and GDB''s command interface. Designed for developers who want to incorporate debugging workflows into AI-assisted development, enabling use cases like automated debugging sessions, intelligent breakpoint management, and conversational access to program state inspection without manually typing GDB commands.', '@jtang613', 'development', 'Unknown', 12, 'https://github.com/jtang613/gdb-mcp', NULL, 0, 'https://github.com/jtang613.png?size=128', '2026-03-09T05:21:02.008212+00:00'),
  ('ghidrassist-ghidra', 'GhidrAssist (Ghidra)', 'This MCP server provides AI assistants with comprehensive reverse engineering capabilities through direct integration with Ghidra''s analysis framework, featuring 30+ specialized tools for binary analysis including function decompilation, disassembly, cross-reference analysis, symbol management, and program structure exploration. Built using Java with Ghidra''s plugin architecture and the MCP SDK, it runs as an embedded HTTP server within Ghidra sessions and offers real-time access to loaded programs through natural language prompts, supporting operations like function renaming, comment insertion, variable manipulation, string extraction, and memory segment analysis. The implementation bridges the gap between AI-assisted analysis and professional reverse engineering workflows, making it valuable for malware analysis, vulnerability research, legacy code understanding, and building AI assistants that need programmatic access to binary analysis capabilities without manual Ghidra interaction.', '@jtang613', 'development', 'Unknown', 510, 'https://github.com/jtang613/ghidrassistmcp', NULL, 0, 'https://github.com/jtang613.png?size=128', '2026-03-09T05:21:02.008246+00:00'),
  ('google-drive-classifier', 'Google Drive Classifier', 'The Google Drive Classifier Processor MCP server enables AI agents to automatically classify documents stored in Google Drive using LLMs. Developed by jtrogers, it processes documents in batches, extracting content from various file types and applying classification based on customizable rubrics. The server features real-time progress updates, confidence thresholds, and validation capabilities to ensure accuracy. It integrates with both Google Drive and OpenAI APIs to analyze document content, assign categories with confidence scores, and update document properties with classification metadata. Particularly valuable for organizations needing to organize large document repositories, identify sensitive information, or implement automated document management workflows.', '@jtrogers', 'ai-ml', 'Unknown', 0, 'https://github.com/jtrogers/goose-gdrive-classifier-processor', NULL, 0, 'https://github.com/jtrogers.png?size=128', '2026-03-09T05:21:02.008340+00:00'),
  ('nettune', 'NetTune', 'Provides systematic network performance optimization for Linux servers through AI-assisted configuration. Offers 10 tools for baseline testing (RTT, throughput, latency under load), pre-built BBR congestion control profiles, buffer tuning, and safe configuration management with automatic snapshots and rollback. Uses a client-server architecture where the server runs with root privileges to modify kernel parameters via sysctl, while clients connect remotely via HTTP API with Bearer token authentication. Designed for network engineers and system administrators optimizing high-bandwidth or long-distance connections.', '@jtsang4', 'development', 'Unknown', 29, 'https://github.com/jtsang4/nettune', NULL, 0, 'https://github.com/jtsang4.png?size=128', '2026-03-09T05:21:02.008367+00:00'),
  ('oparl', 'OParl', 'This MCP server provides AI models with structured access to parliamentary information systems through the standardized OParl API, enabling queries about government bodies, elected officials, meetings, documents, and legislative processes. Built using FastMCP for automatic OpenAPI-to-MCP translation, it supports multiple OParl implementations including Munich, Cologne, Hamburg, and generic endpoints with flexible authentication and Docker deployment. The implementation maps OParl''s 10 core object types (System, Body, Organization, Person, Meeting, AgendaItem, Paper, Consultation, File, Location) into MCP resources and resource templates, making it valuable for civic engagement applications, government transparency tools, political research, and AI assistants that need to understand parliamentary data and democratic processes.', '@jtwolfe', 'cloud', 'Unknown', 1, 'https://github.com/jtwolfe/oparl-mcp-server', NULL, 0, 'https://github.com/jtwolfe.png?size=128', '2026-03-09T05:21:02.008427+00:00'),
  ('judge0-code-execution', 'Judge0 Code Execution', 'A Judge0 RapidAPI integration server for the Model Context Protocol that enables AI assistants to execute code in various programming languages. Built with Node.js and leveraging the MCP SDK, this implementation provides a simple interface to the Judge0 code execution API, allowing for remote compilation and running of code snippets. It''s particularly useful for scenarios requiring code testing, algorithm validation, or educational demonstrations without needing local development environments.', '@zefanhu', 'development', 'Unknown', 1, 'https://github.com/zefanhu/mcp-rapidapi-judge0-server', NULL, 0, 'https://github.com/zefanhu.png?size=128', '2026-03-09T05:21:02.008519+00:00'),
  ('jnews', 'JNews', 'A lightweight server implementation for the MCP protocol built with Python and FastAPI, designed to provide a streamlined interface for server-side interactions. The project uses modern Python tooling like uv for dependency management and includes GitHub Actions for automated testing and publishing, with a focus on clean, type-checked code and easy deployment.', '@juhemcp', 'development', 'Unknown', 0, 'https://github.com/juhemcp/jnews-mcp-server', 'jnews-mcp-server', 2680, 'https://github.com/juhemcp.png?size=128', '2026-03-09T05:21:02.008579+00:00'),
  ('jexchange', 'JExchange', 'JExchange MCP Server provides a lightweight, asynchronous server implementation for the Model Context Protocol (MCP). Built with Python 3.10, it leverages the MCP library with CLI support to enable AI assistants to interact with external services. The server uses modern Python features including asyncio for handling concurrent requests and includes GitHub workflows for automated testing, formatting, and publishing to PyPI. This implementation is designed for developers who need a simple, reliable foundation for building MCP-compatible services that can be easily deployed and maintained.', '@juhemcp', 'development', 'Unknown', 0, 'https://github.com/juhemcp/jexchange-mcp-server', 'jexchange-mcp-server', 2602, 'https://github.com/juhemcp.png?size=128', '2026-03-09T05:21:02.008602+00:00'),
  ('github-repository-integration', 'GitHub Repository Integration', 'MCP Cursor Project integrates GitHub repositories with Cursor IDE through the Model Context Protocol, allowing AI assistants to access and interact with GitHub content directly within the editor. The implementation uses the @modelcontextprotocol/server-github package to establish a connection between Cursor and GitHub repositories, requiring only a GitHub Personal Access Token for authentication. This server-based approach enables developers to leverage AI capabilities while working with their code, supporting custom MCP commands and tools that enhance the coding workflow in Cursor IDE.', '@juicetea', 'development', 'Unknown', 1, 'https://github.com/juicetea/mcp-cursor-project', NULL, 0, 'https://github.com/juicetea.png?size=128', '2026-03-09T05:21:02.008626+00:00'),
  ('modus-design-system', 'Modus Design System', 'MCP server for Modus Web Components documentation, design rules, and setup guides. Built by Julian Oczkowski, it provides AI assistants with comprehensive access to Trimble''s Modus design system through 10 specialized tools including component search, documentation retrieval, design rule queries, and setup instructions for HTML/React projects. The server automatically downloads and indexes component documentation, design guidelines (colors, typography, spacing, icons), and implementation guides on installation, then exposes them through structured search and retrieval functions that enable AI assistants to help developers properly implement and use Modus Web Components in their applications.', '@julianoczkowski', 'productivity', 'Unknown', 5, 'https://github.com/julianoczkowski/mcp-modus', '@julianoczkowski/mcp-modus', 1319, 'https://github.com/julianoczkowski.png?size=128', '2026-03-09T05:21:02.008677+00:00'),
  ('reflection-skills', 'Reflection Skills', 'Provides curated reflection skills and frameworks specifically designed for software engineers, offering structured cards covering communication patterns, decision-making exercises, and daily pulse tools with developer-native tags for contextual recommendations in post-incident reviews, team retrospectives, and personal development workflows.', '@julienavezou', 'development', 'Unknown', 1, 'https://github.com/julienavezou/reflection-skills-mcp', NULL, 0, 'https://github.com/julienavezou.png?size=128', '2026-03-09T05:21:02.008700+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('ign-api-carto', 'IGN API Carto', 'IGN API Carto provides access to French geographic data services through the Institut national de l''information géographique et forestière (IGN) API Carto platform. Built with TypeScript and the Model Context Protocol SDK, it exposes comprehensive tools for cadastral parcels, postal codes, agricultural land use (RPG), protected natural areas (Natura 2000, ZNIEFF), urban planning documents (GPU), wine appellations (AOC/IGP), and administrative boundaries. The implementation supports both JSON and Markdown output formats with automatic response truncation, includes comprehensive error handling, and offers dual transport modes (STDIO and HTTP) for flexible deployment.', '@julienkalamon', 'development', 'Unknown', 3, 'https://github.com/julienkalamon/ign-apicarto-mcp-server', NULL, 0, 'https://github.com/julienkalamon.png?size=128', '2026-03-09T05:21:02.008732+00:00'),
  ('ragdocs-vector-documentation-search', 'RAGDocs (Vector Documentation Search)', 'MCP-RAGDocs is a server implementation that provides semantic documentation search and retrieval using vector databases to augment LLM capabilities. Developed by hannesrudolph and forked by jumasheff, it enables AI assistants to search through stored documentation, extract URLs from web pages, manage documentation sources, and process queues of URLs for indexing. The server uses Qdrant for vector storage and supports multiple embedding providers including Ollama and OpenAI, making it particularly valuable for enhancing AI responses with relevant documentation context without requiring users to switch between interfaces.', '@jumasheff', 'databases', 'Unknown', 0, 'https://github.com/jumasheff/mcp-ragdoc-fork', NULL, 0, 'https://github.com/jumasheff.png?size=128', '2026-03-09T05:21:02.008745+00:00'),
  ('drissionpage', 'DrissionPage', 'Provides browser automation capabilities through DrissionPage library for web scraping, form filling, UI testing, and automated browsing with navigation, element manipulation, screenshot capture, and wait operations.', '@jumodada', 'development', 'Unknown', 7, 'https://github.com/jumodada/drissionpage-mcp-server', NULL, 0, 'https://github.com/jumodada.png?size=128', '2026-03-09T05:21:02.008767+00:00'),
  ('mcpjungle', 'MCPJungle', 'MCPJungle is a self-hosted MCP tool registry and proxy server built in Go that enables enterprise AI agents to discover, manage, and securely access multiple MCP servers through a centralized gateway. The implementation features dual operating modes (development for individual users, production for enterprises with authentication), supports both stdio and streamable HTTP MCP server transports, and provides a comprehensive CLI for server registration, tool management, and invocation with support for text, image, and audio content types. Built with PostgreSQL/SQLite storage, Docker deployment options, and fine-grained access control through client authentication and server allow-lists, it serves organizations needing centralized MCP tool governance, developers managing multiple MCP servers locally, and teams requiring secure multi-tenant access to distributed MCP resources with audit trails and permission management.', '@mcpjungle', 'databases', 'Unknown', 891, 'https://github.com/mcpjungle/mcpjungle', NULL, 0, 'https://github.com/mcpjungle.png?size=128', '2026-03-09T05:21:02.008781+00:00'),
  ('gemini-nanobanana-image-generation', 'Gemini Nanobanana (Image Generation)', 'A TypeScript MCP server that provides AI-powered image generation, editing, and composition capabilities through Google''s Gemini 2.5 Flash Image preview API. Built by Junhan2 with comprehensive error handling, retry logic, and structured logging, it offers four core tools: text-to-image generation, single image editing with prompts, multi-image composition, and style transfer between images. The implementation features robust input validation with support for multiple image formats (PNG, JPEG, WebP, GIF), automatic file saving with collision handling, configurable transport modes (stdio/HTTP), and security measures including path traversal protection and request size limits. Designed for developers and content creators who need programmatic access to advanced image generation capabilities for workflows like automated content creation, design prototyping, or batch image processing tasks.', '@junhan2', 'development', 'Unknown', 11, 'https://github.com/junhan2/gemini-nanobanana-mcp', 'gemini-nanobanana-mcp', 1546, 'https://github.com/junhan2.png?size=128', '2026-03-09T05:21:02.008819+00:00'),
  ('omise', 'Omise', 'Built by jun-omise with TypeScript, this server provides access to Omise''s payment processing platform with 18 specialized tools across payment workflows. Features extensive validation, rate limiting, and monitoring capabilities through Prometheus/Grafana integration, along with proper error handling and security measures including API key validation and environment-specific configurations. The implementation includes Docker deployment, testing suites, and detailed logging, making it valuable for e-commerce platforms, subscription services, marketplace applications, and any system requiring robust payment processing integration with Thailand''s leading payment gateway.', '@jun-omise', 'cloud', 'Unknown', 3, 'https://github.com/jun-omise/omise-mcp-alpha', NULL, 0, 'https://github.com/jun-omise.png?size=128', '2026-03-09T05:21:02.008841+00:00'),
  ('alteryx-server', 'Alteryx Server', 'This Alteryx Server MCP wrapper by Jupiter Bakakeu provides AI assistants with direct access to Alteryx Server''s REST API for workflow automation and data analytics operations. The implementation exposes comprehensive functionality including workflow execution with input data, collection management, user administration, schedule automation, job monitoring, and credential management, along with specialized features for downloading workflow packages and extracting XML configurations for analysis. Built with Python using the MCP protocol and featuring both stdio and SSE transport options, it enables data analysts and administrators to interact with Alteryx Server through natural language for tasks like executing data workflows, managing user assets, monitoring job status, and automating data processing pipelines without directly accessing the Alteryx interface.', '@jupiterbak', 'productivity', 'Unknown', 12, 'https://github.com/jupiterbak/ayx-mcp-wrapper', 'mcp-server-alteryx', 12775, 'https://github.com/jupiterbak.png?size=128', '2026-03-09T05:21:02.008905+00:00'),
  ('auphonic', 'Auphonic', 'Integrates with the Auphonic audio processing platform to automate podcast production workflows. Supports uploading audio files, monitoring production status, downloading processed output, and managing presets. Includes show-specific configurations for different podcast series with preset-based processing pipelines.', '@jupiterbroadcasting', 'file-systems', 'Unknown', 2, 'https://github.com/jupiterbroadcasting/auphonic-mcp', NULL, 0, 'https://github.com/jupiterbroadcasting.png?size=128', '2026-03-09T05:21:02.008943+00:00'),
  ('mcpunk-roaming-rag', 'MCPunk (Roaming RAG)', 'This MCP implementation, developed by Michael Jurasovic, provides a Python-based framework for building and interacting with MCP servers. It leverages libraries like FastMCP, GitPython, and SQLAlchemy to offer a robust foundation for creating MCP tools and resources. The implementation includes features for version control integration, database management, and asynchronous operations. It stands out by focusing on extensibility and developer-friendly abstractions, making it easier to create custom MCP servers and clients. This framework is particularly useful for developers looking to rapidly prototype and deploy MCP-compatible applications, especially those requiring integration with existing Python codebases or complex data processing workflows.', '@jurasofish', 'databases', 'Unknown', 56, 'https://github.com/jurasofish/mcpunk', 'mcpunk', 19810, 'https://github.com/jurasofish.png?size=128', '2026-03-09T05:21:02.008956+00:00'),
  ('ethereum-name-service-ens', 'Ethereum Name Service (ENS)', 'The ENS MCP Server enables Claude to interact with the Ethereum Name Service, providing tools to resolve ENS names to Ethereum addresses, perform reverse lookups, retrieve text records, check name availability, get registration prices, and explore name history. Built with TypeScript using the Model Context Protocol SDK, it connects to Ethereum networks through configurable providers and implements robust error handling for network issues and invalid inputs. This implementation by JustaName offers a complete interface to ENS functionality, making it valuable for blockchain applications that need to work with decentralized naming systems or verify Ethereum identity information.', '@justaname-id', 'development', 'Unknown', 9, 'https://github.com/justaname-id/ens-mcp-server', 'mcp-server-ens', 4667, 'https://github.com/justaname-id.png?size=128', '2026-03-09T05:21:02.008988+00:00'),
  ('accessibility-scanner', 'Accessibility Scanner', 'This accessibility scanner, developed for the Model Context Protocol, integrates Axe Core with Playwright to perform automated web accessibility testing. Built with TypeScript, it leverages the MCP SDK to provide a standardized interface for running accessibility checks on web pages. The implementation focuses on ease of use and comprehensive reporting, offering detailed insights into accessibility issues. It''s particularly useful for developers and quality assurance teams working on web applications, enabling use cases such as continuous integration testing, compliance auditing, and identifying accessibility barriers without manual inspection of each page element.', '@justasmonkev', 'development', 'Unknown', 43, 'https://github.com/justasmonkev/mcp-accessibility-scanner', NULL, 0, 'https://github.com/justasmonkev.png?size=128', '2026-03-09T05:21:02.009017+00:00'),
  ('justcall', 'JustCall', 'Provides integration with JustCall''s voice communication platform, enabling retrieval and analysis of call data through the JustCall API. Built by SaaS Labs, this server exposes tools for listing calls with filtering options including date ranges, contact numbers, agent assignments, call directions (incoming/outgoing), call types (answered/missed/voicemail), and advanced features like queue data and coaching insights. Designed for customer service and sales teams who need to access call logs, analyze communication patterns, track agent performance, or integrate voice data into business intelligence workflows.', '@saaslabsco', 'communication', 'Unknown', 26, 'https://github.com/saaslabsco/justcall-mcp-server', NULL, 0, 'https://github.com/saaslabsco.png?size=128', '2026-03-09T05:21:02.009052+00:00'),
  ('read-website-fast', 'Read Website Fast', 'This MCP server provides fast web content extraction and conversion to clean Markdown format, built by Just Every using TypeScript with Mozilla Readability for intelligent article detection and Turndown for HTML-to-Markdown conversion. It features disk-based caching, robots.txt compliance, concurrent crawling with configurable depth, and both CLI and MCP server modes for flexible integration. The implementation uses JSDOM for DOM parsing, supports relative URL conversion to absolute URLs, and includes smart content detection that applies Readability extraction only to clear article/blog pages while preserving full page content for other types of websites. Valuable for AI assistants that need to quickly extract and process web content for research, documentation, or content analysis workflows where clean Markdown output and fast performance are priorities.', '@just-every', 'development', 'Unknown', 135, 'https://github.com/just-every/mcp-read-website-fast', '@just-every/mcp-read-website-fast', 14547, 'https://github.com/just-every.png?size=128', '2026-03-09T05:21:02.009090+00:00'),
  ('screenshot-website-fast', 'Screenshot Website Fast', 'This MCP server provides fast, AI-optimized website screenshot capture using Puppeteer with automatic image tiling for large pages. Built by Just Every using TypeScript, it captures full-page screenshots and intelligently splits them into 1072x1072 pixel tiles optimized for Claude Vision API processing, with robust error handling including browser restart capabilities and retry logic for problematic sites. The implementation offers both CLI and MCP server interfaces with no caching to ensure always-fresh content, making it valuable for AI assistants that need to analyze web pages visually, generate code from website designs, or perform automated web content analysis where high-quality, properly-sized screenshots are essential for vision model processing.', '@just-every', 'development', 'Unknown', 102, 'https://github.com/just-every/mcp-screenshot-website-fast', NULL, 0, 'https://github.com/just-every.png?size=128', '2026-03-09T05:21:02.009123+00:00'),
  ('adaptive-agent', 'Adaptive Agent', 'Provides a persistent memory system for AI agents with cross-session knowledge retention through vector-based storage and semantic search capabilities. Built on FastMCP with ripgrep integration for fast text search, the system automatically indexes and stores conversation memories, enabling agents to recall past interactions and build contextual understanding over time. Features session management, memory parsing, graph-based knowledge storage, and 14 retrieval tools including hybrid search (vector + full-text), knowledge graph extraction, scope isolation (project/app/global), and concurrent safety mechanisms.', '@justforever17', 'development', 'Unknown', 3, 'https://github.com/justforever17/adaptive-agent-mcp', NULL, 0, 'https://github.com/justforever17.png?size=128', '2026-03-09T05:21:02.009150+00:00'),
  ('gong-io', 'Gong.io', 'Provides access to Gong.io conversation intelligence data through a TypeScript-based implementation. Enables AI assistants to query call recordings, retrieve transcripts with speaker attribution, access call summaries including participants and action items, and list workspace users. The implementation uses Zod validation for robust input handling and formats responses as markdown tables to optimize token usage, making it valuable for sales teams and revenue operations professionals who want to analyze call data, extract insights from customer conversations, and track meeting outcomes through natural language queries.', '@justinbeckwith', 'development', 'Unknown', 6, 'https://github.com/justinbeckwith/gongio-mcp', NULL, 0, 'https://github.com/justinbeckwith.png?size=128', '2026-03-09T05:21:02.009181+00:00'),
  ('linkinator', 'Linkinator', 'Provides automated link validation capabilities through the linkinator library. Performs recursive link crawling within domains, supports HTML, CSS, and Markdown parsing, validates anchor fragments, and delivers detailed error reporting grouped by status code. Includes extensive configuration options for timeouts, retries, SSL settings, and concurrency control.', '@justinbeckwith', 'development', 'Unknown', 3, 'https://github.com/justinbeckwith/linkinator-mcp', NULL, 0, 'https://github.com/justinbeckwith.png?size=128', '2026-03-09T05:21:02.009203+00:00'),
  ('pylon', 'Pylon', 'Provides integration with Pylon''s customer support platform, enabling comprehensive CRUD operations on accounts, contacts, issues, tags, and teams. This TypeScript implementation offers tools for creating and updating support tickets, managing customer relationships, searching across support data with flexible filters, and handling message redaction and issue workflow operations like snoozing and follower management. The server requires admin-level API access from the Pylon dashboard.', '@justinbeckwith', 'development', 'Unknown', 4, 'https://github.com/justinbeckwith/pylon-mcp', NULL, 0, 'https://github.com/justinbeckwith.png?size=128', '2026-03-09T05:21:02.009227+00:00'),
  ('javascript-webassembly-tools', 'JavaScript WebAssembly Tools', 'JavaScript MCP Server Component provides a WebAssembly-based implementation of the Model Context Protocol, enabling AI assistants to access external tools through a standardized interface. Built with a modular architecture, it includes ready-to-use tools like echo, knowledge graph querying, and HTTP requests, while offering a developer-friendly SDK for creating custom tools. The server handles JSON-RPC communication, manages tool registration, and supports asynchronous operations, making it particularly valuable for developers who need to extend AI capabilities with custom functionality in WebAssembly-compatible environments.', '@justin-echternach', 'ai-ml', 'Unknown', 0, 'https://github.com/justin-echternach/js-mcp-server', NULL, 0, 'https://github.com/justin-echternach.png?size=128', '2026-03-09T05:21:02.009307+00:00'),
  ('justrunmy', 'JustRunMy', 'This repository contains only a README.md file with no implementation code or configuration files visible, making it impossible to determine the purpose, functionality, or technical details of any MCP implementation that may be intended for this repository.', '@justrunmy-app', 'development', 'Unknown', 0, 'https://github.com/justrunmy-app/mcp', NULL, 0, 'https://github.com/justrunmy-app.png?size=128', '2026-03-09T05:21:02.009376+00:00'),
  ('ssh-linux-administration', 'SSH Linux Administration', 'An MCP server that enables secure remote Linux administration through SSH connections with comprehensive safety mechanisms. Built using Python with paramiko for SSH connectivity, it loads host configurations from YAML files containing credentials and connection details, then provides tools for connecting to hosts, executing commands with optional sudo privileges, and managing sessions. The implementation features destructive command detection using regex patterns that identify potentially harmful operations like file deletion, system shutdown, package removal, and permission changes, requiring explicit confirmation before execution to prevent accidental damage.', '@jutop', 'communication', 'Unknown', 1, 'https://github.com/jutop/mcp_linux_administration_ssh-openwebui_tool', NULL, 0, 'https://github.com/jutop.png?size=128', '2026-03-09T05:21:02.009412+00:00'),
  ('rest-apis', 'REST APIs', 'This MCP API Connect tool, developed by Jacob Waldor, provides a flexible interface for integrating any REST API into MCP-compatible workflows. Built with TypeScript and leveraging the Model Context Protocol SDK, it allows users to dynamically connect to APIs by simply providing API documentation and keys in a message. The implementation stands out by offering a global npm package with an easy setup process, making it accessible for both developers and non-technical users. It''s particularly useful for rapidly prototyping AI-assisted applications that require real-time data from various web services, enabling seamless integration of external data sources into AI workflows without the need for extensive coding or API-specific implementations.', '@jwaldor', 'development', 'Unknown', 10, 'https://github.com/jwaldor/mcp-api-expert', 'mcp-api-connect', 1287, 'https://github.com/jwaldor.png?size=128', '2026-03-09T05:21:02.009470+00:00'),
  ('jweather', 'JWeather', 'JWeather MCP Server provides a weather data service for AI assistants, built on the MCP framework. The server is implemented in Python 3.10 and uses asyncio for handling concurrent requests. It leverages GitHub Actions for automated testing, formatting, and type checking, with PyPI publishing configured for releases. The implementation follows modern Python packaging practices with uv for dependency management and includes comprehensive CI/CD workflows for quality assurance.', '@juhemcp', 'development', 'Unknown', 0, 'https://github.com/juhemcp/jweather-mcp-server', 'jweather-mcp-server', 1271, 'https://github.com/juhemcp.png?size=128', '2026-03-09T05:21:02.009514+00:00'),
  ('apple-voice-memo', 'Apple Voice Memo', 'Provides programmatic access to Apple Voice Memos on macOS. Enables browsing voice memos with metadata, retrieving specific recordings, accessing audio files in path or base64 format, extracting existing transcripts, and generating new transcripts using Apple''s SFSpeechRecognizer. Requires macOS Sonoma 14.0+ and Full Disk Access permission.', '@jwulff', 'file-systems', 'Unknown', 0, 'https://github.com/jwulff/apple-voice-memo-mcp', NULL, 0, 'https://github.com/jwulff.png?size=128', '2026-03-09T05:21:02.009555+00:00'),
  ('whisper', 'Whisper', 'Provides local speech-to-text transcription using whisper.cpp, enabling private audio processing without cloud dependencies. Supports multiple Whisper model sizes from tiny to large, handles various audio formats including WAV, MP3, and M4A, and includes tools for model management and downloading.', '@jwulff', 'media', 'Unknown', 1, 'https://github.com/jwulff/whisper-mcp', NULL, 0, 'https://github.com/jwulff.png?size=128', '2026-03-09T05:21:02.009600+00:00'),
  ('jxbrowser', 'JxBrowser', 'Provides AI coding assistance for JxBrowser, a cross-platform Java library for embedding Chromium browsers into desktop applications. Offers tools for generating project setup guides across different UI toolkits (Swing, JavaFX, Compose Desktop, SWT) and build systems (Maven, Gradle), as well as querying JxBrowser documentation for API help and troubleshooting.', '@unknown', 'development', 'Unknown', 0, 'https://teamdev.com/jxbrowser/docs/guides/introduction/mcp/', NULL, 0, NULL, '2026-03-09T05:21:02.009619+00:00'),
  ('codemode', 'Codemode', 'This MCP server implements Cloudflare''s "Code Mode" workflow, where instead of struggling with multiple tool calls, AI assistants write TypeScript/JavaScript code that makes HTTP requests to access MCP servers through a local proxy. Built by Jesus Moreno, it provides a single `execute_code` tool that runs code in a Deno sandbox with network-only permissions, while an HTTP proxy on port 3001 forwards requests to configured MCP servers. The approach leverages LLMs'' superior code-writing abilities over tool calling, enabling natural chaining of operations, data processing between calls, and complex multi-step workflows that would be difficult to achieve through traditional tool orchestration.', '@jx-codes', 'cloud', 'Unknown', 115, 'https://github.com/jx-codes/codemode-mcp', NULL, 0, 'https://github.com/jx-codes.png?size=128', '2026-03-09T05:21:02.009638+00:00'),
  ('apple-macos-native-applications', 'Apple macOS Native Applications', 'Python Apple MCP enables AI assistants to interact with macOS native applications through AppleScript. This implementation provides modules for Contacts, Notes, Mail, Messages, Reminders, Calendar, and Maps, offering asynchronous operations with comprehensive error handling and type-safe interfaces using Pydantic models. Built with a modular design for easy extension, it allows AI systems to perform tasks like searching contacts, creating notes, sending emails, scheduling events, and getting directions - making it particularly valuable for automating personal information management tasks on macOS.', '@jxnl', 'communication', 'Unknown', 17, 'https://github.com/jxnl/python-apple-mcp', NULL, 0, 'https://github.com/jxnl.png?size=128', '2026-03-09T05:21:02.009675+00:00'),
  ('cursor-cloud-agents', 'Cursor Cloud Agents', 'Cursor Cloud Agents provides direct access to Cursor''s Cloud Agents API for automated repository management and code generation tasks. Built with TypeScript and the Model Context Protocol SDK, it exposes tools for repository discovery with git context detection, cloud task creation and monitoring, follow-up instruction sending, conversation history retrieval, and task lifecycle management. The implementation features comprehensive error handling, structured logging, regex-based filtering, and support for both STDIO and HTTP transports.', '@jxnl', 'development', 'Unknown', 6, 'https://github.com/jxnl/cursor-cloud-agent-mcp', NULL, 0, 'https://github.com/jxnl.png?size=128', '2026-03-09T05:21:02.009699+00:00'),
  ('spiral-writer', 'Spiral Writer', 'Spiral MCP Server provides a standardized interface for interacting with Spiral''s language models through four powerful tools: listing available models, generating text from prompts, processing content from files, and extracting article content from URLs. Built with FastMCP, it features robust error handling, asynchronous operations for better performance, and smart article extraction capabilities using BeautifulSoup. The implementation is particularly valuable for content generation workflows that require processing inputs from various sources, making it ideal for blog writing, technical documentation expansion, and news article analysis without leaving the conversation interface.', '@jxnl', 'ai-ml', 'Unknown', 17, 'https://github.com/jxnl/spiral-mcp', NULL, 0, 'https://github.com/jxnl.png?size=128', '2026-03-09T05:21:02.009749+00:00'),
  ('biomart', 'Biomart', 'This MCP server implementation provides a bridge to Biomart, a powerful bioinformatics data retrieval system. Developed by John Zinno, it enables AI assistants to perform advanced biological data queries, including gene information retrieval, ID translation, and dataset exploration. The server integrates closely with the pybiomart package, offering features like attribute and filter exploration, data retrieval, and caching for improved performance. It''s designed for applications requiring access to genomic, proteomic, and other biological datasets.', '@jzinno', 'ai-ml', 'Unknown', 7, 'https://github.com/jzinno/biomart-mcp', NULL, 0, 'https://github.com/jzinno.png?size=128', '2026-03-09T05:21:02.009789+00:00'),
  ('design-arena-router', 'Design Arena Router', 'Connects to the designarena.ai crowdsourced leaderboard to identify the highest-ranked design model and routes prompts to it through OpenRouter. Supports filtering by design category (websites, game development, 3D, data visualization, UI components, logos, SVGs, and more). Provides tools for browsing leaderboard rankings, retrieving the current best model, and sending design prompts to either the top-ranked or a specific model.', '@k1ta141k', 'development', 'Unknown', 6, 'https://github.com/k1ta141k/mcp-bench-router', NULL, 0, 'https://github.com/k1ta141k.png?size=128', '2026-03-09T05:21:02.009830+00:00'),
  ('voicepeak', 'VOICEPEAK', 'Built by k2wanko using TypeScript and Bun, this server provides Japanese text-to-speech synthesis capabilities through integration with the VOICEPEAK engine. It supports multiple narrators like Tohoku Zunko and Zundamon with customizable emotions, speed, and pitch parameters. The implementation features robust process management with queuing and retry logic, input validation and sanitization, cross-platform support for macOS/Windows/Linux, and pronunciation dictionary management for custom word pronunciations. Advanced safety features include path traversal protection, concurrent process limiting, automatic temp file cleanup, and WAV format validation, making it valuable for creating Japanese voice content, accessibility applications, and language learning tools.', '@k2wanko', 'development', 'Unknown', 5, 'https://github.com/k2wanko/voicepeak-mcp', 'voicepeak-mcp', 1147, 'https://github.com/k2wanko.png?size=128', '2026-03-09T05:21:02.009873+00:00'),
  ('fumadocs', 'Fumadocs', 'Provides access to Fumadocs documentation through tools for searching, browsing, and retrieving framework-specific setup guides. Enables queries against the Fumadocs knowledge base with specialized tools for getting component documentation, framework installation instructions, and topic exploration across documentation sections. Includes intelligent caching and content extraction from structured documentation indexes.', '@k4cper-g', 'ai-ml', 'Unknown', 9, 'https://github.com/k4cper-g/fumadocs-mcp', NULL, 0, 'https://github.com/k4cper-g.png?size=128', '2026-03-09T05:21:02.009912+00:00'),
  ('ai-pair-programmer', 'AI Pair Programmer', 'This Ruby-based AI pair programming MCP server by K4sku provides five specialized tools for collaborative software development: general pair programming assistance, code review, brainstorming, performance analysis, and security review. Built using the FastMCP framework and RubyLLM library, it integrates with multiple AI models through OpenRouter including Gemini, O3, Grok, DeepSeek, and Claude Opus, with automatic gem installation via inline bundler for easy deployment. The implementation is particularly valuable for developers who want AI-powered code analysis and collaboration directly within their development workflow, offering configurable model selection and temperature settings for different types of programming tasks from creative brainstorming to rigorous security audits.', '@k4sku', 'development', 'Unknown', 3, 'https://github.com/k4sku/ai-pair-programmer-mcp', NULL, 0, 'https://github.com/k4sku.png?size=128', '2026-03-09T05:21:02.009945+00:00'),
  ('fred-economic-data', 'FRED Economic Data', 'This FRED (Federal Reserve Economic Data) MCP server provides AI assistants with access to economic data from the Federal Reserve Bank of St. Louis. It integrates with the FRED API to offer tools for retrieving time series data, searching for economic indicators, and obtaining metadata about data series. Built with TypeScript and the @modelcontextprotocol/sdk, it implements automatic rate limiting to comply with FRED''s usage guidelines. The server abstracts the complexities of working with economic datasets, allowing AI systems to easily incorporate up-to-date economic indicators into their analyses. It is particularly useful for economists, financial analysts, and AI developers working on economic modeling or forecasting applications, enabling use cases like trend analysis, economic research, and data-driven policy recommendations.', '@kablewy', 'development', 'Unknown', 10, 'https://github.com/kablewy/fred-mcp-server', NULL, 0, 'https://github.com/kablewy.png?size=128', '2026-03-09T05:21:02.010029+00:00'),
  ('salesforce', 'Salesforce', 'This Salesforce MCP server, developed as an open-source project, enables AI assistants to interact with Salesforce data and operations through the Salesforce REST API. It provides a streamlined interface for executing SOQL queries, retrieving object metadata, and performing CRUD operations on Salesforce records. The server abstracts the complexities of Salesforce authentication and API calls, offering a set of high-level functions that simplify data access and manipulation. By connecting AI systems with real-time Salesforce data, this implementation facilitates tasks such as customer data analysis, sales pipeline management, and automated CRM updates. It is particularly useful for AI applications requiring integration with Salesforce, such as intelligent sales assistants, automated reporting tools, or any system that needs to programmatically interact with Salesforce data.', '@kablewy', 'productivity', 'Unknown', 43, 'https://github.com/kablewy/salesforce-mcp-server', NULL, 0, 'https://github.com/kablewy.png?size=128', '2026-03-09T05:21:02.010083+00:00'),
  ('lxd', 'LXD', 'Provides comprehensive LXD container and virtual machine management through the Model Context Protocol. Built in Go using the official Canonical LXD client library, it offers complete lifecycle operations including creation, deletion, start/stop/restart, freezing, and configuration updates for both containers and VMs. Supports image management with shortcuts for Ubuntu and LXD image repositories, command execution within instances, and detailed state monitoring. Useful for automating container workflows, managing development environments, or orchestrating containerized applications.', '@kadinsayani', 'development', 'Unknown', 1, 'https://github.com/kadinsayani/lxd-mcp', NULL, 0, 'https://github.com/kadinsayani.png?size=128', '2026-03-09T05:21:02.010109+00:00'),
  ('openapi-schema-explorer', 'OpenAPI Schema Explorer', 'MCP OpenAPI Schema Explorer is a TypeScript server that provides token-efficient access to OpenAPI (v3.0) and Swagger (v2.0) specifications. Developed by Aleksandr Kadykov, it transforms large API specifications into navigable MCP resources with URI-based references, allowing AI assistants to explore API structures without loading entire specs into their context windows. The server loads specs from local files or remote URLs, automatically converts Swagger v2.0 to OpenAPI v3.0, and returns information in configurable formats (JSON, YAML, or minified JSON), making it particularly valuable for working with complex APIs that would otherwise consume excessive tokens.', '@kadykov', 'development', 'Unknown', 66, 'https://github.com/kadykov/mcp-openapi-schema-explorer', 'mcp-openapi-schema-explorer', 6366, 'https://github.com/kadykov.png?size=128', '2026-03-09T05:21:02.010139+00:00'),
  ('n8n-monitoring', 'n8n Monitoring', 'Monitors n8n workflow automation health by analyzing execution history, tracking KPIs like success rates and timing data, and providing detailed error diagnostics for failed workflows.', '@kaewz-manga', 'ai-ml', 'Unknown', 1, 'https://github.com/kaewz-manga/n8n-monitoring-mcp', NULL, 0, 'https://github.com/kaewz-manga.png?size=128', '2026-03-09T05:21:02.010166+00:00'),
  ('wordpress-rest-api', 'WordPress REST API', 'A TypeScript-based MCP server that integrates WordPress with Claude and n8n via REST API, running on Cloudflare Workers infrastructure. Provides 24 tools for managing posts, pages, media, categories, tags, and comments. Supports multi-tenant authentication, external image hosting via NodeFlow, and headless WordPress implementations for automated content workflows.', '@kaewz-manga', 'cloud', 'Unknown', 1, 'https://github.com/kaewz-manga/wordpress-nodeflow-mcp', NULL, 0, 'https://github.com/kaewz-manga.png?size=128', '2026-03-09T05:21:02.010184+00:00'),
  ('kaggle', 'Kaggle', 'Kaggle-MCP provides a bridge between Claude AI and the Kaggle API, enabling AI assistants to interact with Kaggle''s competitions, datasets, kernels, and models. The implementation offers a comprehensive set of tools for authenticating with Kaggle, browsing competitions, downloading datasets, managing kernels, and working with machine learning models. Built on the Model Context Protocol, it allows Claude to perform operations like listing active competitions, searching datasets, submitting to competitions, and creating or updating models—all while maintaining proper authentication and file handling. This integration is particularly valuable for data scientists and machine learning practitioners who want to leverage Claude''s capabilities while working with Kaggle''s resources.', '@54yyyu', 'ai-ml', 'Unknown', 29, 'https://github.com/54yyyu/kaggle-mcp', 'kaggle-mcp', 1997, 'https://github.com/54yyyu.png?size=128', '2026-03-09T05:21:02.010246+00:00'),
  ('kaiafun', 'KaiaFun', 'KaiaFun MCP Server enables AI assistants to interact with the KaiaFun memecoin platform on the Kaia blockchain. It provides tools for listing new memecoins, buying and selling tokens, retrieving token information, and uploading images. The implementation uses the viem library for blockchain interactions and includes features for wallet management, transaction handling, and metadata storage. Ideal for users wanting to automate memecoin trading operations or create AI-powered interfaces for the KaiaFun ecosystem.', '@weero-finance', 'ai-ml', 'Unknown', 1, 'https://github.com/weero-finance/kaiafun-mcp', NULL, 0, 'https://github.com/weero-finance.png?size=128', '2026-03-09T05:21:02.010335+00:00'),
  ('graphql-toolkit', 'GraphQL Toolkit', 'GraphQL MCP Toolkit is a server implementation that enables LLMs to interact with GraphQL APIs through schema introspection and query execution. It provides two main tools: one for retrieving GraphQL schemas and another for executing queries against endpoints, with mutations disabled by default as a security measure. The implementation supports custom headers for authentication, local schema files as an alternative to introspection, and is containerized for easy deployment. Particularly valuable for developers who want to give AI assistants the ability to discover and use GraphQL APIs dynamically without requiring prior knowledge of the schema.', '@kailashappdev', 'ai-ml', 'Unknown', 0, 'https://github.com/kailashappdev/graphql-mcp-toolkit', NULL, 0, 'https://github.com/kailashappdev.png?size=128', '2026-03-09T05:21:02.010382+00:00'),
  ('figma-to-react-native', 'Figma to React Native', 'Figma Component Extractor MCP server enables AI assistants to extract and analyze components from Figma design files. Built by Kailash G, it provides tools for fetching component data, extracting component properties, and converting Figma designs into structured representations. The server requires a Figma API token and file ID to connect to design files, and includes utilities for processing component hierarchies, normalizing naming conventions, and generating component metadata. This implementation is particularly valuable for design-to-code workflows, allowing seamless integration between Figma designs and React Native development without leaving the conversation interface.', '@kailashappdev', 'development', 'Unknown', 7, 'https://github.com/kailashappdev/figma-mcp-toolkit', '@kailashg101/mcp-figma-to-code', 4926, 'https://github.com/kailashappdev.png?size=128', '2026-03-09T05:21:02.010411+00:00'),
  ('python-debugger', 'Python Debugger', 'Debug-MCP provides Python debugging capabilities through breakpoint-based execution control and variable inspection, built by the Debug-MCP team using Python''s standard debugging libraries (bdb/pdb) with an optional DAP (debugpy) backend for enhanced functionality. The server manages debug sessions that can run Python scripts to specific breakpoints, capture local variable states with type information and truncation handling, and continue execution to subsequent breakpoints, all while enforcing safety limits like timeouts and output capture restrictions. It supports multiple concurrent sessions, custom Python interpreter paths, command-line arguments, and environment variables, making it useful for AI-assisted debugging workflows, educational Python environments, and automated code analysis tasks where controlled script execution and state inspection are needed.', '@kaina3', 'development', 'Unknown', 1, 'https://github.com/kaina3/debug-mcp', NULL, 0, 'https://github.com/kaina3.png?size=128', '2026-03-09T05:21:02.010444+00:00'),
  ('nexus-memory', 'Nexus Memory', 'Persistent semantic memory for AI agents with knowledge graphs and Intelligence Packs.', '@kairosmobius', 'ai-ml', 'Unknown', 0, 'https://github.com/kairosmobius/nexus-memory-mcp', NULL, 0, 'https://github.com/kairosmobius.png?size=128', '2026-03-09T05:21:02.010465+00:00'),
  ('mcp-fixer', 'MCP Fixer', 'This MCP server provides diagnostic and repair tools for Model Context Protocol configurations in Claude Desktop, built by the MCP Fixer Team using TypeScript with the official MCP SDK. It offers seven core diagnostic tools including configuration analysis with JSON syntax validation, server status checking with command verification, automatic syntax fixing with backup creation, dependency validation for Node.js/Python/npm/uv, port conflict detection, comprehensive diagnostic reporting with log analysis, and intelligent fix suggestions with step-by-step remediation guides. The implementation features cross-platform support for Windows/macOS/Linux with automatic config path detection, smart error pattern recognition from Claude Desktop logs, and preventive maintenance recommendations, making it valuable for developers and users who need to troubleshoot MCP server connectivity issues, configuration errors, and environment setup problems.', '@kajdep', 'development', 'Unknown', 3, 'https://github.com/kajdep/mcp-fixer', '@kajdep/mcp-fixer', 207, 'https://github.com/kajdep.png?size=128', '2026-03-09T05:21:02.010498+00:00'),
  ('esa', 'esa', 'Provides a bridge between Claude AI and the esa API, enabling AI-driven document management through tools for searching, creating, updating and deleting posts and comments. Built by kajirita2002, this Node.js implementation exposes a full suite of esa''s functionality including member management and post categorization, making it valuable for teams who want to leverage AI assistance for their esa-based documentation and knowledge management workflows.', '@kajirita2002', 'ai-ml', 'Unknown', 8, 'https://github.com/kajirita2002/esa-mcp-server', '@kajirita2002/esa-mcp-server', 5197, 'https://github.com/kajirita2002.png?size=128', '2026-03-09T05:21:02.010534+00:00'),
  ('kakao-mobility', 'Kakao Mobility', 'A Kakao Mobility API integration server that enables AI assistants to access various location-based services through the Model Context Protocol. The server provides tools for geocoding addresses, searching locations by name, and calculating routes between points with various transportation options. It supports both simple point-to-point directions and more complex scenarios like multi-destination routing and future travel time predictions. Built with TypeScript and Node.js, this implementation makes Kakao''s mapping and navigation capabilities available to AI systems for travel planning, commute analysis, and location-based recommendations.', '@unknown', 'development', 'Unknown', 0, 'https://www.pulsemcp.com/servers/kakao-mobility', NULL, 0, NULL, '2026-03-09T05:21:02.010564+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('kakao-navigation', 'Kakao Navigation', 'A Kakao Navigation MCP server that enables AI assistants to access Kakao Maps and Mobility APIs for route planning and location services. The implementation provides tools for direction searching using coordinates or addresses, geocoding, and place name searches. It leverages Kakao''s REST API with proper authentication to retrieve navigation data, making it useful for applications that need to calculate routes, find locations, or provide travel directions within Korea. The server returns structured JSON responses that can be easily parsed and presented to users.', '@cachij', 'ai-ml', 'Unknown', 10, 'https://github.com/cachij/kakao-navigation-mcp-server', NULL, 0, 'https://github.com/cachij.png?size=128', '2026-03-09T05:21:02.010603+00:00'),
  ('mattermost-fetch', 'Mattermost Fetch', 'A web scraping and content extraction MCP server built by Kakehashi Inc, designed to fetch and process web content with robust features like robots.txt compliance, LRU caching, and markdown conversion. The implementation supports both autonomous and manual fetching modes, with configurable user agents and the ability to handle various content types while providing pagination and error handling for web resource retrieval.', '@kakehashi-inc', 'search', 'Unknown', 4, 'https://github.com/kakehashi-inc/mcp-server-mattermost', NULL, 0, 'https://github.com/kakehashi-inc.png?size=128', '2026-03-09T05:21:02.010647+00:00'),
  ('ros-2-robot-control', 'ROS 2 Robot Control', 'The ros2-mcp-server integrates the Model Context Protocol with ROS 2, enabling AI assistants to control robots through standard ROS topics. Built with FastMCP and running as a native ROS 2 node, it processes natural language commands and translates them into geometry_msgs/Twist messages published to the /cmd_vel topic, supporting time-based movement instructions like ''move forward at 0.2 m/s for 5 seconds.'' The implementation combines FastMCP''s asyncio capabilities with ROS 2''s event loop for efficient command processing, making it ideal for robotics researchers and developers who want to enable natural language control of ROS-based robots.', '@kakimochi', 'ai-ml', 'Unknown', 75, 'https://github.com/kakimochi/ros2-mcp-server', NULL, 0, 'https://github.com/kakimochi.png?size=128', '2026-03-09T05:21:02.010691+00:00'),
  ('kalendis', 'Kalendis', 'Kalendis MCP Server generates TypeScript API clients for the Kalendis scheduling API, providing tools to create backend clients with x-api-key authentication, frontend clients for browser applications, and framework-specific route handlers for Next.js, Express, Fastify, and NestJS. Built by the Kalendis team, it eliminates the need for manual API integration by automatically generating properly typed client code that handles user management, availability scheduling, recurring patterns, exceptions, and booking operations. The implementation includes timezone conversion utilities and supports multiple environments (production, staging, development), making it valuable for developers building scheduling applications who need clean, type-safe API clients without writing boilerplate integration code.', '@kalendis-dev', 'development', 'Unknown', 0, 'https://github.com/kalendis-dev/kalendis-mcp', '@kalendis/mcp', 730, 'https://github.com/kalendis-dev.png?size=128', '2026-03-09T05:21:02.010723+00:00'),
  ('stellar-blockchain', 'Stellar Blockchain', 'A Stellar blockchain integration server for the MCP that enables AI assistants to interact with Soroban smart contracts. Built with TypeScript and deployed on Cloudflare Workers, this implementation provides tools for deploying fungible tokens, managing wallet addresses, and executing contract functions on the Stellar testnet. It features a durable object storage system to maintain user-specific contract addresses and credentials, OAuth-based authentication, and integration with PasskeyKit for transaction signing. The server dynamically generates MCP tools from contract specifications, allowing AI assistants to perform operations like token minting, transfers, and custom contract interactions without requiring blockchain expertise.', '@kalepail', 'cloud', 'Unknown', 5, 'https://github.com/kalepail/stellar-mcp-server', NULL, 0, 'https://github.com/kalepail.png?size=128', '2026-03-09T05:21:02.010745+00:00'),
  ('rag', 'RAG', 'A cloud-based RAG server that provides document management and semantic search capabilities using OpenAI''s embedding and chat APIs. The implementation features an in-memory vector store with cosine similarity search, document ingestion tools for adding and managing text content with metadata, search functionality with filtering support, and utility tools for database statistics and management. Built with persistence support through JSON serialization and designed for cloud-only operation without local vector databases, it''s useful for building AI assistants that need to search and retrieve information from custom document collections, knowledge bases, or content repositories.', '@kalicyh', 'databases', 'Unknown', 4, 'https://github.com/kalicyh/mcp-rag', 'mcp-rag', 16249, 'https://github.com/kalicyh.png?size=128', '2026-03-09T05:21:02.010788+00:00'),
  ('enterprise-printer-database', 'Enterprise Printer Database', 'A specialized server providing comprehensive enterprise printer information for sales and service teams with a database covering HP, Canon, Kyocera, Konica Minolta, Sharp, Lexmark, Ricoh, Brother, and Epson. Features intelligent tools for printer search by specifications, detailed model information, side-by-side comparisons, TCO calculations, consumables lookup with part numbers, AI-powered recommendations, troubleshooting assistance, setup instructions, and configuration page access. Built with TypeScript and SQLite with full-text search capabilities, combining structured JSON printer data with PDF manual search functionality for sales teams conducting product research, service technicians performing diagnostics and repairs, and IT departments evaluating printers for fleet deployment.', '@kalistudent', 'databases', 'Unknown', 1, 'https://github.com/kalistudent/pc-hardware-mcp', NULL, 0, 'https://github.com/kalistudent.png?size=128', '2026-03-09T05:21:02.010799+00:00'),
  ('guardian-osv-security-scanner', 'Guardian (OSV Security Scanner)', 'GuardianMCP is a security-focused MCP server built by Kalvisan that provides proactive vulnerability scanning for project dependencies through integration with the OSV (Open Source Vulnerabilities) database. The implementation offers automated vulnerability detection with configurable severity filtering, supports multiple package managers, and includes Docker deployment with multi-stage builds for optimized container size. Built with TypeScript and the MCP SDK, it features npm audit integration, outdated package checking, and structured vulnerability reporting with remediation guidance. Designed for security-conscious development workflows, it enables automated dependency scanning during package installations, before commits, or on explicit security requests, making it valuable for maintaining secure codebases and implementing proactive security monitoring in CI/CD pipelines.', '@kalvisan', 'databases', 'Unknown', 1, 'https://github.com/kalvisan/guardian-mcp', NULL, 0, 'https://github.com/kalvisan.png?size=128', '2026-03-09T05:21:02.010865+00:00'),
  ('deepseek-r1', 'Deepseek R1', 'This MCP server, developed by Kamel IRZOUNI, provides integration with the Deepseek R1 model. Built with TypeScript and leveraging the Model Context Protocol SDK, it enables AI assistants to interact with Deepseek''s advanced language model capabilities. The implementation focuses on providing a standardized interface for text generation and analysis tasks, making it easier to incorporate Deepseek''s AI features into various applications. It''s particularly useful for developers and teams who want to leverage Deepseek''s language model in their AI workflows, enabling use cases such as content generation, text analysis, and AI-assisted decision-making without directly managing API interactions with Deepseek.', '@66julienmartin', 'development', 'Unknown', 69, 'https://github.com/66julienmartin/mcp-server-deepseek_r1', NULL, 0, 'https://github.com/66julienmartin.png?size=128', '2026-03-09T05:21:02.010897+00:00'),
  ('qwen-max', 'Qwen Max', 'This MCP implementation, developed by Kamel IRZOUNI, provides integration with the Qwen Max large language model via the Dashscope API. Built with TypeScript and leveraging the Model Context Protocol SDK, it enables AI assistants to interact with Qwen Max''s advanced natural language processing capabilities. The implementation focuses on providing a standardized interface for text generation and analysis tasks. It''s particularly useful for developers and researchers who want to incorporate Qwen Max''s language understanding into their applications, enabling use cases such as content generation, text analysis, and conversational AI without directly managing API calls to Dashscope.', '@66julienmartin', 'development', 'Unknown', 24, 'https://github.com/66julienmartin/mcp-server-qwen_max', NULL, 0, 'https://github.com/66julienmartin.png?size=128', '2026-03-09T05:21:02.010928+00:00'),
  ('weekly-reports', 'Weekly Reports', 'A lightweight MCP server designed to check and process weekly reports, integrating with Google Sheets via the gspread library. The server provides a development mode for easy testing and configuration, with a simple script-based deployment process. Useful for teams needing automated weekly report validation and tracking.', '@kaneyxx', 'development', 'Unknown', 0, 'https://github.com/kaneyxx/weekly-report-mcp', NULL, 0, 'https://github.com/kaneyxx.png?size=128', '2026-03-09T05:21:02.010949+00:00'),
  ('kanta', 'Kanta', 'The Kanta MCP Server provides integration with the Kanta API, a French accounting and compliance platform focused on anti-money laundering (AML) and know-your-customer (KYC) workflows. Built using TypeScript with comprehensive Zod schema validation, it exposes tools for managing customers, users, persons, firms, and risk assessments through the Kanta API. The server enables AI assistants to perform operations like creating and searching customers by company numbers (SIREN/SIRET), managing user assignments, retrieving risk summaries, and handling compliance documentation. It''s particularly valuable for French accounting firms and financial institutions that need to automate KYC processes, manage client onboarding, assess risk profiles, and maintain regulatory compliance through conversational AI interfaces.', '@kanta-inc', 'development', 'Unknown', 1, 'https://github.com/kanta-inc/kanta-mcp-server', NULL, 0, 'https://github.com/kanta-inc.png?size=128', '2026-03-09T05:21:02.011028+00:00'),
  ('intercom-articles', 'Intercom Articles', 'Provides read-only access to Intercom Help Center articles through the Intercom API, enabling retrieval and reference of customer support documentation. Built using the official MCP SDK, this server connects to Intercom''s API to fetch article content, making it useful for customer service automation, knowledge base integration, and support ticket resolution workflows where agents need access to existing help documentation.', '@kaosensei', 'browser-automation', 'Unknown', 5, 'https://github.com/kaosensei/intercom-mcp', NULL, 0, 'https://github.com/kaosensei.png?size=128', '2026-03-09T05:21:02.011107+00:00'),
  ('dash', 'Dash', 'This MCP server provides AI assistants with access to Dash documentation browser functionality on macOS, built by Kapeli using Python with FastMCP and httpx for HTTP operations. The implementation offers three core tools for listing installed docsets, searching across documentation and code snippets with filtering capabilities, and enabling full-text search for specific docsets, all backed by automatic Dash application launching, API server detection through status file monitoring, and user-guided API server enablement with fallback mechanisms. Built with comprehensive error handling, automatic port discovery, and seamless integration with Dash''s local API server, it serves developers needing conversational access to their locally installed documentation, teams wanting to integrate documentation search into AI-assisted coding workflows, and users requiring quick reference lookups across multiple programming languages and frameworks without leaving their development environment.', '@kapeli', 'development', 'Unknown', 120, 'https://github.com/kapeli/dash-mcp-server', NULL, 0, 'https://github.com/kapeli.png?size=128', '2026-03-09T05:21:02.011140+00:00'),
  ('okta-user-management', 'Okta User Management', 'Okta MCP Server enables Claude to interact with Okta''s user management system through a Node.js implementation that connects to the Okta API. Developed by Kapil Duraphe, it currently provides a ''get_user'' tool that retrieves detailed user information including profile data, account status, employment details, and contact information. The server handles authentication through Okta API tokens, includes robust error handling for common issues like missing users or authentication problems, and is designed to be integrated with Claude Desktop for seamless user information retrieval directly within conversations.', '@kapilduraphe', 'ai-ml', 'Unknown', 20, 'https://github.com/kapilduraphe/okta-mcp-server', NULL, 0, 'https://github.com/kapilduraphe.png?size=128', '2026-03-09T05:21:02.011191+00:00'),
  ('webflow', 'Webflow', 'This MCP server implementation provides a bridge to the Webflow API, enabling AI assistants to interact with Webflow sites. Developed by Kapil Duraphe, it offers tools for retrieving site information, including detailed data on custom domains, locales, and data collection settings. The server is built using TypeScript and integrates with the Model Context Protocol SDK. It focuses on secure API token management and robust error handling, making it suitable for developers and AI applications that need to automate Webflow site management tasks or integrate Webflow data into their workflows. The implementation is designed for easy setup and configuration within the Claude Desktop environment.', '@kapilduraphe', 'development', 'Unknown', 21, 'https://github.com/kapilduraphe/webflow-mcp-server', NULL, 0, 'https://github.com/kapilduraphe.png?size=128', '2026-03-09T05:21:02.011220+00:00'),
  ('notion-markdown', 'Notion Markdown', 'Notion-MCP-Light is a Python-based server implementation that provides AI assistants with access to Notion workspaces through a simplified interface. It converts Notion content to Markdown format, making it easier to retrieve and manipulate information stored in Notion databases and pages. The server includes components for authenticating with the Notion API, converting complex Notion blocks to clean Markdown, and serving the content through an MCP-compatible interface. This implementation is particularly useful for teams who want to enable AI assistants to read from, search through, or summarize their Notion knowledge bases without requiring complex integration code.', '@karaage0703', 'databases', 'Unknown', 51, 'https://github.com/karaage0703/notion-mcp-light', NULL, 0, 'https://github.com/karaage0703.png?size=128', '2026-03-09T05:21:02.011256+00:00'),
  ('lichess', 'Lichess', 'This MCP server enables natural language interaction with the Lichess chess platform, integrating with its API to manage accounts, play games, analyze positions, and participate in tournaments. Developed by Alper Karayaman, it leverages the Model Context Protocol to provide a seamless interface for AI assistants like Claude Desktop to engage with Lichess functionalities. The server is particularly useful for chess enthusiasts looking to enhance their gameplay, analysis, and community engagement through AI-assisted interactions.', '@karayaman', 'ai-ml', 'Unknown', 12, 'https://github.com/karayaman/lichess-mcp', NULL, 0, 'https://github.com/karayaman.png?size=128', '2026-03-09T05:21:02.011296+00:00'),
  ('slack-web-api', 'Slack Web API', 'Provides extensive access to the Slack Web API across all major API families including conversations, messaging, files, users, canvases, lists, reminders, workflows, and calls. Supports both standard OAuth tokens and browser session tokens for accessing undocumented and legacy endpoints. Built on FastMCP 3.0 with the official Slack SDK, requiring Python 3.13+ and a Slack app OAuth token for authentication.', '@karbassi', 'communication', 'Unknown', 1, 'https://github.com/karbassi/slack-mcp', NULL, 0, 'https://github.com/karbassi.png?size=128', '2026-03-09T05:21:02.011321+00:00'),
  ('codezap', 'CodeZap', 'This MCP server acts as a project CTO for vibe coders, helping developers take the crucial step from 0 to 1 in product development by automating the initial setup and architectural decisions that often cause project abandonment. Built by KAREVERIE and designed to integrate with mainstream AI IDEs like Cursor, WindSurf, Trae, and Cline, it clarifies product requirements through simple questions, selects modern AI-friendly technology stacks, automatically builds initialized projects with standardized architecture, and provides AI IDE rules aligned with official best practices. The implementation addresses the common problem where 80% of projects fail because developers spend excessive time on tech stack research and development environment setup, offering development tips and process planning to help users manage code and development flow like experienced engineers.', '@unknown', 'development', 'Unknown', 0, 'https://www.codezap.co', NULL, 0, NULL, '2026-03-09T05:21:02.011352+00:00'),
  ('google-stitch', 'Google Stitch', 'Integrates with Google Stitch design platform to enable automated UI/UX design workflows, component generation, and cross-platform design system management for designers and developers.', '@kargatharaakash', 'aggregators', 'Unknown', 71, 'https://github.com/kargatharaakash/stitch-mcp', NULL, 0, 'https://github.com/kargatharaakash.png?size=128', '2026-03-09T05:21:02.011404+00:00'),
  ('pokemon-nds-desmume', 'Pokemon NDS DeSmuME', 'Controls Nintendo DS emulation through DeSmuME, enabling button presses, touchscreen input, screenshot capture, save state management, and persistent memory tracking for automated gameplay.', '@kartik-2239', 'browser-automation', 'Unknown', 1, 'https://github.com/kartik-2239/pokemon-nds-mcp', NULL, 0, 'https://github.com/kartik-2239.png?size=128', '2026-03-09T05:21:02.011450+00:00'),
  ('kaspa', 'Kaspa', 'Enables interaction with the Kaspa blockchain network through wallet management tools. Supports deriving wallet addresses from BIP39 mnemonics or private keys, checking balances, estimating transaction fees, sending KAS tokens, and retrieving transaction details. Built with kaspa-wasm for cryptographic operations and uses Kaspa REST APIs for network interactions with RPC connections for transaction broadcasting.', '@kasanova-io', 'development', 'Unknown', 3, 'https://github.com/kasanova-io/kaspa-mcp', NULL, 0, 'https://github.com/kasanova-io.png?size=128', '2026-03-09T05:21:02.011476+00:00'),
  ('cairo-coder', 'Cairo Coder', 'The Cairo Coder MCP Server provides AI assistants with access to Cairo and Starknet development expertise through the Cairo Coder API. Built by KasarLabs, it offers a single tool for querying Cairo/Starknet development questions with optional context, supporting both the public Cairo Coder API with authentication and local/custom endpoints for self-hosted deployments. The server enables AI agents to generate Cairo smart contracts, refactor existing code, implement specific features, and provide contextual guidance based on Cairo/Starknet documentation and best practices, making it valuable for blockchain developers working on Starknet applications who need expert-level Cairo programming assistance integrated into their development workflow.', '@kasarlabs', 'development', 'Unknown', 14, 'https://github.com/kasarlabs/cairo-coder-mcp', '@kasarlabs/cairo-coder-mcp', 2959, 'https://github.com/kasarlabs.png?size=128', '2026-03-09T05:21:02.011506+00:00'),
  ('starknet-agent-kit', 'Starknet Agent Kit', 'Snak is a toolkit for creating AI agents that interact with the Starknet blockchain, developed by Kasar Labs. The implementation provides both a ready-to-use NestJS server with web interface and an NPM package, supporting multiple AI providers including Anthropic, OpenAI, Google Gemini, and Ollama. It features a modular architecture with plugins for various DeFi operations, wallet management capabilities, and autonomous agent functionality, making it ideal for developers building blockchain-powered AI assistants that can execute transactions, monitor balances, and interact with smart contracts on Starknet.', '@kasarlabs', 'development', 'Unknown', 96, 'https://github.com/kasarlabs/snak/tree/HEAD/mcp/snak', NULL, 0, 'https://github.com/kasarlabs.png?size=128', '2026-03-09T05:21:02.011537+00:00'),
  ('energyatit', 'EnergyAtIt', 'Connect AI agents to energy infrastructure. Dispatch, attest carbon, read meters.', '@kasathur', 'development', 'Unknown', 0, 'https://github.com/kasathur/energyatit-mcp-server', NULL, 0, 'https://github.com/kasathur.png?size=128', '2026-03-09T05:21:02.011552+00:00'),
  ('vikingdb', 'VikingDB', 'This MCP server, developed by KashiwaByte, provides AI assistants like Claude with access to VikingDB for storing and searching information. It offers tools for introducing collections and indexes, upserting data, and performing searches within VikingDB. The server integrates seamlessly with Claude Desktop on both macOS and Windows, enabling AI-powered data management and retrieval. By bridging AI capabilities with VikingDB''s storage and search functionalities, this implementation facilitates efficient information organization and retrieval. It is particularly useful for scenarios requiring persistent data storage, quick information lookup, or generating insights from stored data in AI-assisted research, knowledge management, and decision-making applications.', '@kashiwabyte', 'databases', 'Unknown', 3, 'https://github.com/kashiwabyte/vikingdb-mcp-server', 'mcp-server-vikingdb', 4689, 'https://github.com/kashiwabyte.png?size=128', '2026-03-09T05:21:02.011562+00:00'),
  ('debug-adapter-protocol-dap', 'Debug Adapter Protocol (DAP)', 'dap-mcp is a server implementation that bridges debugging tools with AI systems through the Debug Adapter Protocol (DAP). It enables AI assistants to control debuggers, set breakpoints, step through code, evaluate expressions, and inspect variables - all through standardized MCP tools. The server supports multiple debugging backends (currently debugpy) and renders debugging information in XML format for easy consumption by LLMs, making it particularly valuable for AI-assisted debugging workflows where context about program state needs to be maintained throughout a conversation.', '@kashuncheng', 'development', 'Unknown', 34, 'https://github.com/kashuncheng/dap_mcp', 'dap-mcp', 5838, 'https://github.com/kashuncheng.png?size=128', '2026-03-09T05:21:02.011588+00:00'),
  ('kaspersky-threat-intelligence', 'Kaspersky Threat Intelligence', 'Multi-component threat intelligence repository by Kaspersky Lab containing three distinct tools: a Python-based OpenCTI connector that imports threat intelligence data from Kaspersky''s TAXII server at taxii.tip.kaspersky.com with STIX object transformation and relationship generation, a Go-based URL normalization utility for standardizing URLs by removing default ports and decoding parameters, and an OpenTIP MCP server that provides conversational access to Kaspersky''s threat intelligence platform. The OpenCTI connector analyzes STIX object descriptions to generate additional threat intelligence relationships and supports configurable data feeds, update intervals, and object expansion, while the MCP component enables AI assistants to query threat data through natural language interactions, serving security analysts, threat researchers, and SOC teams requiring programmatic access to Kaspersky''s commercial threat intelligence feeds.', '@kasperskylab', 'ai-ml', 'Unknown', 21, 'https://github.com/kasperskylab/threat-intelligence/tree/HEAD/opentip-mcp', NULL, 0, 'https://github.com/kasperskylab.png?size=128', '2026-03-09T05:21:02.011647+00:00'),
  ('thoughtbox', 'Thoughtbox', 'Thoughtbox is a successor to Waldzell AI''s Clear Thought that provides structured step-by-step reasoning capabilities through a clear_thought tool, enabling AI assistants to break down complex problems into manageable thoughts with support for revision, branching, and dynamic adjustment of reasoning paths. Built by glassBead at Kastalien Research with TypeScript and featuring both STDIO and HTTP transports via Smithery deployment, it supports multiple thinking approaches including forward thinking for exploration, backward thinking for goal-driven planning, and mixed/branched thinking for complex multi-faceted problems. The implementation includes a comprehensive notebook system for literate programming with JavaScript/TypeScript execution, making it useful for detailed analysis, planning and design workflows, problem-solving that requires course correction, and situations where maintaining context across multiple reasoning steps is critical.', '@kastalien-research', 'development', 'Unknown', 47, 'https://github.com/kastalien-research/thoughtbox', NULL, 0, 'https://github.com/kastalien-research.png?size=128', '2026-03-09T05:21:02.011682+00:00'),
  ('katalon-testops', 'Katalon TestOps', 'Integrates with Katalon TestOps to perform operations on test management objects directly from AI interfaces. Enables creating, updating, moving, duplicating, deleting, and searching test cases, test suites, requirements, sprints, and releases. Provides analytics tools for defect insights, requirement coverage, and test case execution metrics.', '@unknown', 'development', 'Unknown', 0, 'https://katalon.com/testops', NULL, 0, NULL, '2026-03-09T05:21:02.011706+00:00'),
  ('layout-detector', 'Layout Detector', 'Analyzes webpage screenshots to extract precise layout information using OpenCV template matching and computer vision algorithms. Given a screenshot and image assets, it locates each asset with pixel-perfect coordinates and automatically detects layout patterns including radial arrangements, grids, stacked sections, sidebar layouts, or freeform positioning. Returns structured data with spatial relationships, angles, distances, and semantic layout information that enables rebuilding layouts with modern CSS without manual measurement or trial-and-error positioning.', '@katlis', 'development', 'Unknown', 6, 'https://github.com/katlis/layout-detector-mcp', NULL, 0, 'https://github.com/katlis.png?size=128', '2026-03-09T05:21:02.011733+00:00'),
  ('simple-time', 'Simple Time', 'A lightweight MCP server that retrieves current date and time information. Supports three output formats: full (date and time), time only, or date only. Available via npm, npx, or Docker deployment.', '@katomato65', 'cloud', 'Unknown', 0, 'https://github.com/katomato65/timeservice-mcp', NULL, 0, 'https://github.com/katomato65.png?size=128', '2026-03-09T05:21:02.011749+00:00'),
  ('docker-gateway', 'Docker Gateway', 'A Docker CLI plugin that extends the Docker command line to manage MCP server discovery, deployment, and lifecycle. Provides catalog management for browsing and organizing servers, container-based deployment, credential and secret management with OAuth authentication support, and access control policy enforcement. Integrates with Claude Desktop, Cursor, VS Code, Zed, Kiro, and Continue.dev. Supports configuration backup and restoration and OCI registry compatibility for container images.', '@kawai-network', 'cloud', 'Unknown', 1, 'https://github.com/kawai-network/mcp-gateway', NULL, 0, 'https://github.com/kawai-network.png?size=128', '2026-03-09T05:21:02.011795+00:00'),
  ('markdown-editor', 'Markdown Editor', 'Provides structured, semantic editing capabilities for Markdown documents by parsing them into a structural tree of headings, paragraphs, lists, and code blocks. Enables precise operations like replacing specific paragraphs, moving entire sections, or inserting elements at exact locations using semantic paths (e.g., ''Introduction > paragraph 2''). Features include YAML frontmatter management, change journaling with undo functionality, contextual editing that preserves narrative flow, and file system operations for technical documentation and content management workflows.', '@kazkozdev', 'development', 'Unknown', 2, 'https://github.com/kazkozdev/markdown-editor-mcp-server', NULL, 0, 'https://github.com/kazkozdev.png?size=128', '2026-03-09T05:21:02.011821+00:00'),
  ('search', 'Search', 'Provides web search via DuckDuckGo with time filtering, Wikipedia article search and summaries, webpage content extraction using multiple parsing methods, and PDF text extraction. Includes timezone-aware datetime retrieval supporting 596+ timezones worldwide and IP-based geolocation with automatic timezone detection. Features parallel multi-source searching capabilities.', '@kazkozdev', 'search', 'Unknown', 4, 'https://github.com/kazkozdev/mcp-search-server', NULL, 0, 'https://github.com/kazkozdev.png?size=128', '2026-03-09T05:21:02.011867+00:00'),
  ('chrome-tabs', 'Chrome Tabs', 'This MCP server, developed by kazuph, enables retrieval and management of Chrome browser tabs information on macOS. It integrates with Claude Desktop and other MCP clients, allowing them to fetch data about and control open Chrome tabs using AppleScript. The implementation provides tools for getting all open tabs and closing specific tabs by window and tab indices. Its focus on browser tab management differentiates it from more general-purpose MCP implementations. This tool is particularly useful for AI assistants and automation scripts that need to interact with or analyze a user''s current browsing session.', '@kazuph', 'ai-ml', 'Unknown', 11, 'https://github.com/kazuph/mcp-browser-tabs', '@kazuph/mcp-browser-tabs', 4694, 'https://github.com/kazuph.png?size=128', '2026-03-09T05:21:02.011931+00:00'),
  ('devin', 'Devin', 'Integrates Devin AI with Slack to enable seamless collaboration between AI assistants and team communication. The server provides tools for creating Devin sessions that automatically post to Slack channels, maintaining thread context between Devin and Slack conversations, and managing sessions with enhanced Slack integration features. Built with TypeScript and the Slack Web API, it''s particularly valuable for teams who want to incorporate AI assistance directly into their existing Slack workflows while keeping conversations organized and contextual.', '@kazuph', 'development', 'Unknown', 7, 'https://github.com/kazuph/mcp-devin', NULL, 0, 'https://github.com/kazuph.png?size=128', '2026-03-09T05:21:02.011958+00:00'),
  ('docs-rag', 'Docs RAG', 'This MCP server implements a Retrieval-Augmented Generation (RAG) system for documents stored in a local directory, enabling AI assistants to query and interact with Git repositories and text files. Built with TypeScript and leveraging LlamaIndex with Google''s Gemini embeddings, it provides tools for listing documents, performing RAG queries against document collections, and adding new content through Git repository cloning or text file downloads. The server requires a Gemini API key for document indexing and querying, and is designed for integration with Claude Desktop, making it ideal for users who need to reference and analyze documentation, code repositories, or text collections during conversations with AI assistants.', '@kazuph', 'development', 'Unknown', 16, 'https://github.com/kazuph/mcp-docs-rag', NULL, 0, 'https://github.com/kazuph.png?size=128', '2026-03-09T05:21:02.011984+00:00'),
  ('fetch-with-images', 'Fetch with Images', 'This MCP server, developed by kazuph, enables web content fetching and image processing capabilities for AI assistants. It integrates with libraries like jsdom, Readability, and Sharp to extract readable content from web pages, convert HTML to Markdown, and process images for optimal viewing. The implementation handles robots.txt restrictions, merges multiple images vertically with size limits, and uses macOS clipboard operations for seamless image insertion. It''s designed for scenarios requiring web scraping, content summarization, or image handling within AI conversations, allowing assistants to fetch and process web content on demand while respecting web standards and optimizing for readability.', '@kazuph', 'ai-ml', 'Unknown', 39, 'https://github.com/kazuph/mcp-fetch', '@kazuph/mcp-fetch', 58144, 'https://github.com/kazuph.png?size=128', '2026-03-09T05:21:02.012030+00:00'),
  ('github-repo-extractor', 'GitHub Repo Extractor', 'This GitHub MCP server, developed by kazuph, connects GitHub code repositories to Claude.ai using the Pera1 service. It extracts code and context from GitHub repos to provide better information to Claude when discussing codebases. The implementation uses TypeScript and leverages the @modelcontextprotocol/sdk for MCP compatibility. It''s designed for developers and teams who want to seamlessly integrate GitHub discussions into their AI workflows, enabling natural language queries about code structure, dependencies, and development history directly through Claude''s interface.', '@kazuph', 'development', 'Unknown', 6, 'https://github.com/kazuph/mcp-github-pera1', '@kazuph/mcp-github-pera1', 5752, 'https://github.com/kazuph.png?size=128', '2026-03-09T05:21:02.012053+00:00'),
  ('macos-screenshot', 'macOS Screenshot', 'This MCP screenshot server, developed by kazuph, provides AI assistants with the ability to capture and analyze screen content on macOS. Built with TypeScript and leveraging libraries like Tesseract.js for OCR, it offers capabilities for taking screenshots of specific screen regions (left, right, or full) and performing text recognition on the captured images. The server integrates with the macOS system through AppleScript, automatically saving screenshots to dated folders in the user''s Downloads directory. It''s particularly useful for AI assistants focused on visual analysis, enabling use cases such as automated UI testing, content extraction from applications, and visual data processing in macOS environments.', '@kazuph', 'development', 'Unknown', 23, 'https://github.com/kazuph/mcp-screenshot', NULL, 0, 'https://github.com/kazuph.png?size=128', '2026-03-09T05:21:02.012111+00:00'),
  ('pocket', 'Pocket', 'This MCP server integrates with the Pocket API, allowing AI assistants to interact with users'' saved articles. Developed by kazuph, it enables fetching unread articles and marking them as read through natural language commands. The TypeScript implementation uses the Model Context Protocol SDK and Zod for robust type checking. It''s designed for Pocket users who want to incorporate AI assistance into their reading workflow, enabling tasks like summarizing saved articles, prioritizing reading lists, or analyzing reading habits through conversational interfaces.', '@kazuph', 'development', 'Unknown', 9, 'https://github.com/kazuph/mcp-pocket', '@kazuph/mcp-pocket', 4982, 'https://github.com/kazuph.png?size=128', '2026-03-09T05:21:02.012141+00:00'),
  ('taskmanager', 'TaskManager', 'The MCP TaskManager server enables Claude Desktop to manage and execute tasks in a queue-based system. Developed by kazuph, it provides a structured approach to task management with two main phases: planning (accepting task lists and storing them as a queue) and execution (retrieving, completing, and tracking tasks). The implementation uses Cloudflare Workers with KV storage for persistence and offers tools for creating task plans, tracking progress with visual tables, approving completions, and managing task lifecycles. This server is particularly useful for breaking down complex requests into manageable steps, maintaining context across conversations, and ensuring methodical completion of multi-step workflows.', '@rudra-ravi', 'cloud', 'Unknown', 7, 'https://github.com/rudra-ravi/mcp-taskmanager', NULL, 0, 'https://github.com/rudra-ravi.png?size=128', '2026-03-09T05:21:02.012190+00:00'),
  ('youtube-subtitles', 'YouTube Subtitles', 'This MCP server, developed by kazuph, uses yt-dlp to download subtitles from YouTube videos and connects them to claude.ai via the Model Context Protocol. It supports multiple languages and allows for flexible subtitle retrieval based on user-specified language codes. The implementation is designed for easy integration into Node.js projects and can be run using npx. It''s particularly useful for developers looking to incorporate YouTube content analysis or transcription capabilities into their AI-powered applications, enabling natural language queries about video content through Claude.', '@kazuph', 'development', 'Unknown', 4, 'https://github.com/kazuph/mcp-youtube', '@kazuph/mcp-youtube', 5528, 'https://github.com/kazuph.png?size=128', '2026-03-09T05:21:02.012214+00:00'),
  ('google-spreadsheet', 'Google Spreadsheet', 'MCP Google Spreadsheet provides a bridge between AI assistants and Google Drive/Sheets, enabling comprehensive document management capabilities. Developed by Kazuki Akamine, this Go-based server implements tools for listing, copying, and renaming files in Google Drive, as well as manipulating Google Sheets through operations like listing sheets, retrieving data, adding rows/columns, and updating cells. The implementation handles Google authentication and uses the metoro-io/mcp-golang library to expose these capabilities through a standardized interface. It''s particularly useful for workflows requiring document automation, data extraction, or spreadsheet manipulation directly from AI conversations without switching contexts.', '@kazz187', 'ai-ml', 'Unknown', 44, 'https://github.com/kazz187/mcp-google-spreadsheet', NULL, 0, 'https://github.com/kazz187.png?size=128', '2026-03-09T05:21:02.012261+00:00'),
  ('playwright-lighthouse', 'Playwright-Lighthouse', 'Playwright-Lighthouse MCP server enables Claude to analyze website performance by combining Playwright''s browser automation with Lighthouse''s auditing capabilities. Built with TypeScript, it offers two main tools: ''run-lighthouse'' for comprehensive performance analysis across multiple categories (performance, accessibility, SEO, etc.) with detailed improvement recommendations, and ''take-screenshot'' for capturing full or partial webpage images. The server automatically handles browser sessions, generates performance reports with color-coded scores, and saves outputs to local directories, making it valuable for web developers seeking to identify and address performance bottlenecks directly within Claude conversations.', '@kbyk004-diy', 'development', 'Unknown', 5, 'https://github.com/kbyk004-diy/playwright-lighthouse-mcp', NULL, 0, 'https://github.com/kbyk004-diy.png?size=128', '2026-03-09T05:21:02.012290+00:00'),
  ('pmwiki', 'PmWiki', 'Enables interaction with PmWiki instances through full-text search across all wiki pages with case-sensitive and case-insensitive options. List all pages or filter by group, and read complete page contents with context snippets. Designed for Docker deployment with read-only wiki directory mounting.', '@kcofoni', 'cloud', 'Unknown', 0, 'https://github.com/kcofoni/pmwiki-mcp', NULL, 0, 'https://github.com/kcofoni.png?size=128', '2026-03-09T05:21:02.012309+00:00'),
  ('claude-skills', 'Claude Skills', 'A vector search-powered MCP server built by K-Dense AI that enables Claude to discover and retrieve relevant Agent Skills from GitHub repositories and local directories using semantic similarity. The server indexes skill descriptions with sentence transformers, performs RAG-based search to find the most relevant skills for specific tasks, and includes document loading capabilities for accessing Python scripts, references, and assets within skills. Designed primarily for scientific computing workflows, it comes pre-configured with 70+ bioinformatics, cheminformatics, and data analysis skills from K-Dense AI''s scientific skills repository, plus official Anthropic skills, making it useful for researchers and developers who need contextual guidance on specialized technical tasks and proven implementation patterns.', '@k-dense-ai', 'development', 'Unknown', 339, 'https://github.com/k-dense-ai/claude-skills-mcp', 'claude-skills-mcp', 10683, 'https://github.com/k-dense-ai.png?size=128', '2026-03-09T05:21:02.012337+00:00'),
  ('observium-ce', 'Observium CE', 'Provides read-only access to Observium CE network monitoring data through a comprehensive set of tools for querying device status, network port traffic, sensor readings, alerts, and historical trends. Supports both local and remote deployments via SSH tunneling for database access and RRD file retrieval, enabling natural language queries about network infrastructure health, performance metrics, and alert conditions. Built to bridge network monitoring data with LLM interactions, making it easy to ask questions about device status, CPU trends, or alert conditions without needing direct database or RRD tool knowledge.', '@kdesch5000', 'databases', 'Unknown', 2, 'https://github.com/kdesch5000/observium-mcp', NULL, 0, 'https://github.com/kdesch5000.png?size=128', '2026-03-09T05:21:02.012349+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('local-skills', 'Local Skills', 'Universal MCP server enabling any LLM or AI agent to utilize expert skills from your local filesystem. Skills are structured prompts written once and reused across Claude Code, Claude Desktop, Cline, Continue.dev, or any MCP-compatible client. Features lazy loading (only ~50 tokens per skill initially), hot reload for instant updates, and multi-directory skill aggregation. Skills use portable SKILL.md format with YAML frontmatter.', '@kdpa-llc', 'development', 'Unknown', 20, 'https://github.com/kdpa-llc/local-skills-mcp', NULL, 0, 'https://github.com/kdpa-llc.png?size=128', '2026-03-09T05:21:02.012418+00:00'),
  ('zaturn-sql-data-analysis', 'Zaturn (SQL Data Analysis)', 'Zaturn is an AI-powered data analysis MCP server that connects to various data sources (PostgreSQL, SQLite, DuckDB, MySQL, CSV, Parquet) and enables SQL querying with visualization capabilities. Developed by Karthik Devan, it keeps data in its original location while allowing AI to draft and run SQL queries, processing only the results rather than entire datasets. The server includes tools for data source management, query execution, and multiple visualization types (scatter plots, histograms, bar charts), making it ideal for business intelligence tasks and data exploration without requiring the upload of complete datasets to AI systems.', '@kdqed', 'databases', 'Unknown', 73, 'https://github.com/kdqed/zaturn', 'zaturn', 8300, 'https://github.com/kdqed.png?size=128', '2026-03-09T05:21:02.012431+00:00'),
  ('keboola', 'Keboola', 'This Keboola Explorer MCP server, developed by Jordan Burger, provides a bridge between AI assistants and the Keboola Connection platform. Built with Python and leveraging libraries like httpx and pandas, it offers tools for exploring and managing Keboola projects, including bucket and table operations, component configurations, and data previews. The implementation focuses on simplifying interactions with Keboola''s Storage API, making it accessible for AI models to query and analyze data stored in Keboola. It''s particularly useful for tasks like data exploration, project management, and automated reporting, enabling AI assistants to access and manipulate data in Keboola without requiring deep knowledge of the underlying API complexities.', '@keboola', 'databases', 'Unknown', 82, 'https://github.com/keboola/mcp-server', NULL, 0, 'https://github.com/keboola.png?size=128', '2026-03-09T05:21:02.012481+00:00'),
  ('linear-issues', 'Linear Issues', 'The Linear Issues MCP server provides AI assistants with read-only access to Linear issue tracking data through a Node.js implementation. Developed by Keegan Carruthers-Smith, this server exposes two tools: one for fetching basic issue details and another for retrieving complete information including comments. It authenticates with the Linear GraphQL API using either an API key or OAuth token, parses issue identifiers from URLs or direct references, and formats responses in a consistent structure. This implementation is particularly valuable for teams using Linear who want their AI assistants to access project tracking information without switching contexts.', '@keegancsmith', 'productivity', 'Unknown', 1, 'https://github.com/keegancsmith/linear-issues-mcp-server', '@keegancsmith/linear-issues-mcp-server', 4519, 'https://github.com/keegancsmith.png?size=128', '2026-03-09T05:21:02.012532+00:00'),
  ('io-github-techops-services-keeperhub-mcp', 'io.github.techops-services/keeperhub-mcp', 'MCP server for KeeperHub blockchain workflow automation', '@techops-services', 'development', 'Unknown', 0, 'https://github.com/techops-services/keeperhub-mcp', NULL, 0, 'https://github.com/techops-services.png?size=128', '2026-03-09T05:21:02.012552+00:00'),
  ('keeper-secrets-manager', 'Keeper Secrets Manager', 'KSM MCP server by Keeper Security provides AI assistants with secure access to Keeper Secrets Manager through a protective intermediary layer that prevents direct credential exposure while maintaining full secret management capabilities. Built in Go with Docker support and comprehensive CLI tooling, the implementation offers complete CRUD operations for secrets and folders, file attachment management, password generation, TOTP code retrieval, and advanced features like KSM notation parsing and record template schema generation for different secret types. The server uses a confirmation-based security model where sensitive operations require user approval, supports both profile-based encrypted local storage and direct base64 configuration for different deployment scenarios, and includes audit logging and rate limiting, making it ideal for AI-powered workflows that need programmatic access to enterprise secrets while maintaining security controls and compliance requirements.', '@keeper-security', 'cloud', 'Unknown', 6, 'https://github.com/keeper-security/keeper-mcp-golang-docker', NULL, 0, 'https://github.com/keeper-security.png?size=128', '2026-03-09T05:21:02.012583+00:00'),
  ('json-filter', 'JSON Filter', 'A TypeScript-based MCP server that provides JSON schema generation and filtering tools using quicktype-core to convert JSON samples into TypeScript type definitions and extract specific fields from large JSON files. Built by kehvinbehvin, it addresses the common problem of including unwanted data from large JSON files in LLM context by offering shape-based filtering that allows users to specify exactly which fields to extract using a simple object notation. The server integrates seamlessly with Claude Desktop and Claude Code, making it particularly valuable for developers working with APIs, data analysis, or any workflow involving large JSON datasets where selective data extraction is needed.', '@kehvinbehvin', 'development', 'Unknown', 22, 'https://github.com/kehvinbehvin/json-mcp-filter', NULL, 0, 'https://github.com/kehvinbehvin.png?size=128', '2026-03-09T05:21:02.012613+00:00'),
  ('json-schema-generator-filter', 'JSON Schema Generator & Filter', 'JSON MCP server built by kehvinbehvin that provides TypeScript schema generation and filtering tools for JSON data using quicktype, supporting both local files and HTTP/HTTPS URLs through a strategy pattern architecture. The implementation offers three core tools: json_schema for generating TypeScript interfaces from JSON data, json_filter for extracting specific fields using shape objects with automatic chunking for large responses, and json_dry_run for analyzing data size breakdowns before filtering. Built with comprehensive error handling for network issues, authentication requirements, and content validation, plus size limits and chunking capabilities for handling large JSON files up to 50MB, it serves developers needing programmatic JSON analysis, data extraction workflows, and schema generation for API integration tasks.', '@unknown', 'development', 'Unknown', 0, 'https://www.pulsemcp.com/servers/kehvinbehvin-json-schema-filter', 'json-mcp-filter', 1107, NULL, '2026-03-09T05:21:02.012649+00:00'),
  ('yamu-unity-editor', 'Yamu (Unity Editor)', 'This MCP server enables AI coding agents to autonomously iterate through edit-compile-debug cycles in Unity development by providing compilation feedback mechanisms through a C# HTTP server running in the Unity Editor and a Node.js MCP bridge. Built by Keijiro Takahashi as a proof-of-concept for macOS, it offers two core tools: compile_and_wait which triggers Unity Editor compilation and waits for completion, and get_errors which retrieves compilation errors from the last build. The implementation features real-time compilation status monitoring, error collection with file/line details, and polling-based completion detection, making it valuable for AI agents that need to write Unity C# code, test compilation results, and automatically fix errors without manual Unity Editor interaction.', '@keijiro', 'development', 'Unknown', 31, 'https://github.com/keijiro/yamu', NULL, 0, 'https://github.com/keijiro.png?size=128', '2026-03-09T05:21:02.012679+00:00'),
  ('ferreteria-angular', 'Ferreteria Angular', 'Provides tools for querying hardware store (ferreteria) management data through a .NET backend API. Supports retrieving product inventory, looking up individual products by ID, listing orders, fetching order details, and viewing sales history. Built as part of a full-stack Angular/.NET hardware store management system with the MCP server acting as the AI integration layer.', '@keiner-2006', 'ai-ml', 'Unknown', 1, 'https://github.com/keiner-2006/proyectoferreteria-angular/tree/HEAD/mcp-server', NULL, 0, 'https://github.com/keiner-2006.png?size=128', '2026-03-09T05:21:02.012714+00:00'),
  ('popui', 'PopUI', 'PopUI is a companion desktop app that creates a bi-directional bridge between Claude Desktop and visual interfaces. It enables Claude to create, display, and interact with user interfaces through a specialized MCP server, allowing both Claude and users to manipulate a shared visual context in real-time. The implementation leverages Electron to render React components dynamically, supports Tailwind CSS for styling, and includes features for sending messages back to Claude, making it particularly valuable for collaborative experiences like control panels, games, visualization tools, and other interactive interfaces where visual context enhances the conversation.', '@kelnishi', 'ai-ml', 'Unknown', 9, 'https://github.com/kelnishi/popui', 'popui', 1986, 'https://github.com/kelnishi.png?size=128', '2026-03-09T05:21:02.012761+00:00'),
  ('devdocsmcp', 'DevDocsMCP', 'DevDocsMCP provides direct access to DevDocs.io documentation through search and content retrieval tools, enabling AI assistants to query and read technical documentation for various programming languages and frameworks like HTML, CSS, AngularJS, Go, MySQL, and more. The server operates entirely online by fetching data from DevDocs.io''s API endpoints in real-time, supporting both fuzzy and exact search queries across documentation entries and returning full HTML content for specific documentation pages. Built with Go and featuring language-specific server configurations, it''s particularly useful for developers who need quick access to API references, syntax guides, and technical documentation during coding workflows without leaving their development environment.', '@kelvinzer0', 'databases', 'Unknown', 4, 'https://github.com/kelvinzer0/devdocsmcp', NULL, 0, 'https://github.com/kelvinzer0.png?size=128', '2026-03-09T05:21:02.012842+00:00'),
  ('palettemcp', 'PaletteMCP', 'PaletteMCP is a color utility MCP server that converts hexadecimal color codes to their closest matching CSS color names using Euclidean distance calculations in RGB space. Built in Go by kelvinzer0, it provides both command-line functionality and MCP server capabilities with support for stdio, HTTP, and SSE transports, making it useful for design workflows, web development tasks, or any application where converting hex codes to human-readable color names is needed. The implementation includes a comprehensive database of 140+ standard CSS colors and outputs results in JSON format for easy integration with other tools and systems.', '@kelvinzer0', 'databases', 'Unknown', 0, 'https://github.com/kelvinzer0/palettemcp', NULL, 0, 'https://github.com/kelvinzer0.png?size=128', '2026-03-09T05:21:02.012868+00:00'),
  ('fonparam', 'FonParam', 'FonParam MCP provides AI assistants with access to Turkish mutual funds data through the FonParam API, enabling comprehensive financial analysis and investment research for the Turkish market. Built by Kemal Ersin YILMAZ using TypeScript and the Model Context Protocol SDK, it integrates with FonParam''s financial data service to deliver real-time fund information, performance metrics, and market insights. The implementation uses Axios for HTTP requests and Zod for data validation, making it valuable for financial advisors, investment researchers, and AI applications that need to analyze Turkish mutual fund markets, compare fund performance, or provide investment recommendations specific to Turkey''s financial ecosystem.', '@kemalersin', 'development', 'Unknown', 3, 'https://github.com/kemalersin/fonparam-mcp', 'fonparam-mcp', 707, 'https://github.com/kemalersin.png?size=128', '2026-03-09T05:21:02.012899+00:00'),
  ('python-dependency-manager-companion', 'Python Dependency Manager Companion', 'This Python dependency manager companion MCP server appears to be designed to assist with Python package management workflows, though the repository is currently inaccessible or may not exist. Based on the naming convention, it would likely provide tools for managing Python dependencies, package installations, virtual environments, and related development tasks through AI assistant interactions. The implementation would be particularly useful for developers who want to streamline their Python project setup and dependency management processes through natural language commands rather than manual pip or conda operations.', '@keminghe', 'development', 'Unknown', 41, 'https://github.com/keminghe/python-dependency-manager-companion-mcp-server', NULL, 0, 'https://github.com/keminghe.png?size=128', '2026-03-09T05:21:02.012927+00:00'),
  ('docker-container-execution', 'Docker Container Execution', 'This MCP server provides Docker container execution capabilities with intelligent process management and file operations, built by kenforthewin using TypeScript with a Debian-based container pre-configured with Node.js and Playwright. The implementation offers command execution with smart timeout handling based on output activity rather than fixed intervals, background process tracking with unique IDs for long-running tasks, interactive process input capabilities, and comprehensive file operations including reading, writing, editing, directory listing, and content searching. Features include automatic process backgrounding after inactivity periods, persistent container state with mounted file storage, safety mechanisms requiring file reads before edits, and support for both immediate and background command execution patterns, making it valuable for developers who need programmatic access to containerized development environments, automated testing workflows, or AI-assisted development tasks that require isolated execution contexts.', '@kenforthewin', 'cloud', 'Unknown', 6, 'https://github.com/kenforthewin/docker-mcp-server', 'docker-mcp-server', 1700, 'https://github.com/kenforthewin.png?size=128', '2026-03-09T05:21:02.012977+00:00'),
  ('kenji-game-engine', 'Kenji Game Engine', 'Kenji Engine MCP server that provides AI assistants with access to a modern TypeScript game engine featuring Entity Component System architecture, 2D Canvas rendering, pixel art generation, and itch.io deployment capabilities. Built by moikas-code, the implementation includes comprehensive game development tools through MCP integration: project scaffolding and management, asset generation for classic games like Pong and Breakout, build system automation, and Butler-based deployment pipelines for web games. The server integrates with a terminal-based visual editor using OpenTUI, supports real-time game preview and debugging, and includes pre-built systems for collision detection, input handling, audio management, and UI components, making it valuable for developers who want conversational assistance with rapid game prototyping, asset creation, and deployment workflows for browser-based arcade games.', '@moikas-code', 'development', 'Unknown', 2, 'https://github.com/moikas-code/kenji-engine', NULL, 0, 'https://github.com/moikas-code.png?size=128', '2026-03-09T05:21:02.013009+00:00'),
  ('rabbitmq', 'RabbitMQ', 'This RabbitMQ MCP server, developed by Ken Liao, enables AI assistants to interact with RabbitMQ message queues through the Model Context Protocol. Built in Python, it provides a bridge between MCP clients and RabbitMQ instances, allowing operations like publishing and consuming messages. The implementation leverages libraries such as Pika for RabbitMQ communication and supports TLS for secure connections. By abstracting queue operations into MCP-compatible endpoints, it allows AI systems to easily integrate messaging capabilities without directly handling RabbitMQ complexities. This server is particularly useful for scenarios requiring AI-driven message processing, event-driven architectures, or automated workflow management in distributed systems.', '@kenliao94', 'communication', 'Unknown', 39, 'https://github.com/kenliao94/mcp-server-rabbitmq', NULL, 0, 'https://github.com/kenliao94.png?size=128', '2026-03-09T05:21:02.013073+00:00'),
  ('hong-kong-bus', 'Hong Kong Bus', 'KMB Bus MCP Server provides real-time access to Hong Kong''s Kowloon Motor Bus information through a set of specialized tools. The implementation connects to the official KMB API to retrieve bus routes, stops, and estimated arrival times, offering functions to find buses by destination, locate stops by name, get route details, and check next bus arrivals. Built with Python using FastMCP, it includes intelligent caching to minimize redundant API calls and comprehensive error handling for reliable operation. Ideal for Hong Kong residents and visitors who want to query public transportation information through conversational AI.', '@kennyckk', 'ai-ml', 'Unknown', 3, 'https://github.com/kennyckk/mcp_hkbus', NULL, 0, 'https://github.com/kennyckk.png?size=128', '2026-03-09T05:21:02.013163+00:00'),
  ('playwright-rag-automation', 'Playwright RAG Automation', 'Generates TypeScript Playwright automation code by combining vector database search with intelligent query routing to classify requests and provide context-aware responses using ChromaDB document retrieval.', '@kennyhuynh', 'databases', 'Unknown', 1, 'https://github.com/kennyhuynh/mcp_rag_llm', NULL, 0, 'https://github.com/kennyhuynh.png?size=128', '2026-03-09T05:21:02.013179+00:00'),
  ('codecortx', 'CodeCortX', 'CodeCortX is a high-performance code analysis server built in Rust by Kenneth J. Sanchez that delivers deep code understanding capabilities across 15+ programming languages including Rust, Python, TypeScript, Java, Go, and C++. Using Tree-sitter for parsing and BM25 for semantic search, it offers real-time symbol extraction, file watching with automatic re-indexing, and memory-efficient caching with LRU eviction. The implementation prioritizes performance with concurrent processing, smart memory management, and sub-millisecond symbol lookups, making it valuable for understanding large codebases, providing intelligent code suggestions, performing cross-language analysis, and assisting with code navigation and refactoring tasks.', '@kensave', 'development', 'Unknown', 7, 'https://github.com/kensave/roberto-mcp', NULL, 0, 'https://github.com/kensave.png?size=128', '2026-03-09T05:21:02.013206+00:00'),
  ('aivisspeech', 'AivisSpeech', 'AivisSpeech MCP Server provides a bridge between AI assistants and text-to-speech capabilities through the AivisSpeech API. This implementation enables AI agents to generate and play speech audio from text input, with configurable speaker settings. The server exposes the speech synthesis functionality as MCP tools that can be called programmatically, making it valuable for applications requiring voice output such as accessibility tools, language learning, or interactive voice assistants.', '@kentaro', 'ai-ml', 'Unknown', 1, 'https://github.com/kentaro/aivis-speech-mcp', NULL, 0, 'https://github.com/kentaro.png?size=128', '2026-03-09T05:21:02.013245+00:00'),
  ('cloudflare-edge-calculator', 'Cloudflare Edge Calculator', 'A Cloudflare Workers-based MCP server that demonstrates running Model Context Protocol on edge infrastructure with Durable Objects for state management. Built with Remix 3''s experimental DOM and events packages, it provides a calculator tool through the MathMCP Durable Object and includes a React-based calculator widget that can be embedded in web applications. The implementation showcases how to deploy MCP servers to Cloudflare''s global edge network using Vite for building, TypeScript for type safety, and Wrangler for deployment, making it useful for developers who want to run MCP servers with low latency worldwide or integrate MCP capabilities into existing Cloudflare Workers applications.', '@kentcdodds', 'cloud', 'Unknown', 44, 'https://github.com/kentcdodds/cloudflare-remix-vite-mcp', NULL, 0, 'https://github.com/kentcdodds.png?size=128', '2026-03-09T05:21:02.013266+00:00'),
  ('graphdb', 'GraphDB', 'GraphDB MCP Server provides read-only access to Ontotext GraphDB repositories, enabling LLMs to explore RDF graphs and execute SPARQL queries. The server exposes tools for running SPARQL queries and listing graphs, along with resources that provide structured views of repository data including class lists, predicates, statistics, and sample data. Built with TypeScript using the Model Context Protocol SDK, it supports authentication, custom query formats, and graph-specific operations, making it particularly valuable for AI assistants that need to analyze semantic data stored in RDF triple stores without switching contexts.', '@keonchennl', 'development', 'Unknown', 13, 'https://github.com/keonchennl/mcp-graphdb', NULL, 0, 'https://github.com/keonchennl.png?size=128', '2026-03-09T05:21:02.013298+00:00'),
  ('kernel-platform', 'Kernel Platform', 'This MCP server provides AI assistants with comprehensive access to the Kernel platform''s cloud deployment and browser automation capabilities, built by the Kernel team using Next.js with OAuth2 authentication through Clerk and Redis session management. The implementation offers automated app deployment with intelligent dependency resolution for TypeScript and Python projects, browser session management with stealth and recording capabilities, action invocation with real-time streaming, and integrated documentation search through Mintlify API, all featuring automatic project file generation, ZIP-based deployment packaging, and OAuth-secured API access with organization-scoped permissions. Built with dynamic client registration, PKCE-secured authorization flows, comprehensive error handling across deployment and browser operations, and real-time event streaming for deployment monitoring, it serves developers needing conversational access to cloud deployment workflows, automation engineers requiring AI-driven browser control for testing and scraping, and development teams where natural language interfaces enhance productivity for app deployment and browser automation without direct platform API knowledge.', '@kernel', 'databases', 'Unknown', 27, 'https://github.com/kernel/kernel-mcp-server', NULL, 0, 'https://github.com/kernel.png?size=128', '2026-03-09T05:21:02.013317+00:00'),
  ('kestra', 'Kestra', 'This Kestra MCP server by kestra-io provides AI assistants with comprehensive workflow orchestration capabilities through the Kestra platform, enabling natural language interaction with data pipelines, microservices, and automation workflows. The implementation exposes extensive functionality including flow creation and management, execution control (start, pause, resume, restart, replay), namespace and file operations, KV store management, backfill operations, and enterprise features like user management and worker groups. Built with Python using FastMCP and httpx, it includes both Google ADK and OpenAI agent integrations, AI-powered code generation using Gemini models, and Docker containerization, making it valuable for data engineers and DevOps teams who need to manage complex orchestration workflows through conversational interfaces without directly accessing the Kestra UI.', '@kestra-io', 'cloud', 'Unknown', 21, 'https://github.com/kestra-io/mcp-server-python', NULL, 0, 'https://github.com/kestra-io.png?size=128', '2026-03-09T05:21:02.013386+00:00'),
  ('weather-alerts-forecasts', 'Weather Alerts & Forecasts', 'This weather MCP implementation, built with Python, provides a simple interface for retrieving weather data. It leverages the httpx library for efficient HTTP requests and integrates with the MCP CLI for easy command-line usage. The project structure includes test files and development requirements, indicating a focus on code quality and maintainability. While the specific weather API is not evident, the implementation offers a straightforward approach to accessing weather information, making it suitable for AI assistants, chatbots, or applications needing to incorporate weather data into their workflows.', '@kevinlin', 'development', 'Unknown', 0, 'https://github.com/kevinlin/mcp-server-weather', NULL, 0, 'https://github.com/kevinlin.png?size=128', '2026-03-09T05:21:02.013491+00:00'),
  ('fedramp-20x', 'FedRAMP 20x', 'Provides access to FedRAMP 20x security requirements and controls with emphasis on Azure-native implementations. Offers querying across 199 FedRAMP Requirements and 72 Key Security Indicators, code analysis across multiple languages using AST parsing, pattern-based compliance detection with 381 YAML patterns, evidence automation guidance for Azure services, and infrastructure template generation for Bicep and Terraform.', '@kevinrabun', 'cloud', 'Unknown', 3, 'https://github.com/kevinrabun/fedramp20xmcp', NULL, 0, 'https://github.com/kevinrabun.png?size=128', '2026-03-09T05:21:02.013507+00:00'),
  ('gdpr-shift-left-compliance', 'GDPR Shift-Left Compliance', 'Embeds GDPR compliance knowledge directly into development workflows. Provides tools for GDPR article and recital lookup, Data Protection Impact Assessment evaluation using EDPB criteria, Records of Processing Activities generation per Article 30, and data subject rights guidance covering Articles 12-23. Includes infrastructure-as-code analysis for Bicep, Terraform, and ARM templates, application code scanning for PII logging and consent gaps, cross-border transfer detection, and breach readiness assessment. Ships with 19 GDPR-aligned Azure Bicep templates for common cloud resources.', '@kevinrabun', 'cloud', 'Unknown', 2, 'https://github.com/kevinrabun/gdprshiftleftmcp', NULL, 0, 'https://github.com/kevinrabun.png?size=128', '2026-03-09T05:21:02.013526+00:00'),
  ('afl', 'AFL++', 'Provides comprehensive fuzzing capabilities through the AFL++ framework. Offers tools for workspace management, instrumented binary compilation with various sanitizers and coverage modes, corpus management and minimization, fuzzing campaign orchestration across multiple instances, and crash analysis with triage reporting. Supports multiple build systems including Make, CMake, and Cargo, with strict path validation for security. Designed for security researchers integrating systematic fuzz testing into vulnerability discovery workflows.', '@kevin-valerio', 'development', 'Unknown', 3, 'https://github.com/kevin-valerio/aflpp-mcp', NULL, 0, 'https://github.com/kevin-valerio.png?size=128', '2026-03-09T05:21:02.013552+00:00'),
  ('ffmpeg-lite', 'FFmpeg Lite', 'This MCP server provides video and audio processing capabilities through FFmpeg, offering tools for media manipulation including format conversion, compression, trimming, audio extraction, file merging, frame extraction, subtitle addition, and metadata retrieval. Built using Python and the FastMCP framework, it handles common video editing tasks through simple function calls while managing file paths, output directories, and FFmpeg command execution automatically.', '@kevinwatt', 'productivity', 'Unknown', 22, 'https://github.com/kevinwatt/ffmpeg-mcp-lite', NULL, 0, 'https://github.com/kevinwatt.png?size=128', '2026-03-09T05:21:02.013588+00:00'),
  ('searxng-meta-search', 'SearXNG Meta Search', 'This MCP server, developed by Kevin Watt, integrates SearXNG''s meta-search capabilities into AI workflows. Built with TypeScript and leveraging the Model Context Protocol SDK, it provides a privacy-focused search interface that combines results from multiple engines. The implementation offers features like multi-category searches, language filtering, time range selection, and adjustable safe search levels. By connecting AI models with SearXNG''s robust search functionality, this server enables sophisticated information retrieval scenarios such as multi-source research, trend analysis, and content aggregation. It''s particularly valuable for applications requiring privacy-conscious, diverse, and customizable search results, making it ideal for research tools, content curation systems, and privacy-oriented AI assistants.', '@kevinwatt', 'development', 'Unknown', 27, 'https://github.com/kevinwatt/mcp-server-searxng', '@kevinwatt/mcp-server-searxng', 10983, 'https://github.com/kevinwatt.png?size=128', '2026-03-09T05:21:02.013632+00:00'),
  ('shell-command-executor', 'Shell Command Executor', 'This MCP server implementation provides a shell command execution interface, allowing AI models to interact with the local system through a standardized protocol. Developed by Kevin Watt, it leverages the @modelcontextprotocol/sdk to enable secure and controlled access to shell operations. The implementation is designed for automation tasks, system management, and scenarios where AI assistants need to perform local machine operations. It stands out by focusing on shell interactions, making it particularly useful for DevOps, system administration, and automated workflow applications.', '@kevinwatt', 'productivity', 'Unknown', 6, 'https://github.com/kevinwatt/shell-mcp', '@kevinwatt/shell-mcp', 9647, 'https://github.com/kevinwatt.png?size=128', '2026-03-09T05:21:02.013671+00:00'),
  ('webhooks', 'Webhooks', 'This MCP webhook server, developed by kevinwatt, enables AI agents to send messages to external webhook endpoints. Built with TypeScript and leveraging the Model Context Protocol SDK, it provides a simple interface for posting customizable messages. The implementation focuses on flexibility, allowing users to specify content, username, and avatar for each message. It''s particularly useful for integrating AI-driven notifications into existing workflows, enabling use cases such as automated alerts, chat integrations, and system notifications without directly dealing with webhook API complexities. The server''s design emphasizes ease of configuration and deployment, making it suitable for both development and production environments.', '@kevinwatt', 'development', 'Unknown', 25, 'https://github.com/kevinwatt/mcp-webhook', '@kevinwatt/mcp-webhook', 6172, 'https://github.com/kevinwatt.png?size=128', '2026-03-09T05:21:02.013700+00:00'),
  ('youtube-downloader', 'YouTube Downloader', 'This MCP server, developed by Dewei Yen, provides a bridge between AI models and YouTube content through the yt-dlp tool. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers capabilities for downloading YouTube subtitles and videos. The implementation focuses on simplifying access to YouTube content for AI processing, enabling use cases such as video summarization and content analysis. By connecting AI models with YouTube data, this server allows for sophisticated scenarios like automated video transcription, content curation, and language processing of video subtitles. It''s particularly useful for applications and AI assistants that require programmatic access to YouTube content through a standardized MCP interface.', '@kevinwatt', 'development', 'Unknown', 222, 'https://github.com/kevinwatt/yt-dlp-mcp', '@kevinwatt/yt-dlp-mcp', 9564, 'https://github.com/kevinwatt.png?size=128', '2026-03-09T05:21:02.013734+00:00'),
  ('linkedin-posts-hunter', 'LinkedIn Posts Hunter', 'LinkedIn Posts Hunter MCP provides AI-powered LinkedIn job post search and tracking through Playwright browser automation with persistent authentication, local SQLite storage, and a React dashboard interface. Built by Kevin Weitgenant, it automates LinkedIn post scraping with configurable pagination and concurrency, stores all data locally for complete privacy, and offers dual control through natural language AI commands or a modern web UI with advanced filtering by keywords, application status, dates, and post IDs. The implementation features automatic authentication detection, concurrent post processing with metadata extraction (author details, engagement metrics, timestamps), and a responsive dashboard with both table and card views that auto-polls for updates, making it valuable for job seekers who want to systematically track and manage LinkedIn opportunities without relying on external services.', '@kevin-weitgenant', 'databases', 'Unknown', 6, 'https://github.com/kevin-weitgenant/linkedin-posts-hunter-mcp-server', 'linkedin-posts-hunter-mcp', 463, 'https://github.com/kevin-weitgenant.png?size=128', '2026-03-09T05:21:02.013747+00:00'),
  ('fugle-masterlink-taiwan-stock-market', 'Fugle Masterlink (Taiwan Stock Market)', 'Fugle MCP Server provides a bridge between AI assistants and the Masterlink SDK for Taiwan stock market trading and data access. The server exposes tools for account management, market data retrieval (including historical, intraday, and snapshot data), and trade execution capabilities like placing orders, checking balances, and viewing trade history. Built with TypeScript and containerized with Docker, it requires authentication via environment variables for secure access to trading accounts, making it valuable for financial analysis, automated trading strategies, and portfolio management applications.', '@fugle-dev', 'cloud', 'Unknown', 9, 'https://github.com/fugle-dev/fugle-mcp-server', NULL, 0, 'https://github.com/fugle-dev.png?size=128', '2026-03-09T05:21:02.013771+00:00'),
  ('kevodb', 'KevoDB', 'KevoDB MCP Server provides a standardized interface for AI agents to interact with KevoDB, a key-value database system. Developed by KevoDB, it exposes core database operations including key-value operations, range/prefix/suffix scans, transactions, and batch operations through MCP tools. The server connects to a running KevoDB instance (configurable via environment variables) and handles UTF-8 encoding/decoding of data, making it accessible through a simple string-based API. This implementation is particularly valuable for AI applications that need persistent storage with transaction support, enabling agents to read, write, and query structured data without direct database integration.', '@kevodb', 'databases', 'Unknown', 1, 'https://github.com/kevodb/kevo-mcp', NULL, 0, 'https://github.com/kevodb.png?size=128', '2026-03-09T05:21:02.013782+00:00'),
  ('keyfactor-command', 'Keyfactor Command', 'This Keyfactor Command MCP server provides AI assistants with direct access to enterprise certificate lifecycle management operations through the Keyfactor Command platform, a PKI automation system that integrates with various Certificate Authorities and enterprise tools. The implementation exposes core CLM functions including certificate enrollment (both CSR-based and PFX generation), certificate revocation, and advanced certificate search capabilities with support for complex query syntax, making it particularly valuable for PKI administrators who need natural language access to certificate operations. A key differentiator is the integration with Keyfactor''s Risk Intelligence component, which provides proprietary risk scoring and security findings for certificates that the server combines with AI-powered risk assessment, enabling comprehensive security analysis that blends automated risk detection with intelligent interpretation of PKI vulnerabilities and policy compliance issues.', '@keyfactor-research', 'ai-ml', 'Unknown', 5, 'https://github.com/keyfactor-research/command-mcp', NULL, 0, 'https://github.com/keyfactor-research.png?size=128', '2026-03-09T05:21:02.013842+00:00'),
  ('github-pull-request-activity', 'GitHub Pull Request Activity', 'Performance Review Data MCP Server provides developers with tools to retrieve GitHub pull request activity for performance reviews. Built by Kevin Fischer, it integrates with the GitHub API to fetch a user''s opened pull requests within a specified month, formatting the results as structured XML output. The implementation uses environment variables for configuration, includes proper error handling, and follows Ruby best practices with modular code organization. Particularly valuable for developers who need to compile their contributions for regular performance evaluations without manually searching through GitHub history.', '@kfischer-okarin', 'development', 'Unknown', 0, 'https://github.com/kfischer-okarin/mcp-server-performance-review-data', NULL, 0, 'https://github.com/kfischer-okarin.png?size=128', '2026-03-09T05:21:02.013968+00:00'),
  ('a2abench', 'A2ABench', 'Provides a StackOverflow-style developer Q&A service designed for agent consumption. Offers search and fetch tools through both local and remote configurations, with REST API endpoints documented via OpenAPI and Swagger UI. Supports A2A agent discovery at standardized well-known paths and provides canonical citation URLs for questions.', '@khalidsaidi', 'search', 'Unknown', 0, 'https://github.com/khalidsaidi/a2abench', NULL, 0, 'https://github.com/khalidsaidi.png?size=128', '2026-03-09T05:21:02.014001+00:00'),
  ('orchestro', 'Orchestro', 'Orchestro is an intelligent orchestration system that bridges product managers, developers, and AI assistants. It provides task decomposition, dependency tracking, pattern learning, and real-time progress visualization through a Kanban-style dashboard. Designed specifically for AI-assisted development workflows, it includes conflict detection when tasks modify overlapping code resources and automated user story breakdown into technical tasks.', '@khaoss85', 'development', 'Unknown', 13, 'https://github.com/khaoss85/mcp-orchestro', NULL, 0, 'https://github.com/khaoss85.png?size=128', '2026-03-09T05:21:02.014050+00:00'),
  ('spotify-bulk-actions', 'Spotify Bulk Actions', 'Integrates with Spotify''s Web API to perform bulk operations including batch playlist creation, library analysis, and CSV-based imports. Features confidence-scored search matching that categorizes results as HIGH/MEDIUM/LOW certainty, with uncertain matches exported for human review before playlist addition. Provides 18 tools across library analysis, search, playlist management, and export utilities.', '@khglynn', 'ai-ml', 'Unknown', 0, 'https://github.com/khglynn/spotify-bulk-actions-mcp', NULL, 0, 'https://github.com/khglynn.png?size=128', '2026-03-09T05:21:02.014112+00:00'),
  ('kofa', 'KOFA', 'Provides access to decisions from KOFA (Klagenemnda for offentlige anskaffelser), the Norwegian Public Procurement Complaints Board. Offers full-text and semantic search across approximately 5,000 decisions, case retrieval with section-level detail, cross-reference analysis between cases, EU case law integration via EUR-Lex, legislative history browsing, and aggregated statistics. Supports filtering by case type, outcome, and respondent.', '@khjohns', 'ai-ml', 'Unknown', 1, 'https://github.com/khjohns/kofa', NULL, 0, 'https://github.com/khjohns.png?size=128', '2026-03-09T05:21:02.014175+00:00'),
  ('svelte-documentation', 'Svelte Documentation', 'This MCP server provides Svelte 5 and SvelteKit documentation access for AI assistants, automatically syncing content from the official svelte.dev GitHub repository and serving it through both direct preset downloads and MCP protocol integration. Built with SvelteKit and PostgreSQL, the implementation features automated content distillation using Anthropic''s Claude API to compress documentation while preserving technical accuracy, scheduled hourly updates to maintain currency with upstream changes, and multiple preset configurations covering core Svelte concepts, advanced features, and complete SvelteKit workflows. The server offers both raw documentation access and AI-optimized distilled versions with significant size reduction, making it valuable for developers building Svelte applications who need their AI coding assistants to have access to current, comprehensive framework documentation without manual context management.', '@khromov', 'databases', 'Unknown', 160, 'https://github.com/khromov/svelte-llm-mcp', NULL, 0, 'https://github.com/khromov.png?size=128', '2026-03-09T05:21:02.014197+00:00'),
  ('kibela', 'Kibela', 'Kibela MCP Server provides a bridge to Kibela''s knowledge management platform, enabling AI assistants to interact with content through GraphQL API calls. Developed by Bit Journey, Inc., this implementation offers tools for searching, creating, and managing notes, folders, comments, and groups within Kibela workspaces. The server supports internationalization with English and Japanese locales and allows for customization of tool descriptions and prompts through configuration files. Particularly useful for teams looking to organize knowledge bases, collaborate on documentation, or leverage AI assistance with their existing Kibela content.', '@kibela', 'ai-ml', 'Unknown', 13, 'https://github.com/kibela/kibela-mcp-server', NULL, 0, 'https://github.com/kibela.png?size=128', '2026-03-09T05:21:02.014254+00:00'),
  ('io-github-bunnyf-kicad-mcp-server', 'io.github.bunnyf/kicad-mcp-server', 'MCP server for AI-assisted PCB design with KiCad 9.x', '@bunnyf', 'development', 'Unknown', 3, 'https://github.com/bunnyf/pcb-mcp', NULL, 0, 'https://github.com/bunnyf.png?size=128', '2026-03-09T05:21:02.014269+00:00'),
  ('rust-documentation', 'Rust Documentation', 'Provides comprehensive access to Rust crate documentation from docs.rs and metadata from crates.io through specialized tools. Features include searching crates, browsing documentation and API items, listing methods with signatures, resolving type paths, batch lookups for efficiency, and retrieving crate metadata including features, dependencies, and version information. Supports auto-discovery of module paths, handles standard library crates, and includes LRU caching with stale-while-revalidate for performance.', '@kieled', 'search', 'Unknown', 1, 'https://github.com/kieled/mcp-rustdoc', NULL, 0, 'https://github.com/kieled.png?size=128', '2026-03-09T05:21:02.014314+00:00'),
  ('macos-calendar-reminders', 'macOS Calendar & Reminders', 'Provides native macOS Calendar and Reminders integration through Apple''s EventKit framework. Supports full CRUD operations for calendars, events, and reminders across any account synced to the macOS Calendar app, including iCloud, Google Calendar, Microsoft Outlook/Exchange, and CalDAV. Includes advanced features such as multi-keyword search with AND/OR matching, duplicate event detection across calendars, batch operations, conflict detection, recurring events, and location-based reminders.', '@psychquant', 'productivity', 'Unknown', 3, 'https://github.com/psychquant/che-ical-mcp', NULL, 0, 'https://github.com/psychquant.png?size=128', '2026-03-09T05:21:02.014350+00:00'),
  ('pub-dev-package-search', 'Pub.dev Package Search', 'PubDev MCP is a server that enables natural language search for Dart and Flutter packages on pub.dev. It leverages the pub_api_client to retrieve package information, scores, and metrics, allowing users to find appropriate packages through conversational queries rather than traditional keyword searches. The implementation provides detailed package results including version, description, URL, and score, making it easier for developers to discover and evaluate packages that meet their specific needs without having to master pub.dev''s search syntax.', '@kikuchy', 'ai-ml', 'Unknown', 12, 'https://github.com/kikuchy/pubdev_mcp', NULL, 0, 'https://github.com/kikuchy.png?size=128', '2026-03-09T05:21:02.014391+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('web-content-pick', 'Web Content Pick', 'MCP Web Content Pick is a server implementation that extracts structured content from web pages using customizable selectors. Developed by kilicmu, it leverages the web-structure library to crawl websites and parse HTML elements like headings, paragraphs, and lists. The tool supports recursive crawling with configurable depth limits, custom selector definitions, and error handling options. This implementation is particularly valuable for content analysis, web scraping, and generating structured representations of web pages without leaving the AI assistant interface.', '@kilicmu', 'ai-ml', 'Unknown', 1, 'https://github.com/kilicmu/mcp-web-content-pick', 'mcp-web-content-pick', 6319, 'https://github.com/kilicmu.png?size=128', '2026-03-09T05:21:02.014434+00:00'),
  ('nano-currency', 'Nano Currency', 'A lightweight MCP server for sending Nano cryptocurrency, providing tools to send Nano, retrieve account information, and interact with Nano blockchain nodes. Developed by Frank Kilkelly, this implementation enables AI agents and language models to perform cryptocurrency transactions through a standardized, programmatic interface with built-in validation and error handling.', '@kilkelly', 'ai-ml', 'Unknown', 9, 'https://github.com/kilkelly/nano-currency-mcp-server', NULL, 0, 'https://github.com/kilkelly.png?size=128', '2026-03-09T05:21:02.014477+00:00'),
  ('device42', 'Device42', 'Provides comprehensive access to Device42''s IT asset management platform, enabling queries and management of infrastructure data including devices, IP addresses, subnets, racks, rooms, buildings, VLANs, and software inventory. The implementation supports both read-only and read-write modes, with DOQL (Device42 Object Query Language) integration for complex cross-table queries and reporting. Built with minimal dependencies and designed for zero-install deployment via npx or Docker.', '@killcity', 'cloud', 'Unknown', 1, 'https://github.com/killcity/device42-mcp', NULL, 0, 'https://github.com/killcity.png?size=128', '2026-03-09T05:21:02.014500+00:00'),
  ('devtap', 'DevTap', 'DevTap captures stdout and stderr from build and development commands, then feeds them into AI coding tool sessions via MCP. It supports multi-adapter fan-out to multiple AI tools simultaneously with independent output queues for parallel coding sessions. Includes file-based storage by default and an optional GreptimeDB backend for persistent history and cross-machine builds.', '@killme2008', 'development', 'Unknown', 13, 'https://github.com/killme2008/devtap', NULL, 0, 'https://github.com/killme2008.png?size=128', '2026-03-09T05:21:02.014520+00:00'),
  ('kill-process', 'Kill Process', 'This MCP server provides cross-platform process management capabilities through two core tools: process listing with advanced filtering and sorting options, and process termination functionality. Built by Michal Szymanski using Python with psutil for cross-platform process access and FastMCP for the server framework, it offers intelligent memory reporting that uses macOS Activity Monitor-style physical footprint calculations with fallback to RSS/USS metrics on other platforms, CPU usage monitoring with configurable sampling duration, comprehensive filtering by process name, user, status, and resource thresholds, and built-in safety measures that exclude system processes by default and prevent self-termination. The implementation features platform-specific optimizations for process name resolution and memory calculation, robust error handling for process access permissions, and flexible sorting capabilities, making it valuable for system administration tasks, resource monitoring workflows, and building AI assistants that need programmatic process management without manual task manager navigation.', '@misiektoja', 'development', 'Unknown', 11, 'https://github.com/misiektoja/kill-process-mcp', NULL, 0, 'https://github.com/misiektoja.png?size=128', '2026-03-09T05:21:02.014557+00:00'),
  ('kimi-ai', 'KIMI AI', 'MCP server implementation that provides AI assistants with access to KIMI AI services through OpenAI-compatible API endpoints, featuring both text generation and vision capabilities using Qwen models (Qwen2.5-72B-Instruct for text and Qwen2.5-VL-72B-Instruct for vision tasks). The implementation includes a FastAPI-based server architecture with MCP protocol support, custom detection services, and a web-based client interface for testing interactions. Built with configurable API endpoints and model selection, it serves users who want to integrate KIMI''s AI capabilities into their workflows through standardized MCP tooling, supporting use cases like multilingual text generation, image analysis, and custom AI service integration with existing MCP-compatible applications.', '@adamleen', 'development', 'Unknown', 1, 'https://github.com/adamleen/mcp-kimi', NULL, 0, 'https://github.com/adamleen.png?size=128', '2026-03-09T05:21:02.014588+00:00'),
  ('structured-workflow', 'Structured Workflow', 'This MCP server provides structured workflow guidance for AI-assisted programming through disciplined refactoring and development methodologies, built by kingdomseed using TypeScript with the Model Context Protocol SDK and comprehensive session management. It offers four specialized workflow types (refactoring, feature creation, test writing, and test-driven development) with 20+ tools including phase-specific guidance, validation enforcement, file operation safety rules, and automatic artifact generation with numbered file naming. The implementation features a "Guide, Don''t Gate" philosophy that provides structured methodology without restricting AI capabilities, enforces read-before-write safety rules, supports custom workflow configuration with iteration limits and escalation triggers, and maintains session state for workflow progression tracking, making it valuable for professional code refactoring projects, systematic feature development, comprehensive test coverage improvement, and building AI assistants that follow disciplined software engineering practices.', '@kingdomseed', 'development', 'Unknown', 9, 'https://github.com/kingdomseed/structured-workflow-mcp', 'structured-workflow-mcp', 824, 'https://github.com/kingdomseed.png?size=128', '2026-03-09T05:21:02.014669+00:00'),
  ('specs-workflow', 'Specs Workflow', 'Intelligent specification workflow management server that guides users through structured software project documentation phases including requirements, design, and implementation tasks. Built with TypeScript and leveraging OpenAPI specifications as the single source of truth for templates and responses, it provides automated document generation, progress tracking, stage confirmation, and task completion workflows. The implementation uses XML template markers to detect document editing status and maintains workflow state through JSON confirmation files, making it valuable for teams following systematic development processes who need guided assistance in creating and maintaining project specifications with built-in validation and progress monitoring.', '@kingkongshot', 'development', 'Unknown', 128, 'https://github.com/kingkongshot/specs-workflow-mcp', 'spec-workflow-mcp', 21959, 'https://github.com/kingkongshot.png?size=128', '2026-03-09T05:21:02.014742+00:00'),
  ('reddit-research', 'Reddit Research', 'Semantic search across 20,000+ subreddits for market research, competitive analysis, and customer discovery. Discover relevant communities, track sentiment, identify unmet needs from real user feedback, and manage curated research feeds with persistent storage.', '@king-of-the-grackles', 'ai-ml', 'Unknown', 90, 'https://github.com/king-of-the-grackles/reddit-research-mcp', NULL, 0, 'https://github.com/king-of-the-grackles.png?size=128', '2026-03-09T05:21:02.014771+00:00'),
  ('hubitat-elevation', 'Hubitat Elevation', 'Native Hubitat Elevation smart home hub integration that runs directly on the hub as a Groovy app. Provides device control, system queries, and automation management with a built-in rule engine supporting complex triggers, conditions, and actions for comprehensive home automation through natural language. Includes 68+ MCP tools for device management, rule creation, virtual device handling, hub health monitoring, and administrative functions.', '@kingpanther13', 'aggregators', 'Unknown', 4, 'https://github.com/kingpanther13/hubitat-local-mcp-server', NULL, 0, 'https://github.com/kingpanther13.png?size=128', '2026-03-09T05:21:02.014843+00:00'),
  ('ssh-commander', 'SSH Commander', 'SSH MCP Server provides secure remote access and command execution capabilities through the Model Context Protocol. It allows AI assistants to execute SSH commands on remote servers using stored credentials, with a SQLite database for persistent credential management. The implementation includes tools for executing commands, adding/removing credentials, and listing available connections - making it particularly valuable for system administration tasks and remote server management without leaving the conversation interface.', '@kinothe-kafkaesque', 'databases', 'Unknown', 9, 'https://github.com/kinothe-kafkaesque/ssh-mcp-server', NULL, 0, 'https://github.com/kinothe-kafkaesque.png?size=128', '2026-03-09T05:21:02.014871+00:00'),
  ('confluence-chat', 'Confluence Chat', 'A lightweight MCP server for expanding and updating Confluence page content through a JSON-RPC interface. The implementation provides a tool for generating expanded content based on a given header and original text, with a focus on simplifying content generation workflows in Confluence. Designed to be easily configurable through a JSON configuration file and minimal Python dependencies.', '@kinsha-dev', 'communication', 'Unknown', 0, 'https://github.com/kinsha-dev/confluence-chat-mcp-service', NULL, 0, 'https://github.com/kinsha-dev.png?size=128', '2026-03-09T05:21:02.014902+00:00'),
  ('book-fetch-library-genesis', 'Book Fetch (Library Genesis)', 'Book Fetch MCP provides AI assistants with access to published books through a specialized tool that retrieves and processes book content from Library Genesis. Built with Python using the FastMCP framework, it downloads books based on title and author, extracts text from PDFs using parallel processing, and intelligently manages large texts by delivering them in manageable chunks with proper metadata. The implementation includes a caching mechanism to improve performance for repeated requests and handles various error conditions gracefully. It''s particularly valuable for workflows requiring in-depth book analysis, research, or reference within AI assistant conversations without requiring users to manually locate and process book content.', '@kinshukk', 'ai-ml', 'Unknown', 4, 'https://github.com/kinshukk/book-fetch-mcp', NULL, 0, 'https://github.com/kinshukk.png?size=128', '2026-03-09T05:21:02.014954+00:00'),
  ('context-engine', 'Context Engine', 'Context Engine provides semantic code search and context enhancement capabilities for local codebases using the Auggie SDK as its core retrieval engine. Built with a 5-layer architecture, it exposes tools for semantic search, file retrieval, context bundling, and AI-powered prompt enhancement through the Model Context Protocol. The server operates locally-first with no cloud dependencies, supports real-time file watching for incremental indexing, and includes background indexing via worker threads. Designed for AI coding assistants like Claude Desktop and Cursor, it enables natural language queries over codebases for tasks like bug investigation, feature development, and code understanding without requiring manual file navigation.', '@kirachon', 'development', 'Unknown', 33, 'https://github.com/kirachon/context-engine', NULL, 0, 'https://github.com/kirachon.png?size=128', '2026-03-09T05:21:02.014996+00:00'),
  ('volatility3', 'Volatility3', 'Volatility3 MCP Server is a powerful tool that connects MCP clients like Claude Desktop with Volatility3, the advanced memory forensics framework. This integration allows LLMs to analyze memory dumps, detect malware, and perform sophisticated memory forensics tasks through a simple, conversational interface.', '@kirandawadi', 'productivity', 'Unknown', 16, 'https://github.com/kirandawadi/volatility3-mcp', NULL, 0, 'https://github.com/kirandawadi.png?size=128', '2026-03-09T05:21:02.015053+00:00'),
  ('sentinel-dv', 'Sentinel DV', 'Sentinel DV is an MCP server providing safe, structured read-only access to hardware verification artifacts for SystemVerilog, UVM, and cocotb frameworks. It includes 14 specialized tools for analyzing test failures, coverage metrics, assertion data, and regression trends with automatic redaction and bounded responses to ensure security and consistency.', '@kiranreddi', 'development', 'Unknown', 1, 'https://github.com/kiranreddi/sentinel-dv', NULL, 0, 'https://github.com/kiranreddi.png?size=128', '2026-03-09T05:21:02.015076+00:00'),
  ('aionmcp', 'AionMCP', 'Autonomous Go-based server that dynamically imports OpenAPI, GraphQL, and AsyncAPI specifications and exposes them as tools to agents. Features self-learning capabilities and autonomous documentation generation with TOON (Token-Oriented Object Notation) for optimized LLM context handling.', '@kiransth77', 'ai-ml', 'Unknown', 1, 'https://github.com/kiransth77/aionmcp', NULL, 0, 'https://github.com/kiransth77.png?size=128', '2026-03-09T05:21:02.015103+00:00'),
  ('image-toolkit', 'Image Toolkit', 'The Image Toolkit MCP Server provides AI assistants with a comprehensive set of image manipulation capabilities through Google''s Gemini models and third-party APIs. Built with Python using the FastMCP framework, it offers three main tools: generating images from text prompts, modifying existing images based on instructions, and removing image backgrounds. The implementation handles image safety checks, temporary file management, and automatic uploading to FreeImage.host for easy sharing. This server is particularly valuable for workflows requiring image generation and editing directly within AI assistant conversations, eliminating the need for separate image editing tools.', '@kira-pgr', 'ai-ml', 'Unknown', 18, 'https://github.com/kira-pgr/promptshopmcp', NULL, 0, 'https://github.com/kira-pgr.png?size=128', '2026-03-09T05:21:02.015150+00:00'),
  ('kirha-crypto-gateway', 'Kirha Crypto Gateway', 'A gateway server built by Kirha AI that provides access to their specialized tool planning API for cryptocurrency-related queries through a configurable MCP interface. The implementation uses a containerized Express.js server with streamable HTTP transport, automatically routing crypto questions to Kirha''s internal analysis system with built-in summarization capabilities using their kirha-flash model. It features flexible configuration through JSON files and query parameters, supports stateless operation with per-request API key handling, and includes comprehensive debugging capabilities for troubleshooting authentication issues, making it useful for integrating AI assistants with specialized crypto knowledge bases and ensuring accurate pre-validated results before falling back to web searches.', '@kirha-ai', 'development', 'Unknown', 1, 'https://github.com/kirha-ai/kirha-crypto-smithery-gateway', NULL, 0, 'https://github.com/kirha-ai.png?size=128', '2026-03-09T05:21:02.015197+00:00'),
  ('dnf-gold-price-weather', 'DNF Gold Price & Weather', 'A Go-based MCP server implementation that integrates with the mark3labs/mcp-go library to provide specialized tools for retrieving DNF gold prices and weather information. The server leverages the kiririx/krutils utility package for additional functionality, making it suitable for applications that need to access real-time market data and meteorological information through a standardized protocol interface.', '@kirikoko1213', 'ai-ml', 'Unknown', 0, 'https://github.com/kirikoko1213/kr-mcp-server', NULL, 0, 'https://github.com/kirikoko1213.png?size=128', '2026-03-09T05:21:02.015240+00:00'),
  ('simple-tool-website-fetcher', 'Simple Tool (Website Fetcher)', 'This MCP server implementation provides a simple website fetching tool exposed through the Model Context Protocol. Developed by Kirill Markin, it allows AI assistants to retrieve web page content for analysis and processing. The server is built using Python and the MCP SDK, with support for both local development and deployment on Heroku. It features configurable settings for port, host, and user agent, as well as debug mode options. The implementation is designed to be lightweight and easily extensible, making it suitable for a wide range of applications that require web scraping capabilities, such as content aggregation, data analysis, or information retrieval tasks.', '@myblockcities', 'development', 'Unknown', 2, 'https://github.com/myblockcities/mcp-server-heroku', NULL, 0, 'https://github.com/myblockcities.png?size=128', '2026-03-09T05:21:02.015270+00:00'),
  ('simple-website-fetcher', 'Simple Website Fetcher', 'This MCP server, developed by Kirill Markin, provides a simple tool for fetching website content. Built with Python and leveraging the MCP library, it offers a standardized interface for AI models to retrieve web page data. The implementation focuses on ease of deployment, with Docker and Heroku support, and includes configuration options for customizing server behavior. By enabling AI assistants to access web content through a unified API, this server facilitates use cases such as web scraping, content analysis, and information retrieval. It''s particularly useful for applications and AI models that require programmatic access to web data without dealing with the complexities of direct HTTP requests and HTML parsing.', '@chrisboden', 'cloud', 'Unknown', 5, 'https://github.com/chrisboden/mcp_template', NULL, 0, 'https://github.com/chrisboden.png?size=128', '2026-03-09T05:21:02.015294+00:00'),
  ('api-tester', 'API Tester', 'API Tester MCP provides comprehensive API testing capabilities with multi-language test generation, supporting TypeScript/Playwright, JavaScript/Jest, and Python/pytest frameworks. Built by API Tester MCP, it ingests OpenAPI/Swagger specifications and Postman collections to automatically generate test scenarios, executable test cases, and complete project files with proper configuration. The server features concurrent test execution with detailed progress tracking, load testing capabilities, HTML report generation, and intelligent test data generation using Faker, making it valuable for QA engineers and developers who need to quickly validate API functionality, generate automated test suites in their preferred language/framework, and perform comprehensive API testing including performance validation.', '@kirti676', 'development', 'Unknown', 5, 'https://github.com/kirti676/api_tester_mcp', '@kirti676/api-tester-mcp', 2310, 'https://github.com/kirti676.png?size=128', '2026-03-09T05:21:02.015326+00:00'),
  ('todo-manager', 'Todo Manager', 'MCP_Server provides a TypeScript implementation for managing todo items through a structured microservice architecture. Built with FastMCP, it offers tools for adding, searching, updating, and removing todos with robust validation, encryption, and database integration. The implementation follows clean architecture principles with separate modules for API handling (Todo_API), database operations (Todo_Db_Library), and MCP server functionality, featuring event-driven communication through domain events and caching mechanisms. This server is particularly valuable for applications requiring secure todo management with features like AES encryption, PostgreSQL persistence, and Redis caching.', '@kishornaik', 'databases', 'Unknown', 1, 'https://github.com/kishornaik/sol_mcp_server_typescript/tree/HEAD/MCP_Server', NULL, 0, 'https://github.com/kishornaik.png?size=128', '2026-03-09T05:21:02.015419+00:00'),
  ('kismet-travel', 'Kismet Travel', 'Search for hotels using semantic queries or fuzzy matching. 
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('linode', 'Linode', 'Linode MCP server provides a bridge to the Linode cloud infrastructure API, enabling AI assistants to interact with Linode services like region discovery and instance management. Built by Khaja Omer, this implementation uses the Linode API4 library to expose tools for querying cloud resources, with a focus on simplifying cloud infrastructure interactions through a standardized MCP interface. Particularly useful for developers and teams looking to programmatically manage Linode cloud resources through conversational AI.', '@komer3', 'ai-ml', 'Unknown', 1, 'https://github.com/komer3/linode-mcp', 'linode-mcp', 1460, 'https://github.com/komer3.png?size=128', '2026-03-09T05:21:02.016637+00:00'),
  ('io-github-mp-tool-komodo-mcp-server', 'io.github.MP-Tool/komodo-mcp-server', 'MCP server for Komodo - manage Docker containers, servers, stacks, and deployments via AI', '@mp-tool', 'cloud', 'Unknown', 2, 'https://github.com/mp-tool/komodo-mcp-server', NULL, 0, 'https://github.com/mp-tool.png?size=128', '2026-03-09T05:21:02.016653+00:00'),
  ('home-assistant-light', 'Home Assistant Light', 'Enables control of Home Assistant lights and scenes through a safety-focused MCP server that intentionally limits functionality to lighting domains only. Connects via Home Assistant''s API using long-lived access tokens to query and control light states, brightness, and scene activation while excluding potentially dangerous automation capabilities.', '@koneisto', 'ai-ml', 'Unknown', 0, 'https://github.com/koneisto/homeassistant-light-mcp', NULL, 0, 'https://github.com/koneisto.png?size=128', '2026-03-09T05:21:02.016685+00:00'),
  ('kong-konnect', 'Kong Konnect', 'Kong Konnect MCP Server provides tools for managing and analyzing Kong API Gateway configurations and traffic through the Konnect platform. Developed by Kong, this TypeScript implementation offers capabilities for querying API requests, analyzing consumer traffic patterns, and managing control plane configurations including services, routes, plugins, and control plane group memberships. The server connects to Kong''s cloud APIs using authentication tokens and transforms complex API responses into structured, actionable data. It''s particularly valuable for DevOps teams managing API infrastructure who need to monitor traffic patterns, troubleshoot issues, and maintain consistent gateway configurations across multiple environments.', '@kong', 'development', 'Unknown', 38, 'https://github.com/kong/mcp-konnect', NULL, 0, 'https://github.com/kong.png?size=128', '2026-03-09T05:21:02.016716+00:00'),
  ('eve-online-est', 'EVE Online EST', 'EVE Online EST MCP server by kongyo2 that provides EVE Server Time information and downtime calculations for the popular space MMO. The implementation offers a single tool that returns current EVE Server Time (which is identical to UTC), calculates time remaining until the next daily server maintenance window (11:00-11:15 UTC), indicates whether servers are currently offline for maintenance, and uses system time with WorldTimeAPI as a fallback for reliability. Built with TypeScript using the FastMCP framework, it serves EVE Online players who need programmatic access to server status information for planning gameplay sessions, fleet operations, or market activities around the predictable daily downtime schedule.', '@kongyo2', 'development', 'Unknown', 2, 'https://github.com/kongyo2/eve-est-mcp', NULL, 0, 'https://github.com/kongyo2.png?size=128', '2026-03-09T05:21:02.016748+00:00'),
  ('eve-online-osint', 'EVE Online OSINT', 'Provides OSINT (Open Source Intelligence) capabilities for EVE Online using multiple APIs including ESI, EveWho, and zKillboard to gather comprehensive intelligence on characters, corporations, and alliances by name. Built by kongyo2 with TypeScript and FastMCP, the implementation automatically resolves entity names to IDs and combines data from official EVE APIs with third-party intelligence sources to deliver detailed reports including character corporation history, security status, killmail data, corporation member lists with activity metrics, and alliance composition with growth trends. Features robust retry logic with exponential backoff, rate limiting compliance, and structured intelligence reporting, making it valuable for EVE Online players conducting reconnaissance operations, alliance leadership analyzing member activity and recruitment patterns, and security teams investigating potential threats or tracking player movements across New Eden.', '@kongyo2', 'development', 'Unknown', 8, 'https://github.com/kongyo2/eve-online-osint-mcp', NULL, 0, 'https://github.com/kongyo2.png?size=128', '2026-03-09T05:21:02.016785+00:00'),
  ('eve-online-traffic', 'EVE Online Traffic', 'EVE Online Traffic MCP server that provides comprehensive navigation and intelligence tools for the EVE Online universe through integration with the official ESI API, EVE-KILL API, and Static Data Export (SDE). Built by Frank Fiegel at Glama AI, the implementation offers route calculation between solar systems, combat statistics analysis including recent killmails and PvP activity levels, station services discovery with filtering capabilities, landmark proximity searches, and universal name-to-ID conversion for all EVE entities. Features include finding dangerous systems based on kill data, locating nearest trade hubs with detailed routing information, and analyzing system connections with security status filtering, making it valuable for EVE pilots planning safe travel routes, traders seeking optimal market locations, and PvP players identifying high-activity hunting grounds.', '@kongyo2', 'ai-ml', 'Unknown', 3, 'https://github.com/kongyo2/eve-online-traffic-mcp', NULL, 0, 'https://github.com/kongyo2.png?size=128', '2026-03-09T05:21:02.016843+00:00'),
  ('kontent-ai', 'Kontent.ai', 'Connect to Kontent.ai headless CMS to manage content operations through natural language. Enables AI models to understand your content structure, create and update content items, manage content types and taxonomies, and control workflows. Requires a Kontent.ai account with Management API access.', '@kontent-ai', 'ai-ml', 'Unknown', 8, 'https://github.com/kontent-ai/mcp-server', NULL, 0, 'https://github.com/kontent-ai.png?size=128', '2026-03-09T05:21:02.016923+00:00'),
  ('sharptools-roslyn-c-analysis', 'SharpTools (Roslyn C# Analysis)', 'SharpTools is a Roslyn-powered C# analysis and modification MCP server that provides AI agents with advanced capabilities for understanding, analyzing, and modifying C# codebases through deep static analysis rather than simple text operations. Built by kooshi as a personal project, it leverages the .NET Compiler Platform to offer precise code manipulation including surgical member additions/modifications, fuzzy FQN matching, source resolution from multiple sources (SourceLink, embedded PDBs, decompilation), and automated Git integration with dedicated branches and commit tracking. The implementation includes proactive code quality analysis with complexity detection and semantic similarity checking, supports both modern SDK-style and legacy C# projects across all .NET versions, and exposes functionality through both SSE and stdio servers, making it valuable for AI-powered code assistance workflows that require IDE-level insights and reliable code modifications with built-in undo capabilities.', '@kooshi', 'development', 'Unknown', 164, 'https://github.com/kooshi/sharptoolsmcp', NULL, 0, 'https://github.com/kooshi.png?size=128', '2026-03-09T05:21:02.016959+00:00'),
  ('evolvemcp', 'EvolveMCP', 'EvolveMCP is a Python-based MCP server implementation that extends Claude Desktop''s capabilities through custom tools. It provides a framework for creating, managing, and integrating new functionalities like mathematical calculations directly into Claude conversations. The system includes utilities for managing Claude''s configuration, monitoring system status, and installing example tools through an interactive wizard interface. EvolveMCP handles cross-platform compatibility, automatically installs dependencies, and offers a streamlined way for users to enhance their Claude experience without manual configuration.', '@kordless', 'ai-ml', 'Unknown', 57, 'https://github.com/kordless/gnosis-evolve', NULL, 0, 'https://github.com/kordless.png?size=128', '2026-03-09T05:21:02.017003+00:00'),
  ('finlab-ai', 'FinLab AI', 'FinLab AI provides AI assistants with comprehensive tools for quantitative trading strategy development. It offers access to over 900 data columns spanning pricing, financial metrics, valuations, and institutional trading flows. The server includes a backtesting engine with risk management features, factor analysis capabilities, and machine learning integration for feature engineering.', '@koreal6803', 'development', 'Unknown', 305, 'https://github.com/koreal6803/finlab-ai', NULL, 0, 'https://github.com/koreal6803.png?size=128', '2026-03-09T05:21:02.017024+00:00'),
  ('korea-tourism-api', 'Korea Tourism API', 'Korea Tour MCP Server provides AI assistants with access to Korean tourism information through the TOUR API. Developed by Pyungjoo Kim, this TypeScript implementation offers tools for area code lookup, tourism information searches (by region, keyword, or location), and detailed content about attractions, festivals, and accommodations. The server requires an optional API key configuration and uses the Model Context Protocol to enable AI systems to retrieve structured tourism data about Korea, making it particularly useful for travel planning, regional exploration, and tourism research.', '@pjookim', 'development', 'Unknown', 2, 'https://github.com/pjookim/mcp-visit-korea', NULL, 0, 'https://github.com/pjookim.png?size=128', '2026-03-09T05:21:02.017050+00:00'),
  ('slack-conversations', 'Slack Conversations', 'Slack MCP Server provides a bridge between AI assistants and Slack''s messaging platform, enabling access to conversation history from Slack channels. Developed by Dmitrii Korotovskii, this Go implementation authenticates with Slack using XOXC and XOXD tokens, handling the necessary HTTP transport customization to maintain session cookies. The server supports both stdio and SSE transport modes, includes API key authentication for secure access, and offers optional HTTP proxy and custom CA certificate configuration. Particularly useful for AI assistants that need to analyze, reference, or work with team communications stored in Slack channels without requiring direct Slack API integration.', '@korotovsky', 'communication', 'Unknown', 1427, 'https://github.com/korotovsky/slack-mcp-server', NULL, 0, 'https://github.com/korotovsky.png?size=128', '2026-03-09T05:21:02.017156+00:00'),
  ('playwright-web-browser', 'Playwright Web Browser', 'Playwright-MCP-Server provides web browsing capabilities for AI assistants through Playwright automation. It offers tools for navigating websites, extracting visible content, identifying interactive elements, and performing mouse actions. The server is containerized with Docker for easy deployment and uses the Model Context Protocol SDK to expose browser functionality as tools and resources. This implementation is particularly valuable for workflows requiring web scraping, content extraction, and automated browser interactions without leaving the conversation interface.', '@kotelberg', 'cloud', 'Unknown', 1, 'https://github.com/kotelberg/playwright-mcp-server', NULL, 0, 'https://github.com/kotelberg.png?size=128', '2026-03-09T05:21:02.017184+00:00'),
  ('kotlin-android-development', 'Kotlin Android Development', 'Kotlin MCP server by normaltusker that provides AI assistants with complete Android/Kotlin development capabilities through 31+ specialized tools covering code generation, build management, architecture setup, and security features. The implementation integrates Gradle build tools, ktlint formatting, Android Lint analysis, Room database setup, Retrofit API configuration, MVVM architecture scaffolding, Jetpack Compose component creation, and comprehensive security utilities including encryption and audit logging with GDPR/HIPAA compliance support. Built with modular architecture using separate tools for gradle operations, project analysis, build optimization, code generation, and AI integration (OpenAI/Anthropic/local LLM support), it includes Docker deployment, VS Code bridge server, extensive test coverage, and performance monitoring, serving developers building Android applications who need conversational access to the full Android development toolchain from initial project setup through production deployment.', '@normaltusker', 'databases', 'Unknown', 22, 'https://github.com/normaltusker/kotlin-mcp-server', NULL, 0, 'https://github.com/normaltusker.png?size=128', '2026-03-09T05:21:02.017197+00:00'),
  ('zendesk-support', 'Zendesk Support', 'Zendesk MCP Server provides a bridge between AI assistants and the Zendesk customer support platform through the Model Context Protocol. This TypeScript implementation enables agents to perform essential Zendesk operations including retrieving, creating, and updating tickets, adding public and private comments, and searching across the ticket database. The server authenticates with Zendesk using API tokens configured through environment variables and exposes seven specialized tools that handle different aspects of ticket management. It''s particularly valuable for customer support teams who want to leverage AI assistants for ticket triage, response drafting, and support workflow automation without leaving their conversation interface.', '@koundinya', 'databases', 'Unknown', 12, 'https://github.com/koundinya/zd-mcp-server', NULL, 0, 'https://github.com/koundinya.png?size=128', '2026-03-09T05:21:02.017208+00:00'),
  ('duckduckgo-web-search', 'DuckDuckGo Web Search', 'DuckDuckGo Web Search MCP Server enables AI assistants to search the web using DuckDuckGo and optionally fetch content from search results. Built with Python using the FastMCP framework, it extracts titles, URLs, and snippets from search results, with the ability to convert HTML content to markdown using the Jina API. The server handles concurrent URL fetching, gracefully manages timeouts, and provides configurable result limits, making it ideal for workflows requiring real-time internet information without leaving the conversation interface.', '@kouui', 'ai-ml', 'Unknown', 4, 'https://github.com/kouui/web-search-duckduckgo', NULL, 0, 'https://github.com/kouui.png?size=128', '2026-03-09T05:21:02.017254+00:00'),
  ('fetch-url', 'Fetch URL', 'GKMCP is a Rust-based MCP server implementation that provides a fetch tool for retrieving content from URLs. Built with the Tokio async runtime and Reqwest HTTP client, it follows the 2025-03-26 protocol version specification and implements the core MCP request handling flow including initialization, tool listing, and tool execution. The server processes JSON-RPC style requests from stdin, handles tool calls asynchronously, and returns formatted responses with proper error handling. This implementation is particularly useful for AI assistants that need to access web content during conversations, enabling capabilities like retrieving documentation, checking online resources, or gathering information from specific websites.', '@kov', 'ai-ml', 'Unknown', 1, 'https://github.com/kov/gkmcp', 'gkmcp', 0, 'https://github.com/kov.png?size=128', '2026-03-09T05:21:02.017302+00:00'),
  ('xdebug', 'Xdebug', 'Provides comprehensive PHP debugging capabilities through Xdebug''s DBGp protocol. Supports breakpoint management, step debugging, variable inspection and modification, expression evaluation, watch expressions, logpoints, memory profiling, code coverage tracking, and Docker path mapping for containerized environments.', '@kpanuragh', 'cloud', 'Unknown', 10, 'https://github.com/kpanuragh/xdebug-mcp', NULL, 0, 'https://github.com/kpanuragh.png?size=128', '2026-03-09T05:21:02.017319+00:00'),
  ('devrev', 'DevRev', 'This DevRev MCP server, developed by Sunil Pandey, provides AI assistants with search and retrieval capabilities using the DevRev APIs. Built with Python and leveraging the MCP library, it offers tools for searching DevRev data and retrieving detailed information about specific objects. The server implements namespace-aware searching and object retrieval by ID. By abstracting the complexities of API communication, it allows AI systems to easily access and analyze DevRev data. This implementation is particularly valuable for DevRev users and developers working on integrations, enabling use cases such as automated issue tracking, customer support analysis, and data-driven decision making within the DevRev ecosystem.', '@kpsunil97', 'ai-ml', 'Unknown', 3, 'https://github.com/kpsunil97/devrev-mcp-server', 'devrev-mcp', 7308, 'https://github.com/kpsunil97.png?size=128', '2026-03-09T05:21:02.017365+00:00'),
  ('wordpress-abilities-extended', 'WordPress Abilities Extended', 'WordPress Abilities Extended is a WordPress plugin that exposes MCP capabilities through WordPress 6.9+''s native Abilities API. Organized across 8 categories, it provides full CRUD operations for pages and posts, Gutenberg pattern management with block validation, user administration with role-based permissions, plugin activation and theme inspection, media uploads, taxonomy operations, and advanced features like batch updates and content cloning. The implementation emphasizes security with proper capability checks and input validation.', '@kradyy', 'security', 'Unknown', 2, 'https://github.com/kradyy/wordpress-wae', NULL, 0, 'https://github.com/kradyy.png?size=128', '2026-03-09T05:21:02.017433+00:00'),
  ('manticore-search', 'Manticore Search', 'This MCP server provides complete Manticore Search integration for full-text search, document management, table operations, and cluster administration through a Go-based implementation using the mcp-golang library. Built by krajcik with extensive testing coverage and cross-platform support, it offers five core tools covering advanced search with boolean queries, highlighting, fuzzy matching, and field weighting; table schema inspection and listing; document insertion, updating, and deletion; and cluster status monitoring with replication management. The implementation features robust SQL query building with proper escaping, configurable result limits and pagination, retry mechanisms with timeout handling, and support for both standalone and distributed Manticore deployments, making it valuable for building search-powered applications, content management systems, and AI assistants that need enterprise-grade full-text search capabilities without direct database access.', '@krajcik', 'databases', 'Unknown', 2, 'https://github.com/krajcik/manticore-mcp-server', NULL, 0, 'https://github.com/krajcik.png?size=128', '2026-03-09T05:21:02.017445+00:00'),
  ('vrchat-osc', 'VRChat OSC', 'VRChat OSC MCP Server provides a bridge between AI assistants and VRChat, enabling programmatic control of avatar parameters, inputs, and interactions through WebSocket and OSC protocols. Built with TypeScript and supporting features like avatar parameter manipulation, movement control, chatbox messaging, and event handling, it allows AI agents to directly interact with VRChat''s input and avatar systems. Particularly useful for creating dynamic, AI-driven VRChat experiences with fine-grained avatar and interaction control.', '@krekun', 'development', 'Unknown', 20, 'https://github.com/krekun/vrchat-mcp-osc', NULL, 0, 'https://github.com/krekun.png?size=128', '2026-03-09T05:21:02.017501+00:00'),
  ('file-organizer', 'File Organizer', 'Organizes files into categorized directories using intelligent extension-based classification across 12+ file types. Features SHA-256 hash-based duplicate detection, dry-run preview mode for risk-free planning, and full rollback/undo functionality. Implements multi-layer path validation with TOCTOU mitigation, symbolic link restrictions, and reserved name blocking for secure file operations.', '@kridaydave', 'file-systems', 'Unknown', 31, 'https://github.com/kridaydave/file-organizer-mcp', NULL, 0, 'https://github.com/kridaydave.png?size=128', '2026-03-09T05:21:02.017544+00:00'),
  ('obsidian-notes', 'Obsidian Notes', 'Provides seamless integration with Obsidian vaults through the Local REST API plugin, enabling reading, creating, updating, and searching notes with token-optimized responses. Features comprehensive note management including CRUD operations, full-text and tag-based search, frontmatter queries, periodic note handling (daily/weekly/monthly), batch operations for efficiency, and Obsidian command execution. Designed with pagination, content truncation, and smart summarization to minimize token usage while maintaining functionality, making it ideal for note-taking, knowledge management workflows, and automated vault organization tasks.', '@krisk248', 'productivity', 'Unknown', 1, 'https://github.com/krisk248/obsidian-notes-mcp', NULL, 0, 'https://github.com/krisk248.png?size=128', '2026-03-09T05:21:02.017650+00:00'),
  ('career-break-resilience-resume-optimizer', 'Career Break Resilience (Resume Optimizer)', 'This server helps job seekers optimize their resumes by integrating with N8N workflows to automatically score and filter resume bullet points. It fetches resume data via webhook, assigns unique IDs to bullets for easy reference (A1, A2, B1, etc.), and provides filtering tools to remove low-scoring bullets or limit bullets per company. Built with heap-based filtering algorithms for educational purposes, it''s particularly designed for career professionals managing multiple job applications who need to quickly tailor their resume content based on automated relevance scoring. The server is especially useful for those returning from career breaks who want data-driven resume optimization to improve their job search effectiveness.', '@krithika93', 'ai-ml', 'Unknown', 1, 'https://github.com/krithika93/career-break-resilience-mcp', NULL, 0, 'https://github.com/krithika93.png?size=128', '2026-03-09T05:21:02.017703+00:00'),
  ('fledge-iot', 'Fledge IoT', 'Fledge MCP Server provides a bridge between Fledge IoT platform and AI assistants, enabling natural language interaction with sensor data and system management. Developed by Krupal Patel, it offers tools for data access, service control, UI component generation, and real-time streaming over WebSockets. The implementation includes both standard and secure API key authentication modes, with Docker containerization for easy deployment on Smithery.ai. This server is particularly valuable for IoT workflows requiring data visualization, monitoring, and configuration management without leaving the conversation interface.', '@krupalp525', 'cloud', 'Unknown', 0, 'https://github.com/krupalp525/fledge-mcp', NULL, 0, 'https://github.com/krupalp525.png?size=128', '2026-03-09T05:21:02.017748+00:00'),
  ('toolfront', 'ToolFront', 'ToolFront is a lightweight MCP server for database management and querying built by Kruskal Labs that provides unified access to multiple database types including PostgreSQL, MySQL, SQLite, DuckDB, BigQuery, and Snowflake through a single interface. The server offers tools for discovering datasources, inspecting table schemas, sampling data, executing read-only SQL queries with automatic result serialization, and scanning tables using multiple pattern matching algorithms (regex, TF-IDF, Jaro-Winkler similarity). It includes intelligent async/sync fallback mechanisms for database connections, optional integration with Kruskal''s API for query learning and semantic search, and Docker deployment support, making it valuable for AI assistants that need to explore and analyze data across heterogeneous database environments without requiring database-specific knowledge.', '@statespace-tech', 'databases', 'Unknown', 824, 'https://github.com/statespace-tech/statespace', 'toolfront', 16644, 'https://github.com/statespace-tech.png?size=128', '2026-03-09T05:21:02.017760+00:00'),
  ('indian-stock-market', 'Indian Stock Market', 'Integrates with Indian stock market exchanges NSE and BSE to provide real-time equity data through the NSE API. Built with FastMCP and httpx in Python, it offers stock price lookups by symbol, company name search to find stock symbols, and batch queries for multiple securities simultaneously. The implementation supports flexible response formatting and handles both major Indian exchanges, making it useful for financial analysis, portfolio tracking, and market research workflows requiring programmatic access to current Indian stock prices and company information.', '@krutarthchovatiya', 'search', 'Unknown', 1, 'https://github.com/krutarthchovatiya/mcp-server-indian-stock-market', NULL, 0, 'https://github.com/krutarthchovatiya.png?size=128', '2026-03-09T05:21:02.017802+00:00'),
  ('sncf-train-journey-planner', 'SNCF Train Journey Planner', 'The SNCF API MCP Server provides a comprehensive interface to the French National Railway''s (SNCF) API services, enabling Claude to plan train journeys, retrieve station information, check schedules, and monitor service disruptions across France. Created by Christian Delage, it combines a modular Python wrapper for the SNCF API with an intelligent station-finding system that uses both API queries and a CSV database of European train stations with coordinates. The implementation includes fallback mechanisms with hardcoded coordinates for major French cities, ensuring reliability even when API searches fail, and is particularly valuable for travel planning, transportation research, and real-time transit monitoring without leaving the conversation interface.', '@kryzo', 'databases', 'Unknown', 10, 'https://github.com/kryzo/mcp-sncf', NULL, 0, 'https://github.com/kryzo.png?size=128', '2026-03-09T05:21:02.017820+00:00'),
  ('shannon-claude-code-cli', 'Shannon (Claude Code CLI)', 'Shannon MCP is a comprehensive MCP server implementation for Claude Code CLI built using an innovative multi-agent collaborative system where 26 specialized AI agents work together to implement the entire server specification. The implementation provides automatic Claude Code binary discovery, real-time JSONL session management with backpressure handling, Git-like checkpoint system for session state management, extensible hooks framework for event-driven automation, analytics engine for usage tracking, and system-wide process registry for resource monitoring. Designed for developers who need advanced Claude Code integration with features like multi-agent task coordination, session branching and restoration, and comprehensive monitoring capabilities that go beyond basic MCP server functionality.', '@krzemienski', 'development', 'Unknown', 2, 'https://github.com/krzemienski/shannon-mcp', NULL, 0, 'https://github.com/krzemienski.png?size=128', '2026-03-09T05:21:02.017862+00:00'),
  ('google-cloud', 'Google Cloud', 'Google Cloud MCP Server connects AI assistants to Google Cloud services, providing context and tools for interacting with Google Cloud resources. Built by Kristof Kowalski, it currently supports Google Cloud Logging for querying and filtering log entries, Cloud Spanner for executing SQL queries and exploring database schemas, and Cloud Monitoring for retrieving and analyzing metrics. The server authenticates with Google Cloud using either a service account key file or environment variables, and includes lazy authentication loading to prevent timeouts during initialization. It''s designed for deployment with Smithery and is ideal for workflows requiring direct access to Google Cloud resources within AI conversations.', '@krzko', 'databases', 'Unknown', 76, 'https://github.com/krzko/google-cloud-mcp', 'google-cloud-mcp', 4991, 'https://github.com/krzko.png?size=128', '2026-03-09T05:21:02.017875+00:00'),
  ('xcode-documentation', 'Xcode Documentation', 'Provides direct access to Apple developer documentation and SDK symbols from local Xcode installations on macOS. Leverages Spotlight search, SDK headers, and swift-symbolgraph-extract to enable documentation searches, detailed symbol information retrieval, framework discovery, and public symbol extraction from Apple frameworks. Particularly useful for iOS/macOS developers who need quick access to API documentation, symbol definitions, and framework exploration without leaving their development environment.', '@krzyzanowskim', 'development', 'Unknown', 38, 'https://github.com/krzyzanowskim/xcodedocsmcp', NULL, 0, 'https://github.com/krzyzanowskim.png?size=128', '2026-03-09T05:21:02.017901+00:00'),
  ('sound-notification', 'Sound Notification', 'A sound notification MCP server that plays audio alerts when AI assistants need user attention. It integrates with Cursor and Windsurf development environments, triggering sounds at key interaction points like when user approval is needed or when tasks are completed. The implementation uses the play-sound library to handle audio playback across different platforms, making it useful for developers who want clear audio cues during AI-assisted workflows without having to constantly monitor the interface.', '@ks0318-p', 'development', 'Unknown', 2, 'https://github.com/ks0318-p/sound-notification-mcp', 'sound-mcp', 470, 'https://github.com/ks0318-p.png?size=128', '2026-03-09T05:21:02.017928+00:00'),
  ('skolverket', 'Skolverket', 'MCP server providing access to Skolverket''s (Swedish National Agency for Education) open APIs. Integrates three official data sources: Syllabus API for curricula and achievement requirements, School Unit Registry for searching educational institutions, and Planned Educations API for vocational training and adult education programs. Enables AI assistants to query Swedish education data including course plans, school information, and capacity data.', '@isakskogstad', 'ai-ml', 'Unknown', 9, 'https://github.com/isakskogstad/skolverket-mcp', NULL, 0, 'https://github.com/isakskogstad.png?size=128', '2026-03-09T05:21:02.017962+00:00'),
  ('image-dimensions', 'Image Dimensions', 'Image Tools MCP provides a service for retrieving image dimensions from both URL and local file sources, with additional image compression capabilities through the Tinify API. Developed by kshern, this TypeScript implementation uses the probe-image-size library to extract image metadata and exposes these capabilities through a Model Context Protocol interface. The server is designed to run as a standalone service or be integrated as a dependency, making it particularly useful for AI agents that need to analyze or process images without requiring external tools or manual dimension checking.', '@kshern', 'development', 'Unknown', 7, 'https://github.com/kshern/image-tools-mcp', NULL, 0, 'https://github.com/kshern.png?size=128', '2026-03-09T05:21:02.018050+00:00'),
  ('discord-notification', 'Discord Notification', 'Discord notification MCP server by kstonekuan that enables AI assistants to send messages directly to Discord channels through webhook integration. The implementation provides a simple tool for posting notifications, alerts, or updates to Discord servers, making it useful for automated reporting, system monitoring alerts, or bridging AI conversations with Discord communities. Designed for users who want to integrate their AI workflows with Discord communication without manual message posting.', '@kstonekuan', 'communication', 'Unknown', 8, 'https://github.com/kstonekuan/discord-notification-mcp', NULL, 0, 'https://github.com/kstonekuan.png?size=128', '2026-03-09T05:21:02.018107+00:00'),
  ('telegram-bot-api', 'Telegram Bot API', 'Telegram notification MCP server developed by kstonekuan that enables AI assistants to send messages and notifications directly through Telegram''s Bot API. The implementation allows for automated messaging workflows where AI agents can deliver alerts, updates, or responses to users via Telegram channels or direct messages, making it useful for monitoring systems, automated reporting, or creating conversational bots that need to reach users on the popular messaging platform.', '@kstonekuan', 'communication', 'Unknown', 20, 'https://github.com/kstonekuan/telegram-notification-mcp', NULL, 0, 'https://github.com/kstonekuan.png?size=128', '2026-03-09T05:21:02.018136+00:00'),
  ('ephor-collaboration', 'Ephor Collaboration', 'An MCP server that facilitates collaborative debates between multiple AI agents, enabling them to discuss and reach consensus on user prompts. Built with Node.js and TypeScript, it manages multi-turn conversations through a session-based architecture where participants can register, submit responses, and view other contributions in real-time. The server provides tools for participant registration, response submission, and session status checking, making it ideal for scenarios requiring deliberative consensus among AI agents like the ''Council of Ephors'' use case.', '@kstrikis', 'development', 'Unknown', 1, 'https://github.com/kstrikis/ephor-mcp-collaboration', NULL, 0, 'https://github.com/kstrikis.png?size=128', '2026-03-09T05:21:02.018164+00:00'),
  ('llm-responses', 'LLM Responses', 'The LLM Responses MCP Server enables multiple AI agents to share and read each other''s responses to the same prompt, facilitating collaborative analysis and reflection. Built with TypeScript using the Model Context Protocol SDK, it provides two main tools: ''submit-response'' for LLMs to submit their answers to a prompt, and ''get-responses'' to retrieve all responses from other LLMs for a specific question. The implementation includes Docker configuration for easy deployment to EC2 instances and uses Bun as its JavaScript runtime. This server is particularly valuable for scenarios where multiple AI agents need to analyze the same problem and learn from each other''s perspectives.', '@kstrikis', 'cloud', 'Unknown', 2, 'https://github.com/kstrikis/ephor-mcp', NULL, 0, 'https://github.com/kstrikis.png?size=128', '2026-03-09T05:21:02.018188+00:00'),
  ('smcp-proxy-oidc', 'SMCP Proxy (OIDC)', 'SMCP-Proxy is a secure reverse proxy for MCP servers that provides authentication and authorization via OIDC. Developed by Kirill Sysoev, it features both server and client components: the server validates OIDC tokens and forwards authenticated requests to configured MCP backends (supporting both HTTP and local subprocess backends), while the client implements client credentials flow to acquire tokens automatically. The implementation supports multiple backend configurations with path-based routing, model information endpoints, and metrics collection. This proxy is particularly valuable for organizations needing to add authentication layers to existing MCP implementations or managing access to multiple AI models through a unified, secure interface.', '@ksysoev', 'ai-ml', 'Unknown', 2, 'https://github.com/ksysoev/smcp-proxy', NULL, 0, 'https://github.com/ksysoev.png?size=128', '2026-03-09T05:21:02.018237+00:00'),
  ('kubernetes-audit-logs', 'Kubernetes Audit Logs', 'A Go-based MCP server that provides unified access to Kubernetes audit logs across multiple cloud providers including Alibaba Cloud SLS, AWS CloudWatch Logs, and Google Cloud Logging. Built by mozillazg with a provider-agnostic architecture, it offers three core tools for listing clusters, discovering common resource types, and querying audit logs with flexible filtering by user, namespace, verbs, resource types, and time ranges. The implementation features intelligent parameter normalization (resource type mapping, verb expansion), configurable cluster management with aliases and defaults, and comprehensive time parsing supporting both absolute timestamps and relative durations. Designed for DevOps teams and security engineers who need to analyze Kubernetes audit trails across hybrid cloud environments without managing separate tooling for each provider.', '@mozillazg', 'cloud', 'Unknown', 19, 'https://github.com/mozillazg/kube-audit-mcp', NULL, 0, 'https://github.com/mozillazg.png?size=128', '2026-03-09T05:21:02.018269+00:00'),
  ('kubernetes-read-only', 'Kubernetes Read-Only', 'This MCP server provides AI assistants with read-only access to Kubernetes clusters through a comprehensive set of tools for resource inspection, log retrieval, and metrics monitoring, built using Go with the Kubernetes client-go library and supporting both stdio and SSE transport modes. The implementation offers 10 tools including resource listing with filtering, detailed resource inspection, advanced pod log retrieval with grep patterns and time filtering, API resource discovery, context management, node and pod metrics collection, and base64 encoding utilities, all while maintaining strict read-only security to prevent destructive operations. Built with automatic connectivity validation, per-command context switching, and client-side pagination for metrics, it serves DevOps teams needing AI-assisted cluster troubleshooting, developers requiring safe cluster inspection capabilities, and organizations wanting to enable AI assistants to help diagnose Kubernetes issues without modification risks.', '@patrickdappollonio', 'cloud', 'Unknown', 13, 'https://github.com/patrickdappollonio/mcp-kubernetes-ro', NULL, 0, 'https://github.com/patrickdappollonio.png?size=128', '2026-03-09T05:21:02.018299+00:00'),
  ('kubesphere', 'KubeSphere', 'KubeSphere MCP Server provides integration with KubeSphere APIs, enabling AI assistants to interact with KubeSphere resources through four tool modules: Workspace Management, Cluster Management, User and Roles, and Extensions Center. Built using Go and the mcp-go library, it supports both stdio and SSE server modes, handles authentication with KubeSphere''s API server, and implements pagination for resource listings. The server is particularly valuable for KubeSphere administrators who need to query and manage their Kubernetes clusters, workspaces, projects, and applications through natural language interfaces without navigating KubeSphere''s web console.', '@kubesphere', 'cloud', 'Unknown', 12, 'https://github.com/kubesphere/ks-mcp-server', NULL, 0, 'https://github.com/kubesphere.png?size=128', '2026-03-09T05:21:02.018322+00:00'),
  ('kubit', 'Kubit', 'Integrates with Kubit''s warehouse-native analytics platform to enable conversational data analysis. Query, analyze, and explore your data warehouse through natural language without requiring complex syntax. Provides tools for creating reports, exploring schemas, analyzing conversion funnels, examining user behavior, and exporting raw data in CSV format. Works directly with your existing data warehouse infrastructure.', '@kubit-ai', 'search', 'Unknown', 0, 'https://github.com/kubit-ai/mcp-server', NULL, 0, 'https://github.com/kubit-ai.png?size=128', '2026-03-09T05:21:02.018361+00:00'),
  ('binance-alpha', 'Binance Alpha', 'An MCP server for tracking Binance Alpha trades to help AI agents optimize alpha point accumulation by monitoring real-time buy-side activity for Binance Alpha tokens on the Binance Smart Chain. The implementation subscribes to on-chain OrderRecord events from the Binance DEX router, calculates trade values in USD using CryptoCompare price feeds, and maintains trade data in memory with automatic cleanup of records older than one hour. It provides two tools: get_top_tokens returns a markdown table of top tokens by USD trading volume, and get_trade_stats provides trade statistics including min/max/median values and distribution analysis, making it valuable for cryptocurrency trading analysis, alpha point optimization strategies, and building AI assistants that need programmatic access to Binance Alpha trading activity.', '@kukapay', 'development', 'Unknown', 7, 'https://github.com/kukapay/binance-alpha-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.018440+00:00'),
  ('bridge-metrics-defillama', 'Bridge Metrics (DeFiLlama)', 'This MCP server provides real-time cross-chain bridge metrics and analytics by integrating with DeFiLlama''s bridge APIs, enabling AI agents to analyze liquidity flows, transaction volumes, and performance across blockchain networks. Built by kukapay with Python and FastMCP, it offers tools for listing chains sorted by TVL, retrieving bridge data with 24-hour volume rankings, fetching historical volume data with formatted timestamps, analyzing daily token statistics with USD valuations, and accessing transaction summaries with filtering capabilities. The implementation features tabulated data presentation, comprehensive bridge ecosystem coverage, and specialized prompts for volume analysis and bridge comparisons, making it valuable for DeFi researchers, traders, and analysts who need programmatic access to cross-chain bridge performance data and automated insights into blockchain interoperability trends.', '@kukapay', 'ai-ml', 'Unknown', 2, 'https://github.com/kukapay/bridge-metrics-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.018496+00:00'),
  ('bsc-multisend', 'BSC MultiSend', 'BSC MultiSend MCP server by kukapay that enables AI assistants to distribute BNB and ERC20 tokens to multiple recipients on Binance Smart Chain using the C98MultiSend contract. The implementation provides two core tools: distributeNative for sending BNB to multiple addresses in a single transaction, and distributeToken for distributing ERC20 tokens with automatic decimal handling and allowance management. Built with ethers.js and comprehensive error handling, it automatically estimates gas costs, handles token approvals when needed, and validates all addresses and amounts before execution, making it useful for airdrops, batch payments, reward distributions, and any scenario requiring efficient multi-recipient cryptocurrency transfers on BSC.', '@kukapay', 'ai-ml', 'Unknown', 1, 'https://github.com/kukapay/bsc-multisend-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.018546+00:00'),
  ('bybit-announcements', 'Bybit Announcements', 'Connects to Bybit''s public announcements API to retrieve cryptocurrency exchange announcements with comprehensive filtering capabilities. Supports filtering by locale, announcement type, and content tags with configurable pagination up to 50 results per request. Formats announcement data including timestamps, descriptions, and URLs into readable markdown output for easy consumption by AI agents. Useful for monitoring new cryptocurrency listings, trading updates, maintenance notifications, and other exchange-related announcements for trading automation, market analysis, or staying informed about Bybit platform changes.', '@kukapay', 'ai-ml', 'Unknown', 1, 'https://github.com/kukapay/bybit-announcements-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.018592+00:00'),
  ('crypto-fear-greed-index', 'Crypto Fear & Greed Index', 'Crypto Fear & Greed Index MCP Server provides real-time and historical cryptocurrency market sentiment data through integration with Alternative.me''s Fear & Greed Index API. Built by kukapay using the FastMCP framework, it offers resources and tools to fetch current index values, historical data, and trend analysis, making it easy for Claude Desktop and other MCP-compatible clients to incorporate market sentiment indicators into conversations. The implementation is particularly valuable for cryptocurrency investors and analysts who want to gauge market psychology and potential price movements without leaving their AI assistant interface.', '@kukapay', 'ai-ml', 'Unknown', 53, 'https://github.com/kukapay/crypto-feargreed-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.018640+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('crypto-indicators', 'Crypto Indicators', 'Crypto Indicators MCP Server provides AI trading agents with access to over 50 technical analysis indicators and trading strategies for cryptocurrency markets. Built on the Model Context Protocol, it fetches real-time OHLCV data from Binance (configurable to any CCXT-supported exchange) and calculates trend, momentum, volatility, and volume indicators. Each tool returns either raw indicator values or actionable trading signals (-1 for sell, 0 for hold, 1 for buy), enabling AI agents to analyze market conditions and develop quantitative trading strategies without implementing complex technical analysis algorithms themselves.', '@kukapay', 'development', 'Unknown', 112, 'https://github.com/kukapay/crypto-indicators-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.018666+00:00'),
  ('crypto-orderbook', 'Crypto Orderbook', 'An MCP server that analyzes order book depth and imbalance across major cryptocurrency exchanges including Binance, Kraken, Coinbase, Bitfinex, OKX, and Bybit. Built with Python using the CCXT library for exchange connectivity and pandas for data processing, it provides two core tools: calculating bid/ask depth and imbalance metrics for specific trading pairs on individual exchanges, and comparing these metrics across multiple exchanges in unified markdown tables. Designed for AI agents and trading systems that need real-time market structure insights, with configurable depth percentage ranges and robust error handling for exchange API interactions.', '@kukapay', 'ai-ml', 'Unknown', 15, 'https://github.com/kukapay/crypto-orderbook-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.018712+00:00'),
  ('cryptopanic', 'CryptoPanic', 'The cryptopanic-mcp-server provides AI agents with real-time cryptocurrency news from CryptoPanic. Built for Python 3.13, it implements a single tool that fetches news, analysis, or video content with configurable pagination. The server requires a CryptoPanic API key and is designed to be run using the UV package manager. This implementation by kukapay enables AI assistants to stay current on cryptocurrency developments, making it valuable for financial analysis, market research, and investment decision support where timely crypto information is needed.', '@kukapay', 'development', 'Unknown', 68, 'https://github.com/kukapay/cryptopanic-mcp-server', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.018736+00:00'),
  ('crypto-rss', 'Crypto RSS', 'Crypto RSS MCP server by kukapay that aggregates real-time cryptocurrency news from multiple RSS feeds, helping AI agents make informed decisions in fast-paced crypto markets. The implementation provides tools for listing available feeds from a curated OPML file sourced from Chainfeeds, fetching and formatting RSS content as Markdown with HTML-to-text conversion, and filtering feeds by keywords across descriptions and categories. Built with Python using FastMCP, feedparser, and html2text libraries, it includes a prompt template for analyzing feed content to identify market trends and summarize key points, making it valuable for crypto traders, analysts, and AI assistants requiring structured access to cryptocurrency news aggregation and market sentiment analysis.', '@kukapay', 'ai-ml', 'Unknown', 13, 'https://github.com/kukapay/crypto-rss-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.018783+00:00'),
  ('crypto-sentiment-santiment', 'Crypto Sentiment (Santiment)', 'Crypto Sentiment MCP Server delivers cryptocurrency sentiment analysis to AI agents by leveraging Santiment''s aggregated social media and news data. Developed by kukapay, this server exposes five key tools that enable agents to retrieve sentiment balance for specific cryptocurrencies, monitor social media mentions, detect significant volume shifts, identify trending discussion topics, and measure an asset''s dominance in crypto conversations. The implementation uses FastMCP and the Santiment API to fetch and process time-series data, making it particularly valuable for traders, analysts, and researchers who need real-time insights into market mood and emerging trends without leaving their AI assistant interface.', '@kukapay', 'ai-ml', 'Unknown', 48, 'https://github.com/kukapay/crypto-sentiment-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.018840+00:00'),
  ('crypto-stocks', 'Crypto Stocks', 'Crypto Stocks MCP server that tracks real-time data for major crypto-related stocks to help AI agents analyze blockchain investment opportunities. Built by kukapay, the implementation uses yfinance for market data and tabulate for formatted output, providing tools to list crypto-related stocks (including Coinbase, MicroStrategy, Marathon Digital Holdings), fetch real-time prices with timestamps, and retrieve historical price data over specified time periods. The server focuses specifically on publicly traded companies with cryptocurrency exposure rather than direct crypto assets, making it valuable for traditional equity analysis of the blockchain sector and investment research comparing crypto-adjacent stocks.', '@kukapay', 'development', 'Unknown', 3, 'https://github.com/kukapay/crypto-stocks-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.018880+00:00'),
  ('dex-k-line-geckoterminal', 'DEX K-line (GeckoTerminal)', 'DEX K-line MCP server by kukapay that streams OHLCV (Open, High, Low, Close, Volume) candlestick data from decentralized exchanges through the GeckoTerminal API, supporting Ethereum, Binance Smart Chain, and Solana networks. The implementation automatically selects the highest liquidity pools for accurate pricing data and supports multiple timeframes from 1-minute to daily intervals, with flexible end time specification and tabular output formatting using the tabulate library. Designed for AI assistants requiring real-time cryptocurrency market data for trading analysis, price monitoring, and DeFi market research workflows where accurate DEX pricing information is essential for decision-making.', '@kukapay', 'ai-ml', 'Unknown', 4, 'https://github.com/kukapay/dex-kline-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.018932+00:00'),
  ('dex-metrics-dune-analytics', 'DEX Metrics (Dune Analytics)', 'The DEX Metrics MCP server provides trading volume analytics for decentralized exchanges by integrating with Dune Analytics APIs. Built by kukapay, it exposes ten specialized tools that retrieve and format trading volume data across multiple dimensions including DEX platforms, blockchain networks, aggregators, frontends, and Telegram bots, with support for daily, weekly, monthly, and year-over-year analysis. The server automatically formats results as markdown tables using pandas DataFrames, making it particularly valuable for DeFi research, market analysis, and tracking trading activity trends across the decentralized finance ecosystem.', '@kukapay', 'communication', 'Unknown', 1, 'https://github.com/kukapay/dex-metrics-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.018967+00:00'),
  ('dexscreener', 'DexScreener', 'MCP server built by kukapay that tracks and analyzes DEX liquidity pools using the DexScreener API to power intelligent DeFi agents and automated trading strategies. The implementation fetches comprehensive liquidity pool data for specified blockchain networks and token addresses, presenting results in structured markdown tables with key metrics including DEX ID, pair addresses, token symbols, USD prices, 24-hour transaction volumes, liquidity amounts, and market capitalizations, along with calculated total liquidity across all pools. Designed for DeFi applications requiring real-time liquidity analysis, automated trading bots that need pool depth information, and financial analysts monitoring decentralized exchange activity across multiple blockchain networks.', '@kukapay', 'ai-ml', 'Unknown', 2, 'https://github.com/kukapay/liquidity-pools-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019018+00:00'),
  ('ethereum-improvement-proposals-eips', 'Ethereum Improvement Proposals (EIPs)', 'EIPs MCP server by kukapay that provides AI assistants with semantic search capabilities across Ethereum Improvement Proposals (EIPs) using vector embeddings and LanceDB for efficient document retrieval. The implementation uses the agno framework with FastEmbed embeddings to process EIP markdown files from the official Ethereum EIPs repository, chunking documents into 5000-character segments for optimal search performance and returning up to 5 relevant document chunks with clear separators for each query. Built for developers, researchers, and AI assistants who need contextual access to EIP documentation for understanding Ethereum protocol changes, smart contract standards, and blockchain development patterns without manually browsing through hundreds of proposal documents.', '@kukapay', 'development', 'Unknown', 2, 'https://github.com/kukapay/eips-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019085+00:00'),
  ('ens', 'ENS', 'ENS MCP Server resolves, analyzes, and contextualizes ENS domain activity to empower Web3 agents with human-readable identity insights. Built by kukapay, the implementation integrates with The Graph''s ENS subgraph to provide three core tools: resolve_ens_name for mapping ENS domains to Ethereum addresses, get_domain_details for comprehensive domain information including ownership, registration, and resolver data, and get_domain_events for retrieving domain history like transfers and resolver changes. Designed for Web3 applications that need to translate between human-readable ENS names and blockchain addresses, making it valuable for wallet interfaces, DeFi protocols, and blockchain analytics tools that want to provide user-friendly domain resolution without directly managing GraphQL queries to ENS infrastructure.', '@kukapay', 'ai-ml', 'Unknown', 1, 'https://github.com/kukapay/ens-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019135+00:00'),
  ('etf-flow-coinglass', 'ETF Flow (CoinGlass)', 'This MCP server provides crypto ETF flow data from the CoinGlass API, enabling AI assistants to retrieve and analyze historical Bitcoin and Ethereum ETF fund flows in structured markdown tables. Built by kukapay using Python with FastMCP, pandas, and httpx, it features a unified tool that dynamically fetches ETF flow data for BTC or ETH, formats results using pivot tables with ETF tickers as columns and dates as rows, includes total flow calculations, and provides prompt guidance for streamlined LLM interactions. The implementation uses the CoinGlass API for real-time financial data access and presents information in user-friendly markdown tables sorted by date in descending order, making it valuable for cryptocurrency market analysis, ETF performance tracking, and financial decision-making workflows that require current fund flow insights.', '@kukapay', 'ai-ml', 'Unknown', 8, 'https://github.com/kukapay/etf-flow-mcp', 'etf-flow-mcp', 1033, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019189+00:00'),
  ('freqtrade', 'Freqtrade', 'Freqtrade-MCP provides a bridge between AI assistants and the Freqtrade cryptocurrency trading bot via its REST API. The server exposes tools for monitoring market data, managing trades, configuring bot behavior, and analyzing performance metrics. Built with FastMCP and asynchronous processing, it features robust error handling and detailed logging while maintaining secure access through configurable authentication. This implementation is particularly valuable for crypto traders who want to monitor and control their Freqtrade bots through natural language interaction without switching interfaces.', '@kukapay', 'ai-ml', 'Unknown', 108, 'https://github.com/kukapay/freqtrade-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019230+00:00'),
  ('honeypot-detector', 'Honeypot Detector', 'MCP server by kukapay that detects potential honeypot tokens on Ethereum, BNB Smart Chain, and Base networks using the honeypot.is API. The implementation provides a single tool that validates token contract addresses and returns detailed analysis including honeypot status, risk level, buy/sell/transfer taxes, and contract open-source verification in markdown format. Built with FastMCP and httpx for async HTTP requests, it serves traders and DeFi users who need to quickly verify token legitimacy before investing, helping identify fraudulent smart contracts that allow token purchases but prevent or restrict selling.', '@kukapay', 'development', 'Unknown', 2, 'https://github.com/kukapay/honeypot-detector-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019261+00:00'),
  ('jupiter-ultra', 'Jupiter Ultra', 'Jupiter MCP Server provides a bridge to Jupiter''s Ultra API for executing token swaps on the Solana blockchain. It exposes two key tools: one for fetching optimal swap orders that combine DEX routing and RFQ (Request for Quote) pricing, and another for executing these swaps with proper handling of slippage, priority fees, and transaction landing. The implementation uses the Solana Web3.js library to sign transactions with a private key before submitting them to Jupiter''s API, making it valuable for applications that need to perform programmatic token swaps with competitive pricing on Solana.', '@kukapay', 'ai-ml', 'Unknown', 23, 'https://github.com/kukapay/jupiter-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019303+00:00'),
  ('memecoin-radar-dune-analytics', 'Memecoin Radar (Dune Analytics)', 'Real-time memecoin radar MCP server built by kukapay that provides AI assistants with comprehensive Solana memecoin market intelligence through integration with Dune Analytics API. The implementation offers eight specialized tools for tracking trending tokens across platforms (Telegram, Web, Mobile), monitoring Pump.fun graduates by market cap and trading volume, analyzing KOL (Key Opinion Leader) trading activity and recent purchases, and retrieving high-volume tokens on Raydium and PumpSwap exchanges with customizable time spans. Built using FastMCP with tabulated output formatting, the server serves crypto traders needing real-time memecoin trends, analysts tracking influencer activity in the Solana ecosystem, and developers building applications that require structured access to decentralized exchange data and social trading signals.', '@kukapay', 'development', 'Unknown', 1, 'https://github.com/kukapay/memecoin-radar-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019335+00:00'),
  ('nearby-places', 'Nearby Places', 'NearbySearch MCP Server provides location-based place discovery by combining IP-based location detection with Google Places API integration. It offers a single tool endpoint that determines the user''s current location using ipapi.co and then searches for nearby places based on keywords, with options to filter by place type and customize the search radius. Ideal for users who need to quickly find local businesses, restaurants, or services without manually entering location coordinates.', '@kukapay', 'search', 'Unknown', 22, 'https://github.com/kukapay/nearby-search-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019382+00:00'),
  ('opc-ua', 'OPC UA', 'OPC UA MCP server that connects to industrial automation systems and exposes their data points through a standardized interface. Built with FastMCP and asyncua, it provides tools for reading and writing OPC UA node values while handling connection lifecycle management. Particularly valuable for industrial automation engineers and system integrators who need to monitor and control OPC UA-enabled devices through AI assistants.', '@kukapay', 'ai-ml', 'Unknown', 23, 'https://github.com/kukapay/opcua-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019418+00:00'),
  ('pancakeswap-poolspy', 'PancakeSwap PoolSpy', 'PancakeSwap PoolSpy is an MCP server that tracks newly created liquidity pools on PancakeSwap''s decentralized exchange. Built with Python and leveraging The Graph API, it provides real-time data on pools created within customizable time ranges, including detailed metrics like token pairs, creation timestamps, transaction counts, volume, and total value locked. This tool is particularly valuable for DeFi analysts, traders, and developers who need immediate visibility into emerging trading opportunities or want to monitor market activity on the BNB Smart Chain without leaving their conversation interface.', '@kukapay', 'ai-ml', 'Unknown', 7, 'https://github.com/kukapay/pancakeswap-poolspy-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019460+00:00'),
  ('the-graph', 'The Graph', 'TheGraph MCP Server enables AI agents to access indexed blockchain data through The Graph''s decentralized network. Built with Python 3.13, it provides two key tools: getSubgraphSchema for fetching GraphQL schemas of specified subgraphs, and querySubgraph for executing GraphQL queries against blockchain data. The implementation handles API authentication, GraphQL introspection, and response formatting, making it particularly valuable for analyzing token trading volumes, monitoring liquidity pools, or identifying unusual blockchain transaction patterns without requiring deep technical knowledge of GraphQL or blockchain data structures.', '@kukapay', 'ai-ml', 'Unknown', 8, 'https://github.com/kukapay/thegraph-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019501+00:00'),
  ('token-minter', 'Token Minter', 'Token Minter MCP enables AI assistants to deploy and interact with ERC-20 tokens across multiple blockchain networks. Built by kukapay, it provides tools for deploying custom tokens with configurable parameters, querying token information, checking balances, and transferring tokens. The server leverages ethers.js and a SimpleERC20 smart contract to interact with various EVM-compatible chains including Ethereum, Polygon, BSC, and others. This implementation is particularly valuable for blockchain workflows where users need to create and manage tokens without leaving their conversation interface.', '@kukapay', 'ai-ml', 'Unknown', 18, 'https://github.com/kukapay/token-minter-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019541+00:00'),
  ('token-revoke', 'Token Revoke', 'Token Revoke MCP provides a multi-chain solution for managing and revoking ERC20 token allowances, helping users protect their assets from potential security risks. Built with the Model Context Protocol SDK, it integrates with Moralis API to fetch token approvals across 40+ blockchain networks and uses ethers.js to execute revocation transactions. The server offers three main tools: fetching all token approvals for a wallet, revoking specific allowances, and checking transaction status - making it valuable for crypto users who need to audit and control which protocols have permission to spend their tokens.', '@kukapay', 'ai-ml', 'Unknown', 3, 'https://github.com/kukapay/token-revoke-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019583+00:00'),
  ('tornado-cash', 'Tornado Cash', 'MCP server that tracks Tornado Cash deposits and withdrawals to reveal hidden asset trails and wallet interactions by querying The Graph''s Tornado Cash Subgraph. Built by kukapay using Python with FastMCP, the implementation provides two core tools for querying the latest deposit events (including sender address, amount, block number, timestamp, and commitment) and withdrawal events (including recipient address, amount, block number, and timestamp), with results formatted as readable tables using tabulate. Designed for blockchain analysts, compliance teams, and researchers investigating cryptocurrency mixing services and tracing obfuscated transaction flows through Tornado Cash''s privacy protocol.', '@kukapay', 'development', 'Unknown', 3, 'https://github.com/kukapay/tornado-cash-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019612+00:00'),
  ('uniswap-poolspy', 'Uniswap PoolSpy', 'Uniswap PoolSpy MCP Server tracks newly created liquidity pools on Uniswap V3 across nine blockchain networks including Ethereum, Base, Optimism, and others. Built by kukapay, it leverages TheGraph API to query subgraphs for each network, allowing users to retrieve pools created within a specified time range and sort them by various metrics like transaction count, volume, or TVL. The implementation provides a single tool that returns detailed information about each pool including token pairs, creation timestamp, transaction count, and USD values, making it valuable for cryptocurrency traders, researchers, and developers who need real-time data on emerging liquidity opportunities across multiple chains.', '@kukapay', 'ai-ml', 'Unknown', 7, 'https://github.com/kukapay/uniswap-poolspy-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019660+00:00'),
  ('uniswap-trader', 'Uniswap Trader', 'Uniswap Trader MCP enables AI agents to execute cryptocurrency trading strategies across multiple blockchains through the Uniswap decentralized exchange. The implementation provides tools for getting price quotes and executing swaps with optimal multi-hop routing, supporting various EVM-compatible networks including Ethereum, Optimism, Polygon, Arbitrum, Celo, BNB Chain, Avalanche, and Base. It handles native token conversions, slippage tolerance settings, and transaction management with proper error handling, making it particularly valuable for automated trading, portfolio rebalancing, and liquidity provision without leaving the conversation interface.', '@kukapay', 'ai-ml', 'Unknown', 34, 'https://github.com/kukapay/uniswap-trader-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019704+00:00'),
  ('wallet-inspector-dune-analytics', 'Wallet Inspector (Dune Analytics)', 'Wallet Inspector MCP server provides blockchain wallet analysis capabilities by integrating with Dune Analytics'' SIM API to query wallet balances, transaction history, and activity across both EVM chains (Ethereum, Polygon, BSC) and Solana. Built by kukapay, the implementation automatically detects wallet address formats and routes queries to the appropriate blockchain endpoints, returning formatted data including token amounts, USD values, transaction details, and activity summaries. Designed for crypto analysts, traders, and developers who need programmatic access to multi-chain wallet data without managing separate blockchain RPC connections or parsing raw transaction data, enabling conversational wallet investigation and portfolio tracking across major blockchain networks.', '@kukapay', 'ai-ml', 'Unknown', 8, 'https://github.com/kukapay/wallet-inspector-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019763+00:00'),
  ('web3-career', 'Web3 Career', 'This MCP server provides access to Web3 job listings from the web3.career API, enabling AI assistants to search and filter cryptocurrency and blockchain job opportunities with parameters like remote work preferences, country, and technology tags. Built by kukapay using Python with FastMCP and httpx, it fetches job data including titles, companies, locations, remote status, publication dates, and application URLs, with HTML description cleaning and configurable result limits up to 100 jobs per query. The implementation includes a search prompt generator for role-based queries and returns structured Markdown-formatted job listings, making it valuable for job seekers in the Web3 space, recruiters looking for blockchain talent, and career guidance workflows focused on decentralized technology opportunities.', '@kukapay', 'ai-ml', 'Unknown', 6, 'https://github.com/kukapay/web3-jobs-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019816+00:00'),
  ('whale-tracker', 'Whale Tracker', 'The Whale Tracker MCP server provides real-time monitoring of cryptocurrency whale transactions using the Whale Alert API. Built with Python 3.13 and the FastMCP framework, it offers tools to fetch recent large-value transactions across blockchains, retrieve detailed transaction information, and access blockchain-specific transaction data through resource endpoints. The implementation includes configurable parameters for transaction value thresholds and blockchain filtering, with comprehensive error handling for API interactions. This server is particularly valuable for cryptocurrency traders, analysts, and researchers who need to monitor significant market movements and identify patterns in whale behavior without leaving their AI assistant interface.', '@kukapay', 'ai-ml', 'Unknown', 50, 'https://github.com/kukapay/whale-tracker-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019876+00:00'),
  ('world-time', 'World Time', 'WhatTimeIsIt MCP Server is a lightweight implementation that provides the current time based on the client''s IP location using the World Time API. Built with Python 3.13 and the FastMCP framework, it offers a single tool that returns the current time in ISO 8601 format, making it useful for applications that need accurate time information without maintaining their own time synchronization. The server requires minimal configuration and can be easily integrated into existing MCP client setups through a simple command-line interface.', '@kukapay', 'ai-ml', 'Unknown', 8, 'https://github.com/kukapay/whattimeisit-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019913+00:00'),
  ('whereami-ip-geolocation', 'WhereAmI (IP Geolocation)', 'WhereAmI-MCP provides geolocation data based on the user''s IP address through integration with the ipapi.co API. Built with Python using the FastMCP framework, it offers both a resource endpoint for retrieving specific location details (like country, city, coordinates) and a comprehensive tool that returns formatted location information in a Markdown table. The implementation is lightweight, requiring only httpx for API requests, and is particularly useful for workflows where knowing a user''s geographical context enhances the conversation experience without requiring manual location input.', '@kukapay', 'ai-ml', 'Unknown', 4, 'https://github.com/kukapay/whereami-mcp', NULL, 0, 'https://github.com/kukapay.png?size=128', '2026-03-09T05:21:02.019958+00:00'),
  ('paypal-java', 'PayPal Java', 'This PayPal Java MCP server implementation provides tools for analyzing and improving payment processing, including authorization rate analysis and a basic calculator. It supports both REST API and JSON-RPC over stdio interfaces, making it versatile for web clients and Smithery integration. The server is containerized with Docker support, facilitating easy deployment and scalability for various payment processing use cases.', '@kumartheashwani', 'cloud', 'Unknown', 0, 'https://github.com/kumartheashwani/paypal-java-mcp-server', NULL, 0, 'https://github.com/kumartheashwani.png?size=128', '2026-03-09T05:21:02.019978+00:00'),
  ('google-patents-serpapi', 'Google Patents (SerpAPI)', 'A Model Context Protocol (MCP) server implementation for Google Patents, allowing AI assistants to search and retrieve patent information.', '@kunihiros', 'ai-ml', 'Unknown', 28, 'https://github.com/kunihiros/google-patents-mcp', '@kunihiros/google-patents-mcp', 1490, 'https://github.com/kunihiros.png?size=128', '2026-03-09T05:21:02.020002+00:00'),
  ('chain-of-recursive-thoughts', 'Chain-of-Recursive-Thoughts', 'The CoRT MCP Server implements Chain-of-Recursive-Thoughts methodology that enhances AI reasoning by making models argue with themselves repeatedly across multiple rounds. Developed by KunihiroS based on PhialsBasement''s original work, it features multi-LLM inference that randomly selects different models for each alternative response, enhanced evaluation prompts, and detailed logging capabilities. The server integrates with OpenAI and OpenRouter APIs, supporting various LLMs including GPT-4, Llama, Gemini, and Mistral models. It''s particularly valuable for complex problem-solving scenarios where deeper, more thorough reasoning is required to generate optimal responses.', '@kunihiros', 'ai-ml', 'Unknown', 6, 'https://github.com/kunihiros/cort-mcp', 'cort-mcp', 3477, 'https://github.com/kunihiros.png?size=128', '2026-03-09T05:21:02.020050+00:00'),
  ('key-value-extractor', 'Key-Value Extractor', 'The Flexible Key-Value Extraction MCP Server extracts structured key-value pairs from unstructured or noisy text using a multi-step pipeline powered by GPT-4.1-mini and pydantic-ai. Developed by KunihiroS, it performs language detection and named entity recognition with spaCy before using LLMs for extraction, type annotation, evaluation, and normalization. The server supports Japanese, English, and Chinese inputs, ensures type safety through Pydantic validation, and returns results in JSON, YAML, or TOML formats. It''s particularly valuable for applications requiring information extraction from messy text like emails, receipts, or documents where maintaining proper data types and structure is essential.', '@kunihiros', 'communication', 'Unknown', 1, 'https://github.com/kunihiros/kv-extractor-mcp-server', 'kv-extractor-mcp-server', 3557, 'https://github.com/kunihiros.png?size=128', '2026-03-09T05:21:02.020130+00:00'),
  ('patsnap-patent-analytics', 'PatSnap (Patent Analytics)', 'PatSnap MCP Server provides access to PatSnap''s patent analytics API, enabling AI assistants to retrieve patent trends, keyword analyses, and competitive intelligence. Developed by Kunihiros, this TypeScript implementation handles authentication with the PatSnap API, caches access tokens for efficiency, and transforms complex patent data into structured responses. The server exposes nine specialized tools for analyzing patent landscapes, including trend analysis, word clouds, top inventors/assignees identification, and litigation tracking, making it particularly valuable for technology scouting, competitive analysis, and innovation research workflows.', '@kunihiros', 'development', 'Unknown', 6, 'https://github.com/kunihiros/patsnap-mcp', '@kunihiros/patsnap-mcp', 4708, 'https://github.com/kunihiros.png?size=128', '2026-03-09T05:21:02.020163+00:00'),
  ('uniquity', 'Uniquity', 'Uniquity MCP Server is a bridge that makes UniquityReporter''s code similarity analysis capabilities available through the Model Context Protocol. Developed by KunihiroS, it enables AI agents and external tools to analyze GitHub repositories for code similarities, returning detailed reports in Markdown format. The server separates core logic from interface by depending on the uniquity-reporter npm package, making it maintainable and extensible while providing standardized access to repository analysis functions through well-defined MCP tools.', '@kunihiros', 'development', 'Unknown', 0, 'https://github.com/kunihiros/uniquity-mcp', 'uniquity-mcp', 3886, 'https://github.com/kunihiros.png?size=128', '2026-03-09T05:21:02.020210+00:00'),
  ('github-project-manager', 'GitHub Project Manager', 'This GitHub Project Manager MCP server provides comprehensive tools for managing GitHub projects, milestones, tasks, and sprints through deep integration with GitHub Projects V2. Developed by an unnamed author, it offers features like automated kanban workflows, sprint planning, and custom field management. The TypeScript-based implementation uses the Octokit library for GitHub API interactions and includes robust test coverage. It''s designed for development teams and project managers who want to incorporate AI assistance into their GitHub project workflows, enabling natural language queries and updates for project boards, issues, milestones, and sprints.', '@kunwarvivek', 'development', 'Unknown', 84, 'https://github.com/kunwarvivek/mcp-github-project-manager', NULL, 0, 'https://github.com/kunwarvivek.png?size=128', '2026-03-09T05:21:02.020233+00:00'),
  ('advanced-reasoning-with-deepseek', 'Advanced Reasoning with DeepSeek', 'Advanced Reason MCP is a server implementation that enables AI assistants to leverage structured reasoning capabilities through the deepseek-r1 model. It provides three specialized tools: a deepseek reasoner for analytical thinking and problem decomposition, a reflection tool that evaluates reasoning processes with quality scoring (0.0-1.0), and a sequential thinking tool that supports dynamic problem-solving with branching thoughts. Built with TypeScript and the Ollama API, it processes reasoning requests by extracting structured thinking blocks from model outputs, making it particularly valuable for users who need to solve complex problems requiring step-by-step analysis, critical evaluation, and adaptive reasoning strategies.', '@kuon-dev', 'development', 'Unknown', 33, 'https://github.com/kuon-dev/advanced-reason-mcp', NULL, 0, 'https://github.com/kuon-dev.png?size=128', '2026-03-09T05:21:02.020267+00:00'),
  ('github-repos-manager', 'GitHub Repos Manager', 'This MCP server provides comprehensive GitHub repository management capabilities through the GitHub REST API, built by Sergey Kurdin using Node.js with the Model Context Protocol SDK and node-cache for performance optimization. It offers over 60 tools organized into categories including repository operations (listing, searching, content access), issue and pull request management with comment handling, branch and commit operations, file management with binary upload support, security features (webhooks, deploy keys, secrets), analytics and insights (traffic stats, languages, stargazers), search functionality across issues/commits/code/users, and organization management with team operations. The implementation features intelligent caching for analytics data, configurable tool restrictions, repository access controls, default repository settings, and supports both authenticated user operations and public repository access, making it valuable for developers, project managers, and DevOps teams who need AI-assisted GitHub workflow automation and repository analysis.', '@kurdin', 'development', 'Unknown', 18, 'https://github.com/kurdin/github-repos-manager-mcp', 'github-repos-manager-mcp', 1412, 'https://github.com/kurdin.png?size=128', '2026-03-09T05:21:02.020299+00:00'),
  ('multichat', 'Multichat', 'Multichat MCP Server enables parallel communication with multiple unichat-based MCP servers, allowing users to query different language models simultaneously and compare their responses. It acts as an intermediary that manages client connections to target servers like ''Lacayo 1'' and ''openrouter-chat'', handles message routing, and stores responses in organized directories for later retrieval. The implementation includes robust error handling, connection retry logic, and timeout management, making it particularly valuable for applications that benefit from aggregating responses from multiple AI models without requiring users to manage individual connections.', '@kurror', 'communication', 'Unknown', 1, 'https://github.com/kurror/mcp', NULL, 0, 'https://github.com/kurror.png?size=128', '2026-03-09T05:21:02.020343+00:00'),
  ('code2flow', 'Code2Flow', 'Code2Flow MCP Server provides a FastAPI-based interface that enables AI assistants to generate visual code flow diagrams from source code. By leveraging the code2flow Python library, this server allows agents to analyze code structure, visualize execution paths, and understand program flow without manual diagramming. The implementation includes a client example script demonstrating how to interact with the server, making it particularly useful for code comprehension, documentation generation, and architectural analysis tasks.', '@kursk-ye', 'development', 'Unknown', 3, 'https://github.com/kursk-ye/code2flow-mcp-server', NULL, 0, 'https://github.com/kursk-ye.png?size=128', '2026-03-09T05:21:02.020367+00:00'),
  ('video-editor-ffmpeg', 'Video Editor (FFMpeg)', 'This video editing MCP server, developed by Kush Agrawal, enables AI assistants to perform a wide range of video editing operations using FFmpeg. Built with Python and leveraging the MCP framework, it provides a single powerful tool, ''execute_ffmpeg'', which validates and executes FFmpeg commands with real-time progress tracking. The server supports operations like trimming, merging, format conversion, speed adjustment, audio manipulation, and subtitle addition. By abstracting complex FFmpeg operations into a natural language interface, it allows AI systems to easily manipulate video content. This implementation is particularly useful for automating video editing tasks, content creation, and media processing workflows, making it suitable for applications in video production, social media content generation, and automated video analysis.', '@kush36agrawal', 'productivity', 'Unknown', 46, 'https://github.com/kush36agrawal/video_editor_mcp', NULL, 0, 'https://github.com/kush36agrawal.png?size=128', '2026-03-09T05:21:02.020420+00:00'),
  ('fhir-healthcare-data', 'FHIR Healthcare Data', 'Universal FHIR MCP server implementation by Kushagra Dutta that provides AI assistants with access to multiple FHIR healthcare data servers including HAPI FHIR, Firely Server, and other major vendor endpoints through a unified interface. The implementation features intelligent server switching, clinical keyword extraction using OpenAI GPT-4, fuzzy matching for mapping clinical terms to FHIR codes, and patient similarity search based on age, gender, and medical conditions. Built with enterprise-grade features including vendor-specific query optimization, comprehensive error handling, and caching mechanisms, it serves healthcare developers building clinical decision support tools, researchers analyzing patient cohorts across different FHIR implementations, and AI applications requiring standardized access to diverse healthcare data sources without managing individual server complexities.', '@kushagra-dutta', 'development', 'Unknown', 3, 'https://github.com/kushagra-dutta/fhir-mcp', NULL, 0, 'https://github.com/kushagra-dutta.png?size=128', '2026-03-09T05:21:02.020453+00:00'),
  ('amazon-ads', 'Amazon Ads', 'Amazon Ads MCP Server provides AI assistants with direct access to the Amazon Advertising API through a Model Context Protocol implementation built by KuudoAI. The server features a pluggable authentication architecture supporting both direct Amazon Ads API credentials and OpenBridge OAuth integration, with automatic OpenAPI specification loading that dynamically generates tools for campaign management, reporting, profile handling, and DSP operations. It includes intelligent response shaping for large AMC datasets, server-side LLM sampling fallback when clients don''t support sampling, comprehensive token management with secure storage, and Docker deployment support, making it valuable for advertisers and agencies who need to programmatically manage Amazon advertising campaigns, analyze performance data, and automate reporting workflows through conversational AI interfaces.', '@kuudoai', 'cloud', 'Unknown', 25, 'https://github.com/kuudoai/amazon_ads_mcp', NULL, 0, 'https://github.com/kuudoai.png?size=128', '2026-03-09T05:21:02.020479+00:00'),
  ('kuzu', 'Kuzu', 'An MCP server that enables graph database interactions with Kuzu - an embedded property graph -  allowing users to access and manipulate graph data through natural language commands. 
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('kwrds-ai', 'kwrds.ai', 'MCP server implementation for kwrds.ai''s keyword research and SEO API that provides AI-powered keyword analysis, SERP data, and content generation tools. The implementation exposes comprehensive keyword research capabilities including search volume analysis, competition data, People Also Ask questions, LSI keyword generation, URL ranking analysis, and AI-driven content creation for SEO outlines and meta descriptions. Built with response size limiting and truncation utilities to prevent conversation limits, it''s designed for SEO professionals, content marketers, and developers who need programmatic access to keyword intelligence and search engine optimization data through conversational AI interfaces.', '@mkotsollaris', 'ai-ml', 'Unknown', 5, 'https://github.com/mkotsollaris/kwrds-ai-mcp', NULL, 0, 'https://github.com/mkotsollaris.png?size=128', '2026-03-09T05:21:02.020973+00:00'),
  ('file-finder', 'File Finder', 'This MCP server implementation provides a file finding functionality within the filesystem. It offers a tool to search for files based on a path fragment, returning detailed information such as file name, full path, size, and creation date. The server is built using Python and leverages the os module for filesystem operations, making it suitable for use cases requiring file discovery and metadata retrieval in local or networked environments.', '@kyan9400', 'ai-ml', 'Unknown', 0, 'https://github.com/kyan9400/file-finder-mcp', NULL, 0, 'https://github.com/kyan9400.png?size=128', '2026-03-09T05:21:02.021008+00:00'),
  ('binance-spot-trading', 'Binance Spot Trading', 'This MCP server integrates with the Binance spot trading API, enabling automated cryptocurrency trading strategies. It leverages the @binance/connector library for API interactions and uses SQLite for local data storage. The implementation focuses on providing a robust foundation for algorithmic trading, with features like secure credential management via keytar. Ideal for developers looking to build custom trading bots or automate portfolio management on Binance.', '@kydlikebtc', 'databases', 'Unknown', 14, 'https://github.com/kydlikebtc/mcp-server-bn', NULL, 0, 'https://github.com/kydlikebtc.png?size=128', '2026-03-09T05:21:02.021020+00:00'),
  ('todoist-extended', 'Todoist Extended', 'This extended Todoist MCP server by kydycode builds upon the original implementation by abhiz123 to provide enhanced task management capabilities through the Todoist API with improved compatibility and additional features. Built with TypeScript and the official Todoist API client, it offers 25 tools covering comprehensive task operations (creation, updating, completion, moving, bulk operations), project and section management, label management, and advanced search functionality including natural language quick-add and task moving capabilities. The implementation supports pagination, subtask management, priority settings, due dates, and cross-project task organization, making it valuable for AI assistants managing complex productivity workflows, project coordination, and automated task organization across multiple Todoist projects and teams.', '@kydycode', 'development', 'Unknown', 6, 'https://github.com/kydycode/todoist-mcp-server-ext', '@kydycode/todoist-mcp-server-ext', 5248, 'https://github.com/kydycode.png?size=128', '2026-03-09T05:21:02.021050+00:00'),
  ('io-github-kylastech-kylas-crm', 'io.github.kylastech/kylas-crm', 'MCP server for Kylas CRM: create, search, and manage leads. Requires KYLAS_API_KEY.', '@kylastech', 'development', 'Unknown', 11, 'https://github.com/kylastech/kylas-crm-mcp-server', NULL, 0, 'https://github.com/kylastech.png?size=128', '2026-03-09T05:21:02.021066+00:00'),
  ('spotify-playlist', 'Spotify Playlist', 'A Spotify playlist management server built by Kyle Stratis that enables natural language playlist creation with advanced audio-based similarity matching. Features eight different similarity algorithms (Euclidean, Cosine, Weighted, Energy Match, Mood Match, Rhythm Match, Genre Match, Manhattan) that analyze Spotify''s audio features like energy, danceability, valence, and tempo to find similar tracks across catalogs, playlists, artist discographies, or saved libraries. The implementation includes automated playlist creation, customizable feature weighting, and flexible search scopes, making it useful for building workout playlists based on energy levels, mood-based collections using valence matching, or discovering similar tracks within existing playlists using genre analysis.', '@kylestratis', 'development', 'Unknown', 1, 'https://github.com/kylestratis/spotify-mcp', NULL, 0, 'https://github.com/kylestratis.png?size=128', '2026-03-09T05:21:02.021101+00:00'),
  ('patreon-mcp', 'Patreon MCP', 'Access your Patreon creator data — campaigns, patrons, tiers, and posts.', '@kyurish', 'ai-ml', 'Unknown', 0, 'https://github.com/kyurish/patreon-mcp-server', NULL, 0, 'https://github.com/kyurish.png?size=128', '2026-03-09T05:21:02.021177+00:00'),
  ('lighthouse-portfolio-tracker', 'Lighthouse Portfolio Tracker', 'This MCP server provides integration with Lighthouse.one portfolio tracker, allowing AI assistants to fetch and display cryptocurrency portfolio data. Built with TypeScript and FastMCP, it offers two main tools: ''authenticate'' for logging in with a transfer token URL and ''getLighthousePortfolio'' for retrieving detailed portfolio information including total value, asset type breakdown, and major holdings. The implementation securely manages session cookies for persistent authentication and formats portfolio data into readable tables showing asset allocations and values. Ideal for crypto investors who want to quickly analyze their holdings through AI assistants without switching to the Lighthouse web interface.', '@l3wi', 'development', 'Unknown', 1, 'https://github.com/l3wi/mcp-lighthouse', 'mcp-lighthouse', 4815, 'https://github.com/l3wi.png?size=128', '2026-03-09T05:21:02.021238+00:00'),
  ('label-studio', 'Label Studio', 'Label Studio MCP server by HumanSignal that provides AI assistants with programmatic access to Label Studio data labeling platform through the official label-studio-sdk. The implementation offers comprehensive project management capabilities including creating projects with XML labeling configurations, importing tasks from JSON files, and managing predictions, alongside task-level operations for retrieving data, annotations, and adding model predictions to specific tasks. Built with Python using FastMCP and requiring Label Studio API credentials, it serves teams building AI-powered labeling workflows, data scientists needing conversational access to annotation projects, and organizations integrating Label Studio into broader machine learning pipelines where natural language interaction with labeling infrastructure streamlines data preparation and model training processes.', '@humansignal', 'development', 'Unknown', 28, 'https://github.com/humansignal/label-studio-mcp-server', NULL, 0, 'https://github.com/humansignal.png?size=128', '2026-03-09T05:21:02.021269+00:00'),
  ('network-diagnostics', 'Network Diagnostics', 'Provides comprehensive network diagnostic capabilities including connectivity testing (ping, traceroute, DNS, port checks, MTR), local network inspection, packet capture analysis with Scapy, and subnet planning tools. Features security controls with configurable allowlists/blocklists for target validation and restricted PCAP file access. Designed for Tier 1/Tier 2 NOC workflows with cross-platform support for Linux, macOS, and Windows.', '@labeveryday', 'development', 'Unknown', 3, 'https://github.com/labeveryday/network-mcp', NULL, 0, 'https://github.com/labeveryday.png?size=128', '2026-03-09T05:21:02.021292+00:00'),
  ('io-github-jonasrackl-labmate-mcp', 'io.github.JonasRackl/labmate-mcp', '81 chemistry tools — literature, calculations, retrosynthesis', '@jonasrackl', 'development', 'Unknown', 0, 'https://github.com/jonasrackl/labmate-mcp', NULL, 0, 'https://github.com/jonasrackl.png?size=128', '2026-03-09T05:21:02.021309+00:00'),
  ('latex-document-compiler', 'LaTeX Document Compiler', 'LaTeX MCP server by Lachlan Bridges that provides AI assistants with complete LaTeX document compilation and generation capabilities through a Docker-containerized TeXLive environment. The implementation offers tools for compiling LaTeX source to PDF using multiple engines (pdflatex, xelatex, lualatex), managing reusable document templates (article, beamer presentations, math-heavy documents, worksheets), and rendering LaTeX snippets like equations, figures, and multiple choice questions with parameter substitution. Built with security controls that block dangerous LaTeX commands, automatic file cleanup, compilation caching, and a complete deployment stack including Docker containers, systemd services, and nginx configuration, it serves educators creating worksheets and exams, researchers generating academic papers, and developers building document generation workflows that require professional LaTeX typesetting without managing complex LaTeX installations.', '@thetailorretailored', 'cloud', 'Unknown', 3, 'https://github.com/thetailorretailored/latex-mcp', NULL, 0, 'https://github.com/thetailorretailored.png?size=128', '2026-03-09T05:21:02.021339+00:00'),
  ('laei-ro', 'LaEi.ro', 'LaEi.ro MCP server that enables AI assistants to interact directly with Romanian classified ads through a standardized interface. Built for the LaEi.ro platform, it provides tools for searching listings with advanced filters (category, location, price, keywords), retrieving detailed ad information including descriptions and contact details, accessing the complete category structure, and obtaining geographical data for location-based filtering. The implementation features Romanian language support, real-time updates via Server-Sent Events, API key authentication with rate limiting, and comprehensive documentation with code examples in Python, JavaScript, and cURL. Designed for AI applications that need to integrate classified ad functionality, enabling use cases like automated property searches, market analysis, price monitoring, and conversational interfaces for browsing Romanian marketplace listings.', '@unknown', 'development', 'Unknown', 0, 'https://www.pulsemcp.com/servers/laei-ro', NULL, 0, NULL, '2026-03-09T05:21:02.021371+00:00'),
  ('xiaomi-notes', 'Xiaomi Notes', 'A TypeScript server that provides complete access to Xiaomi''s cloud-based note-taking service. Built by LaelLuo with automatic authentication handling, cookie management, and session persistence, it exposes tools for creating, reading, updating, and deleting notes and folders, searching content, moving notes between folders, and uploading images with full metadata support. The implementation includes robust error handling, automatic login retry mechanisms, caching for performance optimization, and support for both manual and automatic authentication flows using service tokens and device credentials, making it useful for building AI assistants that can manage personal notes, automate note organization, or integrate Xiaomi Notes into broader productivity workflows.', '@laelluo', 'development', 'Unknown', 1, 'https://github.com/laelluo/mi_note_mcp', NULL, 0, 'https://github.com/laelluo.png?size=128', '2026-03-09T05:21:02.021401+00:00'),
  ('deep-reasoning-openrouter', 'Deep Reasoning (OpenRouter)', 'This MCP server implementation provides deep reasoning capabilities for AI models using the Model Context Protocol. Developed by Lakphy, it integrates with OpenRouter''s AI SDK to enable sophisticated analysis and inference tasks. The server exposes MCP-compatible endpoints that allow AI assistants to perform complex reasoning operations, likely including multi-step logical deductions, causal analysis, and abstract problem-solving. It is designed for use cases requiring advanced cognitive abilities from AI systems, such as scientific research, strategic planning, or complex decision-making scenarios.', '@lakphy', 'productivity', 'Unknown', 5, 'https://github.com/lakphy/deep-reasoning-mcp', 'deep-reasoning-mcp', 878, 'https://github.com/lakphy.png?size=128', '2026-03-09T05:21:02.021462+00:00'),
  ('iphone-automation', 'iPhone Automation', 'MCP server implementation by Lakr233 that provides AI assistants with iPhone automation capabilities through Appium and XCUITest, enabling device control, app launching, UI interaction, and screenshot capture via streamable HTTP. The implementation combines pymobiledevice3 for device information and app listing with Appium WebDriver for touch operations, swipe gestures, text input, and visual interface analysis, featuring optimized XML filtering to minimize token usage and JPEG compression to keep screenshots under 500KB. Built for developers and teams who need programmatic iPhone automation for testing, UI interaction workflows, or app demonstration scenarios, supporting both Cherry Studio and other MCP clients through a FastMCP-based HTTP interface with comprehensive error handling and configurable Appium integration.', '@lakr233', 'development', 'Unknown', 120, 'https://github.com/lakr233/iphone-mcp', NULL, 0, 'https://github.com/lakr233.png?size=128', '2026-03-09T05:21:02.021496+00:00'),
  ('tmdb-movie-data', 'TMDB Movie Data', 'This MCP server, developed by Laksh-star, integrates with The Movie Database (TMDB) API to provide movie information, search capabilities, and recommendations. It offers tools for searching movies, getting trending titles, and generating personalized recommendations based on movie IDs. The server stands out by combining multiple TMDB API endpoints into a unified interface optimized for AI assistants. By connecting AI capabilities with a vast movie database, this implementation enables AI systems to handle complex movie-related queries and analysis. It is particularly useful for applications in entertainment recommendation systems, film analysis tools, or any AI assistant that needs to work with detailed movie data.', '@laksh-star', 'databases', 'Unknown', 63, 'https://github.com/laksh-star/mcp-server-tmdb', NULL, 0, 'https://github.com/laksh-star.png?size=128', '2026-03-09T05:21:02.021507+00:00'),
  ('comfy-stable-diffusion', 'Comfy (Stable Diffusion)', 'This server implementation provides a bridge between the Model Context Protocol (MCP) and ComfyUI, a powerful UI for Stable Diffusion. It allows users to generate images based on text prompts by interacting with a remote ComfyUI server. The implementation uses a predefined workflow exported from ComfyUI, which can be customized to suit specific image generation needs. It''s particularly useful for integrating AI image generation capabilities into MCP-based applications, enabling tasks such as creating illustrations, concept art, or visual content for various creative projects.', '@lalanikarim', 'productivity', 'Unknown', 38, 'https://github.com/lalanikarim/comfy-mcp-server', 'comfy-mcp-server', 7310, 'https://github.com/lalanikarim.png?size=128', '2026-03-09T05:21:02.021547+00:00'),
  ('systemctl', 'Systemctl', 'Systemctl MCP Server provides a bridge between Claude and systemd services, allowing direct management of system services through the conversation interface. The implementation exposes tools for checking service status, starting, stopping, and restarting systemd services via a FastMCP server that communicates using Server-Sent Events (SSE). Built by Karim Lalani, it leverages pystemd to interact with the systemd daemon and includes both server and client components for flexible deployment. This tool is particularly valuable for system administrators who need to monitor and control system services without leaving their AI assistant conversation or switching to a terminal.', '@lalanikarim', 'ai-ml', 'Unknown', 0, 'https://github.com/lalanikarim/systemctl-mcp-server', NULL, 0, 'https://github.com/lalanikarim.png?size=128', '2026-03-09T05:21:02.021636+00:00'),
  ('kicad', 'KiCad', 'KiCad MCP Server enables Claude to interact with KiCad electronic design automation projects, providing tools for PCB design analysis, validation, and visualization. The server offers Design Rule Check (DRC) capabilities with history tracking, PCB thumbnail generation, schematic analysis, and project management functions. Built to support macOS, Windows, and Linux, it integrates directly with KiCad''s command-line tools and Python modules when available, falling back to alternative methods when needed. This implementation is particularly valuable for electronics designers seeking AI assistance with troubleshooting design rule violations, understanding PCB layouts, and preparing designs for manufacturing without leaving their Claude conversation.', '@lamaalrajih', 'productivity', 'Unknown', 393, 'https://github.com/lamaalrajih/kicad-mcp', NULL, 0, 'https://github.com/lamaalrajih.png?size=128', '2026-03-09T05:21:02.021684+00:00'),
  ('coder-toolbox', 'Coder Toolbox', 'This Coder Toolbox MCP server, developed by lamemind, enhances AI-assisted software development workflows. It provides a set of tools for code analysis, manipulation, and testing, focusing on Java class operations and test execution log retrieval. The server offers functionalities such as locating and creating Java classes, managing class content and structure, and accessing test results. By abstracting complex file operations and providing a programmatic interface, it enables AI assistants to perform code-related tasks efficiently. This implementation is particularly useful for automated code review systems, intelligent IDE assistants, or any AI application that needs to interact with Java codebases and test environments programmatically.', '@lamemind', 'development', 'Unknown', 4, 'https://github.com/lamemind/coder-toolbox-mcp-server', NULL, 0, 'https://github.com/lamemind.png?size=128', '2026-03-09T05:21:02.021711+00:00'),
  ('lammps', 'LAMMPS', 'MCP LAMMPS Server provides AI assistants with direct control over LAMMPS molecular dynamics simulations through a comprehensive set of tools for creating, configuring, running, and analyzing simulations. Built by the MCP LAMMPS Development Team, it wraps the LAMMPS Python interface to enable natural language interaction with complex MD workflows including structure setup, equilibration and production runs, real-time monitoring, trajectory analysis, and thermodynamic property calculations. The server supports multiple force fields (TIP3P, CHARMM, AMBER), various ensembles (NVT, NPT), and includes built-in analysis tools for RMSD, radius of gyration, and energy calculations, making it valuable for computational chemistry research, materials science studies, and educational molecular dynamics workflows where users need to run simulations without writing complex LAMMPS input scripts.', '@chenghao-wu', 'development', 'Unknown', 8, 'https://github.com/chenghao-wu/mcp_lammps', NULL, 0, 'https://github.com/chenghao-wu.png?size=128', '2026-03-09T05:21:02.021742+00:00'),
  ('configuration-manager', 'Configuration Manager', 'This MCP server manages configurations for various MCP clients including Cline, Roo Code, WindSurf, Cursor, and Claude app. It provides tools to retrieve, list, add, and remove server configurations from client configuration files, automatically detecting the appropriate file path based on the operating system. The implementation is designed to simplify configuration management for developers working with multiple MCP clients across different platforms.', '@landicefu', 'development', 'Unknown', 2, 'https://github.com/landicefu/mcp-client-configuration-server', NULL, 0, 'https://github.com/landicefu.png?size=128', '2026-03-09T05:21:02.021790+00:00'),
  ('divide-and-conquer-task-management', 'Divide and Conquer (Task Management)', 'The Divide and Conquer MCP server enables AI agents to break down complex tasks into manageable pieces using structured JSON storage. Developed by Landice Fu, it evolved from a simpler text-based approach to provide robust task tracking with checklist functionality, progress monitoring, and context preservation across multiple conversations. The implementation includes tools for initializing tasks, managing checklist items, tracking completion status, and retrieving task summaries, making it particularly valuable for complex software development projects, research activities, and project planning where context needs to be maintained across multiple interactions.', '@landicefu', 'development', 'Unknown', 7, 'https://github.com/landicefu/divide-and-conquer-mcp-server', '@landicefu/divide-and-conquer-mcp-server', 4966, 'https://github.com/landicefu.png?size=128', '2026-03-09T05:21:02.021820+00:00'),
  ('landiwetter', 'LandiWetter', 'This MCP server provides weather forecasts from LandiWetter, a Swiss weather service. Developed by Nando Bosshart, it exposes tools for searching locations and retrieving detailed weather forecasts including temperature ranges, precipitation probability, wind conditions, and sunshine duration. The implementation includes both a core MCP server component that communicates via stdio and a test HTTP wrapper for easier integration testing. It''s particularly useful for applications needing reliable Swiss-specific weather data through a standardized MCP interface.', '@nabossha', 'development', 'Unknown', 1, 'https://github.com/nabossha/mcp-landiwetter', NULL, 0, 'https://github.com/nabossha.png?size=128', '2026-03-09T05:21:02.021847+00:00'),
  ('langcare-fhir', 'LangCare FHIR', 'An MCP FHIR server written in Go for EMR systems like Epic and Cerner.', '@langcare', 'development', 'Unknown', 12, 'https://github.com/langcare/langcare-mcp-fhir', NULL, 0, 'https://github.com/langcare.png?size=128', '2026-03-09T05:21:02.021925+00:00'),
  ('llms-txt-documentation', 'LLMS.txt Documentation', 'MCPDoc is a server that provides documentation access from llms.txt files through the Model Control Protocol. It allows AI assistants to query documentation sources like LangGraph by fetching and parsing llms.txt files from specified URLs. The implementation supports multiple configuration methods including YAML, JSON, or direct URL specification, and offers features like HTTP redirect following and customizable timeouts. Built for integration with Claude Code and other MCP-compatible assistants, MCPDoc enables seamless documentation lookup during coding sessions without requiring users to leave their conversation interface.', '@langchain-ai', 'development', 'Unknown', 941, 'https://github.com/langchain-ai/mcpdoc', 'mcpdoc', 79446, 'https://github.com/langchain-ai.png?size=128', '2026-03-09T05:21:02.021952+00:00'),
  ('langfuse-prompt-management', 'Langfuse Prompt Management', 'Provides prompt management capabilities for the Langfuse LLM observability platform. Retrieves and lists prompts with filtering by labels and versions, creates new text and chat prompt versions with template variable support, and manages labels across prompt versions. Available as both a cloud-hosted endpoint and a standalone package.', '@langfuse', 'communication', 'Unknown', 158, 'https://github.com/langfuse/mcp-server-langfuse', NULL, 0, 'https://github.com/langfuse.png?size=128', '2026-03-09T05:21:02.021981+00:00'),
  ('langgraph4j-plantuml', 'LangGraph4j PlantUML', 'Converts diagram images into PlantUML code through an orchestrated workflow using LangGraph4j. Features vision model integration for image analysis, structured JSON schema validation for diagram descriptions, and automatic PlantUML syntax generation with error correction and review cycles. Built with Spring AI support for multiple LLM providers including OpenAI and Ollama, and includes an in-memory transport implementation for testing.', '@langgraph4j', 'development', 'Unknown', 1, 'https://github.com/langgraph4j/langraph4j-plantuml-mcp', NULL, 0, 'https://github.com/langgraph4j.png?size=128', '2026-03-09T05:21:02.022003+00:00'),
  ('langgraph-nutrition-analyzer', 'LangGraph Nutrition Analyzer', 'This nutrition analysis MCP server by sunilpowar5 provides food image recognition and nutritional data retrieval through Google''s Gemini AI and the Nutritionix API, featuring a LangGraph-powered workflow that identifies food items from uploaded images and fetches detailed calorie and protein information. Built with FastAPI backend serving nutrition_fetch and wiki_search tools, and a Streamlit frontend for interactive image upload and follow-up questions, it uses Google Generative AI for food identification with quantity estimation and integrates Wikipedia search for additional nutritional context. The implementation leverages LangGraph''s state management for conversational workflows, supports both initial image analysis and follow-up queries about nutrition facts, and includes comprehensive error handling with retry mechanisms, making it valuable for health-conscious users tracking dietary intake, nutritionists analyzing meal compositions, and fitness applications requiring automated food logging capabilities.', '@sunilpowar5', 'communication', 'Unknown', 1, 'https://github.com/sunilpowar5/langgraph-mcp-nutrition-analyzer', NULL, 0, 'https://github.com/sunilpowar5.png?size=128', '2026-03-09T05:21:02.022051+00:00'),
  ('gpt-image', 'GPT Image', 'This MCP server integrates with OpenAI''s gpt-image-1 model for text-to-image generation and editing services, built with Python using asyncio, Pydantic settings management, and organized storage with date-based directory structures. It features comprehensive caching with memory and Redis backends, prompt template management for optimized image generation, flexible transport support (stdio for Claude Desktop, HTTP for web integration), and automatic cost estimation with usage tracking. The implementation includes robust error handling, image metadata management, storage cleanup policies, and supports multiple output formats (PNG, JPEG, WebP) with quality and compression controls, making it valuable for AI assistants that need reliable image generation capabilities with proper file management and cost monitoring.', '@lansespirit', 'databases', 'Unknown', 49, 'https://github.com/lansespirit/image-gen-mcp', NULL, 0, 'https://github.com/lansespirit.png?size=128', '2026-03-09T05:21:02.022067+00:00'),
  ('la-palma-24', 'La Palma 24', 'Integrates with La Palma 24''s vacation rental platform to search over 300 properties across La Palma, Canary Islands. Provides tools for checking availability by date, calculating stay costs with seasonal pricing, retrieving detailed property information, and browsing listings filtered by municipality, neighborhood, or amenities. Supports Spanish, English, and German languages.', '@la-palma-24', 'ai-ml', 'Unknown', 0, 'https://github.com/la-palma-24/lapalma24-mcp', NULL, 0, 'https://github.com/la-palma-24.png?size=128', '2026-03-09T05:21:02.022135+00:00'),
  ('hapi', 'HAPI', 'HAPI enables seamless AI integration by automatically transforming OpenAPI specifications into MCP tools. It supports both brownfield (existing APIs) and greenfield (new AI-first) approaches, allowing developers to expose their REST APIs to AI assistants without writing custom server implementations. The server runs as a Docker container with streamable HTTP transport.', '@larebelion', 'cloud', 'Unknown', 0, 'https://github.com/larebelion/hapimcp', NULL, 0, 'https://github.com/larebelion.png?size=128', '2026-03-09T05:21:02.022210+00:00'),
  ('lark-base', 'Lark Base', 'Lark Base MCP server provides AI assistants with direct access to Lark Base (formerly Feishu Bitable) spreadsheet and database functionality through both stdio and SSE transport modes. Built by the Lark Base Team using TypeScript and Node.js, it integrates with Lark''s collaboration platform using app tokens and personal base tokens for authentication, enabling operations like data retrieval, field management, and table manipulation. The implementation supports session management for multiple concurrent connections and includes comprehensive type definitions for Lark''s field schemas, making it valuable for teams using Lark Base who want to automate data workflows or enable AI assistants to interact with their collaborative databases and spreadsheets.', '@lark-base-team', 'databases', 'Unknown', 9, 'https://github.com/lark-base-team/lark-base-mcp-node-server', '@lark-base-open/mcp-node-server', 515, 'https://github.com/lark-base-team.png?size=128', '2026-03-09T05:21:02.022250+00:00'),
  ('dojo', 'Dojo', 'This MCP server implementation integrates with the Dojo framework, providing a set of tools and prompts for AI-assisted development. It leverages the mark3labs/mcp-go library to create a server with customizable tools and prompts, loaded dynamically from static directories. The implementation includes logging capabilities, resource management, and a Server-Sent Events (SSE) interface, making it suitable for real-time, interactive AI development environments.', '@larkooo', 'development', 'Unknown', 0, 'https://github.com/larkooo/dojo-mcp-go', NULL, 0, 'https://github.com/larkooo.png?size=128', '2026-03-09T05:21:02.022299+00:00'),
  ('heptabase', 'Heptabase', 'This MCP server provides AI assistants with access to Heptabase backup data through a comprehensive toolkit for searching, analyzing, and exporting knowledge graphs from the visual note-taking platform. Built by Stanley using TypeScript and the Model Context Protocol SDK, the implementation automatically extracts and processes Heptabase backup ZIP files to enable querying of whiteboards, cards, connections, and their relationships through tools for backup management, content search with date/tag filtering, whiteboard analysis, and export capabilities supporting multiple formats including Markdown, JSON, and HTML. The server includes advanced features like file watching for automatic backup detection, graph analysis with centrality and clustering metrics, backup comparison tools, and content parsing that converts Heptabase''s rich text format to readable Markdown, serving researchers and knowledge workers who want conversational access to their Heptabase data for analysis, content discovery, and knowledge management workflows without manually navigating the visual interface.', '@larrystanley', 'development', 'Unknown', 11, 'https://github.com/larrystanley/heptabase-mcp', NULL, 0, 'https://github.com/larrystanley.png?size=128', '2026-03-09T05:21:02.022338+00:00'),
  ('mathematica', 'Mathematica', 'Provides an interface to Mathematica''s WolframScript command-line tool, enabling execution of Wolfram Language scripts and access to engine metadata. Supports evaluating arbitrary Wolfram Language code and querying version and license information for both WolframScript and the Wolfram Engine.', '@lars20070', 'development', 'Unknown', 0, 'https://github.com/lars20070/mathematica-mcp', NULL, 0, 'https://github.com/lars20070.png?size=128', '2026-03-09T05:21:02.022359+00:00'),
  ('queue-pilot', 'Queue Pilot', 'MCP server for RabbitMQ and Kafka message inspection with JSON Schema validation.', '@larscowe', 'development', 'Unknown', 2, 'https://github.com/larscowe/queue-pilot', NULL, 0, 'https://github.com/larscowe.png?size=128', '2026-03-09T05:21:02.022398+00:00'),
  ('langextract', 'LangExtract', 'FastMCP server implementation by Larsen Weigle that provides structured information extraction from unstructured text using Google''s LangExtract library and Gemini models. The server maintains persistent connections and intelligent caching for optimal performance in long-running environments like Claude Code, offering tools for text extraction, URL processing, result visualization, and file operations with precise source grounding that maps every extraction to its exact location in the original text. Built with server-side credential management and optimized for Google Gemini models (gemini-2.5-flash and gemini-2.5-pro), it serves use cases across healthcare document processing, legal contract analysis, research paper extraction, and business intelligence workflows where maintaining traceability between extracted structured data and source text is critical.', '@larsenweigle', 'development', 'Unknown', 28, 'https://github.com/larsenweigle/langextract-mcp', NULL, 0, 'https://github.com/larsenweigle.png?size=128', '2026-03-09T05:21:02.022430+00:00'),
  ('playwright-cdp', 'Playwright CDP', 'This MCP implementation, developed by Lars Hagen, provides integration with Playwright and Chrome DevTools Protocol (CDP) for web automation and testing. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers a standardized interface for AI models to interact with web browsers. The implementation focuses on combining Playwright''s powerful automation capabilities with CDP''s low-level browser control, enabling use cases such as advanced web scraping, automated UI testing, and performance analysis. By connecting AI models with browser automation tools, this server allows for sophisticated web interaction scenarios, enhancing the ability to analyze and manipulate web content programmatically.', '@lars-hagen', 'development', 'Unknown', 47, 'https://github.com/lars-hagen/mcp-playwright-cdp', NULL, 0, 'https://github.com/lars-hagen.png?size=128', '2026-03-09T05:21:02.022459+00:00'),
  ('graphql-explorer', 'GraphQL Explorer', 'This MCP server implementation provides a GraphQL client interface for AI assistants. It offers tools for setting up connections to GraphQL endpoints, executing queries, and retrieving schema information. Built using Python and leveraging libraries like gql and httpx, the server focuses on secure authentication handling and efficient query execution. It is particularly useful for AI applications that need to interact with GraphQL APIs, enabling data retrieval and exploration across various domains. The implementation includes features like connection setup, query execution, schema retrieval, and type information lookup, making it versatile for integrating GraphQL data sources into AI workflows.', '@larshvidsten', 'ai-ml', 'Unknown', 0, 'https://github.com/larshvidsten/mcp_af_graph', NULL, 0, 'https://github.com/larshvidsten.png?size=128', '2026-03-09T05:21:02.022530+00:00'),
  ('php-codesniffer', 'PHP_CodeSniffer', 'A lightweight MCP server that exposes PHP_CodeSniffer (phpcs) and PHP Code Beautifier and Fixer (phpcbf) tools for code quality analysis and automatic fixing. Built with zero external dependencies using only native PHP, it provides two core tools: phpcs_check for running coding standard violations analysis with formatted JSON output, and phpcbf_fix for automatically fixing code style issues. The implementation features flexible configuration through environment variables, JSON config files, or automatic ruleset discovery, supports custom coding standards, and includes robust process execution with proper error handling, making it useful for AI-assisted PHP code review, automated code quality checks, and maintaining consistent coding standards across PHP projects.', '@larspohlmann', 'development', 'Unknown', 0, 'https://github.com/larspohlmann/mcp-phpcs-server', NULL, 0, 'https://github.com/larspohlmann.png?size=128', '2026-03-09T05:21:02.022557+00:00'),
  ('phpstan', 'PHPStan', 'A lightweight PHPStan MCP server that exposes static analysis capabilities through two specialized tools: phpstan_analyze for human-readable reports and phpstan_pro for raw JSON output. Built with zero external dependencies using only native PHP, it features automatic PHPStan binary detection (preferring vendor/bin/phpstan), configuration file discovery, and flexible path normalization for analyzing PHP codebases. The implementation includes a custom autoloader, JSON-RPC message handling over STDIO, and configurable analysis levels, making it useful for integrating PHPStan static analysis into AI-assisted development workflows, automated code review processes, and quality assurance pipelines.', '@larspohlmann', 'development', 'Unknown', 0, 'https://github.com/larspohlmann/mcp-phpstan-server', NULL, 0, 'https://github.com/larspohlmann.png?size=128', '2026-03-09T05:21:02.022583+00:00'),
  ('last9', 'Last9', 'Use tools like `get_exceptions`, `get_logs`, `get_service_graph`, and more to give prod context to the IDE AI agent to fix issues and get recommendations to optimize logging and instrumentation.', '@unknown', 'development', 'Unknown', 0, 'https://last9.io/mcp/', NULL, 0, NULL, '2026-03-09T05:21:02.022600+00:00'),
  ('last9-observability', 'Last9 Observability', 'Last9 MCP Server enables AI agents to query exception and service graph data from Last9''s observability platform. The implementation provides two tools: get_exceptions for retrieving server-side exceptions with details like type, message, and stack trace; and get_service_graph for analyzing upstream and downstream service dependencies with throughput metrics. Built with Go and featuring configurable rate limiting, the server integrates seamlessly with Claude desktop app and Cursor, making it valuable for developers who need AI-assisted troubleshooting and service dependency analysis within their Last9 monitoring environment.', '@last9', 'ai-ml', 'Unknown', 50, 'https://github.com/last9/last9-mcp-server', NULL, 0, 'https://github.com/last9.png?size=128', '2026-03-09T05:21:02.022643+00:00'),
  ('pathscan-dirsearch-firecrawl', 'PathScan (Dirsearch + Firecrawl)', 'This MCP server provides web path scanning capabilities by integrating the dirsearch directory brute-forcing tool with Firecrawl web crawling services. Built as a Python-based server using fastmcp, it combines dirsearch''s comprehensive path discovery engine (featuring 70+ report formats, recursive scanning, custom wordlists, and advanced filtering) with Firecrawl''s web crawling infrastructure to enable automated discovery of hidden web directories, files, and endpoints. The implementation includes configurable host/port settings, supports multiple output formats including JSON, XML, CSV, and HTML reports, and leverages dirsearch''s extensive feature set including custom extensions, authentication methods, proxy support, and dynamic content parsing. Designed for security researchers, penetration testers, and web developers who need programmatic access to directory enumeration and web reconnaissance capabilities through AI assistants.', '@lastmiao', 'development', 'Unknown', 2, 'https://github.com/lastmiao/pathscan-mcp-server', NULL, 0, 'https://github.com/lastmiao.png?size=128', '2026-03-09T05:21:02.022682+00:00'),
  ('webdav', 'WebDAV', 'WebDAV MCP Server enables Claude and other MCP clients to interact with WebDAV file systems through natural language commands. Built with TypeScript and the Model Context Protocol, it provides a complete set of CRUD operations for files and directories, supports both stdio transport (for Claude Desktop integration) and HTTP/SSE transport for remote access, and includes security features like basic authentication and bcrypt password encryption. The server exposes WebDAV operations as MCP resources, tools, and prompts, making it ideal for AI assistants that need to manage documents, configuration files, or any content stored on WebDAV-compatible servers.', '@laubplusco', 'development', 'Unknown', 13, 'https://github.com/laubplusco/mcp-webdav-server', NULL, 0, 'https://github.com/laubplusco.png?size=128', '2026-03-09T05:21:02.022745+00:00'),
  ('launchdarkly', 'LaunchDarkly', 'This MCP server provides integration with LaunchDarkly''s feature flag management platform, enabling AI assistants to interact with feature toggles, experimentation frameworks, and progressive deployment controls. The implementation allows access to LaunchDarkly''s feature flag APIs for managing rollouts, A/B testing configurations, and environment-specific flag states, making it valuable for developers and DevOps teams who need AI assistance with feature management workflows, deployment strategies, and experimentation analysis across different application environments.', '@launchdarkly', 'development', 'Unknown', 19, 'https://github.com/launchdarkly/mcp-server', NULL, 0, 'https://github.com/launchdarkly.png?size=128', '2026-03-09T05:21:02.022771+00:00'),
  ('pandas-data-tools', 'Pandas Data Tools', 'MCP server by laurensanp that provides AI assistants with data processing capabilities for CSV and Parquet files through pandas-based tools, along with specialized functionality for starting a Discord bot application. Built with FastMCP and featuring automatic tool discovery through dynamic module loading, the implementation includes file reading utilities that generate summaries of data dimensions, sample data generation scripts, and a Windows-specific bot launcher that opens external Python applications in new command windows. The server demonstrates a modular architecture where tools are automatically registered from the tools directory, making it suitable for data analysis workflows that require quick file inspection and external application management, particularly in development environments where launching auxiliary services like Discord bots is needed alongside data processing tasks.', '@laurensanp', 'development', 'Unknown', 1, 'https://github.com/laurensanp/mcp-server', NULL, 0, 'https://github.com/laurensanp.png?size=128', '2026-03-09T05:21:02.022846+00:00'),
  ('llamacloud', 'LlamaCloud', 'LlamaCloud MCP server provides a tool for querying LlamaIndex documentation through RAG (Retrieval-Augmented Generation) using the LlamaCloud managed index service. Developed by Laurie Voss, this implementation connects to a pre-configured LlamaCloud index containing LlamaIndex documentation and uses it to answer queries with detailed responses including code examples. The server requires a LlamaCloud API key and optionally an OpenAI API key for powering the RAG queries, making it ideal for developers who need up-to-date access to LlamaIndex documentation within their AI assistant workflows.', '@run-llama', 'development', 'Unknown', 224, 'https://github.com/run-llama/llamacloud-mcp', NULL, 0, 'https://github.com/run-llama.png?size=128', '2026-03-09T05:21:02.022882+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('emacs-lisp-development', 'Emacs Lisp Development', 'This MCP server provides Emacs Lisp development assistance through five specialized tools that enable AI agents to interact with Emacs environments for code analysis and documentation lookup. Built by Laurynas Biveinis using TypeScript with the mcp-server-lib foundation, it offers function documentation retrieval, source code definition extraction with header comments, variable information without exposing values, Info documentation lookup from the Emacs Lisp Reference Manual, and secure source file reading from system directories and ELPA packages. The implementation features robust security controls that prevent path traversal attacks, handles both regular and byte-compiled functions, supports dynamic and lexical binding contexts, manages function aliases and C-implemented functions, and provides complete source reconstruction for interactively defined functions, making it valuable for AI-assisted Emacs Lisp development, code exploration and analysis, package development workflows, and building AI tools that need deep integration with Emacs internals.', '@laurynas-biveinis', 'development', 'Unknown', 37, 'https://github.com/laurynas-biveinis/elisp-dev-mcp', NULL, 0, 'https://github.com/laurynas-biveinis.png?size=128', '2026-03-09T05:21:02.022937+00:00'),
  ('org-mcp', 'org-mcp', 'Emacs package providing MCP server for structured Org-mode file access with read/write operations', '@laurynas-biveinis', 'file-systems', 'Unknown', 45, 'https://github.com/laurynas-biveinis/org-mcp', NULL, 0, 'https://github.com/laurynas-biveinis.png?size=128', '2026-03-09T05:21:02.022960+00:00'),
  ('azure-logic-apps', 'Azure Logic Apps', 'Enables management and debugging of Azure Logic Apps through natural language interactions. Supports both Consumption and Standard Logic Apps SKUs, allowing users to investigate failed workflow runs, trace failures through actions and scopes, create and update workflows, and manage connectors without using the Azure portal.', '@laveeshb', 'cloud', 'Unknown', 3, 'https://github.com/laveeshb/logicapps-mcp', NULL, 0, 'https://github.com/laveeshb.png?size=128', '2026-03-09T05:21:02.022981+00:00'),
  ('bitbucket-mcp', 'Bitbucket MCP', 'MCP server for Bitbucket API - manage repositories, pull requests, comments, pipelines and more.', '@lawp09', 'development', 'Unknown', 2, 'https://github.com/lawp09/bitbucket-mcp', NULL, 0, 'https://github.com/lawp09.png?size=128', '2026-03-09T05:21:02.023022+00:00'),
  ('layerzero-oft', 'LayerZero OFT', 'This MCP server provides LayerZero OFT (Omnichain Fungible Token) deployment and cross-chain bridging capabilities, enabling AI assistants to deploy tokens across multiple blockchain networks and facilitate seamless token transfers between chains. Built by Thomas Fevre using TypeScript with the MCP SDK and ethers.js, it features automated multi-chain deployment using CREATE2 factories for consistent addresses, peer connection setup between deployed contracts, enforced options configuration for gas limits, and cross-chain token bridging with automatic fee estimation. The implementation supports Arbitrum Sepolia and Base Sepolia testnets with configurable network parameters, uses environment variables for secure private key and RPC URL management, and provides detailed execution logging for deployment and bridging operations, making it valuable for DeFi developers building cross-chain applications, token projects requiring omnichain functionality, and automated workflows that need to deploy and manage tokens across multiple blockchain networks.', '@thomasfevre', 'development', 'Unknown', 1, 'https://github.com/thomasfevre/layerzero_mcp', NULL, 0, 'https://github.com/thomasfevre.png?size=128', '2026-03-09T05:21:02.023073+00:00'),
  ('eigenlayer-documentation', 'EigenLayer Documentation', 'EigenLayer MCP Server provides a Next.js-based implementation that exposes EigenLayer documentation resources through the Model Context Protocol. The server uses Redis for managing connections and message passing between clients and the MCP handler, supporting both SSE (Server-Sent Events) for persistent connections and HTTP POST endpoints for message exchange. It serves multiple EigenLayer documentation resources including blog articles, overview documentation, middleware, contracts, and developer guides, making it valuable for AI assistants that need to access structured information about EigenLayer''s architecture, capabilities, and implementation details.', '@layr-labs', 'databases', 'Unknown', 1, 'https://github.com/layr-labs/eigenlayer-mcp-server', NULL, 0, 'https://github.com/layr-labs.png?size=128', '2026-03-09T05:21:02.023088+00:00'),
  ('twosplit', 'TwoSplit', 'Twosplit MCP Server leverages multiple Claude instances to provide enhanced AI responses. It sends the same prompt to two separate Claude models and uses a third instance to either select the best response or combine elements from both, delivering a final optimized answer. The server supports various Claude models including Opus, Sonnet, and Haiku, and returns not only the final response but also the original outputs from both AIs along with source attribution. This implementation is particularly valuable for users seeking more comprehensive or nuanced answers by comparing multiple AI perspectives within a single query.', '@lazerthings', 'ai-ml', 'Unknown', 0, 'https://github.com/lazerthings/twosplit', NULL, 0, 'https://github.com/lazerthings.png?size=128', '2026-03-09T05:21:02.023130+00:00'),
  ('ccxt-crypto-trading', 'CCXT Crypto Trading', 'CCXT-MCP provides a bridge between the CCXT cryptocurrency trading library and AI assistants through the Model Context Protocol, enabling natural language interactions with over 100 cryptocurrency exchanges. This TypeScript implementation exposes core functionality for retrieving exchange information, market data, orderbooks, and price information, making it ideal for traders and developers who want to monitor cryptocurrency markets, analyze price trends, or build trading bots with AI assistance. The server supports Node.js environments and is designed to be easily integrated into existing trading systems.', '@lazy-dinosaur', 'development', 'Unknown', 75, 'https://github.com/lazy-dinosaur/ccxt-mcp', '@lazydino/ccxt-mcp', 5662, 'https://github.com/lazy-dinosaur.png?size=128', '2026-03-09T05:21:02.023193+00:00'),
  ('detect-it-easy-die', 'Detect It Easy (DIE)', 'MCP server that bridges AI assistants with Detect It Easy (DIE), a popular executable file analysis tool used for malware detection and reverse engineering. Built by lazy-importer using Python with FastMCP, the implementation wraps DIE''s command-line interface to provide three core tools: analyze_file for comprehensive executable analysis with options for deep scanning, entropy calculation, and JSON output; show_special_info for extracting specific file metadata using DIE''s specialized methods; and list_available_methods for discovering what analysis capabilities are available for a given file. The server supports both stdio and SSE transport modes and includes a standalone example client, making it valuable for security researchers analyzing suspicious executables, malware analysts requiring programmatic access to DIE''s detection capabilities, and AI assistants that need to understand file composition and potential threats in executable files.', '@lazy-importer', 'ai-ml', 'Unknown', 11, 'https://github.com/lazy-importer/d.i.e-mcp', NULL, 0, 'https://github.com/lazy-importer.png?size=128', '2026-03-09T05:21:02.023251+00:00'),
  ('lcbro-browser-automation', 'LCBRO (Browser Automation)', 'This MCP server provides browser automation and web scraping capabilities through Playwright integration with Chrome DevTools Protocol (CDP) support for remote browser connections. Built by Max with TypeScript and featuring intelligent LLM-powered preprocessing that automatically optimizes content for AI processing using local models like Ollama and JAN, it offers tools for navigation, content extraction, form interaction, session management, and screenshot capture with automatic data cleaning that reduces processing costs by 80-90%. The implementation includes Docker deployment, comprehensive logging with performance tracking, support for both local and remote CDP browsers, and configurable security controls, making it ideal for AI assistants that need reliable web automation, data extraction from complex websites, and cost-effective content processing workflows.', '@lcbro', 'cloud', 'Unknown', 5, 'https://github.com/lcbro/lcbro-mcp', NULL, 0, 'https://github.com/lcbro.png?size=128', '2026-03-09T05:21:02.023278+00:00'),
  ('kip', 'KIP', 'KIP (Knowledge Interaction Protocol) bridges large language models with knowledge graphs, providing structured memory and cognitive operation primitives for AI agents. The protocol includes three instruction sets: KQL for querying, KML for knowledge manipulation, and META for schema discovery. Enables persistent memory storage through structured Knowledge Capsules, making agent reasoning more transparent and controllable.', '@ldclabs', 'ai-ml', 'Unknown', 56, 'https://github.com/ldclabs/kip', NULL, 0, 'https://github.com/ldclabs.png?size=128', '2026-03-09T05:21:02.023316+00:00'),
  ('agent-server', 'Agent Server', 'This MCP server provides a foundation for building AI agent systems with persistent memory and workflow integration, designed specifically for SaaS deployment and monetization. Built by Matthew Smith using Node.js, TypeScript, Express, and PostgreSQL with Prisma ORM, it offers core functionality for agent management, persistent memory storage per agent, user authentication with API key management, and n8n workflow integration through trigger endpoints. The implementation features Docker containerization for easy deployment, database migrations for schema management, and a RESTful API structure that supports multi-tenant SaaS applications, making it valuable for developers building AI employee systems that need to maintain context across sessions, integrate with existing workflow automation tools, and scale as commercial offerings.', '@leadbroaf', 'databases', 'Unknown', 3, 'https://github.com/leadbroaf/mcp-agent-server', NULL, 0, 'https://github.com/leadbroaf.png?size=128', '2026-03-09T05:21:02.023328+00:00'),
  ('lunchmoney', 'Lunchmoney', 'This MCP server provides a bridge to the Lunchmoney personal finance API, enabling AI assistants to interact with users'' financial data. It offers tools for retrieving recent transactions, searching transaction history, analyzing category-specific spending, and obtaining detailed budget summaries. Developed by a third-party contributor, it aims to enhance financial management capabilities within AI conversations. The implementation is particularly useful for personal finance tracking, budget analysis, and expense monitoring use cases, allowing users to gain insights into their spending habits and financial health through natural language interactions.', '@leafeye', 'ai-ml', 'Unknown', 25, 'https://github.com/leafeye/lunchmoney-mcp-server', 'lunchmoney-mcp', 4465, 'https://github.com/leafeye.png?size=128', '2026-03-09T05:21:02.023411+00:00'),
  ('leafly-strain-scraper', 'Leafly Strain Scraper', 'Leafly Strain Scraper is an MCP server that extracts structured cannabis strain data from Leafly.com following a standardized methodology. It implements both regex-based and LLM-powered extraction techniques to collect 66 data points per strain including cannabinoids, terpenes, effects, and flavors. The server handles batch processing with rate limiting, provides fallback mechanisms for missing data, and exports results in CSV or JSON format. Built with Node.js and the Firecrawl API, it requires an API key for authentication and is designed for researchers, developers, and cannabis industry professionals who need reliable, normalized strain information.', '@adi2355', 'communication', 'Unknown', 1, 'https://github.com/adi2355/model-context-protocol-servers', NULL, 0, 'https://github.com/adi2355.png?size=128', '2026-03-09T05:21:02.023450+00:00'),
  ('solx402', 'SolX402', 'Integrates Solana blockchain operations with x402 micropayment protocol for wallet management, USDC balance tracking, and service discovery', '@leandrogavidia', 'ai-ml', 'Unknown', 7, 'https://github.com/leandrogavidia/solx402-mcp-server', NULL, 0, 'https://github.com/leandrogavidia.png?size=128', '2026-03-09T05:21:02.023471+00:00'),
  ('vechain', 'VeChain', 'Integrates with VeChain blockchain networks to provide documentation search, account/transaction/block queries, wallet creation, cryptographic signing, and EVM-compatible token operations for building dApps and automated trading systems.', '@leandrogavidia', 'development', 'Unknown', 5, 'https://github.com/leandrogavidia/vechain-mcp-server', NULL, 0, 'https://github.com/leandrogavidia.png?size=128', '2026-03-09T05:21:02.023490+00:00'),
  ('ledger-cli', 'Ledger CLI', 'The mcp-server-ledger provides AI assistants with structured access to Ledger CLI, a powerful command-line accounting system. Built with Python using the FastMCP framework, it exposes nine tools that map directly to Ledger commands including balance reports, transaction registers, account listings, and budget analysis. The server requires a valid Ledger file path and includes security measures to prevent command injection. It''s particularly valuable for users who want to analyze financial data, generate reports, and track budgets through natural language queries without leaving their AI assistant conversation.', '@minhyeoky', 'ai-ml', 'Unknown', 44, 'https://github.com/minhyeoky/mcp-server-ledger', NULL, 0, 'https://github.com/minhyeoky.png?size=128', '2026-03-09T05:21:02.023564+00:00'),
  ('omnifocus', 'OmniFocus', 'Integrates with OmniFocus on macOS using JavaScript for Automation (JXA) to provide task and project management capabilities. Supports retrieving tasks and projects, creating and updating tasks, marking tasks complete with safety checks, and creating new projects with configurable types and folder assignments.', '@leedoughty', 'productivity', 'Unknown', 2, 'https://github.com/leedoughty/omnifocus-mcp', NULL, 0, 'https://github.com/leedoughty.png?size=128', '2026-03-09T05:21:02.023593+00:00'),
  ('iconify-svg', 'Iconify SVG', 'PickApIcon MCP Server provides a bridge to the Iconify API, enabling AI assistants to search and retrieve SVG icons from various icon collections. This TypeScript implementation offers tools for listing available icon repositories, searching icons by description within specific collections, and retrieving SVG code for individual or multiple icons. The server uses environment variables to set default icon prefixes and supports both exact and fuzzy matching of icon names. It''s particularly valuable for developers who need to quickly find and integrate icons into their projects without leaving their AI assistant interface.', '@leee62', 'development', 'Unknown', 4, 'https://github.com/leee62/pickapicon-mcp', 'pickapicon-mcp', 5332, 'https://github.com/leee62.png?size=128', '2026-03-09T05:21:02.023618+00:00'),
  ('sentry-issues', 'Sentry Issues', 'Sentry-issues-mcp is a TypeScript server implementation that provides access to Sentry error tracking data through the MCP protocol. It offers four main tools for retrieving Sentry data: fetching single events, project events, single issues, and project issues by ID or URL. The server connects to the Sentry API using environment variables for authentication and organization/project configuration, making it particularly useful for developers and support teams who need to analyze application errors and exceptions within their LLM workflows.', '@leee62', 'development', 'Unknown', 5, 'https://github.com/leee62/sentry-issues-mcp', 'sentry-issues-mcp', 5098, 'https://github.com/leee62.png?size=128', '2026-03-09T05:21:02.023643+00:00'),
  ('pubmed-smithery', 'PubMed Smithery', 'The PubMed Enhanced Search MCP Server provides AI assistants with powerful tools to search and analyze academic medical literature through the PubMed database. It offers specialized functions for keyword searches with journal filtering, MeSH term lookups, publication count statistics, detailed paper information retrieval, and structured PICO-based evidence searches. Built with Python using the FastMCP framework, this server implements automatic retry mechanisms with backoff delays to handle potential rate limiting by NCBI''s E-utilities service, making it particularly valuable for researchers, healthcare professionals, and academics who need to efficiently access and analyze medical research without leaving their AI assistant conversation.', '@leescot', 'databases', 'Unknown', 4, 'https://github.com/leescot/pubmed-mcp-smithery', NULL, 0, 'https://github.com/leescot.png?size=128', '2026-03-09T05:21:02.023706+00:00'),
  ('xcode-diagnostics', 'Xcode Diagnostics', 'The Xcode Diagnostics MCP plugin extracts and parses build errors and warnings from Xcode''s DerivedData logs, enabling AI assistants to quickly identify issues in Swift projects without manually searching through build logs. Developed by Mike R. Manzano, it provides tools to list available Xcode projects and extract structured diagnostic information including file paths, line numbers, error messages, and fix-it suggestions. The implementation features enhanced regex patterns optimized for capturing Swift concurrency-related warnings and includes comprehensive error categorization for syntax errors, type errors, protocol conformance issues, and Swift 6 language mode compatibility warnings, making it particularly valuable for developers working with Swift concurrency features.', '@leftspin', 'development', 'Unknown', 6, 'https://github.com/leftspin/mcp-xcode-diagnostics', NULL, 0, 'https://github.com/leftspin.png?size=128', '2026-03-09T05:21:02.023734+00:00'),
  ('legion-database', 'Legion Database', 'Database MCP Server, developed by Legion AI, enables AI assistants to access and query data across multiple database types (PostgreSQL, MySQL, SQL Server, BigQuery, etc.) through a standardized interface. Built with Python using the Legion Query Runner library, it exposes database operations as MCP tools and resources, allowing natural language interactions with databases for executing queries, retrieving schemas, and optimizing SQL statements. The implementation features flexible configuration options and maintains query history for context, making it particularly valuable for data analysis, business intelligence, and database exploration use cases where AI assistants need direct, controlled access to structured data.', '@theralabs', 'databases', 'Unknown', 86, 'https://github.com/theralabs/legion-mcp', 'database-mcp', 9066, 'https://github.com/theralabs.png?size=128', '2026-03-09T05:21:02.023745+00:00'),
  ('stellar-xdr-json', 'Stellar XDR-JSON', 'Stellar MCP Server for XDR-JSON provides Claude with tools to decode and understand Stellar blockchain data by converting XDR (External Data Representation) format to human-readable JSON. The server exposes three main tools: guessing XDR types, decoding arbitrary XDR data, and specifically decoding Stellar transactions. Built using the Model Context Protocol SDK and Stellar''s XDR-JSON library, this implementation enables Claude to analyze blockchain transactions and contract events without requiring users to manually decode complex binary data, making it valuable for blockchain developers and analysts working with the Stellar network.', '@leighmcculloch', 'development', 'Unknown', 2, 'https://github.com/leighmcculloch/mcp-stellar-xdr', NULL, 0, 'https://github.com/leighmcculloch.png?size=128', '2026-03-09T05:21:02.023774+00:00'),
  ('joern', 'Joern', 'Joern MCP Server provides AI assistants with static code analysis capabilities using Joern''s Code Property Graph (CPG) technology in isolated Docker environments. Built with Python and Docker integration, it supports loading projects from GitHub repositories or local paths, automatically detects programming languages (C/C++, Java, JavaScript, Python, Go, Kotlin, Scala, C#), generates CPGs for deep code structure analysis, and executes Joern queries for security vulnerability detection, code quality assessment, and metrics calculation. The server includes comprehensive caching, resource management, and pre-built query templates for common security patterns like SQL injection and XSS vulnerabilities, making it valuable for automated code review workflows, security auditing, and building AI assistants that need to understand and analyze codebases at scale.', '@lekssays', 'databases', 'Unknown', 46, 'https://github.com/lekssays/codebadger', NULL, 0, 'https://github.com/lekssays.png?size=128', '2026-03-09T05:21:02.023798+00:00'),
  ('sap-odata-btp', 'SAP OData (BTP)', 'This MCP server provides programmatic access to SAP OData services running on SAP Business Technology Platform (BTP), enabling AI assistants to perform CRUD operations on SAP business data through automatically discovered service endpoints. Built with TypeScript and the SAP Cloud SDK, it features configurable service discovery with pattern-based filtering, automatic metadata parsing to generate type-safe tools for each entity, and support for both OData v2 and v4 protocols with proper SAP authentication handling. The implementation includes comprehensive query capabilities with OData parameters ($filter, $select, $expand, etc.), dynamic tool registration that creates shortened tool names to work within MCP constraints, and flexible deployment options supporting both local development and Cloud Foundry environments. Designed for enterprise scenarios where AI assistants need direct access to SAP business systems for data analysis, reporting, process automation, or integration workflows without requiring manual API configuration or SAP technical expertise.', '@lemaiwo', 'development', 'Unknown', 113, 'https://github.com/lemaiwo/btp-sap-odata-to-mcp-server', NULL, 0, 'https://github.com/lemaiwo.png?size=128', '2026-03-09T05:21:02.023835+00:00'),
  ('nexus-multi-platform-productivity', 'Nexus (Multi-Platform Productivity)', 'A personal assistant MCP server by Oleksandr Hryhor that integrates multiple productivity services through a unified interface. The implementation provides tools for Google Calendar event management, Obsidian vault operations with optional semantic search capabilities, Trello board and card management, web page parsing, and Google News search. Built with FastMCP and featuring modular configuration through environment variables, it supports advanced features like note chunking for large documents, vector-based semantic search using sentence transformers, and comprehensive logging, making it valuable for users who want to manage their digital workspace across multiple platforms through natural language interactions with AI assistants.', '@lemannrus', 'development', 'Unknown', 5, 'https://github.com/lemannrus/nexus-mcp', NULL, 0, 'https://github.com/lemannrus.png?size=128', '2026-03-09T05:21:02.023878+00:00'),
  ('lemonado', 'Lemonado', 'Lemonado provides a unified context layer that enables SQL queries across multiple data sources simultaneously. Connect data from Stripe, Google Ads, Sheets, PostgreSQL, and other sources, then query millions of rows with sub-second response times. The platform automates data integration without requiring SQL expertise or engineering resources.', '@unknown', 'databases', 'Unknown', 0, 'https://docs.lemonado.io/', NULL, 0, NULL, '2026-03-09T05:21:02.023890+00:00'),
  ('glm-4-5v-vision', 'GLM-4.5V Vision', 'This MCP server provides image recognition and analysis capabilities using the GLM-4.5V vision model, built with TypeScript and the Model Context Protocol SDK for integration with Claude and other AI assistants. The implementation offers specialized tools for analyzing various image types including general image description, code screenshot analysis with language detection and architecture insights, and automatic image processing with Sharp for format conversion and metadata extraction. Features include structured analysis results with confidence scoring, comprehensive error handling, and support for both local file paths and image URLs, making it valuable for developers who need AI-powered visual content analysis, code documentation from screenshots, or automated image processing workflows integrated into their development tools.', '@lengbone', 'development', 'Unknown', 10, 'https://github.com/lengbone/mcp-vl', NULL, 0, 'https://github.com/lengbone.png?size=128', '2026-03-09T05:21:02.023919+00:00'),
  ('leni', 'Leni', 'Leni is a hosted MCP server for AI-native task management that integrates directly with Claude and ChatGPT. Users can create, organize, and track tasks through natural conversation commands, with all tasks automatically syncing to a centralized Leni dashboard. Supports commands like creating tasks with due dates, viewing tasks by timeframe, getting priority recommendations, and marking tasks complete.', '@unknown', 'communication', 'Unknown', 0, 'https://www.heyleni.ai', NULL, 0, NULL, '2026-03-09T05:21:02.023946+00:00'),
  ('lenses', 'Lenses', 'Manage and explore data in Apache Kafka topics across multiple clusters using SQL without requiring an additional database. Supports data transformation, joining, and works with various Kafka distributions including Confluent, MSK, and open-source Kafka via Lenses.io platform.', '@lensesio', 'databases', 'Unknown', 21, 'https://github.com/lensesio/lenses-mcp', NULL, 0, 'https://github.com/lensesio.png?size=128', '2026-03-09T05:21:02.023955+00:00'),
  ('college-football-data', 'College Football Data', 'This College Football Data MCP server, developed by Chris Leonard, provides AI assistants with access to comprehensive college football statistics via the College Football Data API. Built with Python and leveraging libraries like httpx and pydantic, it offers a natural language interface for querying game results, team records, player stats, rankings, and advanced metrics. The server implements robust error handling, rate limiting, and caching to optimize API usage. By abstracting the complexities of data retrieval and analysis, it enables AI systems to generate insights on team performance, analyze historical trends, and compare statistics across seasons. This implementation is particularly valuable for sports analysts, researchers, and fans seeking in-depth college football data analysis, facilitating use cases such as game prediction, player evaluation, and historical performance comparisons.', '@lenwood', 'ai-ml', 'Unknown', 24, 'https://github.com/lenwood/cfbd-mcp-server', NULL, 0, 'https://github.com/lenwood.png?size=128', '2026-03-09T05:21:02.024010+00:00'),
  ('vm-terminal', 'VM Terminal', 'MCP Tunnel provides a secure way to access VM command lines through a web-based terminal interface. Built with TypeScript and Express, it creates a WebSocket connection for real-time command execution and automatically establishes a web tunnel using localtunnel, making the VM accessible from anywhere. The server exposes MCP tools for executing shell commands and managing tunnels, while the frontend delivers an interactive terminal experience with features like command history and proper output formatting, making it ideal for remote VM management without requiring direct SSH access.', '@leomercier', 'development', 'Unknown', 5, 'https://github.com/leomercier/mcp-tunnel', NULL, 0, 'https://github.com/leomercier.png?size=128', '2026-03-09T05:21:02.024124+00:00'),
  ('fast-telegram', 'Fast Telegram', 'Integrates with Telegram via MTProto protocol to enable message search across chats, sending and editing messages, file handling with security protections, and contact discovery. Offers multi-user authentication with Bearer tokens, dual transport modes (STDIO and HTTP), and a web-based setup interface for browser authentication flows. Built with FastMCP framework and includes SSRF protection, connection pooling, and comprehensive error handling.', '@leshchenko1979', 'communication', 'Unknown', 29, 'https://github.com/leshchenko1979/fast-mcp-telegram', NULL, 0, 'https://github.com/leshchenko1979.png?size=128', '2026-03-09T05:21:02.024282+00:00'),
  ('markdown-library', 'Markdown Library', 'Library-MCP is a server implementation that enables AI assistants to interact with Markdown knowledge bases through a set of specialized tools. Created by Will Larson (lethain), it indexes folders of Markdown files with YAML frontmatter, allowing users to retrieve content by tags, text search, slugs/URLs, or date ranges. The server exposes navigation tools for exploring tags and content relationships, making it particularly valuable for users with large document collections that exceed context windows or span multiple knowledge bases. Designed as a hobby project for local use, it works well with Claude Desktop and similar MCP-compatible assistants.', '@lethain', 'productivity', 'Unknown', 88, 'https://github.com/lethain/library-mcp', NULL, 0, 'https://github.com/lethain.png?size=128', '2026-03-09T05:21:02.024363+00:00'),
  ('systems-modeling', 'Systems Modeling', 'Systems-MCP is a server implementation that enables AI assistants to interact with the systems modeling library created by Will Larson. It provides two key tools: one for running systems models based on specifications and another for loading documentation to help generate better models. Built with Python 3.13 and the FastMCP framework, it''s designed to work locally with Claude Desktop, allowing users to model complex systems, visualize their behavior over time, and generate specifications for new models without requiring deep knowledge of the underlying library. The implementation is particularly valuable for those interested in systems thinking who want to quickly prototype and analyze system dynamics without leaving their AI assistant conversation.', '@lethain', 'ai-ml', 'Unknown', 14, 'https://github.com/lethain/systems-mcp', NULL, 0, 'https://github.com/lethain.png?size=128', '2026-03-09T05:21:02.024413+00:00'),
  ('auto-causal-inference', 'Auto Causal Inference', 'This MCP server provides automated causal inference capabilities by combining LLM-guided variable classification with DoWhy statistical analysis on SQLite banking data. Built with Python using FastMCP, LangGraph, and OpenAI''s GPT-3.5-turbo, it features a single tool that takes treatment and outcome variables, uses AI to classify other variables as confounders, mediators, effect modifiers, colliders, or instruments, generates causal graphs in DOT format, and executes DoWhy code to estimate Average Treatment Effects using backdoor adjustment with linear regression. The implementation includes both standalone agent and MCP server versions, automatically generates plain-language business summaries of causal effects, and works with predefined banking variables like customer demographics, engagement metrics, and Internet Banking activation, making it valuable for business analysts exploring causal relationships in customer data without requiring deep statistical expertise.', '@lethienhoavn', 'databases', 'Unknown', 23, 'https://github.com/lethienhoavn/auto-causal-inference', NULL, 0, 'https://github.com/lethienhoavn.png?size=128', '2026-03-09T05:21:02.024428+00:00'),
  ('letta-railway', 'Letta Railway', 'This Railway-deployable MCP server implementation by SNYCFIRE-CORE bridges AI clients with Letta.ai agents through HTTP transport, enabling stateful conversations without requiring clients to manage conversation history. Built with FastMCP and Python, it provides comprehensive agent lifecycle management (creation, configuration, deletion), memory block operations for persistent context storage, tool attachment/detachment capabilities, and conversation export functionality. The implementation includes robust error handling, retry logic, streaming support, and Railway-specific deployment configurations, making it particularly useful for teams wanting to integrate Letta''s stateful AI agents into existing workflows through any MCP-compatible client like Claude Desktop, GitHub Copilot, or Cursor while maintaining persistent agent memory across sessions.', '@snycfire-core', 'development', 'Unknown', 5, 'https://github.com/snycfire-core/letta-mcp-server-railway', NULL, 0, 'https://github.com/snycfire-core.png?size=128', '2026-03-09T05:21:02.024457+00:00'),
  ('letzai', 'LetzAI', 'LetzAI-MCP is a server that connects AI assistants to the LetzAI image generation API, enabling image creation and upscaling through natural language. The implementation provides two main tools: image generation with customizable parameters like dimensions, quality, and creativity, and image upscaling with adjustable strength. Built with TypeScript and the Model Context Protocol SDK, the server handles authentication via API keys, manages asynchronous image processing with progress updates, and automatically opens completed images in the user''s browser. This integration is particularly valuable for users who want to generate or enhance images directly through AI assistants without switching to a separate interface.', '@letz-ai', 'development', 'Unknown', 2, 'https://github.com/letz-ai/letzai-mcp', NULL, 0, 'https://github.com/letz-ai.png?size=128', '2026-03-09T05:21:02.024486+00:00'),
  ('grafana-loki', 'Grafana Loki', 'Integrates with Grafana Loki''s log aggregation platform to execute LogQL queries, retrieve label metadata, analyze series data, gather index statistics, and check server health for troubleshooting and observability insights.', '@lexfrei', 'data-analytics', 'Unknown', 1, 'https://github.com/lexfrei/mcp-loki', NULL, 0, 'https://github.com/lexfrei.png?size=128', '2026-03-09T05:21:02.024563+00:00'),
  ('xcode-localizable-xcstrings', 'Xcode Localizable.xcstrings', 'This Rust-based MCP server provides translation management for Xcode''s Localizable.xcstrings files, offering both programmatic access through MCP tools and a web-based editing interface. Built with Tokio for async operations and featuring dual-mode operation (default path vs dynamic path), it supports comprehensive translation operations including CRUD operations for translations, plural variation handling, comment management, and key renaming across multiple languages. The implementation includes thread-safe in-memory caching with automatic persistence, search and filtering capabilities, and a single-page web application for browsing and editing translations when configured with a default xcstrings file path, making it valuable for iOS/macOS developers managing localization workflows, translation teams working with Apple''s xcstrings format, and development teams needing both automated and manual translation management capabilities.', '@lexrus', 'development', 'Unknown', 17, 'https://github.com/lexrus/xcstrings_mcp', NULL, 0, 'https://github.com/lexrus.png?size=128', '2026-03-09T05:21:02.024618+00:00'),
  ('system-bridge', 'System Bridge', 'This MCP server provides a simple bridge to native OS functionalities, offering three core tools for system interaction: opening URLs in the default browser with automatic scheme handling and validation, copying text to the clipboard, and retrieving comprehensive current date/time information including ISO formats, timestamps, day/month names, leap year status, and quarter calculations. Built by leynier using Python with FastMCP and pyperclip, it focuses on basic but essential system operations that AI assistants commonly need, making it valuable for workflows requiring URL launching, clipboard management, or detailed temporal data without external API dependencies.', '@leynier', 'ai-ml', 'Unknown', 10, 'https://github.com/leynier/mcp-sys-bridge', 'mcp-sys-bridge', 4034, 'https://github.com/leynier.png?size=128', '2026-03-09T05:21:02.024664+00:00'),
  ('surrealdb', 'SurrealDB', 'SurrealDB MCP Server provides a Python-based bridge to SurrealDB''s multi-model database, enabling AI assistants to perform graph, document, and relational database operations through a comprehensive set of tools. Built with FastMCP and featuring connection pooling for performance, it exposes ten core database operations including query execution, CRUD operations, graph relations, and bulk operations like insert and upsert. The implementation handles SurrealDB''s unique features like record IDs and graph traversal syntax, making it valuable for applications requiring complex data relationships, real-time analytics, and multi-model data storage without requiring direct database knowledge.', '@lfnovo', 'databases', 'Unknown', 6, 'https://github.com/lfnovo/surreal-mcp', 'surreal-mcp', 2289, 'https://github.com/lfnovo.png?size=128', '2026-03-09T05:21:02.024675+00:00'),
  ('xrp-ledger', 'XRP Ledger', 'XRPL MCP Server provides AI models with direct access to XRP Ledger data and functionality through a standardized interface. It enables querying account information, trust lines, NFTs, transaction history, order book data, and submitting signed transactions to the network. Built with Python using the xrpl-py library and FastMCP framework, it connects to public XRPL nodes by default but can be configured for private node connections. This implementation is valuable for AI assistants that need to retrieve real-time blockchain data or interact with the XRP Ledger ecosystem.', '@lgcarrier', 'ai-ml', 'Unknown', 11, 'https://github.com/lgcarrier/xrpl-mcp-server', NULL, 0, 'https://github.com/lgcarrier.png?size=128', '2026-03-09T05:21:02.024715+00:00'),
  ('motor-current-signature-analysis', 'Motor Current Signature Analysis', 'MCP server for Motor Current Signature Analysis — fault detection in electric motors', '@lgdimaggio', 'development', 'Unknown', 2, 'https://github.com/lgdimaggio/mcp-motor-current-signature-analysis', NULL, 0, 'https://github.com/lgdimaggio.png?size=128', '2026-03-09T05:21:02.024766+00:00'),
  ('rei3-tickets', 'REI3 Tickets', 'This REI3 Tickets MCP server by Lukas Jeckle provides ticket management capabilities for the REI3 ticketing system through a comprehensive API integration. Built with Python using FastMCP, Django, and httpx, it offers tools for creating tickets, managing worklogs, retrieving ticket information, and closing tickets, with configurable ticket key formatting and authentication handling. The implementation features both standalone MCP server operation and optional Django web interface for configuration management, Docker deployment support, and robust error handling with bearer token authentication, making it valuable for teams using REI3 for issue tracking who need AI-assisted ticket management, automated workflow integration, and streamlined ticket operations within their existing REI3 infrastructure.', '@lgndluke', 'cloud', 'Unknown', 4, 'https://github.com/lgndluke/rei3-tickets-mcp-server', NULL, 0, 'https://github.com/lgndluke.png?size=128', '2026-03-09T05:21:02.024790+00:00'),
  ('io-github-lordmendes-lgpd-mcp', 'io.github.LordMendes/lgpd-mcp', 'MCP Server para conformidade LGPD. Ferramentas de bases legais, consentimento, PIA e políticas.', '@lordmendes', 'development', 'Unknown', 1, 'https://github.com/lordmendes/lgpd-mcp', NULL, 0, 'https://github.com/lordmendes.png?size=128', '2026-03-09T05:21:02.024808+00:00'),
  ('archicad', 'ArchiCAD', 'This MCP server implementation by Luka Gradisar provides AI assistants with direct access to ArchiCAD''s API functionality through the Tapir command system. Built with Python using FastMCP and the official ArchiCAD Python library, it dynamically registers all available Tapir commands from ArchiCAD''s command definitions and schema files, automatically handling input validation and parameter resolution. The implementation parses JavaScript-based command definitions to create properly typed MCP tools, enabling AI models to perform architectural modeling operations, element manipulation, and project management tasks within ArchiCAD. It serves architects and designers who want to integrate AI assistance into their CAD workflows, allowing for automated building design tasks, parametric modeling operations, and project analysis through conversational interfaces.', '@lgradisar', 'development', 'Unknown', 12, 'https://github.com/lgradisar/archicad-mcp', NULL, 0, 'https://github.com/lgradisar.png?size=128', '2026-03-09T05:21:02.024838+00:00'),
  ('whatsapp-bridge', 'WhatsApp Bridge', 'WhatsApp MCP Server provides a secure bridge to your personal WhatsApp account, enabling AI assistants to search messages, manage contacts, and send messages through standardized tools. The implementation uses a two-component architecture with a Go-based WhatsApp bridge that connects to the WhatsApp web API via the whatsmeow library, storing all messages locally in SQLite, and a Python MCP server that exposes functionality through nine specialized tools. Designed for privacy, it keeps your message history on your device while allowing controlled AI access to your conversations for tasks like finding past information or sending new messages.', '@lharries', 'databases', 'Unknown', 5389, 'https://github.com/lharries/whatsapp-mcp', NULL, 0, 'https://github.com/lharries.png?size=128', '2026-03-09T05:21:02.024864+00:00'),
  ('obsidian-vault-manager', 'Obsidian Vault Manager', 'An MCP server for Obsidian vault management that provides advanced template-based note creation and link management capabilities. The implementation features a template engine with variable substitution, file system utilities with path validation and sanitization, and comprehensive tools for creating notes from templates, managing wiki-style links, and organizing knowledge bases. Built with TypeScript and the Model Context Protocol SDK, it includes safety features like directory traversal protection and supports Japanese locale formatting for dates and times, making it useful for automated note-taking workflows, knowledge management systems, and AI-assisted content creation within Obsidian vaults.', '@libra850', 'development', 'Unknown', 1, 'https://github.com/libra850/obsidian-mcp-server', NULL, 0, 'https://github.com/libra850.png?size=128', '2026-03-09T05:21:02.024947+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('libragen', 'Libragen', 'Create private, local RAG libraries from files or Git repositories using hybrid search (vector + BM25). Libraries are stored as shareable SQLite files with embeddings, enabling offline operation without API keys or cloud services. Supports collections, cross-encoder reranking, and language-aware chunking.', '@libragen', 'databases', 'Unknown', 17, 'https://github.com/libragen/libragen', NULL, 0, 'https://github.com/libragen.png?size=128', '2026-03-09T05:21:02.024957+00:00'),
  ('parseflow', 'ParseFlow', 'ParseFlow is an AI-driven document parsing library that extracts text and data from multiple file formats including PDF (with encryption support, merging, splitting, watermarking), Word documents, Excel spreadsheets, PowerPoint presentations, and images (OCR in 12 languages). It offers semantic search capabilities using AI vector embeddings and batch processing for handling multiple files in parallel.', '@libres-coder', 'ai-ml', 'Unknown', 2, 'https://github.com/libres-coder/parseflow', NULL, 0, 'https://github.com/libres-coder.png?size=128', '2026-03-09T05:21:02.024988+00:00'),
  ('libresprite', 'LibreSprite', 'LibreSprite MCP server that enables AI assistants to control the LibreSprite pixel art editor through JavaScript scripting. Since LibreSprite lacks a command-line interface, this implementation uses a clever relay architecture where a Flask proxy server bridges communication between the MCP server and a JavaScript script running inside LibreSprite that polls for commands via HTTP requests. The server provides tools for executing JavaScript scripts within LibreSprite''s context, along with documentation resources and examples for common pixel art operations like image manipulation, color processing, and animation effects, making it valuable for automated pixel art creation, batch image processing, and programmatic sprite generation workflows.', '@snehil-shah', 'ai-ml', 'Unknown', 13, 'https://github.com/snehil-shah/libresprite-mcp', 'libresprite-mcp', 2615, 'https://github.com/snehil-shah.png?size=128', '2026-03-09T05:21:02.025042+00:00'),
  ('licensespring', 'LicenseSpring', 'This LicenseSpring MCP server provides AI assistants with direct access to LicenseSpring''s license management platform through both License API and Management API integrations, enabling comprehensive software license lifecycle operations including activation, validation, consumption tracking, and customer management. The implementation features dual server architecture with separate endpoints for license operations and administrative functions, supports HMAC-SHA256 authentication with graceful degradation for different subscription tiers, and includes extensive tooling for trial key generation, floating license management, and bulk operations. Built with TypeScript and comprehensive test coverage, it''s particularly valuable for software vendors and license administrators who need natural language access to license provisioning, customer onboarding workflows, and license compliance monitoring without directly accessing the LicenseSpring dashboard.', '@stier1ba', 'development', 'Unknown', 2, 'https://github.com/stier1ba/licensespring-mcp', '@tfedorko/licensespring-mcp-server', 3659, 'https://github.com/stier1ba.png?size=128', '2026-03-09T05:21:02.025079+00:00'),
  ('lician-financial-data', 'Lician Financial Data', 'Connects to Lician''s financial data API to provide comprehensive stock market data across US and European markets. Supports retrieval of real-time and historical stock prices, income statements, balance sheets, cash flow statements, insider trading activity, institutional holdings from 13F filings, analyst ratings, SEC filings, and company information. Offers a free tier with 100 requests per day and optional API key for higher rate limits.', '@sebastianbo', 'finance', 'Unknown', 0, 'https://github.com/sebastianbo/quant-platform/tree/HEAD/mcp-server', NULL, 0, 'https://github.com/sebastianbo.png?size=128', '2026-03-09T05:21:02.025133+00:00'),
  ('lightdash', 'Lightdash', 'Enables AI assistants to interact directly with Lightdash data. Browse and understand data models, find relevant metrics and dimensions, switch between projects, and execute queries while respecting existing data governance and access controls.', '@unknown', 'productivity', 'Unknown', 0, 'https://docs.lightdash.com/guides/lightdash-mcp', NULL, 0, NULL, '2026-03-09T05:21:02.025197+00:00'),
  ('ssh-tools', 'SSH Tools', 'The SSH Tools MCP server provides a secure interface for AI assistants to connect to and interact with remote servers via SSH. Built using the FastMCP framework and Paramiko library, it exposes three core tools: connecting to SSH servers, executing commands on connected servers, and disconnecting from sessions. This implementation maintains a single global connection state, allowing for persistent SSH sessions throughout a conversation, making it particularly valuable for system administration tasks, server diagnostics, and remote management workflows that require command execution across multiple interactions.', '@lightfate', 'productivity', 'Unknown', 1, 'https://github.com/lightfate/ssh-tools-mcp', NULL, 0, 'https://github.com/lightfate.png?size=128', '2026-03-09T05:21:02.025239+00:00'),
  ('lighthouse-performance-auditing', 'Lighthouse Performance Auditing', 'This MCP server provides comprehensive Lighthouse performance analysis capabilities through automated web performance auditing and deep analysis tools. Built with TypeScript and featuring integration with Google''s Lighthouse engine, Puppeteer, and Chrome launcher, it offers four core tools: URL analysis with configurable device types and audit categories, deep analysis with critical request chain examination and unused code detection, batch analysis for multiple URLs in parallel, and prompt generation for AI-assisted performance optimization workflows. The implementation includes specialized analyzers for Core Web Vitals, performance patterns, problem detection, and score breakdowns, with browser pool management for efficient parallel processing and comprehensive reporting that generates prioritized recommendations with impact assessments, making it ideal for web developers, performance engineers, and automated CI/CD pipelines that need programmatic access to detailed website performance insights and optimization guidance.', '@mizchi', 'development', 'Unknown', 3, 'https://github.com/mizchi/lighthouse-mcp', NULL, 0, 'https://github.com/mizchi.png?size=128', '2026-03-09T05:21:02.025278+00:00'),
  ('io-github-refined-element-lightning-enable-mcp', 'io.github.refined-element/lightning-enable-mcp', 'AI agent Lightning payments: pay invoices, L402 auto-pay, wallet balance, payment history', '@refined-element', 'development', 'Unknown', 4, 'https://github.com/refined-element/lightning-enable-mcp', NULL, 0, 'https://github.com/refined-element.png?size=128', '2026-03-09T05:21:02.025298+00:00'),
  ('lightning-wallet', 'Lightning Wallet', 'Integrates with the Lightning Faucet AI Agent Wallet to give agents their own Bitcoin wallets on the Lightning Network. Supports L402 protocol for pay-per-request API access, keysend payments, BOLT11 invoice management, webhook notifications, and spending analytics. Includes operator controls for account management, key rotation, and fund withdrawal.', '@lightningfaucet', 'ai-ml', 'Unknown', 6, 'https://github.com/lightningfaucet/lightning-wallet-mcp', 'lightning-wallet-mcp', 1351, 'https://github.com/lightningfaucet.png?size=128', '2026-03-09T05:21:02.025331+00:00'),
  ('light-research', 'Light Research', 'This lightweight MCP server by Code-Hex provides efficient web content search and extraction capabilities through DuckDuckGo''s HTML endpoint and GitHub''s Code Search API, eliminating API costs while delivering clean, LLM-optimized content. The implementation combines Playwright-based browser automation with Mozilla''s Readability library and DOMPurify sanitization to extract and convert web content into clean Markdown format, supporting both interactive CLI usage and programmatic integration. It''s particularly valuable for AI assistants that need to research documentation, find code examples, and extract structured content from web pages with built-in rate limiting, locale support, and robust error handling for production use cases.', '@code-hex', 'development', 'Unknown', 7, 'https://github.com/code-hex/light-research-mcp', NULL, 0, 'https://github.com/code-hex.png?size=128', '2026-03-09T05:21:02.025356+00:00'),
  ('reddit-insights', 'Reddit Insights', 'MCP server for AI-powered Reddit search and discovery. Provides tools for natural language semantic search across millions of Reddit posts, browsing and exploring subreddit communities with pagination, retrieving detailed subreddit information, and discovering trending articles and insights. Integrates with the Reddit Insights API and supports an optional API key for premium features.', '@lignertys', 'ai-ml', 'Unknown', 0, 'https://github.com/lignertys/reddit-insights-mcp', NULL, 0, 'https://github.com/lignertys.png?size=128', '2026-03-09T05:21:02.025390+00:00'),
  ('git-tools', 'Git Tools', 'This MCP server implementation provides Git tools for the Model Context Protocol. It integrates with the MCP Core, Server, and Macros libraries to enable Git-related operations. The server is built using Rust and leverages asynchronous programming with Tokio. It''s designed for use cases requiring version control integration within AI-assisted applications, such as managing code repositories or tracking changes in collaborative environments.', '@lileeei', 'development', 'Unknown', 8, 'https://github.com/lileeei/mcp-git-tools', 'mcp-git-tools', 0, 'https://github.com/lileeei.png?size=128', '2026-03-09T05:21:02.025427+00:00'),
  ('lilo-property', 'Lilo Property', 'Provides AI agents with tools to search vacation rental properties, check availability and pricing, create bookings with instant confirmation, and assess guest risk. Includes fraud detection capabilities such as extortion pattern detection and squatter risk analysis across all 50 US states.', '@lilo-property', 'ai-ml', 'Unknown', 0, 'https://github.com/lilo-property/mcp-server', NULL, 0, 'https://github.com/lilo-property.png?size=128', '2026-03-09T05:21:02.025469+00:00'),
  ('ssh-remote-control', 'SSH Remote Control', 'Provides SSH remote control capabilities through the Model Context Protocol, enabling secure command execution and file transfer operations on remote servers. Built with TypeScript and leverages the ssh2 library for SSH connectivity, offering session management, SFTP client functionality, and comprehensive validation utilities. Useful for automating server administration tasks, deploying applications, managing remote configurations, or integrating SSH operations into AI-assisted workflows.', '@lilyjem', 'development', 'Unknown', 1, 'https://github.com/lilyjem/ssh', NULL, 0, 'https://github.com/lilyjem.png?size=128', '2026-03-09T05:21:02.025496+00:00'),
  ('limitless-lifelog', 'Limitless Lifelog', 'The Limitless MCP Server provides AI assistants with access to the Limitless API for retrieving and searching personal lifelogs recorded via the Limitless Pendant. Developed by Ryan Boyle, this TypeScript implementation offers five specialized tools for interacting with lifelog data: retrieving logs by ID, listing logs by date or time range, fetching recent recordings, and performing keyword searches within log content. The server handles API authentication, pagination, error management, and result formatting while providing clear guidance on tool selection—recommending list operations for conceptual analysis and reserving search functionality specifically for keyword queries. It''s particularly useful for users who want their AI assistants to analyze their Limitless recordings for summaries, action items, and key topics without requiring direct API access.', '@boyleryan', 'development', 'Unknown', 22, 'https://github.com/boyleryan/mcp-limitless-server', NULL, 0, 'https://github.com/boyleryan.png?size=128', '2026-03-09T05:21:02.025543+00:00'),
  ('vs-code-diagnostics', 'VS Code Diagnostics', 'MCP server for reading VS Code diagnostics via Debug Adapter Protocol, enabling AI assistants to access error messages, warnings, and other diagnostic information from VS Code workspaces. Built with TypeScript and the vscode-debugadapter library, it provides tools to retrieve diagnostic data from active VS Code sessions, making it valuable for debugging workflows, code analysis, and automated error resolution tasks where AI assistants need visibility into IDE-level diagnostic information.', '@lin037', 'development', 'Unknown', 11, 'https://github.com/lin037/mcp-diagnostics-trae', NULL, 0, 'https://github.com/lin037.png?size=128', '2026-03-09T05:21:02.025570+00:00'),
  ('papersearch-arxiv', 'PaperSearch (arXiv)', 'This papersearch MCP implementation provides an interface for querying academic papers from the arXiv repository. Built with Python using the arxiv library, it enables AI assistants to search for and retrieve metadata about scientific publications. The implementation supports functions like searching by keyword, retrieving paper details, and listing recent submissions across different subject categories. It stands out by focusing specifically on arXiv as a data source, making it particularly useful for researchers, students, and academics who want to leverage AI assistance in literature reviews, staying updated on recent publications, or exploring connections between papers in their field of study.', '@lincest', 'ai-ml', 'Unknown', 4, 'https://github.com/lincest/mcp-papersearch', NULL, 0, 'https://github.com/lincest.png?size=128', '2026-03-09T05:21:02.025616+00:00'),
  ('linear-issue-tracker', 'Linear Issue Tracker', 'MCP Linear App provides a set of tools for AI assistants to interact with Linear''s issue tracking system. Built with TypeScript and the Linear SDK, it enables searching, creating, and updating issues, managing comments, and retrieving user profiles and team information. The implementation features robust error handling, standardized response formatting, and helper utilities for working with Linear''s API. This server is particularly useful for development teams looking to integrate AI assistants into their project management workflow, allowing for issue creation, status updates, and team collaboration directly through conversation interfaces without switching to the Linear application.', '@zalab-inc', 'development', 'Unknown', 0, 'https://github.com/zalab-inc/mcp-linear-app', NULL, 0, 'https://github.com/zalab-inc.png?size=128', '2026-03-09T05:21:02.025671+00:00'),
  ('pyrunner', 'PyRunner', 'PyRunner provides a Python code execution environment through an integrated Jupyter kernel server, enabling persistent Python sessions with variable retention across multiple runs. Features include kernel management, package operations, semantic search for previously written scripts, and a structured memory system. Particularly useful for data analysis workflows requiring expensive initialization steps that benefit from state persistence.', '@linen920611', 'development', 'Unknown', 2, 'https://github.com/linen920611/pyrunner_mcp', NULL, 0, 'https://github.com/linen920611.png?size=128', '2026-03-09T05:21:02.025715+00:00'),
  ('linggen', 'Linggen', 'Linggen provides persistent architectural context for AI coding assistants through local semantic search. It indexes codebases and tribal knowledge, enabling AI to understand architecture, cross-project dependencies, and long-term decisions. All indexing and vector search via LanceDB happens locally for complete privacy. Free for individuals and teams.', '@linggen', 'development', 'Unknown', 0, 'https://github.com/linggen/linggen-releases', NULL, 0, 'https://github.com/linggen.png?size=128', '2026-03-09T05:21:02.025734+00:00'),
  ('file-system-tools', 'File System Tools', 'MCP-tools provides file system management capabilities for AI assistants through a FastMCP server implementation. Created by Linglai Chen, it offers tools for removing directories, counting PDF files, retrieving detailed file information, and recursively analyzing directory structures with comprehensive error handling. The implementation exposes these file operations as callable tools that enable AI systems to interact with the local file system, making it particularly useful for workflows involving file organization, document management, and directory analysis tasks.', '@linglai27', 'productivity', 'Unknown', 0, 'https://github.com/linglai27/mcp-tools', NULL, 0, 'https://github.com/linglai27.png?size=128', '2026-03-09T05:21:02.025773+00:00'),
  ('lingo-dev-translation', 'Lingo.dev (Translation)', 'Lingo.dev MCP server enables AI assistants to translate content across multiple languages through the Model Context Protocol. Built by the Lingo.dev team, it provides a ''translate'' tool that leverages advanced language models to handle app localization, website content, and other text data. The implementation can be run via npx command with an API key from the Lingo.dev platform, making it accessible from various AI tools including Cursor, Claude desktop, and Cline for VS Code. This integration is particularly valuable for developers and content creators who need to translate materials without leaving their AI assistant workflow.', '@lingodotdev', 'development', 'Unknown', 5348, 'https://github.com/lingodotdev/lingo.dev', 'lingo.dev', 526026, 'https://github.com/lingodotdev.png?size=128', '2026-03-09T05:21:02.025800+00:00'),
  ('lingvanex-translate', 'Lingvanex Translate', 'A translation MCP server that integrates with the Backenster translation API to provide text translation capabilities between different languages. The implementation supports both HTTP and stdio transport modes, with configurable environment variables for API credentials and server settings. Built with TypeScript and Express, it offers a single translate_text tool that accepts source text, source language code, and target language code parameters, making it useful for applications that need multilingual content translation or language processing workflows.', '@lingvanex-mt', 'development', 'Unknown', 0, 'https://github.com/lingvanex-mt/mcp-lingvanex-translate', NULL, 0, 'https://github.com/lingvanex-mt.png?size=128', '2026-03-09T05:21:02.025825+00:00'),
  ('linkbreakers', 'Linkbreakers', 'Integrates with the Linkbreakers QR-driven customer journey platform. Create and manage tracked QR codes, short links, and campaign workflows through natural language. Analyze scan performance metrics, automate multi-step workflows, and manage lead capture pipelines without manual API calls.', '@linkbreakers-com', 'development', 'Unknown', 0, 'https://github.com/linkbreakers-com/api', NULL, 0, 'https://github.com/linkbreakers-com.png?size=128', '2026-03-09T05:21:02.025884+00:00'),
  ('linked-api', 'Linked API', 'This MCP server provides comprehensive access to LinkedIn automation and data extraction through the Linked API service. Built with TypeScript and the Model Context Protocol SDK, it offers 25+ tools covering standard LinkedIn operations (messaging, connections, posts, searches) and Sales Navigator functionality, with built-in support for background workflow processing that keeps clients responsive during long-running operations. The implementation handles authentication via API tokens, includes progress tracking for multi-minute LinkedIn workflows, and provides both HTTP and stdio transport options with Docker deployment support. Designed for sales professionals, recruiters, and developers building LinkedIn automation workflows, it enables use cases like lead generation, relationship management, content engagement, and data extraction without directly interfacing with LinkedIn''s complex automation requirements.', '@linked-api', 'cloud', 'Unknown', 44, 'https://github.com/linked-api/linkedapi-mcp', 'linkedapi-mcp', 1511, 'https://github.com/linked-api.png?size=128', '2026-03-09T05:21:02.025909+00:00'),
  ('linkly', 'Linkly', 'Linkly enables creation and management of branded short links with comprehensive analytics. Features include custom domains, UTM parameters, retargeting pixels, QR codes, geo and device-based targeting, link expiration, and real-time click tracking with detailed breakdowns by country, platform, browser, and referrer.', '@linkly-hq', 'development', 'Unknown', 0, 'https://github.com/linkly-hq/linkly-mcp-server', NULL, 0, 'https://github.com/linkly-hq.png?size=128', '2026-03-09T05:21:02.025930+00:00'),
  ('linkup', 'Linkup', 'A web search and content fetching MCP server built by Linkup that provides real-time access to current information through two core tools: web search with configurable depth (standard for direct answers, deep for complex research) and URL content extraction with optional JavaScript rendering. The implementation uses the Linkup SDK to deliver search results and webpage content as JSON responses, with proper error handling and API key authentication. Useful for retrieving breaking news, current events, real-time data like weather and stock prices, product information, and any up-to-date content not available in AI training data.', '@linkupplatform', 'ai-ml', 'Unknown', 24, 'https://github.com/linkupplatform/linkup-mcp-server', NULL, 0, 'https://github.com/linkupplatform.png?size=128', '2026-03-09T05:21:02.025976+00:00'),
  ('linkup-search', 'Linkup Search', 'This MCP server, developed by Linkup Technologies, enables AI assistants to perform web searches using the Linkup API. It leverages the Linkup SDK and MCP library to provide a standardized interface for executing search queries and retrieving results. The server abstracts the complexities of API interactions, offering a simple way for AI systems to access web search capabilities. By connecting AI assistants with Linkup''s search technology, this implementation facilitates tasks such as information gathering, fact-checking, and research. It is particularly useful for AI applications requiring up-to-date web information, like question-answering systems, content generation tools, or any AI that needs to augment its knowledge with current web data.', '@linkupplatform', 'productivity', 'Unknown', 41, 'https://github.com/linkupplatform/python-mcp-server', 'mcp-search-linkup', 95558, 'https://github.com/linkupplatform.png?size=128', '2026-03-09T05:21:02.026018+00:00'),
  ('linux-admin', 'Linux Admin', 'Provides read-only diagnostic tools for Linux system administration on RHEL-based systems. Connects to remote hosts via SSH with key-based authentication and supports multi-host management within single sessions. Includes tools for inspecting services, processes, logs, network configuration, storage, and system information. All operations are strictly read-only for safe diagnostics, with configurable log file access through environment variables.', '@rhel-lightspeed', 'ai-ml', 'Unknown', 182, 'https://github.com/rhel-lightspeed/linux-mcp-server', NULL, 0, 'https://github.com/rhel-lightspeed.png?size=128', '2026-03-09T05:21:02.026058+00:00'),
  ('atest', 'atest', 'Integrates with the atest API testing framework to enable comprehensive API testing, debugging, and mocking workflows. Supports YAML-based test definitions, multiple database backends including SQLite, MySQL, PostgreSQL, and TDengine, and generates test reports in Markdown, HTML, and stdout formats. Provides tools for verifying Kubernetes resources and running automated test suites with configurable duration and threading.', '@linuxsuren', 'databases', 'Unknown', 4, 'https://github.com/linuxsuren/atest-mcp-server', NULL, 0, 'https://github.com/linuxsuren.png?size=128', '2026-03-09T05:21:02.026068+00:00'),
  ('lotus-wisdom', 'Lotus Wisdom', 'Provides structured problem-solving tools that guide reasoning through multiple wisdom domains representing different thinking approaches, from analytical examination to meditative reflection. Includes contemplative thinking methodology with meditation pauses and visual journey tracking.', '@linxule', 'ai-ml', 'Unknown', 21, 'https://github.com/linxule/lotus-wisdom-mcp', NULL, 0, 'https://github.com/linxule.png?size=128', '2026-03-09T05:21:02.026095+00:00'),
  ('mineru', 'MinerU', 'MinerU document parsing API — PDFs, images, DOCX, PPTX with OCR and batch processing.', '@linxule', 'media', 'Unknown', 1, 'https://github.com/linxule/mineru-mcp', NULL, 0, 'https://github.com/linxule.png?size=128', '2026-03-09T05:21:02.026132+00:00'),
  ('what2watch', 'What2Watch', 'Connects AI assistants to real-time TV schedules across 1000+ channels, streaming availability from major services (Netflix, Disney+, HBO Max) and free platforms (Pluto TV, Tubi), and personalized content recommendations. Features content search by title, actor, or director, mood-based suggestions, and a ''Surprise Me'' mode for discovering underrated content.', '@lio1204', 'ai-ml', 'Unknown', 0, 'https://github.com/lio1204/what2watch-mcp', NULL, 0, 'https://github.com/lio1204.png?size=128', '2026-03-09T05:21:02.026165+00:00'),
  ('chain-of-thought-task-manager', 'Chain of Thought Task Manager', 'MCP Chain of Thought is a task management system built for AI agents that emphasizes structured reasoning through chain-of-thought, reflection, and style consistency. Developed by liorfranko, it converts natural language into organized development tasks with dependency tracking, implementation guides, and verification criteria. The system features a workflow that guides agents through planning, analysis, reflection, task decomposition, and execution phases, with built-in memory management to prevent context loss during complex problem-solving. It''s particularly valuable for developers working with reasoning-focused AI systems that need to maintain coherent thought processes across multiple interactions.', '@liorfranko', 'development', 'Unknown', 20, 'https://github.com/liorfranko/mcp-chain-of-thought', 'mcp-chain-of-thought', 4654, 'https://github.com/liorfranko.png?size=128', '2026-03-09T05:21:02.026197+00:00'),
  ('multi-llm-cross-check', 'Multi-LLM Cross-Check', 'Multi LLM Cross-Check MCP Server provides a unified interface for querying multiple LLM providers simultaneously, allowing users to compare responses side-by-side. Built with Python using FastMCP, this server integrates with Claude Desktop and supports OpenAI, Anthropic, Perplexity AI, and Google Gemini APIs through asynchronous parallel processing. The implementation handles API authentication, request formatting, and error management for each provider, making it particularly valuable for users who want to cross-reference AI responses for fact-checking, gathering diverse perspectives, or evaluating different models'' capabilities on the same prompt.', '@lior-ps', 'ai-ml', 'Unknown', 14, 'https://github.com/lior-ps/multi-llm-cross-check-mcp-server', NULL, 0, 'https://github.com/lior-ps.png?size=128', '2026-03-09T05:21:02.026244+00:00'),
  ('excel-master', 'Excel Master', 'This MCP server, developed by an unnamed author, provides integration with Excel operations using XLwings. Built with Node.js and leveraging the Model Context Protocol SDK, it enables AI assistants to interact with Excel spreadsheets programmatically. The implementation focuses on bridging the gap between AI and Excel, allowing for automated data manipulation, analysis, and reporting. It''s particularly useful for businesses and analysts who want to incorporate AI-driven insights into their Excel workflows, enabling use cases such as automated financial modeling, data cleansing, and report generation without manual Excel interactions.', '@lipdog', 'ai-ml', 'Unknown', 8, 'https://github.com/lipdog/excel-master-mcp', NULL, 0, 'https://github.com/lipdog.png?size=128', '2026-03-09T05:21:02.026286+00:00'),
  ('lipsky-memory', 'Lipsky Memory', 'Lipsky Memory MCP is a server for managing project context and relationships using Turso database for persistence. It supports tracking entities, maintaining project memory, and handling transactions, currently operational in the Cline environment with ongoing investigation into connection issues in HyperChat.', '@lipdog', 'databases', 'Unknown', 0, 'https://github.com/lipdog/lipsky-memory', NULL, 0, 'https://github.com/lipdog.png?size=128', '2026-03-09T05:21:02.026299+00:00'),
  ('xueqiu-chinese-stock-market', 'Xueqiu (Chinese Stock Market)', 'Xueqiu-MCP provides access to Chinese stock market data through the Xueqiu (雪球) financial platform API. Built with Python using the fastmcp framework, it leverages the pysnowball library to retrieve real-time stock quotes, company financials, market news, and investor sentiment data from one of China''s largest investment communities. This server enables AI assistants to analyze Chinese equities, track market trends, and access financial information that would otherwise be difficult to obtain through Western financial data sources.', '@liqiongyu', 'ai-ml', 'Unknown', 101, 'https://github.com/liqiongyu/xueqiu_mcp', NULL, 0, 'https://github.com/liqiongyu.png?size=128', '2026-03-09T05:21:02.026352+00:00'),
  ('raindrop', 'Raindrop', 'The Raindrop MCP server transforms Claude Code into a complete infrastructure development platform by providing structured workflows for building, deploying, and managing full-stack applications with databases, APIs, and live infrastructure. Built by LiquidMetal AI, it offers three core workflows: creating new applications from scratch through guided requirements gathering and architecture generation, reattaching to existing development sessions with full context restoration, and updating deployed applications with new features. The server handles the entire development lifecycle from PRD creation to live deployment validation, making it valuable for developers who want to go from idea to production-ready application through conversational AI interactions rather than manual infrastructure management.', '@unknown', 'databases', 'Unknown', 0, 'https://docs.liquidmetal.ai/tutorials/claude-code-mcp-setup/', NULL, 0, NULL, '2026-03-09T05:21:02.026362+00:00'),
  ('node-js-api-documentation', 'Node.js API Documentation', 'Node.js API Documentation MCP server by Liran Tal that provides AI assistants with up-to-date access to official Node.js core module documentation through a caching architecture that fetches from nodejs.org/docs/latest/api/all.json. The implementation offers two primary tools: a search tool for discovering available Node.js modules and their methods, and a retrieval tool for getting detailed API documentation for specific modules with optional filtering by class or method names. Built with TypeScript and featuring a 7-day HTTP cache, file-based logging, and Docker support, it serves developers who want conversational access to current Node.js API documentation without relying on potentially outdated LLM training data, emphasizing built-in core modules over third-party libraries for Node.js development guidance.', '@lirantal', 'cloud', 'Unknown', 10, 'https://github.com/lirantal/mcp-server-nodejs-api-docs', 'mcp-server-nodejs-api-docs', 1379, 'https://github.com/lirantal.png?size=128', '2026-03-09T05:21:02.026388+00:00'),
  ('google-serp', 'Google SERP', 'Enables Google search functionality with automatic browser fingerprint rotation per request using Camoufox for stealth web scraping. Offers two modes: lite mode for reduced traffic returning organic results only, and full mode extracting comprehensive data including sitelinks, People Also Ask questions, related searches, and knowledge graphs. Supports location targeting via protobuf encoding with UULE format, validated country and language codes, and time-based filtering options.', '@liranyoffe', 'development', 'Unknown', 5, 'https://github.com/liranyoffe/serp-mcp', NULL, 0, 'https://github.com/liranyoffe.png?size=128', '2026-03-09T05:21:02.026411+00:00'),
  ('owasp-zap', 'OWASP ZAP', 'This ZAP MCP server by LisBerndt provides AI assistants with comprehensive web application security testing capabilities through OWASP ZAP integration, offering both synchronous and asynchronous scanning modes including active vulnerability scanning, passive analysis, traditional spidering, and AJAX crawling with configurable browser engines. Built with Python and FastAPI, it features Docker containerization with automatic ZAP startup, session management with unique timestamping, progress tracking with heartbeat mechanisms to prevent timeouts, and configurable scan policies with evidence collection options. The implementation includes robust HTTP session handling with retry logic, extensive logging capabilities, and supports both direct MCP protocol communication and HTTP endpoints, making it ideal for security professionals and developers who need AI-assisted vulnerability assessment, automated penetration testing workflows, and integration of security scanning into development pipelines through their existing ZAP infrastructure.', '@lisberndt', 'cloud', 'Unknown', 5, 'https://github.com/lisberndt/zap-mcp-server', NULL, 0, 'https://github.com/lisberndt.png?size=128', '2026-03-09T05:21:02.026441+00:00'),
  ('aws-athena', 'AWS Athena', 'This MCP server enables AI assistants to execute SQL queries against AWS Athena databases and retrieve results. Developed by Shen Li, it integrates with the AWS SDK to provide a standardized interface for Athena operations. The server is particularly useful for applications requiring large-scale data analysis, business intelligence, or integration with AWS data lakes.', '@lishenxydlgzs', 'databases', 'Unknown', 40, 'https://github.com/lishenxydlgzs/aws-athena-mcp', '@lishenxydlgzs/aws-athena-mcp', 12292, 'https://github.com/lishenxydlgzs.png?size=128', '2026-03-09T05:21:02.026452+00:00'),
  ('simple-file-vector-store', 'Simple File Vector Store', 'This MCP server, developed by lishenxydlgzs, provides a vector store for local files and directories, enabling semantic search across their contents. Built with TypeScript and leveraging libraries like LangChain and FAISS, it offers tools for initializing the store and performing searches. The implementation focuses on creating embeddings from supported file types (Markdown, HTML, JSON, plain text) using the all-MiniLM-L6-v2 model and storing them efficiently. It''s particularly useful for teams wanting to add semantic search capabilities to their local document repositories, enabling use cases such as context-aware information retrieval, automated document linking, and AI-assisted content exploration without relying on external search services.', '@lishenxydlgzs', 'development', 'Unknown', 39, 'https://github.com/lishenxydlgzs/simple-files-vectorstore', NULL, 0, 'https://github.com/lishenxydlgzs.png?size=128', '2026-03-09T05:21:02.026484+00:00'),
  ('revit', 'Revit', 'Revit-MCP is a Node.js server implementation that enables AI assistants to interact with Autodesk Revit models through the Model Context Protocol. It provides tools for creating, deleting, and modifying Revit objects, with specific functionality for wall creation and object deletion. The server uses a stdio transport layer for communication and implements a tool registration system that allows for extensible Revit model manipulation capabilities, making it particularly valuable for architectural design workflows and BIM (Building Information Modeling) processes.', '@mcp-servers-for-revit', 'development', 'Unknown', 363, 'https://github.com/mcp-servers-for-revit/revit-mcp', NULL, 0, 'https://github.com/mcp-servers-for-revit.png?size=128', '2026-03-09T05:21:02.026511+00:00'),
  ('listenetic', 'Listenetic', 'The Listenetic MCP server provides a unified API for uploading and managing content across a wide range of MIME types, with specialized support for text-based formats like SSML, markdown, and plain text, as well as binary formats like audio files and images. Built around three core tools - listing supported MIME types, creating text-based content, and uploading binary content - it uses Bearer token authentication with JWT tokens and integrates seamlessly with the npx mcp-remote CLI utility for terminal-based interactions. Designed for content creators and developers who need to programmatically upload diverse content types to the Listenetic platform, with optimized handling for audio and markup formats that align with Listenetic''s content processing capabilities.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://app.listenetic.com/mcp', NULL, 0, NULL, '2026-03-09T05:21:02.026561+00:00'),
  ('mousetail', 'Mousetail', 'MCP server connecting Anki flashcard software to LLMs through basic operations like creating, reading, updating, and deleting flashcards. Supports syncing collections with AnkiWeb or self-hosted sync servers. Key differentiator: unlike competing Anki MCP servers, doesn''t require the AnkiConnect addon - integrates directly with Anki''s stable pylib API, prioritizing simplicity and stability over UI integration features.', '@listfold', 'ai-ml', 'Unknown', 11, 'https://github.com/listfold/mousetail', NULL, 0, 'https://github.com/listfold.png?size=128', '2026-03-09T05:21:02.026598+00:00'),
  ('iterm-terminal', 'iTerm Terminal', 'iTerm-MCP provides AI models with direct access to the active iTerm terminal session, enabling efficient interaction with terminal output and command execution. Built by Ferris Lucas, it features tools for reading terminal output, writing commands, and sending control characters, allowing models to inspect only relevant output and interact with REPLs. The implementation requires minimal dependencies, runs via npx, and integrates seamlessly with Claude Desktop and other MCP clients, making it ideal for workflows where users want to share their terminal with AI assistants for troubleshooting, task delegation, or interactive terminal sessions.', '@lite', 'productivity', 'Unknown', 0, 'https://github.com/lite/iterm-mcp', NULL, 0, 'https://github.com/lite.png?size=128', '2026-03-09T05:21:02.026642+00:00'),
  ('io-github-shin-bot-litellm-litellm-mcp', 'io.github.shin-bot-litellm/litellm-mcp', 'Give AI agents access to 100+ LLMs. Call any model, compare outputs.', '@unknown', 'development', 'Unknown', 0, 'https://github.com/shin-bot-litellm/litellm-agent-mcp', NULL, 0, 'https://github.com/shin-bot-litellm.png?size=128', '2026-03-09T05:21:02.026657+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('litmus-edge', 'Litmus Edge', 'This MCP server provides integration with Litmus Edge for industrial IoT device configuration, monitoring, and management, enabling AI assistants to interact with DeviceHub devices, retrieve real-time tag values, manage Docker containers, and configure system settings. Built by Litmus Automation using Python with FastMCP and featuring both stdio and HTTP transport modes, it offers tools for listing supported drivers, creating and managing DeviceHub devices with various protocols, subscribing to NATS topics for real-time data streaming, managing Docker containers through the Litmus Edge Marketplace, and configuring system properties like friendly names and cloud activation status. The implementation includes a web client interface with streaming support for real-time responses, environment variable management, conversation history tracking, and support for both Anthropic and OpenAI models, making it valuable for industrial automation workflows, IoT device management, real-time monitoring dashboards, and any use case requiring programmatic access to Litmus Edge infrastructure for industrial data collection and device orchestration.', '@litmusautomation', 'cloud', 'Unknown', 6, 'https://github.com/litmusautomation/litmus-mcp-server', NULL, 0, 'https://github.com/litmusautomation.png?size=128', '2026-03-09T05:21:02.026717+00:00'),
  ('deno-kv', 'Deno KV', 'DenoKV MCP Server provides a bridge to Deno''s key-value store, enabling AI assistants to perform persistent data storage operations. The implementation offers three core tools for setting, retrieving, and deleting key-value pairs in the Deno KV database. Built with TypeScript using the Model Context Protocol SDK, it runs as a standalone process that communicates via standard I/O. This server is particularly valuable for applications requiring simple persistent storage between sessions without the complexity of a full database system.', '@littledivy', 'databases', 'Unknown', 5, 'https://github.com/littledivy/mcp-deno-kv', NULL, 0, 'https://github.com/littledivy.png?size=128', '2026-03-09T05:21:02.026728+00:00'),
  ('littlesis', 'LittleSis', 'MCP server that provides AI assistants with access to the LittleSis API for tracking corporate power and accountability relationships, built by Nitay Rabinovich using TypeScript and the Model Context Protocol SDK. The implementation offers comprehensive coverage of LittleSis endpoints including entity search and retrieval, relationship mapping between people and organizations, entity type classification, connection discovery, and list membership tracking, with support for filtering by relationship categories, pagination, and detailed metadata extraction. Designed for researchers investigating corporate influence networks, journalists tracking revolving door relationships between business and government, and analysts studying power structures through LittleSis''s open database of who-knows-who at the heights of business and government, with all data licensed under CC BY-SA 4.0.', '@code-rabi', 'databases', 'Unknown', 1, 'https://github.com/code-rabi/littlesis-mcp', 'littlesis-mcp', 431, 'https://github.com/code-rabi.png?size=128', '2026-03-09T05:21:02.026740+00:00'),
  ('cve-tracer', 'CVE Tracer', 'CVE Tracer provides vulnerability scanning capabilities for Java projects by parsing Maven POM files and querying the National Vulnerability Database (NVD) API to identify security issues in project dependencies. The implementation includes tools for querying detailed CVE information including CVSS scores and CWE classifications, as well as analyzing POM files to correlate vulnerabilities with specific dependencies. Useful for security auditing, dependency management, and identifying potential vulnerabilities in Java applications during development or CI/CD processes.', '@liuayng201314', 'databases', 'Unknown', 1, 'https://github.com/liuayng201314/cvetracer', NULL, 0, 'https://github.com/liuayng201314.png?size=128', '2026-03-09T05:21:02.026754+00:00'),
  ('checkstyle', 'Checkstyle', 'Bridges LLMs with local code quality tools, enabling automated linting and fixing across multiple languages. Supports Go (golangci-lint/gofmt), Java (checkstyle/google-java-format), and Lua (luacheck/stylua) with project-level configuration isolation. Offers both stdio mode for local IDE integration and HTTP/SSE mode for remote access, plus a web management console with environment diagnostics and audit logging.', '@liuhua1307', 'development', 'Unknown', 3, 'https://github.com/liuhua1307/checkstyle_mcp', NULL, 0, 'https://github.com/liuhua1307.png?size=128', '2026-03-09T05:21:02.026818+00:00'),
  ('mcp-host-cli', 'MCP Host CLI', 'A simple and easy-to-use MCP Host CLI that provides a command-line interface for creating and managing MCP hosts. Built by Liu Jilong, this tool leverages the Model Context Protocol SDK to establish connections between AI assistants and external services. The implementation includes both client and server components, allowing users to quickly set up an MCP host environment through a streamlined CLI experience. It''s particularly useful for developers looking to integrate AI capabilities with their applications without dealing with complex configuration processes.', '@liujilongobject', 'ai-ml', 'Unknown', 6, 'https://github.com/liujilongobject/mcp-host-use', 'mcp-host-cli', 829, 'https://github.com/liujilongobject.png?size=128', '2026-03-09T05:21:02.026870+00:00'),
  ('apache-superset', 'Apache Superset', 'Superset-MCP-Server provides a TypeScript-based bridge between AI assistants and Apache Superset, enabling direct interaction with data visualization dashboards through the Model Context Protocol. The implementation leverages the MCP SDK to expose Superset''s API functionality, allowing assistants to query, analyze, and visualize data without context switching. Built with a modular architecture that separates API services from HTTP utilities, it includes example code to demonstrate integration patterns and supports environment-based configuration for flexible deployment options.', '@liuscraft', 'development', 'Unknown', 5, 'https://github.com/liuscraft/superset-mcp-server', NULL, 0, 'https://github.com/liuscraft.png?size=128', '2026-03-09T05:21:02.026897+00:00'),
  ('nasa-astronomy-picture-of-the-day', 'NASA Astronomy Picture of the Day', 'NASA APOD MCP Service provides access to NASA''s Astronomy Picture of the Day API within the Cursor IDE. Developed by Simon Liu, this service allows users to retrieve daily astronomy images and their descriptions directly through the Cursor interface. Built with Node.js and Axios, it creates a streamlined connection to NASA''s APOD data, making it valuable for developers working on astronomy-related projects, educational tools, or simply wanting to incorporate stunning space imagery into their applications without leaving their development environment.', '@liuwanglei-tal', 'development', 'Unknown', 2, 'https://github.com/liuwanglei-tal/nasa-mcp', NULL, 0, 'https://github.com/liuwanglei-tal.png?size=128', '2026-03-09T05:21:02.026924+00:00'),
  ('better-playwright', 'Better Playwright', 'Better Playwright MCP provides enhanced browser automation capabilities through both MCP server and HTTP server modes, built with TypeScript and featuring stealth mode to avoid detection, persistent browser profiles, and intelligent HTML snapshot extraction with diff-based optimization. The implementation uses semantic HTML parsing with XPath references and token limiting (23,000 tokens) to stay within AI context limits, while supporting multi-page management, automatic cleanup, and configurable browser settings including Chrome/Chromium selection and headless operation. Designed for AI assistants that need reliable web scraping, form filling, and browser interaction capabilities with robust snapshot caching and performance optimization for production workflows.', '@livoras', 'development', 'Unknown', 13, 'https://github.com/livoras/better-playwright-mcp', 'better-playwright-mcp', 1852, 'https://github.com/livoras.png?size=128', '2026-03-09T05:21:02.027046+00:00'),
  ('python-code-sandbox', 'Python Code Sandbox', 'Provides secure Python code execution in isolated Docker containers with automatic dependency installation, session persistence, and file retrieval for data analysis and visualization tasks.', '@li-xiu-qi', 'cloud', 'Unknown', 1, 'https://github.com/li-xiu-qi/python-code-sandbox-mcp', NULL, 0, 'https://github.com/li-xiu-qi.png?size=128', '2026-03-09T05:21:02.027062+00:00'),
  ('kali-linux-security-tools', 'Kali Linux Security Tools', 'This Kali Linux security testing MCP server provides AI assistants with secure, controlled access to penetration testing tools like nmap, nikto, dirb, gobuster, sqlmap, and wpscan through both MCP protocol and Server-Sent Events streaming. Built with comprehensive security controls including JWT authentication, role-based authorization, command validation with whitelisting, injection detection, and audit logging, it enables safe execution of security scanning tools with configurable resource limits and real-time result streaming. The implementation includes intelligent features like syntax checking, error learning, and task chaining, making it suitable for security professionals who need AI-assisted penetration testing workflows while maintaining strict security boundaries and audit trails for compliance requirements.', '@liyue1000', 'databases', 'Unknown', 1, 'https://github.com/liyue1000/kali_sse', NULL, 0, 'https://github.com/liyue1000.png?size=128', '2026-03-09T05:21:02.027075+00:00'),
  ('lizeur-pdf-ocr', 'Lizeur (PDF OCR)', 'Lizeur is an MCP server that enables AI assistants to extract and read content from PDF documents using Mistral AI''s OCR capabilities. Built with FastMCP, it provides intelligent caching to avoid re-processing documents and returns clean markdown text for easy integration with AI workflows. The implementation uploads PDFs to Mistral''s OCR service, processes the first page, caches results locally for future use, and handles file cleanup automatically, making it valuable for document analysis, content extraction, and AI assistants that need to work with PDF files where OCR accuracy is important.', '@silverbzh', 'ai-ml', 'Unknown', 1, 'https://github.com/silverbzh/lizeur', 'lizeur', 2326, 'https://github.com/silverbzh.png?size=128', '2026-03-09T05:21:02.027118+00:00'),
  ('terminal-command-executor', 'Terminal Command Executor', 'Terminal MCP Server provides secure command-line access for AI assistants, enabling execution of shell commands through a standardized interface. Built with TypeScript and the Model Context Protocol SDK, it validates input commands using Zod schemas and returns both standard output and error streams in a structured format. The server runs on stdio, making it lightweight and easily integrable into existing workflows where programmatic terminal access is needed, while handling errors gracefully to provide meaningful feedback when commands fail.', '@lizthedeveloper', 'development', 'Unknown', 2, 'https://github.com/lizthedeveloper/terminal-mcp-idk', NULL, 0, 'https://github.com/lizthedeveloper.png?size=128', '2026-03-09T05:21:02.027150+00:00'),
  ('remember-the-milk', 'Remember The Milk', 'Integrates with Remember The Milk''s task management API to enable natural language task creation, list management, note attachments, and Smart Add syntax with undo functionality and timezone-aware date handling.', '@ljadach', 'productivity', 'Unknown', 3, 'https://github.com/ljadach/rtm-mcp', NULL, 0, 'https://github.com/ljadach.png?size=128', '2026-03-09T05:21:02.027180+00:00'),
  ('apollo-io', 'Apollo.io', 'Apollo.io MCP Server provides seamless integration with the Apollo.io API, enabling AI assistants to access and manipulate sales intelligence data. Developed by Lakhvinder Singh, this TypeScript implementation exposes five core tools for enriching people and organization data, searching for contacts and companies, and retrieving job postings. The server authenticates via Apollo.io API keys, supports optional authentication server integration through mcp-proxy-auth, and is designed with extensibility in mind for adding new Apollo.io capabilities. It''s particularly valuable for sales teams and recruiters who need to access up-to-date contact information, company details, and job listings directly through their AI assistants.', '@lkm1developer', 'development', 'Unknown', 35, 'https://github.com/lkm1developer/apollo-io-mcp-server', NULL, 0, 'https://github.com/lkm1developer.png?size=128', '2026-03-09T05:21:02.027212+00:00'),
  ('kakaotalk-emoticons', 'KakaoTalk Emoticons', 'Automates KakaoTalk emoticon creation through a FastAPI-based MCP server. Provides tools for generating emoticons using Hugging Face AI models, creating preview pages for planning and final review, and validating sets against KakaoTalk''s submission specifications. Supports static, animated, large, and mini emoticon formats with automatic WebP conversion.', '@llaa33219', 'ai-ml', 'Unknown', 1, 'https://github.com/llaa33219/playmcp-kakaotalk-emoticon', NULL, 0, 'https://github.com/llaa33219.png?size=128', '2026-03-09T05:21:02.027269+00:00'),
  ('llm-jukebox', 'LLM Jukebox', 'This MCP server enables LLMs to search, download, and play YouTube music through integration with yt-dlp for video downloading and pygame for audio playback. Built with FastMCP and featuring async operations with progress tracking, it provides tools for YouTube music search, MP3 conversion with FFmpeg, local music library management using TinyDB, and basic playback controls including play and stop functionality. The implementation maintains a persistent database of downloaded tracks with metadata like title, artist, duration, and download date, making it valuable for building AI-powered music discovery and playback systems that can autonomously find, acquire, and organize music collections from YouTube while respecting legal considerations around personal use and copyright compliance.', '@jabberjabberjabber', 'databases', 'Unknown', 6, 'https://github.com/jabberjabberjabber/llm-jukebox', NULL, 0, 'https://github.com/jabberjabberjabber.png?size=128', '2026-03-09T05:21:02.027307+00:00'),
  ('llm-search-engine', 'LLM Search Engine', 'Public MCP server for the LLM Search Engine (LLMSE). Provides AI assistants with tools to classify websites, analyze SEO quality, evaluate E-E-A-T (Experience, Expertise, Authoritativeness, Trustworthiness) signals, match relevant advertisers to websites, and discover competitor sites. Operates as a remote-only streamable-http endpoint with no local installation required.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://llmse.ai', NULL, 0, NULL, '2026-03-09T05:21:02.027341+00:00'),
  ('paperbanana', 'PaperBanana', 'Automated academic illustration generation framework that creates publication-quality methodology diagrams and statistical plots from text descriptions using a multi-agent pipeline powered by Google Gemini. Features five specialized agents (Retriever, Planner, Stylist, Visualizer, Critic) that work together through linear planning and iterative refinement phases. Includes VLM-as-Judge evaluation across four dimensions (faithfulness, conciseness, readability, aesthetics) and supports both methodology diagrams for system architectures and statistical plots with matplotlib code generation.', '@llmsresearch', 'development', 'Unknown', 1105, 'https://github.com/llmsresearch/paperbanana', NULL, 0, 'https://github.com/llmsresearch.png?size=128', '2026-03-09T05:21:02.027369+00:00'),
  ('llms-txt', 'LLMs.txt', 'LLMsTXT Agent is a remote server that provides standardized documentation retrieval for Large Language Models by accessing llms.txt files from websites. It follows a two-tier approach: first checking for documentation at the source website, then falling back to a central repository at llmtxt.dev when primary sources are unavailable. The service delivers real-time documentation updates in a consistent format optimized for LLM consumption, and offers multiple connection methods including MCP Inspector, Cursor IDE integration, and direct CLI access.', '@unknown', 'ai-ml', 'Unknown', 0, 'https://llmtxt.dev/mcp', NULL, 0, NULL, '2026-03-09T05:21:02.027412+00:00'),
  ('iot-edge-bridge', 'IoT Edge Bridge', 'Bridges industrial IoT systems with multiple protocol support including MQTT, Modbus RTU/TCP, Redis, and InfluxDB integration. Offers both full IoT connectivity and simulation modes, with the simulation version providing mock sensor data and device interactions for development and testing without requiring actual hardware. Built with FastAPI and featuring PolyMCP agent orchestration capabilities, it enables industrial automation monitoring, sensor data analysis, device control operations, and IoT system prototyping.', '@poly-mcp', 'databases', 'Unknown', 20, 'https://github.com/poly-mcp/iot-edge-mcp-server', NULL, 0, 'https://github.com/poly-mcp.png?size=128', '2026-03-09T05:21:02.027463+00:00'),
  ('io-github-linagora-llng-mcp', 'io.github.linagora/llng-mcp', 'Manage LemonLDAP::NG SSO instances: configuration, sessions, OIDC, SAML, 2FA.', '@unknown', 'development', 'Unknown', 0, 'https://www.pulsemcp.com/servers/llng-mcp', NULL, 0, NULL, '2026-03-09T05:21:02.027477+00:00'),
  ('lark-bitable', 'Lark Bitable', 'Bitable MCP Server provides access to Lark Bitable through the Model Context Protocol, allowing AI assistants to interact with Bitable tables using SQL-like queries. Built by lloydzhou, it leverages the pybitable library to establish connections to Lark''s API and offers three main tools: listing available tables, describing table schemas, and executing read queries against the data. The implementation requires Lark API credentials (personal base token and app token) and supports one-click installation for Claude Desktop, making it ideal for workflows that need to analyze or reference structured data stored in Lark Bitable without leaving the conversation interface.', '@lloydzhou', 'databases', 'Unknown', 2, 'https://github.com/lloydzhou/bitable-mcp', 'bitable-mcp', 4785, 'https://github.com/lloydzhou.png?size=128', '2026-03-09T05:21:02.027488+00:00'),
  ('web-prototyping', 'Web Prototyping', 'A TypeScript-based MCP server that provides web prototype development tools through a dual-mode architecture combining SvelteKit web interface and command-line MCP tools. The implementation features a tree-based file navigator for HTML prototypes, advertisement integration, and specialized tools for initializing prototype directories, generating HTML content with automatic base href injection, and serving web content through configurable routes. Built with comprehensive testing using Vitest, ESLint configurations for both web and MCP contexts, and a modular structure separating web components from MCP functionality, it enables rapid prototyping workflows where developers can manage HTML mockups, inject JavaScript for enhanced functionality, and serve interactive prototypes through both web interface and programmatic MCP access.', '@llxxbb', 'development', 'Unknown', 3, 'https://github.com/llxxbb/mcp-prototype', '@llxxbb/mcp-prototype', 1152, 'https://github.com/llxxbb.png?size=128', '2026-03-09T05:21:02.027519+00:00'),
  ('olx', 'OLX', 'OLX MCP server that enables AI assistants to search and retrieve listing details from OLX marketplaces across five European domains (Portugal, Poland, Bulgaria, Romania, and Ukraine). Built with TypeScript and Playwright for web scraping, it provides two core tools: searchListings for finding marketplace items with filters for price, location, category, and sorting, and getListingDetails for extracting comprehensive information including seller data and descriptions. The implementation features domain-specific scrapers with intelligent URL caching, robust error handling with retry mechanisms, and headless browser automation optimized for OLX''s site structure. Designed for use cases like market research, price monitoring, lead generation, and automated marketplace analysis where users need programmatic access to OLX''s extensive classified ad inventory without manual browsing.', '@l-margiela', 'development', 'Unknown', 2, 'https://github.com/l-margiela/olx-mcp', 'olx-mcp', 707, 'https://github.com/l-margiela.png?size=128', '2026-03-09T05:21:02.027556+00:00'),
  ('flow-blockchain', 'Flow Blockchain', 'Flow MCP Server provides direct RPC communication with the Flow blockchain, enabling AI assistants to interact with blockchain data and execute operations. Built by lmcmz, it offers tools for checking account balances, resolving domain names (.find and .fn), executing Cadence scripts, and sending transactions. The server implements the Model Context Protocol standard for seamless integration with AI agents, and includes both HTTP endpoints and stdio mode for flexible deployment options. This implementation is particularly valuable for blockchain applications that need to access Flow data, query token balances, or automate transaction workflows without requiring users to switch context.', '@lmcmz', 'ai-ml', 'Unknown', 1, 'https://github.com/lmcmz/flow-mcp-server', NULL, 0, 'https://github.com/lmcmz.png?size=128', '2026-03-09T05:21:02.027602+00:00'),
  ('web-scraper', 'Web Scraper', 'This MCP server provides AI assistants with web scraping capabilities using Google Chrome''s headless APIs to extract content from web pages, with automatic fallback to Go''s HTTP client when Chrome is unavailable. Built by Laurence Morgan using Go with chromedp integration, it handles JavaScript-heavy sites and single-page applications by rendering pages in a real browser environment, preferentially extracting article content over full page body, and includes HTML tag stripping to reduce token count for LLM processing. Serves developers needing reliable web content extraction for AI workflows, teams requiring JavaScript-capable scraping for dynamic sites, and applications that need to process web content through conversational interfaces with both MCP server and direct LangChainGo tool integration options.', '@lmorg', 'ai-ml', 'Unknown', 2, 'https://github.com/lmorg/mcp-web-scraper', NULL, 0, 'https://github.com/lmorg.png?size=128', '2026-03-09T05:21:02.027656+00:00'),
  ('rgb-lightning-node', 'RGB Lightning Node', 'This RGB API MCP server by lnfi-network provides integration with RGB Lightning Node APIs for Bitcoin Layer 2 asset management and Lightning Network operations. Built with TypeScript using the Model Context Protocol SDK and featuring the @lnfi-network/rgb-api-js-sdk, it offers 15 tools covering RGB asset operations (listing, balance checking, sending), Lightning Network functionality (invoice creation/payment, channel management), on-chain Bitcoin transactions, and asset swap operations with comprehensive error handling and Zod schema validation. The implementation supports flexible configuration through environment variables or command-line arguments, includes API key authentication with file-based key loading, and provides minified production builds, making it valuable for developers building Bitcoin Layer 2 applications, Lightning Network integrations, and RGB asset management workflows that require AI assistant interaction with RGB-enabled Lightning nodes.', '@lnfi-network', 'development', 'Unknown', 1, 'https://github.com/lnfi-network/rgb-mcp-server', 'rgb-mcp-server', 398, 'https://github.com/lnfi-network.png?size=128', '2026-03-09T05:21:02.027691+00:00'),
  ('beads-village', 'Beads Village', 'Combines Steve Yegge''s Beads git-native issue tracker with Agent Mail coordination patterns for multi-agent AI workflows. Provides task management (claim, create, update, close), file reservation systems to prevent conflicts between agents, and cross-workspace messaging for team coordination. Features daemon client support for 10x faster operations, role-based task filtering, and team isolation with global broadcast capabilities. Designed for scenarios where multiple AI agents collaborate on codebases across different workspaces (frontend, backend, mobile) while maintaining proper coordination and avoiding conflicts through atomic file reservations and structured communication channels.', '@lns2905', 'development', 'Unknown', 21, 'https://github.com/lns2905/mcp-beads-village', NULL, 0, 'https://github.com/lns2905.png?size=128', '2026-03-09T05:21:02.027718+00:00'),
  ('loanpro', 'LoanPro', 'This MCP server provides direct integration with the LoanPro lending platform API, enabling AI assistants to access loan management data and customer information through a comprehensive set of tools. Built in Go with support for multiple transport protocols (STDIO, HTTP, SSE), it offers tools for retrieving individual loan and customer details, searching loans and customers with flexible filtering options, and accessing loan payment history. The implementation includes intelligent data handling that adapts to different LoanPro API response formats, comprehensive date parsing for LoanPro''s timestamp formats, and structured logging with configurable levels and formats. It''s valuable for financial services teams, loan officers, and customer service representatives who need AI assistance with loan portfolio management, customer inquiries, payment tracking, and loan status monitoring workflows.', '@milocreditplatform', 'ai-ml', 'Unknown', 2, 'https://github.com/milocreditplatform/loanpro-mcp-server', NULL, 0, 'https://github.com/milocreditplatform.png?size=128', '2026-03-09T05:21:02.027773+00:00'),
  ('geofs-flight-simulator', 'GeoFS Flight Simulator', 'GeoFS MCP Server provides a bridge between AI assistants and the GeoFS flight simulator, enabling natural language control of aircraft through GPT-4o. The TypeScript implementation creates a WebSocket server that connects to GeoFS via a browser bookmarklet, allowing commands to be translated into simulator actions like takeoff, landing, and navigation maneuvers. It features a simulated flight physics engine for testing without browser access, flight pattern replay capabilities, and a dashboard for monitoring aircraft telemetry. Ideal for flight simulation enthusiasts who want to control aircraft using conversational AI or developers building autonomous flight control systems.', '@lobstercare', 'development', 'Unknown', 4, 'https://github.com/lobstercare/geofs-mcp', NULL, 0, 'https://github.com/lobstercare.png?size=128', '2026-03-09T05:21:02.027802+00:00'),
  ('local-file-organizer', 'Local File Organizer', 'Local File Organizer is a Python-based MCP server that helps users manage and organize their files by automatically categorizing them based on file extensions. It provides tools for analyzing directory contents, creating category folders, moving files in bulk, and identifying project directories to preserve their structure. The implementation includes features like recursive directory scanning, metadata retrieval, and project detection based on common indicators like .git folders or package.json files. Particularly useful for cleaning up messy downloads folders, organizing media collections, or preparing directories for backup while respecting important project structures.', '@diganto-deb', 'development', 'Unknown', 4, 'https://github.com/diganto-deb/local_file_organizer', NULL, 0, 'https://github.com/diganto-deb.png?size=128', '2026-03-09T05:21:02.027829+00:00'),
  ('localizable-xcstrings', 'Localizable XCStrings', 'A specialized MCP server for managing iOS/macOS localization workflows with Xcode String Catalog (.xcstrings) files. Built with FastMCP and OpenAI integration, it provides tools to extract language support information, manage localization keys, and perform automated translations using OpenAI''s API with intelligent chunking and rate limiting. The server handles batch processing of up to 50 strings per request with concurrent translation support, preserves iOS placeholder formatting (%@, %d, etc.), and automatically creates backups before applying changes. Particularly valuable for iOS developers managing multi-language apps who need to automate translation workflows while maintaining the integrity of their String Catalog files and ensuring proper placeholder handling for dynamic content.', '@iamnotagentleman', 'development', 'Unknown', 5, 'https://github.com/iamnotagentleman/localizable-xcstrings-mcp', NULL, 0, 'https://github.com/iamnotagentleman.png?size=128', '2026-03-09T05:21:02.027868+00:00'),
  ('local-repository-bridge', 'Local Repository Bridge', 'This custom MCP server provides a bridge between Claude and local repositories, enabling direct access to codebases and terminal commands. It offers specialized tools for generating solve prompts, executing terminal commands, locating repositories by keyword, and running tests for specific projects. The implementation includes fuzzy matching capabilities using Levenshtein distance to suggest alternatives when exact matches aren''t found. Particularly useful for developers working with multiple repositories who need Claude to assist with code analysis, bug fixes, and feature development without leaving their conversation context.', '@princefishthrower', 'development', 'Unknown', 2, 'https://github.com/princefishthrower/mcp-server', NULL, 0, 'https://github.com/princefishthrower.png?size=128', '2026-03-09T05:21:02.027897+00:00'),
  ('localstack', 'LocalStack', 'LocalStack MCP Server provides essential tools for managing LocalStack containers and local AWS development workflows through six core tools: container lifecycle management (start/stop/restart with Pro authentication), infrastructure deployment via CDK and Terraform with automatic configuration detection, intelligent log analysis for troubleshooting and error pattern identification, IAM policy generation from access violations when enforcement is enabled, chaos engineering fault injection for resilience testing, and Cloud Pods state management for development snapshots. Built by the LocalStack team with TypeScript and the XMCP framework, it eliminates manual LocalStack management scripts by enabling AI assistants to directly orchestrate local cloud development environments, making it ideal for developers building and testing AWS applications locally who need automated infrastructure management, policy troubleshooting, and development workflow optimization.', '@localstack', 'cloud', 'Unknown', 18, 'https://github.com/localstack/localstack-mcp-server', '@localstack/localstack-mcp-server', 1390, 'https://github.com/localstack.png?size=128', '2026-03-09T05:21:02.027918+00:00'),
  ('local-by-flywheel', 'Local by Flywheel', 'A specialized MCP server built by Very Good Plugins that automatically detects and connects to Local by Flywheel WordPress development environments, solving the common problem of dynamic MySQL socket paths that change when Local sites restart. The implementation scans running processes to find active mysqld instances, extracts configuration details, and dynamically builds the correct connection parameters without requiring manual path updates. Built with TypeScript and featuring read-only query safety, automatic fallback to environment variables, and seamless integration with Local''s unique directory structure, it provides a single mysql_query tool for executing SQL against WordPress databases and is designed for WordPress developers who need reliable database access through AI assistants during local development workflows.', '@verygoodplugins', 'databases', 'Unknown', 14, 'https://github.com/verygoodplugins/mcp-local-wp', '@verygoodplugins/mcp-local-wp', 1196, 'https://github.com/verygoodplugins.png?size=128', '2026-03-09T05:21:02.027996+00:00'),
  ('three-js', 'Three.js', 'Three-js-mcp is a Model Context Protocol server that enables AI assistants to control and manipulate Three.js 3D scenes through a WebSocket connection. The implementation provides tools for adding, moving, and removing 3D objects, controlling object rotation, and retrieving scene state information. Built with TypeScript and the MCP SDK, it establishes a bidirectional communication channel between AI assistants and Three.js clients, making it valuable for creating interactive 3D experiences, visualizations, or educational tools through natural language commands without requiring direct code manipulation.', '@locchung', 'development', 'Unknown', 22, 'https://github.com/locchung/three-js-mcp', NULL, 0, 'https://github.com/locchung.png?size=128', '2026-03-09T05:21:02.028022+00:00'),
  ('loda', 'LODA', 'This MCP server provides complete access to the LODA Language API for mining and computing integer sequences from the Online Encyclopedia of Integer Sequences (OEIS), built with TypeScript and featuring both stdio and HTTP transport modes. The implementation offers 8 core tools including sequence search and retrieval, LODA program compilation and evaluation, program submission capabilities, and project statistics, with robust error handling and API client abstraction that validates sequence IDs and handles network failures gracefully. Built for mathematical research, sequence analysis, and AI-assisted program generation workflows where users need programmatic access to OEIS data and the ability to write, test, and submit LODA assembly programs that generate integer sequences.', '@loda-lang', 'development', 'Unknown', 1, 'https://github.com/loda-lang/loda-mcp', NULL, 0, 'https://github.com/loda-lang.png?size=128', '2026-03-09T05:21:02.028081+00:00'),
  ('logic-lm-answer-set-programming', 'Logic-LM (Answer Set Programming)', 'Logic-LM MCP server by Steven Wang that provides AI assistants with symbolic reasoning capabilities through Answer Set Programming (ASP) and the Clingo solver. Built with Python using FastMCP, the implementation follows a three-stage Logic-LM pipeline: translating natural language problems to ASP code, executing symbolic reasoning with Clingo, and interpreting results back to natural language. The server includes comprehensive ASP translation guidelines, template libraries for common logical patterns (syllogisms, conditionals, universal quantification), and tools for direct ASP program verification with self-refinement capabilities. Designed for applications requiring formal logical reasoning, constraint satisfaction problems, and symbolic problem-solving where traditional LLM reasoning may be insufficient, particularly useful for academic research, automated theorem proving, and complex multi-step logical deduction tasks.', '@shipitsteven', 'development', 'Unknown', 3, 'https://github.com/shipitsteven/logic-lm-mcp', 'logic-lm-mcp-server', 1945, 'https://github.com/shipitsteven.png?size=128', '2026-03-09T05:21:02.028133+00:00'),
  ('github-repository-browser', 'GitHub Repository Browser', 'This GitHub repository MCP server, developed by LogLM, provides AI assistants with access to GitHub repository contents. It integrates with the GitHub API to offer file browsing, content retrieval, and directory navigation capabilities. The server handles authentication, request formatting, and response parsing to simplify interactions with GitHub repositories. By connecting AI systems to version-controlled codebases and documentation, this implementation enables assistants to analyze project structures, read source code, and access file contents programmatically. It is particularly useful for applications requiring code analysis, documentation generation, or any scenario where an AI needs to work with and understand GitHub-hosted projects.', '@loglmhq', 'development', 'Unknown', 6, 'https://github.com/loglmhq/mcp-server-github-repo', NULL, 0, 'https://github.com/loglmhq.png?size=128', '2026-03-09T05:21:02.028159+00:00'),
  ('mnemo', 'Mnemo', 'Mnemo provides extended memory for AI assistants through Gemini''s context caching API, enabling efficient loading and querying of large codebases, documentation sites, and arbitrary web content. The system intelligently crawls and extracts content from GitHub repositories, documentation websites, and URLs using specialized extractors for HTML, PDF, and JSON, then creates cached contexts that can be queried repeatedly with minimal token usage. Offers multiple deployment options including Cloudflare Workers, local Bun server, and Claude Desktop integration via MCP stdio transport. Particularly valuable for code analysis, documentation exploration, and maintaining context across long conversations without hitting token limits.', '@logos-flux', 'cloud', 'Unknown', 14, 'https://github.com/logos-flux/mnemo', NULL, 0, 'https://github.com/logos-flux.png?size=128', '2026-03-09T05:21:02.028224+00:00'),
  ('abuse-ch', 'Abuse.ch', 'This MCP server provides threat intelligence analysis by integrating with abuse.ch platforms including MalwareBazaar, URLhaus, and ThreatFox to deliver comprehensive security reports for files, URLs, domains, and IP addresses. Built with Python using FastMCP and aiohttp for async operations, it features structured Pydantic schemas for data validation, concurrent API calls for performance, and automatic response limiting to prevent oversized payloads. The implementation offers four core tools for retrieving detailed threat reports with hash validation, URL formatting, and consolidated intelligence from multiple abuse.ch sources, making it valuable for security analysts, incident responders, and threat hunters who need programmatic access to malware intelligence and IOC enrichment capabilities.', '@lokallost', 'ai-ml', 'Unknown', 2, 'https://github.com/lokallost/abusech-mcp', NULL, 0, 'https://github.com/lokallost.png?size=128', '2026-03-09T05:21:02.028327+00:00'),
  ('rayon-design-cad', 'Rayon Design CAD', 'This MCP server implementation provides a bridge to the Rayon Design CAD interface, enabling AI assistants to search for drawing methods and create shapes programmatically. Developed using Python and the FastMCP framework, it leverages browser automation to interact with the Rayon Design website. The server offers asynchronous operations for searching and drawing, making it suitable for applications requiring CAD integration within AI-assisted design workflows.', '@lolrazh', 'ai-ml', 'Unknown', 6, 'https://github.com/lolrazh/cad-mcp', NULL, 0, 'https://github.com/lolrazh.png?size=128', '2026-03-09T05:21:02.028412+00:00'),
  ('desktop-notifications', 'Desktop Notifications', 'A lightweight bash-based server that provides desktop notification capabilities through the notify-send command on Linux systems. Uses a simple JSON-RPC protocol handler that processes incoming requests and translates them into native desktop notifications via D-Bus. Designed specifically for Linux environments with zero external dependencies beyond standard utilities, making it useful for workflows that need to alert users about completed tasks, important updates, or system events.', '@longdog', 'productivity', 'Unknown', 1, 'https://github.com/longdog/notify-mcp', NULL, 0, 'https://github.com/longdog.png?size=128', '2026-03-09T05:21:02.028449+00:00'),
  ('opengenes', 'OpenGenes', 'This MCP server provides access to the OpenGenes database containing aging and longevity research data across four main tables: experimental lifespan data from genetic interventions in model organisms, aging-related gene criteria classifications, hallmarks of aging associations, and population genetics longevity data from human studies. Built by the Longevity Genie organization using Python with FastMCP and SQLite, it automatically downloads the latest database from Hugging Face Hub and enforces read-only access with comprehensive SQL injection protection. The implementation features intelligent query guidance for multi-value fields, proper result ordering by effect magnitude, cross-table analysis capabilities, and extensive example queries, making it valuable for researchers, bioinformaticians, and AI assistants working with aging research data who need structured access to gene-longevity relationships, experimental outcomes, and population genetics findings.', '@longevity-genie', 'databases', 'Unknown', 17, 'https://github.com/longevity-genie/opengenes-mcp', 'opengenes-mcp', 4389, 'https://github.com/longevity-genie.png?size=128', '2026-03-09T05:21:02.028460+00:00'),
  ('coinmarketcap', 'CoinMarketCap', 'This MCP server, developed by longmans, provides access to CoinMarketCap''s cryptocurrency data through a standardized interface. Built with Python and leveraging the MCP library, it offers tools for fetching cryptocurrency listings, detailed coin information, and market quotes. The implementation stands out by supporting various query parameters like price ranges, market cap filters, and sorting options. By abstracting CoinMarketCap''s API complexities into an MCP-compatible format, this server enables AI systems to easily retrieve and analyze cryptocurrency market data. It is particularly useful for applications requiring real-time crypto market information, such as portfolio tracking tools, market analysis bots, or AI-powered trading assistants.', '@longmans', 'ai-ml', 'Unknown', 36, 'https://github.com/longmans/coin_api_mcp', NULL, 0, 'https://github.com/longmans.png?size=128', '2026-03-09T05:21:02.028556+00:00'),
  ('longport-openapi', 'Longport OpenAPI', 'Longport MCP is a server implementation that provides AI assistants with direct access to Longport''s financial OpenAPI services. Built with Rust, it offers tools for retrieving market data (quotes, depth, trades, candlesticks), executing trades, managing orders, and accessing account information. The server supports both stdio and SSE transport protocols, making it versatile for different integration scenarios. With cross-platform compatibility for Linux, Windows, and macOS (both x86_64 and ARM64), it enables AI agents to perform sophisticated financial operations including submitting orders, checking positions, and analyzing market data without leaving the conversation interface.', '@longportapp', 'ai-ml', 'Unknown', 8, 'https://github.com/longportapp/longport-mcp', 'longport-mcp', 0, 'https://github.com/longportapp.png?size=128', '2026-03-09T05:21:02.028603+00:00'),
  ('imcp-macos-system-integration', 'iMCP (macOS System Integration)', 'This macOS menu bar application provides native system integration for AI assistants through eight specialized services including Contacts, Calendar, Reminders, Messages, Location, Maps, Weather, and Utilities. Built by the loopwork team using Swift and SwiftUI, it runs as a persistent menu bar app that hosts an MCP server accessible via both GUI and CLI, featuring comprehensive permission management with user approval dialogs, security-scoped file access for Messages database integration, and Claude Desktop configuration automation. The implementation offers 30+ tools spanning personal information management (contact CRUD operations, calendar event creation, reminder management), communication (Messages history search with flexible filtering), location services (geocoding, place search, weather forecasts), and system utilities (sound playback), making it valuable for AI assistants that need deep integration with macOS personal data and system services without requiring users to manually export or copy information.', '@unknown', 'databases', 'Unknown', 0, 'https://www.pulsemcp.com/servers/loopwork-imcp-macos-system-integration', NULL, 0, NULL, '2026-03-09T05:21:02.028616+00:00'),
  ('macos-system-services-imcp', 'macOS System Services (iMCP)', 'iMCP is a macOS menu bar application that enables AI assistants to access system services including Calendar, Contacts, Messages, Reminders, Location, and Weather. Developed by Loopwork, it creates a secure bridge between Claude Desktop and macOS native APIs through a Bonjour-advertised TCP server that requires explicit user permission for each connection. The app features a simple toggle interface for enabling specific services and includes integration with Claude Desktop for easy configuration. It''s particularly useful for AI assistants that need to perform tasks like checking schedules, finding contacts, sending reminders, or getting weather information without requiring users to manually copy information.', '@mattt', 'productivity', 'Unknown', 1185, 'https://github.com/mattt/imcp', NULL, 0, 'https://github.com/mattt.png?size=128', '2026-03-09T05:21:02.028657+00:00'),
  ('openapi-transformer', 'OpenAPI Transformer', 'Emcee is a CLI tool that creates Model Context Protocol servers from OpenAPI specifications, enabling AI assistants to interact with REST APIs through JSON-RPC. Developed by Loopwork AI, it processes an OpenAPI spec (from a file, URL, or stdin) and automatically generates tools that map to API endpoints, handling authentication, parameter validation, and response formatting. The tool supports various authentication methods including Bearer tokens and Basic auth, with secure 1Password integration for credential management. Emcee is particularly useful for quickly exposing existing APIs to Claude Desktop and other MCP-compatible assistants without writing custom integration code.', '@mattt', 'development', 'Unknown', 318, 'https://github.com/mattt/emcee', NULL, 0, 'https://github.com/mattt.png?size=128', '2026-03-09T05:21:02.028684+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('openapi-diff', 'OpenAPI Diff', 'Provides automated comparison and compatibility analysis between OpenAPI specifications. Accepts two OpenAPI specs (as raw content or URLs) and generates detailed difference reports in multiple formats including Markdown, AsciiDoc, JSON, and plain text. Identifies breaking changes, compatibility issues, and structural differences between API versions. Built with Quarkus and leveraging the OpenAPITools openapi-diff-core library for versioning workflows, CI/CD pipeline integration, and backward compatibility validation.', '@lordofthejars', 'ai-ml', 'Unknown', 2, 'https://github.com/lordofthejars/openapi-diff-mcp-server', NULL, 0, 'https://github.com/lordofthejars.png?size=128', '2026-03-09T05:21:02.028726+00:00'),
  ('gemini-search', 'Gemini Search', 'This TypeScript-based MCP client, developed by Lorhlona, enables AI assistants to perform searches using the Google Gemini API. Built with the @modelcontextprotocol/sdk and axios, it provides a streamlined interface for querying Gemini and retrieving search results. The implementation stands out by leveraging Gemini''s advanced language understanding capabilities. By connecting AI systems with Google''s latest search technology, this client allows for more contextually relevant and up-to-date information retrieval. It is particularly useful for enhancing AI assistants with powerful web search capabilities, conducting research tasks, or building applications that require natural language understanding in search queries.', '@lorhlona', 'development', 'Unknown', 24, 'https://github.com/lorhlona/geminiserchmcp', NULL, 0, 'https://github.com/lorhlona.png?size=128', '2026-03-09T05:21:02.028756+00:00'),
  ('lark', 'Lark', 'Lark MCP Server provides a bridge between AI assistants and Lark/Feishu workplace collaboration platform, enabling access to employee information and messaging capabilities through a standardized interface. Built with TypeScript and the Model Context Protocol, it exposes tools for retrieving user data from Lark''s Contact API and sending messages to users. The server handles authentication through app credentials provided via command line arguments or environment variables, manages API connections with automatic token management, and properly formats responses for AI consumption. This implementation is particularly valuable for organizations using Lark/Feishu who want their AI assistants to access company directory information without switching contexts.', '@lorrylockie', 'development', 'Unknown', 3, 'https://github.com/lorrylockie/lark-mcp', 'lark-mcp', 429, 'https://github.com/lorrylockie.png?size=128', '2026-03-09T05:21:02.028786+00:00'),
  ('clever-cloud-documentation', 'Clever Cloud Documentation', 'This MCP server, developed by Horacio Gonzalez, exposes Clever Cloud''s documentation through a standardized interface. Built with TypeScript and leveraging FastMCP, it provides tools for querying and accessing Clever Cloud''s documentation programmatically. The implementation focuses on simplifying access to Clever Cloud''s documentation, offering functionality to retrieve and search through documentation content. It''s particularly useful for developers and users of Clever Cloud looking to integrate documentation access into their workflows or tools, enabling use cases such as automated documentation lookup, integration with development environments, and AI-assisted troubleshooting without directly navigating Clever Cloud''s documentation website.', '@lostinbrittany', 'development', 'Unknown', 0, 'https://github.com/lostinbrittany/clever-doc-mcp-server', NULL, 0, 'https://github.com/lostinbrittany.png?size=128', '2026-03-09T05:21:02.028817+00:00'),
  ('gistpad-github-gists', 'GistPad (GitHub Gists)', 'This MCP server provides personal knowledge management through GitHub Gists, enabling AI assistants to manage daily notes, reusable prompts, and general knowledge storage via the GitHub Gists API. Built by lostintangent using TypeScript and the MCP SDK, it offers tools for creating, updating, and organizing gists with special handling for daily notes (automatically dated files for todos and scratch notes), prompt collections (with frontmatter support for arguments and descriptions), and general gist management including archiving, starring, commenting, and file operations. The implementation features intelligent gist categorization, automatic content loading, real-time notifications for changes, and command-line options for filtering content types, making it valuable for developers and knowledge workers who want to use GitHub Gists as a lightweight, version-controlled personal knowledge base accessible through AI assistants.', '@lostintangent', 'development', 'Unknown', 187, 'https://github.com/lostintangent/gistpad-mcp', 'gistpad-mcp', 25247, 'https://github.com/lostintangent.png?size=128', '2026-03-09T05:21:02.028847+00:00'),
  ('lottiefiles', 'LottieFiles', 'LottieFiles MCP Server provides a bridge between AI assistants and the LottieFiles API, enabling search and retrieval of Lottie animations. Built with TypeScript and the Model Context Protocol SDK, it offers tools for searching animations by keywords, retrieving animation details, and accessing popular animations. The server implements resource handling for popular animations and prompt capabilities to guide interactions, making it valuable for workflows requiring animated content without leaving the conversation interface.', '@junmer', 'development', 'Unknown', 12, 'https://github.com/junmer/mcp-server-lottiefiles', NULL, 0, 'https://github.com/junmer.png?size=128', '2026-03-09T05:21:02.028886+00:00'),
  ('napkin-ai', 'Napkin AI', 'Integrates with Napkin AI to generate professional infographics and visuals from text input. Supports multiple output formats (SVG, PNG, PowerPoint) and visual types including mindmaps, flowcharts, timelines, and comparisons. Handles Napkin AI''s asynchronous generation workflow through polling mechanisms and provides flexible storage options including local filesystem, AWS S3, Google Drive, Slack, Discord, Telegram, and Notion. Designed for workflows requiring automated visual content creation, documentation automation, and presentation generation.', '@louischancly', 'cloud', 'Unknown', 5, 'https://github.com/louischancly/napkin-ai-mcp', NULL, 0, 'https://github.com/louischancly.png?size=128', '2026-03-09T05:21:02.028904+00:00'),
  ('vscode-commands', 'VSCode Commands', 'This MCP server enables VSCode extensions to expose their commands through the Model Context Protocol, built by louisfghbvc using TypeScript and the MCP SDK. It provides a bridge between AI assistants and VSCode''s command palette, allowing external tools to discover and execute VSCode commands programmatically through standardized MCP tools. The implementation includes command discovery, execution with parameter support, and proper error handling, making it valuable for AI-powered development workflows where assistants need to interact with VSCode functionality like file operations, debugging, or extension-specific commands.', '@louisfghbvc', 'development', 'Unknown', 2, 'https://github.com/louisfghbvc/mcp-vscode-commands', NULL, 0, 'https://github.com/louisfghbvc.png?size=128', '2026-03-09T05:21:02.028929+00:00'),
  ('lowes-toolkit', 'Lowes Toolkit', 'A collection of Model Context Protocol (MCP) servers developed by Mark Beebe that provide various capabilities to AI assistants. The repository includes servers for dice rolling, price checking on Amazon, Mac notifications, and several Lowe''s-specific implementations that integrate with services like GitHub, Redis, PostgreSQL, and Google Maps. The implementation uses a mix of Python (with FastMCP) and TypeScript servers, with Docker containerization support for deployment flexibility. Each server follows a consistent pattern with tools, resources, and prompts defined according to the MCP specification, making it easy to extend Claude and other AI assistants with new capabilities.', '@mnbpdx', 'databases', 'Unknown', 0, 'https://github.com/mnbpdx/mcp', NULL, 0, 'https://github.com/mnbpdx.png?size=128', '2026-03-09T05:21:02.028941+00:00'),
  ('n8n-workflow-validator', 'n8n Workflow Validator', 'N8n-MCP-Server provides a validation and best practices framework for n8n workflows, enabling AI assistants to interact with n8n automation platform. It implements tools for workflow validation, API integration, NextJS integration, and workflow management through a TypeScript Express server. The implementation includes specialized validators for calendar integrations, documentation, error handling, naming conventions, performance, and security, making it particularly valuable for teams building complex automation workflows that need to maintain quality standards and follow best practices.', '@lowprofix', 'development', 'Unknown', 7, 'https://github.com/lowprofix/n8n-mcp-server', NULL, 0, 'https://github.com/lowprofix.png?size=128', '2026-03-09T05:21:02.029017+00:00'),
  ('dice-roller', 'Dice Roller', 'Server-Dice-Roll is an MCP server for simulating dice rolls with support for standard dice notation and Fate/Fudge dice. Developed by Luke Bayliss, it provides two main tools: one for parsing dice notation strings like ''2d6'' or ''4dF'', and another for generating truly random dice rolls with cryptographically secure randomness. The server includes a sophisticated entropy pool implementation that collects randomness from various system sources to ensure fair and unpredictable results, making it ideal for tabletop RPG applications, game development, or any scenario requiring reliable random number generation.', '@lpbayliss', 'development', 'Unknown', 2, 'https://github.com/lpbayliss/server-dice-roll', 'server-dice-roll', 4179, 'https://github.com/lpbayliss.png?size=128', '2026-03-09T05:21:02.029075+00:00'),
  ('ros-robot-control', 'ROS Robot Control', 'ROS MCP Server provides a bridge between AI assistants and Robot Operating System (ROS) for controlling robot movement through WebSocket communication. Built by Jungsoo Lee, it exposes two main functions: pub_twist for sending immediate movement commands with linear and angular velocities, and pub_twist_seq for executing sequences of movements with specified durations. The server connects to a ROS bridge server on a specified IP address and publishes velocity commands to the /cmd_vel topic, making it particularly valuable for robotics researchers and developers who need to control robots through natural language interfaces without writing complex ROS code.', '@robotmcp', 'development', 'Unknown', 1060, 'https://github.com/robotmcp/ros-mcp-server', NULL, 0, 'https://github.com/robotmcp.png?size=128', '2026-03-09T05:21:02.029105+00:00'),
  ('unitree-go2', 'Unitree Go2', 'The Unitree Go2 MCP Server enables AI assistants to control the Unitree Go2 quadruped robot through natural language commands. Built on Python, it interfaces with the robot''s ROS2 system to execute various movements and actions including walking, dancing, sitting, and performing gestures like handshakes or greetings. The server translates high-level commands into precise ROS2 topic publications that control the robot''s wireless controller, making it particularly valuable for robotics researchers and enthusiasts who want to interact with their Go2 robot using conversational AI rather than traditional programming or manual controls.', '@lpigeon', 'ai-ml', 'Unknown', 75, 'https://github.com/lpigeon/unitree-go2-mcp-server', NULL, 0, 'https://github.com/lpigeon.png?size=128', '2026-03-09T05:21:02.029150+00:00'),
  ('openai-agents', 'OpenAI Agents', 'OpenAI Agents MCP Server exposes OpenAI''s agent capabilities through the Model Context Protocol, allowing AI assistants to access web search, file search, and computer actions. Built by Eric Wang, it implements both specialized agents for individual tools and a multi-agent orchestrator that can coordinate between them based on the task requirements. The server uses FastMCP to handle communication, supports both stdio and SSE transports, and includes a simulated computer interaction mode that can be extended for real-world actions. Particularly valuable for workflows requiring real-time information retrieval, document analysis, or safe computer automation within AI assistant conversations.', '@lroolle', 'productivity', 'Unknown', 10, 'https://github.com/lroolle/openai-agents-mcp-server', NULL, 0, 'https://github.com/lroolle.png?size=128', '2026-03-09T05:21:02.029194+00:00'),
  ('context7', 'Context7', 'Context7-HTTP is an MCP server that provides HTTP streaming access to the Context7 documentation platform. Developed by Liam Stanley, it enables AI assistants to search and retrieve documentation for software libraries through two main tools: ''resolve-library-uri'' for finding libraries and ''search-library-docs'' for retrieving relevant documentation content. The server supports both streamable HTTP and SSE protocols, includes caching and rate limiting for performance, and exposes resources for browsing libraries by popularity and trust score. This implementation makes Context7''s extensive library documentation accessible to any client without requiring local installation, making it ideal for AI assistants that need up-to-date programming documentation.', '@lrstanley', 'ai-ml', 'Unknown', 22, 'https://github.com/lrstanley/context7-http', NULL, 0, 'https://github.com/lrstanley.png?size=128', '2026-03-09T05:21:02.029239+00:00'),
  ('lsd-web-data-extraction', 'LSD Web Data Extraction', 'The LSD MCP server provides AI assistants with access to the LSD programming language for web data extraction and manipulation. Built by lsd.so, this implementation exposes tools for executing LSD code snippets, searching the Brave search engine, and dynamically registering ''trips'' (published LSD modules) as additional tools. The server includes specialized prompts for research tasks and documentation resources that help AI assistants understand the LSD language syntax. It''s particularly valuable for users who need to extract structured data from websites, perform web searches, or leverage community-created data extraction patterns without writing complex scraping code.', '@lsd-so', 'development', 'Unknown', 3, 'https://github.com/lsd-so/internetdata-mcp', 'internetdata', 6607, 'https://github.com/lsd-so.png?size=128', '2026-03-09T05:21:02.029271+00:00'),
  ('lsd-sql', 'LSD SQL', 'This MCP server, developed by LSD.so, enables Claude to directly query and analyze web content using LSD SQL, a domain-specific language for web scraping. Built with Python and leveraging cloud browsers, it allows Claude to write and execute LSD SQL queries to extract structured data from websites. The implementation focuses on providing a flexible interface for web data extraction, including features like parallel processing and just-in-time table creation. It''s particularly useful for applications requiring real-time web data analysis, enabling use cases such as market research, competitor analysis, and content aggregation without complex web scraping setups or API integrations.', '@lsd-so', 'databases', 'Unknown', 64, 'https://github.com/lsd-so/lsd-mcp', NULL, 0, 'https://github.com/lsd-so.png?size=128', '2026-03-09T05:21:02.029283+00:00'),
  ('openhue', 'OpenHue', 'This OpenHue MCP server, developed by an unnamed author, integrates with Philips Hue smart lighting systems to enable AI-controlled home automation. Built with TypeScript and leveraging the Model Context Protocol SDK, it provides tools for managing light states, scenes, and schedules. The server implements secure local network discovery and authentication with Hue bridges, offering a standardized interface for complex lighting operations. By abstracting the intricacies of the Hue API, it allows AI systems to easily control and monitor smart lighting environments. This implementation is particularly valuable for applications requiring programmatic light management, facilitating use cases such as mood-based lighting adjustments, energy optimization, and interactive home experiences.', '@lsemenenko', 'development', 'Unknown', 9, 'https://github.com/lsemenenko/openhue-mcp-server', NULL, 0, 'https://github.com/lsemenenko.png?size=128', '2026-03-09T05:21:02.029325+00:00'),
  ('lspace', 'Lspace', 'This MCP server provides a comprehensive knowledge base and document management system built with TypeScript that transforms Git repositories into AI-powered knowledge repositories through automated document processing, timeline tracking, and intelligent organization. The implementation integrates with OpenAI''s API to extract knowledge from raw documents, generate structured knowledge base pages, and provide semantic search capabilities across repository contents, while maintaining full version control through Git operations and detailed timeline tracking of all changes. It supports both local Git repositories and GitHub integration with Personal Access Tokens, offering tools for content submission (text snippets, file uploads, web URLs), repository management, knowledge base querying, and file system operations, making it valuable for teams wanting to build searchable, AI-enhanced documentation systems from their existing Git-based content workflows.', '@lspace-io', 'development', 'Unknown', 8, 'https://github.com/lspace-io/lspace-server', NULL, 0, 'https://github.com/lspace-io.png?size=128', '2026-03-09T05:21:02.029355+00:00'),
  ('newshub', 'NewsHub', 'News MCP Server provides real-time access to news articles from various RSS feeds through a structured API. It features tools for listing available feeds, retrieving latest news by category, searching across all feeds, and fetching specific article details. The implementation includes intelligent caching to minimize external requests, supports custom feed configuration through environment variables, and organizes content into categories like tech, business, and science. Built with FastMCP and feedparser, it enables AI assistants to deliver current news information from sources like Wired, New York Times, BBC, and specialized publications without requiring direct web access.', '@ltejedor', 'development', 'Unknown', 4, 'https://github.com/ltejedor/newsfeed-mcp', NULL, 0, 'https://github.com/ltejedor.png?size=128', '2026-03-09T05:21:02.029383+00:00'),
  ('arangodb', 'ArangoDB', 'This ArangoDB MCP server, developed by Lucas DE ANGELIS, enables seamless integration of ArangoDB databases into AI-assisted workflows. Built with TypeScript and leveraging the @modelcontextprotocol/sdk, it provides a standardized interface for querying and manipulating ArangoDB collections through Claude Desktop and compatible MCP clients. The implementation supports both read-only and read-write AQL queries, offers tools for listing databases and collections, and allows document retrieval via URIs. It''s particularly useful for developers and data analysts looking to incorporate on-demand access to document-oriented and graph data into their AI-assisted applications, enabling dynamic querying and analysis of ArangoDB-stored information.', '@lucas-deangelis', 'databases', 'Unknown', 4, 'https://github.com/lucas-deangelis/arango-mcp-server', NULL, 0, 'https://github.com/lucas-deangelis.png?size=128', '2026-03-09T05:21:02.029394+00:00'),
  ('mitmproxy', 'Mitmproxy', 'This MCP server implementation integrates mitmproxy, a powerful HTTP/HTTPS interception tool, with the Model Context Protocol. It provides a simple note storage system with custom URI schemes, allows for note summarization, and includes a tool for adding new notes. The server is designed to enhance AI assistants'' capabilities in managing and analyzing network traffic, making it useful for debugging, security analysis, and API testing scenarios.', '@lucasoeth', 'development', 'Unknown', 13, 'https://github.com/lucasoeth/mitmproxy-mcp', NULL, 0, 'https://github.com/lucasoeth.png?size=128', '2026-03-09T05:21:02.029428+00:00'),
  ('db-bridge', 'DB Bridge', 'A multi-database MCP server that provides secure SQL query execution across MySQL, PostgreSQL, and SQLite databases with granular permission controls and enterprise-ready features. Built with an adapter pattern for extensibility, it supports both single-database and multi-database modes, schema-specific permissions for different operations (INSERT, UPDATE, DELETE, DDL), SSL/TLS connections for cloud databases, and Unix socket connections for local setups. The implementation emphasizes security through read-only mode by default, transaction-based query execution, and configurable write operation permissions, making it suitable for controlled database access in production environments.', '@lucassiqueirasurreco', 'databases', 'Unknown', 2, 'https://github.com/lucassiqueirasurreco/mcp-db-bridge', 'mcp-db-bridge', 234, 'https://github.com/lucassiqueirasurreco.png?size=128', '2026-03-09T05:21:02.029439+00:00'),
  ('laravel-telescope', 'Laravel Telescope', 'Laravel Telescope MCP extends Laravel Telescope by exposing application telemetry data via the Model Context Protocol to AI assistants like Cursor, Claude, and Copilot Chat. Developed by Luciano Tonet under the MIT license, it translates natural-language queries into operations that retrieve Telescope records, enabling developers to inspect logs, slow queries, HTTP requests, exceptions, jobs, and more through an AI interface. The implementation includes tools for accessing all Telescope features, supports customizable authentication through middleware, and is particularly valuable for developers who need quick insights into application metrics without leaving their coding environment.', '@lucianotonet', 'communication', 'Unknown', 17, 'https://github.com/lucianotonet/laravel-telescope-mcp', NULL, 0, 'https://github.com/lucianotonet.png?size=128', '2026-03-09T05:21:02.029479+00:00'),
  ('templateio', 'Templateio', 'This MCP server implementation provides a template for building custom MCP servers using TypeScript and the mcp-framework package. It sets up the basic project structure and configuration files needed to develop an MCP server, including TypeScript compilation settings and necessary dependencies. The implementation is designed as a starting point for developers looking to create their own MCP servers tailored to specific APIs or services.', '@lucker631', 'development', 'Unknown', 0, 'https://github.com/lucker631/mcp-templateio', NULL, 0, 'https://github.com/lucker631.png?size=128', '2026-03-09T05:21:02.029502+00:00'),
  ('google-gemini', 'Google Gemini', 'This MCP server provides Google Gemini AI integration through Google''s OpenAI-compatible API endpoint, offering four distinct interaction modes: streaming and non-streaming responses, each with optional reasoning/thinking capabilities. Built using FastMCP and the OpenAI Python client with proxy support for network configurations, it enables AI assistants to leverage Gemini''s reasoning capabilities with configurable effort levels (low/medium/high) and includes utility tools for connection testing and configuration management. The implementation supports Docker deployment with environment-based configuration for API keys, model selection, base URLs, and proxy settings, making it valuable for users who need programmatic access to Gemini''s advanced reasoning features through a standardized MCP interface without direct API integration complexity.', '@lucky-dersan', 'cloud', 'Unknown', 1, 'https://github.com/lucky-dersan/gemini-mcp-server', NULL, 0, 'https://github.com/lucky-dersan.png?size=128', '2026-03-09T05:21:02.029530+00:00'),
  ('pipelock', 'Pipelock', 'Pipelock is a security proxy that wraps MCP servers, scanning bidirectional traffic for threats. It prevents credential exfiltration through a configurable fetch proxy with SSRF protection, detects prompt injection in both client requests and server responses, and monitors tool list changes for tampering. Features include a 9-layer URL scanning pipeline, file integrity monitoring with SHA256 manifests, Ed25519 signing for multi-agent verification, and three configurable security modes (strict, balanced, audit).', '@luckypipewrench', 'file-systems', 'Unknown', 183, 'https://github.com/luckypipewrench/pipelock', NULL, 0, 'https://github.com/luckypipewrench.png?size=128', '2026-03-09T05:21:02.029607+00:00'),
  ('youtube-playlist-transcripts', 'YouTube Playlist Transcripts', 'Playlist-MCP is an experimental server that makes YouTube playlist transcripts searchable through vector embeddings. It fetches and caches video transcripts from a specified YouTube playlist, stores them in a ChromaDB vector database, and exposes a search interface through the MCP protocol. The server comes preloaded with KubeCon London 2025 transcripts but can be configured to work with any YouTube playlist. This implementation is particularly useful for researchers and developers who need to quickly search through video content without watching hours of footage.', '@luebken', 'databases', 'Unknown', 3, 'https://github.com/luebken/playlist-mcp', NULL, 0, 'https://github.com/luebken.png?size=128', '2026-03-09T05:21:02.029618+00:00'),
  ('yfinance-trader', 'YFinance Trader', 'This MCP server provides real-time stock market data and trading capabilities using the yfinance library. It offers six tools for accessing stock quotes, company information, historical price data, symbol search, analyst recommendations, and insider transactions. The implementation handles errors gracefully, returning informative error messages when operations fail. Ideal for financial analysis, investment research, and building trading applications that require up-to-date market information without direct API costs.', '@luigiajah', 'development', 'Unknown', 11, 'https://github.com/luigiajah/mcp-stocks', NULL, 0, 'https://github.com/luigiajah.png?size=128', '2026-03-09T05:21:02.029644+00:00'),
  ('oracle-vector-store', 'Oracle Vector Store', 'This MCP server provides semantic search capabilities over Oracle Vector Store databases, enabling natural language queries against document collections stored in Oracle Database with vector embeddings. Built by Luigi Saetta, it integrates Oracle''s vector database technology with OCI GenAI services for embeddings and includes optional JWT-based authentication through Oracle Identity Cloud Service for enterprise security. The implementation offers two variants: a standard semantic search tool that returns full document content, and a Deep Research-compatible version that follows OpenAI''s specification with separate search and fetch operations for integration with ChatGPT''s research workflows. It''s particularly valuable for enterprise knowledge bases, document retrieval systems, and research applications where users need to query large document collections using conversational language while maintaining enterprise-grade security and leveraging Oracle''s database infrastructure.', '@luigisaetta', 'databases', 'Unknown', 1, 'https://github.com/luigisaetta/mcp-oci-integration', NULL, 0, 'https://github.com/luigisaetta.png?size=128', '2026-03-09T05:21:02.029656+00:00'),
  ('voice-call-twilio', 'Voice Call (Twilio)', 'A voice call automation server that enables AI assistants to make outbound phone calls via Twilio. Built with TypeScript, this implementation handles the complete lifecycle of phone conversations, from initiating calls to processing speech with OpenAI''s real-time audio models. The server features a WebSocket architecture that bridges Twilio''s voice API with OpenAI''s streaming capabilities, allowing for natural conversations with context-aware responses. It''s particularly useful for applications requiring automated phone interactions like appointment scheduling, customer service, or information gathering without human intervention.', '@popcornspace', 'development', 'Unknown', 56, 'https://github.com/popcornspace/voice-call-mcp-server', NULL, 0, 'https://github.com/popcornspace.png?size=128', '2026-03-09T05:21:02.029700+00:00'),
  ('engram-memory', 'Engram Memory', 'Engram MCP provides AI agents with reliable memory capabilities through explainable retrieval mechanisms, built by Lumetra as a streamable HTTP service. The server connects to Lumetra''s hosted Engram service at engram.lumetra.io using API key authentication, enabling agents to store and retrieve information with transparent reasoning about why specific memories were surfaced. This implementation is valuable for AI systems that need persistent memory across conversations, knowledge management workflows, or applications requiring auditable retrieval decisions where understanding the basis for recalled information is critical.', '@lumetra-io', 'communication', 'Unknown', 1, 'https://github.com/lumetra-io/engram-memory-mcp', NULL, 0, 'https://github.com/lumetra-io.png?size=128', '2026-03-09T05:21:02.029737+00:00'),
  ('cryptocurrency-technical-analysis', 'Cryptocurrency Technical Analysis', 'The LumiFAI MCP Technical Analysis Server provides cryptocurrency trading tools through a FastMCP implementation, focusing on Exponential Moving Average (EMA) calculations for Binance pairs. Built with Python 3.13, it integrates with MongoDB to fetch OHLCV (Open, High, Low, Close, Volume) data and calculates 12-period and 26-period EMAs for technical analysis. The server uses Server-Sent Events (SSE) for real-time communication, making it ideal for traders who need quick access to technical indicators for cryptocurrency market analysis and trading decisions.', '@lumif-ai', 'databases', 'Unknown', 1, 'https://github.com/lumif-ai/mcp-ta-tool', NULL, 0, 'https://github.com/lumif-ai.png?size=128', '2026-03-09T05:21:02.029751+00:00'),
  ('lumbretravel', 'LumbreTravel', 'This MCP server, developed by Lumile Argentina S.A., provides access to the LumbreTravel API for managing travel programs and activities. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers a comprehensive set of tools for creating, updating, and managing programs, activities, passengers, agencies, hotels, services, and more. The implementation focuses on providing a standardized interface to LumbreTravel''s functionality, enabling seamless integration with Claude Desktop and other MCP clients. It''s particularly useful for travel agencies, tour operators, and event planners who need programmatic access to LumbreTravel''s features, allowing for efficient management of complex travel itineraries, passenger data, and service bookings.', '@lumile', 'development', 'Unknown', 1, 'https://github.com/lumile/lumbretravel-mcp', 'lumbretravel-mcp', 5201, 'https://github.com/lumile.png?size=128', '2026-03-09T05:21:02.029784+00:00'),
  ('mercadolibre', 'MercadoLibre', 'This MercadoLibre MCP server, developed by Lumile Argentina S.A., enables AI agents to interact with MercadoLibre''s e-commerce platform. Built with TypeScript and leveraging the Model Context Protocol SDK, it provides a standardized interface for accessing MercadoLibre''s API. The implementation focuses on simplifying interactions with the platform, offering functionality to query product and seller information. It''s particularly useful for businesses and developers looking to integrate MercadoLibre data into their AI workflows, enabling use cases such as price monitoring, inventory management, and market analysis without directly dealing with MercadoLibre''s API complexities.', '@lumile', 'development', 'Unknown', 8, 'https://github.com/lumile/mercadolibre-mcp', 'mercadolibre-mcp', 4833, 'https://github.com/lumile.png?size=128', '2026-03-09T05:21:02.029814+00:00'),
  ('promptopia', 'Promptopia', 'Promptopia MCP is a server for managing, organizing, and reusing prompt templates with variable substitution capabilities. Developed by Lumile, it provides persistent storage for both single-content prompts and multi-message conversation templates with automatic variable detection using {{variable}} syntax. The server supports text and image content types within conversation structures, real-time file watching for prompt changes, and exposes a comprehensive set of tools for prompt management operations. This implementation is particularly valuable for teams wanting to centralize their prompt library, maintain version consistency across projects, and seamlessly integrate reusable prompts into MCP-compatible applications like Claude Desktop.', '@lumile', 'productivity', 'Unknown', 2, 'https://github.com/lumile/promptopia-mcp', 'promptopia-mcp', 4545, 'https://github.com/lumile.png?size=128', '2026-03-09T05:21:02.029870+00:00'),
  ('io-github-geored-lumino', 'io.github.geored/lumino', 'AI-powered SRE observability for Kubernetes/OpenShift with 40+ Tekton debugging tools', '@spre-sre', 'cloud', 'Unknown', 5, 'https://github.com/spre-sre/lumino-mcp-server', NULL, 0, 'https://github.com/spre-sre.png?size=128', '2026-03-09T05:21:02.029885+00:00'),
  ('lunarcrush', 'LunarCrush', 'This MCP server provides AI assistants with access to LunarCrush cryptocurrency market intelligence and social sentiment data through a proxy architecture that bridges local stdio communication with LunarCrush''s remote HTTP API. Built by LunarCrush using JavaScript and the Model Context Protocol SDK, the implementation acts as a local proxy server that forwards MCP requests to LunarCrush''s hosted MCP endpoint at lunarcrush.ai/mcp, supporting both streamable HTTP and SSE transport methods while handling API key authentication. The proxy design allows users to integrate LunarCrush''s crypto analytics capabilities into their MCP workflows through either direct remote connection or local stdio interface, serving developers building crypto trading applications, analysts requiring programmatic access to social sentiment data, and AI assistants needing real-time cryptocurrency market intelligence without managing complex API integrations directly.', '@lunarcrush', 'development', 'Unknown', 4, 'https://github.com/lunarcrush/mcp-server', NULL, 0, 'https://github.com/lunarcrush.png?size=128', '2026-03-09T05:21:02.029919+00:00'),
  ('mcpx-control-plane', 'MCPX Control Plane', 'MCPX is a control plane and proxy server for Model Context Protocol implementations, built by Lunar.dev using TypeScript and React. It acts as an intermediary layer that aggregates multiple MCP servers, provides centralized management through a web-based control plane, and offers features like tool access controls, session management, metrics collection, and Docker-based server orchestration. The implementation includes a comprehensive UI for monitoring system connectivity, managing server configurations, and analyzing usage patterns, along with WebSocket-based real-time communication between components. It serves organizations needing centralized MCP infrastructure management, developers building complex multi-server MCP deployments, and teams requiring observability and access control over their MCP tool ecosystem without managing individual server instances manually.', '@thelunarcompany', 'cloud', 'Unknown', 404, 'https://github.com/thelunarcompany/lunar/tree/HEAD/mcpx', NULL, 0, 'https://github.com/thelunarcompany.png?size=128', '2026-03-09T05:21:02.029949+00:00'),
  ('ada', 'Ada', 'Ada is a privacy-first personal AI assistant that runs entirely on your own hardware, providing long-term memory, web search, vision capabilities, and tool use without monthly API fees or cloud dependencies. Built by Luna System using Ollama for local LLM inference, ChromaDB for vector storage, and FastAPI for the backend, it features a specialist plugin system that enables contextual responses based on current media playback, OCR text extraction, DuckDuckGo web search, and other dynamic data sources. The ada-mcp component brings Ada''s conversational AI and semantic memory search capabilities directly into code editors like VS Code, Cursor, Neovim, and Helix, enabling seamless AI assistance during development workflows while maintaining complete data privacy on local infrastructure.', '@luna-system', 'development', 'Unknown', 12, 'https://github.com/luna-system/ada/tree/HEAD/ada-mcp', NULL, 0, 'https://github.com/luna-system.png?size=128', '2026-03-09T05:21:02.029977+00:00'),
  ('lunch-flow', 'Lunch Flow', 'Lunch Flow''s official MCP server provides AI assistants with secure access to personal financial data through their banking aggregation platform. Built with TypeScript and the MCP SDK, it exposes three core tools for listing connected bank accounts, retrieving transaction history, and checking account balances across 20,000+ banks in 40+ countries. The implementation uses ts-rest for type-safe API contracts with comprehensive error handling and requires an API key from the Lunch Flow platform for authentication, making it useful for personal finance analysis, expense tracking, and financial insights within conversational interfaces.', '@lunchflow', 'development', 'Unknown', 4, 'https://github.com/lunchflow/mcp', NULL, 0, 'https://github.com/lunchflow.png?size=128', '2026-03-09T05:21:02.030009+00:00'),
  ('luno', 'Luno', 'Luno MCP Server provides a bridge between AI assistants and the Luno cryptocurrency exchange API, enabling trading operations, market data retrieval, and account management. Built in Go with the luno-go client library, it exposes tools for checking balances, viewing order books, creating and managing trades, and accessing transaction history. The server supports both stdio and SSE transport modes, includes robust error handling with helpful suggestions for invalid trading pairs, and automatically normalizes currency codes (converting BTC to XBT). Particularly valuable for applications requiring programmatic cryptocurrency trading, portfolio monitoring, or market analysis through AI assistant interactions.', '@luno', 'development', 'Unknown', 15, 'https://github.com/luno/luno-mcp', NULL, 0, 'https://github.com/luno.png?size=128', '2026-03-09T05:21:02.030053+00:00'),
  ('asymptote-geometry-renderer', 'Asymptote Geometry Renderer', 'The MCP-Geo server enables AI assistants to generate precise geometric images using Asymptote, a specialized vector graphics language. Developed by luorivergoddess, this TypeScript implementation exposes a single tool, ''renderGeometricImage'', which takes Asymptote code as input and returns rendered images in SVG or PNG format. The server handles the compilation process by executing the Asymptote command-line tool, managing temporary files, and encoding the resulting images as base64 data. It''s particularly valuable for mathematical visualization, technical diagrams, and educational content where precise geometric rendering is required.', '@luorivergoddess', 'development', 'Unknown', 5, 'https://github.com/luorivergoddess/mcp-geo', '@luorivergoddess/mcp-geo', 3904, 'https://github.com/luorivergoddess.png?size=128', '2026-03-09T05:21:02.030082+00:00'),
  ('dall-e-3-image-generator', 'DALL-E 3 Image Generator', 'The Image Generator MCP Server enables AI assistants to create images using OpenAI''s DALL-E 3 model through a simple interface. Built with TypeScript, it provides a ''generate_image'' tool that accepts a prompt and image name, then saves the generated image to a ''generated-images'' directory on the user''s desktop. The server runs locally using stdio communication and requires an OpenAI API key for authentication. It''s particularly useful for workflows where users need to quickly generate and save custom images based on text descriptions without leaving their AI assistant conversation.', '@luoshui-coder', 'development', 'Unknown', 1, 'https://github.com/luoshui-coder/image-generator-mcp-server', NULL, 0, 'https://github.com/luoshui-coder.png?size=128', '2026-03-09T05:21:02.030111+00:00'),
  ('local-code-search', 'Local Code Search', 'Local Code Indexing for Cursor provides a Python-based server that locally indexes codebases using ChromaDB and enables semantic code search through the MCP protocol. Built with FastMCP, it watches specified project directories, automatically indexes code files using language-specific parsers, and maintains a vector database of code chunks that can be queried using natural language. The implementation includes Docker containerization for easy deployment, file system watchers for real-time updates, and configurable ignore patterns for directories and files. This tool is particularly valuable for developers who want to perform semantic code search within their projects directly through the Cursor IDE without sending their code to external services.', '@luotocompany', 'databases', 'Unknown', 34, 'https://github.com/luotocompany/cursor-local-indexing', NULL, 0, 'https://github.com/luotocompany.png?size=128', '2026-03-09T05:21:02.030123+00:00'),
  ('onyx-knowledge-base', 'Onyx Knowledge Base', 'Onyx MCP Server provides a bridge between MCP-compatible clients and Onyx knowledge bases, enabling powerful semantic search and chat capabilities. Developed by lupuletic, this TypeScript implementation offers two main tools: a search tool for retrieving relevant documents with configurable context windows, and a chat tool that leverages Onyx''s RAG capabilities for comprehensive answers. The server connects to the Onyx API using environment variables for configuration, making it particularly valuable for teams who need to access their organizational knowledge through AI assistants without switching contexts.', '@lupuletic', 'development', 'Unknown', 23, 'https://github.com/lupuletic/onyx-mcp-server', 'onyx-mcp-server', 4871, 'https://github.com/lupuletic.png?size=128', '2026-03-09T05:21:02.030158+00:00'),
  ('skim', 'Skim', 'Code transformation server that intelligently compresses code for LLM context windows while preserving structural meaning. Supports multiple compression modes (structure, signatures, types) achieving 60-95% content reduction. Compatible with TypeScript, JavaScript, Python, Rust, Go, Java, JSON, Markdown, and YAML.', '@luw2007', 'development', 'Unknown', 0, 'https://github.com/luw2007/skim-mcp', NULL, 0, 'https://github.com/luw2007.png?size=128', '2026-03-09T05:21:02.030176+00:00'),
  ('kbdb', 'KBDB', 'A PostgreSQL-backed RAG (Retrieval-Augmented Generation) server that provides semantic search across document embeddings using pgvector for vector similarity operations. Built with FastMCP and OpenAI''s embedding API, it supports multiple search modalities including question-answer pairs, semantic similarity, style-based clustering, and code similarity search, each optimized with different embedding prefixes and distance metrics (cosine, inner product, L2). The system stores documents in chunks with pre-computed embeddings and exposes specialized search tools for different use cases, making it valuable for knowledge base applications, documentation search, and content discovery workflows where different types of semantic matching are required.', '@luxter77', 'databases', 'Unknown', 3, 'https://github.com/luxter77/mcp-kbdb', NULL, 0, 'https://github.com/luxter77.png?size=128', '2026-03-09T05:21:02.030187+00:00'),
  ('xiaohongshu', 'Xiaohongshu', 'A Python-based server for automating Xiaohongshu (Little Red Book) interactions through browser automation using Playwright. Built with FastMCP framework, it provides cookie-based session management for persistent authentication, browser control for navigating the platform, and structured storage for maintaining login state across sessions. The implementation uses a modular architecture with separate components for browser management, page control, login handling, and cookie storage, making it useful for social media automation, content management workflows, and interaction with Xiaohongshu''s web interface.', '@luyike221', 'ai-ml', 'Unknown', 77, 'https://github.com/luyike221/xiaohongshu-mcp-python', NULL, 0, 'https://github.com/luyike221.png?size=128', '2026-03-09T05:21:02.030233+00:00'),
  ('solidjs-skills', 'SolidJS Skills', 'SolidJS Skills is an MCP server that provides document browsing capabilities for a curated collection of SolidJS development resources. It exposes tools to list, read, and search through guides, skill modules, and templates covering component building, refactoring assistance, code review, project scaffolding, and design patterns. The server helps developers and agents access structured SolidJS knowledge including reactive primitives, JSX patterns, and framework-specific conventions.', '@lvcoi', 'development', 'Unknown', 2, 'https://github.com/lvcoi/solidjskills', NULL, 0, 'https://github.com/lvcoi.png?size=128', '2026-03-09T05:21:02.030257+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('factorio-ai-companion', 'Factorio AI Companion', 'Provides AI companion control for Factorio through RCON integration. Features bidirectional chat communication where players send messages prefixed with /companion from within Factorio, and the AI companion responds back into the game''s chat system. Includes tools for retrieving unread messages and sending responses, with connection retry logic and comprehensive error handling.', '@lveillard', 'communication', 'Unknown', 7, 'https://github.com/lveillard/factorio-ai-companion', NULL, 0, 'https://github.com/lveillard.png?size=128', '2026-03-09T05:21:02.030285+00:00'),
  ('godot-documentation-rag', 'Godot Documentation RAG', 'A RAG (Retrieval-Augmented Generation) system built with FastMCP that processes Godot game engine documentation by converting RST files to Markdown, splitting them into chunks, generating embeddings, and enabling semantic search and question-answering capabilities. The implementation includes tools for document conversion, text chunking, vector embedding generation, and the main RAG server that handles queries against the processed documentation. Designed for developers working with Godot who need intelligent access to documentation through natural language queries rather than manual searching through extensive technical docs.', '@lvsedeqinglvse', 'ai-ml', 'Unknown', 5, 'https://github.com/lvsedeqinglvse/-fastmcp-godot-rag-', NULL, 0, 'https://github.com/lvsedeqinglvse.png?size=128', '2026-03-09T05:21:02.030336+00:00'),
  ('academic-paper-analyzer', 'Academic Paper Analyzer', 'A research paper analysis server that provides comprehensive tools for academic paper reading and understanding. Built with TypeScript and SQLite, it offers PDF loading and text extraction, mathematical notation explanation with LaTeX parsing, document structure analysis, content summarization, code generation from algorithms, data visualization capabilities, and automated report generation. Integrates with local LLM services (like Ollama) for AI-powered analysis while maintaining a local database of papers, symbols, and experimental data. Designed for researchers and students who need to efficiently process, understand, and extract insights from academic papers with particular strength in handling mathematical content and experimental reproduction.', '@lxy-hqu', 'databases', 'Unknown', 6, 'https://github.com/lxy-hqu/-mcp-for-paper-read-based-on-ai-ide', NULL, 0, 'https://github.com/lxy-hqu.png?size=128', '2026-03-09T05:21:02.030351+00:00'),
  ('kubevirt', 'KubeVirt', 'KubeVirt MCP Server provides a simple interface for managing virtual machines in Kubernetes environments through natural language commands. Built with Go and leveraging the KubeVirt API, it offers tools for listing VM names, starting and stopping VMs, and managing instance types. The server bridges the gap between LLMs and Kubernetes virtualization, enabling AI assistants to control virtual infrastructure through conversational interactions. As demonstrated in the included demo using llama3.2 with ollama, it allows users to perform VM management tasks without needing to write complex kubectl commands or understand the underlying KubeVirt object model.', '@lyarwood', 'cloud', 'Unknown', 3, 'https://github.com/lyarwood/kubevirt-mcp-server', NULL, 0, 'https://github.com/lyarwood.png?size=128', '2026-03-09T05:21:02.030372+00:00'),
  ('marm-systems', 'MARM Systems', 'MARM (Memory Accurate Response Mode) provides a unified, persistent memory layer for AI agents that survives across sessions. Features include semantic search using AI embeddings, auto-classification of content, smart recall with vector similarity, notebook management for reusable instructions, and session logging. Supports HTTP, STDIO, and WebSocket transports.', '@lyellr88', 'ai-ml', 'Unknown', 251, 'https://github.com/lyellr88/marm-systems', NULL, 0, 'https://github.com/lyellr88.png?size=128', '2026-03-09T05:21:02.030403+00:00'),
  ('knowledge-rag', 'Knowledge RAG', 'A local knowledge retrieval system that combines semantic search with keyword-based routing for document analysis across security, development, and general knowledge domains. Uses ChromaDB for vector storage, Ollama for local embeddings, and implements hybrid search through Reciprocal Rank Fusion combining BM25 keyword matching with semantic similarity. Supports multiple document formats (PDF, Markdown, code files) with intelligent chunking and category detection, featuring specialized keyword routing for cybersecurity topics like red team tactics, blue team detection, CTF challenges, and WAF bypass techniques.', '@lyonzin', 'development', 'Unknown', 9, 'https://github.com/lyonzin/knowledge-rag', NULL, 0, 'https://github.com/lyonzin.png?size=128', '2026-03-09T05:21:02.030463+00:00'),
  ('loom', 'Loom', 'Loom is a collaborative text exploration MCP server built with Python using Starlette and Uvicorn. It provides base model completions for interactive text generation workflows, enabling users to explore and expand text content through AI model interactions. The implementation focuses on text-based exploration and completion tasks, making it useful for creative writing, content development, and iterative text refinement processes.', '@lyramakesmusic', 'development', 'Unknown', 9, 'https://github.com/lyramakesmusic/loom-mcp', NULL, 0, 'https://github.com/lyramakesmusic.png?size=128', '2026-03-09T05:21:02.030485+00:00'),
  ('solidity-contract-analyzer', 'Solidity Contract Analyzer', 'This MCP server provides AI assistants with Solidity smart contract analysis capabilities through deep AST parsing and function call flow analysis. Built by LyuboslavLyubenov using TypeScript with the @solidity-parser/parser library, the implementation offers a single analyze-fn tool that takes a Solidity file path and function name to extract detailed execution flow, variable interactions, state changes, and external contract calls with nested call tracking. The server parses contract source code into an Abstract Syntax Tree, identifies function definitions with their modifiers and parameters, traces internal function calls recursively, and maps external calls to contract instances and library functions, returning comprehensive JSON analysis of function behavior. Designed for developers debugging Solidity contracts, auditors performing security reviews, and AI assistants helping users understand complex smart contract execution paths and inter-contract dependencies.', '@lyuboslavlyubenov', 'development', 'Unknown', 6, 'https://github.com/lyuboslavlyubenov/analyze-solidity-mcp', '@lyuboslavlyubenov/analyze-solidity-mcp', 224, 'https://github.com/lyuboslavlyubenov.png?size=128', '2026-03-09T05:21:02.030518+00:00'),
  ('solodit', 'Solodit', 'This Solodit MCP server by LyuboslavLyubenov provides AI assistants with direct access to Solodit''s vulnerability database, enabling search and retrieval of smart contract security audit findings through natural language queries. The implementation offers two core tools: keyword-based search that returns matching vulnerability report titles and slugs, and detailed report retrieval by slug that provides full vulnerability content including impact levels, audit firm details, and technical descriptions. Built using Express.js with retry logic and rate limiting, it integrates with Solodit''s tRPC API endpoints to deliver clean, structured vulnerability data, making it valuable for security researchers, smart contract developers, and auditors who need to quickly reference historical security findings and audit patterns for vulnerability research and security analysis workflows.', '@lyuboslavlyubenov', 'databases', 'Unknown', 40, 'https://github.com/lyuboslavlyubenov/search-solodit-mcp', '@lyuboslavlyubenov/solodit-mcp', 835, 'https://github.com/lyuboslavlyubenov.png?size=128', '2026-03-09T05:21:02.030528+00:00'),
  ('code-intelligence', 'Code Intelligence', 'Code Intelligence provides AI-powered component and utility method recommendations for development teams using private libraries and codebases. It analyzes user requirements to suggest relevant UI components and utility functions from customizable knowledge bases, while also redesigning prompts for better AI assistance. The server supports multiple AI providers including OpenAI, Anthropic, DeepSeek, and Ollama, exposing tools for querying component details, suggesting alternatives, and accessing complete library documentation.', '@lyw405', 'development', 'Unknown', 1, 'https://github.com/lyw405/code-intelligence-mcp', NULL, 0, 'https://github.com/lyw405.png?size=128', '2026-03-09T05:21:02.030583+00:00'),
  ('garenmcp', 'GarenMCP', 'GarenMCP is an AI-powered component design service that transforms natural language descriptions into production-ready React components through XML-based artifact parsing and multi-provider AI integration. Built by the GarenCode Team, it supports Anthropic Claude, OpenAI GPT, DeepSeek, and Ollama models with configurable API endpoints, providing tools for component design, block processing, and component querying with structured XML output formats. The implementation uses TypeScript with strict parsing for ComponentArtifact XML structures and includes comprehensive error handling, making it valuable for developers who want to rapidly prototype UI components through conversational interfaces while maintaining code quality and consistency across different AI providers.', '@lyw405', 'development', 'Unknown', 3, 'https://github.com/lyw405/mcp-garendesign', NULL, 0, 'https://github.com/lyw405.png?size=128', '2026-03-09T05:21:02.030614+00:00'),
  ('aurai-advisor', 'Aurai Advisor', 'Provides advisory capabilities through specialized AI-powered consultation and guidance functions with enterprise-grade operational support and comprehensive tooling for production deployment. Features multi-turn conversation management, intelligent context tracking, and file upload support for comprehensive consultation workflows.', '@lzmw', 'ai-ml', 'Unknown', 8, 'https://github.com/lzmw/mcp-aurai-server', NULL, 0, 'https://github.com/lzmw.png?size=128', '2026-03-09T05:21:02.030646+00:00'),
  ('yapi', 'YApi', 'This MCP server implementation, developed by lzsheng, provides integration with the YApi platform for API management and documentation. It offers tools for querying and retrieving API information, including endpoints, parameters, and response structures. The server is designed to enhance AI-assisted development workflows by enabling seamless access to API documentation, facilitating tasks such as code generation, API testing, and integration planning.', '@lzsheng', 'development', 'Unknown', 62, 'https://github.com/lzsheng/yapi-mcp', NULL, 0, 'https://github.com/lzsheng.png?size=128', '2026-03-09T05:21:02.030668+00:00'),
  ('dyson-sphere-program', 'Dyson Sphere Program', 'Provides factory optimization for Dyson Sphere Program through a dual-component architecture. A C# BepInEx plugin hooks into the game via Harmony patches to collect live production metrics, while a Python MCP server analyzes factory state from both real-time data and save files. Features intelligent data source routing with automatic fallback, production bottleneck detection with root cause analysis, power grid monitoring, belt saturation tracking, and optimized blueprint generation. Includes a comprehensive recipe database with dependency graph analysis for optimizing complex production chains.', '@m2ai-mcp-servers', 'databases', 'Unknown', 4, 'https://github.com/m2ai-mcp-servers/mcp-dsp-game', NULL, 0, 'https://github.com/m2ai-mcp-servers.png?size=128', '2026-03-09T05:21:02.030721+00:00'),
  ('e2e-browser-automation', 'E2E Browser Automation', 'E2E-MCP provides a server for running end-to-end tests using browser automation through the Model Context Protocol. Built with Python, it integrates with LLM providers like OpenAI and Anthropic to power an agent that can interact with web browsers using the browser-use library. The implementation allows for headless or visible browser operation, making it ideal for AI-assisted web testing, content extraction, and automated browsing workflows. The server can be debugged using the MCP inspector tool and is designed to enhance ''Vibe Coding'' workflows in AI IDEs like Cursor or Windsurf.', '@m2rads', 'development', 'Unknown', 3, 'https://github.com/m2rads/limetest', NULL, 0, 'https://github.com/m2rads.png?size=128', '2026-03-09T05:21:02.030749+00:00'),
  ('io-github-jonnybottles-m365-roadmap', 'io.github.jonnybottles/m365-roadmap', 'Query the Microsoft 365 Roadmap from AI agents', '@jonnybottles', 'development', 'Unknown', 1, 'https://github.com/jonnybottles/m365-roadmap-mcp-server', NULL, 0, 'https://github.com/jonnybottles.png?size=128', '2026-03-09T05:21:02.030766+00:00'),
  ('websearch-tools', 'WebSearch Tools', 'This MCP server implementation provides web search and information extraction capabilities. It integrates with external APIs like Firecrawl and Tavily to perform web searches, crawl websites, and extract specific information based on prompts. The server offers tools for searching the internet, crawling linked pages, and scraping content from URLs. It''s designed for use cases requiring AI assistants to access and analyze up-to-date information from the web, such as research tasks, content aggregation, or data mining.', '@josemartinrodriguezmortaloni', 'productivity', 'Unknown', 1, 'https://github.com/josemartinrodriguezmortaloni/websearch-tools', NULL, 0, 'https://github.com/josemartinrodriguezmortaloni.png?size=128', '2026-03-09T05:21:02.030804+00:00'),
  ('dust', 'Dust', 'Dust MCP Server provides a bridge between Claude and the Dust.tt AI agent platform, specifically integrating a SystemsThinking agent that specializes in cognitive neuroscience and problem-solving strategies. Built by an AI research team, this implementation enables users to interact with specialized Dust agents through a standardized MCP interface, supporting features like conversation management, message retrieval, and dynamic agent interactions.', '@ma3u', 'ai-ml', 'Unknown', 0, 'https://github.com/ma3u/mcp-server-dust-py', NULL, 0, 'https://github.com/ma3u.png?size=128', '2026-03-09T05:21:02.030864+00:00'),
  ('maa-automation-assistant', 'MAA Automation Assistant', 'Enables automated control of Android devices and Windows desktop applications through the MaaFramework automation toolkit. Provides device discovery, screen recognition via OCR, and precise control operations including clicks, swipes, text input, and key presses. Supports background operations on Windows and multi-device coordination for cross-device automation workflows, making it valuable for game automation, testing scenarios, and tasks requiring programmatic interaction with visual interfaces.', '@maa-ai', 'development', 'Unknown', 319, 'https://github.com/maa-ai/maamcp', NULL, 0, 'https://github.com/maa-ai.png?size=128', '2026-03-09T05:21:02.030892+00:00'),
  ('daemonize', 'Daemonize', 'mcp-daemonize is a server designed to help AI agents like Claude Code and Cline manage long-running processes (daemons) during development. Created by mackee, it solves the problem of AI agents being unable to start, monitor, and debug development servers that need to run continuously. The implementation provides tools to start daemons without waiting for completion, stop running processes, view real-time logs, and list active daemons. It''s particularly valuable for autonomous coding workflows where AI agents need to manage development servers (like Vite or Next.js), monitor their output, and perform automated debugging without requiring users to manually handle these processes in separate terminals.', '@mackee', 'development', 'Unknown', 7, 'https://github.com/mackee/mcp-daemonize', NULL, 0, 'https://github.com/mackee.png?size=128', '2026-03-09T05:21:02.031026+00:00'),
  ('fathom-analytics', 'Fathom Analytics', 'This MCP server provides access to Fathom Analytics data through an AI assistant, enabling users to retrieve account information, manage sites, track events, generate aggregated analytics reports, and monitor real-time visitor data. Built by Mackenly Jones using the unofficial @mackenly/fathom-api SDK, it exposes five main tools that interface with Fathom''s API endpoints, allowing for flexible data querying and visualization. The implementation is designed for easy integration with Claude Desktop and other MCP clients through a simple configuration that requires only a Fathom API key, making it ideal for website owners who want to analyze traffic patterns, track performance metrics, and monitor visitor engagement without leaving their AI assistant interface.', '@mackenly', 'ai-ml', 'Unknown', 3, 'https://github.com/mackenly/mcp-fathom-analytics', 'mcp-fathom-analytics', 4956, 'https://github.com/mackenly.png?size=128', '2026-03-09T05:21:02.031076+00:00'),
  ('macos-notifications-with-tmux', 'macOS Notifications with tmux', 'This macOS notification MCP server by Yuki Yano provides native macOS notification capabilities with intelligent tmux session integration and terminal emulator detection. The implementation combines a Swift-based notification app bundle with a TypeScript MCP server that can automatically detect the user''s terminal environment (VSCode, Cursor, iTerm2, Terminal, alacritty) and navigate to specific tmux sessions, windows, and panes when notifications are clicked. Built for developers working in tmux environments who want contextual notifications that can instantly return them to the relevant terminal session, it offers both programmatic MCP tools and a standalone CLI for integration into build scripts, CI/CD pipelines, and development workflows.', '@yuki-yano', 'development', 'Unknown', 13, 'https://github.com/yuki-yano/macos-notify-mcp', 'macos-notify-mcp', 842, 'https://github.com/yuki-yano.png?size=128', '2026-03-09T05:21:02.031108+00:00'),
  ('ayd', 'Ayd', 'This MCP server for Ayd, developed by SHIDA Yuma, provides AI assistants with access to Ayd''s service monitoring capabilities. It integrates with the Ayd API to offer tools for listing monitored targets, retrieving status overviews, checking individual target statuses, and reading monitoring logs. Built in Go and implementing the MCP 2024-11-05 specification, it serves as a bridge between AI systems and Ayd''s monitoring infrastructure. The server abstracts Ayd''s API complexities, allowing AI assistants to easily incorporate real-time service status information into their workflows. It''s particularly useful for system administrators, DevOps teams, and AI developers working on operational support tools, enabling use cases like automated status reporting, incident response, and service health analysis.', '@macrat', 'ai-ml', 'Unknown', 0, 'https://github.com/macrat/mcp-ayd-server', NULL, 0, 'https://github.com/macrat.png?size=128', '2026-03-09T05:21:02.031156+00:00'),
  ('kintone', 'Kintone', 'This MCP server, developed by SHIDA Yuma, enables AI assistants to interact with Kintone databases through a standardized interface. It provides tools for listing apps, reading app info, and performing CRUD operations on records via the Kintone API. The server implements custom permission handling and error checking, offering a simplified workflow for AI systems to access and manipulate Kintone data. By connecting AI capabilities with Kintone''s flexible database platform, this implementation empowers AI assistants to perform tasks like data analysis, workflow automation, or custom reporting. It is particularly useful for applications requiring structured data management, business process automation, or any scenario where an AI system needs to interact with and reason about enterprise data stored in Kintone.', '@macrat', 'databases', 'Unknown', 12, 'https://github.com/macrat/mcp-server-kintone', NULL, 0, 'https://github.com/macrat.png?size=128', '2026-03-09T05:21:02.031167+00:00'),
  ('macuse', 'Macuse', 'Macuse is a macOS desktop application that provides deep integration with native macOS apps through toolboxes for system operations, UI automation, and app-specific integrations. Enables access to Calendar, Reminders, Contacts, Notes, Messages, and Maps with local processing and token-based authentication. Supports stdio, SSE, and streamable HTTP transports for connecting with Claude, Cursor, Raycast, and other compatible clients.', '@unknown', 'productivity', 'Unknown', 0, 'https://macuse.app', NULL, 0, NULL, '2026-03-09T05:21:02.031198+00:00'),
  ('ragrabbit', 'RagRabbit', 'This MCP server implementation provides AI assistants with access to RagRabbit, an open-source system for site AI search and LLM.txt generation. It integrates with LlamaIndex and pgVector to crawl websites, convert pages to markdown, generate vector embeddings, and enable AI-powered search and question answering from indexed content. The server exposes functionality for crawling URLs, managing indexes, and querying the knowledge base, making it useful for applications requiring domain-specific information retrieval and conversational AI capabilities.', '@madarco', 'ai-ml', 'Unknown', 132, 'https://github.com/madarco/ragrabbit', '@ragrabbit/mcp', 605, 'https://github.com/madarco.png?size=128', '2026-03-09T05:21:02.031239+00:00'),
  ('agent-orchestration', 'Agent Orchestration', 'Agent Orchestration enables multiple AI agents to collaborate effectively across IDEs and CLI tools. It provides shared memory for storing context and decisions, a turn-based task queue with dependencies, resource locking to prevent file conflicts, and agent discovery to see who else is working on a project. The server uses SQLite for persistence and automatically syncs project context to activeContext.md, making it useful for complex multi-agent workflows where agents need to avoid race conditions, share findings, and coordinate work.', '@madebyaris', 'databases', 'Unknown', 4, 'https://github.com/madebyaris/agent-orchestration', NULL, 0, 'https://github.com/madebyaris.png?size=128', '2026-03-09T05:21:02.031251+00:00'),
  ('obsidian-diary', 'Obsidian Diary', 'Built by Gwyneth Pena-Siguenza using FastMCP, this server provides intelligent diary management capabilities for Obsidian vaults. It analyzes diary content to identify key themes and emotions, then automatically links entries with similar topics while generating personalized reflection questions to encourage deeper self-awareness and personal growth. The server supports creating templated entries, reading existing entries, updating backlinks across all entries, and listing recent diary activity, making it valuable for users who want to maintain a connected, reflective journaling practice with assistance for discovering patterns and insights across their personal writing over time.', '@madebygps', 'ai-ml', 'Unknown', 4, 'https://github.com/madebygps/obsidian-diary-mcp', NULL, 0, 'https://github.com/madebygps.png?size=128', '2026-03-09T05:21:02.031303+00:00'),
  ('deobfuscate', 'Deobfuscate', 'An MCP server that transforms minified and bundled JavaScript code into a searchable database for reverse engineering. Built with webcrack for unpacking Webpack/Browserify bundles, it uses Babel AST parsing to provide structural analysis, module navigation, function extraction, and call graph generation while caching results in memory. Unlike standard beautifiers that only format code, this server enables semantic search across thousands of unbundled modules, selective code retrieval to manage context windows, and architectural mapping through JSON summaries before diving into specific implementations.', '@madebytokens', 'databases', 'Unknown', 5, 'https://github.com/madebytokens/deobfuscate-mcp-server', NULL, 0, 'https://github.com/madebytokens.png?size=128', '2026-03-09T05:21:02.031337+00:00'),
  ('bug-detector', 'Bug Detector', 'A bug detection agent designed to identify and analyze software defects through automated analysis. The minimal repository structure suggests this is an early-stage or conceptual implementation focused on providing AI-powered bug detection capabilities, useful for code review automation, quality assurance workflows, and development process enhancement.', '@madhavi-opsera', 'development', 'Unknown', 0, 'https://github.com/madhavi-opsera/bug-detector', NULL, 0, 'https://github.com/madhavi-opsera.png?size=128', '2026-03-09T05:21:02.031360+00:00'),
  ('itsm-integration', 'ITSM Integration', 'MCP ITSM provides a unified interface for LLMs to interact with multiple IT Service Management systems (ServiceNow, Jira, Zendesk, Ivanti Neurons, and Cherwell) through standardized tools. Built with Node.js, it intelligently routes requests to the appropriate ITSM system, handles ticket creation, retrieval, updates, assignment, and knowledge base searches while maintaining consistent response formats. The implementation supports both HTTP and stdio transports with API key authentication, making it ideal for organizations managing multiple ITSM platforms who want to streamline AI assistant interactions with their ticketing systems.', '@madosh', 'productivity', 'Unknown', 1, 'https://github.com/madosh/mcp-itsm', NULL, 0, 'https://github.com/madosh.png?size=128', '2026-03-09T05:21:02.031400+00:00'),
  ('codex-persistent', 'Codex Persistent', 'Bridges AI agents with the Codex CLI while preserving session continuity. Creates real, resumable Codex CLI sessions via MCP calls that survive server restarts. Provides three primary tools: general conversation (codex_chat), structured planning with critique (codex_plan), and code review (codex_review). Features automatic attribution distinguishing agent requests from human commands, per-request model and reasoning effort overrides, and session storage in Codex''s native format for manual resumption with `codex resume`.', '@madwiki', 'development', 'Unknown', 1, 'https://github.com/madwiki/codex-persistent-mcp', NULL, 0, 'https://github.com/madwiki.png?size=128', '2026-03-09T05:21:02.031426+00:00'),
  ('dynamics-365-finance-operations', 'Dynamics 365 Finance & Operations', 'Comprehensive Python client library for Microsoft Dynamics 365 Finance & Operations that provides access to OData endpoints, metadata operations, and label management. Offers 49 tools across 9 functional categories including full CRUD operations on D365 F&O data entities, enhanced metadata caching with search capabilities, and multilingual label support. Available as both traditional MCP SDK and modern FastMCP framework implementations.', '@mafzaal', 'ai-ml', 'Unknown', 25, 'https://github.com/mafzaal/d365fo-client', NULL, 0, 'https://github.com/mafzaal.png?size=128', '2026-03-09T05:21:02.031461+00:00'),
  ('giphy', 'Giphy', 'A Model Context Protocol (MCP) server implementation for Giphy API that allows AI assistants to search and retrieve GIFs.', '@magarcia', 'ai-ml', 'Unknown', 28, 'https://github.com/magarcia/mcp-server-giphy', 'mcp-server-giphy', 9049, 'https://github.com/magarcia.png?size=128', '2026-03-09T05:21:02.031483+00:00'),
  ('figma-bridge', 'Figma Bridge', 'Enables real-time interaction with Figma documents through a dual-architecture system consisting of a Figma plugin and MCP server connected via WebSocket. Provides comprehensive design operations including node creation and manipulation, styling, layout management with auto-layout support, component and variable handling, and boolean operations. Emphasizes token efficiency with specialized search tools that return compact results, making it suitable for large design systems where traditional bulk operations would exceed token limits.', '@magic-spells', 'search', 'Unknown', 29, 'https://github.com/magic-spells/figma-mcp-bridge', NULL, 0, 'https://github.com/magic-spells.png?size=128', '2026-03-09T05:21:02.031566+00:00'),
  ('magic-ui', 'Magic UI', 'MCP Magic UI is a server that fetches and categorizes Magic UI components from the magicuidesign/magicui GitHub repository, providing AI assistants with a standardized way to discover and use UI components. It supports multiple transport methods (stdio and HTTP), implements local caching to reduce API calls, and automatically categorizes components based on their names and dependencies. The server is particularly useful for developers and AI assistants looking to quickly integrate pre-built, categorized UI components into their projects.', '@idcdev', 'development', 'Unknown', 12, 'https://github.com/idcdev/mcp-magic-ui', NULL, 0, 'https://github.com/idcdev.png?size=128', '2026-03-09T05:21:02.031589+00:00'),
  ('free-usdc-transfer-base', 'Free USDC Transfer (Base)', 'Free USDC Transfer MCP Server enables feeless USDC transfers on the Base blockchain through Coinbase CDP''s MPC wallet integration. Developed by Magnet Labs, it provides tools to create secure MPC wallets and transfer USDC to any Ethereum address or ENS/BaseName domain without transaction fees. The implementation stores wallet seeds locally in a JSON file and requires Coinbase CDP API credentials for authentication. Particularly valuable for workflows requiring blockchain transactions without the complexity of managing gas fees or traditional wallet interfaces.', '@magnetai', 'ai-ml', 'Unknown', 20, 'https://github.com/magnetai/mcp-free-usdc-transfer', '@magnetai/free-usdc-transfer', 406, 'https://github.com/magnetai.png?size=128', '2026-03-09T05:21:02.031658+00:00'),
  ('developer-documentation', 'Developer Documentation', 'This MCP documentation server, developed as an open-source project, provides AI-assisted code improvement and documentation management through Claude Desktop integration. Built with TypeScript and leveraging libraries like Express and Cheerio, it offers features such as an AI documentation guide, code analysis, and framework-specific support for popular technologies like React, Next.js, and Node.js. The server integrates with Brave Search for smart documentation retrieval and implements a learning system to improve suggestions over time. It''s designed for developers and technical writers seeking intelligent assistance in maintaining codebases and documentation, enabling use cases like automated code reviews, dynamic documentation updates, and AI-powered development workflows across multiple programming languages and frameworks.', '@mahawi1992', 'development', 'Unknown', 10, 'https://github.com/mahawi1992/mcp-documentation-server', NULL, 0, 'https://github.com/mahawi1992.png?size=128', '2026-03-09T05:21:02.031686+00:00'),
  ('geoserver', 'GeoServer', 'GeoServer MCP Server provides a bridge between AI assistants and GeoServer''s REST API, enabling management of geospatial data and mapping services. Built with Python using the FastMCP framework, it exposes tools for workspace management, layer operations, feature querying, and map generation through WMS/WFS services. The server connects to any GeoServer instance via configurable credentials, supports both resource-based and tool-based interactions, and includes comprehensive error handling for robust operation. Particularly valuable for geospatial applications requiring AI assistance with data visualization, spatial analysis, or GIS administration tasks.', '@mahdin75', 'productivity', 'Unknown', 59, 'https://github.com/mahdin75/geoserver-mcp', NULL, 0, 'https://github.com/mahdin75.png?size=128', '2026-03-09T05:21:02.031728+00:00'),
  ('gis-operations', 'GIS Operations', 'The GIS MCP server connects LLMs to geospatial operations through Shapely and PyProj libraries, enabling AI assistants to perform geometric transformations, coordinate system conversions, and spatial analyses. Developed by Mahdi Nazari Ashani, this implementation exposes a comprehensive set of tools organized into categories like basic operations, transformations, and geodetic calculations, with each function accepting WKT geometry strings and returning structured results. The server handles error reporting, geometry validation, and proper CRS management, making it valuable for applications requiring spatial analysis, map creation, or location-based services without switching contexts.', '@mahdin75', 'ai-ml', 'Unknown', 119, 'https://github.com/mahdin75/gis-mcp', 'gis-mcp', 9201, 'https://github.com/mahdin75.png?size=128', '2026-03-09T05:21:02.031774+00:00'),
  ('coding-project-structure', 'Coding Project Structure', 'This Project Content Server, implemented in TypeScript, provides a streamlined solution for accessing and retrieving project files and their contents through the Model Context Protocol. It offers a single API endpoint, ''latest_project_data'', which accepts a project path and returns a comprehensive map of file paths to file contents. The server is designed to be easily configurable via environment variables and includes robust error handling. It''s particularly useful for AI assistants or development tools that need to analyze or manipulate entire project structures, enabling use cases such as code review, project analysis, or automated documentation generation.', '@maheshdoiphode', 'development', 'Unknown', 6, 'https://github.com/maheshdoiphode/mcp-cline-project-content-server', NULL, 0, 'https://github.com/maheshdoiphode.png?size=128', '2026-03-09T05:21:02.031803+00:00'),
  ('trino', 'Trino', 'A Trino MCP server that enables secure, controlled data exploration and analysis by providing tools to list tables, read data, and execute SQL queries through a standardized interface. Built by Mahesh Premachandran, this implementation allows AI assistants to interact with Trino databases using environment-based configuration, supporting operations like querying tables, retrieving data samples, and running SQL commands with robust error handling.', '@dataring-engineering', 'databases', 'Unknown', 18, 'https://github.com/dataring-engineering/mcp-server-trino', NULL, 0, 'https://github.com/dataring-engineering.png?size=128', '2026-03-09T05:21:02.031815+00:00'),
  ('ultimatecoder', 'UltimateCoder', 'UltimateCoder is a FastMCP server that exposes comprehensive file system operations and advanced coding functionalities. It provides tools for precise code modifications, process management, code searching/editing, intelligent block replacement, linting, and static analysis. Built with Python and utilizing tools like ripgrep for fast code search, this implementation enables AI assistants to perform complex coding workflows, from reading and modifying files to running linters and analyzing Python code. It''s particularly useful for developers seeking automated code maintenance, refactoring assistance, and intelligent file manipulation through the MCP interface.', '@m-ahmed-elbeskeri', 'development', 'Unknown', 13, 'https://github.com/m-ahmed-elbeskeri/ultimatecodermcp', NULL, 0, 'https://github.com/m-ahmed-elbeskeri.png?size=128', '2026-03-09T05:21:02.031848+00:00'),
  ('mailerlite', 'MailerLite', 'Official MailerLite MCP server that provides AI assistants with comprehensive email marketing capabilities through direct API integration. Built by MailerLite, it offers 40+ tools spanning subscriber management (add, update, list, delete with GDPR compliance), campaign operations (create, schedule, cancel with A/B testing support), group and segment management, automation workflows, form handling, and webhook configuration. The server supports multiple authentication methods and connects seamlessly with popular AI clients including Claude, ChatGPT, Gemini CLI, VSCode, and Cursor through a standardized HTTP endpoint, making it valuable for automating email marketing workflows, managing subscriber databases, and building AI-powered marketing assistants that can handle complex multi-step email campaign operations.', '@unknown', 'databases', 'Unknown', 0, 'https://developers.mailerlite.com/mcp/', NULL, 0, NULL, '2026-03-09T05:21:02.031871+00:00'),
  ('mailersend', 'MailerSend', 'Official MailerSend MCP server (BETA) that provides AI assistants with complete control over MailerSend''s email marketing platform through 30+ standardized tools. Built by MailerSend, it enables management of email campaigns, domain configuration, message scheduling, template creation, webhook setup, activity monitoring, analytics retrieval, and email verification directly through AI conversations. The server supports OAuth authentication and integrates with popular AI clients including Claude, ChatGPT, Gemini CLI, VSCode, and Cursor, making it valuable for automating email marketing workflows, managing subscriber lists, monitoring campaign performance, and handling domain verification processes without switching between multiple interfaces.', '@unknown', 'development', 'Unknown', 0, 'https://developers.mailersend.com/mcp-server.html', NULL, 0, NULL, '2026-03-09T05:21:02.031898+00:00'),
  ('mailgun', 'Mailgun', 'Mailgun MCP Server provides a bridge between Claude Desktop and the Mailgun email service API, enabling AI assistants to send emails and retrieve email statistics through a standardized interface. The implementation transforms Mailgun''s OpenAPI specification into MCP tools, handling authentication, parameter validation, and request formatting automatically. It supports over 30 Mailgun API endpoints including sending messages, retrieving domain information, and analyzing email delivery statistics. Built with Node.js and the MCP SDK, this server requires a Mailgun API key and is ideal for workflows that need email delivery capabilities integrated with AI assistants.', '@mailgun', 'communication', 'Unknown', 47, 'https://github.com/mailgun/mailgun-mcp-server', NULL, 0, 'https://github.com/mailgun.png?size=128', '2026-03-09T05:21:02.031938+00:00'),
  ('mailpace', 'MailPace', 'MailPace MCP Server provides a bridge to MailPace''s transactional email API, enabling AI assistants to send emails with features like HTML/text content, attachments, CC/BCC recipients, and custom headers. Built with TypeScript and running over stdio, it authenticates using domain API tokens and handles error states appropriately, making it valuable for applications that need to send automated emails through natural language requests without managing SMTP servers or complex email infrastructure.', '@mailpace', 'development', 'Unknown', 1, 'https://github.com/mailpace/mailpace-mcp', NULL, 0, 'https://github.com/mailpace.png?size=128', '2026-03-09T05:21:02.031965+00:00'),
  ('mailtrap-email-api', 'Mailtrap Email API', 'The official Mailtrap MCP server enables AI assistants to send transactional emails through the Mailtrap service. Developed by Railsware Products Studio LLC, this TypeScript implementation provides a single tool for sending emails with support for HTML/text content, CC/BCC recipients, and email categorization. The server authenticates with the Mailtrap API using an API token and includes configurable default sender settings. It''s particularly useful for scenarios requiring email notifications, automated messaging, or communication workflows where AI assistants need to send formatted emails to specified recipients.', '@mailtrap', 'development', 'Unknown', 56, 'https://github.com/mailtrap/mailtrap-mcp', 'mcp-mailtrap', 6846, 'https://github.com/mailtrap.png?size=128', '2026-03-09T05:21:02.031992+00:00'),
  ('technical-documentation-search', 'Technical Documentation Search', 'The Custom-MCP-server provides AI assistants with access to technical documentation through a specialized tool for searching and retrieving content from popular libraries including LangChain, LlamaIndex, and OpenAI. Built with Python using the FastMCP framework, it leverages the Brave Search API to find relevant documentation pages based on user queries, then fetches and extracts the content using httpx and BeautifulSoup. The implementation handles proper error cases and timeout scenarios, making it particularly valuable for developers and technical users who need quick access to up-to-date documentation without leaving their AI assistant conversation.', '@maitreyam', 'ai-ml', 'Unknown', 1, 'https://github.com/maitreyam/documentation-fetching-mcp-server', NULL, 0, 'https://github.com/maitreyam.png?size=128', '2026-03-09T05:21:02.032069+00:00'),
  ('pdf-gen-studio', 'PDF Gen Studio', 'Provides document generation capabilities through the PDF Gen Studio cloud API. Supports template-based rendering with dynamic data injection, JSON document conversion, HTML/CSS to PDF conversion, and webpage screenshot capture. Includes tools for template management including listing, retrieving, and understanding template schemas, with configurable output formats (PDF, PNG, JPG) and rendering options.', '@majid9287', 'ai-ml', 'Unknown', 1, 'https://github.com/majid9287/pdfgenstudio-mcp', NULL, 0, 'https://github.com/majid9287.png?size=128', '2026-03-09T05:21:02.032104+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('performance-co-pilot', 'Performance Co-Pilot', 'Integrates with Performance Co-Pilot (PCP) to query system performance metrics including CPU, memory, disk I/O, network, and process information. Provides tools for real-time system snapshots, top process monitoring, metric discovery and search, and detailed metric metadata. Supports monitoring both local and remote hosts through PCP''s pmproxy REST API, with configurable TLS and authentication options.', '@major', 'ai-ml', 'Unknown', 0, 'https://github.com/major/pcp-mcp', NULL, 0, 'https://github.com/major.png?size=128', '2026-03-09T05:21:02.032137+00:00'),
  ('porkbun-dns', 'Porkbun DNS', 'Provides tools for managing DNS records, domains, DNSSEC settings, SSL certificates, and pricing information through Porkbun''s DNS API. Runs in read-only mode by default for safety, with an explicit opt-in flag to enable write operations. Supports both stdio and SSE transports and can be run directly via uvx without installation.', '@major', 'ai-ml', 'Unknown', 4, 'https://github.com/major/porkbun-mcp', NULL, 0, 'https://github.com/major.png?size=128', '2026-03-09T05:21:02.032169+00:00'),
  ('genesys-cloud', 'Genesys Cloud', 'Genesys Cloud MCP Server provides a bridge between AI assistants and Genesys Cloud''s Platform API, enabling access to contact center analytics and routing data. Developed by Lucas Woodward as a personal project, it offers tools for searching queues, querying conversation volumes, sampling conversations by queue, and analyzing voice call quality metrics. The implementation handles authentication through OAuth client credentials and supports both real API connections and a mocking mode for testing. Built with TypeScript and the Model Context Protocol SDK, this server is particularly valuable for creating conversational business intelligence tools that can analyze contact center performance without requiring direct API knowledge.', '@makingchatbots', 'development', 'Unknown', 21, 'https://github.com/makingchatbots/genesys-cloud-mcp-server', '@makingchatbots/genesys-cloud-mcp-server', 6604, 'https://github.com/makingchatbots.png?size=128', '2026-03-09T05:21:02.032277+00:00'),
  ('zebrunner', 'Zebrunner', 'Integrates with Zebrunner''s test automation management platform to provide AI-powered test case management capabilities. Enables retrieval and management of test cases and suites, quality validation against 100+ checkpoints using intelligent rules, automated improvement suggestions, test execution analysis with forensic details, and Selenium WebDriver code generation. Supports QA engineers, SDETs, developers, managers, and product owners with role-specific workflows.', '@maksimsarychau', 'development', 'Unknown', 2, 'https://github.com/maksimsarychau/mcp-zebrunner', NULL, 0, 'https://github.com/maksimsarychau.png?size=128', '2026-03-09T05:21:02.032302+00:00'),
  ('malaysia-prayer-time', 'Malaysia Prayer Time', 'Malaysia Prayer Time MCP Server provides accurate Islamic prayer times for Malaysia by integrating with the waktusolat.app API. It offers tools to retrieve prayer schedules for specific zones, list available geographical zones across Malaysia, and get current prayer status information. The server is implemented in Python using Pydantic for data validation and exposes a simple interface that makes it easy for AI assistants to access and display prayer times for Muslims in Malaysia, making it particularly useful for applications serving Malaysian Muslim communities.', '@amanasmuei', 'ai-ml', 'Unknown', 0, 'https://github.com/amanasmuei/mcp-server-malaysia-prayer-time', NULL, 0, 'https://github.com/amanasmuei.png?size=128', '2026-03-09T05:21:02.032346+00:00'),
  ('malloryai-intelligence', 'MalloryAI Intelligence', 'MalloryAI MCP Server provides a bridge to the MalloryAI Intelligence platform, enabling AI assistants to access threat intelligence data through a structured API. The implementation offers tools for querying vulnerabilities, threat actors, and exploitation data, with each function carefully documented to help AI models understand the context and appropriate use cases. Built by the Mallory team, this server is particularly valuable for security professionals who need to analyze CVEs, track threat actor activities, or monitor exploitation events in the wild.', '@malloryai', 'ai-ml', 'Unknown', 7, 'https://github.com/malloryai/mallorymcp', NULL, 0, 'https://github.com/malloryai.png?size=128', '2026-03-09T05:21:02.032415+00:00'),
  ('audio-playback', 'Audio Playback', 'This Audio MCP server, developed by an unnamed creator, provides a standardized interface for audio playback operations through the Model Context Protocol. Built with TypeScript and leveraging the MCP SDK, it integrates with the play-sound library to enable cross-platform audio playback functionality. The server implements basic audio controls, allowing AI systems to easily trigger sound playback on the host machine. By abstracting the complexities of audio APIs, it facilitates use cases such as voice notifications, sound effects in AI-driven applications, or audio cues in automated systems. This implementation is particularly useful for scenarios requiring programmatic audio output in response to AI-generated events or commands.', '@mamertofabian', 'development', 'Unknown', 1, 'https://github.com/mamertofabian/audio-mcp-server', NULL, 0, 'https://github.com/mamertofabian.png?size=128', '2026-03-09T05:21:02.032458+00:00'),
  ('dbt-cli', 'dbt CLI', 'The dbt-cli-mcp server implementation provides a bridge between Claude and the dbt Core command-line interface, enabling AI assistants to directly interact with data transformation workflows. Currently experiencing setup issues with the MammothGrowth/dbt-cli-mcp repository, this tool would allow users to execute dbt commands, manage data models, and analyze transformation pipelines without leaving their conversation interface. When functioning properly, it would streamline data engineering tasks by bringing dbt''s capabilities directly into Claude-assisted workflows.', '@mammothgrowth', 'productivity', 'Unknown', 19, 'https://github.com/mammothgrowth/dbt-cli-mcp', NULL, 0, 'https://github.com/mammothgrowth.png?size=128', '2026-03-09T05:21:02.032599+00:00'),
  ('psianimator', 'PsiAnimator', 'PsiAnimator-MCP integrates QuTip quantum physics computations with Manim mathematical animations to provide quantum state creation, evolution simulation, and visualization capabilities through MCP tools. The server supports creation of various quantum states (pure, mixed, coherent, squeezed, thermal, Fock), time evolution calculations, measurement operations, entanglement analysis, and gate sequences, with optional animation generation for Bloch spheres, Wigner functions, energy level diagrams, and quantum circuits. Built with graceful degradation to handle missing scientific dependencies, it features multiple Docker configurations for different deployment scenarios and uses a modular architecture separating quantum computations from visualization, making it useful for quantum physics education, research visualization, and AI-assisted quantum system analysis.', '@manasp21', 'cloud', 'Unknown', 2, 'https://github.com/manasp21/psianimator-mcp', NULL, 0, 'https://github.com/manasp21.png?size=128', '2026-03-09T05:21:02.032624+00:00'),
  ('mandoline', 'Mandoline', 'This Mandoline MCP server, developed by Mandoline AI, provides AI assistants with direct access to Mandoline''s LLM evaluation platform through a comprehensive set of tools for creating and managing custom metrics, running evaluations on prompt-response pairs, and retrieving evaluation results. Built with TypeScript and Express, it features session management with automatic cleanup, API key-based authentication, and tools for both individual and batch operations on metrics and evaluations. The implementation includes automatic environment context injection (client info, model names) and content hashing for evaluation tracking, making it particularly useful for AI development teams who need to systematically evaluate and improve their language models through conversational interfaces rather than traditional dashboards.', '@mandoline-ai', 'development', 'Unknown', 4, 'https://github.com/mandoline-ai/mandoline-mcp-server', NULL, 0, 'https://github.com/mandoline-ai.png?size=128', '2026-03-09T05:21:02.032653+00:00'),
  ('malaysia-government-data-data-gov-my', 'Malaysia Government Data (data.gov.my)', 'This MCP server provides AI assistants with access to Malaysia''s official government data through the data.gov.my API and GitHub-hosted metadata repository. Developed by Manfye Goh using TypeScript and the Model Context Protocol SDK, it offers four core tools: listing available data catalogue IDs, fetching detailed metadata for specific datasets, retrieving actual data from the API with configurable limits, and searching catalogues by keyword across titles and descriptions. The implementation combines direct API calls to data.gov.my for live data with GitHub API integration to access catalogue metadata from the datagovmy-meta repository, enabling AI assistants to discover, explore, and analyze Malaysian government datasets including population statistics, economic indicators, and public service data without manual navigation of government data portals.', '@manfye', 'development', 'Unknown', 10, 'https://github.com/manfye/data-dosm-mcp-nodejs', 'datagovmy-mcp-server', 432, 'https://github.com/manfye.png?size=128', '2026-03-09T05:21:02.032683+00:00'),
  ('mysql-sse', 'MySQL SSE', 'MySQL MCP Server provides a lightweight server implementation for MySQL database operations using Server-Sent Events (SSE) transport. It offers a streamlined approach to database interactions, with configuration managed through environment variables and MySQL connection handling abstracted into modular Python components.', '@mangooer', 'databases', 'Unknown', 100, 'https://github.com/mangooer/mysql-mcp-server-sse', NULL, 0, 'https://github.com/mangooer.png?size=128', '2026-03-09T05:21:02.032694+00:00'),
  ('farcaster', 'Farcaster', 'This MCP server provides tools to interact with the Farcaster network, allowing AI models to fetch casts, search channels, and analyze content. It integrates with the Farcaster Hubble API to retrieve user casts by FID or username, as well as channel-specific casts. The implementation is designed for use cases requiring real-time access to Farcaster social data, such as content analysis, trend monitoring, or user engagement tracking.', '@manimohans', 'ai-ml', 'Unknown', 2, 'https://github.com/manimohans/farcaster-mcp', NULL, 0, 'https://github.com/manimohans.png?size=128', '2026-03-09T05:21:02.032730+00:00'),
  ('the-verge-news', 'The Verge News', 'This MCP server integrates with The Verge''s RSS feed to provide AI assistants with access to the latest technology news. It offers tools for fetching daily and weekly news updates, as well as searching for specific topics within a customizable time range. Built with TypeScript and leveraging the @modelcontextprotocol/sdk, it''s designed for use cases requiring up-to-date tech news integration, such as generating summaries, analyzing trends, or answering queries about recent technological developments.', '@manimohans', 'development', 'Unknown', 3, 'https://github.com/manimohans/verge-news-mcp', NULL, 0, 'https://github.com/manimohans.png?size=128', '2026-03-09T05:21:02.032755+00:00'),
  ('emergency-medicare-planner', 'Emergency Medicare Planner', 'This MCP server integrates with Google Maps to locate and evaluate medical facilities in emergency situations. Developed by AMOCA Corp., it provides tools for searching medical facilities, calculating routes, and checking availability within a 10km radius. The server implements sequential thinking for medical evaluation, enabling step-by-step clinical reasoning for more accurate facility matching based on patient symptoms and medical history. It''s designed for use cases requiring urgent healthcare decision-making and real-time medical facility information retrieval.', '@manolaz', 'ai-ml', 'Unknown', 4, 'https://github.com/manolaz/emergency-medicare-planner-mcp-server', NULL, 0, 'https://github.com/manolaz.png?size=128', '2026-03-09T05:21:02.032889+00:00'),
  ('mongodb-database', 'MongoDB Database', 'MCP Database Server provides a bridge between AI assistants and databases through natural language, currently supporting MongoDB operations with plans to expand to PostgreSQL, CockroachDB, and Redis. Developed by Manpreet Singh, this TypeScript implementation uses the Model Context Protocol SDK to expose tools for listing collections, querying documents with filters, inserting and deleting records, and executing aggregate pipeline operations. The server connects to MongoDB via environment variables and handles database operations efficiently, making it valuable for users who need to interact with their databases directly through AI assistants without writing complex queries.', '@manpreet2000', 'databases', 'Unknown', 0, 'https://github.com/manpreet2000/mcp-database-server', NULL, 0, 'https://github.com/manpreet2000.png?size=128', '2026-03-09T05:21:02.032901+00:00'),
  ('manus', 'Manus', 'ManusMCP is a framework for orchestrating specialized AI agents that work together through a Model Context Protocol (MCP) server implementation. Built with TypeScript, it provides file operations, shell command execution, and browser automation capabilities through a comprehensive API. The server enables AI agents to read/write files, execute shell commands, navigate web pages, and interact with browser elements. The implementation includes a Docker-based deployment with services for Flowise, Unstructured API, and LiteLLM, making it ideal for creating AI team members with specialized roles like Planner, FileWizard, CommandRunner, and WebNavigator that can collaborate on complex tasks requiring filesystem access, command-line operations, and web interactions.', '@mantrakp04', 'cloud', 'Unknown', 93, 'https://github.com/mantrakp04/manusmcp', NULL, 0, 'https://github.com/mantrakp04.png?size=128', '2026-03-09T05:21:02.032924+00:00'),
  ('minime', 'MiniMe', 'This MCP server provides AI assistants with comprehensive memory management and meta-learning capabilities for software development workflows, built by the MiniMe Team using Node.js with PostgreSQL storage and Ollama integration for local LLM processing. The implementation features a complete digital developer twin system with memory storage and retrieval, sequential thinking workflows, task extraction and management, AI-powered insights generation, and real-time analytics through a React-based dashboard UI served on port 9000 alongside the MCP server on port 8000. Built with Docker containerization, embedding-based similarity search, pattern detection across development sessions, and configurable prompt templates for learning pipeline automation, it serves developers wanting persistent AI memory across coding sessions, teams needing project-based knowledge management with automated insight generation, and organizations requiring comprehensive development analytics with local-first AI processing and no external API dependencies.', '@manujbawa', 'databases', 'Unknown', 21, 'https://github.com/manujbawa/minime-mcp', '@minimemcp/mcp-client', 1100, 'https://github.com/manujbawa.png?size=128', '2026-03-09T05:21:02.032936+00:00'),
  ('podman', 'Podman', 'This MCP server implementation provides a bridge to Podman, enabling AI assistants to interact with container management functionalities. Developed by manusa, it offers tools for container creation, management, and orchestration using Podman''s API. The server is designed for use cases requiring containerized application deployment and management, such as automating DevOps workflows or managing microservices architectures.', '@manusa', 'ai-ml', 'Unknown', 60, 'https://github.com/manusa/podman-mcp-server', 'podman-mcp-server', 4260, 'https://github.com/manusa.png?size=128', '2026-03-09T05:21:02.032991+00:00'),
  ('registry', 'Registry', 'MCP-Registry-MCP is a server implementation that provides a bridge to the Model Context Protocol Registry service. Developed by maorfr, it enables AI assistants to interact with the MCP registry through four key tools: checking server health, listing registry entries, retrieving server details, and publishing new server entries. The server requires configuration with a registry URL and API key, can be run in containers using Podman or Docker, and is particularly useful for managing and discovering MCP server implementations within the registry ecosystem.', '@redhat-community-ai-tools', 'cloud', 'Unknown', 1, 'https://github.com/redhat-community-ai-tools/mcp-registry-mcp', NULL, 0, 'https://github.com/redhat-community-ai-tools.png?size=128', '2026-03-09T05:21:02.033013+00:00'),
  ('create-server-scaffold', 'Create Server Scaffold', 'This MCP server implementation, developed by maoxiaoke, streamlines the creation of new Model Context Protocol (MCP) servers by providing a structured development protocol and example templates. It offers a specialized tool that can be easily invoked using npx, making it efficient for developers to set up MCP server scaffolds. The implementation is designed to support various use cases where rapid deployment of MCP servers is required, such as in AI-assisted development environments or for quickly prototyping MCP-based applications.', '@maoxiaoke', 'development', 'Unknown', 21, 'https://github.com/maoxiaoke/create-mcp-server', 'create-mcp-server', 339, 'https://github.com/maoxiaoke.png?size=128', '2026-03-09T05:21:02.033044+00:00'),
  ('mapbox', 'Mapbox', 'Provides access to Mapbox''s geospatial APIs for location intelligence. Supports global geocoding and reverse geocoding to convert between addresses and coordinates, POI search across millions of worldwide locations, multi-modal routing with traffic data for driving, walking, and cycling, travel time matrix calculations, isochrone generation to visualize reachable areas, and static map image generation with customizable styling.', '@mapbox', 'search', 'Unknown', 315, 'https://github.com/mapbox/mcp-server', NULL, 0, 'https://github.com/mapbox.png?size=128', '2026-03-09T05:21:02.033084+00:00'),
  ('mapbox-devkit', 'Mapbox DevKit', 'Provides developer-focused access to Mapbox platform capabilities including token management, map style creation and editing, GeoJSON utilities, and comprehensive API documentation. Enables creation and management of public tokens, style manipulation through natural language, coordinate conversion, bounding box generation, and direct access to Mapbox Streets v8 field definitions and style specifications.', '@mapbox', 'file-systems', 'Unknown', 43, 'https://github.com/mapbox/mcp-devkit-server', NULL, 0, 'https://github.com/mapbox.png?size=128', '2026-03-09T05:21:02.033128+00:00'),
  ('ntopng', 'ntopng', 'MCP-ntopng provides AI assistants with direct access to network monitoring data from ntopng systems through both ClickHouse database queries and REST API endpoints. Developed by Marco Graziano of Graziano Labs, this server exposes over 20 specialized tools for retrieving network traffic statistics, analyzing flows, monitoring alerts, and identifying top talkers in a network environment. The implementation requires ntopng with ClickHouse storage and handles authentication through API tokens, making it particularly valuable for cybersecurity professionals who need to investigate network anomalies, track traffic patterns, or diagnose connectivity issues without leaving their conversation interface.', '@marcoeg', 'databases', 'Unknown', 2, 'https://github.com/marcoeg/mcp-server-ntopng', 'mcp-ntopng', 2075, 'https://github.com/marcoeg.png?size=128', '2026-03-09T05:21:02.033282+00:00'),
  ('pega-dx-api', 'Pega DX API', 'This MCP server provides AI assistants with direct access to Pega Infinity''s DX APIs for conversational case management and workflow automation, featuring OAuth2 authentication and a comprehensive tool registry that dynamically loads operations across cases, assignments, attachments, case types, and data views. Built by Marco Looy with Node.js and organized into specialized tool categories, it enables natural language interaction with Pega Platform through standardized error handling, response formatting, and parameter validation, supporting operations like case creation and retrieval, assignment management, file attachments, bulk actions, and advanced data querying with filtering and aggregation. The implementation uses a base tool architecture for consistent API patterns, automatic tool discovery and registration, and detailed response formatting that makes Pega''s enterprise workflow capabilities accessible to AI development workflows, making it valuable for business process automation, case management integration, and building AI assistants that need programmatic access to Pega''s full enterprise platform without manual interface navigation.', '@marco-looy', 'development', 'Unknown', 15, 'https://github.com/marco-looy/pega-dx-mcp', '@pega-enablement/pega-dx-mcp', 1018, 'https://github.com/marco-looy.png?size=128', '2026-03-09T05:21:02.033334+00:00'),
  ('serper-search-and-scrape', 'Serper Search and Scrape', 'This MCP server implementation provides web search and webpage scraping capabilities using the Serper API. Developed by Marco Pesani, it offers tools for performing Google searches with rich results and extracting content from web pages. The server is built using TypeScript and integrates with the Model Context Protocol SDK. It focuses on flexible search options, including region and language targeting, and comprehensive content extraction that preserves document structure. This implementation is particularly useful for AI applications requiring up-to-date web information or content analysis, supporting use cases like research assistance, content aggregation, or data mining across various domains.', '@marcopesani', 'development', 'Unknown', 140, 'https://github.com/marcopesani/mcp-server-serper', 'serper-search-scrape-mcp-server', 103827, 'https://github.com/marcopesani.png?size=128', '2026-03-09T05:21:02.033365+00:00'),
  ('think', 'Think', 'A minimal MCP server that implements Anthropic''s ''think'' tool research, allowing AI assistants to use a dedicated thinking space for complex reasoning. The server provides a simple interface where thoughts are acknowledged with random encouragements, making it ideal for scenarios requiring step-by-step analysis or memory retention without performing external actions. Built with TypeScript and the MCP SDK, it''s containerized for easy deployment and designed to integrate with MCP-compatible clients like Cursor.', '@marcopesani', 'development', 'Unknown', 23, 'https://github.com/marcopesani/think-mcp-server', 'think-mcp-server', 24690, 'https://github.com/marcopesani.png?size=128', '2026-03-09T05:21:02.033393+00:00'),
  ('caiyun-weather', 'Caiyun Weather', 'Caiyun Weather MCP Server provides real-time weather data from the Caiyun Weather API, enabling AI assistants to access meteorological information based on geographic coordinates. The implementation uses TypeScript and the Model Context Protocol SDK to fetch weather forecasts, with geocoding capabilities to convert location names to coordinates. Built with a modular architecture separating weather data retrieval and geocoding services, it handles API authentication and response formatting while maintaining a clean separation of concerns. This server is particularly useful for applications requiring accurate weather forecasts for travel planning, outdoor activities, or location-based services.', '@marcusbai', 'development', 'Unknown', 9, 'https://github.com/marcusbai/caiyun-weather-mcp', 'caiyun-weather-mcp', 24, 'https://github.com/marcusbai.png?size=128', '2026-03-09T05:21:02.033423+00:00'),
  ('amazon-order-history', 'Amazon Order History', 'An MCP server that extracts Amazon order history data across 16 regional sites and exports it to CSV format using Playwright browser automation. The implementation provides four export types: orders summary, item details, shipment tracking with carrier information, and payment transactions, plus gift card balance tracking. Features intelligent date parsing for multiple regions, progress notifications for large datasets, and time estimation to help users batch exports within client timeout limits. Includes a plugin architecture designed for extensibility to other e-commerce platforms, comprehensive extraction strategies that handle Amazon''s evolving DOM structure, and specialized tools for bulk transaction extraction from Amazon''s dedicated payments page.', '@marcusquinn', 'ai-ml', 'Unknown', 3, 'https://github.com/marcusquinn/amazon-order-history-csv-download-mcp', NULL, 0, 'https://github.com/marcusquinn.png?size=128', '2026-03-09T05:21:02.033475+00:00'),
  ('quickfile', 'QuickFile', 'Integrates with QuickFile UK accounting software, enabling comprehensive financial management for UK businesses. Provides tools for managing clients, invoices, estimates, purchase invoices, suppliers, bank accounts and transactions. Generates financial reports including profit and loss statements, balance sheets, VAT obligations, and ageing reports. Uses MD5-based authentication as required by QuickFile''s API specification, features structured error handling and logging, and includes extensive test coverage with Docker support for integration testing. Covers the full spectrum of UK accounting workflows from client onboarding through financial reporting.', '@marcusquinn', 'cloud', 'Unknown', 3, 'https://github.com/marcusquinn/quickfile-mcp', NULL, 0, 'https://github.com/marcusquinn.png?size=128', '2026-03-09T05:21:02.033499+00:00'),
  ('qwen3-toolkit', 'Qwen3 Toolkit', 'MCP server implementation designed for LM Studio integration, providing an extensive toolkit for autonomous coding tasks. Offers 80+ tools spanning file operations (read, write, edit, delete), command execution, git version control, web utilities (search, image download, URL fetching), and memory systems (notes, scratchpads, task lists). Includes specialized support for Jupyter notebooks, ComfyUI workflows (32 dedicated tools), Jekyll blog creation, and media handling. Features a skills system with 16 pre-installed instruction packages for React, Python, security analysis, and design patterns.', '@marduk191', 'development', 'Unknown', 3, 'https://github.com/marduk191/qwen3_mcp', NULL, 0, 'https://github.com/marduk191.png?size=128', '2026-03-09T05:21:02.033523+00:00'),
  ('mariadb-cloud-hybrid-rag-search', 'MariaDB Cloud Hybrid RAG Search', 'This MariaDB Cloud hybrid search implementation combines semantic vector search capabilities with real-time web search augmentation through a Brave Search MCP server. The system uses MariaDB''s native vector search with cosine distance, generating embeddings via SentenceTransformer''s all-MiniLM-L6-v2 model, while simultaneously querying external web results through a FastMCP-powered Brave API integration. This architecture keeps vector data directly in the database, making it ideal for RAG workflows that need both internal knowledge retrieval and real-time external information augmentation.', '@mariadb-roelvandepaar', 'databases', 'Unknown', 4, 'https://github.com/mariadb-roelvandepaar/mariadb-cloud-hybrid-rag-search', NULL, 0, 'https://github.com/mariadb-roelvandepaar.png?size=128', '2026-03-09T05:21:02.033536+00:00'),
  ('decision-os', 'Decision OS', 'Decision OS tracks decisions and extracts learnings from engineering work. It captures unexpected moments during development as pressure events and converts them into reusable knowledge through a structured learning pipeline. Supports hierarchical scoping with global and project-specific foundations, active case persistence across restarts, and zero-regret forgetting to keep the knowledge base lean.', '@marianstefi20', 'development', 'Unknown', 0, 'https://github.com/marianstefi20/decision-os-mcp', NULL, 0, 'https://github.com/marianstefi20.png?size=128', '2026-03-09T05:21:02.033560+00:00'),
  ('sap-abap-adt', 'SAP ABAP ADT', 'This MCP server, developed by mario-andreschak, enables large language models to interact with SAP ABAP systems using the ABAP Development Tools (ADT) interface. Built with TypeScript and leveraging the Model Context Protocol SDK, it provides a bridge between AI models and SAP''s ABAP environment. The implementation focuses on simplifying access to ABAP development capabilities through a standardized MCP interface, abstracting away the complexities of direct ADT API interactions. It''s particularly useful for developers and AI models looking to incorporate ABAP development workflows into their applications, enabling use cases like code generation, system analysis, and automated ABAP interactions without requiring deep SAP-specific knowledge.', '@mario-andreschak', 'development', 'Unknown', 89, 'https://github.com/mario-andreschak/mcp-abap-adt', NULL, 0, 'https://github.com/mario-andreschak.png?size=128', '2026-03-09T05:21:02.033587+00:00'),
  ('sap-abap-development-tools', 'SAP ABAP Development Tools', 'This MCP server, developed by mario-andreschak, integrates the ABAP Development Tools (ADT) API with the Model Context Protocol. Built with TypeScript and leveraging the abap-adt-api library, it provides a bridge between AI agents and ABAP systems. The implementation offers tools for ABAP object management, transport handling, and code analysis. It''s particularly useful for developers and teams working with SAP systems, enabling use cases such as automated code reviews, intelligent transport management, and AI-assisted ABAP development without directly interacting with the complexities of the ADT API.', '@mario-andreschak', 'development', 'Unknown', 92, 'https://github.com/mario-andreschak/mcp-abap-abap-adt-api', NULL, 0, 'https://github.com/mario-andreschak.png?size=128', '2026-03-09T05:21:02.033615+00:00'),
  ('gameboy-emulator', 'GameBoy Emulator', 'MCP GameBoy Server enables AI assistants to interact with a GameBoy emulator through a set of tools for controlling the emulator, loading ROMs, and capturing screen output. Built with TypeScript and the serverboy emulation library, it supports both stdio and SSE transports, allowing integration with various MCP clients like FLUJO. The server provides button controls (up, down, left, right, A, B, start, select), ROM management capabilities, and returns the current screen as an image after each action, making it ideal for AI agents that need to play and analyze GameBoy games through natural language commands.', '@mario-andreschak', 'development', 'Unknown', 22, 'https://github.com/mario-andreschak/mcp-gameboy', NULL, 0, 'https://github.com/mario-andreschak.png?size=128', '2026-03-09T05:21:02.033644+00:00'),
  ('gemini-media-analysis', 'Gemini Media Analysis', 'MCP Video Recognition Server provides tools for image, audio, and video analysis using Google''s Gemini AI. Built with TypeScript and the MCP SDK, it offers three main tools: image recognition for describing visual content, audio recognition for transcription and analysis, and video recognition for understanding video content. The server supports both stdio and SSE transport methods, includes file caching to improve performance, and handles the complexities of waiting for video processing to complete. It''s particularly useful for applications requiring media content analysis, automated descriptions, or accessibility features without requiring direct integration with Google''s APIs.', '@mario-andreschak', 'development', 'Unknown', 10, 'https://github.com/mario-andreschak/mcp_video_recognition', NULL, 0, 'https://github.com/mario-andreschak.png?size=128', '2026-03-09T05:21:02.033677+00:00'),
  ('veo2-video-generation', 'Veo2 Video Generation', 'MCP Video Generation with Veo2 exposes Google''s Veo2 video generation capabilities through a TypeScript server implementation. Developed by mario-andreschak, it enables AI assistants to generate videos from text prompts or images, with support for various configuration options like aspect ratio, duration, and prompt enhancement. The server provides tools for video generation, image creation, and resource management, while supporting both stdio and SSE transports for flexible integration. Generated content is stored locally with metadata and can be accessed through MCP resources, making it valuable for creating visual content from textual descriptions or enhancing existing images with motion.', '@mario-andreschak', 'development', 'Unknown', 33, 'https://github.com/mario-andreschak/mcp-veo2', NULL, 0, 'https://github.com/mario-andreschak.png?size=128', '2026-03-09T05:21:02.033707+00:00'),
  ('word-interop', 'Word Interop', 'A Windows-specific MCP server that provides programmatic interaction with Microsoft Word through COM Interop, exposing a comprehensive set of tools for document manipulation. Built with TypeScript and the Winax library, it enables developers to perform complex Word operations like text editing, formatting, table management, image insertion, and page setup through a standardized protocol. Ideal for automating document generation, report creation, and batch processing tasks in enterprise or productivity workflows.', '@mario-andreschak', 'development', 'Unknown', 15, 'https://github.com/mario-andreschak/mcp-msoffice-interop-word', NULL, 0, 'https://github.com/mario-andreschak.png?size=128', '2026-03-09T05:21:02.033769+00:00'),
  ('local-logs', 'Local Logs', 'This local logs monitoring MCP server by mariosss provides real-time log file access and analysis for development and production environments through six specialized tools including log tailing, error tracking, file listing, server status analysis, log watching, and text search capabilities. Built with Node.js and featuring automatic log directory detection across multiple project structures (monorepos, backend folders, system logs), it offers cross-platform support with memory-efficient streaming for large files, configurable log extensions via environment variables, and read-only access for security. The implementation uses JSON-RPC 2.0 over stdio communication and includes fallback mechanisms for both Unix tail commands and pure JavaScript file reading, making it valuable for developers debugging applications, DevOps teams monitoring server health, and AI assistants that need to analyze log patterns and troubleshoot issues across different deployment environments.', '@mariosss', 'development', 'Unknown', 3, 'https://github.com/mariosss/local-logs-mcp-server', NULL, 0, 'https://github.com/mariosss.png?size=128', '2026-03-09T05:21:02.033804+00:00'),
  ('imessage', 'iMessage', 'This iMessage MCP server, developed as an open-source project, enables AI assistants to interact with Apple''s iMessage and Contacts services. Built with TypeScript and leveraging the @modelcontextprotocol/sdk, it provides a standardized interface for messaging and contact management operations. The server abstracts the complexities of interacting with Apple''s proprietary systems, allowing AI systems to seamlessly incorporate iMessage functionality into their workflows. It''s particularly useful for personal productivity assistants, automated customer service applications, and AI developers looking to integrate iMessage capabilities, enabling use cases like automated message handling, contact management, and personalized communication workflows on Apple platforms.', '@marissamarym', 'development', 'Unknown', 25, 'https://github.com/marissamarym/imessage-mcp-server', NULL, 0, 'https://github.com/marissamarym.png?size=128', '2026-03-09T05:21:02.033836+00:00'),
  ('nuclei', 'Nuclei', 'Nuclei MCP Server provides a secure and efficient interface for integrating ProjectDiscovery''s Nuclei vulnerability scanner with large language models. Developed by Mark3 Labs, this implementation offers multiple scanning tools with configurable options for template filtering, severity levels, and protocol selection. The server features thread-safe concurrent scanning operations, result caching with configurable expiry to improve performance, and comprehensive vulnerability reporting through both structured tool responses and queryable resources. Ideal for security workflows that need to automate vulnerability scanning through AI-driven analysis and remediation.', '@addcontent', 'productivity', 'Unknown', 40, 'https://github.com/addcontent/nuclei-mcp', NULL, 0, 'https://github.com/addcontent.png?size=128', '2026-03-09T05:21:02.033999+00:00'),
  ('phalcon-blocksec-transaction-analysis', 'Phalcon (BlockSec Transaction Analysis)', 'Phalcon MCP is a Go-based server that integrates with BlockSec''s blockchain transaction analysis platform, providing AI assistants with tools to analyze on-chain transactions across multiple blockchains. Developed by Mark3Labs, it offers seven specialized tools including transaction tracing, profiling, address labeling, balance and state change analysis, and chain ID lookups. The server handles authentication with BlockSec''s platform transparently, formats responses as prettified JSON, and implements parallel processing for comprehensive transaction overviews, making it particularly valuable for blockchain developers, analysts, and users who need detailed insights into cryptocurrency transactions beyond basic block explorer data.', '@mark3labs', 'ai-ml', 'Unknown', 9, 'https://github.com/mark3labs/phalcon-mcp', NULL, 0, 'https://github.com/mark3labs.png?size=128', '2026-03-09T05:21:02.034053+00:00'),
  ('members-1st', 'Members 1st', 'Minimal TypeScript-based server that provides financial account data tools with support for both in-memory mock data and Members 1st credit union API integration. The implementation features automatic date range chunking for large transaction queries (over 180 days), comprehensive caching, and a clean abstraction layer that can switch between test data and live banking APIs. Three core tools enable account listing, detailed account information retrieval, and transaction history queries with optional date filtering.', '@markcoleman', 'development', 'Unknown', 2, 'https://github.com/markcoleman/m1-mcp', NULL, 0, 'https://github.com/markcoleman.png?size=128', '2026-03-09T05:21:02.034078+00:00'),
  ('opcon', 'OpCon', 'Integrates with SMA Technologies'' OpCon workload automation platform with 257 auto-generated tools for job scheduling and monitoring', '@markcoleman', 'aggregators', 'Unknown', 1, 'https://github.com/markcoleman/opyconymcpy', NULL, 0, 'https://github.com/markcoleman.png?size=128', '2026-03-09T05:21:02.034110+00:00'),
  ('markdown-mindmap', 'Markdown Mindmap', 'Mindmap-MCP-Server provides a bridge between Markdown content and interactive mind maps using the markmap-cli tool. Built by YuChenSSR, this server exposes a single tool that converts Markdown text into HTML-based mind maps, with options to return either the complete HTML content or just the file path to the generated visualization. The implementation handles temporary file creation, subprocess management for the markmap-cli tool, and proper error handling. It''s particularly useful for workflows that involve visualizing structured content, organizing thoughts, or creating interactive knowledge maps directly within Claude conversations.', '@yuchenssr', 'ai-ml', 'Unknown', 220, 'https://github.com/yuchenssr/mindmap-mcp-server', 'mindmap-mcp-server', 11748, 'https://github.com/yuchenssr.png?size=128', '2026-03-09T05:21:02.034154+00:00'),
  ('io-github-yotsuda-markdown-pointer', 'io.github.yotsuda/markdown-pointer', 'Markdown viewer for AI-assisted document review. Click any element to copy file path + line number.', '@yotsuda', 'development', 'Unknown', 0, 'https://github.com/yotsuda/markdownpointer', NULL, 0, 'https://github.com/yotsuda.png?size=128', '2026-03-09T05:21:02.034169+00:00'),
  ('markdown-to-html', 'Markdown to HTML', 'A Model Context Protocol server that converts Markdown content to HTML with syntax highlighting. Built with TypeScript and leveraging libraries like marked, highlight.js, and DOMPurify, this implementation provides a clean, secure way to render Markdown as styled HTML. The server exposes a single tool, ''markdown_to_html'', which takes Markdown content as input and returns sanitized HTML output. It''s designed for easy integration with Claude Desktop and includes debugging support through the MCP Inspector. This server is particularly useful for applications that need to display formatted content from Markdown sources while ensuring proper syntax highlighting and security through sanitization.', '@fashionzzz', 'development', 'Unknown', 3, 'https://github.com/fashionzzz/markdown-to-html', NULL, 0, 'https://github.com/fashionzzz.png?size=128', '2026-03-09T05:21:02.034201+00:00'),
  ('amazon-ads-marketplaceadpros', 'Amazon Ads (MarketplaceAdPros)', 'This MCP server acts as a proxy bridge to MarketplaceAdPros'' Amazon Advertising platform, enabling AI assistants to access Amazon Ads data including Sponsored Products, Sponsored Brands, and Sponsored Display campaigns, ad groups, keywords, and targeting information. Developed by MarketplaceAdPros, it connects to their hosted service via StreamableHTTP transport and requires a bearer token for authentication, providing both tools for querying advertising resources and generating plain English reports. The implementation offers flexibility through multiple deployment options including npx installation, local builds, or direct connection to their hosted MCP endpoint, making it valuable for Amazon sellers and advertisers who need AI-powered analysis of their advertising performance and recommendations.', '@marketplaceadpros', 'development', 'Unknown', 21, 'https://github.com/marketplaceadpros/amazon-ads-mcp-server', '@marketplaceadpros/amazon-ads-mcp-server', 380, 'https://github.com/marketplaceadpros.png?size=128', '2026-03-09T05:21:02.034263+00:00'),
  ('freeagent', 'FreeAgent', 'This MCP server implementation provides a bridge to the FreeAgent API, enabling management of timeslips and timers for time tracking. Developed by Mark Pitt, it offers tools for listing, creating, updating, and deleting timeslips, as well as starting and stopping timers. The server includes features like automatic OAuth token refresh and comprehensive error handling. It''s designed for use cases requiring AI assistants to interact with FreeAgent accounts for time management and project tracking.', '@markpitt', 'productivity', 'Unknown', 3, 'https://github.com/markpitt/freeagent-mcp', NULL, 0, 'https://github.com/markpitt.png?size=128', '2026-03-09T05:21:02.034380+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('alko', 'Alko', 'Provides access to Finland''s Alko alcohol monopoly catalog featuring products and stores. Combines Alko''s public price list data with real-time web scraping to deliver product search, store availability, opening hours, and Vivino wine ratings. Useful for wine recommendations, store locating, inventory checking, and food pairing suggestions within the Finnish alcohol retail ecosystem.', '@markusl', 'ai-ml', 'Unknown', 12, 'https://github.com/markusl/alko-mcp', NULL, 0, 'https://github.com/markusl.png?size=128', '2026-03-09T05:21:02.034414+00:00'),
  ('gmail-google-calendar', 'Gmail & Google Calendar', 'MCP-GSuite integrates Gmail and Google Calendar APIs into AI assistants, allowing users to access and manage their email and calendar data. Built by Markus Pfundstein, this Python-based implementation authenticates through OAuth2, providing tools to read emails, manage drafts, search messages, create events, and interact with calendar entries. The server requires configuration files for authentication (.gauth.json) and account management (.accounts.json), and can be deployed via Docker or run locally. It''s particularly valuable for workflows requiring email management or scheduling capabilities without leaving the conversation interface.', '@albert-launcher', 'cloud', 'Unknown', 3, 'https://github.com/albert-launcher/mcp-gsuite', NULL, 0, 'https://github.com/albert-launcher.png?size=128', '2026-03-09T05:21:02.034437+00:00'),
  ('lambda-layer', 'Lambda Layer', 'A lightweight AWS Lambda layer for Model Context Protocol (MCP) server infrastructure, specifically designed to support Server-Sent Events (SSE) through Lambda response streaming. Built with TypeScript and the MCP SDK, this implementation provides a flexible handler factory that simplifies creating Lambda functions with streaming capabilities, focusing on ease of tool and prompt configuration while handling complex transport and protocol details.', '@markvp', 'cloud', 'Unknown', 12, 'https://github.com/markvp/mcp-lambda-sam', '@markvp/mcp-lambda-layer', 1243, 'https://github.com/markvp.png?size=128', '2026-03-09T05:21:02.034521+00:00'),
  ('teamspeak', 'TeamSpeak', 'This MCP server provides comprehensive TeamSpeak server administration by enabling AI assistants to control TeamSpeak servers through the ServerQuery protocol. Built by MarlBurroW using Python with the ts3 library, it offers 40+ tools covering user management (messaging, moving, kicking, banning clients), channel operations (creation, deletion, permission management), server configuration (settings, groups, privilege tokens), moderation features (ban rules, complaints, logs), and file management capabilities. The implementation supports both username/password authentication and admin privilege keys, includes Docker deployment options, and features automatic connection handling with fallback authentication methods, making it valuable for server administrators who want AI assistance in managing TeamSpeak communities, automating moderation tasks, and maintaining server configurations without manual intervention.', '@marlburrow', 'cloud', 'Unknown', 8, 'https://github.com/marlburrow/teamspeak-mcp', 'teamspeak-mcp', 13290, 'https://github.com/marlburrow.png?size=128', '2026-03-09T05:21:02.034551+00:00'),
  ('atomic-crm', 'Atomic CRM', 'Provides secure access to Atomic CRM data through OAuth 2.1 authentication with Supabase. Enables querying of customer relationship management data including contacts, companies, deals, tasks, and sales pipeline information. Implements Row Level Security enforcement through PostgreSQL session variables, ensuring users can only access data they have permission to view. Features dynamic schema discovery and supports complex SQL queries with JOINs and aggregations for sales analytics and CRM reporting workflows.', '@marmelab', 'databases', 'Unknown', 3, 'https://github.com/marmelab/atomic-crm-mcp', NULL, 0, 'https://github.com/marmelab.png?size=128', '2026-03-09T05:21:02.034563+00:00'),
  ('personal-expense-tracker', 'Personal Expense Tracker', 'A personal expense tracking MCP server that provides tools for managing financial transactions with categorized expense tracking. Built with FastMCP and SQLite, it offers comprehensive expense management including adding expenses with predefined categories (food, transport, housing, utilities, health, etc.), retrieving expense records with filtering capabilities, and generating expense summaries by category or date range. The server uses a structured JSON configuration for expense categories covering everything from daily necessities to business expenses, making it suitable for personal budgeting, expense reporting, and financial analysis workflows.', '@maroofgadiwale', 'databases', 'Unknown', 1, 'https://github.com/maroofgadiwale/own-mcp-server', NULL, 0, 'https://github.com/maroofgadiwale.png?size=128', '2026-03-09T05:21:02.034575+00:00'),
  ('refactoring', 'Refactoring', 'Provides access to Martin Fowler''s comprehensive refactoring catalog through a pluggable, language-agnostic architecture. Includes 71+ refactoring patterns organized into categories like composing methods, moving features, organizing data, simplifying conditionals, and dealing with generalization. Features preview mode for safe code analysis and token-efficient TOON output format. Currently supports Python with planned support for Ruby, Java, and Go.', '@marshally', 'development', 'Unknown', 3, 'https://github.com/marshally/mcp-refactoring', NULL, 0, 'https://github.com/marshally.png?size=128', '2026-03-09T05:21:02.034598+00:00'),
  ('listenhub', 'ListenHub', 'Official MCP server for ListenHub enabling creation of podcasts and FlowSpeech episodes through natural conversation. Provides speaker management with intelligent name resolution, full podcast generation with multiple modes (quick, deep, debate), two-stage generation allowing script review and modification, FlowSpeech creation for converting text and URLs to speech, and user subscription management. Features automatic polling, speaker caching, and support for single and dual-speaker formats.', '@marswaveai', 'aggregators', 'Unknown', 15, 'https://github.com/marswaveai/listenhub-mcp-server', NULL, 0, 'https://github.com/marswaveai.png?size=128', '2026-03-09T05:21:02.034671+00:00'),
  ('ultimate-64', 'Ultimate 64', 'Controls real Commodore 64 hardware through the Ultimate 64/II+ REST API, bridging modern workflows with vintage computing hardware. Provides 37 specialized tools for operations like uploading and executing PRG files, mounting D64 disk images, reading/writing C64 memory addresses, controlling virtual disk drives, and streaming video/audio from Ultimate 64 devices. Supports both local STDIO mode for desktop clients and optional self-hosted deployment via Server-Sent Events, making it valuable for retro computing enthusiasts, game developers, and educators who want to automate C64 operations or create interactive vintage computing experiences.', '@martijn-devrev', 'file-systems', 'Unknown', 18, 'https://github.com/martijn-devrev/ultimate64mcp', NULL, 0, 'https://github.com/martijn-devrev.png?size=128', '2026-03-09T05:21:02.034730+00:00'),
  ('clipboard-to-supabase', 'Clipboard to Supabase', 'Clipboard to Supabase MCP Helper is a cross-platform local agent that monitors the system clipboard for images, automatically uploads them to Supabase Storage, and writes the public URL back to the clipboard. Built with Node.js, it supports macOS, Windows, and Linux through platform-specific clipboard access methods, and exposes MCP endpoints for AI assistants to trigger image uploads and manage file retention. The implementation features efficient change detection through hash-based deduplication, automatic cleanup of older files, and can be configured to run at system startup, making it particularly valuable for users who frequently need to share screenshots or images without manual upload steps.', '@martinbowling', 'databases', 'Unknown', 2, 'https://github.com/martinbowling/clipboard-to-supabase-mcp-helper', NULL, 0, 'https://github.com/martinbowling.png?size=128', '2026-03-09T05:21:02.034748+00:00'),
  ('thoughtful-claude-deepseek-r1', 'Thoughtful Claude (DeepSeek R1)', 'This FastMCP server implementation integrates DeepSeek''s R1 reasoning engine with Claude, enabling advanced reasoning capabilities in MCP-compatible applications. Developed using Python and the FastMCP framework, it leverages DeepSeek''s API to process queries and return formatted reasoning outputs. The server focuses on enhancing Claude''s thought process by incorporating DeepSeek''s large-scale reinforcement learning-based reasoning. It''s particularly useful for developers and researchers looking to augment AI assistants with external reasoning capabilities, enabling more complex problem-solving, analysis, and decision-making tasks without requiring direct interaction with DeepSeek''s API.', '@martinbowling', 'productivity', 'Unknown', 56, 'https://github.com/martinbowling/thoughtful-claude', NULL, 0, 'https://github.com/martinbowling.png?size=128', '2026-03-09T05:21:02.034795+00:00'),
  ('jooq', 'jOOQ', 'Provides AI-powered access to jOOQ''s Java database library documentation, including full-text search, SQL examples, code generation guides, database dialect support, Query DSL references, and advanced features like transactions and batch operations. Built by jOOQ expert Simon Martinelli to help developers get AI-assisted guidance when working with type-safe SQL in Java.', '@martinellich', 'databases', 'Unknown', 3, 'https://github.com/martinellich/jooq-mcp', NULL, 0, 'https://github.com/martinellich.png?size=128', '2026-03-09T05:21:02.034804+00:00'),
  ('researchtwin', 'ResearchTwin', 'Federated research discovery with S-Index metrics across a network of digital twins.', '@martinfrasch', 'development', 'Unknown', 1, 'https://github.com/martinfrasch/researchtwin', NULL, 0, 'https://github.com/martinfrasch.png?size=128', '2026-03-09T05:21:02.034818+00:00'),
  ('spring-io', 'Spring IO', 'This Spring AI MCP server, developed by an unnamed author, provides access to Spring project release information and support generations via the https://api.spring.io API. Built using Spring Boot and leveraging the Spring AI MCP library, it offers tools for querying release versions and support timelines for Spring projects. The implementation focuses on simplifying access to Spring ecosystem data through a standardized MCP interface. It''s particularly useful for developers and teams working with Spring technologies who need up-to-date information on project versions and support status, enabling use cases like dependency management, upgrade planning, and support lifecycle tracking without directly interacting with the Spring API.', '@martinlippert', 'productivity', 'Unknown', 8, 'https://github.com/martinlippert/spring-io-api-mcp', NULL, 0, 'https://github.com/martinlippert.png?size=128', '2026-03-09T05:21:02.034873+00:00'),
  ('better-mcp-file-server', 'Better MCP File Server', 'The original MCP file server was functional but not optimized for how LLMs actually interact with filesystems. This project delivers a complete redesign focused on simplicity, privacy, and efficiency.', '@martinschlott', 'productivity', 'Unknown', 1, 'https://github.com/martinschlott/bettermcpfileserver', NULL, 0, 'https://github.com/martinschlott.png?size=128', '2026-03-09T05:21:02.034901+00:00'),
  ('oh-my-kegg', 'Oh My KEGG', 'Provides comprehensive access to the KEGG (Kyoto Encyclopedia of Genes and Genomes) database through a FastMCP server implementation with streamable HTTP transport. Offers specialized tools for searching and retrieving detailed information across all major KEGG databases including pathways, genes, compounds, reactions, enzymes, diseases, drugs, modules, and orthology groups. Features advanced analysis capabilities like cross-organism ortholog finding, drug-drug interaction checking, batch processing, and identifier conversion between KEGG and external databases. Designed for bioinformatics workflows, metabolic pathway analysis, drug discovery research, and systems biology applications.', '@martinuslee', 'databases', 'Unknown', 7, 'https://github.com/martinuslee/oh-my-kegg-mcp', NULL, 0, 'https://github.com/martinuslee.png?size=128', '2026-03-09T05:21:02.034913+00:00'),
  ('postgres-connector', 'Postgres Connector', 'This PostgreSQL connector MCP server by Marty Markenson provides direct database querying capabilities for PostgreSQL databases through secure SQL execution and schema inspection tools. Built with TypeScript using the MCP SDK and postgres library, it offers tools for retrieving table listings, executing SELECT queries with security restrictions, and setting up database connections through environment configuration. The implementation includes comprehensive connection management with dotenv support, Zod validation for type safety, and a manifest-based configuration system that allows users to specify database credentials through user config parameters, making it valuable for data analysts querying company databases, developers building database-driven AI applications, and teams needing secure PostgreSQL integration in their AI workflows.', '@martymarkenson', 'databases', 'Unknown', 9, 'https://github.com/martymarkenson/postgres-connector-mcp', 'postgres-connector', 459, 'https://github.com/martymarkenson.png?size=128', '2026-03-09T05:21:02.034927+00:00'),
  ('swagger-openapi', 'Swagger/OpenAPI', 'Bridges AI agents with REST APIs by parsing Swagger/OpenAPI specifications and dynamically generating callable tools. Fetches API documentation from configurable endpoints, analyzes available operations, and exposes them as tools that can invoke HTTP requests. Supports multiple API configurations simultaneously, handles various authentication methods including Bearer tokens, Basic Auth, and API keys, and provides hierarchical API browsing with keyword search capabilities. Includes Docker support for deployment.', '@mary-code217', 'cloud', 'Unknown', 2, 'https://github.com/mary-code217/swagger-mcp', NULL, 0, 'https://github.com/mary-code217.png?size=128', '2026-03-09T05:21:02.034949+00:00'),
  ('logstash', 'Logstash', 'This Logstash MCP server provides direct API integration with Logstash instances for monitoring and performance analysis, featuring 12 specialized tools including connectivity verification, JVM memory analysis, pipeline statistics, hot threads debugging, and queue backpressure monitoring. Built with Python using aiohttp and Flask, it includes both a command-line MCP interface and a web UI for interactive dashboard access, making it valuable for DevOps teams managing ELK stack deployments who need real-time visibility into Logstash performance bottlenecks, pipeline health, and resource utilization through conversational interfaces.', '@mashhurs', 'development', 'Unknown', 1, 'https://github.com/mashhurs/logstash-mcp-server', NULL, 0, 'https://github.com/mashhurs.png?size=128', '2026-03-09T05:21:02.034978+00:00'),
  ('azure', 'Azure', 'This MCP server, developed by Shriram Madurantakam, provides a standardized interface for interacting with Azure services, specifically Azure Blob Storage and Azure Cosmos DB (NoSQL API). Built with Python and leveraging the Model Context Protocol, it offers tools for reading and manipulating Azure resources using an LLM. The implementation focuses on secure authentication and flexible configuration, supporting various Azure credential types. By connecting AI models with Azure cloud services, this server enables sophisticated data management scenarios, enhancing the ability to store, retrieve, and query data in Azure. It''s particularly useful for applications and AI assistants that require programmatic access to Azure resources through a familiar MCP interface, with built-in operation logging for auditing purposes.', '@mashriram', 'databases', 'Unknown', 5, 'https://github.com/mashriram/azure_mcp_server', NULL, 0, 'https://github.com/mashriram.png?size=128', '2026-03-09T05:21:02.034989+00:00'),
  ('source-map-parser', 'Source Map Parser', 'Source Map Parser MCP provides a specialized tool for debugging production JavaScript errors by mapping minified stack traces back to their original source code locations. Built by MasonChow, this server implementation leverages WebAssembly for efficient source map parsing and offers a simple interface to process error stack traces with line and column information. The implementation fetches source maps from provided URLs, parses them using the stack_parser_js_sdk, and returns the original source location along with contextual code lines, making it particularly valuable for developers troubleshooting errors in production environments where code is minified or transpiled.', '@masonchow', 'development', 'Unknown', 2, 'https://github.com/masonchow/source-map-parser-mcp', 'source-map-parser-mcp', 5275, 'https://github.com/masonchow.png?size=128', '2026-03-09T05:21:02.035014+00:00'),
  ('gohighlevel', 'GoHighLevel', 'This MCP server provides complete GoHighLevel CRM integration, enabling AI assistants to manage contacts, conversations, blog posts, calendars, workflows, and other business automation features through the GoHighLevel API. Built by mastanley13 using TypeScript with the MCP SDK and comprehensive API client implementation, it offers contact management with search, creation, and tag operations, messaging capabilities including SMS and email sending, blog content management with post creation and category handling, calendar and appointment scheduling, workflow automation access, and media library management. The implementation includes both HTTP and stdio transport support, extensive tool coverage across 20+ GoHighLevel API endpoints, proper error handling with detailed API response parsing, and deployment configurations for multiple platforms including Vercel, Railway, and Docker, making it valuable for marketing agencies automating client communications, businesses integrating CRM workflows with AI assistants, and developers building custom GoHighLevel automation solutions.', '@mastanley13', 'cloud', 'Unknown', 121, 'https://github.com/mastanley13/gohighlevel-mcp', '@mastanley13/ghl-mcp-server', 282, 'https://github.com/mastanley13.png?size=128', '2026-03-09T05:21:02.035039+00:00'),
  ('xmind', 'XMind', 'Converts Markdown, text, HTML, Word, Excel, CSV, JSON, XML, and YAML files into XMind mind map format. Provides AI-powered analysis of mind map structure with quality metrics and topic suggestions. Supports both FastMCP and STDIO deployment modes via UVX for integration with AI tools and IDEs.', '@master-frank', 'ai-ml', 'Unknown', 13, 'https://github.com/master-frank/xmindmcp', NULL, 0, 'https://github.com/master-frank.png?size=128', '2026-03-09T05:21:02.035066+00:00'),
  ('mastergo-design', 'MasterGo Design', 'MasterGo Magic MCP is a standalone service that enables AI models to directly retrieve DSL (Domain Specific Language) data from MasterGo design files. Developed as a lightweight Node.js tool, it provides a simple mechanism for extracting design file metadata using a personal access token, with a focus on enabling programmatic access to design element details. The implementation is particularly useful for AI-powered design analysis, code generation, and design system exploration.', '@mastergo-design', 'development', 'Unknown', 215, 'https://github.com/mastergo-design/mastergo-magic-mcp', '@mastergo/magic-mcp', 51973, 'https://github.com/mastergo-design.png?size=128', '2026-03-09T05:21:02.035089+00:00'),
  ('discord-bot', 'Discord Bot', 'Discord MCP Server provides a bridge between Discord''s API and Mastra''s MCP Bot component, enabling intelligent assistance for users through slash commands and direct messages. This TypeScript implementation handles Discord interactions, manages bot commands, and routes user questions to the Mastra component for generating responses. It features thread creation for conversations, message chunking for long responses, and cooldown management to prevent spam. The server supports two main commands: ''/ask'' for querying about Mastra and ''/cleardm'' for clearing bot messages in direct messages, making it particularly useful for providing AI-powered support in Discord communities.', '@mastra-ai', 'development', 'Unknown', 2, 'https://github.com/mastra-ai/discord-mcp-server', NULL, 0, 'https://github.com/mastra-ai.png?size=128', '2026-03-09T05:21:02.035120+00:00'),
  ('mastra-docs', 'Mastra Docs', 'A Model Context Protocol (MCP) server that provides AI assistants with direct access to Mastra.ai''s complete knowledge base. This includes comprehensive documentation with MDX support, a collection of production-ready code examples, technical blog posts, and detailed package changelogs. The server integrates with popular AI development environments like Cursor and Windsurf, as well as Mastra agents, making it easy to build documentation-aware AI assistants that can provide accurate, up-to-date information about Mastra.ai''s ecosystem.', '@mastra-ai', 'development', 'Unknown', 21792, 'https://github.com/mastra-ai/mastra/tree/HEAD/packages/mcp-docs-server', '@mastra/mcp-docs-server', 371336, 'https://github.com/mastra-ai.png?size=128', '2026-03-09T05:21:02.035143+00:00'),
  ('autonavi-amap', 'AutoNavi (Amap)', 'Amap Maps MCP server provides integration with China''s AutoNavi (Amap) mapping service, offering comprehensive location-based functionality including geocoding, reverse geocoding, place search, weather data, and multi-modal route planning for driving, walking, cycling, and public transit. The implementation supports 12 distinct tools covering IP geolocation, POI search with detailed business information, distance calculations, and integrated weather forecasting, making it particularly valuable for applications targeting the Chinese market where Amap is the dominant mapping platform. Built as a containerized Node.js application with Express HTTP server support, it handles complex routing scenarios including cross-city public transit planning and provides structured JSON responses for seamless integration with AI assistants requiring location intelligence within China''s geographic and regulatory context.', '@masx200', 'ai-ml', 'Unknown', 2, 'https://github.com/masx200/amap-maps-mcp-server', NULL, 0, 'https://github.com/masx200.png?size=128', '2026-03-09T05:21:02.035206+00:00'),
  ('persistent-terminal', 'Persistent Terminal', 'A persistent terminal session manager that provides MCP tools for creating, managing, and interacting with long-running terminal processes using node-pty. Features include terminal creation with custom shells and working directories, real-time output reading with smart buffering and spinner detection for cleaner output, command execution, session persistence across connections, and a web UI for browser-based terminal access. The implementation includes REST API endpoints, WebSocket support for real-time updates, output compaction to reduce noise from progress indicators, and comprehensive session management with statistics tracking, making it useful for AI agents that need to execute long-running commands, maintain terminal state across interactions, or provide persistent development environments.', '@masx200', 'development', 'Unknown', 3, 'https://github.com/masx200/persistent-terminal-mcp', NULL, 0, 'https://github.com/masx200.png?size=128', '2026-03-09T05:21:02.035237+00:00'),
  ('safe-packages', 'Safe Packages', 'Analyzes npm and Cargo packages for security risks through typosquatting detection, version age analysis, security advisory scanning, install script inspection, and popularity-based scoring. Supports configurable allowlists, staleness detection, and audit logging for CI/CD pipelines and dependency auditing workflows.', '@math280h', 'security', 'Unknown', 6, 'https://github.com/math280h/safe-pkgs', NULL, 0, 'https://github.com/math280h.png?size=128', '2026-03-09T05:21:02.035369+00:00'),
  ('govee', 'Govee', 'This MCP server, developed by MoovAI, provides integration with Govee smart lighting devices. Built with Python and leveraging the Govee API, it enables AI agents to control Govee LED products through natural language commands. The implementation focuses on device management and state control, offering functionality to adjust brightness, color, and power settings. It''s particularly useful for home automation systems and AI assistants looking to incorporate smart lighting control, enabling use cases such as mood-based lighting adjustments, scheduled lighting changes, or voice-controlled ambiance without directly interacting with the Govee API.', '@mathd', 'ai-ml', 'Unknown', 5, 'https://github.com/mathd/govee_mcp_server', NULL, 0, 'https://github.com/mathd.png?size=128', '2026-03-09T05:21:02.035413+00:00'),
  ('matlab', 'MATLAB', 'The official MATLAB MCP server from MathWorks enables AI applications to interact with MATLAB through the Model Context Protocol. Built in Go and actively maintained by MathWorks engineers, it provides five core tools for starting and terminating MATLAB instances, executing and evaluating MATLAB code, performing static code analysis for style and correctness assessment, detecting installed toolboxes, and running test files. The implementation includes robust process management, configurable MATLAB paths, and comprehensive error handling, making it valuable for automated testing workflows, code quality assessment, scientific computing tasks, and AI-assisted MATLAB development where natural language commands can trigger MATLAB computations and analysis.', '@matlab', 'development', 'Unknown', 218, 'https://github.com/matlab/matlab-mcp-core-server', NULL, 0, 'https://github.com/matlab.png?size=128', '2026-03-09T05:21:02.035484+00:00'),
  ('garth-garmin-connect', 'Garth (Garmin Connect)', 'Garth MCP Server provides integration with Garmin Connect, allowing AI assistants to access fitness and health data through the garth library. Developed by Matin Tamizi under MIT license, it offers tools for retrieving sleep statistics, daily stress data, and intensity minutes with customizable date ranges. The server handles authentication via a token environment variable and formats responses for easy consumption by AI assistants. This implementation is particularly valuable for users who want to analyze their Garmin fitness data or incorporate health metrics into conversations with AI assistants without manually retrieving the information from Garmin Connect.', '@matin', 'ai-ml', 'Unknown', 57, 'https://github.com/matin/garth-mcp-server', 'garth-mcp-server', 12654, 'https://github.com/matin.png?size=128', '2026-03-09T05:21:02.035532+00:00'),
  ('watson-discovery', 'Watson Discovery', 'Watson Discovery MCP provides a bridge to IBM Watson Discovery service, enabling AI assistants to search and retrieve information from Watson Discovery projects and collections. The implementation offers three key tools: finding project IDs by name, listing collections within a project, and executing natural language queries against specific collections. Built with Python using the IBM Watson SDK and FastMCP, it handles authentication and asynchronous operations through environment variables, making it ideal for retrieving structured information from enterprise knowledge bases or documentation repositories without leaving the conversation interface.', '@matlock08', 'productivity', 'Unknown', 0, 'https://github.com/matlock08/watson_discovery_mcp', NULL, 0, 'https://github.com/matlock08.png?size=128', '2026-03-09T05:21:02.035581+00:00'),
  ('payload-cms', 'Payload CMS', 'Payload CMS MCP Server provides validation, query, and code generation services for Payload CMS 3.0 development. Built by MATMAX WORLDWIDE, it offers tools to validate collections, fields, and configurations, execute SQL-like queries against validation rules, generate code templates, and scaffold complete projects following best practices. The server integrates with Redis for persistence and exposes endpoints for real-time communication, making it particularly valuable for AI-assisted development environments like Cursor IDE where developers need immediate feedback on Payload CMS code quality and structure.', '@disruption-hub', 'databases', 'Unknown', 108, 'https://github.com/disruption-hub/payloadcmsmcp', 'payload-cms-mcp', 1624, 'https://github.com/disruption-hub.png?size=128', '2026-03-09T05:21:02.035593+00:00'),
  ('maton', 'Maton', 'A TypeScript implementation of the Model Context Protocol (MCP) for the Maton Agent Toolkit, enabling agents to interact with external services and data sources.', '@maton-ai', 'development', 'Unknown', 36, 'https://github.com/maton-ai/agent-toolkit/tree/HEAD/modelcontextprotocol', NULL, 0, 'https://github.com/maton-ai.png?size=128', '2026-03-09T05:21:02.035611+00:00'),
  ('paperclip', 'Paperclip', 'This MCP server provides academic paper search and retrieval across multiple scholarly databases including ArXiv, OpenAlex, and Open Science Framework (OSF) preprint servers, built by Mats Julius Funke using Python with FastMCP and PyMuPDF for PDF processing. The implementation offers unified search capabilities across providers with advanced filtering by publication date, subjects, and authors, plus full-text PDF extraction that converts academic papers to clean markdown format suitable for AI analysis. Features include metadata-only retrieval for quick paper discovery, direct PDF URL processing, robust error handling with API query sanitization, and Docker deployment support, making it valuable for researchers, students, and AI assistants that need programmatic access to academic literature for literature reviews, research analysis, and knowledge synthesis workflows.', '@matsjfunke', 'databases', 'Unknown', 18, 'https://github.com/matsjfunke/paperclip', NULL, 0, 'https://github.com/matsjfunke.png?size=128', '2026-03-09T05:21:02.035623+00:00'),
  ('code-snippets-s3', 'Code Snippets (S3)', 'This Bun-based S3 MCP server, developed for Claude Desktop, provides a streamlined interface for managing code snippets in S3 storage. Leveraging Bun''s S3 bindings for fast API operations, it offers tools for creating, retrieving, and listing code snippets in various programming languages. The implementation focuses on efficient S3 interactions, robust error handling, and seamless integration with Claude Desktop, making it ideal for AI assistants to manage and access code snippets without dealing with S3 complexities directly. It''s particularly useful for tasks like code reference management, collaborative programming, or integrating code snippet functionality into AI-driven development workflows.', '@mattbarlow-sg', 'development', 'Unknown', 0, 'https://github.com/mattbarlow-sg/bun-s3-mcp', NULL, 0, 'https://github.com/mattbarlow-sg.png?size=128', '2026-03-09T05:21:02.035659+00:00'),
  ('zoom-api', 'Zoom API', 'A comprehensive MCP server for the Zoom API that enables AI assistants to interact with Zoom''s platform features including meetings, webinars, users, chat, recordings, and more. The implementation uses OAuth 2.0 authentication with Server-to-Server credentials and provides structured tools with proper validation using Zod. It handles API responses and errors consistently, making it easy for AI models to manage Zoom resources through natural language. Ideal for use cases like scheduling meetings, managing participants, retrieving recordings, and automating administrative tasks within Zoom.', '@mattcoatsworth', 'communication', 'Unknown', 5, 'https://github.com/mattcoatsworth/zoom-mcp-server', NULL, 0, 'https://github.com/mattcoatsworth.png?size=128', '2026-03-09T05:21:02.035727+00:00'),
  ('fathom', 'Fathom', 'Integrates with Fathom.video to provide access to AI meeting transcripts, summaries, and action items. Enables listing and searching meetings by participants, domains, or date ranges, retrieving full meeting details with formatted transcripts and AI-generated summaries, exporting meetings as markdown files to local directories, managing action items across meetings, and creating webhooks for real-time meeting notifications. Features automatic pagination handling, markdown formatting with speaker identification and timestamps, team and member management capabilities, and configurable output directories.', '@matthewbergvinson', 'ai-ml', 'Unknown', 2, 'https://github.com/matthewbergvinson/fathom-mcp', NULL, 0, 'https://github.com/matthewbergvinson.png?size=128', '2026-03-09T05:21:02.035782+00:00'),
  ('rime-text-to-speech', 'Rime Text-to-Speech', 'A text-to-speech server for the MCP ecosystem that integrates with Rime''s API to convert text into spoken audio. This implementation streams audio content with optimized buffering to reduce latency between text generation and speech playback. It provides a ''speak'' tool that can be configured through environment variables to control voice selection, speaking style, and playback behavior. Built with TypeScript and Node.js, it supports cross-platform audio playback through various media players and includes features for handling WebSocket connections and managing temporary audio files. Particularly useful for AI assistants that need to communicate verbally with users or for applications requiring audio narration of generated content.', '@matthewdailey', 'development', 'Unknown', 28, 'https://github.com/matthewdailey/rime-mcp', 'rime-mcp', 1023, 'https://github.com/matthewdailey.png?size=128', '2026-03-09T05:21:02.035844+00:00'),
  ('pbs-api', 'PBS API', 'PBS MCP Server provides access to the Australian Pharmaceutical Benefits Scheme (PBS) API through a standalone server that enables AI models to query pharmaceutical data including medicine listings, pricing, and availability. Developed by Matthew Cage, founder of AI-Advantage.au, this TypeScript implementation offers multiple interfaces including stdio, HTTP/SSE, and a command-line tool with comprehensive error handling for API rate limits. The server supports various PBS endpoints such as prescribers, item-overview, and schedules, making it particularly valuable for healthcare applications, medication research, and integrating up-to-date pharmaceutical information directly into AI workflows without requiring the data in the model''s training.', '@matthewdcage', 'development', 'Unknown', 3, 'https://github.com/matthewdcage/pbs-mcp-server', NULL, 0, 'https://github.com/matthewdcage.png?size=128', '2026-03-09T05:21:02.035917+00:00'),
  ('vapi-voice-ai', 'Vapi Voice AI', 'Vapi MCP for Cursor integrates Vapi''s voice AI capabilities with the Cursor editor through the Model Context Protocol, enabling AI assistants to make outbound calls, manage voice assistants, and retrieve conversation transcripts. The implementation consists of two server components: a core MCP server that handles direct communication with Cursor, and an HTTP server that provides RESTful API endpoints for broader integration with services like n8n. Built with TypeScript and leveraging the Vapi Server SDK, this implementation supports creating customizable voice assistants with different voices and models, initiating phone calls with AI-driven conversations, and analyzing call transcripts—making it particularly useful for automated customer outreach, sales calls, and support interactions.', '@matthewdcage', 'development', 'Unknown', 3, 'https://github.com/matthewdcage/vapi-mcp', NULL, 0, 'https://github.com/matthewdcage.png?size=128', '2026-03-09T05:21:02.035958+00:00'),
  ('consulting-agents', 'Consulting Agents', 'The ConsultingAgents MCP Server enables Claude Code to consult with additional AI agents for enhanced code and problem analysis. It provides access to two expert coding consultants: Darren (powered by OpenAI''s o3-mini model with high reasoning capabilities) and Sonny (powered by Anthropic''s Claude 3.7 Sonnet with enhanced thinking). The server supports multiple transport options including stdio for direct Claude Code integration and HTTP/SSE for broader applications. Built with Python using the FastMCP framework, it requires API keys for both OpenAI and Anthropic services, making it ideal for developers seeking multi-model perspectives on coding problems.', '@matthewpdingle', 'development', 'Unknown', 15, 'https://github.com/matthewpdingle/consulting-agents-mcp', NULL, 0, 'https://github.com/matthewpdingle.png?size=128', '2026-03-09T05:21:02.036079+00:00'),
  ('browserloop', 'BrowserLoop', 'This MCP server provides web screenshot capabilities using Playwright, enabling AI assistants to capture full-page screenshots, element-specific screenshots, and viewport screenshots of web pages with support for PNG, JPEG, and WebP formats. Built by Mattias Wallander with TypeScript and featuring comprehensive cookie authentication support, domain filtering for security, image format conversion with Sharp, and Docker containerization, it offers configurable quality settings, network idle waiting, timeout handling, and performance optimization through browser page pooling. The implementation includes robust error handling with categorized logging, memory cleanup for sensitive data, and NPX-friendly installation, making it valuable for web testing workflows, content verification, visual regression testing, and any use case requiring programmatic web page capture with authentication support.', '@mattiasw', 'cloud', 'Unknown', 22, 'https://github.com/mattiasw/browserloop', 'browserloop', 5126, 'https://github.com/mattiasw.png?size=128', '2026-03-09T05:21:02.036106+00:00'),
  ('senechal-health', 'Senechal Health', 'This MCP server implementation provides a bridge to the Senechal health data API, enabling AI assistants to access and analyze personal health information. Developed by Matt Joyce, it offers tools for retrieving health summaries, profiles, current measurements, trends, and statistics. The server is designed for use cases requiring AI-driven health analysis, such as personalized wellness recommendations or long-term health monitoring.', '@mattjoyce', 'ai-ml', 'Unknown', 0, 'https://github.com/mattjoyce/senechal-mcp', NULL, 0, 'https://github.com/mattjoyce.png?size=128', '2026-03-09T05:21:02.036146+00:00'),
  ('brightsy', 'Brightsy', 'This MCP server implementation provides a bridge to an OpenAI-compatible AI agent. Developed by Matt Levine, it allows for seamless integration of AI capabilities into applications through a standardized protocol. The server supports customizable tool names, environment variable configuration, and includes comprehensive testing scripts. It''s designed for use cases requiring AI-powered task automation, natural language processing, or interactive chat functionalities within larger systems or applications.', '@mattlevine', 'development', 'Unknown', 1, 'https://github.com/mattlevine/brightsy-mcp', NULL, 0, 'https://github.com/mattlevine.png?size=128', '2026-03-09T05:21:02.036175+00:00'),
  ('aqicn-air-quality', 'AQICN Air Quality', 'This MCP server, developed by mattmarcin, provides integration with the World Air Quality Index (AQICN) API for retrieving real-time air quality data. Built with Python and leveraging libraries like FastMCP and Pydantic, it offers tools for querying air quality information by city name or coordinates, as well as searching for monitoring stations. The implementation focuses on providing a standardized interface for accessing global air quality metrics, enabling AI assistants to incorporate up-to-date environmental data into their responses. It''s particularly useful for applications in environmental monitoring, public health, and urban planning, allowing for easy integration of air quality considerations into AI-driven decision-making processes without requiring direct interaction with the AQICN API.', '@mattmarcin', 'ai-ml', 'Unknown', 1, 'https://github.com/mattmarcin/aqicn-mcp', NULL, 0, 'https://github.com/mattmarcin.png?size=128', '2026-03-09T05:21:02.036224+00:00'),
  ('nuanced', 'Nuanced', 'This MCP server implementation provides code analysis capabilities using the nuanced library. It offers tools for initializing code graphs, exploring function call relationships, analyzing dependencies, and assessing the impact of code changes. The server is designed to help AI assistants understand code structure and provide contextually aware assistance for tasks like refactoring, debugging, and code review.', '@mattmorgis', 'development', 'Unknown', 17, 'https://github.com/mattmorgis/nuanced-mcp', NULL, 0, 'https://github.com/mattmorgis.png?size=128', '2026-03-09T05:21:02.036246+00:00'),
  ('standards', 'Standards', 'A self-learning AI standards system that automatically captures tool executions from Claude Code and extracts patterns to continuously improve CLAUDE.md files and project standards. Built by Matt Strautmann, the implementation uses significance scoring to identify valuable learning opportunities from tool usage, tracks agent performance over time, and maintains temporal knowledge graphs to understand how preferences evolve. The system provides intelligent hooks for automatic knowledge capture, pattern extraction for learning from corrections and repetitions, and validation engines that enforce quality gates while learning from failures, making it useful for development teams who want their AI assistants to automatically learn and adapt project-specific conventions without manual intervention.', '@airmcp-com', 'development', 'Unknown', 3, 'https://github.com/airmcp-com/mcp-standards', 'mcp-standards', 1049, 'https://github.com/airmcp-com.png?size=128', '2026-03-09T05:21:02.036276+00:00'),
  ('git-conflict-manager', 'Git Conflict Manager', 'Streamlines Git merge conflict resolution by providing structured tools for identifying conflicted files, reading conflict content, and marking conflicts as resolved without direct command-line interaction.', '@mattyatea', 'development', 'Unknown', 4, 'https://github.com/mattyatea/git-conflict-mcp', NULL, 0, 'https://github.com/mattyatea.png?size=128', '2026-03-09T05:21:02.036293+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('smartmemory', 'SmartMemory', 'SmartMemory transforms conversations into verified knowledge graphs, providing structured long-term memory and logical deduction capabilities. The system operates in conversational mode for individual users and supervision mode with a web dashboard for teams to extract rules from documents and visualize knowledge graphs.', '@mauriceisrael', 'search', 'Unknown', 3, 'https://github.com/mauriceisrael/smartmemory', NULL, 0, 'https://github.com/mauriceisrael.png?size=128', '2026-03-09T05:21:02.036330+00:00'),
  ('brasil-api-mcp-server', 'Brasil API MCP Server', 'Query a variety of data from Brasil resources seamlessly. Access information on postal codes, area codes, banks, holidays, taxes, and more through a unified interface. Enhance your AI agents and applications with rich and updated data from BrasilAPI effortlessly.', '@mauricio-cantu', 'development', 'Unknown', 6, 'https://github.com/mauricio-cantu/brasil-api-mcp-server', NULL, 0, 'https://github.com/mauricio-cantu.png?size=128', '2026-03-09T05:21:02.036350+00:00'),
  ('smartschool', 'Smartschool', 'Integrates with Smartschool, a widely-used educational management platform in Belgium and the Netherlands. Provides read-only access to student data including enrolled courses with teacher information, grades with optional statistics, upcoming assignments organized by date, and mailbox messages with search and filtering capabilities.', '@maurodruwel', 'ai-ml', 'Unknown', 0, 'https://github.com/maurodruwel/smartschool-mcp', NULL, 0, 'https://github.com/maurodruwel.png?size=128', '2026-03-09T05:21:02.036381+00:00'),
  ('glue-code-generator', 'Glue Code Generator', 'Automates frontend integration by mapping messy API JSON responses to Vue or React design system components. Features a two-stage system that analyzes API JSON and component code, then generates Zod validation schemas. Renders live UI previews directly in chat environments via mcp-ui, supporting integration with Roo Code, Cline, and Claude Desktop.', '@maverick7', 'development', 'Unknown', 0, 'https://github.com/maverick7/mcp-glue-code-generator', NULL, 0, 'https://github.com/maverick7.png?size=128', '2026-03-09T05:21:02.036404+00:00'),
  ('maxential-thinking', 'MAXential Thinking', 'Provides explicit tools for managing Claude''s reasoning process through sequential thought addition, parallel exploration branches, thought revision, and navigation through thought history. Enables structured problem-solving with branch creation, switching, merging, and detailed thought retrieval.', '@bam-devcrew', 'ai-ml', 'Unknown', 2, 'https://github.com/bam-devcrew/maxential-thinking-mcp', NULL, 0, 'https://github.com/bam-devcrew.png?size=128', '2026-03-09T05:21:02.036435+00:00'),
  ('macos-photos', 'macOS Photos', 'Provides read-only access to the macOS Photos library through Apple''s PhotoKit framework. Supports album listing, location-based search with geocoding, date range filtering, and keyword-based content classification using Vision ML. Includes image export capabilities for both thumbnails and full-resolution photos as base64-encoded JPEGs, with automatic cleanup of temporary files.', '@maximbilan', 'development', 'Unknown', 3, 'https://github.com/maximbilan/photos-macos-mcp', NULL, 0, 'https://github.com/maximbilan.png?size=128', '2026-03-09T05:21:02.036461+00:00'),
  ('moneywiz', 'MoneyWiz', 'Provides direct access to MoneyWiz personal finance data through SQLite database integration. Built in Go using the mcp-go library, it connects to exported MoneyWiz database backups and exposes tools for account management, transaction analysis, spending/income trend analysis, savings recommendations, and net worth calculations. The implementation handles Core Data timestamp conversions, calculates account balances from transaction history, and provides intelligent financial insights including category-based spending analysis and personalized savings recommendations based on income-to-expense ratios, making it valuable for users who want conversational access to their MoneyWiz financial data for budgeting, financial planning, and expense tracking workflows.', '@maximbilan', 'databases', 'Unknown', 5, 'https://github.com/maximbilan/moneywiz-mcp', NULL, 0, 'https://github.com/maximbilan.png?size=128', '2026-03-09T05:21:02.036472+00:00'),
  ('ibm-maximo', 'IBM Maximo', 'IBM Maximo integration for API discovery, OSLC querying, and UI generation.', '@markusvankempen', 'development', 'Unknown', 1, 'https://github.com/markusvankempen/maximo-mcp-ai-integration-options', NULL, 0, 'https://github.com/markusvankempen.png?size=128', '2026-03-09T05:21:02.036525+00:00'),
  ('safe-local-python-executor', 'Safe Local Python Executor', 'An MCP server (stdio transport) that wraps Hugging Face''s LocalPythonExecutor (from the smolagents framework). It is a custom Python runtime that provides basic isolation/security when running Python code generated by LLMs. This package allows to expose the Python executor via MCP (Model Context Protocol) as a tool for LLM apps like Claude Desktop, Cursor or any other MCP compatible client. In case of Claude Desktop this tool is an easy way to add alternative to ChatGPT''s Python Interpreter plugin.', '@maxim-saplin', 'cloud', 'Unknown', 44, 'https://github.com/maxim-saplin/mcp_safe_local_python_executor', NULL, 0, 'https://github.com/maxim-saplin.png?size=128', '2026-03-09T05:21:02.036547+00:00'),
  ('maximumsats', 'MaximumSats', 'Provides Bitcoin and Lightning Network AI tools alongside Nostr Web of Trust analysis, all accessible via pay-per-use Lightning L402 payments. Includes Bitcoin knowledge queries, image generation, trust scoring, Sybil detection, network analysis, and influence simulation. No accounts or subscriptions required -- invoke a tool, pay the Lightning invoice, and get results.', '@joelklabo', 'ai-ml', 'Unknown', 0, 'https://github.com/joelklabo/maximumsats-mcp', NULL, 0, 'https://github.com/joelklabo.png?size=128', '2026-03-09T05:21:02.036577+00:00'),
  ('dhan-trading', 'Dhan Trading', 'Dhan Trading MCP Server provides a bridge between AI assistants and the Dhan Trading API, enabling automated stock trading capabilities. Built by Mayank Thole, it offers tools for checking account balances, viewing holdings, placing various order types (market, limit, stop-loss), and implementing trading strategies like the ''Inside Value'' system that identifies potential entry points based on price patterns. The server handles authentication with the Dhan API, manages order execution with proper stop-loss and target settings, and includes comprehensive logging for trades and signals. It''s particularly valuable for traders who want to automate their strategies or interact with their trading account through natural language interfaces.', '@mayankthole', 'ai-ml', 'Unknown', 4, 'https://github.com/mayankthole/dhan-mcp-trades', NULL, 0, 'https://github.com/mayankthole.png?size=128', '2026-03-09T05:21:02.036674+00:00'),
  ('mindvalley-products', 'Mindvalley Products', 'Provides structured access to Mindvalley''s educational offerings through static data. Query products, masterclasses, programs, and certifications from the personal growth and transformation platform. Uses locally-stored catalog data without external API calls.', '@mazemax', 'aggregators', 'Unknown', 0, 'https://github.com/mazemax/mindvalley-products-mcp', NULL, 0, 'https://github.com/mazemax.png?size=128', '2026-03-09T05:21:02.036729+00:00'),
  ('traq', 'traQ', 'Provides a bridge to the traQ chat platform, enabling AI assistants to interact with traQ''s messaging ecosystem through a set of standardized MCP tools. Supports retrieving information about channels, messages, users, stamps, and pins with flexible search and filtering capabilities. Built using Deno and the Model Context Protocol SDK, this implementation offers a clean, type-safe interface for querying traQ''s API resources.', '@trap-jp', 'communication', 'Unknown', 2, 'https://github.com/trap-jp/mcp-traq', NULL, 0, 'https://github.com/trap-jp.png?size=128', '2026-03-09T05:21:02.036757+00:00'),
  ('macos-ui-automation', 'macOS UI Automation', 'macOS UI automation MCP server that enables AI assistants to interact with macOS applications through native accessibility APIs and system controls. The implementation provides tools for clicking UI elements, typing text, taking screenshots, and navigating application interfaces programmatically, allowing conversational automation of desktop workflows. Built specifically for macOS environments, it bridges the gap between AI conversation and direct system interaction, useful for automating repetitive tasks, testing applications, or providing accessibility assistance through natural language commands.', '@mb-dev', 'development', 'Unknown', 25, 'https://github.com/mb-dev/macos-ui-automation-mcp', NULL, 0, 'https://github.com/mb-dev.png?size=128', '2026-03-09T05:21:02.036788+00:00'),
  ('daraja', 'Daraja', 'Provides integration with Safaricom''s Daraja API for M-PESA mobile money transactions in Kenya. The server enables initiating STK Push payments, querying payment status, and receiving real-time payment notifications through webhooks. Runs both an MCP server for tool execution and a Flask callback server to handle payment confirmations from Safaricom''s systems, storing notifications locally for retrieval and management. Supports both sandbox and production environments with comprehensive payment tracking and notification management tools.', '@mboya', 'search', 'Unknown', 2, 'https://github.com/mboya/daraja-mcp', NULL, 0, 'https://github.com/mboya.png?size=128', '2026-03-09T05:21:02.036890+00:00'),
  ('goose-fm-radio', 'Goose FM Radio', 'This MCP implementation, developed by Kim, provides a radio tuning interface for AI assistants. Built with Python and leveraging the FastMCP framework, it offers tools for tuning to specific FM frequencies and controlling audio playback. The implementation focuses on integrating with RTL-SDR hardware to enable real-world radio reception. By connecting AI models with radio functionality, this server allows for scenarios like voice-controlled radio tuning, automated station scanning, and audio content analysis. It''s particularly useful for projects involving smart home integration, audio processing experiments, or enhancing AI assistants with live radio capabilities.', '@mccartykim', 'productivity', 'Unknown', 2, 'https://github.com/mccartykim/goose_fm', NULL, 0, 'https://github.com/mccartykim.png?size=128', '2026-03-09T05:21:02.036938+00:00'),
  ('honk', 'Honk', 'This MCP server, developed by Kim McCarty, provides a simple text-to-speech interface for MacOS using the built-in ''say'' command. Built with Python and leveraging the FastMCP framework, it offers a single tool for converting text to speech. The implementation focuses on demonstrating basic MCP functionality in a Nix-based development environment, enabling AI models to generate audible output on MacOS systems. By connecting AI assistants with the system''s text-to-speech capabilities, this server allows for scenarios like voice notifications or audio content generation. It''s particularly useful as a starting point for developers looking to understand MCP server implementation within a Nix ecosystem or those wanting to add basic speech output to their AI-powered applications.', '@mccartykim', 'development', 'Unknown', 0, 'https://github.com/mccartykim/honk_mcp', 'server', 0, 'https://github.com/mccartykim.png?size=128', '2026-03-09T05:21:02.036965+00:00'),
  ('mcdonald-s-china', 'McDonald''s China', 'Official MCP server for McDonald''s China that provides access to their event calendar, coupon inquiry system, and redemption features. Connects to McDonald''s China Open Platform API, enabling programmatic interaction with promotional activities and loyalty program features available in China.', '@unknown', 'productivity', 'Unknown', 0, 'https://open.mcd.cn/mcp', NULL, 0, NULL, '2026-03-09T05:21:02.036992+00:00'),
  ('vizro', 'Vizro', 'The Vizro MCP server enables AI assistants to create and validate data visualization dashboards and charts through integration with the Vizro toolkit. Developed by the Vizro team, this implementation provides tools for analyzing datasets, generating chart code, validating dashboard configurations, and creating interactive visualizations with PyCafe preview links. The server exposes simplified schema models to reduce context size for LLMs while maintaining compatibility with the full Vizro framework. It''s particularly valuable for users who want to rapidly prototype data visualizations through natural language without switching contexts, supporting both standalone chart creation and multi-page dashboard development with filters, parameters, and various component types.', '@mckinsey', 'development', 'Unknown', 3591, 'https://github.com/mckinsey/vizro/tree/HEAD/vizro-mcp', 'vizro-mcp', 7589, 'https://github.com/mckinsey.png?size=128', '2026-03-09T05:21:02.037054+00:00'),
  ('node-fetch', 'Node Fetch', 'MCP Node Fetch provides a server that enables AI assistants to fetch and process web content using Node.js''s undici library. It offers three specialized tools: fetch-url for retrieving content in various formats, extract-html-fragment for targeted HTML extraction using CSS selectors, and check-status for verifying URL accessibility. Developed by Matteo Collina, this implementation is particularly useful for workflows requiring web scraping, API interactions, or content analysis without leaving the conversation interface.', '@mcollina', 'ai-ml', 'Unknown', 11, 'https://github.com/mcollina/mcp-node-fetch', 'mcp-node-fetch', 3698, 'https://github.com/mcollina.png?size=128', '2026-03-09T05:21:02.037094+00:00'),
  ('permshell', 'PermShell', 'PermShell MCP is a TypeScript server that enables AI assistants to execute shell commands with explicit user permission through desktop notifications. Developed by Matteo Collina, it implements a security-focused approach where all commands require user approval via growl notifications that display the exact command and working directory for transparency. The server provides two main tools: ''execute-command'' for running shell commands with permission safeguards and ''system-info'' for retrieving system information without requiring explicit permission. It''s particularly useful for scenarios where AI assistants need controlled access to the local system while maintaining strong security boundaries.', '@mcollina', 'development', 'Unknown', 1, 'https://github.com/mcollina/perm-shell-mcp', 'perm-shell-mcp', 3533, 'https://github.com/mcollina.png?size=128', '2026-03-09T05:21:02.037124+00:00'),
  ('ripgrep', 'Ripgrep', 'MCP Ripgrep Server provides a wrapper around the powerful ripgrep search tool, enabling Claude and other MCP-compatible clients to perform high-performance text searches across files on a user''s system. Developed by Matteo Collina, it offers several specialized tools including basic search, advanced search with filtering options, match counting, and file listing capabilities. The server executes ripgrep commands on the local machine and formats the results for AI assistants, making it particularly useful for code exploration, finding patterns across codebases, and quickly identifying relevant files without leaving the conversation interface.', '@mcollina', 'development', 'Unknown', 63, 'https://github.com/mcollina/mcp-ripgrep', 'mcp-ripgrep', 11817, 'https://github.com/mcollina.png?size=128', '2026-03-09T05:21:02.037152+00:00'),
  ('bilt', 'Bilt', 'AI agents autonomously build and deploy mobile apps through natural language workflows.', '@buildingapplications', 'development', 'Unknown', 1, 'https://github.com/buildingapplications/mcp', NULL, 0, 'https://github.com/buildingapplications.png?size=128', '2026-03-09T05:21:02.037167+00:00'),
  ('io-nestr-mcp', 'io.nestr/mcp', 'Connect AI to Nestr for Holacracy, Sociocracy, and self-organizing teams.', '@nestr-dev', 'ai-ml', 'Unknown', 4, 'https://github.com/nestr-dev/nestr-mcp', NULL, 0, 'https://github.com/nestr-dev.png?size=128', '2026-03-09T05:21:02.037186+00:00'),
  ('com-scrapingant-mcp', 'com.scrapingant/mcp', 'Cloud-based web access with real browsers and JS rendering by ScrapingAnt', '@unknown', 'search', 'Unknown', 0, 'https://api.scrapingant.com/mcp/', NULL, 0, NULL, '2026-03-09T05:21:02.037207+00:00'),
  ('brave-browser', 'Brave Browser', 'This MCP implementation, mcp2brave, provides integration between MCP and the Brave browser. Developed by mcp2everything, it allows AI assistants and other MCP clients to interact with and control Brave browser sessions programmatically. The implementation leverages FastMCP and other libraries to enable capabilities like opening tabs, navigating pages, and extracting web content. It stands out by focusing specifically on Brave rather than being a general browser automation tool. Use cases include web scraping, automated testing of web applications in Brave, and enabling AI assistants to directly access web content through a user''s existing Brave browser.', '@mcp2everything', 'development', 'Unknown', 2, 'https://github.com/mcp2everything/mcp2brave', NULL, 0, 'https://github.com/mcp2everything.png?size=128', '2026-03-09T05:21:02.037232+00:00'),
  ('serial', 'Serial', 'MCP2Serial provides a bridge between AI Large Language Models and physical hardware devices through serial communication. Developed by the MCP2Serial Contributors, it enables AI models to interact with and control real-world electronics using the Model Context Protocol (MCP). The implementation features automatic port detection, multiple baud rate support, and real-time status monitoring. It integrates seamlessly with MCP clients like Claude Desktop and Cline, offering a flexible prompt system and resource management capabilities. MCP2Serial is particularly useful for IoT projects, robotics applications, and any scenario where AI-driven control of serial-connected devices is desired.', '@mcp2everything', 'productivity', 'Unknown', 40, 'https://github.com/mcp2everything/mcp2serial', 'mcp2serial', 3944, 'https://github.com/mcp2everything.png?size=128', '2026-03-09T05:21:02.037318+00:00'),
  ('mcp-analytics', 'MCP Analytics', 'Intelligent analytics platform that automatically selects the right statistical approach for your data. Provides 50+ tools including regression analysis, hypothesis testing, machine learning, time series forecasting, and business analytics. Features natural language discovery, OAuth2 security, cloud-based processing, and generates shareable interactive reports with AI-powered insights.', '@embeddedlayers', 'development', 'Unknown', 2, 'https://github.com/embeddedlayers/mcp-analytics', NULL, 0, 'https://github.com/embeddedlayers.png?size=128', '2026-03-09T05:21:02.037340+00:00'),
  ('io-github-samuelmoraesf-mcp-banco-inter', 'io.github.SamuelMoraesF/mcp-banco-inter', 'Servidor MCP para integração com o Banco Inter (PJ). Consulte saldos e gerencie cobranças.', '@samuelmoraesf', 'development', 'Unknown', 0, 'https://github.com/samuelmoraesf/mcp-banco-inter', NULL, 0, 'https://github.com/samuelmoraesf.png?size=128', '2026-03-09T05:21:02.037358+00:00'),
  ('mcpbundles-hub', 'MCPBundles Hub', 'MCPBundles Hub is a centralized MCP server that aggregates 530+ tool bundles from 510+ providers, providing access to over 5,300 tools through a single endpoint. Users can create custom bundles, manage provider credentials via OAuth or API keys, and connect to any MCP client including Claude Desktop, Cursor, ChatGPT, and VS Code. The hub also provides app-level tools for managing bundles, credentials, and account settings directly through AI assistants.', '@unknown', 'development', 'Unknown', 0, 'https://github.com/thinkchainai/mcpbundles', NULL, 0, 'https://github.com/thinkchainai.png?size=128', '2026-03-09T05:21:02.037379+00:00'),
  ('langchain-hub', 'LangChain Hub', 'MCP server that provides access to LangChain Hub''s prompt repository, enabling AI assistants to fetch and manage prompts from LangChain''s centralized prompt collection. The implementation requires a LangChain API key for authentication and offers both npm package installation and remote HTTP transport options for flexible deployment. Useful for developers working with LangChain who want to programmatically access, search, and utilize community-contributed prompts without manually browsing the LangChain Hub interface.', '@mcpcentral-io', 'ai-ml', 'Unknown', 1, 'https://github.com/mcpcentral-io/langchain-prompts-mcp-server', NULL, 0, 'https://github.com/mcpcentral-io.png?size=128', '2026-03-09T05:21:02.037419+00:00'),
  ('io-github-m2ai-mcp-servers-mcp-christensen', 'io.github.m2ai-mcp-servers/mcp-christensen', 'Clayton Christensen persona agent for strategic advisory using disruption theory', '@m2ai-mcp-servers', 'development', 'Unknown', 1, 'https://github.com/m2ai-mcp-servers/mcp-christensen', NULL, 0, 'https://github.com/m2ai-mcp-servers.png?size=128', '2026-03-09T05:21:02.037498+00:00'),
  ('evm-blockchain', 'EVM Blockchain', 'EVM-MCP-Server provides a bridge between AI assistants and Ethereum Virtual Machine (EVM) compatible blockchains through the Model Context Protocol. Built by mcpdotdirect, it enables interaction with multiple networks including Ethereum, Optimism, Arbitrum, and Base, offering tools for querying blockchain data, transferring tokens (ETH, ERC20, ERC721, ERC1155), reading smart contracts, and resolving ENS names. The server can run in both stdio mode for direct integration and HTTP mode with SSE support, making it flexible for various deployment scenarios while maintaining secure handling of private keys for transaction signing.', '@mcpdotdirect', 'ai-ml', 'Unknown', 367, 'https://github.com/mcpdotdirect/evm-mcp-server', '@mcpdotdirect/evm-mcp-server', 36868, 'https://github.com/mcpdotdirect.png?size=128', '2026-03-09T05:21:02.037571+00:00'),
  ('starknet', 'Starknet', 'Starknet MCP Server provides a bridge to the Starknet blockchain, enabling AI assistants to interact with this Layer 2 scaling solution built on Ethereum. Developed by mcpdotdirect, this TypeScript implementation offers tools for querying blockchain data, managing tokens, resolving Starknet IDs, and executing transactions. The server supports both mainnet and sepolia networks, with capabilities for balance checking, contract interaction, and NFT ownership verification. It can be run in either stdio mode for direct integration or HTTP mode for web-based access, making it valuable for blockchain analysis, wallet management, and decentralized application interaction.', '@mcpdotdirect', 'development', 'Unknown', 5, 'https://github.com/mcpdotdirect/starknet-mcp-server', '@mcpdotdirect/starknet-mcp-server', 3746, 'https://github.com/mcpdotdirect.png?size=128', '2026-03-09T05:21:02.037601+00:00'),
  ('io-github-m2ai-mcp-servers-mcp-dyson-appliances', 'io.github.m2ai-mcp-servers/mcp-dyson-appliances', 'MCP server for controlling Dyson air purifiers and fans', '@m2ai-mcp-servers', 'development', 'Unknown', 0, 'https://github.com/m2ai-mcp-servers/mcp-dyson-appliances', NULL, 0, 'https://github.com/m2ai-mcp-servers.png?size=128', '2026-03-09T05:21:02.037617+00:00'),
  ('io-github-verygoodplugins-mcp-evernote', 'io.github.verygoodplugins/mcp-evernote', 'Evernote note management with OAuth and ENML conversion', '@verygoodplugins', 'development', 'Unknown', 7, 'https://github.com/verygoodplugins/mcp-evernote', NULL, 0, 'https://github.com/verygoodplugins.png?size=128', '2026-03-09T05:21:02.037632+00:00'),
  ('io-github-dimitar-grigorov-mcp-file-tools', 'io.github.dimitar-grigorov/mcp-file-tools', 'Non-UTF-8/Unicode encoding: CP1251, CP1252, KOI8-R, ISO-8859 with auto-detection', '@dimitar-grigorov', 'development', 'Unknown', 7, 'https://github.com/dimitar-grigorov/mcp-file-tools', NULL, 0, 'https://github.com/dimitar-grigorov.png?size=128', '2026-03-09T05:21:02.037653+00:00'),
  ('mcpfinder', 'MCPFinder', 'The MCPFinder server enables AI assistants to discover and integrate new capabilities through the Model Context Protocol registry. Built with Node.js, it provides tools for searching, retrieving details, and configuring MCP servers across various client applications including Claude Desktop, Cursor, Windsurf, VS Code, and others. The implementation supports both HTTP and stdio transport modes, handles configuration file management for different operating systems, and includes an interactive setup process. This server acts as a gateway for expanding AI capabilities by allowing users to seamlessly add specialized tools like browser access, OCR, filesystem operations, or PDF parsing to their existing AI workflows.', '@mcpfinder', 'development', 'Unknown', 10, 'https://github.com/mcpfinder/server', '@mcpfinder/server', 6324, 'https://github.com/mcpfinder.png?size=128', '2026-03-09T05:21:02.037680+00:00'),
  ('mcp-fortress', 'MCP Fortress', 'Security scanner and runtime protection suite for Model Context Protocol servers. Performs automated vulnerability scanning across npm and PyPI packages, detects prompt injection attempts and tool poisoning attacks, and provides real-time monitoring with risk scoring. Can be used standalone or as an MCP server itself to provide security analysis tools to AI assistants.', '@mcp-fortress', 'ai-ml', 'Unknown', 4, 'https://github.com/mcp-fortress/mcp-fortress', NULL, 0, 'https://github.com/mcp-fortress.png?size=128', '2026-03-09T05:21:02.037715+00:00'),
  ('curl', 'Curl', 'This MCP server, developed by the mcp-get community, enables AI assistants to make HTTP requests to any URL using a curl-like interface. Built with TypeScript, it supports all common HTTP methods, customizable headers, request bodies, and configurable timeouts. The server provides a single ''curl'' tool that accepts parameters like URL, method, headers, body, and timeout, returning full response information including status, headers, and body. By allowing AI models to interact with external APIs and web services, this implementation extends their capabilities for tasks such as data retrieval, third-party integrations, and real-time information gathering. It is particularly useful for scenarios requiring dynamic data access or interaction with external systems beyond the AI''s training data.', '@mcp-get', 'development', 'Unknown', 66, 'https://github.com/mcp-get/community-servers/tree/HEAD/src/server-curl', NULL, 0, 'https://github.com/mcp-get.png?size=128', '2026-03-09T05:21:02.037744+00:00'),
  ('llm-txt-directory', 'LLM.txt Directory', 'This LLM.txt MCP server, developed by mcp-get, enables AI assistants to access and search the LLM.txt Directory, a collection of structured documentation files for various APIs and services. Built in TypeScript, it provides tools for listing available LLM.txt files, retrieving their contents, and performing multi-query searches with context. The server implements local caching to improve performance and uses numeric IDs to discourage hallucination of non-existent files. By abstracting access to the LLM.txt ecosystem, this implementation allows AI models to quickly gather accurate information about APIs and services without relying on potentially outdated training data. It is particularly useful for developers and AI assistants needing up-to-date documentation for integrating or troubleshooting various software tools and platforms.', '@mcp-get', 'development', 'Unknown', 66, 'https://github.com/mcp-get/community-servers/tree/HEAD/src/server-llm-txt', '@mcp-get-community/server-llm-txt', 9546, 'https://github.com/mcp-get.png?size=128', '2026-03-09T05:21:02.037774+00:00'),
  ('macos-system', 'macOS System', 'This MCP server, developed by the mcp-get community, provides macOS-specific system information and operations for AI assistants. Built with TypeScript, it offers tools for retrieving detailed system data (CPU, memory, disk, network; via sysctl) and sending native macOS notifications (via AppleScript). The server extends AI capabilities to interact directly with macOS environments, enabling tasks like system monitoring, performance analysis, and user notifications. By bridging AI models with macOS-specific functionalities, this implementation is particularly useful for scenarios requiring real-time system insights, automated macOS management, or enhanced user interaction through native notifications on Apple devices.', '@mcp-get', 'development', 'Unknown', 66, 'https://github.com/mcp-get/community-servers/tree/HEAD/src/server-macos', NULL, 0, 'https://github.com/mcp-get.png?size=128', '2026-03-09T05:21:02.037802+00:00'),
  ('mcpindex', 'MCPIndex', 'Enables LLMs to automatically discover and invoke suitable MCP tools, eliminating the need to manually find and configure suitable MCP tools for every task', '@unknown', 'productivity', 'Unknown', 0, 'https://www.npmjs.com/package/@mcpindex/server', '@mcpindex/server', 912, NULL, '2026-03-09T05:21:02.037821+00:00'),
  ('specification', 'Specification', 'This MCP server provides AI assistants with searchable access to the Model Context Protocol specification document, built by MCPJam using TypeScript with Fuse.js for fuzzy search capabilities. The implementation loads and indexes the complete MCP specification into searchable chunks organized by sections, offering a single tool that accepts predefined section queries like ''Introduction'', ''Core components'', ''Connection lifecycle'', ''Resources'', ''Tools'', and ''Authorization'' to retrieve relevant specification content. Serves developers building MCP implementations who need quick access to protocol details, AI assistants requiring authoritative MCP documentation during development conversations, and teams learning MCP concepts through natural language queries about the specification''s technical requirements and best practices.', '@mcpjam', 'development', 'Unknown', 8, 'https://github.com/mcpjam/mcp-spec', '@mcpjam/mcp-spec', 1400, 'https://github.com/mcpjam.png?size=128', '2026-03-09T05:21:02.037864+00:00'),
  ('klever-vm', 'Klever VM', 'MCP server for Klever blockchain smart contract development.', '@klever-io', 'development', 'Unknown', 30, 'https://github.com/klever-io/mcp-klever-vm', NULL, 0, 'https://github.com/klever-io.png?size=128', '2026-03-09T05:21:02.037880+00:00'),
  ('io-github-trickyfalcon-mcp-msdefenderkql', 'io.github.trickyfalcon/mcp-msdefenderkql', 'Execute KQL queries against Microsoft Defender Advanced Hunting via natural language.', '@unknown', 'development', 'Unknown', 0, 'https://www.pulsemcp.com/servers/mcp-msdefenderkql', NULL, 0, NULL, '2026-03-09T05:21:02.037896+00:00'),
  ('io-github-eaisdevelopment-mcp-multi-edit', 'io.github.eaisdevelopment/mcp-multi-edit', 'Atomic multi-file find-and-replace by Essential AI Solutions (essentialai.uk)', '@eaisdevelopment', 'development', 'Unknown', 0, 'https://github.com/eaisdevelopment/mcp-multi-edit', NULL, 0, 'https://github.com/eaisdevelopment.png?size=128', '2026-03-09T05:21:02.037910+00:00'),
  ('io-github-samuelmoraesf-mcp-nfse-nacional', 'io.github.SamuelMoraesF/mcp-nfse-nacional', 'MCP Server para consulta de NFSe no portal nacional (nfse.gov.br)', '@samuelmoraesf', 'development', 'Unknown', 0, 'https://github.com/samuelmoraesf/mcp-nfse-nacional', NULL, 0, 'https://github.com/samuelmoraesf.png?size=128', '2026-03-09T05:21:02.037926+00:00'),
  ('io-github-kcw2034-sayouzone-mcp-opendart-server', 'io.github.kcw2034-sayouzone/mcp-opendart-server', 'An MCP server that provides OpenDart API', '@sayouzone', 'development', 'Unknown', 0, 'https://github.com/sayouzone/mcp-opendart-server', NULL, 0, 'https://github.com/sayouzone.png?size=128', '2026-03-09T05:21:02.037946+00:00'),
  ('pdf', 'PDF', 'MCP server for creative PDF generation with full emoji, Unicode, and offline support. Enables AI agents to generate professionally formatted PDF documents with comprehensive character support and no external dependencies required.', '@mcp-z', 'development', 'Unknown', 1, 'https://github.com/mcp-z/mcp-pdf', NULL, 0, 'https://github.com/mcp-z.png?size=128', '2026-03-09T05:21:02.037963+00:00');
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('io-github-m2ai-mcp-servers-mcp-philips-hue', 'io.github.m2ai-mcp-servers/mcp-philips-hue', 'MCP server for Philips Hue smart lighting control', '@m2ai-mcp-servers', 'development', 'Unknown', 0, 'https://github.com/m2ai-mcp-servers/mcp-philips-hue', NULL, 0, 'https://github.com/m2ai-mcp-servers.png?size=128', '2026-03-09T05:21:02.037978+00:00'),
  ('plots', 'Plots', 'Provides tools to render charts from data with multiple output formats: Mermaid diagrams (default, renders directly in compatible clients), PNG images, or text representations. Supports line, bar, pie, scatter, heatmap, histogram, funnel, gauge, and sankey chart types. Designed for instant, visual-first charts with configurable dimensions, themes, and data point limits.', '@mr901', 'ai-ml', 'Unknown', 1, 'https://github.com/mr901/mcp-plots', NULL, 0, 'https://github.com/mr901.png?size=128', '2026-03-09T05:21:02.038013+00:00'),
  ('io-github-m2ai-mcp-servers-mcp-ratchet-clinical-charting', 'io.github.m2ai-mcp-servers/mcp-ratchet-clinical-charting', 'MCP server for clinical charting with Claude - document patient visits to EMR', '@m2ai-mcp-servers', 'development', 'Unknown', 0, 'https://github.com/m2ai-mcp-servers/mcp-ratchet-clinical-charting', NULL, 0, 'https://github.com/m2ai-mcp-servers.png?size=128', '2026-03-09T05:21:02.038032+00:00'),
  ('12306-ticket-query', '12306 Ticket Query', 'Queries China''s 12306 railway system for real-time train tickets, schedules, seat availability, pricing, and transfer routes with station fuzzy search.', '@drfccv', 'ai-ml', 'Unknown', 289, 'https://github.com/drfccv/mcp-server-12306', NULL, 0, 'https://github.com/drfccv.png?size=128', '2026-03-09T05:21:02.038079+00:00'),
  ('wordlift', 'WordLift', 'Knowledge Graph, GraphQL, GS1 Digital Link and SEO tools for semantic content optimization', '@unknown', 'development', 'Unknown', 0, 'https://github.com/wordlift/mcp-wordlift', NULL, 0, 'https://github.com/wordlift.png?size=128', '2026-03-09T05:21:02.038093+00:00'),
  ('io-github-pdwi2020-mcp-server-colab-exec', 'io.github.pdwi2020/mcp-server-colab-exec', 'Execute Python code on Google Colab GPU runtimes (T4/L4) from any MCP client', '@pdwi2020', 'development', 'Unknown', 3, 'https://github.com/pdwi2020/mcp-server-colab-exec', NULL, 0, 'https://github.com/pdwi2020.png?size=128', '2026-03-09T05:21:02.038108+00:00'),
  ('media-crawler-chinese-social-platforms', 'Media Crawler (Chinese Social Platforms)', 'This server integrates seven major Chinese social media platforms through a unified crawler interface, wrapping the MediaCrawler project as a git submodule. Built with FastMCP and FastAPI, it provides a dual-layer architecture supporting both STDIO and SSE transport modes. The implementation includes an admin interface for platform configuration and login management, making it particularly useful for researchers, marketers, and developers who need to systematically collect and analyze content from Chinese social media ecosystems. The server offers standardized tools for content extraction across platforms that would otherwise require separate integration efforts.', '@mcp-service', 'development', 'Unknown', 40, 'https://github.com/mcp-service/media-crawler-mcp-service', NULL, 0, 'https://github.com/mcp-service.png?size=128', '2026-03-09T05:21:02.038138+00:00'),
  ('mcpx', 'mcpx', 'mcpx is a dynamic, reprogrammable MCP Server. You install new MCP servlets from mcp.run which are secure and portable WebAssembly modules. When you install a servlet from mcp.run, it will appear in your MCP Client (like Claude Desktop) ready to use - no additional configuration needed.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('atrax-mcp-proxy', 'Atrax (MCP Proxy)', 'Atrax is a proxy service for Model Context Protocol (MCP) servers that aggregates multiple servers and presents them as a unified interface. It supports various transport types including STDIO, HTTP/SSE, and Docker, enabling seamless communication between clients and MCP servers. The implementation features resource aggregation with configurable conflict resolution, transparent proxying, authentication support, and enhanced error handling. Atrax is particularly useful for scenarios where multiple specialized MCP servers need to be accessed through a single endpoint, simplifying client integration while maintaining strict protocol compliance.', '@metcalfc', 'cloud', 'Unknown', 5, 'https://github.com/metcalfc/atrax', NULL, 0, 'https://github.com/metcalfc.png?size=128', '2026-03-09T05:21:02.039965+00:00'),
  ('docxprocessor', 'DocxProcessor', 'DocxProcessor MCP server provides a comprehensive Word document processing service that enables AI assistants to create, edit, and manipulate Microsoft Word documents through a rich set of tools. Built using Python with the python-docx library, it offers functionality for adding and formatting text, managing tables, searching and replacing content, and preserving document styling. The implementation includes state management for maintaining document sessions across server restarts and detailed error handling, making it particularly valuable for workflows requiring document generation, content editing, or template-based document creation without leaving the conversation interface.', '@meterlong', 'ai-ml', 'Unknown', 170, 'https://github.com/meterlong/mcp-doc', NULL, 0, 'https://github.com/meterlong.png?size=128', '2026-03-09T05:21:02.040010+00:00'),
  ('metersphere-api-testing', 'MeterSphere API Testing', 'The MeterSphere MCP server provides AI assistants with direct access to MeterSphere''s testing platform capabilities. This Spring Boot application serves as a bridge between AI systems and MeterSphere''s API, featuring tools for API debugging and documentation generation. The server implements authentication through API keys, supports both synchronous and asynchronous request handling, and includes comprehensive logging for troubleshooting. Built with Java and leveraging Spring''s WebFlux for reactive programming, it''s configured via environment variables and can be deployed as a Docker container. The implementation is particularly valuable for teams who want to manage and execute API tests through natural language interactions without leaving their conversation context.', '@metersphere', 'cloud', 'Unknown', 15, 'https://github.com/metersphere/metersphere-mcp-server', NULL, 0, 'https://github.com/metersphere.png?size=128', '2026-03-09T05:21:02.040035+00:00'),
  ('metoro-kubernetes-observability', 'Metoro Kubernetes Observability', 'This MCP server, developed by Metoro, enables AI assistants like Claude to interact with Kubernetes clusters through Metoro''s observability platform. Built in Go, it exposes Metoro''s APIs to allow querying and analyzing telemetry data collected from microservices using eBPF instrumentation. The implementation stands out by providing deep visibility into Kubernetes environments without requiring code changes. By connecting AI capabilities with Metoro''s comprehensive cluster insights, this server enables AI systems to troubleshoot issues, optimize performance, and understand complex microservice interactions. It is particularly useful for DevOps teams seeking to leverage AI for Kubernetes observability, automated incident response, and performance optimization in cloud-native environments.', '@metoro-io', 'cloud', 'Unknown', 47, 'https://github.com/metoro-io/metoro-mcp-server', NULL, 0, 'https://github.com/metoro-io.png?size=128', '2026-03-09T05:21:02.040086+00:00'),
  ('metricool', 'Metricool', 'Metricool MCP Server provides a bridge between AI assistants and the Metricool social media analytics platform, enabling access to performance metrics and content scheduling across multiple social networks. Built with Python and the FastMCP framework, it exposes over 20 tools for retrieving analytics data from platforms like Instagram, Facebook, Twitter, LinkedIn, TikTok, and YouTube, as well as capabilities for scheduling and updating posts. The server requires Metricool API credentials for authentication and supports both data analysis and content management functions, making it valuable for marketers who want to analyze social media performance, compare against competitors, and schedule optimized content without leaving their AI assistant conversation.', '@metricool', 'ai-ml', 'Unknown', 29, 'https://github.com/metricool/mcp-metricool', 'mcp-metricool', 7819, 'https://github.com/metricool.png?size=128', '2026-03-09T05:21:02.040138+00:00'),
  ('json-logs', 'JSON Logs', 'This MCP server provides JSON log file analysis capabilities, enabling AI assistants to query, filter, and aggregate structured Python application logs stored locally. Built by Michael Freeman using Python with the MCP SDK, it reads JSON log files from a configurable directory (defaulting to /var/log/mcp/json_logs) and expects entries with standard fields like timestamp, level, message, module, function, and line number. The implementation offers tools for searching logs by level, module, function, message content, and time ranges, aggregating data by various criteria (level, module, function, hour), generating overall statistics, and serving individual log files as resources, making it valuable for debugging Python applications, monitoring system behavior over time, and analyzing application performance patterns through structured log data.', '@mfreeman451', 'development', 'Unknown', 4, 'https://github.com/mfreeman451/json-logs-mcp-server', NULL, 0, 'https://github.com/mfreeman451.png?size=128', '2026-03-09T05:21:02.040175+00:00'),
  ('map-traveler', 'Map Traveler', 'Map-Traveler-MCP creates a virtual travel environment on Google Maps for AI assistants, allowing users to simulate journeys with an avatar that can navigate real-world routes. Built by Masahiro Fukushima, it integrates with Google Maps API for location data, image generation services (PixAI, Stability.ai, ComfyUI) for avatar visualization, and Bluesky for social sharing. The implementation stores travel history in SQLite, supports both real-time and skip-ahead travel modes, and includes features like nearby facility discovery and customizable avatar prompts, making it ideal for virtual tourism, storytelling, and interactive geography exploration.', '@mfukushim', 'databases', 'Unknown', 23, 'https://github.com/mfukushim/map-traveler-mcp', '@mfukushim/map-traveler-mcp', 9387, 'https://github.com/mfukushim.png?size=128', '2026-03-09T05:21:02.040187+00:00'),
  ('ghost', 'Ghost', 'A Model Context Protocol (MCP) server for interacting with Ghost CMS through LLM interfaces like Claude. This server provides secure and comprehensive access to your Ghost blog, leveraging JWT authentication and a rich set of MCP tools for managing posts, users, members, tiers, offers, and newsletters.', '@mfydev', 'ai-ml', 'Unknown', 153, 'https://github.com/mfydev/ghost-mcp', NULL, 0, 'https://github.com/mfydev.png?size=128', '2026-03-09T05:21:02.040220+00:00'),
  ('cosa-sai-gemini-docs', 'Cosa-SAI (Gemini Docs)', 'Gemini Docs MCP Server enables AI assistants to access comprehensive documentation for various technologies using Google''s Gemini API with its 2M token context window. Built by M-Gonzalo, it overcomes traditional RAG system limitations by eliminating the need for chunking, custom retrievers, and vector databases, instead loading entire documentation sets directly into the LLM. The server provides specialized tools for checking task feasibility, getting problem-solving hints, evaluating code practices, and exploring implementation alternatives. This approach delivers well-reasoned answers that consider entire technology specifications, making it particularly valuable for learning, debugging, and exploring alternative approaches across both common and obscure technologies.', '@m-gonzalo', 'databases', 'Unknown', 14, 'https://github.com/m-gonzalo/cosa-sai', NULL, 0, 'https://github.com/m-gonzalo.png?size=128', '2026-03-09T05:21:02.040233+00:00'),
  ('json-query', 'JSON Query', 'JSON Query MCP server provides tools for efficiently working with large JSON files through the Model Context Protocol. Developed by Michael Graczyk, this TypeScript implementation offers three key capabilities: querying JSON using JSONPath expressions, searching for keys similar to a query string, and finding values that match search criteria. The server is designed to help LLM models extract specific information from complex JSON structures without having to process the entire file, making it particularly valuable when working with large API specifications, configuration files, or data exports.', '@mgraczyk', 'development', 'Unknown', 10, 'https://github.com/mgraczyk/json-query-mcp', NULL, 0, 'https://github.com/mgraczyk.png?size=128', '2026-03-09T05:21:02.040261+00:00'),
  ('security-detections', 'Security Detections', 'An MCP server that provides unified access to security detection rules from Sigma, Splunk ESCU, Elastic Detection Rules, and KQL query repositories. The implementation indexes detection rules into a searchable SQLite database with full-text search capabilities, automatically parsing YAML and TOML formats to extract MITRE ATT&CK mappings, CVE references, process names, and other metadata. Supports advanced filtering by MITRE tactics, severity levels, data sources, and process names, making it useful for security analysts building detection coverage maps, threat hunters researching specific attack techniques, or security engineers comparing detection approaches across different SIEM platforms.', '@mhaggis', 'databases', 'Unknown', 317, 'https://github.com/mhaggis/security-detections-mcp', NULL, 0, 'https://github.com/mhaggis.png?size=128', '2026-03-09T05:21:02.040275+00:00'),
  ('librenms', 'LibreNMS', 'A Python-based MCP server providing advanced programmable access to LibreNMS network monitoring data and management features. Exposes APIs for querying and automating resources including devices, ports, alerts, inventory, locations, and logs. Supports both read and write operations, with stdio, SSE, and streamable HTTP transports. Also available as a Docker image for easy deployment.', '@mhajder', 'cloud', 'Unknown', 14, 'https://github.com/mhajder/librenms-mcp', NULL, 0, 'https://github.com/mhajder.png?size=128', '2026-03-09T05:21:02.040293+00:00'),
  ('zabbix', 'Zabbix', 'Provides programmatic access to Zabbix monitoring infrastructure through comprehensive tools for managing hosts, templates, items, triggers, problems, events, users, proxies, and maintenance periods. Features robust security options including read-only mode for safe monitoring, tag-based tool filtering, rate limiting, and optional Sentry integration. Supports multiple transport protocols (STDIO, HTTP SSE, HTTP Streamable) with bearer token authentication.', '@mhajder', 'ai-ml', 'Unknown', 2, 'https://github.com/mhajder/zabbix-mcp', NULL, 0, 'https://github.com/mhajder.png?size=128', '2026-03-09T05:21:02.040330+00:00'),
  ('qdrant', 'Qdrant', 'Qdrant MCP Server provides semantic search capabilities using a local Qdrant vector database and OpenAI embeddings, built by mhalder with comprehensive TypeScript implementation and 114 unit tests. The server automatically converts text documents to embeddings using OpenAI''s models, stores them in a locally-running Qdrant instance via Docker for complete data privacy, and enables natural language search with metadata filtering using Qdrant''s powerful filter syntax. It supports full collection lifecycle management (create, delete, info), document operations with automatic UUID normalization for string IDs, and both simple key-value and complex boolean filter expressions, making it valuable for building private knowledge bases, document search systems, and AI assistants that need semantic search without sending data to external vector database services.', '@mhalder', 'databases', 'Unknown', 21, 'https://github.com/mhalder/qdrant-mcp-server', 'qdrant-mcp-server', 1729, 'https://github.com/mhalder.png?size=128', '2026-03-09T05:21:02.040340+00:00'),
  ('relay', 'Relay', 'Facilitates message passing between Claude Desktop and Claude Code through a shared SQLite buffer. Send messages from one interface and fetch them from the other, with system notifications alerting users to incoming messages. Supports a 20-message rolling window with automatic cleanup.', '@mhcoen', 'databases', 'Unknown', 3, 'https://github.com/mhcoen/mcp-relay', NULL, 0, 'https://github.com/mhcoen.png?size=128', '2026-03-09T05:21:02.040350+00:00'),
  ('mh-labs-tools', 'MH Labs Tools', 'Provides comprehensive text preprocessing and natural language processing capabilities. Includes tools for tokenization, part-of-speech tagging, lemmatization, dependency parsing, named entity recognition, and morphological analysis. Supports removal of sensitive data (emails, phone numbers, SSNs, credit cards), URLs, punctuation, stopwords, and provides emoji/emoticon conversion and contraction expansion.', '@musaddiquehussainlabs', 'communication', 'Unknown', 0, 'https://github.com/musaddiquehussainlabs/mhlabs_mcp_tools', NULL, 0, 'https://github.com/musaddiquehussainlabs.png?size=128', '2026-03-09T05:21:02.040380+00:00'),
  ('bm-md', 'bm.md', 'A markdown processing server that exposes tools for rendering markdown to HTML, linting and auto-fixing markdown content, parsing HTML back to markdown, and extracting plain text. The render tool supports multiple typography styles, code themes, and platform-specific optimizations for WeChat public accounts, Zhihu columns, and Juejin articles with inline CSS for rich text editor compatibility.', '@miantiao-me', 'development', 'Unknown', 519, 'https://github.com/miantiao-me/bm.md', NULL, 0, 'https://github.com/miantiao-me.png?size=128', '2026-03-09T05:21:02.040428+00:00'),
  ('resx-resource-files', 'ResX Resource Files', 'ResxMcp is a .NET 8 MCP server that provides tools for working with .resx resource files, commonly used in .NET applications for localization and string management. Built as a Windows executable with PowerShell deployment scripts for automatic downloading from GitHub releases, it integrates with development workflows through configuration systems. The implementation focuses on resource file manipulation and is useful for internationalization tasks, localized application development, and managing string resources across multiple languages in .NET projects.', '@miaofalianhua', 'development', 'Unknown', 2, 'https://github.com/miaofalianhua/resxmcp', NULL, 0, 'https://github.com/miaofalianhua.png?size=128', '2026-03-09T05:21:02.040452+00:00'),
  ('mia-platform-console', 'Mia-Platform Console', 'Integrates with Mia-Platform Console, an AI-native developer platform for building cloud-native applications with microservices and Kubernetes. Provides tools for managing projects, deployments, and infrastructure through the Console APIs. Supports both OAuth user authentication and service account authentication for programmatic access.', '@mia-platform', 'cloud', 'Unknown', 3, 'https://github.com/mia-platform/console-mcp-server', NULL, 0, 'https://github.com/mia-platform.png?size=128', '2026-03-09T05:21:02.040472+00:00'),
  ('vonage-assist', 'Vonage Assist', 'Vonage Assist is an MCP server that helps developers integrate Vonage API capabilities into their applications by providing AI-assisted access to Vonage documentation. Built with FastMCP, the server performs targeted searches within Vonage''s developer documentation using Google Serper API, extracts relevant content from search results, and returns it to the user. The implementation includes a specialized tool called ''Vonage-Assist'' that accepts search queries and library parameters, making it easy for AI assistants to find information about Vonage''s communication APIs for features like SMS, voice, verification, and video.', '@micahman33', 'communication', 'Unknown', 0, 'https://github.com/micahman33/vonageaicodeassist', NULL, 0, 'https://github.com/micahman33.png?size=128', '2026-03-09T05:21:02.040509+00:00'),
  ('graphiti-knowledge-graph', 'Graphiti Knowledge Graph', 'Built by michabbb as a working implementation of Graphiti''s knowledge graph functionality, this server processes episodes (text, messages, or JSON) into nodes (entities) and facts (relationships) with temporal metadata stored in Neo4j. It supports dynamic information that evolves over time and includes custom entity extraction for requirements, preferences, and procedures. The implementation features Docker deployment, authentication via nonce tokens, background processing queues to prevent race conditions, making it valuable for applications that need persistent, queryable memory across conversations and complex data relationships.', '@michabbb', 'cloud', 'Unknown', 9, 'https://github.com/michabbb/graphiti-mcp-but-working', NULL, 0, 'https://github.com/michabbb.png?size=128', '2026-03-09T05:21:02.040535+00:00'),
  ('agentbay', 'AgentBay', 'Alibaba Cloud''s Wuying AgentBay is a cloud infrastructure designed for Agents in the AI era. It provides enterprises, developers, and AI vendors with a one-click configuration tool and execution environment for AI Agent tasks. Through the Wuying API or AgentBay MCP Server, Agent applications can quickly integrate and utilize relevant tools, running serverlessly in the cloud environment.', '@michael98671', 'productivity', 'Unknown', 7, 'https://github.com/michael98671/agentbay', NULL, 0, 'https://github.com/michael98671.png?size=128', '2026-03-09T05:21:02.040577+00:00'),
  ('audiobookshelf', 'Audiobookshelf', 'MCP server providing comprehensive access to Audiobookshelf API for managing audiobook and podcast libraries. Exposes 25+ tools covering libraries, items, authors, series, users, sessions, podcasts, collections, playlists, and server administration. Supports authentication via environment variables or parameters with flexible sub-resource access patterns. Built with mcp-go framework including extensive test coverage with mock server simulation.', '@michaeldvinci', 'development', 'Unknown', 5, 'https://github.com/michaeldvinci/audiobookshelf-mcp', NULL, 0, 'https://github.com/michaeldvinci.png?size=128', '2026-03-09T05:21:02.040644+00:00'),
  ('deepseek-r1-reasoner', 'Deepseek R1 Reasoner', 'This MCP server, developed by an unspecified author, provides a reasoning extension for locally running models using Deepseek r1. Built with TypeScript and leveraging the Model Context Protocol SDK, it offers a tool for task planning and context-based reasoning. The implementation focuses on enabling AI agents to perform reasoning tasks without relying on remote models, using Ollama to run Deepseek r1 locally. It''s particularly useful for applications requiring autonomous planning and decision-making capabilities, enabling use cases such as task decomposition, strategy formulation, and context-aware problem-solving while maintaining data privacy and reducing latency.', '@michaelneale', 'development', 'Unknown', 2, 'https://github.com/michaelneale/deepseek-r1-mcp', 'deepseek-reasoner-mcp', 312, 'https://github.com/michaelneale.png?size=128', '2026-03-09T05:21:02.040673+00:00'),
  ('migadu', 'Migadu', 'This Migadu MCP server by Michael Broel provides AI agents with complete email hosting management through the Migadu API, offering 15+ tools across mailbox operations (create, update, delete, password reset, autoresponder), alias management, identity configuration, and pattern-based rewrite rules. Built with Python using FastMCP and featuring Pydantic 2.0+ validation, bulk processing capabilities, smart domain resolution, and intelligent error handling for Migadu''s API quirks (like 500 status codes on successful deletions), it supports both individual and batch operations with comprehensive logging and context protection. The implementation integrates seamlessly with Claude Desktop through environment variable configuration and includes MCP resource templates for structured data access, making it valuable for automating email account provisioning, managing domain-wide email configurations, and building AI assistants that need programmatic control over Migadu''s unlimited email address hosting service.', '@michaelzag', 'development', 'Unknown', 8, 'https://github.com/michaelzag/migadu-mcp', 'migadu-mcp', 6531, 'https://github.com/michaelzag.png?size=128', '2026-03-09T05:21:02.040709+00:00'),
  ('substack', 'Substack', 'This MCP server implementation enables downloading and parsing of Substack posts for integration with Claude''s desktop app. Developed as an open-source Node.js project, it provides a streamlined interface for retrieving article content, including title, author, and full text. The server leverages libraries like Cheerio for HTML parsing and the Model Context Protocol SDK for standardized communication. It stands out by focusing specifically on Substack content extraction, making it particularly useful for researchers, writers, and analysts who want to easily incorporate Substack articles into their AI-assisted workflows for tasks like summarization, content analysis, or trend identification.', '@michalnaka', 'productivity', 'Unknown', 19, 'https://github.com/michalnaka/mcp-substack', NULL, 0, 'https://github.com/michalnaka.png?size=128', '2026-03-09T05:21:02.040749+00:00'),
  ('powerplatform-dataverse', 'PowerPlatform Dataverse', 'PowerPlatform MCP Server provides intelligent access to Microsoft PowerPlatform/Dataverse entities and records through a Model Context Protocol interface. Developed by Michal Sobieraj, it offers tools for retrieving entity metadata, attributes, relationships, and records with support for OData queries. The server includes formatted, context-rich prompts for entity overviews, attribute details, query templates, and relationship mapping. It authenticates with Azure AD and requires minimal configuration through environment variables, making it ideal for developers working with PowerPlatform who need context-aware assistance for data modeling, query building, and entity exploration directly within AI assistant conversations.', '@michsob', 'cloud', 'Unknown', 29, 'https://github.com/michsob/powerplatform-mcp', 'powerplatform-mcp', 7333, 'https://github.com/michsob.png?size=128', '2026-03-09T05:21:02.040769+00:00'),
  ('crypto-bytes', 'Crypto Bytes', 'Delivers curated cryptocurrency news with time-based filtering (breaking, 24hrs, 1week, all_time) and cryptocurrency symbol targeting (BTC, ETH, SOL, etc.). Provides tools to fetch latest articles and quick summaries for daily updates.', '@unknown', 'development', 'Unknown', 0, 'https://www.pulsemcp.com/servers/mickymultani-crypto-bytes', NULL, 0, NULL, '2026-03-09T05:21:02.040787+00:00'),
  ('microsoft-clarity-analytics', 'Microsoft Clarity Analytics', 'Microsoft Clarity Data Export MCP Server enables AI assistants to fetch analytics data from Microsoft Clarity through a standardized interface. It provides tools for querying metrics like scroll depth, engagement time, and traffic, with filtering capabilities for dimensions such as browser, device, and country. Built with TypeScript using the Model Context Protocol SDK, it securely handles API authentication through multiple configuration methods and implements robust error handling. The server is particularly valuable for users who need to analyze website behavior patterns and performance metrics directly through AI assistants without requiring direct web access to their Clarity dashboard.', '@microsoft', 'development', 'Unknown', 64, 'https://github.com/microsoft/clarity-mcp-server', '@microsoft/clarity-mcp-server', 13889, 'https://github.com/microsoft.png?size=128', '2026-03-09T05:21:02.040818+00:00'),
  ('microsoft-enterprise', 'Microsoft Enterprise', 'Official Microsoft MCP server that enables AI agents to query Microsoft Entra identity and directory data by converting natural language questions into Microsoft Graph API calls. Supports read-only enterprise IT scenarios including user, group, application, and device management, security posture analysis, privileged access reporting, and access governance. Enforces existing Microsoft Graph permissions, user privileges, and tenant security policies with rate limiting of 100 requests per minute per user.', '@microsoft', 'ai-ml', 'Unknown', 35, 'https://github.com/microsoft/enterprisemcp', NULL, 0, 'https://github.com/microsoft.png?size=128', '2026-03-09T05:21:02.040893+00:00'),
  ('microsoft-learn', 'Microsoft Learn', 'Enables AI agents to bring trusted and up-to-date information directly from Microsoft''s official documentation', '@microsoftdocs', 'ai-ml', 'Unknown', 1427, 'https://github.com/microsoftdocs/mcp', NULL, 0, 'https://github.com/microsoftdocs.png?size=128', '2026-03-09T05:21:02.040946+00:00'),
  ('open-deep-research', 'Open Deep Research', 'This is a Model Context Protocol (MCP) server that wraps the HuggingFace Open Deep Research project, built on their smolagents library, making the project available for use with MCP clients, such as AI assistants.
INSERT INTO servers (id, name, description, author, category, language, stars, github_url, npm_package, downloads, logo_url, updated_at) VALUES
  ('devbrain', 'DevBrain', 'This MCP server provides access to DevBrain''s curated developer knowledge base through a REST API, enabling retrieval of relevant coding articles, tutorials, and technical content based on search queries with optional tag filtering. Built by mimeCam using Python with FastMCP and requests, it offers three core tools: retrieve_knowledge for searching developer-curated content with tag-based filtering, read_full_article for fetching complete article content via URL, and token management tools (get_token/set_token) for API authentication. The implementation features environment variable configuration, robust error handling for API failures, and supports both PyPI distribution and Docker deployment, making it valuable for developers seeking contextual programming guidance, building AI coding assistants that need access to high-quality technical articles, and automating research workflows that require developer-focused content discovery.', '@mimecam', 'cloud', 'Unknown', 2, 'https://github.com/mimecam/mcp-devbrain-stdio', 'devbrain', 19080, 'https://github.com/mimecam.png?size=128', '2026-03-09T05:21:02.041886+00:00'),
  ('mindpilot-mermaid-diagrams', 'Mindpilot (Mermaid Diagrams)', 'Mindpilot MCP enables AI assistants to create and render Mermaid diagrams with real-time visualization through a local web interface, designed for visualizing code architecture, system flows, and complex processes. Built by Alex Brinsmead with TypeScript and React, it features a full-stack implementation including diagram history, export capabilities, multi-client support, and git repository integration for organizing diagrams by project. The server automatically launches a browser-based UI on localhost with pan/zoom controls, theme switching, and persistent storage, making it valuable for code reviews, system documentation, and understanding legacy codebases through visual representations.', '@abrinsmead', 'development', 'Unknown', 75, 'https://github.com/abrinsmead/mindpilot-mcp', '@mindpilot/mcp', 4425, 'https://github.com/abrinsmead.png?size=128', '2026-03-09T05:21:02.041915+00:00'),
  ('minds-ai', 'Minds AI', 'Minds AI''s MCP server enables creating and interacting with AI personas, digital twins, and expert advisors trained on specific knowledge domains. Supporting both HTTP and stdio transports, it provides tools for creating personas through multiple training modes (keyword-based expertise, person cloning, or website learning), chatting with created personas, and monitoring training progress. The implementation features comprehensive authentication via OAuth or API keys, rate limiting, circuit breakers, and fuzzy matching for persona discovery.', '@minds-ai-co', 'development', 'Unknown', 1, 'https://github.com/minds-ai-co/mcp-server', NULL, 0, 'https://github.com/minds-ai-co.png?size=128', '2026-03-09T05:21:02.041939+00:00'),
  ('raygun', 'Raygun', 'This Raygun MCP server, developed by MindscapeHQ, provides a standardized interface for AI assistants to interact with Raygun''s crash reporting and real user monitoring services. It integrates with Raygun''s V3 API to enable operations like listing applications, managing error groups, handling deployments, and accessing performance metrics. Built in TypeScript, the implementation handles API authentication and exposes Raygun''s functionality through an MCP interface. By bridging AI models and application monitoring data, this server allows AI systems to analyze crash reports, track user sessions, and monitor application performance. It is particularly useful for AI assistants needing to provide insights on software stability, user experience issues, or deployment impacts in applications monitored by Raygun.', '@mindscapehq', 'development', 'Unknown', 19, 'https://github.com/mindscapehq/mcp-server-raygun', '@raygun.io/mcp-server-raygun', 9352, 'https://github.com/mindscapehq.png?size=128', '2026-03-09T05:21:02.041973+00:00'),
  ('mindsdb', 'MindsDB', 'MindsDB is an MCP server that enables your MCP applications to answer questions over large-scale federated data—spanning databases, data warehouses, and SaaS applications.
